INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في المطاعم؟\", \"رائع! إليكم 10 عبارات شائعة تتعلق بالمطاعم، مع الترجمة الإنجليزية:\"]', '[\"تناول الطعام\", \"طلب الطعام\", \"الدفع والتخليص\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف محدد في ذهنك؟ مثل طلب مشروبات، أو تقديم شكوى، أو الاستفسار عن المكونات؟ لا تتردد في السؤال.\", \"يرجى وصف الموقف الذي يخطر في بالك.\"]', '[]', '[{\"original\": \"عذرًا، كم من الوقت سيستغرق وصول طعامنا؟\", \"translated\": \"Excuse me, how much longer will our food be?\"}, {\"original\": \"طاولة لشخصين، من فضلكم.\", \"translated\": \"A table for two, please.\"}, {\"original\": \"هل يمكننا رؤية القائمة، من فضلكم؟\", \"translated\": \"Could we see the menu, please?\"}, {\"original\": \"هل لديكم أطباق مميزة تقترحونها؟\", \"translated\": \"Do you have any signature dishes to recommend?\"}, {\"original\": \"أود طلب هذا وهذا.\", \"translated\": \"I\'d like to order this, and this.\"}, {\"original\": \"كوب من الماء، من فضلكم. شكرًا.\", \"translated\": \"A glass of water, please. Thanks.\"}, {\"original\": \"الحساب، من فضلكم.\", \"translated\": \"The bill, please.\"}, {\"original\": \"هل يمكنني الدفع باستخدام بطاقة الائتمان؟\", \"translated\": \"Can I pay by credit card?\"}, {\"original\": \"هل يمكنكم تغليف هذا لل带走، من فضلكم؟\", \"translated\": \"Could you pack this to go, please?\"}, {\"original\": \"كان الطعام لذيذًا جدًا، شكرًا لكم.\", \"translated\": \"The food was delicious, thank you.\"}]', 1, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ 10 عبارات شائعة يمكنني استخدامها في الفندق؟\", \"رائع جدًّا! إليك 10 عبارات شائعة عن الفنادق، مع الترجمة الإنجليزية:\"]', '[\"التسجيل الدخول\", \"المغادرة\", \"خدمة الغرف\"]', 'ar', '[\"حاليًّا، هل لديك حالة محددة في بالك، مثل موقع الغرفة أو أي خدمة فندقية أخرى أو المغادرة؟ لا تتردد في طرح أسئلتك.\", \"من فضلك صف لي الحالة التي تدور في ذهنك.\"]', '[]', '[{\"original\": \"مرحبًا، لدي حجزٌ، وهذه جواز سفري.\", \"translated\": \"Hello, I have a reservation, Here is my passport.\"}, {\"original\": \"هل لديكم أماكن شاغرة؟\", \"translated\": \"Do you have any vacancies?\"}, {\"original\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسيل الملابس؟\", \"translated\": \"Excuse me, does the hotel have a gym or a laundry room?\"}, {\"original\": \"في أي وقت تبدأ وجبة الإفطار؟\", \"translated\": \"What time does breakfast start?\"}, {\"original\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\", \"translated\": \"Could I have a room key, please?\"}, {\"original\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\", \"translated\": \"Could you help me take my luggage to the room?\"}, {\"original\": \"كيف أتصل بخدمة الغرف؟\", \"translated\": \"How do I call room service?\"}, {\"original\": \"في أي وقت تكون المغادرة؟\", \"translated\": \"What time is check-out?\"}, {\"original\": \"هل يمكنكم إعطائي إيصالًا/فاتورةً، من فضلكم؟\", \"translated\": \"Could you write me a receipt/invoice?\"}, {\"original\": \"هل يمكنني ترك أمتعتي هنا؟\", \"translated\": \"Can I leave my luggage here?\"}]', 2, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بعشر عبارات شائعة يمكنني استخدامها في المطار؟\", \"رائع جدًّا! إليك 10 عبارات شائعة عن المطار مع الترجمة الإنجليزية:\"]', '[\"التسجيل\", \"الصعود إلى الطائرة\", \"تسجيل الأمتعة\"]', 'ar', '[\"حتى الآن، هل لديك موقف محدد في ذهنك، مثل التسجيل أو استلام الأمتعة أو خدمة تأجير السيارات؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف لي الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"أين كاونتر التسجيل؟\", \"translated\": \"Where is the check-in counter?\"}, {\"original\": \"أود مقعدًا بجوار النافذة، من فضلك.\", \"translated\": \"I\'d like a window seat, please.\"}, {\"original\": \"هل تأخر هذا الرحلة؟\", \"translated\": \"Is this flight delayed?\"}, {\"original\": \"أحتاج إلى تسجيل هذه الأمتعة.\", \"translated\": \"I need to check this baggage.\"}, {\"original\": \"أين بوابة الصعود إلى الطائرة؟\", \"translated\": \"Where is the boarding gate?\"}, {\"original\": \"الطائرة على وشك الإقلاع.\", \"translated\": \"The plane is about to take off.\"}, {\"original\": \"هل عليّ إخراج جهاز اللابتوب والبنك الكهربائي الخاص بي؟\", \"translated\": \"Do I need to take out my laptop and power bank?\"}, {\"original\": \"أين متجر التجزئة المعفى من الضرائب؟\", \"translated\": \"Where is the duty-free shop?\"}, {\"original\": \"لا أستطيع العثور على حقيبتي.\", \"translated\": \"I can\'t find my suitcase.\"}, {\"original\": \"هل تقدمون خدمة الكرسي المتحرك؟\", \"translated\": \"Do you have a wheelchair service?\"}]', 3, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في وسائل النقل العام؟\", \"رائع جدًّا! إليك ١٠ عبارات شائعة تتعلق بوسائل النقل العام، مُرفقةً بترجمتها الإنجليزية:\"]', '[\"ركوب وسائل النقل العام\", \"شراء التذاكر\", \"التحويل بين خطوط النقل\"]', 'ar', '[\"حتى الآن، هل لديك موقف معين في ذهنك؟ مثل الاستفسار عن موقف الحافلة، أو سعر التذكرة، أو النزول من الحافلة — لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"هل هذه الحافلة تذهب إلى المحطة؟\", \"translated\": \"Does this bus go to the terminal?\"}, {\"original\": \"ما هي المحطة التالية؟\", \"translated\": \"What is the next stop?\"}, {\"original\": \"أين يمكنني شراء تذكرة؟\", \"translated\": \"Where can I buy a ticket?\"}, {\"original\": \"تذكرة واحدة إلى [XX]، من فضلك.\", \"translated\": \"One ticket to XX, please.\"}, {\"original\": \"هل يجب أن أقوم بالتحويل؟\", \"translated\": \"Do I need to transfer?\"}, {\"original\": \"كم يبقى حتى وصول قطار المترو القادم؟\", \"translated\": \"How long until the next subway train?\"}, {\"original\": \"عفوًا، من فضلك اسمح لي بالمرور.\", \"translated\": \"Excuse me, please let me pass.\"}, {\"original\": \"هل هذا المقعد محجوز؟\", \"translated\": \"Is this seat taken?\"}, {\"original\": \"عفوًا، أين يمكنني الانتقال إلى الخط ٢ للوصول إلى [XX]؟\", \"translated\": \"Excuse me, where can I transfer to Line 2 to get to XX?\"}, {\"original\": \"كيف أصل إلى [XX]؟\", \"translated\": \"How do I get to XX?\"}]', 4, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ10 عبارات شائعة يمكنني استخدامها في مواقع الجذب السياحي؟\", \"رائع! إليك 10 عبارات شائعة تتعلق بمواقع الجذب السياحي مع ترجمتها الإنجليزية:\"]', '[\"السياحة\", \"التقاط الصور\", \"شراء التذاكر\"]', 'ar', '[\"حتى الآن، هل لديك حالة محددة في بالك؟ مثل الاستفسار عن سعر التذكرة، أو البحث عن موقف سيارات، أو طلب خدمة دليل سياحي؟ لا تتردد في السؤال.\", \"من فضلك صف لي الحالة التي تدور في ذهنك.\"]', '[]', '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"How much is the entrance fee?\"}, {\"original\": \"هل تتوفر تذاكر للطلاب؟\", \"translated\": \"Are there student tickets available?\"}, {\"original\": \"متى يفتح مكان الجذب أبوابه؟\", \"translated\": \"What time does the attraction open?\"}, {\"original\": \"ما الأنشطة الممتعة التي يمكنني القيام بها هنا؟\", \"translated\": \"What are the fun things to do here?\"}, {\"original\": \"هل يمكنك التقاط صورة لنا؟\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"أين حافلة الجولات السياحية؟\", \"translated\": \"Where is the sightseeing bus?\"}, {\"original\": \"أين الحمامات؟\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"ما أفضل مكان لمشاهدة المنظر؟\", \"translated\": \"Where is the best viewing spot?\"}, {\"original\": \"المنظر هنا جميل جدًا.\", \"translated\": \"The scenery here is beautiful.\"}, {\"original\": \"هل تتوفر جولة إرشادية؟\", \"translated\": \"Is there a guided tour available?\"}]', 5, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن توفر لي ١٠ عبارات شائعة يمكنني استخدامها عند طلب تاكسي أو استخدام خدمة تاكسي؟\", \"رائع! إليك ١٠ عبارات شائعة تتعلق بالتاكسي أو خدمات التاكسي، مع ترجمتها الإنجليزية:\"]', '[\"الحصول على تاكسي\", \"إبلاغ الوجهة\", \"الدفع\"]', 'ar', '[\"الرحلة على وشك الانتهاء، هل هناك شيء يمكنني مساعدتك فيه؟ مثل التحقق من التكلفة المُقدَّرة، أو طلب فاتورة إلكترونية، أو تأكيد وسيلة الدفع، أو البحث عن جهة اتصال لاسترجاع الأشياء المفقودة — لا تتردد في طرح أي استفسار!\", \"صف لي bitte المشهد الذي تخيّله في ذهنك.\"]', '[]', '[{\"original\": \"أين يمكنني أخذ تاكسي؟\", \"translated\": \"Where can I get a taxi?\"}, {\"original\": \"من فضلك خذني إلى هذا العنوان.\", \"translated\": \"Please take me to this address.\"}, {\"original\": \"كم ستكون التكلفة تقريباً؟\", \"translated\": \"Roughly how much will it be?\"}, {\"original\": \"هل يمكنك تشغيل العداد من فضلك؟\", \"translated\": \"Could you use the meter, please?\"}, {\"original\": \"من فضلك قُدْ بسرعة أكبر قليلاً، فأنا مستعجل.\", \"translated\": \"Please drive a bit faster, I\'m in a hurry.\"}, {\"original\": \"من فضلك توقف هنا.\", \"translated\": \"Please stop here.\"}, {\"original\": \"هل يمكنني الدفع عبر Alipay؟\", \"translated\": \"Can I pay with Alipay?\"}, {\"original\": \"هل يمكنني الحصول على إشعار دفع من فضلك؟\", \"translated\": \"Could I have a receipt, please?\"}, {\"original\": \"شكراً لك يا سائق.\", \"translated\": \"Thank you, driver.\"}, {\"original\": \"كم تبقى من المسافة؟\", \"translated\": \"How much further is it?\"}]', 6, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكن أن تزودني بـ ١٠ عبارات شائعة يمكنني استخدامها في الصيدلية؟\", \"رائع! إليك ١٠ عبارات شائعة تُستخدم في الصيدليات، مع ترجمتها الإنجليزية:\"]', '[\"شراء الأدوية\", \"الاستفسار\", \"الدفع\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف معين في بالك؟ مثل طلب إرشادات حول كيفية تناول الدواء، أو عبارات مرتبطة باستخدام التأمين الصحي، أو المدة الزمنية لاستخدام الدواء — لا تتردّد في طرح أسئلتك.\", \"يرجى وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"هل لديكم دواء لعلاج البرد؟\", \"translated\": \"Do you have cold medicine?\"}, {\"original\": \"كيف يجب أن آخذ هذا الدواء؟\", \"translated\": \"How should I take this medicine?\"}, {\"original\": \"هل لديكم مسكنات لألم؟\", \"translated\": \"Do you have any painkillers?\"}, {\"original\": \"هل يوجد نشرة إرشادات مع هذا الدواء؟\", \"translated\": \"Is there an instruction leaflet?\"}, {\"original\": \"هل لهذا الدواء أي آثار جانبية؟\", \"translated\": \"Does this medicine have any side effects?\"}, {\"original\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\", \"translated\": \"Can I use my medical insurance card?\"}, {\"original\": \"هل يمكنك تزويدني بعلبة من الضمادات اللاصقة، من فضلك؟\", \"translated\": \"Could I have a box of Band-Aids, please?\"}, {\"original\": \"هل لديكم خافضات للحرارة؟\", \"translated\": \"Do you have any fever reducers?\"}, {\"original\": \"لدي جرح سطحي بسيط. هل لديكم مطهر وضمادات لاصقة؟\", \"translated\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\"}, {\"original\": \"في أي وقت تغلقون؟\", \"translated\": \"What time do you close?\"}]', 7, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ10 عبارات شائعة يمكنني استخدامها في خدمات الطوارئ؟\", \"رائع! إليك 10 عبارات شائعة مرتبطة بخدمات الطوارئ، مع الترجمة الإنجليزية المقابلة:\"]', '[\"الإبلاغ عن جريمة\", \"الحصول على الرعاية الطبية الطارئة\", \"طلب المساعدة\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف طارئ محدد في بالك، مثل الحريق أو الإصابة والاحتياج للمساعدة أو الاتصال بالطوارئ؟ لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"من فضلك ساعدني في الاتصال بالإسعاف.\", \"translated\": \"Please help me call an ambulance.\"}, {\"original\": \"أين يقع المستشفى؟\", \"translated\": \"Where is the hospital?\"}, {\"original\": \"شخص ما أصيب.\", \"translated\": \"Someone is injured.\"}, {\"original\": \"من فضلك ساعدني.\", \"translated\": \"Please help me.\"}, {\"original\": \"أين تقع مركز الشرطة؟\", \"translated\": \"Where is the police station?\"}, {\"original\": \"لقد فقدت أمتعتي.\", \"translated\": \"I\'ve lost my belongings.\"}, {\"original\": \"ما هو رقم إطفاء الحريق؟\", \"translated\": \"What is the number for the fire department?\"}, {\"original\": \"لقد فقدت جواز سفري. هل تعرف أين يقع أقرب مركز شرطة؟\", \"translated\": \"I\'ve lost my passport. Do you know where the nearest police station is?\"}, {\"original\": \"هل هناك مخرج طوارئ؟\", \"translated\": \"Is there an emergency exit?\"}, {\"original\": \"شخص ما فقد وعيه.\", \"translated\": \"Someone has fainted.\"}]', 8, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزوِّدني بعشر عبارات شائعة يمكنني استخدامها على الشاطئ أو بالقرب من حمام السباحة؟\", \"رائع جدًا! إليك عشر عبارات شائعة مرتبطة بالشاطئ أو حمام السباحة، مع ترجمتها الإنجليزية:\"]', '[\"السباحة واللعب في الماء\", \"التعرّض لأشعة الشمس (الاستلقاء للتشمّس)\", \"الأنشطة الرياضية على الرمال\"]', 'ar', '[\"حاليًّا، هل يمكنك من فضلك إخباري بالسياق الخاص بالحدث أو المهرجان المحلي الذي ستشارك فيه؟ مثل مهرجان ثقافي، أو مهرجان للأطعمة، أو مهرجان موسيقي. يُرجى توضيح السياق.\", \"يرجى تزويدي بالأنشطة التي ستشترك فيها.\"]', '[\"هل لديك موقف معيّن في ذهنك؟ لا تتردّد في طرح أي سؤال.\", \"يُرجى وصف الموقف الذي تفكر فيه.\"]', '[{\"original\": \"انظر! الأمواج هناك كبيرة جدًا.\", \"translated\": \"Look! The waves over there are really big.\"}, {\"original\": \"تذكَّر أن تضع واقي الشمس، فأشعة فوق البنفسجية هنا قوية جدًا.\", \"translated\": \"Remember to apply sunscreen, the UV rays here are very strong.\"}, {\"original\": \"الرمال على هذا الشاطئ ناعمة جدًا، لدرجة أن المشي عليها يشبه المشي على القطن.\", \"translated\": \"The sand on this beach is so fine, it feels like stepping on cotton.\"}, {\"original\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\", \"translated\": \"How about playing volleyball on the beach?\"}, {\"original\": \"القوارب الشراعية في الأفق تبدو جميلة جدًا.\", \"translated\": \"The sailboats in the distance look beautiful.\"}, {\"original\": \"الماء هنا شفاف جدًا لدرجة أنك تستطيع رؤية الأسماك بوضوح.\", \"translated\": \"The water here is so clear, you can even see the fish.\"}, {\"original\": \"هيا نبحث عن بعض المحار والقواقع البحرية.\", \"translated\": \"Let\'s go find some seashells.\"}, {\"original\": \"التنزه على الشاطئ عند غروب الشمس يجب أن يكون أمرًا رومانسيًّا للغاية.\", \"translated\": \"Taking a walk on the beach at sunset must be very romantic.\"}, {\"original\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًا، فلنجرّب بعضها.\", \"translated\": \"I heard the seafood here is very fresh, let\'s go try some.\"}, {\"original\": \"المدّ في ارتفاع، فلنتوجّه نحو اليابسة.\", \"translated\": \"The tide is coming in, let\'s head towards the shore.\"}]', 9, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ 10 عبارات شائعة يمكنني استخدامها في الفعاليات والمناسبات المحلية؟\", \"رائع جدًّا! إليك 10 عبارات شائعة عن الفعاليات والمناسبات المحلية، مع ترجمتها الإنجليزية:\"]', '[\"الانضمام إلى الفعاليات\", \"الاحتفال بالعيد\", \"التعرّف على الثقافة\"]', 'ar', '[\"حاليًّا، هل يمكنك إخباري بالسياق الذي ستشارك فيه في الفعالية أو المهرجان المحلي، مثل هالووين أو حفل موسيقي أو حفلة مع الأصدقاء أو أي شيء آخر؟ يُرجى تزويدي بهذا السياق.\", \"يرجى وصف الأنشطة التي تخطر لك في بالك.\"]', '[\"هل لديك موقف معين في ذهنك؟ لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي تخطر لك في بالك.\"]', '[{\"original\": \"هل هناك أي فعاليات اليوم؟\", \"translated\": \"Are there any events today?\"}, {\"original\": \"هل هناك شيء مميز في هذه المهرجان؟\", \"translated\": \"Is there anything special about this festival?\"}, {\"original\": \"أين تُقام الاحتفالات؟\", \"translated\": \"Where is the celebration being held?\"}, {\"original\": \"كيف يمكنني شراء التذاكر؟\", \"translated\": \"How can I buy tickets?\"}, {\"original\": \"في أي وقت تبدأ العروض؟\", \"translated\": \"What time does the performance start?\"}, {\"original\": \"ما الأطعمة التقليدية المتاحة؟\", \"translated\": \"What traditional food is there?\"}, {\"original\": \"المكان حيويٌّ جدًّا هنا.\", \"translated\": \"It\'s really lively here.\"}, {\"original\": \"هل هناك أنشطة شعبية؟\", \"translated\": \"Are there any folk activities?\"}, {\"original\": \"أعياد سعيدة!\", \"translated\": \"Happy holidays!\"}, {\"original\": \"في أي وقت تنتهي الفعالية؟\", \"translated\": \"What time does the event end?\"}]', 10, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكن أن تزودني بـ10 عبارات شائعة يمكنني استخدامها في المتاحف أو المعارض الفنية؟\", \"رائع جدًّا! إليك 10 عبارات شائعة تتعلق بالمتاحف أو المعارض الفنية، مصحوبةً بترجمتها الإنجليزية:\"]', '[\"زيارة\", \"جولة توجيهية\", \"شراء تذاكر\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف معين في بالك؟ مثل طلب كتيب تعريفي، أو عبارات مرتبطة بخريطة الطريق، أو عبارات تعبّر عن آراء حول المعروضات — لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي يخطر في بالك.\"]', '[]', '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"How much is the admission fee?\"}, {\"original\": \"هل لديكم دليل صوتي؟\", \"translated\": \"Do you have audio guides?\"}, {\"original\": \"من هو مبتكر هذه القطعة الفنية؟\", \"translated\": \"Who created this artwork?\"}, {\"original\": \"أين توجد أثمن قطعة في المتحف؟\", \"translated\": \"Where is the museum\'s most prized piece?\"}, {\"original\": \"هل يُسمح بالتصوير الفوتوغرافي؟\", \"translated\": \"Is photography allowed?\"}, {\"original\": \"هل هناك أي معارض خاصة هنا؟\", \"translated\": \"Are there any special exhibitions here?\"}, {\"original\": \"كم تستغرق الجولة من الوقت؟\", \"translated\": \"How long does the visit take?\"}, {\"original\": \"هل يمكنكم إعطاؤنا مقدمة عامة؟\", \"translated\": \"Could you give us an introduction?\"}, {\"original\": \"هذه الأعمال رائعة حقًا.\", \"translated\": \"These works are truly exquisite.\"}, {\"original\": \"أين تقع متجر الهدايا التذكارية؟\", \"translated\": \"Where is the souvenir shop?\"}]', 11, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ10 عبارات شائعة يمكنني استخدامها في مقهى؟\", \"رائع! إليك 10 عبارات شائعة تُستخدم في المقاهي، مع الترجمة الإنجليزية:\"]', '[\"طلب القهوة\", \"الاسترخاء\", \"التواصل الاجتماعي\"]', 'ar', '[\"لِحدِّ الآن، هل لديك موقفٌ معيَّنٌ في بالك؟ مثل طلب القائمة، أو المشروبات المثلَّجة أو الساخنة، أو غيرها من المنتجات — لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"سأطلب لاتيه، من فضلك.\", \"translated\": \"I\'ll have a latte, please.\"}, {\"original\": \"هل لديكم خدمة واي فاي؟\", \"translated\": \"Do you have Wi-Fi?\"}, {\"original\": \"هل يمكنني رؤية القائمة، من فضلك؟\", \"translated\": \"Could I see the menu, please?\"}, {\"original\": \"هل يُسمح بإعادة التعبئة؟\", \"translated\": \"Are refills allowed?\"}, {\"original\": \"هل قهوة الطلب الخاصة بي جاهزة؟\", \"translated\": \"Is my coffee ready?\"}, {\"original\": \"كم من الوقت يمكنني الجلوس هنا؟\", \"translated\": \"How long can I sit here?\"}, {\"original\": \"هل يمكنك التقاط صورة لنا؟\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"أين الحمام؟\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"الحساب، من فضلك. شكرًا لك.\", \"translated\": \"Check, please. Thank you.\"}, {\"original\": \"إنها تذوق جيد جدًا.\", \"translated\": \"It tastes really good.\"}]', 12, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser au restaurant ?\", \"Super ! Voici 10 expressions courantes liées au restaurant, avec leur traduction en anglais :\"]', '[\"Repas\", \"Commande\", \"Règlement\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, comme commander des boissons, formuler une réclamation ou demander des précisions sur les ingrédients ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\", \"translated\": \"Excuse me, how much longer will our food be?\"}, {\"original\": \"Une table pour deux, s\'il vous plaît.\", \"translated\": \"A table for two, please.\"}, {\"original\": \"Pourrions-nous voir la carte, s\'il vous plaît ?\", \"translated\": \"Could we see the menu, please?\"}, {\"original\": \"Avez-vous des plats signature à nous recommander ?\", \"translated\": \"Do you have any signature dishes to recommend?\"}, {\"original\": \"Je voudrais commander ceci et cela.\", \"translated\": \"I\'d like to order this, and this.\"}, {\"original\": \"Un verre d\'eau, s\'il vous plaît. Merci.\", \"translated\": \"A glass of water, please. Thanks.\"}, {\"original\": \"L\'addition, s\'il vous plaît.\", \"translated\": \"The bill, please.\"}, {\"original\": \"Puis-je payer par carte bancaire ?\", \"translated\": \"Can I pay by credit card?\"}, {\"original\": \"Pourriez-vous emballer cela à emporter, s\'il vous plaît ?\", \"translated\": \"Could you pack this to go, please?\"}, {\"original\": \"Le repas était délicieux, merci beaucoup.\", \"translated\": \"The food was delicious, thank you.\"}]', 1, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser à l\'hôtel ?\", \"Génial ! Voici 10 expressions courantes liées à l’hôtel, avec leur traduction anglaise :\"]', '[\"Enregistrement\", \"Départ\", \"Service en chambre\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête — par exemple l’emplacement de la chambre, d’autres services proposés par l’hôtel ou le départ — n’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Bonjour, j\'ai une réservation. Voici mon passeport.\", \"translated\": \"Hello, I have a reservation. Here is my passport.\"}, {\"original\": \"Avez-vous des chambres disponibles ?\", \"translated\": \"Do you have any vacancies?\"}, {\"original\": \"Excusez-moi, l\'hôtel dispose-t-il d\'une salle de sport ou d\'une buanderie ?\", \"translated\": \"Excuse me, does the hotel have a gym or a laundry room?\"}, {\"original\": \"À quelle heure commence le petit-déjeuner ?\", \"translated\": \"What time does breakfast start?\"}, {\"original\": \"Pourrais-je avoir la clé de ma chambre, s\'il vous plaît ?\", \"translated\": \"Could I have a room key, please?\"}, {\"original\": \"Pourriez-vous m\'aider à porter mes bagages jusqu\'à ma chambre ?\", \"translated\": \"Could you help me take my luggage to the room?\"}, {\"original\": \"Comment puis-je appeler le service en chambre ?\", \"translated\": \"How do I call room service?\"}, {\"original\": \"À quelle heure est le départ ?\", \"translated\": \"What time is check-out?\"}, {\"original\": \"Pourriez-vous me rédiger un reçu / une facture ?\", \"translated\": \"Could you write me a receipt/invoice?\"}, {\"original\": \"Puis-je laisser mes bagages ici ?\", \"translated\": \"Can I leave my luggage here?\"}]', 2, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser à l\'aéroport ?\", \"Super ! Voici 10 expressions courantes liées à l\'aéroport, avec leur traduction en anglais :\"]', '[\"Enregistrement\", \"Embarquement\", \"Enregistrement des bagages\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, comme l\'enregistrement, le retrait des bagages ou la location de voiture ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Où se trouve le comptoir d\'enregistrement ?\", \"translated\": \"Where is the check-in counter?\"}, {\"original\": \"Je voudrais un siège côté hublot, s\'il vous plaît.\", \"translated\": \"I\'d like a window seat, please.\"}, {\"original\": \"Ce vol est-il retardé ?\", \"translated\": \"Is this flight delayed?\"}, {\"original\": \"Je dois enregistrer ce bagage.\", \"translated\": \"I need to check this baggage.\"}, {\"original\": \"Où se trouve la porte d\'embarquement ?\", \"translated\": \"Where is the boarding gate?\"}, {\"original\": \"L\'avion va décoller dans un instant.\", \"translated\": \"The plane is about to take off.\"}, {\"original\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\", \"translated\": \"Do I need to take out my laptop and power bank?\"}, {\"original\": \"Où se trouve la boutique hors taxes ?\", \"translated\": \"Where is the duty-free shop?\"}, {\"original\": \"Je ne retrouve pas ma valise.\", \"translated\": \"I can\'t find my suitcase.\"}, {\"original\": \"Proposez-vous un service de fauteuil roulant ?\", \"translated\": \"Do you have a wheelchair service?\"}]', 3, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans les transports en commun ?\", \"Génial ! Voici 10 expressions courantes liées aux transports en commun, avec leur traduction en anglais :\"]', '[\"Prendre les transports en commun\", \"Acheter un billet\", \"Changer de ligne ou de transport\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander l\'arrêt du bus, le prix du billet ou indiquer que vous souhaitez descendre ? N\'hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Ce bus va-t-il jusqu\'à la gare routière ?\", \"translated\": \"Does this bus go to the terminal?\"}, {\"original\": \"Quel est le prochain arrêt ?\", \"translated\": \"What is the next stop?\"}, {\"original\": \"Où puis-je acheter un billet ?\", \"translated\": \"Where can I buy a ticket?\"}, {\"original\": \"Un billet pour XX, s\'il vous plaît.\", \"translated\": \"One ticket to XX, please.\"}, {\"original\": \"Dois-je changer de transport ?\", \"translated\": \"Do I need to transfer?\"}, {\"original\": \"Dans combien de temps arrive le prochain métro ?\", \"translated\": \"How long until the next subway train?\"}, {\"original\": \"Excusez-moi, je dois passer.\", \"translated\": \"Excuse me, please let me pass.\"}, {\"original\": \"Cette place est-elle prise ?\", \"translated\": \"Is this seat taken?\"}, {\"original\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d\'aller à XX ?\", \"translated\": \"Excuse me, where can I transfer to Line 2 to get to XX?\"}, {\"original\": \"Comment puis-je me rendre à XX ?\", \"translated\": \"How do I get to XX?\"}]', 4, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser sur un site touristique ?\", \"Super ! Voici 10 expressions courantes liées aux sites touristiques, avec leur traduction en anglais :\"]', '[\"Visite touristique\", \"Prendre des photos\", \"Acheter des billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander le prix des billets, trouver un parking ou un service de guide touristique ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Quel est le prix de l\'entrée ?\", \"translated\": \"How much is the entrance fee?\"}, {\"original\": \"Y a-t-il des billets étudiants disponibles ?\", \"translated\": \"Are there student tickets available?\"}, {\"original\": \"À quelle heure ouvre l\'attraction ?\", \"translated\": \"What time does the attraction open?\"}, {\"original\": \"Quelles sont les activités amusantes à faire ici ?\", \"translated\": \"What are the fun things to do here?\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"Où est le bus touristique ?\", \"translated\": \"Where is the sightseeing bus?\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"Où est le meilleur point de vue ?\", \"translated\": \"Where is the best viewing spot?\"}, {\"original\": \"Le paysage est magnifique ici.\", \"translated\": \"The scenery here is beautiful.\"}, {\"original\": \"Une visite guidée est-elle disponible ?\", \"translated\": \"Is there a guided tour available?\"}]', 5, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser pour prendre un taxi ou utiliser un service de taxi ?\", \"Génial ! Voici 10 expressions courantes liées aux taxis ou aux services de taxi, avec leur traduction en anglais :\"]', '[\"prendre un taxi\", \"indiquer la destination\", \"payer\"]', 'fr', '[\"Le trajet touche à sa fin — y a-t-il quelque chose dont je peux vous aider ? Par exemple, consulter l\'estimation du coût, demander une facture électronique, confirmer le mode de paiement ou obtenir les coordonnées pour signaler un objet perdu. N\'hésitez pas à demander quoi que ce soit !\", \"Décrivez-moi la scène qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Où puis-je prendre un taxi ?\", \"translated\": \"Where can I get a taxi?\"}, {\"original\": \"Veuillez me conduire à cette adresse.\", \"translated\": \"Please take me to this address.\"}, {\"original\": \"À peu près combien cela coûtera-t-il ?\", \"translated\": \"Roughly how much will it be?\"}, {\"original\": \"Pourriez-vous utiliser le compteur, s\'il vous plaît ?\", \"translated\": \"Could you use the meter, please?\"}, {\"original\": \"Pourriez-vous rouler un peu plus vite ? Je suis pressé(e).\", \"translated\": \"Please drive a bit faster, I\'m in a hurry.\"}, {\"original\": \"Arrêtez-vous ici, s\'il vous plaît.\", \"translated\": \"Please stop here.\"}, {\"original\": \"Puis-je payer avec Alipay ?\", \"translated\": \"Can I pay with Alipay?\"}, {\"original\": \"Pourrais-je avoir un reçu, s\'il vous plaît ?\", \"translated\": \"Could I have a receipt, please?\"}, {\"original\": \"Merci, monsieur/madame le chauffeur.\", \"translated\": \"Thank you, driver.\"}, {\"original\": \"Il reste encore combien de temps ?\", \"translated\": \"How much further is it?\"}]', 6, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser en pharmacie ?\", \"Super ! Voici 10 expressions courantes liées à la pharmacie, accompagnées de leur traduction anglaise :\"]', '[\"Acheter des médicaments\", \"Consulter\", \"Payer\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander des instructions sur la prise d’un médicament, des formulations liées à l’utilisation de votre assurance, ou la durée du traitement ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Avez-vous des médicaments contre le rhume ?\", \"translated\": \"Do you have cold medicine?\"}, {\"original\": \"Comment dois-je prendre ce médicament ?\", \"translated\": \"How should I take this medicine?\"}, {\"original\": \"Avez-vous des antidouleurs ?\", \"translated\": \"Do you have any painkillers?\"}, {\"original\": \"Y a-t-il une notice d\'utilisation ?\", \"translated\": \"Is there an instruction leaflet?\"}, {\"original\": \"Ce médicament a-t-il des effets secondaires ?\", \"translated\": \"Does this medicine have any side effects?\"}, {\"original\": \"Puis-je utiliser ma carte d\'assurance maladie ?\", \"translated\": \"Can I use my medical insurance card?\"}, {\"original\": \"Pourriez-vous me donner une boîte de pansements, s\'il vous plaît ?\", \"translated\": \"Could I have a box of Band-Aids, please?\"}, {\"original\": \"Avez-vous des antipyrétiques ?\", \"translated\": \"Do you have any fever reducers?\"}, {\"original\": \"Je me suis un peu écorché(e). Avez-vous un antiseptique et des pansements ?\", \"translated\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\"}, {\"original\": \"À quelle heure fermez-vous ?\", \"translated\": \"What time do you close?\"}]', 7, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser pour les services d\'urgence ?\", \"Super ! Voici 10 expressions courantes liées aux services d\'urgence, avec leur traduction en anglais :\"]', '[\"Appeler la police\", \"Obtenir des soins médicaux d\'urgence\", \"Demander de l\'aide\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation d\'urgence précise en tête, par exemple incendie, blessure nécessitant de l\'aide, appel d\'urgence ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Veuillez m\'aider à appeler une ambulance.\", \"translated\": \"Please help me call an ambulance.\"}, {\"original\": \"Où est l\'hôpital ?\", \"translated\": \"Where is the hospital?\"}, {\"original\": \"Quelqu\'un est blessé.\", \"translated\": \"Someone is injured.\"}, {\"original\": \"Aidez-moi, s\'il vous plaît.\", \"translated\": \"Please help me.\"}, {\"original\": \"Où est le commissariat de police ?\", \"translated\": \"Where is the police station?\"}, {\"original\": \"J\'ai perdu mes affaires.\", \"translated\": \"I\'ve lost my belongings.\"}, {\"original\": \"Quel est le numéro des pompiers ?\", \"translated\": \"What is the number for the fire department?\"}, {\"original\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le commissariat de police le plus proche ?\", \"translated\": \"I\'ve lost my passport. Do you know where the nearest police station is?\"}, {\"original\": \"Y a-t-il une sortie de secours ?\", \"translated\": \"Is there an emergency exit?\"}, {\"original\": \"Quelqu\'un s\'est évanoui.\", \"translated\": \"Someone has fainted.\"}]', 8, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je pourrais utiliser à la plage ou au bord de la piscine ?\", \"Formidable ! Voici 10 expressions courantes liées à la plage ou au bord de la piscine, avec leur traduction en anglais :\"]', '[\"nager et jouer dans l\'eau\", \"prendre un bain de soleil\", \"faire du sport sur la plage\"]', 'fr', '[\"Pour l’instant, pourriez-vous me décrire le cadre de l’événement ou du festival local auquel vous participez, par exemple un festival culturel, gastronomique ou musical ? Veuillez préciser le contexte.\", \"Veuillez décrire les activités auxquelles vous participez.\"]', '[\"Avez-vous une situation particulière en tête ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\", \"translated\": \"Look! The waves over there are really big.\"}, {\"original\": \"N\'oubliez pas d\'appliquer de la crème solaire, les rayons UV sont très forts ici.\", \"translated\": \"Remember to apply sunscreen, the UV rays here are very strong.\"}, {\"original\": \"Le sable de cette plage est tellement fin qu’on a l’impression de marcher sur du coton.\", \"translated\": \"The sand on this beach is so fine, it feels like stepping on cotton.\"}, {\"original\": \"Et si on jouait au volley-ball sur la plage ?\", \"translated\": \"How about playing volleyball on the beach?\"}, {\"original\": \"Les voiliers au loin sont magnifiques.\", \"translated\": \"The sailboats in the distance look beautiful.\"}, {\"original\": \"L’eau est si claire ici qu’on peut même voir les poissons.\", \"translated\": \"The water here is so clear, you can even see the fish.\"}, {\"original\": \"Allons chercher des coquillages !\", \"translated\": \"Let\'s go find some seashells.\"}, {\"original\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\", \"translated\": \"Taking a walk on the beach at sunset must be very romantic.\"}, {\"original\": \"J’ai entendu dire que les fruits de mer sont très frais ici, allons-en goûter !\", \"translated\": \"I heard the seafood here is very fresh, let\'s go try some.\"}, {\"original\": \"La marée monte, retournons vers la rive.\", \"translated\": \"The tide is coming in, let\'s head towards the shore.\"}]', 9, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je pourrais utiliser lors d’événements et de fêtes locaux ?\", \"Génial ! Voici 10 expressions courantes sur les événements et fêtes locaux, avec leur traduction en anglais :\"]', '[\"Participer à une activité\", \"Célébrer une fête\", \"Découvrir la culture\"]', 'fr', '[\"Pour l\'instant, pourriez-vous me préciser le contexte de l’événement ou de la fête locale à laquelle vous participez — par exemple Halloween, un concert, une soirée entre amis ou autre chose ? Veuillez indiquer ce contexte.\", \"Veuillez décrire les activités qui vous viennent à l’esprit.\"]', '[\"Avez-vous une situation précise en tête ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Y a-t-il des événements aujourd\'hui ?\", \"translated\": \"Are there any events today?\"}, {\"original\": \"Y a-t-il quelque chose de particulier à propos de ce festival ?\", \"translated\": \"Is there anything special about this festival?\"}, {\"original\": \"Où se déroule la célébration ?\", \"translated\": \"Where is the celebration being held?\"}, {\"original\": \"Comment puis-je acheter des billets ?\", \"translated\": \"How can I buy tickets?\"}, {\"original\": \"À quelle heure commence le spectacle ?\", \"translated\": \"What time does the performance start?\"}, {\"original\": \"Quels sont les plats traditionnels proposés ?\", \"translated\": \"What traditional food is there?\"}, {\"original\": \"C\'est vraiment animé ici !\", \"translated\": \"It\'s really lively here.\"}, {\"original\": \"Y a-t-il des activités folkloriques ?\", \"translated\": \"Are there any folk activities?\"}, {\"original\": \"Joyeuses fêtes !\", \"translated\": \"Happy holidays!\"}, {\"original\": \"À quelle heure se termine l\'événement ?\", \"translated\": \"What time does the event end?\"}]', 10, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans un musée ou une galerie d\'art ?\", \"Génial ! Voici 10 expressions courantes liées aux musées et galeries d\'art, avec leur traduction en anglais :\"]', '[\"Visite\", \"Visite guidée\", \"Achat de billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête — par exemple demander une notice explicative, des phrases utiles pour suivre un parcours, ou des formulations pour commenter une œuvre ? N\'hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Quel est le prix d\'entrée ?\", \"translated\": \"How much is the admission fee?\"}, {\"original\": \"Proposez-vous des audioguides ?\", \"translated\": \"Do you have audio guides?\"}, {\"original\": \"Qui est l\'auteur de cette œuvre ?\", \"translated\": \"Who created this artwork?\"}, {\"original\": \"Où se trouve la pièce la plus précieuse du musée ?\", \"translated\": \"Where is the museum\'s most prized piece?\"}, {\"original\": \"La prise de photos est-elle autorisée ?\", \"translated\": \"Is photography allowed?\"}, {\"original\": \"Y a-t-il des expositions temporaires en cours ?\", \"translated\": \"Are there any special exhibitions here?\"}, {\"original\": \"Combien de temps dure la visite ?\", \"translated\": \"How long does the visit take?\"}, {\"original\": \"Pourriez-vous nous présenter brièvement la collection ?\", \"translated\": \"Could you give us an introduction?\"}, {\"original\": \"Ces œuvres sont vraiment remarquables.\", \"translated\": \"These works are truly exquisite.\"}, {\"original\": \"Où se trouve la boutique de souvenirs ?\", \"translated\": \"Where is the souvenir shop?\"}]', 11, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans un café ?\", \"Super ! Voici 10 expressions courantes liées au café, avec leur traduction en anglais :\"]', '[\"commander du café\", \"se détendre\", \"socialiser\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander la carte, des boissons glacées ou chaudes, d\'autres produits ? N\'hésitez pas à demander !\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Je vais prendre un latte, s\'il vous plaît.\", \"translated\": \"I\'ll have a latte, please.\"}, {\"original\": \"Vous avez du Wi-Fi ?\", \"translated\": \"Do you have Wi-Fi?\"}, {\"original\": \"Pourriez-vous me montrer la carte, s\'il vous plaît ?\", \"translated\": \"Could I see the menu, please?\"}, {\"original\": \"Est-ce que les recharges sont autorisées ?\", \"translated\": \"Are refills allowed?\"}, {\"original\": \"Mon café est-il prêt ?\", \"translated\": \"Is my coffee ready?\"}, {\"original\": \"Combien de temps puis-je rester assis ici ?\", \"translated\": \"How long can I sit here?\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"L\'addition, s\'il vous plaît. Merci.\", \"translated\": \"Check, please. Thank you.\"}, {\"original\": \"C\'est vraiment délicieux.\", \"translated\": \"It tastes really good.\"}]', 12, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use in a restaurant?\", \"Great! Here are 10 common restaurant phrases, with Arabic translations:\"]', '[\"Dining\", \"Ordering\", \"Paying the bill\"]', 'en', '[\"For now, do you have a specific situation in mind, like ordering drinks, making a complaint, or asking about ingredients? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Excuse me, how much longer will our food be?\", \"translated\": \"عذرًا، كم من الوقت ستستغرق وجبتنا بعد؟\"}, {\"original\": \"A table for two, please.\", \"translated\": \"طاولة لشخصين، من فضلكم.\"}, {\"original\": \"Could we see the menu, please?\", \"translated\": \"هل يمكننا الاطلاع على القائمة، من فضلكم؟\"}, {\"original\": \"Do you have any signature dishes to recommend?\", \"translated\": \"هل لديكم أي أطباق مميزة تودون التوصية بها؟\"}, {\"original\": \"I\'d like to order this, and this.\", \"translated\": \"أود طلب هذا وهذا.\"}, {\"original\": \"A glass of water, please. Thanks.\", \"translated\": \"كوب ماء، من فضلكم. شكرًا.\"}, {\"original\": \"The bill, please.\", \"translated\": \"الفاتورة، من فضلكم.\"}, {\"original\": \"Can I pay by credit card?\", \"translated\": \"هل يمكنني الدفع باستخدام بطاقة الائتمان؟\"}, {\"original\": \"Could you pack this to go, please?\", \"translated\": \"هل يمكنكم تغليف هذا لأخذها معنا، من فضلكم؟\"}, {\"original\": \"The food was delicious, thank you.\", \"translated\": \"كانت الوجبة لذيذة جدًّا، شكرًا لكم.\"}]', 1, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at the hotel?\", \"Great! Here are 10 common hotel-related phrases, with Arabic translations:\"]', '[\"Check-in\", \"Check-out\", \"Room service\"]', 'en', '[\"For now, do you have a specific situation in mind, like room location, any other hotel service, or check-out? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Hello, I have a reservation, Here is my passport.\", \"translated\": \"مرحبًا، لدي حجزٌ، وهذه جواز سفري.\"}, {\"original\": \"Do you have any vacancies?\", \"translated\": \"هل لديكم غرف شاغرة؟\"}, {\"original\": \"Excuse me, does the hotel have a gym or a laundry room?\", \"translated\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسل الملابس؟\"}, {\"original\": \"What time does breakfast start?\", \"translated\": \"في أي وقت تبدأ وجبة الإفطار؟\"}, {\"original\": \"Could I have a room key, please?\", \"translated\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\"}, {\"original\": \"Could you help me take my luggage to the room?\", \"translated\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\"}, {\"original\": \"How do I call room service?\", \"translated\": \"كيف أطلب خدمة الغرف؟\"}, {\"original\": \"What time is check-out?\", \"translated\": \"في أي وقت تتم عملية تسجيل المغادرة؟\"}, {\"original\": \"Could you write me a receipt/invoice?\", \"translated\": \"هل يمكنكم إعطائي إيصالاً/فاتورةً، من فضلكم؟\"}, {\"original\": \"Can I leave my luggage here?\", \"translated\": \"هل يمكنني ترك أمتعتي هنا؟\"}]', 2, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at the airport?\", \"Awesome! Here are 10 common airport-related phrases, with Arabic translations:\"]', '[\"Check-in\", \"Boarding\", \"Baggage Check\"]', 'en', '[\"For now, do you have a specific situation in mind, like check-in, baggage claim, or car rental service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Where is the check-in counter?\", \"translated\": \"أين مكتب تسجيل الوصول؟\"}, {\"original\": \"I\'d like a window seat, please.\", \"translated\": \"أود مقعدًا بجوار النافذة، من فضلك.\"}, {\"original\": \"Is this flight delayed?\", \"translated\": \"هل هذا الرحلة مؤجلة؟\"}, {\"original\": \"I need to check this baggage.\", \"translated\": \"أحتاج إلى تسجيل هذه الأمتعة.\"}, {\"original\": \"Where is the boarding gate?\", \"translated\": \"أين بوابة الصعود للطائرة؟\"}, {\"original\": \"The plane is about to take off.\", \"translated\": \"الطائرة على وشك الإقلاع.\"}, {\"original\": \"Do I need to take out my laptop and power bank?\", \"translated\": \"هل يجب أن أخرج جهازي اللوحي والبنك المحمول للطاقة؟\"}, {\"original\": \"Where is the duty-free shop?\", \"translated\": \"أين متجر التجزئة المعفي من الرسوم الجمركية؟\"}, {\"original\": \"I can\'t find my suitcase.\", \"translated\": \"لا أستطيع العثور على حقيبتي.\"}, {\"original\": \"Do you have a wheelchair service?\", \"translated\": \"هل تقدمون خدمة الكرسي المتحرك؟\"}]', 3, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you give me 10 common phrases I can use on public transportation?\", \"Great! Here are 10 common public transportation phrases, with Arabic translations:\"]', '[\"Riding\", \"Buying tickets\", \"Transferring\"]', 'en', '[\"For now, do you have a specific situation in mind—like asking about the bus stop, ticket price, or getting off? Feel free to ask!\", \"Please describe the situation you have in mind.\"]', '[]', '[{\"original\": \"Does this bus go to the terminal?\", \"translated\": \"هل هذه الحافلة تذهب إلى المحطة؟\"}, {\"original\": \"What is the next stop?\", \"translated\": \"ما هي المحطة التالية؟\"}, {\"original\": \"Where can I buy a ticket?\", \"translated\": \"أين يمكنني شراء تذكرة؟\"}, {\"original\": \"One ticket to XX, please.\", \"translated\": \"تذكرة واحدة إلى XX، من فضلك.\"}, {\"original\": \"Do I need to transfer?\", \"translated\": \"هل عليّ التنقل إلى حافلة أو قطار آخر؟\"}, {\"original\": \"How long until the next subway train?\", \"translated\": \"كم وقتًا باقٍ حتى القطار التالي في المترو؟\"}, {\"original\": \"Excuse me, please let me pass.\", \"translated\": \"عذرًا، من فضلك اسمح لي بالمرور.\"}, {\"original\": \"Is this seat taken?\", \"translated\": \"هل هذا المقعد مشغول؟\"}, {\"original\": \"Excuse me, where can I transfer to Line 2 to get to XX?\", \"translated\": \"عذرًا، أين يمكنني التنقل إلى الخط 2 للوصول إلى XX؟\"}, {\"original\": \"How do I get to XX?\", \"translated\": \"كيف أصل إلى XX؟\"}]', 4, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at tourist attractions?\", \"Awesome! Here are 10 common phrases for tourist attractions, with Arabic translations:\"]', '[\"sightseeing\", \"taking photos\", \"buying tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking about ticket price, finding a parking lot, or tour guide service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"How much is the entrance fee?\", \"translated\": \"كم تكلفة رسوم الدخول؟\"}, {\"original\": \"Are there student tickets available?\", \"translated\": \"هل تتوفر تذاكر للطلاب؟\"}, {\"original\": \"What time does the attraction open?\", \"translated\": \"في أي وقت تفتح هذه الوجهة السياحية؟\"}, {\"original\": \"What are the fun things to do here?\", \"translated\": \"ما الأشياء الممتعة التي يمكن فعلها هنا؟\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"هل يمكنك أخذ صورة لنا؟\"}, {\"original\": \"Where is the sightseeing bus?\", \"translated\": \"أين حافلة الجولات السياحية؟\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"أين الحمام؟\"}, {\"original\": \"Where is the best viewing spot?\", \"translated\": \"أين أفضل مكان لمشاهدة المنظر؟\"}, {\"original\": \"The scenery here is beautiful.\", \"translated\": \"المنظر هنا جميل جدًا.\"}, {\"original\": \"Is there a guided tour available?\", \"translated\": \"هل توجد جولة إرشادية متاحة؟\"}]', 5, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use for taxis or taxi services?\", \"Great! Here are 10 common taxi-related phrases, with Arabic translations:\"]', '[\"Call a taxi\", \"Tell the destination\", \"Pay\"]', 'en', '[\"Your ride is almost over — is there anything else I can help with? For example: checking the estimated fare, requesting an e-receipt, confirming the payment method, or finding contact info for lost items — feel free to ask!\", \"Please describe the scenario you have in mind.\"]', '[]', '[{\"original\": \"Where can I get a taxi?\", \"translated\": \"أين يمكنني أن أجد تاكسيًا؟\"}, {\"original\": \"Please take me to this address.\", \"translated\": \"من فضلك خذني إلى هذا العنوان.\"}, {\"original\": \"Roughly how much will it be?\", \"translated\": \"كم سيكون المبلغ تقريبًا؟\"}, {\"original\": \"Could you use the meter, please?\", \"translated\": \"هل يمكنك تشغيل العداد من فضلك؟\"}, {\"original\": \"Please drive a bit faster, I\'m in a hurry.\", \"translated\": \"من فضلك ا-driving بسرعة أكبر قليلًا، فأنا مستعجل.\"}, {\"original\": \"Please stop here.\", \"translated\": \"من فضلك توقف هنا.\"}, {\"original\": \"Can I pay with Alipay?\", \"translated\": \"هل يمكنني الدفع عبر علي باي؟\"}, {\"original\": \"Could I have a receipt, please?\", \"translated\": \"هل يمكنني الحصول على إيصال، من فضلك؟\"}, {\"original\": \"Thank you, driver.\", \"translated\": \"شكرًا لك يا سائق.\"}, {\"original\": \"How much further is it?\", \"translated\": \"كم تبقى من المسافة؟\"}]', 6, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a pharmacy?\", \"Great! Here are 10 common pharmacy-related phrases, with Arabic translations:\"]', '[\"buy medicine\", \"ask for advice\", \"pay\"]', 'en', '[\"For now, do you have a specific situation in your mind, like asking for instructions on taking medicine, phrases related to using insurance, duration of medication? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Do you have cold medicine?\", \"translated\": \"هل لديكم دواء لنزلات البرد؟\"}, {\"original\": \"How should I take this medicine?\", \"translated\": \"كيف يجب أن آخذ هذا الدواء؟\"}, {\"original\": \"Do you have any painkillers?\", \"translated\": \"هل لديكم مسكنات للألم؟\"}, {\"original\": \"Is there an instruction leaflet?\", \"translated\": \"هل توجد نشرة إرشادات مع العبوة؟\"}, {\"original\": \"Does this medicine have any side effects?\", \"translated\": \"هل لهذا الدواء أي آثار جانبية؟\"}, {\"original\": \"Can I use my medical insurance card?\", \"translated\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\"}, {\"original\": \"Could I have a box of Band-Aids, please?\", \"translated\": \"هل يمكنني الحصول على علبة من لاصقات الجروح (باند-إيد)، من فضلكم؟\"}, {\"original\": \"Do you have any fever reducers?\", \"translated\": \"هل لديكم خافضات للحرارة؟\"}, {\"original\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\", \"translated\": \"لدي جرح سطحي بسيط. هل لديكم مطهر ولصقات جروح (باند-إيد)؟\"}, {\"original\": \"What time do you close?\", \"translated\": \"في أي وقت تغلقون المتجر؟\"}]', 7, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use when contacting emergency services?\", \"Great! Here are 10 common emergency service phrases, with Arabic translations:\"]', '[\"Call the police\", \"Medical emergency\", \"Ask for help\"]', 'en', '[\"For now, do you have a specific emergency situation in mind, like fire, injured and need help, emergency call — feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Please help me call an ambulance.\", \"translated\": \"من فضلك ساعدني في الاتصال بالإسعاف.\"}, {\"original\": \"Where is the hospital?\", \"translated\": \"أين находится المستشفى؟\"}, {\"original\": \"Someone is injured.\", \"translated\": \"شخص ما أُصيب.\"}, {\"original\": \"Please help me.\", \"translated\": \"من فضلك ساعدني.\"}, {\"original\": \"Where is the police station?\", \"translated\": \"أين находится قسم الشرطة؟\"}, {\"original\": \"I\'ve lost my belongings.\", \"translated\": \"لقد فقدت أغراضي.\"}, {\"original\": \"What is the number for the fire department?\", \"translated\": \"ما هو رقم إدارة الإطفاء؟\"}, {\"original\": \"I\'ve lost my passport. Do you know where the nearest police station is?\", \"translated\": \"لقد فقدت جواز سفري. هل تعرف أين يقع أقرب قسم شرطة؟\"}, {\"original\": \"Is there an emergency exit?\", \"translated\": \"هل يوجد مخرج طوارئ؟\"}, {\"original\": \"Someone has fainted.\", \"translated\": \"شخص ما أُغمي عليه.\"}]', 8, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at the beach or by the pool?\", \"Awesome! Here are 10 common beach- or pool-related phrases, with Arabic translations:\"]', '[\"swimming and playing in the water\", \"sunbathing\", \"beach sports\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you’re attending—such as a cultural festival, food festival, or music festival? Please provide the context.\", \"Please provide the activities that you’re attending.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation you have in mind.\"]', '[{\"original\": \"Look! The waves over there are really big.\", \"translated\": \"انظر! الأمواج هناك كبيرة جدًا.\"}, {\"original\": \"Remember to apply sunscreen, the UV rays here are very strong.\", \"translated\": \"تذكَّر أن تضع واقي الشمس، لأن أشعة فوق البنفسجية هنا قوية جدًا.\"}, {\"original\": \"The sand on this beach is so fine, it feels like stepping on cotton.\", \"translated\": \"الرمال على هذه الشاطئ ناعمة جدًا لدرجة أن المشي عليها يشبه المشي على القطن.\"}, {\"original\": \"How about playing volleyball on the beach?\", \"translated\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\"}, {\"original\": \"The sailboats in the distance look beautiful.\", \"translated\": \"القوارب الشراعية في الأفق تبدو جميلة جدًا.\"}, {\"original\": \"The water here is so clear, you can even see the fish.\", \"translated\": \"الماء هنا صافٍ جدًا لدرجة أنك تستطيع رؤية الأسماك بوضوح.\"}, {\"original\": \"Let\'s go find some seashells.\", \"translated\": \"هيا نذهب للبحث عن بعض قواقع البحر.\"}, {\"original\": \"Taking a walk on the beach at sunset must be very romantic.\", \"translated\": \"التنزه على الشاطئ عند غروب الشمس يجب أن يكون أمرًا رومانسيًّا جدًا.\"}, {\"original\": \"I heard the seafood here is very fresh, let\'s go try some.\", \"translated\": \"سمعت أن المأكولات البحرية هنا طازجة جدًا، فلنشرع في تذوُّق بعضها.\"}, {\"original\": \"The tide is coming in, let\'s head towards the shore.\", \"translated\": \"المد قادم، فلنعد نحو اليابسة.\"}]', 9, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use for local events and festivals?\", \"Awesome! Here are 10 common phrases about local events and festivals, with Arabic translations:\"]', '[\"Attend an event\", \"Celebrate a festival\", \"Learn about culture\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you\'re attending — like Halloween, a concert, a friend\'s party, or something else? Please provide the context.\", \"Please describe the activities in your mind.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[{\"original\": \"Are there any events today?\", \"translated\": \"هل توجد أي فعاليات اليوم؟\"}, {\"original\": \"Is there anything special about this festival?\", \"translated\": \"هل هناك شيءٌ مميزٌ في هذه المهرجان؟\"}, {\"original\": \"Where is the celebration being held?\", \"translated\": \"أين تُقام الاحتفالية؟\"}, {\"original\": \"How can I buy tickets?\", \"translated\": \"كيف يمكنني شراء التذاكر؟\"}, {\"original\": \"What time does the performance start?\", \"translated\": \"في أي وقت تبدأ العروض؟\"}, {\"original\": \"What traditional food is there?\", \"translated\": \"ما الأطعمة التقليدية المتوفرة؟\"}, {\"original\": \"It\'s really lively here.\", \"translated\": \"المكان مليء بالحيوية حقًا!\"}, {\"original\": \"Are there any folk activities?\", \"translated\": \"هل توجد أنشطة شعبية؟\"}, {\"original\": \"Happy holidays!\", \"translated\": \"أعياد سعيدة!\"}, {\"original\": \"What time does the event end?\", \"translated\": \"في أي وقت تنتهي الفعالية؟\"}]', 10, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a museum or art gallery?\", \"Great! Here are 10 common museum or art gallery phrases, with Arabic translations:\"]', '[\"Visit\", \"Guided Tour\", \"Purchase Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for an introduction manual, phrases related to a roadmap, phrases related to commenting on exhibits? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"How much is the admission fee?\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"Do you have audio guides?\", \"translated\": \"هل لديكم أجهزة توجيه صوتية؟\"}, {\"original\": \"Who created this artwork?\", \"translated\": \"من صنع هذه القطعة الفنية؟\"}, {\"original\": \"Where is the museum\'s most prized piece?\", \"translated\": \"أين تقع أثمن قطعة في المتحف؟\"}, {\"original\": \"Is photography allowed?\", \"translated\": \"هل يسمح بالتقاط الصور؟\"}, {\"original\": \"Are there any special exhibitions here?\", \"translated\": \"هل توجد معارض خاصة هنا؟\"}, {\"original\": \"How long does the visit take?\", \"translated\": \"كم يستغرق الجولة؟\"}, {\"original\": \"Could you give us an introduction?\", \"translated\": \"هل يمكنك أن تقدّم لنا مقدمةً؟\"}, {\"original\": \"These works are truly exquisite.\", \"translated\": \"هذه الأعمال رائعةٌ حقًّا.\"}, {\"original\": \"Where is the souvenir shop?\", \"translated\": \"أين تقع متجر التذكارات؟\"}]', 11, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a café?\", \"That\'s great! Here are 10 common café-related phrases, with Arabic translations:\"]', '[\"Ordering coffee\", \"Relaxing\", \"Socializing\"]', 'en', '[\"For now, do you have a specific situation in mind—like asking for a menu, ice or hot drinks, other products? Feel free to ask!\", \"Please describe the situation you have in mind.\"]', '[]', '[{\"original\": \"I\'ll have a latte, please.\", \"translated\": \"سآخذ لاتيه، من فضلك.\"}, {\"original\": \"Do you have Wi-Fi?\", \"translated\": \"هل لديكم اتصال واي فاي؟\"}, {\"original\": \"Could I see the menu, please?\", \"translated\": \"هل يمكنني رؤية القائمة، من فضلك؟\"}, {\"original\": \"Are refills allowed?\", \"translated\": \"هل يُسمح بإعادة الملء؟\"}, {\"original\": \"Is my coffee ready?\", \"translated\": \"هل قهدي جاهزة الآن؟\"}, {\"original\": \"How long can I sit here?\", \"translated\": \"كم من الوقت يمكنني الجلوس هنا؟\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"هل يمكنك التقاط صورة لنا؟\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"أين الحمام؟\"}, {\"original\": \"Check, please. Thank you.\", \"translated\": \"الفاتورة من فضلك. شكرًا لك.\"}, {\"original\": \"It tastes really good.\", \"translated\": \"طعمها لذيذٌ جدًّا.\"}]', 12, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser à l\'hôtel ?\", \"Génial ! Voici 10 expressions courantes liées à l\'hôtel, avec leur traduction en arabe :\"]', '[\"Enregistrement\", \"Départ\", \"Service en chambre\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple l\'emplacement de la chambre, d\'autres services hôteliers ou le départ ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Bonjour, j\'ai une réservation. Voici mon passeport.\", \"translated\": \"مرحبًا، لدي حجز. إليكم جواز سفري.\"}, {\"original\": \"Avez-vous des chambres disponibles ?\", \"translated\": \"هل لديكم غرف شاغرة؟\"}, {\"original\": \"Excusez-moi, l\'hôtel dispose-t-il d\'une salle de sport ou d\'une buanderie ?\", \"translated\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسل الملابس؟\"}, {\"original\": \"À quelle heure commence le petit-déjeuner ?\", \"translated\": \"في أي وقت يبدأ الإفطار؟\"}, {\"original\": \"Pourrais-je avoir la clé de ma chambre, s\'il vous plaît ?\", \"translated\": \"هل يمكنني الحصول على مفتاح غرفتي، من فضلكم؟\"}, {\"original\": \"Pourriez-vous m\'aider à porter mes bagages jusqu\'à ma chambre ?\", \"translated\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى غرفتي؟\"}, {\"original\": \"Comment puis-je contacter le service en chambre ?\", \"translated\": \"كيف يمكنني الاتصال بخدمة الغرف؟\"}, {\"original\": \"À quelle heure doit-on quitter la chambre ?\", \"translated\": \"في أي وقت يجب أن نغادر الغرفة؟\"}, {\"original\": \"Pourriez-vous me faire un reçu / une facture ?\", \"translated\": \"هل يمكنكم إعطائي إيصالًا / فاتورة؟\"}, {\"original\": \"Puis-je laisser mes bagages ici ?\", \"translated\": \"هل يمكنني ترك أمتعتي هنا؟\"}]', 2, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\" pouvez-vous me fournir 10 expressions courantes que je peux utiliser à l\'aéroport ?\", \"Génial ! Voici 10 expressions courantes liées à l\'aéroport, avec leur traduction en arabe :\"]', '[\"Enregistrement\", \"Embarquement\", \"Enregistrement des bagages\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, comme l\'enregistrement, le retrait des bagages ou la location de voiture ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Où se trouve le comptoir d\'enregistrement ?\", \"translated\": \"أين مكان كاونتر تسجيل الوصول؟\"}, {\"original\": \"Je voudrais un siège côté hublot, s\'il vous plaît.\", \"translated\": \"أرغب في مقعد بجانب النافذة، من فضلكم.\"}, {\"original\": \"Ce vol est-il retardé ?\", \"translated\": \"هل هذا الرحلة مؤجلة؟\"}, {\"original\": \"Je dois enregistrer ce bagage.\", \"translated\": \"يجب أن أُسجِّل هذه الأمتعة.\"}, {\"original\": \"Où se trouve la porte d\'embarquement ?\", \"translated\": \"أين باب الصعود إلى الطائرة؟\"}, {\"original\": \"L\'avion va bientôt décoller.\", \"translated\": \"الطائرية على وشك الإقلاع.\"}, {\"original\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\", \"translated\": \"هل يجب أن أخرج حاسوبي المحمول ومحرّكي الطاقة الخارجي؟\"}, {\"original\": \"Où se trouve la boutique hors taxes ?\", \"translated\": \"أين تقع متجر التخفيضات الجمركية؟\"}, {\"original\": \"Je ne trouve pas ma valise.\", \"translated\": \"لا أجد حقيبتي.\"}, {\"original\": \"Proposez-vous un service de fauteuil roulant ?\", \"translated\": \"هل تقدمون خدمة الكرسي المتحرك؟\"}]', 3, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans les transports en commun ?\", \"Génial ! En voici 10 expressions utiles pour les transports en commun, avec leur traduction en arabe :\"]', '[\"Prendre les transports en commun\", \"Acheter un billet\", \"Changer de ligne ou de moyen de transport\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête ? Par exemple, demander où est l’arrêt de bus, le prix du billet ou comment descendre — n\'hésitez pas à me le dire.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Ce bus va-t-il jusqu\'à la gare routière ?\", \"translated\": \"هل تذهب هذه الحافلة إلى المحطة؟\"}, {\"original\": \"Quel est le prochain arrêt ?\", \"translated\": \"ما هو المحطة التالية؟\"}, {\"original\": \"Où puis-je acheter un billet ?\", \"translated\": \"أين يمكنني شراء تذكرة؟\"}, {\"original\": \"Un billet pour XX, s\'il vous plaît.\", \"translated\": \"تذكرة واحدة إلى XX، من فضلكم.\"}, {\"original\": \"Dois-je changer de transport ?\", \"translated\": \"هل يجب أن أنتقل إلى وسيلة نقل أخرى؟\"}, {\"original\": \"Dans combien de temps arrive le prochain métro ?\", \"translated\": \"كم من الوقت يبقى حتى يصل قطار المترو التالي؟\"}, {\"original\": \"Excusez-moi, je dois passer.\", \"translated\": \"عذراً، يُرجى التفضل بالتنحّي.\"}, {\"original\": \"Cette place est-elle occupée ?\", \"translated\": \"هل هذا المقعد مشغول؟\"}, {\"original\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d\'aller à XX ?\", \"translated\": \"عذراً، أين يمكنني الانتقال إلى الخط 2 للوصول إلى XX؟\"}, {\"original\": \"Comment puis-je me rendre à XX ?\", \"translated\": \"كيف يمكنني الوصول إلى XX؟\"}]', 4, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser sur un site touristique ?\", \"Super ! Voici 10 expressions courantes liées aux sites touristiques, avec leur traduction en arabe :\"]', '[\"Visite touristique\", \"Prendre une photo\", \"Acheter des billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander le prix des billets, trouver un parking ou un service de guide touristique ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Quel est le prix de l\'entrée ?\", \"translated\": \"كم سعر رسوم الدخول؟\"}, {\"original\": \"Y a-t-il des billets étudiants disponibles ?\", \"translated\": \"هل توجد تذاكر مخصصة للطلاب؟\"}, {\"original\": \"À quelle heure l\'attraction ouvre-t-elle ?\", \"translated\": \"في أي وقت يفتح موقع الجذب؟\"}, {\"original\": \"Quelles sont les activités amusantes à faire ici ?\", \"translated\": \"ما الأنشطة الممتعة التي يمكن القيام بها هنا؟\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"هل يمكنك أن تلتقط لنا صورة؟\"}, {\"original\": \"Où se trouve le bus touristique ?\", \"translated\": \"أين يوجد الحافلة السياحية؟\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"أين تقع دورات المياه؟\"}, {\"original\": \"Où est le meilleur point de vue ?\", \"translated\": \"ما هو أفضل مكان لالتقاط المنظر؟\"}, {\"original\": \"Le paysage est magnifique ici.\", \"translated\": \"المنظر هنا جميل جدًّا.\"}, {\"original\": \"Une visite guidée est-elle disponible ?\", \"translated\": \"هل تتوفر جولة إرشادية؟\"}]', 5, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser pour prendre un taxi ou utiliser un service de taxi ?\", \"Génial ! Voici 10 expressions courantes liées aux taxis ou aux services de taxi, avec leur traduction en arabe :\"]', '[\"Prendre un taxi\", \"Indiquer la destination\", \"Payer\"]', 'fr', '[\"Le trajet touche à sa fin : y a-t-il quelque chose dont je peux vous aider ? Par exemple, consulter l’estimation du coût, demander une facture électronique, confirmer le mode de paiement ou obtenir les coordonnées pour signaler un objet perdu — n’hésitez pas à demander quoi que ce soit !\", \"Décrivez-moi la situation telle que vous l’imaginez.\"]', '[]', '[{\"original\": \"Où puis-je prendre un taxi ?\", \"translated\": \"أين يمكنني أخذ تاكسي؟\"}, {\"original\": \"Veuillez me conduire à cette adresse.\", \"translated\": \"من فضلك خذني إلى هذا العنوان.\"}, {\"original\": \"Combien cela coûtera-t-il approximativement ?\", \"translated\": \"كم سيكون السعر تقريبًا؟\"}, {\"original\": \"Pourriez-vous utiliser le taximètre, s\'il vous plaît ?\", \"translated\": \"هل يمكنكم تشغيل عداد الأجرة، من فضلكم؟\"}, {\"original\": \"Veuillez conduire un peu plus vite, je suis pressé(e).\", \"translated\": \"من فضلك ا-driving أسرع قليلًا، فأنا مستعجل.\"}, {\"original\": \"Veuillez vous arrêter ici.\", \"translated\": \"من فضلك توقف هنا.\"}, {\"original\": \"Puis-je payer avec Alipay ?\", \"translated\": \"هل يمكنني الدفع عبر «علي بابا باي»؟\"}, {\"original\": \"Pourrais-je avoir un reçu, s\'il vous plaît ?\", \"translated\": \"هل يمكنني الحصول على إشعار دفع، من فضلكم؟\"}, {\"original\": \"Merci, monsieur/madame le chauffeur.\", \"translated\": \"شكراً لك يا سائق التاكسي.\"}, {\"original\": \"Il reste encore combien de temps ?\", \"translated\": \"كم تبقى من الوقت حتى نصل؟\"}]', 6, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser en pharmacie ?\", \"Génial ! Voici 10 expressions courantes liées à la pharmacie, avec leur traduction en arabe :\"]', '[\"Acheter des médicaments\", \"Demander des renseignements\", \"Payer\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander des instructions sur la prise d’un médicament, des formulations liées à l’utilisation de l’assurance maladie ou à la durée du traitement ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Avez-vous des médicaments contre le rhume ?\", \"translated\": \"هل لديكم أدوية لعلاج البرد؟\"}, {\"original\": \"Comment dois-je prendre ce médicament ?\", \"translated\": \"كيف يجب أن آخذ هذا الدواء؟\"}, {\"original\": \"Avez-vous des analgésiques ?\", \"translated\": \"هل لديكم مسكنات للألم؟\"}, {\"original\": \"Y a-t-il une notice d\'utilisation ?\", \"translated\": \"هل توجد نشرة إرشادات الاستخدام؟\"}, {\"original\": \"Ce médicament a-t-il des effets secondaires ?\", \"translated\": \"هل لهذا الدواء أي آثار جانبية؟\"}, {\"original\": \"Puis-je utiliser ma carte d\'assurance maladie ?\", \"translated\": \"هل يمكنني استخدام بطاقتي التأمينية الصحية؟\"}, {\"original\": \"Pourriez-vous me donner une boîte de pansements, s\'il vous plaît ?\", \"translated\": \"هل يمكنكم أن تعطوني علبة من الضمادات، من فضلكم؟\"}, {\"original\": \"Avez-vous des antipyrétiques ?\", \"translated\": \"هل لديكم خافضات للحرارة؟\"}, {\"original\": \"Je me suis un peu écorché(e). Avez-vous un désinfectant et des pansements ?\", \"translated\": \"لقد تعرضتُ لجرح بسيط. هل لديكم مطهر وضمادات؟\"}, {\"original\": \"À quelle heure fermez-vous ?\", \"translated\": \"في أي ساعة تغلقون؟\"}]', 7, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser lors d\'une intervention d\'urgence ?\", \"Génial ! Voici 10 expressions courantes liées aux services d\'urgence, avec leur traduction en arabe :\"]', '[\"Appeler la police\", \"Premiers secours\", \"Demander de l\'aide\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation d\'urgence spécifique en tête, comme un incendie, une personne blessée et nécessitant de l\'aide, ou un appel d\'urgence ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Veuillez m\'aider à appeler une ambulance.\", \"translated\": \"من فضلك ساعدني في الاتصال بالإسعاف.\"}, {\"original\": \"Où se trouve l\'hôpital ?\", \"translated\": \"أين يقع المستشفى؟\"}, {\"original\": \"Quelqu\'un est blessé.\", \"translated\": \"شخص ما أُصيب.\"}, {\"original\": \"Veuillez m\'aider.\", \"translated\": \"من فضلك ساعدني.\"}, {\"original\": \"Où se trouve le commissariat de police ?\", \"translated\": \"أين يقع أقرب قسم شرطة؟\"}, {\"original\": \"J\'ai perdu mes effets personnels.\", \"translated\": \"لقد فقدت أغراضي الشخصية.\"}, {\"original\": \"Quel est le numéro du service d\'incendie ?\", \"translated\": \"ما هو رقم إدارة الإطفاء؟\"}, {\"original\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le commissariat de police le plus proche ?\", \"translated\": \"لقد فقدت جواز سفري. هل تعرف أين يقع أقرب قسم شرطة؟\"}, {\"original\": \"Y a-t-il une sortie de secours ?\", \"translated\": \"هل هناك مخرج طوارئ؟\"}, {\"original\": \"Quelqu\'un s\'est évanoui.\", \"translated\": \"شخص ما فقد وعيه.\"}]', 8, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser à la plage ou au bord de la piscine ?\", \"Super ! Voici 10 expressions courantes liées à la plage ou à la piscine, avec leur traduction en arabe :\"]', '[\"nager et jouer dans l\'eau\", \"prendre un bain de soleil\", \"faire du sport sur la plage\"]', 'fr', '[\"Pour l’instant, pourriez-vous s’il vous plaît me préciser le contexte de l’événement ou du festival local auquel vous comptez assister — par exemple un festival culturel, gastronomique ou musical ? Veuillez fournir ce contexte.\", \"Veuillez décrire les activités auxquelles vous participerez.\"]', '[\"Avez-vous une situation particulière en tête ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\", \"translated\": \"انظر! الأمواج هناك كبيرة جدًا.\"}, {\"original\": \"N\'oubliez pas d\'appliquer de la crème solaire : les rayons UV sont très forts ici.\", \"translated\": \"تذكَّر وضع واقي شمسي، فأشعة فوق البنفسجية هنا قوية جدًا.\"}, {\"original\": \"Le sable de cette plage est si fin qu’on a l’impression de marcher sur du coton.\", \"translated\": \"الرمال على هذه الشاطئ ناعمة للغاية لدرجة أنك تشعر وكأنك تمشي على القطن.\"}, {\"original\": \"Et si on jouait au volley-ball sur la plage ?\", \"translated\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\"}, {\"original\": \"Les voiliers au loin sont magnifiques.\", \"translated\": \"القوارب الشراعية في الأفق تبدو جميلة جدًا.\"}, {\"original\": \"L’eau est tellement claire ici qu’on peut même voir les poissons.\", \"translated\": \"الماء هنا شفافٌ جدًا لدرجة أنك تستطيع رؤية الأسماك بوضوح.\"}, {\"original\": \"Allons chercher des coquillages !\", \"translated\": \"لنذهب نبحث عن أصداف بحرية!\"}, {\"original\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\", \"translated\": \"التنزه على الشاطئ عند غروب الشمس يجب أن يكون أمرًا رومانسيًّا جدًا.\"}, {\"original\": \"J’ai entendu dire que les fruits de mer sont très frais ici, allons-en goûter !\", \"translated\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًا، فلنتناول بعضها!\"}, {\"original\": \"La marée monte, retournons vers la rive.\", \"translated\": \"المدّ يرتفع، فلنعد نحو الساحل.\"}]', 9, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je pourrais utiliser lors d’événements ou de festivals locaux ?\", \"Génial ! En voici 10 expressions courantes sur les événements et festivals locaux, avec leur traduction en arabe :\"]', '[\"Participer à une activité\", \"Célébrer une fête\", \"Découvrir la culture\"]', 'fr', '[\"Pour l’instant, pourriez-vous m’indiquer le contexte de l’événement ou du festival local auquel vous allez participer — par exemple, Halloween, un concert, une fête entre amis, ou autre chose ? Veuillez préciser le contexte.\", \"Veuillez décrire les activités qui vous viennent à l’esprit.\"]', '[\"Avez-vous une situation particulière en tête ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Y a-t-il des événements aujourd\'hui ?\", \"translated\": \"هل توجد أي فعاليات اليوم؟\"}, {\"original\": \"Y a-t-il quelque chose de spécial à propos de ce festival ?\", \"translated\": \"هل هناك شيءٌ مميزٌ حول هذا المهرجان؟\"}, {\"original\": \"Où se déroule la célébration ?\", \"translated\": \"أين تُقام الاحتفالات؟\"}, {\"original\": \"Comment puis-je acheter des billets ?\", \"translated\": \"كيف يمكنني شراء التذاكر؟\"}, {\"original\": \"À quelle heure commence le spectacle ?\", \"translated\": \"في أي وقت يبدأ العرض؟\"}, {\"original\": \"Quels sont les plats traditionnels proposés ?\", \"translated\": \"ما الأطعمة التقليدية المتاحة؟\"}, {\"original\": \"C\'est vraiment animé ici !\", \"translated\": \"المكان نابضٌ بالحياة حقًّا!\"}, {\"original\": \"Y a-t-il des activités folkloriques ?\", \"translated\": \"هل توجد أنشطة تراثية أو شعبية؟\"}, {\"original\": \"Joyeuses fêtes !\", \"translated\": \"أعيادٌ سعيدة!\"}, {\"original\": \"À quelle heure se termine l\'événement ?\", \"translated\": \"في أي وقت تنتهي الفعالية؟\"}]', 10, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pouvez-vous me fournir 10 expressions courantes que je peux utiliser dans un musée ou une galerie d\'art ?\", \"Génial ! Voici 10 expressions courantes liées aux musées et galeries d\'art, avec leur traduction en arabe :\"]', '[\"Visite\", \"Visite guidée\", \"Achat de billets\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander un manuel d’introduction, des expressions liées à un plan de visite, ou des phrases pour commenter une exposition ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Quel est le montant des frais d\'entrée ?\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"Disposez-vous de guides audio ?\", \"translated\": \"هل لديكم أدلة صوتية؟\"}, {\"original\": \"Qui a créé cette œuvre ?\", \"translated\": \"من هو مَن أنشأ هذه القطعة الفنية؟\"}, {\"original\": \"Où se trouve la pièce la plus précieuse du musée ?\", \"translated\": \"أين تقع أثمن قطعة في المتحف؟\"}, {\"original\": \"La photographie est-elle autorisée ?\", \"translated\": \"هل يُسمح بالتقاط الصور؟\"}, {\"original\": \"Y a-t-il des expositions spéciales ici ?\", \"translated\": \"هل توجد هنا أي معارض خاصة؟\"}, {\"original\": \"Combien de temps dure la visite ?\", \"translated\": \"كم يستغرق الجولة من وقت؟\"}, {\"original\": \"Pourriez-vous nous en donner une présentation ?\", \"translated\": \"هل يمكنكم أن تقدّموا لنا عرضًا تعريفيًّا؟\"}, {\"original\": \"Ces œuvres sont vraiment exquises.\", \"translated\": \"هذه الأعمال فعلاً رائعةٌ جدًّا.\"}, {\"original\": \"Où se trouve la boutique de souvenirs ?\", \"translated\": \"أين تقع متجر الهدايا التذكارية؟\"}]', 11, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans un café ?\", \"Génial ! Voici 10 expressions courantes liées au café, accompagnées de leur traduction en arabe :\"]', '[\"commander du café\", \"se reposer\", \"socialiser\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander le menu, des boissons glacées ou chaudes, d\'autres produits ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Je prendrai un latte, s\'il vous plaît.\", \"translated\": \"سآخذ لاتيه، من فضلك.\"}, {\"original\": \"Avez-vous le Wi-Fi ?\", \"translated\": \"هل لديكم اتصال واي فاي؟\"}, {\"original\": \"Pourrais-je voir le menu, s\'il vous plaît ?\", \"translated\": \"هل يمكنني رؤية القائمة، من فضلك؟\"}, {\"original\": \"Est-ce qu\'on peut recharger la boisson ?\", \"translated\": \"هل يُسمح بإعادة التعبئة؟\"}, {\"original\": \"Mon café est-il prêt ?\", \"translated\": \"هل قهوتي جاهزة؟\"}, {\"original\": \"Combien de temps puis-je rester assis ici ?\", \"translated\": \"كم من الوقت يمكنني الجلوس هنا؟\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"هل يمكنك أخذ صورة لنا؟\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"أين الحمام؟\"}, {\"original\": \"L\'addition, s\'il vous plaît. Merci.\", \"translated\": \"الفاتورة، من فضلك. شكرًا لك.\"}, {\"original\": \"C\'est vraiment délicieux.\", \"translated\": \"إنها لذيذة جدًّا.\"}]', 12, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use in a restaurant?\", \"Great! Here are 10 common restaurant phrases, with French translations:\"]', '[\"Dining\", \"Ordering\", \"Paying the bill\"]', 'en', '[\"For now, do you have a specific situation in mind, like ordering drinks, making a complaint, or asking about ingredients? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Excuse me, how much longer will our food be?\", \"translated\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\"}, {\"original\": \"A table for two, please.\", \"translated\": \"Une table pour deux personnes, s’il vous plaît.\"}, {\"original\": \"Could we see the menu, please?\", \"translated\": \"Pourrions-nous voir la carte, s’il vous plaît ?\"}, {\"original\": \"Do you have any signature dishes to recommend?\", \"translated\": \"Avez-vous des plats maison que vous recommandez ?\"}, {\"original\": \"I\'d like to order this, and this.\", \"translated\": \"Je voudrais commander celui-ci et celui-là.\"}, {\"original\": \"A glass of water, please. Thanks.\", \"translated\": \"Un verre d’eau, s’il vous plaît. Merci.\"}, {\"original\": \"The bill, please.\", \"translated\": \"L’addition, s’il vous plaît.\"}, {\"original\": \"Can I pay by credit card?\", \"translated\": \"Puis-je payer par carte bancaire ?\"}, {\"original\": \"Could you pack this to go, please?\", \"translated\": \"Pourriez-vous me l’emballer à emporter, s’il vous plaît ?\"}, {\"original\": \"The food was delicious, thank you.\", \"translated\": \"La nourriture était délicieuse, merci beaucoup.\"}]', 1, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at the hotel?\", \"Great! Here are 10 common hotel-related phrases, with French translations:\"]', '[\"Check-in\", \"Check-out\", \"Room service\"]', 'en', '[\"For now, do you have a specific situation in mind — like room location, other hotel services, or check-out? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Hello, I have a reservation, Here is my passport.\", \"translated\": \"Bonjour, j’ai une réservation. Voici mon passeport.\"}, {\"original\": \"Do you have any vacancies?\", \"translated\": \"Avez-vous des chambres disponibles ?\"}, {\"original\": \"Excuse me, does the hotel have a gym or a laundry room?\", \"translated\": \"Excusez-moi, l’hôtel dispose-t-il d’une salle de sport ou d’une buanderie ?\"}, {\"original\": \"What time does breakfast start?\", \"translated\": \"À quelle heure commence le petit-déjeuner ?\"}, {\"original\": \"Could I have a room key, please?\", \"translated\": \"Pourrais-je avoir la clé de ma chambre, s’il vous plaît ?\"}, {\"original\": \"Could you help me take my luggage to the room?\", \"translated\": \"Pourriez-vous m’aider à monter mes bagages dans ma chambre ?\"}, {\"original\": \"How do I call room service?\", \"translated\": \"Comment puis-je joindre le service d’étage ?\"}, {\"original\": \"What time is check-out?\", \"translated\": \"À quelle heure est le départ ?\"}, {\"original\": \"Could you write me a receipt/invoice?\", \"translated\": \"Pourriez-vous me délivrer un reçu / une facture ?\"}, {\"original\": \"Can I leave my luggage here?\", \"translated\": \"Puis-je laisser mes bagages ici ?\"}]', 2, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at the airport?\", \"Great! Here are 10 common airport phrases, with French translations:\"]', '[\"Check-in\", \"Boarding\", \"Baggage Check\"]', 'en', '[\"For now, do you have a specific situation in mind, like check-in, baggage claim, or car rental service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Where is the check-in counter?\", \"translated\": \"Où se trouve le comptoir d\'enregistrement ?\"}, {\"original\": \"I\'d like a window seat, please.\", \"translated\": \"Je voudrais un siège côté hublot, s\'il vous plaît.\"}, {\"original\": \"Is this flight delayed?\", \"translated\": \"Ce vol est-il retardé ?\"}, {\"original\": \"I need to check this baggage.\", \"translated\": \"Je dois enregistrer ce bagage.\"}, {\"original\": \"Where is the boarding gate?\", \"translated\": \"Où se trouve la porte d\'embarquement ?\"}, {\"original\": \"The plane is about to take off.\", \"translated\": \"L\'avion va bientôt décoller.\"}, {\"original\": \"Do I need to take out my laptop and power bank?\", \"translated\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\"}, {\"original\": \"Where is the duty-free shop?\", \"translated\": \"Où se trouve la boutique hors taxes ?\"}, {\"original\": \"I can\'t find my suitcase.\", \"translated\": \"Je ne retrouve pas ma valise.\"}, {\"original\": \"Do you have a wheelchair service?\", \"translated\": \"Proposez-vous un service de chaise roulante ?\"}]', 3, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use on public transportation?\", \"Awesome! Here are 10 common public transportation phrases, with French translations:\"]', '[\"Riding\", \"Buying tickets\", \"Transferring\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for a bus stop, ticket price, or getting off? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Does this bus go to the terminal?\", \"translated\": \"Est-ce que ce bus va à la gare routière ?\"}, {\"original\": \"What is the next stop?\", \"translated\": \"Quel est le prochain arrêt ?\"}, {\"original\": \"Where can I buy a ticket?\", \"translated\": \"Où puis-je acheter un billet ?\"}, {\"original\": \"One ticket to XX, please.\", \"translated\": \"Un billet pour XX, s’il vous plaît.\"}, {\"original\": \"Do I need to transfer?\", \"translated\": \"Dois-je changer de véhicule ?\"}, {\"original\": \"How long until the next subway train?\", \"translated\": \"Dans combien de temps arrive le prochain métro ?\"}, {\"original\": \"Excuse me, please let me pass.\", \"translated\": \"Excusez-moi, je passe s’il vous plaît.\"}, {\"original\": \"Is this seat taken?\", \"translated\": \"Cette place est-elle prise ?\"}, {\"original\": \"Excuse me, where can I transfer to Line 2 to get to XX?\", \"translated\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d’aller à XX ?\"}, {\"original\": \"How do I get to XX?\", \"translated\": \"Comment puis-je aller à XX ?\"}]', 4, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at tourist attractions?\", \"Awesome! Here are 10 common phrases for tourist attractions, with French translations:\"]', '[\"sightseeing\", \"taking photos\", \"buying tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking about ticket price, finding a parking lot, or tour guide service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"How much is the entrance fee?\", \"translated\": \"Quel est le prix d\'entrée ?\"}, {\"original\": \"Are there student tickets available?\", \"translated\": \"Y a-t-il des billets étudiants disponibles ?\"}, {\"original\": \"What time does the attraction open?\", \"translated\": \"À quelle heure ouvre l\'attraction ?\"}, {\"original\": \"What are the fun things to do here?\", \"translated\": \"Que peut-on faire de sympa ici ?\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"Where is the sightseeing bus?\", \"translated\": \"Où se trouve le bus touristique ?\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"Where is the best viewing spot?\", \"translated\": \"Où est le meilleur point de vue ?\"}, {\"original\": \"The scenery here is beautiful.\", \"translated\": \"Le paysage est magnifique ici.\"}, {\"original\": \"Is there a guided tour available?\", \"translated\": \"Des visites guidées sont-elles proposées ?\"}]', 5, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use for taxis or taxi services?\", \"Great! Here are 10 common taxi-related phrases, with French translations:\"]', '[\"hail a taxi\", \"tell destination\", \"pay\"]', 'en', '[\"We\'re almost at your destination—anything else I can help with? For example, checking the estimated fare, requesting an e-receipt, confirming payment methods, or finding contact info for lost items—feel free to ask!\", \"Please describe the scenario you have in mind.\"]', '[]', '[{\"original\": \"Where can I get a taxi?\", \"translated\": \"Où puis-je prendre un taxi ?\"}, {\"original\": \"Please take me to this address.\", \"translated\": \"Veuillez me conduire à cette adresse.\"}, {\"original\": \"Roughly how much will it be?\", \"translated\": \"Cela coûtera combien environ ?\"}, {\"original\": \"Could you use the meter, please?\", \"translated\": \"Pourriez-vous utiliser le compteur, s\'il vous plaît ?\"}, {\"original\": \"Please drive a bit faster, I\'m in a hurry.\", \"translated\": \"Pourriez-vous rouler un peu plus vite ? Je suis pressé(e).\"}, {\"original\": \"Please stop here.\", \"translated\": \"Veuillez vous arrêter ici.\"}, {\"original\": \"Can I pay with Alipay?\", \"translated\": \"Puis-je payer avec Alipay ?\"}, {\"original\": \"Could I have a receipt, please?\", \"translated\": \"Pourrais-je avoir un reçu, s\'il vous plaît ?\"}, {\"original\": \"Thank you, driver.\", \"translated\": \"Merci, monsieur/madame le chauffeur.\"}, {\"original\": \"How much further is it?\", \"translated\": \"Il reste encore loin ?\"}]', 6, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a pharmacy?\", \"Great! Here are 10 common pharmacy-related phrases, with French translations:\"]', '[\"Buying medicine\", \"Asking for advice\", \"Paying\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for instructions on taking medicine, phrases related to using insurance, or duration of medication? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Do you have cold medicine?\", \"translated\": \"Avez-vous des médicaments contre le rhume ?\"}, {\"original\": \"How should I take this medicine?\", \"translated\": \"Comment dois-je prendre ce médicament ?\"}, {\"original\": \"Do you have any painkillers?\", \"translated\": \"Avez-vous des analgésiques ?\"}, {\"original\": \"Is there an instruction leaflet?\", \"translated\": \"Y a-t-il une notice d’utilisation ?\"}, {\"original\": \"Does this medicine have any side effects?\", \"translated\": \"Ce médicament a-t-il des effets secondaires ?\"}, {\"original\": \"Can I use my medical insurance card?\", \"translated\": \"Puis-je utiliser ma carte d’assurance maladie ?\"}, {\"original\": \"Could I have a box of Band-Aids, please?\", \"translated\": \"Pourriez-vous me donner une boîte de pansements, s’il vous plaît ?\"}, {\"original\": \"Do you have any fever reducers?\", \"translated\": \"Avez-vous des antipyrétiques ?\"}, {\"original\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\", \"translated\": \"J’ai une petite éraflure. Avez-vous un antiseptique et des pansements ?\"}, {\"original\": \"What time do you close?\", \"translated\": \"À quelle heure fermez-vous ?\"}]', 7, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use for emergency services?\", \"Great! Here are 10 common phrases for emergency services, with French translations:\"]', '[\"Call the police\", \"Medical emergency\", \"Ask for help\"]', 'en', '[\"For now, do you have a specific emergency situation in mind, like fire, injured and need help, or emergency call? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Please help me call an ambulance.\", \"translated\": \"Veuillez m\'aider à appeler une ambulance.\"}, {\"original\": \"Where is the hospital?\", \"translated\": \"Où se trouve l\'hôpital ?\"}, {\"original\": \"Someone is injured.\", \"translated\": \"Quelqu\'un est blessé.\"}, {\"original\": \"Please help me.\", \"translated\": \"Aidez-moi, s\'il vous plaît.\"}, {\"original\": \"Where is the police station?\", \"translated\": \"Où se trouve le commissariat de police ?\"}, {\"original\": \"I\'ve lost my belongings.\", \"translated\": \"J\'ai perdu mes affaires.\"}, {\"original\": \"What is the number for the fire department?\", \"translated\": \"Quel est le numéro des pompiers ?\"}, {\"original\": \"I\'ve lost my passport. Do you know where the nearest police station is?\", \"translated\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le commissariat de police le plus proche ?\"}, {\"original\": \"Is there an emergency exit?\", \"translated\": \"Y a-t-il une sortie de secours ?\"}, {\"original\": \"Someone has fainted.\", \"translated\": \"Quelqu\'un s\'est évanoui.\"}]', 8, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at the beach or by the pool?\", \"Great! Here are 10 common beach- or pool-related phrases, with French translations:\"]', '[\"swimming and playing in the water\", \"sunbathing\", \"beach sports\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you’re attending — for example, a cultural festival, food festival, or music festival? Please provide the context.\", \"Please provide the activities that you’re attending.\"]', '[\"Do you have a specific situation in mind? Feel free to ask!\", \"Please describe the situation you have in mind.\"]', '[{\"original\": \"Look! The waves over there are really big.\", \"translated\": \"Regardez ! Les vagues là-bas sont vraiment grosses.\"}, {\"original\": \"Remember to apply sunscreen, the UV rays here are very strong.\", \"translated\": \"N\'oubliez pas d\'appliquer de la crème solaire : les rayons UV sont très forts ici.\"}, {\"original\": \"The sand on this beach is so fine, it feels like stepping on cotton.\", \"translated\": \"Le sable de cette plage est si fin qu’on a l’impression de marcher sur du coton.\"}, {\"original\": \"How about playing volleyball on the beach?\", \"translated\": \"Et si on jouait au volley-ball sur la plage ?\"}, {\"original\": \"The sailboats in the distance look beautiful.\", \"translated\": \"Les voiliers au loin sont magnifiques.\"}, {\"original\": \"The water here is so clear, you can even see the fish.\", \"translated\": \"L’eau est tellement claire ici qu’on peut même voir les poissons.\"}, {\"original\": \"Let\'s go find some seashells.\", \"translated\": \"Allons ramasser des coquillages.\"}, {\"original\": \"Taking a walk on the beach at sunset must be very romantic.\", \"translated\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\"}, {\"original\": \"I heard the seafood here is very fresh, let\'s go try some.\", \"translated\": \"J’ai entendu dire que les fruits de mer sont très frais ici ; allons en goûter !\"}, {\"original\": \"The tide is coming in, let\'s head towards the shore.\", \"translated\": \"La marée monte ; rentrons vers la rive.\"}]', 9, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use for local events and festivals?\", \"Great! Here are 10 common phrases about local events and festivals, with French translations:\"]', '[\"Attend an event\", \"Celebrate a festival\", \"Learn about culture\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you’re attending—for example, Halloween, a concert, a friend’s party, or something else? Please provide the context.\", \"Please describe the activities in your mind.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[{\"original\": \"Are there any events today?\", \"translated\": \"Y a-t-il des événements aujourd\'hui ?\"}, {\"original\": \"Is there anything special about this festival?\", \"translated\": \"Y a-t-il quelque chose de spécial à propos de ce festival ?\"}, {\"original\": \"Where is the celebration being held?\", \"translated\": \"Où se déroule la célébration ?\"}, {\"original\": \"How can I buy tickets?\", \"translated\": \"Comment puis-je acheter des billets ?\"}, {\"original\": \"What time does the performance start?\", \"translated\": \"À quelle heure commence la représentation ?\"}, {\"original\": \"What traditional food is there?\", \"translated\": \"Quels sont les plats traditionnels proposés ?\"}, {\"original\": \"It\'s really lively here.\", \"translated\": \"C\'est vraiment animé ici.\"}, {\"original\": \"Are there any folk activities?\", \"translated\": \"Y a-t-il des activités populaires ou traditionnelles ?\"}, {\"original\": \"Happy holidays!\", \"translated\": \"Joyeuses fêtes !\"}, {\"original\": \"What time does the event end?\", \"translated\": \"À quelle heure se termine l\'événement ?\"}]', 10, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a museum or art gallery?\", \"Great! Here are 10 common museum or art gallery phrases, with French translations:\"]', '[\"Visit\", \"Guided tour\", \"Ticket purchase\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for an introduction manual, phrases related to a roadmap, phrases related to commenting on exhibits? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"How much is the admission fee?\", \"translated\": \"Quel est le montant des frais d\'entrée ?\"}, {\"original\": \"Do you have audio guides?\", \"translated\": \"Proposez-vous des audioguides ?\"}, {\"original\": \"Who created this artwork?\", \"translated\": \"Qui est l\'auteur de cette œuvre ?\"}, {\"original\": \"Where is the museum\'s most prized piece?\", \"translated\": \"Où se trouve la pièce la plus précieuse du musée ?\"}, {\"original\": \"Is photography allowed?\", \"translated\": \"La prise de photos est-elle autorisée ?\"}, {\"original\": \"Are there any special exhibitions here?\", \"translated\": \"Y a-t-il des expositions temporaires ici ?\"}, {\"original\": \"How long does the visit take?\", \"translated\": \"Combien de temps dure la visite ?\"}, {\"original\": \"Could you give us an introduction?\", \"translated\": \"Pourriez-vous nous faire une présentation ?\"}, {\"original\": \"These works are truly exquisite.\", \"translated\": \"Ces œuvres sont vraiment remarquables.\"}, {\"original\": \"Where is the souvenir shop?\", \"translated\": \"Où se trouve la boutique de souvenirs ?\"}]', 11, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use in a café?\", \"Awesome! Here are 10 common café-related phrases, with French translations:\"]', '[\"Order coffee\", \"Take a break\", \"Socialize\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for a menu, ice or hot drinks, other products? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"I\'ll have a latte, please.\", \"translated\": \"Je prendrai un latte, s\'il vous plaît.\"}, {\"original\": \"Do you have Wi-Fi?\", \"translated\": \"Vous avez du Wi-Fi ?\"}, {\"original\": \"Could I see the menu, please?\", \"translated\": \"Pourrais-je voir la carte, s\'il vous plaît ?\"}, {\"original\": \"Are refills allowed?\", \"translated\": \"Est-ce que les recharges sont autorisées ?\"}, {\"original\": \"Is my coffee ready?\", \"translated\": \"Mon café est-il prêt ?\"}, {\"original\": \"How long can I sit here?\", \"translated\": \"Combien de temps puis-je rester assis ici ?\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"Check, please. Thank you.\", \"translated\": \"L\'addition, s\'il vous plaît. Merci.\"}, {\"original\": \"It tastes really good.\", \"translated\": \"C\'est vraiment délicieux.\"}]', 12, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بعشر عبارات شائعة يمكنني استخدامها في المطعم؟\", \"رائع! إليك ١٠ عبارات شائعة تتعلق بالمطاعم، مرفقةً بالترجمة الفرنسية:\"]', '[\"تناول الطعام\", \"طلب الوجبات\", \"تسوية الحساب\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف معين في بالك؟ مثل طلب المشروبات أو التعبير عن شكوى أو الاستفسار عن المكونات؟ لا تتردد في السؤال.\", \"من فضلك صف الموقف الذي يخطر لك في بالك.\"]', '[]', '[{\"original\": \"المعذرة، كم من الوقت سيستغرق وصول طعامنا؟\", \"translated\": \"Excusez-moi, combien de temps encore avant que notre commande n\'arrive ?\"}, {\"original\": \"طاولة لشخصين، من فضلكم.\", \"translated\": \"Une table pour deux, s\'il vous plaît.\"}, {\"original\": \"هل يمكننا رؤية القائمة، من فضلكم؟\", \"translated\": \"Pourrions-nous voir la carte, s\'il vous plaît ?\"}, {\"original\": \"هل لديكم أطباق مميزة توصون بها؟\", \"translated\": \"Avez-vous des plats signature à nous recommander ?\"}, {\"original\": \"أود طلب هذا وهذا.\", \"translated\": \"Je voudrais commander ceci et cela.\"}, {\"original\": \"كوب من الماء، من فضلكم. شكرًا.\", \"translated\": \"Un verre d\'eau, s\'il vous plaît. Merci.\"}, {\"original\": \"الفاتورة، من فضلكم.\", \"translated\": \"L\'addition, s\'il vous plaît.\"}, {\"original\": \"هل يمكنني الدفع ببطاقة الائتمان؟\", \"translated\": \"Puis-je payer par carte bancaire ?\"}, {\"original\": \"هل يمكنكم تغليف هذا ليتم أخذه معى، من فضلكم؟\", \"translated\": \"Pourriez-vous emballer cela à emporter, s\'il vous plaît ?\"}, {\"original\": \"كان الطعام لذيذًا جدًّا، شكرًا لكم.\", \"translated\": \"Le plat était délicieux, merci beaucoup.\"}]', 1, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تُقدّم لي ١٠ عبارات شائعة يمكنني استخدامها في الفندق؟\", \"رائع! إليك ١٠ عبارات شائعة تتعلق بالفندق مع الترجمة الفرنسية:\"]', '[\"التسجيل للإقامة\", \"المغادرة\", \"خدمة الغرف\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف معيّن في بالك؟ مثل موقع الغرفة، أو أي خدمة أخرى يقدمها الفندق، أو عملية المغادرة؟ لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"مرحبًا، لدي حجزٌ هنا، وهذه جواز سفري.\", \"translated\": \"Bonjour, j’ai une réservation, voici mon passeport.\"}, {\"original\": \"هل لديكم غرف شاغرة؟\", \"translated\": \"Avez-vous des chambres disponibles ?\"}, {\"original\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسل الملابس؟\", \"translated\": \"Excusez-moi, l’hôtel dispose-t-il d’une salle de sport ou d’une buanderie ?\"}, {\"original\": \"في أي وقت تبدأ وجبة الإفطار؟\", \"translated\": \"À quelle heure commence le petit-déjeuner ?\"}, {\"original\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\", \"translated\": \"Pourrais-je avoir la clé de ma chambre, s’il vous plaît ?\"}, {\"original\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\", \"translated\": \"Pourriez-vous m’aider à porter mes bagages jusqu’à ma chambre ?\"}, {\"original\": \"كيف أطلب خدمة الغرف؟\", \"translated\": \"Comment puis-je appeler le service d’étage ?\"}, {\"original\": \"في أي وقت يكون موعد المغادرة؟\", \"translated\": \"À quelle heure est le check-out ?\"}, {\"original\": \"هل يمكنكم إعطائي إيصالًا/فاتورةً؟\", \"translated\": \"Pourriez-vous me remettre un reçu / une facture ?\"}, {\"original\": \"هل يمكنني ترك أمتعتي هنا؟\", \"translated\": \"Puis-je laisser mes bagages ici ?\"}]', 2, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بـ10 عبارات شائعة يمكنني استخدامها في المطار؟\", \"رائع! إليك 10 عبارات شائعة عن المطار مع ترجمتها الفرنسية:\"]', '[\"التسجيل\", \"الصعود للطائرة\", \"تسجيل الأمتعة\"]', 'ar', '[\"حاليًا، هل لديك موقف معين في بالك، مثل التسجيل أو استلام الأمتعة أو خدمة تأجير السيارات؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"أين كاونتر التسجيل؟\", \"translated\": \"Où est le comptoir d\'enregistrement ?\"}, {\"original\": \"أود مقعدًا بجانب النافذة، من فضلك.\", \"translated\": \"Je voudrais un siège côté fenêtre, s\'il vous plaît.\"}, {\"original\": \"هل تأخر هذا الرحلة؟\", \"translated\": \"Ce vol est-il retardé ?\"}, {\"original\": \"أحتاج إلى تسجيل هذه الأمتعة.\", \"translated\": \"Je dois enregistrer ce bagage.\"}, {\"original\": \"أين بوابة الصعود للطائرة؟\", \"translated\": \"Où est la porte d\'embarquement ?\"}, {\"original\": \"الطائرة على وشك الإقلاع.\", \"translated\": \"L\'avion est sur le point de décoller.\"}, {\"original\": \"هل يجب أن أخرج جهاز اللابتوب والباور بانك الخاص بي؟\", \"translated\": \"Dois-je sortir mon ordinateur portable et ma power bank ?\"}, {\"original\": \"أين متجر التخفيضات الجمركية؟\", \"translated\": \"Où se trouve la boutique hors taxes ?\"}, {\"original\": \"لا أستطيع العثور على حقيبتي.\", \"translated\": \"Je ne retrouve pas ma valise.\"}, {\"original\": \"هل تتوفر خدمة الكرسي المتحرك؟\", \"translated\": \"Proposez-vous un service de fauteuil roulant ?\"}]', 3, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ ١٠ عبارات شائعة يمكنني استخدامها في وسائل النقل العام؟\", \"رائع! إليك ١٠ عبارات شائعة عن وسائل النقل العام، مع ترجمتها إلى الفرنسية:\"]', '[\"ركوب المركبة\", \"شراء التذاكر\", \"التغيير بين وسائل النقل\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف محدد في ذهنك، مثل الاستفسار عن موقف الحافلات أو سعر التذكرة أو النزول من وسيلة النقل؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي تخيله في ذهنك.\"]', '[]', '[{\"original\": \"هل هذه الحافلة تذهب إلى المحطة؟\", \"translated\": \"Est-ce que ce bus va à la gare routière ?\"}, {\"original\": \"ما هي المحطة التالية؟\", \"translated\": \"Quelle est la prochaine arrêt ?\"}, {\"original\": \"أين يمكنني شراء تذكرة؟\", \"translated\": \"Où puis-je acheter un billet ?\"}, {\"original\": \"تذكرة واحدة إلى XX، من فضلك.\", \"translated\": \"Un billet pour XX, s’il vous plaît.\"}, {\"original\": \"هل يجب أن أغيّر وسيلة النقل؟\", \"translated\": \"Dois-je changer de moyen de transport ?\"}, {\"original\": \"كم من الوقت حتى القطار التالي في المترو؟\", \"translated\": \"Dans combien de temps arrive le prochain train de métro ?\"}, {\"original\": \"عذرًا، من فضلك اسمح لي بالمرور.\", \"translated\": \"Excusez-moi, je peux passer, s’il vous plaît ?\"}, {\"original\": \"هل هذا المقعد مشغول؟\", \"translated\": \"Ce siège est-il pris ?\"}, {\"original\": \"عذرًا، أين يمكنني التحويل إلى الخط ٢ للوصول إلى XX؟\", \"translated\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d’aller à XX ?\"}, {\"original\": \"كيف أصل إلى XX؟\", \"translated\": \"Comment puis-je me rendre à XX ?\"}]', 4, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ10 عبارات شائعة يمكنني استخدامها في المواقع السياحية؟\", \"رائع جدًّا! إليك 10 عبارات شائعة عن المواقع السياحية مع ترجمتها بالفرنسية:\"]', '[\"السياحة\", \"التصوير\", \"شراء التذاكر\"]', 'ar', '[\"حاليًّا، هل لديك موقف معين في ذهنك، مثل الاستفسار عن سعر التذكرة، أو العثور على موقف للسيارات، أو خدمة مرشد سياحي؟ لا تتردد في طرح سؤالك.\", \"يرجى وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"كم سعر رسوم الدخول؟\", \"translated\": \"Combien coûte l\'entrée ?\"}, {\"original\": \"هل توجد تذاكر مخصصة للطلاب؟\", \"translated\": \"Y a-t-il des billets étudiants disponibles ?\"}, {\"original\": \"في أي وقت يفتح الموقع السياحي؟\", \"translated\": \"À quelle heure ouvre l\'attraction ?\"}, {\"original\": \"ما الأنشطة الممتعة التي يمكن القيام بها هنا؟\", \"translated\": \"Quelles sont les activités amusantes à faire ici ?\"}, {\"original\": \"هل يمكنكم التقاط صورة لنا؟\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"أين حافلة الجولات السياحية؟\", \"translated\": \"Où est le bus touristique ?\"}, {\"original\": \"أين الحمامات؟\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"ما أفضل مكان لمشاهدة المناظر؟\", \"translated\": \"Quel est le meilleur point de vue ?\"}, {\"original\": \"المنظر هنا جميل جدًا.\", \"translated\": \"Le paysage est magnifique ici.\"}, {\"original\": \"هل تتوفر جولة إرشادية؟\", \"translated\": \"Une visite guidée est-elle disponible ?\"}]', 5, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ10 عبارات شائعة يمكنني استخدامها عند استئجار تاكسي أو استخدام خدمة تاكسي؟\", \"رائع! إليك 10 عبارات شائعة مرتبطة بالتاكسي أو خدمات التاكسي، مع ترجمتها إلى اللغة الفرنسية:\"]', '[\"استئجار تاكسي\", \"إبلاغ الوجهة\", \"الدفع\"]', 'ar', '[\"انتهاء الرحلة قريب، هل هناك أي شيء يمكنني مساعدتك فيه؟ مثل التحقق من التكلفة المُقدَّرة، أو طلب فاتورة إلكترونية، أو تأكيد وسيلة الدفع، أو الاستفسار عن طريقة الاتصال لاسترجاع الأمتعة المفقودة — لا تتردد في طرح أي سؤال.\", \"صف لي المشهد الذي تتخيله في ذهنك.\"]', '[]', '[{\"original\": \"أين يمكنني أن أستقل تاكسي؟\", \"translated\": \"Où puis-je prendre un taxi ?\"}, {\"original\": \"من فضلك خذني إلى هذا العنوان.\", \"translated\": \"Veuillez me conduire à cette adresse.\"}, {\"original\": \"كم يبلغ المبلغ التقريبي؟\", \"translated\": \"Quel est le montant approximatif ?\"}, {\"original\": \"هل يمكنك استخدام العداد من فضلك؟\", \"translated\": \"Pourriez-vous utiliser le compteur, s’il vous plaît ?\"}, {\"original\": \"من فضلك ا-driving أسرع قليلًا، فأنا في عجلة من أمري.\", \"translated\": \"Pourriez-vous rouler un peu plus vite, je suis pressé(e).\"}, {\"original\": \"من فضلك توقف هنا.\", \"translated\": \"Veuillez vous arrêter ici.\"}, {\"original\": \"هل يمكنني الدفع عبر علي بابا باي؟\", \"translated\": \"Puis-je payer avec Alipay ?\"}, {\"original\": \"هل يمكنني الحصول على إثبات دفع من فضلك؟\", \"translated\": \"Pourrais-je avoir un reçu, s’il vous plaît ?\"}, {\"original\": \"شكرًا لك يا سائق.\", \"translated\": \"Merci, chauffeur.\"}, {\"original\": \"كم تبقى من المسافة؟\", \"translated\": \"Il reste encore combien de temps ?\"}]', 6, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في الصيدلية؟\", \"رائع! إليك ١٠ عبارات شائعة تتعلق بالصيدلية، مع الترجمة الفرنسية:\"]', '[\"شراء أدوية\", \"استفسار\", \"دفع الثمن\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف معين في بالك؟ مثل طلب الإرشادات حول كيفية تناول الدواء، أو العبارات المتعلقة باستخدام التأمين الصحي، أو مدة تناول الدواء — لا تتردد في الاستفسار.\", \"يرجى وصف الموقف الذي يخطر لك في بالك.\"]', '[]', '[{\"original\": \"هل لديكم أدوية لعلاجنزلة البرد؟\", \"translated\": \"Avez-vous des médicaments contre le rhume ?\"}, {\"original\": \"كيف يجب أن آخذ هذا الدواء؟\", \"translated\": \"Comment dois-je prendre ce médicament ?\"}, {\"original\": \"هل لديكم مسكنات للألم؟\", \"translated\": \"Avez-vous des analgésiques ?\"}, {\"original\": \"هل يوجد نشرة إرشادات مع الدواء؟\", \"translated\": \"Y a-t-il une notice d’instructions jointe ?\"}, {\"original\": \"هل لهذا الدواء أي آثار جانبية؟\", \"translated\": \"Ce médicament a-t-il des effets secondaires ?\"}, {\"original\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\", \"translated\": \"Puis-je utiliser ma carte d’assurance maladie ?\"}, {\"original\": \"هل يمكنني الحصول على علبة من الضمادات اللاصقة، من فضلكم؟\", \"translated\": \"Pourriez-vous me donner une boîte de pansements adhésifs, s’il vous plaît ?\"}, {\"original\": \"هل لديكم خافضات للحرارة؟\", \"translated\": \"Avez-vous des antipyrétiques ?\"}, {\"original\": \"لقد أصابني جرح سطحي قليل. هل لديكم مطهر وضمادات لاصقة؟\", \"translated\": \"J’ai une petite éraflure. Avez-vous un antiseptique et des pansements adhésifs ?\"}, {\"original\": \"في أي وقت تغلقون المحل؟\", \"translated\": \"À quelle heure fermez-vous ?\"}]', 7, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بعشر عبارات شائعة يمكنني استخدامها في خدمات الطوارئ؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بخدمات الطوارئ، مع الترجمة الفرنسية:\"]', '[\"الإبلاغ عن جريمة\", \"الحصول على المساعدة الطبية الطارئة\", \"الاستغاثة\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف طارئ معين في بالك، مثل الحريق، أو إصابة شخص واحتياجه للمساعدة، أو الاتصال العاجل بالطوارئ؟ لا تتردد في السؤال.\", \"من فضلك صف الموقف الذي يخطر لك.\"]', '[]', '[{\"original\": \"من فضلك ساعدني في استدعاء الإسعاف.\", \"translated\": \"Veuillez m\'aider à appeler une ambulance.\"}, {\"original\": \"أين находится المستشفى؟\", \"translated\": \"Où se trouve l\'hôpital ?\"}, {\"original\": \"شخص ما أصيب.\", \"translated\": \"Quelqu\'un est blessé.\"}, {\"original\": \"من فضلك ساعدني.\", \"translated\": \"Veuillez m\'aider.\"}, {\"original\": \"أين تقع قسم الشرطة؟\", \"translated\": \"Où se trouve le commissariat de police ?\"}, {\"original\": \"لقد فقدت أمتعتي.\", \"translated\": \"J\'ai perdu mes affaires.\"}, {\"original\": \"ما هو رقم دائرة الإطفاء؟\", \"translated\": \"Quel est le numéro des pompiers ?\"}, {\"original\": \"لقد فقدت جواز سفري. هل تعرف أين يقع أقرب قسم شرطة؟\", \"translated\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le commissariat de police le plus proche ?\"}, {\"original\": \"هل يوجد مخرج طوارئ؟\", \"translated\": \"Y a-t-il une sortie de secours ?\"}, {\"original\": \"شخص ما فقد وعيه.\", \"translated\": \"Quelqu\'un s\'est évanoui.\"}]', 8, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزوّدني بعشر عبارات شائعة يمكنني استخدامها على الشاطئ أو بجانب المسبح؟\", \"رائع جدًّا! إليك عشر عبارات شائعة تتعلّق بالشاطئ أو المسبح، مع ترجمتها إلى اللغة الفرنسية:\"]', '[\"السباحة واللعب في الماء\", \"الاستلقاء تحت أشعة الشمس\", \"ممارسة الرياضات على الرمال\"]', 'ar', '[\"في الوقت الحالي، هل يمكنك إخباري بالسياق الخاص بالفعالية أو المهرجان المحلي الذي ستشارك فيه، مثل مهرجان ثقافي أو مهرجان غذائي أو مهرجان موسيقي؟ من فضلك قدّم لي هذا السياق.\", \"من فضلك حدّد لي الأنشطة التي ستشارك فيها.\"]', '[\"هل لديك موقف محدّد في ذهنك؟ لا تتردّد في طرح سؤالك بصراحة.\", \"من فضلك صف لي الموقف الذي تخيّله في ذهنك.\"]', '[{\"original\": \"انظر! الأمواج هناك كبيرة جدًا.\", \"translated\": \"Regardez ! Les vagues là-bas sont vraiment impressionnantes.\"}, {\"original\": \"تذكَّر أن تضع واقي الشمس، فأشعة فوق البنفسجية هنا قوية جدًا.\", \"translated\": \"N’oubliez pas d’appliquer de la crème solaire : les rayons UV sont très intenses ici.\"}, {\"original\": \"الرمل على هذه الشاطئ ناعم جدًا، لدرجة أن المشي عليه يشبه المشي على القطن.\", \"translated\": \"Le sable de cette plage est si fin qu’on a l’impression de marcher sur du coton.\"}, {\"original\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\", \"translated\": \"Et si on jouait au volley-ball sur la plage ?\"}, {\"original\": \"القوارب الشراعية في الأفق تبدو جميلة جدًا.\", \"translated\": \"Les voiliers au loin sont magnifiques.\"}, {\"original\": \"الماء هنا صافٍ جدًا لدرجة أنك تستطيع رؤية الأسماك.\", \"translated\": \"L’eau est tellement claire ici qu’on peut même voir les poissons.\"}, {\"original\": \"هيا نذهب للبحث عن بعض المحار.\", \"translated\": \"Allons chercher des coquillages !\"}, {\"original\": \"التنزه على الشاطئ عند غروب الشمس يجب أن يكون أمرًا رومانسيًّا للغاية.\", \"translated\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\"}, {\"original\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًا، فلنذهب ونجرب بعضها.\", \"translated\": \"J’ai entendu dire que les fruits de mer sont très frais ici ; allons-en goûter quelques-uns !\"}, {\"original\": \"المدّ في ارتفاع، لذا دعونا نتجه نحو الساحل.\", \"translated\": \"La marée monte : rentrons vers la rive.\"}]', 9, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بـ10 عبارات شائعة يمكنني استخدامها خلال الفعاليات والمناسبات المحلية؟\", \"رائع جدًّا! إليكم 10 عبارات شائعة مرتبطة بالفعاليات والمناسبات المحلية، مع ترجمتها إلى اللغة الفرنسية:\"]', '[\"المشاركة في الفعاليات\", \"الاحتفال بالعيد\", \"التعرّف على الثقافة\"]', 'ar', '[\"حاليًّا، هل يمكنكم إخباري بالسياق الذي تنوي حضوره من الفعاليات أو المناسبات المحلية، مثل هالوين أو حفل موسيقي أو حفلة مع الأصدقاء أو أي شيء آخر؟ يُرجى تزويدي بهذا السياق.\", \"يرجى وصف الأنشطة التي تتخيلها.\"]', '[\"هل لديك موقف معين في ذهنك؟ لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي تتخيله.\"]', '[{\"original\": \"هل توجد أي فعاليات اليوم؟\", \"translated\": \"Y a-t-il des événements aujourd\'hui ?\"}, {\"original\": \"هل هناك أي شيء مميز في هذا المهرجان؟\", \"translated\": \"Y a-t-il quelque chose de particulier à propos de ce festival ?\"}, {\"original\": \"أين تُقام الاحتفالات؟\", \"translated\": \"Où se déroule la célébration ?\"}, {\"original\": \"كيف يمكنني شراء التذاكر؟\", \"translated\": \"Comment puis-je acheter des billets ?\"}, {\"original\": \"متى تبدأ العروض؟\", \"translated\": \"À quelle heure commence la représentation ?\"}, {\"original\": \"ما الأطعمة التقليدية المتاحة؟\", \"translated\": \"Quels plats traditionnels sont proposés ?\"}, {\"original\": \"المكان حيويٌّ جدًّا هنا.\", \"translated\": \"C\'est vraiment animé ici.\"}, {\"original\": \"هل توجد أنشطة شعبية؟\", \"translated\": \"Y a-t-il des activités folkloriques ?\"}, {\"original\": \"أعياد سعيدة!\", \"translated\": \"Joyeuses fêtes !\"}, {\"original\": \"متى تنتهي الفعالية؟\", \"translated\": \"À quelle heure se termine l\'événement ?\"}]', 10, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزوّدني بعشر عبارات شائعة يمكنني استخدامها في المتحف أو المعرض الفني؟\", \"رائع! إليك عشر عبارات شائعة عن المتاحف والمعارض الفنية، مع ترجمتها إلى اللغة الفرنسية:\"]', '[\"زيارة\", \"جولة إرشادية\", \"شراء تذاكر\"]', 'ar', '[\"لِحدِّ الآن، هل لديك وضعٌ معيّنٌ في بالك؟ مثل طلب دليل تعريفي، أو عبارات مرتبطة بخريطة الطريق، أو عبارات للتعليق على المعروضات — لا تتردد في طرح أي سؤال.\", \"من فضلك صف لي الوضع الذي تفكّر فيه.\"]', '[]', '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"Quel est le montant des frais d\'entrée ?\"}, {\"original\": \"هل لديكم أدلة صوتية؟\", \"translated\": \"Proposez-vous des audioguides ?\"}, {\"original\": \"من هو مبتكر هذه القطعة الفنية؟\", \"translated\": \"Qui est l\'auteur de cette œuvre ?\"}, {\"original\": \"أين توجد أثمن قطعة في المتحف؟\", \"translated\": \"Où se trouve la pièce la plus précieuse du musée ?\"}, {\"original\": \"هل يُسمح بالتقاط الصور؟\", \"translated\": \"La photographie est-elle autorisée ?\"}, {\"original\": \"هل توجد معارض خاصة هنا؟\", \"translated\": \"Y a-t-il des expositions temporaires ici ?\"}, {\"original\": \"كم تستغرق الزيارة من وقت؟\", \"translated\": \"Combien de temps dure la visite ?\"}, {\"original\": \"هل يمكنكم أن تقدّموا لنا عرضًا تقديميًّا؟\", \"translated\": \"Pourriez-vous nous donner une introduction ?\"}, {\"original\": \"هذه الأعمال فعلاً رائعةٌ جدًّا.\", \"translated\": \"Ces œuvres sont vraiment exquises.\"}, {\"original\": \"أين تقع متجر الهدايا التذكارية؟\", \"translated\": \"Où se trouve la boutique de souvenirs ?\"}]', 11, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في مقهى؟\", \"رائع! إليك عشر عبارات شائعة عن المقاهي، مع ترجمتها الفرنسية:\"]', '[\"طلب القهوة\", \"الاسترخاء\", \"التواصل الاجتماعي\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف معيّن في بالك؟ مثل طلب القائمة، أو المشروبات الباردة أو الساخنة، أو منتجات أخرى؟ لا تتردد في طرح الأسئلة.\", \"يرجى وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"سأطلب لاتيه، من فضلك.\", \"translated\": \"Je prendrai un latte, s’il vous plaît.\"}, {\"original\": \"هل لديكم خدمة واي فاي؟\", \"translated\": \"Avez-vous le Wi-Fi ?\"}, {\"original\": \"هل يمكنني رؤية القائمة، من فضلك؟\", \"translated\": \"Pourriez-vous me montrer la carte, s’il vous plaît ?\"}, {\"original\": \"هل يُسمح بإعادة التعبئة؟\", \"translated\": \"Les recharges sont-elles autorisées ?\"}, {\"original\": \"هل قهوة بلدي جاهزة؟\", \"translated\": \"Mon café est-il prêt ?\"}, {\"original\": \"كم من الوقت يمكنني الجلوس هنا؟\", \"translated\": \"Combien de temps puis-je rester assis ici ?\"}, {\"original\": \"هل يمكنكم التقاط صورة لنا؟\", \"translated\": \"Pourriez-vous prendre une photo de nous ?\"}, {\"original\": \"أين الحمام؟\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"الفاتورة، من فضلك. شكرًا لكم.\", \"translated\": \"L’addition, s’il vous plaît. Merci.\"}, {\"original\": \"إنها تذوق جيدة جدًّا.\", \"translated\": \"C’est vraiment délicieux.\"}]', 12, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在餐厅使用的10个常用短语吗？\", \"太棒了！这里有10个关于餐厅的常用短语，附带日语翻译：\"]', '[\"用餐\", \"点餐\", \"结账\"]', 'zh', '[\"目前，您心里有特定场景吗？比如点饮料、投诉，或者询问食材成分？欢迎随时提出。\", \"请描述您心里想的场景。\"]', '[]', '[{\"original\": \"打扰一下，我们的餐还要等多久？\", \"translated\": \"すみません、お料理はあとどのくらいでご用意できますか？\"}, {\"original\": \"请给我们一张两人桌。\", \"translated\": \"二人席をお願いします。\"}, {\"original\": \"请问可以看一下菜单吗？\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"您有什么招牌菜可以推荐吗？\", \"translated\": \"おすすめの自家製定番料理はありますか？\"}, {\"original\": \"我要点这个和这个。\", \"translated\": \"こちらとこちらを注文したいです。\"}, {\"original\": \"请来一杯水，谢谢。\", \"translated\": \"お水を一杯お願いします。ありがとうございます。\"}, {\"original\": \"请结账。\", \"translated\": \"お会計をお願いします。\"}, {\"original\": \"我可以刷信用卡付款吗？\", \"translated\": \"クレジットカードでお支払いできますか？\"}, {\"original\": \"麻烦把这份打包带走，谢谢。\", \"translated\": \"こちらをテイクアウトにしてもらえますか？よろしくお願いします。\"}, {\"original\": \"食物很美味，谢谢。\", \"translated\": \"とてもおいしかったです。ありがとうございました。\"}]', 1, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在酒店使用的10个常用短语吗？\", \"太棒了！这里有10个关于酒店的常用短语，附带日语翻译：\"]', '[\"入住\", \"退房\", \"客房服务\"]', 'zh', '[\"目前，您心里有没有特定的情况？比如房间位置、其他酒店服务，或者退房相关事宜？欢迎随时提问。\", \"请描述一下您心里想的情境。\"]', '[]', '[{\"original\": \"你好，我有预订，这是我的护照。\", \"translated\": \"こんにちは、予約しています。こちらが私のパスポートです。\"}, {\"original\": \"你们还有空房吗？\", \"translated\": \"空室はございますか？\"}, {\"original\": \"不好意思，请问酒店有健身房或洗衣房吗？\", \"translated\": \"すみませんが、ホテルにジムやランドリールームはありますか？\"}, {\"original\": \"早餐几点开始？\", \"translated\": \"朝食は何時からですか？\"}, {\"original\": \"请给我房卡，谢谢。\", \"translated\": \"部屋の鍵をお願いします。\"}, {\"original\": \"您能帮我把行李送到房间吗？\", \"translated\": \"荷物を部屋まで運んでいただけますか？\"}, {\"original\": \"我该怎么呼叫客房服务？\", \"translated\": \"ルームサービスの呼び出し方はどうすればいいですか？\"}, {\"original\": \"退房时间是几点？\", \"translated\": \"チェックアウトの時間は何時ですか？\"}, {\"original\": \"请您给我写一张收据／发票。\", \"translated\": \"領収書／請求書を書いていただけますか？\"}, {\"original\": \"我可以把行李暂存在这里吗？\", \"translated\": \"荷物をここに一時預かってもらえますか？\"}]', 2, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在机场使用的10个常用短语吗？\", \"太棒了！这里有10个关于机场的常用短语，附带日语翻译：\"]', '[\"值机\", \"登机\", \"行李托运\"]', 'zh', '[\"目前，您心里有没有特定的场景，比如值机、行李提取或租车服务？欢迎随时提问。\", \"请描述一下您心里想到的场景。\"]', '[]', '[{\"original\": \"值机柜台在哪里？\", \"translated\": \"チェックインカウンターはどこですか？\"}, {\"original\": \"我想要一个靠窗的座位，谢谢。\", \"translated\": \"窓際の席をお願いします。\"}, {\"original\": \"这趟航班延误了吗？\", \"translated\": \"この便は遅れていますか？\"}, {\"original\": \"我需要托运行李。\", \"translated\": \"この荷物を預けたいです。\"}, {\"original\": \"登机口在哪里？\", \"translated\": \"搭乗ゲートはどこですか？\"}, {\"original\": \"飞机马上就要起飞了。\", \"translated\": \"飛行機がまもなく離陸します。\"}, {\"original\": \"我需要把笔记本电脑和充电宝拿出来吗？\", \"translated\": \"ノートパソコンとモバイルバッテリーをバッグから出さなければなりませんか？\"}, {\"original\": \"免税店在哪里？\", \"translated\": \"免税店はどこですか？\"}, {\"original\": \"我找不到我的行李箱了。\", \"translated\": \"私のスーツケースが見つかりません。\"}, {\"original\": \"你们提供轮椅服务吗？\", \"translated\": \"車椅子のサービスはありますか？\"}]', 3, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在公共交通工具使用的10个常用短语吗？\", \"太棒了！这里有10个关于公共交通工具的常用短语，附带日语翻译：\"]', '[\"乘坐公交/地铁\", \"购买车票\", \"换乘\"]', 'zh', '[\"目前，您心里有具体的场景吗？比如问公交站、票价，或者下车等问题，欢迎随时提问。\", \"请描述您心里想到的具体场景。\"]', '[]', '[{\"original\": \"这趟公交车去终点站吗？\", \"translated\": \"このバスは終点に行きますか？\"}, {\"original\": \"下一站是哪里？\", \"translated\": \"次の停留所はどこですか？\"}, {\"original\": \"我在哪儿可以买票？\", \"translated\": \"切符はどこで買えますか？\"}, {\"original\": \"请给我一张去XX的车票。\", \"translated\": \"XX行きの切符を1枚お願いします。\"}, {\"original\": \"我需要换乘吗？\", \"translated\": \"乗り換えが必要ですか？\"}, {\"original\": \"下一班地铁还要等多久？\", \"translated\": \"次の地下鉄はあとどれくらいで来ますか？\"}, {\"original\": \"不好意思，请让我过去一下。\", \"translated\": \"すみません、通らせてください。\"}, {\"original\": \"这个座位有人坐了吗？\", \"translated\": \"この席は空いていますか？\"}, {\"original\": \"不好意思，请问我在哪儿换乘2号线去XX？\", \"translated\": \"すみません、XXへ行くにはどこで2号線に乗り換えればいいですか？\"}, {\"original\": \"我怎么去XX？\", \"translated\": \"XXへはどう行けばいいですか？\"}]', 4, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在旅游景点使用的10个常用短语吗？\", \"太棒了！这里有10个关于旅游景点的常用短语，附带日语翻译：\"]', '[\"观光\", \"拍照\", \"购票\"]', 'zh', '[\"目前，您心里有特定的场景吗？比如询问票价、找停车场，或导游服务等——欢迎随时提问。\", \"请描述您心里想到的场景。\"]', '[]', '[{\"original\": \"门票多少钱？\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"有学生票吗？\", \"translated\": \"学生割引券はありますか？\"}, {\"original\": \"景点几点开门？\", \"translated\": \"観光地は何時から開園していますか？\"}, {\"original\": \"这里有哪些好玩的活动？\", \"translated\": \"ここではどんな楽しいアクティビティがありますか？\"}, {\"original\": \"您能帮我们拍张照吗？\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"观光巴士在哪里？\", \"translated\": \"観光バスの乗り場はどこですか？\"}, {\"original\": \"洗手间在哪里？\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"最佳观景点在哪里？\", \"translated\": \"一番景色がいい見晴らしスポットはどこですか？\"}, {\"original\": \"这里的风景真美。\", \"translated\": \"ここでの景色は本当にきれいです。\"}, {\"original\": \"有导游讲解服务吗？\", \"translated\": \"ガイド付きツアーはありますか？\"}]', 5, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在出租车或出租车服务使用的10个常用短语吗？\", \"太棒了！这里有10个关于出租车或出租车服务的常用短语，附带日语翻译：\"]', '[\"乘坐出租车\", \"告知目的地\", \"支付\"]', 'zh', '[\"目前，您最想做的是什么？比如询问目的地、费用，或者索要发票，欢迎随时提问。\", \"请描述一下您脑海中的场景。\"]', '[]', '[{\"original\": \"我在哪里可以打到出租车？\", \"translated\": \"タクシーはどこで拾えますか？\"}, {\"original\": \"请送我去这个地址。\", \"translated\": \"この住所までお願いします。\"}, {\"original\": \"大概要多少钱？\", \"translated\": \"だいたいいくらくらいですか？\"}, {\"original\": \"请打表计费，谢谢。\", \"translated\": \"メーターを使ってください、お願いします。\"}, {\"original\": \"请开快一点，我赶时间。\", \"translated\": \"少し早く運転してください、急いでいます。\"}, {\"original\": \"请在这里停车。\", \"translated\": \"ここで止めてください。\"}, {\"original\": \"您支持银行卡或手机支付吗？\", \"translated\": \"カードやモバイル決済は使えますか？\"}, {\"original\": \"可以给我一张发票吗？\", \"translated\": \"領収書をいただけますか？\"}, {\"original\": \"谢谢，司机师傅。\", \"translated\": \"ありがとうございます、運転手さん。\"}, {\"original\": \"还有多远？\", \"translated\": \"あとどのくらいですか？\"}]', 6, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在药店使用的10个常用短语吗？\", \"太棒了！这里有10个关于药店的常用短语，附带日语翻译：\"]', '[\"购买药品\", \"咨询\", \"付款\"]', 'zh', '[\"目前，您心里有没有特定的情境？比如询问服药说明、使用医保相关表达、用药时长等，欢迎随时提问。\", \"请描述一下您心里想到的具体情境。\"]', '[]', '[{\"original\": \"您有感冒药吗？\", \"translated\": \"風邪薬はありますか？\"}, {\"original\": \"这个药该怎么服用？\", \"translated\": \"このお薬はどのように服用すればいいですか？\"}, {\"original\": \"您有止痛药吗？\", \"translated\": \"鎮痛剤はありますか？\"}, {\"original\": \"药品附带说明书吗？\", \"translated\": \"このお薬には説明書が付いていますか？\"}, {\"original\": \"这种药有什么副作用吗？\", \"translated\": \"このお薬には副作用がありますか？\"}, {\"original\": \"我可以刷医保卡付款吗？\", \"translated\": \"医療保険カードを使って支払いできますか？\"}, {\"original\": \"请给我一盒创可贴，谢谢。\", \"translated\": \"バンドエイドを1箱、お願いします。\"}, {\"original\": \"您有退烧药吗？\", \"translated\": \"解熱剤はありますか？\"}, {\"original\": \"我有点擦伤，您有消毒液和创可贴吗？\", \"translated\": \"ちょっと切り傷があるんですが、消毒液とバンドエイドはありますか？\"}, {\"original\": \"你们几点关门？\", \"translated\": \"何時まで営業していますか？\"}]', 7, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在紧急服务使用的10个常用短语吗？\", \"太棒了！这里有10个关于紧急服务的常用短语，附带日语翻译：\"]', '[\"报警\", \"急救\", \"求助\"]', 'zh', '[\"目前，您心里有没有特定的紧急情况，比如火灾、受伤需要帮助、紧急呼叫等？欢迎随时提问。\", \"请描述您心中想的情境。\"]', '[]', '[{\"original\": \"请帮我叫一辆救护车。\", \"translated\": \"救急車を呼んでください。\"}, {\"original\": \"医院在哪儿？\", \"translated\": \"病院はどこですか？\"}, {\"original\": \"有人受伤了。\", \"translated\": \"誰かがけがをしました。\"}, {\"original\": \"请帮帮我。\", \"translated\": \"助けてください。\"}, {\"original\": \"警察局在哪儿？\", \"translated\": \"警察署はどこですか？\"}, {\"original\": \"我的物品丢了。\", \"translated\": \"荷物をなくしてしまいました。\"}, {\"original\": \"消防部门的电话号码是多少？\", \"translated\": \"消防署の電話番号は何番ですか？\"}, {\"original\": \"我的护照丢了。您知道最近的警察局在哪儿吗？\", \"translated\": \"パスポートを紛失しました。一番近い警察署はどこですか？\"}, {\"original\": \"有紧急出口吗？\", \"translated\": \"非常口はありますか？\"}, {\"original\": \"有人晕倒了。\", \"translated\": \"誰かが気を失いました。\"}]', 8, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在沙滩或池畔使用的10个常用短语吗？\", \"太棒了！这里有10个关于沙滩或池畔的常用短语，附带日语翻译：\"]', '[\"游泳\", \"日光浴\", \"沙滩运动\"]', 'zh', '[\"目前，能否请您告诉我您要参加的当地活动或节日的背景？例如文化祭、美食节或音乐节。请提供相关背景。\", \"请告诉我您参加的具体活动。\"]', '[\"您心里是否有特定的场景？欢迎随时提问。\", \"请描述一下您脑海中的场景。\"]', '[{\"original\": \"看！那边的海浪真大。\", \"translated\": \"見て！あそこにいる波が本当に大きいですね。\"}, {\"original\": \"记得涂防晒霜，这里的紫外线很强。\", \"translated\": \"日焼け止めを塗ることを忘れないでください。ここでの紫外線は非常に強いです。\"}, {\"original\": \"这个沙滩的沙子非常细腻，踩上去像走在棉花上一样。\", \"translated\": \"このビーチの砂はとても細かくて、踏みしめると綿の上を歩いているような感触です。\"}, {\"original\": \"在沙滩上打排球怎么样？\", \"translated\": \"ビーチでバレーボールをするのはどうですか？\"}, {\"original\": \"远处的帆船看起来真美。\", \"translated\": \"遠くに見えるヨットがとてもきれいですね。\"}, {\"original\": \"这里的海水非常清澈，甚至能看见鱼。\", \"translated\": \"ここでの海水はとても澄んでいて、魚まで見えます。\"}, {\"original\": \"我们去找些贝壳吧。\", \"translated\": \"一緒に貝殻を探しに行きましょう。\"}, {\"original\": \"夕阳下在沙滩上散步一定很浪漫。\", \"translated\": \"夕日が沈むビーチを散歩するのは、きっとロマンチックでしょうね。\"}, {\"original\": \"听说这里的海鲜非常新鲜，我们去尝尝吧。\", \"translated\": \"ここでのシーフードはとても新鮮だと聞きました。ぜひ食べてみましょう。\"}, {\"original\": \"涨潮了，我们往岸边走吧。\", \"translated\": \"満潮になってきていますね。それでは、岸へ向かいましょう。\"}]', 9, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在当地活动和节日使用的10个常用短语吗？\", \"太棒了！这里有10个关于当地活动和节日的常用短语，附带日语翻译：\"]', '[\"参加活动\", \"庆祝节日\", \"了解文化\"]', 'zh', '[\"目前，您能告诉我您要参加的当地活动或节日的具体情境吗？比如万圣节、音乐会、朋友聚会，或者其他什么活动？请提供具体情境。\", \"请描述一下您脑海中想到的活动。\"]', '[\"您心里有没有特定的情境？欢迎随时提问。\", \"请描述一下您脑海中想到的情境。\"]', '[{\"original\": \"今天有什么活动吗？\", \"translated\": \"今日は何かイベントがありますか？\"}, {\"original\": \"这个节日有什么特别之处吗？\", \"translated\": \"この祭りには何か特別な点がありますか？\"}, {\"original\": \"庆祝活动在哪里举行？\", \"translated\": \"お祝いの催しはどこで行われますか？\"}, {\"original\": \"我该怎么买门票？\", \"translated\": \"チケットはどこで購入できますか？\"}, {\"original\": \"演出什么时候开始？\", \"translated\": \"パフォーマンスはいつから始まりますか？\"}, {\"original\": \"有哪些传统食物？\", \"translated\": \"どんな伝統的な食べ物がありますか？\"}, {\"original\": \"这里真热闹啊！\", \"translated\": \"ここは本当に活気がありますね！\"}, {\"original\": \"有民俗活动吗？\", \"translated\": \"民俗行事はありますか？\"}, {\"original\": \"节日快乐！\", \"translated\": \"よいお祝いを！\"}, {\"original\": \"活动几点结束？\", \"translated\": \"イベントはいつ終わりますか？\"}]', 10, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在博物馆或美术馆使用的10个常用短语吗？\", \"太棒了！这里有10个关于博物馆或美术馆的常用短语，附带日语翻译：\"]', '[\"参观\", \"导览服务\", \"购票\"]', 'zh', '[\"目前，您心里有特定的使用场景吗？比如索要导览手册、与参观路线相关的表达、对展品的评价用语等，欢迎随时提问。\", \"请描述一下您心里想到的具体场景。\"]', '[]', '[{\"original\": \"入场费是多少？\", \"translated\": \"入館料はいくらですか？\"}, {\"original\": \"有语音导览吗？\", \"translated\": \"オーディオガイドはありますか？\"}, {\"original\": \"这件艺术品是谁创作的？\", \"translated\": \"この作品は誰が制作したものですか？\"}, {\"original\": \"博物馆最珍贵的藏品在哪里？\", \"translated\": \"美術館で最も貴重な所蔵品はどこにありますか？\"}, {\"original\": \"可以拍照吗？\", \"translated\": \"写真撮影はOKですか？\"}, {\"original\": \"这里有没有特别展览？\", \"translated\": \"ここでは特別展は開催されていますか？\"}, {\"original\": \"参观大约需要多长时间？\", \"translated\": \"見学にはおおよそどのくらいの時間がかかりますか？\"}, {\"original\": \"能为我们简单介绍一下吗？\", \"translated\": \"少し紹介していただけますか？\"}, {\"original\": \"这些作品真是精美极了。\", \"translated\": \"これらの作品は本当に素晴らしく精巧です。\"}, {\"original\": \"纪念品商店在哪儿？\", \"translated\": \"お土産店はどこにありますか？\"}]', 11, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在咖啡馆使用的10个常用短语吗？\", \"太棒了！这里有10个关于咖啡馆的常用短语，附带日语翻译：\"]', '[\"点咖啡\", \"休息\", \"社交\"]', 'zh', '[\"目前，您心里有特定场景吗？比如点菜单、要冰饮或热饮、其他商品等，欢迎随时提问。\", \"请描述一下您心里想到的场景。\"]', '[]', '[{\"original\": \"请给我一杯拿铁。\", \"translated\": \"ラテを一杯お願いします。\"}, {\"original\": \"你们有Wi-Fi吗？\", \"translated\": \"Wi-Fiはありますか？\"}, {\"original\": \"请把菜单给我看一下，谢谢。\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"可以续杯吗？\", \"translated\": \"リフィルはできますか？\"}, {\"original\": \"我的咖啡好了吗？\", \"translated\": \"私のコーヒーはできましたか？\"}, {\"original\": \"我可以在这里坐多久？\", \"translated\": \"ここにどのくらい座っていられますか？\"}, {\"original\": \"能帮我们拍张照吗？\", \"translated\": \"私たちの写真を撮ってもらえませんか？\"}, {\"original\": \"洗手间在哪里？\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"请结账，谢谢。\", \"translated\": \"お会計お願いします。ありがとうございます。\"}, {\"original\": \"味道真的很棒。\", \"translated\": \"本当に美味しいです。\"}]', 12, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a restaurant?\", \"Great! Here are 10 common restaurant phrases, with Japanese translations:\"]', '[\"Dining\", \"Ordering\", \"Checkout\"]', 'en', '[\"For now, do you have a specific situation in your mind, like ordering drinks, making a complaint, or asking about ingredients? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Excuse me, how much longer will our food be?\", \"translated\": \"すみません、お料理はあとどのくらいでございますか？\"}, {\"original\": \"A table for two, please.\", \"translated\": \"二人用のテーブルをお願いします。\"}, {\"original\": \"Could we see the menu, please?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"Do you have any signature dishes to recommend?\", \"translated\": \"おすすめのメインメニューはありますか？\"}, {\"original\": \"I\'d like to order this, and this.\", \"translated\": \"これを1つと、これを1つお願いします。\"}, {\"original\": \"A glass of water, please. Thanks.\", \"translated\": \"お水を1杯お願いします。ありがとうございます。\"}, {\"original\": \"The bill, please.\", \"translated\": \"お会計をお願いします。\"}, {\"original\": \"Can I pay by credit card?\", \"translated\": \"クレジットカードでお支払いできますか？\"}, {\"original\": \"Could you pack this to go, please?\", \"translated\": \"こちらをテイクアウトにしてもらえますか？\"}, {\"original\": \"The food was delicious, thank you.\", \"translated\": \"とても美味しかったです、ありがとうございました。\"}]', 1, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at the hotel?\", \"Great! Here are 10 common hotel-related phrases, with Japanese translations:\"]', '[\"Check-in\", \"Check-out\", \"Room Service\"]', 'en', '[\"For now, do you have a specific situation in mind—like room location, any other hotel service, or check-out? Feel free to ask!\", \"Please describe the situation you have in mind.\"]', '[]', '[{\"original\": \"Hello, I have a reservation, Here is my passport.\", \"translated\": \"こんにちは。予約をしております。こちらが私のパスポートです。\"}, {\"original\": \"Do you have any vacancies?\", \"translated\": \"空室はありますか？\"}, {\"original\": \"Excuse me, does the hotel have a gym or a laundry room?\", \"translated\": \"すみません、ホテルにはジムやランドリールームはありますか？\"}, {\"original\": \"What time does breakfast start?\", \"translated\": \"朝食は何時から開始ですか？\"}, {\"original\": \"Could I have a room key, please?\", \"translated\": \"部屋の鍵をいただけますか？\"}, {\"original\": \"Could you help me take my luggage to the room?\", \"translated\": \"荷物を部屋まで運んでもらえますか？\"}, {\"original\": \"How do I call room service?\", \"translated\": \"ルームサービスを呼ぶにはどうすればいいですか？\"}, {\"original\": \"What time is check-out?\", \"translated\": \"チェックアウトは何時までですか？\"}, {\"original\": \"Could you write me a receipt/invoice?\", \"translated\": \"領収書／請求書を書いてもらえますか？\"}, {\"original\": \"Can I leave my luggage here?\", \"translated\": \"荷物をここに預けても大丈夫ですか？\"}]', 2, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at the airport?\", \"Great! Here are 10 common airport-related phrases with Japanese translations:\"]', '[\"Check-in\", \"Boarding\", \"Baggage Check\"]', 'en', '[\"For now, do you have a specific situation in your mind, like check-in, baggage claim, or car rental service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Where is the check-in counter?\", \"translated\": \"チェックインカウンターはどこですか？\"}, {\"original\": \"I\'d like a window seat, please.\", \"translated\": \"窓際の席をお願いします。\"}, {\"original\": \"Is this flight delayed?\", \"translated\": \"この便は遅れていますか？\"}, {\"original\": \"I need to check this baggage.\", \"translated\": \"この荷物を預けたいのですが。\"}, {\"original\": \"Where is the boarding gate?\", \"translated\": \"搭乗口はどこですか？\"}, {\"original\": \"The plane is about to take off.\", \"translated\": \"飛行機が今から離陸します。\"}, {\"original\": \"Do I need to take out my laptop and power bank?\", \"translated\": \"ノートパソコンとモバイルバッテリーは持ち出さなければなりませんか？\"}, {\"original\": \"Where is the duty-free shop?\", \"translated\": \"免税店はどこですか？\"}, {\"original\": \"I can\'t find my suitcase.\", \"translated\": \"私のスーツケースが見つかりません。\"}, {\"original\": \"Do you have a wheelchair service?\", \"translated\": \"車椅子のサービスはありますか？\"}]', 3, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use on public transportation?\", \"Great! Here are 10 common public transportation phrases, with Japanese translations:\"]', '[\"Taking Bus/Subway\", \"Buying Tickets\", \"Transferring\"]', 'en', '[\"For now, do you have a specific situation in mind—like asking for a bus stop, ticket price, or when to get off? Feel free to ask!\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Does this bus go to the terminal?\", \"translated\": \"このバスは終点に行きますか？\"}, {\"original\": \"What is the next stop?\", \"translated\": \"次の停留所はどこですか？\"}, {\"original\": \"Where can I buy a ticket?\", \"translated\": \"切符はどこで買えますか？\"}, {\"original\": \"One ticket to XX, please.\", \"translated\": \"XX行きの切符を一枚お願いします。\"}, {\"original\": \"Do I need to transfer?\", \"translated\": \"乗り換えが必要ですか？\"}, {\"original\": \"How long until the next subway train?\", \"translated\": \"次の地下鉄の列車まであと何分ですか？\"}, {\"original\": \"Excuse me, please let me pass.\", \"translated\": \"すみません、通らせてください。\"}, {\"original\": \"Is this seat taken?\", \"translated\": \"この席は空いていますか？\"}, {\"original\": \"Excuse me, where can I transfer to Line 2 to get to XX?\", \"translated\": \"すみません、XXに行くのに、どこで2号線に乗り換えられますか？\"}, {\"original\": \"How do I get to XX?\", \"translated\": \"XXにはどう行けばいいですか？\"}]', 4, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at tourist attractions?\", \"Great! Here are 10 common phrases for tourist attractions, with Japanese translations:\"]', '[\"Sightseeing\", \"Taking Photos\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking about ticket prices, finding a parking lot, or tour guide service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"How much is the entrance fee?\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"Are there student tickets available?\", \"translated\": \"学生料金のチケットはありますか？\"}, {\"original\": \"What time does the attraction open?\", \"translated\": \"観光地は何時から開いていますか？\"}, {\"original\": \"What are the fun things to do here?\", \"translated\": \"ここではどんな楽しいことが体験できますか？\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"Where is the sightseeing bus?\", \"translated\": \"観光バスの乗り場はどこですか？\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"Where is the best viewing spot?\", \"translated\": \"一番景色がきれいに見えるポイントはどこですか？\"}, {\"original\": \"The scenery here is beautiful.\", \"translated\": \"ここからの景色は本当に美しいです。\"}, {\"original\": \"Is there a guided tour available?\", \"translated\": \"ガイド付きツアーはありますか？\"}]', 5, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use for taxis or taxi services?\", \"Great! Here are 10 common taxi-related phrases, with Japanese translations:\"]', '[\"Taking Taxi\", \"Telling Destination\", \"Payment\"]', 'en', '[\"For now, what do you most want to do now — like asking for the destination, the fare, or a receipt? Feel free to ask!\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Where can I get a taxi?\", \"translated\": \"タクシーはどこで乗れますか？\"}, {\"original\": \"Please take me to this address.\", \"translated\": \"この住所までお願いします。\"}, {\"original\": \"Roughly how much will it be?\", \"translated\": \"おおよそいくらぐらいになりますか？\"}, {\"original\": \"Could you use the meter, please?\", \"translated\": \"メーターを使ってもらえますか？\"}, {\"original\": \"Please drive a bit faster, I\'m in a hurry.\", \"translated\": \"ちょっと急いでください。急いでいるんです。\"}, {\"original\": \"Please stop here.\", \"translated\": \"ここで止めてください。\"}, {\"original\": \"Do you accept cards or mobile payments?\", \"translated\": \"カードやモバイル決済は使えますか？\"}, {\"original\": \"Could I have a receipt, please?\", \"translated\": \"領収書をいただけますか？\"}, {\"original\": \"Thank you, driver.\", \"translated\": \"ありがとう、運転手さん。\"}, {\"original\": \"How much further is it?\", \"translated\": \"あとどれくらいですか？\"}]', 6, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a pharmacy?\", \"Great! Here are 10 common pharmacy-related phrases, with Japanese translations:\"]', '[\"Buying Medicine\", \"Consultation\", \"Payment\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for instructions on taking medicine, phrases related to using insurance, duration of medication? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Do you have cold medicine?\", \"translated\": \"風邪薬はありますか？\"}, {\"original\": \"How should I take this medicine?\", \"translated\": \"このお薬はどのように服用すればいいですか？\"}, {\"original\": \"Do you have any painkillers?\", \"translated\": \"痛み止めはありますか？\"}, {\"original\": \"Is there an instruction leaflet?\", \"translated\": \"説明書のリーフレットは付いていますか？\"}, {\"original\": \"Does this medicine have any side effects?\", \"translated\": \"このお薬には副作用がありますか？\"}, {\"original\": \"Can I use my medical insurance card?\", \"translated\": \"医療保険証は使えますか？\"}, {\"original\": \"Could I have a box of Band-Aids, please?\", \"translated\": \"バンドエイドを1箱お願いできますか？\"}, {\"original\": \"Do you have any fever reducers?\", \"translated\": \"解熱剤はありますか？\"}, {\"original\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\", \"translated\": \"ちょっと擦り傷をしました。消毒液とバンドエイドはありますか？\"}, {\"original\": \"What time do you close?\", \"translated\": \"何時まで営業していますか？\"}]', 7, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use when contacting emergency services?\", \"Great! Here are 10 common phrases for emergency services, with Japanese translations:\"]', '[\"Calling Police\", \"First Aid\", \"Calling for Help\"]', 'en', '[\"For now, do you have a specific emergency situation in mind, like fire, injured and need help, emergency call? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Please help me call an ambulance.\", \"translated\": \"救急車を呼んでください。\"}, {\"original\": \"Where is the hospital?\", \"translated\": \"病院はどこですか？\"}, {\"original\": \"Someone is injured.\", \"translated\": \"誰かが怪我をしました。\"}, {\"original\": \"Please help me.\", \"translated\": \"助けてください。\"}, {\"original\": \"Where is the police station?\", \"translated\": \"警察署はどこですか？\"}, {\"original\": \"I\'ve lost my belongings.\", \"translated\": \"荷物をなくしました。\"}, {\"original\": \"What is the number for the fire department?\", \"translated\": \"消防署の電話番号は何番ですか？\"}, {\"original\": \"I\'ve lost my passport. Do you know where the nearest police station is?\", \"translated\": \"パスポートを紛失しました。一番近い警察署はどこかわかりますか？\"}, {\"original\": \"Is there an emergency exit?\", \"translated\": \"非常口はありますか？\"}, {\"original\": \"Someone has fainted.\", \"translated\": \"誰かが気を失いました。\"}]', 8, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at the beach or by the pool?\", \"Great! Here are 10 common beach- or pool-related phrases, with Japanese translations:\"]', '[\"Swimming\", \"Sunbathing\", \"Beach Sports\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you’re attending—like a cultural festival, food festival, or music festival? Please provide the context.\", \"Please provide the activities that you attend.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[{\"original\": \"Look! The waves over there are really big.\", \"translated\": \"見て！あそこに来る波、本当に大きいですね。\"}, {\"original\": \"Remember to apply sunscreen, the UV rays here are very strong.\", \"translated\": \"日焼け止めを忘れないでください。この辺りの紫外線はとても強いですよ。\"}, {\"original\": \"The sand on this beach is so fine, it feels like stepping on cotton.\", \"translated\": \"このビーチの砂はとても細かくて、綿の上を歩いているような感触です。\"}, {\"original\": \"How about playing volleyball on the beach?\", \"translated\": \"ビーチでバレーボールをやるのはどうですか？\"}, {\"original\": \"The sailboats in the distance look beautiful.\", \"translated\": \"遠くのヨットがとても美しく見えますね。\"}, {\"original\": \"The water here is so clear, you can even see the fish.\", \"translated\": \"ここでの水はとても透明度が高くて、魚まで見えるんですよ。\"}, {\"original\": \"Let\'s go find some seashells.\", \"translated\": \"一緒に貝殻を探しに行きましょう！\"}, {\"original\": \"Taking a walk on the beach at sunset must be very romantic.\", \"translated\": \"夕日に染まるビーチを散歩するのは、きっととてもロマンチックでしょうね。\"}, {\"original\": \"I heard the seafood here is very fresh, let\'s go try some.\", \"translated\": \"ここでは海産物がすごく新鮮だと聞いたので、ぜひ食べてみましょう！\"}, {\"original\": \"The tide is coming in, let\'s head towards the shore.\", \"translated\": \"潮が満ちてきていますよ。そろそろ岸に向かいましょう。\"}]', 9, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use for local events and festivals?\", \"Great! Here are 10 common phrases about local events and festivals, with Japanese translations:\"]', '[\"Attending Events\", \"Celebrating Festivals\", \"Learning Culture\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you’re attending—like Halloween, a concert, a friend’s party, or something else? Please provide the context.\", \"Please describe the activities in your mind.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[{\"original\": \"Are there any events today?\", \"translated\": \"今日は何かイベントがありますか？\"}, {\"original\": \"Is there anything special about this festival?\", \"translated\": \"この祭りには何か特別なことがありませんか？\"}, {\"original\": \"Where is the celebration being held?\", \"translated\": \"お祝いはどこで行われますか？\"}, {\"original\": \"How can I buy tickets?\", \"translated\": \"チケットはどのように購入できますか？\"}, {\"original\": \"What time does the performance start?\", \"translated\": \"パフォーマンスは何時から始まりますか？\"}, {\"original\": \"What traditional food is there?\", \"translated\": \"どんな伝統的な食べ物がありますか？\"}, {\"original\": \"It\'s really lively here.\", \"translated\": \"ここは本当に活気がありますね。\"}, {\"original\": \"Are there any folk activities?\", \"translated\": \"民俗行事はありますか？\"}, {\"original\": \"Happy holidays!\", \"translated\": \"楽しい休日を！\"}, {\"original\": \"What time does the event end?\", \"translated\": \"イベントは何時までですか？\"}]', 10, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a museum or art gallery?\", \"That\'s great! Here are 10 common museum- or art-gallery-related phrases, with Japanese translations:\"]', '[\"Visiting\", \"Guided Tour\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind—like asking for an introduction manual, phrases related to a roadmap, phrases related to commenting on exhibits? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"How much is the admission fee?\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"Do you have audio guides?\", \"translated\": \"オーディオガイドはありますか？\"}, {\"original\": \"Who created this artwork?\", \"translated\": \"この作品は誰が制作しましたか？\"}, {\"original\": \"Where is the museum\'s most prized piece?\", \"translated\": \"博物館で最も貴重な作品はどこにありますか？\"}, {\"original\": \"Is photography allowed?\", \"translated\": \"写真撮影は可能ですか？\"}, {\"original\": \"Are there any special exhibitions here?\", \"translated\": \"ここでは特別展は開催されていますか？\"}, {\"original\": \"How long does the visit take?\", \"translated\": \"見学にはどれくらい時間がかかりますか？\"}, {\"original\": \"Could you give us an introduction?\", \"translated\": \"ご紹介いただけますか？\"}, {\"original\": \"These works are truly exquisite.\", \"translated\": \"これらの作品は本当に素晴らしいです。\"}, {\"original\": \"Where is the souvenir shop?\", \"translated\": \"お土産ショップはどこにありますか？\"}]', 11, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a café?\", \"Great! Here are 10 common café-related phrases, with Japanese translations:\"]', '[\"Ordering Coffee\", \"Resting\", \"Socializing\"]', 'en', '[\"For now, do you have a specific situation in mind—like asking for a menu, ice or hot drinks, other products? Feel free to ask!\", \"Please describe the situation you have in mind.\"]', '[]', '[{\"original\": \"I\'ll have a latte, please.\", \"translated\": \"ラテをください。\"}, {\"original\": \"Do you have Wi-Fi?\", \"translated\": \"Wi-Fiは使えますか？\"}, {\"original\": \"Could I see the menu, please?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"Are refills allowed?\", \"translated\": \"リフィルはできますか？\"}, {\"original\": \"Is my coffee ready?\", \"translated\": \"私のコーヒーはできましたか？\"}, {\"original\": \"How long can I sit here?\", \"translated\": \"ここにどのくらい座っていられますか？\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"Check, please. Thank you.\", \"translated\": \"お会計お願いします。ありがとうございます。\"}, {\"original\": \"It tastes really good.\", \"translated\": \"とても美味しいです。\"}]', 12, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ10 عبارات شائعة يمكنني استخدامها في المطعم؟\", \"رائع! إليك 10 عبارات شائعة تتعلق بالمطاعم، مع ترجمتها إلى اليابانية:\"]', '[\"تناول الطعام\", \"طلب الطعام\", \"الدفع والخروج\"]', 'ar', '[\"للمoment، هل لديك موقف معين في ذهنك؟ مثل طلب المشروبات أو تقديم شكوى أو الاستفسار عن المكونات — لا تتردد في السؤال!\", \"وصف الموقف الذي تخطره في بالك.\"]', '[]', '[{\"original\": \"عذرًا، كم من الوقت سيستغرق وصول طعامنا؟\", \"translated\": \"すみません、料理はあとどのくらいで来ますか？\"}, {\"original\": \"طاولة لشخصين، من فضلكم.\", \"translated\": \"二人席をお願いします。\"}, {\"original\": \"هل يمكننا رؤية القائمة، من فضلكم؟\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"هل لديكم أطباق مميزة توصون بها؟\", \"translated\": \"おすすめの定番料理はありますか？\"}, {\"original\": \"أود طلب هذا وهذا.\", \"translated\": \"これをひとつと、こちらもお願いします。\"}, {\"original\": \"كوب من الماء، من فضلكم. شكرًا.\", \"translated\": \"お水をお願いします。ありがとうございます。\"}, {\"original\": \"الفاتورة، من فضلكم.\", \"translated\": \"お会計をお願いします。\"}, {\"original\": \"هل يمكنني الدفع باستخدام بطاقة الائتمان؟\", \"translated\": \"クレジットカードで支払えますか？\"}, {\"original\": \"هل يمكنكم تغليف هذا لل带走، من فضلكم؟\", \"translated\": \"これをお持ち帰り用に包んでいただけますか？\"}, {\"original\": \"كان الطعام لذيذًا، شكرًا لكم.\", \"translated\": \"料理がとても美味しかったです。ありがとうございました。\"}]', 1, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ10 عبارات شائعة يمكنني استخدامها في الفندق؟\", \"رائع! إليك 10 عبارات شائعة تستخدم في الفنادق مع الترجمة اليابانية:\"]', '[\"التسجيل عند الوصول\", \"المغادرة\", \"خدمة الغرف\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف محدد في بالك؟ مثل موقع الغرفة، أو أي خدمة فندقية أخرى، أو المغادرة؟ لا تتردد في طرح الأسئلة.\", \"من فضلك صف لي الموقف الذي في بالك.\"]', '[]', '[{\"original\": \"مرحبًا، لدي حجزٌ، وهذه جواز سفري.\", \"translated\": \"こんにちは、予約しています。こちらが私のパスポートです。\"}, {\"original\": \"هل لديكم غرف شاغرة؟\", \"translated\": \"空室はありますか？\"}, {\"original\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسل الملابس؟\", \"translated\": \"すみません、ホテルにジムや Laundry Room（ランドリールーム）はありますか？\"}, {\"original\": \"متى تبدأ وجبة الإفطار؟\", \"translated\": \"朝食は何時からですか？\"}, {\"original\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\", \"translated\": \"部屋の鍵をいただけますか？\"}, {\"original\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\", \"translated\": \"荷物を部屋まで運んでいただけますか？\"}, {\"original\": \"كيف أتصل بخدمة الغرف؟\", \"translated\": \"ルームサービスの呼び出し方はどうすればいいですか？\"}, {\"original\": \"متى موعد المغادرة؟\", \"translated\": \"チェックアウトの時間は何時ですか？\"}, {\"original\": \"هل يمكنكم إعطائي إيصالاً/فاتورة؟\", \"translated\": \"領収書／請求書を発行してもらえますか？\"}, {\"original\": \"هل يمكنني ترك أمتعتي هنا؟\", \"translated\": \"荷物をここに預けても大丈夫ですか？\"}]', 2, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدني بـ10 عبارات شائعة يمكنني استخدامها في المطار؟\", \"رائع جدًّا! إليك 10 عبارات شائعة تُستخدم في المطار، مع الترجمة اليابانية:\"]', '[\"التسجيل\", \"الصعود إلى الطائرة\", \"فحص الأمتعة\"]', 'ar', '[\"حاليًّا، هل لديك موقف معين في بالك، مثل التسجيل أو استلام الأمتعة أو خدمة تأجير السيارات؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف لي الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"أين كاونتر التسجيل؟\", \"translated\": \"チェックインカウンターはどこですか？\"}, {\"original\": \"أود مقعدًا بجوار النافذة، من فضلك.\", \"translated\": \"窓際の席をお願いします。\"}, {\"original\": \"هل تأخر هذا الرحلة؟\", \"translated\": \"この便は遅れていますか？\"}, {\"original\": \"أحتاج إلى تسجيل هذه الأمتعة.\", \"translated\": \"この荷物を預けたいのですが。\"}, {\"original\": \"أين بوابة الصعود إلى الطائرة؟\", \"translated\": \"搭乗口はどこですか？\"}, {\"original\": \"الطائرة على وشك الإقلاع.\", \"translated\": \"飛行機が今から離陸します。\"}, {\"original\": \"هل يجب أن أخرج جهاز اللابتوب وبنك الطاقة الخاص بي؟\", \"translated\": \"ノートパソコンとモバイルバッテリーを取り出さなければなりませんか？\"}, {\"original\": \"أين متجر التخفيضات الجمركية؟\", \"translated\": \"免税店はどこですか？\"}, {\"original\": \"لا أستطيع العثور على حقيبتي.\", \"translated\": \"私のスーツケースが見つかりません。\"}, {\"original\": \"هل لديكم خدمة الكرسي المتحرك؟\", \"translated\": \"車椅子のサービスはありますか？\"}]', 3, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ10 عبارات شائعة يمكنني استخدامها في وسائل النقل العام؟\", \"رائع جدًا! إليك 10 عبارات شائعة لوسائل النقل العام، مع الترجمة اليابانية:\"]', '[\"ركوب الحافلة أو المترو\", \"شراء التذاكر\", \"التحويل بين وسائل النقل\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف محدد في ذهنك؟ مثل الاستفسار عن موقف الحافلة، أو سعر التذكرة، أو مكان النزول؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"هل هذه الحافلة تذهب إلى المحطة؟\", \"translated\": \"このバスは終点に行きますか？\"}, {\"original\": \"ما هو المحطة التالية؟\", \"translated\": \"次の停留所はどこですか？\"}, {\"original\": \"أين يمكنني شراء تذكرة؟\", \"translated\": \"切符はどこで買えますか？\"}, {\"original\": \"تذكرة واحدة إلى (XX)، من فضلك.\", \"translated\": \"XX行きの切符を1枚、お願いします。\"}, {\"original\": \"هل عليّ التحويل؟\", \"translated\": \"乗り換えが必要ですか？\"}, {\"original\": \"كم من الوقت حتى القطار التالي في المترو؟\", \"translated\": \"次の地下鉄の列車まであと何分ですか？\"}, {\"original\": \"عذرًا، من فضلك اسمح لي بالمرور.\", \"translated\": \"すみません、通らせてください。\"}, {\"original\": \"هل هذا المقعد محجوز؟\", \"translated\": \"この席は空いていますか？\"}, {\"original\": \"عذرًا، أين يمكنني التحويل إلى الخط 2 للوصول إلى (XX)؟\", \"translated\": \"すみません、XXへ行くのに2号線に乗り換えるには、どこで乗り換えればいいですか？\"}, {\"original\": \"كيف أصل إلى (XX)؟\", \"translated\": \"XXへはどう行けばいいですか？\"}]', 4, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تُعطيني ١٠ عبارات شائعة يمكنني استخدامها في المعالم السياحية؟\", \"رائع جدًّا! إليك ١٠ عبارات شائعة تُستخدم في أماكن الجذب السياحي، مع ترجمتها إلى اللغة اليابانية:\"]', '[\"السياحة\", \"التقاط الصور\", \"شراء التذاكر\"]', 'ar', '[\"حتى الآن، هل لديك موقف معين في ذهنك؟ مثل الاستفسار عن سعر التذكرة، أو العثور على موقف للسيارات، أو طلب خدمة دليل سياحي. لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي لديك في بالك.\"]', '[]', '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"هل توجد تذاكر مخصصة للطلاب؟\", \"translated\": \"学生向けの割引チケットはありますか？\"}, {\"original\": \"متى يفتح الموقع السياحي أبوابه؟\", \"translated\": \"観光スポットの営業開始時間はいつですか？\"}, {\"original\": \"ما الأنشطة الممتعة التي يمكن القيام بها هنا؟\", \"translated\": \"ここで楽しめるアクティビティは何がありますか？\"}, {\"original\": \"هل يمكنك أخذ صورة لنا؟\", \"translated\": \"私たちの写真を撮ってもらえませんか？\"}, {\"original\": \"أين يوجد حافلة الجولات السياحية؟\", \"translated\": \"観光バスの乗り場はどこですか？\"}, {\"original\": \"أين يوجد الحمام؟\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"ما أفضل مكان لمشاهدة المنظر؟\", \"translated\": \"一番景色がきれいなビュースポットはどこですか？\"}, {\"original\": \"المنظر هنا جميل جدًا.\", \"translated\": \"ここからの景色はとても美しいです。\"}, {\"original\": \"هل توجد جولة إرشادية متاحة؟\", \"translated\": \"ガイド付きツアーはありますか？\"}]', 5, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ10 عبارات شائعة يمكنني استخدامها عند طلب تاكسي أو استخدام خدمة التاكسي؟\", \"رائع! إليك 10 عبارات شائعة مرتبطة بالتاكسي أو خدمات التاكسي، مع الترجمة اليابانية:\"]', '[\"ركوب التاكسي\", \"إبلاغ الوجهة\", \"الدفع\"]', 'ar', '[\"حاليًا، ما الذي تود فعله أكثر الآن؟ مثل الاستفسار عن الوجهة، أو السعر، أو طلب إشعار دفع — لا تتردد في السؤال!\", \"يرجى وصف الموقف الذي تتصوره في ذهنك.\"]', '[]', '[{\"original\": \"أين يمكنني أخذ تاكسي؟\", \"translated\": \"タクシーはどこで拾えますか？\"}, {\"original\": \"من فضلك خذني إلى هذا العنوان.\", \"translated\": \"こちらの住所までお連れください。\"}, {\"original\": \"كم سيكون المبلغ تقريبًا؟\", \"translated\": \"大体いくらぐらいかかりますか？\"}, {\"original\": \"هل يمكنك تشغيل العداد، من فضلك؟\", \"translated\": \"メーターを使っていただけますか？\"}, {\"original\": \"من فضلك ا-driving أسرع قليلًا، فأنا مستعجل.\", \"translated\": \"急いでいるので、少しだけ速く走ってもらえますか？\"}, {\"original\": \"من فضلك توقف هنا.\", \"translated\": \"ここで止めてください。\"}, {\"original\": \"هل تقبل الدفع بالبطاقات أو عبر الهاتف المحمول؟\", \"translated\": \"カードやモバイル決済は使えますか？\"}, {\"original\": \"هل لي أن أحصل على إيصال، من فضلك؟\", \"translated\": \"領収書をいただけますか？\"}, {\"original\": \"شكرًا لك، يا سائق.\", \"translated\": \"ありがとうございます、運転手さん。\"}, {\"original\": \"كم يبعد الوجهة بعد؟\", \"translated\": \"あとどのくらいで着きますか？\"}]', 6, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بـ10 عبارات شائعة يمكنني استخدامها في الصيدلية؟\", \"رائع! إليك 10 عبارات شائعة تتعلق بالصيدلية، مع الترجمة اليابانية:\"]', '[\"شراء أدوية\", \"استشارة طبية\", \"دفع المبلغ\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف محدد في ذهنك؟ مثل طلب إرشادات حول كيفية تناول الدواء، أو العبارات المتعلقة باستخدام التأمين الصحي، أو مدة العلاج… لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"هل لديك دواء للبرد؟\", \"translated\": \"風邪薬はありますか？\"}, {\"original\": \"كيف يجب أن آخذ هذا الدواء؟\", \"translated\": \"このお薬はどのように服用すればいいですか？\"}, {\"original\": \"هل لديك مسكنات للآلام؟\", \"translated\": \"痛み止めはありますか？\"}, {\"original\": \"هل يوجد نشرة إرشادات مع الدواء؟\", \"translated\": \"説明書は付いていますか？\"}, {\"original\": \"هل لهذا الدواء أي آثار جانبية؟\", \"translated\": \"このお薬には副作用がありますか？\"}, {\"original\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\", \"translated\": \"健康保険証は使えますか？\"}, {\"original\": \"هل يمكنني الحصول على علبة من الشاش الطبي (الضمادات اللاصقة)، من فضلك؟\", \"translated\": \"絆創膏を1箱お願いできますか？\"}, {\"original\": \"هل لديك خافضات للحرارة؟\", \"translated\": \"解熱剤はありますか？\"}, {\"original\": \"لديّ جرح سطحي بسيط. هل لديك محلول مطهر وضمادات لاصقة؟\", \"translated\": \"ちょっと擦り傷をしたんですが、消毒液と絆創膏はありますか？\"}, {\"original\": \"في أي وقت تغلقون؟\", \"translated\": \"何時まで営業していますか？\"}]', 7, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ١٠ عبارات شائعة يمكنني استخدامها في خدمات الطوارئ؟\", \"رائع! إليك ١٠ عبارات شائعة تتعلق بخدمات الطوارئ، مع الترجمة اليابانية:\"]', '[\"الاتصال بالشرطة\", \"الإسعافات الأولية\", \"الاستغاثة\"]', 'ar', '[\"للوقت الراهن، هل لديك موقف طارئ محدد في ذهنك، مثل الحريق أو الإصابة والاحتياج للمساعدة أو الاتصال بالطوارئ؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي في ذهنك.\"]', '[]', '[{\"original\": \"من فضلك ساعدني في استدعاء سيارة إسعاف.\", \"translated\": \"救急車を呼んでください。\"}, {\"original\": \"أين находится المستشفى؟\", \"translated\": \"病院はどこですか？\"}, {\"original\": \"شخص ما أصيب.\", \"translated\": \"誰かがけがをしました。\"}, {\"original\": \"من فضلك ساعدني.\", \"translated\": \"助けてください。\"}, {\"original\": \"أين находится قسم الشرطة؟\", \"translated\": \"警察署はどこですか？\"}, {\"original\": \"لقد فقدت أغراضي.\", \"translated\": \"荷物をなくしました。\"}, {\"original\": \"ما هو رقم إدارة الإطفاء؟\", \"translated\": \"消防署の電話番号は何ですか？\"}, {\"original\": \"لقد فقدت جواز سفرى. هل تعرف أين يقع أقرب قسم شرطة؟\", \"translated\": \"パスポートを紛失しました。近くの警察署はどこですか？\"}, {\"original\": \"هل يوجد مخرج طوارئ؟\", \"translated\": \"非常口はどこですか？\"}, {\"original\": \"شخص ما فقد وعيه.\", \"translated\": \"誰かが気を失いました。\"}]', 8, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ10 عبارات شائعة يمكنني استخدامها على الشاطئ أو بجانب المسبح؟\", \"رائع! إليك 10 عبارات شائعة تتعلق بالشاطئ أو المسبح مع الترجمة اليابانية:\"]', '[\"السباحة\", \"الاستلقاء تحت أشعة الشمس\", \"الرياضات الشاطئية\"]', 'ar', '[\"حتى الآن، هل يمكنك إخباري بسياق الفعالية أو المهرجان المحلي الذي ستشارك فيه، مثل مهرجان ثقافي أو مهرجان غذائي أو مهرجان موسيقي؟ من فضلك قدِّم السياق.\", \"من فضلك قدِّم الأنشطة التي ستشارك فيها.\"]', '[\"هل لديك موقف محدد في بالك؟ لا تتردد في طرح سؤال.\", \"من فضلك صف الموقف الذي تفكر فيه.\"]', '[{\"original\": \"انظر! الأمواج هناك كبيرة جدًا.\", \"translated\": \"見て！あそこに見える波は本当に大きいですね。\"}, {\"original\": \"تذكَّر أن تضع واقي الشمس، فأشعة فوق البنفسجية هنا قوية جدًا.\", \"translated\": \"日焼け止めを塗ることを忘れないでください。ここでの紫外線はとても強いです。\"}, {\"original\": \"رمل هذه الشاطئ ناعمٌ جدًا، لدرجة أنك تشعر وكأنك تمشي على القطن.\", \"translated\": \"このビーチの砂はとても細かくて、綿の上を歩いているような感触です。\"}, {\"original\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\", \"translated\": \"ビーチでバレーボールをするのはどうですか？\"}, {\"original\": \"القوارب الشراعية في البعيد تبدو جميلة جدًا.\", \"translated\": \"遠くに見えるヨットがとても美しいですね。\"}, {\"original\": \"الماء هنا شفافٌ جدًا، بل إنك تستطيع رؤية الأسماك فيه.\", \"translated\": \"ここでの水はとても透明で、魚まで見えます。\"}, {\"original\": \"هيا نذهب للبحث عن بعض المحار على الشاطئ.\", \"translated\": \"一緒にビーチで貝殻を探しに行きましょう。\"}, {\"original\": \"المشي على الشاطئ عند غروب الشمس لا بد أنه أمرٌ رومانسيٌّ جدًا.\", \"translated\": \"夕暮れ時のビーチを散歩するのは、きっととてもロマンチックでしょう。\"}, {\"original\": \"سمعتُ أن المأكولات البحرية هنا طازجةٌ جدًا، فلنذهب ونجرب بعضها.\", \"translated\": \"ここでは海産物がとても新鮮だと聞きました。ぜひ食べてみましょう。\"}, {\"original\": \"المدّ يرتفع، لذا دعونا نتجه نحو اليابسة.\", \"translated\": \"潮が満ちてきていますから、岸へ向かいましょう。\"}]', 9, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ10 عبارات شائعة أستطيع استخدامها في الفعاليات والمناسبات المحلية؟\", \"رائع جدًا! إليك 10 عبارات شائعة عن الفعاليات والمناسبات المحلية، مع ترجمتها إلى اللغة اليابانية:\"]', '[\"حضور الفعاليات\", \"الاحتفال بالمناسبات والمواسم\", \"تعلم الثقافة\"]', 'ar', '[\"حتى الآن، هل يمكنك أن تزودني بسياق الحدث أو المناسبة المحلية التي تنوي حضورها، مثل هالووين أو حفل موسيقي أو حفلة صديق أو أي شيء آخر؟ يرجى تزويدي بالسياق.\", \"يرجى وصف الأنشطة التي تتخيلها.\"]', '[\"هل لديك موقف محدد في ذهنك؟ لا تتردد في طرح سؤالك.\", \"يرجى وصف الموقف الذي تتخيله.\"]', '[{\"original\": \"هل توجد أي فعاليات اليوم؟\", \"translated\": \"今日は何かイベントがありますか？\"}, {\"original\": \"هل هناك شيءٌ خاصٌّ حول هذه المهرجان؟\", \"translated\": \"この祭りには何か特別なことがありましたか？\"}, {\"original\": \"أين تُقام الاحتفالات؟\", \"translated\": \"お祝いの行事はどこで行われますか？\"}, {\"original\": \"كيف يمكنني شراء التذاكر؟\", \"translated\": \"チケットはどこで購入できますか？\"}, {\"original\": \"في أي وقت تبدأ العرض؟\", \"translated\": \"パフォーマンスはいつから始まりますか？\"}, {\"original\": \"ما الأطعمة التقليدية المتاحة؟\", \"translated\": \"どんな伝統的な食べ物がありますか？\"}, {\"original\": \"المكان حيويٌّ جدًا هنا.\", \"translated\": \"ここは本当に活気がありますね。\"}, {\"original\": \"هل توجد أنشطة تراثية شعبية؟\", \"translated\": \"民俗活動はありますか？\"}, {\"original\": \"كل عام وأنتم بخير!\", \"translated\": \"おめでとうございます！\"}, {\"original\": \"في أي وقت تنتهي الفعالية؟\", \"translated\": \"イベントはいつ終わりますか？\"}]', 10, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بـ10 عبارات شائعة يمكنني استخدامها في المتاحف أو المعارض الفنية؟\", \"رائع! إليك 10 عبارات شائعة تتعلق بالمتاحف أو المعارض الفنية، مع الترجمة اليابانية:\"]', '[\"الزيارة\", \"الجولة الإرشادية\", \"شراء التذاكر\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف معين في بالك؟ مثل طلب كتيب تمهيدي، أو عبارات تتعلق بخريطة الطريق، أو عبارات للتعليق على المعروضات. لا تتردد في السؤال!\", \"من فضلك وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"入館料はいくらですか？\"}, {\"original\": \"هل لديكم أدلة صوتية؟\", \"translated\": \"オーディオガイドはありますか？\"}, {\"original\": \"من هو مُبتكر هذه القطعة الفنية؟\", \"translated\": \"この作品の作者は誰ですか？\"}, {\"original\": \"أين توجد أثمن قطعة في المتحف؟\", \"translated\": \"博物館で最も貴重な作品はどこにありますか？\"}, {\"original\": \"هل يُسمح بالتصوير الفوتوغرافي؟\", \"translated\": \"写真撮影は可能ですか？\"}, {\"original\": \"هل هناك أي معارض خاصة هنا؟\", \"translated\": \"ここには特別展はありますか？\"}, {\"original\": \"كم تستغرق الزيارة من الوقت؟\", \"translated\": \"見学にはどのくらいの時間がかかりますか？\"}, {\"original\": \"هل يمكنكم أن تقدّموا لنا مقدمة؟\", \"translated\": \"ご案内をいただけますか？\"}, {\"original\": \"هذه الأعمال رائعةٌ حقًّا.\", \"translated\": \"これらの作品は本当に素晴らしいです。\"}, {\"original\": \"أين تقع متجر الهدايا التذكارية؟\", \"translated\": \"お土産ショップはどこですか？\"}]', 11, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ10 عبارات شائعة يمكنني استخدامها في مقهى؟\", \"رائع! إليك 10 عبارات شائعة تُستخدم في المقاهي، مع الترجمة اليابانية:\"]', '[\"طلب القهوة\", \"الاسترخاء\", \"التواصل الاجتماعي\"]', 'ar', '[\"لحد الآن، هل لديك موقف معيّن في بالك؟ مثل طلب القائمة، أو المشروبات المثلجة أو الساخنة، أو منتجات أخرى؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف لي الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"سأطلب لاتيه، من فضلك.\", \"translated\": \"ラテを一杯お願いします。\"}, {\"original\": \"هل لديكم اتصال واي فاي؟\", \"translated\": \"Wi-Fiはありますか？\"}, {\"original\": \"هل يمكنني رؤية القائمة، من فضلك؟\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"هل يُسمح بإعادة التزود بالمشروب؟\", \"translated\": \"リフィルはできますか？\"}, {\"original\": \"هل قهتي جاهزة؟\", \"translated\": \"私のコーヒーはできましたか？\"}, {\"original\": \"كم من الوقت يمكنني الجلوس هنا؟\", \"translated\": \"ここにどのくらい座っていられますか？\"}, {\"original\": \"هل يمكنك أخذ صورة لنا؟\", \"translated\": \"私たちの写真を撮ってもらえますか？\"}, {\"original\": \"أين الحمام؟\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"الفاتورة من فضلك. شكرًا لك.\", \"translated\": \"お会計をお願いします。ありがとうございます。\"}, {\"original\": \"المذاق لذيذٌ جدًّا.\", \"translated\": \"すごく美味しいです。\"}]', 12, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Vous pouvez me donner 10 expressions courantes que je peux utiliser au restaurant ?\", \"Super ! Voici 10 expressions courantes liées aux restaurants, avec leur traduction en japonais :\"]', '[\"Restauration\", \"Commande\", \"Règlement\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête ? Par exemple, commander des boissons, formuler une réclamation ou demander des informations sur les ingrédients ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\", \"translated\": \"すみません、料理はあとどのくらいで出来上がりますか？\"}, {\"original\": \"Une table pour deux, s\'il vous plaît.\", \"translated\": \"二人席をお願いします。\"}, {\"original\": \"Pourrions-nous voir la carte, s\'il vous plaît ?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"Avez-vous des plats signature à nous recommander ?\", \"translated\": \"おすすめの自家製料理（看板メニュー）はありますか？\"}, {\"original\": \"Je voudrais commander ceci et cela.\", \"translated\": \"こちらと、こちらを注文したいです。\"}, {\"original\": \"Un verre d\'eau, s\'il vous plaît. Merci.\", \"translated\": \"お水をお願いします。ありがとうございます。\"}, {\"original\": \"L\'addition, s\'il vous plaît.\", \"translated\": \"お会計をお願いします。\"}, {\"original\": \"Puis-je payer par carte bancaire ?\", \"translated\": \"クレジットカードでお支払いできますか？\"}, {\"original\": \"Pourriez-vous emballer cela à emporter, s\'il vous plaît ?\", \"translated\": \"これをテイクアウト用に包んでいただけますか？\"}, {\"original\": \"Le plat était délicieux, merci.\", \"translated\": \"料理はとても美味しかったです。ありがとうございました。\"}]', 1, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser à l\'hôtel ?\", \"Génial ! Voici 10 expressions courantes liées à l’hôtel, avec leur traduction en japonais :\"]', '[\"Enregistrement\", \"Départ\", \"Service d\'étage\"]', 'fr', '[\"Pour le moment, avez-vous une situation précise en tête ? Par exemple, l’emplacement de la chambre, d’autres services hôteliers ou le départ ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Bonjour, j\'ai une réservation. Voici mon passeport.\", \"translated\": \"こんにちは、予約をしております。こちらが私のパスポートです。\"}, {\"original\": \"Avez-vous des chambres disponibles ?\", \"translated\": \"空室はございますか？\"}, {\"original\": \"Excusez-moi, l\'hôtel dispose-t-il d\'une salle de sport ou d\'une blanchisserie ?\", \"translated\": \"すみませんが、ホテルにはジムやランドリールームはありますか？\"}, {\"original\": \"À quelle heure commence le petit-déjeuner ?\", \"translated\": \"朝食は何時からですか？\"}, {\"original\": \"Pourrais-je avoir la clé de ma chambre, s\'il vous plaît ?\", \"translated\": \"お手数ですが、部屋の鍵をいただけますか？\"}, {\"original\": \"Pourriez-vous m\'aider à porter mes bagages jusqu\'à ma chambre ?\", \"translated\": \"荷物を部屋まで運んでいただけますか？\"}, {\"original\": \"Comment puis-je appeler le service d\'étage ?\", \"translated\": \"ルームサービスへはどうやって連絡すればよいですか？\"}, {\"original\": \"À quelle heure est la sortie ?\", \"translated\": \"チェックアウトの時間は何時ですか？\"}, {\"original\": \"Pourriez-vous me faire un reçu / une facture ?\", \"translated\": \"領収書／請求書を発行していただけますか？\"}, {\"original\": \"Puis-je laisser mes bagages ici ?\", \"translated\": \"荷物をここに預けても大丈夫ですか？\"}]', 2, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser à l\'aéroport ?\", \"Super ! Voici 10 expressions courantes liées à l\'aéroport, avec leur traduction en japonais :\"]', '[\"Enregistrement\", \"Embarquement\", \"Bagages\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, comme l\'enregistrement, le retrait des bagages ou la location de voiture ? N\'hésitez pas à demander !\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Où se trouve le comptoir d\'enregistrement ?\", \"translated\": \"チェックインカウンターはどこですか？\"}, {\"original\": \"Je voudrais un siège côté fenêtre, s\'il vous plaît.\", \"translated\": \"窓側の席をお願いします。\"}, {\"original\": \"Ce vol est-il retardé ?\", \"translated\": \"この便は遅れていますか？\"}, {\"original\": \"Je dois enregistrer ce bagage.\", \"translated\": \"この荷物を預けたいです。\"}, {\"original\": \"Où se trouve la porte d\'embarquement ?\", \"translated\": \"搭乗口はどこですか？\"}, {\"original\": \"L\'avion va bientôt décoller.\", \"translated\": \"飛行機がもうすぐ離陸します。\"}, {\"original\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\", \"translated\": \"ノートパソコンとモバイルバッテリーはバッグから出さなければなりませんか？\"}, {\"original\": \"Où se trouve la boutique duty-free ?\", \"translated\": \"免税店はどこですか？\"}, {\"original\": \"Je ne trouve pas ma valise.\", \"translated\": \"私のスーツケースが見つかりません。\"}, {\"original\": \"Proposez-vous un service de fauteuil roulant ?\", \"translated\": \"車椅子のサービスはありますか？\"}]', 3, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans les transports en commun ?\", \"Super ! Voici 10 expressions courantes liées aux transports en commun, avec leurs traductions en japonais :\"]', '[\"Prendre le bus ou le métro\", \"Acheter des billets\", \"Changer de transport\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête ? Par exemple, demander l\'arrêt de bus, le prix du billet ou quand descendre — n\'hésitez pas à demander !\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Ce bus va-t-il jusqu\'à la gare routière ?\", \"translated\": \"このバスはターミナルまで行きますか？\"}, {\"original\": \"Quel est le prochain arrêt ?\", \"translated\": \"次の停留所はどこですか？\"}, {\"original\": \"Où puis-je acheter un billet ?\", \"translated\": \"切符はどこで買えますか？\"}, {\"original\": \"Un billet pour XX, s\'il vous plaît.\", \"translated\": \"XX行きの切符を1枚、お願いします。\"}, {\"original\": \"Dois-je changer de transport ?\", \"translated\": \"乗り換えが必要ですか？\"}, {\"original\": \"Dans combien de temps arrive le prochain train du métro ?\", \"translated\": \"次の地下鉄の列車はあとどのくらいで来ますか？\"}, {\"original\": \"Excusez-moi, je dois passer.\", \"translated\": \"すみません、通らせてください。\"}, {\"original\": \"Cette place est-elle prise ?\", \"translated\": \"この席は空いていますか？\"}, {\"original\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d\'aller à XX ?\", \"translated\": \"すみません、XXへ行くために2号線に乗り換えるには、どこで乗り換えればいいですか？\"}, {\"original\": \"Comment puis-je me rendre à XX ?\", \"translated\": \"XXへはどうやって行けばいいですか？\"}]', 4, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser sur un site touristique ?\", \"Génial ! Voici 10 expressions courantes utiles sur les sites touristiques, avec leur traduction en japonais :\"]', '[\"Visite touristique\", \"Prendre des photos\", \"Acheter des billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander le prix des billets, trouver un parking ou un service de guide touristique ? N\'hésitez pas à demander !\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Combien coûte l\'entrée ?\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"Y a-t-il des billets étudiants disponibles ?\", \"translated\": \"学生用の割引チケットはありますか？\"}, {\"original\": \"À quelle heure l\'attraction ouvre-t-elle ?\", \"translated\": \"観光スポットの営業時間は何時からですか？\"}, {\"original\": \"Quelles sont les activités amusantes à faire ici ?\", \"translated\": \"ここではどんな楽しいことができますか？\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"Où se trouve le bus touristique ?\", \"translated\": \"観光バスの乗り場はどこですか？\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"トイレはどこにありますか？\"}, {\"original\": \"Où est le meilleur point de vue ?\", \"translated\": \"一番景色のいい展望スポットはどこですか？\"}, {\"original\": \"Le paysage est magnifique ici.\", \"translated\": \"ここからの景色はとてもきれいです。\"}, {\"original\": \"Une visite guidée est-elle disponible ?\", \"translated\": \"ガイド付きツアーはありますか？\"}]', 5, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser pour prendre un taxi ou utiliser un service de taxi ?\", \"Génial ! Voici 10 expressions courantes liées aux taxis ou aux services de taxi, avec leur traduction en japonais :\"]', '[\"Prendre un taxi\", \"Indiquer la destination\", \"Paiement\"]', 'fr', '[\"Pour l’instant, que voulez-vous faire en priorité ? Par exemple, indiquer votre destination, demander le prix, ou demander un reçu — n’hésitez pas à poser vos questions !\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Où puis-je prendre un taxi ?\", \"translated\": \"タクシーはどこで乗れますか？\"}, {\"original\": \"Veuillez me conduire à cette adresse.\", \"translated\": \"この住所までお願いします。\"}, {\"original\": \"Combien cela coûtera-t-il approximativement ?\", \"translated\": \"だいたいいくらぐらいかかりますか？\"}, {\"original\": \"Pourriez-vous utiliser le compteur, s’il vous plaît ?\", \"translated\": \"メーターを使ってもらえますか？\"}, {\"original\": \"Pourriez-vous conduire un peu plus vite ? Je suis pressé(e).\", \"translated\": \"少し速く運転してもらえますか？急いでいます。\"}, {\"original\": \"Veuillez vous arrêter ici.\", \"translated\": \"ここで止めてください。\"}, {\"original\": \"Acceptez-vous les cartes bancaires ou les paiements mobiles ?\", \"translated\": \"クレジットカードやモバイル決済は使えますか？\"}, {\"original\": \"Pourrais-je avoir un reçu, s’il vous plaît ?\", \"translated\": \"領収書をいただけますか？\"}, {\"original\": \"Merci, chauffeur.\", \"translated\": \"ありがとう、ドライバーさん。\"}, {\"original\": \"Il reste encore combien de temps ?\", \"translated\": \"あとどれくらいですか？\"}]', 6, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Vous pouvez me fournir 10 expressions courantes que je pourrais utiliser en pharmacie ?\", \"Super ! Voici 10 expressions courantes liées à la pharmacie, avec leur traduction en japonais :\"]', '[\"Acheter des médicaments\", \"Consulter\", \"Payer\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander des instructions sur la prise d’un médicament, des formulations liées à l’utilisation de l’assurance maladie ou à la durée du traitement ? N’hésitez pas à demander !\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Avez-vous des médicaments contre le rhume ?\", \"translated\": \"風邪薬はありますか？\"}, {\"original\": \"Comment dois-je prendre ce médicament ?\", \"translated\": \"この薬の飲み方はどうすればいいですか？\"}, {\"original\": \"Avez-vous des analgésiques ?\", \"translated\": \"鎮痛剤はありますか？\"}, {\"original\": \"Y a-t-il une notice d’utilisation ?\", \"translated\": \"説明書はついていますか？\"}, {\"original\": \"Ce médicament a-t-il des effets secondaires ?\", \"translated\": \"この薬には副作用がありますか？\"}, {\"original\": \"Puis-je utiliser ma carte d’assurance maladie ?\", \"translated\": \"医療保険証は使えますか？\"}, {\"original\": \"Pourriez-vous me donner une boîte de pansements, s’il vous plaît ?\", \"translated\": \"絆創膏を1箱お願いできますか？\"}, {\"original\": \"Avez-vous des médicaments contre la fièvre ?\", \"translated\": \"解熱剤はありますか？\"}, {\"original\": \"Je me suis un peu écorché. Avez-vous un antiseptique et des pansements ?\", \"translated\": \"ちょっと擦り傷をしました。消毒液と絆創膏はありますか？\"}, {\"original\": \"À quelle heure fermez-vous ?\", \"translated\": \"何時まで営業していますか？\"}]', 7, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Vous pouvez me donner 10 expressions courantes que je peux utiliser pour les services d\'urgence ?\", \"Génial ! Voici 10 expressions courantes liées aux services d\'urgence, accompagnées de leur traduction en japonais :\"]', '[\"Appeler la police\", \"Premiers soins\", \"Demander de l\'aide\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation d\'urgence précise en tête, par exemple : incendie, blessure nécessitant de l\'aide, appel d\'urgence ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Veuillez m\'aider à appeler une ambulance.\", \"translated\": \"救急車を呼んでください。\"}, {\"original\": \"Où se trouve l\'hôpital ?\", \"translated\": \"病院はどこですか？\"}, {\"original\": \"Quelqu\'un est blessé.\", \"translated\": \"誰かが怪我をしています。\"}, {\"original\": \"Veuillez m\'aider.\", \"translated\": \"助けてください。\"}, {\"original\": \"Où se trouve le commissariat de police ?\", \"translated\": \"警察署はどこですか？\"}, {\"original\": \"J\'ai perdu mes affaires.\", \"translated\": \"荷物をなくしました。\"}, {\"original\": \"Quel est le numéro du service des pompiers ?\", \"translated\": \"消防署の電話番号は何番ですか？\"}, {\"original\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le commissariat de police le plus proche ?\", \"translated\": \"パスポートを紛失しました。一番近い警察署はどこですか？\"}, {\"original\": \"Y a-t-il une sortie de secours ?\", \"translated\": \"非常口はありますか？\"}, {\"original\": \"Quelqu\'un s\'est évanoui.\", \"translated\": \"誰かが気を失いました。\"}]', 8, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Vous pouvez me fournir 10 expressions courantes que je peux utiliser à la plage ou au bord de la piscine ?\", \"Génial ! Voici 10 expressions courantes liées à la plage ou à la piscine, avec leur traduction en japonais :\"]', '[\"Natation\", \"Bronzage\", \"Sports de plage\"]', 'fr', '[\"Pour l’instant, pourriez-vous me préciser le contexte de l’événement ou du festival local auquel vous participez, par exemple un festival culturel, un festival gastronomique ou un festival musical ? Veuillez fournir ce contexte.\", \"Veuillez décrire les activités auxquelles vous participez.\"]', '[\"Avez-vous une situation précise en tête ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\", \"translated\": \"見て！あそこに見える波が本当に大きいですよ。\"}, {\"original\": \"N\'oubliez pas d\'appliquer de la crème solaire : les rayons UV sont très forts ici.\", \"translated\": \"日焼け止めを塗ることを忘れないでください。ここでの紫外線はとても強いです。\"}, {\"original\": \"Le sable de cette plage est si fin qu’on a l’impression de marcher sur du coton.\", \"translated\": \"このビーチの砂はとても細かくて、綿の上を歩いているような感覚です。\"}, {\"original\": \"Et si on jouait au volley-ball sur la plage ?\", \"translated\": \"ビーチでバレーボールをしませんか？\"}, {\"original\": \"Les voiliers au loin sont magnifiques.\", \"translated\": \"遠くに見えるヨットがとてもきれいですね。\"}, {\"original\": \"L’eau ici est si claire qu’on peut même voir les poissons.\", \"translated\": \"ここでの水はとても透明度が高く、魚まで見えます。\"}, {\"original\": \"Allons chercher des coquillages !\", \"translated\": \"貝殻を探しに行きましょう！\"}, {\"original\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\", \"translated\": \"夕日に染まるビーチを散歩するのは、きっととてもロマンチックですね。\"}, {\"original\": \"J’ai entendu dire que les fruits de mer ici sont très frais ; allons-en déguster !\", \"translated\": \"ここではシーフードがとても新鮮だと聞きました。ぜひ食べてみましょう！\"}, {\"original\": \"La marée monte ; rentrons vers la berge.\", \"translated\": \"満潮になってきています。それでは岸へ戻りましょう。\"}]', 9, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je pourrais utiliser lors d\'événements et de festivals locaux ?\", \"Génial ! Voici 10 expressions courantes liées aux événements et festivals locaux, avec leur traduction en japonais :\"]', '[\"Assister à des événements\", \"Célébrer des festivals\", \"Découvrir la culture\"]', 'fr', '[\"Pour l\'instant, pourriez-vous me préciser le contexte de l\'événement ou du festival local auquel vous comptez participer — par exemple, Halloween, un concert, une fête entre amis, ou autre chose ? Merci de nous donner ce contexte.\", \"Veuillez décrire les activités qui vous viennent à l\'esprit.\"]', '[\"Avez-vous une situation précise en tête ? N\'hésitez pas à poser votre question librement.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[{\"original\": \"Y a-t-il des événements aujourd\'hui ?\", \"translated\": \"今日は何かイベントがありますか？\"}, {\"original\": \"Y a-t-il quelque chose de spécial à propos de ce festival ?\", \"translated\": \"このお祭りには、何か特別なことがありますか？\"}, {\"original\": \"Où se déroule la célébration ?\", \"translated\": \"お祝いはどこで行われますか？\"}, {\"original\": \"Comment puis-je acheter des billets ?\", \"translated\": \"チケットはどこで購入できますか？\"}, {\"original\": \"À quelle heure commence le spectacle ?\", \"translated\": \"パフォーマンスはいつから始まりますか？\"}, {\"original\": \"Quels sont les plats traditionnels proposés ?\", \"translated\": \"どんな伝統的な食べ物がありますか？\"}, {\"original\": \"C\'est vraiment animé ici !\", \"translated\": \"ここって本当に活気がありますね！\"}, {\"original\": \"Y a-t-il des activités folkloriques ?\", \"translated\": \"民俗活動はありますか？\"}, {\"original\": \"Joyeuses fêtes !\", \"translated\": \"楽しい休日を！\"}, {\"original\": \"À quelle heure se termine l\'événement ?\", \"translated\": \"イベントはいつ終わりますか？\"}]', 10, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Vous pouvez me fournir 10 expressions courantes que je pourrais utiliser dans un musée ou une galerie ?\", \"Génial ! Voici 10 expressions courantes liées aux musées et galeries, avec leur traduction en japonais ：\"]', '[\"Visite\", \"Visite guidée\", \"Achat de billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander un guide d\'introduction, des expressions liées au plan du musée, des expressions pour commenter une exposition ? N\'hésitez pas à demander !\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Combien coûte le droit d\'entrée ?\", \"translated\": \"入館料はいくらですか？\"}, {\"original\": \"Avez-vous des audioguides ?\", \"translated\": \"オーディオガイドはありますか？\"}, {\"original\": \"Qui est l\'auteur de cette œuvre ?\", \"translated\": \"この作品の作者は誰ですか？\"}, {\"original\": \"Où se trouve la pièce la plus précieuse du musée ?\", \"translated\": \"美術館・博物館で最も貴重な作品はどこにありますか？\"}, {\"original\": \"La photographie est-elle autorisée ?\", \"translated\": \"写真撮影は許可されていますか？\"}, {\"original\": \"Y a-t-il des expositions spéciales ici ?\", \"translated\": \"こちらでは特別展は開催されていますか？\"}, {\"original\": \"Combien de temps dure la visite ?\", \"translated\": \"見学にはどのくらいの時間がかかりますか？\"}, {\"original\": \"Pourriez-vous nous donner une introduction ?\", \"translated\": \"簡単にご紹介いただけますか？\"}, {\"original\": \"Ces œuvres sont vraiment exquises.\", \"translated\": \"これらの作品は本当に素晴らしいです。\"}, {\"original\": \"Où se trouve la boutique de souvenirs ?\", \"translated\": \"お土産ショップはどこにありますか？\"}]', 11, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans un café ?\", \"Génial ! Voici 10 expressions courantes utilisées dans les cafés, accompagnées de leur traduction en japonais :\"]', '[\"Commander un café\", \"Se détendre\", \"Socialiser\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête ? Par exemple, demander la carte, choisir entre boisson chaude ou glacée, commander d\'autres produits… N\'hésitez pas à poser vos questions !\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Je voudrais un latte, s\'il vous plaît.\", \"translated\": \"ラテを一つお願いします。\"}, {\"original\": \"Vous avez du Wi-Fi ?\", \"translated\": \"Wi-Fiは使えますか？\"}, {\"original\": \"Pourrais-je voir la carte, s\'il vous plaît ?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"Les remplissages sont-ils autorisés ?\", \"translated\": \"追加注文（リフィル）はできますか？\"}, {\"original\": \"Mon café est-il prêt ?\", \"translated\": \"私のコーヒーはできましたか？\"}, {\"original\": \"Combien de temps puis-je rester ici ?\", \"translated\": \"ここにはどのくらいの時間座っていられますか？\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"私たちの写真を撮ってもらえませんか？\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"L\'addition, s\'il vous plaît. Merci.\", \"translated\": \"お会計をお願いします。ありがとうございます。\"}, {\"original\": \"C\'est vraiment délicieux.\", \"translated\": \"とても美味しいです。\"}]', 12, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"レストランで使える10個のよく使う表現を教えていただけますか？\", \"素晴らしい！こちらにレストラン関連の10個のよく使う表現と、その中国語訳を載せました：\"]', '[\"食事\", \"注文\", \"会計\"]', 'ja', '[\"今のところ、ドリンクの注文やクレーム、食材の確認など、具体的な状況が思い浮かびますか？気軽に聞いてください。\", \"あなたの頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"すみません、料理はあとどのくらいで来ますか？\", \"translated\": \"不好意思，我们的餐还要等多久？\"}, {\"original\": \"二人用のテーブルをお願いします。\", \"translated\": \"请给我们一张两人桌。\"}, {\"original\": \"メニューを見せていただけますか？\", \"translated\": \"能看一下菜单吗？\"}, {\"original\": \"おすすめの定番料理はありますか？\", \"translated\": \"你们有什么招牌菜可以推荐吗？\"}, {\"original\": \"これを注文したいです。あと、これもお願いします。\", \"translated\": \"我要点这个，还有这个。\"}, {\"original\": \"お水を一杯お願いします。ありがとうございます。\", \"translated\": \"请给我一杯水，谢谢！\"}, {\"original\": \"お会計をお願いします。\", \"translated\": \"请结账。\"}, {\"original\": \"クレジットカードで支払えますか？\", \"translated\": \"可以用信用卡付款吗？\"}, {\"original\": \"これをテイクアウトでお願いできますか？\", \"translated\": \"这个能打包带走吗？\"}, {\"original\": \"料理がとても美味しかったです。ありがとうございました。\", \"translated\": \"食物非常美味，谢谢！\"}]', 1, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ホテルで使える10個のよく使うフレーズを教えてもらえますか？\", \"素晴らしい！ホテル関連のよく使う10個のフレーズとその中国語訳を以下にご用意しました：\"]', '[\"チェックイン\", \"チェックアウト\", \"ルームサービス\"]', 'ja', '[\"今のところ、客室の位置や他のホテルサービス、あるいはチェックアウトなど、具体的な状況をお考えですか？何でも遠慮なくお聞きください。\", \"頭の中でイメージしている状況を教えてください。\"]', '[]', '[{\"original\": \"こんにちは。予約しています。こちらが私のパスポートです。\", \"translated\": \"你好，我有预订。这是我的护照。\"}, {\"original\": \"空室はありますか？\", \"translated\": \"还有空房吗？\"}, {\"original\": \"すみません、このホテルにはジムやランドリールームはありますか？\", \"translated\": \"打扰一下，酒店有健身房或洗衣房吗？\"}, {\"original\": \"朝食は何時からですか？\", \"translated\": \"早餐几点开始？\"}, {\"original\": \"ルームキーをいただけますか？\", \"translated\": \"可以给我房间钥匙吗？\"}, {\"original\": \"荷物を部屋まで運んでいただけますか？\", \"translated\": \"您能帮我把行李送到房间吗？\"}, {\"original\": \"ルームサービスの呼び出し方はどうすればいいですか？\", \"translated\": \"怎么呼叫客房服务？\"}, {\"original\": \"チェックアウトは何時ですか？\", \"translated\": \"退房时间是几点？\"}, {\"original\": \"領収書／請求書を書いていただけますか？\", \"translated\": \"可以为我开一张收据／发票吗？\"}, {\"original\": \"荷物をここに預けても大丈夫ですか？\", \"translated\": \"我可以把行李寄存在这里吗？\"}]', 2, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"空港で使える、よく使う10個の短語を教えていただけますか？\", \"すごいですね！こちらに、空港でよく使う10個の表現と中国語訳を載せました：\"]', '[\"チェックイン\", \"搭乗\", \"手荷物検査\"]', 'ja', '[\"今のところ、チェックイン、手荷物受取、またはレンタカーなどの具体的な状況が頭に浮かびますか？ぜひお気軽にお尋ねください。\", \"頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"チェックインカウンターはどこですか？\", \"translated\": \"值机柜台在哪里？\"}, {\"original\": \"窓側の席をお願いします。\", \"translated\": \"我想要一个靠窗的座位。\"}, {\"original\": \"この便は遅れていますか？\", \"translated\": \"这趟航班延误了吗？\"}, {\"original\": \"この荷物を預けたいのですが。\", \"translated\": \"我想托运行李。\"}, {\"original\": \"搭乗口はどこですか？\", \"translated\": \"登机口在哪里？\"}, {\"original\": \"飛行機が今から離陸します。\", \"translated\": \"飞机马上就要起飞了。\"}, {\"original\": \"ノートパソコンとモバイルバッテリーは持ち出す必要がありますか？\", \"translated\": \"我需要把笔记本电脑和充电宝拿出来吗？\"}, {\"original\": \"免税店はどこですか？\", \"translated\": \"免税店在哪里？\"}, {\"original\": \"私のスーツケースが見つかりません。\", \"translated\": \"我找不到我的行李箱了。\"}, {\"original\": \"車椅子サービスはありますか？\", \"translated\": \"你们提供轮椅服务吗？\"}]', 3, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"公共交通機関で使える10個のよく使われる言い回しを教えていただけますか？\", \"素晴らしい！ここに、公共交通機関で使える10個のよく使われる言い回しを、中国語の訳とともにご紹介します：\"]', '[\"バス・地下鉄を利用する\", \"切符を購入する\", \"乗り換える\"]', 'ja', '[\"今のところ、バス停の確認、料金の確認、降車などの具体的な状況が頭に浮かんでいますか？何かあれば、遠慮なく聞いてください。\", \"頭の中に思い浮かんでいる状況を教えてください。\"]', '[]', '[{\"original\": \"このバスは終点へ行きますか？\", \"translated\": \"这趟公交车去终点站吗？\"}, {\"original\": \"次の停留所はどこですか？\", \"translated\": \"下一站是哪儿？\"}, {\"original\": \"切符はどこで買えますか？\", \"translated\": \"我在哪里可以买票？\"}, {\"original\": \"XX行きの切符を1枚、お願いします。\", \"translated\": \"请给我一张去XX的车票。\"}, {\"original\": \"乗り換えが必要ですか？\", \"translated\": \"我需要换乘吗？\"}, {\"original\": \"次の地下鉄の列車まで、あと何分ですか？\", \"translated\": \"下一班地铁还要等多久？\"}, {\"original\": \"すみません、通らせてください。\", \"translated\": \"不好意思，麻烦让我过去一下。\"}, {\"original\": \"この席は空いていますか？\", \"translated\": \"这个座位有人坐吗？\"}, {\"original\": \"すみません、XXへ行くには2号線に乗り換えるにはどこで乗り換えればいいですか？\", \"translated\": \"不好意思，请问我要去XX，该在哪儿换乘2号线？\"}, {\"original\": \"XXへはどう行けばいいですか？\", \"translated\": \"我怎么去XX？\"}]', 4, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"観光スポットで使える10個のよく使うフレーズを教えていただけますか？\", \"すごいですね！観光スポットでよく使う10個のフレーズを、中国語訳付きでご紹介します：\"]', '[\"観光\", \"写真撮影\", \"チケット購入\"]', 'ja', '[\"今のところ、チケットの価格を尋ねる、駐車場を探す、ガイドサービスを利用するなど、具体的な状況が頭に浮かんでいますか？どうぞ自由にお尋ねください。\", \"頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"入場料はいくらですか？\", \"translated\": \"门票多少钱？\"}, {\"original\": \"学生向けの割引チケットはありますか？\", \"translated\": \"有学生票吗？\"}, {\"original\": \"観光スポットの開園時間はいつですか？\", \"translated\": \"景点几点开门？\"}, {\"original\": \"ここではどんな楽しいことが出来ますか？\", \"translated\": \"这里有哪些好玩的项目？\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"能帮我们拍张照吗？\"}, {\"original\": \"観光バスの乗り場はどこですか？\", \"translated\": \"观光巴士在哪里？\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"厕所在哪儿？\"}, {\"original\": \"一番景色がいい展望スポットはどこですか？\", \"translated\": \"最佳观景点在哪儿？\"}, {\"original\": \"ここでの景色はとても美しいですね。\", \"translated\": \"这里的风景真美啊。\"}, {\"original\": \"ガイド付きツアーはありますか？\", \"translated\": \"有导游讲解服务吗？\"}]', 5, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"タクシーまたは配車サービスで使える、よく使われる10の短語を教えていただけますか？\", \"素晴らしい！こちらに、タクシーまたは配車サービスに関するよく使われる10の短語と、それぞれの中国語訳を載せました：\"]', '[\"タクシーを利用する\", \"行き先を伝える\", \"支払い\"]', 'ja', '[\"今のところ、目的地を尋ねたり、料金を確認したり、領収書を請求したり…何でも気軽に聞いてくださいね。\", \"頭の中で思い浮かべている状況を教えてください。\"]', '[]', '[{\"original\": \"タクシーはどこで乗れますか？\", \"translated\": \"我在哪里可以打到出租车？\"}, {\"original\": \"こちらの住所までお願いします。\", \"translated\": \"请送我去这个地址。\"}, {\"original\": \"だいたいいくらぐらいかかりますか？\", \"translated\": \"大概要多少钱？\"}, {\"original\": \"メーターを使ってくださいませんか？\", \"translated\": \"您能打表计费吗？\"}, {\"original\": \"急いでいますので、少しだけスピードを上げてもらえますか？\", \"translated\": \"我赶时间，请开快一点。\"}, {\"original\": \"ここで止めてください。\", \"translated\": \"请在这里停车。\"}, {\"original\": \"カードやモバイル決済は使えますか？\", \"translated\": \"你们接受刷卡或手机支付吗？\"}, {\"original\": \"領収書をいただけますか？\", \"translated\": \"可以给我一张收据吗？\"}, {\"original\": \"ありがとうございました、運転手さん。\", \"translated\": \"谢谢您，司机师傅！\"}, {\"original\": \"あとどのくらいですか？\", \"translated\": \"还有多远？\"}]', 6, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"薬局で使える便利な10個の日常会話フレーズを教えていただけますか？\", \"素晴らしい！こちらに薬局関連のよく使う10フレーズとその中国語訳を載せました：\"]', '[\"薬の購入\", \"相談\", \"支払い\"]', 'ja', '[\"今のところ、例えば「薬の飲み方を聞く」「保険の使い方について尋ねる」「薬の使用期間を確認する」など、具体的なシーンが思い浮かびますか？ぜひ遠慮なく聞いてください。\", \"頭の中にあるシチュエーションを具体的に教えてください。\"]', '[]', '[{\"original\": \"風邪薬はありますか？\", \"translated\": \"你有感冒药吗？\"}, {\"original\": \"このお薬の使い方はどうすればいいですか？\", \"translated\": \"这个药该怎么服用？\"}, {\"original\": \"痛み止めはありますか？\", \"translated\": \"你有止痛药吗？\"}, {\"original\": \"説明書は付いていますか？\", \"translated\": \"这个药附带说明书吗？\"}, {\"original\": \"このお薬には副作用がありますか？\", \"translated\": \"这种药有什么副作用吗？\"}, {\"original\": \"医療保険証を使えますか？\", \"translated\": \"我能用医保卡吗？\"}, {\"original\": \"バンドエイドを1箱いただけますか？\", \"translated\": \"请给我一盒创可贴。\"}, {\"original\": \"解熱剤はありますか？\", \"translated\": \"你有退烧药吗？\"}, {\"original\": \"ちょっと擦り傷をしたんですが、消毒液とバンドエイドはありますか？\", \"translated\": \"我有点擦伤，你们有消毒液和创可贴吗？\"}, {\"original\": \"何時まで営業していますか？\", \"translated\": \"你们几点关门？\"}]', 7, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"緊急サービスで使える、よく使う10の短語を教えていただけますか？\", \"素晴らしい！緊急サービスに関するよく使う10の短語と、その中国語訳を以下にご用意しました：\"]', '[\"警察を呼ぶ\", \"応急処置\", \"助けを求める\"]', 'ja', '[\"今のところ、火事、けがをして助けが必要、緊急通報など、具体的な緊急状況をお考えですか？何でも気軽に聞いてください。\", \"頭の中で思い浮かべている状況を教えてください。\"]', '[]', '[{\"original\": \"救急車を呼んでください。\", \"translated\": \"请帮我叫一辆救护车。\"}, {\"original\": \"病院はどこですか？\", \"translated\": \"医院在哪里？\"}, {\"original\": \"誰かがけがをしました。\", \"translated\": \"有人受伤了。\"}, {\"original\": \"助けてください。\", \"translated\": \"请帮帮我。\"}, {\"original\": \"警察署はどこですか？\", \"translated\": \"警察局在哪里？\"}, {\"original\": \"荷物をなくしてしまいました。\", \"translated\": \"我的物品丢失了。\"}, {\"original\": \"消防署の電話番号は何番ですか？\", \"translated\": \"消防部门的电话号码是多少？\"}, {\"original\": \"パスポートを紛失しました。一番近い警察署はどこですか？\", \"translated\": \"我丢了护照。您知道最近的警察局在哪里吗？\"}, {\"original\": \"非常口はありますか？\", \"translated\": \"有安全出口吗？\"}, {\"original\": \"誰かが気を失いました。\", \"translated\": \"有人昏倒了。\"}]', 8, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"私に、ビーチやプールサイドで使える10個の日常会話フレーズを教えていただけますか？\", \"素晴らしい！こちらに、ビーチやプールサイドに関する10個の日常会話フレーズと、その中国語訳を添えてお届けします：\"]', '[\"泳ぐ\", \"日光浴\", \"ビーチスポーツ\"]', 'ja', '[\"今のところ、ご参加予定の現地イベントやフェスティバル（例：文化祭、フードフェス、音楽フェスなど）の具体的な背景を教えていただけますか？\", \"ご参加予定のアクティビティを教えてください。\"]', '[\"何か特定の状況をお考えですか？何でも気軽にお尋ねください。\", \"あなたの頭の中にある状況を教えてください。\"]', '[{\"original\": \"見て！あそこにある波は本当に大きいわ。\", \"translated\": \"看！那边的浪真大啊。\"}, {\"original\": \"日焼け止めを塗ることを忘れないでね。ここでの紫外線はとても強いわ。\", \"translated\": \"别忘了涂防晒霜，这里的紫外线很强。\"}, {\"original\": \"このビーチの砂はすごく細かくて、綿の上を歩いているみたいだわ。\", \"translated\": \"这片海滩的沙子特别细腻，踩上去像走在棉花上一样。\"}, {\"original\": \"ビーチでバレーボールをやるのはどう？\", \"translated\": \"要不要在海滩打排球？\"}, {\"original\": \"遠くのセーリングボートがとてもきれいに見えるわ。\", \"translated\": \"远处的帆船看起来真美。\"}, {\"original\": \"ここで水はとても透明で、魚まで見えるわ。\", \"translated\": \"这里的海水特别清澈，连鱼都能看见。\"}, {\"original\": \"さあ、貝殻を探しに行こう！\", \"translated\": \"我们去找些贝壳吧！\"}, {\"original\": \"夕焼け時にビーチを散歩するのは、きっととてもロマンチックよね。\", \"translated\": \"夕阳下在海滩散步，一定很浪漫。\"}, {\"original\": \"ここではシーフードがとても新鮮だって聞いたから、食べてみようよ。\", \"translated\": \"听说这里的海鲜特别新鲜，咱们去尝尝吧！\"}, {\"original\": \"潮が満ちてきているわ。岸へ向かいましょう。\", \"translated\": \"涨潮了，咱们往岸边走吧。\"}]', 9, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"現地の行事や祭りで使える、10個のよく使うフレーズを教えていただけますか？\", \"素晴らしいです！以下に、現地の行事・祭りに関するよく使う10フレーズとその中国語訳をご紹介します：\"]', '[\"イベントへの参加\", \"祭りの祝い\", \"文化の学習\"]', 'ja', '[\"今のところ、ハロウィン、コンサート、友達とのパーティーなど、ご参加予定の現地の行事や祭りについて、もう少し具体的な状況を教えていただけますか？状況をお知らせください。\", \"あなたの頭にあるアクティビティを教えてください。\"]', '[\"特に思い浮かぶ状況はありますか？何でも気軽に聞いてください。\", \"あなたの頭にある状況を教えてください。\"]', '[{\"original\": \"今日は何かイベントがありますか？\", \"translated\": \"今天有什么活动吗？\"}, {\"original\": \"このお祭りには何か特別な点がありますか？\", \"translated\": \"这个节日有什么特别之处吗？\"}, {\"original\": \"お祝いはどこで行われますか？\", \"translated\": \"庆祝活动在哪里举行？\"}, {\"original\": \"切符はどこで購入できますか？\", \"translated\": \"我该怎么买票？\"}, {\"original\": \"パフォーマンスは何時から始まりますか？\", \"translated\": \"演出什么时候开始？\"}, {\"original\": \"どんな伝統的な食べ物がありますか？\", \"translated\": \"有哪些传统食物？\"}, {\"original\": \"ここは本当ににぎやかですね。\", \"translated\": \"这里真热闹啊。\"}, {\"original\": \"民俗活動はありますか？\", \"translated\": \"有民间活动吗？\"}, {\"original\": \"おめでとうございます！\", \"translated\": \"节日快乐！\"}, {\"original\": \"イベントはいつ終わりますか？\", \"translated\": \"活动什么时候结束？\"}]', 10, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"私に、博物館や美術館で使える10個のよく使うフレーズを教えていただけますか？\", \"素晴らしい！こちらに、博物館や美術館関連のよく使うフレーズ10個とその中国語訳を載せました：\"]', '[\"来館\", \"ガイド付き見学\", \"チケット購入\"]', 'ja', '[\"今のところ、例えば案内パンフレットを尋ねる場合、ルートマップに関係するフレーズ、展示品に対する感想を述べるフレーズなど、具体的なシーンをお考えですか？ご自由にお聞きください。\", \"あなたの頭の中にあるシーンを具体的に教えてください。\"]', '[]', '[{\"original\": \"入館料はいくらですか？\", \"translated\": \"门票多少钱？\"}, {\"original\": \"オーディオガイドはありますか？\", \"translated\": \"有语音导览吗？\"}, {\"original\": \"この作品は誰が制作しましたか？\", \"translated\": \"这件艺术品是谁创作的？\"}, {\"original\": \"博物館で最も貴重な所蔵品はどこにありますか？\", \"translated\": \"博物馆最珍贵的藏品在哪里？\"}, {\"original\": \"写真撮影は許可されていますか？\", \"translated\": \"允许拍照吗？\"}, {\"original\": \"ここには特別展示がありますか？\", \"translated\": \"这里有特别展览吗？\"}, {\"original\": \"見学にはどれくらい時間がかかりますか？\", \"translated\": \"参观需要多长时间？\"}, {\"original\": \"簡単に紹介していただけますか？\", \"translated\": \"能为我们简单介绍一下吗？\"}, {\"original\": \"これらの作品は本当に素晴らしいですね。\", \"translated\": \"这些作品真的很精美。\"}, {\"original\": \"お土産ショップはどこですか？\", \"translated\": \"纪念品商店在哪儿？\"}]', 11, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"カフェで使える10個のよく使う言い回しを教えていただけますか？\", \"素晴らしい！以下はカフェで使える10個の定番フレーズとその中国語訳です：\"]', '[\"コーヒーを注文する\", \"休憩する\", \"交流する\"]', 'ja', '[\"今のところ、メニューを見せてもらう・アイス/ホットドリンクを頼む・他の商品を尋ねるなど、特定のシーンが思い浮かびますか？どんなことも気軽に聞いてください。\", \"頭の中で思い浮かべているシーンを教えてください。\"]', '[]', '[{\"original\": \"ラテをいただきます。\", \"translated\": \"我要一杯拿铁。\"}, {\"original\": \"Wi-Fiは使えますか？\", \"translated\": \"有Wi-Fi吗？\"}, {\"original\": \"メニューを見せていただいてもいいですか？\", \"translated\": \"我可以看一下菜单吗？\"}, {\"original\": \"リフィルは可能ですか？\", \"translated\": \"可以免费续杯吗？\"}, {\"original\": \"私のコーヒーはできましたか？\", \"translated\": \"我的咖啡好了吗？\"}, {\"original\": \"ここにどのくらい座っていられますか？\", \"translated\": \"我可以在这里坐多久？\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"能帮我们拍张照吗？\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"洗手间在哪里？\"}, {\"original\": \"お会計お願いします。ありがとうございます。\", \"translated\": \"请结账，谢谢。\"}, {\"original\": \"とても美味しいです。\", \"translated\": \"味道真的很好。\"}]', 12, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a restaurant?\", \"Great! Here are 10 common restaurant-related phrases, with Chinese translations:\"]', '[\"Dining\", \"Ordering\", \"Checkout\"]', 'en', '[\"For now, do you have a specific situation in mind, like ordering drinks, making a complaint, or asking about ingredients? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Excuse me, how much longer will our food be?\", \"translated\": \"不好意思，请问我们的菜还要等多久？\"}, {\"original\": \"A table for two, please.\", \"translated\": \"请给我们安排一张两人桌。\"}, {\"original\": \"Could we see the menu, please?\", \"translated\": \"能让我们看一下菜单吗？\"}, {\"original\": \"Do you have any signature dishes to recommend?\", \"translated\": \"你们有什么招牌菜可以推荐吗？\"}, {\"original\": \"I\'d like to order this, and this.\", \"translated\": \"我要点这个和这个。\"}, {\"original\": \"A glass of water, please. Thanks.\", \"translated\": \"请来一杯水，谢谢！\"}, {\"original\": \"The bill, please.\", \"translated\": \"请结账，谢谢。\"}, {\"original\": \"Can I pay by credit card?\", \"translated\": \"我能用信用卡付款吗？\"}, {\"original\": \"Could you pack this to go, please?\", \"translated\": \"能帮我把这份打包带走吗？\"}, {\"original\": \"The food was delicious, thank you.\", \"translated\": \"食物非常美味，谢谢！\"}]', 1, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at the hotel?\", \"Great! Here are 10 common hotel-related phrases, with Chinese translations:\"]', '[\"Check-in\", \"Check-out\", \"Room Service\"]', 'en', '[\"For now, do you have a specific situation in mind, like room location, any other hotel service, or check-out? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Hello, I have a reservation, Here is my passport.\", \"translated\": \"您好，我已预订房间，这是我的护照。\"}, {\"original\": \"Do you have any vacancies?\", \"translated\": \"还有空房吗？\"}, {\"original\": \"Excuse me, does the hotel have a gym or a laundry room?\", \"translated\": \"打扰一下，酒店有健身房或洗衣房吗？\"}, {\"original\": \"What time does breakfast start?\", \"translated\": \"早餐几点开始？\"}, {\"original\": \"Could I have a room key, please?\", \"translated\": \"能给我房卡吗？\"}, {\"original\": \"Could you help me take my luggage to the room?\", \"translated\": \"您能帮我把行李送到房间吗？\"}, {\"original\": \"How do I call room service?\", \"translated\": \"怎么叫客房服务？\"}, {\"original\": \"What time is check-out?\", \"translated\": \"退房时间是几点？\"}, {\"original\": \"Could you write me a receipt/invoice?\", \"translated\": \"能给我开个收据／发票吗？\"}, {\"original\": \"Can I leave my luggage here?\", \"translated\": \"我可以把行李先寄存在这儿吗？\"}]', 2, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at the airport?\", \"Great! Here are 10 common airport-related phrases, with Chinese translations:\"]', '[\"Check-in\", \"Boarding\", \"Baggage Check\"]', 'en', '[\"For now, do you have a specific situation in mind, like check-in, baggage claim, or car rental service? Feel free to ask!\", \"Please describe the situation you have in mind.\"]', '[]', '[{\"original\": \"Where is the check-in counter?\", \"translated\": \"值机柜台在哪里？\"}, {\"original\": \"I\'d like a window seat, please.\", \"translated\": \"我想要一个靠窗的座位，谢谢。\"}, {\"original\": \"Is this flight delayed?\", \"translated\": \"这趟航班延误了吗？\"}, {\"original\": \"I need to check this baggage.\", \"translated\": \"我需要托运行李。\"}, {\"original\": \"Where is the boarding gate?\", \"translated\": \"登机口在哪里？\"}, {\"original\": \"The plane is about to take off.\", \"translated\": \"飞机马上就要起飞了。\"}, {\"original\": \"Do I need to take out my laptop and power bank?\", \"translated\": \"我需要把笔记本电脑和充电宝拿出来吗？\"}, {\"original\": \"Where is the duty-free shop?\", \"translated\": \"免税店在哪里？\"}, {\"original\": \"I can\'t find my suitcase.\", \"translated\": \"我找不到我的行李箱了。\"}, {\"original\": \"Do you have a wheelchair service?\", \"translated\": \"你们提供轮椅服务吗？\"}]', 3, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use on public transportation?\", \"Awesome! Here are 10 common public transportation phrases, with Chinese translations:\"]', '[\"Taking Bus/Subway\", \"Buying Tickets\", \"Transferring\"]', 'en', '[\"For now, do you have a specific situation in mind — like asking for the bus stop, ticket price, or when to get off? Feel free to ask!\", \"Please describe the situation you have in mind.\"]', '[]', '[{\"original\": \"Does this bus go to the terminal?\", \"translated\": \"这趟公交车去终点站吗？\"}, {\"original\": \"What is the next stop?\", \"translated\": \"下一站是哪儿？\"}, {\"original\": \"Where can I buy a ticket?\", \"translated\": \"我在哪儿能买票？\"}, {\"original\": \"One ticket to XX, please.\", \"translated\": \"请给我一张去XX的票。\"}, {\"original\": \"Do I need to transfer?\", \"translated\": \"我需要换乘吗？\"}, {\"original\": \"How long until the next subway train?\", \"translated\": \"下一班地铁还有多久？\"}, {\"original\": \"Excuse me, please let me pass.\", \"translated\": \"不好意思，麻烦让一下。\"}, {\"original\": \"Is this seat taken?\", \"translated\": \"这个座位有人吗？\"}, {\"original\": \"Excuse me, where can I transfer to Line 2 to get to XX?\", \"translated\": \"请问，我在哪儿换乘2号线去XX？\"}, {\"original\": \"How do I get to XX?\", \"translated\": \"我去XX怎么走？\"}]', 4, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at tourist attractions?\", \"Awesome! Here are 10 common phrases for tourist attractions, with Chinese translations:\"]', '[\"Sightseeing\", \"Taking Photos\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind—like asking about ticket prices, finding a parking lot, or requesting tour guide services? Feel free to ask!\", \"Please describe the situation you have in mind.\"]', '[]', '[{\"original\": \"How much is the entrance fee?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"Are there student tickets available?\", \"translated\": \"有学生票吗？\"}, {\"original\": \"What time does the attraction open?\", \"translated\": \"景点几点开门？\"}, {\"original\": \"What are the fun things to do here?\", \"translated\": \"这里有哪些好玩的项目？\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"能帮我们拍张照吗？\"}, {\"original\": \"Where is the sightseeing bus?\", \"translated\": \"观光巴士在哪里？\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"洗手间在哪儿？\"}, {\"original\": \"Where is the best viewing spot?\", \"translated\": \"最佳观景点在哪儿？\"}, {\"original\": \"The scenery here is beautiful.\", \"translated\": \"这里的风景真美。\"}, {\"original\": \"Is there a guided tour available?\", \"translated\": \"有导游讲解服务吗？\"}]', 5, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use for hailing or riding a taxi?\", \"Awesome! Here are 10 common taxi-related phrases, with Chinese translations:\"]', '[\"Taking Taxi\", \"Telling Destination\", \"Payment\"]', 'en', '[\"For now, what do you most want to do now — like asking for the destination, the fare, or a receipt? Feel free to ask!\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Where can I get a taxi?\", \"translated\": \"我在哪儿能打到出租车？\"}, {\"original\": \"Please take me to this address.\", \"translated\": \"请送我去这个地址。\"}, {\"original\": \"Roughly how much will it be?\", \"translated\": \"大概要多少钱？\"}, {\"original\": \"Could you use the meter, please?\", \"translated\": \"麻烦您打表计费，可以吗？\"}, {\"original\": \"Please drive a bit faster, I\'m in a hurry.\", \"translated\": \"麻烦开快一点，我赶时间。\"}, {\"original\": \"Please stop here.\", \"translated\": \"请在这里停车。\"}, {\"original\": \"Do you accept cards or mobile payments?\", \"translated\": \"您支持刷卡或手机支付吗？\"}, {\"original\": \"Could I have a receipt, please?\", \"translated\": \"可以给我开张发票吗？\"}, {\"original\": \"Thank you, driver.\", \"translated\": \"谢谢师傅！\"}, {\"original\": \"How much further is it?\", \"translated\": \"还有多远？\"}]', 6, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a pharmacy?\", \"Great! Here are 10 common pharmacy-related phrases, with Chinese translations:\"]', '[\"Buying Medicine\", \"Consultation\", \"Payment\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for instructions on taking medicine, phrases related to using insurance, or duration of medication? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Do you have cold medicine?\", \"translated\": \"你们有感冒药吗？\"}, {\"original\": \"How should I take this medicine?\", \"translated\": \"这个药该怎么吃？\"}, {\"original\": \"Do you have any painkillers?\", \"translated\": \"你们有止痛药吗？\"}, {\"original\": \"Is there an instruction leaflet?\", \"translated\": \"有说明书吗？\"}, {\"original\": \"Does this medicine have any side effects?\", \"translated\": \"这种药有什么副作用吗？\"}, {\"original\": \"Can I use my medical insurance card?\", \"translated\": \"我能用医保卡付款吗？\"}, {\"original\": \"Could I have a box of Band-Aids, please?\", \"translated\": \"请给我拿一盒创可贴，谢谢。\"}, {\"original\": \"Do you have any fever reducers?\", \"translated\": \"你们有退烧药吗？\"}, {\"original\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\", \"translated\": \"我擦破点皮，你们有消毒药水和创可贴吗？\"}, {\"original\": \"What time do you close?\", \"translated\": \"你们几点关门？\"}]', 7, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use for emergency services?\", \"Great! Here are 10 common emergency service phrases, with Chinese translations:\"]', '[\"Calling Police\", \"First Aid\", \"Calling for Help\"]', 'en', '[\"For now, do you have a specific emergency situation in mind—like fire, injury and need help, or making an emergency call? Feel free to ask!\", \"Please describe the situation you have in mind.\"]', '[]', '[{\"original\": \"Please help me call an ambulance.\", \"translated\": \"请帮我叫一辆救护车。\"}, {\"original\": \"Where is the hospital?\", \"translated\": \"医院在哪里？\"}, {\"original\": \"Someone is injured.\", \"translated\": \"有人受伤了。\"}, {\"original\": \"Please help me.\", \"translated\": \"请帮帮我。\"}, {\"original\": \"Where is the police station?\", \"translated\": \"警察局在哪里？\"}, {\"original\": \"I\'ve lost my belongings.\", \"translated\": \"我的物品丢了。\"}, {\"original\": \"What is the number for the fire department?\", \"translated\": \"消防部门的电话号码是多少？\"}, {\"original\": \"I\'ve lost my passport. Do you know where the nearest police station is?\", \"translated\": \"我的护照丢了。您知道最近的警察局在哪儿吗？\"}, {\"original\": \"Is there an emergency exit?\", \"translated\": \"这里有紧急出口吗？\"}, {\"original\": \"Someone has fainted.\", \"translated\": \"有人晕倒了。\"}]', 8, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at the beach or by the pool?\", \"Awesome! Here are 10 common beach- or pool-related phrases, with Chinese translations:\"]', '[\"Swimming\", \"Sunbathing\", \"Beach Sports\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you\'re attending — for example, a cultural festival, food festival, or music festival? Please provide the context.\", \"Please provide the activities that you\'re attending.\"]', '[\"Do you have a specific situation in mind? Feel free to ask!\", \"Please describe the situation you have in mind.\"]', '[{\"original\": \"Look! The waves over there are really big.\", \"translated\": \"快看！那边的浪好大啊！\"}, {\"original\": \"Remember to apply sunscreen, the UV rays here are very strong.\", \"translated\": \"别忘了涂防晒霜，这里的紫外线很强哦！\"}, {\"original\": \"The sand on this beach is so fine, it feels like stepping on cotton.\", \"translated\": \"这沙滩的沙子真细，踩上去像踩在棉花上一样！\"}, {\"original\": \"How about playing volleyball on the beach?\", \"translated\": \"要不要在沙滩上打排球？\"}, {\"original\": \"The sailboats in the distance look beautiful.\", \"translated\": \"远处的帆船看起来真美！\"}, {\"original\": \"The water here is so clear, you can even see the fish.\", \"translated\": \"这里的水好清澈，连鱼都看得见！\"}, {\"original\": \"Let\'s go find some seashells.\", \"translated\": \"咱们去捡点贝壳吧！\"}, {\"original\": \"Taking a walk on the beach at sunset must be very romantic.\", \"translated\": \"日落时分在沙滩散步一定超浪漫！\"}, {\"original\": \"I heard the seafood here is very fresh, let\'s go try some.\", \"translated\": \"听说这儿的海鲜特别新鲜，咱们去尝尝吧！\"}, {\"original\": \"The tide is coming in, let\'s head towards the shore.\", \"translated\": \"涨潮啦，咱们往岸边走吧！\"}]', 9, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use for local events and festivals?\", \"Amazing! Here are 10 common phrases about local events and festivals, with Chinese translations:\"]', '[\"Attending Events\", \"Celebrating Festivals\", \"Learning Culture\"]', 'en', '[\"For now, could you please tell me the context of the local event or festival you\'re attending—like Halloween, a concert, a friend\'s party, or something else? Please share the context.\", \"Please describe the activities you have in mind.\"]', '[\"Do you have a specific situation in mind? Feel free to ask!\", \"Please describe the situation you have in mind.\"]', '[{\"original\": \"Are there any events today?\", \"translated\": \"今天有什么活动吗？\"}, {\"original\": \"Is there anything special about this festival?\", \"translated\": \"这个节日有什么特别之处吗？\"}, {\"original\": \"Where is the celebration being held?\", \"translated\": \"庆祝活动在哪里举行？\"}, {\"original\": \"How can I buy tickets?\", \"translated\": \"我怎么买票？\"}, {\"original\": \"What time does the performance start?\", \"translated\": \"演出几点开始？\"}, {\"original\": \"What traditional food is there?\", \"translated\": \"有哪些传统美食？\"}, {\"original\": \"It\'s really lively here.\", \"translated\": \"这儿真热闹！\"}, {\"original\": \"Are there any folk activities?\", \"translated\": \"有民间活动吗？\"}, {\"original\": \"Happy holidays!\", \"translated\": \"节日快乐！\"}, {\"original\": \"What time does the event end?\", \"translated\": \"活动几点结束？\"}]', 10, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a museum or art gallery?\", \"Great! Here are 10 common museum- or art gallery-related phrases, with Chinese translations:\"]', '[\"Visiting\", \"Guided Tour\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind—like asking for an introduction manual, phrases related to a roadmap, phrases for commenting on exhibits? Feel free to ask!\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"How much is the admission fee?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"Do you have audio guides?\", \"translated\": \"你们有语音导览吗？\"}, {\"original\": \"Who created this artwork?\", \"translated\": \"这件艺术品是谁创作的？\"}, {\"original\": \"Where is the museum\'s most prized piece?\", \"translated\": \"博物馆最珍贵的展品在哪儿？\"}, {\"original\": \"Is photography allowed?\", \"translated\": \"允许拍照吗？\"}, {\"original\": \"Are there any special exhibitions here?\", \"translated\": \"这里有没有特别展览？\"}, {\"original\": \"How long does the visit take?\", \"translated\": \"参观大概需要多长时间？\"}, {\"original\": \"Could you give us an introduction?\", \"translated\": \"您能给我们简单介绍一下吗？\"}, {\"original\": \"These works are truly exquisite.\", \"translated\": \"这些作品真精美啊！\"}, {\"original\": \"Where is the souvenir shop?\", \"translated\": \"纪念品商店在哪儿？\"}]', 11, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Can you provide me with 10 common phrases I can use at a café?\", \"Awesome! Here are 10 common café-related phrases, with Chinese translations:\"]', '[\"Ordering Coffee\", \"Resting\", \"Socializing\"]', 'en', '[\"For now, do you have a specific situation in mind—like asking for a menu, ice or hot drinks, other products? Feel free to ask!\", \"Please describe the situation you have in mind.\"]', '[]', '[{\"original\": \"I\'ll have a latte, please.\", \"translated\": \"请给我一杯拿铁。\"}, {\"original\": \"Do you have Wi-Fi?\", \"translated\": \"你们有Wi-Fi吗？\"}, {\"original\": \"Could I see the menu, please?\", \"translated\": \"请问可以看一下菜单吗？\"}, {\"original\": \"Are refills allowed?\", \"translated\": \"可以免费续杯吗？\"}, {\"original\": \"Is my coffee ready?\", \"translated\": \"我的咖啡好了吗？\"}, {\"original\": \"How long can I sit here?\", \"translated\": \"我可以在这里坐多久？\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"能帮我们拍张照吗？\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"洗手间在哪儿？\"}, {\"original\": \"Check, please. Thank you.\", \"translated\": \"买单，谢谢。\"}, {\"original\": \"It tastes really good.\", \"translated\": \"味道真的很棒！\"}]', 12, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ10 عبارات شائعة يمكنني استخدامها في المطعم؟\", \"رائع! إليك 10 عبارات شائعة تتعلق بالمطاعم، مع الترجمة الصينية:\"]', '[\"السفر إلى المطعم\", \"إتمام الطلب\", \"المغادرة والدفع\"]', 'ar', '[\"حاليًا، هل لديك حالة معينة في بالك؟ مثل طلب المشروبات، أو تقديم شكوى، أو الاستفسار عن المكونات؟ لا تتردد في السؤال.\", \"من فضلك صف لي الحالة التي تراودك في ذهنك.\"]', '[]', '[{\"original\": \"عذرًا، كم من الوقت سيستغرق وصول طعامنا؟\", \"translated\": \"打扰一下，我们的食物还要多久才能上？\"}, {\"original\": \"طاولة لشخصين، من فضلكم.\", \"translated\": \"请给我们安排一张两人桌。\"}, {\"original\": \"هل يمكننا رؤية القائمة، من فضلكم؟\", \"translated\": \"请问可以把菜单给我们看一下吗？\"}, {\"original\": \"هل لديكم أطباق مميزة توصون بها؟\", \"translated\": \"你们有什么招牌菜可以推荐吗？\"}, {\"original\": \"أود طلب هذا وهذا.\", \"translated\": \"我要点这个和这个。\"}, {\"original\": \"كوب من الماء، من فضلكم. شكرًا.\", \"translated\": \"请来一杯水，谢谢。\"}, {\"original\": \"الفاتورة، من فضلكم.\", \"translated\": \"请把账单拿来。\"}, {\"original\": \"هل يمكنني الدفع بالبطاقة الائتمانية؟\", \"translated\": \"我能用信用卡付款吗？\"}, {\"original\": \"هل يمكنكم تغليف هذا لآخذه معي، من فضلكم؟\", \"translated\": \"请问能把这个打包带走吗？\"}, {\"original\": \"كان الطعام لذيذًا، شكرًا لكم.\", \"translated\": \"食物非常美味，谢谢！\"}]', 1, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بـ10 عبارات شائعة يمكنني استخدامها في الفندق؟\", \"رائع جدًّا! إليك 10 عبارات شائعة تتعلق بالفندق، مع الترجمة العربية:\"]', '[\"تسجيل الدخول\", \"المغادرة\", \"خدمة الغرف\"]', 'ar', '[\"حاليًّا، هل لديك موقفٌ محدد في بالك؟ مثل موقع الغرفة، أو أي خدمة فندقية أخرى، أو وقت المغادرة؟ لا تتردد في طرح الأسئلة.\", \"من فضلك وضّح الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"مرحبًا، لدي حجزٌ هنا. وهذه جواز سفري.\", \"translated\": \"你好，我有预订。这是我的护照。\"}, {\"original\": \"هل لديكم أي غرف شاغرة؟\", \"translated\": \"你们还有空房吗？\"}, {\"original\": \"عذرًا، هل يتوفر في الفندق صالة ألعاب رياضية أو غرفة غسيل؟\", \"translated\": \"打扰一下，酒店有健身房或洗衣房吗？\"}, {\"original\": \"متى يبدأ الفطور؟\", \"translated\": \"早餐什么时候开始？\"}, {\"original\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\", \"translated\": \"请给我房间钥匙，好吗？\"}, {\"original\": \"هل يمكنك مساعدتي في حمل أمتعتي إلى الغرفة؟\", \"translated\": \"您能帮我把行李拿到房间吗？\"}, {\"original\": \"كيف أطلب خدمة الغرف؟\", \"translated\": \"我怎么叫客房服务？\"}, {\"original\": \"متى موعد المغادرة؟\", \"translated\": \"退房时间是几点？\"}, {\"original\": \"هل يمكنكم إعطائي إيصالًا/فاتورةً؟\", \"translated\": \"您能给我开张收据／发票吗？\"}, {\"original\": \"هل يمكنني ترك أمتعتي هنا مؤقتًا؟\", \"translated\": \"我可以把行李暂时寄存在这里吗？\"}]', 2, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بـ10 عبارات شائعة يمكنني استخدامها في المطار؟\", \"رائع! إليك 10 عبارات شائعة عن المطار مع الترجمة الصينية:\"]', '[\"تسجيل الوصول\", \"الصعود إلى الطائرة\", \"فحص الأمتعة\"]', 'ar', '[\"لحد الآن، هل لديك موقف محدد في بالك، مثل تسجيل الوصول أو استلام الأمتعة أو خدمة تأجير السيارات؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"أين كاونتر تسجيل الوصول؟\", \"translated\": \"值机柜台在哪里？\"}, {\"original\": \"أود أن أحصل على مقعد بجانب النافذة، من فضلك.\", \"translated\": \"我想要一个靠窗的座位，谢谢。\"}, {\"original\": \"هل تأخر هذا الرحلة؟\", \"translated\": \"这趟航班延误了吗？\"}, {\"original\": \"أحتاج إلى فحص هذه الأمتعة.\", \"translated\": \"我需要托运行李。\"}, {\"original\": \"أين بوابة الصعود إلى الطائرة؟\", \"translated\": \"登机口在哪里？\"}, {\"original\": \"الطائرة على وشك الإقلاع.\", \"translated\": \"飞机即将起飞。\"}, {\"original\": \"هل عليّ إخراج جهاز اللابتوب وبنك الطاقة الخاص بي؟\", \"translated\": \"我需要把笔记本电脑和充电宝拿出来吗？\"}, {\"original\": \"أين متجر التسوق المعفي من الرسوم الجمركية؟\", \"translated\": \"免税店在哪里？\"}, {\"original\": \"لا أستطيع العثور على حقيبتي.\", \"translated\": \"我找不到我的行李箱了。\"}, {\"original\": \"هل لديكم خدمة الكرسي المتحرك؟\", \"translated\": \"你们提供轮椅服务吗？\"}]', 3, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكن أن تُزودني بـ ١٠ عبارات شائعة يمكنني استخدامها في وسائل النقل العام؟\", \"رائع جدًّا! إليك ١٠ عبارات شائعة تتعلق بوسائل النقل العام، مع ترجمتها العربية:\"]', '[\"ركوب الحافلة أو المترو\", \"شراء التذاكر\", \"التنقل بين وسائل النقل\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف معيّن في ذهنك؟ مثل الاستفسار عن موقف الحافلة، أو سعر التذكرة، أو مكان النزول؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي في بالك.\"]', '[]', '[{\"original\": \"هل هذه الحافلة تذهب إلى المحطة؟\", \"translated\": \"这班车去终点站吗？\"}, {\"original\": \"ما هي المحطة التالية؟\", \"translated\": \"下一站是哪里？\"}, {\"original\": \"أين يمكنني شراء تذكرة؟\", \"translated\": \"我在哪里可以买票？\"}, {\"original\": \"تذكرة واحدة إلى XX، من فضلك.\", \"translated\": \"请给我一张到XX的票。\"}, {\"original\": \"هل عليّ التنقل إلى وسيلة نقل أخرى؟\", \"translated\": \"我需要换乘吗？\"}, {\"original\": \"كم من الوقت حتى القطار التالي في المترو؟\", \"translated\": \"下一班地铁还要等多久？\"}, {\"original\": \"المعذرة، من فضلك اسمح لي بالمرور.\", \"translated\": \"不好意思，请让我过去一下。\"}, {\"original\": \"هل هذا المقعد مشغول؟\", \"translated\": \"这个座位有人坐吗？\"}, {\"original\": \"المعذرة، أين يمكنني التنقل إلى الخط ٢ للوصول إلى XX؟\", \"translated\": \"不好意思，我去XX要在哪里换乘2号线？\"}, {\"original\": \"كيف أصل إلى XX؟\", \"translated\": \"我该怎么去XX？\"}]', 4, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكن أن توفر لي ١٠ عبارات شائعة يمكنني استخدامها في مواقع الجذب السياحي؟\", \"رائع جدًا! إليك ١٠ عبارات شائعة عن المواقع السياحية مع الترجمة الصينية:\"]', '[\"السياحة\", \"التقاط الصور\", \"شراء التذاكر\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف محدد في بالك؟ مثل الاستفسار عن سعر التذكرة، أو العثور على موقف للسيارات، أو خدمة مرشد سياحي؟ لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي يخطر لك في بالك.\"]', '[]', '[{\"original\": \"كم تكلفة رسوم الدخول؟\", \"translated\": \"门票多少钱？\"}, {\"original\": \"هل توجد تذاكر مخفضة للطلاب؟\", \"translated\": \"有学生票吗？\"}, {\"original\": \"متى يفتح موقع الجذب السياحي؟\", \"translated\": \"景点几点开放？\"}, {\"original\": \"ما الأنشطة الممتعة التي يمكن القيام بها هنا؟\", \"translated\": \"这里有哪些好玩的活动？\"}, {\"original\": \"هل يمكنك أخذ صورة لنا؟\", \"translated\": \"您能帮我们拍张照吗？\"}, {\"original\": \"أين حافلة الجولات السياحية؟\", \"translated\": \"观光巴士在哪？\"}, {\"original\": \"أين الحمام؟\", \"translated\": \"洗手间在哪？\"}, {\"original\": \"ما أفضل مكان لرؤية المنظر؟\", \"translated\": \"最佳观景点在哪？\"}, {\"original\": \"المنظر هنا جميل جدًا.\", \"translated\": \"这里的风景真美。\"}, {\"original\": \"هل تتوفر جولة إرشادية؟\", \"translated\": \"有导游服务吗？\"}]', 5, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ10 عبارات شائعة يمكنني استخدامها عند استئجار تاكسي أو استخدام خدمة التاكسي؟\", \"رائع! إليك 10 عبارات شائعة تتعلق بالتاكسي أو خدمات التاكسي، مرفقةً بترجمتها إلى اللغة الصينية:\"]', '[\"ركوب التاكسي\", \"إبلاغ الوجهة\", \"الدفع\"]', 'ar', '[\"في الوقت الحالي، ما الذي تريد فعله أكثر ما يخطر في بالك، مثل: الاستفسار عن الوجهة، السعر، أو طلب فاتورة — لا تتردد في طرح أي سؤال.\", \"من فضلك صف لي الوضع الذي تخطره في ذهنك.\"]', '[]', '[{\"original\": \"أين يمكنني أخذ تاكسي؟\", \"translated\": \"我在哪儿能打到出租车？\"}, {\"original\": \"من فضلك خذني إلى هذا العنوان.\", \"translated\": \"请送我去这个地址。\"}, {\"original\": \"كم يكون السعر تقريبًا؟\", \"translated\": \"大概要多少钱？\"}, {\"original\": \"هل يمكن أن تستخدم العداد من فضلك؟\", \"translated\": \"请问您能打表计费吗？\"}, {\"original\": \"من فضلك ا-driving بسرعة أكبر قليلًا، فأنا مستعجل.\", \"translated\": \"请开快一点，我赶时间。\"}, {\"original\": \"من فضلك توقف هنا.\", \"translated\": \"请在这里停车。\"}, {\"original\": \"هل تقبل الدفع بالبطاقات أو عبر الهاتف المحمول؟\", \"translated\": \"您接受刷卡或手机支付吗？\"}, {\"original\": \"هل يمكنني الحصول على إثبات دفع من فضلك؟\", \"translated\": \"请问可以给我一张收据吗？\"}, {\"original\": \"شكرًا لك يا سائق.\", \"translated\": \"谢谢您，司机师傅。\"}, {\"original\": \"كم يبقى بعد من الطريق؟\", \"translated\": \"还有多远？\"}]', 6, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بعشر عبارات شائعة يمكنني استخدامها في الصيدلية؟\", \"رائع جدًّا! إليك ١٠ عبارات شائعة تُستخدم في الصيدليات، مصحوبةً بالترجمة العربية:\"]', '[\"شراء أدويّة\", \"استشارة طبية\", \"دفع المبلغ\"]', 'ar', '[\"حاليًّا، هل لديك حالة محددة في بالك؟ مثل طلب تعليمات حول كيفية تناول الدواء، أو عبارات مرتبطة باستخدام التأمين الصحي، أو مدة العلاج — لا تتردد في طرح أي سؤال.\", \"من فضلك صف لي الحالة التي تراودك في ذهنك.\"]', '[]', '[{\"original\": \"هل لديك دواء لعلاج البرد؟\", \"translated\": \"您有治感冒的药吗？\"}, {\"original\": \"كيف يجب أن آخذ هذا الدواء؟\", \"translated\": \"我该怎么服用这种药？\"}, {\"original\": \"هل لديك أي مسكنات للألم؟\", \"translated\": \"您有止痛药吗？\"}, {\"original\": \"هل يوجد نشرة إرشادات مرفقة مع الدواء؟\", \"translated\": \"这药有说明书吗？\"}, {\"original\": \"هل لهذا الدواء أي آثار جانبية؟\", \"translated\": \"这种药有什么副作用吗？\"}, {\"original\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\", \"translated\": \"我能刷医保卡吗？\"}, {\"original\": \"هل يمكنني أن أطلب علبة من الضمادات اللاصقة، من فضلك؟\", \"translated\": \"请给我一盒创可贴，谢谢！\"}, {\"original\": \"هل لديك أي خافضات للحرارة؟\", \"translated\": \"您有退烧药吗？\"}, {\"original\": \"لدي جرح سطحي بسيط. هل لديك محلول معقم وضمادات لاصقة؟\", \"translated\": \"我有点擦伤，您有消毒液和创可贴吗？\"}, {\"original\": \"ما وقت إغلاقكم؟\", \"translated\": \"你们几点关门？\"}]', 7, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزوّدني بـ10 عبارات شائعة يمكنني استخدامها عند الاتصال بالخدمات الطارئة؟\", \"رائع! إليك 10 عبارات شائعة تتعلق بالخدمات الطارئة، مع الترجمة الصينية:\"]', '[\"الاتصال بالشرطة\", \"الإسعافات الأولية\", \"طلب المساعدة\"]', 'ar', '[\"لحد الآن، هل لديك حالة طارئة محددة في بالك، مثل الحريق أو الإصابة والاحتياج للمساعدة أو الاتصال الطارئ؟ لا تتردد في السؤال.\", \"يرجى وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"من فضلك ساعدني في طلب سيارة إسعاف.\", \"translated\": \"请帮我叫一辆救护车。\"}, {\"original\": \"أين находится المستشفى؟\", \"translated\": \"医院在哪儿？\"}, {\"original\": \"شخص ما أُصيب.\", \"translated\": \"有人受伤了。\"}, {\"original\": \"من فضلك ساعدني.\", \"translated\": \"请帮帮我。\"}, {\"original\": \"أين تقع مركز الشرطة؟\", \"translated\": \"警察局在哪儿？\"}, {\"original\": \"لقد فقدت أ possessionاتي.\", \"translated\": \"我的物品丢失了。\"}, {\"original\": \"ما هو رقم دائرة الإطفاء؟\", \"translated\": \"消防部门的电话号码是多少？\"}, {\"original\": \"لقد فقدت جواز سفري. هل تعرف أين يقع أقرب مركز شرطة؟\", \"translated\": \"我丢了护照。你知道最近的警察局在哪儿吗？\"}, {\"original\": \"هل يوجد مخرج طوارئ؟\", \"translated\": \"有紧急出口吗？\"}, {\"original\": \"شخص ما فقد وعيه.\", \"translated\": \"有人昏倒了。\"}]', 8, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ10 عبارات شائعة يمكنني استخدامها على الشاطئ أو بجانب حمام السباحة؟\", \"رائع جدًا! إليك 10 عبارات شائعة عن الشاطئ أو حمام السباحة مع الترجمة العربية:\"]', '[\"السباحة\", \"الاستلقاء تحت أشعة الشمس\", \"الرياضات الشاطئية\"]', 'ar', '[\"حاليًا، هل يمكن أن تزودني بسياق الحدث أو المهرجان المحلي الذي ستشارك فيه، مثل مهرجان ثقافي أو مهرجان غذائي أو مهرجان موسيقي؟ من فضلك قدّم لي السياق.\", \"من فضلك قدّم لي الأنشطة التي ستشارك فيها.\"]', '[\"هل لديك موقف محدد في ذهنك؟ لا تتردد في طرح سؤال.\", \"وصف الموقف الموجود في ذهنك.\"]', '[{\"original\": \"انظر! الأمواج هناك كبيرة جدًا.\", \"translated\": \"看！那边的海浪真大。\"}, {\"original\": \"تذكّر أن تضع واقي الشمس، فأشعة فوق البنفسجية هنا قوية جدًا.\", \"translated\": \"记得涂防晒霜，这里的紫外线很强。\"}, {\"original\": \"الرمال على هذا الشاطئ ناعمة جدًا، لدرجة أن المشي عليها يشبه المشي على القطن.\", \"translated\": \"这片海滩的沙子特别细，踩上去就像踩在棉花上一样。\"}, {\"original\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\", \"translated\": \"要不要在海滩上打排球？\"}, {\"original\": \"القوارب الشراعية في الأفق تبدو جميلة جدًا.\", \"translated\": \"远处的帆船看起来真美。\"}, {\"original\": \"الماء هنا شفاف جدًا، بل يمكنك رؤية الأسماك بوضوح.\", \"translated\": \"这里的海水非常清澈，甚至能看到鱼儿游动。\"}, {\"original\": \"هيا نبحث عن بعض المحار والقواقع البحرية.\", \"translated\": \"我们去找些贝壳吧。\"}, {\"original\": \"التمشي على الشاطئ عند غروب الشمس يجب أن يكون أمرًا رومانسيًّا جدًا.\", \"translated\": \"日落时分在海滩散步一定很浪漫。\"}, {\"original\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًا، فلنذهب ونجرب بعضها.\", \"translated\": \"听说这里的海鲜特别新鲜，咱们去尝尝吧。\"}, {\"original\": \"المدّ في ازدياد، هيا نتجه نحو الشاطئ.\", \"translated\": \"涨潮了，咱们往岸边走吧。\"}]', 9, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكن أن تزودني بـ ١٠ عبارات شائعة يمكنني استخدامها في الفعاليات والمناسبات المحلية؟\", \"رائع جدًّا! إليك ١٠ عبارات شائعة عن الفعاليات والمناسبات المحلية، مع الترجمة الصينية:\"]', '[\"حضور الفعاليات\", \"الاحتفال بالمناسبات والمواسم\", \"التعرّف على الثقافة\"]', 'ar', '[\"للمتابعة، هل يمكنك إخباري بسياق الحدث أو المهرجان المحلي الذي تنوي حضوره؟ مثل هالوين، حفل موسيقي، حفلة مع الأصدقاء، أو أي شيء آخر؟ يُرجى تزويدي بالسياق.\", \"من فضلك صف لي الأنشطة التي تتبادر إلى ذهنك.\"]', '[\"هل لديك موقف معين في بالك؟ اسأل على طول دون تردد.\", \"من فضلك صف لي الموقف الذي تتخيله.\"]', '[{\"original\": \"هل توجد أي فعاليات اليوم؟\", \"translated\": \"今天有什么活动吗？\"}, {\"original\": \"هل هناك شيء خاصٌّ متعلّق بهذه المهرجان؟\", \"translated\": \"这个节日有什么特别之处吗？\"}, {\"original\": \"أين تُقام الاحتفالات؟\", \"translated\": \"庆典在哪里举行？\"}, {\"original\": \"كيف يمكنني شراء التذاكر؟\", \"translated\": \"我该怎么买票？\"}, {\"original\": \"متى تبدأ العروض؟\", \"translated\": \"演出什么时候开始？\"}, {\"original\": \"ما هي الأطعمة التقليدية المتاحة؟\", \"translated\": \"有哪些传统食物？\"}, {\"original\": \"المكان مفعَمٌ بالحيوية حقًّا.\", \"translated\": \"这里真的特别热闹！\"}, {\"original\": \"هل توجد أنشطة شعبية؟\", \"translated\": \"有民俗活动吗？\"}, {\"original\": \"أعياد سعيدة!\", \"translated\": \"节日快乐！\"}, {\"original\": \"متى تنتهي الفعالية؟\", \"translated\": \"活动几点结束？\"}]', 10, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم إعطائي ١٠ عبارات شائعة يمكنني استخدامها في المتاحف أو المعارض الفنية؟\", \"رائع جدًّا! إليك ١٠ عبارات شائعة عن المتاحف أو المعارض الفنية، مع الترجمة الصينية:\"]', '[\"الزيارة\", \"الجولة الإرشادية\", \"شراء التذاكر\"]', 'ar', '[\"حتى الآن، هل لديك موقفٌ معين في ذهنك؟ مثل طلب كتيب تعريفي، أو عبارات مرتبطة بخريطة الطريق، أو عبارات تعبّر عن رأي في المعروضات — لا تتردّد في السؤال.\", \"يرجى وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"门票多少钱？\"}, {\"original\": \"هل لديكم أدلة صوتية؟\", \"translated\": \"你们有语音导览吗？\"}, {\"original\": \"من هو صاحب هذا العمل الفني؟\", \"translated\": \"这件艺术品是谁创作的？\"}, {\"original\": \"أين يقع أثمن قطعة في المتحف؟\", \"translated\": \"博物馆最珍贵的藏品在哪里？\"}, {\"original\": \"هل يُسمح بالتصوير الفوتوغرافي؟\", \"translated\": \"允许拍照吗？\"}, {\"original\": \"هل هناك أي معارض خاصة هنا؟\", \"translated\": \"这里有没有特别展览？\"}, {\"original\": \"كم تستغرق الزيارة من الوقت؟\", \"translated\": \"参观需要多长时间？\"}, {\"original\": \"هل يمكنك أن تقدّم لنا تعريفًا عامًّا؟\", \"translated\": \"您能给我们做个简单介绍吗？\"}, {\"original\": \"هذه الأعمال رائعة حقًّا.\", \"translated\": \"这些作品真是精美绝伦。\"}, {\"original\": \"أين تقع متجر الهدايا التذكارية؟\", \"translated\": \"纪念品商店在哪里？\"}]', 11, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ10 عبارات شائعة يمكنني استخدامها في مقهى؟\", \"رائع! إليك 10 عبارات شائعة عن المقاهي مع الترجمة العربية:\"]', '[\"طلب القهوة\", \"الاسترخاء\", \"التواصل الاجتماعي\"]', 'ar', '[\"لوقتٍ الحالي، هل لديك موقف معيّن في بالك؟ مثل طلب القائمة، أو المشروبات الباردة أو الساخنة، أو منتجات أخرى؟ لا تتردد في الاستفسار.\", \"من فضلك صف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"سأطلب لاتيه، من فضلك.\", \"translated\": \"我要一杯拿铁，谢谢。\"}, {\"original\": \"هل لديكم خدمة واي فاي؟\", \"translated\": \"你们有Wi-Fi吗？\"}, {\"original\": \"هل يمكنني رؤية القائمة، من فضلك؟\", \"translated\": \"请问能看一下菜单吗？\"}, {\"original\": \"هل يُسمح بإعادة التعبئة؟\", \"translated\": \"可以续杯吗？\"}, {\"original\": \"هل قهفتي جاهزة بالفعل؟\", \"translated\": \"我的咖啡好了吗？\"}, {\"original\": \"كم من الوقت يمكنني الجلوس هنا؟\", \"translated\": \"我能在这里坐多久？\"}, {\"original\": \"هل يمكنكم التقاط صورة لنا؟\", \"translated\": \"能帮我们拍张照吗？\"}, {\"original\": \"أين المرحاض؟\", \"translated\": \"洗手间在哪儿？\"}, {\"original\": \"الحساب، من فضلك. شكرًا لك.\", \"translated\": \"请结账，谢谢。\"}, {\"original\": \"الطعم لذيذٌ جدًا.\", \"translated\": \"味道真的很棒。\"}]', 12, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser au restaurant ?\", \"Super ! Voici 10 expressions courantes liées au restaurant, avec leur traduction en chinois :\"]', '[\"Repas\", \"Commande\", \"Paiement\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête ? Par exemple : commander des boissons, formuler une réclamation ou demander des précisions sur les ingrédients ? N\'hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\", \"translated\": \"打扰一下，我们的餐还要等多久？\"}, {\"original\": \"Une table pour deux, s\'il vous plaît.\", \"translated\": \"请给我们一张两人桌。\"}, {\"original\": \"Pourrions-nous voir la carte, s\'il vous plaît ?\", \"translated\": \"请问可以看一下菜单吗？\"}, {\"original\": \"Avez-vous des plats signature à nous recommander ?\", \"translated\": \"您有什么招牌菜可以推荐吗？\"}, {\"original\": \"Je voudrais commander ceci et cela.\", \"translated\": \"我要点这个和这个。\"}, {\"original\": \"Un verre d\'eau, s\'il vous plaît. Merci.\", \"translated\": \"请来一杯水，谢谢。\"}, {\"original\": \"L\'addition, s\'il vous plaît.\", \"translated\": \"请结账。\"}, {\"original\": \"Puis-je payer par carte bancaire ?\", \"translated\": \"我可以用信用卡付款吗？\"}, {\"original\": \"Pourriez-vous emballer cela à emporter, s\'il vous plaît ?\", \"translated\": \"麻烦把这份打包带走，可以吗？\"}, {\"original\": \"Le plat était délicieux, merci.\", \"translated\": \"食物非常美味，谢谢！\"}]', 1, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser à l\'hôtel ?\", \"Super ! En voici 10 expressions courantes liées à l\'hôtel, avec leur traduction en chinois :\"]', '[\"Enregistrement\", \"Départ\", \"Service en chambre\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête — par exemple l\'emplacement de la chambre, d\'autres services hôteliers ou le départ ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Bonjour, j\'ai une réservation. Voici mon passeport.\", \"translated\": \"你好，我有预订。这是我的护照。\"}, {\"original\": \"Avez-vous des chambres disponibles ?\", \"translated\": \"你们还有空房吗？\"}, {\"original\": \"Excusez-moi, l\'hôtel dispose-t-il d\'une salle de sport ou d\'un service de blanchisserie ?\", \"translated\": \"打扰一下，酒店有健身房或洗衣房吗？\"}, {\"original\": \"À quelle heure commence le petit-déjeuner ?\", \"translated\": \"早餐几点开始？\"}, {\"original\": \"Pourrais-je avoir la clé de ma chambre, s\'il vous plaît ?\", \"translated\": \"请问可以给我房间钥匙吗？\"}, {\"original\": \"Pourriez-vous m\'aider à porter mes bagages jusqu\'à ma chambre ?\", \"translated\": \"您能帮我把行李送到房间吗？\"}, {\"original\": \"Comment puis-je appeler le service en chambre ?\", \"translated\": \"我怎么呼叫客房服务？\"}, {\"original\": \"À quelle heure est le départ (check-out) ?\", \"translated\": \"退房时间是几点？\"}, {\"original\": \"Pourriez-vous me faire un reçu / une facture ?\", \"translated\": \"您能给我开一张收据／发票吗？\"}, {\"original\": \"Puis-je laisser mes bagages ici ?\", \"translated\": \"我可以把行李暂时寄存在这里吗？\"}]', 2, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser à l\'aéroport ?\", \"Super ! Voici 10 expressions courantes liées à l\'aéroport, avec leur traduction en chinois :\"]', '[\"Enregistrement\", \"Embarquement\", \"Bagages\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, comme l\'enregistrement, le retrait des bagages ou la location de voiture ? N\'hésitez pas à demander !\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Où se trouve le comptoir d\'enregistrement ?\", \"translated\": \"值机柜台在哪里？\"}, {\"original\": \"Je voudrais un siège côté hublot, s\'il vous plaît.\", \"translated\": \"我想要一个靠窗的座位，谢谢。\"}, {\"original\": \"Ce vol est-il retardé ?\", \"translated\": \"这个航班延误了吗？\"}, {\"original\": \"Je dois enregistrer ce bagage.\", \"translated\": \"我需要托运行李。\"}, {\"original\": \"Où se trouve la porte d\'embarquement ?\", \"translated\": \"登机口在哪里？\"}, {\"original\": \"L\'avion va bientôt décoller.\", \"translated\": \"飞机马上就要起飞了。\"}, {\"original\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\", \"translated\": \"我需要把笔记本电脑和充电宝拿出来吗？\"}, {\"original\": \"Où se trouve la boutique hors taxes ?\", \"translated\": \"免税店在哪里？\"}, {\"original\": \"Je ne trouve pas ma valise.\", \"translated\": \"我找不到我的行李箱了。\"}, {\"original\": \"Proposez-vous un service fauteuil roulant ?\", \"translated\": \"你们提供轮椅服务吗？\"}]', 3, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans les transports en commun ?\", \"Génial ! Voici 10 expressions courantes liées aux transports en commun, avec leur traduction en chinois :\"]', '[\"Prendre le bus ou le métro\", \"Acheter des billets\", \"Changer de transport\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête — par exemple demander où est l’arrêt de bus, le prix du billet ou quand descendre ? N’hésitez pas à poser vos questions !\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Ce bus va-t-il au terminus ?\", \"translated\": \"这趟公交车到终点站吗？\"}, {\"original\": \"Quel est le prochain arrêt ?\", \"translated\": \"下一站是哪里？\"}, {\"original\": \"Où puis-je acheter un billet ?\", \"translated\": \"我在哪里可以买票？\"}, {\"original\": \"Un billet pour XX, s’il vous plaît.\", \"translated\": \"请给我一张去XX的票。\"}, {\"original\": \"Dois-je changer de transport ?\", \"translated\": \"我需要换乘吗？\"}, {\"original\": \"Dans combien de temps arrive le prochain train de métro ?\", \"translated\": \"下一班地铁还要多久到？\"}, {\"original\": \"Excusez-moi, je dois passer.\", \"translated\": \"不好意思，麻烦让我过去一下。\"}, {\"original\": \"Cette place est-elle occupée ?\", \"translated\": \"这个座位有人坐吗？\"}, {\"original\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d’aller à XX ?\", \"translated\": \"不好意思，请问我在哪儿换乘2号线去XX？\"}, {\"original\": \"Comment puis-je me rendre à XX ?\", \"translated\": \"我怎么去XX？\"}]', 4, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser sur un site touristique ?\", \"Génial ! Voici 10 expressions courantes liées aux sites touristiques, avec leur traduction en chinois :\"]', '[\"Visite touristique\", \"Prendre des photos\", \"Acheter des billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander le prix des billets, trouver un parking ou solliciter un service de guide touristique ? N\'hésitez pas à demander !\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Combien coûte le droit d\'entrée ?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"Y a-t-il des billets étudiants disponibles ?\", \"translated\": \"有学生票吗？\"}, {\"original\": \"À quelle heure ouvre l\'attraction ?\", \"translated\": \"景点几点开门？\"}, {\"original\": \"Quelles sont les activités amusantes à faire ici ?\", \"translated\": \"这里有哪些好玩的项目？\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"您能帮我们拍张照吗？\"}, {\"original\": \"Où se trouve le bus touristique ?\", \"translated\": \"观光巴士在哪里？\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"厕所在哪儿？\"}, {\"original\": \"Où est le meilleur point de vue ?\", \"translated\": \"最佳观景点在哪儿？\"}, {\"original\": \"Le paysage est magnifique ici.\", \"translated\": \"这里的风景真美。\"}, {\"original\": \"Y a-t-il une visite guidée disponible ?\", \"translated\": \"提供导游服务吗？\"}]', 5, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser pour prendre un taxi ou utiliser un service de taxi ?\", \"Super ! Voici 10 expressions courantes liées aux taxis ou aux services de taxi, avec leur traduction en chinois :\"]', '[\"Prendre un taxi\", \"Indiquer la destination\", \"Paiement\"]', 'fr', '[\"Pour l’instant, que voulez-vous faire en priorité ? Par exemple, demander la destination, le prix, ou une facture — n’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Où puis-je prendre un taxi ?\", \"translated\": \"我在哪儿能打到出租车？\"}, {\"original\": \"Veuillez me conduire à cette adresse.\", \"translated\": \"请送我去这个地址。\"}, {\"original\": \"Ça coûtera environ combien ?\", \"translated\": \"大概要多少钱？\"}, {\"original\": \"Pourriez-vous mettre le compteur, s’il vous plaît ?\", \"translated\": \"麻烦您打表，好吗？\"}, {\"original\": \"Pourriez-vous rouler un peu plus vite ? Je suis pressé(e).\", \"translated\": \"能开快一点吗？我赶时间。\"}, {\"original\": \"Veuillez vous arrêter ici.\", \"translated\": \"请在这里停车。\"}, {\"original\": \"Acceptez-vous les cartes bancaires ou les paiements mobiles ?\", \"translated\": \"您支持银行卡或手机支付吗？\"}, {\"original\": \"Pourrais-je avoir un reçu, s’il vous plaît ?\", \"translated\": \"可以给我一张发票吗？\"}, {\"original\": \"Merci, monsieur/madame le chauffeur.\", \"translated\": \"谢谢，师傅！\"}, {\"original\": \"Il reste encore combien de temps ?\", \"translated\": \"还要多久才到？\"}]', 6, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser en pharmacie ?\", \"Super ! Voici 10 expressions courantes liées à la pharmacie, avec leur traduction en chinois :\"]', '[\"Acheter des médicaments\", \"Consulter\", \"Payer\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander des instructions sur la prise du médicament, des formules liées à l’utilisation de votre assurance santé, ou encore la durée du traitement ? N’hésitez pas à poser vos questions !\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Avez-vous des médicaments contre le rhume ?\", \"translated\": \"您有感冒药吗？\"}, {\"original\": \"Comment dois-je prendre ce médicament ?\", \"translated\": \"我该怎么服用这种药？\"}, {\"original\": \"Avez-vous des analgésiques ?\", \"translated\": \"您有止痛药吗？\"}, {\"original\": \"Y a-t-il une notice d’utilisation ?\", \"translated\": \"这个药有说明书吗？\"}, {\"original\": \"Ce médicament a-t-il des effets secondaires ?\", \"translated\": \"这种药有什么副作用吗？\"}, {\"original\": \"Puis-je utiliser ma carte d’assurance maladie ?\", \"translated\": \"我能用我的医保卡吗？\"}, {\"original\": \"Pourriez-vous me donner une boîte de pansements, s’il vous plaît ?\", \"translated\": \"请给我一盒创可贴，好吗？\"}, {\"original\": \"Avez-vous des médicaments contre la fièvre ?\", \"translated\": \"您有退烧药吗？\"}, {\"original\": \"Je me suis un peu écorché(e). Avez-vous un antiseptique et des pansements ?\", \"translated\": \"我擦破了点皮，您有消毒药水和创可贴吗？\"}, {\"original\": \"À quelle heure fermez-vous ?\", \"translated\": \"你们几点关门？\"}]', 7, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser pour les services d\'urgence ?\", \"Super ! Voici 10 expressions courantes liées aux services d\'urgence, avec leur traduction en chinois :\"]', '[\"Appeler la police\", \"Premiers secours\", \"Demander de l\'aide\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation d\'urgence précise en tête, par exemple un incendie, une personne blessée qui a besoin d\'aide, ou un appel d\'urgence ? N\'hésitez pas à me le dire.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Veuillez m\'aider à appeler une ambulance.\", \"translated\": \"请帮我叫一辆救护车。\"}, {\"original\": \"Où se trouve l\'hôpital ?\", \"translated\": \"医院在哪儿？\"}, {\"original\": \"Quelqu\'un est blessé.\", \"translated\": \"有人受伤了。\"}, {\"original\": \"Veuillez m\'aider.\", \"translated\": \"请帮帮我。\"}, {\"original\": \"Où se trouve le poste de police ?\", \"translated\": \"警察局在哪儿？\"}, {\"original\": \"J\'ai perdu mes affaires.\", \"translated\": \"我的物品丢了。\"}, {\"original\": \"Quel est le numéro des pompiers ?\", \"translated\": \"消防部门的电话号码是多少？\"}, {\"original\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le poste de police le plus proche ?\", \"translated\": \"我的护照丢了。您知道最近的警察局在哪儿吗？\"}, {\"original\": \"Y a-t-il une sortie de secours ?\", \"translated\": \"有紧急出口吗？\"}, {\"original\": \"Quelqu\'un s\'est évanoui.\", \"translated\": \"有人晕倒了。\"}]', 8, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser à la plage ou au bord de la piscine ?\", \"Génial ! Voici 10 expressions courantes liées à la plage ou à la piscine, avec leur traduction en chinois :\"]', '[\"Natation\", \"Bain de soleil\", \"Sports de plage\"]', 'fr', '[\"Pour le moment, pourriez-vous m\'indiquer le contexte de l\'événement ou du festival local auquel vous participez, par exemple un festival culturel, gastronomique ou musical ? Veuillez préciser le contexte.\", \"Veuillez décrire les activités auxquelles vous participez.\"]', '[\"Avez-vous une situation précise en tête ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[{\"original\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\", \"translated\": \"看！那边的海浪真大。\"}, {\"original\": \"N\'oubliez pas d\'appliquer de la crème solaire, les rayons UV sont très forts ici.\", \"translated\": \"记得涂防晒霜，这里的紫外线很强。\"}, {\"original\": \"Le sable de cette plage est si fin qu\'on dirait marcher sur du coton.\", \"translated\": \"这片海滩的沙子特别细，踩上去像踩在棉花上。\"}, {\"original\": \"Et si on jouait au volley-ball sur la plage ?\", \"translated\": \"要不要在沙滩上打排球？\"}, {\"original\": \"Les voiliers au loin sont magnifiques.\", \"translated\": \"远处的帆船真美。\"}, {\"original\": \"L\'eau est si claire ici qu\'on peut même voir les poissons.\", \"translated\": \"这里的水太清澈了，连鱼都能看见。\"}, {\"original\": \"Allons chercher des coquillages.\", \"translated\": \"咱们去找些贝壳吧。\"}, {\"original\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\", \"translated\": \"日落时分在海滩散步一定很浪漫。\"}, {\"original\": \"J\'ai entendu dire que les fruits de mer sont très frais ici, allons-en goûter.\", \"translated\": \"听说这里的海鲜特别新鲜，咱们去尝尝吧。\"}, {\"original\": \"La marée monte, rentrons vers la rive.\", \"translated\": \"涨潮了，咱们往岸边走吧。\"}]', 9, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser lors d\'événements et de festivals locaux ?\", \"Génial ! Voici 10 expressions courantes sur les événements et festivals locaux, avec leur traduction en chinois :\"]', '[\"Assister à des événements\", \"Célébrer des festivals\", \"Découvrir la culture\"]', 'fr', '[\"Pour l\'instant, pourriez-vous m\'indiquer le contexte de l\'événement ou du festival local auquel vous participez — par exemple Halloween, un concert, une fête entre amis ou autre chose ? Veuillez fournir ce contexte.\", \"Veuillez décrire les activités qui vous viennent à l\'esprit.\"]', '[\"Avez-vous une situation précise en tête ? N\'hésitez pas à demander librement.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[{\"original\": \"Y a-t-il des événements aujourd\'hui ?\", \"translated\": \"今天有什么活动吗？\"}, {\"original\": \"Y a-t-il quelque chose de spécial à propos de ce festival ?\", \"translated\": \"这个节日有什么特别之处吗？\"}, {\"original\": \"Où se déroule la célébration ?\", \"translated\": \"庆祝活动在哪里举行？\"}, {\"original\": \"Comment puis-je acheter des billets ?\", \"translated\": \"我怎么买票？\"}, {\"original\": \"À quelle heure commence le spectacle ?\", \"translated\": \"演出什么时候开始？\"}, {\"original\": \"Quels sont les plats traditionnels proposés ?\", \"translated\": \"有哪些传统食物？\"}, {\"original\": \"C\'est vraiment animé ici !\", \"translated\": \"这里真热闹！\"}, {\"original\": \"Y a-t-il des activités folkloriques ?\", \"translated\": \"有民俗活动吗？\"}, {\"original\": \"Joyeuses fêtes !\", \"translated\": \"节日快乐！\"}, {\"original\": \"À quelle heure se termine l\'événement ?\", \"translated\": \"活动什么时候结束？\"}]', 10, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans un musée ou une galerie d\'art ?\", \"Génial ! Voici 10 expressions courantes liées aux musées et galeries d\'art, avec leur traduction en chinois :\"]', '[\"Visite\", \"Visite guidée\", \"Achat de billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête — par exemple demander un guide d\'introduction, des expressions liées au plan de visite, ou celles utilisées pour commenter une exposition ? N\'hésitez pas à poser vos questions !\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Combien coûte le droit d\'entrée ?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"Avez-vous des guides audio ?\", \"translated\": \"提供语音导览吗？\"}, {\"original\": \"Qui a créé cette œuvre ?\", \"translated\": \"这件艺术品是谁创作的？\"}, {\"original\": \"Où se trouve la pièce la plus précieuse du musée ?\", \"translated\": \"博物馆最珍贵的藏品在哪儿？\"}, {\"original\": \"La prise de photos est-elle autorisée ?\", \"translated\": \"可以拍照吗？\"}, {\"original\": \"Y a-t-il des expositions spéciales ici ?\", \"translated\": \"这里有没有特别展览？\"}, {\"original\": \"Combien de temps dure la visite ?\", \"translated\": \"参观大概要多长时间？\"}, {\"original\": \"Pourriez-vous nous en faire une présentation ?\", \"translated\": \"能给我们简单介绍一下吗？\"}, {\"original\": \"Ces œuvres sont vraiment remarquables.\", \"translated\": \"这些作品真精美啊！\"}, {\"original\": \"Où se trouve la boutique de souvenirs ?\", \"translated\": \"纪念品商店在哪儿？\"}]', 11, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans un café ?\", \"Super ! Voici 10 expressions courantes utilisées au café, avec leur traduction en chinois :\"]', '[\"Commander un café\", \"Se reposer\", \"Socialiser\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, comme demander la carte, des boissons glacées ou chaudes, d\'autres produits ? N\'hésitez pas à demander !\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Je voudrais un latte, s\'il vous plaît.\", \"translated\": \"我要一杯拿铁，谢谢。\"}, {\"original\": \"Vous avez du Wi-Fi ?\", \"translated\": \"你们有Wi-Fi吗？\"}, {\"original\": \"Pourrais-je voir la carte, s\'il vous plaît ?\", \"translated\": \"请问可以给我看一下菜单吗？\"}, {\"original\": \"Est-ce que les recharges sont autorisées ?\", \"translated\": \"可以免费续杯吗？\"}, {\"original\": \"Mon café est-il prêt ?\", \"translated\": \"我的咖啡好了吗？\"}, {\"original\": \"Combien de temps puis-je rester assis ici ?\", \"translated\": \"我可以在店里坐多久？\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"您能帮我们拍张照吗？\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"洗手间在哪里？\"}, {\"original\": \"L\'addition, s\'il vous plaît. Merci.\", \"translated\": \"请结账，谢谢。\"}, {\"original\": \"C\'est vraiment délicieux.\", \"translated\": \"味道真棒！\"}]', 12, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在餐厅使用的10个常用短语吗？\", \"太棒了！这里有10个关于餐厅的常用短语，附带英语翻译：\"]', '[\"用餐\", \"点餐\", \"结账\"]', 'zh', '[\"目前您心里有特定场景吗？比如点饮料、投诉，或者询问食材？欢迎随时提问。\", \"请描述您心里想到的那个场景。\"]', '[]', '[{\"original\": \"打扰一下，我们的餐还要等多久？\", \"translated\": \"Excuse me, how much longer will our food be?\"}, {\"original\": \"请给我们安排一张两人桌。\", \"translated\": \"A table for two, please.\"}, {\"original\": \"请问可以看一下菜单吗？\", \"translated\": \"Could we see the menu, please?\"}, {\"original\": \"您有什么招牌菜可以推荐吗？\", \"translated\": \"Do you have any signature dishes to recommend?\"}, {\"original\": \"我要点这个和这个。\", \"translated\": \"I\'d like to order this, and this.\"}, {\"original\": \"请给我一杯水，谢谢。\", \"translated\": \"A glass of water, please. Thanks.\"}, {\"original\": \"请结账。\", \"translated\": \"The bill, please.\"}, {\"original\": \"我可以用信用卡支付吗？\", \"translated\": \"Can I pay by credit card?\"}, {\"original\": \"麻烦把这份打包带走，谢谢。\", \"translated\": \"Could you pack this to go, please?\"}, {\"original\": \"食物非常美味，谢谢！\", \"translated\": \"The food was delicious, thank you.\"}]', 1, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在酒店使用的10个常用短语吗？\", \"太棒了！这里有10个关于酒店的常用短语，附带英语翻译：\"]', '[\"入住\", \"退房\", \"客房服务\"]', 'zh', '[\"目前，您心里有特定的情境吗？比如房间位置、其他酒店服务，或者退房相关问题？欢迎随时提问。\", \"请描述一下您心里想的情境。\"]', '[]', '[{\"original\": \"你好，我有预订，这是我的护照。\", \"translated\": \"Hello, I have a reservation, here is my passport.\"}, {\"original\": \"你们还有空房吗？\", \"translated\": \"Do you have any vacancies?\"}, {\"original\": \"不好意思，请问酒店有健身房或洗衣房吗？\", \"translated\": \"Excuse me, does the hotel have a gym or a laundry room?\"}, {\"original\": \"早餐几点开始？\", \"translated\": \"What time does breakfast start?\"}, {\"original\": \"请给我一把房卡，谢谢。\", \"translated\": \"Could I have a room key, please?\"}, {\"original\": \"您能帮我把行李送到房间吗？\", \"translated\": \"Could you help me take my luggage to the room?\"}, {\"original\": \"我怎么呼叫客房服务？\", \"translated\": \"How do I call room service?\"}, {\"original\": \"退房时间是几点？\", \"translated\": \"What time is check-out?\"}, {\"original\": \"您能给我开张收据／发票吗？\", \"translated\": \"Could you write me a receipt/invoice?\"}, {\"original\": \"我可以把行李先寄存在这里吗？\", \"translated\": \"Can I leave my luggage here?\"}]', 2, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在机场使用的10个常用短语吗？\", \"太棒了！这里有10个关于机场的常用短语，附带英语翻译：\"]', '[\"值机\", \"登机\", \"行李托运\"]', 'zh', '[\"目前，您心里有特定场景吗？比如值机、行李提取或租车服务，欢迎随时提问。\", \"请描述您心里想到的具体场景。\"]', '[]', '[{\"original\": \"值机柜台在哪里？\", \"translated\": \"Where is the check-in counter?\"}, {\"original\": \"我想要一个靠窗的座位，谢谢。\", \"translated\": \"I\'d like a window seat, please.\"}, {\"original\": \"这班航班延误了吗？\", \"translated\": \"Is this flight delayed?\"}, {\"original\": \"我需要托运行李。\", \"translated\": \"I need to check this baggage.\"}, {\"original\": \"登机口在哪里？\", \"translated\": \"Where is the boarding gate?\"}, {\"original\": \"飞机马上就要起飞了。\", \"translated\": \"The plane is about to take off.\"}, {\"original\": \"我需要把笔记本电脑和充电宝拿出来吗？\", \"translated\": \"Do I need to take out my laptop and power bank?\"}, {\"original\": \"免税店在哪里？\", \"translated\": \"Where is the duty-free shop?\"}, {\"original\": \"我找不到我的行李箱了。\", \"translated\": \"I can\'t find my suitcase.\"}, {\"original\": \"你们提供轮椅服务吗？\", \"translated\": \"Do you have a wheelchair service?\"}]', 3, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在公共交通工具使用的10个常用短语吗？\", \"太棒了！这里有10个关于公共交通工具的常用短语，附带英语翻译：\"]', '[\"乘坐公交车/地铁\", \"购票\", \"换乘\"]', 'zh', '[\"目前，您心里有具体的场景吗？比如询问公交站、票价，或者下车——欢迎随时提问。\", \"请描述您心里想到的具体场景。\"]', '[]', '[{\"original\": \"这趟公交车去终点站吗？\", \"translated\": \"Does this bus go to the terminal?\"}, {\"original\": \"下一站是哪里？\", \"translated\": \"What is the next stop?\"}, {\"original\": \"我在哪里可以买票？\", \"translated\": \"Where can I buy a ticket?\"}, {\"original\": \"请给我一张去XX的票。\", \"translated\": \"One ticket to XX, please.\"}, {\"original\": \"我需要换乘吗？\", \"translated\": \"Do I need to transfer?\"}, {\"original\": \"下一班地铁还要等多久？\", \"translated\": \"How long until the next subway train?\"}, {\"original\": \"不好意思，请让我过去一下。\", \"translated\": \"Excuse me, please let me pass.\"}, {\"original\": \"这个座位有人坐了吗？\", \"translated\": \"Is this seat taken?\"}, {\"original\": \"不好意思，请问我去XX，要在哪儿换乘2号线？\", \"translated\": \"Excuse me, where can I transfer to Line 2 to get to XX?\"}, {\"original\": \"我怎么去XX？\", \"translated\": \"How do I get to XX?\"}]', 4, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在旅游景点使用的10个常用短语吗？\", \"太棒了！这里有10个关于旅游景点的常用短语，附带英语翻译：\"]', '[\"观光游览\", \"拍照\", \"购票\"]', 'zh', '[\"目前，您心里有特定场景吗？比如询问票价、找停车场，或导游服务——欢迎随时提问。\", \"请描述您心里想到的场景。\"]', '[]', '[{\"original\": \"入场费多少钱？\", \"translated\": \"How much is the entrance fee?\"}, {\"original\": \"有学生票吗？\", \"translated\": \"Are there student tickets available?\"}, {\"original\": \"景点几点开放？\", \"translated\": \"What time does the attraction open?\"}, {\"original\": \"这里有什么好玩的？\", \"translated\": \"What are the fun things to do here?\"}, {\"original\": \"您能帮我们拍张照吗？\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"观光巴士在哪里？\", \"translated\": \"Where is the sightseeing bus?\"}, {\"original\": \"洗手间在哪儿？\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"最佳观景点在哪儿？\", \"translated\": \"Where is the best viewing spot?\"}, {\"original\": \"这里的风景真美。\", \"translated\": \"The scenery here is beautiful.\"}, {\"original\": \"有提供导览服务吗？\", \"translated\": \"Is there a guided tour available?\"}]', 5, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在出租车或出租车服务使用的10个常用短语吗？\", \"太棒了！这里有10个关于出租车或出租车服务的常用短语，附带英语翻译：\"]', '[\"打车\", \"告知目的地\", \"支付\"]', 'zh', '[\"目前，您最想做什么呢？比如询问目的地、价格，或者索要发票——随时问我哦。\", \"请描述一下您脑海中的场景。\"]', '[]', '[{\"original\": \"我在哪里可以打到出租车？\", \"translated\": \"Where can I get a taxi?\"}, {\"original\": \"请带我去这个地址。\", \"translated\": \"Please take me to this address.\"}, {\"original\": \"大概要多少钱？\", \"translated\": \"Roughly how much will it be?\"}, {\"original\": \"麻烦您打表计费，好吗？\", \"translated\": \"Could you use the meter, please?\"}, {\"original\": \"请开快一点，我赶时间。\", \"translated\": \"Please drive a bit faster, I\'m in a hurry.\"}, {\"original\": \"请在这里停车。\", \"translated\": \"Please stop here.\"}, {\"original\": \"您支持银行卡或手机支付吗？\", \"translated\": \"Do you accept cards or mobile payments?\"}, {\"original\": \"能给我开发票吗？\", \"translated\": \"Could I have a receipt, please?\"}, {\"original\": \"谢谢，师傅！\", \"translated\": \"Thank you, driver.\"}, {\"original\": \"还有多远？\", \"translated\": \"How much further is it?\"}]', 6, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在药店使用的10个常用短语吗？\", \"太棒了！这里有10个关于药店的常用短语，附带英语翻译：\"]', '[\"购药\", \"咨询\", \"付款\"]', 'zh', '[\"目前，您心里有没有具体场景，比如询问用药说明、医保使用相关表达、疗程时长等？欢迎随时提问。\", \"请描述您心里想的情境。\"]', '[]', '[{\"original\": \"你们有治感冒的药吗？\", \"translated\": \"Do you have cold medicine?\"}, {\"original\": \"这种药我该怎么吃？\", \"translated\": \"How should I take this medicine?\"}, {\"original\": \"你们有止痛药吗？\", \"translated\": \"Do you have any painkillers?\"}, {\"original\": \"这药有说明书吗？\", \"translated\": \"Is there an instruction leaflet?\"}, {\"original\": \"这种药有什么副作用吗？\", \"translated\": \"Does this medicine have any side effects?\"}, {\"original\": \"我能用医保卡付款吗？\", \"translated\": \"Can I use my medical insurance card?\"}, {\"original\": \"请给我一盒创可贴，谢谢。\", \"translated\": \"Could I have a box of Band-Aids, please?\"}, {\"original\": \"你们有退烧药吗？\", \"translated\": \"Do you have any fever reducers?\"}, {\"original\": \"我有点擦伤，你们有消毒水和创可贴吗？\", \"translated\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\"}, {\"original\": \"你们几点关门？\", \"translated\": \"What time do you close?\"}]', 7, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在紧急服务中使用的10个常用短语吗？\", \"太棒了！这里有10个关于紧急服务的常用短语，附带英文翻译：\"]', '[\"报警\", \"急救\", \"求助\"]', 'zh', '[\"目前，您心里是否有具体的紧急情况，比如火灾、受伤需要帮助、紧急呼叫等？欢迎随时提问。\", \"请描述您脑海中想到的情况。\"]', '[]', '[{\"original\": \"请帮我叫一辆救护车。\", \"translated\": \"Please help me call an ambulance.\"}, {\"original\": \"医院在哪里？\", \"translated\": \"Where is the hospital?\"}, {\"original\": \"有人受伤了。\", \"translated\": \"Someone is injured.\"}, {\"original\": \"请帮帮我。\", \"translated\": \"Please help me.\"}, {\"original\": \"警察局在哪里？\", \"translated\": \"Where is the police station?\"}, {\"original\": \"我的物品丢了。\", \"translated\": \"I\'ve lost my belongings.\"}, {\"original\": \"消防部门的电话号码是多少？\", \"translated\": \"What is the number for the fire department?\"}, {\"original\": \"我丢了护照。您知道最近的警察局在哪儿吗？\", \"translated\": \"I\'ve lost my passport. Do you know where the nearest police station is?\"}, {\"original\": \"这里有紧急出口吗？\", \"translated\": \"Is there an emergency exit?\"}, {\"original\": \"有人晕倒了。\", \"translated\": \"Someone has fainted.\"}]', 8, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在沙滩或池畔使用的10个常用短语吗？\", \"太棒了！这里有10个关于沙滩或池畔的常用短语，附带英语翻译：\"]', '[\"游泳\", \"日光浴\", \"沙滩运动\"]', 'zh', '[\"目前，您能告诉我您要参加的当地活动或节日的背景吗？比如文化节、美食节或音乐节。请提供相关背景。\", \"请描述您要参加的具体活动。\"]', '[\"您心里有特定场景吗？欢迎随时提问。\", \"请描述您脑海中的场景。\"]', '[{\"original\": \"看！那边的海浪真大。\", \"translated\": \"Look! The waves over there are really big.\"}, {\"original\": \"记得涂防晒霜，这里的紫外线很强。\", \"translated\": \"Remember to apply sunscreen, the UV rays here are very strong.\"}, {\"original\": \"这片海滩的沙子特别细，踩上去像走在棉花上。\", \"translated\": \"The sand on this beach is so fine, it feels like stepping on cotton.\"}, {\"original\": \"要不要来场沙滩排球？\", \"translated\": \"How about playing volleyball on the beach?\"}, {\"original\": \"远处的帆船真漂亮。\", \"translated\": \"The sailboats in the distance look beautiful.\"}, {\"original\": \"这里的水特别清澈，连鱼都能看见。\", \"translated\": \"The water here is so clear, you can even see the fish.\"}, {\"original\": \"咱们去找找贝壳吧。\", \"translated\": \"Let\'s go find some seashells.\"}, {\"original\": \"日落时分在沙滩散步一定很浪漫。\", \"translated\": \"Taking a walk on the beach at sunset must be very romantic.\"}, {\"original\": \"听说这里的海鲜特别新鲜，咱们去尝尝。\", \"translated\": \"I heard the seafood here is very fresh, let\'s go try some.\"}, {\"original\": \"涨潮了，咱们往岸边走吧。\", \"translated\": \"The tide is coming in, let\'s head towards the shore.\"}]', 9, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在当地活动和节日使用的10个常用短语吗？\", \"太棒了！这里有10个关于当地活动和节日的常用短语，附带英语翻译：\"]', '[\"参加活动\", \"庆祝节日\", \"了解文化\"]', 'zh', '[\"目前，您能告诉我您要参加的当地活动或节日的具体情境吗？比如万圣节、音乐会、朋友聚会，或者其他什么活动？请提供具体情境。\", \"请描述一下您脑海中想到的活动。\"]', '[\"您心里有特定的情境吗？欢迎随时提问。\", \"请描述一下您脑海中想到的情境。\"]', '[{\"original\": \"今天有什么活动吗？\", \"translated\": \"Are there any events today?\"}, {\"original\": \"这个节日有什么特别之处吗？\", \"translated\": \"Is there anything special about this festival?\"}, {\"original\": \"庆祝活动在哪里举行？\", \"translated\": \"Where is the celebration being held?\"}, {\"original\": \"我该怎么买票？\", \"translated\": \"How can I buy tickets?\"}, {\"original\": \"演出几点开始？\", \"translated\": \"What time does the performance start?\"}, {\"original\": \"有哪些传统美食？\", \"translated\": \"What traditional food is there?\"}, {\"original\": \"这里真是热闹啊！\", \"translated\": \"It\'s really lively here.\"}, {\"original\": \"有民间活动吗？\", \"translated\": \"Are there any folk activities?\"}, {\"original\": \"节日快乐！\", \"translated\": \"Happy holidays!\"}, {\"original\": \"活动几点结束？\", \"translated\": \"What time does the event end?\"}]', 10, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在博物馆或美术馆使用的10个常用短语吗？\", \"太棒了！这里有10个关于博物馆或美术馆的常用短语，附带英语翻译：\"]', '[\"参观\", \"导览服务\", \"购票\"]', 'zh', '[\"目前，您心里有没有具体场景？比如索要导览手册、跟参观路线相关的表达、对展品发表看法的表达等，欢迎随时提问。\", \"请描述一下您心里想到的具体场景。\"]', '[]', '[{\"original\": \"门票多少钱？\", \"translated\": \"How much is the admission fee?\"}, {\"original\": \"你们提供语音导览吗？\", \"translated\": \"Do you have audio guides?\"}, {\"original\": \"这件艺术品是谁创作的？\", \"translated\": \"Who created this artwork?\"}, {\"original\": \"博物馆最珍贵的藏品在哪儿？\", \"translated\": \"Where is the museum\'s most prized piece?\"}, {\"original\": \"可以拍照吗？\", \"translated\": \"Is photography allowed?\"}, {\"original\": \"这里有没有特别展览？\", \"translated\": \"Are there any special exhibitions here?\"}, {\"original\": \"参观大概需要多长时间？\", \"translated\": \"How long does the visit take?\"}, {\"original\": \"您能给我们做个简单介绍吗？\", \"translated\": \"Could you give us an introduction?\"}, {\"original\": \"这些作品真是精美极了！\", \"translated\": \"These works are truly exquisite.\"}, {\"original\": \"纪念品商店在哪儿？\", \"translated\": \"Where is the souvenir shop?\"}]', 11, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在咖啡馆使用的10个常用短语吗？\", \"太棒了！这里有10个关于咖啡馆的常用短语，附带英语翻译：\"]', '[\"点咖啡\", \"休息\", \"社交\"]', 'zh', '[\"目前，您心里有没有特定场景，比如要菜单、要冰饮或热饮、点其他产品？欢迎随时提问。\", \"请描述一下您心里想的那个场景。\"]', '[]', '[{\"original\": \"请给我一杯拿铁。\", \"translated\": \"I\'ll have a latte, please.\"}, {\"original\": \"你们有Wi-Fi吗？\", \"translated\": \"Do you have Wi-Fi?\"}, {\"original\": \"请问能看一下菜单吗？\", \"translated\": \"Could I see the menu, please?\"}, {\"original\": \"可以免费续杯吗？\", \"translated\": \"Are refills allowed?\"}, {\"original\": \"我的咖啡好了吗？\", \"translated\": \"Is my coffee ready?\"}, {\"original\": \"我可以在这里坐多久？\", \"translated\": \"How long can I sit here?\"}, {\"original\": \"您能帮我们拍张照吗？\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"洗手间在哪里？\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"请结账，谢谢。\", \"translated\": \"Check, please. Thank you.\"}, {\"original\": \"味道真的很棒。\", \"translated\": \"It tastes really good.\"}]', 12, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"レストランで使える10個のよく使う言い回しを教えていただけますか？\", \"素晴らしい！以下はレストラン関連のよく使う10個の言い回しで、アラビア語訳付きです：\"]', '[\"食事\", \"注文\", \"清算\"]', 'ja', '[\"今のところ、ドリンクの注文や苦情の申し立て、材料の確認など、具体的な状況が頭に浮かんでいますか？ 何でも気軽に聞いてください。\", \"あなたの頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"すみません、料理はあとどのくらいで来ますか？\", \"translated\": \"عذرًا، كم من الوقت سيستغرق وصول طعامنا بعدُ؟\"}, {\"original\": \"二人用のテーブルをお願いします。\", \"translated\": \"من فضلكم طاولة لشخصين.\"}, {\"original\": \"メニューを見せていただいてもよろしいですか？\", \"translated\": \"هل يمكنني رؤية القائمة، من فضلكم؟\"}, {\"original\": \"おすすめの特製料理はありますか？\", \"translated\": \"هل لديكم أطباق مميزة توصون بها؟\"}, {\"original\": \"これを注文したいのですが、こちらもお願いします。\", \"translated\": \"أود طلب هذا، وهذا أيضًا من فضلكم.\"}, {\"original\": \"水を一杯お願いします。ありがとうございます。\", \"translated\": \"كوب ماء من فضلكم، شكرًا جزيلًا.\"}, {\"original\": \"お会計をお願いします。\", \"translated\": \"الفاتورة من فضلكم.\"}, {\"original\": \"クレジットカードで支払えますか？\", \"translated\": \"هل يمكنني الدفع باستخدام بطاقة الائتمان؟\"}, {\"original\": \"これをお持ち帰りでお願いできますか？\", \"translated\": \"هل يمكنني أخذ هذا معي للخارج؟\"}, {\"original\": \"料理がとても美味しかったです。ありがとうございました。\", \"translated\": \"كانت الأطباق لذيذة جدًّا، شكرًا جزيلًا.\"}]', 1, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ホテルで使える10個のよく使う表現を教えていただけますか？\", \"素晴らしい！ホテルに関する10個のよく使う表現を、アラビア語での翻訳付きでご紹介します：\"]', '[\"チェックイン\", \"チェックアウト\", \"ルームサービス\"]', 'ja', '[\"今のところ、お部屋の場所やその他のホテルサービス、チェックアウトなど、何か特定の状況が頭に浮かんでいますか？何でも気軽に聞いてください。\", \"あなたの頭にある状況を教えてください。\"]', '[]', '[{\"original\": \"こんにちは、予約しています。こちらが私のパスポートです。\", \"translated\": \"مرحبًا، لدي حجزٌ هنا. وهذه جواز سفري.\"}, {\"original\": \"空室はありますか？\", \"translated\": \"هل تتوفر غرف شاغرة؟\"}, {\"original\": \"すみません、ホテルにはジムやランドリールームがありますか？\", \"translated\": \"عذرًا، هل يتوافر في الفندق صالة ألعاب رياضية أو غرفة لغسيل الملابس؟\"}, {\"original\": \"朝食は何時からですか？\", \"translated\": \"في أي وقت تُقدَّم وجبة الإفطار؟\"}, {\"original\": \"部屋の鍵をいただけますか？\", \"translated\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\"}, {\"original\": \"荷物を部屋まで運んでいただけますか？\", \"translated\": \"هل يمكنكم مساعدتي في نقل أمتعتي إلى الغرفة؟\"}, {\"original\": \"ルームサービスの呼び出し方はどうすればいいですか？\", \"translated\": \"كيف يمكنني الاتصال بخدمة الغرف؟\"}, {\"original\": \"チェックアウトは何時ですか？\", \"translated\": \"في أي وقت يتم المغادرة (التشيكان آوت)؟\"}, {\"original\": \"領収書／請求書を書いていただけますか？\", \"translated\": \"هل يمكنكم إصدار إيصال أو فاتورة لي؟\"}, {\"original\": \"荷物をここで預かってもらえますか？\", \"translated\": \"هل يمكنني ترك أمتعتي هنا مؤقتًا؟\"}]', 2, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"空港で使える便利な10個のフレーズを教えていただけますか？\", \"素晴らしい！こちらに空港関連のよく使う10個のフレーズを、アラビア語訳とともにご用意しました：\"]', '[\"チェックイン\", \"搭乗\", \"手荷物預け\"]', 'ja', '[\"今のところ、チェックイン、手荷物受取、レンタカーなどの特定の状況が頭に浮かんでいますか？ 何でも気軽に聞いてください。\", \"頭に浮かんだ状況を教えてください。\"]', '[]', '[{\"original\": \"チェックインカウンターはどこですか？\", \"translated\": \"أين يكون مكتب تسجيل الوصول؟\"}, {\"original\": \"窓際の席を1つお願いします。\", \"translated\": \"أود أن أجلس في مقعد بجانب النافذة، من فضلك.\"}, {\"original\": \"この便は遅れていますか？\", \"translated\": \"هل هذا الرحلة متأخرة؟\"}, {\"original\": \"この荷物を預けたいのですが。\", \"translated\": \"أريد تسليم هذه الأمتعة للشحن.\"}, {\"original\": \"搭乗口はどこですか？\", \"translated\": \"أين يكون بوابة الصعود إلى الطائرة؟\"}, {\"original\": \"飛行機がすぐ離陸します。\", \"translated\": \"الطائرة على وشك الإقلاع.\"}, {\"original\": \"ノートパソコンとモバイルバッテリーを取り出さなければなりませんか？\", \"translated\": \"هل يجب أن أخرج جهازي اللوحي أو بنك الطاقة الخاص بي من الحقيبة؟\"}, {\"original\": \"免税店はどこですか？\", \"translated\": \"أين تقع متجر التجزئة المعفي من الرسوم الجمركية؟\"}, {\"original\": \"私のスーツケースが見つかりません。\", \"translated\": \"لا أستطيع العثور على حقيبتي.\"}, {\"original\": \"車いすサービスはありますか？\", \"translated\": \"هل تتوفر خدمة الكرسي المتحرك؟\"}]', 3, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"公共交通機関で使える、よく使う表現を10個教えていただけますか？\", \"素晴らしい！こちらが公共交通機関に関するよく使う表現10個と、アラビア語訳付きです：\"]', '[\"バス／地下鉄の利用\", \"切符の購入\", \"乗り換え\"]', 'ja', '[\"今のところ、バス停の確認・運賃の問い合わせ・降車などの具体的な状況をお考えですか？ 何でもお気軽にお尋ねください。\", \"頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"このバスはターミナルへ行きますか？\", \"translated\": \"هل هذه الحافلة تذهب إلى المحطة؟\"}, {\"original\": \"次の停留所はどこですか？\", \"translated\": \"ما هي المحطة التالية؟\"}, {\"original\": \"どこで切符を買えますか？\", \"translated\": \"أين يمكنني شراء التذكرة؟\"}, {\"original\": \"XX行きの切符を1枚、お願いします。\", \"translated\": \"من فضلك، تذكرة واحدة إلى XX.\"}, {\"original\": \"乗り換えが必要ですか？\", \"translated\": \"هل أحتاج إلى التحويل؟\"}, {\"original\": \"次の地下鉄の列車まであと何分ですか？\", \"translated\": \"كم دقيقة متبقية حتى قطار المترو القادم؟\"}, {\"original\": \"すみません、通らせてください。\", \"translated\": \"عذرًا، من فضلك افسح لي الطريق.\"}, {\"original\": \"この席は空いていますか？\", \"translated\": \"هل هذا المقعد شاغر؟\"}, {\"original\": \"すみません、XXへ行くためには、どこで2号線に乗り換えればいいですか？\", \"translated\": \"عذرًا، من أين أنقل إلى الخط ٢ للوصول إلى XX؟\"}, {\"original\": \"XXへはどう行けばいいですか？\", \"translated\": \"كيف أصل إلى XX؟\"}]', 4, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"観光スポットで使える10個のよく使う表現を教えていただけますか？\", \"素晴らしい！観光スポットで使える便利な表現10個を、アラビア語訳とともにご紹介します：\"]', '[\"観光\", \"写真撮影\", \"チケット購入\"]', 'ja', '[\"今のところ、チケットの価格を尋ねる、駐車場を探す、ツアーのガイドサービスについて聞くなど、具体的な状況が思いつきますか？自由に聞いてください。\", \"頭の中で思い浮かぶ状況を教えてください。\"]', '[]', '[{\"original\": \"入場料はいくらですか？\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"学生割引のチケットはありますか？\", \"translated\": \"هل تتوفر تذاكر مخصصة للطلاب؟\"}, {\"original\": \"観光スポットはいつから開いていますか？\", \"translated\": \"متى يفتح موقع الجذب السياحي؟\"}, {\"original\": \"ここではどんな楽しいことができますか？\", \"translated\": \"ما الأنشطة الممتعة التي يمكن القيام بها هنا؟\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"هل يمكنك التقاط صورة لنا؟\"}, {\"original\": \"観光バスの停留所はどこですか？\", \"translated\": \"أين يتوقف حافلة الجولات السياحية؟\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"أين تقع دورة المياه؟\"}, {\"original\": \"一番おすすめの眺めの良い場所はどこですか？\", \"translated\": \"ما أفضل مكان للاستمتاع بالمنظر؟\"}, {\"original\": \"ここからの景色はとてもきれいです。\", \"translated\": \"المنظر من هنا جميلٌ جدًّا.\"}, {\"original\": \"ガイド付きツアーはありますか？\", \"translated\": \"هل توجد جولة سياحية بإرشاد مرشد؟\"}]', 5, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"タクシーまたはタクシーサービスで使える、よく使う10の言い回しを教えていただけますか？\", \"素晴らしい！こちらがタクシーまたはタクシーサービスに関する10のよく使う言い回しで、アラビア語での翻訳付きです：\"]', '[\"タクシーを利用する\", \"行き先を伝える\", \"支払いに関するやりとり\"]', 'ja', '[\"今、あなたが一番やりたいことは何ですか？例えば、行き先を尋ねたり、料金を聞いたり、領収書を頼んだり — 何でも自由に聞いて大丈夫です。\", \"頭の中で思い浮かべている状況を教えてください。\"]', '[]', '[{\"original\": \"タクシーはどこで乗れますか？\", \"translated\": \"أين يمكنني أخذ تاكسي؟\"}, {\"original\": \"この住所までお願いします。\", \"translated\": \"من فضلك خذني إلى هذا العنوان.\"}, {\"original\": \"だいたいいくらぐらいですか？\", \"translated\": \"كم سيكون المبلغ تقريبًا؟\"}, {\"original\": \"メーターを使ってもらえますか？\", \"translated\": \"هل يمكنك استخدام العداد من فضلك؟\"}, {\"original\": \"ちょっと急いでいるので、もう少し速く運転していただけますか？\", \"translated\": \"أنا مستعجل، هل يمكنك القيادة بسرعة أكبر قليلًا؟\"}, {\"original\": \"ここで止めてください。\", \"translated\": \"من فضلك توقف هنا.\"}, {\"original\": \"カードやモバイル決済は使えますか？\", \"translated\": \"هل تقبلون الدفع بالبطاقات أو عبر الهاتف المحمول؟\"}, {\"original\": \"領収書をいただけますか？\", \"translated\": \"هل يمكنني الحصول على إشعار دفع (فواتير) من فضلك؟\"}, {\"original\": \"ありがとうございました、運転手さん。\", \"translated\": \"شكرًا لك يا سائق.\"}, {\"original\": \"あとどれくらいですか？\", \"translated\": \"كم تبقى من المسافة بعد ذلك؟\"}]', 6, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"薬局で使える10個のよく使う表現を教えていただけますか？\", \"素晴らしい！こちらが薬局関連のよく使う表現10個と、アラビア語訳付きです：\"]', '[\"薬の購入\", \"相談\", \"支払い\"]', 'ja', '[\"今のところ、お薬の飲み方の確認、保険の使い方など、具体的なシチュエーションをお考えですか？期間やその他についても、気軽にご質問ください。\", \"頭の中で思い浮かんでいる状況を教えてください。\"]', '[]', '[{\"original\": \"風邪薬はありますか？\", \"translated\": \"هل لديك دواء للبرد؟\"}, {\"original\": \"この薬の飲み方はどうすればいいですか？\", \"translated\": \"كيف يجب أن أتناول هذا الدواء؟\"}, {\"original\": \"鎮痛剤はありますか？\", \"translated\": \"هل لديك مسكنات للألم؟\"}, {\"original\": \"説明書のパンフレットは付いていますか？\", \"translated\": \"هل يُرفق مع الدواء نشرة إرشادية؟\"}, {\"original\": \"この薬には副作用がありますか？\", \"translated\": \"هل لهذا الدواء أي آثار جانبية؟\"}, {\"original\": \"医療保険証を使えますか？\", \"translated\": \"هل يمكنني استخدام بطاقة التأمين الصحي؟\"}, {\"original\": \"絆創膏の箱を1つお願いします。\", \"translated\": \"من فضلك أعطني علبة من اللصقات الطبية.\"}, {\"original\": \"解熱剤はありますか？\", \"translated\": \"هل لديك خافضات للحرارة؟\"}, {\"original\": \"ちょっと切り傷があります。消毒液と絆創膏はありますか？\", \"translated\": \"لدي جرح بسيط، هل لديكم محلول مطهر ولصقات طبية؟\"}, {\"original\": \"何時まで営業していますか？\", \"translated\": \"إلى أي وقت تعملون؟\"}]', 7, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"緊急サービスで使える、10個のよく使う表現を教えていただけますか？\", \"素晴らしい！緊急サービスに関するよく使う表現10個を、アラビア語訳とともにご紹介します：\"]', '[\"警察への通報\", \"応急手当\", \"助けを求める\"]', 'ja', '[\"今のところ、火事・けが・助けが必要・緊急通報など、具体的な緊急状況を思い浮かべていますか？ どんなことでも気軽に聞いてください。\", \"あなたの頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"救急車を呼んでください。\", \"translated\": \"من فضلك ساعِدني في الاتصال بالإسعاف.\"}, {\"original\": \"病院はどこですか？\", \"translated\": \"أين تقع المستشفى؟\"}, {\"original\": \"誰かがけがをしました。\", \"translated\": \"أُصيب شخصٌ ما.\"}, {\"original\": \"助けてください。\", \"translated\": \"من فضلك ساعِدني.\"}, {\"original\": \"警察署はどこですか？\", \"translated\": \"أين تقع أقرب مركز شرطة؟\"}, {\"original\": \"荷物をなくしてしまいました。\", \"translated\": \"لقد فقدتُ أمتعتي.\"}, {\"original\": \"消防署にかける番号は何番ですか？\", \"translated\": \"ما هو رقم هاتف الإطفاء؟\"}, {\"original\": \"パスポートを紛失しました。近くの警察署の場所をご存知ですか？\", \"translated\": \"لقد فقدتُ جواز سفري. هل تعرف مكان أقرب مركز شرطة؟\"}, {\"original\": \"非常口がありますか？\", \"translated\": \"هل توجد مخرج طوارئ؟\"}, {\"original\": \"誰かが気を失いました。\", \"translated\": \"لقد إغمي على شخصٍ ما.\"}]', 8, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"私に、砂浜やプールサイドで使えるよく使う10のフレーズを教えていただけますか？\", \"素晴らしい！こちらに、砂浜やプールサイドに関するよく使う10のフレーズと、そのアラビア語訳を添えてお届けします：\"]', '[\"水泳\", \"日光浴\", \"ビーチスポーツ\"]', 'ja', '[\"今のところ、ご参加予定の現地のイベントやフェスティバル（例：文化祭、フードフェス、音楽フェスなど）について、その文脈を教えていただけますか？文脈をお知らせください。\", \"ご参加される活動内容を教えてください。\"]', '[\"ご希望の特定の状況がすでに頭に浮かんでいらっしゃいますか？何でも自由にお尋ねください。\", \"頭に浮かんでいる状況を詳しく教えてください。\"]', '[{\"original\": \"見て！あそこにある波は本当に大きいわ。\", \"translated\": \"انظر! الأمواج هناك كبيرة جدًّا.\"}, {\"original\": \"日焼け止めを塗ることを忘れないで。ここでの紫外線はとても強いわ。\", \"translated\": \"تذكَّر أن تضع واقيًا شمسيًّا؛ فأشعة فوق البنفسجية هنا قوية جدًّا.\"}, {\"original\": \"このビーチの砂は本当に細かくて、綿の上を歩いているみたいなの。\", \"translated\": \"الرمل على هذا الشاطئ ناعمٌ جدًّا لدرجة أنه يُشعِرك وكأنك تمشي على القطن.\"}, {\"original\": \"ビーチでバレーボールをしようか？\", \"translated\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\"}, {\"original\": \"遠くに見えるセーリングボートはとても美しいわ。\", \"translated\": \"القوارب الشراعية في الأفق تبدو جميلة جدًّا.\"}, {\"original\": \"ここでの水はとても透明で、魚まで見えちゃうわ。\", \"translated\": \"الماء هنا شفافٌ جدًّا لدرجة أنك تستطيع رؤية الأسماك بوضوح.\"}, {\"original\": \"貝殻を探しに行こうよ。\", \"translated\": \"هيا نذهب للبحث عن أصداف البحر.\"}, {\"original\": \"夕日が沈む頃にビーチを散歩するって、きっととてもロマンチックよね。\", \"translated\": \"التنزُّه على الشاطئ عند غروب الشمس لا بد أنه أمرٌ رومانسيٌّ جدًّا.\"}, {\"original\": \"ここで獲れるシーフードは新鮮だって聞いたわ。食べてみようよ。\", \"translated\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًّا؛ فلنجرِّب بعضها.\"}, {\"original\": \"潮が満ちてきてるわ。岸に向かいましょう。\", \"translated\": \"المدّ يرتفع الآن، لذا دعنا نتجه نحو اليابسة.\"}]', 9, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"現地のイベントや祭りで使える、10個のよく使う言い回しを教えていただけますか？\", \"素晴らしい！以下は、現地のイベントや祭りに関する10個のよく使う言い回しで、アラビア語での翻訳も付けています：\"]', '[\"イベントへの参加\", \"祭りの祝賀\", \"文化の学習\"]', 'ja', '[\"今のところ、ハロウィン、コンサート、友人とのパーティーなど、あなたが参加予定の現地のイベントや祭りについて、その文脈を教えていただけますか？文脈をお知らせください。\", \"あなたの頭の中にあるアクティビティを説明してください。\"]', '[\"具体的な状況が思い浮かんでいますか？自由にお尋ねください。\", \"あなたの頭の中にある状況を説明してください。\"]', '[{\"original\": \"今日は何かイベントがありますか？\", \"translated\": \"هل هناك أي فعاليات اليوم؟\"}, {\"original\": \"この祭りには何か特別なことがあるのですか？\", \"translated\": \"هل هناك شيءٌ خاصٌّ بخصوص هذه المهرجان؟\"}, {\"original\": \"お祝いはどこで行われますか？\", \"translated\": \"أين تُقام الاحتفالات؟\"}, {\"original\": \"チケットはどこで購入できますか？\", \"translated\": \"كيف يمكنني شراء التذاكر؟\"}, {\"original\": \"パフォーマンスはいつから始まりますか？\", \"translated\": \"في أي وقت تبدأ العروض؟\"}, {\"original\": \"どんな伝統的な食べ物がありますか？\", \"translated\": \"ما الأطعمة التقليدية المتاحة؟\"}, {\"original\": \"ここは本当ににぎやかですね。\", \"translated\": \"المكان نشيطٌ للغاية هنا.\"}, {\"original\": \"民俗活動はありますか？\", \"translated\": \"هل توجد أنشطة شعبية؟\"}, {\"original\": \"よい休日を！\", \"translated\": \"أعياد سعيدة!\"}, {\"original\": \"イベントはいつ終わりますか？\", \"translated\": \"متى تنتهي الفعالية؟\"}]', 10, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"私に、博物館や美術館で使える10個のよく使う表現を教えていただけますか？\", \"素晴らしい！こちらが博物館や美術館に関する10個のよく使う表現で、アラビア語訳も付いています：\"]', '[\"見学\", \"ガイド付きツアー\", \"チケット購入\"]', 'ja', '[\"今のところ、紹介用パンフレットの依頼、ルートマップに関連する表現、展示品への感想を述べる表現など、具体的な状況が頭に浮かびますか？いつでもご質問ください。\", \"頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"入館料はいくらですか？\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"オーディオガイドはありますか？\", \"translated\": \"هل توجد دلائل صوتية؟\"}, {\"original\": \"この作品は誰が制作しましたか？\", \"translated\": \"من هو فنان هذه القطعة الفنية؟\"}, {\"original\": \"美術館で最も貴重な作品はどこにありますか？\", \"translated\": \"أين تقع أثمن قطعة في المتاحف؟\"}, {\"original\": \"写真撮影は許可されていますか？\", \"translated\": \"هل يُسمح بالتقاط الصور الفوتوغرافية؟\"}, {\"original\": \"ここでは特別展は開催されていますか？\", \"translated\": \"هل تُنظم هنا معارض خاصة؟\"}, {\"original\": \"見学にはどれくらいの時間がかかりますか？\", \"translated\": \"كم من الوقت يستغرق الجولة؟\"}, {\"original\": \"ご紹介いただけますか？\", \"translated\": \"هل يمكنكم تقديم نبذة موجزة لنا؟\"}, {\"original\": \"これらの作品は本当に素晴らしく細かいです。\", \"translated\": \"هذه الأعمال رائعةٌ حقًّا ودقيقةٌ للغاية.\"}, {\"original\": \"お土産ショップはどこですか？\", \"translated\": \"أين تقع محلات بيع التذكارات؟\"}]', 11, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"カフェで使える10個のよく使うフレーズを教えてもらえますか？\", \"素晴らしい！こちらに、アラビア語訳付きでカフェ関連の10個のよく使うフレーズがあります：\"]', '[\"コーヒーを注文する\", \"休憩する\", \"交流する\"]', 'ja', '[\"今のところ、メニューを見せてもらうことや、アイス・ホットドリンク、その他の商品について尋ねるなど、具体的な状況が頭に浮かんでいますか？遠慮なく聞いてください。\", \"頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"ラテをいただきます。\", \"translated\": \"سأطلب لكابتشينو، من فضلك.\"}, {\"original\": \"Wi-Fiは使えますか？\", \"translated\": \"هل يوجد اتصال واي فاي متاح؟\"}, {\"original\": \"メニューを見せていただいてもよろしいですか？\", \"translated\": \"هل يمكنني رؤية القائمة، من فضلك؟\"}, {\"original\": \"リフィルはOKですか？\", \"translated\": \"هل يُسمح بإعادة الملء؟\"}, {\"original\": \"私のコーヒーはできましたか？\", \"translated\": \"هل جاهز قهوتي بالفعل؟\"}, {\"original\": \"ここにどのくらい座っていても大丈夫ですか？\", \"translated\": \"كم من الوقت يمكنني الجلوس هنا؟\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"هل يمكنك التقاط صورة لنا؟\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"أين الحمّام؟\"}, {\"original\": \"お会計をお願いします。ありがとう。\", \"translated\": \"الحساب، من فضلك. شكرًا لك.\"}, {\"original\": \"とても美味しいです！\", \"translated\": \"الطعام لذيذٌ جدًّا!\"}]', 12, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在餐厅使用的10个常用短语吗？\", \"太棒了！这里有10个关于餐厅的常用短语，附带阿拉伯语翻译：\"]', '[\"用餐\", \"点餐\", \"结账\"]', 'zh', '[\"目前，您心里有特定场景吗？比如点饮料、投诉，或询问食材成分？欢迎随时提问。\", \"请描述您心里想到的场景。\"]', '[]', '[{\"original\": \"打扰一下，我们的餐还要等多久？\", \"translated\": \"عذراً، كم من الوقت سيستغرق وصول طعامنا؟\"}, {\"original\": \"请给我们安排一张两人桌。\", \"translated\": \"من فضلكم، حجز طاولة لشخصين.\"}, {\"original\": \"请问可以看一下菜单吗？\", \"translated\": \"هل يمكننا الاطلاع على القائمة من فضلكم؟\"}, {\"original\": \"你们有什么招牌菜推荐吗？\", \"translated\": \"هل لديكم أي أطباق مميزة تُوصون بها؟\"}, {\"original\": \"我要点这个和这个。\", \"translated\": \"أود طلب هذا وهذا.\"}, {\"original\": \"请来一杯水，谢谢。\", \"translated\": \"من فضلكم كوب ماء، شكرًا.\"}, {\"original\": \"请结账。\", \"translated\": \"الحساب من فضلكم.\"}, {\"original\": \"我可以用信用卡付款吗？\", \"translated\": \"هل يمكنني الدفع بواسطة بطاقة الائتمان؟\"}, {\"original\": \"请帮我把这份打包带走，谢谢。\", \"translated\": \"من فضلكم اعبؤوا هذا لآخذه معي، شكرًا.\"}, {\"original\": \"食物很美味，谢谢！\", \"translated\": \"كان الطعام لذيذًا جدًّا، شكرًا لكم!\"}]', 1, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在酒店使用的10个常用短语吗？\", \"太棒了！这里有10个关于酒店的常用短语，附带阿拉伯语翻译：\"]', '[\"入住\", \"退房\", \"客房服务\"]', 'zh', '[\"目前，您心里有没有特定的情境需求？比如房间位置、其他酒店服务，或者退房相关事项？欢迎随时提问。\", \"请描述您心里想到的具体情境。\"]', '[]', '[{\"original\": \"你好，我有预订，这是我的护照。\", \"translated\": \"مرحبًا، لدي حجزٌ، وهذه جواز سفري.\"}, {\"original\": \"你们还有空房吗？\", \"translated\": \"هل لديكم غرف شاغرة؟\"}, {\"original\": \"打扰一下，酒店有健身房或洗衣房吗？\", \"translated\": \"عذرًا، هل يتوفر في الفندق صالة ألعاب رياضية أو غرفة لغسل الملابس؟\"}, {\"original\": \"早餐几点开始？\", \"translated\": \"متى تبدأ وجبة الإفطار؟\"}, {\"original\": \"请给我一把房卡，好吗？\", \"translated\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\"}, {\"original\": \"您能帮我把行李送到房间吗？\", \"translated\": \"هل يمكنك مساعدتي في حمل أمتعتي إلى الغرفة؟\"}, {\"original\": \"我怎么呼叫客房服务？\", \"translated\": \"كيف يمكنني الاتصال بخدمة الغرف؟\"}, {\"original\": \"退房时间是几点？\", \"translated\": \"في أي وقت يتم إنهاء إجراءات المغادرة؟\"}, {\"original\": \"您能给我开一张收据／发票吗？\", \"translated\": \"هل يمكنكم إصدار إيصال/فاتورة لي؟\"}, {\"original\": \"我可以把行李寄存在这里吗？\", \"translated\": \"هل يمكنني ترك أمتعتي هنا مؤقتًا؟\"}]', 2, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在机场使用的10个常用短语吗？\", \"太棒了！这里有10个关于机场的常用短语，附带阿拉伯语翻译：\"]', '[\"值机\", \"登机\", \"行李托运\"]', 'zh', '[\"目前，您心里有没有特定场景？比如值机、行李提取或租车服务，欢迎随时提问。\", \"请描述您心里想到的具体场景。\"]', '[]', '[{\"original\": \"值机柜台在哪里？\", \"translated\": \"أين مكان كاونتر تسجيل الدخول؟\"}, {\"original\": \"我想要一个靠窗的座位，谢谢。\", \"translated\": \"أود جلوسًا على مقعد بجانب النافذة، من فضلك.\"}, {\"original\": \"这趟航班延误了吗？\", \"translated\": \"هل تأخر هذا الرحلة الجوية؟\"}, {\"original\": \"我需要托运行李。\", \"translated\": \"أحتاج إلى فحص هذه الأمتعة للشحن.\"}, {\"original\": \"登机口在哪里？\", \"translated\": \"أين بوابة الصعود إلى الطائرة؟\"}, {\"original\": \"飞机即将起飞。\", \"translated\": \"الطائرة على وشك الإقلاع.\"}, {\"original\": \"我需要把笔记本电脑和充电宝拿出来吗？\", \"translated\": \"هل يجب أن أخرج جهازي اللوحي أو بنك الطاقة من الحقيبة؟\"}, {\"original\": \"免税店在哪里？\", \"translated\": \"أين متجر التحفيرات الخالية من الرسوم الجمركية؟\"}, {\"original\": \"我找不到我的行李箱了。\", \"translated\": \"لا أستطيع العثور على حقيبتي.\"}, {\"original\": \"你们提供轮椅服务吗？\", \"translated\": \"هل تقدمون خدمة الكرسي المتحرك؟\"}]', 3, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在公共交通工具使用的10个常用短语吗？\", \"太棒了！这里有10个关于公共交通工具的常用短语，附带阿拉伯语翻译：\"]', '[\"乘坐公交/地铁\", \"购买车票\", \"换乘\"]', 'zh', '[\"目前，您心里有没有特定的情境，比如问公交车站、票价或下车？欢迎随时提问。\", \"请描述您心里想到的情境。\"]', '[]', '[{\"original\": \"这趟公交车去终点站吗？\", \"translated\": \"هل هذه الحافلة تتجه إلى المحطة النهائية؟\"}, {\"original\": \"下一站是哪儿？\", \"translated\": \"ما هي المحطة التالية؟\"}, {\"original\": \"我在哪儿可以买票？\", \"translated\": \"أين يمكنني شراء التذكرة؟\"}, {\"original\": \"请给我一张去XX的票。\", \"translated\": \"من فضلك، أعطني تذكرة واحدة إلى XX.\"}, {\"original\": \"我需要换乘吗？\", \"translated\": \"هل عليّ التحويل إلى وسيلة نقل أخرى؟\"}, {\"original\": \"下一班地铁列车还有多久？\", \"translated\": \"كم يبقى من الوقت حتى قطار المترو القادم؟\"}, {\"original\": \"不好意思，请让我过去一下。\", \"translated\": \"عفوًا، من فضلك اسمح لي بالمرور.\"}, {\"original\": \"这个座位有人吗？\", \"translated\": \"هل هذا المقعد محجوزٌ؟\"}, {\"original\": \"打扰一下，我去XX坐2号线该在哪儿换乘？\", \"translated\": \"عفوًا، أين يمكنني التحويل إلى الخط ٢ للوصول إلى XX؟\"}, {\"original\": \"我怎么去XX？\", \"translated\": \"كيف أصل إلى XX؟\"}]', 4, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在旅游景点使用的10个常用短语吗？\", \"太棒了！这里有10个关于旅游景点的常用短语，附带阿拉伯语翻译：\"]', '[\"观光游览\", \"拍照留念\", \"购买门票\"]', 'zh', '[\"目前，您心里有没有特定场景？比如询问门票价格、查找停车场，或导游服务——欢迎随时提问。\", \"请描述您心里想到的具体场景。\"]', '[]', '[{\"original\": \"入场费多少钱？\", \"translated\": \"كم تكلفة رسوم الدخول؟\"}, {\"original\": \"有学生票吗？\", \"translated\": \"هل تتوفر تذاكر للطلاب؟\"}, {\"original\": \"景点几点开放？\", \"translated\": \"متى يفتح الموقع السياحي؟\"}, {\"original\": \"这里有哪些好玩的活动？\", \"translated\": \"ما الأنشطة الممتعة المتاحة هنا؟\"}, {\"original\": \"您能帮我们拍张照片吗？\", \"translated\": \"هل يمكنك أن تلتقط لنا صورة؟\"}, {\"original\": \"观光巴士在哪儿？\", \"translated\": \"أين حافلة الجولات السياحية؟\"}, {\"original\": \"洗手间在哪儿？\", \"translated\": \"أين دورات المياه؟\"}, {\"original\": \"最佳观景位置在哪儿？\", \"translated\": \"ما أحسن مكان للاستمتاع بالمنظر؟\"}, {\"original\": \"这里的风景真美。\", \"translated\": \"المنظر هنا جميلٌ جدًّا.\"}, {\"original\": \"提供导游服务吗？\", \"translated\": \"هل تتوفر خدمة دليل سياحي؟\"}]', 5, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在出租车或出租车服务使用的10个常用短语吗？\", \"太棒了！这里有10个关于出租车或出租车服务的常用短语，附带阿拉伯语翻译：\"]', '[\"打车\", \"告知目的地\", \"支付\"]', 'zh', '[\"目前，您最想做什么？比如询问目的地、费用，或索要发票——尽管提问吧。\", \"请在脑海中描述一下您的场景。\"]', '[]', '[{\"original\": \"我在哪里可以打到出租车？\", \"translated\": \"أين يمكنني أن أستقل تاكسي؟\"}, {\"original\": \"请送我去这个地址。\", \"translated\": \"من فضلك خذني إلى هذا العنوان.\"}, {\"original\": \"大概需要多少钱？\", \"translated\": \"كم سيكلفني ذلك تقريبًا؟\"}, {\"original\": \"请您打表计费，好吗？\", \"translated\": \"هل يمكنك تشغيل العداد، من فضلك؟\"}, {\"original\": \"请开快一点，我赶时间。\", \"translated\": \"من فضلك ا-driving أسرع قليلًا، فأنا مسرع.\"}, {\"original\": \"请在这里停车。\", \"translated\": \"من فضلك توقف هنا.\"}, {\"original\": \"您接受银行卡或手机支付吗？\", \"translated\": \"هل تقبل الدفع بالبطاقات أو المدفوعات عبر الهاتف المحمول؟\"}, {\"original\": \"可以给我一张收据吗？\", \"translated\": \"هل يمكنني الحصول على إيصال، من فضلك؟\"}, {\"original\": \"谢谢，司机师傅。\", \"translated\": \"شكرًا لك يا سائق.\"}, {\"original\": \"还有多远？\", \"translated\": \"كم تبقى بعد من الطريق؟\"}]', 6, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在药店使用的10个常用短语吗？\", \"太棒了！这里有10个关于药店的常用短语，附带阿拉伯语翻译：\"]', '[\"购买药品\", \"咨询\", \"支付\"]', 'zh', '[\"目前，您心里有没有特定的情境？比如询问服药说明、使用医保相关表达、用药时长等，欢迎随时提问。\", \"请描述您心里想到的情境。\"]', '[]', '[{\"original\": \"你们有治感冒的药吗？\", \"translated\": \"هل لديكم أدوية لعلاج نزلات البرد؟\"}, {\"original\": \"这个药我该怎么服用？\", \"translated\": \"كيف يجب أن آخذ هذا الدواء؟\"}, {\"original\": \"你们有止痛药吗？\", \"translated\": \"هل لديكم مسكنات للألم؟\"}, {\"original\": \"药品有说明书吗？\", \"translated\": \"هل يرفق مع هذا الدواء نشرة توضيحية؟\"}, {\"original\": \"这种药有什么副作用吗？\", \"translated\": \"هل لهذا الدواء أي آثار جانبية؟\"}, {\"original\": \"我能用医保卡付款吗？\", \"translated\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\"}, {\"original\": \"请给我一盒创可贴，谢谢。\", \"translated\": \"هل يمكنني الحصول على علبة من الشريط الطبي (البلاستر)، من فضلكم؟\"}, {\"original\": \"你们有退烧药吗？\", \"translated\": \"هل لديكم أدوية خافضة للحرارة؟\"}, {\"original\": \"我有点擦伤，你们有消毒液和创可贴吗？\", \"translated\": \"لديّ خدش بسيط، هل لديكم محلول مطهر وشريط طبي (بلاستر)؟\"}, {\"original\": \"你们几点关门？\", \"translated\": \"في أي وقت تغلقون المتجر؟\"}]', 7, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在紧急服务使用的10个常用短语吗？\", \"太棒了！这里有10个关于紧急服务的常用短语，附带阿拉伯语翻译：\"]', '[\"报警\", \"急救\", \"求助\"]', 'zh', '[\"目前，您心里是否有特定的紧急情况，比如火灾、受伤需要帮助、紧急呼叫？欢迎随时提问。\", \"请描述您心里想到的情况。\"]', '[]', '[{\"original\": \"请帮我叫一辆救护车。\", \"translated\": \"من فضلك ساعدني في استدعاء سيارة إسعاف.\"}, {\"original\": \"医院在哪儿？\", \"translated\": \"أين находится المستشفى؟\"}, {\"original\": \"有人受伤了。\", \"translated\": \"شخص ما أُصيب.\"}, {\"original\": \"请帮帮我。\", \"translated\": \"من فضلك ساعدني.\"}, {\"original\": \"警察局在哪儿？\", \"translated\": \"أين مركز الشرطة؟\"}, {\"original\": \"我的物品丢了。\", \"translated\": \"لقد فقدت أ possessionati.\"}, {\"original\": \"消防部门的电话号码是多少？\", \"translated\": \"ما هو رقم هاتف إدارة الإطفاء؟\"}, {\"original\": \"我丢了护照。你知道最近的警察局在哪儿吗？\", \"translated\": \"لقد فقدت جواز سفري. هل تعرف أين يقع أقرب مركز شرطة؟\"}, {\"original\": \"这里有安全出口吗？\", \"translated\": \"هل يوجد مخرج طوارئ هنا؟\"}, {\"original\": \"有人昏倒了。\", \"translated\": \"شخص ما فقد وعيه.\"}]', 8, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在沙滩或池畔使用的10个常用短语吗？\", \"太棒了！这里有10个关于沙滩或池畔的常用短语，附带阿拉伯语翻译：\"]', '[\"游泳\", \"日光浴\", \"沙滩运动\"]', 'zh', '[\"目前，您能告诉我您要参加的当地活动或节日的具体背景吗？比如文化节日、美食节或音乐节。请提供相关背景。\", \"请提供您将参加的具体活动。\"]', '[\"您心里有没有特定的情境？欢迎随时提问。\", \"请描述一下您心中设想的情境。\"]', '[{\"original\": \"看！那边的海浪真大。\", \"translated\": \"انظر! الأمواج هناك كبيرة جدًّا.\"}, {\"original\": \"记得涂防晒霜，这里的紫外线很强。\", \"translated\": \"تذكَّر أن تضع واقٍ شمسيًّا، فأشعة فوق البنفسجية هنا قوية جدًّا.\"}, {\"original\": \"这个海滩的沙子非常细腻，踩上去像踩在棉花上。\", \"translated\": \"رمل هذا الشاطئ ناعم جدًّا، وكأنك تمشي على القطن.\"}, {\"original\": \"在沙滩上打排球怎么样？\", \"translated\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\"}, {\"original\": \"远处的帆船看起来真美。\", \"translated\": \"القوارب الشراعية في الأفق تبدو جميلة جدًّا.\"}, {\"original\": \"这里的海水特别清澈，甚至能看见鱼。\", \"translated\": \"الماء هنا شفاف جدًّا لدرجة أنك تستطيع رؤية الأسماك.\"}, {\"original\": \"咱们去找些贝壳吧。\", \"translated\": \"هيا نبحث معًا عن بعض المحار والقواقع.\"}, {\"original\": \"在日落时分沿着海滩散步一定很浪漫。\", \"translated\": \"التنزُّه على طول الشاطئ عند غروب الشمس لا بد أنه أمرٌ رومانسيٌّ جدًّا.\"}, {\"original\": \"我听说这里的海鲜特别新鲜，咱们去尝尝吧。\", \"translated\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًّا، فلنجرِّبها معًا.\"}, {\"original\": \"涨潮了，咱们往岸边走吧。\", \"translated\": \"المسطح المائي يرتفع (المد قادم)، فلنعد إلى الساحل.\"}]', 9, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在当地活动和节日使用的10个常用短语吗？\", \"太棒了！这里有10个关于当地活动和节日的常用短语，附带阿拉伯语翻译：\"]', '[\"参加活动\", \"庆祝节日\", \"了解文化\"]', 'zh', '[\"目前，您能告诉我您要参加的当地活动或节日的具体情境吗？比如万圣节、音乐会、朋友聚会，或者其他场合？请提供具体情境。\", \"请描述一下您脑海中设想的活动。\"]', '[\"您心中是否有特定的情境？欢迎随时提问。\", \"请描述一下您脑海中设想的情境。\"]', '[{\"original\": \"今天有什么活动吗？\", \"translated\": \"هل هناك أي فعاليات اليوم؟\"}, {\"original\": \"这个节日有什么特别之处吗？\", \"translated\": \"هل هناك شيءٌ مميزٌ حول هذه المهرجان؟\"}, {\"original\": \"庆祝活动在哪里举行？\", \"translated\": \"أين تُقام الاحتفالات؟\"}, {\"original\": \"我该怎么买票？\", \"translated\": \"كيف يمكنني شراء التذاكر؟\"}, {\"original\": \"演出什么时候开始？\", \"translated\": \"متى يبدأ العرض؟\"}, {\"original\": \"有哪些传统食物？\", \"translated\": \"ما الأطعمة التقليدية المتاحة؟\"}, {\"original\": \"这里真热闹！\", \"translated\": \"المكان نابضٌ بالحياة حقًّا!\"}, {\"original\": \"有民俗活动吗？\", \"translated\": \"هل هناك أنشطة تراثية شعبية؟\"}, {\"original\": \"节日快乐！\", \"translated\": \"عيد سعيد!\"}, {\"original\": \"活动什么时候结束？\", \"translated\": \"متى تنتهي الفعالية؟\"}]', 10, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在博物馆或美术馆使用的10个常用短语吗？\", \"太棒了！这里有10个关于博物馆或美术馆的常用短语，附带阿拉伯语翻译：\"]', '[\"参观\", \"导览服务\", \"购票\"]', 'zh', '[\"目前，您心里有没有特定场景？比如索要导览手册、与参观路线相关的表达、对展品发表评论的相关用语——欢迎随时提问。\", \"请描述一下您心中想到的场景。\"]', '[]', '[{\"original\": \"门票多少钱？\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"你们提供语音导览吗？\", \"translated\": \"هل لديكم أجهزة توجيه صوتيّة؟\"}, {\"original\": \"这幅作品是谁创作的？\", \"translated\": \"من هو الفنان الذي أنشأ هذه القطعة الفنّية؟\"}, {\"original\": \"博物馆最珍贵的藏品在哪儿？\", \"translated\": \"أين تقع أثمن قطعة في المتحف؟\"}, {\"original\": \"可以拍照吗？\", \"translated\": \"هل يسمح بالتقاط الصور؟\"}, {\"original\": \"这里有没有特别展览？\", \"translated\": \"هل توجد هنا معارض خاصة؟\"}, {\"original\": \"参观大约需要多长时间？\", \"translated\": \"كم تستغرق الزيارة تقريبًا؟\"}, {\"original\": \"您能为我们简单介绍一下吗？\", \"translated\": \"هل يمكنكم إعطاؤنا مقدمةً موجزةً؟\"}, {\"original\": \"这些作品真是精美极了。\", \"translated\": \"هذه الأعمال فنيّةٌ رائعةٌ حقًّا.\"}, {\"original\": \"纪念品商店在哪儿？\", \"translated\": \"أين تقع متجر الهدايا التذكارية؟\"}]', 11, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在咖啡馆使用的10个常用短语吗？\", \"太棒了！这里有10个关于咖啡馆的常用短语，附带阿拉伯语翻译：\"]', '[\"点咖啡\", \"休息\", \"社交\"]', 'zh', '[\"目前，您心里有特定场景吗？比如要菜单、点冰饮或热饮、其他产品等——欢迎随时提问。\", \"请描述您心里想的场景。\"]', '[]', '[{\"original\": \"请给我一杯拿铁。\", \"translated\": \"أُريد لاتيه، من فضلك.\"}, {\"original\": \"你们有Wi-Fi吗？\", \"translated\": \"هل لديكم اتصال واي فاي؟\"}, {\"original\": \"请给我看一下菜单，谢谢。\", \"translated\": \"هل يمكنني رؤية القائمة من فضلكم؟\"}, {\"original\": \"可以续杯吗？\", \"translated\": \"هل يُسمح بإعادة تعبئة الكوب؟\"}, {\"original\": \"我的咖啡好了吗？\", \"translated\": \"هل انتهت تحضير قهوتي بعد؟\"}, {\"original\": \"我可以在这里坐多久？\", \"translated\": \"كم من الوقت يُسمح لي بالجلوس هنا؟\"}, {\"original\": \"您能帮我们拍张照吗？\", \"translated\": \"هل يمكنك أخذ صورةٍ لنا من فضلك؟\"}, {\"original\": \"洗手间在哪里？\", \"translated\": \"أين الحمام؟\"}, {\"original\": \"请结账，谢谢。\", \"translated\": \"الحساب من فضلكم، شكرًا.\"}, {\"original\": \"味道真的很好。\", \"translated\": \"الطَّعم لذيذٌ جدًّا.\"}]', 12, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"あなたがレストランで使える定番の10フレーズをご紹介しましょうか？\", \"素晴らしい！こちらに、レストランでよく使う10の定番フレーズ（フランス語訳付き）をご用意しました：\"]', '[\"食事\", \"注文\", \"会計\"]', 'ja', '[\"今のところ、ドリンクの注文、クレームの申し立て、食材の確認など、何か特定の状況をお考えですか？どうぞ自由にお尋ねください。\", \"その状況について、詳しくお聞かせください。\"]', '[]', '[{\"original\": \"すみません、私たちの料理はあとどのくらいで来ますか？\", \"translated\": \"Excusez-moi, combien de temps encore avant que notre commande ne soit prête ?\"}, {\"original\": \"2名用のテーブルをお願いします。\", \"translated\": \"Une table pour deux, s’il vous plaît.\"}, {\"original\": \"メニューを見せていただいてもよろしいですか？\", \"translated\": \"Pourrions-nous voir la carte, s’il vous plaît ?\"}, {\"original\": \"おすすめの看板料理はありますか？\", \"translated\": \"Avez-vous des plats signature à nous recommander ?\"}, {\"original\": \"こちらと、こちらを注文したいと思います。\", \"translated\": \"Je voudrais commander ceci et cela.\"}, {\"original\": \"水を1杯お願いします。ありがとうございます。\", \"translated\": \"Un verre d’eau, s’il vous plaît. Merci.\"}, {\"original\": \"お会計をお願いします。\", \"translated\": \"L’addition, s’il vous plaît.\"}, {\"original\": \"クレジットカードで支払えますか？\", \"translated\": \"Puis-je payer par carte bancaire ?\"}, {\"original\": \"これをテイクアウトでお願いできますか？\", \"translated\": \"Pourriez-vous emballer cela à emporter, s’il vous plaît ?\"}, {\"original\": \"料理がとても美味しかったです。ありがとうございました。\", \"translated\": \"Le repas était délicieux, merci beaucoup.\"}]', 1, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ホテルで使える10個のよく使う表現を教えていただけますか？\", \"素晴らしい！ホテル関連のよく使う表現10個を、フランス語訳付きでお届けします：\"]', '[\"チェックイン\", \"チェックアウト\", \"ルームサービス\"]', 'ja', '[\"今のところ、お部屋の位置やその他のホテルサービス、チェックアウトなど、何か具体的なシチュエーションをお考えですか？ 何でもお気軽にお尋ねください。\", \"頭の中にあるシチュエーションを教えてください。\"]', '[]', '[{\"original\": \"こんにちは。予約しています。こちらが私のパスポートです。\", \"translated\": \"Bonjour, j’ai une réservation. Voici mon passeport.\"}, {\"original\": \"空室はありますか？\", \"translated\": \"Avez-vous des chambres disponibles ?\"}, {\"original\": \"すみません、ホテルにジムやランドリールームはありますか？\", \"translated\": \"Excusez-moi, l’hôtel dispose-t-il d’une salle de sport ou d’un service de blanchisserie ?\"}, {\"original\": \"朝食は何時からですか？\", \"translated\": \"À quelle heure commence le petit-déjeuner ?\"}, {\"original\": \"部屋の鍵をいただけますか？\", \"translated\": \"Pourrais-je avoir la clé de ma chambre, s’il vous plaît ?\"}, {\"original\": \"荷物を部屋まで運んでいただけますか？\", \"translated\": \"Pourriez-vous m’aider à porter mes bagages jusqu’à ma chambre ?\"}, {\"original\": \"ルームサービスの電話のかけ方は？\", \"translated\": \"Comment puis-je appeler le service en chambre ?\"}, {\"original\": \"チェックアウトは何時ですか？\", \"translated\": \"À quelle heure est le départ ?\"}, {\"original\": \"領収書／請求書を書いていただけますか？\", \"translated\": \"Pourriez-vous me remettre un reçu / une facture ?\"}, {\"original\": \"荷物をここに預けても大丈夫ですか？\", \"translated\": \"Puis-je laisser mes bagages ici ?\"}]', 2, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"空港で使える10個のよく使うフレーズを教えていただけますか？\", \"素晴らしい！こちらに、空港での場面に合わせた10個のよく使うフレーズと、フランス語訳を載せました：\"]', '[\"チェックイン\", \"搭乗\", \"手荷物預け\"]', 'ja', '[\"今のところ、チェックイン、手荷物受取、レンタカーなどのご希望のシーンがありますか？いつでもお気軽にお尋ねください。\", \"あなたの頭の中にあるシーンを教えてください。\"]', '[]', '[{\"original\": \"チェックインカウンターはどこですか？\", \"translated\": \"Où se trouve le comptoir d\'enregistrement ?\"}, {\"original\": \"窓際の席をお願いします。\", \"translated\": \"Je voudrais un siège près du hublot, s\'il vous plaît.\"}, {\"original\": \"この便は遅れていますか？\", \"translated\": \"Ce vol est-il retardé ?\"}, {\"original\": \"この荷物を預けたいのですが。\", \"translated\": \"Je voudrais enregistrer ce bagage.\"}, {\"original\": \"搭乗口はどこですか？\", \"translated\": \"Où se trouve la porte d\'embarquement ?\"}, {\"original\": \"飛行機が離陸しようとしています。\", \"translated\": \"L\'avion est sur le point de décoller.\"}, {\"original\": \"ノートパソコンとモバイルバッテリーを取り出さなければなりませんか？\", \"translated\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\"}, {\"original\": \"免税店はどこですか？\", \"translated\": \"Où se trouve la boutique hors taxes ?\"}, {\"original\": \"私のスーツケースが見つかりません。\", \"translated\": \"Je ne retrouve pas ma valise.\"}, {\"original\": \"車椅子サービスは利用できますか？\", \"translated\": \"Proposez-vous un service de chaise roulante ?\"}]', 3, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"公共交通機関で使える10個のよく使う表現を教えてもらえますか？\", \"素晴らしい！ここに、公共交通機関に関する10個のよく使う表現と、そのフランス語訳があります：\"]', '[\"バス・地下鉄を利用する\", \"切符を購入する\", \"乗り換える\"]', 'ja', '[\"今のところ、バス停の確認や切符の値段、降車などの具体的な状況について考えていますか？遠慮なく聞いてください。\", \"頭の中で思い浮かんでいる状況を教えてください。\"]', '[]', '[{\"original\": \"このバスは終点へ行きますか？\", \"translated\": \"Ce bus va-t-il jusqu\'à la gare routière ?\"}, {\"original\": \"次の停留所はどこですか？\", \"translated\": \"Quel est le prochain arrêt ?\"}, {\"original\": \"切符はどこで買えますか？\", \"translated\": \"Où puis-je acheter un billet ?\"}, {\"original\": \"XX行きの切符を1枚お願いします。\", \"translated\": \"Un billet pour XX, s\'il vous plaît.\"}, {\"original\": \"乗り換えが必要ですか？\", \"translated\": \"Dois-je changer de ligne ?\"}, {\"original\": \"次の地下鉄の列車まであと何分ですか？\", \"translated\": \"Dans combien de temps arrive le prochain train de métro ?\"}, {\"original\": \"すみません、通らせていただけますか？\", \"translated\": \"Excusez-moi, je peux passer ?\"}, {\"original\": \"この席は空いていますか？\", \"translated\": \"Cette place est-elle libre ?\"}, {\"original\": \"すみません、XXへ行くために2号線への乗り換えはどこでできますか？\", \"translated\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d\'aller à XX ?\"}, {\"original\": \"XXへはどう行けばいいですか？\", \"translated\": \"Comment puis-je me rendre à XX ?\"}]', 4, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"あなたが観光地で使える10個のよく使うフレーズを教えてもらえますか？\", \"素晴らしい！観光地で使える10個のよく使うフレーズを、フランス語訳つきでご紹介します：\"]', '[\"観光\", \"写真撮影\", \"チケット購入\"]', 'ja', '[\"今のところ、入場料を尋ねる、駐車場を探す、ガイドサービスを頼むなど、具体的な状況をお考えですか？遠慮なくどうぞ。\", \"あなたの頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"入場料はいくらですか？\", \"translated\": \"Combien coûte l\'entrée ?\"}, {\"original\": \"学生向けの割引券はありますか？\", \"translated\": \"Y a-t-il des billets étudiants disponibles ?\"}, {\"original\": \"観光スポットの営業時間は何時からですか？\", \"translated\": \"À quelle heure ouvre l\'attraction ?\"}, {\"original\": \"ここですべき楽しいことは何ですか？\", \"translated\": \"Quelles sont les activités amusantes à faire ici ?\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"観光バスはどこにいますか？\", \"translated\": \"Où se trouve le bus touristique ?\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"一番よい展望スポットはどこですか？\", \"translated\": \"Où est le meilleur point de vue ?\"}, {\"original\": \"ここからの景色は本当に美しいですね。\", \"translated\": \"Le paysage est magnifique ici.\"}, {\"original\": \"ガイド付きツアーはありますか？\", \"translated\": \"Une visite guidée est-elle disponible ?\"}]', 5, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"あなたがタクシーや配車サービスで使える10個のよく使う表現を教えてもらえますか？\", \"素晴らしい！以下は、タクシーまたは配車サービスに関する10個のよく使う表現で、フランス語訳もついています：\"]', '[\"タクシーを利用する\", \"行き先を伝える\", \"支払いに関するやりとり\"]', 'ja', '[\"今のところ、目的地を尋ねたり、料金を確認したり、領収書を頼んだり——何でも気軽に聞いてください。\", \"頭の中で思い浮かべている状況を教えてください。\"]', '[]', '[{\"original\": \"タクシーはどこで乗れますか？\", \"translated\": \"Où puis-je prendre un taxi ?\"}, {\"original\": \"この住所までお願いします。\", \"translated\": \"Veuillez me conduire à cette adresse.\"}, {\"original\": \"だいたいいくらぐらいになりますか？\", \"translated\": \"Combien cela coûtera-t-il approximativement ?\"}, {\"original\": \"メーターを使っていただけますか？\", \"translated\": \"Pourriez-vous utiliser le compteur, s\'il vous plaît ?\"}, {\"original\": \"急いでいるので、もう少し速く運転してもらえますか？\", \"translated\": \"Je suis pressé(e), pourriez-vous conduire un peu plus vite, s\'il vous plaît ?\"}, {\"original\": \"ここで止めてください。\", \"translated\": \"Veuillez vous arrêter ici.\"}, {\"original\": \"カードやモバイル決済は使えますか？\", \"translated\": \"Acceptez-vous les paiements par carte ou par mobile ?\"}, {\"original\": \"領収書をいただいてもよろしいですか？\", \"translated\": \"Pourrais-je avoir un reçu, s\'il vous plaît ?\"}, {\"original\": \"ありがとう、ドライバーさん。\", \"translated\": \"Merci, monsieur/madame le chauffeur.\"}, {\"original\": \"あとどのくらいですか？\", \"translated\": \"Il reste encore combien de temps ?\"}]', 6, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"药店で使える10個のよく使う表現を教えていただけますか？\", \"素晴らしい！以下は、薬局関連の10個のよく使う表現で、フランス語訳も付いています：\"]', '[\"薬の購入\", \"相談\", \"支払い\"]', 'ja', '[\"今のところ、例えば「薬の飲み方を尋ねる」「保険の使い方について聞く」「服用期間を確認する」など、具体的な状況が思い浮かびますか？どんどんお気軽に聞いてください。\", \"頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"風邪薬はありますか？\", \"translated\": \"Avez-vous des médicaments contre le rhume ?\"}, {\"original\": \"この薬の飲み方はどうすればいいですか？\", \"translated\": \"Comment dois-je prendre ce médicament ?\"}, {\"original\": \"鎮痛剤はありますか？\", \"translated\": \"Avez-vous des analgésiques ?\"}, {\"original\": \"説明書はついていますか？\", \"translated\": \"Y a-t-il une notice d’utilisation ?\"}, {\"original\": \"この薬には副作用がありますか？\", \"translated\": \"Ce médicament a-t-il des effets secondaires ?\"}, {\"original\": \"医療保険証は使えますか？\", \"translated\": \"Puis-je utiliser ma carte d’assurance maladie ?\"}, {\"original\": \"絆創膏を1箱お願いできますか？\", \"translated\": \"Pourriez-vous me donner une boîte de pansements, s’il vous plaît ?\"}, {\"original\": \"解熱剤はありますか？\", \"translated\": \"Avez-vous des antipyrétiques ?\"}, {\"original\": \"ちょっと擦り傷をしたんですが、消毒液と絆創膏はありますか？\", \"translated\": \"Je me suis un peu écorché(e). Avez-vous un antiseptique et des pansements ?\"}, {\"original\": \"何時まで営業していますか？\", \"translated\": \"À quelle heure fermez-vous ?\"}]', 7, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"緊急サービスで使える10個のよく使うフレーズを教えていただけますか？\", \"素晴らしいです！緊急サービスに関する10個のよく使うフレーズを、フランス語訳付きでご紹介します：\"]', '[\"警察に連絡する\", \"応急処置\", \"助けを求める\"]', 'ja', '[\"今のところ、火事、怪我をして助けが必要、緊急通報など、特定の緊急状況をお考えですか？遠慮なくご質問ください。\", \"頭の中で思い浮かぶ状況を教えてください。\"]', '[]', '[{\"original\": \"救急車を呼んでください。\", \"translated\": \"Veuillez appeler une ambulance.\"}, {\"original\": \"病院はどこですか？\", \"translated\": \"Où se trouve l\'hôpital ?\"}, {\"original\": \"誰かが怪我をしました。\", \"translated\": \"Quelqu’un est blessé.\"}, {\"original\": \"助けてください。\", \"translated\": \"Au secours !\"}, {\"original\": \"警察署はどこですか？\", \"translated\": \"Où se trouve le poste de police ?\"}, {\"original\": \"持ち物をなくしてしまいました。\", \"translated\": \"J’ai perdu mes affaires.\"}, {\"original\": \"消防署の電話番号は何番ですか？\", \"translated\": \"Quel est le numéro d’urgence pour les pompiers ?\"}, {\"original\": \"パスポートを紛失しました。近くの警察署はどこですか？\", \"translated\": \"J’ai perdu mon passeport. Savez-vous où se trouve le poste de police le plus proche ?\"}, {\"original\": \"非常口はどこですか？\", \"translated\": \"Où est la sortie de secours ?\"}, {\"original\": \"誰かが気を失いました。\", \"translated\": \"Quelqu’un s’est évanoui.\"}]', 8, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"私に、ビーチやプールサイドで使える10個のよく使うフレーズを教えていただけますか？\", \"素晴らしい！ビーチやプールサイドに関する10個のよく使うフレーズを、フランス語訳とともにご紹介します：\"]', '[\"泳ぐ\", \"日光浴\", \"ビーチスポーツ\"]', 'ja', '[\"まず、あなたが参加予定の現地のイベントやお祭りについて、文化祭、フードフェスティバル、音楽フェスティバルなどの文脈をお知らせいただけますか？\", \"あなたが参加するアクティビティを教えてください。\"]', '[\"特に思い浮かぶシチュエーションはありますか？遠慮なくお尋ねください。\", \"あなたの頭の中にある状況を教えてください。\"]', '[{\"original\": \"見て！あそこにある波は本当に大きいわ。\", \"translated\": \"Regardez ! Les vagues là-bas sont vraiment énormes.\"}, {\"original\": \"日焼け止めを塗ることを忘れないでね。ここでの紫外線はとても強いから。\", \"translated\": \"N\'oubliez pas d\'appliquer de la crème solaire : les rayons UV sont très forts ici.\"}, {\"original\": \"このビーチの砂はとても細かくて、綿の上を歩いているような感触なの。\", \"translated\": \"Le sable de cette plage est si fin qu’on a l’impression de marcher sur du coton.\"}, {\"original\": \"ビーチでバレーボールをするのはどう？\", \"translated\": \"Et si on jouait au volley-ball sur la plage ?\"}, {\"original\": \"遠くに見えるセーリングボートがとてもきれいね。\", \"translated\": \"Les voiliers au loin sont magnifiques.\"}, {\"original\": \"ここでの水はとても澄んでいて、魚まで見えるのよ。\", \"translated\": \"L’eau ici est tellement claire qu’on peut même voir les poissons.\"}, {\"original\": \"一緒に貝殻を探しに行こう！\", \"translated\": \"Allons chercher des coquillages ensemble !\"}, {\"original\": \"夕日に染まるビーチを散歩するのは、きっととてもロマンチックね。\", \"translated\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\"}, {\"original\": \"ここではシーフードがとても新鮮だって聞いたから、ぜひ食べてみよう！\", \"translated\": \"J’ai entendu dire que les fruits de mer sont très frais ici, allons-en déguster !\"}, {\"original\": \"潮が満ちてきてるわ。そろそろ岸に向かいましょう。\", \"translated\": \"La marée monte, revenons vers la rive.\"}]', 9, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"地元のイベントや祭りで使える10個のよく使うフレーズを教えていただけますか？\", \"素晴らしい！こちらに、地元のイベントや祭りに関する10個のよく使うフレーズと、フランス語訳を添えてお届けします：\"]', '[\"イベントへの参加\", \"祭りの祝い\", \"文化の学習\"]', 'ja', '[\"今のところ、ハロウィン、コンサート、友達とのパーティなど、あなたが参加予定の地元のイベントや祭りの状況について教えていただけますか？状況を教えてください。\", \"あなたの頭にある活動を教えてください。\"]', '[\"具体的な状況を思い浮かべていますか？何でも気軽に聞いてください。\", \"あなたの頭にある状況を教えてください。\"]', '[{\"original\": \"今日は何かイベントがありますか？\", \"translated\": \"Y a-t-il des événements aujourd\'hui ?\"}, {\"original\": \"この祭りには何か特別な点がありますか？\", \"translated\": \"Y a-t-il quelque chose de particulier à propos de ce festival ?\"}, {\"original\": \"お祝いはどこで行われますか？\", \"translated\": \"Où se déroule la célébration ?\"}, {\"original\": \"チケットはどこで購入できますか？\", \"translated\": \"Comment puis-je acheter des billets ?\"}, {\"original\": \"パフォーマンスは何時から始まりますか？\", \"translated\": \"À quelle heure commence la représentation ?\"}, {\"original\": \"どんな伝統的な食べ物がありますか？\", \"translated\": \"Quels plats traditionnels sont proposés ?\"}, {\"original\": \"ここは本当ににぎやかですね。\", \"translated\": \"C\'est vraiment animé ici !\"}, {\"original\": \"民俗行事はありますか？\", \"translated\": \"Y a-t-il des activités folkloriques ?\"}, {\"original\": \"楽しい休日を！\", \"translated\": \"Joyeuses fêtes !\"}, {\"original\": \"イベントはいつ終わりますか？\", \"translated\": \"À quelle heure se termine l\'événement ?\"}]', 10, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"私に、博物館や美術館で使える10個の日常的に使われる短語を教えていただけますか？\", \"素晴らしい！こちらに、博物館や美術館に関する10個のよく使う短語と、それに付随するフランス語訳をご紹介します：\"]', '[\"見学\", \"ガイド付きツアー\", \"チケットの購入\"]', 'ja', '[\"今のところ、展示解説書の請求、ルート案内に関連する表現、展示作品に対する感想を述べる表現など、何か具体的な状況をお考えですか？ 何でもお気軽にお尋ねください。\", \"あなたの頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"入館料はいくらですか？\", \"translated\": \"Combien coûte l\'entrée ?\"}, {\"original\": \"オーディオガイドはありますか？\", \"translated\": \"Proposez-vous des audioguides ?\"}, {\"original\": \"この作品は誰が制作したのですか？\", \"translated\": \"Qui est l\'auteur de cette œuvre ?\"}, {\"original\": \"博物館・美術館で最も貴重な所蔵品はどこにありますか？\", \"translated\": \"Où se trouve la pièce la plus précieuse du musée ?\"}, {\"original\": \"写真撮影は許可されていますか？\", \"translated\": \"La prise de photographies est-elle autorisée ?\"}, {\"original\": \"現在、特別展は開催されていますか？\", \"translated\": \"Y a-t-il des expositions spéciales en cours ?\"}, {\"original\": \"見学にはどれくらい時間がかかりますか？\", \"translated\": \"Combien de temps dure la visite ?\"}, {\"original\": \"簡単にご紹介いただけますか？\", \"translated\": \"Pourriez-vous nous donner une brève présentation ?\"}, {\"original\": \"これらの作品は本当に見事です。\", \"translated\": \"Ces œuvres sont vraiment exquises.\"}, {\"original\": \"お土産ショップはどこですか？\", \"translated\": \"Où se trouve la boutique de souvenirs ?\"}]', 11, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"あなたがカフェで使える10個のよく使うフレーズを教えてもらえますか？\", \"素晴らしい！ここに、フランス語訳付きでカフェ関連の10個のよく使うフレーズがあります：\"]', '[\"コーヒーを注文する\", \"休憩する\", \"おしゃべりする\"]', 'ja', '[\"今のところ、メニューを見せてほしい、アイスかホットの飲み物を選ぶ、その他の商品について尋ねるなど、具体的な状況が思い浮かびますか？遠慮なくどうぞ。\", \"あなたの頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"ラテをいただきます。\", \"translated\": \"Je prendrai un latte, s’il vous plaît.\"}, {\"original\": \"Wi-Fiは使えますか？\", \"translated\": \"Est-ce que le Wi-Fi est disponible ?\"}, {\"original\": \"メニューを見せていただけますか？\", \"translated\": \"Pourriez-vous me montrer la carte, s’il vous plaît ?\"}, {\"original\": \"リフィルはできますか？\", \"translated\": \"Les recharges sont-elles autorisées ?\"}, {\"original\": \"私のコーヒーはできましたか？\", \"translated\": \"Mon café est-il prêt ?\"}, {\"original\": \"ここにどのくらい座っていても大丈夫ですか？\", \"translated\": \"Combien de temps puis-je rester assis ici ?\"}, {\"original\": \"私たちの写真を撮ってもらえますか？\", \"translated\": \"Pourriez-vous prendre une photo de nous ?\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"お勘定をお願いします。ありがとうございます。\", \"translated\": \"L’addition, s’il vous plaît. Merci.\"}, {\"original\": \"とても美味しいです。\", \"translated\": \"C’est vraiment délicieux !\"}]', 12, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在餐厅使用的10个常用短语吗？\", \"太棒了！这里有10个关于餐厅的常用短语，附带法语翻译：\"]', '[\"用餐\", \"点餐\", \"结账\"]', 'zh', '[\"目前，您心里有没有特定的情境，比如点饮料、投诉，或者询问食材成分？欢迎随时提问。\", \"请描述一下您心里想到的具体情境。\"]', '[]', '[{\"original\": \"打扰一下，我们的餐还要等多久？\", \"translated\": \"Excusez-moi, combien de temps encore avant que notre commande ne soit prête ?\"}, {\"original\": \"请给我们安排一张两人桌。\", \"translated\": \"Une table pour deux, s’il vous plaît.\"}, {\"original\": \"请问我们可以看一下菜单吗？\", \"translated\": \"Pourrions-nous voir la carte, s’il vous plaît ?\"}, {\"original\": \"你们有什么招牌菜可以推荐吗？\", \"translated\": \"Avez-vous des plats signature à nous recommander ?\"}, {\"original\": \"我要点这个和这个。\", \"translated\": \"Je voudrais commander ceci et cela.\"}, {\"original\": \"请给我一杯水，谢谢。\", \"translated\": \"Un verre d’eau, s’il vous plaît. Merci.\"}, {\"original\": \"请把账单拿来。\", \"translated\": \"L’addition, s’il vous plaît.\"}, {\"original\": \"我可以刷卡结账吗？\", \"translated\": \"Puis-je payer par carte bancaire ?\"}, {\"original\": \"麻烦帮我把这份打包带走。\", \"translated\": \"Pourriez-vous emballer cela à emporter, s’il vous plaît ?\"}, {\"original\": \"食物非常美味，谢谢！\", \"translated\": \"Le plat était délicieux, merci beaucoup !\"}]', 1, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在酒店使用的10个常用短语吗？\", \"太棒了！这里有10个关于酒店的常用短语，附带法语翻译：\"]', '[\"入住\", \"退房\", \"客房服务\"]', 'zh', '[\"目前，您心里有没有具体的情境？比如房间位置、其他酒店服务，或是退房相关问题？欢迎随时提问。\", \"请描述一下您心里想到的情境。\"]', '[]', '[{\"original\": \"你好，我有预订，这是我的护照。\", \"translated\": \"Bonjour, j’ai une réservation. Voici mon passeport.\"}, {\"original\": \"你们还有空房吗？\", \"translated\": \"Avez-vous encore des chambres disponibles ?\"}, {\"original\": \"不好意思，请问酒店有健身房或洗衣房吗？\", \"translated\": \"Excusez-moi, l’hôtel dispose-t-il d’une salle de sport ou d’une buanderie ?\"}, {\"original\": \"早餐几点开始？\", \"translated\": \"À quelle heure commence le petit-déjeuner ?\"}, {\"original\": \"请给我一把房卡，好吗？\", \"translated\": \"Pourriez-vous me donner la clé de ma chambre, s’il vous plaît ?\"}, {\"original\": \"您能帮我把行李送到房间吗？\", \"translated\": \"Pourriez-vous m’aider à porter mes bagages jusqu’à ma chambre ?\"}, {\"original\": \"我该怎么叫客房服务？\", \"translated\": \"Comment puis-je appeler le service d’étage ?\"}, {\"original\": \"退房时间是几点？\", \"translated\": \"À quelle heure est le départ (check-out) ?\"}, {\"original\": \"您能给我开一张收据／发票吗？\", \"translated\": \"Pourriez-vous me délivrer un reçu / une facture ?\"}, {\"original\": \"我可以把行李寄存在这里吗？\", \"translated\": \"Puis-je laisser mes bagages ici en consigne ?\"}]', 2, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在机场使用的10个常用短语吗？\", \"太棒了！这里有10个关于机场的常用短语，附带法语翻译：\"]', '[\"值机\", \"登机\", \"行李托运\"]', 'zh', '[\"目前，您心里有没有特别想了解的情景，比如值机、行李提取或租车服务？欢迎随时提问。\", \"请描述一下您心里想到的具体情景。\"]', '[]', '[{\"original\": \"值机柜台在哪里？\", \"translated\": \"Où se trouve le comptoir d\'enregistrement ?\"}, {\"original\": \"我想要一个靠窗的座位，谢谢。\", \"translated\": \"Je voudrais un siège près du hublot, s\'il vous plaît.\"}, {\"original\": \"这趟航班延误了吗？\", \"translated\": \"Ce vol est-il retardé ?\"}, {\"original\": \"我需要托运行这件行李。\", \"translated\": \"Je dois enregistrer ce bagage.\"}, {\"original\": \"登机口在哪里？\", \"translated\": \"Où se trouve la porte d\'embarquement ?\"}, {\"original\": \"飞机即将起飞。\", \"translated\": \"L\'avion va bientôt décoller.\"}, {\"original\": \"我需要把笔记本电脑和充电宝拿出来吗？\", \"translated\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\"}, {\"original\": \"免税店在哪里？\", \"translated\": \"Où se trouve la boutique duty-free ?\"}, {\"original\": \"我找不到我的行李箱了。\", \"translated\": \"Je ne retrouve pas ma valise.\"}, {\"original\": \"你们提供轮椅服务吗？\", \"translated\": \"Proposez-vous un service de fauteuil roulant ?\"}]', 3, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在公共交通工具使用的10个常用短语吗？\", \"太棒了！这里有10个关于公共交通工具的常用短语，附带法语翻译：\"]', '[\"乘坐公交车/地铁\", \"购买车票\", \"换乘\"]', 'zh', '[\"目前，您心里有特定场景吗？比如问公交站、票价或下车点——欢迎随时提问。\", \"请描述您心里想到的具体场景。\"]', '[]', '[{\"original\": \"这趟公交车去终点站吗？\", \"translated\": \"Ce bus va-t-il jusqu\'au terminus ?\"}, {\"original\": \"下一站是哪里？\", \"translated\": \"Quelle est la prochaine station ?\"}, {\"original\": \"我在哪儿可以买票？\", \"translated\": \"Où puis-je acheter un billet ?\"}, {\"original\": \"请给我一张去XX的车票。\", \"translated\": \"Un billet pour XX, s\'il vous plaît.\"}, {\"original\": \"我需要换乘吗？\", \"translated\": \"Dois-je changer de transport ?\"}, {\"original\": \"下一班地铁还有多久？\", \"translated\": \"Dans combien de temps arrive le prochain train de métro ?\"}, {\"original\": \"不好意思，请让我过去一下。\", \"translated\": \"Excusez-moi, je passe.\"}, {\"original\": \"这个座位有人吗？\", \"translated\": \"Ce siège est-il occupé ?\"}, {\"original\": \"不好意思，我去XX，要在哪儿换乘2号线？\", \"translated\": \"Excusez-moi, où dois-je changer pour la ligne 2 afin d\'aller à XX ?\"}, {\"original\": \"我怎么去XX？\", \"translated\": \"Comment puis-je me rendre à XX ?\"}]', 4, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在旅游景点使用的10个常用短语吗？\", \"太棒了！这里有10个关于旅游景点的常用短语，附带法语翻译：\"]', '[\"观光\", \"拍照\", \"购票\"]', 'zh', '[\"目前，您心里有特定场景吗？比如询问票价、找停车场，或导游服务——欢迎随时提问。\", \"请描述您心里想到的场景。\"]', '[]', '[{\"original\": \"门票多少钱？\", \"translated\": \"Combien coûte l\'entrée ?\"}, {\"original\": \"有学生票吗？\", \"translated\": \"Y a-t-il des billets étudiants disponibles ?\"}, {\"original\": \"景点几点开门？\", \"translated\": \"À quelle heure ouvre l’attraction ?\"}, {\"original\": \"这里有哪些好玩的项目？\", \"translated\": \"Quelles sont les activités amusantes à faire ici ?\"}, {\"original\": \"您能帮我们拍张照吗？\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"观光巴士在哪儿？\", \"translated\": \"Où se trouve le bus touristique ?\"}, {\"original\": \"厕所在哪儿？\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"最佳观景点在哪儿？\", \"translated\": \"Où est le meilleur point de vue ?\"}, {\"original\": \"这里的景色真美。\", \"translated\": \"Le paysage est magnifique ici.\"}, {\"original\": \"提供导游服务吗？\", \"translated\": \"Une visite guidée est-elle disponible ?\"}]', 5, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在出租车或出租车服务使用的10个常用短语吗？\", \"太棒了！这里有10个关于出租车或出租车服务的常用短语，附带法语翻译：\"]', '[\"打车\", \"告知目的地\", \"支付\"]', 'zh', '[\"目前，您最想做什么呢？比如询问目的地、价格，或者索要发票——随时都可以问。\", \"请在脑海中描述一下您想到的情景。\"]', '[]', '[{\"original\": \"我在哪里可以打到出租车？\", \"translated\": \"Où puis-je prendre un taxi ?\"}, {\"original\": \"请把我送到这个地址。\", \"translated\": \"Veuillez me conduire à cette adresse.\"}, {\"original\": \"大概要多少钱？\", \"translated\": \"Combien cela coûtera-t-il approximativement ?\"}, {\"original\": \"请您打表计费，谢谢。\", \"translated\": \"Pourriez-vous utiliser le compteur, s\'il vous plaît ?\"}, {\"original\": \"请开快一点，我赶时间。\", \"translated\": \"Pourriez-vous rouler un peu plus vite ? Je suis pressé(e).\"}, {\"original\": \"请在这里停车。\", \"translated\": \"Veuillez vous arrêter ici.\"}, {\"original\": \"您接受刷卡或手机支付吗？\", \"translated\": \"Acceptez-vous les paiements par carte ou par mobile ?\"}, {\"original\": \"可以给我一张收据吗？\", \"translated\": \"Pourrais-je avoir un reçu, s\'il vous plaît ?\"}, {\"original\": \"谢谢，司机师傅。\", \"translated\": \"Merci, monsieur/madame le chauffeur.\"}, {\"original\": \"还有多远？\", \"translated\": \"Il reste encore combien de temps ?\"}]', 6, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在药店使用的10个常用短语吗？\", \"太棒了！这里有10个关于药店的常用短语，附带法语翻译：\"]', '[\"购买药品\", \"咨询\", \"付款\"]', 'zh', '[\"目前，您心里有没有具体的情境？比如询问服药说明、使用医保相关表达、用药时长等，欢迎随时提问。\", \"请描述您心里想到的情境。\"]', '[]', '[{\"original\": \"你们有治感冒的药吗？\", \"translated\": \"Avez-vous des médicaments contre le rhume ?\"}, {\"original\": \"这种药我该怎么吃？\", \"translated\": \"Comment dois-je prendre ce médicament ?\"}, {\"original\": \"你们有止痛药吗？\", \"translated\": \"Avez-vous des analgésiques ?\"}, {\"original\": \"药品有说明书吗？\", \"translated\": \"Y a-t-il une notice d\'emploi incluse ?\"}, {\"original\": \"这种药有什么副作用吗？\", \"translated\": \"Ce médicament a-t-il des effets secondaires ?\"}, {\"original\": \"我能用医保卡付款吗？\", \"translated\": \"Puis-je payer avec ma carte d\'assurance maladie ?\"}, {\"original\": \"请给我一盒创可贴，谢谢。\", \"translated\": \"Pourriez-vous me donner une boîte de pansements, s\'il vous plaît ?\"}, {\"original\": \"你们有退烧药吗？\", \"translated\": \"Avez-vous des antipyrétiques ?\"}, {\"original\": \"我有点擦伤，你们有消毒液和创可贴吗？\", \"translated\": \"Je me suis un peu écorché(e). Avez-vous un antiseptique et des pansements ?\"}, {\"original\": \"你们几点关门？\", \"translated\": \"À quelle heure fermez-vous ?\"}]', 7, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在紧急服务使用的10个常用短语吗？\", \"太棒了！这里有10个关于紧急服务的常用短语，附带法语翻译：\"]', '[\"报警\", \"急救\", \"求助\"]', 'zh', '[\"目前，您心里有没有具体的紧急情况，比如火灾、受伤需要帮助、紧急电话？尽管随时问我。\", \"请描述一下您脑海中设想的情况。\"]', '[]', '[{\"original\": \"请帮我叫一辆救护车。\", \"translated\": \"Pourriez-vous m\'appeler une ambulance, s\'il vous plaît ?\"}, {\"original\": \"医院在哪里？\", \"translated\": \"Où se trouve l\'hôpital ?\"}, {\"original\": \"有人受伤了。\", \"translated\": \"Quelqu\'un est blessé.\"}, {\"original\": \"请帮帮我。\", \"translated\": \"Aidez-moi, s\'il vous plaît.\"}, {\"original\": \"警察局在哪里？\", \"translated\": \"Où se trouve le poste de police ?\"}, {\"original\": \"我的物品丢失了。\", \"translated\": \"J\'ai perdu mes affaires.\"}, {\"original\": \"消防部门的电话号码是多少？\", \"translated\": \"Quel est le numéro du service incendie ?\"}, {\"original\": \"我丢失了护照。您知道最近的警察局在哪里吗？\", \"translated\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le poste de police le plus proche ?\"}, {\"original\": \"这里有安全出口吗？\", \"translated\": \"Y a-t-il une sortie de secours ?\"}, {\"original\": \"有人昏倒了。\", \"translated\": \"Quelqu\'un s\'est évanoui.\"}]', 8, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在沙滩或池畔使用的10个常用短语吗？\", \"太棒了！这里有10个关于沙滩或池畔的常用短语，附带法语翻译：\"]', '[\"游泳\", \"日光浴\", \"沙滩运动\"]', 'zh', '[\"目前，您能告诉我您要参加的当地活动或节日的背景吗？比如文化节日、美食节或音乐节。请提供相关背景。\", \"请说明您参加的活动内容。\"]', '[\"您心中是否有特定场景？欢迎随时提问。\", \"请描述一下您心目中的场景。\"]', '[{\"original\": \"看！那边的海浪真大。\", \"translated\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\"}, {\"original\": \"记得涂防晒霜，这里的紫外线很强。\", \"translated\": \"N\'oubliez pas d\'appliquer de la crème solaire, les rayons UV sont très forts ici.\"}, {\"original\": \"这片海滩的沙子特别细腻，踩上去像走在棉花上一样。\", \"translated\": \"Le sable de cette plage est si fin qu’on a l’impression de marcher sur du coton.\"}, {\"original\": \"在海滩上打排球怎么样？\", \"translated\": \"Et si on jouait au volley-ball sur la plage ?\"}, {\"original\": \"远处的帆船看起来真美。\", \"translated\": \"Les voiliers au loin sont magnifiques.\"}, {\"original\": \"这里的水真清澈，连鱼都能看得见。\", \"translated\": \"L’eau est tellement claire ici qu’on peut même voir les poissons.\"}, {\"original\": \"咱们去找些贝壳吧。\", \"translated\": \"Allons ramasser des coquillages !\"}, {\"original\": \"日落时分在海滩散步一定很浪漫。\", \"translated\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\"}, {\"original\": \"听说这里的海鲜特别新鲜，咱们去尝尝吧。\", \"translated\": \"J’ai entendu dire que les fruits de mer sont très frais ici, allons en déguster !\"}, {\"original\": \"涨潮了，咱们往岸边走吧。\", \"translated\": \"La marée monte, rentrons vers la rive !\"}]', 9, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在当地活动和节日使用的10个常用短语吗？\", \"太棒了！这里有10个关于当地活动和节日的常用短语，附带法语翻译：\"]', '[\"参加活动\", \"庆祝节日\", \"了解文化\"]', 'zh', '[\"目前，您能告诉我您要参加的当地活动或节日的具体情境吗？比如万圣节、音乐会、朋友聚会，或者其他活动？请提供具体情境。\", \"请描述一下您脑海中设想的活动。\"]', '[\"您心中有特定的情境吗？欢迎随时提问。\", \"请描述一下您脑海中设想的情境。\"]', '[{\"original\": \"今天有什么活动吗？\", \"translated\": \"Y a-t-il des événements aujourd\'hui ?\"}, {\"original\": \"这个节日有什么特别之处吗？\", \"translated\": \"Y a-t-il quelque chose de particulier à propos de ce festival ?\"}, {\"original\": \"庆祝活动在哪里举行？\", \"translated\": \"Où se déroule la célébration ?\"}, {\"original\": \"我怎么买票？\", \"translated\": \"Comment puis-je acheter des billets ?\"}, {\"original\": \"演出什么时候开始？\", \"translated\": \"À quelle heure commence le spectacle ?\"}, {\"original\": \"有哪些传统食物？\", \"translated\": \"Quels sont les plats traditionnels ?\"}, {\"original\": \"这里真的很热闹。\", \"translated\": \"C\'est vraiment animé ici.\"}, {\"original\": \"有民俗活动吗？\", \"translated\": \"Y a-t-il des activités folkloriques ?\"}, {\"original\": \"节日快乐！\", \"translated\": \"Joyeuses fêtes !\"}, {\"original\": \"活动什么时候结束？\", \"translated\": \"À quelle heure se termine l\'événement ?\"}]', 10, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在博物馆或美术馆使用的10个常用短语吗？\", \"太棒了！这里有10个关于博物馆或美术馆的常用短语，附带法语翻译：\"]', '[\"参观\", \"导览服务\", \"购票\"]', 'zh', '[\"目前，您心里有特定的使用场景吗？比如索要导览手册、与参观路线相关的表达、对展品的评价用语等，欢迎随时提问。\", \"请描述一下您心里想到的具体场景。\"]', '[]', '[{\"original\": \"门票多少钱？\", \"translated\": \"Combien coûte l\'entrée ?\"}, {\"original\": \"你们提供语音导览吗？\", \"translated\": \"Proposez-vous des audioguides ?\"}, {\"original\": \"这件艺术品是谁创作的？\", \"translated\": \"Qui est l\'auteur de cette œuvre ?\"}, {\"original\": \"博物馆最珍贵的藏品在哪里？\", \"translated\": \"Où se trouve la pièce la plus précieuse du musée ?\"}, {\"original\": \"可以拍照吗？\", \"translated\": \"Est-ce que la prise de photos est autorisée ?\"}, {\"original\": \"这里有没有特别展览？\", \"translated\": \"Y a-t-il des expositions temporaires ici ?\"}, {\"original\": \"参观需要多长时间？\", \"translated\": \"Combien de temps dure la visite ?\"}, {\"original\": \"您能为我们做个简要介绍吗？\", \"translated\": \"Pourriez-vous nous donner une présentation ?\"}, {\"original\": \"这些作品真是精美绝伦。\", \"translated\": \"Ces œuvres sont vraiment exquises.\"}, {\"original\": \"纪念品商店在哪里？\", \"translated\": \"Où se trouve la boutique de souvenirs ?\"}]', 11, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供我可以在咖啡馆使用的10个常用短语吗？\", \"太棒了！这里有10个关于咖啡馆的常用短语，附带法语翻译：\"]', '[\"点咖啡\", \"休息\", \"社交\"]', 'zh', '[\"目前，您心里有没有具体的情境？比如要菜单、要冰饮或热饮、点其他产品等等——欢迎随时提问。\", \"请描述一下您心里想到的情境。\"]', '[]', '[{\"original\": \"请给我一杯拿铁。\", \"translated\": \"Je vais prendre un latte, s’il vous plaît.\"}, {\"original\": \"你们有Wi-Fi吗？\", \"translated\": \"Est-ce que vous avez le Wi-Fi ?\"}, {\"original\": \"请给我看一下菜单，谢谢。\", \"translated\": \"Pourriez-vous me montrer la carte, s’il vous plaît ?\"}, {\"original\": \"可以免费续杯吗？\", \"translated\": \"Les recharges sont-elles gratuites ?\"}, {\"original\": \"我的咖啡好了吗？\", \"translated\": \"Mon café est-il prêt ?\"}, {\"original\": \"我可以在这里坐多久？\", \"translated\": \"Combien de temps puis-je rester ici ?\"}, {\"original\": \"您能帮我们拍张照吗？\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"洗手间在哪儿？\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"请结账，谢谢。\", \"translated\": \"L’addition, s’il vous plaît. Merci.\"}, {\"original\": \"味道真的很棒。\", \"translated\": \"C’est vraiment délicieux.\"}]', 12, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser au restaurant ?\", \"Formidable ! Voici 10 expressions courantes liées au restaurant, accompagnées de leurs traductions en arabe :\"]', '[\"Restauration\", \"Commande\", \"Règlement\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple commander des boissons, formuler une réclamation ou demander des informations sur les ingrédients ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\", \"translated\": \"عذرًا، كم من الوقت يبقى حتى يكون طعامنا جاهزًا؟\"}, {\"original\": \"Une table pour deux, s’il vous plaît.\", \"translated\": \"طاولة لشخصين، من فضلكم.\"}, {\"original\": \"Pourrions-nous voir la carte, s’il vous plaît ?\", \"translated\": \"هل يمكننا رؤية القائمة، من فضلكم؟\"}, {\"original\": \"Avez-vous des plats signature à nous recommander ?\", \"translated\": \"هل لديكم أطباق مميَّزة ننصح بها؟\"}, {\"original\": \"Je voudrais commander ceci et cela.\", \"translated\": \"أود طلب هذا وهذا.\"}, {\"original\": \"Un verre d’eau, s’il vous plaît. Merci.\", \"translated\": \"كوب من الماء، من فضلكم. شكرًا لكم.\"}, {\"original\": \"L’addition, s’il vous plaît.\", \"translated\": \"الفاتورة، من فضلكم.\"}, {\"original\": \"Puis-je payer par carte bancaire ?\", \"translated\": \"هل يمكنني الدفع بالبطاقة الائتمانية؟\"}, {\"original\": \"Pourriez-vous emballer cela à emporter, s’il vous plaît ?\", \"translated\": \"هل يمكنكم تغليف هذا للاستلام خارج المطعم، من فضلكم؟\"}, {\"original\": \"Le plat était délicieux, merci.\", \"translated\": \"كان الطبق لذيذًا، شكرًا لكم.\"}]', 1, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Können Sie mir 10 gängige Ausdrücke nennen, die ich im Restaurant verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke rund ums Restaurant – inklusive japanischer Übersetzungen:\"]', '[\"Essen\", \"Bestellen\", \"Bezahlen\"]', 'de', '[\"Erst einmal: Haben Sie eine bestimmte Situation im Kopf – etwa Getränke bestellen, eine Beschwerde äußern oder nach Zutaten fragen? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen gerade einfällt.\"]', '[]', '[{\"original\": \"Entschuldigung, wie lange dauert es noch, bis unser Essen kommt?\", \"translated\": \"すみません、料理まであとどのくらいかかりますか？\"}, {\"original\": \"Ein Tisch für zwei Personen, bitte.\", \"translated\": \"2名様用のテーブルをお願いします。\"}, {\"original\": \"Könnten wir bitte die Speisekarte sehen?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"Haben Sie empfehlenswerte Hausgerichte?\", \"translated\": \"おすすめの看板料理はありますか？\"}, {\"original\": \"Ich möchte dies hier und das hier bestellen.\", \"translated\": \"これを1つと、こちらを1つお願いします。\"}, {\"original\": \"Ein Glas Wasser, bitte. Danke.\", \"translated\": \"お水を1杯お願いします。ありがとうございます。\"}, {\"original\": \"Die Rechnung, bitte.\", \"translated\": \"お会計をお願いします。\"}, {\"original\": \"Kann ich mit Kreditkarte bezahlen?\", \"translated\": \"クレジットカードで支払えますか？\"}, {\"original\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\", \"translated\": \"これをお持ち帰り用に包装していただけますか？\"}, {\"original\": \"Das Essen war köstlich, vielen Dank!\", \"translated\": \"とても美味しかったです。ありがとうございました！\"}]', 1, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Hotels nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke rund um das Thema Hotel inklusive japanischer Übersetzung:\"]', '[\"Check-in\", \"Check-out\", \"Zimmerservice\"]', 'de', '[\"Für den Augenblick – Haben Sie eine konkrete Situation im Kopf, z. B. Zimmerlage, weitere Hoteldienstleistungen oder Check-out? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Hallo, ich habe eine Reservierung. Hier ist mein Reisepass.\", \"translated\": \"こんにちは、予約をしております。こちらが私のパスポートです。\"}, {\"original\": \"Haben Sie noch freie Zimmer?\", \"translated\": \"空室はございますか？\"}, {\"original\": \"Entschuldigung, verfügt das Hotel über ein Fitnessstudio oder einen Wäscheservice?\", \"translated\": \"すみませんが、このホテルにはフィットネスルームやランドリールームはありますか？\"}, {\"original\": \"Wann beginnt das Frühstück?\", \"translated\": \"朝食は何時からですか？\"}, {\"original\": \"Könnte ich bitte den Zimmerschlüssel haben?\", \"translated\": \"お部屋の鍵をいただけますか？\"}, {\"original\": \"Könnten Sie mir beim Tragen meines Gepäcks aufs Zimmer helfen?\", \"translated\": \"荷物を部屋まで運んでいただけますか？\"}, {\"original\": \"Wie rufe ich den Zimmerservice an?\", \"translated\": \"ルームサービスを呼ぶにはどうすればよいですか？\"}, {\"original\": \"Wann ist der Check-out?\", \"translated\": \"チェックアウトは何時までですか？\"}, {\"original\": \"Könnten Sie mir bitte eine Quittung/Rechnung ausstellen?\", \"translated\": \"領収書／請求書を発行していただけますか？\"}, {\"original\": \"Kann ich mein Gepäck hier lassen?\", \"translated\": \"荷物をここで預けてもよろしいですか？\"}]', 2, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 gängige Sätze nennen, die ich am Flughafen verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Sätze zum Thema Flughafen – inklusive japanischer Übersetzungen:\"]', '[\"Check-in\", \"Boarding\", \"Gepäckabgabe\"]', 'de', '[\"Gibt es gerade eine bestimmte Situation, an die Sie denken – zum Beispiel Check-in, Gepäckausgabe oder Mietwagen-Service? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Wo ist der Check-in-Schalter?\", \"translated\": \"チェックインカウンターはどこですか？\"}, {\"original\": \"Ich hätte gerne einen Fensterplatz.\", \"translated\": \"窓際の席をお願いします。\"}, {\"original\": \"Ist dieser Flug verspätet?\", \"translated\": \"この便は遅れていますか？\"}, {\"original\": \"Ich muss dieses Gepäck aufgeben.\", \"translated\": \"この荷物を預けたいのですが。\"}, {\"original\": \"Wo ist das Boarding-Gate?\", \"translated\": \"搭乗口はどこですか？\"}, {\"original\": \"Das Flugzeug startet gleich.\", \"translated\": \"飛行機がまもなく離陸します。\"}, {\"original\": \"Muss ich meinen Laptop und die externe Batterie herausnehmen?\", \"translated\": \"ノートパソコンとモバイルバッテリーを取り出さなければいけませんか？\"}, {\"original\": \"Wo ist der Duty-free-Shop?\", \"translated\": \"免税店はどこですか？\"}, {\"original\": \"Ich kann meinen Koffer nicht finden.\", \"translated\": \"私のスーツケースが見当たりません。\"}, {\"original\": \"Bieten Sie einen Rollstuhl-Service an?\", \"translated\": \"車椅子サービスはありますか？\"}]', 3, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für öffentliche Verkehrsmittel nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke rund um öffentliche Verkehrsmittel – inklusive japanischer Übersetzungen:\"]', '[\"Mit Bus/U-Bahn fahren\", \"Tickets kaufen\", \"Umsteigen\"]', 'de', '[\"Gibt es gerade eine konkrete Situation im Kopf – z. B. nach einer Bushaltestelle fragen, den Fahrpreis erfragen oder darum bitten, auszusteigen? Fühlen Sie sich frei, danach zu fragen.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Fährt dieser Bus zum Terminal?\", \"translated\": \"このバスはターミナルへ行きますか？\"}, {\"original\": \"Was ist die nächste Haltestelle?\", \"translated\": \"次の停車駅はどこですか？\"}, {\"original\": \"Wo kann ich ein Ticket kaufen?\", \"translated\": \"切符はどこで買えますか？\"}, {\"original\": \"Ein Ticket nach XX, bitte.\", \"translated\": \"XX行きの切符を一枚お願いします。\"}, {\"original\": \"Muss ich umsteigen?\", \"translated\": \"乗り換えが必要ですか？\"}, {\"original\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\", \"translated\": \"次の地下鉄の列車まであとどれくらいですか？\"}, {\"original\": \"Entschuldigung, könnten Sie bitte Platz machen?\", \"translated\": \"すみません、通らせていただいてもよろしいですか？\"}, {\"original\": \"Ist dieser Platz bereits besetzt?\", \"translated\": \"この席は空いていますか？\"}, {\"original\": \"Entschuldigung, wo kann ich umsteigen, um mit der Linie 2 nach XX zu gelangen?\", \"translated\": \"すみません、XXへ行くためには、どこで2号線に乗り換えればよいですか？\"}, {\"original\": \"Wie komme ich nach XX?\", \"translated\": \"XXへはどうやって行けばいいですか？\"}]', 4, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Touristenattraktionen nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke rund um Touristenattraktionen samt japanischer Übersetzung:\"]', '[\"Sehenswürdigkeiten besuchen\", \"Fotos machen\", \"Eintrittskarten kaufen\"]', 'de', '[\"Im Moment – Haben Sie eine konkrete Situation im Kopf, z. B. Fragen zum Eintrittspreis, zur Parkplatzsuche oder zu einem Guide-Service? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"Gibt es ermäßigte Eintrittskarten für Schüler und Studenten?\", \"translated\": \"学生向け割引券はありますか？\"}, {\"original\": \"Wann öffnet die Sehenswürdigkeit?\", \"translated\": \"この観光スポットの営業時間は何時からですか？\"}, {\"original\": \"Was kann man hier Lustiges unternehmen?\", \"translated\": \"ここではどんな楽しいアクティビティができますか？\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"Wo befindet sich der Sightseeing-Bus?\", \"translated\": \"観光バスの乗り場はどこですか？\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"Wo ist der beste Aussichtspunkt?\", \"translated\": \"一番景色がいい展望スポットはどこですか？\"}, {\"original\": \"Die Landschaft hier ist wunderschön.\", \"translated\": \"ここでの景色はとても美しいです。\"}, {\"original\": \"Gibt es eine Führung mit Guide?\", \"translated\": \"ガイド付きツアーはありますか？\"}]', 5, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Redewendungen für Taxis oder Taxidienstleistungen nennen?\", \"Fantastisch! Hier sind 10 gängige Redewendungen zum Thema Taxis oder Taxidienstleistungen – jeweils mit japanischer Übersetzung:\"]', '[\"Taxi nehmen\", \"Zielort angeben\", \"Bezahlen\"]', 'de', '[\"Vorerst: Was möchten Sie gerade am liebsten tun – z. B. nach dem Zielort fragen, nach dem Preis, oder um eine Rechnung bitten? Fragen Sie ruhig einfach los!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', '[]', '[{\"original\": \"Wo kann ich ein Taxi bekommen?\", \"translated\": \"タクシーはどこで乗れますか？\"}, {\"original\": \"Bitte fahren Sie mich zu dieser Adresse.\", \"translated\": \"この住所までお願いします。\"}, {\"original\": \"Wie viel wird es ungefähr kosten?\", \"translated\": \"だいたいいくらぐらいかかりますか？\"}, {\"original\": \"Könnten Sie bitte den Taxameter benutzen?\", \"translated\": \"メーターを使っていただけますか？\"}, {\"original\": \"Könnten Sie bitte etwas schneller fahren? Ich habe es eilig.\", \"translated\": \"急いでいるので、少しだけ速く運転してもらえますか？\"}, {\"original\": \"Bitte halten Sie hier an.\", \"translated\": \"ここで止めてください。\"}, {\"original\": \"Akzeptieren Sie Karten- oder Mobile-Zahlungen?\", \"translated\": \"カードやモバイル決済は使えますか？\"}, {\"original\": \"Könnte ich bitte eine Quittung haben?\", \"translated\": \"領収書をいただけますか？\"}, {\"original\": \"Danke, Fahrer.\", \"translated\": \"ありがとうございます、運転手さん。\"}, {\"original\": \"Wie weit ist es noch?\", \"translated\": \"あとどのくらいですか？\"}]', 6, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Sätze nennen, die ich in einer Apotheke verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Sätze rund um die Apotheke – inklusive japanischer Übersetzung:\"]', '[\"Medikamente kaufen\", \"Beratung\", \"Bezahlung\"]', 'de', '[\"Vorerst – Haben Sie eine konkrete Situation im Kopf? Zum Beispiel Fragen zur Einnahme von Medikamenten, zum Einsatz der Versicherung oder zur Dauer der Behandlung? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Haben Sie Erkältungsmedikamente?\", \"translated\": \"風邪薬はありますか？\"}, {\"original\": \"Wie soll ich dieses Medikament einnehmen?\", \"translated\": \"この薬の飲み方はどうすればいいですか？\"}, {\"original\": \"Haben Sie Schmerzmittel?\", \"translated\": \"痛み止めはありますか？\"}, {\"original\": \"Gibt es eine Gebrauchsanweisung?\", \"translated\": \"説明書はついていますか？\"}, {\"original\": \"Hat dieses Medikament Nebenwirkungen?\", \"translated\": \"この薬には副作用がありますか？\"}, {\"original\": \"Kann ich meine Krankenversicherungskarte verwenden?\", \"translated\": \"健康保険証は使えますか？\"}, {\"original\": \"Könnten Sie mir bitte eine Packung Pflaster geben?\", \"translated\": \"絆創膏を1箱お願いできますか？\"}, {\"original\": \"Haben Sie Fieber senkende Mittel?\", \"translated\": \"解熱剤はありますか？\"}, {\"original\": \"Ich habe mir leicht das Knie aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\", \"translated\": \"ちょっと擦り傷を作ってしまったのですが、消毒液と絆創膏はありますか？\"}, {\"original\": \"Wann schließen Sie?\", \"translated\": \"何時までやっていますか？\"}]', 7, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für den Notdienst nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Notdienst – inklusive japanischer Übersetzung:\"]', '[\"Polizei rufen\", \"Erste Hilfe\", \"Hilfe rufen\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Notsituation im Kopf, z. B. Brand, Verletzung und Hilfsbedarf, Notruf? Fragen Sie ruhig!\", \"Beschreiben Sie bitte die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Bitte rufen Sie einen Krankenwagen für mich.\", \"translated\": \"救急車を呼んでください。\"}, {\"original\": \"Wo ist das Krankenhaus?\", \"translated\": \"病院はどこですか？\"}, {\"original\": \"Jemand ist verletzt.\", \"translated\": \"誰かが怪我をしました。\"}, {\"original\": \"Bitte helfen Sie mir.\", \"translated\": \"助けてください。\"}, {\"original\": \"Wo ist die Polizeistation?\", \"translated\": \"警察署はどこですか？\"}, {\"original\": \"Ich habe meine Sachen verloren.\", \"translated\": \"荷物をなくしました。\"}, {\"original\": \"Was ist die Notrufnummer für die Feuerwehr?\", \"translated\": \"消防署への緊急電話番号は何番ですか？\"}, {\"original\": \"Ich habe meinen Reisepass verloren. Können Sie mir sagen, wo die nächste Polizeistation ist?\", \"translated\": \"パスポートを紛失しました。最寄りの警察署はどこですか？\"}, {\"original\": \"Gibt es einen Notausgang?\", \"translated\": \"非常口はありますか？\"}, {\"original\": \"Jemand ist in Ohnmacht gefallen.\", \"translated\": \"誰かが気を失いました。\"}]', 8, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 gängige Ausdrücke für den Strand oder am Pool nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Strand oder Pool inklusive japanischer Übersetzung:\"]', '[\"Schwimmen\", \"Sonnenbaden\", \"Strandsport\"]', 'de', '[\"Bitte teilen Sie mir vorläufig den Kontext des lokalen Events oder Festivals mit, an dem Sie teilnehmen – z. B. ein Kulturfestival, ein kulinarisches Festival oder ein Musikfestival. Geben Sie bitte den Kontext an.\", \"Bitte nennen Sie mir die Aktivitäten, an denen Sie teilnehmen.\"]', '[\"Haben Sie bereits eine konkrete Situation im Kopf? Fragen Sie ruhig frei nach.\", \"Beschreiben Sie bitte die Situation, die Ihnen vorschwebt.\"]', '[{\"original\": \"Schau mal! Die Wellen dort drüben sind wirklich groß.\", \"translated\": \"見て！あそこに見える波は本当に大きいよ。\"}, {\"original\": \"Vergiss nicht, Sonnencreme aufzutragen – die UV-Strahlen hier sind sehr stark.\", \"translated\": \"日焼け止めを塗ることを忘れないでね。ここでの紫外線はとても強いんだよ。\"}, {\"original\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle gehen.\", \"translated\": \"このビーチの砂はとても細かくて、綿の上を歩いているような感触だよ。\"}, {\"original\": \"Wie wäre es mit einem Volleyballspiel am Strand?\", \"translated\": \"ビーチでバレーボールをするのはどう？\"}, {\"original\": \"Die Segelboote in der Ferne sehen wunderschön aus.\", \"translated\": \"遠くに見えるセーリングボートはとても美しく見えるね。\"}, {\"original\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\", \"translated\": \"ここでの水はとても透明度が高くて、魚まで見えちゃうよ。\"}, {\"original\": \"Lass uns doch ein paar Muscheln suchen gehen.\", \"translated\": \"一緒に貝殻を探しに行こうよ。\"}, {\"original\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss wirklich romantisch sein.\", \"translated\": \"夕日が沈む頃のビーチ散歩は、きっととてもロマンチックだろうね。\"}, {\"original\": \"Ich habe gehört, dass die Meeresfrüchte hier besonders frisch sind – lass uns welche probieren!\", \"translated\": \"ここではシーフードがすごく新鮮だって聞いたよ。ぜひ食べてみよう！\"}, {\"original\": \"Die Flut kommt herein – lasst uns Richtung Ufer gehen.\", \"translated\": \"潮が満ちてきているから、岸へ向かおう。\"}]', 9, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Redewendungen für lokale Veranstaltungen und Feste nennen?\", \"Fantastisch! Hier sind 10 gängige Redewendungen zu lokalen Veranstaltungen und Festen sowie deren japanische Übersetzungen:\"]', '[\"Veranstaltungen besuchen\", \"Feste feiern\", \"Kultur kennenlernen\"]', 'de', '[\"Momentan: Könnten Sie mir bitte den Kontext der lokalen Veranstaltung oder des Festes, an dem Sie teilnehmen möchten, mitteilen – z. B. Halloween, ein Konzert, eine Party bei Freunden oder etwas anderes? Bitte geben Sie den Kontext an.\", \"Bitte beschreiben Sie die Aktivitäten, die Ihnen spontan in den Sinn kommen.\"]', '[\"Haben Sie eine konkrete Situation im Kopf? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', '[{\"original\": \"Gibt es heute irgendwelche Veranstaltungen?\", \"translated\": \"今日は何かイベントがありますか？\"}, {\"original\": \"Gibt es bei diesem Fest etwas Besonderes?\", \"translated\": \"このお祭りには何か特別なことがありますか？\"}, {\"original\": \"Wo findet die Feier statt?\", \"translated\": \"お祝いはどこで行われますか？\"}, {\"original\": \"Wie kann ich Tickets kaufen?\", \"translated\": \"チケットの購入方法を教えていただけますか？\"}, {\"original\": \"Wann beginnt die Vorstellung?\", \"translated\": \"パフォーマンスはいつから始まりますか？\"}, {\"original\": \"Welche traditionellen Speisen gibt es?\", \"translated\": \"どんな伝統料理がありますか？\"}, {\"original\": \"Es ist hier wirklich lebendig!\", \"translated\": \"ここは本当ににぎやかですね！\"}, {\"original\": \"Gibt es volkstümliche Aktivitäten?\", \"translated\": \"民俗的な行事はありますか？\"}, {\"original\": \"Frohe Feiertage!\", \"translated\": \"楽しい祝日を！\"}, {\"original\": \"Wann endet die Veranstaltung?\", \"translated\": \"イベントはいつ終わりますか？\"}]', 10, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Können Sie mir 10 gängige Sätze nennen, die ich im Museum oder in der Kunstgalerie verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Sätze zum Thema Museum oder Kunstgalerie – inklusive japanischer Übersetzungen:\"]', '[\"Besuch\", \"Geführte Tour\", \"Tickets kaufen\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf? Zum Beispiel: nach einer Einführungsbroschüre fragen, Sätze zu einem Rundgangplan, Sätze zur Kommentierung von Exponaten – fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"入館料はいくらですか？\"}, {\"original\": \"Haben Sie Audioguides?\", \"translated\": \"オーディオガイドはありますか？\"}, {\"original\": \"Wer hat dieses Kunstwerk geschaffen?\", \"translated\": \"この作品の作者は誰ですか？\"}, {\"original\": \"Wo befindet sich das wertvollste Stück des Museums?\", \"translated\": \"博物館で最も価値のある作品はどこにありますか？\"}, {\"original\": \"Ist Fotografieren erlaubt?\", \"translated\": \"写真撮影は許可されていますか？\"}, {\"original\": \"Gibt es hier besondere Ausstellungen?\", \"translated\": \"こちらでは特別展は開催されていますか？\"}, {\"original\": \"Wie lange dauert der Besuch?\", \"translated\": \"見学にはどれくらい時間がかかりますか？\"}, {\"original\": \"Könnten Sie uns bitte eine Einführung geben?\", \"translated\": \"ぜひ、ご案内をお願いできますか？\"}, {\"original\": \"Diese Werke sind wirklich exquisit.\", \"translated\": \"これらの作品は本当に素晴らしいですね。\"}, {\"original\": \"Wo befindet sich der Souvenirladen?\", \"translated\": \"お土産ショップはどこにありますか？\"}]', 11, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich in einem Café verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Cafés – inklusive japanischer Übersetzungen:\"]', '[\"Kaffee bestellen\", \"Ausruhen\", \"Sozialisieren\"]', 'de', '[\"Für den Moment – Haben Sie eine bestimmte Situation im Kopf, z. B. die Bestellung einer Speisekarte, kalte oder heiße Getränke, andere Produkte? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Ich nehme einen Latte, bitte.\", \"translated\": \"ラテをいただきます。\"}, {\"original\": \"Haben Sie WLAN?\", \"translated\": \"Wi-Fiは使えますか？\"}, {\"original\": \"Könnte ich bitte die Speisekarte sehen?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"Darf man nachfüllen?\", \"translated\": \"追加注文はできますか？\"}, {\"original\": \"Ist mein Kaffee schon fertig?\", \"translated\": \"私のコーヒーはもうできましたか？\"}, {\"original\": \"Wie lange darf ich hier sitzen bleiben?\", \"translated\": \"ここにどのくらい座っていられますか？\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"Die Rechnung, bitte. Danke.\", \"translated\": \"お会計をお願いします。ありがとう。\"}, {\"original\": \"Es schmeckt wirklich gut.\", \"translated\": \"とてもおいしいです。\"}]', 12, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Restaurant verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Restaurant inklusive chinesischer Übersetzungen:\"]', '[\"Essen\", \"Bestellen\", \"Bezahlen\"]', 'de', '[\"Fürs Erste – Haben Sie eine konkrete Situation im Kopf? Zum Beispiel Getränke bestellen, eine Beschwerde äußern oder nach Zutaten fragen? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Entschuldigung, wie lange dauert es noch, bis unser Essen kommt?\", \"translated\": \"打扰一下，我们的餐还要等多久？\"}, {\"original\": \"Ein Tisch für zwei Personen, bitte.\", \"translated\": \"请给我们安排一张两人桌。\"}, {\"original\": \"Könnten wir bitte die Speisekarte sehen?\", \"translated\": \"我们可以看一下菜单吗？\"}, {\"original\": \"Haben Sie empfehlenswerte Hausgerichte?\", \"translated\": \"您有什么招牌菜可以推荐吗？\"}, {\"original\": \"Ich möchte dies und das bestellen.\", \"translated\": \"我要点这个和这个。\"}, {\"original\": \"Ein Glas Wasser, bitte. Danke.\", \"translated\": \"请来一杯水，谢谢。\"}, {\"original\": \"Die Rechnung, bitte.\", \"translated\": \"请把账单拿来。\"}, {\"original\": \"Kann ich mit Kreditkarte bezahlen?\", \"translated\": \"我可以用信用卡付款吗？\"}, {\"original\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\", \"translated\": \"麻烦把这份打包带走，谢谢。\"}, {\"original\": \"Das Essen war köstlich, danke!\", \"translated\": \"饭菜非常美味，谢谢！\"}]', 1, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Hotels nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Hotel inklusive chinesischer Übersetzung:\"]', '[\"Check-in\", \"Check-out\", \"Zimmerservice\"]', 'de', '[\"Mal sehen – haben Sie gerade eine bestimmte Situation im Kopf, z. B. Lage des Zimmers, weitere Hotelangebote oder den Check-out? Fragen Sie ruhig einfach los!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Hallo, ich habe eine Reservierung. Hier ist mein Reisepass.\", \"translated\": \"你好，我有预订。这是我的护照。\"}, {\"original\": \"Haben Sie noch freie Zimmer?\", \"translated\": \"你们还有空房吗？\"}, {\"original\": \"Entschuldigung, verfügt das Hotel über ein Fitnessstudio oder einen Wäschebereich?\", \"translated\": \"打扰一下，酒店有健身房或洗衣房吗？\"}, {\"original\": \"Wann beginnt das Frühstück?\", \"translated\": \"早餐几点开始？\"}, {\"original\": \"Könnte ich bitte den Zimmerschlüssel haben?\", \"translated\": \"请给我房卡，好吗？\"}, {\"original\": \"Könnten Sie mir beim Tragen meines Gepäcks auf mein Zimmer helfen?\", \"translated\": \"您能帮我把行李送到房间吗？\"}, {\"original\": \"Wie rufe ich den Zimmerservice an?\", \"translated\": \"怎么呼叫客房服务？\"}, {\"original\": \"Wann ist der Check-out?\", \"translated\": \"几点退房？\"}, {\"original\": \"Könnten Sie mir bitte eine Quittung / Rechnung ausstellen?\", \"translated\": \"您能给我开一张收据／发票吗？\"}, {\"original\": \"Darf ich mein Gepäck hier lassen?\", \"translated\": \"我可以把行李寄存在这里吗？\"}]', 2, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich am Flughafen verwenden kann?\", \"Toll! Hier sind 10 gängige Ausdrücke zum Thema Flughafen – inklusive chinesischer Übersetzung:\"]', '[\"Check-in\", \"Boarding\", \"Gepäckabgabe\"]', 'de', '[\"Im Moment – Haben Sie eine konkrete Situation im Kopf, z. B. Check-in, Gepäckausgabe oder Autovermietung? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wo ist der Check-in-Schalter?\", \"translated\": \"值机柜台在哪里？\"}, {\"original\": \"Ich hätte gerne einen Fensterplatz, bitte.\", \"translated\": \"我想要一个靠窗的座位，谢谢。\"}, {\"original\": \"Ist dieser Flug verspätet?\", \"translated\": \"这个航班延误了吗？\"}, {\"original\": \"Ich muss dieses Gepäck aufgeben.\", \"translated\": \"我需要托运这件行李。\"}, {\"original\": \"Wo ist die Boarding-Tür?\", \"translated\": \"登机口在哪里？\"}, {\"original\": \"Das Flugzeug startet gleich.\", \"translated\": \"飞机即将起飞。\"}, {\"original\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\", \"translated\": \"我需要把笔记本电脑和充电宝拿出来吗？\"}, {\"original\": \"Wo ist der Duty-free-Shop?\", \"translated\": \"免税店在哪里？\"}, {\"original\": \"Ich kann meinen Koffer nicht finden.\", \"translated\": \"我找不到我的行李箱了。\"}, {\"original\": \"Bieten Sie einen Rollstuhlservice an?\", \"translated\": \"你们提供轮椅服务吗？\"}]', 3, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für öffentliche Verkehrsmittel nennen?\", \"Toll! Hier sind 10 gängige Ausdrücke zum Thema öffentliche Verkehrsmittel – inklusive chinesischer Übersetzung:\"]', '[\"Mit Bus/U-Bahn fahren\", \"Tickets kaufen\", \"Umsteigen\"]', 'de', '[\"Im Moment: Haben Sie eine konkrete Situation im Kopf – z. B. nach der Bushaltestelle fragen, den Fahrpreis erfragen oder darum bitten, aussteigen zu dürfen? Fragen Sie ruhig!\", \"Beschreiben Sie bitte die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Fährt dieser Bus zum Terminal?\", \"translated\": \"这趟公交车去终点站吗？\"}, {\"original\": \"Was ist die nächste Haltestelle?\", \"translated\": \"下一站是哪里？\"}, {\"original\": \"Wo kann ich ein Ticket kaufen?\", \"translated\": \"我在哪里可以买票？\"}, {\"original\": \"Ein Ticket nach XX, bitte.\", \"translated\": \"一张去XX的车票，谢谢。\"}, {\"original\": \"Muss ich umsteigen?\", \"translated\": \"我需要换乘吗？\"}, {\"original\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\", \"translated\": \"下一班地铁还要等多久？\"}, {\"original\": \"Entschuldigung, darf ich bitte durch?\", \"translated\": \"不好意思，请让我过去一下。\"}, {\"original\": \"Ist dieser Platz schon besetzt?\", \"translated\": \"这个座位有人了吗？\"}, {\"original\": \"Entschuldigung, wo kann ich umsteigen, um mit der Linie 2 nach XX zu gelangen?\", \"translated\": \"不好意思，请问我在哪里换乘2号线去XX？\"}, {\"original\": \"Wie komme ich nach XX?\", \"translated\": \"我怎么去XX？\"}]', 4, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Touristenattraktionen nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zu Touristenattraktionen mit chinesischen Übersetzungen:\"]', '[\"Besichtigung\", \"Fotografieren\", \"Tickets kaufen\"]', 'de', '[\"Im Moment – Haben Sie eine konkrete Situation im Kopf, z. B. Nachfragen zum Ticketpreis, zum Parkplatz oder zur Reiseleistungs- bzw. Fremdenführerservice? Fragen Sie ruhig!\", \"Beschreiben Sie bitte die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"Gibt es ermäßigte Eintrittskarten für Schüler?\", \"translated\": \"有学生票吗？\"}, {\"original\": \"Wann öffnet die Sehenswürdigkeit?\", \"translated\": \"景点几点开放？\"}, {\"original\": \"Was kann man hier Lustiges unternehmen?\", \"translated\": \"这里有哪些好玩的活动？\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"您能帮我们拍张照吗？\"}, {\"original\": \"Wo befindet sich der Sightseeing-Bus?\", \"translated\": \"观光巴士在哪里？\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"洗手间在哪儿？\"}, {\"original\": \"Wo ist der beste Aussichtspunkt?\", \"translated\": \"最佳观景点在哪里？\"}, {\"original\": \"Die Landschaft hier ist wunderschön.\", \"translated\": \"这里的风景真美。\"}, {\"original\": \"Gibt es eine geführte Tour?\", \"translated\": \"有导游讲解服务吗？\"}]', 5, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für das Nutzen eines Taxis oder einer Taxidienstleistung nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Taxi oder Taxidienstleistung – jeweils mit chinesischer Übersetzung:\"]', '[\"Taxi nehmen\", \"Zielort angeben\", \"Bezahlen\"]', 'de', '[\"Was möchten Sie gerade am liebsten tun – etwa nach dem Zielort fragen, nach dem Preis, oder nach einer Rechnung? Fühlen Sie sich frei, danach zu fragen.\", \"Beschreiben Sie bitte die Situation, die Ihnen im Kopf vorschwebt.\"]', '[]', '[{\"original\": \"Wo kann ich ein Taxi bekommen?\", \"translated\": \"我在哪里可以打到出租车？\"}, {\"original\": \"Bitte fahren Sie mich zu dieser Adresse.\", \"translated\": \"请送我去这个地址。\"}, {\"original\": \"Wie viel wird es ungefähr kosten?\", \"translated\": \"大概要多少钱？\"}, {\"original\": \"Könnten Sie bitte den Taxameter einschalten?\", \"translated\": \"请问您能打表计费吗？\"}, {\"original\": \"Könnten Sie bitte etwas schneller fahren? Ich habe es eilig.\", \"translated\": \"请开快一点，我赶时间。\"}, {\"original\": \"Bitte halten Sie hier an.\", \"translated\": \"请在这里停车。\"}, {\"original\": \"Akzeptieren Sie Karten- oder Mobilzahlungen?\", \"translated\": \"您支持刷卡或手机支付吗？\"}, {\"original\": \"Könnte ich bitte eine Quittung bekommen?\", \"translated\": \"我可以要一张收据吗？\"}, {\"original\": \"Danke, Fahrer.\", \"translated\": \"谢谢，司机师傅。\"}, {\"original\": \"Wie weit ist es noch?\", \"translated\": \"还有多远？\"}]', 6, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für die Apotheke nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit der Apotheke – inklusive chinesischer Übersetzungen:\"]', '[\"Medikamente kaufen\", \"Beratung\", \"Bezahlung\"]', 'de', '[\"Im Moment haben Sie bereits eine konkrete Situation im Kopf, z. B. Fragen zur Einnahme von Medikamenten, zum Versicherungseinsatz, zur Dauer der Behandlung – fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen gerade einfällt.\"]', '[]', '[{\"original\": \"Haben Sie fiebersenkende Medikamente?\", \"translated\": \"你们有退烧药吗？\"}, {\"original\": \"Wie soll ich dieses Medikament einnehmen?\", \"translated\": \"这个药我该怎么吃？\"}, {\"original\": \"Haben Sie Schmerzmittel?\", \"translated\": \"你们有止痛药吗？\"}, {\"original\": \"Gibt es eine Gebrauchsanweisung?\", \"translated\": \"有说明书吗？\"}, {\"original\": \"Hat dieses Medikament Nebenwirkungen?\", \"translated\": \"这个药有什么副作用吗？\"}, {\"original\": \"Kann ich meine Krankenversicherungskarte verwenden?\", \"translated\": \"我能用医保卡吗？\"}, {\"original\": \"Könnte ich bitte eine Packung Pflaster haben?\", \"translated\": \"请问能给我一盒创可贴吗？\"}, {\"original\": \"Haben Sie fiebersenkende Mittel?\", \"translated\": \"你们有退烧药吗？\"}, {\"original\": \"Ich habe mir leicht die Haut aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\", \"translated\": \"我有点擦伤，你们有消毒药水和创可贴吗？\"}, {\"original\": \"Um wie viel Uhr machen Sie zu?\", \"translated\": \"你们几点关门？\"}]', 7, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Notfalldienste nennen?\", \"Toll! Hier sind 10 gängige Ausdrücke zum Thema Notfalldienste sowie die chinesischen Übersetzungen:\"]', '[\"Polizei rufen\", \"Erste Hilfe leisten\", \"Hilfe rufen\"]', 'de', '[\"Momentan: Haben Sie eine konkrete Notsituation im Kopf – etwa Feuer, Verletzung und Hilfe benötigt, Notruf? Fragen Sie ruhig nach.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Bitte rufen Sie einen Krankenwagen für mich.\", \"translated\": \"请帮我叫一辆救护车。\"}, {\"original\": \"Wo ist das Krankenhaus?\", \"translated\": \"医院在哪儿？\"}, {\"original\": \"Jemand ist verletzt.\", \"translated\": \"有人受伤了。\"}, {\"original\": \"Bitte helfen Sie mir.\", \"translated\": \"请帮帮我。\"}, {\"original\": \"Wo ist die Polizeistation?\", \"translated\": \"警察局在哪儿？\"}, {\"original\": \"Ich habe meine Sachen verloren.\", \"translated\": \"我的物品丢了。\"}, {\"original\": \"Wie lautet die Notrufnummer für die Feuerwehr?\", \"translated\": \"消防部门的电话号码是多少？\"}, {\"original\": \"Ich habe meinen Pass verloren. Wissen Sie, wo die nächste Polizeistation ist?\", \"translated\": \"我的护照丢了。您知道最近的警察局在哪儿吗？\"}, {\"original\": \"Gibt es einen Notausgang?\", \"translated\": \"有安全出口吗？\"}, {\"original\": \"Jemand ist in Ohnmacht gefallen.\", \"translated\": \"有人昏倒了。\"}]', 8, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 gängige Ausdrücke für den Strand oder den Poolbereich nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Strand oder Poolbereich inklusive chinesischer Übersetzung:\"]', '[\"Schwimmen\", \"Sonnenbaden\", \"Strandsport\"]', 'de', '[\"Momentan: Könnten Sie mir bitte den Hintergrund der lokalen Veranstaltung oder des Festivals, an dem Sie teilnehmen, nennen – etwa ein Kulturfestival, ein Kulinarikfestival oder ein Musikfestival? Bitte geben Sie den Kontext an.\", \"Bitte nennen Sie die Aktivitäten, an denen Sie teilnehmen.\"]', '[\"Haben Sie bereits eine konkrete Situation im Kopf? Fragen Sie ruhig frei nach.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[{\"original\": \"Schau mal! Die Wellen dort drüben sind wirklich groß.\", \"translated\": \"看！那边的海浪真大。\"}, {\"original\": \"Vergiss nicht, Sonnencreme aufzutragen – die UV-Strahlen hier sind sehr stark.\", \"translated\": \"记得涂防晒霜，这里的紫外线很强。\"}, {\"original\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle gehen.\", \"translated\": \"这片海滩的沙子非常细腻，踩上去就像踩在棉花上。\"}, {\"original\": \"Wie wär’s mit etwas Beachvolleyball?\", \"translated\": \"要不要去沙滩打排球？\"}, {\"original\": \"Die Segelboote in der Ferne sehen wunderschön aus.\", \"translated\": \"远处的帆船看起来真漂亮。\"}, {\"original\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\", \"translated\": \"这里的水特别清澈，甚至能看见鱼。\"}, {\"original\": \"Lass uns doch ein paar Muscheln suchen.\", \"translated\": \"咱们去找些贝壳吧。\"}, {\"original\": \"Spazieren gehen am Strand bei Sonnenuntergang muss sehr romantisch sein.\", \"translated\": \"日落时分在沙滩散步一定很浪漫。\"}, {\"original\": \"Ich habe gehört, dass die Meeresfrüchte hier besonders frisch sind – lass uns welche probieren!\", \"translated\": \"我听说这里的海鲜特别新鲜，咱们去尝尝吧！\"}, {\"original\": \"Die Flut kommt herein – gehen wir lieber Richtung Ufer.\", \"translated\": \"涨潮了，咱们往岸边走吧。\"}]', 9, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Redewendungen für lokale Aktivitäten und Feste nennen?\", \"Fantastisch! Hier sind 10 gängige Redewendungen zu lokalen Aktivitäten und Festen – inklusive chinesischer Übersetzung:\"]', '[\"Veranstaltungen besuchen\", \"Feste feiern\", \"Kultur kennenlernen\"]', 'de', '[\"Momentan: Könnten Sie mir bitte den Kontext der lokalen Veranstaltung oder des Festes, an dem Sie teilnehmen möchten, nennen? Zum Beispiel Halloween, ein Konzert, eine private Party oder etwas anderes? Bitte geben Sie den Kontext an.\", \"Bitte beschreiben Sie die Aktivitäten, die Ihnen im Kopf herumschwirren.\"]', '[\"Haben Sie eine konkrete Situation im Kopf? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', '[{\"original\": \"Gibt es heute irgendwelche Veranstaltungen?\", \"translated\": \"今天有什么活动吗？\"}, {\"original\": \"Gibt es bei diesem Fest etwas Besonderes?\", \"translated\": \"这个节日有什么特别之处吗？\"}, {\"original\": \"Wo findet die Feier statt?\", \"translated\": \"庆祝活动在哪里举行？\"}, {\"original\": \"Wie kann ich Tickets kaufen?\", \"translated\": \"我该怎么买票？\"}, {\"original\": \"Wann beginnt die Vorstellung?\", \"translated\": \"演出什么时候开始？\"}, {\"original\": \"Welche traditionellen Speisen gibt es?\", \"translated\": \"有哪些传统食物？\"}, {\"original\": \"Es ist hier wirklich lebendig!\", \"translated\": \"这儿真热闹！\"}, {\"original\": \"Gibt es Volksaktivitäten?\", \"translated\": \"有民俗活动吗？\"}, {\"original\": \"Frohe Feiertage!\", \"translated\": \"节日快乐！\"}, {\"original\": \"Wann endet die Veranstaltung?\", \"translated\": \"活动什么时候结束？\"}]', 10, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 gängige Ausdrücke für Museen oder Kunstmuseen nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Museen oder Kunstmuseen sowie deren chinesische Übersetzungen:\"]', '[\"Besuch\", \"Geführte Tour\", \"Tickets kaufen\"]', 'de', '[\"Vorläufig: Haben Sie eine konkrete Situation im Kopf – etwa die Bitte um ein Einführungshandbuch, Ausdrücke zum Ausstellungsplan oder zur Kommentierung von Exponaten? Fühlen Sie sich frei, danach zu fragen.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"Haben Sie Audioführungen?\", \"translated\": \"你们提供语音导览吗？\"}, {\"original\": \"Wer hat dieses Kunstwerk geschaffen?\", \"translated\": \"这件艺术品是谁创作的？\"}, {\"original\": \"Wo befindet sich das wertvollste Stück des Museums?\", \"translated\": \"博物馆最珍贵的藏品在哪儿？\"}, {\"original\": \"Ist Fotografieren erlaubt?\", \"translated\": \"可以拍照吗？\"}, {\"original\": \"Gibt es hier besondere Ausstellungen?\", \"translated\": \"这里有特别展览吗？\"}, {\"original\": \"Wie lange dauert der Besuch?\", \"translated\": \"参观需要多长时间？\"}, {\"original\": \"Könnten Sie uns eine kurze Einführung geben?\", \"translated\": \"您能给我们简单介绍一下吗？\"}, {\"original\": \"Diese Werke sind wirklich exquisit.\", \"translated\": \"这些作品真的非常精美。\"}, {\"original\": \"Wo befindet sich der Souvenirladen?\", \"translated\": \"纪念品商店在哪儿？\"}]', 11, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Cafés nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Café mit chinesischen Übersetzungen:\"]', '[\"Kaffee bestellen\", \"Ausruhen\", \"Sozialisieren\"]', 'de', '[\"Für den Moment – Haben Sie eine konkrete Situation im Kopf, z. B. nach der Speisekarte fragen, Eis- oder Heißgetränke bestellen, andere Produkte anfragen? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Ich nehme einen Latte, bitte.\", \"translated\": \"我要一杯拿铁，谢谢。\"}, {\"original\": \"Haben Sie WLAN?\", \"translated\": \"你们有Wi-Fi吗？\"}, {\"original\": \"Könnte ich bitte die Speisekarte sehen?\", \"translated\": \"请问可以看一下菜单吗？\"}, {\"original\": \"Darf ich Nachschank bekommen?\", \"translated\": \"可以免费续杯吗？\"}, {\"original\": \"Ist mein Kaffee fertig?\", \"translated\": \"我的咖啡好了吗？\"}, {\"original\": \"Wie lange darf ich hier sitzen?\", \"translated\": \"我可以在这里坐多久？\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"能帮我们拍张照吗？\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"洗手间在哪里？\"}, {\"original\": \"Die Rechnung, bitte. Vielen Dank.\", \"translated\": \"请结账，谢谢。\"}, {\"original\": \"Das schmeckt wirklich gut.\", \"translated\": \"味道真的很好。\"}]', 12, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Können Sie mir 10 gängige Ausdrücke für Restaurants nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke rund um das Thema Restaurant – inklusive englischer Übersetzung:\"]', '[\"Essen (im Restaurant)\", \"Bestellen\", \"Bezahlen / Abrechnen\"]', 'de', '[\"Vorläufig: Haben Sie eine konkrete Situation im Kopf – etwa Getränke bestellen, sich beschweren oder nach Zutaten fragen? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Entschuldigung, wie lange dauert es noch, bis unser Essen kommt?\", \"translated\": \"Excuse me, how much longer will our food be?\"}, {\"original\": \"Ein Tisch für zwei, bitte.\", \"translated\": \"A table for two, please.\"}, {\"original\": \"Könnten wir bitte die Speisekarte sehen?\", \"translated\": \"Could we see the menu, please?\"}, {\"original\": \"Haben Sie besondere Empfehlungen oder Signature-Dishes?\", \"translated\": \"Do you have any signature dishes to recommend?\"}, {\"original\": \"Ich möchte dies hier und das hier bestellen.\", \"translated\": \"I\'d like to order this, and this.\"}, {\"original\": \"Ein Glas Wasser, bitte. Danke.\", \"translated\": \"A glass of water, please. Thanks.\"}, {\"original\": \"Die Rechnung, bitte.\", \"translated\": \"The bill, please.\"}, {\"original\": \"Kann ich mit Kreditkarte bezahlen?\", \"translated\": \"Can I pay by credit card?\"}, {\"original\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\", \"translated\": \"Could you pack this to go, please?\"}, {\"original\": \"Das Essen war köstlich, vielen Dank!\", \"translated\": \"The food was delicious, thank you.\"}]', 1, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Hotels nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke rund um Hotels – jeweils mit englischer Übersetzung:\"]', '[\"Check-in\", \"Check-out\", \"Zimmerservice\"]', 'de', '[\"Im Moment: Haben Sie eine konkrete Situation im Kopf, z. B. Zimmerlage, weitere Hoteldienstleistungen oder Check-out? Fragen Sie ruhig nach.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Hallo, ich habe eine Reservierung. Hier ist mein Reisepass.\", \"translated\": \"Hello, I have a reservation, Here is my passport.\"}, {\"original\": \"Haben Sie noch freie Zimmer?\", \"translated\": \"Do you have any vacancies?\"}, {\"original\": \"Entschuldigung, hat das Hotel einen Fitnessraum oder eine Waschküche?\", \"translated\": \"Excuse me, does the hotel have a gym or a laundry room?\"}, {\"original\": \"Wann beginnt das Frühstück?\", \"translated\": \"What time does breakfast start?\"}, {\"original\": \"Könnte ich bitte den Zimmerschlüssel haben?\", \"translated\": \"Could I have a room key, please?\"}, {\"original\": \"Könnten Sie mir beim Tragen meines Gepäcks aufs Zimmer helfen?\", \"translated\": \"Could you help me take my luggage to the room?\"}, {\"original\": \"Wie rufe ich den Zimmerservice an?\", \"translated\": \"How do I call room service?\"}, {\"original\": \"Wann ist der Check-out?\", \"translated\": \"What time is check-out?\"}, {\"original\": \"Könnten Sie mir bitte eine Quittung / Rechnung ausstellen?\", \"translated\": \"Could you write me a receipt/invoice?\"}, {\"original\": \"Kann ich mein Gepäck hier lassen?\", \"translated\": \"Can I leave my luggage here?\"}]', 2, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Phrasen für den Flughafen nennen?\", \"Toll! Hier sind 10 gängige Phrasen zum Thema Flughafen – inklusive englischer Übersetzung:\"]', '[\"Check-in\", \"Boarding\", \"Gepäckabgabe\"]', 'de', '[\"Gibt es gerade eine konkrete Situation im Kopf – zum Beispiel Check-in, Gepäckausgabe oder Mietwagen-Service? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wo ist der Check-in-Schalter?\", \"translated\": \"Where is the check-in counter?\"}, {\"original\": \"Ich hätte gerne einen Fensterplatz, bitte.\", \"translated\": \"I\'d like a window seat, please.\"}, {\"original\": \"Ist dieser Flug verspätet?\", \"translated\": \"Is this flight delayed?\"}, {\"original\": \"Ich muss dieses Gepäck aufgeben.\", \"translated\": \"I need to check this baggage.\"}, {\"original\": \"Wo ist das Boarding-Gate?\", \"translated\": \"Where is the boarding gate?\"}, {\"original\": \"Das Flugzeug startet gleich.\", \"translated\": \"The plane is about to take off.\"}, {\"original\": \"Muss ich meinen Laptop und meine externe Batterie herausnehmen?\", \"translated\": \"Do I need to take out my laptop and power bank?\"}, {\"original\": \"Wo ist der Duty-free-Shop?\", \"translated\": \"Where is the duty-free shop?\"}, {\"original\": \"Ich kann meinen Koffer nicht finden.\", \"translated\": \"I can\'t find my suitcase.\"}, {\"original\": \"Bieten Sie einen Rollstuhlservice an?\", \"translated\": \"Do you have a wheelchair service?\"}]', 3, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für öffentliche Verkehrsmittel nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke rund um öffentliche Verkehrsmittel – inklusive englischer Übersetzung:\"]', '[\"Mit Bus/U-Bahn fahren\", \"Tickets kaufen\", \"Umsteigen\"]', 'de', '[\"Im Moment: Haben Sie eine konkrete Situation im Kopf, z. B. nach einer Bushaltestelle, dem Ticketpreis oder dem Aussteigen? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Fährt dieser Bus zum Terminal?\", \"translated\": \"Does this bus go to the terminal?\"}, {\"original\": \"Was ist die nächste Haltestelle?\", \"translated\": \"What is the next stop?\"}, {\"original\": \"Wo kann ich ein Ticket kaufen?\", \"translated\": \"Where can I buy a ticket?\"}, {\"original\": \"Ein Ticket nach XX, bitte.\", \"translated\": \"One ticket to XX, please.\"}, {\"original\": \"Muss ich umsteigen?\", \"translated\": \"Do I need to transfer?\"}, {\"original\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\", \"translated\": \"How long until the next subway train?\"}, {\"original\": \"Entschuldigung, dürfen Sie mich bitte vorbeilassen?\", \"translated\": \"Excuse me, please let me pass.\"}, {\"original\": \"Ist dieser Platz schon besetzt?\", \"translated\": \"Is this seat taken?\"}, {\"original\": \"Entschuldigung, wo kann ich umsteigen, um mit der Linie 2 nach XX zu gelangen?\", \"translated\": \"Excuse me, where can I transfer to Line 2 to get to XX?\"}, {\"original\": \"Wie komme ich nach XX?\", \"translated\": \"How do I get to XX?\"}]', 4, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für touristische Sehenswürdigkeiten nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zu touristischen Sehenswürdigkeiten – jeweils mit englischer Übersetzung:\"]', '[\"Sehenswürdigkeiten besichtigen\", \"Fotos machen\", \"Tickets kaufen\"]', 'de', '[\"Gerne! Haben Sie gerade eine konkrete Situation im Kopf – etwa nach dem Eintrittspreis fragen, nach einem Parkplatz suchen oder nach einer Führung fragen? Fragen Sie einfach los!\", \"Bitte beschreiben Sie die Situation, die Ihnen gerade im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"How much is the entrance fee?\"}, {\"original\": \"Gibt es ermäßigte Tickets für Schüler?\", \"translated\": \"Are there student tickets available?\"}, {\"original\": \"Wann öffnet die Sehenswürdigkeit?\", \"translated\": \"What time does the attraction open?\"}, {\"original\": \"Was kann man hier Lustiges unternehmen?\", \"translated\": \"What are the fun things to do here?\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"Wo ist der Sightseeing-Bus?\", \"translated\": \"Where is the sightseeing bus?\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"Wo ist der beste Aussichtspunkt?\", \"translated\": \"Where is the best viewing spot?\"}, {\"original\": \"Die Landschaft hier ist wunderschön.\", \"translated\": \"The scenery here is beautiful.\"}, {\"original\": \"Gibt es eine Führung?\", \"translated\": \"Is there a guided tour available?\"}]', 5, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Taxis oder Taxidienste nennen?\", \"Toll! Hier sind 10 gängige Ausdrücke rund um Taxis oder Taxidienste – inklusive englischer Übersetzungen:\"]', '[\"Taxi nehmen\", \"Zielort angeben\", \"Bezahlen\"]', 'de', '[\"Was möchten Sie gerade am liebsten tun – etwa nach dem Zielort fragen, den Preis erfragen oder eine Quittung anfordern? Fragen Sie einfach los!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', '[]', '[{\"original\": \"Wo kann ich ein Taxi bekommen?\", \"translated\": \"Where can I get a taxi?\"}, {\"original\": \"Bitte fahren Sie mich zu dieser Adresse.\", \"translated\": \"Please take me to this address.\"}, {\"original\": \"Wie viel kostet das ungefähr?\", \"translated\": \"Roughly how much will it be?\"}, {\"original\": \"Könnten Sie bitte den Taxameter benutzen?\", \"translated\": \"Could you use the meter, please?\"}, {\"original\": \"Fahren Sie bitte etwas schneller, ich habe es eilig.\", \"translated\": \"Please drive a bit faster, I\'m in a hurry.\"}, {\"original\": \"Bitte halten Sie hier an.\", \"translated\": \"Please stop here.\"}, {\"original\": \"Akzeptieren Sie Karten oder mobile Zahlungen?\", \"translated\": \"Do you accept cards or mobile payments?\"}, {\"original\": \"Könnte ich bitte eine Quittung haben?\", \"translated\": \"Could I have a receipt, please?\"}, {\"original\": \"Danke, Fahrer.\", \"translated\": \"Thank you, driver.\"}, {\"original\": \"Wie weit ist es noch?\", \"translated\": \"How much further is it?\"}]', 6, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 häufig verwendete Ausdrücke für die Apotheke nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit der Apotheke – inklusive englischer Übersetzung.\"]', '[\"Medikamente kaufen\", \"Beratung\", \"Bezahlung\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf, z. B. Fragen zur Einnahme von Medikamenten, zur Verwendung Ihrer Versicherungskarte oder zur Dauer der Behandlung? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Haben Sie Erkältungsmedikamente?\", \"translated\": \"Do you have cold medicine?\"}, {\"original\": \"Wie soll ich dieses Medikament einnehmen?\", \"translated\": \"How should I take this medicine?\"}, {\"original\": \"Haben Sie irgendwelche Schmerzmittel?\", \"translated\": \"Do you have any painkillers?\"}, {\"original\": \"Gibt es eine Gebrauchsanweisung?\", \"translated\": \"Is there an instruction leaflet?\"}, {\"original\": \"Hat dieses Medikament Nebenwirkungen?\", \"translated\": \"Does this medicine have any side effects?\"}, {\"original\": \"Kann ich meine Krankenversicherungskarte benutzen?\", \"translated\": \"Can I use my medical insurance card?\"}, {\"original\": \"Könnten Sie mir bitte eine Packung Pflaster geben?\", \"translated\": \"Could I have a box of Band-Aids, please?\"}, {\"original\": \"Haben Sie Fieber senkende Mittel?\", \"translated\": \"Do you have any fever reducers?\"}, {\"original\": \"Ich habe mir leicht die Haut aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\", \"translated\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\"}, {\"original\": \"Wann schließen Sie?\", \"translated\": \"What time do you close?\"}]', 7, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 häufig verwendete Ausdrücke für den Notdienst nennen?\", \"Fantastisch! Hier sind 10 häufig verwendete Ausdrücke zum Thema Notdienst samt englischer Übersetzung:\"]', '[\"Polizei rufen\", \"Erste Hilfe\", \"Hilfe rufen\"]', 'de', '[\"Gerade jetzt: Haben Sie eine bestimmte Notfallsituation im Kopf, z. B. Brand, Verletzung und Hilfebedarf, Notruf – fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Bitte rufen Sie einen Krankenwagen für mich.\", \"translated\": \"Please help me call an ambulance.\"}, {\"original\": \"Wo ist das Krankenhaus?\", \"translated\": \"Where is the hospital?\"}, {\"original\": \"Jemand ist verletzt.\", \"translated\": \"Someone is injured.\"}, {\"original\": \"Bitte helfen Sie mir.\", \"translated\": \"Please help me.\"}, {\"original\": \"Wo ist die Polizeistation?\", \"translated\": \"Where is the police station?\"}, {\"original\": \"Ich habe meine Sachen verloren.\", \"translated\": \"I\'ve lost my belongings.\"}, {\"original\": \"Wie lautet die Notrufnummer für die Feuerwehr?\", \"translated\": \"What is the number for the fire department?\"}, {\"original\": \"Ich habe meinen Pass verloren. Wissen Sie, wo die nächste Polizeistation ist?\", \"translated\": \"I\'ve lost my passport. Do you know where the nearest police station is?\"}, {\"original\": \"Gibt es einen Notausgang?\", \"translated\": \"Is there an emergency exit?\"}, {\"original\": \"Jemand ist in Ohnmacht gefallen.\", \"translated\": \"Someone has fainted.\"}]', 8, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 gängige Ausdrücke für den Strand oder am Pool nennen?\", \"Toll! Hier sind 10 gängige Ausdrücke zum Thema Strand oder Pool – jeweils mit englischer Übersetzung:\"]', '[\"Schwimmen\", \"Sonnenbaden\", \"Strandsport\"]', 'de', '[\"Für den Moment: Können Sie mir bitte den Hintergrund der lokalen Veranstaltung oder des Festes nennen, an dem Sie teilnehmen – z. B. ein Kulturfestival, ein Food-Festival oder ein Musikfestival? Bitte geben Sie den Kontext an.\", \"Bitte nennen Sie die Aktivitäten, an denen Sie teilnehmen.\"]', '[\"Haben Sie eine konkrete Situation im Kopf? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[{\"original\": \"Schau mal! Die Wellen dort drüben sind wirklich groß.\", \"translated\": \"Look! The waves over there are really big.\"}, {\"original\": \"Vergiss nicht, Sonnencreme aufzutragen – die UV-Strahlen hier sind sehr stark.\", \"translated\": \"Remember to apply sunscreen, the UV rays here are very strong.\"}, {\"original\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle gehen.\", \"translated\": \"The sand on this beach is so fine, it feels like stepping on cotton.\"}, {\"original\": \"Wie wäre es mit einer Runde Volleyball am Strand?\", \"translated\": \"How about playing volleyball on the beach?\"}, {\"original\": \"Die Segelboote in der Ferne sehen wunderschön aus.\", \"translated\": \"The sailboats in the distance look beautiful.\"}, {\"original\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\", \"translated\": \"The water here is so clear, you can even see the fish.\"}, {\"original\": \"Lass uns ein paar Muscheln suchen.\", \"translated\": \"Let\'s go find some seashells.\"}, {\"original\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\", \"translated\": \"Taking a walk on the beach at sunset must be very romantic.\"}, {\"original\": \"Ich habe gehört, dass die Meeresfrüchte hier sehr frisch sind – lass uns welche probieren!\", \"translated\": \"I heard the seafood here is very fresh, let\'s go try some.\"}, {\"original\": \"Die Flut kommt herein – lass uns Richtung Ufer gehen.\", \"translated\": \"The tide is coming in, let\'s head towards the shore.\"}]', 9, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für lokale Aktivitäten und Feste nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zu lokalen Aktivitäten und Festen – inklusive englischer Übersetzung:\"]', '[\"Veranstaltungen besuchen\", \"Feste feiern\", \"Kultur kennenlernen\"]', 'de', '[\"Könnten Sie mir vorerst den Kontext der lokalen Veranstaltung oder des Festes, an dem Sie teilnehmen möchten, nennen? Zum Beispiel Halloween, ein Konzert, eine Freundesparty oder etwas anderes? Bitte geben Sie den Kontext an.\", \"Bitte beschreiben Sie die Aktivitäten, die Ihnen vorschweben.\"]', '[\"Haben Sie eine konkrete Situation im Kopf? Fragen Sie ruhig frei nach.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[{\"original\": \"Gibt es heute irgendwelche Veranstaltungen?\", \"translated\": \"Are there any events today?\"}, {\"original\": \"Gibt es bei diesem Festival etwas Besonderes?\", \"translated\": \"Is there anything special about this festival?\"}, {\"original\": \"Wo findet die Feier statt?\", \"translated\": \"Where is the celebration being held?\"}, {\"original\": \"Wie kann ich Tickets kaufen?\", \"translated\": \"How can I buy tickets?\"}, {\"original\": \"Wann beginnt die Vorstellung?\", \"translated\": \"What time does the performance start?\"}, {\"original\": \"Welche traditionellen Speisen gibt es?\", \"translated\": \"What traditional food is there?\"}, {\"original\": \"Es ist hier wirklich lebendig.\", \"translated\": \"It\'s really lively here.\"}, {\"original\": \"Gibt es Volksaktivitäten?\", \"translated\": \"Are there any folk activities?\"}, {\"original\": \"Frohe Feiertage!\", \"translated\": \"Happy holidays!\"}, {\"original\": \"Wann endet die Veranstaltung?\", \"translated\": \"What time does the event end?\"}]', 10, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gebräuchliche Phrasen für Museen oder Kunstmuseen nennen?\", \"Fantastisch! Hier sind 10 gebräuchliche Phrasen zu Museen oder Kunstmuseen samt englischer Übersetzung:\"]', '[\"Besuch\", \"Geführte Tour\", \"Eintrittskarten kaufen\"]', 'de', '[\"Für den Augenblick – Haben Sie eine konkrete Situation im Kopf, z. B. die Nachfrage nach einem Einführungsflyer, Phrasen zum Ausstellungsplan oder zum Kommentieren von Exponaten? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"How much is the admission fee?\"}, {\"original\": \"Haben Sie Audioführungen?\", \"translated\": \"Do you have audio guides?\"}, {\"original\": \"Wer hat dieses Kunstwerk geschaffen?\", \"translated\": \"Who created this artwork?\"}, {\"original\": \"Wo befindet sich das wertvollste Stück des Museums?\", \"translated\": \"Where is the museum\'s most prized piece?\"}, {\"original\": \"Ist Fotografieren erlaubt?\", \"translated\": \"Is photography allowed?\"}, {\"original\": \"Gibt es hier besondere Ausstellungen?\", \"translated\": \"Are there any special exhibitions here?\"}, {\"original\": \"Wie lange dauert der Besuch?\", \"translated\": \"How long does the visit take?\"}, {\"original\": \"Könnten Sie uns bitte eine Einführung geben?\", \"translated\": \"Could you give us an introduction?\"}, {\"original\": \"Diese Werke sind wirklich exquisit.\", \"translated\": \"These works are truly exquisite.\"}, {\"original\": \"Wo befindet sich der Souvenirladen?\", \"translated\": \"Where is the souvenir shop?\"}]', 11, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich in einem Café verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke rund um das Thema Café – inklusive englischer Übersetzung:\"]', '[\"Kaffee bestellen\", \"Ausruhen\", \"Sozialisieren\"]', 'de', '[\"Vorerst – Haben Sie eine bestimmte Situation im Kopf, z. B. nach der Speisekarte fragen, nach kalten oder heißen Getränken, nach anderen Produkten? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Ich nehme einen Latte, bitte.\", \"translated\": \"I\'ll have a latte, please.\"}, {\"original\": \"Haben Sie WLAN?\", \"translated\": \"Do you have Wi-Fi?\"}, {\"original\": \"Könnte ich bitte die Speisekarte sehen?\", \"translated\": \"Could I see the menu, please?\"}, {\"original\": \"Darf ich nachfüllen lassen?\", \"translated\": \"Are refills allowed?\"}, {\"original\": \"Ist mein Kaffee schon fertig?\", \"translated\": \"Is my coffee ready?\"}, {\"original\": \"Wie lange darf ich hier sitzen?\", \"translated\": \"How long can I sit here?\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"Die Rechnung, bitte. Vielen Dank.\", \"translated\": \"Check, please. Thank you.\"}, {\"original\": \"Es schmeckt wirklich gut.\", \"translated\": \"It tastes really good.\"}]', 12, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 gängige Ausdrücke nennen, die ich im Restaurant verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Restaurant samt arabischer Übersetzung:\"]', '[\"Essen\", \"Bestellen\", \"Bezahlen\"]', 'de', '[\"Für den Moment: Haben Sie eine konkrete Situation im Kopf – etwa Bestellen von Getränken, Beschwerde äußern oder Fragen zu Zutaten? Fühlen Sie sich frei, danach zu fragen.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Entschuldigung, wie lange dauert es noch, bis unser Essen kommt?\", \"translated\": \"عذرًا، كم من الوقت سيستغرق وصول طعامنا؟\"}, {\"original\": \"Ein Tisch für zwei Personen, bitte.\", \"translated\": \"طاولة لشخصين، من فضلكم.\"}, {\"original\": \"Könnten wir bitte die Speisekarte sehen?\", \"translated\": \"هل يمكننا رؤية قائمة الطعام، من فضلكم؟\"}, {\"original\": \"Haben Sie empfehlenswerte Hausgerichte?\", \"translated\": \"هل لديكم أطباق مميزة نوصي بها؟\"}, {\"original\": \"Ich möchte dies und das bestellen.\", \"translated\": \"أود طلب هذا وهذا.\"}, {\"original\": \"Ein Glas Wasser, bitte. Danke.\", \"translated\": \"كوب ماء من فضلكم. شكرًا.\"}, {\"original\": \"Die Rechnung, bitte.\", \"translated\": \"الفاتورة من فضلكم.\"}, {\"original\": \"Kann ich mit Kreditkarte bezahlen?\", \"translated\": \"هل يمكنني الدفع ببطاقة الائتمان؟\"}, {\"original\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\", \"translated\": \"هل يمكنكم تغليف هذا لأأخذه معًا، من فضلكم؟\"}, {\"original\": \"Das Essen war köstlich, danke.\", \"translated\": \"كان الطعام لذيذًا جدًّا، شكرًا لكم.\"}]', 1, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 häufig verwendete Ausdrücke für Hotels nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Hotels sowie deren arabische Übersetzungen:\"]', '[\"Einchecken\", \"Auschecken\", \"Zimmerservice\"]', 'de', '[\"Vorerst: Haben Sie eine bestimmte Situation im Kopf, z. B. Zimmerlage, weitere Hoteldienstleistungen oder das Auschecken? Fragen Sie ruhig nach.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Hallo, ich habe eine Reservierung. Hier ist mein Reisepass.\", \"translated\": \"مرحبًا، لدي حجز. إليكم جواز سفري.\"}, {\"original\": \"Haben Sie noch freie Zimmer?\", \"translated\": \"هل لديكم غرف شاغرة؟\"}, {\"original\": \"Entschuldigung, verfügt das Hotel über ein Fitnessstudio oder eine Wäscherei?\", \"translated\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسيل الملابس؟\"}, {\"original\": \"Wann beginnt das Frühstück?\", \"translated\": \"متى يبدأ الإفطار؟\"}, {\"original\": \"Könnte ich bitte einen Zimmerschlüssel haben?\", \"translated\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\"}, {\"original\": \"Könnten Sie mir bitte beim Tragen meines Gepäcks ins Zimmer helfen?\", \"translated\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة، من فضلكم؟\"}, {\"original\": \"Wie rufe ich den Zimmerservice an?\", \"translated\": \"كيف أطلب خدمة الغرف؟\"}, {\"original\": \"Wann ist die Abreisezeit?\", \"translated\": \"ما هو وقت المغادرة؟\"}, {\"original\": \"Könnten Sie mir bitte eine Quittung / Rechnung ausstellen?\", \"translated\": \"هل يمكنكم إعطائي إيصالًا أو فاتورة، من فضلكم؟\"}, {\"original\": \"Darf ich mein Gepäck hier lassen?\", \"translated\": \"هل يمكنني ترك أمتعتي هنا؟\"}]', 2, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Sätze nennen, die ich am Flughafen verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Sätze zum Thema Flughafen – inklusive arabischer Übersetzungen:\"]', '[\"Check-in\", \"Boarding\", \"Gepäckaufgabe\"]', 'de', '[\"Im Moment: Haben Sie eine bestimmte Situation im Kopf, wie Check-in, Gepäckausgabe oder Autovermietung? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wo ist der Check-in-Schalter?\", \"translated\": \"أين مكان تسجيل الدخول؟\"}, {\"original\": \"Ich hätte gerne einen Fensterplatz, bitte.\", \"translated\": \"أود أن أجلس بالقرب من النافذة، من فضلكم.\"}, {\"original\": \"Ist dieser Flug verspätet?\", \"translated\": \"هل هذا الرحلة مؤجلة؟\"}, {\"original\": \"Ich muss dieses Gepäck aufgeben.\", \"translated\": \"يجب أن أودع هذه الأمتعة.\"}, {\"original\": \"Wo ist das Boarding-Gate?\", \"translated\": \"أين بوابة الصعود إلى الطائرة؟\"}, {\"original\": \"Das Flugzeug startet gleich.\", \"translated\": \"الطائرة على وشك الإقلاع.\"}, {\"original\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\", \"translated\": \"هل يجب أن أخرج جهازي اللوحي والبنك الكهربائي من الحقيبة؟\"}, {\"original\": \"Wo ist der Duty-free-Shop?\", \"translated\": \"أين متجر التجزئة الخالي من الرسوم الجمركية؟\"}, {\"original\": \"Ich finde meinen Koffer nicht.\", \"translated\": \"لا أستطيع العثور على حقيبتي.\"}, {\"original\": \"Bieten Sie einen Rollstuhl-Service an?\", \"translated\": \"هل تقدمون خدمة كرسي متحرك؟\"}]', 3, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für öffentliche Verkehrsmittel nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema öffentliche Verkehrsmittel mit arabischen Übersetzungen:\"]', '[\"Mit Bus/U-Bahn fahren\", \"Tickets kaufen\", \"Umsteigen\"]', 'de', '[\"Vorläufig: Haben Sie eine konkrete Situation im Kopf – z. B. Fragen nach einer Bushaltestelle, dem Ticketpreis oder dem Aussteigen? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Fährt dieser Bus zum Terminal?\", \"translated\": \"هل تصل هذه الحافلة إلى المحطة النهائية؟\"}, {\"original\": \"Was ist die nächste Haltestelle?\", \"translated\": \"ما هي المحطة التالية؟\"}, {\"original\": \"Wo kann ich ein Ticket kaufen?\", \"translated\": \"أين يمكنني شراء تذكرة؟\"}, {\"original\": \"Ein Ticket nach XX, bitte.\", \"translated\": \"تذكرة واحدة إلى XX، من فضلك.\"}, {\"original\": \"Muss ich umsteigen?\", \"translated\": \"هل يجب أن أغير وسيلة النقل؟\"}, {\"original\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\", \"translated\": \"كم من الوقت يتبقى حتى قطار المترو القادم؟\"}, {\"original\": \"Entschuldigung, bitte lassen Sie mich durch.\", \"translated\": \"عذراً، من فضلك اتركني أعبر.\"}, {\"original\": \"Ist dieser Platz schon besetzt?\", \"translated\": \"هل هذا المقعد محجوز بالفعل؟\"}, {\"original\": \"Entschuldigung, wo kann ich zur Linie 2 umsteigen, um nach XX zu gelangen?\", \"translated\": \"عذراً، أين يمكنني التحويل إلى الخط ٢ للوصول إلى XX؟\"}, {\"original\": \"Wie komme ich nach XX?\", \"translated\": \"كيف أصل إلى XX؟\"}]', 4, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Können Sie mir 10 gängige Ausdrücke für touristische Sehenswürdigkeiten nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zu touristischen Sehenswürdigkeiten – jeweils mit arabischer Übersetzung:\"]', '[\"Sehenswürdigkeiten besichtigen\", \"Fotos machen\", \"Eintrittskarten kaufen\"]', 'de', '[\"Im Moment: Haben Sie eine konkrete Situation im Kopf, z. B. Fragen zum Eintrittspreis, Suche nach einem Parkplatz oder nach einer Führung – fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"كم تكلفة رسوم الدخول؟\"}, {\"original\": \"Gibt es ermäßigte Eintrittskarten für Schüler und Studenten?\", \"translated\": \"هل تتوفر تذاكر مُخفضة للطلاب؟\"}, {\"original\": \"Wann öffnet die Sehenswürdigkeit?\", \"translated\": \"في أي وقت تفتح معالم الجذب؟\"}, {\"original\": \"Was kann man hier Lustiges unternehmen?\", \"translated\": \"ما الأنشطة الممتعة التي يمكن القيام بها هنا؟\"}, {\"original\": \"Könnten Sie uns bitte ein Foto machen?\", \"translated\": \"هل يمكنك التصوير لنا، من فضلك؟\"}, {\"original\": \"Wo befindet sich der Sightseeing-Bus?\", \"translated\": \"أين يقع حافلة الجولات السياحية؟\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"أين توجد دورة المياه؟\"}, {\"original\": \"Wo ist der beste Aussichtspunkt?\", \"translated\": \"أين أفضل مكان للاستمتاع بالمنظر؟\"}, {\"original\": \"Die Landschaft hier ist wunderschön.\", \"translated\": \"الطبيعة هنا جميلة جدًّا.\"}, {\"original\": \"Gibt es eine Führung durch die Sehenswürdigkeit?\", \"translated\": \"هل تتوفر جولة إرشادية في المعلم السياحي؟\"}]', 5, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Taxi- oder Taxidienste nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Taxi- oder Taxidienste – jeweils mit arabischer Übersetzung:\"]', '[\"Taxi nehmen\", \"Ziel angeben\", \"Bezahlen\"]', 'de', '[\"Im Moment: Was möchten Sie am liebsten tun – z. B. nach dem Ziel fragen, nach dem Preis, oder nach einer Rechnung? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen gerade in den Sinn kommt.\"]', '[]', '[{\"original\": \"Wo kann ich ein Taxi bekommen?\", \"translated\": \"أين يمكنني الحصول على تاكسي؟\"}, {\"original\": \"Bitte bringen Sie mich zu dieser Adresse.\", \"translated\": \"من فضلك خذني إلى هذا العنوان.\"}, {\"original\": \"Wie viel wird es ungefähr kosten?\", \"translated\": \"كم سيكون السعر تقريبًا؟\"}, {\"original\": \"Könnten Sie bitte den Taxameter benutzen?\", \"translated\": \"هل يمكنك استخدام عداد التاكسي من فضلك؟\"}, {\"original\": \"Bitte fahren Sie etwas schneller, ich habe es eilig.\", \"translated\": \"من فضلك اقُدّ بسرعة أكبر قليلًا، فأنا مستعجل.\"}, {\"original\": \"Bitte halten Sie hier an.\", \"translated\": \"من فضلك توقف هنا.\"}, {\"original\": \"Akzeptieren Sie Karten oder mobile Zahlungen?\", \"translated\": \"هل تقبلون الدفع بالبطاقات أو عبر الهاتف المحمول؟\"}, {\"original\": \"Könnte ich bitte eine Quittung haben?\", \"translated\": \"هل يمكنني الحصول على إيصال، من فضلك؟\"}, {\"original\": \"Danke, Fahrer.\", \"translated\": \"شكرًا لك يا سائق.\"}, {\"original\": \"Wie weit ist es noch?\", \"translated\": \"كم تبقى من المسافة؟\"}]', 6, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gebräuchliche Redewendungen für die Apotheke nennen?\", \"Fantastisch! Hier sind 10 gebräuchliche Redewendungen im Zusammenhang mit der Apotheke sowie deren arabischen Übersetzungen:\"]', '[\"Medikamente kaufen\", \"Beratung\", \"Zahlung\"]', 'de', '[\"Vorläufig: Haben Sie eine bestimmte Situation im Kopf, z. B. Fragen zur Einnahme von Medikamenten, zum Einsatz der Krankenversicherung oder zur Dauer der Behandlung? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Haben Sie Erkältungsmedikamente?\", \"translated\": \"هل لديكم أدوية للبرد؟\"}, {\"original\": \"Wie soll ich dieses Medikament einnehmen?\", \"translated\": \"كيف يجب أن آخذ هذه الأدوية؟\"}, {\"original\": \"Haben Sie irgendwelche Schmerzmittel?\", \"translated\": \"هل لديكم أي مسكنات للألم؟\"}, {\"original\": \"Gibt es eine Gebrauchsanweisung?\", \"translated\": \"هل توجد نشرة إرشادات الاستخدام؟\"}, {\"original\": \"Hat dieses Medikament Nebenwirkungen?\", \"translated\": \"هل لهذا الدواء آثار جانبية؟\"}, {\"original\": \"Kann ich meine Krankenversicherungskarte verwenden?\", \"translated\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\"}, {\"original\": \"Könnte ich bitte eine Packung Pflaster haben?\", \"translated\": \"هل يمكنني الحصول على علبة من الجبائر، من فضلكم؟\"}, {\"original\": \"Haben Sie Fieber senkende Mittel?\", \"translated\": \"هل لديكم أدوية خافضة للحرارة؟\"}, {\"original\": \"Ich habe mir leicht die Haut aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\", \"translated\": \"لقد أصبتُ بجرح سطحي بسيط. هل لديكم مطهر وجبائر؟\"}, {\"original\": \"Wann schließen Sie?\", \"translated\": \"متى تغلقون؟\"}]', 7, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Redewendungen für den Notdienst nennen?\", \"Fantastisch! Hier sind 10 gängige Redewendungen zum Thema Notdienst – jeweils mit arabischer Übersetzung:\"]', '[\"Polizei rufen\", \"Erste Hilfe\", \"Hilfe rufen\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Notsituation im Kopf, z. B. Brand, Verletzung und Hilfebedarf, Notruf? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Bitte rufen Sie einen Krankenwagen für mich.\", \"translated\": \"من فضلك اتصل بالإسعاف من أجلي.\"}, {\"original\": \"Wo ist das Krankenhaus?\", \"translated\": \"أين يوجد المستشفى؟\"}, {\"original\": \"Jemand ist verletzt.\", \"translated\": \"شخص ما أُصيب.\"}, {\"original\": \"Bitte helfen Sie mir.\", \"translated\": \"من فضلك ساعدني.\"}, {\"original\": \"Wo ist die Polizeistation?\", \"translated\": \"أين تقع مركز الشرطة؟\"}, {\"original\": \"Ich habe meine Sachen verloren.\", \"translated\": \"لقد فقدت أغراضي.\"}, {\"original\": \"Wie lautet die Notrufnummer für die Feuerwehr?\", \"translated\": \"ما رقم الطوارئ الخاص بالإطفاء؟\"}, {\"original\": \"Ich habe meinen Pass verloren. Wissen Sie, wo die nächste Polizeistation ist?\", \"translated\": \"لقد فقدت جواز سفري. هل تعرف أين يقع أقرب مركز شرطة؟\"}, {\"original\": \"Gibt es einen Notausgang?\", \"translated\": \"هل يوجد مخرج طوارئ؟\"}, {\"original\": \"Jemand ist in Ohnmacht gefallen.\", \"translated\": \"شخص ما أُغمي عليه.\"}]', 8, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 gängige Ausdrücke für Strand oder Pool bereitstellen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Strand oder Pool samt arabischer Übersetzung:\"]', '[\"Schwimmen\", \"Sonnenbaden\", \"Strandsport\"]', 'de', '[\"Bitte teilen Sie mir vorerst den Kontext des lokalen Ereignisses oder Festes mit, an dem Sie teilnehmen – z. B. ein Kulturfestival, ein kulinarisches Festival oder ein Musikfestival. Geben Sie bitte den Kontext an.\", \"Bitte beschreiben Sie die Aktivitäten, an denen Sie teilnehmen.\"]', '[\"Haben Sie bereits eine konkrete Situation im Kopf? Fragen Sie ruhig frei nach.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[{\"original\": \"Schau mal! Die Wellen dort drüben sind wirklich groß.\", \"translated\": \"انظر! الأمواج هناك كبيرة جدًا.\"}, {\"original\": \"Vergiss nicht, Sonnencreme aufzutragen – die UV-Strahlen sind hier sehr stark.\", \"translated\": \"لا تنسَ وضع واقي شمسي، فأشعة فوق البنفسجية هنا قوية جدًا.\"}, {\"original\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle gehen.\", \"translated\": \"الرمل على هذا الشاطئ ناعم جدًا لدرجة أنك تشعر وكأنك تمشي على القطن.\"}, {\"original\": \"Wie wäre es mit einem Volleyballspiel am Strand?\", \"translated\": \"كيف يكون لعب الكرة الطائرة على الشاطئ؟\"}, {\"original\": \"Die Segelboote in der Ferne sehen wunderschön aus.\", \"translated\": \"القوارب الشراعية في الأفق تبدو جميلة جدًا.\"}, {\"original\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\", \"translated\": \"الماء هنا شفافٌ جدًا لدرجة أنك تستطيع رؤية الأسماك.\"}, {\"original\": \"Lass uns nach Muscheln suchen.\", \"translated\": \"هيا بنا نبحث عن المحار.\"}, {\"original\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\", \"translated\": \"المشي على الشاطئ عند غروب الشمس لا بد أنه أمرٌ رومانسيٌ جدًا.\"}, {\"original\": \"Ich habe gehört, dass die Meeresfrüchte hier sehr frisch sind – lass uns welche probieren!\", \"translated\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًا، فلنجرّب بعضها!\"}, {\"original\": \"Die Flut kommt herein – lass uns zum Ufer gehen.\", \"translated\": \"المدّ يقترب، فلنعد إلى الساحل.\"}]', 9, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Redewendungen für lokale Veranstaltungen und Feste nennen?\", \"Fantastisch! Hier sind 10 gängige Redewendungen zu lokalen Veranstaltungen und Festen – inklusive arabischer Übersetzungen:\"]', '[\"Veranstaltungen besuchen\", \"Feste feiern\", \"Kultur kennenlernen\"]', 'de', '[\"Könnten Sie mir vorerst den Kontext der lokalen Veranstaltung oder des Festes, an dem Sie teilnehmen möchten, nennen? Zum Beispiel Halloween, ein Konzert, eine private Party oder etwas anderes? Bitte geben Sie den Kontext an.\", \"Bitte beschreiben Sie die Aktivitäten, die Ihnen im Kopf herumgehen.\"]', '[\"Haben Sie eine konkrete Situation im Kopf? Fragen Sie ruhig danach.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[{\"original\": \"Gibt es heute irgendwelche Veranstaltungen?\", \"translated\": \"هل هناك أي فعاليات اليوم؟\"}, {\"original\": \"Gibt es etwas Besonderes an diesem Fest?\", \"translated\": \"هل هناك شيء مميز في هذه المهرجان؟\"}, {\"original\": \"Wo findet die Feier statt?\", \"translated\": \"أين تُقام الاحتفالات؟\"}, {\"original\": \"Wie kann ich Eintrittskarten kaufen?\", \"translated\": \"كيف يمكنني شراء التذاكر؟\"}, {\"original\": \"Wann beginnt die Aufführung?\", \"translated\": \"في أي وقت تبدأ العرض؟\"}, {\"original\": \"Welche traditionellen Speisen gibt es?\", \"translated\": \"ما الأطعمة التقليدية المتوفرة؟\"}, {\"original\": \"Es ist hier wirklich lebendig.\", \"translated\": \"المكان حيويٌّ للغاية.\"}, {\"original\": \"Gibt es volkskulturelle Aktivitäten?\", \"translated\": \"هل هناك أنشطة شعبية؟\"}, {\"original\": \"Frohe Feiertage!\", \"translated\": \"أعياد سعيدة!\"}, {\"original\": \"Wann endet die Veranstaltung?\", \"translated\": \"في أي وقت تنتهي الفعالية؟\"}]', 10, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 gebräuchliche Wendungen nennen, die ich im Museum oder in der Kunstgalerie verwenden kann?\", \"Fantastisch! Hier sind 10 gebräuchliche Wendungen zum Thema Museum oder Kunstgalerie samt arabischer Übersetzung:\"]', '[\"Besuch\", \"Geführte Tour\", \"Tickets kaufen\"]', 'de', '[\"Vorläufig: Haben Sie eine bestimmte Situation im Kopf, z. B. das Nachfragen nach einem Einführungsfaltblatt, Wendungen zum Rundgang oder zur Kommentierung von Exponaten? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"Haben Sie Audio-Führungen?\", \"translated\": \"هل لديكم أدلة صوتية؟\"}, {\"original\": \"Wer hat dieses Kunstwerk geschaffen?\", \"translated\": \"من صنع هذه القطعة الفنية؟\"}, {\"original\": \"Wo befindet sich das wertvollste Stück des Museums?\", \"translated\": \"أين تقع أثمن قطعة في المتحف؟\"}, {\"original\": \"Ist Fotografieren erlaubt?\", \"translated\": \"هل يُسمح بالتقاط الصور؟\"}, {\"original\": \"Gibt es hier besondere Ausstellungen?\", \"translated\": \"هل توجد هنا معارض خاصة؟\"}, {\"original\": \"Wie lange dauert der Besuch?\", \"translated\": \"كم تدوم الزيارة؟\"}, {\"original\": \"Könnten Sie uns eine Einführung geben?\", \"translated\": \"هل يمكنكم أن تقدّموا لنا عرضاً تمهيدياً؟\"}, {\"original\": \"Diese Werke sind wirklich exquisit.\", \"translated\": \"هذه الأعمال فعلاً رائعةٌ ومُتقنة.\"}, {\"original\": \"Wo befindet sich der Souvenirladen?\", \"translated\": \"أين يقع متجر الهدايا التذكارية؟\"}]', 11, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 gängige Ausdrücke nennen, die ich in einem Café verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Café samt arabischer Übersetzung:\"]', '[\"Kaffee bestellen\", \"Ausruhen\", \"Sozialisieren\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf – etwa nach der Speisekarte fragen, Eis- oder Heißgetränke bestellen, andere Produkte anfragen? Fühlen Sie sich frei, einfach danach zu fragen.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Ich nehme einen Latte, bitte.\", \"translated\": \"سآخذ لاتيه، من فضلك.\"}, {\"original\": \"Haben Sie WLAN?\", \"translated\": \"هل لديكم اتصال واي فاي؟\"}, {\"original\": \"Könnte ich bitte die Speisekarte sehen?\", \"translated\": \"هل يمكنني رؤية القائمة، من فضلك؟\"}, {\"original\": \"Sind Nachfüllungen erlaubt?\", \"translated\": \"هل يُسمح بإعادة التعبئة؟\"}, {\"original\": \"Ist mein Kaffee fertig?\", \"translated\": \"هل قهوة الكافيين جاهزة؟\"}, {\"original\": \"Wie lange darf ich hier sitzen?\", \"translated\": \"كم من الوقت يُسمح لي بالجلوس هنا؟\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"هل يمكنكم أخذ صورة لنا، من فضلكم؟\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"أين الحمام؟\"}, {\"original\": \"Die Rechnung, bitte. Vielen Dank.\", \"translated\": \"الحساب، من فضلك. شكرًا جزيلًا.\"}, {\"original\": \"Es schmeckt wirklich gut.\", \"translated\": \"إنها تذوق رائعة حقًّا.\"}]', 12, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Restaurant verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Restaurant samt französischen Übersetzungen:\"]', '[\"Essen\", \"Bestellen\", \"Bezahlen\"]', 'de', '[\"Für den Augenblick – Haben Sie eine konkrete Situation im Kopf, etwa Getränke bestellen, eine Beschwerde äußern oder nach Zutaten fragen? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Entschuldigung, wie lange dauert es noch, bis unser Essen kommt?\", \"translated\": \"Excusez-moi, combien de temps encore avant que notre commande ne soit prête ?\"}, {\"original\": \"Ein Tisch für zwei Personen, bitte.\", \"translated\": \"Une table pour deux personnes, s’il vous plaît.\"}, {\"original\": \"Könnten wir bitte die Speisekarte sehen?\", \"translated\": \"Pourrions-nous voir la carte, s’il vous plaît ?\"}, {\"original\": \"Haben Sie typische Gerichte, die Sie empfehlen können?\", \"translated\": \"Avez-vous des plats signature que vous pourriez nous recommander ?\"}, {\"original\": \"Ich möchte dieses und jenes bestellen.\", \"translated\": \"Je voudrais commander ceci et cela.\"}, {\"original\": \"Ein Glas Wasser, bitte. Danke.\", \"translated\": \"Un verre d’eau, s’il vous plaît. Merci.\"}, {\"original\": \"Die Rechnung, bitte.\", \"translated\": \"L’addition, s’il vous plaît.\"}, {\"original\": \"Kann ich mit Kreditkarte bezahlen?\", \"translated\": \"Puis-je payer par carte bancaire ?\"}, {\"original\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\", \"translated\": \"Pourriez-vous emballer cela à emporter, s’il vous plaît ?\"}, {\"original\": \"Das Essen war köstlich, danke.\", \"translated\": \"Le repas était délicieux, merci.\"}]', 1, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Hotels nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Hotels – inklusive französischer Übersetzung:\"]', '[\"Check-in\", \"Check-out\", \"Zimmerservice\"]', 'de', '[\"Im Moment: Haben Sie eine konkrete Situation im Sinn, z. B. Zimmerlage, weitere Hoteldienstleistungen oder Check-out? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Hallo, ich habe eine Reservierung. Hier ist mein Reisepass.\", \"translated\": \"Bonjour, j’ai une réservation. Voici mon passeport.\"}, {\"original\": \"Haben Sie noch freie Zimmer?\", \"translated\": \"Avez-vous des chambres disponibles ?\"}, {\"original\": \"Entschuldigung, hat das Hotel einen Fitnessraum oder eine Wäscherei?\", \"translated\": \"Excusez-moi, l’hôtel dispose-t-il d’une salle de sport ou d’un service de blanchisserie ?\"}, {\"original\": \"Wann beginnt das Frühstück?\", \"translated\": \"À quelle heure commence le petit-déjeuner ?\"}, {\"original\": \"Könnte ich bitte den Zimmerschlüssel haben?\", \"translated\": \"Pourriez-vous me donner la clé de ma chambre, s’il vous plaît ?\"}, {\"original\": \"Könnten Sie mir helfen, mein Gepäck aufs Zimmer zu bringen?\", \"translated\": \"Pourriez-vous m’aider à porter mes bagages jusqu’à ma chambre ?\"}, {\"original\": \"Wie rufe ich den Zimmerservice an?\", \"translated\": \"Comment puis-je joindre le service d’étage ?\"}, {\"original\": \"Wann ist der Check-out?\", \"translated\": \"À quelle heure doit-on quitter la chambre ?\"}, {\"original\": \"Könnten Sie mir bitte eine Quittung / Rechnung ausstellen?\", \"translated\": \"Pourriez-vous me remettre un reçu / une facture, s’il vous plaît ?\"}, {\"original\": \"Kann ich mein Gepäck hier lassen?\", \"translated\": \"Puis-je laisser mes bagages ici ?\"}]', 2, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für den Flughafen nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Flughafen – inklusive französischer Übersetzungen:\"]', '[\"Check-in\", \"Boarding\", \"Gepäckabgabe\"]', 'de', '[\"Im Moment: Haben Sie eine konkrete Situation im Kopf, etwa Check-in, Gepäckausgabe oder Mietwagen-Service? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wo ist der Check-in-Schalter?\", \"translated\": \"Où se trouve le comptoir d\'enregistrement ?\"}, {\"original\": \"Ich hätte gern einen Fensterplatz, bitte.\", \"translated\": \"Je voudrais un siège près du hublot, s\'il vous plaît.\"}, {\"original\": \"Ist dieser Flug verspätet?\", \"translated\": \"Ce vol est-il retardé ?\"}, {\"original\": \"Ich muss dieses Gepäck aufgeben.\", \"translated\": \"Je dois enregistrer ce bagage.\"}, {\"original\": \"Wo ist das Boarding-Gate?\", \"translated\": \"Où se trouve la porte d\'embarquement ?\"}, {\"original\": \"Das Flugzeug startet gleich.\", \"translated\": \"L\'avion va bientôt décoller.\"}, {\"original\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\", \"translated\": \"Dois-je sortir mon ordinateur portable et mon chargeur portable ?\"}, {\"original\": \"Wo ist der Duty-free-Shop?\", \"translated\": \"Où se trouve la boutique hors taxes ?\"}, {\"original\": \"Ich kann meinen Koffer nicht finden.\", \"translated\": \"Je ne trouve pas ma valise.\"}, {\"original\": \"Bieten Sie einen Rollstuhl-Service an?\", \"translated\": \"Proposez-vous un service de fauteuil roulant ?\"}]', 3, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für öffentliche Verkehrsmittel nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema öffentliche Verkehrsmittel samt französischer Übersetzung:\"]', '[\"Mit Bus/U-Bahn fahren\", \"Tickets kaufen\", \"Umsteigen\"]', 'de', '[\"Im Moment: Haben Sie eine konkrete Situation im Kopf, z. B. nach einer Bushaltestelle, dem Ticketpreis oder dem Aussteigen? Fühlen Sie sich frei, danach zu fragen.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Fährt dieser Bus zum Terminal?\", \"translated\": \"Ce bus va-t-il jusqu\'au terminus ?\"}, {\"original\": \"Was ist die nächste Haltestelle?\", \"translated\": \"Quelle est la prochaine station ?\"}, {\"original\": \"Wo kann ich ein Ticket kaufen?\", \"translated\": \"Où puis-je acheter un billet ?\"}, {\"original\": \"Ein Ticket nach XX, bitte.\", \"translated\": \"Un billet pour XX, s\'il vous plaît.\"}, {\"original\": \"Muss ich umsteigen?\", \"translated\": \"Dois-je changer de ligne ?\"}, {\"original\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\", \"translated\": \"Dans combien de temps arrive le prochain métro ?\"}, {\"original\": \"Entschuldigung, bitte lassen Sie mich durch.\", \"translated\": \"Excusez-moi, je vous prie de me laisser passer.\"}, {\"original\": \"Ist dieser Platz besetzt?\", \"translated\": \"Cette place est-elle occupée ?\"}, {\"original\": \"Entschuldigung, wo kann ich umsteigen, um mit der Linie 2 nach XX zu gelangen?\", \"translated\": \"Excusez-moi, où puis-je changer pour prendre la ligne 2 en direction de XX ?\"}, {\"original\": \"Wie komme ich nach XX?\", \"translated\": \"Comment puis-je me rendre à XX ?\"}]', 4, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 häufig verwendete Phrasen für Touristenattraktionen nennen?\", \"Fantastisch! Hier sind 10 gängige Phrasen zu Touristenattraktionen inklusive französischer Übersetzungen:\"]', '[\"Besichtigung\", \"Fotografieren\", \"Tickets kaufen\"]', 'de', '[\"Vorläufig: Haben Sie bereits eine konkrete Situation im Kopf – z. B. nach dem Eintrittspreis fragen, nach einem Parkplatz suchen oder nach einem Führerservice erkundigen? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"Quel est le prix d\'entrée ?\"}, {\"original\": \"Gibt es ermäßigte Tickets für Studenten?\", \"translated\": \"Y a-t-il des billets étudiants disponibles ?\"}, {\"original\": \"Wann öffnet die Sehenswürdigkeit?\", \"translated\": \"À quelle heure ouvre l’attraction ?\"}, {\"original\": \"Was kann man hier Spannendes unternehmen?\", \"translated\": \"Quelles sont les activités amusantes à faire ici ?\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"Pourriez-vous prendre une photo de nous ?\"}, {\"original\": \"Wo befindet sich der Sightseeing-Bus?\", \"translated\": \"Où se trouve le bus touristique ?\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"Wo ist der beste Aussichtspunkt?\", \"translated\": \"Quel est le meilleur point de vue ?\"}, {\"original\": \"Die Landschaft hier ist wunderschön.\", \"translated\": \"Le paysage est magnifique ici.\"}, {\"original\": \"Gibt es eine Führung?\", \"translated\": \"Une visite guidée est-elle disponible ?\"}]', 5, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Phrasen für Taxi- oder Taxidienste nennen?\", \"Fantastisch! Hier sind 10 gängige Phrasen zum Thema Taxi- oder Taxidienste – inklusive französischer Übersetzungen:\"]', '[\"Taxi nehmen\", \"Zielort angeben\", \"Bezahlen\"]', 'de', '[\"Im Moment: Was möchten Sie am liebsten tun – etwa nach dem Zielort fragen, nach dem Preis oder nach einer Quittung? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen gerade in den Sinn kommt.\"]', '[]', '[{\"original\": \"Wo kann ich ein Taxi bekommen?\", \"translated\": \"Où puis-je prendre un taxi ?\"}, {\"original\": \"Bitte fahren Sie mich zu dieser Adresse.\", \"translated\": \"Veuillez me conduire à cette adresse.\"}, {\"original\": \"Wie viel kostet das ungefähr?\", \"translated\": \"Cela coûtera-t-il environ combien ?\"}, {\"original\": \"Könnten Sie bitte den Taxameter benutzen?\", \"translated\": \"Pourriez-vous utiliser le compteur, s’il vous plaît ?\"}, {\"original\": \"Fahren Sie bitte etwas schneller, ich habe es eilig.\", \"translated\": \"Pourriez-vous conduire un peu plus vite, je suis pressé(e).\"}, {\"original\": \"Bitte halten Sie hier an.\", \"translated\": \"Veuillez vous arrêter ici.\"}, {\"original\": \"Akzeptieren Sie Karten oder mobile Zahlungen?\", \"translated\": \"Acceptez-vous les cartes ou les paiements mobiles ?\"}, {\"original\": \"Könnte ich bitte eine Quittung bekommen?\", \"translated\": \"Pourrais-je avoir un reçu, s’il vous plaît ?\"}, {\"original\": \"Vielen Dank, Fahrer.\", \"translated\": \"Merci beaucoup, chauffeur.\"}, {\"original\": \"Wie weit ist es noch?\", \"translated\": \"Combien de temps reste-t-il avant d’arriver ?\"}]', 6, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für die Apotheke nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit der Apotheke – inklusive französischer Übersetzungen.\"]', '[\"Medikamente kaufen\", \"Beratung\", \"Bezahlen\"]', 'de', '[\"Momentan: Haben Sie eine konkrete Situation im Kopf, z. B. Fragen zur Einnahme von Medikamenten, zum Einsatz Ihrer Versicherungskarte oder zur Dauer der Behandlung? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Haben Sie fiebersenkende Medikamente?\", \"translated\": \"Avez-vous des médicaments contre la fièvre ?\"}, {\"original\": \"Wie soll ich dieses Medikament einnehmen?\", \"translated\": \"Comment dois-je prendre ce médicament ?\"}, {\"original\": \"Haben Sie Schmerzmittel?\", \"translated\": \"Avez-vous des analgésiques ?\"}, {\"original\": \"Gibt es eine Gebrauchsanweisung?\", \"translated\": \"Y a-t-il une notice d’utilisation ?\"}, {\"original\": \"Hat dieses Medikament Nebenwirkungen?\", \"translated\": \"Ce médicament a-t-il des effets secondaires ?\"}, {\"original\": \"Kann ich meine Krankenversicherungskarte verwenden?\", \"translated\": \"Puis-je utiliser ma carte d’assurance maladie ?\"}, {\"original\": \"Könnten Sie mir bitte eine Packung Pflaster geben?\", \"translated\": \"Pourriez-vous me donner une boîte de pansements, s’il vous plaît ?\"}, {\"original\": \"Haben Sie fiebersenkende Mittel?\", \"translated\": \"Avez-vous des antipyrétiques ?\"}, {\"original\": \"Ich habe mir leicht das Knie aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\", \"translated\": \"Je me suis un peu écorché. Avez-vous un désinfectant et des pansements ?\"}, {\"original\": \"Wann schließen Sie ?\", \"translated\": \"À quelle heure fermez-vous ?\"}]', 7, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gebräuchliche Ausdrücke für den Notdienst nennen?\", \"Fantastisch! Hier sind 10 gebräuchliche Ausdrücke zum Thema Notdienst – inklusive französischer Übersetzungen:\"]', '[\"Polizei rufen\", \"Erste Hilfe leisten\", \"Hilfe rufen\"]', 'de', '[\"Im Moment: Haben Sie eine konkrete Notsituation im Kopf, z. B. Brand, Verletzung und Hilfebedarf, Notruf? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Bitte rufen Sie einen Krankenwagen für mich.\", \"translated\": \"Veuillez m\'appeler une ambulance.\"}, {\"original\": \"Wo ist das Krankenhaus?\", \"translated\": \"Où se trouve l\'hôpital ?\"}, {\"original\": \"Jemand ist verletzt.\", \"translated\": \"Quelqu’un est blessé.\"}, {\"original\": \"Bitte helfen Sie mir.\", \"translated\": \"Aidez-moi, s’il vous plaît.\"}, {\"original\": \"Wo ist die Polizeistation?\", \"translated\": \"Où se trouve le commissariat de police ?\"}, {\"original\": \"Ich habe meine Sachen verloren.\", \"translated\": \"J’ai perdu mes affaires.\"}, {\"original\": \"Was ist die Notrufnummer der Feuerwehr?\", \"translated\": \"Quel est le numéro d’urgence des pompiers ?\"}, {\"original\": \"Ich habe meinen Reisepass verloren. Wissen Sie, wo sich die nächste Polizeistation befindet?\", \"translated\": \"J’ai perdu mon passeport. Savez-vous où se trouve le commissariat de police le plus proche ?\"}, {\"original\": \"Gibt es einen Notausgang?\", \"translated\": \"Y a-t-il une sortie de secours ?\"}, {\"original\": \"Jemand ist ohnmächtig geworden.\", \"translated\": \"Quelqu’un a perdu connaissance.\"}]', 8, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 gängige Ausdrücke für Strand oder Poolbereich nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Strand oder Poolbereich samt französischer Übersetzung:\"]', '[\"Schwimmen\", \"Sonnenbaden\", \"Strandsport\"]', 'de', '[\"Vorerst: Könnten Sie mir bitte den Kontext der lokalen Veranstaltung oder des Festivals, an dem Sie teilnehmen, nennen – z. B. ein Kulturfestival, ein kulinarisches Festival oder ein Musikfestival? Bitte geben Sie den Kontext an.\", \"Bitte nennen Sie die Aktivitäten, an denen Sie teilnehmen.\"]', '[\"Haben Sie eine konkrete Situation im Kopf? Fragen Sie ruhig frei nach.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[{\"original\": \"Schau mal! Die Wellen dort drüben sind wirklich groß.\", \"translated\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\"}, {\"original\": \"Vergiss nicht, Sonnencreme aufzutragen – die UV-Strahlen hier sind sehr stark.\", \"translated\": \"N\'oubliez pas d\'appliquer de la crème solaire, les rayons UV sont très forts ici.\"}, {\"original\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle gehen.\", \"translated\": \"Le sable de cette plage est si fin qu’on a l’impression de marcher sur du coton.\"}, {\"original\": \"Wie wär’s mit Volleyball am Strand?\", \"translated\": \"Et si on jouait au volley-ball sur la plage ?\"}, {\"original\": \"Die Segelboote in der Ferne sehen wunderschön aus.\", \"translated\": \"Les voiliers au loin sont magnifiques.\"}, {\"original\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\", \"translated\": \"L’eau est tellement claire ici qu’on peut même voir les poissons.\"}, {\"original\": \"Lass uns Muscheln suchen gehen.\", \"translated\": \"Allons chercher des coquillages.\"}, {\"original\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\", \"translated\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\"}, {\"original\": \"Ich habe gehört, dass die Meeresfrüchte hier sehr frisch sind – lasst uns welche probieren!\", \"translated\": \"J’ai entendu dire que les fruits de mer sont très frais ici ; allons-en goûter !\"}, {\"original\": \"Die Flut kommt herein – gehen wir Richtung Ufer.\", \"translated\": \"La marée monte, rentrons vers le rivage.\"}]', 9, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Redewendungen für lokale Veranstaltungen und Feste nennen?\", \"Fantastisch! Hier sind 10 gängige Redewendungen zu lokalen Veranstaltungen und Festen – inklusive französischer Übersetzungen:\"]', '[\"Veranstaltungen besuchen\", \"Feste feiern\", \"Kultur kennenlernen\"]', 'de', '[\"Könnten Sie mir vorläufig bitte den Kontext der lokalen Veranstaltung oder des Festes mitteilen, an dem Sie teilnehmen möchten – z. B. Halloween, ein Konzert, eine Party bei Freunden oder etwas anderes? Bitte geben Sie den Kontext an.\", \"Bitte beschreiben Sie die Aktivitäten, die Ihnen spontan in den Sinn kommen.\"]', '[\"Haben Sie eine konkrete Situation im Kopf? Fragen Sie ruhig frei nach.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', '[{\"original\": \"Gibt es heute irgendwelche Veranstaltungen?\", \"translated\": \"Y a-t-il des événements prévus aujourd\'hui ?\"}, {\"original\": \"Gibt es etwas Besonderes an diesem Fest?\", \"translated\": \"Y a-t-il quelque chose de particulier à propos de cette fête ?\"}, {\"original\": \"Wo findet die Feier statt?\", \"translated\": \"Où se déroule la célébration ?\"}, {\"original\": \"Wie kann ich Tickets kaufen?\", \"translated\": \"Comment puis-je acheter des billets ?\"}, {\"original\": \"Wann beginnt die Aufführung?\", \"translated\": \"À quelle heure commence la représentation ?\"}, {\"original\": \"Welche traditionellen Speisen gibt es?\", \"translated\": \"Quels plats traditionnels sont proposés ?\"}, {\"original\": \"Es ist hier wirklich lebendig.\", \"translated\": \"C’est vraiment animé ici.\"}, {\"original\": \"Gibt es Volksaktivitäten?\", \"translated\": \"Y a-t-il des activités populaires ?\"}, {\"original\": \"Frohe Feiertage!\", \"translated\": \"Joyeuses fêtes !\"}, {\"original\": \"Wann endet die Veranstaltung?\", \"translated\": \"À quelle heure se termine l\'événement ?\"}]', 10, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Redewendungen nennen, die ich im Museum oder in der Galerie verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Redewendungen zum Thema Museum oder Galerie – inklusive französischer Übersetzungen:\"]', '[\"Besuch\", \"Geführte Tour\", \"Tickets kaufen\"]', 'de', '[\"Für den Augenblick: Haben Sie eine konkrete Situation im Kopf, z. B. das Nachfragen nach einem Einführungsfaltblatt, Formulierungen zum Rundgang oder zum Kommentieren von Exponaten? Fragen Sie ruhig!\", \"Schildern Sie bitte die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"Quel est le prix d\'entrée ?\"}, {\"original\": \"Haben Sie Audioguides?\", \"translated\": \"Proposez-vous des audioguides ?\"}, {\"original\": \"Wer hat dieses Kunstwerk geschaffen?\", \"translated\": \"Qui est l\'auteur de cette œuvre ?\"}, {\"original\": \"Wo befindet sich das wertvollste Stück des Museums?\", \"translated\": \"Où se trouve la pièce la plus précieuse du musée ?\"}, {\"original\": \"Ist Fotografieren erlaubt?\", \"translated\": \"La photographie est-elle autorisée ?\"}, {\"original\": \"Gibt es hier besondere Ausstellungen?\", \"translated\": \"Y a-t-il des expositions spéciales ici ?\"}, {\"original\": \"Wie lange dauert der Besuch?\", \"translated\": \"Combien de temps dure la visite ?\"}, {\"original\": \"Könnten Sie uns kurz etwas vorstellen?\", \"translated\": \"Pourriez-vous nous faire une brève présentation ?\"}, {\"original\": \"Diese Werke sind wirklich exquisit.\", \"translated\": \"Ces œuvres sont vraiment remarquables.\"}, {\"original\": \"Wo befindet sich der Souvenirladen?\", \"translated\": \"Où se trouve la boutique de souvenirs ?\"}]', 11, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Cafés nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Cafés – inklusive französischer Übersetzung:\"]', '[\"Kaffee bestellen\", \"Ausruhen\", \"Sozialisieren\"]', 'de', '[\"Für den Moment: Haben Sie eine konkrete Situation im Kopf, z. B. das Bestellen einer Speisekarte, kalter oder warmer Getränke, anderer Produkte? Fühlen Sie sich frei, danach zu fragen.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Ich nehme einen Latte, bitte.\", \"translated\": \"Je voudrais un latte, s’il vous plaît.\"}, {\"original\": \"Haben Sie WLAN?\", \"translated\": \"Avez-vous un accès Wi-Fi ?\"}, {\"original\": \"Könnte ich bitte die Speisekarte sehen?\", \"translated\": \"Pourriez-vous me montrer la carte, s’il vous plaît ?\"}, {\"original\": \"Darf man Nachfüllungen bekommen?\", \"translated\": \"Les recharges sont-elles autorisées ?\"}, {\"original\": \"Ist mein Kaffee schon fertig?\", \"translated\": \"Mon café est-il prêt ?\"}, {\"original\": \"Wie lange darf ich hier sitzen bleiben?\", \"translated\": \"Combien de temps puis-je rester assis ici ?\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"Pourriez-vous prendre une photo de nous, s’il vous plaît ?\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"Die Rechnung, bitte. Vielen Dank.\", \"translated\": \"L’addition, s’il vous plaît. Merci beaucoup.\"}, {\"original\": \"Es schmeckt wirklich gut.\", \"translated\": \"C’est vraiment délicieux.\"}]', 12, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"レストランで使える一般的な表現を10個教えてもらえますか？\", \"素晴らしい！以下はレストラン関連の一般的な表現10個と、そのドイツ語訳です：\"]', '[\"食事\", \"注文\", \"会計\"]', 'ja', '[\"今のところ、ドリンクの注文やクレームの申し立て、材料についての質問など、具体的な状況をお考えですか？遠慮なくご質問ください。\", \"あなたが思い浮かべている状況を教えてください。\"]', '[]', '[{\"original\": \"すみません、料理はあとどのくらいで来ますか？\", \"translated\": \"Entschuldigung, wie lange dauert es noch, bis unser Essen kommt?\"}, {\"original\": \"2名のテーブルをお願いします。\", \"translated\": \"Ein Tisch für zwei Personen, bitte.\"}, {\"original\": \"メニューを見せていただいてもよろしいですか？\", \"translated\": \"Könnten wir bitte die Speisekarte sehen?\"}, {\"original\": \"おすすめの看板メニューはありますか？\", \"translated\": \"Haben Sie empfehlenswerte Hausgerichte?\"}, {\"original\": \"これを注文したいのですが、これもお願いします。\", \"translated\": \"Ich möchte dieses Gericht bestellen – und auch dieses hier.\"}, {\"original\": \"水を一杯お願いします。ありがとうございます。\", \"translated\": \"Ein Glas Wasser, bitte. Vielen Dank.\"}, {\"original\": \"お会計をお願いします。\", \"translated\": \"Die Rechnung, bitte.\"}, {\"original\": \"クレジットカードで支払えますか？\", \"translated\": \"Kann ich mit Kreditkarte bezahlen?\"}, {\"original\": \"これを持ち帰り用に包んでいただけますか？\", \"translated\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\"}, {\"original\": \"料理がとても美味しかったです。ありがとうございました。\", \"translated\": \"Das Essen war köstlich, vielen Dank!\"}]', 1, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ホテルで使える代表的な10の表現を教えてください。\", \"素晴らしい！以下に、ホテルに関連する代表的な10の表現と、それらのドイツ語訳をご紹介します。\"]', '[\"チェックイン\", \"チェックアウト\", \"ルームサービス\"]', 'ja', '[\"今のところ、お部屋の位置やその他のホテルサービス、チェックアウトなど、具体的な状況が頭に浮かんでいますか？遠慮なくご質問ください。\", \"頭に浮かんでいる状況を教えてください。\"]', '[]', '[{\"original\": \"こんにちは、予約しています。こちらが私のパスポートです。\", \"translated\": \"Hallo, ich habe eine Reservierung. Hier ist mein Pass.\"}, {\"original\": \"空室はありますか？\", \"translated\": \"Haben Sie noch freie Zimmer?\"}, {\"original\": \"すみませんが、このホテルにはジムやランドリールームはありますか？\", \"translated\": \"Entschuldigung, hat das Hotel einen Fitnessraum oder eine Wäscherei?\"}, {\"original\": \"朝食は何時からですか？\", \"translated\": \"Wann beginnt das Frühstück?\"}, {\"original\": \"部屋の鍵をいただけますか？\", \"translated\": \"Könnte ich bitte den Zimmerschlüssel haben?\"}, {\"original\": \"荷物を部屋まで運んでいただけますか？\", \"translated\": \"Könnten Sie mir bitte mein Gepäck aufs Zimmer bringen?\"}, {\"original\": \"ルームサービスの電話のかけ方は？\", \"translated\": \"Wie rufe ich den Zimmerservice an?\"}, {\"original\": \"チェックアウトは何時ですか？\", \"translated\": \"Wann ist der Check-out?\"}, {\"original\": \"領収書／請求書を書いていただけますか？\", \"translated\": \"Könnten Sie mir bitte eine Quittung / Rechnung ausstellen?\"}, {\"original\": \"荷物をここに預けても大丈夫ですか？\", \"translated\": \"Darf ich mein Gepäck hier vorübergehend abgeben?\"}]', 2, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"空港で使えるよく使う表現を10個教えてください。\", \"素晴らしい！以下に、空港関連のよく使う表現10個と、そのドイツ語訳をご紹介します：\"]', '[\"チェックイン\", \"搭乗\", \"手荷物預け\"]', 'ja', '[\"今、チェックイン、手荷物受取、またはレンタカーなどの具体的なシーンを思い浮かべていますか？どんな質問でもどうぞ。\", \"あなたの頭に浮かんでいる状況について教えてください。\"]', '[]', '[{\"original\": \"チェックインカウンターはどこですか？\", \"translated\": \"Wo ist der Check-in-Schalter?\"}, {\"original\": \"窓際の席を1つお願いします。\", \"translated\": \"Ich hätte gerne einen Fensterplatz.\"}, {\"original\": \"この便は遅れていますか？\", \"translated\": \"Ist dieser Flug verspätet?\"}, {\"original\": \"こちらの荷物を預けたいのですが。\", \"translated\": \"Ich möchte dieses Gepäck aufgeben.\"}, {\"original\": \"搭乗口はどこですか？\", \"translated\": \"Wo ist das Boarding-Gate?\"}, {\"original\": \"飛行機が今から離陸します。\", \"translated\": \"Das Flugzeug startet gleich.\"}, {\"original\": \"ノートパソコンとモバイルバッテリーは取り出さなければいけませんか？\", \"translated\": \"Muss ich meinen Laptop und die Powerbank herausnehmen?\"}, {\"original\": \"免税店はどこですか？\", \"translated\": \"Wo ist der Duty-free-Shop?\"}, {\"original\": \"私のスーツケースが見当たりません。\", \"translated\": \"Ich kann meinen Koffer nicht finden.\"}, {\"original\": \"車椅子のサービスはありますか？\", \"translated\": \"Bieten Sie einen Rollstuhl-Service an?\"}]', 3, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"公共交通機関で使える一般的なフレーズを10個教えてもらえますか？\", \"素晴らしい！以下は、公共交通機関に関する一般的なフレーズ10個と、そのドイツ語訳です：\"]', '[\"バス・地下鉄を利用する\", \"切符を購入する\", \"乗り換える\"]', 'ja', '[\"今のところ、バス停の確認、料金の問い合わせ、降車などの具体的なシーンを思い浮かべていますか？自由に聞いてください。\", \"頭の中で思い浮かんでいるシーンを教えてください。\"]', '[]', '[{\"original\": \"このバスは終点へ行きますか？\", \"translated\": \"Fährt dieser Bus zum Endbahnhof?\"}, {\"original\": \"次の停留所はどこですか？\", \"translated\": \"Wo ist die nächste Haltestelle?\"}, {\"original\": \"切符はどこで買えますか？\", \"translated\": \"Wo kann ich eine Fahrkarte kaufen?\"}, {\"original\": \"XX行きの切符を一枚お願いします。\", \"translated\": \"Eine Fahrkarte nach XX, bitte.\"}, {\"original\": \"乗り換えが必要ですか？\", \"translated\": \"Muss ich umsteigen?\"}, {\"original\": \"次の地下鉄の列車まで、あとどのくらいですか？\", \"translated\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\"}, {\"original\": \"すみません、通らせてください。\", \"translated\": \"Entschuldigung, darf ich bitte durch?\"}, {\"original\": \"この席は空いていますか？\", \"translated\": \"Ist dieser Platz frei?\"}, {\"original\": \"すみません、XXへ行くには2号線へ乗り換えるにはどこで乗り換えればいいですか？\", \"translated\": \"Entschuldigung, wo muss ich umsteigen, um in die Linie 2 zu wechseln, um nach XX zu gelangen?\"}, {\"original\": \"XXへはどう行けばいいですか？\", \"translated\": \"Wie komme ich nach XX?\"}]', 4, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"10個のよく使う旅行先（観光地）での定番フレーズを教えてください。\", \"素晴らしい！以下が、旅行先（観光地）でよく使う10個の定番フレーズと、それに対応するドイツ語訳です：\"]', '[\"観光\", \"写真撮影\", \"チケット購入\"]', 'ja', '[\"今のところ、入場料の確認、駐車場の探し方、ガイドサービスの有無など、具体的な状況が頭に浮かんでいますか？ぜひお気軽にお知らせください。\", \"頭に浮かんでいる状況を教えてください。\"]', '[]', '[{\"original\": \"入場料はいくらですか？\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"学生料金のチケットはありますか？\", \"translated\": \"Gibt es Ermäßigungen für Schüler oder Studenten?\"}, {\"original\": \"この観光地の営業時間は何時からですか？\", \"translated\": \"Wann öffnet die Sehenswürdigkeit?\"}, {\"original\": \"ここで楽しめるアクティビティは何がありますか？\", \"translated\": \"Was gibt es hier Spannendes zu tun?\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"観光バスの乗り場はどこですか？\", \"translated\": \"Wo befindet sich die Haltestelle des Sightseeing-Busses?\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"一番景色が良い展望スポットはどこですか？\", \"translated\": \"Wo ist der beste Aussichtspunkt?\"}, {\"original\": \"ここでの景色はとても美しいです。\", \"translated\": \"Die Aussicht hier ist wunderschön.\"}, {\"original\": \"ガイド付きツアーはありますか？\", \"translated\": \"Gibt es geführte Touren?\"}]', 5, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"タクシーまたはタクシーサービスで使える、よく使う表現を10個教えてもらえますか？\", \"素晴らしい！以下に、タクシーまたはタクシーサービスに関連するよく使う表現10個と、そのドイツ語訳をご紹介します。\"]', '[\"タクシーを利用する\", \"目的地を伝える\", \"支払いに関するやりとり\"]', 'ja', '[\"今のところ、目的地を尋ねたり、料金を聞いたり、領収書の請求をしたりなど、あなたが今一番したいことは何ですか？自由にお尋ねください。\", \"あなたの頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"タクシーはどこで乗れますか？\", \"translated\": \"Wo kann ich ein Taxi nehmen?\"}, {\"original\": \"この住所までお願いします。\", \"translated\": \"Bitte fahren Sie mich zu dieser Adresse.\"}, {\"original\": \"だいたいいくらぐらいになりますか？\", \"translated\": \"Wie viel kostet die Fahrt ungefähr?\"}, {\"original\": \"メーターを使っていただけますか？\", \"translated\": \"Könnten Sie bitte den Taxameter benutzen?\"}, {\"original\": \"急いでいるので、少し速く運転してもらえますか？\", \"translated\": \"Könnten Sie bitte etwas schneller fahren? Ich habe es eilig.\"}, {\"original\": \"ここで止めてください。\", \"translated\": \"Bitte halten Sie hier an.\"}, {\"original\": \"カードやモバイル決済は使えますか？\", \"translated\": \"Akzeptieren Sie Karten oder mobile Zahlungen?\"}, {\"original\": \"領収書をいただけますか？\", \"translated\": \"Könnte ich bitte eine Quittung bekommen?\"}, {\"original\": \"ありがとうございます、運転手さん。\", \"translated\": \"Vielen Dank, Fahrer!\"}, {\"original\": \"あとどのくらいですか？\", \"translated\": \"Wie weit ist es noch?\"}]', 6, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"薬局で使えるよく使う表現を10個教えてもらえますか？\", \"素晴らしい！以下は薬局に関連するよく使う表現10個と、それらのドイツ語訳です：\"]', '[\"薬の購入\", \"相談\", \"支払い\"]', 'ja', '[\"今のところ、お薬の飲み方を聞く、保険の使い方について尋ねる、服用期間について確認するなど、具体的なシチュエーションが思い浮かんでいますか？どんどん聞いてください。\", \"頭の中で想像しているシチュエーションを教えてください。\"]', '[]', '[{\"original\": \"風邪薬はありますか？\", \"translated\": \"Haben Sie Erkältungsmedikamente?\"}, {\"original\": \"このお薬はどのように服用すればいいですか？\", \"translated\": \"Wie soll ich dieses Medikament einnehmen?\"}, {\"original\": \"鎮痛剤はありますか？\", \"translated\": \"Haben Sie Schmerzmittel?\"}, {\"original\": \"説明書のパンフレットはありますか？\", \"translated\": \"Gibt es eine Gebrauchsanweisung?\"}, {\"original\": \"このお薬には副作用がありますか？\", \"translated\": \"Hat dieses Medikament Nebenwirkungen?\"}, {\"original\": \"医療保険証を使えますか？\", \"translated\": \"Kann ich meine Krankenversicherungskarte verwenden?\"}, {\"original\": \"絆創膏を1箱お願いします。\", \"translated\": \"Könnte ich bitte eine Packung Pflaster haben?\"}, {\"original\": \"解熱剤はありますか？\", \"translated\": \"Haben Sie Fiebersenkende Mittel?\"}, {\"original\": \"ちょっと擦り傷があるので、消毒液と絆創膏をお願いします。\", \"translated\": \"Ich habe eine kleine Schürfwunde – hätten Sie Desinfektionsmittel und Pflaster?\"}, {\"original\": \"何時まで営業していますか？\", \"translated\": \"Um wie viel Uhr schließen Sie?\"}]', 7, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"緊急サービスで使えるよく使う表現を10個教えていただけますか？\", \"素晴らしい！以下に、緊急サービスに関するよく使う表現10個と、それぞれのドイツ語訳をご紹介します：\"]', '[\"警察を呼ぶ\", \"応急処置\", \"助けを求める\"]', 'ja', '[\"今のところ、火事、怪我をして助けが必要、緊急通報など、具体的な緊急状況をお考えですか？遠慮なくお聞かせください。\", \"頭の中で思い浮かんでいる状況を教えてください。\"]', '[]', '[{\"original\": \"救急車を呼んでください。\", \"translated\": \"Bitte rufen Sie einen Krankenwagen.\"}, {\"original\": \"病院はどこですか？\", \"translated\": \"Wo ist das Krankenhaus?\"}, {\"original\": \"誰かが怪我をしました。\", \"translated\": \"Jemand ist verletzt.\"}, {\"original\": \"助けてください。\", \"translated\": \"Bitte helfen Sie mir.\"}, {\"original\": \"警察署はどこですか？\", \"translated\": \"Wo ist die nächste Polizeistation?\"}, {\"original\": \"荷物をなくしてしまいました。\", \"translated\": \"Ich habe meine Sachen verloren.\"}, {\"original\": \"消防署への電話番号は何番ですか？\", \"translated\": \"Wie lautet die Notrufnummer für die Feuerwehr?\"}, {\"original\": \"パスポートを紛失しました。近くの警察署はどこですか？\", \"translated\": \"Ich habe meinen Reisepass verloren. Können Sie mir sagen, wo die nächste Polizeistation ist?\"}, {\"original\": \"非常口はありますか？\", \"translated\": \"Gibt es einen Notausgang?\"}, {\"original\": \"誰かが気を失いました。\", \"translated\": \"Jemand ist in Ohnmacht gefallen.\"}]', 8, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ビーチやプールサイドで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、ビーチやプールサイドに関連する一般的な表現10個と、それぞれのドイツ語訳をご紹介します：\"]', '[\"泳ぐこと\", \"日光浴\", \"ビーチスポーツ\"]', 'ja', '[\"今のところ、ご参加予定の現地のイベントやお祭り（例：文化祭、フードフェスティバル、音楽フェスティバルなど）について、そのコンテキストを教えていただけますか？\", \"ご参加されるアクティビティをお知らせください。\"]', '[\"特に思い浮かぶ具体的情境はありますか？遠慮なくご質問ください。\", \"頭の中にある状況について、詳しく教えてください。\"]', '[{\"original\": \"見て！あそこにある波は本当に大きいね。\", \"translated\": \"Schau mal! Die Wellen dort drüben sind wirklich groß.\"}, {\"original\": \"日焼け止めを塗ることを忘れないでね。ここでの紫外線はとても強いわ。\", \"translated\": \"Vergiss nicht, Sonnencreme aufzutragen – die UV-Strahlen hier sind sehr stark.\"}, {\"original\": \"このビーチの砂はとても細かくて、綿の上を歩いているみたいなの。\", \"translated\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle gehen.\"}, {\"original\": \"ビーチでバレーボールをするのはどう？\", \"translated\": \"Wie wäre es mit einem Volleyballspiel am Strand?\"}, {\"original\": \"遠くに見えるセーリングボートがとてもきれいね。\", \"translated\": \"Die Segelboote in der Ferne sehen wunderschön aus.\"}, {\"original\": \"ここでの水はとても透明で、魚まで見えるわ。\", \"translated\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\"}, {\"original\": \"一緒に貝殻を探しに行こうよ。\", \"translated\": \"Lass uns gemeinsam Muscheln suchen gehen.\"}, {\"original\": \"夕日が沈むビーチを散歩するのは、きっととてもロマンチックね。\", \"translated\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\"}, {\"original\": \"ここではシーフードがとても新鮮だと聞いたわ。ぜひ食べてみよう！\", \"translated\": \"Ich habe gehört, dass die Meeresfrüchte hier sehr frisch sind – lasst uns welche probieren!\"}, {\"original\": \"潮が満ちてきてるわ。岸に向かって戻りましょう。\", \"translated\": \"Die Flut kommt herein – lass uns zum Ufer zurückgehen.\"}]', 9, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"現地の行事や祭りで使える、よく使う表現を10個教えてもらえますか？\", \"素晴らしい！以下は、現地の行事や祭りに関連するよく使う表現10個と、そのドイツ語訳です：\"]', '[\"イベントへの参加\", \"祭りの祝い\", \"文化の学習\"]', 'ja', '[\"今のところ、ハロウィン、コンサート、友人とのパーティーなど、あなたが参加予定の現地の行事や祭りの具体的な状況を教えていただけますか？状況をご説明ください。\", \"あなたの頭の中にある活動を教えてください。\"]', '[\"特定の状況を思い浮かべていますか？何でも気軽に聞いてください。\", \"あなたの頭の中にある状況を教えてください。\"]', '[{\"original\": \"今日は何かイベントがありますか？\", \"translated\": \"Gibt es heute irgendwelche Veranstaltungen?\"}, {\"original\": \"この祭りには何か特別なことがありますが？\", \"translated\": \"Gibt es bei diesem Fest etwas Besonderes?\"}, {\"original\": \"お祝いはどこで行われますか？\", \"translated\": \"Wo findet die Feier statt?\"}, {\"original\": \"チケットはどこで買えますか？\", \"translated\": \"Wo kann ich Tickets kaufen?\"}, {\"original\": \"パフォーマンスは何時から始まりますか？\", \"translated\": \"Wann beginnt die Aufführung?\"}, {\"original\": \"どんな伝統料理がありますか？\", \"translated\": \"Welche traditionellen Speisen gibt es?\"}, {\"original\": \"ここは本当ににぎやかですね。\", \"translated\": \"Es ist hier wirklich lebendig.\"}, {\"original\": \"民俗活動はありますか？\", \"translated\": \"Gibt es Volksaktivitäten?\"}, {\"original\": \"楽しい休日を！\", \"translated\": \"Frohe Feiertage!\"}, {\"original\": \"イベントは何時までですか？\", \"translated\": \"Wann endet die Veranstaltung?\"}]', 10, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"私に、美術館や博物館で使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下は、美術館や博物館に関連する一般的な表現10個と、そのドイツ語訳です。\"]', '[\"来館\", \"ガイド付き見学\", \"チケットの購入\"]', 'ja', '[\"今のところ、展示解説書の依頼、ルートマップに関する表現、展示品への感想に関する表現など、特定のシーンを思い浮かべていますか？ ぜひ教えてください。\", \"あなたの頭の中にあるシーンを具体的に教えてください。\"]', '[]', '[{\"original\": \"入館料はいくらですか？\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"オーディオガイドはありますか？\", \"translated\": \"Bieten Sie Audioführungen an?\"}, {\"original\": \"この作品は誰が制作しましたか？\", \"translated\": \"Wer hat dieses Kunstwerk geschaffen?\"}, {\"original\": \"美術館・博物館で最も価値のある品はどこにありますか？\", \"translated\": \"Wo befindet sich das wertvollste Exponat des Museums?\"}, {\"original\": \"写真撮影は可能ですか？\", \"translated\": \"Ist das Fotografieren erlaubt?\"}, {\"original\": \"ここには特別展はありますか？\", \"translated\": \"Gibt es hier aktuell Sonderausstellungen?\"}, {\"original\": \"見学にはどのくらい時間がかかりますか？\", \"translated\": \"Wie lange dauert der Besuch?\"}, {\"original\": \"簡単な紹介をしていただけますか？\", \"translated\": \"Könnten Sie uns kurz einführen?\"}, {\"original\": \"これらの作品は本当に素晴らしいですね。\", \"translated\": \"Diese Werke sind wirklich exquisit.\"}, {\"original\": \"お土産ショップはどこですか？\", \"translated\": \"Wo befindet sich der Souvenirladen?\"}]', 11, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"カフェで使える一般的なフレーズを10個教えてください。\", \"素晴らしい！以下は、カフェに関連する10個の一般的なフレーズと、そのドイツ語訳です：\"]', '[\"コーヒーを注文する\", \"休憩する\", \"交流する\"]', 'ja', '[\"今のところ、メニューの確認や、アイス／ホットドリンクの注文、他の商品について尋ねるなど、特定の状況が頭に浮かんでいますか？何でも気軽に聞いてください。\", \"頭に浮かんでいる状況を教えてください。\"]', '[]', '[{\"original\": \"お願いですが、ラテを一杯ください。\", \"translated\": \"Ich hätte gerne einen Latte, bitte.\"}, {\"original\": \"Wi-Fiは使えますか？\", \"translated\": \"Haben Sie WLAN?\"}, {\"original\": \"メニューを見せていただけますか？\", \"translated\": \"Könnte ich bitte die Speisekarte sehen?\"}, {\"original\": \"リフィルは可能ですか？\", \"translated\": \"Darf ich Nachfüllungen erhalten?\"}, {\"original\": \"私のコーヒーはできましたか？\", \"translated\": \"Ist mein Kaffee bereits fertig?\"}, {\"original\": \"ここにどのくらい座っていられますか？\", \"translated\": \"Wie lange darf ich hier sitzen bleiben?\"}, {\"original\": \"私たちの写真を撮ってもらえますか？\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"お会計をお願いします。ありがとうございます。\", \"translated\": \"Die Rechnung, bitte. Vielen Dank.\"}, {\"original\": \"とても美味しいです！\", \"translated\": \"Das schmeckt wirklich gut!\"}]', 12, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在餐厅常用的表达吗？\", \"太棒了！以下是10个与餐厅相关的常用表达，并附有德语翻译：\"]', '[\"就餐\", \"点餐\", \"结账\"]', 'zh', '[\"目前，您心里有没有特定的场景，比如点饮料、提出投诉，或者询问食材成分？欢迎随时提问。\", \"请描述一下您心里想到的情境。\"]', '[]', '[{\"original\": \"打扰一下，我们的餐还要等多久？\", \"translated\": \"Entschuldigung, wie lange müssen wir noch auf unser Essen warten?\"}, {\"original\": \"请给我们安排一张两人桌。\", \"translated\": \"Ein Tisch für zwei Personen, bitte.\"}, {\"original\": \"请问可以看一下菜单吗？\", \"translated\": \"Könnten wir bitte die Speisekarte sehen?\"}, {\"original\": \"你们有什么招牌菜可以推荐吗？\", \"translated\": \"Haben Sie empfehlenswerte Hausgerichte?\"}, {\"original\": \"我要点这个和这个。\", \"translated\": \"Ich möchte dieses und jenes bestellen.\"}, {\"original\": \"请来一杯水，谢谢。\", \"translated\": \"Ein Glas Wasser, bitte. Vielen Dank.\"}, {\"original\": \"请结账。\", \"translated\": \"Die Rechnung, bitte.\"}, {\"original\": \"我可以用信用卡付款吗？\", \"translated\": \"Kann ich mit Kreditkarte bezahlen?\"}, {\"original\": \"请帮我把这份打包带走，谢谢。\", \"translated\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\"}, {\"original\": \"食物非常美味，谢谢！\", \"translated\": \"Das Essen war köstlich, vielen Dank!\"}]', 1, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在酒店常用的句子吗？\", \"太棒了！以下是与酒店相关的10个常用句子，并附上德语翻译：\"]', '[\"入住\", \"退房\", \"客房服务\"]', 'zh', '[\"目前，您心里有没有特定场景，比如房间位置、其他酒店服务，或者退房？欢迎随时提问。\", \"请描述一下您脑海中的具体场景。\"]', '[]', '[{\"original\": \"你好，我有预订，这是我的护照。\", \"translated\": \"Hallo, ich habe eine Reservierung. Hier ist mein Pass.\"}, {\"original\": \"你们还有空房吗？\", \"translated\": \"Haben Sie noch freie Zimmer?\"}, {\"original\": \"打扰一下，酒店有健身房或洗衣房吗？\", \"translated\": \"Entschuldigung, verfügt das Hotel über ein Fitnessstudio oder einen Waschraum?\"}, {\"original\": \"早餐几点开始？\", \"translated\": \"Wann beginnt das Frühstück?\"}, {\"original\": \"请给我一把房卡，好吗？\", \"translated\": \"Könnte ich bitte einen Zimmerschlüssel haben?\"}, {\"original\": \"您能帮我把行李送到房间吗？\", \"translated\": \"Könnten Sie mir bitte beim Tragen meines Gepäcks ins Zimmer helfen?\"}, {\"original\": \"我怎么呼叫客房服务？\", \"translated\": \"Wie rufe ich den Zimmerservice an?\"}, {\"original\": \"退房时间是几点？\", \"translated\": \"Um wie viel Uhr ist der Check-out?\"}, {\"original\": \"您能给我开一张收据/发票吗？\", \"translated\": \"Könnten Sie mir bitte eine Quittung / Rechnung ausstellen?\"}, {\"original\": \"我可以把行李寄存在这里吗？\", \"translated\": \"Kann ich mein Gepäck hier abgeben?\"}]', 2, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在机场常用的说法吗？\", \"太棒了！以下是与机场相关的10个常用说法，并附有德语翻译：\"]', '[\"值机\", \"登机\", \"行李托运\"]', 'zh', '[\"目前，您心里是否有特定场景，比如值机、行李提取或租车服务？欢迎随时提问。\", \"请描述您心里想到的具体场景。\"]', '[]', '[{\"original\": \"值机柜台在哪里？\", \"translated\": \"Wo ist der Check-in-Schalter?\"}, {\"original\": \"我想要一个靠窗的座位，谢谢。\", \"translated\": \"Ich hätte gerne einen Fensterplatz, bitte.\"}, {\"original\": \"这趟航班延误了吗？\", \"translated\": \"Ist dieser Flug verspätet?\"}, {\"original\": \"我需要托运行李。\", \"translated\": \"Ich muss dieses Gepäck aufgeben.\"}, {\"original\": \"登机口在哪里？\", \"translated\": \"Wo ist das Boarding-Gate?\"}, {\"original\": \"飞机即将起飞。\", \"translated\": \"Das Flugzeug startet gleich.\"}, {\"original\": \"我需要把笔记本电脑和充电宝拿出来吗？\", \"translated\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\"}, {\"original\": \"免税店在哪里？\", \"translated\": \"Wo ist der Duty-free-Shop?\"}, {\"original\": \"我找不到我的行李箱了。\", \"translated\": \"Ich kann meinen Koffer nicht finden.\"}, {\"original\": \"你们提供轮椅服务吗？\", \"translated\": \"Bieten Sie einen Rollstuhlservice an?\"}]', 3, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在公共交通工具上常用的表达吗？\", \"太棒了！以下是与公共交通工具有关的10个常用表达，附带德语翻译：\"]', '[\"乘坐公交/地铁\", \"购买车票\", \"换乘\"]', 'zh', '[\"目前，您心中是否有特定场景，比如询问公交站、票价或下车？欢迎随时提问。\", \"请描述您心里想到的具体场景。\"]', '[]', '[{\"original\": \"这辆公交车去终点站吗？\", \"translated\": \"Fährt dieser Bus zum Terminal?\"}, {\"original\": \"下一站是哪里？\", \"translated\": \"Was ist die nächste Haltestelle?\"}, {\"original\": \"我在哪里可以买票？\", \"translated\": \"Wo kann ich ein Ticket kaufen?\"}, {\"original\": \"请给我一张去XX的车票。\", \"translated\": \"Ein Ticket nach XX, bitte.\"}, {\"original\": \"我需要换乘吗？\", \"translated\": \"Muss ich umsteigen?\"}, {\"original\": \"下一班地铁还要多久？\", \"translated\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\"}, {\"original\": \"不好意思，请让我过去一下。\", \"translated\": \"Entschuldigung, bitte lassen Sie mich durch.\"}, {\"original\": \"这个座位有人坐了吗？\", \"translated\": \"Ist dieser Platz bereits besetzt?\"}, {\"original\": \"不好意思，请问我在哪儿换乘2号线去XX？\", \"translated\": \"Entschuldigung, wo kann ich umsteigen, um mit der Linie 2 nach XX zu gelangen?\"}, {\"original\": \"我怎么去XX？\", \"translated\": \"Wie komme ich nach XX?\"}]', 4, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在旅游景点常用的短语吗？\", \"太棒了！以下是与旅游景点相关的10个常用短语，附带德语翻译：\"]', '[\"观光游览\", \"拍照\", \"购票\"]', 'zh', '[\"目前，您心中是否有特定场景，比如询问票价、寻找停车场，或导游服务？欢迎随时提问。\", \"请描述一下您心中想到的具体场景。\"]', '[]', '[{\"original\": \"入场费是多少？\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"有学生票吗？\", \"translated\": \"Gibt es ermäßigte Eintrittskarten für Schüler und Studenten?\"}, {\"original\": \"这个景点几点开门？\", \"translated\": \"Wann öffnet die Sehenswürdigkeit?\"}, {\"original\": \"这里有哪些好玩的活动？\", \"translated\": \"Was kann man hier Spannendes unternehmen?\"}, {\"original\": \"能帮我们拍张照吗？\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"观光巴士在哪里？\", \"translated\": \"Wo befindet sich der Sightseeing-Bus?\"}, {\"original\": \"洗手间在哪里？\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"最佳观景点在哪里？\", \"translated\": \"Wo ist der beste Aussichtspunkt?\"}, {\"original\": \"这里的风景真美。\", \"translated\": \"Die Aussicht hier ist wunderschön.\"}, {\"original\": \"提供导览服务吗？\", \"translated\": \"Gibt es eine Führung?\"}]', 5, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在乘坐出租车或使用出租车服务时常用的表达吗？\", \"太棒了！以下是10个与乘坐出租车或出租车服务相关的常用表达，并附上德语翻译：\"]', '[\"打车\", \"告知目的地\", \"支付\"]', 'zh', '[\"目前，您最想做什么呢？比如询问目的地、询问费用，或是索要发票，欢迎随时提问。\", \"请在脑海中描述一下当时的场景。\"]', '[]', '[{\"original\": \"我在哪里可以打到出租车？\", \"translated\": \"Wo kann ich ein Taxi bekommen?\"}, {\"original\": \"请送我去这个地址。\", \"translated\": \"Fahren Sie mich bitte zu dieser Adresse.\"}, {\"original\": \"大概要多少钱？\", \"translated\": \"Wie viel kostet es ungefähr?\"}, {\"original\": \"请打表计费，好吗？\", \"translated\": \"Könnten Sie bitte den Taxameter einschalten?\"}, {\"original\": \"麻烦开快一点，我赶时间。\", \"translated\": \"Könnten Sie bitte etwas schneller fahren? Ich habe es eilig.\"}, {\"original\": \"请在这里停车。\", \"translated\": \"Bitte halten Sie hier an.\"}, {\"original\": \"您接受银行卡或手机支付吗？\", \"translated\": \"Akzeptieren Sie Karten- oder Mobile-Payments?\"}, {\"original\": \"能给我一张发票吗？\", \"translated\": \"Könnte ich bitte eine Quittung haben?\"}, {\"original\": \"谢谢，师傅。\", \"translated\": \"Danke, Fahrer!\"}, {\"original\": \"还有多远？\", \"translated\": \"Wie weit ist es noch?\"}]', 6, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在药店常用的短语吗？\", \"太棒了！以下是与药店相关的10个常用短语，附带德语翻译：\"]', '[\"买药\", \"咨询\", \"付款\"]', 'zh', '[\"目前，您心里有没有特定的情境，比如询问服药说明、使用医保相关表达、用药时长等？欢迎随时提问。\", \"请描述一下您心里想的情境。\"]', '[]', '[{\"original\": \"你们有感冒药吗？\", \"translated\": \"Haben Sie Erkältungsmedikamente?\"}, {\"original\": \"这个药该怎么吃？\", \"translated\": \"Wie soll ich dieses Medikament einnehmen?\"}, {\"original\": \"你们有止痛药吗？\", \"translated\": \"Haben Sie Schmerzmittel?\"}, {\"original\": \"这药有说明书吗？\", \"translated\": \"Gibt es eine Gebrauchsanweisung dazu?\"}, {\"original\": \"这个药有什么副作用吗？\", \"translated\": \"Hat dieses Medikament Nebenwirkungen?\"}, {\"original\": \"我可以用医保卡付款吗？\", \"translated\": \"Kann ich mit meiner gesetzlichen Krankenversicherungskarte bezahlen?\"}, {\"original\": \"请给我一盒创可贴，谢谢。\", \"translated\": \"Könnten Sie mir bitte eine Packung Pflaster geben?\"}, {\"original\": \"你们有退烧药吗？\", \"translated\": \"Haben Sie Fiebersenkende Mittel?\"}, {\"original\": \"我有点擦伤，你们有消毒水和创可贴吗？\", \"translated\": \"Ich habe mir leicht die Haut aufgeschürft – haben Sie Desinfektionsmittel und Pflaster?\"}, {\"original\": \"你们几点关门？\", \"translated\": \"Wann schließen Sie?\"}]', 7, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个可用于紧急服务的常用短语吗？\", \"太棒了！以下是10个与紧急服务相关的常用短语，并附有德语翻译：\"]', '[\"报警\", \"急救\", \"求助\"]', 'zh', '[\"目前，您心里是否有具体的紧急情况，比如火灾、受伤需要帮助、紧急呼叫等？欢迎随时提问。\", \"请描述您脑海中设想的情况。\"]', '[]', '[{\"original\": \"请帮我叫一辆救护车。\", \"translated\": \"Bitte rufen Sie einen Krankenwagen für mich.\"}, {\"original\": \"医院在哪儿？\", \"translated\": \"Wo ist das Krankenhaus?\"}, {\"original\": \"有人受伤了。\", \"translated\": \"Jemand ist verletzt.\"}, {\"original\": \"请帮帮我。\", \"translated\": \"Bitte helfen Sie mir.\"}, {\"original\": \"警察局在哪儿？\", \"translated\": \"Wo ist die Polizeistation?\"}, {\"original\": \"我的物品丢了。\", \"translated\": \"Ich habe meine Sachen verloren.\"}, {\"original\": \"消防部门的电话号码是多少？\", \"translated\": \"Was ist die Notrufnummer der Feuerwehr?\"}, {\"original\": \"我丢了护照。您知道最近的警察局在哪儿吗？\", \"translated\": \"Ich habe meinen Reisepass verloren. Können Sie mir sagen, wo die nächste Polizeistation ist?\"}, {\"original\": \"这里有紧急出口吗？\", \"translated\": \"Gibt es hier einen Notausgang?\"}, {\"original\": \"有人晕倒了。\", \"translated\": \"Jemand ist in Ohnmacht gefallen.\"}]', 8, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在沙滩或泳池边常用的表达吗？\", \"太棒了！以下是10个与沙滩或泳池边相关的常用表达，并附上德语翻译：\"]', '[\"游泳\", \"日光浴\", \"沙滩运动\"]', 'zh', '[\"目前，请您告诉我您要参加的当地活动或节日的具体背景，比如文化节日、美食节或音乐节。请提供相关背景。\", \"请您说明您参加的活动内容。\"]', '[\"您心里是否有特定情境？欢迎随时提问。\", \"请描述一下您心中设想的情境。\"]', '[{\"original\": \"看！那边的海浪真大。\", \"translated\": \"Schau! Die Wellen dort drüben sind wirklich groß.\"}, {\"original\": \"记得涂防晒霜，这里的紫外线很强。\", \"translated\": \"Denk daran, Sonnencreme aufzutragen – die UV-Strahlen hier sind sehr stark.\"}, {\"original\": \"这个海滩的沙子非常细腻，踩上去像踩在棉花上。\", \"translated\": \"Der Sand an diesem Strand ist so fein, dass er sich anfühlt wie Baumwolle.\"}, {\"original\": \"要不要在海滩上打排球？\", \"translated\": \"Wie wäre es mit einem Volleyballspiel am Strand?\"}, {\"original\": \"远处的帆船看起来真美。\", \"translated\": \"Die Segelboote in der Ferne sehen wunderschön aus.\"}, {\"original\": \"这里的海水特别清澈，甚至能看到鱼。\", \"translated\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\"}, {\"original\": \"咱们去找些贝壳吧。\", \"translated\": \"Lass uns mal nach Muscheln suchen.\"}, {\"original\": \"日落时分在海滩散步一定很浪漫。\", \"translated\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\"}, {\"original\": \"听说这里的海鲜特别新鲜，咱们去尝尝吧。\", \"translated\": \"Ich habe gehört, dass die Meeresfrüchte hier besonders frisch sind – probieren wir sie aus!\"}, {\"original\": \"涨潮了，咱们往岸边走吧。\", \"translated\": \"Die Flut kommt herein – gehen wir zum Ufer zurück.\"}]', 9, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在本地活动和节日中常用的表达吗？\", \"太棒了！以下是与本地活动和节日相关的10个常用表达，附带德语翻译：\"]', '[\"参加活动\", \"庆祝节日\", \"了解文化\"]', 'zh', '[\"目前，您能告诉我您要参加的本地活动或节日的具体背景吗？比如万圣节、音乐会、朋友聚会，或者其他场合？请提供相关背景。\", \"请描述一下您脑海中设想的活动内容。\"]', '[\"您心里有没有特定的情境？欢迎随时提问。\", \"请描述一下您心中设想的情境。\"]', '[{\"original\": \"今天有什么活动吗？\", \"translated\": \"Gibt es heute irgendwelche Veranstaltungen?\"}, {\"original\": \"这个节日有什么特别之处吗？\", \"translated\": \"Gibt es bei diesem Fest etwas Besonderes?\"}, {\"original\": \"庆祝活动在哪里举行？\", \"translated\": \"Wo findet die Feier statt?\"}, {\"original\": \"我该怎么买票？\", \"translated\": \"Wie kann ich Tickets kaufen?\"}, {\"original\": \"演出几点开始？\", \"translated\": \"Wann beginnt die Vorstellung?\"}, {\"original\": \"有哪些传统食物？\", \"translated\": \"Welche traditionellen Speisen gibt es?\"}, {\"original\": \"这里真热闹！\", \"translated\": \"Es ist hier wirklich lebhaft!\"}, {\"original\": \"有民俗活动吗？\", \"translated\": \"Gibt es Volksbräuche oder volkstümliche Aktivitäten?\"}, {\"original\": \"节日快乐！\", \"translated\": \"Frohe Feiertage!\"}, {\"original\": \"活动几点结束？\", \"translated\": \"Wann endet die Veranstaltung?\"}]', 10, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在博物馆或美术馆常用的短语吗？\", \"太棒了！以下是与博物馆或美术馆相关的10个常用短语，附带德语翻译：\"]', '[\"参观\", \"导览服务\", \"购票\"]', 'zh', '[\"目前，您心里有特定场景吗？比如索要介绍手册、与参观路线相关的短语、对展品发表评论的短语等——欢迎随时提问。\", \"请描述一下您心里想到的具体场景。\"]', '[]', '[{\"original\": \"入场费是多少？\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"你们有语音导览吗？\", \"translated\": \"Bieten Sie Audioführungen an?\"}, {\"original\": \"这件艺术品是谁创作的？\", \"translated\": \"Wer ist der Schöpfer dieses Kunstwerks?\"}, {\"original\": \"博物馆最珍贵的展品在哪里？\", \"translated\": \"Wo befindet sich das wertvollste Stück des Museums?\"}, {\"original\": \"可以拍照吗？\", \"translated\": \"Ist Fotografieren erlaubt?\"}, {\"original\": \"这里有没有特别展览？\", \"translated\": \"Gibt es hier aktuell Sonderausstellungen?\"}, {\"original\": \"参观需要多长时间？\", \"translated\": \"Wie lange dauert der Besuch?\"}, {\"original\": \"能为我们简单介绍一下吗？\", \"translated\": \"Könnten Sie uns kurz vorstellen?\"}, {\"original\": \"这些作品真是精美绝伦。\", \"translated\": \"Diese Werke sind wirklich exquisit.\"}, {\"original\": \"纪念品商店在哪儿？\", \"translated\": \"Wo befindet sich der Souvenirshop?\"}]', 11, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在咖啡馆常用的句子吗？\", \"太棒了！以下是与咖啡馆相关的10个常用句子，附带德语翻译：\"]', '[\"点咖啡\", \"休息\", \"社交\"]', 'zh', '[\"目前，您心里有没有特定的场景，比如点菜单、要冰饮或热饮、点其他产品？欢迎随时提问。\", \"请描述一下您心里想到的场景。\"]', '[]', '[{\"original\": \"请给我一杯拿铁。\", \"translated\": \"Ich hätte gerne einen Latte, bitte.\"}, {\"original\": \"你们有Wi-Fi吗？\", \"translated\": \"Haben Sie WLAN?\"}, {\"original\": \"请问可以看一下菜单吗？\", \"translated\": \"Könnte ich bitte die Speisekarte sehen?\"}, {\"original\": \"可以免费续杯吗？\", \"translated\": \"Darf man Nachschlag bekommen?\"}, {\"original\": \"我的咖啡好了吗？\", \"translated\": \"Ist mein Kaffee schon fertig?\"}, {\"original\": \"我可以在这里坐多久？\", \"translated\": \"Wie lange darf ich hier sitzen?\"}, {\"original\": \"能帮我们拍张照吗？\", \"translated\": \"Könnten Sie uns bitte ein Foto machen?\"}, {\"original\": \"洗手间在哪里？\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"请结账，谢谢。\", \"translated\": \"Die Rechnung, bitte. Danke.\"}, {\"original\": \"味道真的很棒。\", \"translated\": \"Es schmeckt wirklich sehr gut.\"}]', 12, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a restaurant?\", \"Fantastic! Here are 10 common phrases related to a restaurant, along with German translations:\"]', '[\"Dining\", \"Ordering\", \"Checkout\"]', 'en', '[\"For now, do you have a specific situation in your mind, like ordering drinks, making a complaint, or asking about ingredients? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Excuse me, how much longer will our food be?\", \"translated\": \"Entschuldigung, wie lange dauert es noch bis zu unserem Essen?\"}, {\"original\": \"A table for two, please.\", \"translated\": \"Ein Tisch für zwei Personen, bitte.\"}, {\"original\": \"Could we see the menu, please?\", \"translated\": \"Könnten wir bitte die Speisekarte sehen?\"}, {\"original\": \"Do you have any signature dishes to recommend?\", \"translated\": \"Haben Sie besondere Empfehlungen oder Spezialitäten?\"}, {\"original\": \"I\'d like to order this, and this.\", \"translated\": \"Ich möchte dieses und dieses bestellen.\"}, {\"original\": \"A glass of water, please. Thanks.\", \"translated\": \"Ein Glas Wasser, bitte. Danke.\"}, {\"original\": \"The bill, please.\", \"translated\": \"Die Rechnung, bitte.\"}, {\"original\": \"Can I pay by credit card?\", \"translated\": \"Kann ich mit Kreditkarte bezahlen?\"}, {\"original\": \"Could you pack this to go, please?\", \"translated\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\"}, {\"original\": \"The food was delicious, thank you.\", \"translated\": \"Das Essen war köstlich, vielen Dank.\"}]', 1, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a hotel?\", \"Fantastic! Here are 10 common phrases related to hotels, along with German translations:\"]', '[\"Check-in\", \"Check-out\", \"Room Service\"]', 'en', '[\"For now, do you have a specific situation in mind, like room location, any other hotel service, or check-out? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Hello, I have a reservation, Here is my passport.\", \"translated\": \"Hallo, ich habe eine Reservierung – hier ist mein Pass.\"}, {\"original\": \"Do you have any vacancies?\", \"translated\": \"Haben Sie noch freie Zimmer?\"}, {\"original\": \"Excuse me, does the hotel have a gym or a laundry room?\", \"translated\": \"Entschuldigung, verfügt das Hotel über ein Fitnessstudio oder einen Waschraum?\"}, {\"original\": \"What time does breakfast start?\", \"translated\": \"Wann beginnt das Frühstück?\"}, {\"original\": \"Could I have a room key, please?\", \"translated\": \"Könnte ich bitte den Zimmerschlüssel haben?\"}, {\"original\": \"Could you help me take my luggage to the room?\", \"translated\": \"Könnten Sie mir bitte beim Tragen meines Gepäcks ins Zimmer helfen?\"}, {\"original\": \"How do I call room service?\", \"translated\": \"Wie rufe ich den Zimmerservice?\"}, {\"original\": \"What time is check-out?\", \"translated\": \"Wann ist der Check-out?\"}, {\"original\": \"Could you write me a receipt/invoice?\", \"translated\": \"Könnten Sie mir bitte eine Quittung/eine Rechnung ausstellen?\"}, {\"original\": \"Can I leave my luggage here?\", \"translated\": \"Darf ich mein Gepäck hier lassen?\"}]', 2, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use at the airport?\", \"Fantastic! Here are 10 common phrases related to the airport, along with German translations:\"]', '[\"Check-in\", \"Boarding\", \"Baggage Check\"]', 'en', '[\"For now, do you have a specific situation in mind, like check-in, baggage claim, or car rental service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Where is the check-in counter?\", \"translated\": \"Wo ist der Check-in-Schalter?\"}, {\"original\": \"I\'d like a window seat, please.\", \"translated\": \"Ich hätte gerne einen Fensterplatz, bitte.\"}, {\"original\": \"Is this flight delayed?\", \"translated\": \"Ist dieser Flug verspätet?\"}, {\"original\": \"I need to check this baggage.\", \"translated\": \"Ich muss dieses Gepäck aufgeben.\"}, {\"original\": \"Where is the boarding gate?\", \"translated\": \"Wo ist das Boarding-Gate?\"}, {\"original\": \"The plane is about to take off.\", \"translated\": \"Das Flugzeug startet gleich.\"}, {\"original\": \"Do I need to take out my laptop and power bank?\", \"translated\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\"}, {\"original\": \"Where is the duty-free shop?\", \"translated\": \"Wo ist der Duty-free-Shop?\"}, {\"original\": \"I can\'t find my suitcase.\", \"translated\": \"Ich kann meinen Koffer nicht finden.\"}, {\"original\": \"Do you have a wheelchair service?\", \"translated\": \"Bieten Sie einen Rollstuhlservice an?\"}]', 3, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in public transportation?\", \"Fantastic! Here are 10 common phrases related to public transportation, along with German translations:\"]', '[\"Taking Bus/Subway\", \"Buying Tickets\", \"Transferring\"]', 'en', '[\"For now, do you have a specific situation in your mind, like asking for a bus stop, ticket price, or getting off? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Does this bus go to the terminal?\", \"translated\": \"Fährt dieser Bus zum Terminal?\"}, {\"original\": \"What is the next stop?\", \"translated\": \"Was ist die nächste Haltestelle?\"}, {\"original\": \"Where can I buy a ticket?\", \"translated\": \"Wo kann ich ein Ticket kaufen?\"}, {\"original\": \"One ticket to XX, please.\", \"translated\": \"Ein Ticket nach XX, bitte.\"}, {\"original\": \"Do I need to transfer?\", \"translated\": \"Muss ich umsteigen?\"}, {\"original\": \"How long until the next subway train?\", \"translated\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\"}, {\"original\": \"Excuse me, please let me pass.\", \"translated\": \"Entschuldigung, bitte lassen Sie mich durch.\"}, {\"original\": \"Is this seat taken?\", \"translated\": \"Ist dieser Platz belegt?\"}, {\"original\": \"Excuse me, where can I transfer to Line 2 to get to XX?\", \"translated\": \"Entschuldigung, wo kann ich umsteigen, um mit Linie 2 nach XX zu kommen?\"}, {\"original\": \"How do I get to XX?\", \"translated\": \"Wie komme ich nach XX?\"}]', 4, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in tourist attractions?\", \"Fantastic! Here are 10 common phrases related to tourist attractions, along with German translations:\"]', '[\"Sightseeing\", \"Taking Photos\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking about ticket prices, finding a parking lot, or tour guide service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"How much is the entrance fee?\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"Are there student tickets available?\", \"translated\": \"Gibt es ermäßigte Eintrittskarten für Schüler und Studenten?\"}, {\"original\": \"What time does the attraction open?\", \"translated\": \"Wann öffnet die Sehenswürdigkeit?\"}, {\"original\": \"What are the fun things to do here?\", \"translated\": \"Was kann man hier Lustiges unternehmen?\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"Where is the sightseeing bus?\", \"translated\": \"Wo befindet sich der Sightseeing-Bus?\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"Where is the best viewing spot?\", \"translated\": \"Wo ist der beste Aussichtspunkt?\"}, {\"original\": \"The scenery here is beautiful.\", \"translated\": \"Die Landschaft hier ist wunderschön.\"}, {\"original\": \"Is there a guided tour available?\", \"translated\": \"Gibt es eine geführte Tour?\"}]', 5, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in taxis or taxi services?\", \"Fantastic! Here are 10 common phrases related to taxis or taxi services, along with German translations:\"]', '[\"Taking Taxi\", \"Telling Destination\", \"Payment\"]', 'en', '[\"For now, what do you most want to do now—like asking for the destination, the fare, or requesting an invoice? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Where can I get a taxi?\", \"translated\": \"Wo kann ich ein Taxi bekommen?\"}, {\"original\": \"Please take me to this address.\", \"translated\": \"Bitte fahren Sie mich zu dieser Adresse.\"}, {\"original\": \"Roughly how much will it be?\", \"translated\": \"Wie viel wird es ungefähr kosten?\"}, {\"original\": \"Could you use the meter, please?\", \"translated\": \"Könnten Sie bitte den Taxameter benutzen?\"}, {\"original\": \"Please drive a bit faster, I\'m in a hurry.\", \"translated\": \"Bitte fahren Sie etwas schneller, ich habe es eilig.\"}, {\"original\": \"Please stop here.\", \"translated\": \"Bitte halten Sie hier an.\"}, {\"original\": \"Do you accept cards or mobile payments?\", \"translated\": \"Akzeptieren Sie Karten- oder Mobile-Payments?\"}, {\"original\": \"Could I have a receipt, please?\", \"translated\": \"Könnte ich bitte eine Quittung bekommen?\"}, {\"original\": \"Thank you, driver.\", \"translated\": \"Danke, Fahrer.\"}, {\"original\": \"How much further is it?\", \"translated\": \"Wie weit ist es noch?\"}]', 6, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a pharmacy?\", \"Fantastic! Here are 10 common phrases related to a pharmacy, along with German translations:\"]', '[\"Buying Medicine\", \"Consultation\", \"Payment\"]', 'en', '[\"For now, do you have a specific situation in your mind, like asking for instructions on taking medicine, phrases related to using insurance, or duration of medication? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Do you have cold medicine?\", \"translated\": \"Haben Sie Erkältungsmedikamente?\"}, {\"original\": \"How should I take this medicine?\", \"translated\": \"Wie soll ich dieses Medikament einnehmen?\"}, {\"original\": \"Do you have any painkillers?\", \"translated\": \"Haben Sie Schmerzmittel?\"}, {\"original\": \"Is there an instruction leaflet?\", \"translated\": \"Gibt es eine Gebrauchsanweisung?\"}, {\"original\": \"Does this medicine have any side effects?\", \"translated\": \"Hat dieses Medikament Nebenwirkungen?\"}, {\"original\": \"Can I use my medical insurance card?\", \"translated\": \"Kann ich meine Krankenversicherungskarte verwenden?\"}, {\"original\": \"Could I have a box of Band-Aids, please?\", \"translated\": \"Könnte ich bitte eine Packung Pflaster haben?\"}, {\"original\": \"Do you have any fever reducers?\", \"translated\": \"Haben Sie Fiebersenkende Mittel?\"}, {\"original\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\", \"translated\": \"Ich habe mir leicht die Haut aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\"}, {\"original\": \"What time do you close?\", \"translated\": \"Um welche Uhrzeit machen Sie zu?\"}]', 7, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in emergency services?\", \"Fantastic! Here are 10 common phrases related to emergency services, along with German translations:\"]', '[\"Calling Police\", \"First Aid\", \"Calling for Help\"]', 'en', '[\"For now, do you have a specific emergency situation in your mind, like fire, injured and need help, emergency call? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Please help me call an ambulance.\", \"translated\": \"Bitte helfen Sie mir, einen Krankenwagen zu rufen.\"}, {\"original\": \"Where is the hospital?\", \"translated\": \"Wo ist das Krankenhaus?\"}, {\"original\": \"Someone is injured.\", \"translated\": \"Jemand ist verletzt.\"}, {\"original\": \"Please help me.\", \"translated\": \"Bitte helfen Sie mir.\"}, {\"original\": \"Where is the police station?\", \"translated\": \"Wo ist die Polizeistation?\"}, {\"original\": \"I\'ve lost my belongings.\", \"translated\": \"Ich habe meine Sachen verloren.\"}, {\"original\": \"What is the number for the fire department?\", \"translated\": \"Wie lautet die Telefonnummer der Feuerwehr?\"}, {\"original\": \"I\'ve lost my passport. Do you know where the nearest police station is?\", \"translated\": \"Ich habe meinen Reisepass verloren. Wissen Sie, wo die nächste Polizeistation ist?\"}, {\"original\": \"Is there an emergency exit?\", \"translated\": \"Gibt es einen Notausgang?\"}, {\"original\": \"Someone has fainted.\", \"translated\": \"Jemand ist in Ohnmacht gefallen.\"}]', 8, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use at the beach or by the pool?\", \"Fantastic! Here are 10 common phrases related to the beach or by the pool, along with German translations:\"]', '[\"Swimming\", \"Sunbathing\", \"Beach Sports\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you’re attending, such as a cultural festival, food festival, or music festival? Please provide the context.\", \"Please provide the activities that you’re attending.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation you have in mind.\"]', '[{\"original\": \"Look! The waves over there are really big.\", \"translated\": \"Schau! Die Wellen dort drüben sind wirklich groß.\"}, {\"original\": \"Remember to apply sunscreen, the UV rays here are very strong.\", \"translated\": \"Vergiss nicht, Sonnenschutzmittel aufzutragen – die UV-Strahlen hier sind sehr stark.\"}, {\"original\": \"The sand on this beach is so fine, it feels like stepping on cotton.\", \"translated\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle gehen.\"}, {\"original\": \"How about playing volleyball on the beach?\", \"translated\": \"Wie wäre es mit einer Runde Volleyball am Strand?\"}, {\"original\": \"The sailboats in the distance look beautiful.\", \"translated\": \"Die Segelboote in der Ferne sehen wunderschön aus.\"}, {\"original\": \"The water here is so clear, you can even see the fish.\", \"translated\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\"}, {\"original\": \"Let\'s go find some seashells.\", \"translated\": \"Lass uns ein paar Muscheln suchen.\"}, {\"original\": \"Taking a walk on the beach at sunset must be very romantic.\", \"translated\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\"}, {\"original\": \"I heard the seafood here is very fresh, let\'s go try some.\", \"translated\": \"Ich habe gehört, dass die Meeresfrüchte hier besonders frisch sind – lass uns welche probieren!\"}, {\"original\": \"The tide is coming in, let\'s head towards the shore.\", \"translated\": \"Die Flut kommt herein – lass uns Richtung Ufer gehen.\"}]', 9, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in local events and festivals?\", \"Fantastic! Here are 10 common phrases related to local events and festivals, along with German translations:\"]', '[\"Attending Events\", \"Celebrating Festivals\", \"Learning Culture\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you’re attending, like Halloween, a concert, a friend’s party, or something else? Please provide the context.\", \"Please describe the activities in your mind.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[{\"original\": \"Are there any events today?\", \"translated\": \"Gibt es heute irgendwelche Veranstaltungen?\"}, {\"original\": \"Is there anything special about this festival?\", \"translated\": \"Gibt es bei diesem Fest etwas Besonderes?\"}, {\"original\": \"Where is the celebration being held?\", \"translated\": \"Wo findet die Feier statt?\"}, {\"original\": \"How can I buy tickets?\", \"translated\": \"Wie kann ich Tickets kaufen?\"}, {\"original\": \"What time does the performance start?\", \"translated\": \"Um wie viel Uhr beginnt die Vorstellung?\"}, {\"original\": \"What traditional food is there?\", \"translated\": \"Welche traditionellen Speisen gibt es?\"}, {\"original\": \"It\'s really lively here.\", \"translated\": \"Es ist hier wirklich lebendig.\"}, {\"original\": \"Are there any folk activities?\", \"translated\": \"Gibt es Volksaktivitäten?\"}, {\"original\": \"Happy holidays!\", \"translated\": \"Frohe Feiertage!\"}, {\"original\": \"What time does the event end?\", \"translated\": \"Um wie viel Uhr endet die Veranstaltung?\"}]', 10, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a museum or art gallery?\", \"Fantastic! Here are 10 common phrases related to a museum or art gallery, along with German translations:\"]', '[\"Visiting\", \"Guided Tour\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for an introduction manual, phrases related to a roadmap, phrases related to commenting on exhibits? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"How much is the admission fee?\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"Do you have audio guides?\", \"translated\": \"Bieten Sie Audioguides an?\"}, {\"original\": \"Who created this artwork?\", \"translated\": \"Wer hat dieses Kunstwerk geschaffen?\"}, {\"original\": \"Where is the museum\'s most prized piece?\", \"translated\": \"Wo befindet sich das wertvollste Exponat des Museums?\"}, {\"original\": \"Is photography allowed?\", \"translated\": \"Ist Fotografieren erlaubt?\"}, {\"original\": \"Are there any special exhibitions here?\", \"translated\": \"Gibt es hier Sonderausstellungen?\"}, {\"original\": \"How long does the visit take?\", \"translated\": \"Wie lange dauert der Besuch?\"}, {\"original\": \"Could you give us an introduction?\", \"translated\": \"Könnten Sie uns eine Einführung geben?\"}, {\"original\": \"These works are truly exquisite.\", \"translated\": \"Diese Werke sind wirklich außergewöhnlich.\"}, {\"original\": \"Where is the souvenir shop?\", \"translated\": \"Wo befindet sich der Souvenirladen?\"}]', 11, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a café?\", \"Fantastic! Here are 10 common phrases related to cafés, along with German translations:\"]', '[\"Ordering Coffee\", \"Resting\", \"Socializing\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for a menu, ice or hot drinks, other products? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"I\'ll have a latte, please.\", \"translated\": \"Ich hätte gerne einen Latte, bitte.\"}, {\"original\": \"Do you have Wi-Fi?\", \"translated\": \"Haben Sie WLAN?\"}, {\"original\": \"Could I see the menu, please?\", \"translated\": \"Könnte ich bitte die Speisekarte sehen?\"}, {\"original\": \"Are refills allowed?\", \"translated\": \"Darf ich Nachschank bekommen?\"}, {\"original\": \"Is my coffee ready?\", \"translated\": \"Ist mein Kaffee fertig?\"}, {\"original\": \"How long can I sit here?\", \"translated\": \"Wie lange darf ich hier sitzen?\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"Check, please. Thank you.\", \"translated\": \"Die Rechnung, bitte. Danke.\"}, {\"original\": \"It tastes really good.\", \"translated\": \"Es schmeckt wirklich gut.\"}]', 12, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بعشر عبارات شائعة يمكنني استخدامها في المطعم؟\", \"رائع! إليك عشر عبارات شائعة مرتبطة بالمطعم، مع الترجمة الألمانية:\"]', '[\"تناول الطعام\", \"الطلب\", \"الدفع والخروج\"]', 'ar', '[\"لحد الآن، هل لديك موقف معين في ذهنك، مثل طلب المشروبات أو تقديم شكوى أو الاستفسار عن المكونات؟ لا تتردد في السؤال.\", \"من فضلك صف الموقف الذي يخطر في بالك.\"]', '[]', '[{\"original\": \"المعذرة، كم من الوقت سيستغرق وصول طعامنا؟\", \"translated\": \"Entschuldigung, wie lange dauert es noch, bis unser Essen kommt?\"}, {\"original\": \"طاولة لشخصين، من فضلكم.\", \"translated\": \"Ein Tisch für zwei Personen, bitte.\"}, {\"original\": \"هل يمكننا رؤية القائمة، من فضلكم؟\", \"translated\": \"Könnten wir bitte die Speisekarte sehen?\"}, {\"original\": \"هل لديكم أطباق مميزة تُوصون بها؟\", \"translated\": \"Haben Sie empfehlenswerte Spezialitäten?\"}, {\"original\": \"أود طلب هذا وهذا.\", \"translated\": \"Ich möchte dieses und jenes bestellen.\"}, {\"original\": \"كأس من الماء، من فضلكم. شكرًا.\", \"translated\": \"Ein Glas Wasser, bitte. Danke.\"}, {\"original\": \"الحساب، من فضلكم.\", \"translated\": \"Die Rechnung, bitte.\"}, {\"original\": \"هل يمكنني الدفع باستخدام بطاقة الائتمان؟\", \"translated\": \"Kann ich mit Kreditkarte bezahlen?\"}, {\"original\": \"هل يمكنكم تغليف هذا للاستلام خارج المطعم، من فضلكم؟\", \"translated\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\"}, {\"original\": \"كان الطعام لذيذًا، شكرًا لكم.\", \"translated\": \"Das Essen war köstlich, danke!\"}]', 1, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في الفندق؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بالفندق، مع ترجمتها إلى اللغة الألمانية:\"]', '[\"تسجيل الدخول\", \"المغادرة\", \"خدمة الغرف\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف محدَّد في ذهنك، مثل موقع الغرفة أو أي خدمة أخرى في الفندق أو وقت المغادرة؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي يخطر لك في بالك.\"]', '[]', '[{\"original\": \"مرحبًا، لدي حجزٌ هنا جواز سفري.\", \"translated\": \"Hallo, ich habe eine Reservierung. Hier ist mein Reisepass.\"}, {\"original\": \"هل لديكم أماكن شاغرة؟\", \"translated\": \"Haben Sie noch freie Zimmer?\"}, {\"original\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسيل الملابس؟\", \"translated\": \"Entschuldigung, verfügt das Hotel über ein Fitnessstudio oder einen Wäscheservice?\"}, {\"original\": \"في أي وقت تبدأ وجبة الإفطار؟\", \"translated\": \"Wann beginnt das Frühstück?\"}, {\"original\": \"هل يمكنني الحصول على مفتاح الغرفة من فضلكم؟\", \"translated\": \"Könnte ich bitte den Zimmerschlüssel haben?\"}, {\"original\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\", \"translated\": \"Könnten Sie mir bitte beim Tragen meines Gepäcks ins Zimmer helfen?\"}, {\"original\": \"كيف أطلب خدمة الغرف؟\", \"translated\": \"Wie rufe ich den Zimmerservice?\"}, {\"original\": \"في أي وقت يكون وقت المغادرة؟\", \"translated\": \"Wann ist der Check-out?\"}, {\"original\": \"هل يمكنكم إعطائي إيصالاً/فاتورةً؟\", \"translated\": \"Könnten Sie mir bitte eine Quittung/eine Rechnung ausstellen?\"}, {\"original\": \"هل يمكنني ترك أمتعتي هنا؟\", \"translated\": \"Kann ich mein Gepäck hier lassen?\"}]', 2, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بـ 10 عبارات شائعة يمكنني استخدامها في المطار؟\", \"رائع! إليك 10 عبارات شائعة مرتبطة بالمطار، مع الترجمة الألمانية لها:\"]', '[\"تسجيل الوصول\", \"الصعود إلى الطائرة\", \"فحص الأمتعة\"]', 'ar', '[\"حاليًا، هل لديك موقف معين في بالك، مثل تسجيل الوصول أو استلام الأمتعة أو خدمة تأجير السيارات؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي يخطر لك.\"]', '[]', '[{\"original\": \"أين كاونتر التسجيل؟\", \"translated\": \"Wo ist der Check-in-Schalter?\"}, {\"original\": \"أود مقعدًا بجوار النافذة، من فضلك.\", \"translated\": \"Ich hätte gerne einen Fensterplatz, bitte.\"}, {\"original\": \"هل تأخر هذا الرحلة؟\", \"translated\": \"Ist dieser Flug verspätet?\"}, {\"original\": \"يجب أن أُسجل هذه الأمتعة.\", \"translated\": \"Ich muss dieses Gepäck aufgeben.\"}, {\"original\": \"أين بوابة الصعود إلى الطائرة؟\", \"translated\": \"Wo ist das Boarding-Gate?\"}, {\"original\": \"الطائرة على وشك الإقلاع.\", \"translated\": \"Das Flugzeug startet gleich.\"}, {\"original\": \"هل يجب أن أخرج جهاز الكمبيوتر المحمول والبنك الإلكتروني؟\", \"translated\": \"Muss ich meinen Laptop und die Powerbank herausnehmen?\"}, {\"original\": \"أين متجر duty-free؟\", \"translated\": \"Wo befindet sich der Duty-free-Shop?\"}, {\"original\": \"لا أستطيع العثور على حقيبتي.\", \"translated\": \"Ich kann meinen Koffer nicht finden.\"}, {\"original\": \"هل تقدمون خدمة الكرسي المتحرك؟\", \"translated\": \"Bieten Sie einen Rollstuhl-Service an?\"}]', 3, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ ١٠ عبارات شائعة يمكنني استخدامها في وسائل النقل العام؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بوسائل النقل العام، مع الترجمة الألمانية:\"]', '[\"استخدام الحافلة أو المترو\", \"شراء التذاكر\", \"التغيير بين وسائل النقل\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف محدد في ذهنك؟ مثل سؤال عن موقف الحافلة أو سعر التذكرة أو النزول من الحافلة؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"هل هذه الحافلة تذهب إلى المحطة؟\", \"translated\": \"Fährt dieser Bus zum Terminal?\"}, {\"original\": \"ما هي المحطة التالية؟\", \"translated\": \"Was ist die nächste Haltestelle?\"}, {\"original\": \"أين يمكنني شراء تذكرة؟\", \"translated\": \"Wo kann ich ein Ticket kaufen?\"}, {\"original\": \"تذكرة واحدة إلى [XX]، من فضلك.\", \"translated\": \"Ein Ticket nach [XX], bitte.\"}, {\"original\": \"هل يجب أن أغير وسيلة النقل؟\", \"translated\": \"Muss ich umsteigen?\"}, {\"original\": \"كم من الوقت يبقى حتى قطار المترو القادم؟\", \"translated\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\"}, {\"original\": \"المعذرة، من فضلك اسمح لي بالمرور.\", \"translated\": \"Entschuldigung, bitte lassen Sie mich durch.\"}, {\"original\": \"هل هذا المقعد مشغول؟\", \"translated\": \"Ist dieser Platz besetzt?\"}, {\"original\": \"المعذرة، أين يمكنني الانتقال إلى الخط 2 للوصول إلى [XX]؟\", \"translated\": \"Entschuldigung, wo kann ich auf Linie 2 umsteigen, um nach [XX] zu gelangen?\"}, {\"original\": \"كيف أصل إلى [XX]؟\", \"translated\": \"Wie komme ich nach [XX]?\"}]', 4, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ 10 عبارات شائعة يمكنني استخدامها في أماكن الجذب السياحي؟\", \"رائع! إليك 10 عبارات شائعة مرتبطة بأماكن الجذب السياحي، مع الترجمة الألمانية لها:\"]', '[\"القيام بجولة سياحية\", \"أخذ الصور\", \"شراء التذاكر\"]', 'ar', '[\"حتى الآن، هل لديك موقف محدد في بالك؟ مثل الاستفسار عن سعر التذكرة، أو إيجاد موقف للسيارات، أو خدمة دليل سياحي؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"كم تكلفة رسوم الدخول؟\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"هل تتوفر تذاكر للطلاب؟\", \"translated\": \"Gibt es ermäßigte Eintrittskarten für Schüler und Studenten?\"}, {\"original\": \"في أي وقت يبدأ العمل في المعلم السياحي؟\", \"translated\": \"Wann öffnet die Sehenswürdigkeit?\"}, {\"original\": \"ما الأشياء الممتعة التي يمكن القيام بها هنا؟\", \"translated\": \"Was kann man hier alles Lustiges unternehmen?\"}, {\"original\": \"هل يمكنك أن تلتقط لنا صورة؟\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"أين حافلة الجولات السياحية؟\", \"translated\": \"Wo befindet sich der Sightseeing-Bus?\"}, {\"original\": \"أين الحمامات؟\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"ما أفضل مكان لمشاهدة المناظر؟\", \"translated\": \"Wo ist der beste Aussichtspunkt?\"}, {\"original\": \"المنظر هنا جميل جدًا.\", \"translated\": \"Die Aussicht hier ist wunderschön.\"}, {\"original\": \"هل توجد جولة إرشادية متاحة؟\", \"translated\": \"Gibt es eine Führung?\"}]', 5, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ ١٠ عبارات شائعة يمكنني استخدامها في خدمات التاكسي أو سيارات الأجرة؟\", \"رائع! إليك ١٠ عبارات شائعة تتعلق بخدمات التاكسي أو سيارات الأجرة، مع ترجمتها إلى اللغة الألمانية:\"]', '[\"أخذ تاكسي\", \"إبلاغ الوجهة\", \"الدفع\"]', 'ar', '[\"لحد الآن، ماذا تريد أن تفعل أكثر ما يخطر على بالك الآن؟ مثل الاستفسار عن الوجهة، أو السعر، أو طلب فاتورة — لا تتردد في السؤال.\", \"من فضلك صف لي الموقف الذي تتخيله في ذهنك.\"]', '[]', '[{\"original\": \"أين يمكنني أخذ تاكسي؟\", \"translated\": \"Wo kann ich ein Taxi nehmen?\"}, {\"original\": \"من فضلك خذني إلى هذا العنوان.\", \"translated\": \"Bitte fahren Sie mich zu dieser Adresse.\"}, {\"original\": \"كم ستكون التكلفة تقريبًا؟\", \"translated\": \"Wie viel wird es ungefähr kosten?\"}, {\"original\": \"هل يمكنكم استخدام عداد الركوب، من فضلكم؟\", \"translated\": \"Könnten Sie bitte den Taxameter benutzen?\"}, {\"original\": \"من فضلك اسرع قليلًا في القيادة، فأنا مستعجل.\", \"translated\": \"Bitte fahren Sie etwas schneller, ich habe es eilig.\"}, {\"original\": \"توقّف هنا من فضلك.\", \"translated\": \"Bitte halten Sie hier an.\"}, {\"original\": \"هل تقبلون الدفع بالبطاقات أو عبر الهاتف المحمول؟\", \"translated\": \"Akzeptieren Sie Karten- oder Mobile-Payments?\"}, {\"original\": \"هل يمكنني الحصول على إيصال، من فضلك؟\", \"translated\": \"Könnte ich bitte eine Quittung haben?\"}, {\"original\": \"شكرًا لك يا سائق.\", \"translated\": \"Danke, Fahrer.\"}, {\"original\": \"كم تبقى من المسافة؟\", \"translated\": \"Wie weit ist es noch?\"}]', 6, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في الصيدلية؟\", \"رائع! إليك عشر عبارات شائعة مرتبطة بالصيدلية، مع ترجمتها إلى اللغة الألمانية:\"]', '[\"شراء أدويــة\", \"استشارة\", \"دفع\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف محدد في ذهنك، مثل طلب توجيهات حول كيفية أخذ الدواء أو عبارات تتعلق باستخدام التأمين الصحي أو مدة العلاج؟ لا تتردد في طرح استفساراتك.\", \"يرجى وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"هل لديك دواء للبرد؟\", \"translated\": \"Haben Sie Medikamente gegen Erkältung?\"}, {\"original\": \"كيف يجب أن آخذ هذا الدواء؟\", \"translated\": \"Wie soll ich dieses Medikament einnehmen?\"}, {\"original\": \"هل لديك أي مسكنات للألم؟\", \"translated\": \"Haben Sie Schmerzmittel?\"}, {\"original\": \"هل توجد نشرة تعليمات مع العبوة؟\", \"translated\": \"Gibt es eine Gebrauchsanweisung dazu?\"}, {\"original\": \"هل لهذا الدواء أي آثار جانبية؟\", \"translated\": \"Hat dieses Medikament Nebenwirkungen?\"}, {\"original\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\", \"translated\": \"Kann ich meine Krankenversicherungskarte verwenden?\"}, {\"original\": \"هل يمكنني الحصول على علبة من الشرايط اللاصقة، من فضلك؟\", \"translated\": \"Könnte ich bitte eine Packung Pflaster haben?\"}, {\"original\": \"هل لديك أي خافضات للحرارة؟\", \"translated\": \"Haben Sie Fiebersenkende Mittel?\"}, {\"original\": \"لقد أصبتُ بجرح سطحي بسيط. هل عندكم مطهر وشرايط لاصقة؟\", \"translated\": \"Ich habe eine kleine Schürfwunde. Haben Sie Desinfektionsmittel und Pflaster?\"}, {\"original\": \"في أي وقت تغلقون؟\", \"translated\": \"Wann schließen Sie?\"}]', 7, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بـ 10 عبارات شائعة يمكنني استخدامها في خدمات الطوارئ؟\", \"رائع! إليك 10 عبارات شائعة مرتبطة بخدمات الطوارئ، مع الترجمات الألمانية الخاصة بها:\"]', '[\"الاتصال بالشرطة\", \"الإسعافات الأولية\", \"الاستغاثة\"]', 'ar', '[\"حتى الآن، هل لديك موقف طارئ معين في ذهنك، مثل الحريق، أو الإصابة واحتياجك للمساعدة، أو إجراء اتصال طارئ؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف لي الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"من فضلك ساعدني في الاتصال بالإسعاف.\", \"translated\": \"Bitte rufen Sie einen Krankenwagen für mich.\"}, {\"original\": \"أين تقع المستشفى؟\", \"translated\": \"Wo ist das Krankenhaus?\"}, {\"original\": \"شخص ما أُصيب.\", \"translated\": \"Jemand ist verletzt.\"}, {\"original\": \"من فضلك ساعدني.\", \"translated\": \"Bitte helfen Sie mir.\"}, {\"original\": \"أين تقع قسم الشرطة؟\", \"translated\": \"Wo ist die Polizeistation?\"}, {\"original\": \"لقد فقدت أشيائي.\", \"translated\": \"Ich habe meine Sachen verloren.\"}, {\"original\": \"ما هو رقم مركز الإطفاء؟\", \"translated\": \"Was ist die Telefonnummer der Feuerwehr?\"}, {\"original\": \"لقد فقدت جواز سفري. هل تعرف أين تقع أقرب قسم شرطة؟\", \"translated\": \"Ich habe meinen Pass verloren. Können Sie mir sagen, wo die nächste Polizeistation ist?\"}, {\"original\": \"هل يوجد مخرج طوارئ؟\", \"translated\": \"Gibt es einen Notausgang?\"}, {\"original\": \"شخص ما فقد وعيه.\", \"translated\": \"Jemand ist in Ohnmacht gefallen.\"}]', 8, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ10 عبارات شائعة يمكنني استخدامها في الشاطئ أو بالقرب من حوض السباحة؟\", \"رائع! إليك 10 عبارات شائعة تتعلق بالشاطئ أو بالقرب من حوض السباحة، مع الترجمات الألمانية لها:\"]', '[\"السباحة\", \"الاستلقاء تحت أشعة الشمس\", \"الرياضات الشاطئية\"]', 'ar', '[\"في الوقت الحالي، هل يمكنك تزويدي بسياق الحدث أو المهرجان المحلي الذي ستشارك فيه، مثل مهرجان ثقافي أو مهرجان غذائي أو مهرجان موسيقي؟ يرجى تزويدي بالسياق.\", \"يرجى ذكر الأنشطة التي ستشارك فيها.\"]', '[\"هل لديك موقفٌ محدّد في بالك؟ لا تتردد في طرح أي سؤال.\", \"صف لي الموقف الذي يخطر لك في بالك.\"]', '[{\"original\": \"انظر! الأمواج هناك كبيرة جدًا.\", \"translated\": \"Schau! Die Wellen dort drüben sind wirklich groß.\"}, {\"original\": \"تذكّر أن تضع واقي الشمس، فأشعة فوق البنفسجية هنا قوية جدًا.\", \"translated\": \"Vergiss nicht, Sonnencreme aufzutragen – die UV-Strahlen hier sind sehr stark.\"}, {\"original\": \"الرمل على هذه الشاطئ ناعم جدًا، لدرجة أن المشي عليه يشبه المشي على القطن.\", \"translated\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Watte gehen.\"}, {\"original\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\", \"translated\": \"Wie wäre es mit einem Volleyballspiel am Strand?\"}, {\"original\": \"القوارب الشراعية في الأفق تبدو جميلة جدًا.\", \"translated\": \"Die Segelboote in der Ferne sehen wunderschön aus.\"}, {\"original\": \"الماء هنا شفاف جدًا لدرجة أنك تستطيع رؤية الأسماك حتى.\", \"translated\": \"Das Wasser hier ist so klar, dass du sogar die Fische sehen kannst.\"}, {\"original\": \"هيا نبحث عن بعض المحار على الشاطئ.\", \"translated\": \"Lass uns nach Muscheln am Strand suchen.\"}, {\"original\": \"التنزه على الشاطئ عند غروب الشمس يجب أن يكون عمليًّا رومانسيًّا للغاية.\", \"translated\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\"}, {\"original\": \"سمعت أن المأكولات البحرية هنا طازجة جدًا، فلنذهب ونجرب بعضها.\", \"translated\": \"Ich habe gehört, dass die Meeresfrüchte hier sehr frisch sind – lasst uns welche probieren!\"}, {\"original\": \"المد يرتفع الآن، لذا دعونا نتجه نحو الساحل.\", \"translated\": \"Die Flut kommt herein – gehen wir also zum Ufer zurück.\"}]', 9, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في الفعاليات والمناسبات المحلية؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بالفعاليات والمناسبات المحلية، مع ترجمتها إلى اللغة الألمانية:\"]', '[\"حضور الفعاليات\", \"الاحتفال بالمناسبات\", \"تعلّم الثقافة\"]', 'ar', '[\"في الوقت الراهن، هل يمكنك إخباري بالسياق الخاص بالفعالية أو المناسبة المحلية التي ستشارك فيها، مثل هالوين أو حفل موسيقي أو حفلة صديق أو أي شيء آخر؟ يُرجى تزويدي بهذا السياق.\", \"يرجى وصف الأنشطة التي تتصورها في ذهنك.\"]', '[\"هل لديك وضعٌ معينٌ في ذهنك؟ لا تتردد في طرح أي سؤال.\", \"يرجى وصف الوضع الذي تفكر فيه.\"]', '[{\"original\": \"هل توجد أي فعاليات اليوم؟\", \"translated\": \"Gibt es heute irgendwelche Veranstaltungen?\"}, {\"original\": \"هل هناك أي شيء مميزٌ في هذه المناسبة؟\", \"translated\": \"Gibt es bei diesem Fest etwas Besonderes?\"}, {\"original\": \"أين تُقام الاحتفالات؟\", \"translated\": \"Wo findet die Feier statt?\"}, {\"original\": \"كيف يمكنني شراء التذاكر؟\", \"translated\": \"Wie kann ich Tickets kaufen?\"}, {\"original\": \"متى يبدأ العرض؟\", \"translated\": \"Wann beginnt die Aufführung?\"}, {\"original\": \"ما الأطعمة التقليدية المتوفرة؟\", \"translated\": \"Welche traditionellen Speisen gibt es?\"}, {\"original\": \"المكان حيويٌّ جدًّا هنا.\", \"translated\": \"Es ist hier wirklich lebendig.\"}, {\"original\": \"هل توجد أنشطة تراثية شعبية؟\", \"translated\": \"Gibt es Volksaktivitäten?\"}, {\"original\": \"أعياد سعيدة!\", \"translated\": \"Frohe Feiertage!\"}, {\"original\": \"متى تنتهي الفعالية؟\", \"translated\": \"Wann endet die Veranstaltung?\"}]', 10, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزوّدني بعشر عبارات شائعة يمكنني استخدامها في متحف أو معرض فني؟\", \"رائع! إليك عشر عبارات شائعة مرتبطة بمتحف أو معرض فني، مع ترجمتها إلى الألمانية:\"]', '[\"زيارة\", \"جولة مرشدة\", \"شراء التذاكر\"]', 'ar', '[\"لحد الآن، هل لديك موقف معيّن في بالك، مثل طلب كتيب إرشادي، أو عبارات مرتبطة بخريطة الطريق، أو عبارات تتعلق بالتعليق على المعروضات؟ لا تتردد في طرح سؤالك.\", \"صف لي الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"هل لديكم أجهزة دليل صوتي؟\", \"translated\": \"Bieten Sie Audio-Führungen an?\"}, {\"original\": \"من صاحب هذا العمل الفني؟\", \"translated\": \"Wer ist der Schöpfer dieses Kunstwerks?\"}, {\"original\": \"أين يقع أثمن قطعة في المتحف؟\", \"translated\": \"Wo befindet sich das wertvollste Exponat des Museums?\"}, {\"original\": \"هل يُسمح بالتقاط الصور؟\", \"translated\": \"Ist das Fotografieren erlaubt?\"}, {\"original\": \"هل توجد معارض خاصة هنا؟\", \"translated\": \"Gibt es hier besondere Sonderausstellungen?\"}, {\"original\": \"كم يستغرق الجولة من الوقت؟\", \"translated\": \"Wie lange dauert der Besuch?\"}, {\"original\": \"هل يمكنكم إعطاؤنا مقدمة عامة؟\", \"translated\": \"Könnten Sie uns bitte eine kurze Einführung geben?\"}, {\"original\": \"هذه الأعمال رائعةٌ حقًّا.\", \"translated\": \"Diese Werke sind wirklich exquisit.\"}, {\"original\": \"أين تقع متجر الهدايا التذكارية؟\", \"translated\": \"Wo befindet sich der Souvenirshop?\"}]', 11, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بعشر عبارات شائعة يمكنني استخدامها في مقهى؟\", \"رائع! إليك عشر عبارات شائعة مرتبطة بمقهى، مع ترجمتها إلى الألمانية:\"]', '[\"طلب قهوة\", \"الاسترخاء\", \"التفاعل الاجتماعي\"]', 'ar', '[\"لليوم، هل لديك موقف معيّن في ذهنك، مثل طلب القائمة أو الثلج أو المشروبات الساخنة أو غيرها من المنتجات؟ لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"سأطلب لاتيه، من فضلك.\", \"translated\": \"Ich hätte gerne einen Latte, bitte.\"}, {\"original\": \"هل لديكم اتصال واي فاي؟\", \"translated\": \"Haben Sie WLAN?\"}, {\"original\": \"هل يمكنني رؤية القائمة، من فضلك؟\", \"translated\": \"Könnte ich bitte die Speisekarte sehen?\"}, {\"original\": \"هل يُسمح بإعادة التعبئة؟\", \"translated\": \"Dürfen Getränke nachgefüllt werden?\"}, {\"original\": \"هل قهوةً الخاصة جاهزة بالفعل؟\", \"translated\": \"Ist mein Kaffee schon fertig?\"}, {\"original\": \"كم من الوقت يمكنني الجلوس هنا؟\", \"translated\": \"Wie lange darf ich hier sitzen?\"}, {\"original\": \"هل يمكنك أخذ صورة لنا؟\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"أين الحمام؟\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"الفاتورة، من فضلك. شكرًا لك.\", \"translated\": \"Die Rechnung, bitte. Vielen Dank.\"}, {\"original\": \"إنها تذوق جيدٌ جدًا.\", \"translated\": \"Es schmeckt wirklich gut.\"}]', 12, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser au restaurant ?\", \"Fantastique ! Voici 10 expressions courantes liées au restaurant, accompagnées de traductions en allemand :\"]', '[\"Repas\", \"Commande\", \"Règlement\"]', 'fr', '[\"Pour l’instant, avez-vous une situation particulière en tête, par exemple commander des boissons, formuler une réclamation ou demander des informations sur les ingrédients ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\", \"translated\": \"Entschuldigung, wie lange dauert es noch, bis unser Essen fertig ist?\"}, {\"original\": \"Une table pour deux, s’il vous plaît.\", \"translated\": \"Ein Tisch für zwei Personen, bitte.\"}, {\"original\": \"Pourrions-nous voir la carte, s’il vous plaît ?\", \"translated\": \"Könnten wir bitte die Speisekarte sehen?\"}, {\"original\": \"Avez-vous des plats signature à nous recommander ?\", \"translated\": \"Haben Sie empfehlenswerte Hausgerichte?\"}, {\"original\": \"Je voudrais commander ceci et cela.\", \"translated\": \"Ich möchte dies und das bestellen.\"}, {\"original\": \"Un verre d’eau, s’il vous plaît. Merci.\", \"translated\": \"Ein Glas Wasser, bitte. Danke.\"}, {\"original\": \"L’addition, s’il vous plaît.\", \"translated\": \"Die Rechnung, bitte.\"}, {\"original\": \"Puis-je payer par carte bancaire ?\", \"translated\": \"Kann ich mit Kreditkarte bezahlen?\"}, {\"original\": \"Pourriez-vous emballer cela à emporter, s’il vous plaît ?\", \"translated\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\"}, {\"original\": \"Le repas était délicieux, merci.\", \"translated\": \"Das Essen war köstlich, danke.\"}]', 1, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser à l\'hôtel ?\", \"Fantastique ! Voici 10 expressions courantes liées à l\'hôtel, accompagnées de leurs traductions en allemand :\"]', '[\"Enregistrement\", \"Départ\", \"Service en chambre\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple l\'emplacement de la chambre, d\'autres services hôteliers ou le départ ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Bonjour, j\'ai une réservation. Voici mon passeport.\", \"translated\": \"Hallo, ich habe eine Reservierung. Hier ist mein Reisepass.\"}, {\"original\": \"Avez-vous des chambres disponibles ?\", \"translated\": \"Haben Sie noch Zimmer frei?\"}, {\"original\": \"Excusez-moi, l\'hôtel dispose-t-il d\'une salle de sport ou d\'une buanderie ?\", \"translated\": \"Entschuldigung, hat das Hotel einen Fitnessraum oder eine Wäscherei?\"}, {\"original\": \"À quelle heure commence le petit-déjeuner ?\", \"translated\": \"Wann beginnt das Frühstück?\"}, {\"original\": \"Pourriez-vous me donner la clé de ma chambre, s\'il vous plaît ?\", \"translated\": \"Könnten Sie mir bitte den Zimmerschlüssel geben?\"}, {\"original\": \"Pourriez-vous m\'aider à porter mes bagages jusqu\'à ma chambre ?\", \"translated\": \"Könnten Sie mir helfen, mein Gepäck aufs Zimmer zu tragen?\"}, {\"original\": \"Comment puis-je appeler le service d\'étage ?\", \"translated\": \"Wie rufe ich den Zimmerservice?\"}, {\"original\": \"À quelle heure doit-on quitter la chambre ?\", \"translated\": \"Wann ist der Check-out?\"}, {\"original\": \"Pourriez-vous me faire un reçu / une facture ?\", \"translated\": \"Könnten Sie mir bitte eine Quittung / eine Rechnung ausstellen?\"}, {\"original\": \"Puis-je laisser mon bagage ici ?\", \"translated\": \"Darf ich mein Gepäck hier lassen?\"}]', 2, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser à l\'aéroport ?\", \"Formidable ! Voici 10 expressions courantes liées à l\'aéroport, accompagnées de leurs traductions en allemand :\"]', '[\"Enregistrement\", \"Embarquement\", \"Bagages\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, comme l\'enregistrement, la récupération des bagages ou la location de voiture ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Où se trouve le comptoir d\'enregistrement ?\", \"translated\": \"Wo ist der Check-in-Schalter?\"}, {\"original\": \"Je voudrais un siège côté fenêtre, s\'il vous plaît.\", \"translated\": \"Ich hätte gerne einen Fensterplatz, bitte.\"}, {\"original\": \"Ce vol est-il retardé ?\", \"translated\": \"Ist dieser Flug verspätet?\"}, {\"original\": \"Je dois enregistrer ce bagage.\", \"translated\": \"Ich muss dieses Gepäck aufgeben.\"}, {\"original\": \"Où se trouve la porte d\'embarquement ?\", \"translated\": \"Wo ist die Boarding-Tür?\"}, {\"original\": \"L\'avion est sur le point de décoller.\", \"translated\": \"Das Flugzeug startet gleich.\"}, {\"original\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\", \"translated\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\"}, {\"original\": \"Où se trouve la boutique hors taxes ?\", \"translated\": \"Wo ist der Duty-free-Shop?\"}, {\"original\": \"Je ne trouve pas ma valise.\", \"translated\": \"Ich kann meinen Koffer nicht finden.\"}, {\"original\": \"Proposez-vous un service de fauteuil roulant ?\", \"translated\": \"Bieten Sie einen Rollstuhlservice an?\"}]', 3, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans les transports en commun ?\", \"Formidable ! Voici 10 expressions courantes liées aux transports en commun, accompagnées de leurs traductions en allemand :\"]', '[\"Prendre le bus ou le métro\", \"Acheter des billets\", \"Changer de transport\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander l\'arrêt du bus, le prix du billet ou indiquer que vous souhaitez descendre ? N\'hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Ce bus va-t-il jusqu\'à la gare routière ?\", \"translated\": \"Fährt dieser Bus bis zum Busbahnhof?\"}, {\"original\": \"Quel est le prochain arrêt ?\", \"translated\": \"Was ist die nächste Haltestelle?\"}, {\"original\": \"Où puis-je acheter un billet ?\", \"translated\": \"Wo kann ich ein Ticket kaufen?\"}, {\"original\": \"Un billet pour XX, s\'il vous plaît.\", \"translated\": \"Ein Ticket nach XX, bitte.\"}, {\"original\": \"Dois-je changer de transport ?\", \"translated\": \"Muss ich umsteigen?\"}, {\"original\": \"Combien de temps avant le prochain train de métro ?\", \"translated\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\"}, {\"original\": \"Excusez-moi, je voudrais passer.\", \"translated\": \"Entschuldigung, bitte lassen Sie mich durch.\"}, {\"original\": \"Cette place est-elle occupée ?\", \"translated\": \"Ist dieser Platz besetzt?\"}, {\"original\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d\'aller à XX ?\", \"translated\": \"Entschuldigung, wo kann ich zur Linie 2 wechseln, um nach XX zu gelangen?\"}, {\"original\": \"Comment puis-je me rendre à XX ?\", \"translated\": \"Wie komme ich nach XX?\"}]', 4, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans un lieu touristique ?\", \"Formidable ! Voici 10 expressions courantes liées aux lieux touristiques, accompagnées de leurs traductions en allemand :\"]', '[\"Visite touristique\", \"Prendre des photos\", \"Acheter des billets\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander le prix des billets, trouver un parking ou obtenir un service de guide touristique ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Combien coûte le droit d\'entrée ?\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"Y a-t-il des billets étudiants disponibles ?\", \"translated\": \"Gibt es ermäßigte Eintrittskarten für Studenten?\"}, {\"original\": \"À quelle heure ouvre l’attraction ?\", \"translated\": \"Wann öffnet die Sehenswürdigkeit?\"}, {\"original\": \"Quelles sont les activités amusantes à faire ici ?\", \"translated\": \"Was kann man hier alles Lustiges machen?\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"Où se trouve le bus touristique ?\", \"translated\": \"Wo befindet sich der Sightseeing-Bus?\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"Wo sind die Toiletten?\"}, {\"original\": \"Où est le meilleur point de vue ?\", \"translated\": \"Wo ist der beste Aussichtspunkt?\"}, {\"original\": \"Le paysage est magnifique ici.\", \"translated\": \"Die Landschaft hier ist wunderschön.\"}, {\"original\": \"Y a-t-il une visite guidée disponible ?\", \"translated\": \"Gibt es eine geführte Tour?\"}]', 5, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser pour prendre un taxi ou utiliser un service de taxi ?\", \"Excellent ! Voici 10 expressions courantes liées aux taxis ou aux services de taxi, accompagnées de leurs traductions en allemand :\"]', '[\"Prendre un taxi\", \"Indiquer la destination\", \"Paiement\"]', 'fr', '[\"Pour l’instant, que souhaitez-vous faire principalement : demander la destination, connaître le montant approximatif, ou demander une facture ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Où puis-je prendre un taxi ?\", \"translated\": \"Wo kann ich ein Taxi nehmen?\"}, {\"original\": \"Veuillez me conduire à cette adresse.\", \"translated\": \"Bitte fahren Sie mich zu dieser Adresse.\"}, {\"original\": \"À combien s’élèvera approximativement la course ?\", \"translated\": \"Wie viel wird die Fahrt ungefähr kosten?\"}, {\"original\": \"Pourriez-vous utiliser le compteur, s’il vous plaît ?\", \"translated\": \"Könnten Sie bitte den Taxameter benutzen?\"}, {\"original\": \"Pourriez-vous rouler un peu plus vite, je suis pressé(e).\", \"translated\": \"Könnten Sie bitte etwas schneller fahren? Ich habe es eilig.\"}, {\"original\": \"Veuillez vous arrêter ici.\", \"translated\": \"Bitte halten Sie hier an.\"}, {\"original\": \"Acceptez-vous les cartes bancaires ou les paiements mobiles ?\", \"translated\": \"Akzeptieren Sie Kreditkarten oder Mobile Payments?\"}, {\"original\": \"Pourrais-je avoir un reçu, s’il vous plaît ?\", \"translated\": \"Könnte ich bitte eine Quittung haben?\"}, {\"original\": \"Merci, monsieur/madame le chauffeur.\", \"translated\": \"Danke, Fahrer!\"}, {\"original\": \"Il reste encore combien de temps ?\", \"translated\": \"Wie viel Zeit bleibt noch?\"}]', 6, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser en pharmacie ?\", \"Fantastique ! Voici 10 expressions courantes liées à la pharmacie, accompagnées de traductions en allemand.\"]', '[\"Acheter des médicaments\", \"Consulter\", \"Payer\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander des instructions sur la prise d’un médicament, des formulations liées à l’utilisation de votre assurance, ou la durée du traitement ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Avez-vous des médicaments contre le rhume ?\", \"translated\": \"Haben Sie Erkältungsmittel?\"}, {\"original\": \"Comment dois-je prendre ce médicament ?\", \"translated\": \"Wie soll ich dieses Medikament einnehmen?\"}, {\"original\": \"Avez-vous des analgésiques ?\", \"translated\": \"Haben Sie Schmerzmittel?\"}, {\"original\": \"Y a-t-il une notice d’utilisation ?\", \"translated\": \"Gibt es eine Gebrauchsanweisung?\"}, {\"original\": \"Ce médicament a-t-il des effets secondaires ?\", \"translated\": \"Hat dieses Medikament Nebenwirkungen?\"}, {\"original\": \"Puis-je utiliser ma carte d’assurance maladie ?\", \"translated\": \"Kann ich meine Krankenversicherungskarte benutzen?\"}, {\"original\": \"Pourriez-vous me donner une boîte de pansements, s’il vous plaît ?\", \"translated\": \"Könnten Sie mir bitte eine Packung Pflaster geben?\"}, {\"original\": \"Avez-vous des antipyrétiques ?\", \"translated\": \"Haben Sie Fiebersenkungsmittel?\"}, {\"original\": \"Je me suis un peu écorché(e). Avez-vous un antiseptique et des pansements ?\", \"translated\": \"Ich habe mir ein bisschen die Haut aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\"}, {\"original\": \"À quelle heure fermez-vous ?\", \"translated\": \"Wann schließen Sie?\"}]', 7, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans le cadre des services d\'urgence ?\", \"Fantastique ! Voici 10 expressions courantes liées aux services d\'urgence, accompagnées de leurs traductions en allemand :\"]', '[\"Appeler la police\", \"Premiers secours\", \"Demander de l\'aide\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation d\'urgence précise en tête, comme un incendie, une personne blessée et qui a besoin d\'aide, ou un appel d\'urgence ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Veuillez m\'aider à appeler une ambulance.\", \"translated\": \"Bitte helfen Sie mir, einen Krankenwagen zu rufen.\"}, {\"original\": \"Où se trouve l\'hôpital ?\", \"translated\": \"Wo ist das Krankenhaus?\"}, {\"original\": \"Quelqu\'un est blessé.\", \"translated\": \"Jemand ist verletzt.\"}, {\"original\": \"Veuillez m\'aider.\", \"translated\": \"Bitte helfen Sie mir.\"}, {\"original\": \"Où se trouve le commissariat de police ?\", \"translated\": \"Wo ist die nächste Polizeistation?\"}, {\"original\": \"J\'ai perdu mes affaires.\", \"translated\": \"Ich habe meinen Besitz verloren.\"}, {\"original\": \"Quel est le numéro des pompiers ?\", \"translated\": \"Wie lautet die Notrufnummer für die Feuerwehr?\"}, {\"original\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le commissariat de police le plus proche ?\", \"translated\": \"Ich habe meinen Reisepass verloren. Wissen Sie, wo die nächste Polizeistation ist?\"}, {\"original\": \"Y a-t-il une sortie de secours ?\", \"translated\": \"Gibt es einen Notausgang?\"}, {\"original\": \"Quelqu\'un s\'est évanoui.\", \"translated\": \"Jemand ist in Ohnmacht gefallen.\"}]', 8, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser à la plage ou au bord de la piscine ?\", \"Formidable ! Voici 10 expressions courantes liées à la plage ou au bord de la piscine, accompagnées de leurs traductions en allemand :\"]', '[\"Natation\", \"Bain de soleil\", \"Sports de plage\"]', 'fr', '[\"Pour l’instant, pourriez-vous me préciser le cadre de l’événement ou de la fête locale à laquelle vous participez, par exemple un festival culturel, un festival gastronomique ou un festival musical ? Veuillez indiquer ce cadre.\", \"Veuillez décrire les activités auxquelles vous participez.\"]', '[\"Avez-vous une situation particulière en tête ? N’hésitez pas à demander.\", \"Décrivez-moi la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\", \"translated\": \"Schauen Sie mal! Die Wellen dort drüben sind wirklich groß.\"}, {\"original\": \"N\'oubliez pas d\'appliquer de la crème solaire, les rayons UV sont très forts ici.\", \"translated\": \"Vergessen Sie nicht, Sonnencreme aufzutragen – die UV-Strahlen sind hier sehr stark.\"}, {\"original\": \"Le sable de cette plage est tellement fin qu’on a l’impression de marcher sur du coton.\", \"translated\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle laufen.\"}, {\"original\": \"Et si on jouait au volley-ball sur la plage ?\", \"translated\": \"Wie wäre es mit einer Partie Beachvolleyball?\"}, {\"original\": \"Les voiliers au loin sont magnifiques.\", \"translated\": \"Die Segelboote in der Ferne sehen wunderschön aus.\"}, {\"original\": \"L’eau est tellement claire ici qu’on peut même voir les poissons.\", \"translated\": \"Das Wasser ist hier so klar, dass man sogar die Fische sehen kann.\"}, {\"original\": \"Allons chercher des coquillages.\", \"translated\": \"Lass uns Muscheln sammeln gehen.\"}, {\"original\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\", \"translated\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\"}, {\"original\": \"J’ai entendu dire que les fruits de mer sont très frais ici, allons-en goûter.\", \"translated\": \"Ich habe gehört, dass die Meeresfrüchte hier besonders frisch sind – lasst uns welche probieren!\"}, {\"original\": \"La marée monte, rentrons vers la rive.\", \"translated\": \"Die Flut kommt herein, gehen wir zur Küste zurück.\"}]', 9, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser lors d\'activités et de festivals locaux ?\", \"Formidable ! Voici 10 expressions courantes liées aux activités et festivals locaux, accompagnées de leurs traductions en allemand :\"]', '[\"Assister à des événements\", \"Célébrer des festivals\", \"Découvrir la culture\"]', 'fr', '[\"Pour l\'instant, pourriez-vous m\'indiquer le contexte de l\'événement ou du festival local auquel vous comptez participer, par exemple Halloween, un concert, une fête entre amis ou autre chose ? Veuillez préciser le contexte.\", \"Veuillez décrire les activités qui vous viennent à l\'esprit.\"]', '[\"Avez-vous une situation particulière en tête ? N\'hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[{\"original\": \"Y a-t-il des événements aujourd\'hui ?\", \"translated\": \"Gibt es heute irgendwelche Veranstaltungen?\"}, {\"original\": \"Y a-t-il quelque chose de spécial à propos de ce festival ?\", \"translated\": \"Gibt es bei diesem Festival etwas Besonderes?\"}, {\"original\": \"Où se déroule la célébration ?\", \"translated\": \"Wo findet die Feier statt?\"}, {\"original\": \"Comment puis-je acheter des billets ?\", \"translated\": \"Wie kann ich Tickets kaufen?\"}, {\"original\": \"À quelle heure commence le spectacle ?\", \"translated\": \"Wann beginnt die Vorstellung?\"}, {\"original\": \"Quels sont les plats traditionnels proposés ?\", \"translated\": \"Welche traditionellen Speisen gibt es?\"}, {\"original\": \"C\'est vraiment animé ici.\", \"translated\": \"Es ist hier wirklich lebhaft.\"}, {\"original\": \"Y a-t-il des activités populaires ?\", \"translated\": \"Gibt es volkstümliche Aktivitäten?\"}, {\"original\": \"Joyeuses fêtes !\", \"translated\": \"Frohe Feiertage!\"}, {\"original\": \"À quelle heure se termine l\'événement ?\", \"translated\": \"Wann endet die Veranstaltung?\"}]', 10, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans un musée ou une galerie d\'art ?\", \"Fantastique ! Voici 10 expressions courantes liées aux musées ou galeries d\'art, accompagnées de leurs traductions en allemand :\"]', '[\"Visite\", \"Visite guidée\", \"Achat de billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander une notice explicative, des expressions liées à un plan d\'orientation, ou des formulations pour commenter une exposition ? N\'hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Combien coûte le droit d\'entrée ?\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"Proposez-vous des audioguides ?\", \"translated\": \"Bieten Sie Audioführungen an?\"}, {\"original\": \"Qui est l\'auteur de cette œuvre ?\", \"translated\": \"Wer ist der Schöpfer dieses Kunstwerks?\"}, {\"original\": \"Où se trouve la pièce la plus précieuse du musée ?\", \"translated\": \"Wo befindet sich das wertvollste Exponat des Museums?\"}, {\"original\": \"La prise de photos est-elle autorisée ?\", \"translated\": \"Ist das Fotografieren erlaubt?\"}, {\"original\": \"Y a-t-il des expositions spéciales ici ?\", \"translated\": \"Gibt es hier besondere Ausstellungen?\"}, {\"original\": \"Combien de temps dure la visite ?\", \"translated\": \"Wie lange dauert der Besuch?\"}, {\"original\": \"Pourriez-vous nous en faire une présentation ?\", \"translated\": \"Könnten Sie uns bitte eine Einführung geben?\"}, {\"original\": \"Ces œuvres sont vraiment exquises.\", \"translated\": \"Diese Werke sind wirklich exquisit.\"}, {\"original\": \"Où se trouve la boutique de souvenirs ?\", \"translated\": \"Wo befindet sich der Souvenirshop?\"}]', 11, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans un café ?\", \"Formidable ! Voici 10 expressions courantes liées au café, accompagnées de leurs traductions en allemand :\"]', '[\"Commander un café\", \"Se reposer\", \"Socialiser\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander la carte, de la glace ou des boissons chaudes, d\'autres produits ? N\'hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Je prendrai un latte, s\'il vous plaît.\", \"translated\": \"Ich hätte gerne einen Latte, bitte.\"}, {\"original\": \"Avez-vous le Wi-Fi ?\", \"translated\": \"Haben Sie WLAN?\"}, {\"original\": \"Pourrais-je voir la carte, s\'il vous plaît ?\", \"translated\": \"Könnte ich bitte die Speisekarte sehen?\"}, {\"original\": \"Est-ce que les recharges sont autorisées ?\", \"translated\": \"Sind Nachfüllungen erlaubt?\"}, {\"original\": \"Mon café est-il prêt ?\", \"translated\": \"Ist mein Kaffee schon fertig?\"}, {\"original\": \"Puis-je rester ici longtemps ?\", \"translated\": \"Wie lange darf ich hier sitzen bleiben?\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"L\'addition, s\'il vous plaît. Merci.\", \"translated\": \"Die Rechnung, bitte. Vielen Dank.\"}, {\"original\": \"C\'est vraiment délicieux.\", \"translated\": \"Es schmeckt wirklich sehr gut.\"}]', 12, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Me gustaría que me proporcionara 10 frases comunes que pueda usar en el aeropuerto.\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el aeropuerto, junto con sus traducciones al japonés:\"]', '[\"Facturación\", \"Embarque\", \"Facturación de equipaje\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como la facturación, la recogida de equipaje o el servicio de alquiler de coches? No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Dónde está el mostrador de facturación?\", \"translated\": \"チェックインカウンターはどこですか？\"}, {\"original\": \"Quisiera un asiento junto a la ventana, por favor.\", \"translated\": \"窓際の席をお願いします。\"}, {\"original\": \"¿Este vuelo tiene retraso?\", \"translated\": \"この便は遅れていますか？\"}, {\"original\": \"Necesito facturar este equipaje.\", \"translated\": \"この荷物を預けたいのですが。\"}, {\"original\": \"¿Dónde está la puerta de embarque?\", \"translated\": \"搭乗口はどこですか？\"}, {\"original\": \"El avión está a punto de despegar.\", \"translated\": \"飛行機が今から離陸します。\"}, {\"original\": \"¿Necesito sacar mi portátil y mi power bank?\", \"translated\": \"ノートパソコンとモバイルバッテリーを取り出さなければなりませんか？\"}, {\"original\": \"¿Dónde está la tienda libre de impuestos?\", \"translated\": \"免税店はどこですか？\"}, {\"original\": \"No puedo encontrar mi maleta.\", \"translated\": \"私のスーツケースが見つかりません。\"}, {\"original\": \"¿Ofrecen servicio de silla de ruedas?\", \"translated\": \"車椅子サービスはありますか？\"}]', 3, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en el transporte público?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el transporte público, junto con sus traducciones al japonés:\"]', '[\"Tomar autobús o metro\", \"Comprar boletos\", \"Hacer trasbordo\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como preguntar sobre la parada de autobús, el precio del boleto o dónde bajarse? No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Este autobús va a la terminal?\", \"translated\": \"このバスはターミナルに行きますか？\"}, {\"original\": \"¿Cuál es la próxima parada?\", \"translated\": \"次の停車駅はどこですか？\"}, {\"original\": \"¿Dónde puedo comprar un boleto?\", \"translated\": \"切符はどこで買えますか？\"}, {\"original\": \"Un boleto para XX, por favor.\", \"translated\": \"XX行きの切符を一枚、お願いします。\"}, {\"original\": \"¿Tengo que hacer trasbordo?\", \"translated\": \"乗り換えが必要ですか？\"}, {\"original\": \"¿Cuánto falta para el próximo tren del metro?\", \"translated\": \"次の地下鉄の列車まであとどのくらいですか？\"}, {\"original\": \"Perdón, déjeme pasar, por favor.\", \"translated\": \"すみません、通らせてください。\"}, {\"original\": \"¿Esta silla está ocupada?\", \"translated\": \"この席は空いていますか？\"}, {\"original\": \"Disculpe, ¿dónde puedo hacer trasbordo a la Línea 2 para llegar a XX?\", \"translated\": \"すみません、XXへ行くのに、どこで2号線に乗り換えればいいですか？\"}, {\"original\": \"¿Cómo llego a XX?\", \"translated\": \"XXへはどう行けばいいですか？\"}]', 4, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en lugares turísticos?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con lugares turísticos, junto con sus traducciones al japonés:\"]', '[\"Turismo\", \"Sacar fotos\", \"Comprar entradas\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, por ejemplo: preguntar sobre el precio de las entradas, buscar un estacionamiento o solicitar un servicio de guía turística? ¡No dude en preguntar!\", \"Por favor, describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"¿Hay entradas para estudiantes?\", \"translated\": \"学生用のチケットはありますか？\"}, {\"original\": \"¿A qué hora abre esta atracción?\", \"translated\": \"この観光スポットはいつから開いていますか？\"}, {\"original\": \"¿Qué cosas divertidas se pueden hacer aquí?\", \"translated\": \"ここではどんな楽しいことが体験できますか？\"}, {\"original\": \"¿Podría hacernos una foto?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"¿Dónde está el autobús turístico?\", \"translated\": \"観光バスはどこですか？\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"¿Cuál es el mejor lugar para ver las vistas?\", \"translated\": \"一番景色がきれいな見晴らしスポットはどこですか？\"}, {\"original\": \"El paisaje aquí es hermoso.\", \"translated\": \"ここでの景色はとても美しいです。\"}, {\"original\": \"¿Hay visitas guiadas disponibles?\", \"translated\": \"ガイド付きツアーはありますか？\"}]', 5, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en servicios de taxis o taxis?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con servicios de taxis o taxis, junto con sus traducciones al japonés:\"]', '[\"Tomar un taxi\", \"Indicar el destino\", \"Pago\"]', 'es', '[\"Por ahora, ¿qué es lo que más quiere hacer ahora? Por ejemplo, preguntar la dirección, el precio o solicitar una factura. ¡No dude en preguntar!\", \"Por favor, descríbame la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Dónde puedo conseguir un taxi?\", \"translated\": \"タクシーはどこで乗れますか？\"}, {\"original\": \"Por favor, lléveme a esta dirección.\", \"translated\": \"この住所までお願いします。\"}, {\"original\": \"¿Cuánto costará aproximadamente?\", \"translated\": \"おおよそいくらくらいかかりますか？\"}, {\"original\": \"¿Podría usar el taxímetro, por favor?\", \"translated\": \"メーターを使っていただけますか？\"}, {\"original\": \"Por favor, conduzca un poco más rápido, tengo prisa.\", \"translated\": \"急いでいるので、少し速くお願いします。\"}, {\"original\": \"Por favor, pare aquí.\", \"translated\": \"ここで止めてください。\"}, {\"original\": \"¿Acepta tarjetas o pagos móviles?\", \"translated\": \"カードやモバイル決済は使えますか？\"}, {\"original\": \"¿Podría darme un recibo, por favor?\", \"translated\": \"領収書をもらえますか？\"}, {\"original\": \"Gracias, conductor.\", \"translated\": \"ありがとうございました、運転手さん。\"}, {\"original\": \"¿Cuánto falta todavía?\", \"translated\": \"あとどれくらいですか？\"}]', 6, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en una farmacia?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con las farmacias, junto con sus traducciones al japonés:\"]', '[\"Comprar medicamentos\", \"Consulta\", \"Pago\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir instrucciones sobre cómo tomar un medicamento, frases relacionadas con el uso del seguro médico o la duración del tratamiento? No dude en preguntar.\", \"Por favor, descríbame la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Tiene medicamento para el resfriado?\", \"translated\": \"風邪薬はありますか？\"}, {\"original\": \"¿Cómo debo tomar este medicamento?\", \"translated\": \"この薬の飲み方はどうすればいいですか？\"}, {\"original\": \"¿Tiene algún analgésico?\", \"translated\": \"痛み止めはありますか？\"}, {\"original\": \"¿Hay un folleto informativo?\", \"translated\": \"説明書はありますか？\"}, {\"original\": \"¿Este medicamento tiene efectos secundarios?\", \"translated\": \"この薬には副作用がありますか？\"}, {\"original\": \"¿Puedo usar mi tarjeta de seguro médico?\", \"translated\": \"医療保険証は使えますか？\"}, {\"original\": \"¿Podría darme una caja de tiritas, por favor?\", \"translated\": \"絆創膏を1箱お願いします。\"}, {\"original\": \"¿Tiene algún antipirético?\", \"translated\": \"解熱剤はありますか？\"}, {\"original\": \"Me he raspado un poco. ¿Tiene antiséptico y tiritas?\", \"translated\": \"ちょっと擦り傷をしました。消毒液と絆創膏はありますか？\"}, {\"original\": \"¿A qué hora cierran?\", \"translated\": \"何時まで営業していますか？\"}]', 7, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría facilitarme 10 frases comunes que pueda usar en servicios de emergencia?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con servicios de emergencia, junto con sus traducciones al japonés:\"]', '[\"Llamar a la policía\", \"Primeros auxilios\", \"Pedir ayuda\"]', 'es', '[\"Por ahora, ¿tiene alguna situación de emergencia específica en mente, como incendio, persona herida que necesita ayuda o llamada de emergencia? No dude en preguntar.\", \"Descríbame la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Por favor, ayúdeme a llamar a una ambulancia.\", \"translated\": \"救急車を呼んでください。\"}, {\"original\": \"¿Dónde está el hospital?\", \"translated\": \"病院はどこですか？\"}, {\"original\": \"Alguien resultó herido.\", \"translated\": \"誰かがけがをしました。\"}, {\"original\": \"Por favor, ayúdeme.\", \"translated\": \"助けてください。\"}, {\"original\": \"¿Dónde está la comisaría de policía?\", \"translated\": \"警察署はどこですか？\"}, {\"original\": \"He perdido mis pertenencias.\", \"translated\": \"荷物をなくしてしまいました。\"}, {\"original\": \"¿Cuál es el número del cuerpo de bomberos?\", \"translated\": \"消防署の電話番号は何番ですか？\"}, {\"original\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría de policía más cercana?\", \"translated\": \"パスポートを紛失しました。最寄りの警察署はどこかご存じですか？\"}, {\"original\": \"¿Hay una salida de emergencia?\", \"translated\": \"非常口はありますか？\"}, {\"original\": \"Alguien se ha desmayado.\", \"translated\": \"誰かが気を失いました。\"}]', 8, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en actividades y festivales locales?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con actividades y festivales locales, junto con sus traducciones al japonés:\"]', '[\"Asistir a eventos\", \"Celebrar festivales\", \"Aprender sobre la cultura\"]', 'es', '[\"Por ahora, ¿podría indicarme el contexto del evento o festival local al que asistirá, por ejemplo, Halloween, un concierto, una fiesta con amigos u otra ocasión? Por favor, proporcione dicho contexto.\", \"Describa las actividades que tiene en mente.\"]', '[\"¿Tiene alguna situación específica en mente? No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[{\"original\": \"¿Hay algún evento hoy?\", \"translated\": \"今日は何かイベントがありますか？\"}, {\"original\": \"¿Hay algo especial sobre este festival?\", \"translated\": \"この祭りには何か特別なことがありますか？\"}, {\"original\": \"¿Dónde se lleva a cabo la celebración?\", \"translated\": \"お祝いはどこで行われますか？\"}, {\"original\": \"¿Cómo puedo comprar las entradas?\", \"translated\": \"チケットはどこで購入できますか？\"}, {\"original\": \"¿A qué hora comienza la presentación?\", \"translated\": \"パフォーマンスは何時から始まりますか？\"}, {\"original\": \"¿Qué comida tradicional hay?\", \"translated\": \"どんな伝統料理がありますか？\"}, {\"original\": \"Aquí está muy animado.\", \"translated\": \"ここは本当に活気がありますね。\"}, {\"original\": \"¿Hay alguna actividad popular?\", \"translated\": \"民俗的な活動はありますか？\"}, {\"original\": \"¡Felices fiestas!\", \"translated\": \"楽しい祝日を！\"}, {\"original\": \"¿A qué hora termina el evento?\", \"translated\": \"イベントは何時までですか？\"}]', 10, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un museo o galería de arte?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con museos o galerías de arte, junto con sus traducciones al japonés:\"]', '[\"Visitar\", \"Visita guiada\", \"Comprar entradas\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como solicitar un manual informativo, frases relacionadas con un plano del recorrido o frases para comentar las exposiciones? ¡No dude en preguntar!\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"¿Tienen guías de audio?\", \"translated\": \"オーディオガイドはありますか？\"}, {\"original\": \"¿Quién creó esta obra de arte?\", \"translated\": \"この作品は誰が制作したものですか？\"}, {\"original\": \"¿Dónde se encuentra la pieza más valiosa del museo?\", \"translated\": \"博物館で最も価値のある作品はどこにありますか？\"}, {\"original\": \"¿Está permitida la fotografía?\", \"translated\": \"写真撮影は許可されていますか？\"}, {\"original\": \"¿Hay alguna exposición especial aquí?\", \"translated\": \"ここでは特別展は開催されていますか？\"}, {\"original\": \"¿Cuánto tiempo dura la visita?\", \"translated\": \"見学にはどのくらい時間がかかりますか？\"}, {\"original\": \"¿Podrían darnos una introducción?\", \"translated\": \"簡単な紹介をしていただけますか？\"}, {\"original\": \"Estas obras son verdaderamente exquisitas.\", \"translated\": \"これらの作品は本当に素晴らしいです。\"}, {\"original\": \"¿Dónde está la tienda de recuerdos?\", \"translated\": \"お土産ショップはどこですか？\"}]', 11, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en una cafetería?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con las cafeterías, junto con sus traducciones al japonés:\"]', '[\"Pedir café\", \"Descansar\", \"Socializar\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como pedir el menú, bebidas frías o calientes, otros productos? ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"Pediré un latte, por favor.\", \"translated\": \"ラテをください。\"}, {\"original\": \"¿Tienen conexión Wi-Fi?\", \"translated\": \"Wi-Fiは使えますか？\"}, {\"original\": \"¿Podría ver el menú, por favor?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"¿Se permiten recargas?\", \"translated\": \"ドリンクの追加注文（リフィル）はできますか？\"}, {\"original\": \"¿Ya está listo mi café?\", \"translated\": \"私のコーヒーはできましたか？\"}, {\"original\": \"¿Cuánto tiempo puedo quedarme aquí sentado?\", \"translated\": \"ここに座っていられる時間は何分ですか？\"}, {\"original\": \"¿Podría hacernos una foto?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"La cuenta, por favor. Gracias.\", \"translated\": \"お会計をお願いします。ありがとうございます。\"}, {\"original\": \"Sabe realmente delicioso.\", \"translated\": \"とても美味しいです！\"}]', 12, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un restaurante?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el restaurante, junto con sus traducciones al chino:\"]', '[\"Comer\", \"Pedir\", \"Pagar la cuenta\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir bebidas, presentar una queja o preguntar sobre los ingredientes? ¡No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Disculpe, ¿cuánto tiempo más tardará nuestra comida?\", \"translated\": \"打扰一下，我们的菜还要多久才能上？\"}, {\"original\": \"Una mesa para dos, por favor.\", \"translated\": \"请给我们安排一张两人桌。\"}, {\"original\": \"¿Podríamos ver el menú, por favor?\", \"translated\": \"请问可以看一下菜单吗？\"}, {\"original\": \"¿Tienen algún plato especial que nos puedan recomendar?\", \"translated\": \"你们有什么招牌菜可以推荐吗？\"}, {\"original\": \"Quisiera pedir esto y esto.\", \"translated\": \"我要点这个和这个。\"}, {\"original\": \"Un vaso de agua, por favor. Gracias.\", \"translated\": \"请来一杯水，谢谢。\"}, {\"original\": \"La cuenta, por favor.\", \"translated\": \"请结账。\"}, {\"original\": \"¿Puedo pagar con tarjeta de crédito?\", \"translated\": \"我能用信用卡付款吗？\"}, {\"original\": \"¿Podrían empaquetar esto para llevar, por favor?\", \"translated\": \"麻烦把这份打包带走，谢谢。\"}, {\"original\": \"La comida estuvo deliciosa, gracias.\", \"translated\": \"饭菜非常美味，谢谢！\"}]', 1, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un hotel?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el hotel, junto con sus traducciones al chino:\"]', '[\"Check-in\", \"Check-out\", \"Servicio de habitaciones\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como la ubicación de la habitación, otros servicios del hotel o el check-out? ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"Hola, tengo una reservación. Aquí está mi pasaporte.\", \"translated\": \"你好，我有一笔预订。这是我的护照。\"}, {\"original\": \"¿Tienen habitaciones disponibles?\", \"translated\": \"你们还有空房吗？\"}, {\"original\": \"Disculpe, ¿tiene el hotel gimnasio o lavandería?\", \"translated\": \"打扰一下，酒店有健身房或洗衣房吗？\"}, {\"original\": \"¿A qué hora empieza el desayuno?\", \"translated\": \"早餐几点开始？\"}, {\"original\": \"¿Podría darme la llave de la habitación, por favor?\", \"translated\": \"请给我房间钥匙，好吗？\"}, {\"original\": \"¿Podría ayudarme a llevar mi equipaje a la habitación?\", \"translated\": \"您能帮我把行李送到房间吗？\"}, {\"original\": \"¿Cómo llamo al servicio de habitaciones?\", \"translated\": \"怎么呼叫客房服务？\"}, {\"original\": \"¿A qué hora es el check-out?\", \"translated\": \"退房时间是几点？\"}, {\"original\": \"¿Podría darme un recibo/factura, por favor?\", \"translated\": \"请问能给我开一张收据／发票吗？\"}, {\"original\": \"¿Puedo dejar aquí mi equipaje?\", \"translated\": \"我可以把行李先寄存在这里吗？\"}]', 2, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en el aeropuerto?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el aeropuerto, junto con sus traducciones al chino:\"]', '[\"Facturación\", \"Embarque\", \"Facturación de equipaje\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como la facturación, la recogida de equipaje o el servicio de alquiler de coches? ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Dónde está el mostrador de facturación?\", \"translated\": \"值机柜台在哪里？\"}, {\"original\": \"Quisiera un asiento junto a la ventana, por favor.\", \"translated\": \"我想要一个靠窗的座位，谢谢。\"}, {\"original\": \"¿Este vuelo está retrasado?\", \"translated\": \"这个航班延误了吗？\"}, {\"original\": \"Necesito facturar este equipaje.\", \"translated\": \"我需要托运行李。\"}, {\"original\": \"¿Dónde está la puerta de embarque?\", \"translated\": \"登机口在哪里？\"}, {\"original\": \"El avión está a punto de despegar.\", \"translated\": \"飞机即将起飞。\"}, {\"original\": \"¿Necesito sacar mi computadora portátil y mi batería externa?\", \"translated\": \"我需要把笔记本电脑和充电宝拿出来吗？\"}, {\"original\": \"¿Dónde está la tienda libre de impuestos?\", \"translated\": \"免税店在哪里？\"}, {\"original\": \"No puedo encontrar mi maleta.\", \"translated\": \"我找不到我的行李箱了。\"}, {\"original\": \"¿Ofrecen servicio de silla de ruedas?\", \"translated\": \"你们提供轮椅服务吗？\"}]', 3, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en el transporte público?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el transporte público, junto con sus traducciones al chino:\"]', '[\"Tomar autobús o metro\", \"Comprar boletos\", \"Hacer trasbordo\"]', 'es', '[\"De momento, ¿tienes alguna situación específica en mente, como preguntar por la parada de autobús, el precio del boleto o dónde bajarse? No dudes en preguntar.\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Este autobús va a la terminal?\", \"translated\": \"这趟公交车去终点站吗？\"}, {\"original\": \"¿Cuál es la próxima parada?\", \"translated\": \"下一站是哪里？\"}, {\"original\": \"¿Dónde puedo comprar un boleto?\", \"translated\": \"我在哪里可以买票？\"}, {\"original\": \"Un boleto para XX, por favor.\", \"translated\": \"一张去XX的票，谢谢。\"}, {\"original\": \"¿Necesito hacer trasbordo?\", \"translated\": \"我需要换乘吗？\"}, {\"original\": \"¿Cuánto falta para el próximo tren del metro?\", \"translated\": \"下一班地铁列车还要多久？\"}, {\"original\": \"Disculpe, ¿me deja pasar, por favor?\", \"translated\": \"不好意思，请让我过去一下。\"}, {\"original\": \"¿Esta plaza está ocupada?\", \"translated\": \"这个座位有人坐了吗？\"}, {\"original\": \"Disculpe, ¿dónde puedo trasbordar a la Línea 2 para llegar a XX?\", \"translated\": \"不好意思，请问我在哪里换乘2号线去XX？\"}, {\"original\": \"¿Cómo llego a XX?\", \"translated\": \"我怎么去XX？\"}]', 4, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podrías proporcionarme 10 frases comunes que pueda usar en lugares turísticos?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con lugares turísticos, junto con sus traducciones al chino:\"]', '[\"Turismo\", \"Tomar fotos\", \"Comprar entradas\"]', 'es', '[\"De momento, ¿tienes alguna situación específica en mente, como preguntar sobre el precio de las entradas, encontrar un estacionamiento o contratar un servicio de guía turística? ¡No dudes en preguntar.\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"¿Hay entradas para estudiantes disponibles?\", \"translated\": \"有学生票吗？\"}, {\"original\": \"¿A qué hora abre la atracción?\", \"translated\": \"景点几点开门？\"}, {\"original\": \"¿Qué cosas divertidas se pueden hacer aquí?\", \"translated\": \"这里有什么好玩的？\"}, {\"original\": \"¿Podría hacernos una foto?\", \"translated\": \"能帮我们拍张照吗？\"}, {\"original\": \"¿Dónde está el autobús turístico?\", \"translated\": \"观光巴士在哪里？\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"洗手间在哪儿？\"}, {\"original\": \"¿Cuál es el mejor lugar para disfrutar de las vistas?\", \"translated\": \"最佳观景位置在哪里？\"}, {\"original\": \"El paisaje aquí es precioso.\", \"translated\": \"这里的风景真美。\"}, {\"original\": \"¿Hay visitas guiadas disponibles?\", \"translated\": \"有导游服务吗？\"}]', 5, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en servicios de taxi?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con servicios de taxi, junto con sus traducciones al chino:\"]', '[\"Tomar un taxi\", \"Indicar el destino\", \"Pago\"]', 'es', '[\"Por ahora, ¿qué es lo que más quieres hacer ahora? Por ejemplo: preguntar la dirección, el precio o solicitar una factura. ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Dónde puedo conseguir un taxi?\", \"translated\": \"我在哪儿能打到出租车？\"}, {\"original\": \"Por favor, lléveme a esta dirección.\", \"translated\": \"请送我去这个地址。\"}, {\"original\": \"¿Cuánto costará aproximadamente?\", \"translated\": \"大概要多少钱？\"}, {\"original\": \"¿Podría usar el taxímetro, por favor?\", \"translated\": \"麻烦您打表计费，好吗？\"}, {\"original\": \"Por favor, conduzca un poco más rápido, tengo prisa.\", \"translated\": \"请开快一点，我赶时间。\"}, {\"original\": \"Párese aquí, por favor.\", \"translated\": \"请在这里停车。\"}, {\"original\": \"¿Acepta tarjetas o pagos móviles?\", \"translated\": \"支持刷卡或手机支付吗？\"}, {\"original\": \"¿Podría darme un recibo, por favor?\", \"translated\": \"可以给我一张发票吗？\"}, {\"original\": \"Gracias, conductor.\", \"translated\": \"谢谢师傅！\"}, {\"original\": \"¿Cuánto falta todavía?\", \"translated\": \"还有多远？\"}]', 6, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en una farmacia?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con la farmacia, junto con sus traducciones al chino:\"]', '[\"Comprar medicamentos\", \"Consulta\", \"Pago\"]', 'es', '[\"De momento, ¿tiene alguna situación específica en mente, como pedir indicaciones sobre cómo tomar un medicamento, frases relacionadas con el uso del seguro médico o la duración del tratamiento? ¡No dude en preguntar!\", \"Por favor, descríbame la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Tiene medicamento para el resfriado?\", \"translated\": \"您有感冒药吗？\"}, {\"original\": \"¿Cómo debo tomar este medicamento?\", \"translated\": \"我该怎么服用这种药？\"}, {\"original\": \"¿Tiene analgésicos?\", \"translated\": \"您有止痛药吗？\"}, {\"original\": \"¿Viene con un folleto de instrucciones?\", \"translated\": \"这个药附带说明书吗？\"}, {\"original\": \"¿Este medicamento tiene efectos secundarios?\", \"translated\": \"这种药有什么副作用吗？\"}, {\"original\": \"¿Puedo usar mi tarjeta de seguro médico?\", \"translated\": \"我能用医保卡付款吗？\"}, {\"original\": \"¿Me podría dar una caja de tiritas, por favor?\", \"translated\": \"请给我一盒创可贴，谢谢。\"}, {\"original\": \"¿Tiene medicamentos para bajar la fiebre?\", \"translated\": \"您有退烧药吗？\"}, {\"original\": \"Me he hecho una pequeña herida superficial. ¿Tiene antiséptico y tiritas?\", \"translated\": \"我蹭破了一点皮，您有消毒液和创可贴吗？\"}, {\"original\": \"¿A qué hora cierran?\", \"translated\": \"你们几点关门？\"}]', 7, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en servicios de emergencia?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con los servicios de emergencia, junto con sus traducciones al chino:\"]', '[\"Llamar a la policía\", \"Primeros auxilios\", \"Pedir ayuda\"]', 'es', '[\"De momento, ¿tiene alguna situación de emergencia específica en mente, como incendio, lesión y necesidad de ayuda, o llamada de emergencia? ¡No dude en preguntar.\", \"Por favor, descríbame la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Por favor, ayúdeme a llamar a una ambulancia.\", \"translated\": \"请帮我叫一辆救护车。\"}, {\"original\": \"¿Dónde está el hospital?\", \"translated\": \"医院在哪儿？\"}, {\"original\": \"Alguien ha resultado herido.\", \"translated\": \"有人受伤了。\"}, {\"original\": \"Por favor, ayúdeme.\", \"translated\": \"请帮帮我。\"}, {\"original\": \"¿Dónde está la comisaría de policía?\", \"translated\": \"警察局在哪儿？\"}, {\"original\": \"He perdido mis pertenencias.\", \"translated\": \"我的物品丢了。\"}, {\"original\": \"¿Cuál es el número del cuerpo de bomberos?\", \"translated\": \"消防部门的电话号码是多少？\"}, {\"original\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría de policía más cercana?\", \"translated\": \"我的护照丢了。您知道最近的警察局在哪儿吗？\"}, {\"original\": \"¿Hay una salida de emergencia?\", \"translated\": \"有安全出口吗？\"}, {\"original\": \"Alguien ha desmayado.\", \"translated\": \"有人晕倒了。\"}]', 8, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podrías darme 10 frases comunes que pueda usar en la playa o junto a la piscina?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con la playa o junto a la piscina, junto con sus traducciones al chino:\"]', '[\"Nadar\", \"Tomar el sol\", \"Deportes playeros\"]', 'es', '[\"Por ahora, ¿podrías indicarme el contexto del evento o festival local al que asistirás? Por ejemplo: festival cultural, festival gastronómico o festival musical. Por favor, dame el contexto.\", \"Indícame las actividades a las que asistirás.\"]', '[\"¿Tienes alguna situación específica en mente? ¡No dudes en preguntar!\", \"Describe la situación que tienes en mente.\"]', '[{\"original\": \"¡Mira! Las olas allí son realmente grandes.\", \"translated\": \"看！那边的浪真的很大。\"}, {\"original\": \"Recuerda aplicar protector solar, aquí los rayos UV son muy intensos.\", \"translated\": \"记得涂防晒霜，这里的紫外线很强。\"}, {\"original\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\", \"translated\": \"这片海滩的沙子特别细腻，踩上去像踩在棉花上。\"}, {\"original\": \"¿Qué te parece jugar al vóleibol en la playa?\", \"translated\": \"在沙滩上打排球怎么样？\"}, {\"original\": \"Los veleros a lo lejos se ven preciosos.\", \"translated\": \"远处的帆船看起来真美。\"}, {\"original\": \"El agua aquí es tan transparente que hasta puedes ver los peces.\", \"translated\": \"这里的水非常清澈，连鱼都能看见。\"}, {\"original\": \"Vamos a buscar algunas conchas marinas.\", \"translated\": \"咱们去找些贝壳吧。\"}, {\"original\": \"Dar un paseo por la playa al atardecer debe de ser muy romántico.\", \"translated\": \"日落时分在沙滩上散步一定很浪漫。\"}, {\"original\": \"Escuché que aquí el marisco es muy fresco; vayamos a probarlo.\", \"translated\": \"听说这里的海鲜特别新鲜，咱们去尝尝吧。\"}, {\"original\": \"La marea está subiendo, vamos hacia la orilla.\", \"translated\": \"涨潮了，咱们往岸边走吧。\"}]', 9, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podrías darme 10 frases comunes que pueda usar en actividades y festivales locales?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con actividades y festivales locales, junto con sus traducciones al chino:\"]', '[\"Asistir a eventos\", \"Celebrar festivales\", \"Aprender sobre la cultura\"]', 'es', '[\"Por ahora, ¿podrías indicarme el contexto del evento o festival local al que vas a asistir? Por ejemplo: Halloween, un concierto, una fiesta entre amigos u otra cosa. Por favor, indícanos el contexto.\", \"Describe las actividades que tienes en mente.\"]', '[\"¿Tienes alguna situación específica en mente? ¡No dudes en preguntar!\", \"Describe la situación que tienes en mente.\"]', '[{\"original\": \"¿Hay algún evento hoy?\", \"translated\": \"今天有什么活动吗？\"}, {\"original\": \"¿Hay algo especial sobre este festival?\", \"translated\": \"这个节日有什么特别之处吗？\"}, {\"original\": \"¿Dónde se lleva a cabo la celebración?\", \"translated\": \"庆祝活动在哪里举行？\"}, {\"original\": \"¿Cómo puedo comprar entradas?\", \"translated\": \"我该怎么买票？\"}, {\"original\": \"¿A qué hora empieza la actuación?\", \"translated\": \"演出几点开始？\"}, {\"original\": \"¿Qué comida tradicional hay?\", \"translated\": \"有哪些传统美食？\"}, {\"original\": \"¡Aquí está muy animado!\", \"translated\": \"这里真的好热闹！\"}, {\"original\": \"¿Hay alguna actividad folclórica?\", \"translated\": \"有民俗活动吗？\"}, {\"original\": \"¡Felices fiestas!\", \"translated\": \"节日快乐！\"}, {\"original\": \"¿A qué hora termina el evento?\", \"translated\": \"活动几点结束？\"}]', 10, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un museo o una galería de arte?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con museos o galerías de arte, junto con sus traducciones al chino:\"]', '[\"Visita\", \"Visita guiada\", \"Compra de entradas\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, por ejemplo pedir un folleto informativo, frases relacionadas con el plano del lugar, frases para comentar las exposiciones? ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"¿Tienen audioguías?\", \"translated\": \"有语音导览吗？\"}, {\"original\": \"¿Quién creó esta obra de arte?\", \"translated\": \"这件艺术品是谁创作的？\"}, {\"original\": \"¿Dónde está la pieza más valiosa del museo?\", \"translated\": \"博物馆最珍贵的展品在哪里？\"}, {\"original\": \"¿Está permitida la fotografía?\", \"translated\": \"可以拍照吗？\"}, {\"original\": \"¿Hay alguna exposición especial aquí?\", \"translated\": \"这里有什么特别展览吗？\"}, {\"original\": \"¿Cuánto tiempo dura la visita?\", \"translated\": \"参观需要多长时间？\"}, {\"original\": \"¿Podrían darnos una introducción?\", \"translated\": \"能给我们做个简单介绍吗？\"}, {\"original\": \"Estas obras son verdaderamente exquisitas.\", \"translated\": \"这些作品真是精美绝伦。\"}, {\"original\": \"¿Dónde está la tienda de souvenirs?\", \"translated\": \"纪念品商店在哪儿？\"}]', 11, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podrías darme 10 frases comunes que pueda usar en una cafetería?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con la cafetería, junto con sus traducciones al chino:\"]', '[\"Pedir café\", \"Descansar\", \"Socializar\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como pedir el menú, bebidas heladas o calientes, otros productos? ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"Pediré un latte, por favor.\", \"translated\": \"我要一杯拿铁，谢谢。\"}, {\"original\": \"¿Tienen conexión Wi-Fi?\", \"translated\": \"你们有Wi-Fi吗？\"}, {\"original\": \"¿Podría ver el menú, por favor?\", \"translated\": \"请问可以看一下菜单吗？\"}, {\"original\": \"¿Se permiten recargas?\", \"translated\": \"可以免费续杯吗？\"}, {\"original\": \"¿Ya está listo mi café?\", \"translated\": \"我的咖啡好了吗？\"}, {\"original\": \"¿Cuánto tiempo puedo quedarme aquí sentado?\", \"translated\": \"我可以在这里坐多久？\"}, {\"original\": \"¿Podrían hacernos una foto?\", \"translated\": \"能帮我们拍张照片吗？\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"洗手间在哪儿？\"}, {\"original\": \"La cuenta, por favor. ¡Gracias!\", \"translated\": \"请结账，谢谢！\"}, {\"original\": \"¡Sabe realmente delicioso!\", \"translated\": \"味道真的很棒！\"}]', 12, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"レストランで使えるよく使う表現を10個教えてください。\", \"素晴らしい！こちらがレストラン関連のよく使う表現10個と、英語での翻訳です：\"]', '[\"食事\", \"注文\", \"会計\"]', 'ja', '[\"今のところ、注文する・文句を言う・食材について尋ねるなど、具体的なシーンが思い浮かびますか？自由にお聞かせください。\", \"あなたの頭にあるシーンを教えてください。\"]', '[]', '[{\"original\": \"すみません、料理はあとどのくらいで出てきますか？\", \"translated\": \"Excuse me, how much longer will our food be?\"}, {\"original\": \"二人席をお願いします。\", \"translated\": \"A table for two, please.\"}, {\"original\": \"メニューを見せていただけますか？\", \"translated\": \"Could we see the menu, please?\"}, {\"original\": \"おすすめの名物料理はありますか？\", \"translated\": \"Do you have any signature dishes to recommend?\"}, {\"original\": \"これを注文したいです。あと、これもお願いします。\", \"translated\": \"I\'d like to order this, and this.\"}, {\"original\": \"水を一杯お願いします。ありがとうございます。\", \"translated\": \"A glass of water, please. Thanks.\"}, {\"original\": \"お会計お願いします。\", \"translated\": \"The bill, please.\"}, {\"original\": \"クレジットカードで支払えますか？\", \"translated\": \"Can I pay by credit card?\"}, {\"original\": \"これをお持ち帰りにできますか？\", \"translated\": \"Could you pack this to go, please?\"}, {\"original\": \"料理がとても美味しかったです。ありがとうございました！\", \"translated\": \"The food was delicious, thank you.\"}]', 1, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"10個のホテルでよく使う表現を教えてもらえますか？\", \"素晴らしい！ホテル関連のよく使う表現10個と、その英語訳を以下に載せました：\"]', '[\"チェックイン\", \"チェックアウト\", \"ルームサービス\"]', 'ja', '[\"今のところ、部屋の位置、その他ホテルのサービス、チェックアウトなど、具体的な状況をお考えですか？ご質問はいつでも大歓迎です。\", \"頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"こんにちは、予約しています。こちらが私のパスポートです。\", \"translated\": \"Hello, I have a reservation. Here is my passport.\"}, {\"original\": \"空室はありますか？\", \"translated\": \"Do you have any vacancies?\"}, {\"original\": \"すみません、このホテルにはジムやランドリールームはありますか？\", \"translated\": \"Excuse me, does the hotel have a gym or a laundry room?\"}, {\"original\": \"朝食は何時から始まりますか？\", \"translated\": \"What time does breakfast start?\"}, {\"original\": \"鍵をいただけますか？\", \"translated\": \"Could I have a room key, please?\"}, {\"original\": \"荷物を部屋まで運んでいただけますか？\", \"translated\": \"Could you help me take my luggage to the room?\"}, {\"original\": \"ルームサービスの呼び出し方はどうすればいいですか？\", \"translated\": \"How do I call room service?\"}, {\"original\": \"チェックアウトは何時ですか？\", \"translated\": \"What time is check-out?\"}, {\"original\": \"領収書／請求書を書いてもらえますか？\", \"translated\": \"Could you write me a receipt/invoice?\"}, {\"original\": \"荷物をここに預けてもいいですか？\", \"translated\": \"Can I leave my luggage here?\"}]', 2, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"空港で使える代表的なフレーズを10個教えてもらえますか？\", \"素晴らしい！では、空港関連の代表的なフレーズ10個と、その英語訳をご紹介します：\"]', '[\"チェックイン\", \"搭乗\", \"手荷物預け\"]', 'ja', '[\"今のところ、チェックイン、手荷物受取、レンタカーなどのように、ご希望の具体的なシーンはありますか？お気軽にご質問ください。\", \"どんな状況を想定されているか、ぜひ教えてください。\"]', '[]', '[{\"original\": \"チェックインカウンターはどこですか？\", \"translated\": \"Where is the check-in counter?\"}, {\"original\": \"窓側の席をお願いします。\", \"translated\": \"I\'d like a window seat, please.\"}, {\"original\": \"この便は遅れていますか？\", \"translated\": \"Is this flight delayed?\"}, {\"original\": \"この荷物を預けたいのですが。\", \"translated\": \"I need to check this baggage.\"}, {\"original\": \"搭乗口はどこですか？\", \"translated\": \"Where is the boarding gate?\"}, {\"original\": \"飛行機がもうすぐ離陸します。\", \"translated\": \"The plane is about to take off.\"}, {\"original\": \"ノートパソコンとモバイルバッテリーは持ち出さなければいけませんか？\", \"translated\": \"Do I need to take out my laptop and power bank?\"}, {\"original\": \"免税店はどこですか？\", \"translated\": \"Where is the duty-free shop?\"}, {\"original\": \"私のスーツケースが見つかりません。\", \"translated\": \"I can\'t find my suitcase.\"}, {\"original\": \"車椅子のサービスは利用できますか？\", \"translated\": \"Do you have a wheelchair service?\"}]', 3, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"公共交通機関で使えるよく使う表現を10個教えてもらえますか？\", \"素晴らしい！以下に、公共交通機関に関するよく使う表現10個と、その英語訳をご紹介します：\"]', '[\"バス・地下鉄の利用\", \"切符の購入\", \"乗り換え\"]', 'ja', '[\"今のところ、バス停の確認、運賃の問い合わせ、降車のタイミングなど、具体的な状況が思い浮かびますか？何でも気軽に聞いてください。\", \"あなたの頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"このバスは終点へ行きますか？\", \"translated\": \"Does this bus go to the terminal?\"}, {\"original\": \"次の停留所はどこですか？\", \"translated\": \"What is the next stop?\"}, {\"original\": \"切符はどこで買えますか？\", \"translated\": \"Where can I buy a ticket?\"}, {\"original\": \"XX行きの切符を1枚お願いします。\", \"translated\": \"One ticket to XX, please.\"}, {\"original\": \"乗り換えが必要ですか？\", \"translated\": \"Do I need to transfer?\"}, {\"original\": \"次の地下鉄の列車まで、あとどのくらいですか？\", \"translated\": \"How long until the next subway train?\"}, {\"original\": \"すみません、通らせていただけますか？\", \"translated\": \"Excuse me, please let me pass.\"}, {\"original\": \"この席は空いていますか？\", \"translated\": \"Is this seat taken?\"}, {\"original\": \"すみません、XXへ行くには2号線に乗り換えるにはどこで降りればいいですか？\", \"translated\": \"Excuse me, where can I transfer to Line 2 to get to XX?\"}, {\"original\": \"XXへはどう行けばいいですか？\", \"translated\": \"How do I get to XX?\"}]', 4, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"10個のよく使う表現を、観光地で使えるように教えてもらえますか？\", \"素晴らしい！以下は、観光地に関連する10個のよく使う表現と、その英語訳です：\"]', '[\"観光\", \"写真撮影\", \"チケット購入\"]', 'ja', '[\"今のところ、チケットの値段を聞いたり、駐車場を探したり、ツアーガイドサービスについて尋ねたりするなど、具体的な状況が思い浮かびますか？遠慮なくご質問ください。\", \"あなたが頭に描いている状況を教えてください。\"]', '[]', '[{\"original\": \"入場料はいくらですか？\", \"translated\": \"How much is the entrance fee?\"}, {\"original\": \"学生割引のチケットはありますか？\", \"translated\": \"Are there student tickets available?\"}, {\"original\": \"この観光スポットの営業開始時間は何時ですか？\", \"translated\": \"What time does the attraction open?\"}, {\"original\": \"ここですべき楽しいことは何ですか？\", \"translated\": \"What are the fun things to do here?\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"観光バスの乗り場はどこですか？\", \"translated\": \"Where is the sightseeing bus?\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"一番景色がきれいに見えるポイントはどこですか？\", \"translated\": \"Where is the best viewing spot?\"}, {\"original\": \"ここでの景色はとても美しいです。\", \"translated\": \"The scenery here is beautiful.\"}, {\"original\": \"ガイド付きツアーはありますか？\", \"translated\": \"Is there a guided tour available?\"}]', 5, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"タクシーまたは配車サービスで使える、よく使う表現を10個教えてもらえますか？\", \"素晴らしい！以下が、タクシーまたは配車サービスに関連するよく使う表現10個と、その英語訳です：\"]', '[\"タクシーを利用する\", \"行き先を伝える\", \"支払いに関するやりとり\"]', 'ja', '[\"今、あなたが一番したいことは何ですか？たとえば、行き先を聞いたり、料金を確認したり、領収書を頼んだり — 何でも自由に聞いて大丈夫ですよ。\", \"頭の中で想像している状況を教えてください。\"]', '[]', '[{\"original\": \"タクシーはどこで捕まえられますか？\", \"translated\": \"Where can I get a taxi?\"}, {\"original\": \"この住所まで送ってください。\", \"translated\": \"Please take me to this address.\"}, {\"original\": \"だいたいいくらぐらいになりますか？\", \"translated\": \"Roughly how much will it be?\"}, {\"original\": \"メーターを使っていただけますか？\", \"translated\": \"Could you use the meter, please?\"}, {\"original\": \"急いでいるので、もう少し速く運転していただけますか？\", \"translated\": \"Please drive a bit faster, I\'m in a hurry.\"}, {\"original\": \"ここで止めてください。\", \"translated\": \"Please stop here.\"}, {\"original\": \"カードやモバイル決済は使えますか？\", \"translated\": \"Do you accept cards or mobile payments?\"}, {\"original\": \"領収書をいただけますか？\", \"translated\": \"Could I have a receipt, please?\"}, {\"original\": \"ありがとうございました、運転手さん。\", \"translated\": \"Thank you, driver.\"}, {\"original\": \"あとどのくらいで着きますか？\", \"translated\": \"How much further is it?\"}]', 6, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"薬局で使えるよく使う表現を10個教えてもらえますか？\", \"素晴らしい！こちらが薬局関連のよく使う表現10個と、その英語訳です：\"]', '[\"お薬の購入\", \"相談\", \"支払い\"]', 'ja', '[\"今のところ、お薬の飲み方の確認、保険の使い方、服用期間など、具体的な状況をお考えですか？どんなことでも気軽に聞いてください。\", \"あなたが思い浮かべている状況を教えてください。\"]', '[]', '[{\"original\": \"風邪薬はありますか？\", \"translated\": \"Do you have cold medicine?\"}, {\"original\": \"このお薬の飲み方はどうすればいいですか？\", \"translated\": \"How should I take this medicine?\"}, {\"original\": \"痛み止めはありますか？\", \"translated\": \"Do you have any painkillers?\"}, {\"original\": \"添付の説明書はついていますか？\", \"translated\": \"Is there an instruction leaflet?\"}, {\"original\": \"このお薬には副作用がありますか？\", \"translated\": \"Does this medicine have any side effects?\"}, {\"original\": \"医療保険証を使って支払えますか？\", \"translated\": \"Can I use my medical insurance card?\"}, {\"original\": \"バンドエイドを1箱お願いします。\", \"translated\": \"Could I have a box of Band-Aids, please?\"}, {\"original\": \"解熱剤はありますか？\", \"translated\": \"Do you have any fever reducers?\"}, {\"original\": \"ちょっと擦り傷をしました。殺菌液とバンドエイドはありますか？\", \"translated\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\"}, {\"original\": \"何時まで営業していますか？\", \"translated\": \"What time do you close?\"}]', 7, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"緊急サービスで使える、よく使うフレーズを10個教えてもらえますか？\", \"素晴らしい！以下は、緊急サービスに関連するよく使うフレーズ10個と、その英語訳です：\"]', '[\"警察を呼ぶ\", \"応急処置\", \"助けを求める\"]', 'ja', '[\"今のところ、火事、けがをして助けてほしい、緊急通報など、具体的な緊急状況について思い浮かべていますか？遠慮せずに聞いてください。\", \"頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"救急車を呼んでください。\", \"translated\": \"Please help me call an ambulance.\"}, {\"original\": \"病院はどこですか？\", \"translated\": \"Where is the hospital?\"}, {\"original\": \"誰かが怪我をしました。\", \"translated\": \"Someone is injured.\"}, {\"original\": \"助けてください。\", \"translated\": \"Please help me.\"}, {\"original\": \"警察署はどこですか？\", \"translated\": \"Where is the police station?\"}, {\"original\": \"荷物をなくしてしまいました。\", \"translated\": \"I\'ve lost my belongings.\"}, {\"original\": \"消防署にかける電話番号は何番ですか？\", \"translated\": \"What is the number for the fire department?\"}, {\"original\": \"パスポートを紛失しました。近くの警察署はどこですか？\", \"translated\": \"I\'ve lost my passport. Do you know where the nearest police station is?\"}, {\"original\": \"緊急出口はありますか？\", \"translated\": \"Is there an emergency exit?\"}, {\"original\": \"誰かが気を失いました。\", \"translated\": \"Someone has fainted.\"}]', 8, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ビーチやプールサイドで使える、よく使う表現を10個教えていただけますか？\", \"素晴らしい！以下は、ビーチやプールサイドに関連する10個のよく使う表現と、その英語訳です：\"]', '[\"水泳\", \"日光浴\", \"ビーチスポーツ\"]', 'ja', '[\"今のところ、ご参加予定の地域のお祭りやイベント（例：文化フェスティバル、フードフェスティバル、音楽フェスティバルなど）の具体的な内容を教えていただけますか？\", \"ご参加されるアクティビティを教えてください。\"]', '[\"何か特定の状況を思い浮かべていらっしゃいますか？気軽にご質問ください。\", \"ご想像されている状況を詳しく教えてください。\"]', '[{\"original\": \"見て！あそこにある波は本当に大きいわ。\", \"translated\": \"Look! The waves over there are really big.\"}, {\"original\": \"日焼け止めを忘れずに塗ってください。ここでの紫外線はとても強いです。\", \"translated\": \"Remember to apply sunscreen, the UV rays here are very strong.\"}, {\"original\": \"このビーチの砂はすごく細かくて、綿の上を歩いているみたいだわ。\", \"translated\": \"The sand on this beach is so fine, it feels like stepping on cotton.\"}, {\"original\": \"ビーチでバレーボールをやるのはどう？\", \"translated\": \"How about playing volleyball on the beach?\"}, {\"original\": \"遠くに見えるヨットがきれいね。\", \"translated\": \"The sailboats in the distance look beautiful.\"}, {\"original\": \"ここでの水はとても透明度が高く、魚まで見えちゃうわ。\", \"translated\": \"The water here is so clear, you can even see the fish.\"}, {\"original\": \"一緒に貝殻を探しに行きましょう！\", \"translated\": \"Let\'s go find some seashells.\"}, {\"original\": \"夕日に染まるビーチを散歩するのって、きっとロマンチックよね。\", \"translated\": \"Taking a walk on the beach at sunset must be very romantic.\"}, {\"original\": \"ここではシーフードがとても新鮮だと聞いたから、ぜひ食べてみよう！\", \"translated\": \"I heard the seafood here is very fresh, let\'s go try some.\"}, {\"original\": \"潮が満ちてきたわ。そろそろ岸へ戻りましょう。\", \"translated\": \"The tide is coming in, let\'s head towards the shore.\"}]', 9, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"地元のイベントやお祭りで使える、よく使う表現を10個教えていただけますか？\", \"素晴らしい！以下は、地元のイベントやお祭りに関連するよく使う表現10個と、その英語訳です：\"]', '[\"イベントに参加する\", \"お祭りを祝う\", \"文化を学ぶ\"]', 'ja', '[\"まず、ハロウィン、コンサート、友達とのパーティーなど、あなたが参加予定の地元のイベントやお祭りの具体的な状況を教えていただけますか？どうぞご自由にお知らせください。\", \"あなたの頭に浮かぶアクティビティを教えてください。\"]', '[\"何か特定の状況をイメージされていますか？遠慮なくお聞かせください。\", \"あなたの頭に浮かぶ状況を教えてください。\"]', '[{\"original\": \"今日は何かイベントがありますか？\", \"translated\": \"Are there any events today?\"}, {\"original\": \"このお祭りには何か特別なことがありますか？\", \"translated\": \"Is there anything special about this festival?\"}, {\"original\": \"お祝いはどこで行われますか？\", \"translated\": \"Where is the celebration being held?\"}, {\"original\": \"チケットはどこで買えますか？\", \"translated\": \"How can I buy tickets?\"}, {\"original\": \"パフォーマンスはいつから始まりますか？\", \"translated\": \"What time does the performance start?\"}, {\"original\": \"どんな伝統的な食べ物がありますか？\", \"translated\": \"What traditional food is there?\"}, {\"original\": \"ここ、本当に活気がありますね。\", \"translated\": \"It\'s really lively here.\"}, {\"original\": \"民俗行事はありますか？\", \"translated\": \"Are there any folk activities?\"}, {\"original\": \"楽しいお休みを！\", \"translated\": \"Happy holidays!\"}, {\"original\": \"イベントはいつ終わりますか？\", \"translated\": \"What time does the event end?\"}]', 10, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"10個の、美術館や博物館で使えるよく使う表現を教えてもらえますか？\", \"素晴らしい！以下は、美術館や博物館に関連する10個のよく使う表現と、その英語訳です：\"]', '[\"見学\", \"ガイド付きツアー\", \"チケット購入\"]', 'ja', '[\"今のところ、展示解説 pamphlet の依頼、館内マップに関する表現、展示作品への感想を述べる表現など、具体的な場面を思い浮かべていますか？ ご自由にお聞きください。\", \"頭の中で思い浮かべている状況を教えてください。\"]', '[]', '[{\"original\": \"入館料はいくらですか？\", \"translated\": \"How much is the admission fee?\"}, {\"original\": \"オーディオガイドはありますか？\", \"translated\": \"Do you have audio guides?\"}, {\"original\": \"この作品は誰が制作しましたか？\", \"translated\": \"Who created this artwork?\"}, {\"original\": \"美術館・博物館で最も価値のある作品はどこにありますか？\", \"translated\": \"Where is the museum\'s most prized piece?\"}, {\"original\": \"写真撮影は許可されていますか？\", \"translated\": \"Is photography allowed?\"}, {\"original\": \"特別展は開催されていますか？\", \"translated\": \"Are there any special exhibitions here?\"}, {\"original\": \"見学にはどのくらいの時間がかかりますか？\", \"translated\": \"How long does the visit take?\"}, {\"original\": \"簡単にご紹介いただけますか？\", \"translated\": \"Could you give us an introduction?\"}, {\"original\": \"これらの作品は本当に素晴らしいですね。\", \"translated\": \"These works are truly exquisite.\"}, {\"original\": \"お土産ショップはどこにありますか？\", \"translated\": \"Where is the souvenir shop?\"}]', 11, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"カフェで使えるよく使う表現を10個教えていただけますか？\", \"素晴らしい！以下はカフェ関連のよく使う表現10個と、英語での翻訳です：\"]', '[\"コーヒーを注文する\", \"休憩する\", \"おしゃべりする\"]', 'ja', '[\"今のところ、メニューを見たい、アイス／ホットドリンクを頼みたい、他の商品について聞きたい、など、具体的な状況が思い浮かびますか？自由にお尋ねください。\", \"あなたの頭に浮かんだ状況を教えてください。\"]', '[]', '[{\"original\": \"ラテを一杯ください。\", \"translated\": \"I\'ll have a latte, please.\"}, {\"original\": \"Wi-Fiは使えますか？\", \"translated\": \"Do you have Wi-Fi?\"}, {\"original\": \"メニューを見せていただけますか？\", \"translated\": \"Could I see the menu, please?\"}, {\"original\": \"リフィルは可能です、か？\", \"translated\": \"Are refills allowed?\"}, {\"original\": \"私のコーヒーはできましたか？\", \"translated\": \"Is my coffee ready?\"}, {\"original\": \"ここにどのくらい座っていられますか？\", \"translated\": \"How long can I sit here?\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"お会計をお願いします。ありがとうございます。\", \"translated\": \"Check, please. Thank you.\"}, {\"original\": \"本当に美味しいです！\", \"translated\": \"It tastes really good.\"}]', 12, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en un restaurante?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el restaurante, junto con sus traducciones al inglés:\"]', '[\"Comer\", \"Pedir\", \"Pagar\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir bebidas, formular una queja o preguntar sobre los ingredientes? ¡No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Disculpe, ¿cuánto tiempo más tardará nuestra comida?\", \"translated\": \"Excuse me, how much longer will our food be?\"}, {\"original\": \"Una mesa para dos, por favor.\", \"translated\": \"A table for two, please.\"}, {\"original\": \"¿Podríamos ver el menú, por favor?\", \"translated\": \"Could we see the menu, please?\"}, {\"original\": \"¿Tienen algún plato especial que nos recomiende?\", \"translated\": \"Do you have any signature dishes to recommend?\"}, {\"original\": \"Quisiera pedir esto y esto.\", \"translated\": \"I\'d like to order this, and this.\"}, {\"original\": \"Un vaso de agua, por favor. Gracias.\", \"translated\": \"A glass of water, please. Thanks.\"}, {\"original\": \"La cuenta, por favor.\", \"translated\": \"The bill, please.\"}, {\"original\": \"¿Puedo pagar con tarjeta de crédito?\", \"translated\": \"Can I pay by credit card?\"}, {\"original\": \"¿Podría empaquetar esto para llevar, por favor?\", \"translated\": \"Could you pack this to go, please?\"}, {\"original\": \"La comida estuvo deliciosa, gracias.\", \"translated\": \"The food was delicious, thank you.\"}]', 1, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un hotel?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el hotel, junto con sus traducciones al inglés:\"]', '[\"Registro de entrada\", \"Registro de salida\", \"Servicio a la habitación\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como la ubicación de la habitación, otros servicios del hotel o el registro de salida? ¡No dudes en preguntar.\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"Hola, tengo una reservación. Aquí está mi pasaporte.\", \"translated\": \"Hello, I have a reservation. Here is my passport.\"}, {\"original\": \"¿Tienen habitaciones disponibles?\", \"translated\": \"Do you have any vacancies?\"}, {\"original\": \"Disculpe, ¿tiene el hotel gimnasio o servicio de lavandería?\", \"translated\": \"Excuse me, does the hotel have a gym or a laundry room?\"}, {\"original\": \"¿A qué hora empieza el desayuno?\", \"translated\": \"What time does breakfast start?\"}, {\"original\": \"¿Podría darme la llave de la habitación, por favor?\", \"translated\": \"Could I have a room key, please?\"}, {\"original\": \"¿Me podría ayudar a llevar mi equipaje a la habitación?\", \"translated\": \"Could you help me take my luggage to the room?\"}, {\"original\": \"¿Cómo llamo al servicio a la habitación?\", \"translated\": \"How do I call room service?\"}, {\"original\": \"¿A qué hora es la salida del hotel?\", \"translated\": \"What time is check-out?\"}, {\"original\": \"¿Podría darme un recibo/factura?\", \"translated\": \"Could you write me a receipt/invoice?\"}, {\"original\": \"¿Puedo dejar mi equipaje aquí?\", \"translated\": \"Can I leave my luggage here?\"}]', 2, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podrías darme 10 frases comunes que pueda usar en el aeropuerto?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el aeropuerto, junto con sus traducciones al inglés:\"]', '[\"Facturación\", \"Embarque\", \"Revisión de equipaje\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como facturación, reclamación de equipaje o servicio de alquiler de coches? ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Dónde está el mostrador de facturación?\", \"translated\": \"Where is the check-in counter?\"}, {\"original\": \"Me gustaría un asiento junto a la ventana, por favor.\", \"translated\": \"I\'d like a window seat, please.\"}, {\"original\": \"¿Este vuelo tiene retraso?\", \"translated\": \"Is this flight delayed?\"}, {\"original\": \"Necesito facturar este equipaje.\", \"translated\": \"I need to check this baggage.\"}, {\"original\": \"¿Dónde está la puerta de embarque?\", \"translated\": \"Where is the boarding gate?\"}, {\"original\": \"El avión está a punto de despegar.\", \"translated\": \"The plane is about to take off.\"}, {\"original\": \"¿Necesito sacar mi portátil y mi banco de energía?\", \"translated\": \"Do I need to take out my laptop and power bank?\"}, {\"original\": \"¿Dónde está la tienda libre de impuestos?\", \"translated\": \"Where is the duty-free shop?\"}, {\"original\": \"No encuentro mi maleta.\", \"translated\": \"I can\'t find my suitcase.\"}, {\"original\": \"¿Ofrecen servicio de silla de ruedas?\", \"translated\": \"Do you have a wheelchair service?\"}]', 3, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en transporte público?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el transporte público, junto con sus traducciones al inglés:\"]', '[\"Tomar autobús o metro\", \"Comprar billetes\", \"Hacer transbordo\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como preguntar por una parada de autobús, el precio del billete o bajarse del vehículo? ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Este autobús va a la terminal?\", \"translated\": \"Does this bus go to the terminal?\"}, {\"original\": \"¿Cuál es la próxima parada?\", \"translated\": \"What is the next stop?\"}, {\"original\": \"¿Dónde puedo comprar un billete?\", \"translated\": \"Where can I buy a ticket?\"}, {\"original\": \"Un billete para XX, por favor.\", \"translated\": \"One ticket to XX, please.\"}, {\"original\": \"¿Tengo que hacer transbordo?\", \"translated\": \"Do I need to transfer?\"}, {\"original\": \"¿Cuánto falta para el próximo tren del metro?\", \"translated\": \"How long until the next subway train?\"}, {\"original\": \"Perdón, ¿me deja pasar?\", \"translated\": \"Excuse me, please let me pass.\"}, {\"original\": \"¿Está ocupado este asiento?\", \"translated\": \"Is this seat taken?\"}, {\"original\": \"Disculpe, ¿dónde puedo hacer transbordo a la Línea 2 para llegar a XX?\", \"translated\": \"Excuse me, where can I transfer to Line 2 to get to XX?\"}, {\"original\": \"¿Cómo llego a XX?\", \"translated\": \"How do I get to XX?\"}]', 4, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría darme 10 frases comunes que pueda usar en lugares turísticos?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con lugares turísticos, junto con sus traducciones al inglés:\"]', '[\"Turismo\", \"Tomar fotos\", \"Comprar entradas\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como preguntar sobre el precio de las entradas, encontrar un estacionamiento o solicitar el servicio de guía turística? No dudes en preguntar.\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"How much is the entrance fee?\"}, {\"original\": \"¿Hay entradas para estudiantes disponibles?\", \"translated\": \"Are there student tickets available?\"}, {\"original\": \"¿A qué hora abre la atracción?\", \"translated\": \"What time does the attraction open?\"}, {\"original\": \"¿Qué cosas divertidas se pueden hacer aquí?\", \"translated\": \"What are the fun things to do here?\"}, {\"original\": \"¿Podría hacernos una foto?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"¿Dónde está el autobús turístico?\", \"translated\": \"Where is the sightseeing bus?\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"¿Cuál es el mejor lugar para disfrutar de las vistas?\", \"translated\": \"Where is the best viewing spot?\"}, {\"original\": \"El paisaje aquí es precioso.\", \"translated\": \"The scenery here is beautiful.\"}, {\"original\": \"¿Hay visitas guiadas disponibles?\", \"translated\": \"Is there a guided tour available?\"}]', 5, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un taxi o servicio de taxis?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con taxis o servicios de taxis, junto con sus traducciones al inglés:\"]', '[\"Tomar un taxi\", \"Indicar el destino\", \"Pago\"]', 'es', '[\"Por ahora, ¿qué es lo que más quieres hacer ahora? Por ejemplo: preguntar la dirección, el precio o solicitar una factura. ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Dónde puedo conseguir un taxi?\", \"translated\": \"Where can I get a taxi?\"}, {\"original\": \"Por favor, lléveme a esta dirección.\", \"translated\": \"Please take me to this address.\"}, {\"original\": \"¿Cuánto costará aproximadamente?\", \"translated\": \"Roughly how much will it be?\"}, {\"original\": \"¿Podría usar el taxímetro, por favor?\", \"translated\": \"Could you use the meter, please?\"}, {\"original\": \"Por favor, conduzca un poco más rápido, tengo prisa.\", \"translated\": \"Please drive a bit faster, I\'m in a hurry.\"}, {\"original\": \"Por favor, párese aquí.\", \"translated\": \"Please stop here.\"}, {\"original\": \"¿Acepta tarjetas o pagos móviles?\", \"translated\": \"Do you accept cards or mobile payments?\"}, {\"original\": \"¿Podría darme un recibo, por favor?\", \"translated\": \"Could I have a receipt, please?\"}, {\"original\": \"Gracias, conductor.\", \"translated\": \"Thank you, driver.\"}, {\"original\": \"¿Cuánto falta todavía?\", \"translated\": \"How much further is it?\"}]', 6, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en una farmacia?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con la farmacia, junto con sus traducciones al inglés:\"]', '[\"Comprar medicamentos\", \"Consulta\", \"Pago\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir instrucciones sobre cómo tomar un medicamento, frases relacionadas con el uso del seguro médico o la duración del tratamiento? No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Tiene medicamento para el resfriado?\", \"translated\": \"Do you have cold medicine?\"}, {\"original\": \"¿Cómo debo tomar este medicamento?\", \"translated\": \"How should I take this medicine?\"}, {\"original\": \"¿Tiene algún analgésico?\", \"translated\": \"Do you have any painkillers?\"}, {\"original\": \"¿Viene con un folleto de instrucciones?\", \"translated\": \"Is there an instruction leaflet?\"}, {\"original\": \"¿Este medicamento tiene efectos secundarios?\", \"translated\": \"Does this medicine have any side effects?\"}, {\"original\": \"¿Puedo usar mi tarjeta de seguro médico?\", \"translated\": \"Can I use my medical insurance card?\"}, {\"original\": \"¿Me podría dar una caja de tiritas, por favor?\", \"translated\": \"Could I have a box of Band-Aids, please?\"}, {\"original\": \"¿Tiene algún antipirético?\", \"translated\": \"Do you have any fever reducers?\"}, {\"original\": \"Tengo una pequeña rozadura. ¿Tiene antiséptico y tiritas?\", \"translated\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\"}, {\"original\": \"¿A qué hora cierran?\", \"translated\": \"What time do you close?\"}]', 7, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en servicios de emergencia?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con servicios de emergencia, junto con sus traducciones al inglés:\"]', '[\"Llamar a la policía\", \"Primeros auxilios\", \"Pedir ayuda\"]', 'es', '[\"Por ahora, ¿tiene en mente alguna situación de emergencia específica, como incendio, persona herida que necesita ayuda o llamada de emergencia? ¡No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Por favor, ayúdeme a llamar a una ambulancia.\", \"translated\": \"Please help me call an ambulance.\"}, {\"original\": \"¿Dónde está el hospital?\", \"translated\": \"Where is the hospital?\"}, {\"original\": \"Alguien resultó herido.\", \"translated\": \"Someone is injured.\"}, {\"original\": \"Por favor, ayúdeme.\", \"translated\": \"Please help me.\"}, {\"original\": \"¿Dónde está la comisaría de policía?\", \"translated\": \"Where is the police station?\"}, {\"original\": \"He perdido mis pertenencias.\", \"translated\": \"I\'ve lost my belongings.\"}, {\"original\": \"¿Cuál es el número del cuerpo de bomberos?\", \"translated\": \"What is the number for the fire department?\"}, {\"original\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría de policía más cercana?\", \"translated\": \"I\'ve lost my passport. Do you know where the nearest police station is?\"}, {\"original\": \"¿Hay una salida de emergencia?\", \"translated\": \"Is there an emergency exit?\"}, {\"original\": \"Alguien ha perdido el conocimiento.\", \"translated\": \"Someone has fainted.\"}]', 8, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podrías proporcionarme 10 frases comunes que pueda usar en la playa o junto a la piscina?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con la playa o junto a la piscina, junto con sus traducciones al inglés:\"]', '[\"Nadar\", \"Tomar el sol\", \"Deportes playeros\"]', 'es', '[\"Por ahora, ¿podrías indicarme el contexto del evento o festival local al que asistirás, como un festival cultural, un festival gastronómico o un festival musical? Por favor, proporcióname el contexto.\", \"Por favor, indica las actividades a las que asistirás.\"]', '[\"¿Tienes una situación específica en mente? ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[{\"original\": \"¡Mira! ¡Las olas allá son realmente grandes!\", \"translated\": \"Look! The waves over there are really big.\"}, {\"original\": \"Recuerda aplicarte protector solar; aquí los rayos UV son muy intensos.\", \"translated\": \"Remember to apply sunscreen, the UV rays here are very strong.\"}, {\"original\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\", \"translated\": \"The sand on this beach is so fine, it feels like stepping on cotton.\"}, {\"original\": \"¿Qué tal jugar voleibol en la playa?\", \"translated\": \"How about playing volleyball on the beach?\"}, {\"original\": \"Los veleros a lo lejos se ven hermosos.\", \"translated\": \"The sailboats in the distance look beautiful.\"}, {\"original\": \"El agua aquí es tan transparente que incluso puedes ver los peces.\", \"translated\": \"The water here is so clear, you can even see the fish.\"}, {\"original\": \"Vamos a buscar conchas marinas.\", \"translated\": \"Let\'s go find some seashells.\"}, {\"original\": \"Dar un paseo por la playa al atardecer debe ser muy romántico.\", \"translated\": \"Taking a walk on the beach at sunset must be very romantic.\"}, {\"original\": \"Escuché que los mariscos aquí están muy frescos; vamos a probarlos.\", \"translated\": \"I heard the seafood here is very fresh, let\'s go try some.\"}, {\"original\": \"La marea está subiendo; volvamos hacia la orilla.\", \"translated\": \"The tide is coming in, let\'s head towards the shore.\"}]', 9, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podrías darme 10 frases comunes que pueda usar en actividades y festivales locales?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con actividades y festivales locales, junto con sus traducciones al inglés:\"]', '[\"Asistir a eventos\", \"Celebrar festivales\", \"Aprender sobre la cultura\"]', 'es', '[\"Por ahora, ¿podrías indicarme el contexto del evento o festival local al que asistirás? Por ejemplo: Halloween, un concierto, una fiesta entre amigos u otra cosa. Por favor, dame más detalles.\", \"Por favor, descríbeme las actividades que tienes en mente.\"]', '[\"¿Tienes alguna situación específica en mente? ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[{\"original\": \"¿Hay algún evento hoy?\", \"translated\": \"Are there any events today?\"}, {\"original\": \"¿Hay algo especial sobre este festival?\", \"translated\": \"Is there anything special about this festival?\"}, {\"original\": \"¿Dónde se lleva a cabo la celebración?\", \"translated\": \"Where is the celebration being held?\"}, {\"original\": \"¿Cómo puedo comprar las entradas?\", \"translated\": \"How can I buy tickets?\"}, {\"original\": \"¿A qué hora empieza la actuación?\", \"translated\": \"What time does the performance start?\"}, {\"original\": \"¿Qué comida tradicional hay?\", \"translated\": \"What traditional food is there?\"}, {\"original\": \"¡Aquí todo está muy animado!\", \"translated\": \"It\'s really lively here.\"}, {\"original\": \"¿Hay alguna actividad popular o folclórica?\", \"translated\": \"Are there any folk activities?\"}, {\"original\": \"¡Felices fiestas!\", \"translated\": \"Happy holidays!\"}, {\"original\": \"¿A qué hora termina el evento?\", \"translated\": \"What time does the event end?\"}]', 10, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un museo o galería de arte?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con museos o galerías de arte, junto con sus traducciones al inglés.\"]', '[\"Visitar\", \"Visita guiada\", \"Comprar entradas\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir un manual introductorio, frases relacionadas con el plano del recorrido o frases para comentar las obras expuestas? ¡No dude en preguntar!\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"How much is the admission fee?\"}, {\"original\": \"¿Tienen guías de audio?\", \"translated\": \"Do you have audio guides?\"}, {\"original\": \"¿Quién creó esta obra de arte?\", \"translated\": \"Who created this artwork?\"}, {\"original\": \"¿Dónde está la pieza más valiosa del museo?\", \"translated\": \"Where is the museum\'s most prized piece?\"}, {\"original\": \"¿Se permite hacer fotos?\", \"translated\": \"Is photography allowed?\"}, {\"original\": \"¿Hay alguna exposición especial aquí?\", \"translated\": \"Are there any special exhibitions here?\"}, {\"original\": \"¿Cuánto tiempo dura la visita?\", \"translated\": \"How long does the visit take?\"}, {\"original\": \"¿Podrían darnos una introducción?\", \"translated\": \"Could you give us an introduction?\"}, {\"original\": \"Estas obras son verdaderamente exquisitas.\", \"translated\": \"These works are truly exquisite.\"}, {\"original\": \"¿Dónde está la tienda de souvenirs?\", \"translated\": \"Where is the souvenir shop?\"}]', 11, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría darme 10 frases comunes que pueda usar en una cafetería?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con cafeterías, junto con sus traducciones al inglés:\"]', '[\"Pedir café\", \"Descansar\", \"Socializar\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como pedir el menú, bebidas frías o calientes, otros productos? ¡No dudes en preguntar!\", \"Por favor, describe la situación que tienes en mente.\"]', '[]', '[{\"original\": \"Pediré un latte, por favor.\", \"translated\": \"I\'ll have a latte, please.\"}, {\"original\": \"¿Tienen conexión Wi-Fi?\", \"translated\": \"Do you have Wi-Fi?\"}, {\"original\": \"¿Podría ver el menú, por favor?\", \"translated\": \"Could I see the menu, please?\"}, {\"original\": \"¿Se permiten recargas?\", \"translated\": \"Are refills allowed?\"}, {\"original\": \"¿Ya está listo mi café?\", \"translated\": \"Is my coffee ready?\"}, {\"original\": \"¿Cuánto tiempo puedo quedarme aquí sentado?\", \"translated\": \"How long can I sit here?\"}, {\"original\": \"¿Nos podría tomar una foto?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"La cuenta, por favor. Gracias.\", \"translated\": \"Check, please. Thank you.\"}, {\"original\": \"Sabe realmente delicioso.\", \"translated\": \"It tastes really good.\"}]', 12, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un restaurante?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con los restaurantes, junto con sus traducciones al francés:\"]', '[\"Comer\", \"Pedir\", \"Pagar\"]', 'es', '[\"De momento, ¿tiene alguna situación específica en mente, como pedir bebidas, presentar una queja o preguntar sobre los ingredientes? No dude en preguntar.\", \"Por favor, descríbame la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Disculpe, ¿cuánto tiempo más tardará nuestra comida?\", \"translated\": \"Excusez-moi, combien de temps encore faudra-t-il pour que notre commande soit prête ?\"}, {\"original\": \"Una mesa para dos, por favor.\", \"translated\": \"Une table pour deux, s\'il vous plaît.\"}, {\"original\": \"¿Podríamos ver el menú, por favor?\", \"translated\": \"Pourrions-nous voir la carte, s\'il vous plaît ?\"}, {\"original\": \"¿Tienen algún plato especial que nos puedan recomendar?\", \"translated\": \"Avez-vous des spécialités maison que vous pourriez nous recommander ?\"}, {\"original\": \"Quisiera pedir esto y esto.\", \"translated\": \"Je voudrais commander ceci et cela.\"}, {\"original\": \"Un vaso de agua, por favor. Gracias.\", \"translated\": \"Un verre d\'eau, s\'il vous plaît. Merci.\"}, {\"original\": \"La cuenta, por favor.\", \"translated\": \"L\'addition, s\'il vous plaît.\"}, {\"original\": \"¿Puedo pagar con tarjeta de crédito?\", \"translated\": \"Puis-je payer par carte bancaire ?\"}, {\"original\": \"¿Podría envolver esto para llevar, por favor?\", \"translated\": \"Pourriez-vous emballer cela à emporter, s\'il vous plaît ?\"}, {\"original\": \"La comida estaba deliciosa, gracias.\", \"translated\": \"Le repas était délicieux, merci.\"}]', 1, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un hotel?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el hotel, junto con sus traducciones al francés:\"]', '[\"Registro de entrada\", \"Registro de salida\", \"Servicio de habitaciones\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como la ubicación de la habitación, otros servicios del hotel o el registro de salida? No dude en preguntar.\", \"Por favor, describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Hola, tengo una reserva. Aquí está mi pasaporte.\", \"translated\": \"Bonjour, j’ai une réservation. Voici mon passeport.\"}, {\"original\": \"¿Tienen habitaciones disponibles?\", \"translated\": \"Avez-vous des chambres disponibles ?\"}, {\"original\": \"Disculpe, ¿tiene el hotel gimnasio o servicio de lavandería?\", \"translated\": \"Excusez-moi, l’hôtel dispose-t-il d’une salle de sport ou d’un service de blanchisserie ?\"}, {\"original\": \"¿A qué hora comienza el desayuno?\", \"translated\": \"À quelle heure commence le petit-déjeuner ?\"}, {\"original\": \"¿Podría darme la llave de la habitación, por favor?\", \"translated\": \"Pourriez-vous me remettre la clé de ma chambre, s’il vous plaît ?\"}, {\"original\": \"¿Podría ayudarme a llevar mi equipaje hasta la habitación?\", \"translated\": \"Pourriez-vous m’aider à porter mes bagages jusqu’à ma chambre ?\"}, {\"original\": \"¿Cómo llamo al servicio de habitaciones?\", \"translated\": \"Comment puis-je appeler le service en chambre ?\"}, {\"original\": \"¿A qué hora es la salida?\", \"translated\": \"À quelle heure doit-on quitter la chambre ?\"}, {\"original\": \"¿Podría darme un recibo/factura?\", \"translated\": \"Pourriez-vous me remettre un reçu/une facture ?\"}, {\"original\": \"¿Puedo dejar mi equipaje aquí?\", \"translated\": \"Puis-je laisser mes bagages ici ?\"}]', 2, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podrías proporcionarme 10 frases comunes que pueda usar en el aeropuerto?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el aeropuerto, junto con sus traducciones al francés:\"]', '[\"Facturación\", \"Embarque\", \"Facturación de equipaje\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como la facturación, la recogida de equipaje o el servicio de alquiler de coches? No dudes en preguntar.\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Dónde está el mostrador de facturación?\", \"translated\": \"Où se trouve le comptoir d\'enregistrement ?\"}, {\"original\": \"Quisiera un asiento junto a la ventana, por favor.\", \"translated\": \"Je voudrais un siège côté hublot, s\'il vous plaît.\"}, {\"original\": \"¿Este vuelo tiene retraso?\", \"translated\": \"Ce vol est-il retardé ?\"}, {\"original\": \"Necesito facturar este equipaje.\", \"translated\": \"Je dois enregistrer ce bagage.\"}, {\"original\": \"¿Dónde está la puerta de embarque?\", \"translated\": \"Où se trouve la porte d\'embarquement ?\"}, {\"original\": \"El avión está a punto de despegar.\", \"translated\": \"L\'avion est sur le point de décoller.\"}, {\"original\": \"¿Necesito sacar mi ordenador portátil y mi power bank?\", \"translated\": \"Dois-je sortir mon ordinateur portable et mon chargeur externe ?\"}, {\"original\": \"¿Dónde está la tienda libre de impuestos?\", \"translated\": \"Où se trouve la boutique hors taxes ?\"}, {\"original\": \"No encuentro mi maleta.\", \"translated\": \"Je ne retrouve pas ma valise.\"}, {\"original\": \"¿Ofrecen servicio de silla de ruedas?\", \"translated\": \"Proposez-vous un service de chaise roulante ?\"}]', 3, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en transporte público?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el transporte público, junto con sus traducciones al francés:\"]', '[\"Tomar autobús o metro\", \"Comprar boletos\", \"Transbordar\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como preguntar por una parada de autobús, el precio del boleto o dónde bajarse? No dudes en preguntar.\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Este autobús va a la terminal?\", \"translated\": \"Cet autobus va-t-il à la gare routière ?\"}, {\"original\": \"¿Cuál es la próxima parada?\", \"translated\": \"Quelle est le prochain arrêt ?\"}, {\"original\": \"¿Dónde puedo comprar un boleto?\", \"translated\": \"Où puis-je acheter un billet ?\"}, {\"original\": \"Un boleto para XX, por favor.\", \"translated\": \"Un billet pour XX, s’il vous plaît.\"}, {\"original\": \"¿Necesito transbordar?\", \"translated\": \"Dois-je changer de véhicule ?\"}, {\"original\": \"¿Cuánto tiempo falta para el próximo tren del metro?\", \"translated\": \"Dans combien de temps arrive le prochain train du métro ?\"}, {\"original\": \"Disculpe, permítame pasar.\", \"translated\": \"Excusez-moi, je dois passer.\"}, {\"original\": \"¿Esta plaza está ocupada?\", \"translated\": \"Cette place est-elle occupée ?\"}, {\"original\": \"Disculpe, ¿dónde puedo transbordar a la Línea 2 para llegar a XX?\", \"translated\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d’aller à XX ?\"}, {\"original\": \"¿Cómo llego a XX?\", \"translated\": \"Comment puis-je me rendre à XX ?\"}]', 4, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en lugares turísticos?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con lugares turísticos, junto con sus traducciones al francés:\"]', '[\"Turismo\", \"Hacer fotos\", \"Comprar entradas\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como preguntar sobre el precio de las entradas, encontrar un aparcamiento o solicitar un servicio de guía turística? No dudes en preguntar.\", \"Describe la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"Combien coûte l\'entrée ?\"}, {\"original\": \"¿Hay entradas para estudiantes disponibles?\", \"translated\": \"Y a-t-il des billets étudiants disponibles ?\"}, {\"original\": \"¿A qué hora abre la atracción?\", \"translated\": \"À quelle heure ouvre l\'attraction ?\"}, {\"original\": \"¿Qué cosas divertidas se pueden hacer aquí?\", \"translated\": \"Quelles sont les activités amusantes à faire ici ?\"}, {\"original\": \"¿Podría hacernos una foto?\", \"translated\": \"Pourriez-vous nous prendre en photo ?\"}, {\"original\": \"¿Dónde está el autobús turístico?\", \"translated\": \"Où est le bus touristique ?\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"¿Cuál es el mejor lugar para ver las vistas?\", \"translated\": \"Quel est le meilleur endroit pour admirer la vue ?\"}, {\"original\": \"El paisaje aquí es hermoso.\", \"translated\": \"Le paysage ici est magnifique.\"}, {\"original\": \"¿Hay visitas guiadas disponibles?\", \"translated\": \"Des visites guidées sont-elles disponibles ?\"}]', 5, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en servicios de taxi o taxis?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con servicios de taxi o taxis, junto con sus traducciones al francés:\"]', '[\"Tomar un taxi\", \"Indicar el destino\", \"Pago\"]', 'es', '[\"Por ahora, ¿qué es lo que más te gustaría hacer ahora? Por ejemplo: pedir la dirección, preguntar el precio o solicitar una factura. ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Dónde puedo conseguir un taxi?\", \"translated\": \"Où puis-je prendre un taxi ?\"}, {\"original\": \"Lléveme, por favor, a esta dirección.\", \"translated\": \"Veuillez me conduire à cette adresse, s’il vous plaît.\"}, {\"original\": \"¿Cuánto costará aproximadamente?\", \"translated\": \"Combien cela coûtera-t-il approximativement ?\"}, {\"original\": \"¿Podría usar el taxímetro, por favor?\", \"translated\": \"Pourriez-vous utiliser le compteur, s’il vous plaît ?\"}, {\"original\": \"Por favor, conduzca un poco más rápido, tengo prisa.\", \"translated\": \"Pourriez-vous conduire un peu plus vite, je suis pressé(e).\"}, {\"original\": \"Párese aquí, por favor.\", \"translated\": \"Veuillez vous arrêter ici, s’il vous plaît.\"}, {\"original\": \"¿Acepta tarjetas o pagos móviles?\", \"translated\": \"Acceptez-vous les cartes bancaires ou les paiements mobiles ?\"}, {\"original\": \"¿Podría darme un recibo, por favor?\", \"translated\": \"Pourriez-vous me donner un reçu, s’il vous plaît ?\"}, {\"original\": \"Gracias, conductor.\", \"translated\": \"Merci, conducteur.\"}, {\"original\": \"¿Cuánto falta todavía?\", \"translated\": \"Il reste encore combien de temps ?\"}]', 6, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría indicarme 10 frases comunes que puedo usar en una farmacia?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con la farmacia, junto con sus traducciones al francés:\"]', '[\"Comprar medicamentos\", \"Consulta\", \"Pago\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir indicaciones sobre cómo tomar un medicamento, frases relacionadas con el uso del seguro médico o la duración del tratamiento? No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Tiene medicamento para el resfriado?\", \"translated\": \"Avez-vous des médicaments contre le rhume ?\"}, {\"original\": \"¿Cómo debo tomar este medicamento?\", \"translated\": \"Comment dois-je prendre ce médicament ?\"}, {\"original\": \"¿Tiene analgésicos?\", \"translated\": \"Avez-vous des analgésiques ?\"}, {\"original\": \"¿Viene con un folleto de instrucciones?\", \"translated\": \"Ce médicament est-il accompagné d\'une notice d\'utilisation ?\"}, {\"original\": \"¿Este medicamento tiene efectos secundarios?\", \"translated\": \"Ce médicament a-t-il des effets secondaires ?\"}, {\"original\": \"¿Puedo usar mi tarjeta de seguro médico?\", \"translated\": \"Puis-je utiliser ma carte d\'assurance maladie ?\"}, {\"original\": \"¿Me podría dar una caja de tiritas, por favor?\", \"translated\": \"Pourriez-vous me donner une boîte de pansements, s\'il vous plaît ?\"}, {\"original\": \"¿Tiene medicamentos para bajar la fiebre?\", \"translated\": \"Avez-vous des antipyrétiques ?\"}, {\"original\": \"Tengo una pequeña raspadura. ¿Tiene antiséptico y tiritas?\", \"translated\": \"J’ai une petite éraflure. Avez-vous un antiseptique et des pansements ?\"}, {\"original\": \"¿A qué hora cierran?\", \"translated\": \"À quelle heure fermez-vous ?\"}]', 7, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en servicios de emergencia?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con los servicios de emergencia, junto con sus traducciones al francés:\"]', '[\"Llamar a la policía\", \"Primeros auxilios\", \"Pedir ayuda\"]', 'es', '[\"De momento, ¿tiene alguna situación de emergencia específica en mente, como incendio, personas heridas que necesitan ayuda o llamadas de emergencia? ¡No dude en preguntar!\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Por favor, ayúdeme a llamar a una ambulancia.\", \"translated\": \"Veuillez m\'aider à appeler une ambulance.\"}, {\"original\": \"¿Dónde está el hospital?\", \"translated\": \"Où se trouve l\'hôpital ?\"}, {\"original\": \"Alguien ha resultado herido.\", \"translated\": \"Quelqu\'un est blessé.\"}, {\"original\": \"Por favor, ayúdeme.\", \"translated\": \"Au secours !\"}, {\"original\": \"¿Dónde está la comisaría de policía?\", \"translated\": \"Où se trouve le poste de police ?\"}, {\"original\": \"He perdido mis pertenencias.\", \"translated\": \"J\'ai perdu mes affaires.\"}, {\"original\": \"¿Cuál es el número del cuerpo de bomberos?\", \"translated\": \"Quel est le numéro des pompiers ?\"}, {\"original\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría de policía más cercana?\", \"translated\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le poste de police le plus proche ?\"}, {\"original\": \"¿Hay una salida de emergencia?\", \"translated\": \"Y a-t-il une sortie de secours ?\"}, {\"original\": \"Alguien ha perdido el conocimiento.\", \"translated\": \"Quelqu\'un s\'est évanoui.\"}]', 8, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en la playa o junto a la piscina?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con la playa o junto a la piscina, junto con sus traducciones al francés:\"]', '[\"Nadar\", \"Tomar el sol\", \"Deportes playeros\"]', 'es', '[\"Por ahora, ¿podría indicarme el contexto del evento o festival local al que asistirá, por ejemplo un festival cultural, gastronómico o musical? Por favor, proporcióneme el contexto.\", \"Indíqueme las actividades a las que asistirá.\"]', '[\"¿Tiene alguna situación específica en mente? ¡No dude en preguntar!\", \"Describa la situación que tiene en mente.\"]', '[{\"original\": \"¡Mira! Las olas allí son realmente grandes.\", \"translated\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\"}, {\"original\": \"Recuerda aplicarte protector solar; aquí los rayos UV son muy intensos.\", \"translated\": \"N’oubliez pas d’appliquer de la crème solaire : les rayons UV sont très forts ici.\"}, {\"original\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\", \"translated\": \"Le sable de cette plage est si fin qu’on a l’impression de marcher sur du coton.\"}, {\"original\": \"¿Qué tal jugar al voleibol en la playa?\", \"translated\": \"Et si on jouait au volley-ball sur la plage ?\"}, {\"original\": \"Los veleros a lo lejos se ven preciosos.\", \"translated\": \"Les voiliers au loin sont magnifiques.\"}, {\"original\": \"El agua aquí es tan transparente que hasta puedes ver los peces.\", \"translated\": \"L’eau est ici si claire qu’on peut même voir les poissons.\"}, {\"original\": \"Vamos a buscar conchas marinas.\", \"translated\": \"Allons ramasser des coquillages.\"}, {\"original\": \"Pasear por la playa al atardecer debe de ser muy romántico.\", \"translated\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\"}, {\"original\": \"Escuché que los mariscos de aquí son muy frescos; vamos a probarlos.\", \"translated\": \"J’ai entendu dire que les fruits de mer ici sont très frais — allons-en goûter !\"}, {\"original\": \"La marea está subiendo; volvamos hacia la orilla.\", \"translated\": \"La marée monte — rentrons vers la rive.\"}]', 9, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podrías proporcionarme 10 frases comunes que pueda usar en actividades y festivales locales?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con actividades y festivales locales, junto con sus traducciones al francés:\"]', '[\"Asistir a eventos\", \"Celebrar festivales\", \"Aprender sobre la cultura\"]', 'es', '[\"Por ahora, ¿podrías indicarme el contexto del evento o festival local al que vas a asistir? Por ejemplo: Halloween, un concierto, una fiesta entre amigos u otra cosa. Por favor, indícanos el contexto.\", \"Por favor, descríbeme las actividades que tienes en mente.\"]', '[\"¿Tienes alguna situación específica en mente? No dudes en preguntar lo que necesites.\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[{\"original\": \"¿Hay algún evento hoy?\", \"translated\": \"Y a-t-il des événements aujourd\'hui ?\"}, {\"original\": \"¿Hay algo especial en este festival?\", \"translated\": \"Y a-t-il quelque chose de particulier à propos de ce festival ?\"}, {\"original\": \"¿Dónde se lleva a cabo la celebración?\", \"translated\": \"Où se déroule la célébration ?\"}, {\"original\": \"¿Cómo puedo comprar entradas?\", \"translated\": \"Comment puis-je acheter des billets ?\"}, {\"original\": \"¿A qué hora comienza la actuación?\", \"translated\": \"À quelle heure commence le spectacle ?\"}, {\"original\": \"¿Qué comida tradicional hay?\", \"translated\": \"Quels plats traditionnels y a-t-il ?\"}, {\"original\": \"Aquí está realmente animado.\", \"translated\": \"C’est vraiment animé ici.\"}, {\"original\": \"¿Hay alguna actividad popular?\", \"translated\": \"Y a-t-il des activités populaires ou traditionnelles ?\"}, {\"original\": \"¡Felices fiestas!\", \"translated\": \"Joyeuses fêtes !\"}, {\"original\": \"¿A qué hora termina el evento?\", \"translated\": \"À quelle heure se termine l’événement ?\"}]', 10, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un museo o una galería de arte?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con museos o galerías de arte, junto con sus traducciones al francés:\"]', '[\"Visitar\", \"Recibir una visita guiada\", \"Comprar entradas\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir un manual introductorio, frases relacionadas con un plano, frases para comentar una exposición? No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"Combien coûte l\'entrée ?\"}, {\"original\": \"¿Tienen guías de audio?\", \"translated\": \"Avez-vous des audioguides ?\"}, {\"original\": \"¿Quién creó esta obra de arte?\", \"translated\": \"Qui a créé cette œuvre d\'art ?\"}, {\"original\": \"¿Dónde se encuentra la pieza más valiosa del museo?\", \"translated\": \"Où se trouve la pièce la plus précieuse du musée ?\"}, {\"original\": \"¿Está permitida la fotografía?\", \"translated\": \"La photographie est-elle autorisée ?\"}, {\"original\": \"¿Hay alguna exposición especial aquí?\", \"translated\": \"Y a-t-il des expositions spéciales ici ?\"}, {\"original\": \"¿Cuánto tiempo dura la visita?\", \"translated\": \"Combien de temps dure la visite ?\"}, {\"original\": \"¿Podrían darnos una introducción?\", \"translated\": \"Pourriez-vous nous donner une introduction ?\"}, {\"original\": \"Estas obras son verdaderamente exquisitas.\", \"translated\": \"Ces œuvres sont vraiment exquises.\"}, {\"original\": \"¿Dónde está la tienda de souvenirs?\", \"translated\": \"Où se trouve la boutique de souvenirs ?\"}]', 11, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en una cafetería?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con las cafeterías, junto con sus traducciones al francés:\"]', '[\"Pedir café\", \"Descansar\", \"Socializar\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como pedir el menú, bebidas frías o calientes, otros productos? ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"Pediré un latte, por favor.\", \"translated\": \"Je prendrai un latte, s’il vous plaît.\"}, {\"original\": \"¿Tienen conexión Wi-Fi?\", \"translated\": \"Avez-vous le Wi-Fi ?\"}, {\"original\": \"¿Podría ver el menú, por favor?\", \"translated\": \"Pourriez-vous me montrer la carte, s’il vous plaît ?\"}, {\"original\": \"¿Se permiten recargas?\", \"translated\": \"Les recharges sont-elles autorisées ?\"}, {\"original\": \"¿Ya está listo mi café?\", \"translated\": \"Mon café est-il prêt ?\"}, {\"original\": \"¿Cuánto tiempo puedo quedarme aquí sentado?\", \"translated\": \"Combien de temps puis-je rester assis ici ?\"}, {\"original\": \"¿Podrían hacernos una foto?\", \"translated\": \"Pourriez-vous nous prendre en photo ?\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"La cuenta, por favor. Gracias.\", \"translated\": \"L’addition, s’il vous plaît. Merci.\"}, {\"original\": \"Sabe realmente bien.\", \"translated\": \"C’est vraiment délicieux.\"}]', 12, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un restaurante?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el restaurante, junto con sus traducciones al alemán:\"]', '[\"Comer\", \"Pedir\", \"Pagar\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir bebidas, presentar una queja o preguntar sobre los ingredientes? ¡No dude en preguntar!\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Disculpe, ¿cuánto tiempo más tardará nuestra comida?\", \"translated\": \"Entschuldigung, wie lange dauert es noch, bis unser Essen fertig ist?\"}, {\"original\": \"Una mesa para dos personas, por favor.\", \"translated\": \"Ein Tisch für zwei Personen, bitte.\"}, {\"original\": \"¿Podríamos ver el menú, por favor?\", \"translated\": \"Könnten wir bitte die Speisekarte sehen?\"}, {\"original\": \"¿Tienen algún plato especial que nos puedan recomendar?\", \"translated\": \"Haben Sie empfehlenswerte Spezialitäten?\"}, {\"original\": \"Me gustaría pedir esto y esto.\", \"translated\": \"Ich möchte dies und das bestellen.\"}, {\"original\": \"Un vaso de agua, por favor. Gracias.\", \"translated\": \"Ein Glas Wasser, bitte. Danke.\"}, {\"original\": \"La cuenta, por favor.\", \"translated\": \"Die Rechnung, bitte.\"}, {\"original\": \"¿Puedo pagar con tarjeta de crédito?\", \"translated\": \"Kann ich mit Kreditkarte bezahlen?\"}, {\"original\": \"¿Podrían empaquetar esto para llevar, por favor?\", \"translated\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\"}, {\"original\": \"La comida estuvo deliciosa, gracias.\", \"translated\": \"Das Essen war köstlich, danke.\"}]', 1, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un hotel?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el hotel, junto con sus traducciones al alemán:\"]', '[\"Check-in\", \"Check-out\", \"Servicio de habitaciones\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como la ubicación de la habitación, otros servicios del hotel o el check-out? ¡No dudes en preguntar.\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"Hola, tengo una reserva. Aquí está mi pasaporte.\", \"translated\": \"Hallo, ich habe eine Reservierung. Hier ist mein Reisepass.\"}, {\"original\": \"¿Tienen habitaciones disponibles?\", \"translated\": \"Haben Sie noch freie Zimmer?\"}, {\"original\": \"Perdone, ¿tiene el hotel gimnasio o servicio de lavandería?\", \"translated\": \"Entschuldigung, hat das Hotel ein Fitnessstudio oder einen Wäscheservice?\"}, {\"original\": \"¿A qué hora comienza el desayuno?\", \"translated\": \"Wann beginnt das Frühstück?\"}, {\"original\": \"¿Podría darme la llave de la habitación, por favor?\", \"translated\": \"Könnten Sie mir bitte den Zimmerschlüssel geben?\"}, {\"original\": \"¿Podría ayudarme a llevar mi equipaje a la habitación?\", \"translated\": \"Könnten Sie mir helfen, mein Gepäck aufs Zimmer zu bringen?\"}, {\"original\": \"¿Cómo llamo al servicio de habitaciones?\", \"translated\": \"Wie rufe ich den Zimmerservice?\"}, {\"original\": \"¿A qué hora es la salida del hotel?\", \"translated\": \"Wann ist der Check-out?\"}, {\"original\": \"¿Podría darme un recibo/factura?\", \"translated\": \"Könnten Sie mir bitte eine Quittung/Rechnung ausstellen?\"}, {\"original\": \"¿Puedo dejar mi equipaje aquí?\", \"translated\": \"Darf ich mein Gepäck hier lassen?\"}]', 2, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en el aeropuerto?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el aeropuerto, junto con sus traducciones al alemán:\"]', '[\"Facturación\", \"Embarque\", \"Facturación de equipaje\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como facturación, reclamación de equipaje o servicio de alquiler de coches? ¡No dudes en preguntar.\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Dónde está el mostrador de facturación?\", \"translated\": \"Wo ist der Check-in-Schalter?\"}, {\"original\": \"Me gustaría un asiento junto a la ventana, por favor.\", \"translated\": \"Ich hätte gerne einen Fensterplatz, bitte.\"}, {\"original\": \"¿Está retrasado este vuelo?\", \"translated\": \"Ist dieser Flug verspätet?\"}, {\"original\": \"Necesito facturar este equipaje.\", \"translated\": \"Ich muss dieses Gepäck aufgeben.\"}, {\"original\": \"¿Dónde está la puerta de embarque?\", \"translated\": \"Wo ist die Boarding-Tür?\"}, {\"original\": \"El avión está a punto de despegar.\", \"translated\": \"Das Flugzeug startet gleich.\"}, {\"original\": \"¿Necesito sacar mi ordenador portátil y mi power bank?\", \"translated\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\"}, {\"original\": \"¿Dónde está la tienda libre de impuestos?\", \"translated\": \"Wo ist der Duty-free-Shop?\"}, {\"original\": \"No encuentro mi maleta.\", \"translated\": \"Ich kann meinen Koffer nicht finden.\"}, {\"original\": \"¿Ofrecen servicio de silla de ruedas?\", \"translated\": \"Bieten Sie einen Rollstuhlservice an?\"}]', 3, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podrías darme 10 frases comunes que pueda usar en los medios de transporte público?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con los medios de transporte público, junto con sus traducciones al alemán:\"]', '[\"Tomar autobús o metro\", \"Comprar billetes\", \"Hacer transbordo\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como preguntar por una parada de autobús, el precio del billete o dónde bajarse? ¡No dudes en preguntar.\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Este autobús va a la terminal?\", \"translated\": \"Fährt dieser Bus zum Busbahnhof?\"}, {\"original\": \"¿Cuál es la próxima parada?\", \"translated\": \"Was ist die nächste Haltestelle?\"}, {\"original\": \"¿Dónde puedo comprar un billete?\", \"translated\": \"Wo kann ich ein Ticket kaufen?\"}, {\"original\": \"Un billete para XX, por favor.\", \"translated\": \"Ein Ticket nach XX, bitte.\"}, {\"original\": \"¿Tengo que hacer transbordo?\", \"translated\": \"Muss ich umsteigen?\"}, {\"original\": \"¿Cuánto tiempo falta para el próximo tren del metro?\", \"translated\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\"}, {\"original\": \"Perdón, ¿me deja pasar, por favor?\", \"translated\": \"Entschuldigung, darf ich bitte vorbei?\"}, {\"original\": \"¿Está ocupado este asiento?\", \"translated\": \"Ist dieser Platz schon besetzt?\"}, {\"original\": \"Perdón, ¿dónde puedo hacer transbordo a la línea 2 para llegar a XX?\", \"translated\": \"Entschuldigung, wo kann ich zur Linie 2 umsteigen, um nach XX zu gelangen?\"}, {\"original\": \"¿Cómo llego a XX?\", \"translated\": \"Wie komme ich nach XX?\"}]', 4, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en lugares turísticos?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con lugares turísticos, junto con sus traducciones al alemán:\"]', '[\"Turismo\", \"Hacer fotos\", \"Comprar entradas\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, por ejemplo preguntar sobre el precio de las entradas, encontrar un estacionamiento o solicitar un servicio de guía turística? ¡No dudes en preguntar.\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"¿Hay entradas para estudiantes disponibles?\", \"translated\": \"Gibt es ermäßigte Eintrittskarten für Schüler und Studenten?\"}, {\"original\": \"¿A qué hora abre la atracción?\", \"translated\": \"Wann öffnet die Sehenswürdigkeit?\"}, {\"original\": \"¿Qué cosas divertidas se pueden hacer aquí?\", \"translated\": \"Was kann man hier alles Lustiges unternehmen?\"}, {\"original\": \"¿Podría hacernos una foto?\", \"translated\": \"Könnten Sie uns bitte ein Foto machen?\"}, {\"original\": \"¿Dónde está el autobús turístico?\", \"translated\": \"Wo befindet sich der Sightseeing-Bus?\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"¿Cuál es el mejor lugar para contemplar las vistas?\", \"translated\": \"Wo ist der beste Aussichtspunkt?\"}, {\"original\": \"El paisaje aquí es precioso.\", \"translated\": \"Die Landschaft hier ist wunderschön.\"}, {\"original\": \"¿Hay visitas guiadas disponibles?\", \"translated\": \"Gibt es geführte Touren?\"}]', 5, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en taxis o servicios de taxi?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con taxis o servicios de taxi, junto con sus traducciones al alemán:\"]', '[\"Tomar un taxi\", \"Indicar el destino\", \"Pago\"]', 'es', '[\"Por ahora, ¿qué es lo que más te gustaría hacer ahora? Por ejemplo: preguntar la dirección, el precio o solicitar una factura. ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Dónde puedo conseguir un taxi?\", \"translated\": \"Wo kann ich ein Taxi bekommen?\"}, {\"original\": \"Por favor, lléveme a esta dirección.\", \"translated\": \"Bitte bringen Sie mich zu dieser Adresse.\"}, {\"original\": \"¿Cuánto costará aproximadamente?\", \"translated\": \"Wie viel wird es ungefähr kosten?\"}, {\"original\": \"¿Podría usar el taxímetro, por favor?\", \"translated\": \"Könnten Sie bitte den Taxameter benutzen?\"}, {\"original\": \"Por favor, conduzca un poco más rápido, voy con prisa.\", \"translated\": \"Bitte fahren Sie etwas schneller, ich habe es eilig.\"}, {\"original\": \"Deténgase aquí, por favor.\", \"translated\": \"Bitte halten Sie hier an.\"}, {\"original\": \"¿Acepta tarjetas o pagos móviles?\", \"translated\": \"Akzeptieren Sie Karten- oder Mobile-Payment?\"}, {\"original\": \"¿Podría darme un recibo, por favor?\", \"translated\": \"Könnte ich bitte eine Quittung bekommen?\"}, {\"original\": \"Gracias, señor conductor.\", \"translated\": \"Danke, Fahrer.\"}, {\"original\": \"¿Cuánto falta todavía?\", \"translated\": \"Wie weit ist es noch?\"}]', 6, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en una farmacia?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con las farmacias, junto con sus traducciones al alemán:\"]', '[\"Comprar medicamentos\", \"Consulta\", \"Pago\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir indicaciones sobre cómo tomar un medicamento, frases relacionadas con el uso del seguro médico o la duración del tratamiento? No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Tiene medicamento para el resfriado?\", \"translated\": \"Haben Sie Medikamente gegen Erkältung?\"}, {\"original\": \"¿Cómo debo tomar este medicamento?\", \"translated\": \"Wie soll ich dieses Medikament einnehmen?\"}, {\"original\": \"¿Tiene analgésicos?\", \"translated\": \"Haben Sie Schmerzmittel?\"}, {\"original\": \"¿Hay un prospecto incluido?\", \"translated\": \"Gibt es eine Gebrauchsanweisung?\"}, {\"original\": \"¿Este medicamento tiene efectos secundarios?\", \"translated\": \"Hat dieses Medikament Nebenwirkungen?\"}, {\"original\": \"¿Puedo usar mi tarjeta de seguro médico?\", \"translated\": \"Kann ich meine Krankenversicherungskarte verwenden?\"}, {\"original\": \"¿Podría darme una caja de tiras adhesivas, por favor?\", \"translated\": \"Könnten Sie mir bitte eine Packung Pflaster geben?\"}, {\"original\": \"¿Tiene medicamentos para bajar la fiebre?\", \"translated\": \"Haben Sie Fiebersenkungsmittel?\"}, {\"original\": \"Tengo una pequeña herida superficial. ¿Tiene antiséptico y tiras adhesivas?\", \"translated\": \"Ich habe eine kleine Schürfwunde. Haben Sie Desinfektionsmittel und Pflaster?\"}, {\"original\": \"¿A qué hora cierran?\", \"translated\": \"Wann schließen Sie?\"}]', 7, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en servicios de emergencia?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con los servicios de emergencia, junto con sus traducciones al alemán:\"]', '[\"Llamar a la policía\", \"Primeros auxilios\", \"Pedir ayuda\"]', 'es', '[\"Por ahora, ¿tiene alguna situación de emergencia específica en mente, como incendio, persona herida y que necesita ayuda, llamada de emergencia? No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Por favor, ayúdeme a llamar a una ambulancia.\", \"translated\": \"Bitte helfen Sie mir, einen Krankenwagen zu rufen.\"}, {\"original\": \"¿Dónde está el hospital?\", \"translated\": \"Wo ist das Krankenhaus?\"}, {\"original\": \"Alguien resultó herido.\", \"translated\": \"Jemand ist verletzt.\"}, {\"original\": \"Por favor, ayúdeme.\", \"translated\": \"Bitte helfen Sie mir.\"}, {\"original\": \"¿Dónde está la comisaría de policía?\", \"translated\": \"Wo ist die nächste Polizeistation?\"}, {\"original\": \"He perdido mis pertenencias.\", \"translated\": \"Ich habe meine Habseligkeiten verloren.\"}, {\"original\": \"¿Cuál es el número del cuerpo de bomberos?\", \"translated\": \"Was ist die Telefonnummer der Feuerwehr?\"}, {\"original\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría de policía más cercana?\", \"translated\": \"Ich habe meinen Pass verloren. Können Sie mir sagen, wo die nächste Polizeistation ist?\"}, {\"original\": \"¿Hay una salida de emergencia?\", \"translated\": \"Gibt es einen Notausgang?\"}, {\"original\": \"Alguien ha perdido el conocimiento.\", \"translated\": \"Jemand ist in Ohnmacht gefallen.\"}]', 8, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podrías proporcionarme 10 frases comunes que pueda usar en la playa o junto a la piscina?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con la playa o junto a la piscina, junto con sus traducciones al alemán:\"]', '[\"Nadar\", \"Tomar el sol\", \"Deportes playeros\"]', 'es', '[\"Por ahora, ¿podrías indicarme el contexto del evento o festival local al que asistirás, por ejemplo, un festival cultural, gastronómico o musical? Por favor, indica el contexto.\", \"Indica las actividades a las que asistirás.\"]', '[\"¿Tienes una situación específica en mente? ¡No dudes en preguntar!\", \"Describe la situación que tienes en mente.\"]', '[{\"original\": \"¡Mira! Las olas allí son realmente grandes.\", \"translated\": \"Schau mal! Die Wellen dort drüben sind wirklich groß.\"}, {\"original\": \"Recuerda aplicar protector solar; aquí los rayos UV son muy intensos.\", \"translated\": \"Denk daran, Sonnenschutzmittel aufzutragen – die UV-Strahlen sind hier sehr stark.\"}, {\"original\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\", \"translated\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Watte gehen.\"}, {\"original\": \"¿Qué tal jugar al voleibol en la playa?\", \"translated\": \"Wie wäre es mit einem Volleyballspiel am Strand?\"}, {\"original\": \"Los veleros a lo lejos se ven preciosos.\", \"translated\": \"Die Segelboote in der Ferne sehen wunderschön aus.\"}, {\"original\": \"El agua aquí es tan transparente que incluso puedes ver los peces.\", \"translated\": \"Das Wasser hier ist so klar, dass du sogar die Fische sehen kannst.\"}, {\"original\": \"Vamos a buscar conchas marinas.\", \"translated\": \"Lass uns nach Muscheln suchen.\"}, {\"original\": \"Dar un paseo por la playa al atardecer debe ser muy romántico.\", \"translated\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\"}, {\"original\": \"He oído que aquí el marisco es muy fresco; vamos a probarlo.\", \"translated\": \"Ich habe gehört, dass die Meeresfrüchte hier besonders frisch sind – lasst uns welche probieren!\"}, {\"original\": \"La marea está subiendo; volvamos hacia la orilla.\", \"translated\": \"Die Flut kommt herein – gehen wir zurück zum Ufer.\"}]', 9, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podrías darme 10 frases comunes que pueda usar en actividades y festivales locales?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con actividades y festivales locales, junto con sus traducciones al alemán:\"]', '[\"Asistir a eventos\", \"Celebrar festivales\", \"Aprender sobre la cultura\"]', 'es', '[\"Por ahora, ¿podrías indicarme el contexto del evento o festival local al que vas a asistir? Por ejemplo: Halloween, un concierto, una fiesta entre amigos u otra cosa. Por favor, indícame el contexto.\", \"Describe las actividades que tienes en mente.\"]', '[\"¿Tienes alguna situación específica en mente? ¡Pregunta libremente!\", \"Describe la situación que tienes en mente.\"]', '[{\"original\": \"¿Hay algún evento hoy?\", \"translated\": \"Gibt es heute irgendwelche Veranstaltungen?\"}, {\"original\": \"¿Hay algo especial sobre este festival?\", \"translated\": \"Gibt es etwas Besonderes an diesem Festival?\"}, {\"original\": \"¿Dónde se celebra la fiesta?\", \"translated\": \"Wo findet die Feier statt?\"}, {\"original\": \"¿Cómo puedo comprar entradas?\", \"translated\": \"Wie kann ich Tickets kaufen?\"}, {\"original\": \"¿A qué hora empieza la actuación?\", \"translated\": \"Wann beginnt die Vorstellung?\"}, {\"original\": \"¿Qué comida tradicional hay?\", \"translated\": \"Welche traditionellen Speisen gibt es?\"}, {\"original\": \"Aquí está muy animado.\", \"translated\": \"Es ist hier wirklich lebhaft.\"}, {\"original\": \"¿Hay alguna actividad folclórica?\", \"translated\": \"Gibt es volkstümliche Aktivitäten?\"}, {\"original\": \"¡Felices fiestas!\", \"translated\": \"Frohe Feiertage!\"}, {\"original\": \"¿A qué hora termina el evento?\", \"translated\": \"Wann endet die Veranstaltung?\"}]', 10, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría facilitarme 10 frases comunes que pueda usar en un museo o galería de arte?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con museos o galerías de arte, junto con sus traducciones al alemán:\"]', '[\"Visita\", \"Visita guiada\", \"Compra de entradas\"]', 'es', '[\"Por ahora, ¿tiene usted alguna situación específica en mente, como pedir un folleto informativo, frases relacionadas con un plano del recorrido o frases para comentar las exposiciones? ¡No dude en preguntar.\", \"Describa la situación que tenga en mente.\"]', '[]', '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"¿Tienen guías de audio?\", \"translated\": \"Bieten Sie Audioführungen an?\"}, {\"original\": \"¿Quién creó esta obra de arte?\", \"translated\": \"Wer hat dieses Kunstwerk geschaffen?\"}, {\"original\": \"¿Dónde está la pieza más valiosa del museo?\", \"translated\": \"Wo befindet sich das wertvollste Exponat des Museums?\"}, {\"original\": \"¿Está permitida la fotografía?\", \"translated\": \"Ist das Fotografieren erlaubt?\"}, {\"original\": \"¿Hay alguna exposición especial aquí?\", \"translated\": \"Gibt es hier aktuell besondere Ausstellungen?\"}, {\"original\": \"¿Cuánto tiempo dura la visita?\", \"translated\": \"Wie lange dauert der Besuch?\"}, {\"original\": \"¿Podrían darnos una introducción?\", \"translated\": \"Könnten Sie uns eine Einführung geben?\"}, {\"original\": \"Estas obras son verdaderamente exquisitas.\", \"translated\": \"Diese Werke sind wirklich exquisit.\"}, {\"original\": \"¿Dónde está la tienda de souvenirs?\", \"translated\": \"Wo befindet sich der Souvenirshop?\"}]', 11, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en una cafetería?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con la cafetería, junto con sus traducciones al alemán:\"]', '[\"Pedir café\", \"Descansar\", \"Socializar\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como pedir el menú, bebidas frías o calientes, otros productos? ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"Pediré un latte, por favor.\", \"translated\": \"Ich hätte gerne einen Latte, bitte.\"}, {\"original\": \"¿Tienen conexión Wi-Fi?\", \"translated\": \"Haben Sie WLAN?\"}, {\"original\": \"¿Podría ver el menú, por favor?\", \"translated\": \"Könnte ich bitte die Speisekarte sehen?\"}, {\"original\": \"¿Se permiten recargas?\", \"translated\": \"Sind Nachfüllungen erlaubt?\"}, {\"original\": \"¿Ya está listo mi café?\", \"translated\": \"Ist mein Kaffee schon fertig?\"}, {\"original\": \"¿Cuánto tiempo puedo quedarme aquí sentado?\", \"translated\": \"Wie lange darf ich hier sitzen bleiben?\"}, {\"original\": \"¿Nos podría hacer una foto?\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"La cuenta, por favor. Gracias.\", \"translated\": \"Die Rechnung, bitte. Danke.\"}, {\"original\": \"Sabe realmente delicioso.\", \"translated\": \"Es schmeckt wirklich gut.\"}]', 12, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"レストランで使えるよく使う表現を10個教えてもらえますか？\", \"素晴らしい！以下に、レストラン関連のよく使う表現10個と、スペイン語訳を載せました。\"]', '[\"食事\", \"注文\", \"会計\"]', 'ja', '[\"今のところ、ドリンクの注文、クレームの申し立て、材料についての質問など、特定の状況が頭に浮かんでいますか？遠慮なく聞いてください。\", \"あなたの頭に浮かんでいる状況を教えてください。\"]', '[]', '[{\"original\": \"すみません、料理はまだどれくらいで来ますか？\", \"translated\": \"Perdone, ¿cuánto tiempo más tardará nuestra comida?\"}, {\"original\": \"2名様のテーブルをお願いします。\", \"translated\": \"Una mesa para dos, por favor.\"}, {\"original\": \"メニューを見せていただけますか？\", \"translated\": \"¿Nos podría traer el menú, por favor?\"}, {\"original\": \"おすすめの看板料理はありますか？\", \"translated\": \"¿Tienen algún plato típico que nos recomiende?\"}, {\"original\": \"これを注文したいです。あと、これもお願いします。\", \"translated\": \"Quisiera pedir esto y también esto.\"}, {\"original\": \"水を一杯お願いします。ありがとうございます。\", \"translated\": \"Una copa de agua, por favor. Gracias.\"}, {\"original\": \"お会計をお願いします。\", \"translated\": \"La cuenta, por favor.\"}, {\"original\": \"クレジットカードで支払えますか？\", \"translated\": \"¿Puedo pagar con tarjeta de crédito?\"}, {\"original\": \"こちらは持ち帰りでお願いします。\", \"translated\": \"¿Podría empaquetar esto para llevar, por favor?\"}, {\"original\": \"とても美味しかったです。ありがとうございました。\", \"translated\": \"La comida estuvo deliciosa, ¡gracias!\"}]', 1, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ホテルで使える一般的なフレーズを10個教えてもらえますか？\", \"素晴らしい！こちらがホテル関連のよく使うフレーズ10個と、スペイン語訳です：\"]', '[\"チェックイン\", \"チェックアウト\", \"ルームサービス\"]', 'ja', '[\"今のところ、部屋の位置、その他のホテルサービス、あるいはチェックアウトなど、ご希望の具体的な状況はありますか？何でも遠慮なくお尋ねください。\", \"あなたの頭にある状況を教えてください。\"]', '[]', '[{\"original\": \"こんにちは、予約しています。こちらが私のパスポートです。\", \"translated\": \"Hola, tengo una reserva. Aquí está mi pasaporte.\"}, {\"original\": \"空室はありますか？\", \"translated\": \"¿Tienen habitaciones disponibles?\"}, {\"original\": \"すみません、このホテルにはジムやランドリールームはありますか？\", \"translated\": \"Disculpe, ¿el hotel tiene gimnasio o servicio de lavandería?\"}, {\"original\": \"朝食は何時から始まりますか？\", \"translated\": \"¿A qué hora comienza el desayuno?\"}, {\"original\": \"部屋の鍵をいただけますか？\", \"translated\": \"¿Podría darme la llave de la habitación, por favor?\"}, {\"original\": \"荷物を部屋まで運んでいただけますか？\", \"translated\": \"¿Podría ayudarme a llevar mi equipaje hasta la habitación?\"}, {\"original\": \"ルームサービスの電話のかけ方はどうすればいいですか？\", \"translated\": \"¿Cómo puedo llamar al servicio de habitaciones?\"}, {\"original\": \"チェックアウトの時間は何時ですか？\", \"translated\": \"¿A qué hora es el check-out?\"}, {\"original\": \"領収書／請求書を書いていただけますか？\", \"translated\": \"¿Podría emitirme un recibo/factura?\"}, {\"original\": \"荷物をここに預けておいても大丈夫ですか？\", \"translated\": \"¿Puedo dejar mi equipaje aquí por un rato?\"}]', 2, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"空港で使える便利なフレーズを10個教えていただけますか？\", \"素晴らしい！以下に、空港に関する便利なフレーズ10個とそのスペイン語訳をご紹介します：\"]', '[\"チェックイン\", \"搭乗\", \"手荷物預け\"]', 'ja', '[\"今のところ、チェックイン、手荷物受取、レンタカーなどの特定の場面を思い浮かべていますか？ どんなことでも気軽にご質問ください。\", \"あなたの頭の中で思い浮かべている状況について教えてください。\"]', '[]', '[{\"original\": \"チェックインカウンターはどこですか？\", \"translated\": \"¿Dónde está el mostrador de facturación?\"}, {\"original\": \"窓際の席をお願いします。\", \"translated\": \"Me gustaría un asiento junto a la ventana, por favor.\"}, {\"original\": \"この便は遅れていますか？\", \"translated\": \"¿Está retrasado este vuelo?\"}, {\"original\": \"この荷物を預けたいのですが。\", \"translated\": \"Necesito facturar este equipaje.\"}, {\"original\": \"搭乗口はどこですか？\", \"translated\": \"¿Dónde está la puerta de embarque?\"}, {\"original\": \"飛行機がもうすぐ離陸します。\", \"translated\": \"El avión está a punto de despegar.\"}, {\"original\": \"ノートパソコンとモバイルバッテリーを出し必要がありますか？\", \"translated\": \"¿Debo sacar mi ordenador portátil y mi power bank?\"}, {\"original\": \"免税店はどこですか？\", \"translated\": \"¿Dónde está la tienda libre de impuestos?\"}, {\"original\": \"自分のスーツケースが見つかりません。\", \"translated\": \"No puedo encontrar mi maleta.\"}, {\"original\": \"車椅子サービスはありますか？\", \"translated\": \"¿Ofrecen servicio de silla de ruedas?\"}]', 3, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"公共交通機関で使える定番のフレーズを10個教えてもらえますか？\", \"素晴らしい！以下は、公共交通機関に関する定番のフレーズ10個と、そのスペイン語訳です：\"]', '[\"バス・地下鉄の利用\", \"切符の購入\", \"乗り換え\"]', 'ja', '[\"今のところ、バス停の確認、運賃の問い合わせ、降車のタイミングなど、何か特定の状況が頭に浮かんでいますか？気兼ねなくお聞かせください。\", \"頭に浮かんだ状況を教えてください。\"]', '[]', '[{\"original\": \"このバスは終点へ行きますか？\", \"translated\": \"¿Este autobús va a la terminal?\"}, {\"original\": \"次の停留所はどこですか？\", \"translated\": \"¿Cuál es la próxima parada?\"}, {\"original\": \"切符はどこで買えますか？\", \"translated\": \"¿Dónde puedo comprar un boleto?\"}, {\"original\": \"XX行きの切符を1枚お願いします。\", \"translated\": \"Un boleto para XX, por favor.\"}, {\"original\": \"乗り換えが必要ですか？\", \"translated\": \"¿Necesito hacer transbordo?\"}, {\"original\": \"次の地下鉄の列車まであと何分ですか？\", \"translated\": \"¿Cuántos minutos faltan para el próximo tren del metro?\"}, {\"original\": \"すみません、通らせてください。\", \"translated\": \"Disculpe, permítame pasar.\"}, {\"original\": \"この席は空いていますか？\", \"translated\": \"¿Está este asiento libre?\"}, {\"original\": \"すみません、XXへ行くには2号線に乗り換えるにはどこで乗り換えればいいですか？\", \"translated\": \"Disculpe, ¿dónde puedo transferirme a la Línea 2 para llegar a XX?\"}, {\"original\": \"XXへはどう行けばいいですか？\", \"translated\": \"¿Cómo llego a XX?\"}]', 4, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"10個のよく使う旅行先での会話フレーズを教えてください。\", \"素晴らしい！以下は、旅行先に関連する10個のよく使う会話フレーズと、そのスペイン語訳です：\"]', '[\"観光\", \"写真撮影\", \"チケット購入\"]', 'ja', '[\"今のところ、チケットの値段を尋ねる、駐車場を探す、またはツアー案内サービスに関するなど、具体的な状況が頭に浮かんでいますか？いつでもお気軽に聞いてください。\", \"あなたの頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"入場料はいくらですか？\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"学生向けの割引チケットはありますか？\", \"translated\": \"¿Hay entradas con descuento para estudiantes?\"}, {\"original\": \"観光スポットの開園時間は何時からですか？\", \"translated\": \"¿A qué hora abre la atracción?\"}, {\"original\": \"ここではどんな楽しいことが体験できますか？\", \"translated\": \"¿Qué cosas divertidas se pueden hacer aquí?\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"¿Podría tomarnos una foto?\"}, {\"original\": \"観光バスの乗り場はどこですか？\", \"translated\": \"¿Dónde está el punto de partida del autobús turístico?\"}, {\"original\": \"トイレはどこにありますか？\", \"translated\": \"¿Dónde están los baños?\"}, {\"original\": \"一番景色がきれいに見えるおすすめのスポットはどこですか？\", \"translated\": \"¿Cuál es el mejor lugar para disfrutar de las vistas?\"}, {\"original\": \"ここでの風景はとても美しいですね。\", \"translated\": \"El paisaje aquí es muy hermoso.\"}, {\"original\": \"ガイド付きツアーはありますか？\", \"translated\": \"¿Hay visitas guiadas disponibles?\"}]', 5, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"タクシーまたは配車サービスで使える10のよく使う表現を教えてください。\", \"素晴らしい！以下は、タクシーまたは配車サービスに関連する10のよく使う表現と、そのスペイン語訳です：\"]', '[\"タクシーを利用する\", \"目的地を伝える\", \"支払いに関するやりとり\"]', 'ja', '[\"今のところ、目的地の確認、料金の確認、領収書の請求など、何を一番知りたいですか？遠慮なく聞いてください。\", \"頭の中で思い浮かべている状況を教えてください。\"]', '[]', '[{\"original\": \"タクシーはどこで乗れますか？\", \"translated\": \"¿Dónde puedo tomar un taxi?\"}, {\"original\": \"この住所までお願いします。\", \"translated\": \"Por favor, lléveme a esta dirección.\"}, {\"original\": \"だいたいいくらぐらいになりますか？\", \"translated\": \"¿Cuánto costará aproximadamente?\"}, {\"original\": \"メーターを使っていただけますか？\", \"translated\": \"¿Podría usar el taxímetro, por favor?\"}, {\"original\": \"急いでいますので、少しだけスピードを上げてもらえますか？\", \"translated\": \"Por favor, conduzca un poco más rápido; tengo prisa.\"}, {\"original\": \"ここで止めてください。\", \"translated\": \"Por favor, párese aquí.\"}, {\"original\": \"カードやモバイル決済は使えますか？\", \"translated\": \"¿Acepta tarjetas o pagos móviles?\"}, {\"original\": \"領収書をいただけますか？\", \"translated\": \"¿Podría darme un recibo, por favor?\"}, {\"original\": \"ありがとう、運転手さん。\", \"translated\": \"Gracias, conductor.\"}, {\"original\": \"あとどれくらいですか？\", \"translated\": \"¿Cuánto falta todavía?\"}]', 6, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"薬局で使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下は、薬局でよく使う10個の表現と、そのスペイン語訳です。\"]', '[\"お薬の購入\", \"相談\", \"支払い\"]', 'ja', '[\"今のところ、お薬の飲み方の確認、保険の使い方、服用期間など、特定の状況を想定されていますか？ご自由にお知らせください。\", \"ご希望の状況について、詳しく教えてください。\"]', '[]', '[{\"original\": \"風邪薬はありますか？\", \"translated\": \"¿Tienen medicamento para el resfriado?\"}, {\"original\": \"この薬の飲み方はどうすればいいですか？\", \"translated\": \"¿Cómo debo tomar este medicamento?\"}, {\"original\": \"鎮痛剤はありますか？\", \"translated\": \"¿Tienen analgésicos?\"}, {\"original\": \"説明書はついていますか？\", \"translated\": \"¿Viene con un folleto de instrucciones?\"}, {\"original\": \"この薬には副作用がありますか？\", \"translated\": \"¿Este medicamento tiene efectos secundarios?\"}, {\"original\": \"医療保険証を使えますか？\", \"translated\": \"¿Puedo usar mi tarjeta de seguro médico?\"}, {\"original\": \"バンドエイドを1箱ください。\", \"translated\": \"¿Me podría dar una caja de vendas adhesivas, por favor?\"}, {\"original\": \"解熱剤はありますか？\", \"translated\": \"¿Tienen medicamentos para bajar la fiebre?\"}, {\"original\": \"ちょっと擦り傷をしました。消毒液とバンドエイドはありますか？\", \"translated\": \"Me he hecho una pequeña rozadura. ¿Tienen antiséptico y vendas adhesivas?\"}, {\"original\": \"何時まで営業していますか？\", \"translated\": \"¿A qué hora cierran?\"}]', 7, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"緊急サービスで使える一般的なフレーズを10個教えてもらえますか？\", \"素晴らしい！以下は、緊急サービスに関連する一般的なフレーズ10個と、そのスペイン語訳です：\"]', '[\"警察を呼ぶ\", \"応急処置\", \"助けを求める\"]', 'ja', '[\"今のところ、火事、怪我をして助けが必要、緊急通報など、具体的な緊急状況をお考えですか？遠慮なくどうぞ。\", \"頭の中で思い浮かぶ状況を教えてください。\"]', '[]', '[{\"original\": \"救急車を呼んでください。\", \"translated\": \"Por favor, llame a una ambulancia.\"}, {\"original\": \"病院はどこですか？\", \"translated\": \"¿Dónde está el hospital?\"}, {\"original\": \"誰かが怪我をしました。\", \"translated\": \"Alguien resultó herido.\"}, {\"original\": \"助けてください。\", \"translated\": \"Por favor, ayúdeme.\"}, {\"original\": \"警察署はどこですか？\", \"translated\": \"¿Dónde está la comisaría de policía?\"}, {\"original\": \"荷物を紛失しました。\", \"translated\": \"He perdido mis pertenencias.\"}, {\"original\": \"消防署にかける電話番号は何番ですか？\", \"translated\": \"¿Cuál es el número de teléfono del cuerpo de bomberos?\"}, {\"original\": \"パスポートを紛失しました。最寄りの警察署をご存知ですか？\", \"translated\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría de policía más cercana?\"}, {\"original\": \"非常口がありますか？\", \"translated\": \"¿Hay una salida de emergencia?\"}, {\"original\": \"誰かが気を失いました。\", \"translated\": \"Alguien ha perdido el conocimiento.\"}]', 8, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"今から、『ビーチまたはプールサイド』で使える一般的なフレーズを10個教えていただけますか？\", \"素晴らしい！以下に、『ビーチまたはプールサイド』に関する一般的なフレーズ10個と、そのスペイン語訳をご紹介します：\"]', '[\"水泳\", \"日光浴\", \"ビーチスポーツ\"]', 'ja', '[\"今のところ、参加予定の地元のイベントやお祭り（例：文化祭、フードフェスティバル、音楽フェスティバルなど）について、具体的な背景情報を教えていただけますか？\", \"参加する予定のアクティビティを教えてください。\"]', '[\"何か特定の状況が頭に浮かんでいますか？遠慮なく聞いてください。\", \"頭の中で思い描いている状況を教えてください。\"]', '[{\"original\": \"見て！あそこにある波は本当に大きいわ。\", \"translated\": \"¡Mira! Las olas allí son realmente grandes.\"}, {\"original\": \"日焼け止めを塗ることを忘れないでください。ここでの紫外線はとても強いですよ。\", \"translated\": \"Recuerda aplicarte protector solar; aquí los rayos UV son muy intensos.\"}, {\"original\": \"このビーチの砂はとても滑らかで、綿の上を歩いているような気分になります。\", \"translated\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\"}, {\"original\": \"ビーチでバレーボールをやるのはどうですか？\", \"translated\": \"¿Qué tal si jugamos voleibol en la playa?\"}, {\"original\": \"遠くに見えるセーリングボートがとても美しいですね。\", \"translated\": \"Los veleros a lo lejos se ven preciosos.\"}, {\"original\": \"ここでの水はとても透明で、魚もはっきり見えますよ。\", \"translated\": \"El agua aquí es tan cristalina que incluso puedes ver los peces.\"}, {\"original\": \"一緒に貝殻を探しに行きましょう！\", \"translated\": \"¡Vamos a buscar conchas marinas!\"}, {\"original\": \"夕暮れ時にビーチを散歩するのは、きっととてもロマンチックでしょうね。\", \"translated\": \"Pasear por la playa al atardecer debe ser muy romántico.\"}, {\"original\": \"ここではシーフードがとても新鮮だと聞きました。ぜひ食べてみましょう！\", \"translated\": \"He oído que los mariscos aquí son muy frescos; ¡vamos a probarlos!\"}, {\"original\": \"潮が満ちてきていますね。じゃあ、浜辺に向かいましょう。\", \"translated\": \"La marea está subiendo; vamos hacia la orilla.\"}]', 9, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"現地のイベントや祭りで使える、10個のよく使うフレーズを教えていただけますか？\", \"素晴らしい！以下は、現地のイベントや祭りに関連する10個のよく使うフレーズと、そのスペイン語訳です：\"]', '[\"イベントへの参加\", \"祭りの祝い\", \"文化の学習\"]', 'ja', '[\"まず、ハロウィン、コンサート、友だちとのパーティーなど、ご参加予定の現地のイベントや祭りについて、もう少し状況を教えていただけますか？ご自由にお知らせください。\", \"あなたが思い浮かべているアクティビティを教えてください。\"]', '[\"特定のシーン（状況）を思い浮かべていますか？何でもお気軽にお尋ねください。\", \"あなたが思い浮かべている状況を教えてください。\"]', '[{\"original\": \"今日は何かイベントがありますか？\", \"translated\": \"¿Hay algún evento hoy?\"}, {\"original\": \"この祭りには何か特別なことってありますか？\", \"translated\": \"¿Hay algo especial sobre este festival?\"}, {\"original\": \"お祝いの場所はどこですか？\", \"translated\": \"¿Dónde se lleva a cabo la celebración?\"}, {\"original\": \"チケットはどこで買えますか？\", \"translated\": \"¿Cómo puedo comprar las entradas?\"}, {\"original\": \"パフォーマンスは何時から始まりますか？\", \"translated\": \"¿A qué hora comienza la presentación?\"}, {\"original\": \"どんな伝統的な食べ物がありますか？\", \"translated\": \"¿Qué comida tradicional hay?\"}, {\"original\": \"ここ、本当に活気がありますね。\", \"translated\": \"¡Qué animado está aquí!\"}, {\"original\": \"民俗活動はありますか？\", \"translated\": \"¿Hay actividades folclóricas?\"}, {\"original\": \"よいお休みを！\", \"translated\": \"¡Felices fiestas!\"}, {\"original\": \"イベントはいつ終わりますか？\", \"translated\": \"¿A qué hora termina el evento?\"}]', 10, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"博物館または美術館で使える10のよく使う表現を10個教えてください。\", \"素晴らしい！以下は、博物館または美術館に関連する10のよく使う表現と、そのスペイン語訳です：\"]', '[\"見学\", \"ガイド付きツアー\", \"チケット購入\"]', 'ja', '[\"今のところ、たとえば解説パンフレットの依頼、館内マップに関する表現、展示品への感想を述べる表現など、具体的な状況を思い浮かべていますか？自由にご質問ください。\", \"あなたが頭に浮かべている状況を教えてください。\"]', '[]', '[{\"original\": \"入館料はいくらですか？\", \"translated\": \"¿Cuál es la tarifa de entrada?\"}, {\"original\": \"オーディオガイドはありますか？\", \"translated\": \"¿Tienen guías de audio?\"}, {\"original\": \"この作品は誰が制作したのですか？\", \"translated\": \"¿Quién creó esta obra de arte?\"}, {\"original\": \"博物館の最も貴重な所蔵品はどこにありますか？\", \"translated\": \"¿Dónde se encuentra la pieza más valiosa del museo?\"}, {\"original\": \"写真撮影は許可されていますか？\", \"translated\": \"¿Está permitida la fotografía?\"}, {\"original\": \"ここには特別展はありますか？\", \"translated\": \"¿Hay alguna exposición especial aquí?\"}, {\"original\": \"見学にはどのくらい時間がかかりますか？\", \"translated\": \"¿Cuánto tiempo lleva la visita?\"}, {\"original\": \"少し紹介していただけますか？\", \"translated\": \"¿Podrían darnos una breve introducción?\"}, {\"original\": \"これらの作品は本当に素晴らしいですね。\", \"translated\": \"Estas obras son verdaderamente exquisitas.\"}, {\"original\": \"お土産ショップはどこですか？\", \"translated\": \"¿Dónde está la tienda de souvenirs?\"}]', 11, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"カフェで使える一般的なフレーズを10個教えていただけますか？\", \"素晴らしい！こちらがカフェ関連の一般的なフレーズ10個と、スペイン語での翻訳です：\"]', '[\"コーヒーを注文する\", \"休憩する\", \"交流する\"]', 'ja', '[\"今のところ、メニューを見たい、アイスやホットドリンクを頼みたい、他の商品について確認したいなど、具体的な状況がありますか？遠慮なくご質問ください。\", \"あなたの頭の中にある状況を教えてください。\"]', '[]', '[{\"original\": \"お願いですが、ラテを一杯ください。\", \"translated\": \"Quisiera un latte, por favor.\"}, {\"original\": \"Wi-Fiは使えますか？\", \"translated\": \"¿Tienen conexión Wi-Fi?\"}, {\"original\": \"メニューを見せていただいてもよろしいですか？\", \"translated\": \"¿Podría ver el menú, por favor?\"}, {\"original\": \"リフィルはできますか？\", \"translated\": \"¿Se permiten recargas?\"}, {\"original\": \"私のコーヒーはもうできましたか？\", \"translated\": \"¿Ya está listo mi café?\"}, {\"original\": \"ここで何分ぐらい座っていられますか？\", \"translated\": \"¿Cuánto tiempo puedo quedarme sentado aquí?\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"¿Podría hacernos una foto?\"}, {\"original\": \"お手洗いはどこですか？\", \"translated\": \"¿Dónde están los baños?\"}, {\"original\": \"お会計をお願いします。ありがとうございます。\", \"translated\": \"La cuenta, por favor. Gracias.\"}, {\"original\": \"とても美味しいです！\", \"translated\": \"¡Sabe realmente delicioso!\"}]', 12, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在餐厅常用的表达吗？\", \"太棒了！以下是与餐厅相关的10个常用表达，并附有西班牙语翻译：\"]', '[\"用餐\", \"点餐\", \"结账\"]', 'zh', '[\"目前，您心里有没有特别的情境？比如点饮料、投诉，或者询问食材成分？欢迎随时提问。\", \"请描述一下您心中想到的具体情境。\"]', '[]', '[{\"original\": \"打扰一下，我们的餐还要等多久？\", \"translated\": \"Disculpe, ¿cuánto tiempo más tendremos que esperar nuestra comida?\"}, {\"original\": \"请给我们安排一张两人桌。\", \"translated\": \"Una mesa para dos, por favor.\"}, {\"original\": \"请问可以给我们看一下菜单吗？\", \"translated\": \"¿Podríamos ver el menú, por favor?\"}, {\"original\": \"您有什么招牌菜可以推荐吗？\", \"translated\": \"¿Tienen algún plato especial que puedan recomendarnos?\"}, {\"original\": \"我想点这个和这个。\", \"translated\": \"Quisiera pedir esto y esto.\"}, {\"original\": \"请给我一杯水，谢谢。\", \"translated\": \"Una copa de agua, por favor. Gracias.\"}, {\"original\": \"请结账。\", \"translated\": \"La cuenta, por favor.\"}, {\"original\": \"我可以用信用卡支付吗？\", \"translated\": \"¿Puedo pagar con tarjeta de crédito?\"}, {\"original\": \"麻烦把这份打包带走，谢谢。\", \"translated\": \"¿Podrían empaquetar esto para llevar, por favor?\"}, {\"original\": \"食物非常美味，谢谢！\", \"translated\": \"¡La comida estuvo deliciosa, gracias!\"}]', 1, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能提供10句在酒店常用的表达吗？\", \"太棒了！以下是与酒店相关的10句常用表达，并附上西班牙语翻译：\"]', '[\"入住\", \"退房\", \"客房服务\"]', 'zh', '[\"目前，您心里是否有特定场景，比如房间位置、其他酒店服务，或是退房？欢迎随时提问。\", \"请描述您脑海中设想的具体场景。\"]', '[]', '[{\"original\": \"你好，我已预订房间，这是我的护照。\", \"translated\": \"Hola, tengo una reserva. Aquí está mi pasaporte.\"}, {\"original\": \"请问还有空房吗？\", \"translated\": \"¿Tienen habitaciones disponibles?\"}, {\"original\": \"打扰一下，酒店有健身房或洗衣房吗？\", \"translated\": \"Disculpe, ¿tiene el hotel gimnasio o lavandería?\"}, {\"original\": \"早餐几点开始？\", \"translated\": \"¿A qué hora empieza el desayuno?\"}, {\"original\": \"请给我一把房卡，谢谢。\", \"translated\": \"¿Podría darme la llave de la habitación, por favor?\"}, {\"original\": \"您能帮我把行李送到房间吗？\", \"translated\": \"¿Podría ayudarme a llevar mi equipaje a la habitación?\"}, {\"original\": \"怎么呼叫客房服务？\", \"translated\": \"¿Cómo llamo al servicio de habitaciones?\"}, {\"original\": \"退房时间是几点？\", \"translated\": \"¿A qué hora es el check-out?\"}, {\"original\": \"能帮我开一张收据／发票吗？\", \"translated\": \"¿Podría emitirme un recibo/factura, por favor?\"}, {\"original\": \"我可以把行李先寄存在这里吗？\", \"translated\": \"¿Puedo dejar mi equipaje aquí temporalmente?\"}]', 2, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在机场常用的短语吗？\", \"太棒了！以下是10个与机场相关的常用短语，并附上西班牙语翻译：\"]', '[\"值机\", \"登机\", \"行李托运\"]', 'zh', '[\"目前，您心里有没有特定场景？比如值机、行李提取，或是租车服务？欢迎随时提问。\", \"请描述一下您心里想到的具体场景。\"]', '[]', '[{\"original\": \"值机柜台在哪里？\", \"translated\": \"¿Dónde está el mostrador de facturación?\"}, {\"original\": \"我想要一个靠窗的座位，谢谢。\", \"translated\": \"Me gustaría un asiento junto a la ventana, por favor.\"}, {\"original\": \"这个航班延误了吗？\", \"translated\": \"¿Está retrasado este vuelo?\"}, {\"original\": \"我需要托运行李。\", \"translated\": \"Necesito facturar esta maleta.\"}, {\"original\": \"登机口在哪里？\", \"translated\": \"¿Dónde está la puerta de embarque?\"}, {\"original\": \"飞机即将起飞。\", \"translated\": \"El avión está a punto de despegar.\"}, {\"original\": \"我需要把笔记本电脑和充电宝拿出来吗？\", \"translated\": \"¿Necesito sacar mi portátil y mi power bank?\"}, {\"original\": \"免税店在哪里？\", \"translated\": \"¿Dónde está la tienda libre de impuestos?\"}, {\"original\": \"我找不到我的行李箱了。\", \"translated\": \"No puedo encontrar mi maleta.\"}, {\"original\": \"你们提供轮椅服务吗？\", \"translated\": \"¿Ofrecen servicio de sillas de ruedas?\"}]', 3, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在公共交通工具上常用的表达吗？\", \"太棒了！以下是与公共交通工具相关的10个常用表达，附西班牙语翻译：\"]', '[\"乘坐公交/地铁\", \"购买车票\", \"换乘\"]', 'zh', '[\"目前，您心里有没有特定场景？比如问公交站、票价或下车等，欢迎随时提问。\", \"请描述您心里想到的具体场景。\"]', '[]', '[{\"original\": \"这趟公交车去终点站吗？\", \"translated\": \"¿Este autobús va a la terminal?\"}, {\"original\": \"下一站是哪里？\", \"translated\": \"¿Cuál es la próxima parada?\"}, {\"original\": \"我在哪里可以买票？\", \"translated\": \"¿Dónde puedo comprar un boleto?\"}, {\"original\": \"请给我一张去XX的车票。\", \"translated\": \"Un boleto para XX, por favor.\"}, {\"original\": \"我需要换乘吗？\", \"translated\": \"¿Tengo que hacer transbordo?\"}, {\"original\": \"下一班地铁还要等多久？\", \"translated\": \"¿Cuánto tiempo falta para el próximo tren del metro?\"}, {\"original\": \"不好意思，请让我过去一下。\", \"translated\": \"Disculpe, permítame pasar, por favor.\"}, {\"original\": \"这个座位有人吗？\", \"translated\": \"¿Está ocupado este asiento?\"}, {\"original\": \"请问，我去XX要在哪儿换乘2号线？\", \"translated\": \"Disculpe, ¿dónde debo hacer transbordo a la línea 2 para llegar a XX?\"}, {\"original\": \"我怎么去XX？\", \"translated\": \"¿Cómo llego a XX?\"}]', 4, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在旅游景点常用的句子吗？\", \"太棒了！以下是与旅游景点相关的10个常用句子，附西班牙语翻译：\"]', '[\"观光游览\", \"拍照\", \"购票\"]', 'zh', '[\"目前，您心里有没有特定的场景？比如询问票价、找停车场或导游服务，欢迎随时提问。\", \"请描述一下您心里想到的具体场景。\"]', '[]', '[{\"original\": \"门票多少钱？\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"有学生票吗？\", \"translated\": \"¿Hay entradas para estudiantes?\"}, {\"original\": \"景点几点开门？\", \"translated\": \"¿A qué hora abre la atracción?\"}, {\"original\": \"这里有什么好玩的？\", \"translated\": \"¿Qué cosas divertidas se pueden hacer aquí?\"}, {\"original\": \"能帮我们拍张照吗？\", \"translated\": \"¿Podría hacernos una foto?\"}, {\"original\": \"观光巴士在哪里？\", \"translated\": \"¿Dónde está el autobús turístico?\"}, {\"original\": \"厕所在哪儿？\", \"translated\": \"¿Dónde están los baños?\"}, {\"original\": \"最佳观景点在哪儿？\", \"translated\": \"¿Dónde está el mejor punto de vista?\"}, {\"original\": \"这里的风景真美。\", \"translated\": \"¡El paisaje aquí es precioso!\"}, {\"original\": \"有提供导览服务吗？\", \"translated\": \"¿Ofrecen visitas guiadas?\"}]', 5, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在乘坐出租车或使用出租车服务时常用的短语吗？\", \"太棒了！以下是与乘坐出租车或使用出租车服务相关的10个常用短语，附带西班牙语翻译：\"]', '[\"打车\", \"告知目的地\", \"支付\"]', 'zh', '[\"目前，您最想做什么呢？比如询问目的地、费用，或者索要发票，欢迎随时提问。\", \"请在脑海中描述一下您当时的情境。\"]', '[]', '[{\"original\": \"我在哪儿能打到出租车？\", \"translated\": \"¿Dónde puedo tomar un taxi?\"}, {\"original\": \"请送我去这个地址。\", \"translated\": \"Por favor, lléveme a esta dirección.\"}, {\"original\": \"大概要多少钱？\", \"translated\": \"¿Cuánto costará aproximadamente?\"}, {\"original\": \"麻烦您打表计费，好吗？\", \"translated\": \"¿Podría usar el taxímetro, por favor?\"}, {\"original\": \"请开快一点，我赶时间。\", \"translated\": \"Por favor, conduzca un poco más rápido, ¡tengo prisa!\"}, {\"original\": \"请在这里停车。\", \"translated\": \"Por favor, párese aquí.\"}, {\"original\": \"你们支持刷卡或手机支付吗？\", \"translated\": \"¿Aceptan tarjetas o pagos móviles?\"}, {\"original\": \"可以给我一张收据吗？\", \"translated\": \"¿Podría darme un recibo, por favor?\"}, {\"original\": \"谢谢，师傅。\", \"translated\": \"Gracias, señor conductor.\"}, {\"original\": \"还有多远？\", \"translated\": \"¿Cuánto falta todavía?\"}]', 6, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在药店常用的句子吗？\", \"太棒了！以下是与药店相关的10个常用句子，附西班牙语翻译：\"]', '[\"买药\", \"咨询\", \"付款\"]', 'zh', '[\"目前，您心里有没有特别想问的情境？比如询问服药说明、医保使用、用药时长等，欢迎随时提问。\", \"请描述一下您心里想到的具体情境。\"]', '[]', '[{\"original\": \"你们有感冒药吗？\", \"translated\": \"¿Tienen medicamento para el resfriado?\"}, {\"original\": \"这个药该怎么吃？\", \"translated\": \"¿Cómo debo tomar este medicamento?\"}, {\"original\": \"有止痛药吗？\", \"translated\": \"¿Tienen analgésicos?\"}, {\"original\": \"药品附带说明书吗？\", \"translated\": \"¿Viene con un folleto de instrucciones?\"}, {\"original\": \"这种药有什么副作用吗？\", \"translated\": \"¿Este medicamento tiene efectos secundarios?\"}, {\"original\": \"可以用医保卡支付吗？\", \"translated\": \"¿Puedo pagar con mi tarjeta de seguro médico?\"}, {\"original\": \"请给我一盒创可贴，谢谢。\", \"translated\": \"¿Podría darme una caja de tiritas, por favor?\"}, {\"original\": \"有退烧药吗？\", \"translated\": \"¿Tienen medicamentos para bajar la fiebre?\"}, {\"original\": \"我擦破了点皮，有消毒药水和创可贴吗？\", \"translated\": \"Me he raspado un poco. ¿Tienen antiséptico y tiritas?\"}, {\"original\": \"你们几点关门？\", \"translated\": \"¿A qué hora cierran?\"}]', 7, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在紧急服务中常用的短语吗？\", \"太棒了！以下是10个与紧急服务相关的常用短语，附带西班牙语翻译：\"]', '[\"报警\", \"急救\", \"求助\"]', 'zh', '[\"目前，您心里有没有具体的紧急情况，比如火灾、受伤需要帮助、紧急呼叫等？欢迎随时提问。\", \"请描述一下您脑海中设想的情况。\"]', '[]', '[{\"original\": \"请帮我叫一辆救护车。\", \"translated\": \"Por favor, ayúdeme a llamar una ambulancia.\"}, {\"original\": \"医院在哪儿？\", \"translated\": \"¿Dónde está el hospital?\"}, {\"original\": \"有人受伤了。\", \"translated\": \"Alguien resultó herido.\"}, {\"original\": \"请帮帮我。\", \"translated\": \"Por favor, ayúdeme.\"}, {\"original\": \"警察局在哪儿？\", \"translated\": \"¿Dónde está la comisaría de policía?\"}, {\"original\": \"我的物品丢了。\", \"translated\": \"He perdido mis pertenencias.\"}, {\"original\": \"消防部门的电话号码是多少？\", \"translated\": \"¿Cuál es el número de teléfono del cuerpo de bomberos?\"}, {\"original\": \"我丢了护照。您知道最近的警察局在哪儿吗？\", \"translated\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría de policía más cercana?\"}, {\"original\": \"这里有紧急出口吗？\", \"translated\": \"¿Hay una salida de emergencia?\"}, {\"original\": \"有人晕倒了。\", \"translated\": \"Alguien se ha desmayado.\"}]', 8, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在沙滩或池畔常用的表达吗？\", \"太棒了！以下是10个与沙滩或池畔相关的常用表达，并附有西班牙语翻译：\"]', '[\"游泳\", \"日光浴\", \"沙滩运动\"]', 'zh', '[\"目前，请您告诉我您要参加的当地活动或节日的具体背景，比如文化节、美食节还是音乐节。请提供相关背景信息。\", \"请您说明您将参与的活动项目。\"]', '[\"您心里是否有特定的场景？欢迎随时提问。\", \"请描述一下您脑海中设想的场景。\"]', '[{\"original\": \"快看！那边的海浪真大啊。\", \"translated\": \"¡Mira! ¡Las olas allí son realmente grandes!\"}, {\"original\": \"记得涂防晒霜，这里的紫外线很强。\", \"translated\": \"Recuerda aplicar protector solar, ya que los rayos UV aquí son muy intensos.\"}, {\"original\": \"这片海滩的沙子非常细腻，踩上去就像踏在棉花上一样。\", \"translated\": \"La arena de esta playa es tan fina que al pisarla parece caminar sobre algodón.\"}, {\"original\": \"在海滩上打排球怎么样？\", \"translated\": \"¿Qué tal jugar voleibol en la playa?\"}, {\"original\": \"远处的帆船看起来真美。\", \"translated\": \"Los veleros a lo lejos se ven preciosos.\"}, {\"original\": \"这里的海水真清澈，连鱼都能看得见。\", \"translated\": \"El agua aquí es tan transparente que ¡incluso puedes ver los peces!\"}, {\"original\": \"咱们去找些贝壳吧。\", \"translated\": \"Vamos a buscar conchas marinas.\"}, {\"original\": \"日落时分在海滩散步一定很浪漫。\", \"translated\": \"Pasear por la playa al atardecer debe ser muy romántico.\"}, {\"original\": \"听说这里的海鲜特别新鲜，咱们去尝尝吧。\", \"translated\": \"He oído decir que los mariscos aquí son muy frescos; ¡vamos a probarlos!\"}, {\"original\": \"涨潮了，咱们往岸边走吧。\", \"translated\": \"La marea está subiendo; vamos hacia la orilla.\"}]', 9, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在本地活动和节日中常用的短语吗？\", \"太棒了！以下是与本地活动和节日相关的10个常用短语，并附上西班牙语翻译：\"]', '[\"参加活动\", \"庆祝节日\", \"了解文化\"]', 'zh', '[\"目前，您能告诉我您要参加的本地活动或节日的具体背景吗？比如万圣节、音乐会、朋友聚会，或者其他场合？请提供相关背景。\", \"请描述一下您脑海中设想的活动内容。\"]', '[\"您心里有没有特定的场景？欢迎随时提问。\", \"请描述一下您脑海中的具体情境。\"]', '[{\"original\": \"今天有什么活动吗？\", \"translated\": \"¿Hay algún evento hoy?\"}, {\"original\": \"这个节日有什么特别之处吗？\", \"translated\": \"¿Hay algo especial en este festival?\"}, {\"original\": \"庆祝活动在哪里举行？\", \"translated\": \"¿Dónde se celebra la festividad?\"}, {\"original\": \"我该怎么买票？\", \"translated\": \"¿Cómo puedo comprar las entradas?\"}, {\"original\": \"演出什么时候开始？\", \"translated\": \"¿A qué hora empieza la actuación?\"}, {\"original\": \"有哪些传统食物？\", \"translated\": \"¿Qué comidas tradicionales hay?\"}, {\"original\": \"这里真热闹！\", \"translated\": \"¡Aquí hay mucha animación!\"}, {\"original\": \"有民间活动吗？\", \"translated\": \"¿Hay actividades folclóricas?\"}, {\"original\": \"节日快乐！\", \"translated\": \"¡Felices fiestas!\"}, {\"original\": \"活动什么时候结束？\", \"translated\": \"¿A qué hora termina el evento?\"}]', 10, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"能否给我提供10句在博物馆或美术馆中常用的表达？\", \"太棒了！以下是与博物馆或美术馆相关的10个常用表达，附西班牙语翻译：\"]', '[\"参观\", \"导览服务\", \"购票\"]', 'zh', '[\"目前，您心里是否有特定场景？比如索要导览手册、问路相关表达、对展品发表评论的相关表达——欢迎随时提问。\", \"请描述一下您脑海中设想的具体场景。\"]', '[]', '[{\"original\": \"门票多少钱？\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"你们提供语音导览吗？\", \"translated\": \"¿Ofrecen audioguías?\"}, {\"original\": \"这件艺术品是谁创作的？\", \"translated\": \"¿Quién creó esta obra de arte?\"}, {\"original\": \"博物馆最珍贵的藏品在哪儿？\", \"translated\": \"¿Dónde está la pieza más valiosa del museo?\"}, {\"original\": \"允许拍照吗？\", \"translated\": \"¿Se permite tomar fotos?\"}, {\"original\": \"这里有没有特别展览？\", \"translated\": \"¿Hay alguna exposición especial aquí?\"}, {\"original\": \"参观大概需要多长时间？\", \"translated\": \"¿Cuánto tiempo dura la visita aproximadamente?\"}, {\"original\": \"能给我们做个简单介绍吗？\", \"translated\": \"¿Podrían hacernos una breve introducción?\"}, {\"original\": \"这些作品真是精美绝伦。\", \"translated\": \"Estas obras son verdaderamente exquisitas.\"}, {\"original\": \"纪念品商店在哪儿？\", \"translated\": \"¿Dónde está la tienda de souvenirs?\"}]', 11, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能给我提供10个在咖啡馆里常用的句子吗？\", \"太棒了！以下是10个与咖啡馆相关的常用句子，并附上西班牙语翻译：\"]', '[\"点咖啡\", \"休息\", \"社交\"]', 'zh', '[\"目前，您心里有没有特定的场景？比如要点菜单、要冰饮或热饮、或其他商品，欢迎随时提问。\", \"请描述一下您脑海中想到的具体场景。\"]', '[]', '[{\"original\": \"我要一杯拿铁，谢谢。\", \"translated\": \"Tomaré un latte, por favor.\"}, {\"original\": \"你们有Wi-Fi吗？\", \"translated\": \"¿Tienen conexión Wi-Fi?\"}, {\"original\": \"请问可以给我看看菜单吗？\", \"translated\": \"¿Podría ver el menú, por favor?\"}, {\"original\": \"可以免费续杯吗？\", \"translated\": \"¿Se permiten recargas?\"}, {\"original\": \"我的咖啡好了吗？\", \"translated\": \"¿Ya está listo mi café?\"}, {\"original\": \"我能在这里坐多久？\", \"translated\": \"¿Cuánto tiempo puedo quedarme aquí sentado?\"}, {\"original\": \"能帮我们拍张照吗？\", \"translated\": \"¿Podrían hacernos una foto?\"}, {\"original\": \"洗手间在哪儿？\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"请结账，谢谢。\", \"translated\": \"La cuenta, por favor. Gracias.\"}, {\"original\": \"味道真的很棒！\", \"translated\": \"¡Sabe realmente delicioso!\"}]', 12, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a restaurant?\", \"Fantastic! Here are 10 common phrases related to restaurants, along with Spanish translations:\"]', '[\"Dining\", \"Ordering\", \"Checkout\"]', 'en', '[\"For now, do you have a specific situation in mind, like ordering drinks, making a complaint, or asking about ingredients? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Excuse me, how much longer will our food be?\", \"translated\": \"Disculpe, ¿cuánto tiempo más tardará nuestra comida?\"}, {\"original\": \"A table for two, please.\", \"translated\": \"Una mesa para dos, por favor.\"}, {\"original\": \"Could we see the menu, please?\", \"translated\": \"¿Podríamos ver el menú, por favor?\"}, {\"original\": \"Do you have any signature dishes to recommend?\", \"translated\": \"¿Tienen algún plato especial que nos puedan recomendar?\"}, {\"original\": \"I\'d like to order this, and this.\", \"translated\": \"Quisiera pedir esto y esto otro.\"}, {\"original\": \"A glass of water, please. Thanks.\", \"translated\": \"Un vaso de agua, por favor. Gracias.\"}, {\"original\": \"The bill, please.\", \"translated\": \"La cuenta, por favor.\"}, {\"original\": \"Can I pay by credit card?\", \"translated\": \"¿Puedo pagar con tarjeta de crédito?\"}, {\"original\": \"Could you pack this to go, please?\", \"translated\": \"¿Podrían empaquetar esto para llevar, por favor?\"}, {\"original\": \"The food was delicious, thank you.\", \"translated\": \"La comida estuvo deliciosa, gracias.\"}]', 1, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a hotel?\", \"Fantastic! Here are 10 common phrases related to hotels, along with Spanish translations:\"]', '[\"Check-in\", \"Check-out\", \"Room Service\"]', 'en', '[\"For now, do you have a specific situation in mind, like room location, any other hotel service, or check-out? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Hello, I have a reservation, Here is my passport.\", \"translated\": \"Hola, tengo una reserva. Aquí tiene mi pasaporte.\"}, {\"original\": \"Do you have any vacancies?\", \"translated\": \"¿Tienen habitaciones disponibles?\"}, {\"original\": \"Excuse me, does the hotel have a gym or a laundry room?\", \"translated\": \"Disculpe, ¿tiene el hotel gimnasio o servicio de lavandería?\"}, {\"original\": \"What time does breakfast start?\", \"translated\": \"¿A qué hora comienza el desayuno?\"}, {\"original\": \"Could I have a room key, please?\", \"translated\": \"¿Podría darme la llave de la habitación, por favor?\"}, {\"original\": \"Could you help me take my luggage to the room?\", \"translated\": \"¿Podría ayudarme a llevar mi equipaje a la habitación?\"}, {\"original\": \"How do I call room service?\", \"translated\": \"¿Cómo llamo al servicio de habitaciones?\"}, {\"original\": \"What time is check-out?\", \"translated\": \"¿A qué hora es la salida?\"}, {\"original\": \"Could you write me a receipt/invoice?\", \"translated\": \"¿Podría darme un recibo/factura?\"}, {\"original\": \"Can I leave my luggage here?\", \"translated\": \"¿Puedo dejar mi equipaje aquí?\"}]', 2, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in the airport?\", \"Fantastic! Here are 10 common phrases related to the airport, along with Spanish translations:\"]', '[\"Check-in\", \"Boarding\", \"Baggage Check\"]', 'en', '[\"For now, do you have a specific situation in mind, like check-in, baggage claim, or car rental service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Where is the check-in counter?\", \"translated\": \"¿Dónde está el mostrador de facturación?\"}, {\"original\": \"I\'d like a window seat, please.\", \"translated\": \"Me gustaría un asiento junto a la ventana, por favor.\"}, {\"original\": \"Is this flight delayed?\", \"translated\": \"¿Este vuelo tiene retraso?\"}, {\"original\": \"I need to check this baggage.\", \"translated\": \"Necesito facturar este equipaje.\"}, {\"original\": \"Where is the boarding gate?\", \"translated\": \"¿Dónde está la puerta de embarque?\"}, {\"original\": \"The plane is about to take off.\", \"translated\": \"El avión está a punto de despegar.\"}, {\"original\": \"Do I need to take out my laptop and power bank?\", \"translated\": \"¿Necesito sacar mi portátil y mi batería externa?\"}, {\"original\": \"Where is the duty-free shop?\", \"translated\": \"¿Dónde está la tienda libre de impuestos?\"}, {\"original\": \"I can\'t find my suitcase.\", \"translated\": \"No encuentro mi maleta.\"}, {\"original\": \"Do you have a wheelchair service?\", \"translated\": \"¿Ofrecen servicio de sillas de ruedas?\"}]', 3, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in public transportation?\", \"Fantastic! Here are 10 common phrases related to public transportation, along with Spanish translations:\"]', '[\"Taking Bus/Subway\", \"Buying Tickets\", \"Transferring\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for a bus stop, ticket price, or getting off? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Does this bus go to the terminal?\", \"translated\": \"¿Este autobús va a la terminal?\"}, {\"original\": \"What is the next stop?\", \"translated\": \"¿Cuál es la próxima parada?\"}, {\"original\": \"Where can I buy a ticket?\", \"translated\": \"¿Dónde puedo comprar un boleto?\"}, {\"original\": \"One ticket to XX, please.\", \"translated\": \"Un boleto a XX, por favor.\"}, {\"original\": \"Do I need to transfer?\", \"translated\": \"¿Tengo que hacer transbordo?\"}, {\"original\": \"How long until the next subway train?\", \"translated\": \"¿Cuánto tiempo falta para el próximo tren del metro?\"}, {\"original\": \"Excuse me, please let me pass.\", \"translated\": \"Con permiso, ¿me deja pasar?\"}, {\"original\": \"Is this seat taken?\", \"translated\": \"¿Esta silla está ocupada?\"}, {\"original\": \"Excuse me, where can I transfer to Line 2 to get to XX?\", \"translated\": \"Disculpe, ¿dónde puedo hacer transbordo a la Línea 2 para llegar a XX?\"}, {\"original\": \"How do I get to XX?\", \"translated\": \"¿Cómo llego a XX?\"}]', 4, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in tourist attractions?\", \"Fantastic! Here are 10 common phrases related to tourist attractions, along with Spanish translations:\"]', '[\"Sightseeing\", \"Taking Photos\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking about ticket prices, finding a parking lot, or tour guide service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"How much is the entrance fee?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"Are there student tickets available?\", \"translated\": \"¿Hay entradas para estudiantes disponibles?\"}, {\"original\": \"What time does the attraction open?\", \"translated\": \"¿A qué hora abre la atracción?\"}, {\"original\": \"What are the fun things to do here?\", \"translated\": \"¿Qué cosas divertidas se pueden hacer aquí?\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"¿Nos podría tomar una foto?\"}, {\"original\": \"Where is the sightseeing bus?\", \"translated\": \"¿Dónde está el autobús turístico?\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"Where is the best viewing spot?\", \"translated\": \"¿Cuál es el mejor lugar para tomar fotos o disfrutar de la vista?\"}, {\"original\": \"The scenery here is beautiful.\", \"translated\": \"El paisaje aquí es precioso.\"}, {\"original\": \"Is there a guided tour available?\", \"translated\": \"¿Hay visitas guiadas disponibles?\"}]', 5, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in taxi or cab services?\", \"Fantastic! Here are 10 common phrases related to taxi or cab services, along with Spanish translations:\"]', '[\"Taking Taxi\", \"Telling Destination\", \"Payment\"]', 'en', '[\"For now, what do you most want to do now — like asking for the destination, the fare, or requesting a receipt? Feel free to ask!\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Where can I get a taxi?\", \"translated\": \"¿Dónde puedo tomar un taxi?\"}, {\"original\": \"Please take me to this address.\", \"translated\": \"Por favor, lléveme a esta dirección.\"}, {\"original\": \"Roughly how much will it be?\", \"translated\": \"¿Cuánto costará aproximadamente?\"}, {\"original\": \"Could you use the meter, please?\", \"translated\": \"¿Podría usar el taxímetro, por favor?\"}, {\"original\": \"Please drive a bit faster, I\'m in a hurry.\", \"translated\": \"Por favor, conduzca un poco más rápido, tengo prisa.\"}, {\"original\": \"Please stop here.\", \"translated\": \"Por favor, pare aquí.\"}, {\"original\": \"Do you accept cards or mobile payments?\", \"translated\": \"¿Acepta tarjetas o pagos móviles?\"}, {\"original\": \"Could I have a receipt, please?\", \"translated\": \"¿Podría darme un recibo, por favor?\"}, {\"original\": \"Thank you, driver.\", \"translated\": \"Gracias, conductor.\"}, {\"original\": \"How much further is it?\", \"translated\": \"¿Cuánto falta todavía?\"}]', 6, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a pharmacy?\", \"Fantastic! Here are 10 common phrases related to pharmacies, along with Spanish translations:\"]', '[\"Buying Medicine\", \"Consultation\", \"Payment\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for instructions on taking medicine, phrases related to using insurance, or duration of medication? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Do you have cold medicine?\", \"translated\": \"¿Tienen medicamento para el resfriado?\"}, {\"original\": \"How should I take this medicine?\", \"translated\": \"¿Cómo debo tomar este medicamento?\"}, {\"original\": \"Do you have any painkillers?\", \"translated\": \"¿Tienen algún analgésico?\"}, {\"original\": \"Is there an instruction leaflet?\", \"translated\": \"¿Viene con un folleto de instrucciones?\"}, {\"original\": \"Does this medicine have any side effects?\", \"translated\": \"¿Este medicamento tiene efectos secundarios?\"}, {\"original\": \"Can I use my medical insurance card?\", \"translated\": \"¿Puedo usar mi tarjeta de seguro médico?\"}, {\"original\": \"Could I have a box of Band-Aids, please?\", \"translated\": \"¿Podría darme una caja de vendas adhesivas, por favor?\"}, {\"original\": \"Do you have any fever reducers?\", \"translated\": \"¿Tienen algo para bajar la fiebre?\"}, {\"original\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\", \"translated\": \"Me he raspado un poco. ¿Tienen antiséptico y vendas adhesivas?\"}, {\"original\": \"What time do you close?\", \"translated\": \"¿A qué hora cierran?\"}]', 7, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in emergency services?\", \"Fantastic! Here are 10 common phrases related to emergency services, along with Spanish translations:\"]', '[\"Calling Police\", \"First Aid\", \"Calling for Help\"]', 'en', '[\"For now, do you have a specific emergency situation in your mind, like fire, injured and need help, emergency call — feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"Please help me call an ambulance.\", \"translated\": \"Por favor, ayúdeme a llamar a una ambulancia.\"}, {\"original\": \"Where is the hospital?\", \"translated\": \"¿Dónde está el hospital?\"}, {\"original\": \"Someone is injured.\", \"translated\": \"Alguien está herido.\"}, {\"original\": \"Please help me.\", \"translated\": \"Por favor, ayúdeme.\"}, {\"original\": \"Where is the police station?\", \"translated\": \"¿Dónde está la comisaría?\"}, {\"original\": \"I\'ve lost my belongings.\", \"translated\": \"He perdido mis pertenencias.\"}, {\"original\": \"What is the number for the fire department?\", \"translated\": \"¿Cuál es el número de los bomberos?\"}, {\"original\": \"I\'ve lost my passport. Do you know where the nearest police station is?\", \"translated\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría más cercana?\"}, {\"original\": \"Is there an emergency exit?\", \"translated\": \"¿Hay una salida de emergencia?\"}, {\"original\": \"Someone has fainted.\", \"translated\": \"Alguien ha desmayado.\"}]', 8, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use at the beach or pool?\", \"Fantastic! Here are 10 common phrases related to the beach or pool, along with Spanish translations:\"]', '[\"Swimming\", \"Sunbathing\", \"Beach Sports\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you’re attending—such as a cultural festival, food festival, or music festival? Please provide the context.\", \"Please provide the activities that you’ll be attending.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation you have in mind.\"]', '[{\"original\": \"Look! The waves over there are really big.\", \"translated\": \"¡Mira! ¡Las olas allá son realmente grandes!\"}, {\"original\": \"Remember to apply sunscreen, the UV rays here are very strong.\", \"translated\": \"Recuerda aplicarte protector solar; aquí los rayos UV son muy intensos.\"}, {\"original\": \"The sand on this beach is so fine, it feels like stepping on cotton.\", \"translated\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\"}, {\"original\": \"How about playing volleyball on the beach?\", \"translated\": \"¿Qué tal jugar voleibol en la playa?\"}, {\"original\": \"The sailboats in the distance look beautiful.\", \"translated\": \"Los veleros a lo lejos se ven hermosos.\"}, {\"original\": \"The water here is so clear, you can even see the fish.\", \"translated\": \"El agua aquí es tan transparente que hasta puedes ver los peces.\"}, {\"original\": \"Let\'s go find some seashells.\", \"translated\": \"Vamos a buscar algunas conchas marinas.\"}, {\"original\": \"Taking a walk on the beach at sunset must be very romantic.\", \"translated\": \"Pasear por la playa al atardecer debe de ser muy romántico.\"}, {\"original\": \"I heard the seafood here is very fresh, let\'s go try some.\", \"translated\": \"Escuché que los mariscos aquí son muy frescos; vamos a probar algunos.\"}, {\"original\": \"The tide is coming in, let\'s head towards the shore.\", \"translated\": \"La marea está subiendo; volvamos hacia la orilla.\"}]', 9, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in local events and festivals?\", \"Fantastic! Here are 10 common phrases related to local events and festivals, along with Spanish translations:\"]', '[\"Attending Events\", \"Celebrating Festivals\", \"Learning Culture\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you’re attending, like Halloween, a concert, a friend’s party, or something else? Please provide the context.\", \"Please describe the activities in your mind.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[{\"original\": \"Are there any events today?\", \"translated\": \"¿Hay algún evento hoy?\"}, {\"original\": \"Is there anything special about this festival?\", \"translated\": \"¿Hay algo especial en este festival?\"}, {\"original\": \"Where is the celebration being held?\", \"translated\": \"¿Dónde se celebra la fiesta?\"}, {\"original\": \"How can I buy tickets?\", \"translated\": \"¿Cómo puedo comprar entradas?\"}, {\"original\": \"What time does the performance start?\", \"translated\": \"¿A qué hora empieza la función?\"}, {\"original\": \"What traditional food is there?\", \"translated\": \"¿Qué comida tradicional hay?\"}, {\"original\": \"It\'s really lively here.\", \"translated\": \"Aquí hay mucha animación.\"}, {\"original\": \"Are there any folk activities?\", \"translated\": \"¿Hay alguna actividad folclórica?\"}, {\"original\": \"Happy holidays!\", \"translated\": \"¡Felices fiestas!\"}, {\"original\": \"What time does the event end?\", \"translated\": \"¿A qué hora termina el evento?\"}]', 10, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a museum or art gallery?\", \"Fantastic! Here are 10 common phrases related to a museum or art gallery, along with Spanish translations:\"]', '[\"Visiting\", \"Guided Tour\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for an introduction manual, phrases related to a roadmap, or phrases related to commenting on an exhibit? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"How much is the admission fee?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"Do you have audio guides?\", \"translated\": \"¿Tienen audioguías?\"}, {\"original\": \"Who created this artwork?\", \"translated\": \"¿Quién creó esta obra de arte?\"}, {\"original\": \"Where is the museum\'s most prized piece?\", \"translated\": \"¿Dónde está la pieza más valiosa del museo?\"}, {\"original\": \"Is photography allowed?\", \"translated\": \"¿Está permitida la fotografía?\"}, {\"original\": \"Are there any special exhibitions here?\", \"translated\": \"¿Hay alguna exposición especial aquí?\"}, {\"original\": \"How long does the visit take?\", \"translated\": \"¿Cuánto tiempo dura la visita?\"}, {\"original\": \"Could you give us an introduction?\", \"translated\": \"¿Podrían darnos una introducción?\"}, {\"original\": \"These works are truly exquisite.\", \"translated\": \"Estas obras son verdaderamente exquisitas.\"}, {\"original\": \"Where is the souvenir shop?\", \"translated\": \"¿Dónde está la tienda de souvenirs?\"}]', 11, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a café?\", \"Fantastic! Here are 10 common phrases related to cafés, along with Spanish translations:\"]', '[\"Ordering Coffee\", \"Resting\", \"Socializing\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for a menu, ice or hot drinks, other products? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[]', '[{\"original\": \"I\'ll have a latte, please.\", \"translated\": \"Pediré un latte, por favor.\"}, {\"original\": \"Do you have Wi-Fi?\", \"translated\": \"¿Tienen Wi-Fi?\"}, {\"original\": \"Could I see the menu, please?\", \"translated\": \"¿Podría ver el menú, por favor?\"}, {\"original\": \"Are refills allowed?\", \"translated\": \"¿Se permiten recargas?\"}, {\"original\": \"Is my coffee ready?\", \"translated\": \"¿Ya está listo mi café?\"}, {\"original\": \"How long can I sit here?\", \"translated\": \"¿Cuánto tiempo puedo quedarme sentado/a aquí?\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"¿Nos podría tomar una foto?\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"Check, please. Thank you.\", \"translated\": \"La cuenta, por favor. Gracias.\"}, {\"original\": \"It tastes really good.\", \"translated\": \"Sabe realmente delicioso.\"}]', 12, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في المطعم؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بالمطاعم، مع ترجمتها إلى الإسبانية:\"]', '[\"تجربة تناول الطعام\", \"الطلب\", \"إنهاء العملية والدفع\"]', 'ar', '[\"حاليًّا، هل لديك موقف معين في ذهنك؟ مثل طلب المشروبات، أو تقديم شكوى، أو الاستفسار عن المكونات — لا تتردد في السؤال.\", \"من فضلك صف الموقف الذي يخطر لك في بالك.\"]', '[]', '[{\"original\": \"عذرًا، كم من الوقت سيستغرق وصول طعامنا؟\", \"translated\": \"Perdone, ¿cuánto tiempo más tardará nuestra comida?\"}, {\"original\": \"طاولة لشخصين، من فضلكم.\", \"translated\": \"Una mesa para dos, por favor.\"}, {\"original\": \"هل يمكننا رؤية القائمة، من فضلكم؟\", \"translated\": \"¿Podríamos ver el menú, por favor?\"}, {\"original\": \"هل لديكم أطباق مميزة توصون بها؟\", \"translated\": \"¿Tienen algún plato especial que puedan recomendarnos?\"}, {\"original\": \"أود طلب هذا وهذا.\", \"translated\": \"Quisiera pedir esto y esto.\"}, {\"original\": \"كوب من الماء، من فضلكم. شكرًا لكم.\", \"translated\": \"Un vaso de agua, por favor. Gracias.\"}, {\"original\": \"الفاتورة، من فضلكم.\", \"translated\": \"La cuenta, por favor.\"}, {\"original\": \"هل يمكنني الدفع بالبطاقة الائتمانية؟\", \"translated\": \"¿Puedo pagar con tarjeta de crédito?\"}, {\"original\": \"هل يمكنكم تغليف هذا للاصطحاب معنا، من فضلكم؟\", \"translated\": \"¿Podrían empaquetar esto para llevar, por favor?\"}, {\"original\": \"كان الطعام لذيذًا، شكرًا لكم.\", \"translated\": \"La comida estuvo deliciosa, ¡gracias!\"}]', 1, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في الفندق؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بالفندق، مع ترجمتها إلى الإسبانية:\"]', '[\"تسجيل الدخول\", \"تسجيل المغادرة\", \"خدمة الغرف\"]', 'ar', '[\"حتى الآن، هل لديك موقف معين في ذهنك؟ مثل موقع الغرفة، أو أي خدمة أخرى في الفندق، أو وقت المغادرة؟ لا تتردد في طرح الأسئلة.\", \"من فضلك صف لي الموقف الذي تخيله في ذهنك.\"]', '[]', '[{\"original\": \"مرحبًا، لدي حجزٌ هنا جواز سفري.\", \"translated\": \"Hola, tengo una reserva. Aquí está mi pasaporte.\"}, {\"original\": \"هل لديكم غرف شاغرة؟\", \"translated\": \"¿Tienen habitaciones disponibles?\"}, {\"original\": \"معذرةً، هل يوجد في الفندق صالة ألعاب رياضية أو غرفة لغسل الملابس؟\", \"translated\": \"Disculpe, ¿tiene el hotel gimnasio o servicio de lavandería?\"}, {\"original\": \"متى يبدأ الإفطار؟\", \"translated\": \"¿A qué hora comienza el desayuno?\"}, {\"original\": \"هل يمكنني الحصول على مفتاح الغرفة من فضلكم؟\", \"translated\": \"¿Podría darme la llave de la habitación, por favor?\"}, {\"original\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\", \"translated\": \"¿Podrían ayudarme a llevar mi equipaje a la habitación?\"}, {\"original\": \"كيف أطلب خدمة الغرف؟\", \"translated\": \"¿Cómo puedo llamar al servicio de habitaciones?\"}, {\"original\": \"متى يكون وقت المغادرة؟\", \"translated\": \"¿A qué hora es el check-out?\"}, {\"original\": \"هل يمكنكم إعطائي إيصالًا/فاتورة؟\", \"translated\": \"¿Podrían darme un recibo/factura?\"}, {\"original\": \"هل يمكنني ترك أمتعتي هنا مؤقتًا؟\", \"translated\": \"¿Puedo dejar mi equipaje aquí temporalmente?\"}]', 2, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في المطار؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بالمطار، مع ترجمتها إلى الإسبانية:\"]', '[\"التسجيل\", \"الصعود للطائرة\", \"فحص الأمتعة\"]', 'ar', '[\"لحد الآن، هل لديك موقف معين في بالك، مثل التسجيل أو استلام الأمتعة أو خدمة تأجير السيارات؟ لا تتردد في طرح سؤال.\", \"من فضلك صف لي الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"أين كاونتر التسجيل؟\", \"translated\": \"¿Dónde está el mostrador de facturación?\"}, {\"original\": \"أود مقعدًا بجانب النافذة، من فضلك.\", \"translated\": \"Me gustaría un asiento junto a la ventana, por favor.\"}, {\"original\": \"هل هذا الرحلة متأخرة؟\", \"translated\": \"¿Está retrasado este vuelo?\"}, {\"original\": \"أحتاج إلى تسجيل هذه الأمتعة.\", \"translated\": \"Necesito facturar este equipaje.\"}, {\"original\": \"أين بوابة الصعود للطائرة؟\", \"translated\": \"¿Dónde está la puerta de embarque?\"}, {\"original\": \"الطائرة على وشك الإقلاع.\", \"translated\": \"El avión está a punto de despegar.\"}, {\"original\": \"هل عليّ إخراج جهازي اللوحي والبنك المحمول للطاقة؟\", \"translated\": \"¿Debo sacar mi computadora portátil y mi banco de energía?\"}, {\"original\": \"أين محلات الجمرك الحر؟\", \"translated\": \"¿Dónde está la tienda libre de impuestos?\"}, {\"original\": \"لا أستطيع العثور على حقيبتي.\", \"translated\": \"No puedo encontrar mi maleta.\"}, {\"original\": \"هل تقدمون خدمة الكرسي المتحرك؟\", \"translated\": \"¿Ofrecen servicio de silla de ruedas?\"}]', 3, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في وسائل النقل العامة؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بوسائل النقل العامة، مع ترجمتها إلى الإسبانية:\"]', '[\"ركوب الحافلة أو المترو\", \"شراء التذاكر\", \"التنقل بين وسائل النقل (التحويل)\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف معين في ذهنك، مثل الاستفسار عن موقف الحافلة أو سعر التذكرة أو النزول؟ لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي يدور في ذهنك.\"]', '[]', '[{\"original\": \"هل هذه الحافلة تذهب إلى المحطة؟\", \"translated\": \"¿Este autobús va a la terminal?\"}, {\"original\": \"ما هي المحطة التالية؟\", \"translated\": \"¿Cuál es la próxima parada?\"}, {\"original\": \"أين يمكنني شراء تذكرة؟\", \"translated\": \"¿Dónde puedo comprar un billete?\"}, {\"original\": \"تذكرة واحدة إلى XX، من فضلك.\", \"translated\": \"Un billete para XX, por favor.\"}, {\"original\": \"هل يجب أن أغير وسيلة النقل؟\", \"translated\": \"¿Tengo que hacer transbordo?\"}, {\"original\": \"كم تبقى حتى قدوم قطار المترو القادم؟\", \"translated\": \"¿Cuánto falta para el próximo tren del metro?\"}, {\"original\": \"المعذرة، من فضلك اسمح لي بالمرور.\", \"translated\": \"Disculpe, permítame pasar, por favor.\"}, {\"original\": \"هل هذا المقعد مشغول؟\", \"translated\": \"¿Está ocupado este asiento?\"}, {\"original\": \"المعذرة، أين يمكنني الانتقال إلى الخط ٢ للوصول إلى XX؟\", \"translated\": \"Disculpe, ¿dónde puedo hacer transbordo a la Línea 2 para llegar a XX?\"}, {\"original\": \"كيف أصل إلى XX؟\", \"translated\": \"¿Cómo llego a XX?\"}]', 4, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في أماكن الجذب السياحي؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بأماكن الجذب السياحي، مع ترجمتها إلى الإسبانية:\"]', '[\"القيام بجولة سياحية\", \"التقاط الصور\", \"شراء التذاكر\"]', 'ar', '[\"للحظة، هل لديك موقف محدد في ذهنك، مثل الاستفسار عن سعر التذكرة، أو العثور على موقف للسيارات، أو طلب خدمة دليل سياحي؟ لا تتردد في طرح سؤالك.\", \"يرجى وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"كم تكلفة رسوم الدخول؟\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"هل تتوفر تذاكر للطلاب؟\", \"translated\": \"¿Hay entradas para estudiantes?\"}, {\"original\": \"في أي وقت يفتح المعلم السياحي؟\", \"translated\": \"¿A qué hora abre la atracción?\"}, {\"original\": \"ما الأنشطة الممتعة التي يمكن القيام بها هنا؟\", \"translated\": \"¿Qué cosas divertidas se pueden hacer aquí?\"}, {\"original\": \"هل يمكنك أن تلتقط لنا صورة؟\", \"translated\": \"¿Podrías hacernos una foto?\"}, {\"original\": \"أين حافلة الجولات السياحية؟\", \"translated\": \"¿Dónde está el autobús turístico?\"}, {\"original\": \"أين دورات المياه؟\", \"translated\": \"¿Dónde están los baños?\"}, {\"original\": \"ما أفضل مكان لمشاهدة المنظر؟\", \"translated\": \"¿Cuál es el mejor punto de vista?\"}, {\"original\": \"المنظر هنا جميل جدًا.\", \"translated\": \"El paisaje aquí es precioso.\"}, {\"original\": \"هل توجد جولة إرشادية متاحة؟\", \"translated\": \"¿Hay visitas guiadas disponibles?\"}]', 5, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكن أن تزودني بـ ١٠ عبارات شائعة يمكنني استخدامها في خدمات التاكسي أو سيارات الأجرة؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بخدمات التاكسي أو سيارات الأجرة، مع ترجمتها إلى الإسبانية:\"]', '[\"أخذ تاكسي\", \"إبلاغ الوجهة\", \"الدفع\"]', 'ar', '[\"في الوقت الحالي، ما الذي تود فعله أكثر الآن؟ مثل الاستفسار عن الوجهة، أو السعر، أو طلب إشعار دفع — لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي تتصوره في ذهنك.\"]', '[]', '[{\"original\": \"أين يمكنني أخذ تاكسي؟\", \"translated\": \"¿Dónde puedo conseguir un taxi?\"}, {\"original\": \"من فضلك خذني إلى هذا العنوان.\", \"translated\": \"Por favor, lléveme a esta dirección.\"}, {\"original\": \"كم يكون السعر تقريبًا؟\", \"translated\": \"¿Cuánto costará aproximadamente?\"}, {\"original\": \"هل يمكنك تشغيل العداد من فضلك؟\", \"translated\": \"¿Podría usar el taxímetro, por favor?\"}, {\"original\": \"من فضلك ا-driving أسرع قليلًا، فأنا مستعجل.\", \"translated\": \"Por favor, conduzca un poco más rápido, estoy con prisa.\"}, {\"original\": \"من فضلك توقف هنا.\", \"translated\": \"Por favor, pare aquí.\"}, {\"original\": \"هل تقبل الدفع بالبطاقات أو المدفوعات عبر الهاتف المحمول؟\", \"translated\": \"¿Acepta tarjetas o pagos móviles?\"}, {\"original\": \"هل يمكنني الحصول على إشعار دفع من فضلك؟\", \"translated\": \"¿Podría darme un recibo, por favor?\"}, {\"original\": \"شكرًا لك يا سائق.\", \"translated\": \"Gracias, conductor.\"}, {\"original\": \"كم تبقى بعد من المسافة؟\", \"translated\": \"¿Cuánto falta aún?\"}]', 6, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في الصيدلية؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بالصيدلية، مع ترجمتها إلى الإسبانية:\"]', '[\"شراء أدوية\", \"استشارة طبية\", \"دفع مقابل الخدمة\"]', 'ar', '[\"للوقت الحالي، هل لديك موقف معيّن في ذهنك؟ مثل الاستفسار عن طريقة تناول الدواء، أو العبارات المرتبطة باستخدام التأمين الصحي، أو مدة العلاج. لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي يخطر في بالك.\"]', '[]', '[{\"original\": \"هل لديكم أدوية لعلاجنزلة البرد؟\", \"translated\": \"¿Tienen medicamentos para el resfriado?\"}, {\"original\": \"كيف يجب أن آخذ هذا الدواء؟\", \"translated\": \"¿Cómo debo tomar este medicamento?\"}, {\"original\": \"هل لديكم أي مسكنات للألم؟\", \"translated\": \"¿Tienen algún analgésico?\"}, {\"original\": \"هل يوجد كتيب تعليمات مع الدواء؟\", \"translated\": \"¿Viene con un folleto de instrucciones?\"}, {\"original\": \"هل لهذا الدواء أي آثار جانبية؟\", \"translated\": \"¿Este medicamento tiene efectos secundarios?\"}, {\"original\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\", \"translated\": \"¿Puedo usar mi tarjeta de seguro médico?\"}, {\"original\": \"هل يمكنني الحصول على علبة من الشاش الطبي اللاصق (باند-إيد)، من فضلكم؟\", \"translated\": \"¿Podría darme una caja de vendas adhesivas, por favor?\"}, {\"original\": \"هل لديكم أدوية خافضة للحرارة؟\", \"translated\": \"¿Tienen medicamentos para reducir la fiebre?\"}, {\"original\": \"لدي جرح سطحي بسيط. هل لديكم مطهر وشاش طبي لاصق (باند-إيد)؟\", \"translated\": \"Tengo una pequeña raspadura. ¿Tienen antiséptico y vendas adhesivas?\"}, {\"original\": \"في أي وقت تغلقون المحل؟\", \"translated\": \"¿A qué hora cierran?\"}]', 7, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في خدمات الطوارئ؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بخدمات الطوارئ، مع الترجمة إلى الإسبانية:\"]', '[\"الاتصال بالشرطة\", \"الإسعافات الأولية\", \"طلب المساعدة\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف طارئ محدد في ذهنك، مثل: حريق، إصابة وضرورة الحصول على مساعدة، أو اتصال طارئ؟ لا تتردد في السؤال.\", \"من فضلك صف لي الموقف الذي يجول بخاطرك.\"]', '[]', '[{\"original\": \"من فضلك ساعدني في استدعاء الإسعاف.\", \"translated\": \"Por favor, ayúdeme a llamar a una ambulancia.\"}, {\"original\": \"أين تقع المستشفى؟\", \"translated\": \"¿Dónde está el hospital?\"}, {\"original\": \"شخص ما أُصيب.\", \"translated\": \"Alguien ha resultado herido.\"}, {\"original\": \"من فضلك ساعدني.\", \"translated\": \"Por favor, ayúdeme.\"}, {\"original\": \"أين تقع مركز الشرطة؟\", \"translated\": \"¿Dónde está la comisaría de policía?\"}, {\"original\": \"لقد فقدت أ possessionati الخاصة بي.\", \"translated\": \"He perdido mis pertenencias.\"}, {\"original\": \"ما هو رقم إطفاء الحريق؟\", \"translated\": \"¿Cuál es el número de los bomberos?\"}, {\"original\": \"لقد فقدت جواز سفري. هل تعلم أين أقرب مركز شرطة؟\", \"translated\": \"He perdido mi pasaporte. ¿Sabes dónde está la comisaría de policía más cercana?\"}, {\"original\": \"هل يوجد مخرج طوارئ؟\", \"translated\": \"¿Hay una salida de emergencia?\"}, {\"original\": \"شخص ما فقد وعيه.\", \"translated\": \"Alguien ha perdido el conocimiento.\"}]', 8, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في الشاطئ أو حوض السباحة؟\", \"رائع! إليك ١٠ عبارات شائعة تتعلّق بالشاطئ أو حوض السباحة، إلى جانب ترجمتها إلى الإسبانية:\"]', '[\"السباحة\", \"الاستلقاء تحت أشعة الشمس\", \"الرياضات الشاطئية\"]', 'ar', '[\"حاليًا، هل يمكنك إخباري عن سياق الحدث أو المهرجان المحلي الذي ستشارك فيه، مثل مهرجان ثقافي، أو مهرجان غذائي، أو مهرجان موسيقي؟ يُرجى تزويدي بالسياق.\", \"يرجى تزويدي بالأنشطة التي ستشارك فيها.\"]', '[\"هل لديك موقف معين في ذهنك؟ لا تتردد في طرح سؤالك.\", \"صف لي الموقف الذي تخيّله في ذهنك.\"]', '[{\"original\": \"انظر! الأمواج هناك كبيرة جدًا.\", \"translated\": \"¡Mira! Las olas allí son realmente grandes.\"}, {\"original\": \"تذكّر وضع واقي الشمس، فأشعة فوق البنفسجية هنا قوية جدًا.\", \"translated\": \"Recuerda aplicar protector solar; aquí los rayos UV son muy intensos.\"}, {\"original\": \"الرمل على هذا الشاطئ ناعم جدًا، لدرجة أن المشي عليه يشبه الخوض في القطن.\", \"translated\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\"}, {\"original\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\", \"translated\": \"¿Qué te parece jugar al voleibol en la playa?\"}, {\"original\": \"القوارب الشراعية في الأفق تبدو جميلة جدًا.\", \"translated\": \"Los veleros a lo lejos se ven preciosos.\"}, {\"original\": \"الماء هنا شفاف جدًا لدرجة أنك تستطيع رؤية الأسماك بوضوح.\", \"translated\": \"El agua aquí es tan clara que incluso puedes ver los peces.\"}, {\"original\": \"هيا نذهب للبحث عن بعض قواقع البحر.\", \"translated\": \"Vamos a buscar algunas conchas marinas.\"}, {\"original\": \"التجوّل على الشاطئ عند غروب الشمس يجب أن يكون أمرًا رومانسيًّا جدًا.\", \"translated\": \"Pasear por la playa al atardecer debe ser muy romántico.\"}, {\"original\": \"سمعت أن المأكولات البحرية هنا طازجة جدًا، لذا دعونا نجربها.\", \"translated\": \"He oído decir que los mariscos aquí son muy frescos; ¡vamos a probarlos!\"}, {\"original\": \"المدّ على وشك الارتفاع، لذا دعونا نتجه نحو الساحل.\", \"translated\": \"La marea está subiendo, ¡vamos hacia la orilla!\"}]', 9, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ ١٠ عبارات شائعة يمكنني استخدامها في الفعاليات والمناسبات المحلية؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بالفعاليات والمناسبات المحلية، مع ترجمتها إلى الإسبانية:\"]', '[\"الحضور إلى الفعاليات\", \"الاحتفال بالمناسبات والموسميات\", \"التعرف على الثقافة\"]', 'ar', '[\"حاليًّا، هل يمكنك من فضلك تزويدي بسياق الفعالية أو المناسبة المحلية التي ستشارك فيها، مثل الهالوين أو الحفلة الموسيقية أو حفلة صديق أو أي شيء آخر؟ يُرجى تحديد السياق.\", \"يرجى وصف الأنشطة التي تفكر فيها.\"]', '[\"هل لديك موقف معيّن في بالك؟ لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي تفكر فيه.\"]', '[{\"original\": \"هل توجد أي فعاليات اليوم؟\", \"translated\": \"¿Hay algún evento hoy?\"}, {\"original\": \"هل هناك شيء مميز في هذه المهرجان؟\", \"translated\": \"¿Hay algo especial acerca de este festival?\"}, {\"original\": \"أين تُقام الاحتفالات؟\", \"translated\": \"¿Dónde se lleva a cabo la celebración?\"}, {\"original\": \"كيف يمكنني شراء التذاكر؟\", \"translated\": \"¿Cómo puedo comprar las entradas?\"}, {\"original\": \"في أي وقت تبدأ العروض؟\", \"translated\": \"¿A qué hora comienza la actuación?\"}, {\"original\": \"ما الأطعمة التقليدية المتوفرة؟\", \"translated\": \"¿Qué comida tradicional hay?\"}, {\"original\": \"المكان مليء بالحيوية حقًا!\", \"translated\": \"¡Aquí hay mucha animación!\"}, {\"original\": \"هل توجد أنشطة شعبية؟\", \"translated\": \"¿Hay alguna actividad folclórica?\"}, {\"original\": \"أعياد سعيدة!\", \"translated\": \"¡Felices fiestas!\"}, {\"original\": \"في أي وقت تنتهي الفعالية؟\", \"translated\": \"¿A qué hora termina el evento?\"}]', 10, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بعشر عبارات شائعة يمكنني استخدامها في متحف أو معرض فني؟\", \"رائع! إليك عشر عبارات شائعة مرتبطة بالمتحف أو المعرض الفني، مع ترجمتها إلى الإسبانية:\"]', '[\"الزيارة\", \"الجولة المُرشدة\", \"شراء التذاكر\"]', 'ar', '[\"لحد الآن، هل لديك موقفٌ معيّن في ذهنك؟ مثل طلب كتيب تعريفي، أو عبارات مرتبطة بخريطة الطريق، أو عبارات للتعليق على المعروضات؟ لا تتردد في السؤال!\", \"من فضلك صف الموقف الذي في ذهنك.\"]', '[]', '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"هل لديكم أجهزة دليل صوتي؟\", \"translated\": \"¿Tienen guías auditivos?\"}, {\"original\": \"من قام بإنشاء هذه القطعة الفنية؟\", \"translated\": \"¿Quién creó esta obra de arte?\"}, {\"original\": \"أين توجد أثمن قطعة في المتحف؟\", \"translated\": \"¿Dónde se encuentra la pieza más valiosa del museo?\"}, {\"original\": \"هل يُسمح بالتصوير الفوتوغرافي؟\", \"translated\": \"¿Está permitida la fotografía?\"}, {\"original\": \"هل توجد معارض خاصة هنا؟\", \"translated\": \"¿Hay alguna exposición especial aquí?\"}, {\"original\": \"كم تستغرق الجولة من الوقت؟\", \"translated\": \"¿Cuánto tiempo dura la visita?\"}, {\"original\": \"هل يمكنكم أن تقدّموا لنا مقدمة عامة؟\", \"translated\": \"¿Podrían darnos una introducción?\"}, {\"original\": \"هذه الأعمال فعلاً رائعة ودقيقة جدًا.\", \"translated\": \"Estas obras son verdaderamente exquisitas.\"}, {\"original\": \"أين تقع متجر الهدايا التذكارية؟\", \"translated\": \"¿Dónde está la tienda de recuerdos?\"}]', 11, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بـ ١٠ عبارات شائعة يمكنني استخدامها في مقهى؟\", \"رائع! إليك ١٠ عبارات شائعة مرتبطة بالمقاهي، مع ترجمتها إلى الإسبانية:\"]', '[\"طلب قهوة\", \"الراحة\", \"التواصل الاجتماعي\"]', 'ar', '[\"حتى الآن، هل لديك موقف معيَّن في ذهنك؟ مثل طلب القائمة، أو الطلبات الباردة أو الساخنة، أو منتجات أخرى؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي تفكر فيه.\"]', '[]', '[{\"original\": \"سأطلب لاتيه، من فضلك.\", \"translated\": \"Pediré un latte, por favor.\"}, {\"original\": \"هل لديكم خدمة واي فاي؟\", \"translated\": \"¿Tienen conexión Wi-Fi?\"}, {\"original\": \"هل يمكنني رؤية القائمة، من فضلك؟\", \"translated\": \"¿Podría ver el menú, por favor?\"}, {\"original\": \"هل يُسمح بإعادة التعبئة؟\", \"translated\": \"¿Se permiten recargas?\"}, {\"original\": \"هل قهوة الفنجان جاهزة؟\", \"translated\": \"¿Ya está lista mi café?\"}, {\"original\": \"كم من الوقت يمكنني الجلوس هنا؟\", \"translated\": \"¿Cuánto tiempo puedo quedarme sentado aquí?\"}, {\"original\": \"هل يمكنكم أن تلتقطوا لنا صورة؟\", \"translated\": \"¿Podrían tomarnos una foto?\"}, {\"original\": \"أين الحمام؟\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"الحساب، من فضلك. شكرًا لكم.\", \"translated\": \"La cuenta, por favor. Gracias.\"}, {\"original\": \"الط taste لذيذٌ جدًّا.\", \"translated\": \"¡Sabe realmente delicioso!\"}]', 12, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser au restaurant ?\", \"Formidable ! Voici 10 expressions courantes liées au restaurant, accompagnées de leurs traductions en espagnol :\"]', '[\"Restauration\", \"Commande\", \"Règlement\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, comme commander des boissons, formuler une réclamation ou demander des précisions sur les ingrédients ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\", \"translated\": \"Disculpe, ¿cuánto tiempo más tardará nuestra comida?\"}, {\"original\": \"Une table pour deux personnes, s\'il vous plaît.\", \"translated\": \"Una mesa para dos personas, por favor.\"}, {\"original\": \"Pourrions-nous voir la carte, s\'il vous plaît ?\", \"translated\": \"¿Podríamos ver el menú, por favor?\"}, {\"original\": \"Avez-vous des plats signature à nous recommander ?\", \"translated\": \"¿Tienen algún plato típico que nos puedan recomendar?\"}, {\"original\": \"Je voudrais commander ceci et cela.\", \"translated\": \"Quisiera pedir esto y esto otro.\"}, {\"original\": \"Un verre d\'eau, s\'il vous plaît. Merci.\", \"translated\": \"Un vaso de agua, por favor. Gracias.\"}, {\"original\": \"L\'addition, s\'il vous plaît.\", \"translated\": \"La cuenta, por favor.\"}, {\"original\": \"Puis-je payer par carte bancaire ?\", \"translated\": \"¿Puedo pagar con tarjeta de crédito?\"}, {\"original\": \"Pourriez-vous emballer cela à emporter, s\'il vous plaît ?\", \"translated\": \"¿Podrían empaquetar esto para llevar, por favor?\"}, {\"original\": \"Le repas était délicieux, merci.\", \"translated\": \"La comida estaba deliciosa, gracias.\"}]', 1, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser à l\'hôtel ?\", \"Génial ! Voici 10 expressions courantes liées à l\'hôtel, accompagnées de leurs traductions en espagnol :\"]', '[\"Enregistrement\", \"Départ\", \"Service en chambre\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple l\'emplacement de la chambre, d\'autres services hôteliers ou le départ ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Bonjour, j\'ai une réservation. Voici mon passeport.\", \"translated\": \"Hola, tengo una reserva. Aquí tiene mi pasaporte.\"}, {\"original\": \"Avez-vous des chambres disponibles ?\", \"translated\": \"¿Tienen habitaciones disponibles?\"}, {\"original\": \"Excusez-moi, l\'hôtel dispose-t-il d\'une salle de sport ou d\'une buanderie ?\", \"translated\": \"Disculpe, ¿el hotel tiene gimnasio o lavandería?\"}, {\"original\": \"À quelle heure commence le petit-déjeuner ?\", \"translated\": \"¿A qué hora empieza el desayuno?\"}, {\"original\": \"Pourrais-je avoir la clé de ma chambre, s\'il vous plaît ?\", \"translated\": \"¿Podría darme la llave de mi habitación, por favor?\"}, {\"original\": \"Pourriez-vous m\'aider à porter mes bagages jusqu\'à ma chambre ?\", \"translated\": \"¿Podría ayudarme a llevar mi equipaje hasta la habitación?\"}, {\"original\": \"Comment puis-je appeler le service d\'étage ?\", \"translated\": \"¿Cómo puedo llamar al servicio de habitaciones?\"}, {\"original\": \"À quelle heure est l\'heure de départ ?\", \"translated\": \"¿A qué hora es la salida?\"}, {\"original\": \"Pourriez-vous me faire un reçu/facture ?\", \"translated\": \"¿Podría darme un recibo/factura?\"}, {\"original\": \"Puis-je laisser mes bagages ici ?\", \"translated\": \"¿Puedo dejar aquí mi equipaje?\"}]', 2, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en el aeropuerto?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con el aeropuerto, junto con sus traducciones al español:\"]', '[\"Enregistrement\", \"Embarquement\", \"Enregistrement des bagages\"]', 'fr', '[\"Por ahora, ¿tiene alguna situación específica en mente, como el check-in, la recogida de equipajes o el servicio de alquiler de coches? ¡No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Où se trouve le comptoir d\'enregistrement ?\", \"translated\": \"¿Dónde está el mostrador de facturación?\"}, {\"original\": \"Je voudrais un siège côté hublot, s\'il vous plaît.\", \"translated\": \"Quisiera un asiento junto a la ventanilla, por favor.\"}, {\"original\": \"Ce vol est-il retardé ?\", \"translated\": \"¿Este vuelo tiene retraso?\"}, {\"original\": \"Je dois enregistrer ce bagage.\", \"translated\": \"Necesito facturar este equipaje.\"}, {\"original\": \"Où se trouve la porte d\'embarquement ?\", \"translated\": \"¿Dónde está la puerta de embarque?\"}, {\"original\": \"L\'avion va bientôt décoller.\", \"translated\": \"El avión despegará en breve.\"}, {\"original\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\", \"translated\": \"¿Debo sacar mi portátil y mi power bank?\"}, {\"original\": \"Où se trouve la boutique hors taxes ?\", \"translated\": \"¿Dónde está la tienda libre de impuestos?\"}, {\"original\": \"Je ne retrouve pas ma valise.\", \"translated\": \"No encuentro mi maleta.\"}, {\"original\": \"Proposez-vous un service de fauteuil roulant ?\", \"translated\": \"¿Ofrecen servicio de silla de ruedas?\"}]', 3, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser en transports en commun ?\", \"Génial ! Voici 10 expressions courantes liées aux transports en commun, accompagnées de leurs traductions en espagnol :\"]', '[\"Prendre le bus ou le métro\", \"Acheter des billets\", \"Effectuer une correspondance\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander où se trouve l\'arrêt de bus, le prix du billet ou indiquer qu\'on veut descendre ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Ce bus va-t-il jusqu\'à la gare routière ?\", \"translated\": \"¿Este autobús va hasta la terminal?\"}, {\"original\": \"Quelle est la prochaine arrêt ?\", \"translated\": \"¿Cuál es la siguiente parada?\"}, {\"original\": \"Où puis-je acheter un billet ?\", \"translated\": \"¿Dónde puedo comprar un billete?\"}, {\"original\": \"Un billet pour XX, s\'il vous plaît.\", \"translated\": \"Un billete para XX, por favor.\"}, {\"original\": \"Dois-je changer de véhicule ?\", \"translated\": \"¿Tengo que hacer transbordo?\"}, {\"original\": \"Dans combien de temps arrive le prochain métro ?\", \"translated\": \"¿En cuánto tiempo llega el próximo tren del metro?\"}, {\"original\": \"Excusez-moi, je dois passer.\", \"translated\": \"Disculpe, por favor déjeme pasar.\"}, {\"original\": \"Cette place est-elle occupée ?\", \"translated\": \"¿Está ocupado este asiento?\"}, {\"original\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d\'aller à XX ?\", \"translated\": \"Disculpe, ¿dónde puedo transbordar a la línea 2 para llegar a XX?\"}, {\"original\": \"Comment puis-je me rendre à XX ?\", \"translated\": \"¿Cómo llego a XX?\"}]', 4, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans un site touristique ?\", \"Formidable ! Voici 10 expressions courantes liées aux sites touristiques, accompagnées de leurs traductions en espagnol :\"]', '[\"Visite touristique\", \"Prendre des photos\", \"Acheter des billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander le prix des billets, trouver un parking ou un service de guide touristique ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Combien coûte l\'entrée ?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"Y a-t-il des billets étudiants disponibles ?\", \"translated\": \"¿Hay entradas para estudiantes disponibles?\"}, {\"original\": \"À quelle heure ouvre l\'attraction ?\", \"translated\": \"¿A qué hora abre la atracción?\"}, {\"original\": \"Quelles sont les activités amusantes à faire ici ?\", \"translated\": \"¿Qué cosas divertidas se pueden hacer aquí?\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"¿Podría hacernos una foto?\"}, {\"original\": \"Où se trouve le bus touristique ?\", \"translated\": \"¿Dónde está el autobús turístico?\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"¿Dónde están los baños?\"}, {\"original\": \"Où est le meilleur point de vue ?\", \"translated\": \"¿Dónde está el mejor mirador?\"}, {\"original\": \"Le paysage est magnifique ici.\", \"translated\": \"El paisaje es precioso aquí.\"}, {\"original\": \"Y a-t-il une visite guidée disponible ?\", \"translated\": \"¿Hay visitas guiadas disponibles?\"}]', 5, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser pour prendre un taxi ou utiliser un service de taxi ?\", \"Formidable ! Voici 10 expressions courantes liées aux taxis ou aux services de taxi, accompagnées de leurs traductions en espagnol :\"]', '[\"Prendre un taxi\", \"Indiquer la destination\", \"Paiement\"]', 'fr', '[\"Pour l’instant, que voulez-vous faire principalement maintenant ? Par exemple, demander la destination, le montant, ou une facture — n’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Où puis-je prendre un taxi ?\", \"translated\": \"¿Dónde puedo tomar un taxi?\"}, {\"original\": \"Veuillez me conduire à cette adresse.\", \"translated\": \"Por favor, lléveme a esta dirección.\"}, {\"original\": \"Combien cela coûtera-t-il approximativement ?\", \"translated\": \"¿Cuánto costará aproximadamente?\"}, {\"original\": \"Pourriez-vous utiliser le compteur, s’il vous plaît ?\", \"translated\": \"¿Podría usar el taxímetro, por favor?\"}, {\"original\": \"Veuillez rouler un peu plus vite, je suis pressé(e).\", \"translated\": \"Por favor, conduzca un poco más rápido, tengo prisa.\"}, {\"original\": \"Arrêtez-vous ici, s’il vous plaît.\", \"translated\": \"Párese aquí, por favor.\"}, {\"original\": \"Acceptez-vous les cartes ou les paiements mobiles ?\", \"translated\": \"¿Acepta tarjetas o pagos móviles?\"}, {\"original\": \"Pourrais-je avoir un reçu, s’il vous plaît ?\", \"translated\": \"¿Podría darme un recibo, por favor?\"}, {\"original\": \"Merci beaucoup, monsieur/madame le chauffeur.\", \"translated\": \"Muchas gracias, señor conductor.\"}, {\"original\": \"Combien de temps reste-t-il avant d’arriver ?\", \"translated\": \"¿Cuánto falta todavía?\"}]', 6, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans une pharmacie ?\", \"Formidable ! Voici 10 expressions courantes liées à la pharmacie, accompagnées de leurs traductions en espagnol :\"]', '[\"Acheter des médicaments\", \"Consulter\", \"Payer\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander des instructions sur la prise d’un médicament, des expressions liées à l’utilisation de l’assurance maladie ou à la durée du traitement ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Avez-vous des médicaments contre le rhume ?\", \"translated\": \"¿Tiene medicamentos para el resfriado?\"}, {\"original\": \"Comment dois-je prendre ce médicament ?\", \"translated\": \"¿Cómo debo tomar este medicamento?\"}, {\"original\": \"Avez-vous des analgésiques ?\", \"translated\": \"¿Tiene analgésicos?\"}, {\"original\": \"Y a-t-il une notice d’instructions ?\", \"translated\": \"¿Viene con un folleto informativo?\"}, {\"original\": \"Ce médicament a-t-il des effets secondaires ?\", \"translated\": \"¿Este medicamento tiene efectos secundarios?\"}, {\"original\": \"Puis-je utiliser ma carte d’assurance maladie ?\", \"translated\": \"¿Puedo usar mi tarjeta de seguro médico?\"}, {\"original\": \"Pourriez-vous me donner une boîte de pansements, s’il vous plaît ?\", \"translated\": \"¿Podría darme una caja de vendajes adhesivos, por favor?\"}, {\"original\": \"Avez-vous des antipyrétiques ?\", \"translated\": \"¿Tiene medicamentos para la fiebre?\"}, {\"original\": \"Je me suis fait une petite éraflure. Avez-vous de l’antiseptique et des pansements ?\", \"translated\": \"Me he hecho una pequeña raspadura. ¿Tiene antiséptico y vendajes adhesivos?\"}, {\"original\": \"À quelle heure fermez-vous ?\", \"translated\": \"¿A qué hora cierran?\"}]', 7, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans les services d\'urgence ?\", \"Formidable ! Voici 10 expressions courantes liées aux services d\'urgence, accompagnées de leurs traductions en espagnol :\"]', '[\"Appeler la police\", \"Premiers secours\", \"Demander de l\'aide\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation d\'urgence précise en tête, comme un incendie, une personne blessée qui a besoin d’aide, ou un appel d’urgence ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[]', '[{\"original\": \"Veuillez m\'aider à appeler une ambulance.\", \"translated\": \"Por favor, ayúdeme a llamar a una ambulancia.\"}, {\"original\": \"Où est l\'hôpital ?\", \"translated\": \"¿Dónde está el hospital?\"}, {\"original\": \"Quelqu\'un est blessé.\", \"translated\": \"Alguien está herido.\"}, {\"original\": \"Veuillez m\'aider.\", \"translated\": \"Por favor, ayúdeme.\"}, {\"original\": \"Où est le poste de police ?\", \"translated\": \"¿Dónde está la comisaría de policía?\"}, {\"original\": \"J\'ai perdu mes affaires.\", \"translated\": \"He perdido mis pertenencias.\"}, {\"original\": \"Quel est le numéro des pompiers ?\", \"translated\": \"¿Cuál es el número de los bomberos?\"}, {\"original\": \"J\'ai perdu mon passeport. Savez-vous où se trouve la poste de police la plus proche ?\", \"translated\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría de policía más cercana?\"}, {\"original\": \"Y a-t-il une sortie de secours ?\", \"translated\": \"¿Hay una salida de emergencia?\"}, {\"original\": \"Quelqu\'un s\'est évanoui.\", \"translated\": \"Alguien ha perdido el conocimiento.\"}]', 8, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en la playa o junto a la piscina?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con la playa o la piscina, junto con sus traducciones al francés:\"]', '[\"Natation\", \"Bronzage\", \"Sports de plage\"]', 'fr', '[\"Por ahora, ¿podría indicarme el contexto del evento o festival local al que asistirá, como un festival cultural, gastronómico o musical? Por favor, indíqueme el contexto.\", \"Indíqueme las actividades a las que asistirá.\"]', '[\"¿Tiene alguna situación específica en mente? Pregunte sin ningún problema.\", \"Describa la situación que tiene en mente.\"]', '[{\"original\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\", \"translated\": \"¡Miren! ¡Las olas allí son realmente grandes!\"}, {\"original\": \"N\'oubliez pas d\'appliquer de la crème solaire : les rayons UV sont très forts ici.\", \"translated\": \"Recuerden aplicar protector solar, los rayos UV aquí son muy intensos.\"}, {\"original\": \"Le sable de cette plage est si fin qu’on a l’impression de marcher sur du coton.\", \"translated\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\"}, {\"original\": \"Et si on jouait au volley-ball sur la plage ?\", \"translated\": \"¿Qué tal si jugamos voleibol en la playa?\"}, {\"original\": \"Les voiliers au loin sont magnifiques.\", \"translated\": \"Los veleros a lo lejos se ven preciosos.\"}, {\"original\": \"L’eau est tellement claire ici qu’on peut même voir les poissons.\", \"translated\": \"El agua aquí es tan transparente que hasta se pueden ver los peces.\"}, {\"original\": \"Allons chercher des coquillages.\", \"translated\": \"Vamos a buscar conchas marinas.\"}, {\"original\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\", \"translated\": \"Pasear por la playa al atardecer debe ser muy romántico.\"}, {\"original\": \"J’ai entendu dire que les fruits de mer sont très frais ici ; allons-en goûter.\", \"translated\": \"He oído decir que los mariscos aquí son muy frescos; vamos a probarlos.\"}, {\"original\": \"La marée monte ; rentrons vers la rive.\", \"translated\": \"La marea está subiendo; volvamos hacia la orilla.\"}]', 9, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser lors d\'activités et de festivals locaux ?\", \"Fantastique ! Voici 10 expressions courantes liées aux activités et festivals locaux, accompagnées de leurs traductions en espagnol :\"]', '[\"Assister à des événements\", \"Célébrer des festivals\", \"Découvrir la culture\"]', 'fr', '[\"Pour l’instant, pourriez-vous me préciser le contexte de l’activité ou du festival local auquel vous participez — par exemple Halloween, un concert, une fête entre amis ou autre chose ? Veuillez fournir ce contexte.\", \"Veuillez décrire les activités qui vous viennent à l’esprit.\"]', '[\"Avez-vous une situation précise en tête ? N’hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Y a-t-il des événements aujourd\'hui ?\", \"translated\": \"¿Hay algún evento hoy?\"}, {\"original\": \"Y a-t-il quelque chose de spécial à propos de ce festival ?\", \"translated\": \"¿Hay algo especial sobre este festival?\"}, {\"original\": \"Où se déroule la célébration ?\", \"translated\": \"¿Dónde se celebra la festividad?\"}, {\"original\": \"Comment puis-je acheter des billets ?\", \"translated\": \"¿Cómo puedo comprar entradas?\"}, {\"original\": \"À quelle heure commence le spectacle ?\", \"translated\": \"¿A qué hora empieza la actuación?\"}, {\"original\": \"Quels sont les plats traditionnels proposés ?\", \"translated\": \"¿Qué comidas tradicionales hay?\"}, {\"original\": \"C’est vraiment animé ici.\", \"translated\": \"¡Es realmente animado aquí!\"}, {\"original\": \"Y a-t-il des activités folkloriques ?\", \"translated\": \"¿Hay alguna actividad folclórica?\"}, {\"original\": \"Joyeuses fêtes !\", \"translated\": \"¡Felices fiestas!\"}, {\"original\": \"À quelle heure se termine l\'événement ?\", \"translated\": \"¿A qué hora termina el evento?\"}]', 10, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans un musée ou une galerie d\'art ?\", \"Fantastique ! Voici 10 expressions courantes liées aux musées ou galeries d\'art, accompagnées de leurs traductions en espagnol :\"]', '[\"Visite\", \"Visite guidée\", \"Achat de billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander une notice explicative, des expressions liées à un plan de visite, ou des formulations pour commenter une exposition ? N\'hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Combien coûte le droit d\'entrée ?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"Proposez-vous des guides audio ?\", \"translated\": \"¿Ofrecen audioguías?\"}, {\"original\": \"Qui a créé cette œuvre ?\", \"translated\": \"¿Quién creó esta obra?\"}, {\"original\": \"Où se trouve la pièce la plus précieuse du musée ?\", \"translated\": \"¿Dónde se encuentra la pieza más valiosa del museo?\"}, {\"original\": \"La prise de photos est-elle autorisée ?\", \"translated\": \"¿Está permitida la fotografía?\"}, {\"original\": \"Y a-t-il des expositions spéciales ici ?\", \"translated\": \"¿Hay alguna exposición especial aquí?\"}, {\"original\": \"Combien de temps dure la visite ?\", \"translated\": \"¿Cuánto tiempo dura la visita?\"}, {\"original\": \"Pourriez-vous nous en faire une présentation ?\", \"translated\": \"¿Podrían darnos una introducción?\"}, {\"original\": \"Ces œuvres sont vraiment exquises.\", \"translated\": \"Estas obras son verdaderamente exquisitas.\"}, {\"original\": \"Où se trouve la boutique de souvenirs ?\", \"translated\": \"¿Dónde está la tienda de souvenirs?\"}]', 11, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans un café ?\", \"Fantastique ! Voici 10 expressions courantes liées au café, accompagnées de traductions en espagnol :\"]', '[\"Commander un café\", \"Se reposer\", \"Socialiser\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, comme demander le menu, des boissons glacées ou chaudes, d\'autres produits ? N\'hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', '[]', '[{\"original\": \"Je prendrai un latte, s\'il vous plaît.\", \"translated\": \"Tomaré un latte, por favor.\"}, {\"original\": \"Avez-vous le Wi-Fi ?\", \"translated\": \"¿Tienen conexión Wi-Fi?\"}, {\"original\": \"Pourrais-je voir le menu, s\'il vous plaît ?\", \"translated\": \"¿Podría ver el menú, por favor?\"}, {\"original\": \"Les recharges sont-elles autorisées ?\", \"translated\": \"¿Se permiten recargas?\"}, {\"original\": \"Mon café est-il prêt ?\", \"translated\": \"¿Ya está listo mi café?\"}, {\"original\": \"Combien de temps puis-je rester ici ?\", \"translated\": \"¿Cuánto tiempo puedo quedarme aquí?\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"¿Podrían tomarnos una foto?\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"¿Dónde están los baños?\"}, {\"original\": \"L\'addition, s\'il vous plaît. Merci.\", \"translated\": \"La cuenta, por favor. Gracias.\"}, {\"original\": \"C\'est vraiment délicieux.\", \"translated\": \"Sabe realmente delicioso.\"}]', 12, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Phrasen nennen, die ich im Restaurant verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Phrasen zum Thema Restaurant – inklusive spanischer Übersetzungen:\"]', '[\"Essen\", \"Bestellen\", \"Bezahlen\"]', 'de', '[\"Für den Augenblick: Haben Sie eine konkrete Situation im Kopf – etwa Getränke bestellen, eine Beschwerde äußern oder nach Zutaten fragen? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Entschuldigung, wie lange dauert es noch, bis unser Essen kommt?\", \"translated\": \"Perdón, ¿cuánto tiempo más tardará nuestra comida?\"}, {\"original\": \"Ein Tisch für zwei, bitte.\", \"translated\": \"Una mesa para dos, por favor.\"}, {\"original\": \"Könnten wir bitte die Speisekarte sehen?\", \"translated\": \"¿Podríamos ver el menú, por favor?\"}, {\"original\": \"Haben Sie empfehlenswerte Hausgerichte?\", \"translated\": \"¿Tienen algún plato especial que nos puedan recomendar?\"}, {\"original\": \"Ich möchte dieses und jenes bestellen.\", \"translated\": \"Quisiera pedir esto y esto otro.\"}, {\"original\": \"Ein Glas Wasser, bitte. Danke.\", \"translated\": \"Un vaso de agua, por favor. Gracias.\"}, {\"original\": \"Die Rechnung, bitte.\", \"translated\": \"La cuenta, por favor.\"}, {\"original\": \"Kann ich mit Kreditkarte bezahlen?\", \"translated\": \"¿Puedo pagar con tarjeta de crédito?\"}, {\"original\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\", \"translated\": \"¿Podrían empaquetarlo para llevar, por favor?\"}, {\"original\": \"Das Essen war köstlich, vielen Dank.\", \"translated\": \"La comida estuvo deliciosa, muchas gracias.\"}]', 1, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Hotels nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Hotel – inklusive spanischer Übersetzungen:\"]', '[\"Einchecken\", \"Auschecken\", \"Zimmerservice\"]', 'de', '[\"Für den Moment: Haben Sie eine konkrete Situation im Kopf, z. B. Zimmerlage, weitere Hoteldienstleistungen oder Auschecken? Fragen Sie ruhig alles, was Ihnen auf dem Herzen liegt.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Hallo, ich habe eine Reservierung. Hier ist mein Reisepass.\", \"translated\": \"Hola, tengo una reserva. Aquí está mi pasaporte.\"}, {\"original\": \"Haben Sie noch freie Zimmer?\", \"translated\": \"¿Tienen habitaciones disponibles?\"}, {\"original\": \"Entschuldigung, hat das Hotel einen Fitnessraum oder eine Waschküche?\", \"translated\": \"Perdón, ¿tiene el hotel un gimnasio o una lavandería?\"}, {\"original\": \"Um welche Uhrzeit beginnt das Frühstück?\", \"translated\": \"¿A qué hora comienza el desayuno?\"}, {\"original\": \"Könnte ich bitte den Zimmerschlüssel bekommen?\", \"translated\": \"¿Podría darme la llave de la habitación, por favor?\"}, {\"original\": \"Könnten Sie mir helfen, mein Gepäck aufs Zimmer zu bringen?\", \"translated\": \"¿Podría ayudarme a llevar mi equipaje a la habitación?\"}, {\"original\": \"Wie rufe ich den Zimmerservice an?\", \"translated\": \"¿Cómo llamo al servicio de habitaciones?\"}, {\"original\": \"Wann ist die Abreisezeit?\", \"translated\": \"¿A qué hora es la salida?\"}, {\"original\": \"Könnten Sie mir bitte eine Quittung / Rechnung ausstellen?\", \"translated\": \"¿Podría emitirme una factura o recibo, por favor?\"}, {\"original\": \"Kann ich mein Gepäck hier lassen?\", \"translated\": \"¿Puedo dejar aquí mi equipaje?\"}]', 2, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Phrasen für den Flughafen nennen?\", \"Fantastisch! Hier sind 10 gängige Phrasen zum Thema Flughafen – inklusive spanischer Übersetzungen:\"]', '[\"Check-in\", \"Boarding\", \"Gepäckabgabe\"]', 'de', '[\"Im Moment: Haben Sie eine konkrete Situation im Kopf, z. B. Check-in, Gepäckausgabe oder Mietwagenservice? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wo ist der Check-in-Schalter?\", \"translated\": \"¿Dónde está el mostrador de facturación?\"}, {\"original\": \"Ich hätte gerne einen Fensterplatz, bitte.\", \"translated\": \"Me gustaría un asiento junto a la ventana, por favor.\"}, {\"original\": \"Ist dieser Flug verspätet?\", \"translated\": \"¿Este vuelo está retrasado?\"}, {\"original\": \"Ich muss dieses Gepäck aufgeben.\", \"translated\": \"Necesito facturar este equipaje.\"}, {\"original\": \"Wo ist das Boarding-Tor?\", \"translated\": \"¿Dónde está la puerta de embarque?\"}, {\"original\": \"Das Flugzeug startet gleich.\", \"translated\": \"El avión despegará en breve.\"}, {\"original\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\", \"translated\": \"¿Tengo que sacar mi ordenador portátil y mi banco de energía?\"}, {\"original\": \"Wo ist der Duty-free-Shop?\", \"translated\": \"¿Dónde está la tienda libre de impuestos?\"}, {\"original\": \"Ich kann meinen Koffer nicht finden.\", \"translated\": \"No encuentro mi maleta.\"}, {\"original\": \"Bieten Sie einen Rollstuhl-Service an?\", \"translated\": \"¿Ofrecen servicio de silla de ruedas?\"}]', 3, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für öffentliche Verkehrsmittel nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema öffentliche Verkehrsmittel – inklusive spanischer Übersetzungen:\"]', '[\"Mit Bus/U-Bahn fahren\", \"Tickets kaufen\", \"Umsteigen\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf, z. B. nach der Bushaltestelle fragen, den Ticketpreis erfragen oder um das Aussteigen bitten? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', '[]', '[{\"original\": \"Fährt dieser Bus zum Terminal?\", \"translated\": \"¿Va este autobús a la estación terminal?\"}, {\"original\": \"Was ist die nächste Haltestelle?\", \"translated\": \"¿Cuál es la próxima parada?\"}, {\"original\": \"Wo kann ich ein Ticket kaufen?\", \"translated\": \"¿Dónde puedo comprar un billete?\"}, {\"original\": \"Ein Ticket nach XX, bitte.\", \"translated\": \"Un billete para XX, por favor.\"}, {\"original\": \"Muss ich umsteigen?\", \"translated\": \"¿Tengo que transbordar?\"}, {\"original\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\", \"translated\": \"¿Cuánto tiempo falta para el próximo tren del metro?\"}, {\"original\": \"Entschuldigung, bitte lassen Sie mich durch.\", \"translated\": \"Disculpe, permítame pasar.\"}, {\"original\": \"Ist dieser Platz bereits besetzt?\", \"translated\": \"¿Está ocupado este asiento?\"}, {\"original\": \"Entschuldigung, wo kann ich umsteigen, um mit der Linie 2 nach XX zu gelangen?\", \"translated\": \"Disculpe, ¿dónde puedo transbordar a la línea 2 para llegar a XX?\"}, {\"original\": \"Wie komme ich nach XX?\", \"translated\": \"¿Cómo llego a XX?\"}]', 4, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Floskeln nennen, die ich an Touristenattraktionen verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Floskeln rund um Touristenattraktionen – inklusive spanischer Übersetzungen:\"]', '[\"Sehenswürdigkeiten besichtigen\", \"Fotos machen\", \"Eintrittskarten kaufen\"]', 'de', '[\"Vorläufig: Haben Sie eine bestimmte Situation im Kopf – z. B. nach dem Eintrittspreis fragen, einen Parkplatz suchen oder nach einem Führungsservice fragen? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen gerade einfällt.\"]', '[]', '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"Gibt es ermäßigte Eintrittskarten für Schüler und Studenten?\", \"translated\": \"¿Hay entradas para estudiantes disponibles?\"}, {\"original\": \"Wann öffnet die Sehenswürdigkeit?\", \"translated\": \"¿A qué hora abre la atracción?\"}, {\"original\": \"Was kann man hier Lustiges unternehmen?\", \"translated\": \"¿Qué cosas divertidas se pueden hacer aquí?\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"¿Podría hacernos una foto?\"}, {\"original\": \"Wo befindet sich der Sightseeing-Bus?\", \"translated\": \"¿Dónde está el autobús turístico?\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"Wo ist der beste Aussichtspunkt?\", \"translated\": \"¿Cuál es el mejor lugar para contemplar las vistas?\"}, {\"original\": \"Die Landschaft hier ist wunderschön.\", \"translated\": \"El paisaje aquí es hermoso.\"}, {\"original\": \"Gibt es eine geführte Tour?\", \"translated\": \"¿Hay disponible una visita guiada?\"}]', 5, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke für Taxis oder Taxidienstleistungen nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Taxis oder Taxidienstleistungen – inklusive spanischer Übersetzungen:\"]', '[\"Ein Taxi nehmen\", \"Das Ziel angeben\", \"Zahlen\"]', 'de', '[\"Was möchten Sie im Moment am liebsten tun – beispielsweise das Ziel angeben, nach dem Preis fragen oder um eine Rechnung bitten? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen gerade in den Sinn kommt.\"]', '[]', '[{\"original\": \"Wo kann ich ein Taxi bekommen?\", \"translated\": \"¿Dónde puedo conseguir un taxi?\"}, {\"original\": \"Bitte fahren Sie mich zu dieser Adresse.\", \"translated\": \"Por favor, lléveme a esta dirección.\"}, {\"original\": \"Wie viel kostet es ungefähr?\", \"translated\": \"¿Cuánto costará aproximadamente?\"}, {\"original\": \"Könnten Sie bitte den Taxameter benutzen?\", \"translated\": \"¿Podría usar, por favor, el taxímetro?\"}, {\"original\": \"Fahren Sie bitte etwas schneller, ich habe es eilig.\", \"translated\": \"Por favor, conduzca un poco más rápido, tengo prisa.\"}, {\"original\": \"Bitte halten Sie hier an.\", \"translated\": \"Por favor, pare aquí.\"}, {\"original\": \"Akzeptieren Sie Karten- oder Mobile-Payments?\", \"translated\": \"¿Acepta pagos con tarjeta o mediante móvil?\"}, {\"original\": \"Könnte ich bitte eine Quittung bekommen?\", \"translated\": \"¿Podría darme, por favor, un recibo?\"}, {\"original\": \"Danke, Fahrer.\", \"translated\": \"Gracias, conductor.\"}, {\"original\": \"Wie viel weiter ist es noch?\", \"translated\": \"¿Cuánto falta todavía?\"}]', 6, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Redewendungen für die Apotheke nennen?\", \"Fantastisch! Hier sind 10 gängige Redewendungen rund um die Apotheke – inklusive spanischer Übersetzung:\"]', '[\"Medikamente kaufen\", \"Beratung\", \"Bezahlung\"]', 'de', '[\"Für den Moment: Haben Sie eine konkrete Situation im Kopf, z. B. Fragen zur Einnahme von Medikamenten, zum Versicherungseinsatz, zur Dauer der Behandlung? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Haben Sie Medikamente gegen Erkältungen?\", \"translated\": \"¿Tiene medicamentos para el resfriado?\"}, {\"original\": \"Wie soll ich dieses Medikament einnehmen?\", \"translated\": \"¿Cómo debo tomar este medicamento?\"}, {\"original\": \"Haben Sie Schmerzmittel?\", \"translated\": \"¿Tiene analgésicos?\"}, {\"original\": \"Gibt es eine Gebrauchsanweisung?\", \"translated\": \"¿Viene con un folleto de instrucciones?\"}, {\"original\": \"Hat dieses Medikament Nebenwirkungen?\", \"translated\": \"¿Este medicamento tiene efectos secundarios?\"}, {\"original\": \"Kann ich meine Krankenversicherungskarte verwenden?\", \"translated\": \"¿Puedo usar mi tarjeta de seguro médico?\"}, {\"original\": \"Könnte ich bitte eine Packung Pflaster haben?\", \"translated\": \"¿Podría darme una caja de tiritas, por favor?\"}, {\"original\": \"Haben Sie Fiebersenkende Mittel?\", \"translated\": \"¿Tiene medicamentos para bajar la fiebre?\"}, {\"original\": \"Ich habe mir leicht das Knie aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\", \"translated\": \"Me he hecho una pequeña herida raspada. ¿Tienen antiséptico y tiritas?\"}, {\"original\": \"Wann machen Sie heute zu?\", \"translated\": \"¿A qué hora cierran hoy?\"}]', 7, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Können Sie mir 10 gängige Redewendungen für Notfalldienste nennen?\", \"Fantastisch! Hier sind 10 gängige Redewendungen zum Thema Notfalldienste – inklusive spanischer Übersetzungen:\"]', '[\"Polizei rufen\", \"Erste Hilfe\", \"Hilfe rufen\"]', 'de', '[\"Vorläufig: Haben Sie eine konkrete Notsituation im Kopf, z. B. Brand, Verletzung und benötigte Hilfe, Notruf? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf ist.\"]', '[]', '[{\"original\": \"Bitte rufen Sie einen Krankenwagen für mich.\", \"translated\": \"Por favor, llame a una ambulancia.\"}, {\"original\": \"Wo ist das Krankenhaus?\", \"translated\": \"¿Dónde está el hospital?\"}, {\"original\": \"Jemand ist verletzt.\", \"translated\": \"Alguien está herido.\"}, {\"original\": \"Bitte helfen Sie mir.\", \"translated\": \"Por favor, ayúdeme.\"}, {\"original\": \"Wo ist die Polizeistation?\", \"translated\": \"¿Dónde está la comisaría de policía?\"}, {\"original\": \"Ich habe meine Sachen verloren.\", \"translated\": \"He perdido mis pertenencias.\"}, {\"original\": \"Wie lautet die Notrufnummer für die Feuerwehr?\", \"translated\": \"¿Cuál es el número de emergencia para los bomberos?\"}, {\"original\": \"Ich habe meinen Reisepass verloren. Wissen Sie, wo die nächste Polizeistation ist?\", \"translated\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría de policía más cercana?\"}, {\"original\": \"Gibt es einen Notausgang?\", \"translated\": \"¿Hay una salida de emergencia?\"}, {\"original\": \"Jemand ist in Ohnmacht gefallen.\", \"translated\": \"Alguien ha perdido el conocimiento.\"}]', 8, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 gängige Ausdrücke für den Strand oder den Poolbereich nennen?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Strand oder Poolbereich samt spanischer Übersetzung:\"]', '[\"Schwimmen\", \"Sonnenbaden\", \"Strandsport\"]', 'de', '[\"Momentan: Könnten Sie mir bitte den Kontext der lokalen Veranstaltung oder des Festivals, an dem Sie teilnehmen, nennen? Zum Beispiel ein Kulturfestival, ein kulinarisches Festival oder ein Musikfestival. Bitte geben Sie den Kontext an.\", \"Bitte nennen Sie die Aktivitäten, an denen Sie teilnehmen.\"]', '[\"Haben Sie bereits eine konkrete Situation im Kopf? Fragen Sie ruhig frei nach.\", \"Beschreiben Sie bitte die Situation, die Ihnen im Kopf herumgeht.\"]', '[{\"original\": \"Schau mal! Die Wellen dort drüben sind wirklich groß.\", \"translated\": \"¡Mira! Las olas allá lejos son realmente grandes.\"}, {\"original\": \"Vergiss nicht, Sonnencreme aufzutragen – die UV-Strahlen hier sind sehr stark.\", \"translated\": \"Recuerda aplicarte protector solar; aquí los rayos UV son muy intensos.\"}, {\"original\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Watte laufen.\", \"translated\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\"}, {\"original\": \"Wie wäre es mit Volleyball am Strand?\", \"translated\": \"¿Qué tal jugar al voleibol en la playa?\"}, {\"original\": \"Die Segelboote in der Ferne sehen wunderschön aus.\", \"translated\": \"Los veleros a lo lejos se ven preciosos.\"}, {\"original\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\", \"translated\": \"El agua aquí es tan transparente que incluso se pueden ver los peces.\"}, {\"original\": \"Lass uns ein paar Muscheln suchen.\", \"translated\": \"Vamos a buscar algunas conchas.\"}, {\"original\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\", \"translated\": \"Pasear por la playa al atardecer debe ser muy romántico.\"}, {\"original\": \"Ich habe gehört, dass die Meeresfrüchte hier sehr frisch sind – lasst uns welche probieren!\", \"translated\": \"He oído que los mariscos aquí son muy frescos; ¡vamos a probarlos!\"}, {\"original\": \"Die Flut kommt herein – gehen wir zurück zum Ufer.\", \"translated\": \"La marea está subiendo; volvamos hacia la orilla.\"}]', 9, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Redewendungen für lokale Veranstaltungen und Feste nennen?\", \"Toll! Hier sind 10 gängige Redewendungen zu lokalen Veranstaltungen und Festen – inklusive spanischer Übersetzungen:\"]', '[\"Veranstaltungen besuchen\", \"Feste feiern\", \"Kultur kennenlernen\"]', 'de', '[\"Könnten Sie mir vorerst bitte den Kontext der lokalen Veranstaltung oder des Festes nennen, an dem Sie teilnehmen möchten – zum Beispiel Halloween, ein Konzert, eine Party bei Freunden oder etwas anderes? Bitte geben Sie den Kontext an.\", \"Bitte beschreiben Sie die Aktivitäten, die Ihnen vorschweben.\"]', '[\"Haben Sie eine bestimmte Situation im Kopf? Fragen Sie ruhig einfach nach.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[{\"original\": \"Gibt es heute irgendwelche Veranstaltungen?\", \"translated\": \"¿Hay algún evento hoy?\"}, {\"original\": \"Gibt es bei diesem Fest etwas Besonderes?\", \"translated\": \"¿Hay algo especial en este festival?\"}, {\"original\": \"Wo findet die Feier statt?\", \"translated\": \"¿Dónde se celebra la festividad?\"}, {\"original\": \"Wie kann ich Tickets kaufen?\", \"translated\": \"¿Cómo puedo comprar entradas?\"}, {\"original\": \"Wann beginnt die Vorstellung?\", \"translated\": \"¿A qué hora empieza la actuación?\"}, {\"original\": \"Welche traditionellen Speisen gibt es?\", \"translated\": \"¿Qué comidas tradicionales hay?\"}, {\"original\": \"Es ist hier wirklich lebhaft!\", \"translated\": \"¡Aquí hay mucha animación!\"}, {\"original\": \"Gibt es Volksaktivitäten?\", \"translated\": \"¿Hay actividades folclóricas?\"}, {\"original\": \"Frohe Feiertage!\", \"translated\": \"¡Felices fiestas!\"}, {\"original\": \"Wann endet die Veranstaltung?\", \"translated\": \"¿A qué hora termina el evento?\"}]', 10, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir bitte 10 häufig verwendete Redewendungen für Museen oder Kunstmuseen nennen?\", \"Fantastisch! Hier sind 10 gängige Redewendungen im Zusammenhang mit Museen oder Kunstmuseen – inklusive spanischer Übersetzungen:\"]', '[\"Besuch\", \"Geführte Tour\", \"Tickets kaufen\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf, z. B. die Bitte um ein Einführungshandbuch, Redewendungen zum Lageplan, Formulierungen zur Kommentierung von Exponaten? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"¿Cuál es el precio de la entrada?\"}, {\"original\": \"Haben Sie Audioführungen?\", \"translated\": \"¿Tienen audioguías?\"}, {\"original\": \"Wer hat dieses Kunstwerk geschaffen?\", \"translated\": \"¿Quién creó esta obra de arte?\"}, {\"original\": \"Wo befindet sich das wertvollste Stück des Museums?\", \"translated\": \"¿Dónde se encuentra la pieza más valiosa del museo?\"}, {\"original\": \"Ist Fotografieren erlaubt?\", \"translated\": \"¿Está permitida la fotografía?\"}, {\"original\": \"Gibt es hier besondere Ausstellungen?\", \"translated\": \"¿Hay aquí exposiciones especiales?\"}, {\"original\": \"Wie lange dauert der Besuch?\", \"translated\": \"¿Cuánto tiempo dura la visita?\"}, {\"original\": \"Könnten Sie uns bitte eine Einführung geben?\", \"translated\": \"¿Podrían darnos una introducción?\"}, {\"original\": \"Diese Werke sind wirklich exquisit.\", \"translated\": \"Estas obras son verdaderamente exquisitas.\"}, {\"original\": \"Wo befindet sich der Souvenirladen?\", \"translated\": \"¿Dónde está la tienda de souvenirs?\"}]', 11, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich in einem Café verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Café – inklusive spanischer Übersetzungen:\"]', '[\"Kaffee bestellen\", \"Ausruhen\", \"Sozialisieren\"]', 'de', '[\"Für den Moment: Haben Sie eine konkrete Situation im Kopf? Zum Beispiel nach der Speisekarte fragen, nach Eis- oder Heißgetränken, nach anderen Produkten – fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[]', '[{\"original\": \"Ich nehme einen Latte, bitte.\", \"translated\": \"Quisiera un latte, por favor.\"}, {\"original\": \"Haben Sie WLAN?\", \"translated\": \"¿Tienen conexión Wi-Fi?\"}, {\"original\": \"Könnte ich bitte die Speisekarte sehen?\", \"translated\": \"¿Podría ver el menú, por favor?\"}, {\"original\": \"Sind Nachfüllungen erlaubt?\", \"translated\": \"¿Se permiten recargas?\"}, {\"original\": \"Ist mein Kaffee schon fertig?\", \"translated\": \"¿Ya está listo mi café?\"}, {\"original\": \"Wie lange darf ich hier sitzen bleiben?\", \"translated\": \"¿Cuánto tiempo puedo quedarme sentado/a aquí?\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"¿Podría hacernos una foto, por favor?\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"Die Rechnung, bitte. Vielen Dank.\", \"translated\": \"La cuenta, por favor. Gracias.\"}, {\"original\": \"Es schmeckt wirklich gut.\", \"translated\": \"Sabe realmente delicioso.\"}]', 12, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Puede proporcionarme 10 frases comunes que pueda usar en un restaurante?\", \"¡Excelente! Aquí tiene 10 frases comunes relacionadas con restaurantes, con traducción al árabe:\"]', '[\"Comer\", \"Hacer un pedido\", \"Pagar la cuenta\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir bebidas, presentar una queja o preguntar sobre ingredientes? ¡No dude en preguntar!\", \"Por favor, describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Disculpe, ¿cuánto tiempo más tardará nuestra comida?\", \"translated\": \"عذرًا، كم من الوقت سيستغرق وصول طعامنا؟\"}, {\"original\": \"Una mesa para dos, por favor.\", \"translated\": \"طاولة لشخصين، من فضلك.\"}, {\"original\": \"¿Podríamos ver el menú, por favor?\", \"translated\": \"هل يمكننا رؤية القائمة، من فضلك؟\"}, {\"original\": \"¿Tienen algún plato especial que nos recomiende?\", \"translated\": \"هل لديكم أي أطباق مميزة توصون بها؟\"}, {\"original\": \"Quisiera pedir esto y esto.\", \"translated\": \"أود طلب هذا وهذا.\"}, {\"original\": \"Un vaso de agua, por favor. Gracias.\", \"translated\": \"كوب ماء، من فضلك. شكرًا لك.\"}, {\"original\": \"La cuenta, por favor.\", \"translated\": \"الفاتورة، من فضلك.\"}, {\"original\": \"¿Puedo pagar con tarjeta de crédito?\", \"translated\": \"هل يمكنني الدفع باستخدام بطاقة الائتمان؟\"}, {\"original\": \"¿Podría empaquetar esto para llevar, por favor?\", \"translated\": \"هل يمكنكم تغليف هذا لأخذه معي، من فضلك؟\"}, {\"original\": \"La comida estuvo deliciosa, gracias.\", \"translated\": \"كان الطعام لذيذًا جدًّا، شكرًا لكم.\"}]', 1, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Puede proporcionarme 10 frases útiles que pueda usar en un hotel?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con hoteles, con su traducción al árabe:\"]', '[\"Registro de entrada\", \"Registro de salida\", \"Servicio de habitaciones\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como la ubicación de la habitación, otros servicios del hotel o el registro de salida? ¡No dude en preguntar!\", \"Por favor, descríbame la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Hola, tengo una reservación. Aquí está mi pasaporte.\", \"translated\": \"مرحبًا، لدي حجزٌ. إليك جواز سفري.\"}, {\"original\": \"¿Tienen habitaciones disponibles?\", \"translated\": \"هل لديكم غرف شاغرة؟\"}, {\"original\": \"Disculpe, ¿tiene el hotel gimnasio o sala de lavandería?\", \"translated\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة غسيل؟\"}, {\"original\": \"¿A qué hora comienza el desayuno?\", \"translated\": \"في أي وقت يبدأ الإفطار؟\"}, {\"original\": \"¿Podría darme la llave de la habitación, por favor?\", \"translated\": \"هل يمكنكم أن تعطوني مفتاح الغرفة من فضلكم؟\"}, {\"original\": \"¿Podría ayudarme a llevar mi equipaje a la habitación?\", \"translated\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\"}, {\"original\": \"¿Cómo llamo al servicio de habitaciones?\", \"translated\": \"كيف أطلب خدمة الغرف؟\"}, {\"original\": \"¿A qué hora es la salida del hotel?\", \"translated\": \"في أي وقت تتم عملية تسجيل المغادرة؟\"}, {\"original\": \"¿Podría darme un recibo/factura, por favor?\", \"translated\": \"هل يمكنكم إعطائي إيصالاً/فاتورة، من فضلكم؟\"}, {\"original\": \"¿Puedo dejar mi equipaje aquí?\", \"translated\": \"هل يمكنني ترك أمتعتي هنا؟\"}]', 2, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Puede proporcionarme 10 frases comunes que pueda usar en el aeropuerto?\", \"¡Qué genial! Aquí tienes 10 frases comunes sobre el aeropuerto, con su traducción al árabe:\"]', '[\"Facturación\", \"Embarque\", \"Facturación de equipaje\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como facturación, reclamo de equipaje o servicio de alquiler de coches? ¡No dude en preguntar!\", \"Por favor, describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Dónde está el mostrador de facturación?\", \"translated\": \"أين يكون مكتب تسجيل الدخول؟\"}, {\"original\": \"Quisiera un asiento junto a la ventana, por favor.\", \"translated\": \"أود أن أحجز مقعداً بجانب النافذة، من فضلك.\"}, {\"original\": \"¿Este vuelo tiene retraso?\", \"translated\": \"هل هذا الرحلة متأخرة؟\"}, {\"original\": \"Necesito facturar este equipaje.\", \"translated\": \"أحتاج إلى تسجيل هذه الأمتعة.\"}, {\"original\": \"¿Dónde está la puerta de embarque?\", \"translated\": \"أين تكون بوابة الصعود إلى الطائرة؟\"}, {\"original\": \"El avión está a punto de despegar.\", \"translated\": \"الطائرة على وشك الإقلاع.\"}, {\"original\": \"¿Necesito sacar mi computadora portátil y mi banco de energía?\", \"translated\": \"هل يجب أن أخرج جهازي اللوحي المحمول وبنك الطاقة الخاص بي؟\"}, {\"original\": \"¿Dónde está la tienda libre de impuestos?\", \"translated\": \"أين توجد متجر التسوق المعفي من الضرائب؟\"}, {\"original\": \"No puedo encontrar mi maleta.\", \"translated\": \"لا أستطيع العثور على حقيبتي.\"}, {\"original\": \"¿Ofrecen servicio de sillas de ruedas?\", \"translated\": \"هل تقدمون خدمة الكراسي المتحركة؟\"}]', 3, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Puede proporcionarme 10 frases comunes que pueda usar en el transporte público?\", \"¡Genial! Aquí tiene 10 frases comunes sobre el transporte público, con traducción al árabe:\"]', '[\"Tomar autobús o metro\", \"Comprar boletos\", \"Hacer transbordo\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como preguntar por la parada de autobús, el precio del boleto o bajarse? ¡No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Este autobús va a la terminal?\", \"translated\": \"هل هذه الحافلة تتجه إلى المحطة؟\"}, {\"original\": \"¿Cuál es la próxima parada?\", \"translated\": \"ما هي المحطة التالية؟\"}, {\"original\": \"¿Dónde puedo comprar un billete?\", \"translated\": \"أين يمكنني شراء تذكرة؟\"}, {\"original\": \"Un billete para XX, por favor.\", \"translated\": \"تذكرة واحدة إلى XX، من فضلك.\"}, {\"original\": \"¿Necesito hacer transbordo?\", \"translated\": \"هل عليّ التحويل؟\"}, {\"original\": \"¿Cuánto tiempo falta para el próximo tren del metro?\", \"translated\": \"كم من الوقت يبقى حتى قطار المترو القادم؟\"}, {\"original\": \"Disculpe, permítame pasar.\", \"translated\": \"عذرًا، من فضلك اسمح لي بالمرور.\"}, {\"original\": \"¿Esta plaza está ocupada?\", \"translated\": \"هل هذا المقعد مشغول؟\"}, {\"original\": \"Disculpe, ¿dónde puedo transbordar a la Línea 2 para llegar a XX?\", \"translated\": \"عذرًا، أين يمكنني التحويل إلى الخط ٢ للوصول إلى XX؟\"}, {\"original\": \"¿Cómo llego a XX?\", \"translated\": \"كيف أصل إلى XX؟\"}]', 4, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Puede proporcionarme 10 frases comunes que pueda usar en lugares turísticos?\", \"¡Estupendo! Aquí tiene 10 frases comunes sobre lugares turísticos, con traducción al árabe:\"]', '[\"Turismo\", \"Tomar fotos\", \"Comprar entradas\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como preguntar sobre el precio de las entradas, encontrar un estacionamiento o solicitar un servicio de guía turística? ¡No dude en preguntar!\", \"Por favor, describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"كم تكلفة رسوم الدخول؟\"}, {\"original\": \"¿Hay entradas para estudiantes disponibles?\", \"translated\": \"هل تتوفر تذاكر للطلاب؟\"}, {\"original\": \"¿A qué hora abre la atracción?\", \"translated\": \"في أي وقت تفتح المعالم السياحية؟\"}, {\"original\": \"¿Qué cosas divertidas se pueden hacer aquí?\", \"translated\": \"ما الأنشطة الممتعة التي يمكن القيام بها هنا؟\"}, {\"original\": \"¿Podría hacernos una foto?\", \"translated\": \"هل يمكنك أن تلتقط لنا صورة؟\"}, {\"original\": \"¿Dónde está el autobús turístico?\", \"translated\": \"أين يقع باص الجولات السياحية؟\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"أين هو الحمام؟\"}, {\"original\": \"¿Cuál es el mejor lugar para disfrutar de la vista?\", \"translated\": \"ما أفضل مكان للاستمتاع بالمنظر؟\"}, {\"original\": \"El paisaje aquí es hermoso.\", \"translated\": \"المنظر هنا جميل جدًا.\"}, {\"original\": \"¿Hay visitas guiadas disponibles?\", \"translated\": \"هل تتوفر جولات إرشادية؟\"}]', 5, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Puedes proporcionarme 10 frases comunes que pueda usar para tomar un taxi o contratar un servicio de taxis?\", \"¡Genial! Aquí tienes 10 frases comunes relacionadas con los taxis o servicios de taxis, con su traducción al árabe:\"]', '[\"Tomar un taxi\", \"Indicar el destino\", \"Pago\"]', 'es', '[\"Por ahora, ¿qué es lo que más quieres hacer ahora? Por ejemplo: preguntar la dirección, el precio o solicitar un recibo. ¡No dudes en preguntar!\", \"Por favor, descríbeme la situación que tienes en mente.\"]', '[]', '[{\"original\": \"¿Dónde puedo conseguir un taxi?\", \"translated\": \"أين يمكنني أن أحصل على تاكسي؟\"}, {\"original\": \"Por favor, lléveme a esta dirección.\", \"translated\": \"من فضلك خذني إلى هذا العنوان.\"}, {\"original\": \"¿Cuánto costará aproximadamente?\", \"translated\": \"كم سيكلفك تقريبًا؟\"}, {\"original\": \"¿Podría usar el taxímetro, por favor?\", \"translated\": \"هل يمكنك استخدام عداد الأجرة، من فضلك؟\"}, {\"original\": \"Por favor, conduzca un poco más rápido, tengo prisa.\", \"translated\": \"من فضلك قُدْ بسرعةٍ أكبر قليلًا، فأنا مسرع.\"}, {\"original\": \"Deténgase aquí, por favor.\", \"translated\": \"توقف هنا من فضلك.\"}, {\"original\": \"¿Acepta tarjetas o pagos móviles?\", \"translated\": \"هل تقبل البطاقات أو الدفع عبر الهاتف المحمول؟\"}, {\"original\": \"¿Podría darme un recibo, por favor?\", \"translated\": \"هل يمكنني الحصول على إيصال، من فضلك؟\"}, {\"original\": \"Gracias, conductor.\", \"translated\": \"شكراً لك يا سائق.\"}, {\"original\": \"¿Cuánto falta todavía?\", \"translated\": \"كم تبقى بعدُ من المسافة؟\"}]', 6, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Puede proporcionarme 10 frases comunes que pueda usar en una farmacia?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con la farmacia, con su traducción al árabe:\"]', '[\"Compra de medicamentos\", \"Consulta\", \"Pago\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir instrucciones sobre cómo tomar un medicamento, frases relacionadas con el uso del seguro médico o la duración del tratamiento? No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Tiene medicamento para el resfriado?\", \"translated\": \"هل لديك دواء لنزلات البرد؟\"}, {\"original\": \"كيف يجب أن آخذ هذا الدواء؟\", \"translated\": \"كيف يجب أن أتناول هذا الدواء؟\"}, {\"original\": \"¿Tiene algún analgésico?\", \"translated\": \"هل لديك أي مسكنات للألم؟\"}, {\"original\": \"¿Viene con un folleto de instrucciones?\", \"translated\": \"هل يحتوي على كتيب إرشادات؟\"}, {\"original\": \"¿Este medicamento tiene efectos secundarios?\", \"translated\": \"هل لهذا الدواء أي آثار جانبية؟\"}, {\"original\": \"¿Puedo usar mi tarjeta de seguro médico?\", \"translated\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\"}, {\"original\": \"¿Podría darme una caja de tiritas, por favor?\", \"translated\": \"هل يمكنني الحصول على علبة من الشاش الطبي (اللصقات) من فضلكم؟\"}, {\"original\": \"¿Tiene algún antipirético?\", \"translated\": \"هل لديك أي خافض للحرارة؟\"}, {\"original\": \"Tengo una pequeña raspadura. ¿Tiene antiséptico y tiritas?\", \"translated\": \"لدي جرح سطحي صغير. هل لديكم مطهر ولصقات طبية؟\"}, {\"original\": \"¿A qué hora cierran?\", \"translated\": \"في أي وقت تغلقون؟\"}]', 7, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Puede proporcionarme 10 frases comunes que pueda usar en servicios de emergencia?\", \"¡Excelente! Aquí tiene 10 frases comunes relacionadas con servicios de emergencia, con sus traducciones al árabe:\"]', '[\"Llamar a la policía\", \"Primeros auxilios\", \"Pedir ayuda\"]', 'es', '[\"Por ahora, ¿tiene alguna situación de emergencia específica en mente, como incendio, persona herida y que necesita ayuda, o una llamada de emergencia? ¡No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', '[]', '[{\"original\": \"Por favor, ayúdeme a llamar a una ambulancia.\", \"translated\": \"من فضلك ساعدني في استدعاء سيارة إسعاف.\"}, {\"original\": \"¿Dónde está el hospital?\", \"translated\": \"أين находится المستشفى؟\"}, {\"original\": \"Alguien resultó herido.\", \"translated\": \"شخص ما أُصيب.\"}, {\"original\": \"Por favor, ayúdeme.\", \"translated\": \"من فضلك ساعدني.\"}, {\"original\": \"¿Dónde está la comisaría de policía?\", \"translated\": \"أين تقع أقرب مركز شرطة؟\"}, {\"original\": \"He perdido mis pertenencias.\", \"translated\": \"لقد فقدت أغراضي.\"}, {\"original\": \"¿Cuál es el número del departamento de bomberos?\", \"translated\": \"ما هو رقم دائرة الإطفاء؟\"}, {\"original\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría de policía más cercana?\", \"translated\": \"لقد فقدت جواز سفري. هل تعرف أين تقع أقرب مركز شرطة؟\"}, {\"original\": \"¿Hay una salida de emergencia?\", \"translated\": \"هل توجد مخرج طوارئ؟\"}, {\"original\": \"Alguien ha perdido el conocimiento.\", \"translated\": \"شخص ما أغمي عليه.\"}]', 8, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Puede proporcionarme 10 frases comunes que pueda usar en un museo o galería de arte?\", \"¡Genial! Aquí tiene 10 frases comunes sobre museos o galerías de arte, con traducción al árabe:\"]', '[\"Visita\", \"Visita guiada\", \"Compra de entradas\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir un manual introductorio, frases relacionadas con un plano orientativo o frases para comentar las exhibiciones? ¡No dude en preguntar!\", \"Por favor, describa la situación que tiene en mente.\"]', '[]', '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"¿Tienen guías de audio?\", \"translated\": \"هل لديكم دلائل صوتية؟\"}, {\"original\": \"¿Quién creó esta obra de arte?\", \"translated\": \"من هو الفنان الذي أنشأ هذه القطعة الفنية؟\"}, {\"original\": \"¿Dónde se encuentra la pieza más valiosa del museo?\", \"translated\": \"أين تقع أثمن قطعة في المتاحف؟\"}, {\"original\": \"¿Está permitida la fotografía?\", \"translated\": \"هل يُسمح بالتصوير الفوتوغرافي؟\"}, {\"original\": \"¿Hay alguna exposición especial aquí?\", \"translated\": \"هل توجد أي معارض خاصة هنا؟\"}, {\"original\": \"¿Cuánto tiempo dura la visita?\", \"translated\": \"كم تستغرق الجولة من الوقت؟\"}, {\"original\": \"¿Podrían darnos una introducción?\", \"translated\": \"هل يمكنكم إعطاؤنا مقدمة؟\"}, {\"original\": \"Estas obras son verdaderamente exquisitas.\", \"translated\": \"هذه الأعمال رائعةٌ حقًّا.\"}, {\"original\": \"¿Dónde está la tienda de souvenirs?\", \"translated\": \"أين تقع متجر الهدايا التذكارية؟\"}]', 11, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en actividades y festivales locales?\", \"¡Genial! Aquí tienes 10 frases comunes sobre las actividades y festivales locales, con su traducción al árabe:\"]', '[\"Asistir a eventos\", \"Celebrar festivales\", \"Aprender sobre la cultura\"]', 'es', '[\"Por ahora, ¿podría proporcionarme el contexto del evento o festival local al que asiste, como Halloween, un concierto o una fiesta con amigos, o algo más? Por favor, proporcione el contexto.\", \"Por favor, describa las actividades que tiene en mente.\"]', '[\"¿Tiene una situación específica en mente? Siéntase libre de preguntar.\", \"Por favor, describa la situación que tiene en mente.\"]', '[{\"original\": \"¿Hay algún evento hoy?\", \"translated\": \"هل هناك أي حدث اليوم؟\"}, {\"original\": \"هل هناك شيء خاص حول هذا المهرجان؟\", \"translated\": \"هل يوجد شيء مميز في هذا المهرجان؟\"}, {\"original\": \"¿Dónde se celebra el evento?\", \"translated\": \"أين يُعقد الاحتفال؟\"}, {\"original\": \"¿Cómo puedo comprar boletos?\", \"translated\": \"كيف يمكنني شراء التذاكر؟\"}, {\"original\": \"¿A qué hora comienza la presentación?\", \"translated\": \"ما هو وقت بدء العرض؟\"}, {\"original\": \"¿Qué tipo de comida tradicional hay?\", \"translated\": \"ما هي أنواع الطعام التقليدية المتاحة؟\"}, {\"original\": \"Está realmente animado aquí.\", \"translated\": \"إنها حقًا حيوية هنا.\"}, {\"original\": \"¿Hay alguna actividad folclórica?\", \"translated\": \"هل هناك أي أنشطة شعبية؟\"}, {\"original\": \"Felices fiestas!\", \"translated\": \"عيد سعيد!\"}, {\"original\": \"¿A qué hora termina el evento?\", \"translated\": \"ما هو وقت انتهاء الحدث؟\"}]', 10, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en la playa o junto a la piscina?\", \"¡Genial! Aquí tienes 10 frases comunes sobre la playa o la piscina, con su traducción al árabe:\"]', '[\"Nadar\", \"Tomar el sol\", \"Deportes de playa\"]', 'es', '[\"Por ahora, ¿podría proporcionarme el contexto del evento local o festival al que asiste, como un festival cultural, gastronómico o musical? Por favor, proporcione el contexto.\", \"Por favor, proporcione las actividades a las que asiste.\"]', '[\"¿Tiene una situación específica en mente? No dudes en preguntar.\", \"Por favor, describa la situación que tiene en mente.\"]', '[{\"original\": \"¡Mira! Las olas allí son muy grandes.\", \"translated\": \"انظر! الأمواج هناك كبيرة جداً.\"}, {\"original\": \"No olvides aplicar protector solar, los rayos UV aquí son muy fuertes.\", \"translated\": \"لا تنسَ وضع واقي الشمس، أشعة فوق البنفسجية هنا قوية جداً.\"}, {\"original\": \"La arena en esta playa es tan fina, se siente como caminar sobre algodón.\", \"translated\": \"الرمل في هذه الشاطئ ناعم جداً، يشعر وكأنك تسير على القطن.\"}, {\"original\": \"¿Qué tal jugar al voleibol en la playa?\", \"translated\": \"ماذا عن اللعب بالكرة الطائرة على الشاطئ؟\"}, {\"original\": \"Los veleros a lo lejos se ven hermosos.\", \"translated\": \"يبدو القوارب الشراعية البعيدة جميلة.\"}, {\"original\": \"El agua aquí es tan clara que incluso puedes ver los peces.\", \"translated\": \"الماء هنا شفاف جداً بحيث يمكنك رؤية الأسماك.\"}, {\"original\": \"Vamos a buscar algunas conchas marinas.\", \"translated\": \"دعونا نبحث عن بعض الأصداف البحرية.\"}, {\"original\": \"Caminar por la playa al atardecer debe ser muy romántico.\", \"translated\": \"سير على الشاطئ عند الغروب يجب أن يكون رومانسياً للغاية.\"}, {\"original\": \"Escuché que el marisco aquí es muy fresco, vamos a probarlo.\", \"translated\": \"سمعت أن المأكولات البحرية هنا طازجة جدًا، دعنا نجربها.\"}, {\"original\": \"La marea está subiendo, vamos hacia la orilla.\", \"translated\": \"المد آتٍ، دعنا نتجه نحو الشاطئ.\"}]', 9, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en una cafetería?\", \"¡Genial! Aquí tienes 10 frases comunes sobre cafeterías, con su traducción al árabe:\"]', '[\"Pedir Café\", \"Descansar\", \"Socializar\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como pedir la carta, bebidas heladas o calientes, otros productos? Pregunta libremente.\", \"Por favor, describe la situación que tienes en mente.\"]', '[]', '[{\"original\": \"Me gustaría un latte, por favor.\", \"translated\": \"أريد لاتيه، من فضلك.\"}, {\"original\": \"¿Tienen Wi-Fi?\", \"translated\": \"هل لديكم واي فاي؟\"}, {\"original\": \"¿Podría ver el menú, por favor?\", \"translated\": \"هل يمكنني رؤية القائمة من فضلك؟\"}, {\"original\": \"¿Se permiten los rellenos?\", \"translated\": \"هل يُسمح بإعادة التعبئة؟\"}, {\"original\": \"¿Mi café está listo?\", \"translated\": \"هل قهوتي جاهزة؟\"}, {\"original\": \"¿Cuánto tiempo puedo quedarme aquí?\", \"translated\": \"كم من الوقت يمكنني الجلوس هنا؟\"}, {\"original\": \"¿Podrías tomar una foto para nosotros?\", \"translated\": \"هل يمكنك التقاط صورة لنا؟\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"أين هو الحمام؟\"}, {\"original\": \"La cuenta, por favor. Gracias.\", \"translated\": \"الحساب من فضلك. شكراً لك.\"}, {\"original\": \"Sabe realmente bien.\", \"translated\": \"طعمه حقاً رائع.\"}]', 12, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un restaurante?\", \"¡Fantástico! Aquí tienes 10 frases comunes relacionadas con restaurantes, junto con las traducciones al japonés：\"]', '[\"Comer\", \"Pedir\", \"Cobro\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como pedir bebidas, hacer una queja o preguntar sobre ingredientes? Puedes preguntar libremente.\", \"Por favor, describe la situación que tienes en mente.\"]', '[]', '[{\"original\": \"Disculpe, ¿cuánto tiempo más tardará nuestra comida?\", \"translated\": \"すみません、私たちの料理はもう少しででき上がりますか？\"}, {\"original\": \"Por favor, una mesa para dos.\", \"translated\": \"2人用のテーブルをお願いします。\"}, {\"original\": \"¿Podríamos ver el menú, por favor?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"おすすめの看板料理はありますか？\", \"translated\": \"お勧めの料理はありますか？\"}, {\"original\": \"Esto y esto me gustaría pedir.\", \"translated\": \"これとこれを注文したいです。\"}, {\"original\": \"Por favor, un vaso de agua. Gracias.\", \"translated\": \"水を一杯お願いします。ありがとうございます。\"}, {\"original\": \"Por favor, la cuenta.\", \"translated\": \"お会計をお願いします。\"}, {\"original\": \"¿Puedo pagar con tarjeta de crédito?\", \"translated\": \"クレジットカードでお支払いできますか？\"}, {\"original\": \"Por favor, empaquételo para llevar.\", \"translated\": \"これをお持ち帰りにパックしていただけますか？\"}, {\"original\": \"La comida estaba deliciosa, gracias.\", \"translated\": \"料理がとても美味しかったです、ありがとうございます。\"}]', 1, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Me podría proporcionar 10 frases comunes que puedo usar en un hotel?\", \"¡Genial! Aquí tienes 10 frases comunes relacionadas con hoteles, junto con sus traducciones al japonés:\"]', '[\"Hacer el check-in\", \"Hacer el check-out\", \"Servicio de habitaciones\"]', 'es', '[\"Por ahora, ¿tienes alguna situación específica en mente, como la ubicación de la habitación, algún otro servicio del hotel o el check-out? Pregunta libremente.\", \"Por favor, describe la situación que tienes en mente.\"]', '[]', '[{\"original\": \"Hola, tengo una reserva, aquí está mi pasaporte.\", \"translated\": \"こんにちは、予約をしています。パスポートです。\"}, {\"original\": \"Tienen alguna habitación disponible?\", \"translated\": \"空いている部屋はありますか？\"}, {\"original\": \"Disculpe, ¿el hotel tiene gimnasio o lavandería?\", \"translated\": \"すみません、ホテルにジムやランドリーはありますか？\"}, {\"original\": \"El desayuno a qué hora empieza?\", \"translated\": \"朝食は何時からですか？\"}, {\"original\": \"¿Me das la llave de la habitación, por favor?\", \"translated\": \"部屋のキーをください。\"}, {\"original\": \"¿Podrías ayudarme a llevar mi equipaje a la habitación?\", \"translated\": \"荷物を部屋まで運んでいただけますか？\"}, {\"original\": \"¿Cómo se llama al servicio de habitaciones?\", \"translated\": \"ルームサービスをどうやって呼び出しますか？\"}, {\"original\": \"A qué hora es el check-out?\", \"translated\": \"チェックアウトは何時ですか？\"}, {\"original\": \"¿Me podrías escribir un recibo/factura?\", \"translated\": \"領収書または請求書を書いていただけますか？\"}, {\"original\": \"¿Puedo dejar mi equipaje aquí?\", \"translated\": \"ここで荷物を預けられますか？\"}]', 2, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en la playa o junto a la piscina?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con la playa o la piscina, junto con sus traducciones al japonés:\"]', '[\"Nadar\", \"Tomar el sol\", \"Practicar deportes playeros\"]', 'es', '[\"Por ahora, ¿podría indicarme el contexto del evento o festival local al que asistirá, como un festival cultural, un festival gastronómico o un festival musical? Por favor, proporcione el contexto.\", \"Por favor, indique las actividades a las que asistirá.\"]', '[\"¿Tiene alguna situación específica en mente? No dude en preguntar.\", \"Por favor, describa la situación que tiene en mente.\"]', '[{\"original\": \"¡Mira! Las olas allí son realmente grandes.\", \"translated\": \"見て！あそこに波がすごく大きいよ。\"}, {\"original\": \"Recuerda aplicar protector solar, aquí los rayos UV son muy intensos.\", \"translated\": \"日焼け止めを塗ることを忘れないでね。ここは紫外線がとても強いんだよ。\"}, {\"original\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\", \"translated\": \"このビーチの砂はとても細かくて、綿の上を歩いているような感じがするよ。\"}, {\"original\": \"¿Qué te parece jugar voleibol en la playa?\", \"translated\": \"ビーチでバレーボールをするのはどう？\"}, {\"original\": \"Los veleros a lo lejos se ven hermosos.\", \"translated\": \"遠くのヨットがとてもきれいに見えるよ。\"}, {\"original\": \"El agua aquí es tan clara que incluso puedes ver los peces.\", \"translated\": \"ここの水はとても透明で、魚まで見えちゃうよ。\"}, {\"original\": \"Vamos a buscar conchas marinas.\", \"translated\": \"貝殻を探しに行こう！\"}, {\"original\": \"Pasear por la playa al atardecer debe ser muy romántico.\", \"translated\": \"夕暮れ時にビーチを散歩するのは、きっととてもロマンチックだろうね。\"}, {\"original\": \"Escuché que el marisco aquí es muy fresco, vayamos a probarlo.\", \"translated\": \"ここでのシーフードはすごく新鮮だって聞いたから、ぜひ食べてみよう！\"}, {\"original\": \"La marea está subiendo, vamos hacia la orilla.\", \"translated\": \"潮が満ちてきているから、浜辺に向かおう。\"}]', 9, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在餐厅常用的说法吗？\", \"太棒了！以下是与餐厅相关的10个常用说法，并附有土耳其语翻译：\"]', '[\"用餐\", \"下单\", \"结账\"]', 'zh', '[\"目前，您心中是否有特定场景，例如点饮料、提出投诉或询问食材？欢迎随时提问。\", \"请描述您心中所想的场景。\"]', NULL, '[{\"original\": \"打扰一下，我们的餐还要等多久？\", \"translated\": \"Affedersiniz, yemeğimiz ne kadar daha sürecektir?\"}, {\"original\": \"请给我们安排一张两人桌。\", \"translated\": \"Lütfen iki kişilik bir masa ayarlayabilir misiniz?\"}, {\"original\": \"请问可以看一下菜单吗？\", \"translated\": \"Menüyü görebilir miyiz, lütfen?\"}, {\"original\": \"你们有什么招牌菜可以推荐吗？\", \"translated\": \"Önerdiğiniz özel yemekleriniz var mı?\"}, {\"original\": \"我要点这个和这个。\", \"translated\": \"Bunu ve bunu sipariş etmek istiyorum.\"}, {\"original\": \"请来一杯水，谢谢。\", \"translated\": \"Lütfen bir bardak su getirir misiniz? Teşekkür ederim.\"}, {\"original\": \"请结账。\", \"translated\": \"Hesabı getirir misiniz, lütfen?\"}, {\"original\": \"我可以刷信用卡付款吗？\", \"translated\": \"Kredi kartıyla ödeme yapabilir miyim?\"}, {\"original\": \"请帮我把这份打包带走。\", \"translated\": \"Lütfen bunu paketleyebilir misiniz?\"}, {\"original\": \"食物非常美味，谢谢。\", \"translated\": \"Yiyecekler çok lezzetliydi, teşekkür ederiz.\"}]', 1, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在酒店场景中常用的表达吗？\", \"太棒了！以下是与酒店相关的10个常用表达，以及对应的土耳其语翻译：\"]', '[\"入住\", \"退房\", \"客房服务\"]', 'zh', '[\"目前，您心中是否有特定的情境？例如房间位置、其他酒店服务或退房等，欢迎随时提问。\", \"请描述您心中所想的情境。\"]', NULL, '[{\"original\": \"你好，我有预订，这是我的护照。\", \"translated\": \"Merhaba, rezervasyonum var, işte pasaportum.\"}, {\"original\": \"你们还有空房吗？\", \"translated\": \"Boş odanız var mı?\"}, {\"original\": \"打扰一下，酒店有健身房或洗衣房吗？\", \"translated\": \"Affedersiniz, otelin bir fitness merkezi veya çamaşırhane bölümü var mı?\"}, {\"original\": \"早餐几点开始？\", \"translated\": \"Kahvaltı saat kaçta başlıyor?\"}, {\"original\": \"请给我一把房卡，谢谢。\", \"translated\": \"Lütfen bana bir oda anahtarı verebilir misiniz?\"}, {\"original\": \"您能帮我把行李送到房间吗？\", \"translated\": \"Lütfen bagajımı odaya taşıyabilir misiniz?\"}, {\"original\": \"我怎么呼叫客房服务？\", \"translated\": \"Oda servisini nasıl arayabilirim?\"}, {\"original\": \"退房时间是几点？\", \"translated\": \"Çıkış saati kaçta?\"}, {\"original\": \"您能给我开一张收据/发票吗？\", \"translated\": \"Bana bir makbuz/fatura verebilir misiniz?\"}, {\"original\": \"我可以把行李寄存在这里吗？\", \"translated\": \"Bagajımı burada bırakabilir miyim?\"}]', 2, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能提供10个在机场常用的短语吗？\", \"太棒了！以下是与机场相关的10个常用短语，以及对应的中文翻译：\"]', '[\"办理登机手续\", \"登机\", \"行李托运\"]', 'zh', '[\"目前，您心中是否有特定场景，例如办理登机手续、行李提取或租车服务？欢迎随时提问。\", \"请描述您心中所想的场景。\"]', NULL, '[{\"original\": \"值机柜台在哪里？\", \"translated\": \"Giriş masası nerede?\"}, {\"original\": \"我想要一个靠窗的座位，谢谢。\", \"translated\": \"Lütfen bir pencere kenarı koltuğu istiyorum.\"}, {\"original\": \"这趟航班延误了吗？\", \"translated\": \"Bu uçuş gecikti mi?\"}, {\"original\": \"我需要托运行李。\", \"translated\": \"Bu bagajı kayıt ettirmem gerekiyor.\"}, {\"original\": \"登机口在哪里？\", \"translated\": \"İniş kapısı nerede?\"}, {\"original\": \"飞机即将起飞。\", \"translated\": \"Uçak kalkmak üzere.\"}, {\"original\": \"我需要把笔记本电脑和充电宝拿出来吗？\", \"translated\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\"}, {\"original\": \"免税店在哪里？\", \"translated\": \"Vergi içermeyen ürün mağazası nerede?\"}, {\"original\": \"我找不到我的行李箱了。\", \"translated\": \"Bavulumu bulamıyorum.\"}, {\"original\": \"你们提供轮椅服务吗？\", \"translated\": \"Te kerli sandalye hizmeti sunuyor musunuz?\"}]', 3, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在公共交通中常用的表达吗？\", \"太棒了！以下是与公共交通相关的10个常用表达，以及对应的土耳其语翻译：\"]', '[\"乘坐公交/地铁\", \"购买车票\", \"换乘\"]', 'zh', '[\"目前，您心里是否有特定的情境，例如询问公交站、票价或下车等？欢迎随时提问。\", \"请描述您心中所想的情境。\"]', NULL, '[{\"original\": \"这趟公交车去终点站吗？\", \"translated\": \"Bu otobüs terminal\'e mi gidiyor?\"}, {\"original\": \"下一站是哪里？\", \"translated\": \"Bir sonraki durak nerede?\"}, {\"original\": \"我在哪里可以买票？\", \"translated\": \"Bilet nereden alınır?\"}, {\"original\": \"请给我一张去XX的车票。\", \"translated\": \"Lütfen XX\'e giden bir bilet verir misiniz?\"}, {\"original\": \"我需要换乘吗？\", \"translated\": \"Aktarma yapmam gerekiyor mu?\"}, {\"original\": \"下一班地铁列车还有多久？\", \"translated\": \"Bir sonraki metro treni ne zaman geliyor?\"}, {\"original\": \"不好意思，请让我过去。\", \"translated\": \"Affedersiniz, geçmem için yer açar mısınız?\"}, {\"original\": \"这个座位有人坐了吗？\", \"translated\": \"Bu koltuk boş mu?\"}, {\"original\": \"不好意思，请问我在哪里换乘2号线去XX？\", \"translated\": \"Affedersiniz, XX\'e gitmek için 2. hat\'a nerede aktarma yapabilirim?\"}, {\"original\": \"我怎么去XX？\", \"translated\": \"XX\'e nasıl giderim?\"}]', 4, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在旅游景点常用的表达吗？\", \"太棒了！以下是与旅游景点相关的10个常用表达，以及对应的土耳其语翻译：\"]', '[\"观光游览\", \"拍照留念\", \"购买门票\"]', 'zh', '[\"目前，您心中是否有特定场景，例如询问门票价格、寻找停车场或导游服务？欢迎随时提问。\", \"请描述您心中所想的场景。\"]', NULL, '[{\"original\": \"门票多少钱？\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"有学生票吗？\", \"translated\": \"Öğrenci biletleri mevcut mu?\"}, {\"original\": \"景点几点开放？\", \"translated\": \"Yerleşim saati kaçta başlar?\"}, {\"original\": \"这里有哪些好玩的活动？\", \"translated\": \"Burada yapılabilecek eğlenceli şeyler nelerdir?\"}, {\"original\": \"您能帮我们拍张照吗？\", \"translated\": \"Bize bir fotoğraf çekebilir misiniz?\"}, {\"original\": \"观光巴士在哪里？\", \"translated\": \"Sightseeing otobüsü nerede?\"}, {\"original\": \"洗手间在哪里？\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"最佳观景点在哪里？\", \"translated\": \"En iyi manzara noktası nerede?\"}, {\"original\": \"这里的风景真美。\", \"translated\": \"Buradaki manzara çok güzel.\"}, {\"original\": \"有导游讲解服务吗？\", \"translated\": \"Rehberli tur mevcut mu?\"}]', 5, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在乘坐出租车或使用出租车服务时常用的表达吗？\", \"太棒了！以下是与出租车或出租车服务相关的10个常用表达，以及对应的土耳其语翻译：\"]', '[\"乘坐出租车\", \"告知目的地\", \"付款\"]', 'zh', '[\"目前，您最想做什么呢？比如询问目的地、车费，或索要发票，欢迎随时提问。\", \"请描述您脑海中设想的情境。\"]', NULL, '[{\"original\": \"我在哪里可以打到出租车？\", \"translated\": \"Bir taksi nerede bulabilirim?\"}, {\"original\": \"请送我去这个地址。\", \"translated\": \"Lütfen beni bu adrese götürün.\"}, {\"original\": \"大概需要多少钱？\", \"translated\": \"Yaklaşık olarak ne kadar tutar?\"}, {\"original\": \"请您打表计费，好吗？\", \"translated\": \"Lütfen taksimetreyle ücretlendirir misiniz?\"}, {\"original\": \"请开快一点，我赶时间。\", \"translated\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\"}, {\"original\": \"请在这里停车。\", \"translated\": \"Lütfen burada durur musunuz?\"}, {\"original\": \"您接受银行卡或手机支付吗？\", \"translated\": \"Kart veya mobil ödeme kabul ediyor musunuz?\"}, {\"original\": \"可以给我一张收据吗？\", \"translated\": \"Bana bir makbuz verebilir misiniz?\"}, {\"original\": \"谢谢，司机师傅。\", \"translated\": \"Teşekkür ederim, şoför bey.\"}, {\"original\": \"还有多远？\", \"translated\": \"Kaç dakika kaldı?\"}]', 6, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个药房常用表达吗？\", \"太棒了！以下是与药房相关的10个常用表达，以及对应的土耳其语翻译：\"]', '[\"购买药品\", \"咨询\", \"支付\"]', 'zh', '[\"目前，您心中是否有特定场景？例如询问服药说明、与使用保险相关的问题、用药时长等，欢迎随时提问。\", \"请描述您心中设想的场景。\"]', NULL, '[{\"original\": \"你们有感冒药吗？\", \"translated\": \"Soğuk algınlığı ilacı var mı?\"}, {\"original\": \"我该怎么服用这种药？\", \"translated\": \"Bu ilacı nasıl kullanmalıyım?\"}, {\"original\": \"你们有止痛药吗？\", \"translated\": \"Ağrı kesici ilaç var mı?\"}, {\"original\": \"有说明书吗？\", \"translated\": \"Kullanım kılavuzu var mı?\"}, {\"original\": \"这种药有什么副作用吗？\", \"translated\": \"Bu ilacın yan etkileri var mı?\"}, {\"original\": \"我能用我的医保卡吗？\", \"translated\": \"Sağlık sigortamı kullanabilir miyim?\"}, {\"original\": \"请给我一盒创可贴，谢谢。\", \"translated\": \"Bir kutu yara bandı verebilir misiniz, lütfen?\"}, {\"original\": \"你们有退烧药吗？\", \"translated\": \"Ateş düşürücü ilaç var mı?\"}, {\"original\": \"我有点擦伤，你们有消毒剂和创可贴吗？\", \"translated\": \"Hafif bir sıyrık var, antiseptik ve yara bandı var mı?\"}, {\"original\": \"你们几点关门？\", \"translated\": \"Kaçta kapanıyorsunuz?\"}]', 7, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在紧急服务中常用的短语吗？\", \"太棒了！以下是与紧急服务相关的10个常用短语，以及对应的土耳其语翻译：\"]', '[\"报警\", \"急救\", \"呼救\"]', 'zh', '[\"目前，您脑海中是否有特定的紧急情况，例如火灾、受伤需要帮助、紧急电话等？欢迎随时提问。\", \"请描述您脑海中设想的情况。\"]', NULL, '[{\"original\": \"请帮我叫一辆救护车。\", \"translated\": \"Lütfen bana bir ambulans çağırın.\"}, {\"original\": \"医院在哪里？\", \"translated\": \"Hastane nerede?\"}, {\"original\": \"有人受伤了。\", \"translated\": \"Birisi yaralandı.\"}, {\"original\": \"请帮帮我。\", \"translated\": \"Lütfen bana yardım edin.\"}, {\"original\": \"警察局在哪里？\", \"translated\": \"Polis karakolu nerede?\"}, {\"original\": \"我的物品丢失了。\", \"translated\": \"Eşyalarımı kaybettim.\"}, {\"original\": \"消防部门的电话号码是多少？\", \"translated\": \"Yangın departmanının telefon numarası nedir?\"}, {\"original\": \"我的护照丢失了。您知道最近的警察局在哪里吗？\", \"translated\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\"}, {\"original\": \"有紧急出口吗？\", \"translated\": \"Acil çıkış var mı?\"}, {\"original\": \"有人晕倒了。\", \"translated\": \"Birisi bayıldı.\"}]', 8, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在海滩或泳池边常用的表达吗？\", \"太棒了！以下是与海滩或泳池边相关的10个常用表达，以及对应的土耳其语翻译：\"]', '[\"游泳\", \"日光浴\", \"海滩运动\"]', 'zh', '[\"目前，请您提供您将要参加的当地活动或节日的背景信息，例如文化节、美食节或音乐节。请说明具体背景。\", \"请您提供您将要参加的活动内容。\"]', '[\"您心中是否有特定的情境？欢迎随时提问。\", \"请描述您心中设想的具体情境。\"]', '[{\"original\": \"看！那边的海浪真大。\", \"translated\": \"Bakın! Oradaki dalgalar gerçekten büyük.\"}, {\"original\": \"记得涂防晒霜，这里的紫外线很强。\", \"translated\": \"Güneş koruyucu sürmeyi unutmayın, buradaki UV ışınları çok güçlü.\"}, {\"original\": \"这个海滩的沙子非常细腻，踩上去像踩在棉花上。\", \"translated\": \"Bu plajdaki kum çok ince, pamuk üzerinde yürüyormuş gibi hissettiriyor.\"}, {\"original\": \"在海滩上打排球怎么样？\", \"translated\": \"Plajda voleybol oynamak nasıl olur?\"}, {\"original\": \"远处的帆船看起来真美。\", \"translated\": \"Uzaktaki yelkenliler çok güzel görünüyor.\"}, {\"original\": \"这里的水非常清澈，甚至能看到鱼。\", \"translated\": \"Buradaki su çok berrak, balıkları bile görebiliyorsunuz.\"}, {\"original\": \"我们去找些贝壳吧。\", \"translated\": \"Hadi biraz deniz kabuğu bulalım.\"}, {\"original\": \"日落时在海滩上散步一定很浪漫。\", \"translated\": \"Gün batımında plajda yürüyüş yapmak kesinlikle çok romantik olur.\"}, {\"original\": \"听说这里的海鲜非常新鲜，我们去尝尝吧。\", \"translated\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\"}, {\"original\": \"涨潮了，我们往岸边走吧。\", \"translated\": \"Su yükseliyor, sahile doğru gidelim.\"}]', 9, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在本地活动和节日中常用的短语吗？\", \"太棒了！以下是与本地活动和节日相关的10个常用短语，以及对应的土耳其语翻译：\"]', '[\"参加活动\", \"庆祝节日\", \"学习文化\"]', 'zh', '[\"目前，您能否告诉我您将要参加的本地活动或节日的具体背景？例如万圣节、音乐会、朋友聚会，或其他活动？请提供相关背景。\", \"请描述一下您脑海中设想的活动内容。\"]', '[\"您心中是否有特定的情境？欢迎随时提出。\", \"请描述一下您脑海中设想的具体情境。\"]', '[{\"original\": \"今天有什么活动吗？\", \"translated\": \"Bugün herhangi bir etkinlik var mı?\"}, {\"original\": \"这个节日有什么特别之处吗？\", \"translated\": \"Bu festivalle ilgili özel bir şey var mı?\"}, {\"original\": \"庆祝活动在哪里举行？\", \"translated\": \"Kutlama nerede yapılacak?\"}, {\"original\": \"我怎样才能买到票？\", \"translated\": \"Biletleri nasıl alabilirim?\"}, {\"original\": \"演出什么时候开始？\", \"translated\": \"Etkinlik saat kaçta başlıyor?\"}, {\"original\": \"有哪些传统食物？\", \"translated\": \"Hangi geleneksel yiyecekler var?\"}, {\"original\": \"这里真的很热闹。\", \"translated\": \"Burada gerçekten canlı bir atmosfer var.\"}, {\"original\": \"有民间活动吗？\", \"translated\": \"Halk etkinlikleri var mı?\"}, {\"original\": \"节日快乐！\", \"translated\": \"Bayramınız kutlu olsun!\"}, {\"original\": \"活动什么时候结束？\", \"translated\": \"Etkinlik saat kaçta bitiyor?\"}]', 10, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在博物馆或美术馆中常用的表达吗？\", \"太棒了！以下是与博物馆或美术馆相关的10个常用表达，以及对应的土耳其语翻译：\"]', '[\"参观\", \"导览游\", \"购票\"]', 'zh', '[\"目前，您心中是否有特定场景？例如索要导览手册、与参观路线相关的表达、对展品进行评论的表达等，欢迎随时提问。\", \"请描述您心中所想的具体场景。\"]', NULL, '[{\"original\": \"门票多少钱？\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"你们提供语音导览吗？\", \"translated\": \"Sesli rehber hizmeti var mı?\"}, {\"original\": \"这件艺术品是谁创作的？\", \"translated\": \"Bu eseri kim yaratmış?\"}, {\"original\": \"博物馆最珍贵的藏品在哪里？\", \"translated\": \"Müzenin en değerli eseri nerede?\"}, {\"original\": \"允许拍照吗？\", \"translated\": \"Fotoğraf çekmeye izin veriliyor mu?\"}, {\"original\": \"这里有什么特别展览吗？\", \"translated\": \"Burada özel bir sergi var mı?\"}, {\"original\": \"参观需要多长时间？\", \"translated\": \"Ziyaret ne kadar sürer?\"}, {\"original\": \"您能为我们做个介绍吗？\", \"translated\": \"Bize bir tanıtım yapar mısınız?\"}, {\"original\": \"这些作品真是精美绝伦。\", \"translated\": \"Bu eserler gerçekten muhteşem.\"}, {\"original\": \"纪念品商店在哪里？\", \"translated\": \"Hediyelik eşya dükkanı nerede?\"}]', 11, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在咖啡馆常用的说法吗？\", \"太棒了！以下是与咖啡馆相关的10个常用说法，以及对应的土耳其语翻译：\"]', '[\"点咖啡\", \"休息\", \"社交\"]', 'zh', '[\"目前，您心里是否有特定的情境，比如点餐单、要冰饮或热饮、购买其他商品等？欢迎随时提问。\", \"请描述您心中所想的情境。\"]', NULL, '[{\"original\": \"请给我一杯拿铁。\", \"translated\": \"Lütfen bir latte getirir misiniz?\"}, {\"original\": \"你们有Wi-Fi吗？\", \"translated\": \"Wi-Fi var mı?\"}, {\"original\": \"请给我看一下菜单，谢谢。\", \"translated\": \"Menüyü görebilir miyim, lütfen?\"}, {\"original\": \"可以续杯吗？\", \"translated\": \"Yeniden doldurma yapılıyor mu?\"}, {\"original\": \"我的咖啡好了吗？\", \"translated\": \"Kahvaltım hazır mı?\"}, {\"original\": \"我可以在这里坐多久？\", \"translated\": \"Burada ne kadar süre oturabilirim?\"}, {\"original\": \"能帮我们拍张照片吗？\", \"translated\": \"Bize bir fotoğraf çeker misiniz?\"}, {\"original\": \"洗手间在哪里？\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"请结账，谢谢。\", \"translated\": \"Hesabı getirir misiniz, lütfen. Teşekkür ederim.\"}, {\"original\": \"味道真的很好。\", \"translated\": \"Gerçekten çok lezzetli.\"}]', 12, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Restoranda kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte restoranla ilgili 10 yaygın ifade ve bunların Çince çevirileri:\"]', '[\"Yemek Yeme\", \"Sipariş Verme\", \"Ödeme\"]', 'tr', '[\"Şimdilik aklınızda içecek siparişi vermek, bir şikayette bulunmak veya malzemeler hakkında sormak gibi belirli bir durum mu var? Sorunuzu özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Affedersiniz, yemeğimiz ne kadar daha sürede hazır olur?\", \"translated\": \"打扰一下，我们的餐还要多久才能好？\"}, {\"original\": \"İki kişi için bir masa, lütfen.\", \"translated\": \"请给我们安排一张两人桌。\"}, {\"original\": \"Menüyü görebilir miyiz, lütfen?\", \"translated\": \"请问我们可以看一下菜单吗？\"}, {\"original\": \"Önerdiğiniz özel yemekleriniz var mı?\", \"translated\": \"您有什么特色菜可以推荐吗？\"}, {\"original\": \"Bunu ve bunu sipariş etmek istiyorum.\", \"translated\": \"我要点这个和这个。\"}, {\"original\": \"Bir bardak su, lütfen. Teşekkürler.\", \"translated\": \"请来一杯水，谢谢。\"}, {\"original\": \"Hesap, lütfen.\", \"translated\": \"请结账。\"}, {\"original\": \"Kredi kartıyla ödeyebilir miyim?\", \"translated\": \"我可以刷信用卡付款吗？\"}, {\"original\": \"Bunu alıp gidebileceğim şekilde paketleyebilir misiniz, lütfen?\", \"translated\": \"请问可以帮我把这份打包带走吗？\"}, {\"original\": \"Yiyecekler çok lezzetliydi, teşekkür ederim.\", \"translated\": \"食物非常美味，谢谢！\"}]', 1, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Otelde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte otel ile ilgili 10 yaygın ifade ve bunların Çince çevirileri:\"]', '[\"Kayıt Ol\", \"Çıkış Yap\", \"Oda Hizmeti\"]', 'tr', '[\"Şu anda aklınızda özel bir durum var mı, örneğin oda konumu, başka bir otel hizmeti ya da çıkış işlemi? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Merhaba, bir rezervasyonum var. İşte pasaportum.\", \"translated\": \"你好，我有预订。这是我的护照。\"}, {\"original\": \"Boş odanız var mı?\", \"translated\": \"你们还有空房吗？\"}, {\"original\": \"Affedersiniz, otelde bir spor salonu ya da çamaşırhane var mı?\", \"translated\": \"打扰一下，酒店有健身房或洗衣房吗？\"}, {\"original\": \"Kahvaltı saat kaçta başlıyor?\", \"translated\": \"早餐几点开始？\"}, {\"original\": \"Lütfen bir oda anahtarı alabilir miyim?\", \"translated\": \"请给我一把房卡，好吗？\"}, {\"original\": \"Lütfen bagajımı odaya taşımanıza yardımcı olur musunuz?\", \"translated\": \"您能帮我把行李送到房间吗？\"}, {\"original\": \"Oda servisini nasıl arayabilirim?\", \"translated\": \"我怎样才能呼叫客房服务？\"}, {\"original\": \"Çıkış saati kaçta?\", \"translated\": \"退房时间是几点？\"}, {\"original\": \"Bana bir makbuz/fatura yazabilir misiniz?\", \"translated\": \"您能给我开一张收据/发票吗？\"}, {\"original\": \"Bagajımı burada bırakabilir miyim?\", \"translated\": \"我可以把行李寄存在这里吗？\"}]', 2, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Havaalanında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte havaalanıyla ilgili 10 yaygın ifade ve bunların Çince çevirileri:\"]', '[\"Giriş yapma\", \"Uçağa binme\", \"Bagaj kontrolü\"]', 'tr', '[\"Şu anda aklınızda özel bir durum var mı, örneğin check-in, bagaj teslimi veya araç kiralama hizmeti? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş masası nerede?\", \"translated\": \"值机柜台在哪里？\"}, {\"original\": \"Lütfen bir pencere koltuğu istiyorum.\", \"translated\": \"我想要一个靠窗的座位。\"}, {\"original\": \"Bu uçuş gecikmiş mi?\", \"translated\": \"这个航班延误了吗？\"}, {\"original\": \"Bu bagajı kontrol ettirmem gerekiyor.\", \"translated\": \"我需要托运行李。\"}, {\"original\": \"İniş kapısı nerede?\", \"translated\": \"登机口在哪里？\"}, {\"original\": \"Uçak hemen kalkacak.\", \"translated\": \"飞机即将起飞。\"}, {\"original\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\", \"translated\": \"我需要把笔记本电脑和充电宝拿出来吗？\"}, {\"original\": \"Vergisiz alışveriş mağazası nerede?\", \"translated\": \"免税店在哪里？\"}, {\"original\": \"Bavulumu bulamıyorum.\", \"translated\": \"我找不到我的行李箱了。\"}, {\"original\": \"Tekerlekli sandalye servisi var mı?\", \"translated\": \"你们提供轮椅服务吗？\"}]', 3, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Toplu taşıma araçlarında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Toplu Taşıma ile ilgili 10 yaygın ifade ve Türkçe çevirileri:\"]', '[\"Otobüs/Metro Kullanma\", \"Bilet Satın Alma\", \"Aktarma\"]', 'tr', '[\"Şu an için aklınızda özel bir durum var mı, örneğin otobüs durağı sormak, bilet fiyatını öğrenmek ya da inecek yer belirtmek? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bu otobüs terminala gidiyor mu?\", \"translated\": \"这趟公交车去终点站吗？\"}, {\"original\": \"Bir sonraki durak nerede?\", \"translated\": \"下一站是哪里？\"}, {\"original\": \"Bilet nereden alabilirim?\", \"translated\": \"我在哪里可以买票？\"}, {\"original\": \"Lütfen XX\'e giden bir bilet.\", \"translated\": \"请给我一张去XX的车票。\"}, {\"original\": \"Aktarma yapmam gerekiyor mu?\", \"translated\": \"我需要换乘吗？\"}, {\"original\": \"Bir sonraki metro treni ne zaman geliyor?\", \"translated\": \"下一班地铁列车还有多久到？\"}, {\"original\": \"Affedersiniz, geçmem için yer açar mısınız?\", \"translated\": \"不好意思，请让我过去一下。\"}, {\"original\": \"Bu koltuk alınmış mı?\", \"translated\": \"这个座位有人了吗？\"}, {\"original\": \"Affedersiniz, XX\'e gitmek için 2. Hat\'a nereden aktarım yapabilirim?\", \"translated\": \"不好意思，请问去XX需要在哪里换乘2号线？\"}, {\"original\": \"XX\'e nasıl giderim?\", \"translated\": \"我怎么去XX？\"}]', 4, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Turistik yerlerde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte turistik yerlerle ilgili 10 yaygın ifade ve bunların Çince çevirileri:\"]', '[\"Manzara Görme\", \"Fotoğraf Çekme\", \"Bilet Satın Alma\"]', 'tr', '[\"Şu anda aklınızda, bilet fiyatını sormak, bir otopark bulmak ya da tur rehberi hizmeti gibi belirli bir durum mu var? Sorunuz ne olursa olsun memnuniyetle yardımcı olurum.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"Öğrenci biletleri mevcut mu?\", \"translated\": \"有学生票吗？\"}, {\"original\": \"Yerleşim saati kaçta açılıyor?\", \"translated\": \"景点几点开放？\"}, {\"original\": \"Burada yapılacak eğlenceli şeyler neler?\", \"translated\": \"这里有哪些好玩的活动？\"}, {\"original\": \"Bizi birlikte fotoğraflar mısınız?\", \"translated\": \"能帮我们拍张合影吗？\"}, {\"original\": \"Sightseeing otobüsü nerede?\", \"translated\": \"观光巴士在哪里？\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"洗手间在哪里？\"}, {\"original\": \"En iyi manzara noktası nerede?\", \"translated\": \"最佳观景点在哪里？\"}, {\"original\": \"Buradaki manzara çok güzel.\", \"translated\": \"这里的风景很美。\"}, {\"original\": \"Rehberli tur mevcut mu?\", \"translated\": \"有导游讲解服务吗？\"}]', 5, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Taksi veya taksi hizmeti ile ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Taksi veya Taksi Hizmeti ile ilgili 10 yaygın ifade ve bunların Çince çevirileri:\"]', '[\"Taksiye Biniş\", \"Varış Yerini Belirtme\", \"Ödeme\"]', 'tr', '[\"Şu anda en çok ne yapmak istersiniz? Örneğin, varış yerini sormak, ücreti öğrenmek ya da fatura talep etmek gibi; sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bir taksi nerede bulabilirim?\", \"translated\": \"我在哪里可以打到出租车？\"}, {\"original\": \"Lütfen beni bu adrese götürün.\", \"translated\": \"请送我去这个地址。\"}, {\"original\": \"Yaklaşık olarak ne kadar olur?\", \"translated\": \"大概需要多少钱？\"}, {\"original\": \"Lütfen taksimetreyi kullanır mısınız?\", \"translated\": \"请使用计价器，好吗？\"}, {\"original\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\", \"translated\": \"请开快一点，我赶时间。\"}, {\"original\": \"Lütfen burada durun.\", \"translated\": \"请在这里停车。\"}, {\"original\": \"Kart veya mobil ödeme kabul ediyor musunuz?\", \"translated\": \"您接受银行卡或移动支付吗？\"}, {\"original\": \"Lütfen bana bir makbuz verebilir misiniz?\", \"translated\": \"请给我一张收据，好吗？\"}, {\"original\": \"Teşekkür ederim, şöförüm.\", \"translated\": \"谢谢，司机师傅。\"}, {\"original\": \"Kaç dakika kaldı?\", \"translated\": \"还有多远？\"}]', 6, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Eczanede kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte eczane ile ilgili 10 yaygın ifade ve bunların Çince çevirileri:\"]', '[\"İlaç Satın Almak\", \"Danışmanlık\", \"Ödeme\"]', 'tr', '[\"Şimdilik aklınızda ilaç alma talimatları sorma, sigorta kullanımıyla ilgili ifadeler, ilaç kullanım süresi gibi belirli bir durum mu var? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Soğuk algınlığı ilacı var mı?\", \"translated\": \"您有感冒药吗？\"}, {\"original\": \"Bu ilacı nasıl kullanmalıyım?\", \"translated\": \"我该如何服用这种药？\"}, {\"original\": \"Ağrı kesici ilaçlarınız var mı?\", \"translated\": \"您有止痛药吗？\"}, {\"original\": \"Kullanım kılavuzu var mı?\", \"translated\": \"有说明书吗？\"}, {\"original\": \"Bu ilacın yan etkileri var mı?\", \"translated\": \"这种药有副作用吗？\"}, {\"original\": \"Tıbbi sigorta kartımı kullanabilir miyim?\", \"translated\": \"我可以使用我的医疗保险卡吗？\"}, {\"original\": \"Lütfen bir kutu yara bandı verebilir misiniz?\", \"translated\": \"请给我一盒创可贴，谢谢。\"}, {\"original\": \"Ateş düşürücü ilaçlarınız var mı?\", \"translated\": \"您有退烧药吗？\"}, {\"original\": \"Hafif bir sıyrık var. Antiseptik ve yara bandınız var mı?\", \"translated\": \"我有点擦伤，您有消毒药水和创可贴吗？\"}, {\"original\": \"Kaçta kapanıyorsunuz?\", \"translated\": \"您几点关门？\"}]', 7, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Acil Servislerle ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Acil Servislerle ilgili 10 yaygın ifade ve bunların Çince çevirileri:\"]', '[\"Polisi Aramak\", \"İlkyardım\", \"Yardım Çağrısı\"]', 'tr', '[\"Şu an için aklınızda belirli bir acil durum var mı, örneğin yangın, yaralanma ve yardım gereksinimi, acil çağrı? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bana bir ambulans çağırmanıza yardımcı olur musunuz?\", \"translated\": \"请帮我叫一辆救护车。\"}, {\"original\": \"Hastane nerede?\", \"translated\": \"医院在哪里？\"}, {\"original\": \"Birisi yaralandı.\", \"translated\": \"有人受伤了。\"}, {\"original\": \"Lütfen bana yardım eder misiniz?\", \"translated\": \"请帮帮我。\"}, {\"original\": \"Polis karakolu nerede?\", \"translated\": \"警察局在哪里？\"}, {\"original\": \"Eşyalarımı kaybettim.\", \"translated\": \"我的物品丢失了。\"}, {\"original\": \"İtfaİYE numarası nedir?\", \"translated\": \"消防部门的电话号码是多少？\"}, {\"original\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\", \"translated\": \"我的护照丢了。您知道最近的警察局在哪里吗？\"}, {\"original\": \"Acil çıkış var mı?\", \"translated\": \"有紧急出口吗？\"}, {\"original\": \"Birisi bayıldı.\", \"translated\": \"有人晕倒了。\"}]', 8, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Sahilde veya havuz kenarında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte sahil veya havuz kenarında kullanılan 10 yaygın ifade ve bunların Çince çevirileri:\"]', '[\"Yüzme\", \"Güneşlenme\", \"Plaj Sporları\"]', 'tr', '[\"Şimdilik, katıldığınız yerel etkinlik veya festivale ilişkin bağlamı bana verebilir misiniz? Örneğin kültürel festival, gıda festivali veya müzik festivali gibi. Lütfen bu bağlamı belirtin.\", \"Katıldığınız etkinlikleri belirtir misiniz?\"]', '[\"Aklınızda özel bir durum mu var? Sorunuzu özgürce sorabilirsiniz.\", \"Aklınızda canlandırdığınız durumu lütfen açıklayın.\"]', '[{\"original\": \"Bak! Oradaki dalgalar gerçekten büyük.\", \"translated\": \"看！那边的浪真的很大。\"}, {\"original\": \"Güneş koruyucu sürmeyi unutma, buradaki UV ışınları çok güçlü.\", \"translated\": \"记得涂防晒霜，这里的紫外线很强。\"}, {\"original\": \"Bu plajdaki kum çok ince, pamuk üzerinde yürüyormuş gibi hissediyorsun.\", \"translated\": \"这个海滩的沙子非常细腻，踩上去就像走在棉花上。\"}, {\"original\": \"Plajda voleybol oynamak nasıl olur?\", \"translated\": \"在海滩上打排球怎么样？\"}, {\"original\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\", \"translated\": \"远处的帆船看起来很美。\"}, {\"original\": \"Buradaki su çok berrak, balıkları bile görebiliyorsun.\", \"translated\": \"这里的水非常清澈，连鱼都能看见。\"}, {\"original\": \"Hadi biraz deniz kabuğu bulmaya gidelim.\", \"translated\": \"我们去找些贝壳吧。\"}, {\"original\": \"Gün batımında plajda yürüyüş yapmak kesinlikle çok romantik olmalı.\", \"translated\": \"日落时分在海滩散步一定非常浪漫。\"}, {\"original\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\", \"translated\": \"听说这里的海鲜非常新鲜，我们去尝尝吧。\"}, {\"original\": \"Deniz yükseliyor, kıyıya doğru yürüyelim.\", \"translated\": \"涨潮了，我们往岸边走吧。\"}]', 9, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Yerel Etkinlikler ve Festivallerde kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte Yerel Etkinlikler ve Festivallerle ilgili 10 yaygın ifade ve Çince çevirileri:\"]', '[\"Etkinliklere Katılmak\", \"Festivalleri Kutlamak\", \"Kültür Öğrenmek\"]', 'tr', '[\"Şimdilik, katıldığınız yerel etkinlik veya festivalin bağlamını, örneğin Cadılar Bayramı, konser veya arkadaş partisi gibi, ya da başka bir şey olarak lütfen bana belirtir misiniz? Lütfen bağlamı sağlayın.\", \"Aklınızda canlandırdığınız etkinlikleri tanımlar mısınız?\"]', '[\"Aklınızda belirli bir durum mu var? Sorunuzu özgürce sorabilirsiniz.\", \"Aklınızda canlandırdığınız durumu tanımlar mısınız?\"]', '[{\"original\": \"Bugün herhangi bir etkinlik var mı?\", \"translated\": \"今天有活动吗？\"}, {\"original\": \"Bu festivalle ilgili özel bir şey var mı?\", \"translated\": \"这个节日有什么特别之处吗？\"}, {\"original\": \"Kutlama nerede yapılacak?\", \"translated\": \"庆祝活动在哪里举行？\"}, {\"original\": \"Biletleri nasıl satın alabilirim?\", \"translated\": \"我该如何购买门票？\"}, {\"original\": \"Performans saat kaçta başlıyor?\", \"translated\": \"演出几点开始？\"}, {\"original\": \"Hangi geleneksel yiyecekler var?\", \"translated\": \"有哪些传统食物？\"}, {\"original\": \"Burada gerçekten hareketli.\", \"translated\": \"这里真的很热闹。\"}, {\"original\": \"Halk aktiviteleri var mı?\", \"translated\": \"有民俗活动吗？\"}, {\"original\": \"Mutlu tatiller!\", \"translated\": \"节日快乐！\"}, {\"original\": \"Etkinlik saat kaçta bitiyor?\", \"translated\": \"活动几点结束？\"}]', 10, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Müze veya Sanat Galerisi\'nde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Müze veya Sanat Galerisi ile ilgili 10 yaygın ifade ve bunların Çince çevirileri:\"]', '[\"Ziyaret Etmek\", \"Rehberli Tur\", \"Bilet Satın Almak\"]', 'tr', '[\"Şimdilik aklınızda, tanıtım kılavuzu istemek, bir yol haritası ile ilgili ifadeler kullanmak veya sergilenen eserler hakkında yorum yapmak gibi belirli bir durum var mı? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"Sesli rehberleriniz var mı?\", \"translated\": \"你们有语音导览吗？\"}, {\"original\": \"Bu eseri kim yaratmış?\", \"translated\": \"这件艺术品是谁创作的？\"}, {\"original\": \"Müzenin en değerli eseri nerede?\", \"translated\": \"博物馆最珍贵的藏品在哪里？\"}, {\"original\": \"Fotoğraf çekmeye izin veriliyor mu?\", \"translated\": \"允许拍照吗？\"}, {\"original\": \"Burada özel sergiler var mı?\", \"translated\": \"这里有没有特别展览？\"}, {\"original\": \"Ziyaret kaç dakika sürüyor?\", \"translated\": \"参观需要多长时间？\"}, {\"original\": \"Bize bir tanıtım yapar mısınız?\", \"translated\": \"能为我们做个介绍吗？\"}, {\"original\": \"Bu eserler gerçekten çok zarif.\", \"translated\": \"这些作品确实极为精美。\"}, {\"original\": \"Hediyelik eşya dükkanı nerede?\", \"translated\": \"纪念品商店在哪里？\"}]', 11, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Kafelerde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte kafelerle ilgili 10 yaygın ifade ve bunların Çince çevirileri:\"]', '[\"Kahvaltı Kahvesi Siparişi\", \"Dinlenme\", \"Sosyalleşme\"]', 'tr', '[\"Şimdilik aklınızda menü istemek, soğuk veya sıcak içecekler sipariş etmek, diğer ürünler hakkında bilgi almak gibi belirli bir durum mu var? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bir latte getirir misiniz?\", \"translated\": \"请给我一杯拿铁。\"}, {\"original\": \"Wi-Fi var mı?\", \"translated\": \"有Wi-Fi吗？\"}, {\"original\": \"Lütfen menüyü görebilir miyim?\", \"translated\": \"请把菜单给我看一下。\"}, {\"original\": \"İkinci servis (doldurma) yapılıyor mu?\", \"translated\": \"可以续杯吗？\"}, {\"original\": \"Kahvaltım hazır mı?\", \"translated\": \"我的咖啡好了吗？\"}, {\"original\": \"Burada ne kadar süre oturabilirim?\", \"translated\": \"我可以在这里坐多久？\"}, {\"original\": \"Lütfen bize bir fotoğraf çeker misiniz?\", \"translated\": \"能帮我们拍张照吗？\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"洗手间在哪里？\"}, {\"original\": \"Hesap lütfen. Teşekkür ederim.\", \"translated\": \"请结账，谢谢。\"}, {\"original\": \"Gerçekten çok lezzetli.\", \"translated\": \"味道真的很好。\"}]', 12, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Restoranda kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte restoranla ilgili 10 yaygın ifade ve Japonca çevirileri:\"]', '[\"Yemek Yeme\", \"Sipariş Verme\", \"Ödeme\"]', 'tr', '[\"Şimdilik aklınızda içecek siparişi vermek, bir şikayette bulunmak veya malzemeler hakkında sormak gibi belirli bir durum mu var? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Affedersiniz, yemeğimiz ne kadar sürede hazır olur?\", \"translated\": \"すみません、料理はあとどのくらいで出来上がりますか？\"}, {\"original\": \"İki kişilik bir masa lütfen.\", \"translated\": \"二人用のテーブルをお願いします。\"}, {\"original\": \"Menüyü görebilir miyiz lütfen?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"Önerdiğiniz özel yemekleriniz var mı?\", \"translated\": \"おすすめの特製料理はありますか？\"}, {\"original\": \"Bunu ve bunu sipariş etmek istiyorum.\", \"translated\": \"これをひとつと、これをひとつお願いします。\"}, {\"original\": \"Bir bardak su lütfen. Teşekkürler.\", \"translated\": \"お水を一杯お願いします。ありがとうございます。\"}, {\"original\": \"Hesabı lütfen.\", \"translated\": \"お会計をお願いします。\"}, {\"original\": \"Kredi kartıyla ödeyebilir miyim?\", \"translated\": \"クレジットカードで支払えますか？\"}, {\"original\": \"Bunu götürmek için paketleyebilir misiniz lütfen?\", \"translated\": \"これをテイクアウト用に包んでいただけますか？\"}, {\"original\": \"Yiyecekler çok lezzetliydi, teşekkürler.\", \"translated\": \"料理はとても美味しかったです。ありがとうございました。\"}]', 1, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Otelde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte otel ile ilgili 10 yaygın ifade ve Japonca çevirileri:\"]', '[\"Kayıt Ol\", \"Çıkış Yap\", \"Oda Hizmeti\"]', 'tr', '[\"Şu an için aklınızda özel bir durum var mı, örneğin oda konumu, başka bir otel hizmeti ya da çıkış işlemi? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\", \"translated\": \"こんにちは、予約をしております。こちらが私のパスポートです。\"}, {\"original\": \"Boş odanız var mı?\", \"translated\": \"空室はありますか？\"}, {\"original\": \"Affedersiniz, otelde spor salonu veya çamaşırhane var mı?\", \"translated\": \"すみません、ホテルにジムやランドリールームはありますか？\"}, {\"original\": \"Kahvaltı saat kaçta başlıyor?\", \"translated\": \"朝食は何時からですか？\"}, {\"original\": \"Oda anahtarını alabilir miyim, lütfen?\", \"translated\": \"お部屋の鍵をいただけますか？\"}, {\"original\": \"Lütfen bagajımı odaya taşımanıza yardımcı olur musunuz?\", \"translated\": \"荷物を部屋まで運んでいただけますか？\"}, {\"original\": \"Oda servisini nasıl arayabilirim?\", \"translated\": \"ルームサービスの電話番号を教えていただけますか？\"}, {\"original\": \"Çıkış saati kaçta?\", \"translated\": \"チェックアウトは何時ですか？\"}, {\"original\": \"Bana bir makbuz/fatura yazabilir misiniz?\", \"translated\": \"領収書／請求書を発行していただけますか？\"}, {\"original\": \"Bagajımı burada bırakabilir miyim?\", \"translated\": \"荷物をここに預けてもよろしいですか？\"}]', 2, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Havaalanında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte havaalanıyla ilgili 10 yaygın ifade ve bunların Japonca çevirileri:\"]', '[\"Giriş yapma\", \"Uçağa binme\", \"Bagaj kontrolü\"]', 'tr', '[\"Şu an için aklınızda özel bir durum var mı, örneğin check-in, bagaj teslimi veya araç kiralama hizmeti? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş masası nerede?\", \"translated\": \"チェックインカウンターはどこですか？\"}, {\"original\": \"Lütfen bir pencere koltuğu istiyorum.\", \"translated\": \"窓側の席をお願いします。\"}, {\"original\": \"Bu uçuş gecikmiş mi?\", \"translated\": \"この便は遅れていますか？\"}, {\"original\": \"Bu bagajı kontrol ettirmem gerekiyor.\", \"translated\": \"この手荷物を預けたいのですが。\"}, {\"original\": \"İniş kapısı nerede?\", \"translated\": \"搭乗口はどこですか？\"}, {\"original\": \"Uçak kalkmak üzere.\", \"translated\": \"飛行機が離陸しようとしています。\"}, {\"original\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\", \"translated\": \"ノートパソコンとモバイルバッテリーをバッグから出さなければなりませんか？\"}, {\"original\": \"Vergisiz mağaza nerede?\", \"translated\": \"免税店はどこですか？\"}, {\"original\": \"Bavulumu bulamıyorum.\", \"translated\": \"私のスーツケースが見つかりません。\"}, {\"original\": \"Tekerlekli sandalye hizmeti var mı?\", \"translated\": \"車椅子サービスはありますか？\"}]', 3, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Toplu taşıma alanında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Toplu Taşıma ile ilgili 10 yaygın ifade ve bunların Japonca çevirileri:\"]', '[\"Otobüs/Metro Kullanma\", \"Bilet Satın Alma\", \"Aktarma\"]', 'tr', '[\"Şimdilik aklınızda özel bir durum var mı? Örneğin otobüs durağı sormak, bilet fiyatını öğrenmek ya da inecek yer belirtmek gibi. Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bu otobüs terminala gidiyor mu?\", \"translated\": \"このバスはターミナルに行きますか？\"}, {\"original\": \"Bir sonraki durak neresi?\", \"translated\": \"次の停留所はどこですか？\"}, {\"original\": \"Bilet nereden alabilirim?\", \"translated\": \"切符はどこで買えますか？\"}, {\"original\": \"XX\'e giden bir bilet lütfen.\", \"translated\": \"XX行きの切符を一枚お願いします。\"}, {\"original\": \"Aktarma yapmam gerekiyor mu?\", \"translated\": \"乗り換えが必要ですか？\"}, {\"original\": \"Bir sonraki metro treni ne zaman geliyor?\", \"translated\": \"次の地下鉄の列車はいつ来ますか？\"}, {\"original\": \"Affedersiniz, geçebilir miyim?\", \"translated\": \"すみません、通らせていただけますか？\"}, {\"original\": \"Bu koltuk alınmış mı?\", \"translated\": \"この席は空いていますか？\"}, {\"original\": \"Affedersiniz, XX\'e gitmek için 2. Hat\'a nereden aktarabilirim?\", \"translated\": \"すみません、XXへ行くために2号線にはどこで乗り換えればいいですか？\"}, {\"original\": \"XX\'e nasıl giderim?\", \"translated\": \"XXへはどう行けばいいですか？\"}]', 4, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Turistik yerlerde kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte turistik yerlerle ilgili 10 yaygın ifade ve Japonca çevirileri:\"]', '[\"Manzara İzlemek\", \"Fotoğraf Çekmek\", \"Bilet Almak\"]', 'tr', '[\"Şu anda aklınızda bilet fiyatı sorma, otopark bulma veya tur rehberi hizmeti gibi belirli bir durum mu var? Sorun değil, sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"Öğrenci biletleri mevcut mu?\", \"translated\": \"学生割引のチケットはありますか？\"}, {\"original\": \"Bu yer saat kaçta açılıyor?\", \"translated\": \"この観光スポットの営業開始時間は何時ですか？\"}, {\"original\": \"Burada yapılacak eğlenceli şeyler nelerdir?\", \"translated\": \"ここではどんな楽しいことが体験できますか？\"}, {\"original\": \"Bize bir fotoğraf çeker misiniz?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"Seyahat otobüsü nerede?\", \"translated\": \"観光バスの乗り場はどこですか？\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"En iyi manzara noktası nerede?\", \"translated\": \"最も景色が美しい展望スポットはどこですか？\"}, {\"original\": \"Buradaki manzara çok güzel.\", \"translated\": \"ここからの景色はとても美しいです。\"}, {\"original\": \"Rehberli tur mevcut mu?\", \"translated\": \"ガイド付きツアーはありますか？\"}]', 5, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Taksi veya taksi hizmeti ile ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Taksi veya Taksi Hizmeti ile ilgili 10 yaygın ifade ve Japonca çevirileri:\"]', '[\"Taksiye Biniş\", \"Varış Yerini Belirtme\", \"Ödeme\"]', 'tr', '[\"Şu anda en çok ne yapmak istersiniz? Örneğin, varış yerini sormak, ücreti öğrenmek ya da fatura istemek gibi. Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Taksi nerede bulabilirim?\", \"translated\": \"タクシーはどこで乗れますか？\"}, {\"original\": \"Lütfen beni bu adrese götürün.\", \"translated\": \"こちらの住所までお願いします。\"}, {\"original\": \"Yaklaşık olarak ne kadar tutar?\", \"translated\": \"だいたいいくらぐらいですか？\"}, {\"original\": \"Lütfen taksimetreyi kullanır mısınız?\", \"translated\": \"メーターを使っていただけますか？\"}, {\"original\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\", \"translated\": \"急いでいるので、少し速く運転していただけますか？\"}, {\"original\": \"Lütfen burada durun.\", \"translated\": \"ここで止めてください。\"}, {\"original\": \"Kart veya mobil ödeme kabul ediyor musunuz?\", \"translated\": \"カードやモバイル決済は使えますか？\"}, {\"original\": \"Bir fiş alabilir miyim, lütfen?\", \"translated\": \"領収書をいただけますか？\"}, {\"original\": \"Teşekkür ederim, şoför bey.\", \"translated\": \"ありがとうございました、運転手さん。\"}, {\"original\": \"Kaç dakika daha var?\", \"translated\": \"あとどのくらいですか？\"}]', 6, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Eczanede kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte eczane ile ilgili 10 yaygın ifade ve Japonca çevirileri:\"]', '[\"İlaç Satın Almak\", \"Danışmanlık\", \"Ödeme\"]', 'tr', '[\"Şimdilik aklınızda, ilaç kullanımına ilişkin talimat istemek, sigorta kullanımıyla ilgili ifadeler veya tedavi süresi gibi belirli bir durum mu var? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Soğuk algınlığına karşı ilaç var mı?\", \"translated\": \"風邪薬はありますか？\"}, {\"original\": \"Bu ilacı nasıl kullanmalıyım?\", \"translated\": \"この薬の使い方はどうすればいいですか？\"}, {\"original\": \"Ağrı kesici ilaçlarınız var mı?\", \"translated\": \"鎮痛剤はありますか？\"}, {\"original\": \"Kullanım kılavuzu var mı?\", \"translated\": \"説明書はありますか？\"}, {\"original\": \"Bu ilacın yan etkileri var mı?\", \"translated\": \"この薬には副作用がありますか？\"}, {\"original\": \"Sağlık sigortamı kullanabilir miyim?\", \"translated\": \"健康保険証を使っても大丈夫ですか？\"}, {\"original\": \"Lütfen bir kutu plastik yara bandı verebilir misiniz?\", \"translated\": \"絆創膏を一箱お願いできますか？\"}, {\"original\": \"Ateş düşürücü ilaçlarınız var mı?\", \"translated\": \"解熱剤はありますか？\"}, {\"original\": \"Hafif bir yaralanmam var. Antiseptik ve plastik yara bandı var mı?\", \"translated\": \"ちょっと擦り傷があるんですが、消毒液と絆創膏はありますか？\"}, {\"original\": \"Kaçta kapanıyorsunuz?\", \"translated\": \"何時まで営業していますか？\"}]', 7, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Acil Servislerle ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Acil Servislerle ilgili 10 yaygın ifade ve Japonca çevirileri:\"]', '[\"Polisi Aramak\", \"İlkyardım\", \"Yardım Çağrısı\"]', 'tr', '[\"Şimdilik aklınızda yangın, yaralanma ve yardım gereksinimi, acil çağrı gibi belirli bir acil durum mu var? Soru sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bir ambulans çağırın.\", \"translated\": \"救急車を呼んでください。\"}, {\"original\": \"Hastane nerede?\", \"translated\": \"病院はどこですか？\"}, {\"original\": \"Birisi yaralandı.\", \"translated\": \"誰かが怪我をしました。\"}, {\"original\": \"Lütfen bana yardım edin.\", \"translated\": \"助けてください。\"}, {\"original\": \"Polis karakolu nerede?\", \"translated\": \"警察署はどこですか？\"}, {\"original\": \"Eşyalarımı kaybettim.\", \"translated\": \"荷物をなくしました。\"}, {\"original\": \"İtfaaiye numarası nedir?\", \"translated\": \"消防署の電話番号は何番ですか？\"}, {\"original\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\", \"translated\": \"パスポートを紛失しました。最寄りの警察署はどこですか？\"}, {\"original\": \"Acil çıkış var mı?\", \"translated\": \"非常口はありますか？\"}, {\"original\": \"Birisi bayıldı.\", \"translated\": \"誰かが気を失いました。\"}]', 8, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Sahilde veya havuz kenarında kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte sahil veya havuz kenarıyla ilgili 10 yaygın ifade ve bunların Japonca çevirileri:\"]', '[\"Yüzme\", \"Güneşlenme\", \"Plaj Sporları\"]', 'tr', '[\"Şimdilik, katılacağınız yerel etkinlik veya festivalin bağlamını, örneğin kültürel festival, gıda festivali veya müzik festivali gibi, lütfen bana belirtir misiniz? Lütfen bağlamı sağlayın.\", \"Katıldığınız etkinlikleri lütfen belirtin.\"]', '[\"Aklınızda belirli bir durum mu var? Sorunuzu özgürce sorabilirsiniz.\", \"Aklınızda canlandırdığınız durumu lütfen açıklayın.\"]', '[{\"original\": \"Bak! Oradaki dalgalar gerçekten büyük.\", \"translated\": \"見て！あそこにいる波は本当に大きいです。\"}, {\"original\": \"Güneş koruyucu sürmeyi unutma, buradaki UV ışınları çok güçlü.\", \"translated\": \"日焼け止めを塗ることを忘れないでください。ここでの紫外線はとても強いです。\"}, {\"original\": \"Bu plajdaki kum çok ince, pamuk üzerinde yürüyormuş gibi hissediliyor.\", \"translated\": \"このビーチの砂はとても細かくて、綿の上を歩いているような気がします。\"}, {\"original\": \"Plajda voleybol oynamak nasıl olur?\", \"translated\": \"ビーチでバレーボールをやるのはどうですか？\"}, {\"original\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\", \"translated\": \"遠くのヨットがとても美しく見えます。\"}, {\"original\": \"Buradaki su çok berrak, balıkları bile görebiliyorsun.\", \"translated\": \"ここでの水はとても透明で、魚さえも見えるほどです。\"}, {\"original\": \"Hadi biraz deniz kabuğu bulmaya gidelim.\", \"translated\": \"さあ、少し貝殻を探しに行きましょう。\"}, {\"original\": \"Günbatımında plajda yürüyüş yapmak kesinlikle çok romantik olmalı.\", \"translated\": \"夕暮れ時にビーチを散歩するのは、きっととてもロマンチックでしょう。\"}, {\"original\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\", \"translated\": \"ここでのシーフードはとても新鮮だと聞きました。さあ、少しだけ食べてみましょう。\"}, {\"original\": \"Deniz yükseliyor, kıyıya doğru gidelim.\", \"translated\": \"潮が満ちてきています。岸へ向かいましょう。\"}]', 9, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Yerel Etkinlikler ve Festivallerde kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte Yerel Etkinlikler ve Festivallerle ilgili 10 yaygın ifade ve Japonca çevirileri:\"]', '[\"Etkinliklere Katılmak\", \"Festivalleri Kutlamak\", \"Kültür Öğrenmek\"]', 'tr', '[\"Şimdilik, katılacağınız yerel etkinlik veya festivalin bağlamını, örneğin Cadılar Bayramı, konser veya arkadaş partisi gibi, lütfen bana belirtir misiniz? Başka bir şey de olabilir. Lütfen bağlamı sağlayın.\", \"Aklınızda canlandırdığınız etkinlikleri tanımlar mısınız?\"]', '[\"Aklınızda belirli bir durum mu var? Soru sormaktan çekinmeyin.\", \"Aklınızda canlandırdığınız durumu tanımlar mısınız?\"]', '[{\"original\": \"Bugün herhangi bir etkinlik var mı?\", \"translated\": \"今日は何かイベントがありますか？\"}, {\"original\": \"Bu festivalle ilgili özel bir şey var mı?\", \"translated\": \"この祭りには何か特別なことがありますか？\"}, {\"original\": \"Kutlama nerede yapılacak?\", \"translated\": \"お祝いはどこで行われますか？\"}, {\"original\": \"Biletleri nasıl alabilirim?\", \"translated\": \"チケットはどのように購入できますか？\"}, {\"original\": \"Performans saat kaçta başlıyor?\", \"translated\": \"パフォーマンスはいつから始まりますか？\"}, {\"original\": \"Hangi geleneksel yiyecekler var?\", \"translated\": \"どんな伝統的な食べ物がありますか？\"}, {\"original\": \"Burada gerçekten hareketli.\", \"translated\": \"ここは本当に活気があります。\"}, {\"original\": \"Halk oyunları var mı?\", \"translated\": \"民俗活動はありますか？\"}, {\"original\": \"Mutlu tatiller!\", \"translated\": \"楽しい休日を！\"}, {\"original\": \"Etkinlik saat kaçta bitiyor?\", \"translated\": \"イベントはいつ終わりますか？\"}]', 10, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Müze veya Sanat Galerisi\'nde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Müze veya Sanat Galerisi ile ilgili 10 yaygın ifade ve bunların Japonca çevirileri:\"]', '[\"Ziyaret Etmek\", \"Rehberli Tur\", \"Bilet Satın Almak\"]', 'tr', '[\"Şimdilik aklınızda, tanıtım kılavuzu istemek, yol haritasıyla ilgili ifadeler kullanmak veya sergilenen eserlerle ilgili yorum yapmak gibi belirli bir durum var mı? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"入館料はいくらですか？\"}, {\"original\": \"Sesli rehberiniz var mı?\", \"translated\": \"オーディオガイドはありますか？\"}, {\"original\": \"Bu eseri kim yaratmış?\", \"translated\": \"この作品は誰が制作しましたか？\"}, {\"original\": \"Müzenin en değerli eseri nerede?\", \"translated\": \"美術館の最も貴重な作品はどこにありますか？\"}, {\"original\": \"Fotoğraf çekmeye izin veriliyor mu?\", \"translated\": \"写真撮影は許可されていますか？\"}, {\"original\": \"Burada özel sergiler var mı?\", \"translated\": \"ここには特別展はありますか？\"}, {\"original\": \"Ziyaret kaç dakika sürüyor?\", \"translated\": \"見学にはどのくらい時間がかかりますか？\"}, {\"original\": \"Bize bir tanıtım yapar mısınız?\", \"translated\": \"ぜひご案内をお願いできますか？\"}, {\"original\": \"Bu eserler gerçekten çok zarif.\", \"translated\": \"これらの作品は本当に素晴らしいです。\"}, {\"original\": \"Hediyelik eşya dükkanı nerede?\", \"translated\": \"お土産ショップはどこですか？\"}]', 11, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Kafelerde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte kafelerle ilgili 10 yaygın ifade ve bunların Japonca çevirileri:\"]', '[\"Kahvaltı Siparişi Verme\", \"Dinlenme\", \"Sosyalleşme\"]', 'tr', '[\"Şimdilik aklınızda, bir menü istemek, soğuk ya da sıcak içecekler sipariş etmek, diğer ürünler almak gibi belirli bir durum mu var? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bir latte alacağım.\", \"translated\": \"ラテを一杯お願いします。\"}, {\"original\": \"Wi-Fi var mı?\", \"translated\": \"Wi-Fiはありますか？\"}, {\"original\": \"Menüyü görebilir miyim, lütfen?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"İkinci servis (refill) yapılıyor mu?\", \"translated\": \"リフィルは可能ですか？\"}, {\"original\": \"Kahvaltım hazır mı?\", \"translated\": \"私のコーヒーは出来上がりましたか？\"}, {\"original\": \"Burada ne kadar süre oturabilirim?\", \"translated\": \"ここにどのくらいの時間座っていられますか？\"}, {\"original\": \"Bizi birlikte çektikten sonra fotoğraf çekebilir misiniz?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"Hesap, lütfen. Teşekkür ederim.\", \"translated\": \"お会計をお願いします。ありがとうございます。\"}, {\"original\": \"Gerçekten çok lezzetli.\", \"translated\": \"本当に美味しいです。\"}]', 12, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"レストランで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、レストランに関連する一般的な表現10個とそのトルコ語訳を示します：\"]', '[\"飲食\", \"注文\", \"レジ\"]', 'ja', '[\"今のところ、注文やクレーム、食材の確認など、特定の状況をお考えですか？ご自由にお尋ねください。\", \"頭の中で思い浮かべている状況を教えてください。\"]', NULL, '[{\"original\": \"すみません、料理はあとどのくらいで来ますか？\", \"translated\": \"Affedersiniz, yemeğimiz kaç dakika sonra gelir?\"}, {\"original\": \"2人用のテーブルをお願いします。\", \"translated\": \"İki kişilik bir masa lütfen.\"}, {\"original\": \"メニューを見せていただけますか？\", \"translated\": \"Menüyü görebilir miyiz, lütfen?\"}, {\"original\": \"おすすめの特製料理はありますか？\", \"translated\": \"Önerdiğiniz özel yemekleriniz var mı?\"}, {\"original\": \"これを注文したいです。それと、これもお願いします。\", \"translated\": \"Bunu sipariş etmek istiyorum. Ayrıca bunu da lütfen.\"}, {\"original\": \"水を一杯お願いします。ありがとうございます。\", \"translated\": \"Bir bardak su lütfen. Teşekkür ederim.\"}, {\"original\": \"お会計をお願いします。\", \"translated\": \"Hesabı lütfen.\"}, {\"original\": \"クレジットカードで支払えますか？\", \"translated\": \"Kredi kartı ile ödeme yapabilir miyim?\"}, {\"original\": \"これを持ち帰り用に包んでいただけますか？\", \"translated\": \"Bunu alıp gidecek şekilde paketleyebilir misiniz, lütfen?\"}, {\"original\": \"料理はとても美味しかったです。ありがとうございました。\", \"translated\": \"Yemek çok lezzetliydi. Teşekkür ederiz.\"}]', 1, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ホテルで使える一般的な表現を10個教えていただけますか？\", \"素晴らしいです！以下に、ホテルに関連する一般的な表現10個とそのトルコ語訳を示します：\"]', '[\"チェックイン\", \"チェックアウト\", \"ルームサービス\"]', 'ja', '[\"今のところ、部屋の位置やその他のホテルサービス、チェックアウトなど、特定の状況をお考えですか？何でもお気軽にお尋ねください。\", \"頭の中で思い浮かべている状況を教えてください。\"]', NULL, '[{\"original\": \"こんにちは、予約しています。こちらが私のパスポートです。\", \"translated\": \"Merhaba, rezervasyon yapmıştım. İşte pasaportum.\"}, {\"original\": \"空室はありますか？\", \"translated\": \"Boş odanız var mı?\"}, {\"original\": \"すみません、このホテルにはジムやランドリールームはありますか？\", \"translated\": \"Affedersiniz, bu otelin bir spor salonu veya çamaşırhane bölümü var mı?\"}, {\"original\": \"朝食は何時からですか？\", \"translated\": \"Kahvaltı saat kaçta başlıyor?\"}, {\"original\": \"部屋の鍵をいただけますか？\", \"translated\": \"Oda anahtarını alabilir miyim?\"}, {\"original\": \"荷物を部屋まで運んでいただけますか？\", \"translated\": \"Bagajlarımı odaya taşıyabilir misiniz?\"}, {\"original\": \"ルームサービスの呼び出し方はどうすればいいですか？\", \"translated\": \"Oda servisini nasıl çağırabilirim?\"}, {\"original\": \"チェックアウトは何時ですか？\", \"translated\": \"Çıkış saati kaçta?\"}, {\"original\": \"領収書／請求書を書いていただけますか？\", \"translated\": \"Bana bir makbuz/fatura yazabilir misiniz?\"}, {\"original\": \"荷物をここに預けても大丈夫ですか？\", \"translated\": \"Bagajlarımı burada bırakabilir miyim?\"}]', 2, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"空港で使える一般的な表現を10個教えていただけますか？\", \"素晴らしいです！以下に、空港に関連する一般的な表現10個とそのトルコ語訳を示します：\"]', '[\"チェックイン\", \"搭乗\", \"手荷物預け\"]', 'ja', '[\"今のところ、チェックイン、手荷物受取、またはレンタカー利用など、特定の状況をお考えですか？お気軽にご質問ください。\", \"頭の中で思い浮かべている状況をご説明ください。\"]', NULL, '[{\"original\": \"チェックインカウンターはどこですか？\", \"translated\": \"Giriş masası nerede?\"}, {\"original\": \"窓際の席をお願いします。\", \"translated\": \"Lütfen pencere kenarında bir koltuk ayırtın.\"}, {\"original\": \"この便は遅れていますか？\", \"translated\": \"Bu uçuş gecikmiş mi?\"}, {\"original\": \"この荷物を預けたいのですが。\", \"translated\": \"Bu bagajı teslim etmem gerekiyor.\"}, {\"original\": \"搭乗口はどこですか？\", \"translated\": \"İniş kapısı nerede?\"}, {\"original\": \"飛行機が離陸しようとしています。\", \"translated\": \"Uçak kalkmaya hazırlanıyor.\"}, {\"original\": \"ノートパソコンとモバイルバッテリーを取り出さなければなりませんか？\", \"translated\": \"Dizüstü bilgisayarımı ve taşınabilir şarj cihazımı çıkarmam gerekiyor mu?\"}, {\"original\": \"免税店はどこですか？\", \"translated\": \"Vergi içermeyen mağaza nerede?\"}, {\"original\": \"私のスーツケースが見つかりません。\", \"translated\": \"Bavulumu bulamıyorum.\"}, {\"original\": \"車椅子サービスはありますか？\", \"translated\": \"Tekerlekli sandalye hizmeti var mı?\"}]', 3, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"公共交通機関で使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、公共交通機関に関連する一般的な表現10個とそのトルコ語訳を示します：\"]', '[\"バスまたは地下鉄の利用\", \"切符の購入\", \"乗り換え\"]', 'ja', '[\"今のところ、バス停の場所を尋ねる、運賃を確認する、降車するなど、特定の状況が頭に浮かんでいますか？何でもお気軽にお尋ねください。\", \"頭に浮かんでいる状況を教えてください。\"]', NULL, '[{\"original\": \"このバスは終点まで行きますか？\", \"translated\": \"Bu otobüs terminala gidiyor mu?\"}, {\"original\": \"次の停留所はどこですか？\", \"translated\": \"Bir sonraki durak nerede?\"}, {\"original\": \"切符はどこで買えますか？\", \"translated\": \"Bilet nerede alınabilir?\"}, {\"original\": \"XX行きの切符を一枚ください。\", \"translated\": \"XX\'e giden bir bilet lütfen.\"}, {\"original\": \"乗り換えが必要ですか？\", \"translated\": \"Aktarma yapmam gerekiyor mu?\"}, {\"original\": \"次の地下鉄の列車まであと何分ですか？\", \"translated\": \"Bir sonraki metro trenine kadar kaç dakika var?\"}, {\"original\": \"すみません、通らせてください。\", \"translated\": \"Affedersiniz, geçmem için yer açar mısınız?\"}, {\"original\": \"この席は空いていますか？\", \"translated\": \"Bu koltuk boş mu?\"}, {\"original\": \"すみません、XXへ行くには2号線にどこで乗り換えればいいですか？\", \"translated\": \"Affedersiniz, XX\'e gitmek için 2. hatla nerede aktarma yapmalıyım?\"}, {\"original\": \"XXへはどう行けばいいですか？\", \"translated\": \"XX\'e nasıl giderim?\"}]', 4, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"観光地で使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、観光地に関連する一般的な表現10個とそのトルコ語訳を示します：\"]', '[\"観光\", \"写真撮影\", \"チケット購入\"]', 'ja', '[\"今のところ、入場料の問い合わせ、駐車場の場所確認、ガイドサービスの利用など、特定の状況が頭に浮かんでいますか？何でもお気軽にお尋ねください。\", \"頭に浮かんでいる状況を教えてください。\"]', NULL, '[{\"original\": \"入場料はいくらですか？\", \"translated\": \"Giriş ücreti ne kadardır?\"}, {\"original\": \"学生割引のチケットはありますか？\", \"translated\": \"Öğrenci biletleri mevcut mu?\"}, {\"original\": \"この観光スポットの営業時間は何時からですか？\", \"translated\": \"Bu turistik yer saat kaçta açar?\"}, {\"original\": \"ここですべき楽しいことは何ですか？\", \"translated\": \"Burada yapılacak eğlenceli şeyler nelerdir?\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"Bize bir fotoğraf çeker misiniz?\"}, {\"original\": \"観光バスの乗り場はどこですか？\", \"translated\": \"Seyahat otobüsü nerede durur?\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"Tuvalet nerededir?\"}, {\"original\": \"一番良い展望スポットはどこですか？\", \"translated\": \"En iyi manzara noktası nerededir?\"}, {\"original\": \"ここからの景色はとても美しいです。\", \"translated\": \"Buradaki manzara çok güzeldir.\"}, {\"original\": \"ガイド付きツアーはありますか？\", \"translated\": \"Rehberli tur mevcut mu?\"}]', 5, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"タクシーまたはタクシーサービスで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、タクシーまたはタクシーサービスに関連する一般的な表現10個とそのトルコ語訳を示します：\"]', '[\"タクシーを利用する\", \"行き先を伝える\", \"支払い\"]', 'ja', '[\"今のところ、目的地の確認、料金の確認、領収書の請求など、今最も知りたいことを自由にお尋ねください。\", \"頭の中で思い浮かべている状況を説明してください。\"]', NULL, '[{\"original\": \"タクシーはどこで乗れますか？\", \"translated\": \"Taksi nerede bulabilirim?\"}, {\"original\": \"この住所までお願いします。\", \"translated\": \"Lütfen bu adrese götürün.\"}, {\"original\": \"だいたいいくらぐらいですか？\", \"translated\": \"Yaklaşık ne kadar tutar?\"}, {\"original\": \"メーターを使っていただけますか？\", \"translated\": \"Lütfen taksimetre kullanır mısınız?\"}, {\"original\": \"急いでいるので、もう少し速く運転していただけますか？\", \"translated\": \"Acele etmem gerekiyor, lütfen biraz daha hızlı sürer misiniz?\"}, {\"original\": \"ここで止めてください。\", \"translated\": \"Lütfen burada durun.\"}, {\"original\": \"カードやモバイル決済は使えますか？\", \"translated\": \"Kart veya mobil ödeme kabul ediyor musunuz?\"}, {\"original\": \"領収書をいただけますか？\", \"translated\": \"Bir makbuz alabilir miyim?\"}, {\"original\": \"ありがとうございました、運転手さん。\", \"translated\": \"Teşekkür ederim, şoför bey.\"}, {\"original\": \"あとどのくらいですか？\", \"translated\": \"Kaç dakika daha var?\"}]', 6, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"薬局で使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、薬局でよく使われる10個の表現と、そのトルコ語訳を示します：\"]', '[\"薬の購入\", \"相談\", \"支払い\"]', 'ja', '[\"今のところ、服薬方法の確認、保険の利用に関する表現、服用期間など、特定の状況を思い浮かべていますか？ご自由にお尋ねください。\", \"頭の中で思い浮かべている状況を教えてください。\"]', NULL, '[{\"original\": \"風邪薬はありますか？\", \"translated\": \"Soğuk algınlığı ilacı var mı?\"}, {\"original\": \"この薬の飲み方はどうすればいいですか？\", \"translated\": \"Bu ilacı nasıl kullanmalıyım?\"}, {\"original\": \"鎮痛剤はありますか？\", \"translated\": \"Ağrı kesici var mı?\"}, {\"original\": \"説明書は付いていますか？\", \"translated\": \"Kullanım kılavuzu var mı?\"}, {\"original\": \"この薬には副作用がありますか？\", \"translated\": \"Bu ilacın yan etkileri var mı?\"}, {\"original\": \"健康保険証を使ってもいいですか？\", \"translated\": \"Sağlık sigortamı kullanabilir miyim?\"}, {\"original\": \"絆創膏の箱を1つお願いします。\", \"translated\": \"Lütfen bir kutu yara bandı verir misiniz?\"}, {\"original\": \"解熱剤はありますか？\", \"translated\": \"Ateş düşürücü ilaç var mı?\"}, {\"original\": \"ちょっと擦り傷をしたんですが、消毒液と絆創膏はありますか？\", \"translated\": \"Hafif bir çizik aldım, antiseptik ve yara bandı var mı?\"}, {\"original\": \"何時まで開いていますか？\", \"translated\": \"Kaçta kapanıyorsunuz?\"}]', 7, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"緊急サービスで使える一般的な表現を10個教えていただけますか？\", \"素晴らしいです！以下に、緊急サービスに関連する一般的な表現10個とそのトルコ語訳を示します：\"]', '[\"警察を呼ぶ\", \"応急処置\", \"助けを呼ぶ\"]', 'ja', '[\"今のところ、火事、怪我をして助けが必要、緊急通報など、特定の緊急状況が頭に浮かんでいますか？遠慮なくお尋ねください。\", \"頭の中にある状況を教えてください。\"]', NULL, '[{\"original\": \"救急車を呼んでください。\", \"translated\": \"Lütfen bir ambulans çağırın.\"}, {\"original\": \"病院はどこですか？\", \"translated\": \"Hastane nerede?\"}, {\"original\": \"誰かが怪我をしました。\", \"translated\": \"Birisi yaralandı.\"}, {\"original\": \"助けてください。\", \"translated\": \"Lütfen yardım edin.\"}, {\"original\": \"警察署はどこですか？\", \"translated\": \"Polis karakolu nerede?\"}, {\"original\": \"荷物をなくしてしまいました。\", \"translated\": \"Eşyalarımı kaybettim.\"}, {\"original\": \"消防署の電話番号は何番ですか？\", \"translated\": \"İtfaiye numarası kaçtır?\"}, {\"original\": \"パスポートを紛失しました。最寄りの警察署はどこかわかりますか？\", \"translated\": \"Pasaportumu kaybettim. En yakın polis karakolu nerede bilir misiniz?\"}, {\"original\": \"非常口はありますか？\", \"translated\": \"Acil çıkış var mı?\"}, {\"original\": \"誰かが気を失いました。\", \"translated\": \"Birisi bayıldı.\"}]', 8, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ビーチやプールサイドで使える一般的な表現を10個教えていただけますか？\", \"素晴らしいです！以下に、ビーチやプールサイドに関連する一般的な表現10個とそのトルコ語訳を示します：\"]', '[\"水泳\", \"日光浴\", \"ビーチスポーツ\"]', 'ja', '[\"現時点では、ご参加予定の地域のイベントまたはフェスティバル（例：文化祭、フードフェス、音楽フェスなど）の背景について教えていただけますか？背景情報をご提供ください。\", \"ご参加予定のアクティビティを教えてください。\"]', '[\"具体的な状況が頭に浮かんでいますか？遠慮なくお尋ねください。\", \"頭に浮かんでいる状況を詳しく説明してください。\"]', '[{\"original\": \"見て！あそこに見える波が本当に大きいよ。\", \"translated\": \"Bak! Oradaki dalgalar gerçekten büyük.\"}, {\"original\": \"日焼け止めを塗ることを忘れないでね。ここでの紫外線はとても強いよ。\", \"translated\": \"Güneş koruyucu sürmeyi unutma, buradaki UV ışınları çok güçlü.\"}, {\"original\": \"このビーチの砂はとても細かくて、綿の上を歩いているような感じがするよ。\", \"translated\": \"Bu plajdaki kum çok ince ve pamuk üzerinde yürüyormuş gibi hissettiriyor.\"}, {\"original\": \"ビーチでバレーボールをするのはどう？\", \"translated\": \"Plajda voleybol oynamak nasıl olur?\"}, {\"original\": \"遠くに見えるヨットがとても美しいね。\", \"translated\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\"}, {\"original\": \"ここでの水はとても透明で、魚まで見えるよ。\", \"translated\": \"Buradaki su çok berrak, balıkları bile görebiliyorsun.\"}, {\"original\": \"貝殻を探しに行こう。\", \"translated\": \"Deniz kabukları aramaya gidelim.\"}, {\"original\": \"夕日が沈む頃にビーチを散歩するのは、きっととてもロマンチックだろうね。\", \"translated\": \"Gün batımında plajda yürüyüş yapmak kesinlikle çok romantik olur.\"}, {\"original\": \"ここではシーフードがとても新鮮だと聞いたから、食べてみよう。\", \"translated\": \"Burada deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\"}, {\"original\": \"潮が満ちてきてるから、岸へ向かおう。\", \"translated\": \"Su yükseliyor, sahile doğru gidelim.\"}]', 9, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"地域のイベントや祭りで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、地域のイベントや祭りに関連する一般的な表現10個とそのトルコ語訳を示します：\"]', '[\"イベントへの参加\", \"祭りの祝い\", \"文化の学習\"]', 'ja', '[\"まずは、あなたが参加予定の地域のイベントや祭りの状況（例：ハロウィン、コンサート、友人とのパーティーなど）について教えていただけますか？それ以外の状況でも構いませんので、ご説明ください。\", \"頭に浮かぶ活動内容を教えてください。\"]', '[\"頭に浮かぶ特定の状況はありますか？遠慮なくお尋ねください。\", \"頭に浮かぶ状況を教えてください。\"]', '[{\"original\": \"今日は何かイベントがありますか？\", \"translated\": \"Bugün herhangi bir etkinlik var mı?\"}, {\"original\": \"この祭りには何か特別な点はありますか？\", \"translated\": \"Bu festivalde özel bir şey var mı?\"}, {\"original\": \"お祝いはどこで行われますか？\", \"translated\": \"Kutlama nerede yapılacak?\"}, {\"original\": \"チケットはどこで購入できますか？\", \"translated\": \"Biletleri nereden satın alabilirim?\"}, {\"original\": \"パフォーマンスの開始時間は何時ですか？\", \"translated\": \"Performans saat kaçta başlıyor?\"}, {\"original\": \"どんな伝統的な食べ物がありますか？\", \"translated\": \"Hangi geleneksel yiyecekler mevcut?\"}, {\"original\": \"ここは本当に活気がありますね。\", \"translated\": \"Burada gerçekten canlı bir atmosfer var.\"}, {\"original\": \"民俗活動はありますか？\", \"translated\": \"Halk aktiviteleri var mı?\"}, {\"original\": \"楽しい休日を！\", \"translated\": \"Mutlu tatiller!\"}, {\"original\": \"イベントの終了時間は何時ですか？\", \"translated\": \"Etkinlik saat kaçta bitiyor?\"}]', 10, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"美術館や博物館で使える一般的な表現を10個教えていただけますか？\", \"素晴らしいです！以下に、美術館や博物館に関連する一般的な表現10個と、そのトルコ語訳を示します：\"]', '[\"訪問\", \"ガイド付きツアー\", \"チケット購入\"]', 'ja', '[\"現時点では、案内用マニュアルの請求、展示ルートに関する表現、展示品への感想を述べる表現など、特定の状況をお考えですか？ご自由にお尋ねください。\", \"頭の中にある状況を詳しくお聞かせください。\"]', NULL, '[{\"original\": \"入場料はいくらですか？\", \"translated\": \"Giriş ücreti ne kadardır?\"}, {\"original\": \"オーディオガイドはありますか？\", \"translated\": \"Sesli rehberler mevcut mu?\"}, {\"original\": \"この作品は誰が制作したのですか？\", \"translated\": \"Bu eser kim tarafından yapılmıştır?\"}, {\"original\": \"美術館の最も貴重な作品はどこにありますか？\", \"translated\": \"Müzenin en değerli eseri nerededir?\"}, {\"original\": \"写真撮影は許可されていますか？\", \"translated\": \"Fotoğraf çekmeye izin veriliyor mu?\"}, {\"original\": \"ここには特別展はありますか？\", \"translated\": \"Burada özel sergiler var mı?\"}, {\"original\": \"見学にはどのくらい時間がかかりますか？\", \"translated\": \"Ziyaret ne kadar sürer?\"}, {\"original\": \"簡単にご案内いただけますか？\", \"translated\": \"Bize kısa bir tanıtım yapabilir misiniz?\"}, {\"original\": \"これらの作品は本当に素晴らしいです。\", \"translated\": \"Bu eserler gerçekten muhteşemdir.\"}, {\"original\": \"お土産ショップはどこですか？\", \"translated\": \"Hediyelik eşya dükkanı nerededir?\"}]', 11, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"カフェで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、カフェに関連する一般的な表現10個とそのトルコ語訳を示します：\"]', '[\"コーヒーを注文する\", \"休む\", \"交流する\"]', 'ja', '[\"今のところ、メニューの注文、アイスまたはホットドリンクの依頼、その他の商品の購入など、特定の状況をお考えですか？何でもお気軽にお尋ねください。\", \"頭の中で思い浮かべている状況を教えてください。\"]', NULL, '[{\"original\": \"ラテを一杯お願いします。\", \"translated\": \"Bir latte alacağım, lütfen.\"}, {\"original\": \"Wi-Fiはありますか？\", \"translated\": \"Wi-Fi var mı?\"}, {\"original\": \"メニューを見せていただけますか？\", \"translated\": \"Menüyü görebilir miyim, lütfen?\"}, {\"original\": \"追加の注文はできますか？\", \"translated\": \"Ekstra servis yapılabilir mi?\"}, {\"original\": \"私のコーヒーはできましたか？\", \"translated\": \"Kahvaltım hazır mı?\"}, {\"original\": \"ここにどのくらい座っていられますか？\", \"translated\": \"Burada ne kadar süre oturabilirim?\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"Bize bir fotoğraf çeker misiniz, lütfen?\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"お会計をお願いします。ありがとうございます。\", \"translated\": \"Hesabı getirir misiniz, lütfen. Teşekkür ederim.\"}, {\"original\": \"とても美味しいです。\", \"translated\": \"Gerçekten çok lezzetli.\"}]', 12, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Restoranda kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte restoranla ilgili 10 yaygın ifade ve İngilizce çevirileri:\"]', '[\"Yemek Yeme\", \"Sipariş Verme\", \"Ödeme\"]', 'tr', '[\"Şu an için aklınızda içecek siparişi vermek, bir şikayette bulunmak veya malzemeler hakkında soru sormak gibi belirli bir durum mu var? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Affedersiniz, yemeğimiz ne kadar daha sürede hazır olur?\", \"translated\": \"Excuse me, how much longer will our food be?\"}, {\"original\": \"İki kişilik bir masa lütfen.\", \"translated\": \"A table for two, please.\"}, {\"original\": \"Menüyü görebilir miyiz lütfen?\", \"translated\": \"Could we see the menu, please?\"}, {\"original\": \"Önerdiğiniz özel yemekleriniz var mı?\", \"translated\": \"Do you have any signature dishes to recommend?\"}, {\"original\": \"Bunu ve bunu sipariş etmek istiyorum.\", \"translated\": \"I\'d like to order this, and this.\"}, {\"original\": \"Bir bardak su lütfen. Teşekkürler.\", \"translated\": \"A glass of water, please. Thanks.\"}, {\"original\": \"Hesap lütfen.\", \"translated\": \"The bill, please.\"}, {\"original\": \"Kredi kartıyla ödeyebilir miyim?\", \"translated\": \"Can I pay by credit card?\"}, {\"original\": \"Bunu alıp götürmem için paketleyebilir misiniz lütfen?\", \"translated\": \"Could you pack this to go, please?\"}, {\"original\": \"Yiyecekler çok lezzetliydi, teşekkür ederiz.\", \"translated\": \"The food was delicious, thank you.\"}]', 1, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Otelde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte otel ile ilgili 10 yaygın ifade ve İngilizce çevirileri:\"]', '[\"Kayıt Ol\", \"Çıkış Yap\", \"Oda Hizmeti\"]', 'tr', '[\"Şimdilik aklınızda özel bir durum var mı, örneğin oda konumu, diğer otel hizmetleri veya çıkış işlemi? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\", \"translated\": \"Hello, I have a reservation, here is my passport.\"}, {\"original\": \"Boş odanız var mı?\", \"translated\": \"Do you have any vacancies?\"}, {\"original\": \"Affedersiniz, otelde bir spor salonu veya çamaşırhane var mı?\", \"translated\": \"Excuse me, does the hotel have a gym or a laundry room?\"}, {\"original\": \"Kahvaltı saat kaçta başlıyor?\", \"translated\": \"What time does breakfast start?\"}, {\"original\": \"Lütfen bir oda anahtarı alabilir miyim?\", \"translated\": \"Could I have a room key, please?\"}, {\"original\": \"Lütfen bagajımı odaya taşımanıza yardımcı olur musunuz?\", \"translated\": \"Could you help me take my luggage to the room?\"}, {\"original\": \"Oda servisini nasıl arayabilirim?\", \"translated\": \"How do I call room service?\"}, {\"original\": \"Çıkış saati kaçta?\", \"translated\": \"What time is check-out?\"}, {\"original\": \"Bana bir makbuz/fatura yazabilir misiniz?\", \"translated\": \"Could you write me a receipt/invoice?\"}, {\"original\": \"Bagajımı burada bırakabilir miyim?\", \"translated\": \"Can I leave my luggage here?\"}]', 2, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Havaalanında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte havaalanı ile ilgili 10 yaygın ifade ve İngilizce çevirileri:\"]', '[\"Giriş yapma\", \"Uçağa binme\", \"Bagaj kontrolü\"]', 'tr', '[\"Şu anda aklınızda özel bir durum var mı, örneğin check-in, bagaj teslimi ya da araç kiralama hizmeti? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş masası nerede?\", \"translated\": \"Where is the check-in counter?\"}, {\"original\": \"Lütfen bir pencere koltuğu istiyorum.\", \"translated\": \"I\'d like a window seat, please.\"}, {\"original\": \"Bu uçuş gecikmiş mi?\", \"translated\": \"Is this flight delayed?\"}, {\"original\": \"Bu bagajı teslim etmem gerekiyor.\", \"translated\": \"I need to check this baggage.\"}, {\"original\": \"İniş kapısı nerede?\", \"translated\": \"Where is the boarding gate?\"}, {\"original\": \"Uçak kalkmak üzere.\", \"translated\": \"The plane is about to take off.\"}, {\"original\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\", \"translated\": \"Do I need to take out my laptop and power bank?\"}, {\"original\": \"Vergisiz mağaza nerede?\", \"translated\": \"Where is the duty-free shop?\"}, {\"original\": \"Bavulumu bulamıyorum.\", \"translated\": \"I can\'t find my suitcase.\"}, {\"original\": \"Tekerlekli sandalye hizmetiniz var mı?\", \"translated\": \"Do you have a wheelchair service?\"}]', 3, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Toplu taşıma araçlarında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Toplu Taşıma ile ilgili 10 yaygın ifade ve İngilizce çevirileri:\"]', '[\"Otobüs/Metro Kullanma\", \"Bilet Satın Alma\", \"Aktarma\"]', 'tr', '[\"Şimdilik aklınızda özel bir durum var mı, örneğin otobüs durağı sormak, bilet ücretini öğrenmek ya da inecek yer belirtmek? Soru sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bu otobüs terminala gidiyor mu?\", \"translated\": \"Does this bus go to the terminal?\"}, {\"original\": \"Bir sonraki durak nerede?\", \"translated\": \"What is the next stop?\"}, {\"original\": \"Bilet nereden alabilirim?\", \"translated\": \"Where can I buy a ticket?\"}, {\"original\": \"Lütfen bir tane XX\'e giden bilet.\", \"translated\": \"One ticket to XX, please.\"}, {\"original\": \"Aktarma yapmam gerekiyor mu?\", \"translated\": \"Do I need to transfer?\"}, {\"original\": \"Bir sonraki metro trenine ne kadar zaman var?\", \"translated\": \"How long until the next subway train?\"}, {\"original\": \"Affedersiniz, geçmem için yer açar mısınız?\", \"translated\": \"Excuse me, please let me pass.\"}, {\"original\": \"Bu koltuk alınmış mı?\", \"translated\": \"Is this seat taken?\"}, {\"original\": \"Affedersiniz, XX\'e gitmek için 2. Hat\'a nerede aktarım yapabilirim?\", \"translated\": \"Excuse me, where can I transfer to Line 2 to get to XX?\"}, {\"original\": \"XX\'e nasıl giderim?\", \"translated\": \"How do I get to XX?\"}]', 4, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Turistik yerlerde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte turistik yerlerle ilgili 10 yaygın ifade ve İngilizce çevirileri:\"]', '[\"Manzara Görme\", \"Fotoğraf Çekme\", \"Bilet Satın Alma\"]', 'tr', '[\"Şu an için aklınızda bilet fiyatını sorma, park yeri bulma veya tur rehberi hizmeti gibi belirli bir durum mu var? Sorunuzı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"How much is the entrance fee?\"}, {\"original\": \"Öğrenci biletleri mevcut mu?\", \"translated\": \"Are there student tickets available?\"}, {\"original\": \"Bu yer saat kaçta açılıyor?\", \"translated\": \"What time does the attraction open?\"}, {\"original\": \"Burada yapılacak eğlenceli şeyler neler?\", \"translated\": \"What are the fun things to do here?\"}, {\"original\": \"Bize bir fotoğraf çeker misiniz?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"Sightseeing otobüsü nerede?\", \"translated\": \"Where is the sightseeing bus?\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"En iyi görüntüleme noktası nerede?\", \"translated\": \"Where is the best viewing spot?\"}, {\"original\": \"Buradaki manzara çok güzel.\", \"translated\": \"The scenery here is beautiful.\"}, {\"original\": \"Rehberli tur mevcut mu?\", \"translated\": \"Is there a guided tour available?\"}]', 5, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Taksi veya taksi hizmeti ile ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Taksi veya Taksi Hizmeti ile ilgili 10 yaygın ifade ve İngilizce çevirileri:\"]', '[\"Taksiye Biniş\", \"Varış Yerini Belirtme\", \"Ödeme\"]', 'tr', '[\"Şu anda en çok ne yapmak istersiniz? Örneğin, varış yerini sormak, ücreti öğrenmek ya da fatura talep etmek gibi. Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bir taksi nerede bulabilirim?\", \"translated\": \"Where can I get a taxi?\"}, {\"original\": \"Lütfen beni bu adrese götürün.\", \"translated\": \"Please take me to this address.\"}, {\"original\": \"Yaklaşık olarak ne kadar tutar?\", \"translated\": \"Roughly how much will it be?\"}, {\"original\": \"Lütfen taksimetreyi kullanır mısınız?\", \"translated\": \"Could you use the meter, please?\"}, {\"original\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\", \"translated\": \"Please drive a bit faster, I\'m in a hurry.\"}, {\"original\": \"Lütfen burada durun.\", \"translated\": \"Please stop here.\"}, {\"original\": \"Kart veya mobil ödeme kabul ediyor musunuz?\", \"translated\": \"Do you accept cards or mobile payments?\"}, {\"original\": \"Lütfen bana bir makbuz verebilir misiniz?\", \"translated\": \"Could I have a receipt, please?\"}, {\"original\": \"Teşekkür ederim, şoför bey.\", \"translated\": \"Thank you, driver.\"}, {\"original\": \"Kaç dakika kaldı?\", \"translated\": \"How much further is it?\"}]', 6, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Eczanede kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte eczane ile ilgili 10 yaygın ifade ve İngilizce çevirileri:\"]', '[\"İlaç Satın Almak\", \"Danışmanlık\", \"Ödeme\"]', 'tr', '[\"Şimdilik aklınızda ilaç alma talimatları sorma, sigorta kullanımıyla ilgili ifadeler, tedavi süresi gibi belirli bir durum var mı? Soru sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Soğuk algınlığı ilacı var mı?\", \"translated\": \"Do you have cold medicine?\"}, {\"original\": \"Bu ilacı nasıl kullanmalıyım?\", \"translated\": \"How should I take this medicine?\"}, {\"original\": \"Ağrı kesici ilaçlarınız var mı?\", \"translated\": \"Do you have any painkillers?\"}, {\"original\": \"Kullanım kılavuzu var mı?\", \"translated\": \"Is there an instruction leaflet?\"}, {\"original\": \"Bu ilacın yan etkileri var mı?\", \"translated\": \"Does this medicine have any side effects?\"}, {\"original\": \"Sağlık sigortamı kullanabilir miyim?\", \"translated\": \"Can I use my medical insurance card?\"}, {\"original\": \"Lütfen bir kutu plastir yapabilir miyim?\", \"translated\": \"Could I have a box of Band-Aids, please?\"}, {\"original\": \"Ateş düşürücü ilaçlarınız var mı?\", \"translated\": \"Do you have any fever reducers?\"}, {\"original\": \"Hafif bir çizik aldım. Antiseptik ve plastiriniz var mı?\", \"translated\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\"}, {\"original\": \"Kaçta kapanıyorsunuz?\", \"translated\": \"What time do you close?\"}]', 7, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Acil Servislerle ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Acil Servislerle ilgili 10 yaygın ifade ve İngilizce çevirileri:\"]', '[\"Polisi Aramak\", \"İlkyardım\", \"Yardım Çağrısı\"]', 'tr', '[\"Şu an için aklınızda belirli bir acil durum var mı, örneğin yangın, yaralanma ve yardım gereksinimi, acil çağrı? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bana bir ambulans çağırmama yardımcı olun.\", \"translated\": \"Please help me call an ambulance.\"}, {\"original\": \"Hastane nerede?\", \"translated\": \"Where is the hospital?\"}, {\"original\": \"Birisi yaralandı.\", \"translated\": \"Someone is injured.\"}, {\"original\": \"Lütfen bana yardım edin.\", \"translated\": \"Please help me.\"}, {\"original\": \"Polis karakolu nerede?\", \"translated\": \"Where is the police station?\"}, {\"original\": \"Eşyalarımı kaybettim.\", \"translated\": \"I\'ve lost my belongings.\"}, {\"original\": \"Yangın departmanı numarası nedir?\", \"translated\": \"What is the number for the fire department?\"}, {\"original\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\", \"translated\": \"I\'ve lost my passport. Do you know where the nearest police station is?\"}, {\"original\": \"Acil çıkış var mı?\", \"translated\": \"Is there an emergency exit?\"}, {\"original\": \"Birisi bayıldı.\", \"translated\": \"Someone has fainted.\"}]', 8, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Sahilde veya havuz kenarında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte sahil veya havuz kenarıyla ilgili 10 yaygın ifade ve İngilizce çevirileri:\"]', '[\"Yüzme\", \"Güneşlenme\", \"Plaj Sporları\"]', 'tr', '[\"Şimdilik, katıldığınız yerel etkinlik veya festivale ilişkin bağlamı bana verebilir misiniz? Örneğin kültürel festival, gıda festivali veya müzik festivali gibi. Lütfen bağlamı belirtin.\", \"Katıldığınız etkinlikleri belirtir misiniz?\"]', '[\"Aklınızda özel bir durum mu var? Özgürce sorabilirsiniz.\", \"Aklınızda canlandırdığınız durumu tanımlar mısınız?\"]', '[{\"original\": \"Bak! Oradaki dalgalar gerçekten büyük.\", \"translated\": \"Look! The waves over there are really big.\"}, {\"original\": \"Güneş koruyucu sürmeyi unutma, buradaki UV ışınları çok güçlü.\", \"translated\": \"Remember to apply sunscreen, the UV rays here are very strong.\"}, {\"original\": \"Bu plajdaki kum o kadar ince ki pamuk üzerinde yürüyormuş gibi hissediyorsun.\", \"translated\": \"The sand on this beach is so fine, it feels like stepping on cotton.\"}, {\"original\": \"Plajda voleybol oynamak nasıl olur?\", \"translated\": \"How about playing volleyball on the beach?\"}, {\"original\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\", \"translated\": \"The sailboats in the distance look beautiful.\"}, {\"original\": \"Buradaki su o kadar berrak ki balıkları bile görebiliyorsun.\", \"translated\": \"The water here is so clear, you can even see the fish.\"}, {\"original\": \"Hadi biraz deniz kabuğu bulmaya gidelim.\", \"translated\": \"Let\'s go find some seashells.\"}, {\"original\": \"Günbatımında plajda yürüyüş yapmak kesinlikle çok romantik olmalı.\", \"translated\": \"Taking a walk on the beach at sunset must be very romantic.\"}, {\"original\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\", \"translated\": \"I heard the seafood here is very fresh, let\'s go try some.\"}, {\"original\": \"Deniz yükseliyor, hadi kıyıya doğru gidelim.\", \"translated\": \"The tide is coming in, let\'s head towards the shore.\"}]', 9, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Yerel Etkinlikler ve Festivallerde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Yerel Etkinlikler ve Festivallerle ilgili 10 yaygın ifade ile birlikte İngilizce çevirileri:\"]', '[\"Etkinliklere Katılmak\", \"Festivalleri Kutlamak\", \"Kültür Öğrenmek\"]', 'tr', '[\"Şimdilik, katıldığınız yerel etkinlik veya festivalin bağlamını, örneğin Cadılar Bayramı, konser veya arkadaş partisi gibi ya da başka bir şey olarak lütfen bana belirtir misiniz? Lütfen bağlamı sağlayın.\", \"Aklınızda canlandırdığınız etkinlikleri tanımlar mısınız?\"]', '[\"Aklınızda belirli bir durum mu var? Sorunuz için özgürsünüz.\", \"Aklınızda canlandırdığınız durumu tanımlar mısınız?\"]', '[{\"original\": \"Bugün herhangi bir etkinlik var mı?\", \"translated\": \"Are there any events today?\"}, {\"original\": \"Bu festivalle ilgili özel bir şey var mı?\", \"translated\": \"Is there anything special about this festival?\"}, {\"original\": \"Kutlama nerede yapılacak?\", \"translated\": \"Where is the celebration being held?\"}, {\"original\": \"Biletleri nasıl satın alabilirim?\", \"translated\": \"How can I buy tickets?\"}, {\"original\": \"Gösteri saat kaçta başlıyor?\", \"translated\": \"What time does the performance start?\"}, {\"original\": \"Hangi geleneksel yiyecekler var?\", \"translated\": \"What traditional food is there?\"}, {\"original\": \"Burada gerçekten hareketli.\", \"translated\": \"It\'s really lively here.\"}, {\"original\": \"Halka ait etkinlikler var mı?\", \"translated\": \"Are there any folk activities?\"}, {\"original\": \"Mutlu tatiller!\", \"translated\": \"Happy holidays!\"}, {\"original\": \"Etkinlik saat kaçta bitiyor?\", \"translated\": \"What time does the event end?\"}]', 10, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Müze veya Sanat Galerisi\'nde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Müze veya Sanat Galerisi ile ilgili 10 yaygın ifade ve İngilizce çevirileri:\"]', '[\"Ziyaret Etmek\", \"Rehberli Tur\", \"Bilet Satın Almak\"]', 'tr', '[\"Şimdilik aklınızda özel bir durum var mı, örneğin tanıtım kılavuzu istemek, yol haritasıyla ilgili ifadeler kullanmak ya da sergilenen eserler hakkında yorum yapmak gibi? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"How much is the admission fee?\"}, {\"original\": \"Sesli rehberiniz var mı?\", \"translated\": \"Do you have audio guides?\"}, {\"original\": \"Bu eseri kim yaratmış?\", \"translated\": \"Who created this artwork?\"}, {\"original\": \"Müzenin en değerli eseri nerede?\", \"translated\": \"Where is the museum\'s most prized piece?\"}, {\"original\": \"Fotoğraf çekmeye izin veriliyor mu?\", \"translated\": \"Is photography allowed?\"}, {\"original\": \"Burada özel sergiler var mı?\", \"translated\": \"Are there any special exhibitions here?\"}, {\"original\": \"Ziyaret kaç dakika sürüyor?\", \"translated\": \"How long does the visit take?\"}, {\"original\": \"Bize bir tanıtım yapabilir misiniz?\", \"translated\": \"Could you give us an introduction?\"}, {\"original\": \"Bu eserler gerçekten çok zarif.\", \"translated\": \"These works are truly exquisite.\"}, {\"original\": \"Hediyelik eşya dükkanı nerede?\", \"translated\": \"Where is the souvenir shop?\"}]', 11, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Kafelerde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte kafelerle ilgili 10 yaygın ifade ve İngilizce çevirileri:\"]', '[\"Kahvaltı Siparişi Verme\", \"Dinlenme\", \"Sosyalleşme\"]', 'tr', '[\"Şimdilik aklınızda menü istemek, buzlu veya sıcak içecekler sipariş etmek, diğer ürünler hakkında bilgi almak gibi belirli bir durum mu var? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bir latte alacağım.\", \"translated\": \"I\'ll have a latte, please.\"}, {\"original\": \"Wi-Fi var mı?\", \"translated\": \"Do you have Wi-Fi?\"}, {\"original\": \"Lütfen menüyü görebilir miyim?\", \"translated\": \"Could I see the menu, please?\"}, {\"original\": \"Yeniden doldurma yapılıyor mu?\", \"translated\": \"Are refills allowed?\"}, {\"original\": \"Kahvaltım hazır mı?\", \"translated\": \"Is my coffee ready?\"}, {\"original\": \"Burada ne kadar oturabilirim?\", \"translated\": \"How long can I sit here?\"}, {\"original\": \"Lütfen bize bir fotoğraf çeker misiniz?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"Hesap lütfen. Teşekkür ederim.\", \"translated\": \"Check, please. Thank you.\"}, {\"original\": \"Gerçekten çok lezzetli.\", \"translated\": \"It tastes really good.\"}]', 12, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a restaurant?\", \"Fantastic! Here are 10 common phrases related to restaurants, along with Turkish translations:\"]', '[\"Dining\", \"Ordering\", \"Checkout\"]', 'en', '[\"For now, do you have a specific situation in mind, such as ordering drinks, making a complaint, or asking about ingredients? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Excuse me, how much longer will our food be?\", \"translated\": \"Affedersiniz, yemeğimiz ne kadar sürede hazır olur?\"}, {\"original\": \"A table for two, please.\", \"translated\": \"İki kişi için bir masa, lütfen.\"}, {\"original\": \"Could we see the menu, please?\", \"translated\": \"Menüyü görebilir miyiz, lütfen?\"}, {\"original\": \"Do you have any signature dishes to recommend?\", \"translated\": \"Önerdiğiniz özel yemekleriniz var mı?\"}, {\"original\": \"I\'d like to order this, and this.\", \"translated\": \"Bunu ve bunu sipariş etmek istiyorum.\"}, {\"original\": \"A glass of water, please. Thanks.\", \"translated\": \"Bir bardak su, lütfen. Teşekkürler.\"}, {\"original\": \"The bill, please.\", \"translated\": \"Hesap, lütfen.\"}, {\"original\": \"Can I pay by credit card?\", \"translated\": \"Kredi kartıyla ödeyebilir miyim?\"}, {\"original\": \"Could you pack this to go, please?\", \"translated\": \"Bunu götürmek için paketleyebilir misiniz, lütfen?\"}, {\"original\": \"The food was delicious, thank you.\", \"translated\": \"Yiyecekler çok lezzetliydi, teşekkür ederiz.\"}]', 1, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a hotel?\", \"Fantastic! Here are 10 common phrases related to hotels, along with Turkish translations:\"]', '[\"Check-in\", \"Check-out\", \"Room Service\"]', 'en', '[\"For now, do you have a specific situation in mind, such as room location, other hotel services, or check-out? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Hello, I have a reservation, Here is my passport.\", \"translated\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\"}, {\"original\": \"Do you have any vacancies?\", \"translated\": \"Boş odanız var mı?\"}, {\"original\": \"Excuse me, does the hotel have a gym or a laundry room?\", \"translated\": \"Affedersiniz, otelde bir spor salonu veya çamaşırhane var mı?\"}, {\"original\": \"What time does breakfast start?\", \"translated\": \"Kahvaltı saat kaçta başlar?\"}, {\"original\": \"Could I have a room key, please?\", \"translated\": \"Lütfen bir oda anahtarı verebilir misiniz?\"}, {\"original\": \"Could you help me take my luggage to the room?\", \"translated\": \"Lütfen bagajımı odaya taşımama yardımcı olur musunuz?\"}, {\"original\": \"How do I call room service?\", \"translated\": \"Oda servisini nasıl ararım?\"}, {\"original\": \"What time is check-out?\", \"translated\": \"Çıkış saati kaçta?\"}, {\"original\": \"Could you write me a receipt/invoice?\", \"translated\": \"Bana bir makbuz/fatura yazabilir misiniz?\"}, {\"original\": \"Can I leave my luggage here?\", \"translated\": \"Bagajımı burada bırakabilir miyim?\"}]', 2, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use at the airport?\", \"Fantastic! Here are 10 common phrases related to the airport, along with Turkish translations:\"]', '[\"Check-in\", \"Boarding\", \"Baggage Check\"]', 'en', '[\"For now, do you have a specific situation in mind, such as check-in, baggage claim, or car rental service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Where is the check-in counter?\", \"translated\": \"Check-in masası nerede?\"}, {\"original\": \"I\'d like a window seat, please.\", \"translated\": \"Lütfen bir pencere koltuğu istiyorum.\"}, {\"original\": \"Is this flight delayed?\", \"translated\": \"Bu uçuş gecikmiş mi?\"}, {\"original\": \"I need to check this baggage.\", \"translated\": \"Bu bagajı kayıt ettirmem gerekiyor.\"}, {\"original\": \"Where is the boarding gate?\", \"translated\": \"İniş kapısı nerede?\"}, {\"original\": \"The plane is about to take off.\", \"translated\": \"Uçak kalkmak üzere.\"}, {\"original\": \"Do I need to take out my laptop and power bank?\", \"translated\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\"}, {\"original\": \"Where is the duty-free shop?\", \"translated\": \"Vergi içermeyen ürün mağazası nerede?\"}, {\"original\": \"I can\'t find my suitcase.\", \"translated\": \"Bavulumu bulamıyorum.\"}, {\"original\": \"Do you have a wheelchair service?\", \"translated\": \"Tekerlekli sandalye hizmetiniz var mı?\"}]', 3, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in public transportation?\", \"Fantastic! Here are 10 common phrases related to public transportation, along with Turkish translations:\"]', '[\"Taking Bus/Subway\", \"Buying Tickets\", \"Transferring\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking for a bus stop, ticket price, or getting off? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Does this bus go to the terminal?\", \"translated\": \"Bu otobüs terminale gidiyor mu?\"}, {\"original\": \"What is the next stop?\", \"translated\": \"Bir sonraki durak neresi?\"}, {\"original\": \"Where can I buy a ticket?\", \"translated\": \"Bilet nereden alınır?\"}, {\"original\": \"One ticket to XX, please.\", \"translated\": \"Lütfen bir adet XX\'e bilet.\"}, {\"original\": \"Do I need to transfer?\", \"translated\": \"Aktarma yapmam gerekiyor mu?\"}, {\"original\": \"How long until the next subway train?\", \"translated\": \"Bir sonraki metro trenine ne kadar zaman var?\"}, {\"original\": \"Excuse me, please let me pass.\", \"translated\": \"Affedersiniz, lütfen geçmem için yer açar mısınız?\"}, {\"original\": \"Is this seat taken?\", \"translated\": \"Bu koltuk boş mu?\"}, {\"original\": \"Excuse me, where can I transfer to Line 2 to get to XX?\", \"translated\": \"Affedersiniz, XX\'e gitmek için Hat 2\'ye nerede aktarma yapabilirim?\"}, {\"original\": \"How do I get to XX?\", \"translated\": \"XX\'e nasıl giderim?\"}]', 4, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in tourist attractions?\", \"Fantastic! Here are 10 common phrases related to tourist attractions, along with Turkish translations:\"]', '[\"Sightseeing\", \"Taking Photos\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking about ticket prices, finding a parking lot, or requesting tour guide services? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"How much is the entrance fee?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"Are there student tickets available?\", \"translated\": \"Öğrenci biletleri mevcut mu?\"}, {\"original\": \"What time does the attraction open?\", \"translated\": \"Bu yer saat kaçta açılıyor?\"}, {\"original\": \"What are the fun things to do here?\", \"translated\": \"Burada yapılacak eğlenceli şeyler neler?\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"Bize bir fotoğraf çeker misiniz?\"}, {\"original\": \"Where is the sightseeing bus?\", \"translated\": \"Gezi otobüsü nerede?\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"Where is the best viewing spot?\", \"translated\": \"En iyi manzara noktası nerede?\"}, {\"original\": \"The scenery here is beautiful.\", \"translated\": \"Buradaki manzara çok güzel.\"}, {\"original\": \"Is there a guided tour available?\", \"translated\": \"Rehberli tur mevcut mu?\"}]', 5, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in Taxi or Taxi Service?\", \"Fantastic! Here are 10 common phrases related to Taxi or Taxi Service, along with Turkish translations:\"]', '[\"Taking Taxi\", \"Telling Destination\", \"Payment\"]', 'en', '[\"For now, what do you most want to do now—such as asking for the destination, the fare, or requesting an invoice? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Where can I get a taxi?\", \"translated\": \"Bir taksi nerede bulabilirim?\"}, {\"original\": \"Please take me to this address.\", \"translated\": \"Lütfen beni bu adrese götürün.\"}, {\"original\": \"Roughly how much will it be?\", \"translated\": \"Yaklaşık olarak ne kadar olur?\"}, {\"original\": \"Could you use the meter, please?\", \"translated\": \"Lütfen taksimetreyi kullanır mısınız?\"}, {\"original\": \"Please drive a bit faster, I\'m in a hurry.\", \"translated\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\"}, {\"original\": \"Please stop here.\", \"translated\": \"Lütfen burada durun.\"}, {\"original\": \"Do you accept cards or mobile payments?\", \"translated\": \"Kart veya mobil ödeme kabul ediyor musunuz?\"}, {\"original\": \"Could I have a receipt, please?\", \"translated\": \"Lütfen bir fiş verebilir misiniz?\"}, {\"original\": \"Thank you, driver.\", \"translated\": \"Teşekkür ederim, şoför bey.\"}, {\"original\": \"How much further is it?\", \"translated\": \"Kaç kilometre daha var?\"}]', 6, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in pharmacy?\", \"Fantastic! Here are 10 common phrases related to pharmacy, along with Turkish translations:\"]', '[\"Buying Medicine\", \"Consultation\", \"Payment\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking for instructions on taking medicine, phrases related to using insurance, or duration of medication? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Do you have cold medicine?\", \"translated\": \"Soğuk algınlığı ilacı var mı?\"}, {\"original\": \"How should I take this medicine?\", \"translated\": \"Bu ilacı nasıl kullanmalıyım?\"}, {\"original\": \"Do you have any painkillers?\", \"translated\": \"Ağrı kesici var mı?\"}, {\"original\": \"Is there an instruction leaflet?\", \"translated\": \"Kullanım kılavuzu var mı?\"}, {\"original\": \"Does this medicine have any side effects?\", \"translated\": \"Bu ilacın yan etkileri var mı?\"}, {\"original\": \"Can I use my medical insurance card?\", \"translated\": \"Tıbbi sigorta kartımı kullanabilir miyim?\"}, {\"original\": \"Could I have a box of Band-Aids, please?\", \"translated\": \"Lütfen bir kutu yara bandı verebilir misiniz?\"}, {\"original\": \"Do you have any fever reducers?\", \"translated\": \"Ateş düşürücü ilaç var mı?\"}, {\"original\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\", \"translated\": \"Hafif bir sıyrık var. Antiseptik ve yara bandı var mı?\"}, {\"original\": \"What time do you close?\", \"translated\": \"Kaçta kapanıyorsunuz?\"}]', 7, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in Emergency Services?\", \"Fantastic! Here are 10 common phrases related to Emergency Services, along with Turkish translations:\"]', '[\"Calling Police\", \"First Aid\", \"Calling for Help\"]', 'en', '[\"For now, do you have a specific emergency situation in mind, such as fire, injury and need for help, or an emergency call? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Please help me call an ambulance.\", \"translated\": \"Lütfen bana bir ambulans çağırmada yardımcı olun.\"}, {\"original\": \"Where is the hospital?\", \"translated\": \"Hastane nerede?\"}, {\"original\": \"Someone is injured.\", \"translated\": \"Birisi yaralanmış.\"}, {\"original\": \"Please help me.\", \"translated\": \"Lütfen bana yardım edin.\"}, {\"original\": \"Where is the police station?\", \"translated\": \"Polis karakolu nerede?\"}, {\"original\": \"I\'ve lost my belongings.\", \"translated\": \"Eşyalarımı kaybettim.\"}, {\"original\": \"What is the number for the fire department?\", \"translated\": \"İtfaiye numarası nedir?\"}, {\"original\": \"I\'ve lost my passport. Do you know where the nearest police station is?\", \"translated\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\"}, {\"original\": \"Is there an emergency exit?\", \"translated\": \"Acil çıkış var mı?\"}, {\"original\": \"Someone has fainted.\", \"translated\": \"Birisi bayılmış.\"}]', 8, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use at the beach or poolside?\", \"Fantastic! Here are 10 common phrases related to the beach or poolside, along with Turkish translations:\"]', '[\"Swimming\", \"Sunbathing\", \"Beach Sports\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you’re attending, such as a cultural festival, food festival, or music festival? Please provide the context.\", \"Please provide the activities that you attend.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation you have in mind.\"]', '[{\"original\": \"Look! The waves over there are really big.\", \"translated\": \"Bak! Oradaki dalgalar gerçekten büyük.\"}, {\"original\": \"Remember to apply sunscreen, the UV rays here are very strong.\", \"translated\": \"Güneş koruyucu sürmeyi unutma, buradaki UV ışınları çok güçlü.\"}, {\"original\": \"The sand on this beach is so fine, it feels like stepping on cotton.\", \"translated\": \"Bu plajdaki kum çok ince, pamuk üzerinde yürüyormuş gibi hissettiriyor.\"}, {\"original\": \"How about playing volleyball on the beach?\", \"translated\": \"Plajda voleybol oynamak nasıl olur?\"}, {\"original\": \"The sailboats in the distance look beautiful.\", \"translated\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\"}, {\"original\": \"The water here is so clear, you can even see the fish.\", \"translated\": \"Buradaki su çok berrak, balıkları bile görebiliyorsun.\"}, {\"original\": \"Let\'s go find some seashells.\", \"translated\": \"Hadi biraz deniz kabuğu arayalım.\"}, {\"original\": \"Taking a walk on the beach at sunset must be very romantic.\", \"translated\": \"Gün batımında plajda yürüyüş yapmak çok romantik olmalı.\"}, {\"original\": \"I heard the seafood here is very fresh, let\'s go try some.\", \"translated\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\"}, {\"original\": \"The tide is coming in, let\'s head towards the shore.\", \"translated\": \"Gelgit geliyor, kıyıya doğru gidelim.\"}]', 9, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in Local Events and Festivals?\", \"Fantastic! Here are 10 common phrases related to Local Events and Festivals, along with Turkish translations:\"]', '[\"Attending Events\", \"Celebrating Festivals\", \"Learning Culture\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you’re attending, such as Halloween, a concert, a friend’s party, or something else? Please provide the context.\", \"Please describe the activities you have in mind.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation you have in mind.\"]', '[{\"original\": \"Are there any events today?\", \"translated\": \"Bugün herhangi bir etkinlik var mı?\"}, {\"original\": \"Is there anything special about this festival?\", \"translated\": \"Bu festival hakkında özel bir şey var mı?\"}, {\"original\": \"Where is the celebration being held?\", \"translated\": \"Kutlama nerede yapılıyor?\"}, {\"original\": \"How can I buy tickets?\", \"translated\": \"Biletleri nasıl satın alabilirim?\"}, {\"original\": \"What time does the performance start?\", \"translated\": \"Gösteri saat kaçta başlıyor?\"}, {\"original\": \"What traditional food is there?\", \"translated\": \"Hangi geleneksel yiyecekler var?\"}, {\"original\": \"It\'s really lively here.\", \"translated\": \"Burada gerçekten hareketli bir atmosfer var.\"}, {\"original\": \"Are there any folk activities?\", \"translated\": \"Herhangi bir halk etkinliği var mı?\"}, {\"original\": \"Happy holidays!\", \"translated\": \"Mutlu tatiller!\"}, {\"original\": \"What time does the event end?\", \"translated\": \"Etkinlik saat kaçta bitiyor?\"}]', 10, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a museum or art gallery?\", \"Fantastic! Here are 10 common phrases related to museums or art galleries, along with Turkish translations:\"]', '[\"Visiting\", \"Guided Tour\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking for an introduction manual, phrases related to a roadmap, or phrases related to commenting on an exhibit? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"How much is the admission fee?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"Do you have audio guides?\", \"translated\": \"Sesli rehberleriniz var mı?\"}, {\"original\": \"Who created this artwork?\", \"translated\": \"Bu eseri kim yaratmış?\"}, {\"original\": \"Where is the museum\'s most prized piece?\", \"translated\": \"Müzenin en değerli eseri nerede?\"}, {\"original\": \"Is photography allowed?\", \"translated\": \"Fotoğraf çekmeye izin veriliyor mu?\"}, {\"original\": \"Are there any special exhibitions here?\", \"translated\": \"Burada özel sergiler var mı?\"}, {\"original\": \"How long does the visit take?\", \"translated\": \"Ziyaret ne kadar sürer?\"}, {\"original\": \"Could you give us an introduction?\", \"translated\": \"Bize bir giriş yapar mısınız?\"}, {\"original\": \"These works are truly exquisite.\", \"translated\": \"Bu eserler gerçekten muhteşem.\"}, {\"original\": \"Where is the souvenir shop?\", \"translated\": \"Hediyelik eşya dükkanı nerede?\"}]', 11, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in cafes?\", \"Fantastic! Here are 10 common phrases related to cafes, along with Turkish translations:\"]', '[\"Ordering Coffee\", \"Resting\", \"Socializing\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking for a menu, ordering iced or hot drinks, or requesting other products? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"I\'ll have a latte, please.\", \"translated\": \"Bir latte alacağım, lütfen.\"}, {\"original\": \"Do you have Wi-Fi?\", \"translated\": \"Wi-Fi var mı?\"}, {\"original\": \"Could I see the menu, please?\", \"translated\": \"Menüyü görebilir miyim, lütfen?\"}, {\"original\": \"Are refills allowed?\", \"translated\": \"İkinci dolumlar kabul ediliyor mu?\"}, {\"original\": \"Is my coffee ready?\", \"translated\": \"Kahvaltım hazır mı?\"}, {\"original\": \"How long can I sit here?\", \"translated\": \"Burada ne kadar süre oturabilirim?\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"Bize bir fotoğraf çekebilir misiniz?\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"Check, please. Thank you.\", \"translated\": \"Hesap, lütfen. Teşekkür ederim.\"}, {\"original\": \"It tastes really good.\", \"translated\": \"Gerçekten çok lezzetli.\"}]', 12, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في المطعم؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بالمطاعم، مع الترجمات التركية لها:\"]', '[\"الوجبات\", \"الطلب\", \"إنهاء الشراء\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف محدد في ذهنك، مثل طلب المشروبات أو تقديم شكوى أو الاستفسار عن المكونات؟ لا تتردد في السؤال.\", \"يرجى وصف الموقف الذي يدور في ذهنك.\"]', NULL, '[{\"original\": \"عذرًا، كم من الوقت سيستغرق وصول طعامنا؟\", \"translated\": \"Affedersiniz, yemeğimiz ne kadar sürede gelecek?\"}, {\"original\": \"طاولة لشخصين، من فضلكم.\", \"translated\": \"İki kişilik bir masa, lütfen.\"}, {\"original\": \"هل يمكننا رؤية القائمة، من فضلكم؟\", \"translated\": \"Menüyü görebilir miyiz, lütfen?\"}, {\"original\": \"هل لديكم أطباق مميزة توصون بها؟\", \"translated\": \"Önerdiğiniz özel yemekleriniz var mı?\"}, {\"original\": \"أود طلب هذا وهذا.\", \"translated\": \"Bunu ve bunu sipariş etmek istiyorum.\"}, {\"original\": \"كوب من الماء، من فضلك. شكرًا.\", \"translated\": \"Bir su bardağı, lütfen. Teşekkür ederim.\"}, {\"original\": \"الفاتورة، من فضلك.\", \"translated\": \"Hesap, lütfen.\"}, {\"original\": \"هل يمكنني الدفع باستخدام بطاقة الائتمان؟\", \"translated\": \"Kredi kartıyla ödeyebilir miyim?\"}, {\"original\": \"هل يمكنكم تغليف هذا لآخذه معي، من فضلكم؟\", \"translated\": \"Bunu götürmek için paketleyebilir misiniz, lütfen?\"}, {\"original\": \"كان الطعام لذيذًا، شكرًا لكم.\", \"translated\": \"Yemek çok lezzetliydi, teşekkür ederiz.\"}]', 1, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في الفندق؟\", \"رائع! إليكم عشر عبارات شائعة تتعلق بالفندق، مع الترجمات التركية لها:\"]', '[\"تسجيل الدخول\", \"تسجيل المغادرة\", \"خدمة الغرف\"]', 'ar', '[\"في الوقت الحالي، هل لديكم موقف محدد في بالكم، مثل موقع الغرفة أو أي خدمة أخرى يقدمها الفندق أو إجراءات المغادرة؟ لا تترددوا في طرح الأسئلة.\", \"يرجى وصف الموقف الذي تفكرون فيه.\"]', NULL, '[{\"original\": \"مرحبًا، لدي حجز، وهذه جواز سفري.\", \"translated\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\"}, {\"original\": \"هل لديكم أي غرف شاغرة؟\", \"translated\": \"Boş odanız var mı?\"}, {\"original\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسيل الملابس؟\", \"translated\": \"Affedersiniz, otelinizde bir spor salonu veya çamaşırhane var mı?\"}, {\"original\": \"في أي وقت تبدأ وجبة الإفطار؟\", \"translated\": \"Kahvaltı saat kaçta başlar?\"}, {\"original\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\", \"translated\": \"Oda anahtarını alabilir miyim, lütfen?\"}, {\"original\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\", \"translated\": \"Bavullarımı odaya taşımanıza yardımcı olur musunuz?\"}, {\"original\": \"كيف أتصل بخدمة الغرف؟\", \"translated\": \"Oda servisini nasıl arayabilirim?\"}, {\"original\": \"في أي وقت يكون وقت المغادرة؟\", \"translated\": \"Çıkış saati kaçta?\"}, {\"original\": \"هل يمكنكم إعطائي إيصالاً/فاتورة؟\", \"translated\": \"Bana bir makbuz/fatura verebilir misiniz?\"}, {\"original\": \"هل يمكنني ترك أمتعتي هنا؟\", \"translated\": \"Bavullarımı burada bırakabilir miyim?\"}]', 2, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في المطار؟\", \"رائع! إليكم عشر عبارات شائعة تتعلق بالمطار، مع الترجمات التركية لها:\"]', '[\"التسجيل\", \"الصعود إلى الطائرة\", \"فحص الأمتعة\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف معين في بالك، مثل إجراءات تسجيل الوصول أو استلام الأمتعة أو خدمة تأجير السيارات؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي يدور في ذهنك.\"]', NULL, '[{\"original\": \"أين كاونتر تسجيل الدخول؟\", \"translated\": \"Giriş masası nerede?\"}, {\"original\": \"أود أن أجلس في مقعد بجانب النافذة، من فضلك.\", \"translated\": \"Lütfen pencere kenarında bir koltuk istiyorum.\"}, {\"original\": \"هل هذا الرحلة متأخرة؟\", \"translated\": \"Bu uçuş gecikmiş mi?\"}, {\"original\": \"أحتاج إلى تسجيل هذه الأمتعة.\", \"translated\": \"Bu bagajı kayıt ettirmem gerekiyor.\"}, {\"original\": \"أين بوابة الصعود إلى الطائرة؟\", \"translated\": \"Uçağa binme kapısı nerede?\"}, {\"original\": \"الطائرة على وشك الإقلاع.\", \"translated\": \"Uçak kalkmak üzere.\"}, {\"original\": \"هل يجب أن أخرج جهاز الكمبيوتر المحمول والبنك الكهربائي الخاص بي؟\", \"translated\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\"}, {\"original\": \"أين متجر التجزئة المعفي من الرسوم الجمركية؟\", \"translated\": \"Vergi içermeyen ürün mağazası nerede?\"}, {\"original\": \"لا أستطيع العثور على حقيبتي.\", \"translated\": \"Bavulumu bulamıyorum.\"}, {\"original\": \"هل لديكم خدمة عربات كرسي متحرك؟\", \"translated\": \"Tekerlekli sandalye hizmetiniz var mı?\"}]', 3, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في وسائل النقل العام؟\", \"رائع! إليكم عشر عبارات شائعة تتعلق بوسائل النقل العام، مع الترجمات التركية لها:\"]', '[\"ركوب الحافلة أو المترو\", \"شراء التذاكر\", \"التحويل\"]', 'ar', '[\"في الوقت الراهن، هل لديك موقفٌ معيّن في ذهنك، مثل الاستفسار عن موقف الحافلة أو سعر التذكرة أو طلب النزول من الحافلة؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي يدور في ذهنك.\"]', NULL, '[{\"original\": \"هل هذه الحافلة تذهب إلى المحطة؟\", \"translated\": \"Bu otobüs terminal\'e mi gidiyor?\"}, {\"original\": \"ما هي المحطة التالية؟\", \"translated\": \"Bir sonraki durak neresi?\"}, {\"original\": \"أين يمكنني شراء تذكرة؟\", \"translated\": \"Bilet nereden alabilirim?\"}, {\"original\": \"تذكرة واحدة إلى XX، من فضلك.\", \"translated\": \"Lütfen bir adet XX\'e bilet.\"}, {\"original\": \"هل عليّ التحويل؟\", \"translated\": \"Aktarma yapmam gerekiyor mu?\"}, {\"original\": \"كم من الوقت بقي حتى القطار التالي في المترو؟\", \"translated\": \"Bir sonraki metro trenine ne kadar zaman kaldı?\"}, {\"original\": \"عذرًا، من فضلك اسمح لي بالمرور.\", \"translated\": \"Affedersiniz, geçmem için izin verir misiniz?\"}, {\"original\": \"هل هذا المقعد مشغول؟\", \"translated\": \"Bu koltuk boş mu?\"}, {\"original\": \"عذرًا، أين يمكنني التحويل إلى الخط ٢ للوصول إلى XX؟\", \"translated\": \"Affedersiniz, XX\'e gitmek için Hat 2\'ye nerede aktarma yapabilirim?\"}, {\"original\": \"كيف أصل إلى XX؟\", \"translated\": \"XX\'e nasıl giderim?\"}]', 4, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في أماكن الجذب السياحي؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بأماكن الجذب السياحي، مع الترجمات التركية لها:\"]', '[\"السياحة\", \"التقاط الصور\", \"شراء التذاكر\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقفٌ معيّن في ذهنك، مثل الاستفسار عن سعر التذاكر أو إيجاد موقف للسيارات أو طلب خدمة دليل سياحي؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي يدور في ذهنك.\"]', NULL, '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"هل توجد تذاكر مخصصة للطلاب؟\", \"translated\": \"Öğrenci biletleri mevcut mu?\"}, {\"original\": \"متى يفتح مكان الجذب أبوابه؟\", \"translated\": \"İlgi çekici yer saat kaçta açıyor?\"}, {\"original\": \"ما الأشياء الممتعة التي يمكن القيام بها هنا؟\", \"translated\": \"Burada yapılabilecek eğlenceli şeyler nelerdir?\"}, {\"original\": \"هل يمكنك أن تلتقط لنا صورة؟\", \"translated\": \"Bize bir fotoğraf çeker misiniz?\"}, {\"original\": \"أين حافلة الجولات السياحية؟\", \"translated\": \"Seyahat otobüsü nerede?\"}, {\"original\": \"أين الحمام؟\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"ما أفضل مكان لمشاهدة المناظر؟\", \"translated\": \"En iyi manzara noktası nerede?\"}, {\"original\": \"المنظر هنا جميل جدًا.\", \"translated\": \"Manzara burada çok güzel.\"}, {\"original\": \"هل تتوفر جولة إرشادية؟\", \"translated\": \"Rehberli tur mevcut mu?\"}]', 5, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها عند استئجار تاكسي أو استخدام خدمة التاكسي؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بالتاكسي أو خدمة التاكسي، مع الترجمة التركية لها:\"]', '[\"أخذ تاكسي\", \"إبلاغ الوجهة\", \"الدفع\"]', 'ar', '[\"في الوقت الحالي، ما الشيء الذي ترغب في فعله أكثر ما يخطر لك الآن، مثل طلب الوجهة أو سؤال عن السعر أو طلب فاتورة، فلا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي تتصوره في ذهنك.\"]', NULL, '[{\"original\": \"أين يمكنني أن أستقل تاكسي؟\", \"translated\": \"Bir taksi nerede bulabilirim?\"}, {\"original\": \"من فضلك خذني إلى هذا العنوان.\", \"translated\": \"Lütfen beni bu adrese götürün.\"}, {\"original\": \"كم سيكون المبلغ تقريبًا؟\", \"translated\": \"Yaklaşık olarak ne kadar olur?\"}, {\"original\": \"هل يمكنك استخدام العداد، من فضلك؟\", \"translated\": \"Lütfen taksimetre kullanır mısınız?\"}, {\"original\": \"من فضلك ا-driving أسرع قليلًا، فأنا في عجلة من أمري.\", \"translated\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\"}, {\"original\": \"من فضلك توقف هنا.\", \"translated\": \"Lütfen burada durun.\"}, {\"original\": \"هل تقبلون الدفع بالبطاقات أو الدفع عبر الهاتف المحمول؟\", \"translated\": \"Kart veya mobil ödeme kabul ediyor musunuz?\"}, {\"original\": \"هل يمكنني الحصول على إشعار دفع، من فضلك؟\", \"translated\": \"Lütfen bir makbuz verebilir misiniz?\"}, {\"original\": \"شكرًا لك يا سائق.\", \"translated\": \"Teşekkür ederim, şoför bey.\"}, {\"original\": \"كم تبقى بعد من المسافة؟\", \"translated\": \"Kaç dakika kaldı?\"}]', 6, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في الصيدلية؟\", \"رائع! إليكم عشر عبارات شائعة مرتبطة بالصيدلية، مع الترجمات التركية لها:\"]', '[\"شراء أدوية\", \"استشارة\", \"دفع\"]', 'ar', '[\"في الوقت الحالي، هل لديكم موقف محدد في ذهنكم، مثل طلب تعليمات حول كيفية تناول الدواء، أو عبارات مرتبطة باستخدام التأمين الصحي، أو مدة العلاج؟ لا تترددوا في طرح الأسئلة.\", \"من فضلكم وصفوا الموقف الذي يخطر ببالكم.\"]', NULL, '[{\"original\": \"هل لديك دواء لعلاج البرد؟\", \"translated\": \"Soğuk algınlığı ilacı var mı?\"}, {\"original\": \"كيف يجب أن آخذ هذا الدواء؟\", \"translated\": \"Bu ilacı nasıl kullanmalıyım?\"}, {\"original\": \"هل لديك أي مسكنات للألم؟\", \"translated\": \"Ağrı kesici bir ilaç var mı?\"}, {\"original\": \"هل يوجد نشرة إرشادات؟\", \"translated\": \"Kullanım kılavuzu var mı?\"}, {\"original\": \"هل لهذا الدواء أي آثار جانبية؟\", \"translated\": \"Bu ilacın yan etkileri var mı?\"}, {\"original\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\", \"translated\": \"Sağlık sigortamı kullanabilir miyim?\"}, {\"original\": \"هل يمكنني الحصول على علبة من الشاش الطبي، من فضلكم؟\", \"translated\": \"Lütfen bir kutu yara bandı verebilir misiniz?\"}, {\"original\": \"هل لديك أي خافضات للحرارة؟\", \"translated\": \"Ateş düşürücü ilaç var mı?\"}, {\"original\": \"لدي جرح سطحي بسيط. هل لديك أي مطهر وشاش طبي؟\", \"translated\": \"Hafif bir sıyrık var. Antiseptik ve yara bandı var mı?\"}, {\"original\": \"في أي وقت تغلقون؟\", \"translated\": \"Kaçta kapanıyorsunuz?\"}]', 7, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في خدمات الطوارئ؟\", \"رائع! إليكم عشر عبارات شائعة تتعلق بخدمات الطوارئ، مع الترجمات التركية لها:\"]', '[\"الاتصال بالشرطة\", \"الإسعافات الأولية\", \"الاستغاثة\"]', 'ar', '[\"في الوقت الحالي، هل توجد لديك حالة طارئة محددة في بالك، مثل الحريق أو الإصابة والاحتياج للمساعدة أو الاتصال بالطوارئ؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الحالة التي تدور في ذهنك.\"]', NULL, '[{\"original\": \"من فضلك ساعدني في الاتصال بالإسعاف.\", \"translated\": \"Lütfen bana ambulans çağırma konusunda yardımcı olur musunuz?\"}, {\"original\": \"أين المستشفى؟\", \"translated\": \"Hastane nerede?\"}, {\"original\": \"شخص ما أصيب.\", \"translated\": \"Birisi yaralandı.\"}, {\"original\": \"من فضلك ساعدني.\", \"translated\": \"Lütfen bana yardım eder misiniz?\"}, {\"original\": \"أين قسم الشرطة؟\", \"translated\": \"Polis karakolu nerede?\"}, {\"original\": \"لقد فقدت أغراضي.\", \"translated\": \"Eşyalarımı kaybettim.\"}, {\"original\": \"ما هو رقم إدارة الإطفاء؟\", \"translated\": \"İtfaiye numarası nedir?\"}, {\"original\": \"لقد فقدت جواز سفري. هل تعرف أين أقرب قسم شرطة؟\", \"translated\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\"}, {\"original\": \"هل يوجد مخرج طوارئ؟\", \"translated\": \"Acil çıkış var mı?\"}, {\"original\": \"شخص ما فقد وعيه.\", \"translated\": \"Birisi bayıldı.\"}]', 8, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها على الشاطئ أو بالقرب من المسبح؟\", \"رائع! إليكم عشر عبارات شائعة مرتبطة بالشاطئ أو المسبح، مع الترجمات التركية لها:\"]', '[\"السباحة\", \"الاستلقاء تحت أشعة الشمس\", \"الرياضات الشاطئية\"]', 'ar', '[\"في الوقت الحالي، هل يمكنكم تزويدي بسياق الحدث المحلي أو المهرجان الذي ستحضرونه، مثل مهرجان ثقافي أو مهرجان غذائي أو مهرجان موسيقي؟ يُرجى تزويدي بهذا السياق.\", \"يرجى تزويدي بالأنشطة التي ستشاركون فيها.\"]', '[\"هل لديكم موقفٌ معيّن في أذهانكم؟ لا تترددوا في طرح أي سؤال.\", \"يرجى وصف الموقف الذي تفكرون فيه.\"]', '[{\"original\": \"انظر! الأمواج هناك كبيرة جدًّا.\", \"translated\": \"Bak! Oradaki dalgalar gerçekten büyük.\"}, {\"original\": \"تذكَّر أن تضع واقي الشمس، فأشعة فوق البنفسجية هنا قوية جدًّا.\", \"translated\": \"Güneş kremi sürmeyi unutma, buradaki UV ışınları çok güçlü.\"}, {\"original\": \"الرمل على هذه الشاطئ ناعم جدًّا، لدرجة أن المشي عليه يشبه المشي على القطن.\", \"translated\": \"Bu plajdaki kum çok ince, üzerinde yürümek pamuk üzerinde yürüyormuş gibi hissettiriyor.\"}, {\"original\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\", \"translated\": \"Plajda voleybol oynamak nasıl olur?\"}, {\"original\": \"القوارب الشراعية في الأفق تبدو جميلة جدًّا.\", \"translated\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\"}, {\"original\": \"الماء هنا شفاف جدًّا، بل يمكنك رؤية الأسماك حتى.\", \"translated\": \"Buradaki su çok berrak, balıkları bile görebilirsin.\"}, {\"original\": \"هيا نذهب للبحث عن بعض المحار.\", \"translated\": \"Hadi biraz deniz kabuğu arayalım.\"}, {\"original\": \"التنزه على الشاطئ عند غروب الشمس يجب أن يكون رومانسيًّا جدًّا.\", \"translated\": \"Gün batımında plajda yürüyüş yapmak çok romantik olmalı.\"}, {\"original\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًّا، فلنذهب ونجرب بعضها.\", \"translated\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\"}, {\"original\": \"المدّ قادم، فلنتحرك نحو الساحل.\", \"translated\": \"Deniz suyu yükseliyor, kıyıya doğru gidelim.\"}]', 9, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بعشر عبارات شائعة يمكنني استخدامها في الفعاليات والمهرجانات المحلية؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بالفعاليات والمهرجانات المحلية، مع الترجمات التركية لها:\"]', '[\"حضور الفعاليات\", \"الاحتفال بالمناسبات\", \"تعلم الثقافة\"]', 'ar', '[\"في الوقت الحالي، هل يمكنك إخباري عن سياق الفعالية أو المهرجان المحلي الذي ستشارك فيه، مثل عيد الهالوين أو حفلة موسيقية أو حفلة صديق أو أي شيء آخر؟ يُرجى تزويدي بهذا السياق.\", \"يرجى وصف الأنشطة التي تتبادر إلى ذهنك.\"]', '[\"هل لديك موقف معيّن في ذهنك؟ لا تتردد في طرح سؤال.\", \"يرجى وصف الموقف الذي تتخيله في ذهنك.\"]', '[{\"original\": \"هل توجد أي فعاليات اليوم؟\", \"translated\": \"Bugün herhangi bir etkinlik var mı?\"}, {\"original\": \"هل هناك شيءٌ مميزٌ في هذه المهرجان؟\", \"translated\": \"Bu festivalde özel bir şey var mı?\"}, {\"original\": \"أين تُقام الاحتفالية؟\", \"translated\": \"Kutlama nerede yapılacak?\"}, {\"original\": \"كيف يمكنني شراء التذاكر؟\", \"translated\": \"Biletleri nasıl alabilirim?\"}, {\"original\": \"متى يبدأ العرض؟\", \"translated\": \"Gösteri saat kaçta başlıyor?\"}, {\"original\": \"ما الأطعمة التقليدية المتاحة؟\", \"translated\": \"Hangi geleneksel yiyecekler mevcut?\"}, {\"original\": \"المكان نابضٌ بالحياة حقًا.\", \"translated\": \"Burada gerçekten hareketli bir atmosfer var.\"}, {\"original\": \"هل توجد أنشطة شعبية؟\", \"translated\": \"Halk oyunları gibi etkinlikler var mı?\"}, {\"original\": \"أعياد سعيدة!\", \"translated\": \"Mutlu Bayramlar!\"}, {\"original\": \"متى تنتهي الفعالية؟\", \"translated\": \"Etkinlik saat kaçta bitiyor?\"}]', 10, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في متحف أو معرض فني؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بالمتحف أو المعرض الفني، مع الترجمات التركية لها:\"]', '[\"الزيارة\", \"الجولة المُرشدة\", \"شراء التذاكر\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف معين في ذهنك، مثل طلب دليل تعريفي، أو عبارات تتعلق بالخريطة التوجيهية، أو عبارات تتعلق بالتعليق على المعروضات؟ لا تتردد في السؤال.\", \"من فضلك وصف الموقف الذي في ذهنك.\"]', NULL, '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"Giriş ücreti ne kadardır?\"}, {\"original\": \"هل لديكم أدلة صوتية؟\", \"translated\": \"Sesli rehberleriniz var mı?\"}, {\"original\": \"من هو من أنشأ هذه القطعة الفنية؟\", \"translated\": \"Bu eseri kim yaratmıştır?\"}, {\"original\": \"أين تقع أثمن قطعة في المتحف؟\", \"translated\": \"Müzeyin en değerli eseri nerededir?\"}, {\"original\": \"هل يُسمح بالتقاط الصور؟\", \"translated\": \"Fotoğraf çekmeye izin veriliyor mu?\"}, {\"original\": \"هل توجد هنا أي معارض خاصة؟\", \"translated\": \"Burada özel sergiler var mı?\"}, {\"original\": \"كم تستغرق الزيارة؟\", \"translated\": \"Ziyaret ne kadar sürer?\"}, {\"original\": \"هل يمكنكم أن تقدّموا لنا مقدمة؟\", \"translated\": \"Bize bir giriş yapabilir misiniz?\"}, {\"original\": \"هذه الأعمال فعلاً رائعة.\", \"translated\": \"Bu eserler gerçekten muhteşem.\"}, {\"original\": \"أين متجر الهدايا التذكارية؟\", \"translated\": \"Hatıra eşyaları mağazası nerede?\"}]', 11, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في المقاهي؟\", \"رائع! إليك عشر عبارات شائعة مرتبطة بالمقاهي، مع الترجمات التركية لها:\"]', '[\"طلب القهوة\", \"الاستراحة\", \"التواصل الاجتماعي\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف محدد في ذهنك، مثل طلب القائمة أو الطلبات المتعلقة بالمشروبات الباردة أو الساخنة أو غيرها من المنتجات؟ لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي يدور في ذهنك.\"]', NULL, '[{\"original\": \"سأطلب لاتيه، من فضلك.\", \"translated\": \"Bir latte alacağım, lütfen.\"}, {\"original\": \"هل لديكم اتصال واي فاي؟\", \"translated\": \"Wi-Fi var mı?\"}, {\"original\": \"هل يمكنني رؤية القائمة، من فضلك؟\", \"translated\": \"Menüyü görebilir miyim, lütfen?\"}, {\"original\": \"هل يُسمح بإعادة التعبئة؟\", \"translated\": \"Yeniden doldurmaya izin veriliyor mu?\"}, {\"original\": \"هل قهوةً قد أصبحت جاهزة؟\", \"translated\": \"Kahvem hazır mı?\"}, {\"original\": \"كم من الوقت يمكنني الجلوس هنا؟\", \"translated\": \"Burada ne kadar süre oturabilirim?\"}, {\"original\": \"هل يمكنك أخذ صورة لنا؟\", \"translated\": \"Bize bir fotoğraf çekebilir misiniz?\"}, {\"original\": \"أين الحمام؟\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"الفاتورة، من فضلك. شكرًا لك.\", \"translated\": \"Hesap, lütfen. Teşekkür ederim.\"}, {\"original\": \"إنها تذوق جيدة جدًا.\", \"translated\": \"Çok lezzetli.\"}]', 12, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Otelde kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte otel ile ilgili 10 yaygın ifade ve Arapça çevirileri:\"]', '[\"Kayıt Ol\", \"Çıkış Yap\", \"Oda Hizmeti\"]', 'tr', '[\"Şu an için aklınızda özel bir durum var mı, örneğin oda konumu, başka bir otel hizmeti ya da çıkış işlemi? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\", \"translated\": \"مرحبًا، لدي حجزٌ، وهذه جواز سفري.\"}, {\"original\": \"Boş odanız var mı?\", \"translated\": \"هل لديكم أي غرف شاغرة؟\"}, {\"original\": \"Affedersiniz, otelde bir spor salonu veya çamaşırhane var mı?\", \"translated\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسيل الملابس؟\"}, {\"original\": \"Kahvaltı saat kaçta başlıyor?\", \"translated\": \"في أي وقت تبدأ وجبة الإفطار؟\"}, {\"original\": \"Lütfen bir oda anahtarı verebilir misiniz?\", \"translated\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\"}, {\"original\": \"Bagajımı odaya taşımama yardımcı olur musunuz?\", \"translated\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\"}, {\"original\": \"Oda servisini nasıl arayabilirim?\", \"translated\": \"كيف أطلب خدمة الغرف؟\"}, {\"original\": \"Çıkış saati kaçta?\", \"translated\": \"في أي وقت يتم المغادرة؟\"}, {\"original\": \"Bana bir makbuz/fatura yazabilir misiniz?\", \"translated\": \"هل يمكنكم إعطائي إيصالًا/فاتورةً؟\"}, {\"original\": \"Bagajımı burada bırakabilir miyim?\", \"translated\": \"هل يمكنني ترك أمتعتي هنا؟\"}]', 2, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Havaalanında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte havaalanı ile ilgili 10 yaygın ifade ve Arapça çevirileri:\"]', '[\"Giriş yapma\", \"Uçağa binme\", \"Bagaj kontrolü\"]', 'tr', '[\"Şu anda aklınızda özel bir durum var mı, örneğin check-in, bagaj teslimi ya da araç kiralama hizmeti? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş masası nerede?\", \"translated\": \"أين كاونتر تسجيل الوصول؟\"}, {\"original\": \"Lütfen pencere kenarında bir koltuk istiyorum.\", \"translated\": \"أود مقعدًا بجانب النافذة، من فضلك.\"}, {\"original\": \"Bu uçuş gecikmiş mi?\", \"translated\": \"هل هذا الرحلة متأخرة؟\"}, {\"original\": \"Bu bagajı kontrol ettirmem gerekiyor.\", \"translated\": \"أحتاج إلى فحص هذه الأمتعة.\"}, {\"original\": \"İniş kapısı nerede?\", \"translated\": \"أين بوابة الصعود إلى الطائرة؟\"}, {\"original\": \"Uçak hemen kalkacak.\", \"translated\": \"الطائرة على وشك الإقلاع.\"}, {\"original\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\", \"translated\": \"هل يجب أن أخرج جهاز الكمبيوتر المحمول والبنك الكهربائي الخاص بي؟\"}, {\"original\": \"Vergisiz alışveriş mağazası nerede?\", \"translated\": \"أين متجر التخفيضات الجمركية؟\"}, {\"original\": \"Bavulumu bulamıyorum.\", \"translated\": \"لا أستطيع العثور على حقيبتي.\"}, {\"original\": \"Tekerlekli sandalye hizmetiniz var mı?\", \"translated\": \"هل تقدمون خدمة الكرسي المتحرك؟\"}]', 3, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Toplu taşıma alanında kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte Toplu Taşıma ile ilgili 10 yaygın ifade ve Arapça çevirileri:\"]', '[\"Otobüs/Metro Kullanma\", \"Bilet Satın Alma\", \"Aktarma\"]', 'tr', '[\"Şimdilik aklınızda özel bir durum var mı, örneğin otobüs durağı sormak, bilet fiyatını öğrenmek ya da inecek yer belirtmek? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bu otobüs terminala gidiyor mu?\", \"translated\": \"هل هذه الحافلة تذهب إلى المحطة؟\"}, {\"original\": \"Bir sonraki durak neresi?\", \"translated\": \"ما هي المحطة التالية؟\"}, {\"original\": \"Bilet nereden alabilirim?\", \"translated\": \"أين يمكنني شراء تذكرة؟\"}, {\"original\": \"XX\'e bir bilet, lütfen.\", \"translated\": \"تذكرة واحدة إلى XX، من فضلك.\"}, {\"original\": \"Aktarma yapmam gerekiyor mu?\", \"translated\": \"هل عليَّ التحويل؟\"}, {\"original\": \"Bir sonraki metro trenine ne kadar kaldı?\", \"translated\": \"كم المدة المتبقية حتى قطار المترو القادم؟\"}, {\"original\": \"Üzgünüm, geçebilir miyim?\", \"translated\": \"عذرًا، من فضلك اسمح لي بالمرور.\"}, {\"original\": \"Bu koltuk dolu mu?\", \"translated\": \"هل هذا المقعد محجوز؟\"}, {\"original\": \"Üzgünüm, XX\'e gitmek için 2. Hat\'a nerede aktarım yapabilirim?\", \"translated\": \"عذرًا، أين يمكنني التحويل إلى الخط الثاني للوصول إلى XX؟\"}, {\"original\": \"XX\'e nasıl giderim?\", \"translated\": \"كيف أصل إلى XX؟\"}]', 4, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Turistik yerlerde kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte turistik yerlerle ilgili 10 yaygın ifade ve Arapça çevirileri:\"]', '[\"Manzara Görme\", \"Fotoğraf Çekme\", \"Bilet Satın Alma\"]', 'tr', '[\"Şimdilik aklınızda bilet fiyatını sorma, bir park yeri bulma ya da tur rehberi hizmeti gibi belirli bir durum mu var? Sorun olmaz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"Öğrenci biletleri mevcut mu?\", \"translated\": \"هل تتوفر تذاكر للطلاب؟\"}, {\"original\": \"Bu yer saat kaçta açılıyor?\", \"translated\": \"في أي وقت يفتح المعلم السياحي؟\"}, {\"original\": \"Burada yapılacak eğlenceli şeyler neler?\", \"translated\": \"ما الأشياء الممتعة التي يمكن القيام بها هنا؟\"}, {\"original\": \"Bizi birlikte çeker misiniz?\", \"translated\": \"هل يمكنك التقاط صورة لنا؟\"}, {\"original\": \"Sightseeing otobüsü nerede?\", \"translated\": \"أين حافلة الجولات السياحية؟\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"أين الحمام؟\"}, {\"original\": \"En iyi manzara noktası nerede?\", \"translated\": \"ما أفضل مكان لمشاهدة المناظر؟\"}, {\"original\": \"Buradaki manzara çok güzel.\", \"translated\": \"المنظر هنا جميلٌ جدًّا.\"}, {\"original\": \"Rehberli tur mevcut mu?\", \"translated\": \"هل توجد جولة إرشادية متاحة؟\"}]', 5, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Taksi veya taksi hizmeti ile ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Taksi veya Taksi Hizmeti ile ilgili 10 yaygın ifade ve Arapça çevirileri:\"]', '[\"Taksiye Binme\", \"Varış Yerini Bildirme\", \"Ödeme\"]', 'tr', '[\"Şu anda en çok ne yapmak istersiniz? Örneğin, varış yerini sormak, ücreti öğrenmek ya da bir fatura talep etmek gibi. Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bir taksi nerede bulabilirim?\", \"translated\": \"أين يمكنني أخذ تاكسي؟\"}, {\"original\": \"Lütfen beni bu adrese götürür müsünüz?\", \"translated\": \"من فضلك خذني إلى هذا العنوان.\"}, {\"original\": \"Yaklaşık olarak ne kadar tutar?\", \"translated\": \"كم يبلغ السعر تقريبًا؟\"}, {\"original\": \"Lütfen taksimetre kullanır mısınız?\", \"translated\": \"هل يمكنك استخدام العداد من فضلك؟\"}, {\"original\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\", \"translated\": \"من فضلك ا-driving أسرع قليلًا، فأنا مستعجل.\"}, {\"original\": \"Lütfen burada durur musunuz?\", \"translated\": \"من فضلك توقف هنا.\"}, {\"original\": \"Kart veya mobil ödeme kabul ediyor musunuz?\", \"translated\": \"هل تقبل الدفع بالبطاقات أو عبر الهاتف المحمول؟\"}, {\"original\": \"Lütfen bir fiş verebilir misiniz?\", \"translated\": \"هل يمكنني الحصول على إشعار دفع من فضلك؟\"}, {\"original\": \"Teşekkür ederim, şoför bey.\", \"translated\": \"شكرًا لك يا سائق.\"}, {\"original\": \"Kaç dakika daha var?\", \"translated\": \"كم تبقى من المسافة؟\"}]', 6, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Eczanede kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte eczane ile ilgili 10 yaygın ifade ve bunların Arapça çevirileri:\"]', '[\"İlaç Satın Almak\", \"Danışmanlık\", \"Ödeme\"]', 'tr', '[\"Şimdilik aklınızda, ilaç kullanımına ilişkin talimat istemek, sigorta kullanımıyla ilgili ifadeler veya tedavi süresi gibi belirli bir durum mu var? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Soğuk algınlığı ilacı var mı?\", \"translated\": \"هل لديكم دواء للبرد؟\"}, {\"original\": \"Bu ilacı nasıl kullanmalıyım?\", \"translated\": \"كيف يجب أن آخذ هذا الدواء؟\"}, {\"original\": \"Ağrı kesici ilaçlarınız var mı?\", \"translated\": \"هل لديكم مسكنات للألم؟\"}, {\"original\": \"Kullanım kılavuzu var mı?\", \"translated\": \"هل توجد نشرة إرشادات مع هذا الدواء؟\"}, {\"original\": \"Bu ilacın yan etkileri var mı?\", \"translated\": \"هل لهذا الدواء أي آثار جانبية؟\"}, {\"original\": \"Tıbbi sigorta kartımı kullanabilir miyim?\", \"translated\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\"}, {\"original\": \"Lütfen bir kutu plastirş (bant) verebilir misiniz?\", \"translated\": \"هل يمكنني الحصول على علبة من الضمادات اللاصقة، من فضلكم؟\"}, {\"original\": \"Ateş düşürücü ilaçlarınız var mı?\", \"translated\": \"هل لديكم خافضات للحرارة؟\"}, {\"original\": \"Hafif bir çizik aldım. Antiseptik ve plastirş (bant) var mı?\", \"translated\": \"لديّ جرح سطحي بسيط. هل لديكم مطهر وضمادات لاصقة؟\"}, {\"original\": \"Kaçta kapanıyorsunuz?\", \"translated\": \"في أي وقت تغلقون؟\"}]', 7, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Acil Servislerle ilgili kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte Acil Servislerle ilgili 10 yaygın ifade ve bunların Arapça çevirileri:\"]', '[\"Polisi Aramak\", \"İlkyardım\", \"Yardım Çağrısı\"]', 'tr', '[\"Şimdilik aklınızda yangın, yaralanma ve yardım gereksinimi, acil çağrı gibi belirli bir acil durum var mı? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırılan durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bana bir ambulans çağırmama yardımcı olun.\", \"translated\": \"من فضلك ساعدني في الاتصال بالإسعاف.\"}, {\"original\": \"Hastane nerede?\", \"translated\": \"أين находится المستشفى؟\"}, {\"original\": \"Birisi yaralandı.\", \"translated\": \"شخص ما أُصيب.\"}, {\"original\": \"Lütfen bana yardımcı olun.\", \"translated\": \"من فضلك ساعدني.\"}, {\"original\": \"Polis karakolu nerede?\", \"translated\": \"أين مركز الشرطة؟\"}, {\"original\": \"Eşyalarımı kaybettim.\", \"translated\": \"لقد فقدت أغراضي.\"}, {\"original\": \"İtfaiye numarası nedir?\", \"translated\": \"ما هو رقم إدارة الإطفاء؟\"}, {\"original\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\", \"translated\": \"لقد فقدت جواز سفري. هل تعرف أين يقع أقرب مركز شرطة؟\"}, {\"original\": \"Acil çıkış var mı?\", \"translated\": \"هل يوجد مخرج طوارئ؟\"}, {\"original\": \"Birisi bayıldı.\", \"translated\": \"شخص ما فقد وعيه.\"}]', 8, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Sahil veya havuz kenarında kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte sahil veya havuz kenarına ilişkin 10 yaygın ifade ve bunların Arapça çevirileri:\"]', '[\"Yüzme\", \"Güneşlenme\", \"Plaj Sporları\"]', 'tr', '[\"Şimdilik, katılacağınız yerel etkinlik veya festivalin bağlamını, örneğin kültürel festival, gastronomi festivali ya da müzik festivali gibi, lütfen bana belirtir misiniz? Lütfen bağlamı sağlayın.\", \"Katıldığınız etkinlikleri lütfen belirtin.\"]', '[\"Aklınızda özel bir durum mu var? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Aklınızda canlandırdığınız durumu lütfen açıklayın.\"]', '[{\"original\": \"Bakın! Oradaki dalgalar gerçekten büyük.\", \"translated\": \"انظر! الأمواج هناك كبيرة جدًّا.\"}, {\"original\": \"Güneş koruyucu sürmeyi unutmayın, buradaki UV ışınları çok güçlü.\", \"translated\": \"تذكَّر أن تضع واقي الشمس، فأشعة فوق البنفسجية هنا قوية جدًّا.\"}, {\"original\": \"Bu plajdaki kum çok ince, pamuk üzerinde yürüyormuş gibi hissediliyor.\", \"translated\": \"الرمال على هذه الشاطئ ناعمة جدًّا، لدرجة أن المشي عليها يشبه المشي على القطن.\"}, {\"original\": \"Plajda voleybol oynamak nasıl olur?\", \"translated\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\"}, {\"original\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\", \"translated\": \"القوارب الشراعية في الأفق تبدو جميلة جدًّا.\"}, {\"original\": \"Buradaki su çok berrak, balıkları bile görebiliyorsunuz.\", \"translated\": \"الماء هنا صافٍ جدًّا لدرجة أنك تستطيع رؤية الأسماك.\"}, {\"original\": \"Hadi biraz deniz kabuğu arayalım.\", \"translated\": \"هيا نذهب للبحث عن بعض المحار.\"}, {\"original\": \"Gün batımında plajda yürüyüş yapmak kesinlikle çok romantik olmalı.\", \"translated\": \"التنزُّه على الشاطئ عند غروب الشمس لا بد أنه أمرٌ رومانسيٌّ جدًّا.\"}, {\"original\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\", \"translated\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًّا، فلنذهب ونجرب بعضها.\"}, {\"original\": \"Deniz yükseliyor, kıyıya doğru gidelim.\", \"translated\": \"المدّ في ازدياد، فلنتوجَّه نحو اليابسة.\"}]', 9, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Yerel Etkinlikler ve Festivallerde kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte Yerel Etkinlikler ve Festivallerle ilgili 10 yaygın ifade ile birlikte Arapça çevirileri:\"]', '[\"Etkinliklere Katılmak\", \"Festivalleri Kutlamak\", \"Kültür Öğrenmek\"]', 'tr', '[\"Şu anda, katıldığınız yerel etkinlik veya festivalin bağlamını, örneğin Cadılar Bayramı, konser veya arkadaş partisi gibi, ya da başka bir şey olarak lütfen bana belirtir misiniz? Lütfen bağlamı sağlayın.\", \"Aklınızda canlandırdığınız etkinlikleri tanımlayınız.\"]', '[\"Aklınızda belirli bir durum mu var? Sorularınızı özgürce sorabilirsiniz.\", \"Aklınızda canlandırdığınız durumu tanımlayınız.\"]', '[{\"original\": \"Bugün herhangi bir etkinlik var mı?\", \"translated\": \"هل توجد أي فعاليات اليوم؟\"}, {\"original\": \"Bu festivalle ilgili özel bir şey var mı?\", \"translated\": \"هل هناك شيء خاص في هذه المهرجان؟\"}, {\"original\": \"Kutlama nerede yapılacak?\", \"translated\": \"أين تُقام الاحتفالية؟\"}, {\"original\": \"Biletleri nasıl alabilirim?\", \"translated\": \"كيف يمكنني شراء التذاكر؟\"}, {\"original\": \"Gösteri saat kaçta başlıyor?\", \"translated\": \"في أي وقت تبدأ العروض؟\"}, {\"original\": \"Hangi geleneksel yiyecekler var?\", \"translated\": \"ما الأطعمة التقليدية المتاحة؟\"}, {\"original\": \"Burada gerçekten hareketli bir atmosfer var.\", \"translated\": \"المكان حيويٌّ جدًّا هنا.\"}, {\"original\": \"Halk oyunu gibi etkinlikler var mı?\", \"translated\": \"هل توجد أنشطة شعبية؟\"}, {\"original\": \"Mutlu tatiller!\", \"translated\": \"أعياد سعيدة!\"}, {\"original\": \"Etkinlik saat kaçta bitiyor?\", \"translated\": \"في أي وقت تنتهي الفعالية؟\"}]', 10, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Müze veya Sanat Galerisi\'nde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Müze veya Sanat Galerisi ile ilgili 10 yaygın ifade ve bunların Arapça çevirileri:\"]', '[\"Ziyaret Etmek\", \"Rehberli Tur\", \"Bilet Satın Almak\"]', 'tr', '[\"Şimdilik aklınızda, tanıtım kılavuzu istemek, yol haritası ile ilgili ifadeler kullanmak veya sergilenen eserlerle ilgili yorum yapmak gibi belirli bir durum mu var? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"Sesli rehberleriniz var mı?\", \"translated\": \"هل لديكم أدلة صوتية؟\"}, {\"original\": \"Bu eseri kim yaratmış?\", \"translated\": \"من هو مبتكر هذه القطعة الفنية؟\"}, {\"original\": \"Müzenin en değerli eseri nerede?\", \"translated\": \"أين توجد أثمن قطعة في المتحف؟\"}, {\"original\": \"Fotoğraf çekmeye izin veriliyor mu?\", \"translated\": \"هل يُسمح بالتصوير الفوتوغرافي؟\"}, {\"original\": \"Burada özel sergiler var mı?\", \"translated\": \"هل توجد هنا أي معارض خاصة؟\"}, {\"original\": \"Ziyaret kaç dakika sürüyor?\", \"translated\": \"كم تستغرق الزيارة من الوقت؟\"}, {\"original\": \"Bize bir giriş yapar mısınız?\", \"translated\": \"هل يمكنكم إعطاؤنا مقدمة؟\"}, {\"original\": \"Bu eserler gerçekten çok zarif.\", \"translated\": \"هذه الأعمال فعلاً رائعةٌ جداً.\"}, {\"original\": \"Hediyelik eşya dükkanı nerede?\", \"translated\": \"أين تقع متجر الهدايا التذكارية؟\"}]', 11, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Kafelerde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte kafelerle ilgili 10 yaygın ifade ve Arapça çevirileri:\"]', '[\"Kahvaltı Siparişi Verme\", \"Dinlenme\", \"Sosyalleşme\"]', 'tr', '[\"Şimdilik aklınızda, bir menü istemek, soğuk veya sıcak içecekler sipariş etmek, diğer ürünler almak gibi belirli bir durum mu var? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bir latte getirir misiniz?\", \"translated\": \"سأطلب لاتيه، من فضلك.\"}, {\"original\": \"Wi-Fi var mı?\", \"translated\": \"هل لديكم اتصال واي فاي؟\"}, {\"original\": \"Menüyü görebilir miyim, lütfen?\", \"translated\": \"هل يمكنني رؤية القائمة، من فضلك؟\"}, {\"original\": \"İkinci dolum yapılabilir mi?\", \"translated\": \"هل يُسمح بإعادة التعبئة؟\"}, {\"original\": \"Kahvaltım hazır mı?\", \"translated\": \"هل قهوةُّي جاهزةٌ؟\"}, {\"original\": \"Burada ne kadar süre oturabilirim?\", \"translated\": \"كم من الوقت يمكنني الجلوس هنا؟\"}, {\"original\": \"Bizi birlikte çektikten sonra fotoğraf çekebilir misiniz?\", \"translated\": \"هل يمكنكم التقاط صورةٍ لنا؟\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"أين الحمام؟\"}, {\"original\": \"Hesap, lütfen. Teşekkür ederim.\", \"translated\": \"الفاتورة، من فضلك. شكرًا لكم.\"}, {\"original\": \"Gerçekten çok lezzetli.\", \"translated\": \"إنها تذوق جيدةٌ جدًّا.\"}]', 12, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Restoranlarda kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte Restoran ile ilgili 10 yaygın ifade:\"]', '[\"Yemek Ye\", \"Sipariş Ver\", \"Ödeme\"]', 'tr', '[\"Şu anda, içecek siparişi vermek, şikayetçi olmak veya malzemeler hakkında sormak gibi belirli bir durumunuz var mı? İstediğiniz gibi sorabilirsiniz.\", \"Aklınızdaki durumu tanımlayın.\"]', NULL, '[{\"original\": \"Üzgünüm, yemeklerimiz ne kadar süre daha bekliyor?\", \"translated\": \"عذرا، كم سيستغرق طعامنا؟\"}, {\"original\": \"Lütfen iki kişilik bir masa.\", \"translated\": \"طاولة لشخصين من فضلك.\"}, {\"original\": \"Lütfen menüyü gösterebilir misiniz?\", \"translated\": \"هل يمكننا رؤية القائمة من فضلك؟\"}, {\"original\": \"Önerdiğiniz özel yemekleriniz var mı?\", \"translated\": \"هل لديك أي أطباق خاصة توصي بها؟\"}, {\"original\": \"Bunları ve bunları sipariş etmek istiyorum.\", \"translated\": \"أود أن أطلب هذا وهذا.\"}, {\"original\": \"Bir bardak su lütfen. Teşekkür ederim.\", \"translated\": \"كأس من الماء من فضلك. شكراً.\"}, {\"original\": \"Hesabı lütfen.\", \"translated\": \"الفاتورة من فضلك.\"}, {\"original\": \"Kredi kartıyla ödemek mümkün mü?\", \"translated\": \"هل يمكنني الدفع بالبطاقة الائتمانية؟\"}, {\"original\": \"Bunu alabilecek şekilde paketleyebilir misiniz lütfen?\", \"translated\": \"هل يمكنك تغليف هذا ليأخذ معه من فضلك؟\"}, {\"original\": \"Yemekler lezzetliydi, teşekkür ederim.\", \"translated\": \"كان الطعام شهيًا، شكراً لك.\"}]', 1, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Restoranda kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte Restorant ile ilgili 10 yaygın ifade:\"]', '[\"Yemek yeme\", \"Sipariş verme\", \"Ödeme\"]', 'tr', '[\"Şu anda, içecek siparişi verme, şikayet etme veya malzemeler hakkında soru sorma gibi belirli bir durumunuz var mı? İstediğiniz gibi sormaktan çekinmeyin.\", \"Aklınızdaki durumu tanımlayın.\"]', NULL, '[{\"original\": \"Üzgünüm, yemeklerimiz ne kadar süre daha?\", \"translated\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\"}, {\"original\": \"Lütfen iki kişilik bir masa.\", \"translated\": \"Une table pour deux, s\'il vous plaît.\"}, {\"original\": \"Menüyü görebilir miyiz, lütfen?\", \"translated\": \"Pourrait-on voir le menu, s\'il vous plaît ?\"}, {\"original\": \"Önerilebilecek herhangi bir özel yeminiz var mı?\", \"translated\": \"Avez-vous des plats spéciaux à recommander ?\"}, {\"original\": \"Bunu ve bunu sipariş etmek istiyorum.\", \"translated\": \"Je voudrais commander ceci et cela.\"}, {\"original\": \"Bir bardak su, lütfen. Teşekkürler.\", \"translated\": \"Un verre d\'eau, s\'il vous plaît. Merci.\"}, {\"original\": \"Hesabı, lütfen.\", \"translated\": \"L\'addition, s\'il vous plaît.\"}, {\"original\": \"Kredi kartıyla ödeme yapabilir miyim?\", \"translated\": \"Puis-je payer par carte de crédit ?\"}, {\"original\": \"Bunu alıp gidebilir miyim, lütfen?\", \"translated\": \"Pourriez-vous emballer ceci à emporter, s\'il vous plaît ?\"}, {\"original\": \"Yemek çok lezzetliydi, teşekkür ederim.\", \"translated\": \"Le repas était délicieux, merci.\"}]', 1, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Otelde kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte otel ile ilgili 10 yaygın ifade:\"]', '[\"Giriş Yap\", \"Çıkış Yap\", \"Oda Servisi\"]', 'tr', '[\"Şu anda, odanın konumu, başka bir otel hizmeti veya check out gibi aklınızda belirli bir durum var mı? Sorabilirsiniz.\", \"Aklınızdaki durumu tanımlayın.\"]', NULL, '[{\"original\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\", \"translated\": \"Bonjour, j\'ai une réservation, voici mon passeport.\"}, {\"original\": \"Boş oda var mı?\", \"translated\": \"Avez-vous des chambres disponibles ?\"}, {\"original\": \"Özür dilerim, otelde fitness salonu veya çamaşırhane var mı?\", \"translated\": \"Excusez-moi, l\'hôtel a-t-il une salle de sport ou une buanderie ?\"}, {\"original\": \"Kahvaltı ne zaman başlıyor?\", \"translated\": \"À quelle heure commence le petit-déjeuner ?\"}, {\"original\": \"Lütfen bana bir oda anahtarı verebilir misiniz?\", \"translated\": \"Pourrais-je avoir une clé de chambre, s\'il vous plaît ?\"}, {\"original\": \"Lütfen bagajımı odama taşıma konusunda yardımcı olabilir misiniz?\", \"translated\": \"Pourriez-vous m\'aider à monter mes bagages dans la chambre ?\"}, {\"original\": \"Oda servisine nasıl ulaşabilirim?\", \"translated\": \"Comment appelle-t-on le service en chambre ?\"}, {\"original\": \"Çıkış saati ne zaman?\", \"translated\": \"À quelle heure est le départ ?\"}, {\"original\": \"Lütfen bana bir fatura/yazdırılmış fiş yazabilir misiniz?\", \"translated\": \"Pourriez-vous me faire un reçu/facture, s\'il vous plaît ?\"}, {\"original\": \"Bagajımı burada bırakabilir miyim?\", \"translated\": \"Puis-je laisser mes bagages ici ?\"}]', 2, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Havalimanında kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte havalimanıyla ilgili 10 yaygın ifade:\"]', '[\"Giriş Yapma\", \"Binme\", \"Bagaj Teslimi\"]', 'tr', '[\"Şu anda, giriş formaliteleri, bagaj alma veya araba kiralama servisi gibi belirli bir durumunuz var mı? Sorabilirsiniz.\", \"Aklınızdaki durumu açıklayınız.\"]', NULL, '[{\"original\": \"Giriş masası nerede?\", \"translated\": \"Où est le comptoir d\'enregistrement ?\"}, {\"original\": \"Lütfen bir pencere koltuğu isterim.\", \"translated\": \"Je voudrais un siège près du hublot, s\'il vous plaît.\"}, {\"original\": \"Bu uçuş gecikiyor mu?\", \"translated\": \"Ce vol est-il retardé ?\"}, {\"original\": \"Bu bagajımı kontrol etmem gerekiyor.\", \"translated\": \"J\'ai besoin d\'enregistrer ce bagage.\"}, {\"original\": \"Yolcu kapısı nerede?\", \"translated\": \"Où est la porte d\'embarquement ?\"}, {\"original\": \"Uçak kalkışa hazırlanıyor.\", \"translated\": \"L\'avion va décoller.\"}, {\"original\": \"Bilgisayarımı ve güç bankamı çıkarmam gerekiyor mu?\", \"translated\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\"}, {\"original\": \"Mükafat mağazası nerede?\", \"translated\": \"Où se trouve le magasin hors taxes ?\"}, {\"original\": \"Valizimi bulamıyorum.\", \"translated\": \"Je ne trouve pas ma valise.\"}, {\"original\": \"Tekerlekli sandalye hizmetiniz var mı?\", \"translated\": \"Avez-vous un service de fauteuil roulant ?\"}]', 3, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Kamu taşımacılığında kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte Kamu Taşımacılığı ile ilgili 10 yaygın ifade:\"]', '[\"Otobüsü/Metroyu Kullanmak\", \"Bilet Almak\", \"Bağlantıya Geçmek\"]', 'tr', '[\"Şu anda, otobüs durakları, bilet fiyatı veya inme gibi belirli bir durum aklınızda var mı? Sorabilirsiniz.\", \"Aklınızdaki durumu lütfen açıklayın.\"]', NULL, '[{\"original\": \"Bu otobüs terminaline gidiyor mu?\", \"translated\": \"Ce bus va-t-il jusqu\'au terminus ?\"}, {\"original\": \"Bir sonraki durak nedir?\", \"translated\": \"Quel est l\'arrêt suivant ?\"}, {\"original\": \"Bilet nereden alabilirim?\", \"translated\": \"Où puis-je acheter un billet ?\"}, {\"original\": \"Lütfen XX\'ye bir bilet.\", \"translated\": \"Un billet pour XX, s\'il vous plaît.\"}, {\"original\": \"Başka bir yere aktarmam gerekiyor mu?\", \"translated\": \"Dois-je faire un transfert ?\"}, {\"original\": \"Bir sonraki metro ne zaman geliyor?\", \"translated\": \"Combien de temps avant le prochain métro ?\"}, {\"original\": \"Affedersiniz, geçmem için lütfen yol verin.\", \"translated\": \"Excusez-moi, laissez-moi passer, s\'il vous plaît.\"}, {\"original\": \"Bu koltuk boş mu?\", \"translated\": \"Cette place est-elle prise ?\"}, {\"original\": \"Affedersiniz, XX\'e gitmek için 2. hat\'a nerede aktarabilirim?\", \"translated\": \"Excusez-moi, où puis-je prendre la ligne 2 pour aller à XX ?\"}, {\"original\": \"XX\'e nasıl gidebilirim?\", \"translated\": \"Comment puis-je me rendre à XX ?\"}]', 4, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Turistik yerlerde kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte turistik yerlere ilişkin 10 yaygın ifade:\"]', '[\"Görsel Gezinti\", \"Fotoğraf Çekme\", \"Bilet Alma\"]', 'tr', '[\"Şu anda, bilet fiyatı hakkında sormak, park yeri bulmak veya tur rehberi hizmeti almak gibi belirli bir durumunuz var mı? İstediğiniz gibi sorabilirsiniz.\", \"Aklınızdaki durumu tanımlayın.\"]', NULL, '[{\"original\": \"Giriş ücreti kaç para?\", \"translated\": \"Combien coûte le droit d\'entrée ?\"}, {\"original\": \"Öğrenci bileti var mı?\", \"translated\": \"Y a-t-il des billets pour étudiants disponibles ?\"}, {\"original\": \"Yer çekimi ne zaman açıyor?\", \"translated\": \"À quelle heure l\'attraction ouvre-t-elle ?\"}, {\"original\": \"Burada yapabileceğimiz eğlenceli şeyler nelerdir?\", \"translated\": \"Quelles sont les activités amusantes à faire ici ?\"}, {\"original\": \"Bize bir fotoğraf çekebilir misiniz?\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"Seyahat otobüsü nerede?\", \"translated\": \"Où est le bus touristique ?\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"En iyi manzara noktası nerededir?\", \"translated\": \"Où se trouve le meilleur point de vue ?\"}, {\"original\": \"Buradaki manzara çok güzel.\", \"translated\": \"Le paysage ici est magnifique.\"}, {\"original\": \"Rehberli tur mevcut mu?\", \"translated\": \"Y a-t-il une visite guidée disponible ?\"}]', 5, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Taksi veya Taksi Hizmeti\'nde kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte Taksi veya Taksi Hizmeti ile ilgili 10 yaygın ifade, bunların yanı sıra Fransızca çevirileri:\"]', '[\"Taksiye Binme\", \"Varış Noktasını Bildirme\", \"Ödeme\"]', 'tr', '[\"Şu an ne yapmak istersiniz, mesela varış noktasını sormak, ücreti öğrenmek veya fatura istemek gibi, özgürce sormanız mümkün.\", \"Aklınızda bulunan durumu lütfen açıklayın.\"]', NULL, '[{\"original\": \"Nerede taksi bulabilirim?\", \"translated\": \"Où puis-je prendre un taxi ?\"}, {\"original\": \"Lütfen beni bu adrese götürün.\", \"translated\": \"Veuillez m\'emmener à cette adresse.\"}, {\"original\": \"Tahmini olarak ne kadar olacak?\", \"translated\": \"Combien cela va-t-il coûter approximativement ?\"}, {\"original\": \"Lütfen kilometre sayacını kullanır mısınız?\", \"translated\": \"Pourriez-vous utiliser le compteur, s\'il vous plaît ?\"}, {\"original\": \"Lütfen biraz daha hızlı sür, acelem var.\", \"translated\": \"Pouvez-vous conduire un peu plus vite, je suis pressé.\"}, {\"original\": \"Lütfen burada durun.\", \"translated\": \"Veuillez vous arrêter ici.\"}, {\"original\": \"Kart veya mobil ödeme kabul ediyor musunuz?\", \"translated\": \"Acceptez-vous les cartes ou les paiements mobiles ?\"}, {\"original\": \"Lütfen bir fatura alabilir miyim?\", \"translated\": \"Pourrais-je avoir un reçu, s\'il vous plaît ?\"}, {\"original\": \"Teşekkür ederim, şoför bey.\", \"translated\": \"Merci, chauffeur.\"}, {\"original\": \"Daha ne kadar var?\", \"translated\": \"Combien de temps reste-t-il encore ?\"}]', 6, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Eczanede kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte eczane ile ilgili 10 yaygın ifade:\"]', '[\"İlaç Satın Alma\", \"Danışma\", \"Ödeme\"]', 'tr', '[\"Şu anda, ilaç alma talimatları istemek, sigorta ile ilgili ifadeler, ilaç süresi gibi belirli bir durumunuz var mı? Sorularınızı sormaktan çekinmeyin.\", \"Aklınızda olan durumu tanımlayabilir misiniz?\"]', NULL, '[{\"original\": \"Soğuk ilacı var mı?\", \"translated\": \"Avez-vous des médicaments pour le rhume?\"}, {\"original\": \"Bu ilacı nasıl kullanmalıyım?\", \"translated\": \"Comment dois-je prendre ce médicament?\"}, {\"original\": \"Ağrı kesiciniz var mı?\", \"translated\": \"Avez-vous des analgésiques?\"}, {\"original\": \"Kullanma talimatı bulunan bir broşür var mı?\", \"translated\": \"Y a-t-il une notice d\'information?\"}, {\"original\": \"Bu ilaç herhangi bir yan etkiye sahip mi?\", \"translated\": \"Ce médicament a-t-il des effets secondaires?\"}, {\"original\": \"Sağlık sigortamı burada kullanabilir miyim?\", \"translated\": \"Puis-je utiliser ma carte d\'assurance maladie?\"}, {\"original\": \"Lütfen bana bir kutu Band-Aid verir misiniz?\", \"translated\": \"Pourrais-je avoir une boîte de pansements, s\'il vous plaît?\"}, {\"original\": \"Ateşi düşürücü ilaçlarınız var mı?\", \"translated\": \"Avez-vous des antipyrétiques?\"}, {\"original\": \"Biraz yaralandım. Antiseptik ve Band-Aid\'iniz var mı?\", \"translated\": \"Je me suis un peu égratigné. Avez-vous du désinfectant et des pansements?\"}, {\"original\": \"Kaçta kapanıyorsunuz?\", \"translated\": \"À quelle heure fermez-vous?\"}]', 7, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Acil Yardım Hizmetleri\'nde kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte Acil Yardım Hizmetleri ile ilgili 10 yaygın ifade:\"]', '[\"Polisi Arama\", \"İlk Yardım\", \"Yardım Çağırma\"]', 'tr', '[\"Şu anda, Yangın, Yaralı ve yardım ihtiyacı, acil çağrı gibi aklınızda belirli bir acil durum var mı? Sorularınızı serbestçe sorabilirsiniz.\", \"Lütfen aklınızdaki durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bana bir ambulans çağırın.\", \"translated\": \"Aidez-moi à appeler une ambulance.\"}, {\"original\": \"Hastane nerede?\", \"translated\": \"Où est l\'hôpital ?\"}, {\"original\": \"Birisi yaralandı.\", \"translated\": \"Quelqu\'un est blessé.\"}, {\"original\": \"Lütfen bana yardım edin.\", \"translated\": \"Aidez-moi, s\'il vous plaît.\"}, {\"original\": \"Polis karakolu nerede?\", \"translated\": \"Où se trouve le commissariat de police ?\"}, {\"original\": \"Eşyalarımı kaybettim.\", \"translated\": \"J\'ai perdu mes affaires.\"}, {\"original\": \"Yangın departmanının numarası nedir?\", \"translated\": \"Quel est le numéro des pompiers ?\"}, {\"original\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\", \"translated\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le commissariat de police le plus proche ?\"}, {\"original\": \"Acil çıkış var mı?\", \"translated\": \"Y a-t-il une sortie de secours ?\"}, {\"original\": \"Birisi bayıldı.\", \"translated\": \"Quelqu\'un est évanoui.\"}]', 8, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Plajda veya havuz kenarında kullanabileceğim 10 yaygın ifadeyi verebilir misiniz?\", \"Harika! İşte plaj veya havuz kenarına ilişkin 10 yaygın ifade:\"]', '[\"Yüzme\", \"Güneşlenme\", \"Plaj Sporları\"]', 'tr', '[\"Şu anda, katıldığınız yerel etkinlik veya festivalin bağlamını verir misiniz, örneğin kültür festivali, yemek festivali veya müzik festivali. Lütfen bağlamı verin.\", \"Katıldığınız etkinlikleri belirtir misiniz?\"]', '[\"Aklınızda bir belirli durum var mı, sorabilirsiniz.\", \"Aklındaki durumu açıklayabilir misiniz.\"]', '[{\"original\": \"Bak! Oradaki dalgalar gerçekten büyük.\", \"translated\": \"Regarde ! Les vagues là-bas sont vraiment grandes.\"}, {\"original\": \"Güneş kremi sürmeyi unutma, buradaki UV ışınları çok güçlü.\", \"translated\": \"N\'oublie pas d\'appliquer de la crème solaire, les rayons UV ici sont très forts.\"}, {\"original\": \"Bu plajdaki kum o kadar ince ki, pamuğa basıyormuş hissi veriyor.\", \"translated\": \"Le sable sur cette plage est si fin, c\'est comme marcher sur du coton.\"}, {\"original\": \"Plajda voleybol oynamayı ne dersin?\", \"translated\": \"Que dirais-tu de jouer au volley-ball sur la plage ?\"}, {\"original\": \"Uzakta olan yelkencilik tekneleri çok güzel görünüyor.\", \"translated\": \"Les voiliers au loin sont magnifiques.\"}, {\"original\": \"Buradaki su o kadar temiz ki, hatta balıkları bile görebiliyorsun.\", \"translated\": \"L\'eau ici est tellement claire qu\'on peut même voir les poissons.\"}, {\"original\": \"Hadi bazı deniz kabuklarını bulmaya gidelim.\", \"translated\": \"Allons chercher des coquillages.\"}, {\"original\": \"Gün batımında plajda yürüyüş yapmak çok romantik olmalı.\", \"translated\": \"Faire une promenade sur la plage au coucher du soleil doit être très romantique.\"}, {\"original\": \"Buradaki deniz ürünleri çok taze olduğunu duydum, hadi biraz deneyelim.\", \"translated\": \"J\'ai entendu dire que les fruits de mer ici sont très frais, allons en goûter.\"}, {\"original\": \"Gelgit geliyor, sahil tarafına doğru ilerleyelim.\", \"translated\": \"La marée monte, allons vers le rivage.\"}]', 9, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Yerel Etkinlikler ve Festival lerde kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte Yerel Etkinlikler ve Festival lerle ilgili 10 yaygın ifade:\"]', '[\"Etkinliklere Katılım\", \"Festivalleri Kutlama\", \"Kültürü Öğrenme\"]', 'tr', '[\"Şu anda, katılacağınız yerel etkinlik veya festivalin bağlamını (örneğin, Cadılar Bayramı, konser, arkadaş partisi vb.) verir misiniz? Lütfen bağlamı belirtin.\", \"Aklındaki faaliyetleri tanımlayın.\"]', '[\"Aklında belirli bir durum var mı, sorusunu sormaktan çekinme.\", \"Aklındaki durumu tanımlayın.\"]', '[{\"original\": \"Bugün herhangi bir etkinlik var mı?\", \"translated\": \"Y a-t-il des événements aujourd\'hui ?\"}, {\"original\": \"Bu festivalin özel bir yanı var mı?\", \"translated\": \"Y a-t-il quelque chose de spécial à propos de cette fête ?\"}, {\"original\": \"Kutlama nerede gerçekleşiyor?\", \"translated\": \"Où se déroule la célébration ?\"}, {\"original\": \"Bilet nasıl alabilirim?\", \"translated\": \"Comment puis-je acheter des billets ?\"}, {\"original\": \"Performans ne zaman başlıyor?\", \"translated\": \"À quelle heure commence la représentation ?\"}, {\"original\": \"Burada hangi geleneksel yemekler var?\", \"translated\": \"Quels plats traditionnels y a-t-il ?\"}, {\"original\": \"Burası gerçekten canlı.\", \"translated\": \"C\'est vraiment animé ici.\"}, {\"original\": \"Herhangi bir halk etkinliği var mı?\", \"translated\": \"Y a-t-il des activités folkloriques ?\"}, {\"original\": \"Mutlu tatiller!\", \"translated\": \"Joyeuses fêtes !\"}, {\"original\": \"Etkinlik ne zaman sona eriyor?\", \"translated\": \"À quelle heure se termine l\'événement ?\"}]', 10, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Müze veya Sanat Galerisi\'nde kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte Müze veya Sanat Galerisi ile ilgili 10 yaygın ifade:\"]', '[\"Ziyaret\", \"Rehberli Tur\", \"Bilet Almak\"]', 'tr', '[\"Şu anda, tanıtım kılavuzu istemek, yol haritası ile ilgili ifadeler, sergideki eser hakkında yorum yapma ile ilgili ifadeler gibi belirli bir durum aklınızda var mı? Sorularınızı sormaktan çekinmeyin.\", \"Aklınızdaki durumu tanımlayın.\"]', NULL, '[{\"original\": \"Giriş ücreti kaç para?\", \"translated\": \"Combien coûte le droit d\'entrée ?\"}, {\"original\": \"Sesli rehberiniz var mı?\", \"translated\": \"Avez-vous des audioguides ?\"}, {\"original\": \"Bu eseri kim yarattı?\", \"translated\": \"Qui a créé cette œuvre d\'art ?\"}, {\"original\": \"Müzenin en değerli parçası nerede?\", \"translated\": \"Où se trouve la pièce la plus précieuse du musée ?\"}, {\"original\": \"Fotograf çekmek serbest mi?\", \"translated\": \"La photographie est-elle autorisée ?\"}, {\"original\": \"Burada özel bir sergi var mı?\", \"translated\": \"Y a-t-il des expositions spéciales ici ?\"}, {\"original\": \"Ziyaret ne kadar sürer?\", \"translated\": \"Combien de temps prend la visite ?\"}, {\"original\": \"Bize bir tanıtım yapabilir misiniz?\", \"translated\": \"Pourriez-vous nous faire une introduction ?\"}, {\"original\": \"Bu eserler gerçekten becerikli.\", \"translated\": \"Ces œuvres sont vraiment exquises.\"}, {\"original\": \"Hatırlatma mağazası nerede?\", \"translated\": \"Où se trouve la boutique de souvenirs ?\"}]', 11, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Kafede kullanabileceğim 10 yaygın ifadeyi verebilir misiniz?\", \"Harika! İşte kafelerle ilgili 10 yaygın ifade:\"]', '[\"Kahve Sipariş Etme\", \"Dinlenme\", \"Sosyalleşme\"]', 'tr', '[\"Şu anda, menü istemek, soğuk veya sıcak içecekler, diğer ürünler gibi belirli bir durum aklınızda var mı? Sorabilirsiniz.\", \"Aklınızdaki durumu tanımlayın.\"]', NULL, '[{\"original\": \"Bir latte alacağım, lütfen.\", \"translated\": \"Je voudrais un latte, s\'il vous plaît.\"}, {\"original\": \"Wi-Fi var mı?\", \"translated\": \"Avez-vous du Wi-Fi ?\"}, {\"original\": \"Menüyü görebilir miyim, lütfen?\", \"translated\": \"Pourrais-je voir le menu, s\'il vous plaît ?\"}, {\"original\": \"Yeniden doldurma izni var mı?\", \"translated\": \"Est-ce que les recharges sont autorisées ?\"}, {\"original\": \"Kahvem hazır mı?\", \"translated\": \"Mon café est-il prêt ?\"}, {\"original\": \"Burada ne kadar oturabilirim?\", \"translated\": \"Pendant combien de temps puis-je rester ici ?\"}, {\"original\": \"Bize bir fotoğraf çekebilir misiniz, lütfen?\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"Où se trouve les toilettes ?\"}, {\"original\": \"Hesap, lütfen. Teşekkür ederim.\", \"translated\": \"L\'addition, s\'il vous plaît. Merci.\"}, {\"original\": \"Gerçekten çok lezzetli.\", \"translated\": \"C\'est vraiment très bon.\"}]', 12, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Restoranda kullanabileceğim 10 yaygın ifadeyi verebilir misiniz?\", \"Harika! İşte Restoran ile ilgili 10 yaygın ifade:\"]', '[\"Yemek yeme\", \"Sipariş verme\", \"Ödeme işlemi\"]', 'tr', '[\"Şu anda, içecek siparişi vermek, şikayetçi olmak veya malzemeler hakkında sormak gibi belirli bir durumunuz var mı? İstediğiniz gibi sorabilirsiniz.\", \"Aklınızda olan durumu tanımlayın.\"]', NULL, '[{\"original\": \"Afedersiniz, yemeklerimiz ne kadar süre içinde hazır olacak?\", \"translated\": \"Entschuldigung, wie lange dauert es noch, bis unser Essen fertig ist?\"}, {\"original\": \"Lütfen iki kişilik bir masa.\", \"translated\": \"Einen Tisch für zwei, bitte.\"}, {\"original\": \"Menüyü görebilir miyiz, lütfen?\", \"translated\": \"Könnten wir die Speisekarte sehen, bitte?\"}, {\"original\": \"Önerdiğiniz bir özel yemek var mı?\", \"translated\": \"Haben Sie ein Hausgericht, das Sie empfehlen können?\"}, {\"original\": \"Bunu ve bunu sipariş etmek istiyorum.\", \"translated\": \"Ich möchte dies und dies bestellen.\"}, {\"original\": \"Bir bardak su, lütfen. Teşekkür ederim.\", \"translated\": \"Ein Glas Wasser, bitte. Danke.\"}, {\"original\": \"Hesabı, lütfen.\", \"translated\": \"Die Rechnung, bitte.\"}, {\"original\": \"Kredi kartı ile ödeme yapabilir miyim?\", \"translated\": \"Kann ich mit Kreditkarte zahlen?\"}, {\"original\": \"Bu yemeği alıp gidebilir mi, lütfen?\", \"translated\": \"Könnten Sie dies zum Mitnehmen verpacken, bitte?\"}, {\"original\": \"Yemekler lezzetliydi, teşekkür ederim.\", \"translated\": \"Das Essen war köstlich, vielen Dank.\"}]', 1, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Otelde kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte otel ile ilgili 10 yaygın ifade:\"]', '[\"Giriş Yap\", \"Çıkış Yap\", \"Oda Servisi\"]', 'tr', '[\"Şu anda, odanın konumu, başka bir otel hizmeti veya check out gibi belirli bir durum aklınızda var mı? Sorabilirsiniz.\", \"Aklınızdaki durumu tanımlayın.\"]', NULL, '[{\"original\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\", \"translated\": \"Hallo, ich habe eine Reservierung. Hier ist mein Pass.\"}, {\"original\": \"Boş odanız var mı?\", \"translated\": \"Haben Sie noch freie Zimmer?\"}, {\"original\": \"Özür dilerim, otelde fitness salonu veya çamaşırhane var mı?\", \"translated\": \"Entschuldigung, hat das Hotel ein Fitnessstudio oder eine Wäscherei?\"}, {\"original\": \"Kahvaltı ne zaman başlıyor?\", \"translated\": \"Wann beginnt das Frühstück?\"}, {\"original\": \"Lütfen bana bir oda anahtarı verebilir misiniz?\", \"translated\": \"Könnte ich bitte einen Zimmerschlüssel haben?\"}, {\"original\": \"Lütfen bagajımı odaya taşıma konusunda yardımcı olabilir misiniz?\", \"translated\": \"Könnten Sie mir helfen, mein Gepäck ins Zimmer zu bringen?\"}, {\"original\": \"Oda servisine nasıl ulaşabilirim?\", \"translated\": \"Wie rufe ich den Zimmerservice an?\"}, {\"original\": \"Çıkış saati ne zaman?\", \"translated\": \"Wann ist die Auscheckzeit?\"}, {\"original\": \"Lütfen bana bir fatura/yazılı fiş yazabilir misiniz?\", \"translated\": \"Könnten Sie mir bitte eine Quittung/Rechnung ausstellen?\"}, {\"original\": \"Bagajımı burada bırakabilir miyim?\", \"translated\": \"Kann ich mein Gepäck hier lassen?\"}]', 2, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Havalimanında kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte havalimanıyla ilgili 10 yaygın ifade:\"]', '[\"Giriş Yapma\", \"Yolculuğa Binme\", \"Bagaj Teslimi\"]', 'tr', '[\"Şu anda, giriş yapma, bagaj alma veya araba kiralama servisi gibi belirli bir durumunuz var mı? Sorabilirsiniz.\", \"Aklınızdaki durumu tanımlayın.\"]', NULL, '[{\"original\": \"Giriş masası nerede?\", \"translated\": \"Wo ist der Check-in-Schalter?\"}, {\"original\": \"Lütfen bir pencere koltuğu isterim.\", \"translated\": \"Ich möchte bitte einen Platz am Fenster.\"}, {\"original\": \"Bu uçuş gecikiyor mu?\", \"translated\": \"Ist dieser Flug verzögert?\"}, {\"original\": \"Bu bagajımı kontrol etmem gerekiyor.\", \"translated\": \"Ich muss dieses Gepäckstück aufgeben.\"}, {\"original\": \"Binme kapısı nerede?\", \"translated\": \"Wo ist das Boarding-Gate?\"}, {\"original\": \"Uçak kalkışa hazırlanıyor.\", \"translated\": \"Das Flugzeug wird gleich abheben.\"}, {\"original\": \"Bilgisayarımı ve güç bankamı çıkarıp çıkarmam gerekiyor mu?\", \"translated\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\"}, {\"original\": \"Mükafatlı alışveriş dükkanı nerede?\", \"translated\": \"Wo ist der Duty-free-Shop?\"}, {\"original\": \"Valizimi bulamıyorum.\", \"translated\": \"Ich kann mein Gepäckstück nicht finden.\"}, {\"original\": \"Tekerlekli sandalye hizmetiniz var mı?\", \"translated\": \"Haben Sie einen Rollstuhl-Service?\"}]', 3, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Kamu taşımacılığında kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte Kamu Taşımacılığı ile ilgili 10 yaygın ifade:\"]', '[\"Otobüs/Metroye Binme\", \"Bilet Alışveriş\", \"Bağlantıya Geçme\"]', 'tr', '[\"Şu anda, otobüs durakları, bilet fiyatı veya indirme gibi belirli bir durum aklınızda var mı? Sorabilirsiniz.\", \"Aklınızdaki durumu açıklayın.\"]', NULL, '[{\"original\": \"Bu otobüs terminaline gidiyor mu?\", \"translated\": \"Fährt dieser Bus zum Terminal?\"}, {\"original\": \"Bir sonraki duraç hangisi?\", \"translated\": \"Was ist die nächste Haltestelle?\"}, {\"original\": \"Bilet nereden alınır?\", \"translated\": \"Wo kann ich eine Fahrkarte kaufen?\"}, {\"original\": \"Lütfen XX\'ye bir bilet.\", \"translated\": \"Eine Fahrkarte nach XX, bitte.\"}, {\"original\": \"Başka bir hattan mı geçmem gerekiyor?\", \"translated\": \"Muss ich umsteigen?\"}, {\"original\": \"Bir sonraki metro ne zaman geliyor?\", \"translated\": \"Wie lange dauert es bis zur nächsten U-Bahn?\"}, {\"original\": \"Afedersiniz, geçmeme izin verir misiniz lütfen?\", \"translated\": \"Entschuldigung, darf ich durch?\"}, {\"original\": \"Bu koltuk boş mu?\", \"translated\": \"Ist dieser Platz noch frei?\"}, {\"original\": \"Afedersiniz, XX\'e gitmek için 2. hat\'a nerede geçiş yapabilirim?\", \"translated\": \"Entschuldigung, wo kann ich in die Linie 2 umsteigen, um nach XX zu kommen?\"}, {\"original\": \"XX\'e nasıl giderim?\", \"translated\": \"Wie komme ich nach XX?\"}]', 4, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Turistik yerlerde kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte turistik yerlere ilişkin 10 yaygın ifade:\"]', '[\"Turizm\", \"Fotoğraf Çekme\", \"Bilet Almak\"]', 'tr', '[\"Şu anda, bilet fiyatı hakkında sormak, park yeri bulmak veya tur rehberi hizmeti gibi belirli bir durumunuz var mı? Sorabilirsiniz.\", \"Aklınızdaki durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti kaç para?\", \"translated\": \"Wie viel kostet der Eintritt?\"}, {\"original\": \"Öğrenci biletleri mevcut mu?\", \"translated\": \"Gibt es Studierendentickets?\"}, {\"original\": \"Turuistik yer ne zaman açıyor?\", \"translated\": \"Wann öffnet die Sehenswürdigkeit?\"}, {\"original\": \"Burada yapabileceğimiz eğlenceli şeyler nelerdir?\", \"translated\": \"Was gibt es hier Schönes zu tun?\"}, {\"original\": \"Bize bir fotoğraf çekebilir misiniz?\", \"translated\": \"Könnten Sie ein Foto von uns machen?\"}, {\"original\": \"Sightseeing otobüsü nerede?\", \"translated\": \"Wo ist der Sightseeing-Bus?\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"En iyi manzara noktası nerede?\", \"translated\": \"Wo ist der beste Aussichtspunkt?\"}, {\"original\": \"Buradaki manzara çok güzel.\", \"translated\": \"Die Landschaft hier ist wunderschön.\"}, {\"original\": \"Rehberlik turu mevcut mu?\", \"translated\": \"Gibt es eine Führung?\"}]', 5, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Taksi veya taksi hizmetinde kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte taksi veya taksi hizmetiyle ilgili 10 yaygın ifade:\"]', '[\"Taksiye Binme\", \"Varış Noktasını Bildirme\", \"Ödeme\"]', 'tr', '[\"Şu anda, varış noktasını sormak, ücreti öğrenmek veya fatura istemek gibi en çok ne yapmak istersiniz, özgürce sorun.\", \"Aklınızda olduğunuz durumu lütfen açıklayın.\"]', NULL, '[{\"original\": \"Nerede taksi bulabilirim?\", \"translated\": \"Wo kann ich ein Taxi bekommen?\"}, {\"original\": \"Lütfen beni bu adrese götürün.\", \"translated\": \"Bringen Sie mich bitte zu dieser Adresse.\"}, {\"original\": \"Tahmini olarak ne kadar olacak?\", \"translated\": \"Ungefähr, wie viel wird es kosten?\"}, {\"original\": \"Lütfen kilometre sayacını kullanır mısınız?\", \"translated\": \"Können Sie bitte den Taxameter benutzen?\"}, {\"original\": \"Lütfen biraz daha hızlı sür, acelem var.\", \"translated\": \"Fahren Sie bitte etwas schneller, ich habe es eilig.\"}, {\"original\": \"Lütfen burada durun.\", \"translated\": \"Haltens Sie bitte hier an.\"}, {\"original\": \"Kart veya mobil ödeme kabul ediyor musunuz?\", \"translated\": \"Akzeptieren Sie Karten- oder Mobilzahlungen?\"}, {\"original\": \"Lütfen faturayı verebilir misiniz?\", \"translated\": \"Könnte ich eine Quittung haben, bitte?\"}, {\"original\": \"Teşekkürler, şoför bey.\", \"translated\": \"Danke, Fahrer.\"}, {\"original\": \"Daha ne kadar var?\", \"translated\": \"Wie viel weiter ist es noch?\"}]', 6, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Eczanede kullanabileceğim 10 yaygın ifadeyi verebilir misiniz?\", \"Harika! İşte eczaneyle ilgili 10 yaygın ifade:\"]', '[\"İlaç Alımı\", \"Danışma\", \"Ödeme\"]', 'tr', '[\"Şu anda, ilaç alma talimatları istemek, sigorta ile ilgili ifadeler, ilaç süresi gibi belirli bir durumunuz var mı? Sorularınızı sormaktan çekinmeyin.\", \"Aklınızda olan durumu tanımlayabilir misiniz?\"]', NULL, '[{\"original\": \"Soğuk ilacı var mı?\", \"translated\": \"Haben Sie Medikamente gegen Erkältungen?\"}, {\"original\": \"Bu ilacı nasıl kullanmalıyım?\", \"translated\": \"Wie soll ich diese Medikamente einnehmen?\"}, {\"original\": \"Ağrı kesici ilacınız var mı?\", \"translated\": \"Haben Sie Schmerzmittel?\"}, {\"original\": \"Kullanma talimatı bulunan bir broşür var mı?\", \"translated\": \"Gibt es eine Gebrauchsanweisung?\"}, {\"original\": \"Bu ilacın yan etkileri var mı?\", \"translated\": \"Hat dieses Medikament Nebenwirkungen?\"}, {\"original\": \"Sağlık sigortamı burada kullanabilir miyim?\", \"translated\": \"Kann ich meine Krankenversicherungskarte verwenden?\"}, {\"original\": \"Lütfen bana bir kutu Band-Aid verir misiniz?\", \"translated\": \"Könnte ich bitte eine Packung Pflaster haben?\"}, {\"original\": \"Ateşi düşürücü ilaçlarınız var mı?\", \"translated\": \"Haben Sie Fieber senkende Mittel?\"}, {\"original\": \"Biraz sıyrık oldu. Antiseptik ve Band-Aid\'iniz var mı?\", \"translated\": \"Ich habe mich ein wenig verletzt. Haben Sie Desinfektionsmittel und Pflaster?\"}, {\"original\": \"Ne zaman kapanıyorsunuz?\", \"translated\": \"Wann schließen Sie?\"}]', 7, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Acil Servislerde kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte Acil Servislerle ilgili 10 yaygın ifade:\"]', '[\"Polisi Arama\", \"İlk Yardım\", \"Yardım Çağırma\"]', 'tr', '[\"Şu anda, Yangın, Yaralı ve yardım ihtiyacı, acil arama gibi belirli bir acil durum düşünüyor musunuz? Sorularınızı serbestçe sorabilirsiniz.\", \"Aklınızdaki durumu lütfen tanımlayın.\"]', NULL, '[{\"original\": \"Lütfen bana bir ambulans çağırın.\", \"translated\": \"Bitte helfen Sie mir, einen Krankenwagen zu rufen.\"}, {\"original\": \"Hastane nerede?\", \"translated\": \"Wo ist das Krankenhaus?\"}, {\"original\": \"Birisi yaralandı.\", \"translated\": \"Jemand ist verletzt.\"}, {\"original\": \"Lütfen bana yardım edin.\", \"translated\": \"Bitte helfen Sie mir.\"}, {\"original\": \"Polis merkezi nerede?\", \"translated\": \"Wo ist die Polizeistation?\"}, {\"original\": \"Eşyalarımı kaybettim.\", \"translated\": \"Ich habe meine Habseligkeiten verloren.\"}, {\"original\": \"Yangın departmanının numarası nedir?\", \"translated\": \"Was ist die Nummer der Feuerwehr?\"}, {\"original\": \"Pasaportumu kaybettim. En yakın polis merkezinin nerede olduğunu biliyor musunuz?\", \"translated\": \"Ich habe meinen Reisepass verloren. Wissen Sie, wo die nächste Polizeistation ist?\"}, {\"original\": \"Acil çıkış var mı?\", \"translated\": \"Gibt es einen Notausgang?\"}, {\"original\": \"Birisi bayıldı.\", \"translated\": \"Jemand ist ohnmächtig geworden.\"}]', 8, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Plajda veya havuz kenarında kullanabileceğim 10 yaygın ifadeyi verebilir misiniz?\", \"Harika! İşte plaj veya havuz kenarı ile ilgili 10 yaygın ifade:\"]', '[\"Yüzme\", \"Güneşlenme\", \"Plaj Sporları\"]', 'tr', '[\"Şu anda, katıldığınız yerel etkinlik veya festivalin bağlamını verir misiniz, örneğin kültür festivali, yemek festivali veya müzik festivali. Lütfen bağlamı belirtin.\", \"Katıldığınız etkinlikleri belirtir misiniz?\"]', '[\"Aklınızda belirli bir durum var mı, sorabilirsiniz.\", \"Aklındaki durumu açıklayabilir misiniz.\"]', '[{\"original\": \"Bak! Oradaki dalgalar gerçekten büyük.\", \"translated\": \"Schau! Die Wellen dort drüben sind wirklich groß.\"}, {\"original\": \"Güneş kremi sürmeyi unutma, buradaki UV ışınları çok güçlü.\", \"translated\": \"Denk daran, Sonnencreme aufzutragen, die UV-Strahlung hier ist sehr stark.\"}, {\"original\": \"Bu plajdaki kum o kadar ince ki, pamuğa basıyormuş hissi veriyor.\", \"translated\": \"Der Sand auf diesem Strand ist so fein, es fühlt sich an, als würde man auf Watte treten.\"}, {\"original\": \"Plajda voleybol oynamayı ne dersin?\", \"translated\": \"Wie wäre es mit Volleyballspielen am Strand?\"}, {\"original\": \"Uzakta olan yelkencilik tekneleri çok güzel görünüyor.\", \"translated\": \"Die Segelboote in der Ferne sehen wunderschön aus.\"}, {\"original\": \"Buradaki su o kadar berraktır ki, hatta balıkları bile görebilirsiniz.\", \"translated\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\"}, {\"original\": \"Hadi biraz kabuklu deniz nesnesi toplamaya gidelim.\", \"translated\": \"Lass uns nach Muscheln suchen gehen.\"}, {\"original\": \"Güneşin batışı sırasında plajda yürümek çok romantik olmalı.\", \"translated\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\"}, {\"original\": \"Buradaki deniz ürünleri çok taze olduğu söyleniyor, hadi biraz deneyelim.\", \"translated\": \"Ich habe gehört, dass der Fisch hier sehr frisch ist, lass uns etwas probieren.\"}, {\"original\": \"Dalga geliyor, hadi sahil tarafına doğru ilerleyelim.\", \"translated\": \"Die Flut kommt, lass uns zum Ufer gehen.\"}]', 9, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Yerel Etkinlikler ve Festival lerde kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte Yerel Etkinlikler ve Festival lerle ilgili 10 yaygın ifade, Almanca çevirileriyle birlikte:\"]', '[\"Etkinliklere Katılım\", \"Festivalleri kutlama\", \"Kültürü öğrenme\"]', 'tr', '[\"Şimdilik, katıldığınız yerel etkinlik veya festivalin bağlamını, örneğin Cadılar Bayramı, konser, arkadaş partisi veya başka bir şey gibi belirtir misiniz? Lütfen bağlamı belirtin.\", \"Aklındaki faaliyetleri tanımlayın.\"]', '[\"Aklınızda belirli bir durum var mı, lütfen sormaktan çekinmeyin.\", \"Aklındaki durumu tanımlayın.\"]', '[{\"original\": \"Bugün herhangi bir etkinlik var mı?\", \"translated\": \"Gibt es heute irgendwelche Veranstaltungen?\"}, {\"original\": \"Bu festivalin özel bir yanı var mı?\", \"translated\": \"Ist an diesem Fest etwas Besonderes?\"}, {\"original\": \"Kutlama nerede gerçekleşiyor?\", \"translated\": \"Wo findet die Feier statt?\"}, {\"original\": \"Biletleri nasıl alabilirim?\", \"translated\": \"Wie kann ich Tickets kaufen?\"}, {\"original\": \"Performans saat kaçta başlıyor?\", \"translated\": \"Wann beginnt die Vorstellung?\"}, {\"original\": \"Hangi geleneksel yemekler var?\", \"translated\": \"Welche traditionellen Speisen gibt es?\"}, {\"original\": \"Burası gerçekten canlı.\", \"translated\": \"Es ist wirklich lebendig hier.\"}, {\"original\": \"Herhangi bir halk etkinliği var mı?\", \"translated\": \"Gibt es irgendwelche Volksaktivitäten?\"}, {\"original\": \"Mutlu tatiller!\", \"translated\": \"Frohe Feiertage!\"}, {\"original\": \"Etkinlik saat kaçta sona eriyor?\", \"translated\": \"Wann endet die Veranstaltung?\"}]', 10, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Müze veya Sanat Galerisi\'nde kullanabileceğim 10 yaygın ifadeyi sağlayabilir misiniz?\", \"Harika! İşte Müze veya Sanat Galerisi ile ilgili 10 yaygın ifade:\"]', '[\"Ziyaret\", \"Rehberli Tur\", \"Bilet Alma\"]', 'tr', '[\"Şu anda, tanıtım kılavuzu isteme, yol haritası ile ilgili ifadeler, sergideki eser hakkında yorum yapma gibi belirli bir durum aklınızda mı? Sorularınızı sormaktan çekinmeyin.\", \"Aklınızdaki durumu tanımlayın.\"]', NULL, '[{\"original\": \"Giriş ücreti kaçtır?\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"Sesli rehberiniz var mı?\", \"translated\": \"Haben Sie Audioguides?\"}, {\"original\": \"Bu eseri kim yarattı?\", \"translated\": \"Wer hat dieses Kunstwerk geschaffen?\"}, {\"original\": \"Müzenin en değerli parçası nerede?\", \"translated\": \"Wo befindet sich das wertvollste Stück des Museums?\"}, {\"original\": \"Fotoğraf çekmek serbest mi?\", \"translated\": \"Ist Fotografieren erlaubt?\"}, {\"original\": \"Burada özel bir sergi var mı?\", \"translated\": \"Gibt es hier Sonderausstellungen?\"}, {\"original\": \"Ziyaret ne kadar sürer?\", \"translated\": \"Wie lange dauert der Besuch?\"}, {\"original\": \"Bize bir tanıtım yapabilir misiniz?\", \"translated\": \"Könnten Sie uns eine Einführung geben?\"}, {\"original\": \"Bu eserler gerçekten çok güzel.\", \"translated\": \"Diese Werke sind wirklich exquisit.\"}, {\"original\": \"Hatırlatma mağazası nerededir?\", \"translated\": \"Wo befindet sich der Souvenirladen?\"}]', 11, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Kafelerde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte kafelerle ilgili 10 yaygın ifade ve bunların Almanca çevirileri:\"]', '[\"Kahvaltı Siparişi Verme\", \"Dinlenme\", \"Sosyalleşme\"]', 'tr', '[\"Şimdilik aklınızda, bir menü istemek, soğuk veya sıcak içecekler sipariş etmek, diğer ürünler almak gibi belirli bir durum var mı? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bir latte getirir misiniz?\", \"translated\": \"Ich hätte gerne einen Latte, bitte.\"}, {\"original\": \"Wi-Fi var mı?\", \"translated\": \"Haben Sie WLAN?\"}, {\"original\": \"Menüyü görebilir miyim, lütfen?\", \"translated\": \"Könnte ich bitte die Speisekarte sehen?\"}, {\"original\": \"İkinci dolum yapılabilir mi?\", \"translated\": \"Darf man nachfüllen?\"}, {\"original\": \"Kahvaltım hazır mı?\", \"translated\": \"Ist mein Kaffee fertig?\"}, {\"original\": \"Burada ne kadar süre oturabilirim?\", \"translated\": \"Wie lange darf ich hier sitzen?\"}, {\"original\": \"Bizi birlikte çektikten sonra fotoğraf çekebilir misiniz?\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"Hesap, lütfen. Teşekkür ederim.\", \"translated\": \"Die Rechnung, bitte. Vielen Dank.\"}, {\"original\": \"Gerçekten çok lezzetli.\", \"translated\": \"Es schmeckt wirklich gut.\"}]', 12, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Restoranda kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte restoranla ilgili 10 yaygın ifade ve İspanyolca çevirileri:\"]', '[\"Yemek Yeme\", \"Sipariş Verme\", \"Ödeme\"]', 'tr', '[\"Şu anda aklınızda içecek siparişi vermek, bir şikayette bulunmak ya da malzemeler hakkında soru sormak gibi belirli bir durum mu var? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Affedersiniz, yemeğimiz ne kadar sonra hazır olur?\", \"translated\": \"Perdón, ¿cuánto tiempo más tardará nuestra comida?\"}, {\"original\": \"Lütfen iki kişilik bir masa.\", \"translated\": \"Una mesa para dos, por favor.\"}, {\"original\": \"Lütfen menüyü görebilir miyiz?\", \"translated\": \"¿Podríamos ver el menú, por favor?\"}, {\"original\": \"Önerdiğiniz özel yemekleriniz var mı?\", \"translated\": \"¿Tienen algún plato especial que nos recomienden?\"}, {\"original\": \"Bunu ve bunu sipariş etmek istiyorum.\", \"translated\": \"Quisiera pedir esto y esto.\"}, {\"original\": \"Lütfen bir bardak su. Teşekkürler.\", \"translated\": \"Un vaso de agua, por favor. Gracias.\"}, {\"original\": \"Hesabı lütfen.\", \"translated\": \"La cuenta, por favor.\"}, {\"original\": \"Kredi kartıyla ödeyebilir miyim?\", \"translated\": \"¿Puedo pagar con tarjeta de crédito?\"}, {\"original\": \"Lütfen bunu götürmek için paketleyebilir misiniz?\", \"translated\": \"¿Podrían empaquetar esto para llevar, por favor?\"}, {\"original\": \"Yiyecekler çok lezzetliydi, teşekkür ederim.\", \"translated\": \"La comida estaba deliciosa, gracias.\"}]', 1, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Otelde kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte otel ile ilgili 10 yaygın ifade ve İspanyolca çevirileri:\"]', '[\"Kayıt Ol\", \"Çıkış Yap\", \"Oda Hizmeti\"]', 'tr', '[\"Şimdilik aklınızda özel bir durum var mı? Örneğin oda konumu, diğer otel hizmetleri veya çıkış işlemi gibi. Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\", \"translated\": \"Hola, tengo una reserva. Aquí tiene mi pasaporte.\"}, {\"original\": \"Boş odanız var mı?\", \"translated\": \"¿Tienen habitaciones disponibles?\"}, {\"original\": \"Affedersiniz, otelde bir spor salonu veya çamaşırhane var mı?\", \"translated\": \"Disculpe, ¿tiene el hotel gimnasio o lavandería?\"}, {\"original\": \"Kahvaltı saat kaçta başlıyor?\", \"translated\": \"¿A qué hora comienza el desayuno?\"}, {\"original\": \"Lütfen bir oda anahtarı verebilir misiniz?\", \"translated\": \"¿Podría darme la llave de la habitación, por favor?\"}, {\"original\": \"Lütfen bagajlarımı odaya taşıma konusunda bana yardımcı olur musunuz?\", \"translated\": \"¿Podría ayudarme a llevar mi equipaje a la habitación?\"}, {\"original\": \"Oda servisini nasıl arayabilirim?\", \"translated\": \"¿Cómo llamo al servicio de habitaciones?\"}, {\"original\": \"Çıkış saati kaçta?\", \"translated\": \"¿A qué hora es la salida?\"}, {\"original\": \"Bana bir makbuz/fatura yazabilir misiniz?\", \"translated\": \"¿Podría emitirme un recibo/factura?\"}, {\"original\": \"Bagajlarımı burada bırakabilir miyim?\", \"translated\": \"¿Puedo dejar mi equipaje aquí?\"}]', 2, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Havaalanında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte havaalanı ile ilgili 10 yaygın ifade ve bunların İspanyolca çevirileri:\"]', '[\"Giriş yapma\", \"Uçağa binme\", \"Bagaj kontrolü\"]', 'tr', '[\"Şu an için aklınızda özel bir durum var mı, örneğin check-in, bagaj teslimi ya da araç kiralama hizmeti? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş masası nerede?\", \"translated\": \"¿Dónde está el mostrador de facturación?\"}, {\"original\": \"Lütfen bir pencere koltuğu istiyorum.\", \"translated\": \"Me gustaría un asiento junto a la ventana, por favor.\"}, {\"original\": \"Bu uçuş gecikmiş mi?\", \"translated\": \"¿Este vuelo tiene retraso?\"}, {\"original\": \"Bu bagajı kontrol ettirmem gerekiyor.\", \"translated\": \"Necesito facturar este equipaje.\"}, {\"original\": \"İniş kapısı nerede?\", \"translated\": \"¿Dónde está la puerta de embarque?\"}, {\"original\": \"Uçak hemen kalkacak.\", \"translated\": \"El avión está a punto de despegar.\"}, {\"original\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\", \"translated\": \"¿Tengo que sacar mi ordenador portátil y mi power bank?\"}, {\"original\": \"Vergisiz alışveriş mağazası nerede?\", \"translated\": \"¿Dónde está la tienda libre de impuestos?\"}, {\"original\": \"Bavulumu bulamıyorum.\", \"translated\": \"No encuentro mi maleta.\"}, {\"original\": \"Tekerlekli sandalye hizmetiniz var mı?\", \"translated\": \"¿Ofrecen servicio de sillas de ruedas?\"}]', 3, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Toplu taşıma alanında kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte Toplu Taşıma ile ilgili 10 yaygın ifade ve bunların İspanyolca çevirileri:\"]', '[\"Otobüs/Metro Kullanma\", \"Bilet Satın Alma\", \"Aktarma\"]', 'tr', '[\"Şimdilik aklınızda özel bir durum var mı, örneğin otobüs durağı sormak, bilet fiyatını öğrenmek ya da inecek yer belirtmek? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bu otobüs terminala gidiyor mu?\", \"translated\": \"¿Este autobús va a la terminal?\"}, {\"original\": \"Bir sonraki durak neresi?\", \"translated\": \"¿Cuál es la próxima parada?\"}, {\"original\": \"Bilet nereden alabilirim?\", \"translated\": \"¿Dónde puedo comprar un billete?\"}, {\"original\": \"XX\'e bir bilet, lütfen.\", \"translated\": \"Un billete para XX, por favor.\"}, {\"original\": \"Aktarma yapmam gerekiyor mu?\", \"translated\": \"¿Tengo que hacer transbordo?\"}, {\"original\": \"Bir sonraki metro treni ne zaman geliyor?\", \"translated\": \"¿Cuánto tiempo falta para el próximo tren del metro?\"}, {\"original\": \"Affedersiniz, geçebilir miyim?\", \"translated\": \"Disculpe, permítame pasar, por favor.\"}, {\"original\": \"Bu koltuk dolu mu?\", \"translated\": \"¿Esta plaza está ocupada?\"}, {\"original\": \"Affedersiniz, XX’e gitmek için 2. Hat’a nerede aktarım yapabilirim?\", \"translated\": \"Disculpe, ¿dónde puedo transbordar a la línea 2 para llegar a XX?\"}, {\"original\": \"XX’e nasıl giderim?\", \"translated\": \"¿Cómo llego a XX?\"}]', 4, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Turistik yerlerde kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte turistik yerlerle ilgili 10 yaygın ifade ve bunların İspanyolca çevirileri:\"]', '[\"Manzara Görme\", \"Fotoğraf Çekme\", \"Bilet Satın Alma\"]', 'tr', '[\"Şimdilik aklınızda bilet ücreti sorma, otopark bulma veya tur rehberi hizmeti gibi belirli bir durum mu var? Sorunuzu özgürce iletebilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"Öğrenci biletleri mevcut mu?\", \"translated\": \"¿Hay entradas para estudiantes disponibles?\"}, {\"original\": \"Bu yer saat kaçta açılıyor?\", \"translated\": \"¿A qué hora abre la atracción?\"}, {\"original\": \"Burada yapılacak eğlenceli şeyler neler?\", \"translated\": \"¿Qué cosas divertidas se pueden hacer aquí?\"}, {\"original\": \"Bizi birlikte çeker misiniz?\", \"translated\": \"¿Podría hacernos una foto?\"}, {\"original\": \"Sightseeing otobüsü nerede?\", \"translated\": \"¿Dónde está el autobús turístico?\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"En iyi manzara noktası nerede?\", \"translated\": \"¿Cuál es el mejor lugar para observar?\"}, {\"original\": \"Buradaki manzara çok güzel.\", \"translated\": \"El paisaje aquí es hermoso.\"}, {\"original\": \"Rehberli tur mevcut mu?\", \"translated\": \"¿Hay visitas guiadas disponibles?\"}]', 5, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Taksi veya taksi hizmeti ile ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Taksi veya Taksi Hizmeti ile ilgili 10 yaygın ifade ve bunların İspanyolca çevirileri:\"]', '[\"Taksiye Biniş\", \"Varış Yerini Belirtme\", \"Ödeme\"]', 'tr', '[\"Şu anda en çok ne yapmak istersiniz? Örneğin, varış yerini sormak, ücreti öğrenmek ya da fatura istemek; sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bir taksi nerede bulabilirim?\", \"translated\": \"¿Dónde puedo conseguir un taxi?\"}, {\"original\": \"Lütfen beni bu adrese götürür müsünüz?\", \"translated\": \"Por favor, lléveme a esta dirección.\"}, {\"original\": \"Yaklaşık olarak ne kadar tutar?\", \"translated\": \"¿Cuánto costará aproximadamente?\"}, {\"original\": \"Lütfen taksimetre kullanır mısınız?\", \"translated\": \"¿Podría usar el taxímetro, por favor?\"}, {\"original\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\", \"translated\": \"Por favor, conduzca un poco más rápido, tengo prisa.\"}, {\"original\": \"Lütfen burada durur musunuz?\", \"translated\": \"Párese aquí, por favor.\"}, {\"original\": \"Kart veya mobil ödeme kabul ediyor musunuz?\", \"translated\": \"¿Acepta tarjetas o pagos móviles?\"}, {\"original\": \"Lütfen bir fiş verebilir misiniz?\", \"translated\": \"¿Podría darme un recibo, por favor?\"}, {\"original\": \"Teşekkür ederim, şoför bey.\", \"translated\": \"Gracias, conductor.\"}, {\"original\": \"Kaç dakika daha var?\", \"translated\": \"¿Cuánto falta todavía?\"}]', 6, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Eczanede kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte eczane ile ilgili 10 yaygın ifade ve bunların İspanyolca çevirileri:\"]', '[\"İlaç Satın Almak\", \"Danışmanlık\", \"Ödeme\"]', 'tr', '[\"Şimdilik aklınızda, ilaç kullanım talimatları sormak, sigorta kullanımıyla ilgili ifadeler veya tedavi süresi gibi belirli bir durum mu var? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Soğuk algınlığı ilacı var mı?\", \"translated\": \"¿Tiene medicamento para el resfriado?\"}, {\"original\": \"Bu ilacı nasıl kullanmalıyım?\", \"translated\": \"¿Cómo debo tomar este medicamento?\"}, {\"original\": \"Ağrı kesici ilaçlarınız var mı?\", \"translated\": \"¿Tiene algún analgésico?\"}, {\"original\": \"Kullanım kılavuzu var mı?\", \"translated\": \"¿Hay un folleto con instrucciones?\"}, {\"original\": \"Bu ilacın yan etkileri var mı?\", \"translated\": \"¿Este medicamento tiene efectos secundarios?\"}, {\"original\": \"Tıbbi sigorta kartımı kullanabilir miyim?\", \"translated\": \"¿Puedo usar mi tarjeta de seguro médico?\"}, {\"original\": \"Lütfen bir kutu yara bandı verebilir misiniz?\", \"translated\": \"¿Podría darme una caja de tiritas, por favor?\"}, {\"original\": \"Ateş düşürücü ilaçlarınız var mı?\", \"translated\": \"¿Tiene algún antipirético?\"}, {\"original\": \"Hafif bir çizik aldım. Antiseptik ve yara bandı var mı?\", \"translated\": \"Tengo una pequeña herida superficial. ¿Tiene antiséptico y tiritas?\"}, {\"original\": \"Kaçta kapanıyorsunuz?\", \"translated\": \"¿A qué hora cierran?\"}]', 7, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Acil Servislerle ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Acil Servislerle ilgili 10 yaygın ifade ve bunların İspanyolca çevirileri:\"]', '[\"Polisi Aramak\", \"İlkyardım\", \"Yardım Çağrısı\"]', 'tr', '[\"Şu anda aklınızda belirli bir acil durum var mı, örneğin yangın, yaralanma ve yardım gereksinimi, acil çağrı? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bana bir ambulans çağırmama yardımcı olun.\", \"translated\": \"Por favor, ayúdeme a llamar a una ambulancia.\"}, {\"original\": \"Hastane nerede?\", \"translated\": \"¿Dónde está el hospital?\"}, {\"original\": \"Birisi yaralandı.\", \"translated\": \"Alguien resultó herido.\"}, {\"original\": \"Lütfen bana yardımcı olun.\", \"translated\": \"Por favor, ayúdeme.\"}, {\"original\": \"Polis karakolu nerede?\", \"translated\": \"¿Dónde está la comisaría?\"}, {\"original\": \"Eşyalarımı kaybettim.\", \"translated\": \"He perdido mis pertenencias.\"}, {\"original\": \"İtfaiye numarası nedir?\", \"translated\": \"¿Cuál es el número de los bomberos?\"}, {\"original\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\", \"translated\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría más cercana?\"}, {\"original\": \"Acil çıkış var mı?\", \"translated\": \"¿Hay una salida de emergencia?\"}, {\"original\": \"Birisi bayıldı.\", \"translated\": \"Alguien ha desmayado.\"}]', 8, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Sahil veya havuz kenarında kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte sahil veya havuz kenarına ilişkin 10 yaygın ifade ve bunların İspanyolca çevirileri:\"]', '[\"Yüzme\", \"Güneşlenme\", \"Plaj Sporları\"]', 'tr', '[\"Şimdilik, katılacağınız yerel etkinlik veya festivalin bağlamını, örneğin kültürel festival, gıda festivali veya müzik festivali gibi, lütfen bana belirtir misiniz? Lütfen bağlamı sağlayın.\", \"Katıldığınız etkinlikleri lütfen belirtin.\"]', '[\"Aklınızda özel bir durum mu var? Sorunuzu özgürce sorabilirsiniz.\", \"Aklınızda canlandırdığınız durumu lütfen açıklayın.\"]', '[{\"original\": \"Bakın! Oradaki dalgalar gerçekten büyük.\", \"translated\": \"¡Mira! Las olas allí son realmente grandes.\"}, {\"original\": \"Güneş koruyucu sürmeyi unutmayın, buradaki UV ışınları çok güçlü.\", \"translated\": \"Recuerda aplicar protector solar; los rayos UV aquí son muy intensos.\"}, {\"original\": \"Bu plajdaki kum çok ince, pamuğun üzerinde yürüyormuş gibi hissettiriyor.\", \"translated\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\"}, {\"original\": \"Plajda voleybol oynamak nasıl olur?\", \"translated\": \"¿Qué tal jugar al voleibol en la playa?\"}, {\"original\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\", \"translated\": \"Los veleros a lo lejos se ven hermosos.\"}, {\"original\": \"Buradaki su çok berrak, balıkları bile görebiliyorsunuz.\", \"translated\": \"El agua aquí es tan transparente que incluso puedes ver los peces.\"}, {\"original\": \"Hadi biraz deniz kabuğu bulmaya gidelim.\", \"translated\": \"Vamos a buscar conchas marinas.\"}, {\"original\": \"Gün batımında plajda yürüyüş yapmak kesinlikle çok romantik olmalı.\", \"translated\": \"Pasear por la playa al atardecer debe ser muy romántico.\"}, {\"original\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\", \"translated\": \"He oído que los mariscos aquí son muy frescos; vamos a probarlos.\"}, {\"original\": \"Deniz yükseliyor, hadi kıyıya doğru gidelim.\", \"translated\": \"La marea está subiendo; volvamos hacia la orilla.\"}]', 9, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Yerel Etkinlikler ve Festivallerde kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte Yerel Etkinlikler ve Festivallerle ilgili 10 yaygın ifade ile birlikte İspanyolca çevirileri:\"]', '[\"Etkinliklere Katılmak\", \"Festivalleri Kutlamak\", \"Kültür Öğrenmek\"]', 'tr', '[\"Şimdilik, katıldığınız yerel etkinlik veya festival hakkında bağlamı bana verebilir misiniz? Örneğin Cadılar Bayramı, konser ya da arkadaş partisi gibi; ya da başka bir şey. Lütfen bağlamı belirtin.\", \"Aklınızda canlandırdığınız etkinlikleri tanımlayınız.\"]', '[\"Aklınızda belirli bir durum mu var? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu tanımlayınız.\"]', '[{\"original\": \"Bugün herhangi bir etkinlik var mı?\", \"translated\": \"¿Hay algún evento hoy?\"}, {\"original\": \"Bu festivalle ilgili özel bir şey var mı?\", \"translated\": \"¿Hay algo especial en este festival?\"}, {\"original\": \"Kutlama nerede yapılacak?\", \"translated\": \"¿Dónde se celebra la festividad?\"}, {\"original\": \"Biletleri nasıl alabilirim?\", \"translated\": \"¿Cómo puedo comprar entradas?\"}, {\"original\": \"Gösteri saat kaçta başlıyor?\", \"translated\": \"¿A qué hora empieza la actuación?\"}, {\"original\": \"Hangi geleneksel yiyecekler var?\", \"translated\": \"¿Qué comida tradicional hay?\"}, {\"original\": \"Burada gerçekten hareketli bir atmosfer var.\", \"translated\": \"Aquí es realmente animado.\"}, {\"original\": \"Halk oyunu gibi etkinlikler var mı?\", \"translated\": \"¿Hay alguna actividad popular?\"}, {\"original\": \"Mutlu tatiller!\", \"translated\": \"¡Felices fiestas!\"}, {\"original\": \"Etkinlik saat kaçta bitiyor?\", \"translated\": \"¿A qué hora termina el evento?\"}]', 10, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Müze veya Sanat Galerisi\'nde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Müze veya Sanat Galerisi ile ilgili 10 yaygın ifade ve bunların İspanyolca çevirileri:\"]', '[\"Ziyaret Etmek\", \"Rehberli Tur\", \"Bilet Satın Almak\"]', 'tr', '[\"Şimdilik aklınızda, tanıtım kılavuzu istemek, yol haritası ile ilgili ifadeler kullanmak veya sergilenen eserler hakkında yorum yapmak gibi belirli bir durum var mı? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"Sesli rehberleriniz var mı?\", \"translated\": \"¿Tienen guías de audio?\"}, {\"original\": \"Bu eseri kim yaratmış?\", \"translated\": \"¿Quién creó esta obra de arte?\"}, {\"original\": \"Müzenin en değerli eseri nerede?\", \"translated\": \"¿Dónde se encuentra la pieza más valiosa del museo?\"}, {\"original\": \"Fotoğraf çekmeye izin veriliyor mu?\", \"translated\": \"¿Está permitida la fotografía?\"}, {\"original\": \"Burada özel sergiler var mı?\", \"translated\": \"¿Hay alguna exposición especial aquí?\"}, {\"original\": \"Ziyaret kaç dakika sürüyor?\", \"translated\": \"¿Cuánto tiempo dura la visita?\"}, {\"original\": \"Bize bir giriş yapar mısınız?\", \"translated\": \"¿Podrían darnos una introducción?\"}, {\"original\": \"Bu eserler gerçekten çok zarif.\", \"translated\": \"Estas obras son verdaderamente exquisitas.\"}, {\"original\": \"Hediyelik eşya dükkanı nerede?\", \"translated\": \"¿Dónde está la tienda de souvenirs?\"}]', 11, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Kafelerde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte kafelerle ilgili 10 yaygın ifade ve bunların İspanyolca çevirileri:\"]', '[\"Kahvaltı Siparişi Verme\", \"Dinlenme\", \"Sosyalleşme\"]', 'tr', '[\"Şimdilik aklınızda, bir menü istemek, soğuk ya da sıcak içecekler sipariş etmek, diğer ürünler almak gibi belirli bir durum mu var? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bir latte getirir misiniz?\", \"translated\": \"Tomaré un latte, por favor.\"}, {\"original\": \"Wi-Fi var mı?\", \"translated\": \"¿Tienen conexión Wi-Fi?\"}, {\"original\": \"Menüyü görebilir miyim, lütfen?\", \"translated\": \"¿Podría ver el menú, por favor?\"}, {\"original\": \"İkinci dolum yapılabilir mi?\", \"translated\": \"¿Se permiten recargas?\"}, {\"original\": \"Kahvaltım hazır mı?\", \"translated\": \"¿Ya está listo mi café?\"}, {\"original\": \"Burada ne kadar süre oturabilirim?\", \"translated\": \"¿Cuánto tiempo puedo quedarme aquí?\"}, {\"original\": \"Bizi birlikte çektikten sonra fotoğraf çekebilir misiniz?\", \"translated\": \"¿Podría tomarnos una foto?\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"Hesap, lütfen. Teşekkür ederim.\", \"translated\": \"La cuenta, por favor. Gracias.\"}, {\"original\": \"Gerçekten çok lezzetli.\", \"translated\": \"Sabe realmente bien.\"}]', 12, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser au restaurant ?\", \"Formidable ! Voici 10 expressions courantes liées au restaurant, accompagnées de leurs traductions en turc :\"]', '[\"Restauration\", \"Commande\", \"Paiement\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple commander des boissons, formuler une réclamation ou demander des informations sur les ingrédients ? N’hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\", \"translated\": \"Affedersiniz, yemeğimiz ne kadar sonra hazır olur?\"}, {\"original\": \"Une table pour deux, s\'il vous plaît.\", \"translated\": \"Lütfen iki kişilik bir masa.\"}, {\"original\": \"Pourrions-nous voir la carte, s\'il vous plaît ?\", \"translated\": \"Lütfen menüyü görebilir miyiz?\"}, {\"original\": \"Avez-vous des plats signature à nous recommander ?\", \"translated\": \"Önerdiğiniz özel yemekleriniz var mı?\"}, {\"original\": \"Je voudrais commander ceci et cela.\", \"translated\": \"Bunu ve bunu sipariş etmek istiyorum.\"}, {\"original\": \"Un verre d\'eau, s\'il vous plaît. Merci.\", \"translated\": \"Lütfen bir bardak su. Teşekkürler.\"}, {\"original\": \"L\'addition, s\'il vous plaît.\", \"translated\": \"Hesabı lütfen.\"}, {\"original\": \"Puis-je payer par carte bancaire ?\", \"translated\": \"Kredi kartıyla ödeyebilir miyim?\"}, {\"original\": \"Pourriez-vous emballer cela à emporter, s\'il vous plaît ?\", \"translated\": \"Lütfen bunu götürmek için paketleyebilir misiniz?\"}, {\"original\": \"Le plat était délicieux, merci.\", \"translated\": \"Yiyecekler çok lezzetliydi, teşekkür ederim.\"}]', 1, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser à l’hôtel ?\", \"Formidable ! Voici 10 expressions courantes liées à l’hôtel, accompagnées de leurs traductions en turc :\"]', '[\"Enregistrement\", \"Départ\", \"Service en chambre\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple l’emplacement de la chambre, d’autres services hôteliers ou le départ ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Bonjour, j’ai une réservation. Voici mon passeport.\", \"translated\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\"}, {\"original\": \"Avez-vous des chambres disponibles ?\", \"translated\": \"Boş odanız var mı?\"}, {\"original\": \"Excusez-moi, l’hôtel dispose-t-il d’une salle de sport ou d’une buanderie ?\", \"translated\": \"Affedersiniz, otelin bir spor salonu veya çamaşırhane bölümü var mı?\"}, {\"original\": \"À quelle heure commence le petit-déjeuner ?\", \"translated\": \"Kahvaltı saat kaçta başlıyor?\"}, {\"original\": \"Pourrais-je avoir la clé de ma chambre, s’il vous plaît ?\", \"translated\": \"Lütfen bir oda anahtarı alabilir miyim?\"}, {\"original\": \"Pourriez-vous m’aider à porter mes bagages jusqu’à ma chambre ?\", \"translated\": \"Lütfen bana bagajlarımı odaya taşımada yardımcı olur musunuz?\"}, {\"original\": \"Comment puis-je appeler le service d’étage ?\", \"translated\": \"Oda servisini nasıl arayabilirim?\"}, {\"original\": \"À quelle heure est la sortie ?\", \"translated\": \"Çıkış saati kaçta?\"}, {\"original\": \"Pourriez-vous me délivrer un reçu / une facture ?\", \"translated\": \"Bana bir makbuz/fatura yazabilir misiniz?\"}, {\"original\": \"Puis-je laisser mes bagages ici ?\", \"translated\": \"Bagajlarımı burada bırakabilir miyim?\"}]', 2, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser à l’aéroport ?\", \"Formidable ! Voici 10 expressions courantes liées à l’aéroport, accompagnées de leurs traductions en turc :\"]', '[\"Enregistrement\", \"Embarquement\", \"Enregistrement des bagages\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, comme l’enregistrement, le retrait des bagages ou la location de voiture ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Où se trouve le comptoir d\'enregistrement ?\", \"translated\": \"Giriş masası nerede?\"}, {\"original\": \"Je voudrais un siège côté hublot, s\'il vous plaît.\", \"translated\": \"Lütfen bir pencere koltuğu istiyorum.\"}, {\"original\": \"Ce vol est-il retardé ?\", \"translated\": \"Bu uçuş gecikmiş mi?\"}, {\"original\": \"Je dois enregistrer ce bagage.\", \"translated\": \"Bu bagajı kontrol ettirmem gerekiyor.\"}, {\"original\": \"Où se trouve la porte d\'embarquement ?\", \"translated\": \"İniş kapısı nerede?\"}, {\"original\": \"L\'avion va bientôt décoller.\", \"translated\": \"Uçak hemen kalkacak.\"}, {\"original\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\", \"translated\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\"}, {\"original\": \"Où se trouve la boutique hors taxes ?\", \"translated\": \"Vergisiz alışveriş mağazası nerede?\"}, {\"original\": \"Je ne trouve pas ma valise.\", \"translated\": \"Bavulumu bulamıyorum.\"}, {\"original\": \"Proposez-vous un service de fauteuil roulant ?\", \"translated\": \"Tekerlekli sandalye hizmetiniz var mı?\"}]', 3, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans les transports en commun ?\", \"Formidable ! Voici 10 expressions courantes liées aux transports en commun, accompagnées de leurs traductions en turc :\"]', '[\"Prendre le bus ou le métro\", \"Acheter des billets\", \"Effectuer une correspondance\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander où se trouve l’arrêt de bus, le prix du billet ou indiquer que vous souhaitez descendre ? N’hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Ce bus va-t-il jusqu\'à la gare routière ?\", \"translated\": \"Bu otobüs terminala gidiyor mu?\"}, {\"original\": \"Quel est le prochain arrêt ?\", \"translated\": \"Bir sonraki durak neresi?\"}, {\"original\": \"Où puis-je acheter un billet ?\", \"translated\": \"Bilet nereden alabilirim?\"}, {\"original\": \"Un billet pour XX, s\'il vous plaît.\", \"translated\": \"XX\'e bir bilet, lütfen.\"}, {\"original\": \"Dois-je changer de transport ?\", \"translated\": \"Aktarma yapmam gerekiyor mu?\"}, {\"original\": \"Combien de temps avant le prochain métro ?\", \"translated\": \"Bir sonraki metro trenine ne kadar kaldı?\"}, {\"original\": \"Excusez-moi, laissez-moi passer, s\'il vous plaît.\", \"translated\": \"Üzgünüm, geçebilir miyim?\"}, {\"original\": \"Cette place est-elle occupée ?\", \"translated\": \"Bu koltuk dolu mu?\"}, {\"original\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d\'aller à XX ?\", \"translated\": \"Üzgünüm, XX\'e gitmek için 2. Hat\'a nerede aktarım yapabilirim?\"}, {\"original\": \"Comment puis-je me rendre à XX ?\", \"translated\": \"XX\'e nasıl giderim?\"}]', 4, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans les sites touristiques ?\", \"Formidable ! Voici 10 expressions courantes liées aux sites touristiques, accompagnées de leurs traductions en turc :\"]', '[\"Visite touristique\", \"Prendre des photos\", \"Acheter des billets\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander le prix des billets, trouver un parking ou solliciter un service de guide touristique ? N’hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Combien coûte l\'entrée ?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"Y a-t-il des billets étudiants disponibles ?\", \"translated\": \"Öğrenci biletleri mevcut mu?\"}, {\"original\": \"À quelle heure ouvre l\'attraction ?\", \"translated\": \"Bu yer saat kaçta açılıyor?\"}, {\"original\": \"Quelles sont les activités amusantes à faire ici ?\", \"translated\": \"Burada yapılacak eğlenceli şeyler neler?\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"Bizi birlikte çeker misiniz?\"}, {\"original\": \"Où est le bus touristique ?\", \"translated\": \"Sightseeing otobüsü nerede?\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"Quel est le meilleur endroit pour admirer la vue ?\", \"translated\": \"En iyi manzara noktası nerede?\"}, {\"original\": \"Le paysage est magnifique ici.\", \"translated\": \"Buradaki manzara çok güzel.\"}, {\"original\": \"Une visite guidée est-elle disponible ?\", \"translated\": \"Rehberli tur mevcut mu?\"}]', 5, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser avec un taxi ou un service de taxi ?\", \"Formidable ! Voici 10 expressions courantes liées au taxi ou au service de taxi, accompagnées de leurs traductions en turc :\"]', '[\"Prendre un taxi\", \"Indiquer la destination\", \"Paiement\"]', 'fr', '[\"Pour l’instant, que souhaitez-vous faire principalement maintenant : demander la destination, le montant ou une facture ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Où puis-je prendre un taxi ?\", \"translated\": \"Bir taksi nerede bulabilirim?\"}, {\"original\": \"Veuillez me conduire à cette adresse.\", \"translated\": \"Lütfen beni bu adrese götürür müsünüz?\"}, {\"original\": \"Combien cela coûtera-t-il approximativement ?\", \"translated\": \"Yaklaşık olarak ne kadar tutar?\"}, {\"original\": \"Pourriez-vous utiliser le compteur, s’il vous plaît ?\", \"translated\": \"Lütfen taksimetre kullanır mısınız?\"}, {\"original\": \"Pourriez-vous conduire un peu plus vite, je suis pressé(e).\", \"translated\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\"}, {\"original\": \"Veuillez vous arrêter ici.\", \"translated\": \"Lütfen burada durur musunuz?\"}, {\"original\": \"Acceptez-vous les paiements par carte ou mobile ?\", \"translated\": \"Kart veya mobil ödeme kabul ediyor musunuz?\"}, {\"original\": \"Pourrais-je avoir un reçu, s’il vous plaît ?\", \"translated\": \"Lütfen bir fiş verebilir misiniz?\"}, {\"original\": \"Merci, monsieur/madame le chauffeur.\", \"translated\": \"Teşekkür ederim, şoför bey.\"}, {\"original\": \"Il reste encore combien de temps ?\", \"translated\": \"Kaç dakika daha var?\"}]', 6, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser en pharmacie ?\", \"Formidable ! Voici 10 expressions courantes liées à la pharmacie, accompagnées de leurs traductions en turc :\"]', '[\"Acheter des médicaments\", \"Consultation\", \"Paiement\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander des instructions sur la prise de médicaments, des expressions liées à l’utilisation de l’assurance ou à la durée du traitement ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Avez-vous des médicaments contre le rhume ?\", \"translated\": \"Soğuk algınlığı ilacı var mı?\"}, {\"original\": \"Comment dois-je prendre ce médicament ?\", \"translated\": \"Bu ilacı nasıl kullanmalıyım?\"}, {\"original\": \"Avez-vous des analgésiques ?\", \"translated\": \"Ağrı kesici ilaçlarınız var mı?\"}, {\"original\": \"Y a-t-il une notice d’instructions ?\", \"translated\": \"Kullanım kılavuzu var mı?\"}, {\"original\": \"Ce médicament a-t-il des effets secondaires ?\", \"translated\": \"Bu ilacın yan etkileri var mı?\"}, {\"original\": \"Puis-je utiliser ma carte d’assurance maladie ?\", \"translated\": \"Tıbbi sigorta kartımı kullanabilir miyim?\"}, {\"original\": \"Pourriez-vous me donner une boîte de pansements, s’il vous plaît ?\", \"translated\": \"Lütfen bir kutu yara bandı verebilir misiniz?\"}, {\"original\": \"Avez-vous des antipyrétiques ?\", \"translated\": \"Ateş düşürücü ilaçlarınız var mı?\"}, {\"original\": \"Je me suis un peu écorché. Avez-vous un antiseptique et des pansements ?\", \"translated\": \"Hafif bir çizik aldım. Antiseptik ve yara bandı var mı?\"}, {\"original\": \"À quelle heure fermez-vous ?\", \"translated\": \"Kaçta kapanıyorsunuz?\"}]', 7, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans les services d\'urgence ?\", \"Formidable ! Voici 10 expressions courantes liées aux services d\'urgence, accompagnées de leurs traductions en turc :\"]', '[\"Appeler la police\", \"Premiers secours\", \"Appeler à l\'aide\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation d\'urgence précise en tête, par exemple un incendie, une personne blessée nécessitant de l\'aide ou un appel d\'urgence ? N\'hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', NULL, '[{\"original\": \"Veuillez m\'aider à appeler une ambulance.\", \"translated\": \"Lütfen bana bir ambulans çağırmama yardımcı olun.\"}, {\"original\": \"Où se trouve l\'hôpital ?\", \"translated\": \"Hastane nerede?\"}, {\"original\": \"Quelqu\'un est blessé.\", \"translated\": \"Birisi yaralandı.\"}, {\"original\": \"Veuillez m\'aider.\", \"translated\": \"Lütfen bana yardımcı olun.\"}, {\"original\": \"Où se trouve le poste de police ?\", \"translated\": \"Polis karakolu nerede?\"}, {\"original\": \"J\'ai perdu mes affaires.\", \"translated\": \"Eşyalarımı kaybettim.\"}, {\"original\": \"Quel est le numéro des pompiers ?\", \"translated\": \"İtfaiye numarası nedir?\"}, {\"original\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le poste de police le plus proche ?\", \"translated\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\"}, {\"original\": \"Y a-t-il une sortie de secours ?\", \"translated\": \"Acil çıkış var mı?\"}, {\"original\": \"Quelqu\'un s\'est évanoui.\", \"translated\": \"Birisi bayıldı.\"}]', 8, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser à la plage ou au bord de la piscine ?\", \"Formidable ! Voici 10 expressions courantes liées à la plage ou au bord de la piscine, accompagnées de leurs traductions en turc :\"]', '[\"Natation\", \"Bain de soleil\", \"Sports de plage\"]', 'fr', '[\"Pour l’instant, pourriez-vous me préciser le contexte de l’événement ou de la fête locale auquel vous participez, par exemple un festival culturel, un festival gastronomique ou un festival musical ? Veuillez fournir ce contexte.\", \"Veuillez indiquer les activités auxquelles vous participez.\"]', '[\"Avez-vous une situation précise en tête ? N’hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\", \"translated\": \"Bakın! Oradaki dalgalar gerçekten büyük.\"}, {\"original\": \"N\'oubliez pas d\'appliquer de la crème solaire, les rayons UV sont très intenses ici.\", \"translated\": \"Güneş koruyucu sürmeyi unutmayın, buradaki UV ışınları çok güçlü.\"}, {\"original\": \"Le sable de cette plage est si fin qu\'on a l\'impression de marcher sur du coton.\", \"translated\": \"Bu plajdaki kum çok ince, pamuk üzerinde yürüyormuş gibi hissettiriyor.\"}, {\"original\": \"Et si on jouait au volley-ball sur la plage ?\", \"translated\": \"Plajda voleybol oynamak nasıl olur?\"}, {\"original\": \"Les voiliers au loin sont magnifiques.\", \"translated\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\"}, {\"original\": \"L\'eau est si claire ici qu\'on peut même voir les poissons.\", \"translated\": \"Buradaki su çok berrak, balıkları bile görebiliyorsunuz.\"}, {\"original\": \"Allons chercher des coquillages.\", \"translated\": \"Hadi biraz deniz kabuğu arayalım.\"}, {\"original\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\", \"translated\": \"Gün batımında plajda yürüyüş yapmak kesinlikle çok romantik olmalı.\"}, {\"original\": \"J\'ai entendu dire que les fruits de mer sont très frais ici, allons-en goûter.\", \"translated\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\"}, {\"original\": \"La marée monte, dirigeons-nous vers la rive.\", \"translated\": \"Deniz yükseliyor, kıyıya doğru gidelim.\"}]', 9, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser lors d’événements locaux et de festivals ?\", \"Formidable ! Voici 10 expressions courantes liées aux événements locaux et aux festivals, accompagnées de leurs traductions en turc :\"]', '[\"Assister à des événements\", \"Célébrer des festivals\", \"Apprendre la culture\"]', 'fr', '[\"Pour l’instant, pourriez-vous s’il vous plaît me préciser le contexte de l’événement local ou du festival auquel vous participez, par exemple Halloween, un concert, une fête entre amis ou autre chose ? Veuillez fournir ce contexte.\", \"Veuillez décrire les activités qui vous viennent à l’esprit.\"]', '[\"Avez-vous une situation précise en tête ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Y a-t-il des événements aujourd\'hui ?\", \"translated\": \"Bugün herhangi bir etkinlik var mı?\"}, {\"original\": \"Y a-t-il quelque chose de particulier à propos de ce festival ?\", \"translated\": \"Bu festivalle ilgili özel bir şey var mı?\"}, {\"original\": \"Où se déroule la célébration ?\", \"translated\": \"Kutlama nerede yapılacak?\"}, {\"original\": \"Comment puis-je acheter des billets ?\", \"translated\": \"Biletleri nasıl alabilirim?\"}, {\"original\": \"À quelle heure commence la représentation ?\", \"translated\": \"Gösteri saat kaçta başlıyor?\"}, {\"original\": \"Quels sont les plats traditionnels ?\", \"translated\": \"Hangi geleneksel yiyecekler var?\"}, {\"original\": \"C\'est vraiment animé ici.\", \"translated\": \"Burada gerçekten hareketli bir atmosfer var.\"}, {\"original\": \"Y a-t-il des activités folkloriques ?\", \"translated\": \"Halk oyunları gibi etkinlikler var mı?\"}, {\"original\": \"Joyeuses fêtes !\", \"translated\": \"Mutlu tatiller!\"}, {\"original\": \"À quelle heure se termine l\'événement ?\", \"translated\": \"Etkinlik saat kaçta bitiyor?\"}]', 10, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans un musée ou une galerie d\'art ?\", \"Formidable ! Voici 10 expressions courantes liées au musée ou à la galerie d\'art, accompagnées de leurs traductions en turc :\"]', '[\"Visite\", \"Visite guidée\", \"Achat de billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander une notice explicative, des expressions liées à un parcours guidé, des expressions pour commenter une exposition ? N\'hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', NULL, '[{\"original\": \"Quel est le montant des frais d\'entrée ?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"Proposez-vous des guides audio ?\", \"translated\": \"Sesli rehberleriniz var mı?\"}, {\"original\": \"Qui est l\'auteur de cette œuvre ?\", \"translated\": \"Bu eseri kim yaratmış?\"}, {\"original\": \"Où se trouve la pièce la plus précieuse du musée ?\", \"translated\": \"Müzenin en değerli eseri nerede?\"}, {\"original\": \"La photographie est-elle autorisée ?\", \"translated\": \"Fotoğraf çekmeye izin veriliyor mu?\"}, {\"original\": \"Y a-t-il des expositions spéciales ici ?\", \"translated\": \"Burada özel sergiler var mı?\"}, {\"original\": \"Combien de temps dure la visite ?\", \"translated\": \"Ziyaret kaç dakika sürüyor?\"}, {\"original\": \"Pourriez-vous nous en faire une présentation ?\", \"translated\": \"Bize bir giriş yapar mısınız?\"}, {\"original\": \"Ces œuvres sont véritablement exquises.\", \"translated\": \"Bu eserler gerçekten çok zarif.\"}, {\"original\": \"Où se trouve la boutique de souvenirs ?\", \"translated\": \"Hediyelik eşya dükkanı nerede?\"}]', 11, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans les cafés ?\", \"Formidable ! Voici 10 expressions courantes liées aux cafés, accompagnées de leurs traductions en turc :\"]', '[\"Commander du café\", \"Se reposer\", \"Socialiser\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander la carte, des boissons glacées ou chaudes, d’autres produits ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Je prendrai un latte, s’il vous plaît.\", \"translated\": \"Lütfen bir latte getirir misiniz?\"}, {\"original\": \"Avez-vous le Wi-Fi ?\", \"translated\": \"Wi-Fi var mı?\"}, {\"original\": \"Pourrais-je voir la carte, s’il vous plaît ?\", \"translated\": \"Menüyü görebilir miyim, lütfen?\"}, {\"original\": \"Les recharges sont-elles autorisées ?\", \"translated\": \"İkinci dolum yapılabilir mi?\"}, {\"original\": \"Mon café est-il prêt ?\", \"translated\": \"Kahvaltım hazır mı?\"}, {\"original\": \"Combien de temps puis-je rester assis ici ?\", \"translated\": \"Burada ne kadar süre oturabilirim?\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"Bizi birlikte çektikten sonra fotoğraf çekebilir misiniz?\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"L’addition, s’il vous plaît. Merci.\", \"translated\": \"Hesap, lütfen. Teşekkür ederim.\"}, {\"original\": \"C’est vraiment délicieux.\", \"translated\": \"Gerçekten çok lezzetli.\"}]', 12, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Restaurant verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Restaurants sowie deren türkische Übersetzungen:\"]', '[\"Gastronomie\", \"Bestellen\", \"Kasse\"]', 'de', '[\"Vorläufig: Haben Sie eine bestimmte Situation im Kopf, etwa Getränke bestellen, eine Beschwerde äußern oder nach Zutaten fragen? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', NULL, '[{\"original\": \"Entschuldigung, wie lange dauert es noch bis zu unserem Essen?\", \"translated\": \"Affedersiniz, yemeğimiz ne kadar sonra hazır olur?\"}, {\"original\": \"Ein Tisch für zwei Personen, bitte.\", \"translated\": \"Lütfen iki kişilik bir masa.\"}, {\"original\": \"Könnten wir bitte die Speisekarte sehen?\", \"translated\": \"Lütfen menüyü görebilir miyiz?\"}, {\"original\": \"Haben Sie empfehlenswerte Hausgerichte?\", \"translated\": \"Önerdiğiniz özel yemekleriniz var mı?\"}, {\"original\": \"Ich möchte dies hier und das hier bestellen.\", \"translated\": \"Bunu ve bunu sipariş etmek istiyorum.\"}, {\"original\": \"Ein Glas Wasser, bitte. Danke.\", \"translated\": \"Lütfen bir bardak su. Teşekkürler.\"}, {\"original\": \"Die Rechnung, bitte.\", \"translated\": \"Hesabı lütfen.\"}, {\"original\": \"Kann ich mit Kreditkarte bezahlen?\", \"translated\": \"Kredi kartıyla ödeyebilir miyim?\"}, {\"original\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\", \"translated\": \"Lütfen bunu götürmek için paketleyebilir misiniz?\"}, {\"original\": \"Das Essen war köstlich, vielen Dank.\", \"translated\": \"Yiyecekler çok lezzetliydi, teşekkür ederim.\"}]', 1, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Hotel verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Hotels sowie deren türkische Übersetzungen:\"]', '[\"Einchecken\", \"Auschecken\", \"Zimmerservice\"]', 'de', '[\"Vorerst: Haben Sie eine bestimmte Situation im Kopf, z. B. die Lage des Zimmers, weitere Hoteldienstleistungen oder den Check-out? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', NULL, '[{\"original\": \"Hallo, ich habe eine Reservierung. Hier ist mein Reisepass.\", \"translated\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\"}, {\"original\": \"Haben Sie noch freie Zimmer?\", \"translated\": \"Boş odanız var mı?\"}, {\"original\": \"Entschuldigung, verfügt das Hotel über ein Fitnessstudio oder einen Waschraum?\", \"translated\": \"Affedersiniz, otelde bir spor salonu veya çamaşırhane var mı?\"}, {\"original\": \"Wann beginnt das Frühstück?\", \"translated\": \"Kahvaltı saat kaçta başlıyor?\"}, {\"original\": \"Könnte ich bitte den Zimmerschlüssel haben?\", \"translated\": \"Lütfen bir oda anahtarı alabilir miyim?\"}, {\"original\": \"Könnten Sie mir helfen, mein Gepäck auf das Zimmer zu bringen?\", \"translated\": \"Lütfen bagajlarımı odaya taşıma konusunda bana yardımcı olur musunuz?\"}, {\"original\": \"Wie rufe ich den Zimmerservice?\", \"translated\": \"Oda servisini nasıl arayabilirim?\"}, {\"original\": \"Wann ist der Check-out?\", \"translated\": \"Çıkış saati kaçta?\"}, {\"original\": \"Könnten Sie mir bitte eine Quittung / Rechnung ausstellen?\", \"translated\": \"Bana bir makbuz/fatura yazabilir misiniz?\"}, {\"original\": \"Darf ich mein Gepäck hier lassen?\", \"translated\": \"Bagajlarımı burada bırakabilir miyim?\"}]', 2, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich am Flughafen verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Flughafen zusammen mit türkischen Übersetzungen.\"]', '[\"Einchecken\", \"Boarding\", \"Gepäckabgabe\"]', 'de', '[\"Vorerst: Haben Sie eine bestimmte Situation im Kopf, wie etwa das Einchecken, die Gepäckausgabe oder einen Mietwagenservice? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', NULL, '[{\"original\": \"Wo ist der Check-in-Schalter?\", \"translated\": \"Giriş masası nerede?\"}, {\"original\": \"Ich hätte gerne einen Fensterplatz.\", \"translated\": \"Lütfen bir pencere koltuğu istiyorum.\"}, {\"original\": \"Ist dieser Flug verspätet?\", \"translated\": \"Bu uçuş gecikmiş mi?\"}, {\"original\": \"Ich muss dieses Gepäck aufgeben.\", \"translated\": \"Bu bagajı kontrol ettirmem gerekiyor.\"}, {\"original\": \"Wo ist das Boarding-Gate?\", \"translated\": \"İniş kapısı nerede?\"}, {\"original\": \"Das Flugzeug startet gleich.\", \"translated\": \"Uçak hemen kalkacak.\"}, {\"original\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\", \"translated\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\"}, {\"original\": \"Wo ist der Duty-free-Shop?\", \"translated\": \"Vergisiz alışveriş mağazası nerede?\"}, {\"original\": \"Ich kann meinen Koffer nicht finden.\", \"translated\": \"Bavulumu bulamıyorum.\"}, {\"original\": \"Bieten Sie einen Rollstuhlservice an?\", \"translated\": \"Tekerlekli sandalye hizmetiniz var mı?\"}]', 3, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im öffentlichen Nahverkehr verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema öffentlicher Nahverkehr samt türkischer Übersetzungen:\"]', '[\"Mit Bus/U-Bahn fahren\", \"Fahrkarten kaufen\", \"Umsteigen\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf, etwa nach einer Haltestelle, dem Fahrpreis oder dem Aussteigen zu fragen? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', NULL, '[{\"original\": \"Fährt dieser Bus zum Terminal?\", \"translated\": \"Bu otobüs terminala mı gidiyor?\"}, {\"original\": \"Was ist die nächste Haltestelle?\", \"translated\": \"Bir sonraki durak neresi?\"}, {\"original\": \"Wo kann ich ein Ticket kaufen?\", \"translated\": \"Bilet nereden alabilirim?\"}, {\"original\": \"Ein Ticket nach XX, bitte.\", \"translated\": \"XX\'e bir bilet lütfen.\"}, {\"original\": \"Muss ich umsteigen?\", \"translated\": \"Aktarma yapmam gerekiyor mu?\"}, {\"original\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\", \"translated\": \"Bir sonraki metro trenine ne kadar kaldı?\"}, {\"original\": \"Entschuldigung, bitte lassen Sie mich durch.\", \"translated\": \"Affedersiniz, geçebilir miyim?\"}, {\"original\": \"Ist dieser Platz bereits besetzt?\", \"translated\": \"Bu koltuk dolu mu?\"}, {\"original\": \"Entschuldigung, wo kann ich umsteigen, um mit der Linie 2 nach XX zu gelangen?\", \"translated\": \"Affedersiniz, XX\'e gitmek için 2. Hat\'a nerede aktarım yapabilirim?\"}, {\"original\": \"Wie komme ich nach XX?\", \"translated\": \"XX\'e nasıl giderim?\"}]', 4, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich an touristischen Sehenswürdigkeiten verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit touristischen Sehenswürdigkeiten samt türkischer Übersetzung:\"]', '[\"Sehenswürdigkeiten besichtigen\", \"Fotos machen\", \"Tickets kaufen\"]', 'de', '[\"Momentan: Haben Sie eine konkrete Situation im Kopf, etwa das Erfragen des Eintrittspreises, das Suchen eines Parkplatzes oder die Inanspruchnahme eines Fremdenführers? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', NULL, '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"Gibt es ermäßigte Eintrittskarten für Schüler?\", \"translated\": \"Öğrenci biletleri mevcut mu?\"}, {\"original\": \"Wann öffnet die Sehenswürdigkeit?\", \"translated\": \"Bu yer saat kaçta açılıyor?\"}, {\"original\": \"Was gibt es hier Spannendes zu tun?\", \"translated\": \"Burada yapılacak eğlenceli şeyler neler?\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"Bizi birlikte çeker misiniz?\"}, {\"original\": \"Wo befindet sich der Sightseeing-Bus?\", \"translated\": \"Sightseeing otobüsü nerede?\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"Wo ist der beste Aussichtspunkt?\", \"translated\": \"En iyi manzara noktası nerede?\"}, {\"original\": \"Die Landschaft hier ist wunderschön.\", \"translated\": \"Buradaki manzara çok güzel.\"}, {\"original\": \"Gibt es eine geführte Tour?\", \"translated\": \"Rehberli tur mevcut mu?\"}]', 5, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Zusammenhang mit einem Taxi oder einem Taxidienst verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit einem Taxi oder einem Taxidienst sowie deren türkische Übersetzungen:\"]', '[\"Taxi nehmen\", \"Ziel angeben\", \"Zahlen\"]', 'de', '[\"Was möchten Sie im Moment am dringendsten tun – beispielsweise das Ziel angeben, nach dem Preis fragen oder eine Rechnung anfordern? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen gerade in den Sinn kommt.\"]', NULL, '[{\"original\": \"Wo kann ich ein Taxi bekommen?\", \"translated\": \"Bir taksi nerede bulabilirim?\"}, {\"original\": \"Bitte fahren Sie mich zu dieser Adresse.\", \"translated\": \"Lütfen beni bu adrese götürür müsünüz?\"}, {\"original\": \"Wie viel kostet es ungefähr?\", \"translated\": \"Yaklaşık olarak ne kadar tutar?\"}, {\"original\": \"Könnten Sie bitte den Taxameter benutzen?\", \"translated\": \"Lütfen taksimetre kullanır mısınız?\"}, {\"original\": \"Bitte fahren Sie etwas schneller, ich habe es eilig.\", \"translated\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\"}, {\"original\": \"Bitte halten Sie hier an.\", \"translated\": \"Lütfen burada durur musunuz?\"}, {\"original\": \"Akzeptieren Sie Karten oder mobile Zahlungen?\", \"translated\": \"Kart veya mobil ödeme kabul ediyor musunuz?\"}, {\"original\": \"Könnte ich bitte eine Quittung haben?\", \"translated\": \"Lütfen bir fiş verebilir misiniz?\"}, {\"original\": \"Vielen Dank, Fahrer.\", \"translated\": \"Teşekkür ederim, şoför bey.\"}, {\"original\": \"Wie weit ist es noch?\", \"translated\": \"Kaç dakika daha var?\"}]', 6, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich in der Apotheke verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke aus dem Bereich der Apotheke samt türkischer Übersetzung:\"]', '[\"Medikamente kaufen\", \"Beratung\", \"Zahlung\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf, etwa die Bitte um Anweisungen zur Einnahme von Medikamenten, Formulierungen im Zusammenhang mit der Nutzung einer Krankenversicherung oder zur Dauer der Medikamenteneinnahme? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', NULL, '[{\"original\": \"Haben Sie Medikamente gegen Erkältung?\", \"translated\": \"Soğuk algınlığı ilacı var mı?\"}, {\"original\": \"Wie soll ich dieses Medikament einnehmen?\", \"translated\": \"Bu ilacı nasıl kullanmalıyım?\"}, {\"original\": \"Haben Sie Schmerzmittel?\", \"translated\": \"Ağrı kesici ilaçlarınız var mı?\"}, {\"original\": \"Gibt es eine Gebrauchsanweisung?\", \"translated\": \"Kullanım kılavuzu var mı?\"}, {\"original\": \"Hat dieses Medikament Nebenwirkungen?\", \"translated\": \"Bu ilacın yan etkileri var mı?\"}, {\"original\": \"Kann ich meine Krankenversicherungskarte verwenden?\", \"translated\": \"Tıbbi sigorta kartımı kullanabilir miyim?\"}, {\"original\": \"Könnte ich bitte eine Packung Pflaster haben?\", \"translated\": \"Lütfen bir kutu yara bandı verebilir misiniz?\"}, {\"original\": \"Haben Sie Fiebersenkende Mittel?\", \"translated\": \"Ateş düşürücü ilaçlarınız var mı?\"}, {\"original\": \"Ich habe mir leicht die Haut aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\", \"translated\": \"Hafif bir çizik aldım. Antiseptik ve yara bandı var mı?\"}, {\"original\": \"Wann schließen Sie?\", \"translated\": \"Kaçta kapanıyorsunuz?\"}]', 7, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Notdienst verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Notdiensten sowie deren türkische Übersetzungen:\"]', '[\"Polizei rufen\", \"Erste Hilfe leisten\", \"Hilfe rufen\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Notsituation im Kopf, z. B. Feuer, Verletzung und Hilfebedarf, Notruf? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', NULL, '[{\"original\": \"Bitte helfen Sie mir, einen Krankenwagen zu rufen.\", \"translated\": \"Lütfen bana bir ambulans çağırmama yardımcı olun.\"}, {\"original\": \"Wo ist das Krankenhaus?\", \"translated\": \"Hastane nerede?\"}, {\"original\": \"Jemand ist verletzt.\", \"translated\": \"Birisi yaralandı.\"}, {\"original\": \"Bitte helfen Sie mir.\", \"translated\": \"Lütfen bana yardımcı olun.\"}, {\"original\": \"Wo ist die Polizeistation?\", \"translated\": \"Polis karakolu nerede?\"}, {\"original\": \"Ich habe meine Sachen verloren.\", \"translated\": \"Eşyalarımı kaybettim.\"}, {\"original\": \"Wie lautet die Notrufnummer für die Feuerwehr?\", \"translated\": \"İtfaiye numarası nedir?\"}, {\"original\": \"Ich habe meinen Pass verloren. Wissen Sie, wo die nächste Polizeistation ist?\", \"translated\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\"}, {\"original\": \"Gibt es einen Notausgang?\", \"translated\": \"Acil çıkış var mı?\"}, {\"original\": \"Jemand ist in Ohnmacht gefallen.\", \"translated\": \"Birisi bayıldı.\"}]', 8, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich am Strand oder am Pool verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Strand oder Schwimmbad sowie deren türkische Übersetzungen:\"]', '[\"Schwimmen\", \"Sonnenbaden\", \"Strandsport\"]', 'de', '[\"Könnten Sie mir vorläufig den Kontext der lokalen Veranstaltung oder des Festivals, an dem Sie teilnehmen, mitteilen – beispielsweise ein Kulturfestival, ein Kulinarikfestival oder ein Musikfestival? Bitte geben Sie den Kontext an.\", \"Bitte nennen Sie die Aktivitäten, an denen Sie teilnehmen.\"]', '[\"Haben Sie bereits eine konkrete Situation im Kopf? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[{\"original\": \"Schau! Die Wellen dort drüben sind wirklich groß.\", \"translated\": \"Bakın! Oradaki dalgalar gerçekten büyük.\"}, {\"original\": \"Vergiss nicht, Sonnencreme aufzutragen – die UV-Strahlen sind hier sehr stark.\", \"translated\": \"Güneş koruyucu sürmeyi unutmayın, buradaki UV ışınları çok güçlü.\"}, {\"original\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle gehen.\", \"translated\": \"Bu plajdaki kum o kadar ince ki pamuk üzerinde yürüyor gibi hissediyorsunuz.\"}, {\"original\": \"Wie wäre es mit einem Volleyballspiel am Strand?\", \"translated\": \"Plajda voleybol oynamak nasıl olur?\"}, {\"original\": \"Die Segelboote in der Ferne sehen wunderschön aus.\", \"translated\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\"}, {\"original\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\", \"translated\": \"Buradaki su o kadar berrak ki balıkları bile görebiliyorsunuz.\"}, {\"original\": \"Lass uns Muscheln suchen gehen.\", \"translated\": \"Hadi biraz deniz kabuğu arayalım.\"}, {\"original\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\", \"translated\": \"Gün batımında plajda yürüyüş yapmak kesinlikle çok romantik olmalı.\"}, {\"original\": \"Ich habe gehört, dass die Meeresfrüchte hier sehr frisch sind – lass uns welche probieren.\", \"translated\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\"}, {\"original\": \"Die Flut kommt näher, gehen wir zum Ufer zurück.\", \"translated\": \"Deniz yükseliyor, kıyıya doğru gidelim.\"}]', 9, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich bei lokalen Veranstaltungen und Festen verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zu lokalen Veranstaltungen und Festen samt türkischer Übersetzung:\"]', '[\"Teilnahme an Veranstaltungen\", \"Feiern von Festen\", \"Kultur kennenlernen\"]', 'de', '[\"Könnten Sie mir vorerst den Kontext der lokalen Veranstaltung oder des Festes mitteilen, an dem Sie teilnehmen – beispielsweise Halloween, ein Konzert, eine Party bei Freunden oder etwas anderes? Bitte geben Sie den Kontext an.\", \"Bitte beschreiben Sie die Aktivitäten, die Ihnen dabei in den Sinn kommen.\"]', '[\"Haben Sie eine konkrete Situation im Kopf? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen dabei in den Sinn kommt.\"]', '[{\"original\": \"Gibt es heute irgendwelche Veranstaltungen?\", \"translated\": \"Bugün herhangi bir etkinlik var mı?\"}, {\"original\": \"Gibt es bei diesem Fest etwas Besonderes?\", \"translated\": \"Bu festivalle ilgili özel bir şey var mı?\"}, {\"original\": \"Wo findet die Feier statt?\", \"translated\": \"Kutlama nerede yapılacak?\"}, {\"original\": \"Wie kann ich Tickets kaufen?\", \"translated\": \"Biletleri nasıl alabilirim?\"}, {\"original\": \"Wann beginnt die Aufführung?\", \"translated\": \"Gösteri saat kaçta başlıyor?\"}, {\"original\": \"Welche traditionellen Speisen gibt es?\", \"translated\": \"Hangi geleneksel yiyecekler var?\"}, {\"original\": \"Es ist hier wirklich lebhaft.\", \"translated\": \"Burada gerçekten hareketli bir atmosfer var.\"}, {\"original\": \"Gibt es Volksaktivitäten?\", \"translated\": \"Halk oyunu gibi etkinlikler var mı?\"}, {\"original\": \"Frohe Feiertage!\", \"translated\": \"Mutlu tatiller!\"}, {\"original\": \"Wann endet die Veranstaltung?\", \"translated\": \"Etkinlik saat kaçta bitiyor?\"}]', 10, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich in einem Museum oder einer Kunstgalerie verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Museen oder Kunstgalerien sowie deren türkische Übersetzungen:\"]', '[\"Besuch\", \"Geführte Tour\", \"Kartenvorverkauf\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf, etwa das Nachfragen nach einer Einführungsbroschüre, Ausdrücke im Zusammenhang mit einem Rundgang oder Formulierungen zum Kommentieren einer Ausstellung? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', NULL, '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"Bieten Sie Audioführungen an?\", \"translated\": \"Sesli rehberleriniz var mı?\"}, {\"original\": \"Wer hat dieses Kunstwerk geschaffen?\", \"translated\": \"Bu eseri kim yaratmış?\"}, {\"original\": \"Wo befindet sich das wertvollste Stück des Museums?\", \"translated\": \"Müzenin en değerli eseri nerede?\"}, {\"original\": \"Ist das Fotografieren erlaubt?\", \"translated\": \"Fotoğraf çekmeye izin veriliyor mu?\"}, {\"original\": \"Gibt es hier besondere Ausstellungen?\", \"translated\": \"Burada özel sergiler var mı?\"}, {\"original\": \"Wie lange dauert der Besuch?\", \"translated\": \"Ziyaret kaç dakika sürüyor?\"}, {\"original\": \"Könnten Sie uns bitte eine Einführung geben?\", \"translated\": \"Bize bir tanıtım yapabilir misiniz?\"}, {\"original\": \"Diese Werke sind wirklich exquisit.\", \"translated\": \"Bu eserler gerçekten çok zarif.\"}, {\"original\": \"Wo befindet sich der Souvenirladen?\", \"translated\": \"Hediyelik eşya dükkanı nerede?\"}]', 11, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich in Cafés verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Cafés sowie deren türkische Übersetzungen:\"]', '[\"Kaffee bestellen\", \"Ausruhen\", \"Sozialisieren\"]', 'de', '[\"Vorerst: Haben Sie eine bestimmte Situation im Kopf, etwa das Bestellen einer Speisekarte, von kalten oder heißen Getränken oder anderer Produkte? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', NULL, '[{\"original\": \"Ich hätte gerne einen Latte, bitte.\", \"translated\": \"Lütfen bir latte getirir misiniz?\"}, {\"original\": \"Haben Sie WLAN?\", \"translated\": \"Wi-Fi var mı?\"}, {\"original\": \"Könnte ich bitte die Speisekarte sehen?\", \"translated\": \"Menüyü görebilir miyim, lütfen?\"}, {\"original\": \"Darf man nachfüllen?\", \"translated\": \"İkinci dolum yapılabilir mi?\"}, {\"original\": \"Ist mein Kaffee fertig?\", \"translated\": \"Kahvaltım hazır mı?\"}, {\"original\": \"Wie lange darf ich hier sitzen?\", \"translated\": \"Burada ne kadar oturabilirim?\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"Bizi birlikte fotoğraflar mısınız?\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"Die Rechnung, bitte. Vielen Dank.\", \"translated\": \"Hesap lütfen. Teşekkür ederim.\"}, {\"original\": \"Es schmeckt wirklich gut.\", \"translated\": \"Gerçekten çok lezzetli.\"}]', 12, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un restaurante?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con los restaurantes, junto con sus traducciones al turco:\"]', '[\"Comer\", \"Pedir\", \"Pagar\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir bebidas, presentar una queja o preguntar sobre los ingredientes? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"Perdón, ¿cuánto tiempo más tardará nuestra comida?\", \"translated\": \"Affedersiniz, yemeğimiz kaç dakika daha sürecektir?\"}, {\"original\": \"Una mesa para dos, por favor.\", \"translated\": \"İki kişilik bir masa lütfen.\"}, {\"original\": \"¿Podríamos ver el menú, por favor?\", \"translated\": \"Menüyü görebilir miyiz lütfen?\"}, {\"original\": \"¿Tienen algún plato especial que nos recomienden?\", \"translated\": \"Önerdiğiniz özel yemekleriniz var mı?\"}, {\"original\": \"Quisiera pedir esto y esto.\", \"translated\": \"Bunu ve bunu sipariş etmek istiyorum.\"}, {\"original\": \"Un vaso de agua, por favor. Gracias.\", \"translated\": \"Bir su bardağı lütfen. Teşekkürler.\"}, {\"original\": \"La cuenta, por favor.\", \"translated\": \"Hesap lütfen.\"}, {\"original\": \"¿Puedo pagar con tarjeta de crédito?\", \"translated\": \"Kredi kartıyla ödeyebilir miyim?\"}, {\"original\": \"¿Podrían empaquetar esto para llevar, por favor?\", \"translated\": \"Bunu alıp gidecek şekilde paketleyebilir misiniz lütfen?\"}, {\"original\": \"La comida estaba deliciosa, gracias.\", \"translated\": \"Yiyecekler çok lezzetliydi, teşekkür ederim.\"}]', 1, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en un hotel?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el hotel, junto con sus traducciones al turco:\"]', '[\"Registro de entrada\", \"Registro de salida\", \"Servicio de habitaciones\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como la ubicación de la habitación, otros servicios del hotel o el proceso de salida? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"Hola, tengo una reserva. Aquí tiene mi pasaporte.\", \"translated\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\"}, {\"original\": \"¿Tienen habitaciones disponibles?\", \"translated\": \"Boş odanız var mı?\"}, {\"original\": \"Disculpe, ¿tiene el hotel gimnasio o lavandería?\", \"translated\": \"Affedersiniz, otelin bir spor salonu veya çamaşırhane bölümü var mı?\"}, {\"original\": \"¿A qué hora comienza el desayuno?\", \"translated\": \"Kahvaltı saat kaçta başlıyor?\"}, {\"original\": \"¿Podría darme la llave de la habitación, por favor?\", \"translated\": \"Lütfen bir oda anahtarı alabilir miyim?\"}, {\"original\": \"¿Podría ayudarme a llevar mi equipaje a la habitación?\", \"translated\": \"Lütfen bana bagajlarımı odaya taşımada yardımcı olur musunuz?\"}, {\"original\": \"¿Cómo llamo al servicio de habitaciones?\", \"translated\": \"Oda servisini nasıl arayabilirim?\"}, {\"original\": \"¿A qué hora es la salida?\", \"translated\": \"Çıkış saati kaçta?\"}, {\"original\": \"¿Podría emitirme un recibo/factura?\", \"translated\": \"Bana bir makbuz/fatura yazabilir misiniz?\"}, {\"original\": \"¿Puedo dejar aquí mi equipaje?\", \"translated\": \"Bagajlarımı burada bırakabilir miyim?\"}]', 2, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en el aeropuerto?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el aeropuerto, junto con sus traducciones al turco:\"]', '[\"Registro\", \"Embarque\", \"Facturación de equipaje\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como el registro de embarque, la recogida de equipaje o el servicio de alquiler de coches? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Dónde está el mostrador de facturación?\", \"translated\": \"Giriş masası nerede?\"}, {\"original\": \"Me gustaría un asiento junto a la ventana, por favor.\", \"translated\": \"Lütfen pencere kenarında bir koltuk istiyorum.\"}, {\"original\": \"¿Este vuelo tiene retraso?\", \"translated\": \"Bu uçuş gecikmiş mi?\"}, {\"original\": \"Necesito facturar este equipaje.\", \"translated\": \"Bu bagajı kayıt ettirmem gerekiyor.\"}, {\"original\": \"¿Dónde está la puerta de embarque?\", \"translated\": \"İniş kapısı nerede?\"}, {\"original\": \"El avión está a punto de despegar.\", \"translated\": \"Uçak kalkmak üzere.\"}, {\"original\": \"¿Tengo que sacar mi ordenador portátil y mi power bank?\", \"translated\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\"}, {\"original\": \"¿Dónde está la tienda libre de impuestos?\", \"translated\": \"Vergisiz alışveriş mağazası nerede?\"}, {\"original\": \"No encuentro mi maleta.\", \"translated\": \"Bavulumu bulamıyorum.\"}, {\"original\": \"¿Ofrecen servicio de sillas de ruedas?\", \"translated\": \"Tekerlekli sandalye hizmetiniz var mı?\"}]', 3, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en el transporte público?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el transporte público, junto con sus traducciones al turco:\"]', '[\"Tomar autobús o metro\", \"Comprar entradas\", \"Transbordar\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como preguntar por la parada de autobús, el precio del billete o dónde bajarse? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Este autobús va a la terminal?\", \"translated\": \"Bu otobüs terminala gidiyor mu?\"}, {\"original\": \"¿Cuál es la próxima parada?\", \"translated\": \"Bir sonraki durak neresi?\"}, {\"original\": \"¿Dónde puedo comprar un billete?\", \"translated\": \"Bilet nereden alabilirim?\"}, {\"original\": \"Un billete para XX, por favor.\", \"translated\": \"XX\'e bir bilet, lütfen.\"}, {\"original\": \"¿Tengo que hacer transbordo?\", \"translated\": \"Aktarma yapmam gerekiyor mu?\"}, {\"original\": \"¿Cuánto falta para el próximo tren de metro?\", \"translated\": \"Bir sonraki metro trenine ne kadar kaldı?\"}, {\"original\": \"Disculpe, permítame pasar, por favor.\", \"translated\": \"Üzgünüm, geçebilir miyim?\"}, {\"original\": \"¿Esta plaza está ocupada?\", \"translated\": \"Bu koltuk dolu mu?\"}, {\"original\": \"Disculpe, ¿dónde puedo transbordar a la línea 2 para llegar a XX?\", \"translated\": \"Üzgünüm, XX\'e gitmek için 2. Hat\'a nerede aktarım yapabilirim?\"}, {\"original\": \"¿Cómo llego a XX?\", \"translated\": \"XX\'e nasıl giderim?\"}]', 4, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en atracciones turísticas?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con atracciones turísticas, junto con sus traducciones al turco:\"]', '[\"Visitar lugares de interés\", \"Tomar fotos\", \"Comprar entradas\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como preguntar sobre el precio de las entradas, encontrar un estacionamiento o solicitar un servicio de guía turístico? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"¿Hay entradas para estudiantes disponibles?\", \"translated\": \"Öğrenci biletleri mevcut mu?\"}, {\"original\": \"¿A qué hora abre la atracción?\", \"translated\": \"Bu yer saat kaçta açılıyor?\"}, {\"original\": \"¿Qué cosas divertidas se pueden hacer aquí?\", \"translated\": \"Burada yapılacak eğlenceli şeyler neler?\"}, {\"original\": \"¿Podría hacernos una foto?\", \"translated\": \"Bizi birlikte çeker misiniz?\"}, {\"original\": \"¿Dónde está el autobús turístico?\", \"translated\": \"Sightseeing otobüsü nerede?\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"¿Cuál es el mejor lugar para observar?\", \"translated\": \"En iyi manzara noktası nerede?\"}, {\"original\": \"El paisaje aquí es hermoso.\", \"translated\": \"Buradaki manzara çok güzel.\"}, {\"original\": \"¿Hay visitas guiadas disponibles?\", \"translated\": \"Rehberli tur mevcut mu?\"}]', 5, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en un taxi o servicio de taxis?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con taxis o servicios de taxis, junto con sus traducciones al turco:\"]', '[\"Tomar un taxi\", \"Indicar el destino\", \"Pago\"]', 'es', '[\"Por ahora, ¿qué es lo que más desea hacer ahora? Por ejemplo: preguntar por el destino, el precio o solicitar una factura. No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Dónde puedo conseguir un taxi?\", \"translated\": \"Bir taksi nerede bulabilirim?\"}, {\"original\": \"Por favor, lléveme a esta dirección.\", \"translated\": \"Lütfen beni bu adrese götürür müsünüz?\"}, {\"original\": \"¿Cuánto costará aproximadamente?\", \"translated\": \"Yaklaşık olarak ne kadar tutar?\"}, {\"original\": \"¿Podría usar el taxímetro, por favor?\", \"translated\": \"Lütfen taksimetre kullanır mısınız?\"}, {\"original\": \"Por favor, conduzca un poco más rápido, tengo prisa.\", \"translated\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\"}, {\"original\": \"Por favor, pare aquí.\", \"translated\": \"Lütfen burada durur musunuz?\"}, {\"original\": \"¿Acepta tarjetas o pagos móviles?\", \"translated\": \"Kart veya mobil ödeme kabul ediyor musunuz?\"}, {\"original\": \"¿Podría darme un recibo, por favor?\", \"translated\": \"Lütfen bir fiş verebilir misiniz?\"}, {\"original\": \"Gracias, conductor.\", \"translated\": \"Teşekkür ederim, şoför bey.\"}, {\"original\": \"¿Cuánto falta todavía?\", \"translated\": \"Kaç dakika daha var?\"}]', 6, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en una farmacia?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con la farmacia, junto con sus traducciones al turco:\"]', '[\"Compra de Medicamentos\", \"Consulta\", \"Pago\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir instrucciones sobre cómo tomar un medicamento, frases relacionadas con el uso del seguro médico o la duración del tratamiento? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Tiene medicamento para el resfriado?\", \"translated\": \"Soğuk algınlığı ilacı var mı?\"}, {\"original\": \"¿Cómo debo tomar este medicamento?\", \"translated\": \"Bu ilacı nasıl kullanmalıyım?\"}, {\"original\": \"¿Tiene algún analgésico?\", \"translated\": \"Ağrı kesici ilaçlarınız var mı?\"}, {\"original\": \"¿Hay un folleto con instrucciones?\", \"translated\": \"Kullanım kılavuzu var mı?\"}, {\"original\": \"¿Este medicamento tiene efectos secundarios?\", \"translated\": \"Bu ilacın yan etkileri var mı?\"}, {\"original\": \"¿Puedo usar mi tarjeta de seguro médico?\", \"translated\": \"Tıbbi sigorta kartımı kullanabilir miyim?\"}, {\"original\": \"¿Podría darme una caja de tiritas, por favor?\", \"translated\": \"Lütfen bir kutu yara bandı verebilir misiniz?\"}, {\"original\": \"¿Tiene algún antipirético?\", \"translated\": \"Ateş düşürücü ilaçlarınız var mı?\"}, {\"original\": \"Tengo una pequeña herida superficial. ¿Tiene antiséptico y tiritas?\", \"translated\": \"Hafif bir çizik aldım. Antiseptik ve yara bandı var mı?\"}, {\"original\": \"¿A qué hora cierran?\", \"translated\": \"Kaçta kapanıyorsunuz?\"}]', 7, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en los servicios de emergencia?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con los servicios de emergencia, junto con sus traducciones al turco:\"]', '[\"Llamar a la policía\", \"Primeros auxilios\", \"Pedir ayuda\"]', 'es', '[\"Por ahora, ¿tiene alguna situación de emergencia específica en mente, como incendio, lesión y necesidad de ayuda, llamada de emergencia? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"Por favor, ayúdeme a llamar una ambulancia.\", \"translated\": \"Lütfen bana bir ambulans çağırmama yardımcı olun.\"}, {\"original\": \"¿Dónde está el hospital?\", \"translated\": \"Hastane nerede?\"}, {\"original\": \"Alguien resultó herido.\", \"translated\": \"Birisi yaralandı.\"}, {\"original\": \"Por favor, ayúdeme.\", \"translated\": \"Lütfen bana yardımcı olun.\"}, {\"original\": \"¿Dónde está la comisaría?\", \"translated\": \"Polis karakolu nerede?\"}, {\"original\": \"He perdido mis pertenencias.\", \"translated\": \"Eşyalarımı kaybettim.\"}, {\"original\": \"¿Cuál es el número de los bomberos?\", \"translated\": \"İtfaiye numarası nedir?\"}, {\"original\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría más cercana?\", \"translated\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\"}, {\"original\": \"¿Hay una salida de emergencia?\", \"translated\": \"Acil çıkış var mı?\"}, {\"original\": \"Alguien ha perdido el conocimiento.\", \"translated\": \"Birisi bayıldı.\"}]', 8, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en la playa o junto a la piscina?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con la playa o la piscina, junto con sus traducciones al turco:\"]', '[\"Nadar\", \"Tomar el sol\", \"Practicar deportes playeros\"]', 'es', '[\"Por ahora, ¿podría indicarme el contexto del evento o festival local al que asistirá, como un festival cultural, un festival gastronómico o un festival musical? Por favor, proporcione ese contexto.\", \"Indique las actividades a las que asistirá.\"]', '[\"¿Tiene alguna situación específica en mente? No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[{\"original\": \"¡Mira! Las olas allí son realmente grandes.\", \"translated\": \"Bakın! Oradaki dalgalar gerçekten büyük.\"}, {\"original\": \"Recuerda aplicar protector solar; aquí los rayos UV son muy intensos.\", \"translated\": \"Güneş koruyucu sürmeyi unutmayın, buradaki UV ışınları çok güçlü.\"}, {\"original\": \"La arena de esta playa es tan fina que parece pisar algodón.\", \"translated\": \"Bu plajdaki kum çok ince, pamuk üzerinde yürüyormuş gibi hissediliyor.\"}, {\"original\": \"¿Qué tal jugar al voleibol en la playa?\", \"translated\": \"Plajda voleybol oynamak nasıl olur?\"}, {\"original\": \"Los veleros a lo lejos se ven hermosos.\", \"translated\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\"}, {\"original\": \"El agua aquí es tan transparente que incluso puedes ver los peces.\", \"translated\": \"Buradaki su çok berrak, balıkları bile görebiliyorsunuz.\"}, {\"original\": \"Vamos a buscar conchas marinas.\", \"translated\": \"Hadi biraz deniz kabuğu arayalım.\"}, {\"original\": \"Pasear por la playa al atardecer debe ser muy romántico.\", \"translated\": \"Gün batımında plajda yürüyüş yapmak kesinlikle çok romantik olmalı.\"}, {\"original\": \"He oído que los mariscos aquí son muy frescos; vayamos a probarlos.\", \"translated\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\"}, {\"original\": \"La marea está subiendo; volvamos hacia la orilla.\", \"translated\": \"Deniz yükseliyor, kıyıya doğru gidelim.\"}]', 9, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en eventos y festivales locales?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con eventos y festivales locales, junto con sus traducciones al turco:\"]', '[\"Asistir a eventos\", \"Celebrar festivales\", \"Aprender sobre la cultura\"]', 'es', '[\"Por ahora, ¿podría indicarme el contexto del evento o festival local al que asistirá, por ejemplo, Halloween, un concierto, una fiesta entre amigos o algo más? Por favor, proporcione ese contexto.\", \"Describa, por favor, las actividades que tiene en mente.\"]', '[\"¿Tiene alguna situación específica en mente? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', '[{\"original\": \"¿Hay algún evento hoy?\", \"translated\": \"Bugün herhangi bir etkinlik var mı?\"}, {\"original\": \"¿Hay algo especial en este festival?\", \"translated\": \"Bu festivalle ilgili özel bir şey var mı?\"}, {\"original\": \"¿Dónde se celebra la festividad?\", \"translated\": \"Kutlama nerede yapılacak?\"}, {\"original\": \"¿Cómo puedo comprar entradas?\", \"translated\": \"Biletleri nasıl alabilirim?\"}, {\"original\": \"¿A qué hora empieza la actuación?\", \"translated\": \"Gösteri saat kaçta başlıyor?\"}, {\"original\": \"¿Qué comida tradicional hay?\", \"translated\": \"Hangi geleneksel yiyecekler var?\"}, {\"original\": \"Aquí es realmente animado.\", \"translated\": \"Burada gerçekten hareketli bir ortam var.\"}, {\"original\": \"¿Hay alguna actividad popular?\", \"translated\": \"Halk oyunu gibi etkinlikler var mı?\"}, {\"original\": \"¡Felices fiestas!\", \"translated\": \"Mutlu tatiller!\"}, {\"original\": \"¿A qué hora termina el evento?\", \"translated\": \"Etkinlik saat kaçta bitiyor?\"}]', 10, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un museo o galería de arte?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con museos o galerías de arte, junto con sus traducciones al turco:\"]', '[\"Visita\", \"Visita guiada\", \"Compra de entradas\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir un manual de introducción, frases relacionadas con una ruta guiada o frases para comentar una exposición? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Cuál es la tarifa de entrada?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"¿Tienen guías de audio?\", \"translated\": \"Sesli rehberleriniz var mı?\"}, {\"original\": \"¿Quién creó esta obra de arte?\", \"translated\": \"Bu eseri kim yaratmış?\"}, {\"original\": \"¿Dónde se encuentra la pieza más valiosa del museo?\", \"translated\": \"Müzede en değerli eser nerede?\"}, {\"original\": \"¿Está permitida la fotografía?\", \"translated\": \"Fotoğraf çekmeye izin veriliyor mu?\"}, {\"original\": \"¿Hay alguna exposición especial aquí?\", \"translated\": \"Burada özel sergiler var mı?\"}, {\"original\": \"¿Cuánto tiempo dura la visita?\", \"translated\": \"Ziyaret kaç dakika sürüyor?\"}, {\"original\": \"¿Podría darnos una introducción?\", \"translated\": \"Bize bir tanıtım yapar mısınız?\"}, {\"original\": \"Estas obras son verdaderamente exquisitas.\", \"translated\": \"Bu eserler gerçekten muhteşem.\"}, {\"original\": \"¿Dónde está la tienda de souvenirs?\", \"translated\": \"Hediyelik eşya dükkanı nerede?\"}]', 11, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en cafeterías?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con cafeterías, junto con sus traducciones al turco:\"]', '[\"Pedir café\", \"Descansar\", \"Socializar\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir el menú, bebidas frías o calientes, otros productos? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"Tomaré un latte, por favor.\", \"translated\": \"Lütfen bir latte getirir misiniz?\"}, {\"original\": \"¿Tienen conexión Wi-Fi?\", \"translated\": \"Wi-Fi var mı?\"}, {\"original\": \"¿Podría ver el menú, por favor?\", \"translated\": \"Menüyü görebilir miyim, lütfen?\"}, {\"original\": \"¿Se permiten recargas?\", \"translated\": \"İkinci dolum yapılabilir mi?\"}, {\"original\": \"¿Ya está listo mi café?\", \"translated\": \"Kahvaltım hazır mı?\"}, {\"original\": \"¿Cuánto tiempo puedo quedarme aquí?\", \"translated\": \"Burada ne kadar süre oturabilirim?\"}, {\"original\": \"¿Podría tomarnos una foto?\", \"translated\": \"Bizi birlikte çektikten sonra fotoğraf çekebilir misiniz?\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"La cuenta, por favor. Gracias.\", \"translated\": \"Hesap, lütfen. Teşekkür ederim.\"}, {\"original\": \"Sabe realmente bien.\", \"translated\": \"Gerçekten çok lezzetli.\"}]', 12, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в ресторане?\", \"Отлично! Вот 10 распространённых фраз, связанных с рестораном, а также их переводы на китайский язык:\"]', '[\"Питание\", \"Заказ\", \"Оформление заказа\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например заказ напитков, жалоба или вопрос об ингредиентах? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Извините, сколько ещё ждать нашу еду?\", \"translated\": \"打扰一下，我们的菜还要等多久？\"}, {\"original\": \"Столик на двоих, пожалуйста.\", \"translated\": \"请给我们安排一张两人桌。\"}, {\"original\": \"Можно посмотреть меню, пожалуйста?\", \"translated\": \"请问可以看一下菜单吗？\"}, {\"original\": \"У вас есть фирменные блюда, которые вы могли бы порекомендовать?\", \"translated\": \"你们有什么招牌菜可以推荐吗？\"}, {\"original\": \"Я хочу заказать это и это.\", \"translated\": \"我要点这个和这个。\"}, {\"original\": \"Стакан воды, пожалуйста. Спасибо.\", \"translated\": \"请给我一杯水，谢谢。\"}, {\"original\": \"Счёт, пожалуйста.\", \"translated\": \"请结账。\"}, {\"original\": \"Можно оплатить кредитной картой?\", \"translated\": \"我可以刷信用卡付款吗？\"}, {\"original\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\", \"translated\": \"请问可以帮我把这份打包带走吗？\"}, {\"original\": \"Еда была восхитительной, спасибо.\", \"translated\": \"饭菜非常美味，谢谢。\"}]', 1, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в отеле?\", \"Отлично! Вот 10 распространённых фраз, связанных с отелем, а также их переводы на китайский язык:\"]', '[\"Регистрация заезда\", \"Регистрация выезда\", \"Обслуживание в номере\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например, расположение номера, другие услуги отеля или выезд из отеля? Свободно задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\", \"translated\": \"你好，我已预订房间，这是我的护照。\"}, {\"original\": \"У вас есть свободные номера?\", \"translated\": \"请问还有空房吗？\"}, {\"original\": \"Извините, в отеле есть тренажёрный зал или прачечная?\", \"translated\": \"打扰一下，酒店有健身房或洗衣房吗？\"}, {\"original\": \"Во сколько начинается завтрак?\", \"translated\": \"早餐几点开始？\"}, {\"original\": \"Можно мне ключ от номера, пожалуйста?\", \"translated\": \"请给我一把房卡，谢谢。\"}, {\"original\": \"Не могли бы вы помочь мне отнести багаж в номер?\", \"translated\": \"您能帮我把行李送到房间吗？\"}, {\"original\": \"Как вызвать службу обслуживания номеров?\", \"translated\": \"我该怎么呼叫客房服务？\"}, {\"original\": \"До какого времени необходимо освободить номер?\", \"translated\": \"退房时间是几点？\"}, {\"original\": \"Не могли бы вы выписать мне квитанцию/счёт?\", \"translated\": \"请您给我开一张收据/发票。\"}, {\"original\": \"Можно оставить здесь мой багаж?\", \"translated\": \"我可以把行李寄存在这里吗？\"}]', 2, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в аэропорту?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с аэропортом, а также их китайские переводы:\"]', '[\"Регистрация на рейс\", \"Посадка на борт\", \"Сдача багажа\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например регистрация на рейс, получение багажа или аренда автомобиля? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Где стойка регистрации?\", \"translated\": \"值机柜台在哪里？\"}, {\"original\": \"Я бы хотел место у окна, пожалуйста.\", \"translated\": \"我想要一个靠窗的座位，谢谢。\"}, {\"original\": \"Этот рейс задерживается?\", \"translated\": \"这趟航班延误了吗？\"}, {\"original\": \"Мне нужно зарегистрировать этот багаж.\", \"translated\": \"我需要托运行李。\"}, {\"original\": \"Где выход на посадку?\", \"translated\": \"登机口在哪里？\"}, {\"original\": \"Самолёт вот-вот взлетит.\", \"translated\": \"飞机即将起飞。\"}, {\"original\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\", \"translated\": \"我需要把笔记本电脑和充电宝拿出来吗？\"}, {\"original\": \"Где магазин беспошлинной торговли?\", \"translated\": \"免税店在哪里？\"}, {\"original\": \"Я не могу найти свой чемодан.\", \"translated\": \"我找不到我的行李箱了。\"}, {\"original\": \"Предоставляется ли услуга инвалидных колясок?\", \"translated\": \"你们提供轮椅服务吗？\"}]', 3, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в общественном транспорте?\", \"Отлично! Вот 10 распространённых фраз, связанных с общественным транспортом, а также их китайские переводы:\"]', '[\"Поездка на автобусе/метро\", \"Покупка билетов\", \"Пересадка\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, спросить о месте остановки автобуса, цене билета или выходе из транспорта? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Этот автобус идёт до автовокзала?\", \"translated\": \"这趟公交车去终点站吗？\"}, {\"original\": \"Какая следующая остановка?\", \"translated\": \"下一站是哪里？\"}, {\"original\": \"Где я могу купить билет?\", \"translated\": \"我在哪里可以买票？\"}, {\"original\": \"Один билет до XX, пожалуйста.\", \"translated\": \"请给我一张去XX的车票。\"}, {\"original\": \"Нужно ли мне пересаживаться?\", \"translated\": \"我需要换乘吗？\"}, {\"original\": \"Через сколько прибудет следующий поезд метро?\", \"translated\": \"下一班地铁列车还要等多久？\"}, {\"original\": \"Извините, пропустите меня, пожалуйста.\", \"translated\": \"不好意思，请让我过去。\"}, {\"original\": \"Это место занято?\", \"translated\": \"这个座位有人吗？\"}, {\"original\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\", \"translated\": \"不好意思，请问我在哪里换乘二号线去XX？\"}, {\"original\": \"Как мне добраться до XX?\", \"translated\": \"我怎么去XX？\"}]', 4, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в туристических местах?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с туристическими достопримечательностями, а также их китайские переводы:\"]', '[\"Осмотр достопримечательностей\", \"Фотографирование\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например, вопрос о цене билетов, поиск парковочного места или услуг гида? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"Есть ли льготные билеты для студентов?\", \"translated\": \"有学生票吗？\"}, {\"original\": \"Во сколько открывается достопримечательность?\", \"translated\": \"景点几点开放？\"}, {\"original\": \"Чем здесь можно интересно заняться?\", \"translated\": \"这里有哪些好玩的项目？\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"您能帮我们拍张照片吗？\"}, {\"original\": \"Где автобус для осмотра достопримечательностей?\", \"translated\": \"观光巴士在哪里？\"}, {\"original\": \"Где находится туалет?\", \"translated\": \"洗手间在哪里？\"}, {\"original\": \"Где лучшее место для просмотра?\", \"translated\": \"最佳观景点在哪里？\"}, {\"original\": \"Здесь прекрасные виды.\", \"translated\": \"这里的风景很美。\"}, {\"original\": \"Доступна ли экскурсия с гидом?\", \"translated\": \"提供导游讲解服务吗？\"}]', 5, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать при заказе такси или пользовании услугами такси?\", \"Отлично! Вот 10 распространённых фраз, связанных с такси или услугами такси, а также их китайские переводы:\"]', '[\"Вызов такси\", \"Указание места назначения\", \"Оплата\"]', 'ru', '[\"Пока что: что вы сейчас больше всего хотите сделать — уточнить пункт назначения, узнать стоимость или запросить чек? Свободно задавайте любые вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас возникла в мыслях.\"]', NULL, '[{\"original\": \"Где я могу взять такси?\", \"translated\": \"我在哪里可以打到出租车？\"}, {\"original\": \"Пожалуйста, отвезите меня по этому адресу.\", \"translated\": \"请送我去这个地址。\"}, {\"original\": \"Примерно сколько это будет стоить?\", \"translated\": \"大概需要多少钱？\"}, {\"original\": \"Не могли бы вы, пожалуйста, включить счётчик?\", \"translated\": \"请您打表计费，好吗？\"}, {\"original\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\", \"translated\": \"请开快一点，我赶时间。\"}, {\"original\": \"Остановитесь, пожалуйста, здесь.\", \"translated\": \"请在这里停车。\"}, {\"original\": \"Принимаете ли вы оплату картой или через мобильные платежи?\", \"translated\": \"您接受银行卡或手机支付吗？\"}, {\"original\": \"Можно мне, пожалуйста, чек?\", \"translated\": \"可以给我一张发票吗？\"}, {\"original\": \"Спасибо, водитель.\", \"translated\": \"谢谢，司机师傅。\"}, {\"original\": \"Как далеко ещё?\", \"translated\": \"还有多远？\"}]', 6, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в аптеке?\", \"Превосходно! Вот 10 распространённых фраз, связанных с аптекой, а также их китайские переводы:\"]', '[\"Покупка лекарств\", \"Консультация\", \"Оплата\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, запрос инструкций по приёму лекарств, фразы, связанные с использованием страхования, продолжительностью приёма лекарств? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"У вас есть лекарство от простуды?\", \"translated\": \"你们有治感冒的药吗？\"}, {\"original\": \"Как мне принимать это лекарство?\", \"translated\": \"这种药我该怎么服用？\"}, {\"original\": \"У вас есть обезболивающие?\", \"translated\": \"你们有止痛药吗？\"}, {\"original\": \"Есть ли инструкция по применению?\", \"translated\": \"这个药有说明书吗？\"}, {\"original\": \"Это лекарство имеет какие-либо побочные эффекты?\", \"translated\": \"这种药有什么副作用吗？\"}, {\"original\": \"Могу ли я воспользоваться своей медицинской страховой картой?\", \"translated\": \"我能用我的医保卡吗？\"}, {\"original\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\", \"translated\": \"请给我一盒创可贴，谢谢。\"}, {\"original\": \"У вас есть жаропонижающие?\", \"translated\": \"你们有退烧药吗？\"}, {\"original\": \"Я немного поранился. У вас есть антисептик и пластыри?\", \"translated\": \"我有点擦伤，你们有消毒药水和创可贴吗？\"}, {\"original\": \"Во сколько вы закрываетесь?\", \"translated\": \"你们几点关门？\"}]', 7, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в службах экстренной помощи?\", \"Отлично! Вот 10 распространённых фраз, связанных со службами экстренной помощи, а также их переводы на китайский язык:\"]', '[\"Вызов полиции\", \"Первая помощь\", \"Вызов на помощь\"]', 'ru', '[\"Пока что у вас есть в виду какая-то конкретная чрезвычайная ситуация, например пожар, травма и необходимость помощи, экстренный вызов — смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Пожалуйста, помогите мне вызвать скорую помощь.\", \"translated\": \"请帮我叫一辆救护车。\"}, {\"original\": \"Где находится больница?\", \"translated\": \"医院在哪儿？\"}, {\"original\": \"Кто-то получил травму.\", \"translated\": \"有人受伤了。\"}, {\"original\": \"Пожалуйста, помогите мне.\", \"translated\": \"请帮帮我。\"}, {\"original\": \"Где находится полицейский участок?\", \"translated\": \"警察局在哪儿？\"}, {\"original\": \"Я потерял свои вещи.\", \"translated\": \"我的物品丢失了。\"}, {\"original\": \"Какой номер пожарной службы?\", \"translated\": \"消防部门的电话号码是多少？\"}, {\"original\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\", \"translated\": \"我的护照丢了。您知道最近的警察局在哪儿吗？\"}, {\"original\": \"Здесь есть аварийный выход?\", \"translated\": \"这里有安全出口吗？\"}, {\"original\": \"Кто-то потерял сознание.\", \"translated\": \"有人晕倒了。\"}]', 8, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на пляже или у бассейна?\", \"Превосходно! Вот 10 распространённых фраз, связанных с пляжем или бассейном, а также их китайские переводы:\"]', '[\"Плавание\", \"Загар\", \"Пляжные виды спорта\"]', 'ru', '[\"Пока что, не могли бы вы сообщить мне контекст местного мероприятия или фестиваля, в котором вы участвуете, например, культурного фестиваля, гастрономического фестиваля или музыкального фестиваля? Пожалуйста, укажите контекст.\", \"Пожалуйста, опишите мероприятия, в которых вы участвуете.\"]', '[\"У вас есть конкретная ситуация в уме? Свободно задавайте вопрос.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', '[{\"original\": \"Смотрите! Волны там действительно очень большие.\", \"translated\": \"看！那边的海浪真大。\"}, {\"original\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\", \"translated\": \"记得涂防晒霜，这里的紫外线很强。\"}, {\"original\": \"Песок на этом пляже такой мелкий, что кажется, будто вы ступаете по вате.\", \"translated\": \"这片海滩的沙子非常细腻，踩上去像踩在棉花上。\"}, {\"original\": \"Как насчёт игры в волейбол на пляже?\", \"translated\": \"去海滩打排球怎么样？\"}, {\"original\": \"Парусники вдалеке выглядят очень красиво.\", \"translated\": \"远处的帆船看起来真美。\"}, {\"original\": \"Вода здесь такая прозрачная, что даже видно рыб.\", \"translated\": \"这里的海水如此清澈，连鱼都能看见。\"}, {\"original\": \"Давайте пойдём поискать ракушки.\", \"translated\": \"我们去找些贝壳吧。\"}, {\"original\": \"Прогулка по пляжу на закате, наверное, очень романтична.\", \"translated\": \"日落时分在海滩散步一定很浪漫。\"}, {\"original\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\", \"translated\": \"听说这里的海鲜非常新鲜，我们去尝尝吧。\"}, {\"original\": \"Начинается прилив, давайте направимся к берегу.\", \"translated\": \"涨潮了，我们往岸边走吧。\"}]', 9, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать на местных мероприятиях и праздниках?\", \"Превосходно! Вот 10 распространённых фраз, связанных с местными мероприятиями и праздниками, а также их китайские переводы:\"]', '[\"Посещение мероприятий\", \"Празднование фестивалей\", \"Изучение культуры\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного мероприятия или праздника, на который вы собираетесь пойти: Хэллоуин, концерт, вечеринка у друзей или что-то ещё? Пожалуйста, укажите контекст.\", \"Опишите, пожалуйста, те мероприятия, которые приходят вам на ум.\"]', '[\"У вас есть конкретная ситуация на уме? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ту ситуацию, которая приходит вам на ум.\"]', '[{\"original\": \"Есть ли сегодня какие-нибудь мероприятия?\", \"translated\": \"今天有什么活动吗？\"}, {\"original\": \"В этом празднике есть что-нибудь особенное?\", \"translated\": \"这个节日有什么特别之处吗？\"}, {\"original\": \"Где проходит празднование?\", \"translated\": \"庆祝活动在哪里举行？\"}, {\"original\": \"Как я могу купить билеты?\", \"translated\": \"我该如何购买门票？\"}, {\"original\": \"Во сколько начинается представление?\", \"translated\": \"演出什么时候开始？\"}, {\"original\": \"Какая традиционная еда здесь есть?\", \"translated\": \"有哪些传统食物？\"}, {\"original\": \"Здесь действительно очень оживлённо.\", \"translated\": \"这里真热闹。\"}, {\"original\": \"Есть ли какие-нибудь народные мероприятия?\", \"translated\": \"有民俗活动吗？\"}, {\"original\": \"Счастливых праздников!\", \"translated\": \"节日快乐！\"}, {\"original\": \"Во сколько заканчивается мероприятие?\", \"translated\": \"活动什么时候结束？\"}]', 10, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в музее или художественной галерее?\", \"Отлично! Вот 10 распространённых фраз, связанных с музеем или художественной галереей, а также их переводы на китайский язык:\"]', '[\"Посещение\", \"Экскурсия\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, запрос справочного буклета, фразы, связанные с маршрутом посетителя, фразы, связанные с комментированием экспонатов? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"У вас есть аудиогиды?\", \"translated\": \"你们提供语音导览吗？\"}, {\"original\": \"Кто создал это произведение искусства?\", \"translated\": \"这件艺术品是谁创作的？\"}, {\"original\": \"Где находится самая ценная экспонат музея?\", \"translated\": \"博物馆最珍贵的展品在哪里？\"}, {\"original\": \"Разрешена ли фотосъёмка?\", \"translated\": \"允许拍照吗？\"}, {\"original\": \"Здесь проходят какие-нибудь специальные выставки?\", \"translated\": \"这里有没有特别展览？\"}, {\"original\": \"Сколько времени занимает посещение?\", \"translated\": \"参观需要多长时间？\"}, {\"original\": \"Не могли бы вы представить нам краткое введение?\", \"translated\": \"您能为我们做个介绍吗？\"}, {\"original\": \"Эти произведения действительно изысканны.\", \"translated\": \"这些作品真是精美绝伦。\"}, {\"original\": \"Где находится магазин сувениров?\", \"translated\": \"纪念品商店在哪儿？\"}]', 11, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в кафе?\", \"Превосходно! Вот 10 распространённых фраз, связанных с кафе, а также их переводы на китайский язык:\"]', '[\"Заказ кофе\", \"Отдых\", \"Общение\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация в уме, например, заказ меню, прохладительные или горячие напитки, другие товары? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Я возьму латте, пожалуйста.\", \"translated\": \"请给我一杯拿铁。\"}, {\"original\": \"У вас есть Wi-Fi?\", \"translated\": \"你们有无线网络吗？\"}, {\"original\": \"Можно мне посмотреть меню, пожалуйста?\", \"translated\": \"请给我看一下菜单，谢谢。\"}, {\"original\": \"Разрешено ли добавлять кофе бесплатно?\", \"translated\": \"可以续杯吗？\"}, {\"original\": \"Мой кофе уже готов?\", \"translated\": \"我的咖啡好了吗？\"}, {\"original\": \"Сколько времени я могу здесь посидеть?\", \"translated\": \"我可以在这里坐多久？\"}, {\"original\": \"Не могли бы вы сделать нам фотографию?\", \"translated\": \"您能帮我们拍张照片吗？\"}, {\"original\": \"Где туалет?\", \"translated\": \"洗手间在哪里？\"}, {\"original\": \"Счёт, пожалуйста. Спасибо.\", \"translated\": \"请结账，谢谢。\"}, {\"original\": \"Очень вкусно.\", \"translated\": \"味道 really 好。\"}]', 12, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в ресторане?\", \"Отлично! Вот 10 распространённых фраз, связанных с рестораном, а также их переводы на турецкий язык:\"]', '[\"Питание\", \"Заказ\", \"Оформление заказа\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация на уме, например, заказ напитков, жалоба или вопрос об ингредиентах? Смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Извините, сколько ещё ждать нашу еду?\", \"translated\": \"Affedersiniz, yemeğimiz kaç dakika daha sürecektir?\"}, {\"original\": \"Столик на двоих, пожалуйста.\", \"translated\": \"Lütfen iki kişilik bir masa.\"}, {\"original\": \"Можно посмотреть меню, пожалуйста?\", \"translated\": \"Lütfen menüyü görebilir miyiz?\"}, {\"original\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\", \"translated\": \"Önerdiğiniz özel yemekleriniz var mı?\"}, {\"original\": \"Я хочу заказать это и это.\", \"translated\": \"Bunu ve bunu sipariş etmek istiyorum.\"}, {\"original\": \"Стакан воды, пожалуйста. Спасибо.\", \"translated\": \"Lütfen bir bardak su. Teşekkürler.\"}, {\"original\": \"Счёт, пожалуйста.\", \"translated\": \"Hesabı lütfen.\"}, {\"original\": \"Можно оплатить кредитной картой?\", \"translated\": \"Kredi kartıyla ödeyebilir miyim?\"}, {\"original\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\", \"translated\": \"Lütfen bunu götürmek için paketleyebilir misiniz?\"}, {\"original\": \"Еда была восхитительной, спасибо.\", \"translated\": \"Yiyecek çok lezzetliydi, teşekkür ederiz.\"}]', 1, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в отеле?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с отелем, а также их переводы на турецкий язык:\"]', '[\"Регистрация заезда\", \"Регистрация выезда\", \"Обслуживание в номере\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например, расположение номера, другие услуги отеля или выезд из отеля — не стесняйтесь задавать вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\", \"translated\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\"}, {\"original\": \"У вас есть свободные номера?\", \"translated\": \"Boş odanız var mı?\"}, {\"original\": \"Извините, в отеле есть тренажёрный зал или прачечная?\", \"translated\": \"Affedersiniz, otelin bir spor salonu veya çamaşırhane bölümü var mı?\"}, {\"original\": \"Во сколько начинается завтрак?\", \"translated\": \"Kahvaltı saat kaçta başlıyor?\"}, {\"original\": \"Можно мне ключ от номера, пожалуйста?\", \"translated\": \"Lütfen bir oda anahtarı alabilir miyim?\"}, {\"original\": \"Не могли бы вы помочь мне отнести багаж в номер?\", \"translated\": \"Lütfen bana bagajlarımı odaya taşımada yardımcı olur musunuz?\"}, {\"original\": \"Как вызвать службу обслуживания номеров?\", \"translated\": \"Oda servisini nasıl arayabilirim?\"}, {\"original\": \"Во сколько заканчивается регистрация выезда?\", \"translated\": \"Çıkış saati kaçta?\"}, {\"original\": \"Не могли бы вы выписать мне квитанцию/счёт?\", \"translated\": \"Bana bir makbuz/fatura yazabilir misiniz?\"}, {\"original\": \"Можно оставить здесь мой багаж?\", \"translated\": \"Bagajlarımı burada bırakabilir miyim?\"}]', 2, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в аэропорту?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с аэропортом, а также их переводы на турецкий язык:\"]', '[\"Регистрация на рейс\", \"Посадка на борт\", \"Сдача багажа\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например регистрация на рейс, получение багажа или аренда автомобиля? Свободно задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Где стойка регистрации?\", \"translated\": \"Giriş masası nerede?\"}, {\"original\": \"Я бы хотел место у окна, пожалуйста.\", \"translated\": \"Lütfen pencere kenarında bir koltuk istiyorum.\"}, {\"original\": \"Этот рейс задерживается?\", \"translated\": \"Bu uçuş gecikmiş mi?\"}, {\"original\": \"Мне нужно зарегистрировать этот багаж.\", \"translated\": \"Bu bagajı kontrol ettirmem gerekiyor.\"}, {\"original\": \"Где выход на посадку?\", \"translated\": \"İniş kapısı nerede?\"}, {\"original\": \"Самолёт вот-вот взлетит.\", \"translated\": \"Uçak kalkmak üzere.\"}, {\"original\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\", \"translated\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\"}, {\"original\": \"Где магазин беспошлинной торговли?\", \"translated\": \"Vergisiz mağaza nerede?\"}, {\"original\": \"Я не могу найти свой чемодан.\", \"translated\": \"Bavulumu bulamıyorum.\"}, {\"original\": \"Предоставляется ли услуга инвалидных колясок?\", \"translated\": \"Tekerlekli sandalye hizmetiniz var mı?\"}]', 3, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в общественном транспорте?\", \"Превосходно! Вот 10 распространённых фраз, связанных с общественным транспортом, а также их переводы на турецкий язык:\"]', '[\"Поездка на автобусе/метро\", \"Покупка билетов\", \"Пересадка\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например, запрос о месте остановки автобуса, цене билета или выходе из транспорта? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Этот автобус идёт до автовокзала?\", \"translated\": \"Bu otobüs terminala gidiyor mu?\"}, {\"original\": \"Какая следующая остановка?\", \"translated\": \"Bir sonraki durak neresi?\"}, {\"original\": \"Где я могу купить билет?\", \"translated\": \"Bilet nereden alabilirim?\"}, {\"original\": \"Один билет до XX, пожалуйста.\", \"translated\": \"XX\'e bir bilet, lütfen.\"}, {\"original\": \"Нужно ли мне пересаживаться?\", \"translated\": \"Aktarma yapmam gerekiyor mu?\"}, {\"original\": \"Через сколько прибудет следующий поезд метро?\", \"translated\": \"Bir sonraki metro treni ne zaman geliyor?\"}, {\"original\": \"Извините, пропустите меня, пожалуйста.\", \"translated\": \"Affedersiniz, geçebilir miyim?\"}, {\"original\": \"Это место занято?\", \"translated\": \"Bu koltuk dolu mu?\"}, {\"original\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\", \"translated\": \"Affedersiniz, XX’e gitmek için 2. Hat’a nerede aktarma yapabilirim?\"}, {\"original\": \"Как мне добраться до XX?\", \"translated\": \"XX’e nasıl giderim?\"}]', 4, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на туристических объектах?\", \"Отлично! Вот 10 распространённых фраз, связанных с туристическими объектами, а также их переводы на турецкий язык:\"]', '[\"Осмотр достопримечательностей\", \"Фотографирование\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, вопрос о цене билетов, поиск парковочного места или услуг гида? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"Есть ли льготные билеты для студентов?\", \"translated\": \"Öğrenci biletleri mevcut mu?\"}, {\"original\": \"Во сколько открывается достопримечательность?\", \"translated\": \"Bu yer saat kaçta açılıyor?\"}, {\"original\": \"Чем здесь можно интересно заняться?\", \"translated\": \"Burada yapılacak eğlenceli şeyler neler?\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"Bizi birlikte çeker misiniz?\"}, {\"original\": \"Где автобус для осмотра достопримечательностей?\", \"translated\": \"Sightseeing otobüsü nerede?\"}, {\"original\": \"Где находится туалет?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"Где лучшее место для просмотра?\", \"translated\": \"En iyi manzara noktası nerede?\"}, {\"original\": \"Здесь прекрасный вид.\", \"translated\": \"Buradaki manzara çok güzel.\"}, {\"original\": \"Доступна ли экскурсия с гидом?\", \"translated\": \"Rehberli tur mevcut mu?\"}]', 5, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать при заказе такси или пользовании услугами такси?\", \"Отлично! Вот 10 распространённых фраз, связанных с такси или услугами такси, а также их переводы на турецкий язык:\"]', '[\"Вызов такси\", \"Указание места назначения\", \"Оплата\"]', 'ru', '[\"Пока что: что вы сейчас больше всего хотите сделать — уточнить пункт назначения, спросить цену или запросить счёт? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас возникает в воображении.\"]', NULL, '[{\"original\": \"Где я могу взять такси?\", \"translated\": \"Bir taksi nerede bulabilirim?\"}, {\"original\": \"Пожалуйста, отвезите меня по этому адресу.\", \"translated\": \"Lütfen beni bu adrese götürür müsünüz?\"}, {\"original\": \"Примерно сколько это будет стоить?\", \"translated\": \"Yaklaşık olarak ne kadar tutar?\"}, {\"original\": \"Не могли бы вы, пожалуйста, включить счётчик?\", \"translated\": \"Lütfen taksimetre kullanır mısınız?\"}, {\"original\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\", \"translated\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\"}, {\"original\": \"Остановитесь, пожалуйста, здесь.\", \"translated\": \"Lütfen burada durur musunuz?\"}, {\"original\": \"Принимаете ли вы оплату картой или через мобильные платежи?\", \"translated\": \"Kart veya mobil ödeme kabul ediyor musunuz?\"}, {\"original\": \"Можно мне, пожалуйста, чек?\", \"translated\": \"Lütfen bir fiş verebilir misiniz?\"}, {\"original\": \"Спасибо, водитель.\", \"translated\": \"Teşekkür ederim, şoför bey.\"}, {\"original\": \"Сколько ещё осталось ехать?\", \"translated\": \"Kaç dakika daha var?\"}]', 6, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в аптеке?\", \"Отлично! Вот 10 распространённых фраз, связанных с аптекой, а также их переводы на турецкий язык:\"]', '[\"Покупка лекарств\", \"Консультация\", \"Оплата\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация в уме, например, запрос инструкций по приёму лекарств, фразы, связанные с использованием страхования, продолжительностью приёма лекарств — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"У вас есть лекарство от простуды?\", \"translated\": \"Soğuk algınlığı ilacı var mı?\"}, {\"original\": \"Как мне принимать это лекарство?\", \"translated\": \"Bu ilacı nasıl kullanmalıyım?\"}, {\"original\": \"У вас есть обезболивающие?\", \"translated\": \"Ağrı kesici ilaçlarınız var mı?\"}, {\"original\": \"Есть ли инструкция по применению?\", \"translated\": \"Kullanım kılavuzu var mı?\"}, {\"original\": \"Это лекарство имеет какие-либо побочные эффекты?\", \"translated\": \"Bu ilacın yan etkileri var mı?\"}, {\"original\": \"Можно ли воспользоваться моей медицинской страховкой?\", \"translated\": \"Sağlık sigortamı kullanabilir miyim?\"}, {\"original\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\", \"translated\": \"Lütfen bir kutu plastik yara bandı verebilir misiniz?\"}, {\"original\": \"У вас есть жаропонижающие?\", \"translated\": \"Ateş düşürücü ilaçlarınız var mı?\"}, {\"original\": \"Я немного поранился. У вас есть антисептик и пластыри?\", \"translated\": \"Hafif bir çizik aldım. Antiseptik ve plastik yara bandı var mı?\"}, {\"original\": \"Во сколько вы закрываетесь?\", \"translated\": \"Kaçta kapanıyorsunuz?\"}]', 7, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в службах экстренной помощи?\", \"Отлично! Вот 10 распространённых фраз, связанных со службами экстренной помощи, а также их переводы на турецкий язык:\"]', '[\"Вызов полиции\", \"Первая помощь\", \"Вызов на помощь\"]', 'ru', '[\"Пока что: у вас есть конкретная чрезвычайная ситуация в уме, например пожар, травма и необходимость помощи, экстренный вызов — смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Пожалуйста, помогите мне вызвать скорую помощь.\", \"translated\": \"Lütfen bana bir ambulans çağırmama yardımcı olun.\"}, {\"original\": \"Где находится больница?\", \"translated\": \"Hastane nerede?\"}, {\"original\": \"Кто-то получил травму.\", \"translated\": \"Birisi yaralandı.\"}, {\"original\": \"Пожалуйста, помогите мне.\", \"translated\": \"Lütfen bana yardımcı olun.\"}, {\"original\": \"Где находится полицейский участок?\", \"translated\": \"Polis karakolu nerede?\"}, {\"original\": \"Я потерял свои вещи.\", \"translated\": \"Eşyalarımı kaybettim.\"}, {\"original\": \"Какой номер пожарной службы?\", \"translated\": \"İtfaiye numarası nedir?\"}, {\"original\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\", \"translated\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\"}, {\"original\": \"Здесь есть аварийный выход?\", \"translated\": \"Acil çıkış var mı?\"}, {\"original\": \"Кто-то потерял сознание.\", \"translated\": \"Birisi bayıldı.\"}]', 8, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на пляже или у бассейна?\", \"Превосходно! Вот 10 распространённых фраз, связанных с пляжем или бассейном, а также их переводы на турецкий язык:\"]', '[\"Плавание\", \"Загар\", \"Пляжные виды спорта\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного мероприятия или фестиваля, в котором вы участвуете: культурный фестиваль, гастрономический фестиваль или музыкальный фестиваль? Пожалуйста, укажите контекст.\", \"Пожалуйста, опишите мероприятия, в которых вы участвуете.\"]', '[\"У вас есть конкретная ситуация в уме? Смело задавайте вопрос.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', '[{\"original\": \"Смотрите! Волны там действительно очень большие.\", \"translated\": \"Bakın! Oradaki dalgalar gerçekten büyük.\"}, {\"original\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\", \"translated\": \"Güneş koruyucu sürmeyi unutmayın, buradaki UV ışınları çok güçlü.\"}, {\"original\": \"Песок на этом пляже такой мелкий, что идти по нему — всё равно что ступать по хлопку.\", \"translated\": \"Bu plajdaki kum o kadar ince ki pamuk üzerinde yürüyor gibi hissediyorsunuz.\"}, {\"original\": \"Как насчёт игры в волейбол на пляже?\", \"translated\": \"Plajda voleybol oynamak nasıl olur?\"}, {\"original\": \"Парусники вдали выглядят очень красиво.\", \"translated\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\"}, {\"original\": \"Вода здесь такая прозрачная, что даже рыбок можно разглядеть.\", \"translated\": \"Buradaki su o kadar berrak ki balıkları bile görebiliyorsunuz.\"}, {\"original\": \"Давайте пойдём собирать морские ракушки.\", \"translated\": \"Hadi biraz deniz kabuğu arayalım.\"}, {\"original\": \"Прогулка по пляжу на закате, наверное, очень романтична.\", \"translated\": \"Gün batımında plajda yürüyüş yapmak kesinlikle çok romantik olmalı.\"}, {\"original\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\", \"translated\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\"}, {\"original\": \"Начинается прилив, давайте направимся к берегу.\", \"translated\": \"Deniz yükseliyor, kıyıya doğru gidelim.\"}]', 9, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на местных мероприятиях и фестивалях?\", \"Превосходно! Вот 10 распространённых фраз, связанных с местными мероприятиями и фестивалями, а также их переводы на турецкий язык:\"]', '[\"Посещение мероприятий\", \"Празднование фестивалей\", \"Изучение культуры\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного мероприятия или фестиваля, на который вы собираетесь пойти: Хэллоуин, концерт, вечеринка у друзей или что-то ещё? Пожалуйста, укажите контекст.\", \"Опишите, пожалуйста, те виды деятельности, которые у вас возникают в воображении.\"]', '[\"У вас есть какая-нибудь конкретная ситуация в уме? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас возникает в воображении.\"]', '[{\"original\": \"Есть ли сегодня какие-нибудь мероприятия?\", \"translated\": \"Bugün herhangi bir etkinlik var mı?\"}, {\"original\": \"В этом празднике есть что-нибудь особенное?\", \"translated\": \"Bu festivalle ilgili özel bir şey var mı?\"}, {\"original\": \"Где проходит празднование?\", \"translated\": \"Kutlama nerede yapılacak?\"}, {\"original\": \"Как я могу купить билеты?\", \"translated\": \"Biletleri nasıl alabilirim?\"}, {\"original\": \"Во сколько начинается представление?\", \"translated\": \"Gösteri saat kaçta başlıyor?\"}, {\"original\": \"Какая традиционная еда здесь есть?\", \"translated\": \"Hangi geleneksel yiyecekler var?\"}, {\"original\": \"Здесь действительно очень оживлённо.\", \"translated\": \"Burada gerçekten hareketli bir atmosfer var.\"}, {\"original\": \"Есть ли какие-нибудь народные мероприятия?\", \"translated\": \"Halk oyunları gibi etkinlikler var mı?\"}, {\"original\": \"Счастливых праздников!\", \"translated\": \"Mutlu tatiller!\"}, {\"original\": \"Во сколько заканчивается мероприятие?\", \"translated\": \"Etkinlik saat kaçta bitiyor?\"}]', 10, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в музее или художественной галерее?\", \"Превосходно! Вот 10 распространённых фраз, связанных с музеем или художественной галереей, а также их переводы на турецкий язык:\"]', '[\"Посещение\", \"Экскурсия\", \"Покупка билетов\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация на уме, например, просьба о вводном буклете, фразы, связанные с маршрутом посетителя, фразы, связанные с комментариями к экспонатам — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"У вас есть аудиогиды?\", \"translated\": \"Sesli rehberleriniz var mı?\"}, {\"original\": \"Кто создал это произведение искусства?\", \"translated\": \"Bu eseri kim yaratmış?\"}, {\"original\": \"Где находится самая ценная экспонат музея?\", \"translated\": \"Müzenin en değerli eseri nerede?\"}, {\"original\": \"Разрешена ли фотосъёмка?\", \"translated\": \"Fotoğraf çekmeye izin veriliyor mu?\"}, {\"original\": \"Здесь проходят какие-нибудь специальные выставки?\", \"translated\": \"Burada özel sergiler var mı?\"}, {\"original\": \"Сколько времени занимает посещение?\", \"translated\": \"Ziyaret kaç dakika sürüyor?\"}, {\"original\": \"Не могли бы вы представить нам краткое введение?\", \"translated\": \"Bize bir tanıtım yapabilir misiniz?\"}, {\"original\": \"Эти произведения действительно изысканны.\", \"translated\": \"Bu eserler gerçekten çok zarif.\"}, {\"original\": \"Где находится магазин сувениров?\", \"translated\": \"Hediyelik eşya dükkanı nerede?\"}]', 11, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в кафе?\", \"Отлично! Вот 10 распространённых фраз, связанных с кафе, а также их переводы на турецкий язык:\"]', '[\"Заказ кофе\", \"Отдых\", \"Общение\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, заказ меню, прохладительных или горячих напитков, других товаров? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Я возьму латте, пожалуйста.\", \"translated\": \"Lütfen bir latte getirir misiniz?\"}, {\"original\": \"У вас есть Wi-Fi?\", \"translated\": \"Wi-Fi var mı?\"}, {\"original\": \"Можно мне посмотреть меню, пожалуйста?\", \"translated\": \"Menüyü görebilir miyim, lütfen?\"}, {\"original\": \"Разрешено ли добавлять кофе бесплатно?\", \"translated\": \"İkinci dolum yapılabilir mi?\"}, {\"original\": \"Мой кофе уже готов?\", \"translated\": \"Kahvaltım hazır mı?\"}, {\"original\": \"Сколько времени я могу здесь посидеть?\", \"translated\": \"Burada ne kadar süre oturabilirim?\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"Bizi birlikte çektikten sonra fotoğraf çekebilir misiniz?\"}, {\"original\": \"Где туалет?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"Счёт, пожалуйста. Спасибо.\", \"translated\": \"Hesap, lütfen. Teşekkür ederim.\"}, {\"original\": \"Очень вкусно.\", \"translated\": \"Gerçekten çok lezzetli.\"}]', 12, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в ресторане?\", \"Отлично! Вот 10 распространённых фраз, связанных с рестораном, а также их переводы на японский язык:\"]', '[\"Питание\", \"Заказ\", \"Оформление заказа\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация в уме, например заказ напитков, жалоба или вопрос об ингредиентах? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Извините, сколько ещё ждать нашу еду?\", \"translated\": \"すみません、料理はあとどのくらいで来ますか？\"}, {\"original\": \"Столик на двоих, пожалуйста.\", \"translated\": \"二人用のテーブルをお願いします。\"}, {\"original\": \"Можно посмотреть меню, пожалуйста?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\", \"translated\": \"おすすめの自慢料理はありますか？\"}, {\"original\": \"Я хочу заказать это и это.\", \"translated\": \"これを注文したいのですが、あとこれもお願いします。\"}, {\"original\": \"Стакан воды, пожалуйста. Спасибо.\", \"translated\": \"水を一杯お願いします。ありがとうございます。\"}, {\"original\": \"Счёт, пожалуйста.\", \"translated\": \"お会計をお願いします。\"}, {\"original\": \"Можно оплатить кредитной картой?\", \"translated\": \"クレジットカードで支払えますか？\"}, {\"original\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\", \"translated\": \"これを持ち帰り用に包んでいただけますか？\"}, {\"original\": \"Еда была восхитительной, спасибо.\", \"translated\": \"料理がとても美味しかったです。ありがとうございました。\"}]', 1, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в отеле?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с отелем, а также их переводы на японский язык:\"]', '[\"Регистрация заезда\", \"Регистрация выезда\", \"Обслуживание в номере\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация в уме, например, расположение номера, другие услуги отеля или выезд из отеля — смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\", \"translated\": \"こんにちは、予約をしております。こちらが私のパスポートです。\"}, {\"original\": \"У вас есть свободные номера?\", \"translated\": \"空室はありますか？\"}, {\"original\": \"Извините, в отеле есть тренажёрный зал или прачечная?\", \"translated\": \"すみませんが、ホテルにはジムやランドリールームはありますか？\"}, {\"original\": \"Во сколько начинается завтрак?\", \"translated\": \"朝食の開始時間は何時ですか？\"}, {\"original\": \"Можно мне ключ от номера, пожалуйста?\", \"translated\": \"部屋の鍵をいただけますか？\"}, {\"original\": \"Не могли бы вы помочь мне отнести багаж в номер?\", \"translated\": \"荷物を部屋まで運んでいただけますか？\"}, {\"original\": \"Как вызвать службу обслуживания номеров?\", \"translated\": \"ルームサービスの呼び出し方はどうすればいいですか？\"}, {\"original\": \"До какого времени необходимо освободить номер?\", \"translated\": \"チェックアウトの時間は何時ですか？\"}, {\"original\": \"Не могли бы вы выписать мне квитанцию/счёт?\", \"translated\": \"領収書／請求書を書いていただけますか？\"}, {\"original\": \"Можно оставить здесь мой багаж?\", \"translated\": \"荷物をここに預けても大丈夫ですか？\"}]', 2, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в аэропорту?\", \"Отлично! Вот 10 распространённых фраз, связанных с аэропортом, а также их переводы на японский язык:\"]', '[\"Регистрация на рейс\", \"Посадка на борт\", \"Сдача багажа\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например регистрация на рейс, получение багажа или аренда автомобиля? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Где стойка регистрации?\", \"translated\": \"チェックインカウンターはどこですか？\"}, {\"original\": \"Я бы хотел место у окна, пожалуйста.\", \"translated\": \"窓側の席をお願いします。\"}, {\"original\": \"Этот рейс задерживается?\", \"translated\": \"この便は遅れていますか？\"}, {\"original\": \"Мне нужно зарегистрировать этот багаж.\", \"translated\": \"この荷物を預けたいのですが。\"}, {\"original\": \"Где выход на посадку?\", \"translated\": \"搭乗口はどこですか？\"}, {\"original\": \"Самолёт вот-вот взлетит.\", \"translated\": \"飛行機が今から離陸します。\"}, {\"original\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\", \"translated\": \"ノートパソコンとモバイルバッテリーを取り出さなければなりませんか？\"}, {\"original\": \"Где магазин беспошлинной торговли?\", \"translated\": \"免税店はどこですか？\"}, {\"original\": \"Я не могу найти свой чемодан.\", \"translated\": \"私のスーツケースが見つかりません。\"}, {\"original\": \"Предоставляется ли услуга инвалидных колясок?\", \"translated\": \"車椅子サービスはありますか？\"}]', 3, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в общественном транспорте?\", \"Отлично! Вот 10 распространённых фраз, связанных с общественным транспортом, а также их переводы на японский язык:\"]', '[\"Поездка на автобусе/метро\", \"Покупка билетов\", \"Пересадка\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, запрос о месте остановки автобуса, цене билета или выходе из транспорта? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Этот автобус идёт до автовокзала?\", \"translated\": \"このバスは終点まで行きますか？\"}, {\"original\": \"Какая следующая остановка?\", \"translated\": \"次の停留所はどこですか？\"}, {\"original\": \"Где я могу купить билет?\", \"translated\": \"切符はどこで買えますか？\"}, {\"original\": \"Один билет до XX, пожалуйста.\", \"translated\": \"XX行きの切符を一枚お願いします。\"}, {\"original\": \"Нужно ли мне пересаживаться?\", \"translated\": \"乗り換えが必要ですか？\"}, {\"original\": \"Через сколько прибывает следующий поезд метро?\", \"translated\": \"次の地下鉄の列車まであと何分ですか？\"}, {\"original\": \"Извините, пропустите меня, пожалуйста.\", \"translated\": \"すみません、通らせてください。\"}, {\"original\": \"Это место занято?\", \"translated\": \"この席は空いていますか？\"}, {\"original\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\", \"translated\": \"すみません、XXへ行くには２号線にどこで乗り換えればいいですか？\"}, {\"original\": \"Как мне добраться до XX?\", \"translated\": \"XXへはどう行けばいいですか？\"}]', 4, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на туристических объектах?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с туристическими объектами, а также их переводы на японский язык:\"]', '[\"Осмотр достопримечательностей\", \"Фотографирование\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, вопрос о цене билетов, поиск парковочного места или услуг гида? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"Есть ли льготные билеты для студентов?\", \"translated\": \"学生割引のチケットはありますか？\"}, {\"original\": \"Во сколько открывается достопримечательность?\", \"translated\": \"観光スポットの開園時間は何時ですか？\"}, {\"original\": \"Чем здесь интересно заняться?\", \"translated\": \"ここではどんな楽しいことが体験できますか？\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"Где автобус для осмотра достопримечательностей?\", \"translated\": \"観光バスの乗り場はどこですか？\"}, {\"original\": \"Где находится туалет?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"Где лучшее место для просмотра?\", \"translated\": \"一番良い展望スポットはどこですか？\"}, {\"original\": \"Здесь прекрасный вид.\", \"translated\": \"ここからの景色はとても美しいです。\"}, {\"original\": \"Доступна ли экскурсия с гидом?\", \"translated\": \"ガイド付きツアーはありますか？\"}]', 5, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать при заказе такси или пользовании услугами такси?\", \"Отлично! Вот 10 распространённых фраз, связанных с такси или услугами такси, а также их переводы на японский язык:\"]', '[\"Вызов такси\", \"Указание места назначения\", \"Оплата\"]', 'ru', '[\"Пока что: что именно вы сейчас хотели бы сделать — уточнить пункт назначения, узнать стоимость поездки или запросить счёт? Свободно задавайте любые вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас возникла в мыслях.\"]', NULL, '[{\"original\": \"Где я могу взять такси?\", \"translated\": \"タクシーはどこで乗れますか？\"}, {\"original\": \"Пожалуйста, отвезите меня по этому адресу.\", \"translated\": \"この住所までお願いします。\"}, {\"original\": \"Примерно сколько это будет стоить?\", \"translated\": \"だいたいいくらぐらいになりますか？\"}, {\"original\": \"Не могли бы вы, пожалуйста, включить счётчик?\", \"translated\": \"メーターを使っていただけますか？\"}, {\"original\": \"Пожалуйста, поезжайте немного быстрее, мне спешно.\", \"translated\": \"急いでいるので、もう少し速く運転していただけますか？\"}, {\"original\": \"Остановитесь, пожалуйста, здесь.\", \"translated\": \"ここで止めてください。\"}, {\"original\": \"Принимаете ли вы оплату картой или через мобильные приложения?\", \"translated\": \"カードやモバイル決済は使えますか？\"}, {\"original\": \"Можно мне, пожалуйста, чек?\", \"translated\": \"領収書をいただけますか？\"}, {\"original\": \"Спасибо, водитель.\", \"translated\": \"ありがとうございました、運転手さん。\"}, {\"original\": \"Сколько ещё осталось ехать?\", \"translated\": \"あとどのくらいですか？\"}]', 6, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в аптеке?\", \"Превосходно! Вот 10 распространённых фраз, связанных с аптекой, а также их переводы на японский язык:\"]', '[\"Покупка лекарств\", \"Консультация\", \"Оплата\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация в уме, например, запрос инструкций по приёму лекарств, фразы, связанные с использованием страхования, продолжительностью приёма лекарств — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"У вас есть лекарство от простуды?\", \"translated\": \"風邪薬はありますか？\"}, {\"original\": \"Как мне принимать это лекарство?\", \"translated\": \"この薬の飲み方はどうすればいいですか？\"}, {\"original\": \"У вас есть обезболивающие?\", \"translated\": \"鎮痛剤はありますか？\"}, {\"original\": \"Есть ли инструкция по применению?\", \"translated\": \"説明書はついていますか？\"}, {\"original\": \"Это лекарство имеет какие-либо побочные эффекты?\", \"translated\": \"この薬には副作用がありますか？\"}, {\"original\": \"Можно ли воспользоваться моей медицинской страховкой?\", \"translated\": \"医療保険証を使っても大丈夫ですか？\"}, {\"original\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\", \"translated\": \"絆創膏の箱を一箱いただけますか？\"}, {\"original\": \"У вас есть жаропонижающие?\", \"translated\": \"解熱剤はありますか？\"}, {\"original\": \"Я немного поранился. У вас есть антисептик и пластыри?\", \"translated\": \"ちょっと擦り傷をしました。消毒液と絆創膏はありますか？\"}, {\"original\": \"Во сколько вы закрываетесь?\", \"translated\": \"何時まで営業していますか？\"}]', 7, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в службах экстренной помощи?\", \"Отлично! Вот 10 распространённых фраз, связанных со службами экстренной помощи, а также их переводы на японский язык:\"]', '[\"Вызов полиции\", \"Первая помощь\", \"Вызов на помощь\"]', 'ru', '[\"Пока что: у вас есть конкретная чрезвычайная ситуация в уме, например пожар, травма и необходимость помощи, экстренный вызов — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас возникла в уме.\"]', NULL, '[{\"original\": \"Пожалуйста, помогите мне вызвать скорую помощь.\", \"translated\": \"救急車を呼んでください。\"}, {\"original\": \"Где находится больница?\", \"translated\": \"病院はどこですか？\"}, {\"original\": \"Кто-то получил травму.\", \"translated\": \"誰かが怪我をしました。\"}, {\"original\": \"Пожалуйста, помогите мне.\", \"translated\": \"助けてください。\"}, {\"original\": \"Где находится полицейский участок?\", \"translated\": \"警察署はどこですか？\"}, {\"original\": \"Я потерял свои вещи.\", \"translated\": \"荷物をなくしました。\"}, {\"original\": \"Какой номер пожарной службы?\", \"translated\": \"消防署の電話番号は何番ですか？\"}, {\"original\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\", \"translated\": \"パスポートを紛失しました。近くの警察署はどこですか？\"}, {\"original\": \"Здесь есть аварийный выход?\", \"translated\": \"非常口はありますか？\"}, {\"original\": \"Кто-то потерял сознание.\", \"translated\": \"誰かが気を失いました。\"}]', 8, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на пляже или у бассейна?\", \"Превосходно! Вот 10 распространённых фраз, связанных с пляжем или бассейном, а также их переводы на японский язык:\"]', '[\"Плавание\", \"Загар\", \"Пляжные виды спорта\"]', 'ru', '[\"Пока что, не могли бы вы сообщить мне контекст местного события или фестиваля, в котором вы участвуете: культурный фестиваль, гастрономический фестиваль или музыкальный фестиваль? Пожалуйста, укажите контекст.\", \"Пожалуйста, опишите мероприятия, в которых вы участвуете.\"]', '[\"У вас есть конкретная ситуация в уме? Смело задавайте вопрос.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', '[{\"original\": \"Смотрите! Волны там действительно очень большие.\", \"translated\": \"見て！あそこに見える波が本当に大きいよ。\"}, {\"original\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\", \"translated\": \"日焼け止めを塗ることを忘れないでね。ここでの紫外線はとても強いから。\"}, {\"original\": \"Песок на этом пляже такой мелкий, что идти по нему — всё равно что ступать по хлопку.\", \"translated\": \"このビーチの砂はとても細かくて、綿の上を歩いているような感じがする。\"}, {\"original\": \"Как насчёт игры в волейбол на пляже?\", \"translated\": \"ビーチでバレーボールをやるのはどう？\"}, {\"original\": \"Парусники вдали выглядят очень красиво.\", \"translated\": \"遠くに見えるヨットがとても美しいね。\"}, {\"original\": \"Вода здесь такая прозрачная, что даже рыбок можно разглядеть.\", \"translated\": \"ここでの水はとても透明で、魚まで見えちゃうよ。\"}, {\"original\": \"Давайте пойдём собирать морские ракушки.\", \"translated\": \"一緒に貝殻を探しに行こう。\"}, {\"original\": \"Прогулка по пляжу на закате, наверное, очень романтична.\", \"translated\": \"夕日に染まるビーチを散歩するのはきっととてもロマンチックだろうね。\"}, {\"original\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\", \"translated\": \"ここでは海産物がとても新鮮だと聞いたから、ぜひ食べてみよう。\"}, {\"original\": \"Начинается прилив, давайте вернёмся к берегу.\", \"translated\": \"潮が満ちてきたから、そろそろ海岸の方へ戻ろう。\"}]', 9, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать на местных мероприятиях и праздниках?\", \"Превосходно! Вот 10 распространённых фраз, связанных с местными мероприятиями и праздниками, а также их переводы на японский язык:\"]', '[\"Посещение мероприятий\", \"Празднование фестивалей\", \"Изучение культуры\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного мероприятия или праздника, на который вы собираетесь пойти: Хэллоуин, концерт, вечеринка у друзей или что-то ещё? Пожалуйста, укажите контекст.\", \"Опишите, пожалуйста, те виды деятельности, которые приходят вам на ум.\"]', '[\"У вас есть конкретная ситуация в уме? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая приходит вам на ум.\"]', '[{\"original\": \"Есть ли сегодня какие-нибудь мероприятия?\", \"translated\": \"今日何かイベントはありますか？\"}, {\"original\": \"В этом празднике есть что-нибудь особенное?\", \"translated\": \"この祭りには何か特別なことがありますか？\"}, {\"original\": \"Где проходит празднование?\", \"translated\": \"お祝いはどこで行われますか？\"}, {\"original\": \"Как я могу купить билеты?\", \"translated\": \"チケットの購入方法を教えてください。\"}, {\"original\": \"Во сколько начинается представление?\", \"translated\": \"パフォーマンスは何時から始まりますか？\"}, {\"original\": \"Какая традиционная еда здесь есть?\", \"translated\": \"どんな伝統的な食べ物がありますか？\"}, {\"original\": \"Здесь действительно очень оживлённо.\", \"translated\": \"ここは本当ににぎやかですね。\"}, {\"original\": \"Есть ли какие-нибудь народные мероприятия?\", \"translated\": \"民俗行事はありますか？\"}, {\"original\": \"Счастливых праздников!\", \"translated\": \"楽しい休日を！\"}, {\"original\": \"Во сколько заканчивается мероприятие?\", \"translated\": \"イベントは何時までですか？\"}]', 10, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в музее или художественной галерее?\", \"Превосходно! Вот 10 распространённых фраз, связанных с музеем или художественной галереей, а также их переводы на японский язык:\"]', '[\"Посещение\", \"Экскурсия\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, просьба о вводном буклете, фразы, связанные с маршрутом посещения, фразы, связанные с комментариями к экспонатам? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"入館料はいくらですか？\"}, {\"original\": \"У вас есть аудиогиды?\", \"translated\": \"オーディオガイドはありますか？\"}, {\"original\": \"Кто создал это произведение искусства?\", \"translated\": \"この作品は誰が制作したのですか？\"}, {\"original\": \"Где находится самая ценная экспонат музея?\", \"translated\": \"美術館の最も貴重な作品はどこにありますか？\"}, {\"original\": \"Разрешена ли фотосъёмка?\", \"translated\": \"写真撮影は許可されていますか？\"}, {\"original\": \"Здесь проходят какие-нибудь специальные выставки?\", \"translated\": \"ここには特別展はありますか？\"}, {\"original\": \"Сколько времени занимает посещение?\", \"translated\": \"見学にはどのくらいの時間がかかりますか？\"}, {\"original\": \"Не могли бы вы представить нам краткое введение?\", \"translated\": \"ご案内いただけますか？\"}, {\"original\": \"Эти произведения действительно изысканны.\", \"translated\": \"これらの作品は本当に素晴らしいです。\"}, {\"original\": \"Где находится магазин сувениров?\", \"translated\": \"お土産ショップはどこですか？\"}]', 11, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в кафе?\", \"Отлично! Вот 10 распространённых фраз, связанных с кафе, а также их переводы на японский язык:\"]', '[\"Заказ кофе\", \"Отдых\", \"Общение\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация в уме, например, заказ меню, прохладительных или горячих напитков, других товаров? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас возникла в уме.\"]', NULL, '[{\"original\": \"Я возьму латте, пожалуйста.\", \"translated\": \"ラテを一杯お願いします。\"}, {\"original\": \"У вас есть Wi-Fi?\", \"translated\": \"Wi-Fiはありますか？\"}, {\"original\": \"Можно мне посмотреть меню, пожалуйста?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"Разрешено ли добавлять кофе бесплатно?\", \"translated\": \"追加注文はできますか？\"}, {\"original\": \"Мой кофе уже готов?\", \"translated\": \"私のコーヒーはできましたか？\"}, {\"original\": \"Сколько времени я могу здесь посидеть?\", \"translated\": \"ここにどのくらい座っていられますか？\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"Где туалет?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"Счёт, пожалуйста. Спасибо.\", \"translated\": \"お会計をお願いします。ありがとうございます。\"}, {\"original\": \"Очень вкусно.\", \"translated\": \"とてもおいしいです。\"}]', 12, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в ресторане?\", \"Отлично! Вот 10 распространённых фраз, связанных с посещением ресторана, а также их переводы на английский язык:\"]', '[\"Питание\", \"Заказ\", \"Оформление заказа\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например заказ напитков, жалоба или вопрос об ингредиентах? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Извините, сколько ещё ждать нашу еду?\", \"translated\": \"Excuse me, how much longer will our food be?\"}, {\"original\": \"Столик на двоих, пожалуйста.\", \"translated\": \"A table for two, please.\"}, {\"original\": \"Можно посмотреть меню, пожалуйста?\", \"translated\": \"Could we see the menu, please?\"}, {\"original\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\", \"translated\": \"Do you have any signature dishes to recommend?\"}, {\"original\": \"Я хочу заказать это и это.\", \"translated\": \"I\'d like to order this, and this.\"}, {\"original\": \"Стакан воды, пожалуйста. Спасибо.\", \"translated\": \"A glass of water, please. Thanks.\"}, {\"original\": \"Счёт, пожалуйста.\", \"translated\": \"The bill, please.\"}, {\"original\": \"Можно оплатить кредитной картой?\", \"translated\": \"Can I pay by credit card?\"}, {\"original\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\", \"translated\": \"Could you pack this to go, please?\"}, {\"original\": \"Еда была восхитительной, спасибо.\", \"translated\": \"The food was delicious, thank you.\"}]', 1, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в отеле?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с отелем, а также их переводы на английский язык:\"]', '[\"Регистрация заезда\", \"Регистрация выезда\", \"Обслуживание в номере\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например, расположение номера, другие услуги отеля или выезд из отеля? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\", \"translated\": \"Hello, I have a reservation. Here is my passport.\"}, {\"original\": \"У вас есть свободные номера?\", \"translated\": \"Do you have any vacancies?\"}, {\"original\": \"Извините, в отеле есть тренажёрный зал или прачечная?\", \"translated\": \"Excuse me, does the hotel have a gym or a laundry room?\"}, {\"original\": \"Во сколько начинается завтрак?\", \"translated\": \"What time does breakfast start?\"}, {\"original\": \"Можно мне ключ от номера, пожалуйста?\", \"translated\": \"Could I have a room key, please?\"}, {\"original\": \"Не могли бы вы помочь мне отнести багаж в номер?\", \"translated\": \"Could you help me take my luggage to the room?\"}, {\"original\": \"Как вызвать службу обслуживания номеров?\", \"translated\": \"How do I call room service?\"}, {\"original\": \"Во сколько время выезда?\", \"translated\": \"What time is check-out?\"}, {\"original\": \"Не могли бы вы выписать мне квитанцию/счёт?\", \"translated\": \"Could you write me a receipt/invoice?\"}, {\"original\": \"Можно оставить здесь мой багаж?\", \"translated\": \"Can I leave my luggage here?\"}]', 2, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в аэропорту?\", \"Отлично! Вот 10 распространённых фраз, связанных с аэропортом, вместе с переводом на английский язык:\"]', '[\"Регистрация на рейс\", \"Посадка на борт\", \"Сдача багажа\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например, регистрация на рейс, получение багажа или аренда автомобиля? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Где стойка регистрации?\", \"translated\": \"Where is the check-in counter?\"}, {\"original\": \"Я бы хотел место у окна, пожалуйста.\", \"translated\": \"I\'d like a window seat, please.\"}, {\"original\": \"Этот рейс задерживается?\", \"translated\": \"Is this flight delayed?\"}, {\"original\": \"Мне нужно зарегистрировать этот багаж.\", \"translated\": \"I need to check this baggage.\"}, {\"original\": \"Где выход на посадку?\", \"translated\": \"Where is the boarding gate?\"}, {\"original\": \"Самолёт вот-вот взлетит.\", \"translated\": \"The plane is about to take off.\"}, {\"original\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\", \"translated\": \"Do I need to take out my laptop and power bank?\"}, {\"original\": \"Где магазин беспошлинной торговли?\", \"translated\": \"Where is the duty-free shop?\"}, {\"original\": \"Я не могу найти свой чемодан.\", \"translated\": \"I can\'t find my suitcase.\"}, {\"original\": \"Предоставляется ли услуга инвалидных колясок?\", \"translated\": \"Do you have a wheelchair service?\"}]', 3, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в общественном транспорте?\", \"Отлично! Вот 10 распространённых фраз, связанных с общественным транспортом, а также их переводы на английский язык:\"]', '[\"Поездка на автобусе/метро\", \"Покупка билетов\", \"Пересадка\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например, вопрос о месте остановки автобуса, цене билета или выходе из транспорта? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Этот автобус идёт до автовокзала?\", \"translated\": \"Does this bus go to the terminal?\"}, {\"original\": \"Какая следующая остановка?\", \"translated\": \"What is the next stop?\"}, {\"original\": \"Где я могу купить билет?\", \"translated\": \"Where can I buy a ticket?\"}, {\"original\": \"Один билет до XX, пожалуйста.\", \"translated\": \"One ticket to XX, please.\"}, {\"original\": \"Нужно ли мне пересаживаться?\", \"translated\": \"Do I need to transfer?\"}, {\"original\": \"Через сколько прибудет следующий поезд метро?\", \"translated\": \"How long until the next subway train?\"}, {\"original\": \"Извините, пропустите меня, пожалуйста.\", \"translated\": \"Excuse me, please let me pass.\"}, {\"original\": \"Это место занято?\", \"translated\": \"Is this seat taken?\"}, {\"original\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\", \"translated\": \"Excuse me, where can I transfer to Line 2 to get to XX?\"}, {\"original\": \"Как мне добраться до XX?\", \"translated\": \"How do I get to XX?\"}]', 4, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать на туристических объектах?\", \"Превосходно! Вот 10 распространённых фраз, связанных с туристическими объектами, а также их переводы на английский язык:\"]', '[\"Осмотр достопримечательностей\", \"Фотографирование\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас в голове есть какая-то конкретная ситуация, например, вопрос о цене билетов, поиск парковочного места или услуг гида? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в голове.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"How much is the entrance fee?\"}, {\"original\": \"Есть ли льготные билеты для студентов?\", \"translated\": \"Are there student tickets available?\"}, {\"original\": \"Во сколько открывается достопримечательность?\", \"translated\": \"What time does the attraction open?\"}, {\"original\": \"Чем здесь можно интересно заняться?\", \"translated\": \"What are the fun things to do here?\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"Где автобус для осмотра достопримечательностей?\", \"translated\": \"Where is the sightseeing bus?\"}, {\"original\": \"Где находится туалет?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"Где лучшее место для просмотра?\", \"translated\": \"Where is the best viewing spot?\"}, {\"original\": \"Здесь прекрасные виды.\", \"translated\": \"The scenery here is beautiful.\"}, {\"original\": \"Доступна ли экскурсия с гидом?\", \"translated\": \"Is there a guided tour available?\"}]', 5, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать при заказе такси или пользовании услугами такси?\", \"Отлично! Вот 10 распространённых фраз, связанных с такси или услугами такси, а также их переводы на английский язык:\"]', '[\"Вызов такси\", \"Указание места назначения\", \"Оплата\"]', 'ru', '[\"Пока что: что вы сейчас больше всего хотите сделать — уточнить пункт назначения, узнать стоимость поездки или запросить счёт? Свободно задавайте любые вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в голове.\"]', NULL, '[{\"original\": \"Где я могу взять такси?\", \"translated\": \"Where can I get a taxi?\"}, {\"original\": \"Пожалуйста, отвезите меня по этому адресу.\", \"translated\": \"Please take me to this address.\"}, {\"original\": \"Примерно сколько это будет стоить?\", \"translated\": \"Roughly how much will it be?\"}, {\"original\": \"Не могли бы вы, пожалуйста, включить счётчик?\", \"translated\": \"Could you use the meter, please?\"}, {\"original\": \"Пожалуйста, поезжайте немного быстрее, мне спешно.\", \"translated\": \"Please drive a bit faster, I\'m in a hurry.\"}, {\"original\": \"Остановитесь, пожалуйста, здесь.\", \"translated\": \"Please stop here.\"}, {\"original\": \"Принимаете ли вы оплату картой или через мобильные приложения?\", \"translated\": \"Do you accept cards or mobile payments?\"}, {\"original\": \"Можно мне, пожалуйста, чек?\", \"translated\": \"Could I have a receipt, please?\"}, {\"original\": \"Спасибо, водитель.\", \"translated\": \"Thank you, driver.\"}, {\"original\": \"Сколько ещё осталось ехать?\", \"translated\": \"How much further is it?\"}]', 6, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в аптеке?\", \"Отлично! Вот 10 распространённых фраз, связанных с аптекой, а также их переводы на английский язык:\"]', '[\"Покупка лекарств\", \"Консультация\", \"Оплата\"]', 'ru', '[\"Пока что: У вас есть конкретная ситуация в уме, например, запрос инструкций по приёму лекарств, фразы, связанные с использованием страхования, продолжительностью приёма лекарств — не стесняйтесь задавать вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"У вас есть лекарство от простуды?\", \"translated\": \"Do you have cold medicine?\"}, {\"original\": \"Как мне принимать это лекарство?\", \"translated\": \"How should I take this medicine?\"}, {\"original\": \"У вас есть обезболивающие?\", \"translated\": \"Do you have any painkillers?\"}, {\"original\": \"Есть ли инструкция по применению?\", \"translated\": \"Is there an instruction leaflet?\"}, {\"original\": \"Это лекарство имеет какие-либо побочные эффекты?\", \"translated\": \"Does this medicine have any side effects?\"}, {\"original\": \"Можно ли воспользоваться моей медицинской страховкой?\", \"translated\": \"Can I use my medical insurance card?\"}, {\"original\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\", \"translated\": \"Could I have a box of Band-Aids, please?\"}, {\"original\": \"У вас есть жаропонижающие?\", \"translated\": \"Do you have any fever reducers?\"}, {\"original\": \"Я немного поранился. У вас есть антисептик и пластыри?\", \"translated\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\"}, {\"original\": \"Во сколько вы закрываетесь?\", \"translated\": \"What time do you close?\"}]', 7, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в службах экстренной помощи?\", \"Отлично! Вот 10 распространённых фраз, связанных со службами экстренной помощи, а также их переводы на английский язык:\"]', '[\"Вызов полиции\", \"Первая помощь\", \"Вызов на помощь\"]', 'ru', '[\"Пока что у вас есть в виду какая-то конкретная чрезвычайная ситуация, например пожар, травма и необходимость помощи, экстренный вызов — смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Пожалуйста, помогите мне вызвать скорую помощь.\", \"translated\": \"Please help me call an ambulance.\"}, {\"original\": \"Где находится больница?\", \"translated\": \"Where is the hospital?\"}, {\"original\": \"Кто-то получил травму.\", \"translated\": \"Someone is injured.\"}, {\"original\": \"Пожалуйста, помогите мне.\", \"translated\": \"Please help me.\"}, {\"original\": \"Где находится полицейский участок?\", \"translated\": \"Where is the police station?\"}, {\"original\": \"Я потерял свои вещи.\", \"translated\": \"I\'ve lost my belongings.\"}, {\"original\": \"Какой номер пожарной службы?\", \"translated\": \"What is the number for the fire department?\"}, {\"original\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\", \"translated\": \"I\'ve lost my passport. Do you know where the nearest police station is?\"}, {\"original\": \"Здесь есть аварийный выход?\", \"translated\": \"Is there an emergency exit?\"}, {\"original\": \"Кто-то потерял сознание.\", \"translated\": \"Someone has fainted.\"}]', 8, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на пляже или у бассейна?\", \"Превосходно! Вот 10 распространённых фраз, связанных с пляжем или бассейном, а также их переводы на английский язык:\"]', '[\"Плавание\", \"Загар\", \"Пляжные виды спорта\"]', 'ru', '[\"Пока что, не могли бы вы сообщить мне контекст местного события или фестиваля, в котором вы участвуете: культурный фестиваль, гастрономический фестиваль или музыкальный фестиваль? Пожалуйста, укажите контекст.\", \"Пожалуйста, опишите мероприятия, в которых вы участвуете.\"]', '[\"У вас есть конкретная ситуация в уме? Смело задавайте вопрос.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', '[{\"original\": \"Смотрите! Волны там действительно очень большие.\", \"translated\": \"Look! The waves over there are really big.\"}, {\"original\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\", \"translated\": \"Remember to apply sunscreen; the UV rays here are very strong.\"}, {\"original\": \"Песок на этом пляже такой мелкий, что кажется, будто вы ступаете по хлопку.\", \"translated\": \"The sand on this beach is so fine, it feels like stepping on cotton.\"}, {\"original\": \"Как насчёт игры в волейбол на пляже?\", \"translated\": \"How about playing volleyball on the beach?\"}, {\"original\": \"Парусники вдали выглядят очень красиво.\", \"translated\": \"The sailboats in the distance look beautiful.\"}, {\"original\": \"Вода здесь такая прозрачная, что даже видно рыб.\", \"translated\": \"The water here is so clear, you can even see the fish.\"}, {\"original\": \"Давайте пойдём собирать ракушки.\", \"translated\": \"Let\'s go find some seashells.\"}, {\"original\": \"Прогулка по пляжу на закате, наверное, очень романтична.\", \"translated\": \"Taking a walk on the beach at sunset must be very romantic.\"}, {\"original\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\", \"translated\": \"I heard the seafood here is very fresh; let\'s go try some.\"}, {\"original\": \"Начинается прилив, давайте направимся к берегу.\", \"translated\": \"The tide is coming in; let\'s head towards the shore.\"}]', 9, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на местных мероприятиях и праздниках?\", \"Превосходно! Вот 10 распространённых фраз, связанных с местными мероприятиями и праздниками, а также их переводы на английский язык:\"]', '[\"Посещение мероприятий\", \"Празднование фестивалей\", \"Изучение культуры\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного мероприятия или праздника, на который вы собираетесь пойти: Хэллоуин, концерт, вечеринка у друзей или что-то ещё? Пожалуйста, укажите контекст.\", \"Опишите, пожалуйста, те мероприятия, которые у вас на уме.\"]', '[\"У вас есть конкретная ситуация, о которой вы хотели бы спросить? Свободно задавайте вопрос.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', '[{\"original\": \"Есть ли сегодня какие-нибудь мероприятия?\", \"translated\": \"Are there any events today?\"}, {\"original\": \"В этом празднике есть что-нибудь особенное?\", \"translated\": \"Is there anything special about this festival?\"}, {\"original\": \"Где проходит празднование?\", \"translated\": \"Where is the celebration being held?\"}, {\"original\": \"Как я могу купить билеты?\", \"translated\": \"How can I buy tickets?\"}, {\"original\": \"Во сколько начинается представление?\", \"translated\": \"What time does the performance start?\"}, {\"original\": \"Какая традиционная еда здесь есть?\", \"translated\": \"What traditional food is there?\"}, {\"original\": \"Здесь действительно очень оживлённо.\", \"translated\": \"It\'s really lively here.\"}, {\"original\": \"Есть ли какие-нибудь народные мероприятия?\", \"translated\": \"Are there any folk activities?\"}, {\"original\": \"Счастливых праздников!\", \"translated\": \"Happy holidays!\"}, {\"original\": \"Во сколько заканчивается мероприятие?\", \"translated\": \"What time does the event end?\"}]', 10, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в музее или художественной галерее?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с музеем или художественной галереей, а также их переводы на английский язык:\"]', '[\"Посещение\", \"Экскурсия\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например, просьба о справочном буклете, фразы, связанные с маршрутом посетителя, фразы, связанные с комментариями к экспонатам? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"How much is the admission fee?\"}, {\"original\": \"У вас есть аудиогиды?\", \"translated\": \"Do you have audio guides?\"}, {\"original\": \"Кто создал это произведение искусства?\", \"translated\": \"Who created this artwork?\"}, {\"original\": \"Где находится самая ценная экспонат музея?\", \"translated\": \"Where is the museum\'s most prized piece?\"}, {\"original\": \"Разрешена ли фотосъёмка?\", \"translated\": \"Is photography allowed?\"}, {\"original\": \"Здесь проходят какие-нибудь специальные выставки?\", \"translated\": \"Are there any special exhibitions here?\"}, {\"original\": \"Сколько времени занимает посещение?\", \"translated\": \"How long does the visit take?\"}, {\"original\": \"Не могли бы вы представить нам краткое введение?\", \"translated\": \"Could you give us an introduction?\"}, {\"original\": \"Эти произведения действительно изысканны.\", \"translated\": \"These works are truly exquisite.\"}, {\"original\": \"Где находится магазин сувениров?\", \"translated\": \"Where is the souvenir shop?\"}]', 11, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в кафе?\", \"Превосходно! Вот 10 распространённых фраз, связанных с кафе, а также их переводы на английский язык:\"]', '[\"Заказ кофе\", \"Отдых\", \"Общение\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, запрос меню, прохладительных или горячих напитков, других товаров? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Я возьму латте, пожалуйста.\", \"translated\": \"I\'ll have a latte, please.\"}, {\"original\": \"У вас есть Wi-Fi?\", \"translated\": \"Do you have Wi-Fi?\"}, {\"original\": \"Можно мне посмотреть меню, пожалуйста?\", \"translated\": \"Could I see the menu, please?\"}, {\"original\": \"Разрешено ли дополнительное наливание?\", \"translated\": \"Are refills allowed?\"}, {\"original\": \"Готов мой кофе?\", \"translated\": \"Is my coffee ready?\"}, {\"original\": \"Сколько времени я могу здесь посидеть?\", \"translated\": \"How long can I sit here?\"}, {\"original\": \"Не могли бы вы сделать нам фотографию?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"Где туалет?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"Счёт, пожалуйста. Спасибо.\", \"translated\": \"Check, please. Thank you.\"}, {\"original\": \"Очень вкусно.\", \"translated\": \"It tastes really good.\"}]', 12, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в ресторане?\", \"Превосходно! Вот 10 распространённых фраз, связанных с рестораном, а также их переводы на арабский язык:\"]', '[\"Питание\", \"Заказ\", \"Оформление заказа\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация на уме, например, заказ напитков, жалоба или вопрос об ингредиентах — смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Извините, сколько ещё ждать нашу еду?\", \"translated\": \"عذرًا، كم من الوقت سيستغرق وصول طعامنا؟\"}, {\"original\": \"Столик на двоих, пожалуйста.\", \"translated\": \"طاولة لشخصين، من فضلكم.\"}, {\"original\": \"Можно посмотреть меню, пожалуйста?\", \"translated\": \"هل يمكننا رؤية القائمة، من فضلكم؟\"}, {\"original\": \"У вас есть фирменные блюда, которые вы могли бы порекомендовать?\", \"translated\": \"هل لديكم أطباق مميزة توصون بها؟\"}, {\"original\": \"Я хочу заказать это и это.\", \"translated\": \"أود طلب هذا وهذا.\"}, {\"original\": \"Стакан воды, пожалуйста. Спасибо.\", \"translated\": \"كوب من الماء، من فضلكم. شكرًا لكم.\"}, {\"original\": \"Счёт, пожалуйста.\", \"translated\": \"الفاتورة، من فضلكم.\"}, {\"original\": \"Можно оплатить кредитной картой?\", \"translated\": \"هل يمكنني الدفع باستخدام بطاقة الائتمان؟\"}, {\"original\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\", \"translated\": \"هل يمكنكم تغليف هذا لل带走، من فضلكم؟\"}, {\"original\": \"Еда была восхитительной, спасибо.\", \"translated\": \"كان الطعام لذيذًا جدًّا، شكرًا لكم.\"}]', 1, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в отеле?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с отелем, а также их переводы на арабский язык:\"]', '[\"Регистрация заезда\", \"Регистрация выезда\", \"Обслуживание в номере\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация в уме, например, расположение номера, другие услуги отеля или выезд из отеля — смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\", \"translated\": \"مرحبًا، لدي حجزٌ، وهذه جواز سفري.\"}, {\"original\": \"У вас есть свободные номера?\", \"translated\": \"هل لديكم أي غرف شاغرة؟\"}, {\"original\": \"Извините, в отеле есть тренажёрный зал или прачечная?\", \"translated\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسيل الملابس؟\"}, {\"original\": \"Во сколько начинается завтрак?\", \"translated\": \"في أي وقت تبدأ وجبة الإفطار؟\"}, {\"original\": \"Можно мне ключ от номера, пожалуйста?\", \"translated\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\"}, {\"original\": \"Не могли бы вы помочь мне отнести багаж в номер?\", \"translated\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\"}, {\"original\": \"Как вызвать службу обслуживания номеров?\", \"translated\": \"كيف أطلب خدمة الغرف؟\"}, {\"original\": \"До какого времени необходимо освободить номер?\", \"translated\": \"في أي وقت يتم المغادرة؟\"}, {\"original\": \"Не могли бы вы выписать мне квитанцию/счёт?\", \"translated\": \"هل يمكنكم إعطائي إيصالًا/فاتورةً؟\"}, {\"original\": \"Можно оставить здесь мой багаж?\", \"translated\": \"هل يمكنني ترك أمتعتي هنا؟\"}]', 2, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в аэропорту?\", \"Превосходно! Вот 10 распространённых фраз, связанных с аэропортом, а также их переводы на арабский язык:\"]', '[\"Регистрация на рейс\", \"Посадка на борт\", \"Сдача багажа\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация в уме, например регистрация на рейс, получение багажа или аренда автомобиля? Свободно задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Где стойка регистрации?\", \"translated\": \"أين كاونتر تسجيل الدخول؟\"}, {\"original\": \"Я бы хотел место у окна, пожалуйста.\", \"translated\": \"أود أن أجلس في مقعد بجانب النافذة، من فضلك.\"}, {\"original\": \"Этот рейс задерживается?\", \"translated\": \"هل هذا الرحلة متأخرة؟\"}, {\"original\": \"Мне нужно зарегистрировать этот багаж.\", \"translated\": \"يجب أن أُسجّل هذه الأمتعة.\"}, {\"original\": \"Где выход на посадку?\", \"translated\": \"أين بوابة الصعود إلى الطائرة؟\"}, {\"original\": \"Самолёт вот-вот взлетит.\", \"translated\": \"الطائرة على وشك الإقلاع.\"}, {\"original\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\", \"translated\": \"هل يجب أن أخرج جهاز الكمبيوتر المحمول والباور بانك الخاص بي؟\"}, {\"original\": \"Где магазин беспошлинной торговли?\", \"translated\": \"أين متجر التجزئة المعفي من الرسوم الجمركية؟\"}, {\"original\": \"Я не могу найти свой чемодан.\", \"translated\": \"لا أستطيع العثور على حقيبتي.\"}, {\"original\": \"Предоставляется ли услуга инвалидных колясок?\", \"translated\": \"هل تقدمون خدمة الكرسي المتحرك؟\"}]', 3, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в общественном транспорте?\", \"Превосходно! Вот 10 распространённых фраз, связанных с общественным транспортом, а также их переводы на арабский язык:\"]', '[\"Поездка на автобусе/метро\", \"Покупка билетов\", \"Пересадка\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация на уме, например, спросить о месте остановки автобуса, цене билета или выходе из транспорта — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Этот автобус идёт до автовокзала?\", \"translated\": \"هل هذه الحافلة تذهب إلى المحطة؟\"}, {\"original\": \"Какая следующая остановка?\", \"translated\": \"ما هي المحطة التالية؟\"}, {\"original\": \"Где я могу купить билет?\", \"translated\": \"أين يمكنني شراء تذكرة؟\"}, {\"original\": \"Один билет до XX, пожалуйста.\", \"translated\": \"تذكرة واحدة إلى XX، من فضلك.\"}, {\"original\": \"Мне нужно пересаживаться?\", \"translated\": \"هل عليَّ التحويل؟\"}, {\"original\": \"Через сколько прибывает следующий поезд метро?\", \"translated\": \"كم المدة المتبقية حتى قطار المترو القادم؟\"}, {\"original\": \"Извините, пропустите меня, пожалуйста.\", \"translated\": \"عذرًا، من فضلك اسمح لي بالمرور.\"}, {\"original\": \"Это место занято?\", \"translated\": \"هل هذا المقعد محجوز؟\"}, {\"original\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\", \"translated\": \"عذرًا، أين يمكنني التحويل إلى الخط ٢ للوصول إلى XX؟\"}, {\"original\": \"Как мне добраться до XX?\", \"translated\": \"كيف أصل إلى XX؟\"}]', 4, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на туристических объектах?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с туристическими объектами, а также их переводы на арабский язык:\"]', '[\"Осмотр достопримечательностей\", \"Фотографирование\", \"Покупка билетов\"]', 'ru', '[\"Пока что: у вас в голове есть какая-то конкретная ситуация, например, вопрос о цене билетов, поиск парковочного места или услуг гида? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в голове.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"Есть ли льготные билеты для студентов?\", \"translated\": \"هل تتوفر تذاكر للطلاب؟\"}, {\"original\": \"Во сколько открывается достопримечательность?\", \"translated\": \"في أي وقت يفتح المعلم السياحي؟\"}, {\"original\": \"Чем здесь интересно заняться?\", \"translated\": \"ما الأشياء الممتعة التي يمكن القيام بها هنا؟\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"هل يمكنك التقاط صورة لنا؟\"}, {\"original\": \"Где автобус для осмотра достопримечательностей?\", \"translated\": \"أين حافلة الجولات السياحية؟\"}, {\"original\": \"Где находится туалет?\", \"translated\": \"أين الحمام؟\"}, {\"original\": \"Где лучшее место для просмотра?\", \"translated\": \"ما أفضل مكان لمشاهدة المناظر؟\"}, {\"original\": \"Здесь прекрасный вид.\", \"translated\": \"المنظر هنا جميلٌ جدًّا.\"}, {\"original\": \"Доступна ли экскурсия с гидом?\", \"translated\": \"هل توجد جولة إرشادية متاحة؟\"}]', 5, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать при заказе такси или пользовании таксисервисом?\", \"Превосходно! Вот 10 распространённых фраз, связанных с такси или таксисервисом, а также их переводы на арабский язык:\"]', '[\"Вызов такси\", \"Указание места назначения\", \"Оплата\"]', 'ru', '[\"Пока что: что именно вы хотели бы сделать сейчас — уточнить пункт назначения, узнать стоимость поездки или запросить счёт? Свободно задавайте любые вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас возникла в воображении.\"]', NULL, '[{\"original\": \"Где я могу взять такси?\", \"translated\": \"أين يمكنني أخذ تاكسي؟\"}, {\"original\": \"Пожалуйста, отвезите меня по этому адресу.\", \"translated\": \"من فضلك خذني إلى هذا العنوان.\"}, {\"original\": \"Примерно сколько это будет стоить?\", \"translated\": \"كم يبلغ السعر تقريبًا؟\"}, {\"original\": \"Не могли бы вы, пожалуйста, включить счётчик?\", \"translated\": \"هل يمكنك استخدام العداد من فضلك؟\"}, {\"original\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\", \"translated\": \"من فضلك ا-driving أسرع قليلًا، فأنا مستعجل.\"}, {\"original\": \"Остановитесь, пожалуйста, здесь.\", \"translated\": \"من فضلك توقف هنا.\"}, {\"original\": \"Принимаете ли вы оплату картой или через мобильные платежи?\", \"translated\": \"هل تقبل الدفع بالبطاقات أو عبر الهاتف المحمول؟\"}, {\"original\": \"Можно мне, пожалуйста, чек?\", \"translated\": \"هل يمكنني الحصول على إشعار دفع من فضلك؟\"}, {\"original\": \"Спасибо, водитель.\", \"translated\": \"شكرًا لك يا سائق.\"}, {\"original\": \"Как далеко ещё?\", \"translated\": \"كم تبقى من المسافة؟\"}]', 6, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в аптеке?\", \"Превосходно! Вот 10 распространённых фраз, связанных с аптекой, а также их переводы на арабский язык:\"]', '[\"Покупка лекарств\", \"Консультация\", \"Оплата\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация в уме, например, запрос инструкций по приёму лекарств, фразы, связанные с использованием страхования, продолжительностью приёма лекарств — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"У вас есть лекарство от простуды?\", \"translated\": \"هل لديكم دواء للبرد؟\"}, {\"original\": \"Как мне принимать это лекарство?\", \"translated\": \"كيف يجب أن آخذ هذا الدواء؟\"}, {\"original\": \"У вас есть обезболивающие?\", \"translated\": \"هل لديكم مسكنات للألم؟\"}, {\"original\": \"Есть ли инструкция по применению?\", \"translated\": \"هل توجد نشرة إرشادات مع هذا الدواء؟\"}, {\"original\": \"Это лекарство имеет какие-либо побочные эффекты?\", \"translated\": \"هل لهذا الدواء أي آثار جانبية؟\"}, {\"original\": \"Можно ли воспользоваться моей медицинской страховкой?\", \"translated\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\"}, {\"original\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\", \"translated\": \"هل يمكنني الحصول على علبة من الضمادات اللاصقة، من فضلكم؟\"}, {\"original\": \"У вас есть жаропонижающие?\", \"translated\": \"هل لديكم خافضات للحرارة؟\"}, {\"original\": \"Я немного поранился. У вас есть антисептик и пластыри?\", \"translated\": \"لديّ جرح سطحي بسيط. هل لديكم مطهر وضمادات لاصقة؟\"}, {\"original\": \"Во сколько вы закрываетесь?\", \"translated\": \"في أي وقت تغلقون؟\"}]', 7, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в службах экстренной помощи?\", \"Отлично! Вот 10 распространённых фраз, связанных со службами экстренной помощи, а также их переводы на арабский язык:\"]', '[\"Вызов полиции\", \"Первая помощь\", \"Вызов на помощь\"]', 'ru', '[\"Пока что: у вас на уме какая-то конкретная чрезвычайная ситуация, например пожар, травма и необходимость помощи, экстренный вызов — смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Пожалуйста, помогите мне вызвать скорую помощь.\", \"translated\": \"من فضلك ساعدني في الاتصال بالإسعاف.\"}, {\"original\": \"Где находится больница?\", \"translated\": \"أين المستشفى؟\"}, {\"original\": \"Кто-то получил травму.\", \"translated\": \"شخص ما أُصيب.\"}, {\"original\": \"Пожалуйста, помогите мне.\", \"translated\": \"من فضلك ساعدني.\"}, {\"original\": \"Где находится полицейский участок?\", \"translated\": \"أين قسم الشرطة؟\"}, {\"original\": \"Я потерял свои вещи.\", \"translated\": \"لقد فقدت أغراضي.\"}, {\"original\": \"Какой номер пожарной службы?\", \"translated\": \"ما هو رقم إدارة الإطفاء؟\"}, {\"original\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\", \"translated\": \"لقد فقدت جواز سفري. هل تعرف أين أقرب قسم شرطة؟\"}, {\"original\": \"Здесь есть аварийный выход?\", \"translated\": \"هل يوجد مخرج طوارئ؟\"}, {\"original\": \"Кто-то потерял сознание.\", \"translated\": \"شخص ما فقد وعيه.\"}]', 8, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на пляже или у бассейна?\", \"Превосходно! Вот 10 распространённых фраз, связанных с пляжем или бассейном, а также их переводы на арабский язык:\"]', '[\"Плавание\", \"Загар\", \"Пляжные виды спорта\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного события или фестиваля, в котором вы участвуете: культурный фестиваль, гастрономический фестиваль или музыкальный фестиваль? Пожалуйста, укажите контекст.\", \"Пожалуйста, опишите мероприятия, в которых вы участвуете.\"]', '[\"У вас есть конкретная ситуация в уме? Свободно задавайте вопрос.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', '[{\"original\": \"Смотрите! Волны там действительно очень большие.\", \"translated\": \"انظر! الأمواج هناك كبيرة جدًّا.\"}, {\"original\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\", \"translated\": \"تذكَّر أن تضع واقي الشمس، فأشعة فوق البنفسجية هنا قوية جدًّا.\"}, {\"original\": \"Песок на этом пляже такой мелкий, что кажется, будто вы ступаете по хлопку.\", \"translated\": \"الرمال على هذه الشاطئ ناعمة جدًّا، لدرجة أن المشي عليها يشبه المشي على القطن.\"}, {\"original\": \"Как насчёт игры в волейбол на пляже?\", \"translated\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\"}, {\"original\": \"Парусники вдали выглядят очень красиво.\", \"translated\": \"القوارب الشراعية في الأفق تبدو جميلة جدًّا.\"}, {\"original\": \"Вода здесь такая прозрачная, что даже видно рыб.\", \"translated\": \"الماء هنا صافٍ جدًّا لدرجة أنك تستطيع رؤية الأسماك.\"}, {\"original\": \"Давайте пойдём собирать ракушки.\", \"translated\": \"هيا نذهب للبحث عن بعض المحار.\"}, {\"original\": \"Прогулка по пляжу на закате, наверное, очень романтична.\", \"translated\": \"التنزه على الشاطئ عند غروب الشمس لا بد أنه أمرٌ رومانسيٌّ جدًّا.\"}, {\"original\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\", \"translated\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًّا، فلنذهب ونجرب بعضها.\"}, {\"original\": \"Начинается прилив, давайте направимся к берегу.\", \"translated\": \"المدّ في ازدياد، لذا دعونا نتجه نحو الساحل.\"}]', 9, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на местных мероприятиях и фестивалях?\", \"Превосходно! Вот 10 распространённых фраз, связанных с местными мероприятиями и фестивалями, а также их переводы на арабский язык:\"]', '[\"Посещение мероприятий\", \"Празднование фестивалей\", \"Изучение культуры\"]', 'ru', '[\"Пока что не могли бы вы, пожалуйста, сообщить мне контекст местного мероприятия или фестиваля, на который вы собираетесь пойти: Хэллоуин, концерт, вечеринка у друга или что-то ещё? Пожалуйста, укажите контекст.\", \"Опишите, пожалуйста, те виды деятельности, которые приходят вам на ум.\"]', '[\"У вас есть конкретная ситуация в уме? Свободно задавайте вопрос.\", \"Опишите, пожалуйста, ту ситуацию, которая приходит вам на ум.\"]', '[{\"original\": \"Есть ли сегодня какие-нибудь мероприятия?\", \"translated\": \"هل توجد أي فعاليات اليوم؟\"}, {\"original\": \"В этом празднике есть что-нибудь особенное?\", \"translated\": \"هل هناك شيء خاص في هذه المهرجان؟\"}, {\"original\": \"Где проходит празднование?\", \"translated\": \"أين تُقام الاحتفالات؟\"}, {\"original\": \"Как я могу купить билеты?\", \"translated\": \"كيف يمكنني شراء التذاكر؟\"}, {\"original\": \"Во сколько начинается представление?\", \"translated\": \"في أي وقت تبدأ العروض؟\"}, {\"original\": \"Какая традиционная еда здесь есть?\", \"translated\": \"ما الأطعمة التقليدية المتاحة؟\"}, {\"original\": \"Здесь действительно очень оживлённо.\", \"translated\": \"المكان مفعَمٌ بالحيوية حقًّا.\"}, {\"original\": \"Есть ли какие-нибудь народные мероприятия?\", \"translated\": \"هل توجد أنشطة شعبية؟\"}, {\"original\": \"Счастливых праздников!\", \"translated\": \"أعياد سعيدة!\"}, {\"original\": \"Во сколько заканчивается мероприятие?\", \"translated\": \"في أي وقت تنتهي الفعالية؟\"}]', 10, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в музее или художественной галерее?\", \"Превосходно! Вот 10 распространённых фраз, связанных с музеем или художественной галереей, а также их переводы на арабский язык:\"]', '[\"Посещение\", \"Экскурсия\", \"Покупка билетов\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация в уме, например, просьба о вводном буклете, фразы, связанные с маршрутом посетителя, фразы, связанные с комментариями к экспонатам — свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"У вас есть аудиогиды?\", \"translated\": \"هل لديكم أدلة صوتية؟\"}, {\"original\": \"Кто создал это произведение искусства?\", \"translated\": \"من هو مبتكر هذه القطعة الفنية؟\"}, {\"original\": \"Где находится самая ценная экспонат музея?\", \"translated\": \"أين توجد أثمن قطعة في المتحف؟\"}, {\"original\": \"Разрешена ли фотосъёмка?\", \"translated\": \"هل يُسمح بالتصوير الفوتوغرافي؟\"}, {\"original\": \"Здесь проходят какие-нибудь специальные выставки?\", \"translated\": \"هل توجد هنا أي معارض خاصة؟\"}, {\"original\": \"Сколько времени занимает посещение?\", \"translated\": \"كم تستغرق الزيارة من الوقت؟\"}, {\"original\": \"Не могли бы вы дать нам краткое введение?\", \"translated\": \"هل يمكنكم أن تقدّموا لنا عرضًا تمهيديًّا؟\"}, {\"original\": \"Эти произведения действительно изысканны.\", \"translated\": \"هذه الأعمال فعلاً رائعةٌ جدًّا.\"}, {\"original\": \"Где находится магазин сувениров?\", \"translated\": \"أين تقع متجر الهدايا التذكارية؟\"}]', 11, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в кафе?\", \"Превосходно! Вот 10 распространённых фраз, связанных с кафе, а также их переводы на арабский язык:\"]', '[\"Заказ кофе\", \"Отдых\", \"Общение\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например, заказ меню, прохладительных или горячих напитков, других товаров? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Я возьму латте, пожалуйста.\", \"translated\": \"سأطلب لاتيه، من فضلك.\"}, {\"original\": \"У вас есть Wi-Fi?\", \"translated\": \"هل لديكم اتصال واي فاي؟\"}, {\"original\": \"Можно мне посмотреть меню, пожалуйста?\", \"translated\": \"هل يمكنني رؤية القائمة، من فضلك؟\"}, {\"original\": \"Разрешено ли добавлять кофе бесплатно?\", \"translated\": \"هل يُسمح بإعادة التعبئة؟\"}, {\"original\": \"Мой кофе уже готов?\", \"translated\": \"هل قهوةُّي جاهزةٌ؟\"}, {\"original\": \"Сколько времени я могу здесь посидеть?\", \"translated\": \"كم من الوقت يمكنني الجلوس هنا؟\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"هل يمكنكم التقاط صورةٍ لنا؟\"}, {\"original\": \"Где туалет?\", \"translated\": \"أين الحمام؟\"}, {\"original\": \"Счёт, пожалуйста. Спасибо.\", \"translated\": \"الفاتورة، من فضلك. شكرًا لكم.\"}, {\"original\": \"Очень вкусно.\", \"translated\": \"إنها تذوق جيدةٌ جدًّا.\"}]', 12, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в ресторане?\", \"Превосходно! Вот 10 распространённых фраз, связанных с рестораном, а также их переводы на французский язык:\"]', '[\"Питание\", \"Заказ\", \"Оформление заказа\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например заказ напитков, жалоба или вопрос об ингредиентах? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Извините, сколько ещё ждать нашу еду?\", \"translated\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\"}, {\"original\": \"Столик на двоих, пожалуйста.\", \"translated\": \"Une table pour deux, s\'il vous plaît.\"}, {\"original\": \"Можно посмотреть меню, пожалуйста?\", \"translated\": \"Pourrions-nous voir la carte, s\'il vous plaît ?\"}, {\"original\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\", \"translated\": \"Avez-vous des plats signature à nous recommander ?\"}, {\"original\": \"Я хочу заказать это и это.\", \"translated\": \"Je voudrais commander ceci et cela.\"}, {\"original\": \"Стакан воды, пожалуйста. Спасибо.\", \"translated\": \"Un verre d\'eau, s\'il vous plaît. Merci.\"}, {\"original\": \"Счёт, пожалуйста.\", \"translated\": \"L\'addition, s\'il vous plaît.\"}, {\"original\": \"Можно оплатить кредитной картой?\", \"translated\": \"Puis-je payer par carte bancaire ?\"}, {\"original\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\", \"translated\": \"Pourriez-vous emballer cela à emporter, s\'il vous plaît ?\"}, {\"original\": \"Еда была восхитительной, спасибо.\", \"translated\": \"Le repas était délicieux, merci.\"}]', 1, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в отеле?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с отелем, а также их переводы на французский язык:\"]', '[\"Регистрация заезда\", \"Регистрация выезда\", \"Обслуживание в номере\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, расположение номера, другие услуги отеля или выезд из отеля? Смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\", \"translated\": \"Bonjour, j’ai une réservation. Voici mon passeport.\"}, {\"original\": \"У вас есть свободные номера?\", \"translated\": \"Avez-vous des chambres disponibles ?\"}, {\"original\": \"Извините, в отеле есть тренажёрный зал или прачечная?\", \"translated\": \"Excusez-moi, l’hôtel dispose-t-il d’une salle de sport ou d’une buanderie ?\"}, {\"original\": \"Во сколько начинается завтрак?\", \"translated\": \"À quelle heure commence le petit-déjeuner ?\"}, {\"original\": \"Можно мне ключ от номера, пожалуйста?\", \"translated\": \"Pourrais-je avoir la clé de ma chambre, s’il vous plaît ?\"}, {\"original\": \"Не могли бы вы помочь мне отнести багаж в номер?\", \"translated\": \"Pourriez-vous m’aider à porter mes bagages jusqu’à ma chambre ?\"}, {\"original\": \"Как вызвать службу обслуживания номеров?\", \"translated\": \"Comment puis-je appeler le service d’étage ?\"}, {\"original\": \"До какого времени необходимо освободить номер?\", \"translated\": \"À quelle heure est la sortie ?\"}, {\"original\": \"Не могли бы вы выписать мне квитанцию/счёт?\", \"translated\": \"Pourriez-vous me délivrer un reçu / une facture ?\"}, {\"original\": \"Можно оставить здесь мой багаж?\", \"translated\": \"Puis-je laisser mes bagages ici ?\"}]', 2, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в аэропорту?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с аэропортом, а также их переводы на французский язык:\"]', '[\"Регистрация на рейс\", \"Посадка на борт\", \"Сдача багажа\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например регистрация на рейс, получение багажа или аренда автомобиля? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Где стойка регистрации?\", \"translated\": \"Où se trouve le comptoir d\'enregistrement ?\"}, {\"original\": \"Я бы хотел место у окна, пожалуйста.\", \"translated\": \"Je voudrais un siège côté fenêtre, s\'il vous plaît.\"}, {\"original\": \"Этот рейс задерживается?\", \"translated\": \"Ce vol est-il retardé ?\"}, {\"original\": \"Мне нужно зарегистрировать этот багаж.\", \"translated\": \"Je dois enregistrer ce bagage.\"}, {\"original\": \"Где выход на посадку?\", \"translated\": \"Où se trouve la porte d\'embarquement ?\"}, {\"original\": \"Самолёт вот-вот взлетит.\", \"translated\": \"L\'avion va bientôt décoller.\"}, {\"original\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\", \"translated\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\"}, {\"original\": \"Где магазин беспошлинной торговли?\", \"translated\": \"Où se trouve la boutique hors taxes ?\"}, {\"original\": \"Я не могу найти свой чемодан.\", \"translated\": \"Je ne trouve pas ma valise.\"}, {\"original\": \"Предоставляется ли услуга инвалидных колясок?\", \"translated\": \"Proposez-vous un service de fauteuil roulant ?\"}]', 3, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в общественном транспорте?\", \"Отлично! Вот 10 распространённых фраз, связанных с общественным транспортом, а также их переводы на французский язык:\"]', '[\"Поездка на автобусе/метро\", \"Покупка билетов\", \"Пересадка\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, спросить о ближайшей остановке автобуса, цене билета или том, как выйти из транспорта? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Этот автобус идёт до конечной остановки?\", \"translated\": \"Ce bus va-t-il jusqu\'à la gare routière ?\"}, {\"original\": \"Какая следующая остановка?\", \"translated\": \"Quel est le prochain arrêt ?\"}, {\"original\": \"Где я могу купить билет?\", \"translated\": \"Où puis-je acheter un billet ?\"}, {\"original\": \"Один билет до XX, пожалуйста.\", \"translated\": \"Un billet pour XX, s\'il vous plaît.\"}, {\"original\": \"Нужно ли мне пересаживаться?\", \"translated\": \"Dois-je changer de transport ?\"}, {\"original\": \"Через сколько прибывает следующий поезд метро?\", \"translated\": \"Combien de temps avant le prochain métro ?\"}, {\"original\": \"Извините, пропустите меня, пожалуйста.\", \"translated\": \"Excusez-moi, laissez-moi passer, s\'il vous plaît.\"}, {\"original\": \"Это место занято?\", \"translated\": \"Cette place est-elle occupée ?\"}, {\"original\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\", \"translated\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d\'aller à XX ?\"}, {\"original\": \"Как мне добраться до XX?\", \"translated\": \"Comment puis-je me rendre à XX ?\"}]', 4, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать на туристических объектах?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с туристическими объектами, а также их переводы на французский язык:\"]', '[\"Осмотр достопримечательностей\", \"Фотографирование\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас в голове есть какая-то конкретная ситуация, например, вопрос о цене билетов, поиск парковочного места или услуг гида? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас возникла.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"Combien coûte l\'entrée ?\"}, {\"original\": \"Есть ли льготные билеты для студентов?\", \"translated\": \"Y a-t-il des billets étudiants disponibles ?\"}, {\"original\": \"Во сколько открывается достопримечательность?\", \"translated\": \"À quelle heure ouvre l\'attraction ?\"}, {\"original\": \"Чем здесь интересно заняться?\", \"translated\": \"Quelles sont les activités amusantes à faire ici ?\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"Где автобус для осмотра достопримечательностей?\", \"translated\": \"Où se trouve le bus touristique ?\"}, {\"original\": \"Где находится туалет?\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"Где лучшее место для просмотра?\", \"translated\": \"Quel est le meilleur point de vue ?\"}, {\"original\": \"Здесь прекрасный вид.\", \"translated\": \"Le paysage est magnifique ici.\"}, {\"original\": \"Доступна ли экскурсия с гидом?\", \"translated\": \"Une visite guidée est-elle disponible ?\"}]', 5, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать при заказе такси или пользовании услугами такси?\", \"Отлично! Вот 10 распространённых фраз, связанных с такси или услугами такси, а также их переводы на французский язык:\"]', '[\"Вызов такси\", \"Указание места назначения\", \"Оплата\"]', 'ru', '[\"Пока что: что вы сейчас больше всего хотите сделать — уточнить пункт назначения, узнать стоимость поездки или запросить счёт? Свободно задавайте любые вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас возникла в воображении.\"]', NULL, '[{\"original\": \"Где я могу взять такси?\", \"translated\": \"Où puis-je prendre un taxi ?\"}, {\"original\": \"Пожалуйста, отвезите меня по этому адресу.\", \"translated\": \"Veuillez me conduire à cette adresse.\"}, {\"original\": \"Примерно сколько это будет стоить?\", \"translated\": \"Combien cela coûtera-t-il approximativement ?\"}, {\"original\": \"Не могли бы вы, пожалуйста, включить счётчик?\", \"translated\": \"Pourriez-vous utiliser le compteur, s’il vous plaît ?\"}, {\"original\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\", \"translated\": \"Pourriez-vous conduire un peu plus vite, je suis pressé(e).\"}, {\"original\": \"Остановитесь, пожалуйста, здесь.\", \"translated\": \"Veuillez vous arrêter ici.\"}, {\"original\": \"Принимаете ли вы оплату картой или через мобильные платежи?\", \"translated\": \"Acceptez-vous les cartes bancaires ou les paiements mobiles ?\"}, {\"original\": \"Можно мне, пожалуйста, чек?\", \"translated\": \"Pourrais-je avoir un reçu, s’il vous plaît ?\"}, {\"original\": \"Спасибо, водитель.\", \"translated\": \"Merci, monsieur/madame le chauffeur.\"}, {\"original\": \"Как далеко ещё?\", \"translated\": \"Combien de temps reste-t-il avant d’arriver ?\"}]', 6, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в аптеке?\", \"Превосходно! Вот 10 распространённых фраз, связанных с аптекой, а также их переводы на французский язык:\"]', '[\"Покупка лекарств\", \"Консультация\", \"Оплата\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, запрос инструкций по приёму лекарств, фразы, связанные с использованием страхования, продолжительностью приёма лекарств? Свободно задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас возникла в уме.\"]', NULL, '[{\"original\": \"У вас есть лекарство от простуды?\", \"translated\": \"Avez-vous des médicaments contre le rhume ?\"}, {\"original\": \"Как мне принимать это лекарство?\", \"translated\": \"Comment dois-je prendre ce médicament ?\"}, {\"original\": \"У вас есть обезболивающие?\", \"translated\": \"Avez-vous des analgésiques ?\"}, {\"original\": \"Есть ли инструкция по применению?\", \"translated\": \"Y a-t-il une notice d’instructions ?\"}, {\"original\": \"Это лекарство имеет какие-либо побочные эффекты?\", \"translated\": \"Ce médicament a-t-il des effets secondaires ?\"}, {\"original\": \"Можно ли воспользоваться моей медицинской страховой картой?\", \"translated\": \"Puis-je utiliser ma carte d’assurance maladie ?\"}, {\"original\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\", \"translated\": \"Pourriez-vous me donner une boîte de pansements, s’il vous plaît ?\"}, {\"original\": \"У вас есть жаропонижающие?\", \"translated\": \"Avez-vous des antipyrétiques ?\"}, {\"original\": \"Я немного поранился. У вас есть антисептик и пластыри?\", \"translated\": \"Je me suis un peu écorché. Avez-vous un antiseptique et des pansements ?\"}, {\"original\": \"Во сколько вы закрываетесь?\", \"translated\": \"À quelle heure fermez-vous ?\"}]', 7, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в службах экстренной помощи?\", \"Отлично! Вот 10 распространённых фраз, связанных со службами экстренной помощи, а также их переводы на французский язык:\"]', '[\"Вызов полиции\", \"Первая помощь\", \"Вызов на помощь\"]', 'ru', '[\"Пока что: у вас на уме какая-то конкретная чрезвычайная ситуация, например пожар, травма и необходимость помощи, экстренный вызов — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Пожалуйста, помогите мне вызвать скорую помощь.\", \"translated\": \"Veuillez m\'aider à appeler une ambulance.\"}, {\"original\": \"Где находится больница?\", \"translated\": \"Où se trouve l\'hôpital ?\"}, {\"original\": \"Кто-то получил травму.\", \"translated\": \"Quelqu\'un est blessé.\"}, {\"original\": \"Пожалуйста, помогите мне.\", \"translated\": \"Veuillez m\'aider.\"}, {\"original\": \"Где находится полицейский участок?\", \"translated\": \"Où se trouve le commissariat ?\"}, {\"original\": \"Я потерял свои вещи.\", \"translated\": \"J\'ai perdu mes affaires.\"}, {\"original\": \"Какой номер пожарной службы?\", \"translated\": \"Quel est le numéro des pompiers ?\"}, {\"original\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\", \"translated\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le commissariat le plus proche ?\"}, {\"original\": \"Здесь есть аварийный выход?\", \"translated\": \"Y a-t-il une sortie de secours ?\"}, {\"original\": \"Кто-то потерял сознание.\", \"translated\": \"Quelqu\'un s\'est évanoui.\"}]', 8, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на пляже или у бассейна?\", \"Превосходно! Вот 10 распространённых фраз, связанных с пляжем или бассейном, а также их переводы на французский язык:\"]', '[\"Плавание\", \"Загар\", \"Пляжные виды спорта\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного события или фестиваля, в котором вы участвуете, например, культурного фестиваля, гастрономического фестиваля или музыкального фестиваля? Пожалуйста, укажите контекст.\", \"Пожалуйста, опишите мероприятия, в которых вы участвуете.\"]', '[\"У вас есть конкретная ситуация в уме? Смело задавайте вопрос.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', '[{\"original\": \"Смотрите! Волны там действительно очень большие.\", \"translated\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\"}, {\"original\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\", \"translated\": \"N\'oubliez pas d\'appliquer de la crème solaire, les rayons UV sont très intenses ici.\"}, {\"original\": \"Песок на этом пляже такой мелкий, что идти по нему — всё равно что ступать по хлопку.\", \"translated\": \"Le sable de cette plage est si fin qu\'on a l\'impression de marcher sur du coton.\"}, {\"original\": \"Как насчёт игры в волейбол на пляже?\", \"translated\": \"Et si on jouait au volley-ball sur la plage ?\"}, {\"original\": \"Парусники вдали выглядят очень красиво.\", \"translated\": \"Les voiliers au loin sont magnifiques.\"}, {\"original\": \"Вода здесь такая прозрачная, что даже рыбок можно разглядеть.\", \"translated\": \"L\'eau est tellement claire ici qu\'on peut même voir les poissons.\"}, {\"original\": \"Давайте пойдём собирать морские ракушки.\", \"translated\": \"Allons chercher des coquillages.\"}, {\"original\": \"Прогулка по пляжу на закате, наверное, очень романтична.\", \"translated\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\"}, {\"original\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\", \"translated\": \"J\'ai entendu dire que les fruits de mer sont très frais ici, allons-en goûter.\"}, {\"original\": \"Начинается прилив, давайте вернёмся к берегу.\", \"translated\": \"La marée monte, dirigeons-nous vers la rive.\"}]', 9, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на местных мероприятиях и фестивалях?\", \"Превосходно! Вот 10 распространённых фраз, связанных с местными мероприятиями и фестивалями, а также их переводы на французский язык:\"]', '[\"Посещение мероприятий\", \"Празднование фестивалей\", \"Изучение культуры\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного мероприятия или фестиваля, на который вы собираетесь пойти: Хэллоуин, концерт, вечеринка у друзей или что-то ещё? Пожалуйста, укажите контекст.\", \"Опишите, пожалуйста, те виды деятельности, которые приходят вам на ум.\"]', '[\"У вас есть конкретная ситуация в уме? Свободно задавайте вопрос.\", \"Опишите, пожалуйста, ситуацию, которая приходит вам на ум.\"]', '[{\"original\": \"Есть ли сегодня какие-нибудь мероприятия?\", \"translated\": \"Y a-t-il des événements aujourd\'hui ?\"}, {\"original\": \"В чём особенность этого праздника?\", \"translated\": \"Y a-t-il quelque chose de particulier à propos de ce festival ?\"}, {\"original\": \"Где проходит празднование?\", \"translated\": \"Où se déroule la célébration ?\"}, {\"original\": \"Как я могу купить билеты?\", \"translated\": \"Comment puis-je acheter des billets ?\"}, {\"original\": \"Во сколько начинается представление?\", \"translated\": \"À quelle heure commence la représentation ?\"}, {\"original\": \"Какая традиционная еда здесь есть?\", \"translated\": \"Quels sont les plats traditionnels ?\"}, {\"original\": \"Здесь действительно оживлённо.\", \"translated\": \"C\'est vraiment animé ici.\"}, {\"original\": \"Есть ли народные мероприятия?\", \"translated\": \"Y a-t-il des activités folkloriques ?\"}, {\"original\": \"С праздником!\", \"translated\": \"Joyeuses fêtes !\"}, {\"original\": \"Во сколько заканчивается мероприятие?\", \"translated\": \"À quelle heure se termine l\'événement ?\"}]', 10, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в музее или художественной галерее?\", \"Превосходно! Вот 10 распространённых фраз, связанных с музеем или художественной галереей, а также их переводы на французский язык:\"]', '[\"Посещение\", \"Экскурсия\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, просьба о руководстве по посещению, фразы, связанные с маршрутом посетителя, фразы, связанные с комментариями к экспонатам? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"Quel est le montant des frais d\'entrée ?\"}, {\"original\": \"У вас есть аудиогиды?\", \"translated\": \"Proposez-vous des guides audio ?\"}, {\"original\": \"Кто создал это произведение искусства?\", \"translated\": \"Qui est l\'auteur de cette œuvre ?\"}, {\"original\": \"Где находится самая ценная экспозиция музея?\", \"translated\": \"Où se trouve la pièce la plus précieuse du musée ?\"}, {\"original\": \"Разрешена ли фотосъёмка?\", \"translated\": \"La photographie est-elle autorisée ?\"}, {\"original\": \"Здесь проходят какие-нибудь специальные выставки?\", \"translated\": \"Y a-t-il des expositions spéciales ici ?\"}, {\"original\": \"Сколько времени занимает посещение?\", \"translated\": \"Combien de temps dure la visite ?\"}, {\"original\": \"Не могли бы вы кратко рассказать об экспозиции?\", \"translated\": \"Pourriez-vous nous en faire une brève présentation ?\"}, {\"original\": \"Эти произведения действительно изысканны.\", \"translated\": \"Ces œuvres sont véritablement exquises.\"}, {\"original\": \"Где находится магазин сувениров?\", \"translated\": \"Où se trouve la boutique de souvenirs ?\"}]', 11, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в кафе?\", \"Превосходно! Вот 10 распространённых фраз, связанных с кафе, а также их переводы на французский язык:\"]', '[\"Заказ кофе\", \"Отдых\", \"Общение\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например, запрос меню, прохладительных или горячих напитков, других товаров? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Я возьму латте, пожалуйста.\", \"translated\": \"Je prendrai un latte, s’il vous plaît.\"}, {\"original\": \"У вас есть Wi-Fi?\", \"translated\": \"Avez-vous le Wi-Fi ?\"}, {\"original\": \"Можно мне посмотреть меню, пожалуйста?\", \"translated\": \"Pourrais-je voir la carte, s’il vous plaît ?\"}, {\"original\": \"Дополнительная порция кофе разрешена?\", \"translated\": \"Les recharges sont-elles autorisées ?\"}, {\"original\": \"Мой кофе уже готов?\", \"translated\": \"Mon café est-il prêt ?\"}, {\"original\": \"Сколько времени я могу здесь посидеть?\", \"translated\": \"Combien de temps puis-je rester assis ici ?\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"Где находится туалет?\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"Счёт, пожалуйста. Спасибо.\", \"translated\": \"L’addition, s’il vous plaît. Merci.\"}, {\"original\": \"Очень вкусно.\", \"translated\": \"C’est vraiment délicieux.\"}]', 12, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в ресторане?\", \"Отлично! Вот 10 распространённых фраз, связанных с рестораном, а также их переводы на немецкий язык:\"]', '[\"Питание\", \"Заказ\", \"Оформление заказа\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация на уме, например заказ напитков, жалоба или вопрос об ингредиентах? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Извините, сколько ещё ждать нашу еду?\", \"translated\": \"Entschuldigung, wie lange dauert es noch bis zu unserem Essen?\"}, {\"original\": \"Столик на двоих, пожалуйста.\", \"translated\": \"Ein Tisch für zwei Personen, bitte.\"}, {\"original\": \"Можно посмотреть меню, пожалуйста?\", \"translated\": \"Könnten wir bitte die Speisekarte sehen?\"}, {\"original\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\", \"translated\": \"Haben Sie empfehlenswerte Hausgerichte?\"}, {\"original\": \"Я хочу заказать это и это.\", \"translated\": \"Ich möchte dies hier und das hier bestellen.\"}, {\"original\": \"Стакан воды, пожалуйста. Спасибо.\", \"translated\": \"Ein Glas Wasser, bitte. Danke.\"}, {\"original\": \"Счёт, пожалуйста.\", \"translated\": \"Die Rechnung, bitte.\"}, {\"original\": \"Можно оплатить кредитной картой?\", \"translated\": \"Kann ich mit Kreditkarte bezahlen?\"}, {\"original\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\", \"translated\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\"}, {\"original\": \"Еда была восхитительной, спасибо.\", \"translated\": \"Das Essen war köstlich, vielen Dank.\"}]', 1, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в отеле?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с отелем, а также их переводы на немецкий язык:\"]', '[\"Регистрация заезда\", \"Регистрация выезда\", \"Обслуживание в номере\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация в уме, например, расположение номера, другие услуги отеля или выезд из отеля — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\", \"translated\": \"Hallo, ich habe eine Reservierung. Hier ist mein Pass.\"}, {\"original\": \"У вас есть свободные номера?\", \"translated\": \"Haben Sie noch freie Zimmer?\"}, {\"original\": \"Извините, в отеле есть тренажёрный зал или прачечная?\", \"translated\": \"Entschuldigung, verfügt das Hotel über ein Fitnessstudio oder einen Waschraum?\"}, {\"original\": \"Во сколько начинается завтрак?\", \"translated\": \"Wann beginnt das Frühstück?\"}, {\"original\": \"Можно мне ключ от номера, пожалуйста?\", \"translated\": \"Könnte ich bitte den Zimmerschlüssel haben?\"}, {\"original\": \"Не могли бы вы помочь мне отнести багаж в номер?\", \"translated\": \"Könnten Sie mir beim Tragen meines Gepäcks auf das Zimmer helfen?\"}, {\"original\": \"Как вызвать службу обслуживания номеров?\", \"translated\": \"Wie rufe ich den Zimmerservice an?\"}, {\"original\": \"До какого времени необходимо освободить номер?\", \"translated\": \"Wann ist der Check-out?\"}, {\"original\": \"Не могли бы вы выписать мне квитанцию/счёт?\", \"translated\": \"Könnten Sie mir bitte eine Quittung / Rechnung ausstellen?\"}, {\"original\": \"Можно оставить здесь мой багаж?\", \"translated\": \"Darf ich mein Gepäck hier lassen?\"}]', 2, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в аэропорту?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с аэропортом, а также их переводы на немецкий язык:\"]', '[\"Регистрация на рейс\", \"Посадка на борт\", \"Сдача багажа\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация в уме, например регистрация на рейс, получение багажа или аренда автомобиля? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Где стойка регистрации?\", \"translated\": \"Wo ist der Check-in-Schalter?\"}, {\"original\": \"Я бы хотел место у окна, пожалуйста.\", \"translated\": \"Ich hätte gerne einen Fensterplatz.\"}, {\"original\": \"Этот рейс задерживается?\", \"translated\": \"Ist dieser Flug verspätet?\"}, {\"original\": \"Мне нужно зарегистрировать этот багаж.\", \"translated\": \"Ich muss dieses Gepäck aufgeben.\"}, {\"original\": \"Где выход на посадку?\", \"translated\": \"Wo ist das Boarding-Gate?\"}, {\"original\": \"Самолёт вот-вот взлетит.\", \"translated\": \"Das Flugzeug startet gleich.\"}, {\"original\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\", \"translated\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\"}, {\"original\": \"Где магазин беспошлинной торговли?\", \"translated\": \"Wo ist der Duty-free-Shop?\"}, {\"original\": \"Я не могу найти свой чемодан.\", \"translated\": \"Ich kann meinen Koffer nicht finden.\"}, {\"original\": \"Предоставляется ли услуга инвалидных колясок?\", \"translated\": \"Bieten Sie einen Rollstuhlservice an?\"}]', 3, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в общественном транспорте?\", \"Отлично! Вот 10 распространённых фраз, связанных с общественным транспортом, а также их переводы на немецкий язык:\"]', '[\"Поездка на автобусе/метро\", \"Покупка билетов\", \"Пересадка\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация в уме, например, спросить о месте остановки автобуса, цене билета или выходе из транспорта — смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Этот автобус идёт до автовокзала?\", \"translated\": \"Fährt dieser Bus zum Terminal?\"}, {\"original\": \"Какая следующая остановка?\", \"translated\": \"Was ist die nächste Haltestelle?\"}, {\"original\": \"Где я могу купить билет?\", \"translated\": \"Wo kann ich ein Ticket kaufen?\"}, {\"original\": \"Один билет до XX, пожалуйста.\", \"translated\": \"Ein Ticket nach XX, bitte.\"}, {\"original\": \"Нужно ли мне пересаживаться?\", \"translated\": \"Muss ich umsteigen?\"}, {\"original\": \"Через сколько прибудет следующий поезд метро?\", \"translated\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\"}, {\"original\": \"Извините, пропустите меня, пожалуйста.\", \"translated\": \"Entschuldigung, bitte lassen Sie mich durch.\"}, {\"original\": \"Это место занято?\", \"translated\": \"Ist dieser Platz bereits besetzt?\"}, {\"original\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\", \"translated\": \"Entschuldigung, wo kann ich umsteigen, um mit der Linie 2 nach XX zu gelangen?\"}, {\"original\": \"Как мне добраться до XX?\", \"translated\": \"Wie komme ich nach XX?\"}]', 4, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на туристических объектах?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с туристическими объектами, а также их переводы на немецкий язык:\"]', '[\"Осмотр достопримечательностей\", \"Фотографирование\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, вопрос о цене билетов, поиск парковочного места или услуг гида? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"Есть ли льготные билеты для студентов?\", \"translated\": \"Gibt es ermäßigte Eintrittskarten für Schüler?\"}, {\"original\": \"Во сколько открывается достопримечательность?\", \"translated\": \"Wann öffnet die Sehenswürdigkeit?\"}, {\"original\": \"Чем здесь можно интересно заняться?\", \"translated\": \"Was gibt es hier Spannendes zu tun?\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"Где автобус для осмотра достопримечательностей?\", \"translated\": \"Wo befindet sich der Sightseeing-Bus?\"}, {\"original\": \"Где находится туалет?\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"Где лучшее место для просмотра?\", \"translated\": \"Wo ist der beste Aussichtspunkt?\"}, {\"original\": \"Здесь прекрасные виды.\", \"translated\": \"Die Landschaft hier ist wunderschön.\"}, {\"original\": \"Доступна ли экскурсия с гидом?\", \"translated\": \"Gibt es eine geführte Tour?\"}]', 5, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать при заказе такси или пользовании услугами такси?\", \"Отлично! Вот 10 распространённых фраз, связанных с такси или услугами такси, а также их переводы на немецкий язык:\"]', '[\"Вызов такси\", \"Указание места назначения\", \"Оплата\"]', 'ru', '[\"Пока что: что вы сейчас больше всего хотите сделать — уточнить пункт назначения, спросить цену или запросить счёт? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас возникает в воображении.\"]', NULL, '[{\"original\": \"Где я могу взять такси?\", \"translated\": \"Wo kann ich ein Taxi bekommen?\"}, {\"original\": \"Пожалуйста, отвезите меня по этому адресу.\", \"translated\": \"Bitte fahren Sie mich zu dieser Adresse.\"}, {\"original\": \"Примерно сколько это будет стоить?\", \"translated\": \"Wie viel kostet es ungefähr?\"}, {\"original\": \"Не могли бы вы, пожалуйста, включить счётчик?\", \"translated\": \"Könnten Sie bitte den Taxameter benutzen?\"}, {\"original\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\", \"translated\": \"Bitte fahren Sie etwas schneller, ich habe es eilig.\"}, {\"original\": \"Остановитесь, пожалуйста, здесь.\", \"translated\": \"Bitte halten Sie hier an.\"}, {\"original\": \"Принимаете ли вы оплату картой или через мобильные платежи?\", \"translated\": \"Akzeptieren Sie Karten oder mobile Zahlungen?\"}, {\"original\": \"Можно мне, пожалуйста, чек?\", \"translated\": \"Könnte ich bitte eine Quittung haben?\"}, {\"original\": \"Спасибо, водитель.\", \"translated\": \"Vielen Dank, Fahrer.\"}, {\"original\": \"Как далеко ещё?\", \"translated\": \"Wie weit ist es noch?\"}]', 6, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в аптеке?\", \"Превосходно! Вот 10 распространённых фраз, связанных с аптекой, а также их переводы на немецкий язык:\"]', '[\"Покупка лекарств\", \"Консультация\", \"Оплата\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация в голове, например, запрос инструкций по приёму лекарств, фразы, связанные с использованием страхования, продолжительностью приёма лекарств — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в голове.\"]', NULL, '[{\"original\": \"У вас есть лекарство от простуды?\", \"translated\": \"Haben Sie Medikamente gegen Erkältung?\"}, {\"original\": \"Как мне принимать это лекарство?\", \"translated\": \"Wie soll ich dieses Medikament einnehmen?\"}, {\"original\": \"У вас есть обезболивающие?\", \"translated\": \"Haben Sie Schmerzmittel?\"}, {\"original\": \"Есть ли инструкция по применению?\", \"translated\": \"Gibt es eine Gebrauchsanweisung?\"}, {\"original\": \"Это лекарство имеет какие-либо побочные эффекты?\", \"translated\": \"Hat dieses Medikament Nebenwirkungen?\"}, {\"original\": \"Можно ли воспользоваться моей медицинской страховкой?\", \"translated\": \"Kann ich meine Krankenversicherungskarte verwenden?\"}, {\"original\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\", \"translated\": \"Könnte ich bitte eine Packung Pflaster haben?\"}, {\"original\": \"У вас есть жаропонижающие?\", \"translated\": \"Haben Sie Fiebersenkende Mittel?\"}, {\"original\": \"Я немного поранился. У вас есть антисептик и пластыри?\", \"translated\": \"Ich habe mir leicht die Haut aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\"}, {\"original\": \"Во сколько вы закрываетесь?\", \"translated\": \"Wann schließen Sie?\"}]', 7, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в службах экстренной помощи?\", \"Превосходно! Вот 10 распространённых фраз, связанных со службами экстренной помощи, а также их переводы на немецкий язык:\"]', '[\"Вызов полиции\", \"Первая помощь\", \"Вызов на помощь\"]', 'ru', '[\"Пока что: у вас на уме какая-то конкретная чрезвычайная ситуация, например пожар, травма и необходимость помощи, экстренный вызов — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Пожалуйста, помогите мне вызвать скорую помощь.\", \"translated\": \"Bitte helfen Sie mir, einen Krankenwagen zu rufen.\"}, {\"original\": \"Где находится больница?\", \"translated\": \"Wo ist das Krankenhaus?\"}, {\"original\": \"Кто-то получил травму.\", \"translated\": \"Jemand ist verletzt.\"}, {\"original\": \"Пожалуйста, помогите мне.\", \"translated\": \"Bitte helfen Sie mir.\"}, {\"original\": \"Где находится полицейский участок?\", \"translated\": \"Wo ist die Polizeistation?\"}, {\"original\": \"Я потерял свои вещи.\", \"translated\": \"Ich habe meine Sachen verloren.\"}, {\"original\": \"Какой номер пожарной службы?\", \"translated\": \"Wie lautet die Notrufnummer für die Feuerwehr?\"}, {\"original\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\", \"translated\": \"Ich habe meinen Pass verloren. Wissen Sie, wo die nächste Polizeistation ist?\"}, {\"original\": \"Здесь есть аварийный выход?\", \"translated\": \"Gibt es einen Notausgang?\"}, {\"original\": \"Кто-то потерял сознание.\", \"translated\": \"Jemand ist in Ohnmacht gefallen.\"}]', 8, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на пляже или у бассейна?\", \"Превосходно! Вот 10 распространённых фраз, связанных с пляжем или бассейном, а также их переводы на немецкий язык:\"]', '[\"Плавание\", \"Загар\", \"Пляжные виды спорта\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного мероприятия или фестиваля, в котором вы участвуете: культурный фестиваль, гастрономический фестиваль или музыкальный фестиваль? Пожалуйста, укажите контекст.\", \"Пожалуйста, опишите мероприятия, в которых вы участвуете.\"]', '[\"У вас есть конкретная ситуация в уме? Смело задавайте вопрос.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', '[{\"original\": \"Смотрите! Волны там действительно огромные.\", \"translated\": \"Schau! Die Wellen dort drüben sind wirklich groß.\"}, {\"original\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\", \"translated\": \"Vergiss nicht, Sonnencreme aufzutragen – die UV-Strahlen sind hier sehr stark.\"}, {\"original\": \"Песок на этом пляже такой мелкий, что идти по нему — всё равно что ступать по хлопку.\", \"translated\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle gehen.\"}, {\"original\": \"Как насчёт игры в волейбол на пляже?\", \"translated\": \"Wie wäre es mit einem Volleyballspiel am Strand?\"}, {\"original\": \"Парусники вдали выглядят очень красиво.\", \"translated\": \"Die Segelboote in der Ferne sehen wunderschön aus.\"}, {\"original\": \"Вода здесь такая прозрачная, что даже рыбок видно.\", \"translated\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\"}, {\"original\": \"Давайте пойдём собирать морские ракушки.\", \"translated\": \"Lass uns Muscheln suchen.\"}, {\"original\": \"Прогулка по пляжу на закате, наверное, очень романтична.\", \"translated\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\"}, {\"original\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\", \"translated\": \"Ich habe gehört, dass die Meeresfrüchte hier sehr frisch sind – lass uns welche probieren.\"}, {\"original\": \"Начинается прилив, давайте вернёмся к берегу.\", \"translated\": \"Die Flut kommt näher, gehen wir zum Ufer zurück.\"}]', 9, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на местных мероприятиях и праздниках?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с местными мероприятиями и праздниками, а также их переводы на немецкий язык:\"]', '[\"Посещение мероприятий\", \"Празднование фестивалей\", \"Изучение культуры\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного мероприятия или праздника, на который вы собираетесь пойти: Хэллоуин, концерт, вечеринка у друга или что-то ещё? Пожалуйста, укажите контекст.\", \"Опишите, пожалуйста, те мероприятия, которые приходят вам на ум.\"]', '[\"У вас есть конкретная ситуация на уме? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая приходит вам на ум.\"]', '[{\"original\": \"Есть ли сегодня какие-нибудь мероприятия?\", \"translated\": \"Gibt es heute irgendwelche Veranstaltungen?\"}, {\"original\": \"В этом празднике есть что-нибудь особенное?\", \"translated\": \"Gibt es bei diesem Fest etwas Besonderes?\"}, {\"original\": \"Где проходит празднование?\", \"translated\": \"Wo findet die Feier statt?\"}, {\"original\": \"Как я могу купить билеты?\", \"translated\": \"Wie kann ich Tickets kaufen?\"}, {\"original\": \"Во сколько начинается представление?\", \"translated\": \"Wann beginnt die Aufführung?\"}, {\"original\": \"Какая традиционная еда здесь есть?\", \"translated\": \"Welche traditionellen Speisen gibt es?\"}, {\"original\": \"Здесь действительно очень оживлённо.\", \"translated\": \"Es ist hier wirklich lebhaft.\"}, {\"original\": \"Есть ли какие-нибудь народные мероприятия?\", \"translated\": \"Gibt es Volksaktivitäten?\"}, {\"original\": \"Счастливых праздников!\", \"translated\": \"Frohe Feiertage!\"}, {\"original\": \"Во сколько заканчивается мероприятие?\", \"translated\": \"Wann endet die Veranstaltung?\"}]', 10, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в музее или художественной галерее?\", \"Превосходно! Вот 10 распространённых фраз, связанных с музеем или художественной галереей, а также их переводы на немецкий язык:\"]', '[\"Посещение\", \"Экскурсия\", \"Покупка билетов\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация в уме, например, просьба о вводном буклете, фразы, связанные с маршрутом посетителя, фразы, связанные с комментариями к экспонатам — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"У вас есть аудиогиды?\", \"translated\": \"Bieten Sie Audioführungen an?\"}, {\"original\": \"Кто создал это произведение искусства?\", \"translated\": \"Wer hat dieses Kunstwerk geschaffen?\"}, {\"original\": \"Где находится самая ценная экспонат музея?\", \"translated\": \"Wo befindet sich das wertvollste Stück des Museums?\"}, {\"original\": \"Разрешена ли фотосъёмка?\", \"translated\": \"Ist Fotografieren erlaubt?\"}, {\"original\": \"Здесь проходят какие-нибудь специальные выставки?\", \"translated\": \"Gibt es hier besondere Ausstellungen?\"}, {\"original\": \"Сколько времени занимает посещение?\", \"translated\": \"Wie lange dauert der Besuch?\"}, {\"original\": \"Не могли бы вы представить нам краткое введение?\", \"translated\": \"Könnten Sie uns bitte eine Einführung geben?\"}, {\"original\": \"Эти произведения действительно изысканны.\", \"translated\": \"Diese Werke sind wirklich exquisit.\"}, {\"original\": \"Где находится магазин сувениров?\", \"translated\": \"Wo befindet sich der Souvenirladen?\"}]', 11, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в кафе?\", \"Отлично! Вот 10 распространённых фраз, связанных с кафе, а также их переводы на немецкий язык:\"]', '[\"Заказ кофе\", \"Отдых\", \"Общение\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация в уме, например, запрос меню, льда или горячих напитков, других товаров? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Я возьму латте, пожалуйста.\", \"translated\": \"Ich hätte gerne einen Latte, bitte.\"}, {\"original\": \"У вас есть Wi-Fi?\", \"translated\": \"Haben Sie WLAN?\"}, {\"original\": \"Можно мне посмотреть меню, пожалуйста?\", \"translated\": \"Könnte ich bitte die Speisekarte sehen?\"}, {\"original\": \"Разрешено ли добавлять кофе бесплатно?\", \"translated\": \"Dürfen Nachfüllungen gemacht werden?\"}, {\"original\": \"Мой кофе уже готов?\", \"translated\": \"Ist mein Kaffee fertig?\"}, {\"original\": \"Сколько времени я могу здесь посидеть?\", \"translated\": \"Wie lange darf ich hier sitzen?\"}, {\"original\": \"Не могли бы вы сделать нам фотографию?\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"Где туалет?\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"Счёт, пожалуйста. Спасибо.\", \"translated\": \"Die Rechnung, bitte. Vielen Dank.\"}, {\"original\": \"Очень вкусно.\", \"translated\": \"Es schmeckt wirklich gut.\"}]', 12, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в ресторане?\", \"Превосходно! Вот 10 распространённых фраз, связанных с рестораном, а также их переводы на испанский язык:\"]', '[\"Питание\", \"Заказ\", \"Оформление заказа\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация на уме, например заказ напитков, жалоба или вопрос об ингредиентах? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Извините, сколько ещё ждать нашу еду?\", \"translated\": \"Disculpe, ¿cuánto tiempo más tardará nuestra comida?\"}, {\"original\": \"Столик на двоих, пожалуйста.\", \"translated\": \"Una mesa para dos, por favor.\"}, {\"original\": \"Можно посмотреть меню, пожалуйста?\", \"translated\": \"¿Podríamos ver el menú, por favor?\"}, {\"original\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\", \"translated\": \"¿Tienen algún plato especial que nos recomiende?\"}, {\"original\": \"Я хочу заказать это и это.\", \"translated\": \"Quisiera pedir esto y esto.\"}, {\"original\": \"Стакан воды, пожалуйста. Спасибо.\", \"translated\": \"Un vaso de agua, por favor. Gracias.\"}, {\"original\": \"Счёт, пожалуйста.\", \"translated\": \"La cuenta, por favor.\"}, {\"original\": \"Можно оплатить кредитной картой?\", \"translated\": \"¿Puedo pagar con tarjeta de crédito?\"}, {\"original\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\", \"translated\": \"¿Podría empaquetar esto para llevar, por favor?\"}, {\"original\": \"Еда была восхитительной, спасибо.\", \"translated\": \"La comida estaba deliciosa, gracias.\"}]', 1, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в отеле?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с отелем, а также их переводы на испанский язык:\"]', '[\"Регистрация заезда\", \"Регистрация выезда\", \"Обслуживание в номере\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация в уме, например, расположение номера, другие услуги отеля или выезд из отеля? Смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас есть в виду.\"]', NULL, '[{\"original\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\", \"translated\": \"Hola, tengo una reserva. Aquí tiene mi pasaporte.\"}, {\"original\": \"У вас есть свободные номера?\", \"translated\": \"¿Tienen habitaciones disponibles?\"}, {\"original\": \"Извините, в отеле есть тренажёрный зал или прачечная?\", \"translated\": \"Disculpe, ¿tiene el hotel gimnasio o lavandería?\"}, {\"original\": \"Во сколько начинается завтрак?\", \"translated\": \"¿A qué hora comienza el desayuno?\"}, {\"original\": \"Можно мне ключ от номера, пожалуйста?\", \"translated\": \"¿Podría darme la llave de la habitación, por favor?\"}, {\"original\": \"Не могли бы вы помочь мне отнести багаж в номер?\", \"translated\": \"¿Podría ayudarme a llevar mi equipaje a la habitación?\"}, {\"original\": \"Как вызвать службу обслуживания номеров?\", \"translated\": \"¿Cómo llamo al servicio de habitaciones?\"}, {\"original\": \"До какого времени необходимо освободить номер?\", \"translated\": \"¿A qué hora es la salida?\"}, {\"original\": \"Не могли бы вы выписать мне квитанцию/счёт?\", \"translated\": \"¿Podría emitirme un recibo/factura?\"}, {\"original\": \"Можно оставить здесь мой багаж?\", \"translated\": \"¿Puedo dejar aquí mi equipaje?\"}]', 2, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в аэропорту?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с аэропортом, а также их переводы на испанский язык:\"]', '[\"Регистрация на рейс\", \"Посадка на борт\", \"Сдача багажа\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например регистрация на рейс, получение багажа или аренда автомобиля? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Где стойка регистрации?\", \"translated\": \"¿Dónde está el mostrador de facturación?\"}, {\"original\": \"Я бы хотел место у окна, пожалуйста.\", \"translated\": \"Me gustaría un asiento junto a la ventana, por favor.\"}, {\"original\": \"Этот рейс задерживается?\", \"translated\": \"¿Este vuelo tiene retraso?\"}, {\"original\": \"Мне нужно зарегистрировать этот багаж.\", \"translated\": \"Necesito facturar este equipaje.\"}, {\"original\": \"Где выход на посадку?\", \"translated\": \"¿Dónde está la puerta de embarque?\"}, {\"original\": \"Самолёт вот-вот взлетит.\", \"translated\": \"El avión está a punto de despegar.\"}, {\"original\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\", \"translated\": \"¿Tengo que sacar mi ordenador portátil y mi power bank?\"}, {\"original\": \"Где магазин беспошлинной торговли?\", \"translated\": \"¿Dónde está la tienda libre de impuestos?\"}, {\"original\": \"Я не могу найти свой чемодан.\", \"translated\": \"No encuentro mi maleta.\"}, {\"original\": \"Предоставляется ли услуга инвалидных колясок?\", \"translated\": \"¿Ofrecen servicio de sillas de ruedas?\"}]', 3, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в общественном транспорте?\", \"Превосходно! Вот 10 распространённых фраз, связанных с общественным транспортом, а также их переводы на испанский язык:\"]', '[\"Поездка на автобусе/метро\", \"Покупка билетов\", \"Пересадка\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, спросить о ближайшей остановке автобуса, цене билета или выходе из транспорта? Свободно задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Этот автобус идёт до автовокзала?\", \"translated\": \"¿Este autobús va a la terminal?\"}, {\"original\": \"Какая следующая остановка?\", \"translated\": \"¿Cuál es la próxima parada?\"}, {\"original\": \"Где я могу купить билет?\", \"translated\": \"¿Dónde puedo comprar un billete?\"}, {\"original\": \"Один билет до XX, пожалуйста.\", \"translated\": \"Un billete para XX, por favor.\"}, {\"original\": \"Нужно ли мне пересаживаться?\", \"translated\": \"¿Tengo que hacer transbordo?\"}, {\"original\": \"Через сколько прибудет следующий поезд метро?\", \"translated\": \"¿Cuánto tiempo falta para el próximo tren del metro?\"}, {\"original\": \"Извините, пропустите меня, пожалуйста.\", \"translated\": \"Disculpe, permítame pasar, por favor.\"}, {\"original\": \"Это место занято?\", \"translated\": \"¿Esta plaza está ocupada?\"}, {\"original\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\", \"translated\": \"Disculpe, ¿dónde puedo hacer transbordo a la línea 2 para llegar a XX?\"}, {\"original\": \"Как мне добраться до XX?\", \"translated\": \"¿Cómo llego a XX?\"}]', 4, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на туристических объектах?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с туристическими объектами, а также их переводы на испанский язык:\"]', '[\"Осмотр достопримечательностей\", \"Фотографирование\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, вопрос о цене билетов, поиск парковочного места или услуг гида? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"Есть ли льготные билеты для студентов?\", \"translated\": \"¿Hay entradas para estudiantes disponibles?\"}, {\"original\": \"Во сколько открывается достопримечательность?\", \"translated\": \"¿A qué hora abre la atracción?\"}, {\"original\": \"Чем здесь можно интересно заняться?\", \"translated\": \"¿Qué cosas divertidas se pueden hacer aquí?\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"¿Podría hacernos una foto?\"}, {\"original\": \"Где автобус для осмотра достопримечательностей?\", \"translated\": \"¿Dónde está el autobús turístico?\"}, {\"original\": \"Где находится туалет?\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"Где лучшее место для просмотра?\", \"translated\": \"¿Cuál es el mejor lugar para observar?\"}, {\"original\": \"Здесь прекрасный вид.\", \"translated\": \"El paisaje aquí es hermoso.\"}, {\"original\": \"Доступна ли экскурсия с гидом?\", \"translated\": \"¿Hay visitas guiadas disponibles?\"}]', 5, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать при заказе такси или пользовании таксисервисом?\", \"Превосходно! Вот 10 распространённых фраз, связанных с такси или таксисервисом, а также их переводы на испанский язык:\"]', '[\"Вызов такси\", \"Указание места назначения\", \"Оплата\"]', 'ru', '[\"Пока что: что вы сейчас больше всего хотите сделать — уточнить пункт назначения, узнать стоимость поездки или запросить счёт? Свободно задавайте любые вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас возникла в воображении.\"]', NULL, '[{\"original\": \"Где я могу взять такси?\", \"translated\": \"¿Dónde puedo conseguir un taxi?\"}, {\"original\": \"Пожалуйста, отвезите меня по этому адресу.\", \"translated\": \"Por favor, lléveme a esta dirección.\"}, {\"original\": \"Примерно сколько это будет стоить?\", \"translated\": \"¿Cuánto costará aproximadamente?\"}, {\"original\": \"Не могли бы вы, пожалуйста, включить счётчик?\", \"translated\": \"¿Podría usar el taxímetro, por favor?\"}, {\"original\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\", \"translated\": \"Por favor, conduzca un poco más rápido, tengo prisa.\"}, {\"original\": \"Остановитесь, пожалуйста, здесь.\", \"translated\": \"Por favor, pare aquí.\"}, {\"original\": \"Принимаете ли вы оплату картой или через мобильные платежи?\", \"translated\": \"¿Acepta tarjetas o pagos móviles?\"}, {\"original\": \"Можно мне, пожалуйста, чек?\", \"translated\": \"¿Podría darme un recibo, por favor?\"}, {\"original\": \"Спасибо, водитель.\", \"translated\": \"Gracias, conductor.\"}, {\"original\": \"Как далеко ещё?\", \"translated\": \"¿Cuánto falta todavía?\"}]', 6, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в аптеке?\", \"Отлично! Вот 10 распространённых фраз, связанных с аптекой, а также их переводы на испанский язык:\"]', '[\"Покупка лекарств\", \"Консультация\", \"Оплата\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, запрос инструкций по приёму лекарств, фразы, связанные с использованием страхования, продолжительностью приёма лекарств — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"У вас есть лекарство от простуды?\", \"translated\": \"¿Tiene medicamento para el resfriado?\"}, {\"original\": \"Как мне принимать это лекарство?\", \"translated\": \"¿Cómo debo tomar este medicamento?\"}, {\"original\": \"У вас есть обезболивающие?\", \"translated\": \"¿Tiene algún analgésico?\"}, {\"original\": \"Есть ли инструкция по применению?\", \"translated\": \"¿Hay un folleto con instrucciones?\"}, {\"original\": \"Это лекарство имеет какие-либо побочные эффекты?\", \"translated\": \"¿Este medicamento tiene efectos secundarios?\"}, {\"original\": \"Можно ли воспользоваться моей медицинской страховкой?\", \"translated\": \"¿Puedo usar mi tarjeta de seguro médico?\"}, {\"original\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\", \"translated\": \"¿Podría darme una caja de tiritas, por favor?\"}, {\"original\": \"У вас есть жаропонижающие?\", \"translated\": \"¿Tiene algún antipirético?\"}, {\"original\": \"Я немного поранился. У вас есть антисептик и пластыри?\", \"translated\": \"Tengo una pequeña herida superficial. ¿Tiene antiséptico y tiritas?\"}, {\"original\": \"Во сколько вы закрываетесь?\", \"translated\": \"¿A qué hora cierran?\"}]', 7, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в службах экстренной помощи?\", \"Отлично! Вот 10 распространённых фраз, связанных со службами экстренной помощи, а также их переводы на испанский язык:\"]', '[\"Вызов полиции\", \"Первая помощь\", \"Вызов на помощь\"]', 'ru', '[\"Пока что: у вас есть в виду какая-то конкретная чрезвычайная ситуация, например пожар, травма и необходимость помощи, экстренный звонок — смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Пожалуйста, помогите мне вызвать скорую помощь.\", \"translated\": \"Por favor, ayúdeme a llamar a una ambulancia.\"}, {\"original\": \"Где находится больница?\", \"translated\": \"¿Dónde está el hospital?\"}, {\"original\": \"Кто-то получил травму.\", \"translated\": \"Alguien resultó herido.\"}, {\"original\": \"Пожалуйста, помогите мне.\", \"translated\": \"Por favor, ayúdeme.\"}, {\"original\": \"Где находится полицейский участок?\", \"translated\": \"¿Dónde está la comisaría?\"}, {\"original\": \"Я потерял свои вещи.\", \"translated\": \"He perdido mis pertenencias.\"}, {\"original\": \"Какой номер пожарной службы?\", \"translated\": \"¿Cuál es el número de los bomberos?\"}, {\"original\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\", \"translated\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría más cercana?\"}, {\"original\": \"Здесь есть аварийный выход?\", \"translated\": \"¿Hay una salida de emergencia?\"}, {\"original\": \"Кто-то потерял сознание.\", \"translated\": \"Alguien ha desmayado.\"}]', 8, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на пляже или у бассейна?\", \"Превосходно! Вот 10 распространённых фраз, связанных с пляжем или бассейном, а также их переводы на испанский язык:\"]', '[\"Плавание\", \"Загар\", \"Пляжные виды спорта\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного мероприятия или фестиваля, в котором вы участвуете: культурный фестиваль, гастрономический фестиваль или музыкальный фестиваль? Пожалуйста, укажите контекст.\", \"Пожалуйста, опишите мероприятия, в которых вы участвуете.\"]', '[\"У вас есть конкретная ситуация, о которой вы хотели бы спросить? Свободно задавайте вопрос.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', '[{\"original\": \"Смотрите! Волны там действительно очень большие.\", \"translated\": \"¡Mira! Las olas allí son realmente grandes.\"}, {\"original\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\", \"translated\": \"Recuerda aplicarte protector solar; los rayos UV aquí son muy intensos.\"}, {\"original\": \"Песок на этом пляже такой мелкий, что идти по нему — всё равно что ступать по хлопку.\", \"translated\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\"}, {\"original\": \"Как насчёт игры в волейбол на пляже?\", \"translated\": \"¿Qué tal jugar al voleibol en la playa?\"}, {\"original\": \"Парусники вдалеке выглядят очень красиво.\", \"translated\": \"Los veleros a lo lejos se ven hermosos.\"}, {\"original\": \"Вода здесь такая прозрачная, что даже рыбок можно разглядеть.\", \"translated\": \"El agua aquí es tan transparente que incluso puedes ver los peces.\"}, {\"original\": \"Давайте пойдём собирать морские ракушки.\", \"translated\": \"Vamos a buscar conchas marinas.\"}, {\"original\": \"Прогулка по пляжу на закате, наверное, очень романтична.\", \"translated\": \"Pasear por la playa al atardecer debe ser muy romántico.\"}, {\"original\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\", \"translated\": \"He oído decir que los mariscos aquí son muy frescos; vamos a probarlos.\"}, {\"original\": \"Начинается прилив, давайте направимся к берегу.\", \"translated\": \"La marea está subiendo; volvamos hacia la orilla.\"}]', 9, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на местных мероприятиях и праздниках?\", \"Превосходно! Вот 10 распространённых фраз, связанных с местными мероприятиями и праздниками, а также их переводы на испанский язык:\"]', '[\"Посещение мероприятий\", \"Празднование фестивалей\", \"Изучение культуры\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного мероприятия или праздника, на который вы собираетесь пойти: Хэллоуин, концерт, вечеринка у друзей или что-то ещё? Пожалуйста, укажите контекст.\", \"Опишите, пожалуйста, те виды деятельности, которые у вас ассоциируются с этим мероприятием.\"]', '[\"У вас есть конкретная ситуация в уме? Свободно задавайте вопрос.\", \"Опишите, пожалуйста, ситуацию, которая у вас ассоциируется с этим.\"]', '[{\"original\": \"Есть ли сегодня какие-нибудь мероприятия?\", \"translated\": \"¿Hay algún evento hoy?\"}, {\"original\": \"В этом празднике есть что-нибудь особенное?\", \"translated\": \"¿Hay algo especial en este festival?\"}, {\"original\": \"Где проходит празднование?\", \"translated\": \"¿Dónde se celebra la festividad?\"}, {\"original\": \"Как я могу купить билеты?\", \"translated\": \"¿Cómo puedo comprar entradas?\"}, {\"original\": \"Во сколько начинается представление?\", \"translated\": \"¿A qué hora empieza la actuación?\"}, {\"original\": \"Какая традиционная еда здесь есть?\", \"translated\": \"¿Qué comida tradicional hay?\"}, {\"original\": \"Здесь действительно оживлённо.\", \"translated\": \"Aquí hay mucha animación.\"}, {\"original\": \"Есть ли какие-нибудь народные мероприятия?\", \"translated\": \"¿Hay alguna actividad popular?\"}, {\"original\": \"Счастливых праздников!\", \"translated\": \"¡Felices fiestas!\"}, {\"original\": \"Во сколько заканчивается мероприятие?\", \"translated\": \"¿A qué hora termina el evento?\"}]', 10, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в музее или художественной галерее?\", \"Превосходно! Вот 10 распространённых фраз, связанных с музеем или художественной галереей, а также их переводы на испанский язык:\"]', '[\"Посещение\", \"Экскурсия\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, просьба о руководстве по посещению, фразы, связанные с маршрутом посетителя, фразы для комментариев к экспонатам — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"У вас есть аудиогиды?\", \"translated\": \"¿Tienen guías de audio?\"}, {\"original\": \"Кто создал это произведение искусства?\", \"translated\": \"¿Quién creó esta obra de arte?\"}, {\"original\": \"Где находится самая ценная экспонат музея?\", \"translated\": \"¿Dónde se encuentra la pieza más valiosa del museo?\"}, {\"original\": \"Разрешена ли фотосъёмка?\", \"translated\": \"¿Está permitida la fotografía?\"}, {\"original\": \"Здесь проходят какие-нибудь специальные выставки?\", \"translated\": \"¿Hay alguna exposición especial aquí?\"}, {\"original\": \"Сколько времени занимает посещение?\", \"translated\": \"¿Cuánto tiempo dura la visita?\"}, {\"original\": \"Не могли бы вы представить нам краткое введение?\", \"translated\": \"¿Podría darnos una introducción?\"}, {\"original\": \"Эти произведения действительно изысканны.\", \"translated\": \"Estas obras son verdaderamente exquisitas.\"}, {\"original\": \"Где находится магазин сувениров?\", \"translated\": \"¿Dónde está la tienda de souvenirs?\"}]', 11, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в кафе?\", \"Отлично! Вот 10 распространённых фраз, связанных с кафе, а также их переводы на испанский язык:\"]', '[\"Заказ кофе\", \"Отдых\", \"Общение\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, заказ меню, льда или горячих напитков, других товаров? Свободно задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Я возьму латте, пожалуйста.\", \"translated\": \"Tomaré un latte, por favor.\"}, {\"original\": \"У вас есть Wi-Fi?\", \"translated\": \"¿Tienen conexión Wi-Fi?\"}, {\"original\": \"Можно мне посмотреть меню, пожалуйста?\", \"translated\": \"¿Podría ver el menú, por favor?\"}, {\"original\": \"Разрешено ли добавлять кофе бесплатно?\", \"translated\": \"¿Se permiten recargas?\"}, {\"original\": \"Мой кофе уже готов?\", \"translated\": \"¿Ya está listo mi café?\"}, {\"original\": \"Сколько времени я могу здесь посидеть?\", \"translated\": \"¿Cuánto tiempo puedo quedarme aquí?\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"¿Podría tomarnos una foto?\"}, {\"original\": \"Где туалет?\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"Счёт, пожалуйста. Спасибо.\", \"translated\": \"La cuenta, por favor. Gracias.\"}, {\"original\": \"Очень вкусно.\", \"translated\": \"Sabe realmente bien.\"}]', 12, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在餐厅常用的说法吗？\", \"太棒了！以下是与餐厅相关的10个常用说法，以及对应的中文翻译：\"]', '[\"用餐\", \"下单\", \"结账\"]', 'zh', '[\"目前，您心中是否有特定场景，例如点饮料、提出投诉或询问食材成分？欢迎随时提问。\", \"请描述您心中所想的具体场景。\"]', NULL, '[{\"original\": \"打扰一下，我们的菜还要等多久？\", \"translated\": \"Извините, сколько ещё ждать нашу еду?\"}, {\"original\": \"请给我们安排一张两人桌。\", \"translated\": \"Столик на двоих, пожалуйста.\"}, {\"original\": \"请问可以看一下菜单吗？\", \"translated\": \"Можно посмотреть меню, пожалуйста?\"}, {\"original\": \"你们有什么招牌菜可以推荐吗？\", \"translated\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\"}, {\"original\": \"我要点这个和这个。\", \"translated\": \"Я хочу заказать это и это.\"}, {\"original\": \"请给我一杯水，谢谢。\", \"translated\": \"Стакан воды, пожалуйста. Спасибо.\"}, {\"original\": \"请结账。\", \"translated\": \"Счёт, пожалуйста.\"}, {\"original\": \"我可以刷信用卡付款吗？\", \"translated\": \"Можно оплатить кредитной картой?\"}, {\"original\": \"请问可以帮我把这份打包带走吗？\", \"translated\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\"}, {\"original\": \"饭菜非常美味，谢谢。\", \"translated\": \"Еда была восхитительной, спасибо.\"}]', 1, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在酒店场景中常用的表达吗？\", \"太棒了！以下是与酒店相关的10个常用表达，以及对应的中文翻译：\"]', '[\"入住\", \"退房\", \"客房服务\"]', 'zh', '[\"目前，您心中是否有特定的情境？例如房间位置、其他酒店服务，或退房等？欢迎随时提问。\", \"请描述您心中所想的情境。\"]', NULL, '[{\"original\": \"你好，我已预订房间，这是我的护照。\", \"translated\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\"}, {\"original\": \"请问还有空房吗？\", \"translated\": \"У вас есть свободные номера?\"}, {\"original\": \"打扰一下，酒店有健身房或洗衣房吗？\", \"translated\": \"Извините, в отеле есть тренажёрный зал или прачечная?\"}, {\"original\": \"早餐几点开始？\", \"translated\": \"Во сколько начинается завтрак?\"}, {\"original\": \"请给我一把房卡，好吗？\", \"translated\": \"Можно мне ключ от номера, пожалуйста?\"}, {\"original\": \"您能帮我把行李送到房间吗？\", \"translated\": \"Не могли бы вы помочь мне отнести багаж в номер?\"}, {\"original\": \"我该怎么呼叫客房服务？\", \"translated\": \"Как вызвать службу обслуживания номеров?\"}, {\"original\": \"退房时间是几点？\", \"translated\": \"До какого времени необходимо освободить номер?\"}, {\"original\": \"请您给我开一张收据／发票，好吗？\", \"translated\": \"Не могли бы вы выписать мне квитанцию/счёт?\"}, {\"original\": \"我可以把行李寄存在这里吗？\", \"translated\": \"Можно оставить здесь мой багаж?\"}]', 2, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在机场常用的短语吗？\", \"太棒了！以下是与机场相关的10个常用短语，以及对应的中文翻译：\"]', '[\"办理登机手续\", \"登机\", \"行李托运\"]', 'zh', '[\"目前，您心中是否有特定场景，例如办理登机手续、行李提取或租车服务？欢迎随时提问。\", \"请描述您心中所想的场景。\"]', NULL, '[{\"original\": \"值机柜台在哪里？\", \"translated\": \"Где находится стойка регистрации?\"}, {\"original\": \"我想要一个靠窗的座位，谢谢。\", \"translated\": \"Я бы хотел(а) место у окна, пожалуйста.\"}, {\"original\": \"这个航班延误了吗？\", \"translated\": \"Этот рейс задерживается?\"}, {\"original\": \"我需要托运行李。\", \"translated\": \"Мне нужно зарегистрировать этот багаж.\"}, {\"original\": \"登机口在哪里？\", \"translated\": \"Где находится выход на посадку?\"}, {\"original\": \"飞机即将起飞。\", \"translated\": \"Самолёт вот-вот взлетит.\"}, {\"original\": \"我需要把笔记本电脑和充电宝拿出来吗？\", \"translated\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\"}, {\"original\": \"免税店在哪里？\", \"translated\": \"Где находится магазин беспошлинной торговли?\"}, {\"original\": \"我找不到我的行李箱了。\", \"translated\": \"Я не могу найти свой чемодан.\"}, {\"original\": \"你们提供轮椅服务吗？\", \"translated\": \"Предоставляется ли услуга инвалидной коляски?\"}]', 3, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在公共交通中常用的表达吗？\", \"太棒了！以下是与公共交通相关的10个常用表达，以及对应的中文翻译：\"]', '[\"乘坐公交/地铁\", \"购买车票\", \"换乘\"]', 'zh', '[\"目前，您心里是否有特定的场景，例如询问公交站、票价或下车等？欢迎随时提问。\", \"请描述您心中所想的场景。\"]', NULL, '[{\"original\": \"这趟公交车去终点站吗？\", \"translated\": \"Этот автобус идёт до конечной остановки?\"}, {\"original\": \"下一站是哪里？\", \"translated\": \"Какая следующая остановка?\"}, {\"original\": \"我在哪里可以买票？\", \"translated\": \"Где я могу купить билет?\"}, {\"original\": \"请给我一张去XX的车票。\", \"translated\": \"Один билет до XX, пожалуйста.\"}, {\"original\": \"我需要换乘吗？\", \"translated\": \"Нужно ли мне пересаживаться?\"}, {\"original\": \"下一班地铁列车还要等多久？\", \"translated\": \"Сколько осталось до прибытия следующего поезда метро?\"}, {\"original\": \"不好意思，请让我过去。\", \"translated\": \"Извините, пропустите меня, пожалуйста.\"}, {\"original\": \"这个座位有人吗？\", \"translated\": \"Это место занято?\"}, {\"original\": \"不好意思，请问我在哪里换乘二号线去XX？\", \"translated\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\"}, {\"original\": \"我怎么去XX？\", \"translated\": \"Как мне добраться до XX?\"}]', 4, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在旅游景点常用的表达吗？\", \"太棒了！以下是与旅游景点相关的10个常用表达，以及对应的中文翻译：\"]', '[\"观光游览\", \"拍照留念\", \"购买门票\"]', 'zh', '[\"目前，您心中是否有特定场景？例如询问门票价格、寻找停车场或导游服务等，欢迎随时提问。\", \"请描述您心中想到的具体场景。\"]', NULL, '[{\"original\": \"门票多少钱？\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"有学生票吗？\", \"translated\": \"Есть ли льготные билеты для студентов?\"}, {\"original\": \"景点几点开门？\", \"translated\": \"Во сколько открывается достопримечательность?\"}, {\"original\": \"这里有哪些好玩的项目？\", \"translated\": \"Чем здесь интересно заняться?\"}, {\"original\": \"您能帮我们拍张照片吗？\", \"translated\": \"Не могли бы вы сделать для нас фотографию?\"}, {\"original\": \"观光巴士在哪里？\", \"translated\": \"Где автобус для осмотра достопримечательностей?\"}, {\"original\": \"洗手间在哪儿？\", \"translated\": \"Где находится туалет?\"}, {\"original\": \"最佳观景点在哪儿？\", \"translated\": \"Где лучшее место для просмотра?\"}, {\"original\": \"这里的风景很美。\", \"translated\": \"Здесь прекрасные виды.\"}, {\"original\": \"有提供导游服务吗？\", \"translated\": \"Доступна ли экскурсия с гидом?\"}]', 5, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在乘坐出租车或使用出租车服务时常用的表达吗？\", \"太棒了！以下是与出租车或出租车服务相关的10个常用表达，以及对应的中文翻译：\"]', '[\"乘坐出租车\", \"告知目的地\", \"付款\"]', 'zh', '[\"目前，您最想做什么呢？比如询问目的地、车费，或是索要发票，欢迎随时提问。\", \"请描述您脑海中设想的情境。\"]', NULL, '[{\"original\": \"我在哪里可以打到出租车？\", \"translated\": \"Где я могу взять такси?\"}, {\"original\": \"请送我去这个地址。\", \"translated\": \"Пожалуйста, отвезите меня по этому адресу.\"}, {\"original\": \"大概需要多少钱？\", \"translated\": \"Примерно сколько это будет стоить?\"}, {\"original\": \"请您打表计费，好吗？\", \"translated\": \"Не могли бы вы, пожалуйста, включить счётчик?\"}, {\"original\": \"请开快一点，我赶时间。\", \"translated\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\"}, {\"original\": \"请在这里停车。\", \"translated\": \"Остановитесь, пожалуйста, здесь.\"}, {\"original\": \"您接受银行卡或手机支付吗？\", \"translated\": \"Принимаете ли вы оплату картой или через мобильные платежи?\"}, {\"original\": \"可以给我一张发票吗？\", \"translated\": \"Можно мне, пожалуйста, чек?\"}, {\"original\": \"谢谢，司机师傅。\", \"translated\": \"Спасибо, водитель.\"}, {\"original\": \"还有多远？\", \"translated\": \"Как далеко ещё?\"}]', 6, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个药房常用表达吗？\", \"太棒了！以下是与药房相关的10个常用表达，以及对应的俄语翻译：\"]', '[\"购买药品\", \"咨询\", \"支付\"]', 'zh', '[\"目前，您心中是否有特定场景？例如询问服药说明、与保险使用相关的问题、用药时长等，欢迎随时提问。\", \"请描述您心中所想的场景。\"]', NULL, '[{\"original\": \"你们有治感冒的药吗？\", \"translated\": \"У вас есть лекарство от простуды?\"}, {\"original\": \"这种药我该怎么服用？\", \"translated\": \"Как мне принимать это лекарство?\"}, {\"original\": \"你们有止痛药吗？\", \"translated\": \"У вас есть обезболивающие?\"}, {\"original\": \"这个药有说明书吗？\", \"translated\": \"Есть ли инструкция по применению?\"}, {\"original\": \"这种药有什么副作用吗？\", \"translated\": \"Это лекарство имеет какие-либо побочные эффекты?\"}, {\"original\": \"我能用我的医保卡吗？\", \"translated\": \"Можно ли воспользоваться моей медицинской страховкой?\"}, {\"original\": \"请给我一盒创可贴，谢谢。\", \"translated\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\"}, {\"original\": \"你们有退烧药吗？\", \"translated\": \"У вас есть жаропонижающие?\"}, {\"original\": \"我有点擦伤，你们有消毒药水和创可贴吗？\", \"translated\": \"Я немного поранился. У вас есть антисептик и пластыри?\"}, {\"original\": \"你们几点关门？\", \"translated\": \"Во сколько вы закрываетесь?\"}]', 7, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在紧急服务中常用的短语吗？\", \"太棒了！以下是与紧急服务相关的10个常用短语，以及对应的俄语翻译：\"]', '[\"报警\", \"急救\", \"求助\"]', 'zh', '[\"目前，您脑海中是否有特定的紧急情况，例如火灾、受伤需要帮助、紧急呼叫等？欢迎随时提问。\", \"请描述您脑海中设想的情况。\"]', NULL, '[{\"original\": \"请帮我叫一辆救护车。\", \"translated\": \"Пожалуйста, помогите вызвать скорую помощь.\"}, {\"original\": \"医院在哪儿？\", \"translated\": \"Где находится больница?\"}, {\"original\": \"有人受伤了。\", \"translated\": \"Кто-то пострадал.\"}, {\"original\": \"请帮帮我。\", \"translated\": \"Пожалуйста, помогите мне.\"}, {\"original\": \"警察局在哪儿？\", \"translated\": \"Где находится полицейский участок?\"}, {\"original\": \"我的物品丢失了。\", \"translated\": \"Я потерял(а) свои вещи.\"}, {\"original\": \"消防部门的电话号码是多少？\", \"translated\": \"Какой номер пожарной службы?\"}, {\"original\": \"我的护照丢了。您知道最近的警察局在哪儿吗？\", \"translated\": \"Я потерял(а) паспорт. Не подскажете, где ближайший полицейский участок?\"}, {\"original\": \"有紧急出口吗？\", \"translated\": \"Здесь есть аварийный выход?\"}, {\"original\": \"有人晕倒了。\", \"translated\": \"Кто-то потерял сознание.\"}]', 8, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在海滩或泳池边常用的短语吗？\", \"太棒了！以下是与海滩或泳池边相关的10个常用短语，以及对应的俄语翻译：\"]', '[\"游泳\", \"日光浴\", \"海滩运动\"]', 'zh', '[\"目前，请您提供您将要参加的当地活动或节日的背景信息，例如文化节、美食节或音乐节。请提供相关背景。\", \"请您说明您将参与的活动内容。\"]', '[\"您心中是否有特定的情境？欢迎随时提问。\", \"请描述您心中设想的情境。\"]', '[{\"original\": \"看！那边的海浪真大。\", \"translated\": \"Смотрите! Волны там действительно очень большие.\"}, {\"original\": \"记得涂防晒霜，这里的紫外线很强。\", \"translated\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\"}, {\"original\": \"这片海滩的沙子非常细腻，踩上去像踩在棉花上。\", \"translated\": \"Песок на этом пляже такой мелкий, что ощущение такое, будто идёшь по хлопку.\"}, {\"original\": \"在海滩上打排球怎么样？\", \"translated\": \"Как насчёт игры в волейбол на пляже?\"}, {\"original\": \"远处的帆船看起来真美。\", \"translated\": \"Парусники вдали выглядят очень красиво.\"}, {\"original\": \"这里的海水如此清澈，甚至能看见鱼。\", \"translated\": \"Вода здесь такая прозрачная, что даже рыб видно.\"}, {\"original\": \"我们去找些贝壳吧。\", \"translated\": \"Давайте пойдём собирать ракушки.\"}, {\"original\": \"日落时分在海滩上散步一定很浪漫。\", \"translated\": \"Прогулка по пляжу на закате, наверное, очень романтична.\"}, {\"original\": \"听说这里的海鲜非常新鲜，我们去尝尝吧。\", \"translated\": \"Я слышал, что морепродукты здесь очень свежие, давайте попробуем.\"}, {\"original\": \"潮水涨起来了，我们往岸边走吧。\", \"translated\": \"Начинается прилив, давайте направимся к берегу.\"}]', 9, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在本地活动和节日中常用的表达吗？\", \"太棒了！以下是与本地活动和节日相关的10个常用表达，以及对应的俄语翻译：\"]', '[\"参加活动\", \"庆祝节日\", \"学习文化\"]', 'zh', '[\"目前，您能否告诉我您将参加的本地活动或节日的具体情境？例如万圣节、音乐会、朋友聚会，或其他场合？请提供具体情境。\", \"请描述您脑海中设想的活动内容。\"]', '[\"您心中是否有特定的情境？欢迎随时提问。\", \"请描述您脑海中设想的具体情境。\"]', '[{\"original\": \"今天有什么活动吗？\", \"translated\": \"Есть ли сегодня какие-нибудь мероприятия?\"}, {\"original\": \"这个节日有什么特别之处吗？\", \"translated\": \"В этом празднике есть что-нибудь особенное?\"}, {\"original\": \"庆祝活动在哪里举行？\", \"translated\": \"Где проходит празднование?\"}, {\"original\": \"我该如何购买门票？\", \"translated\": \"Как я могу купить билеты?\"}, {\"original\": \"演出什么时候开始？\", \"translated\": \"Во сколько начинается представление?\"}, {\"original\": \"有哪些传统食物？\", \"translated\": \"Какая традиционная еда здесь есть?\"}, {\"original\": \"这里真热闹。\", \"translated\": \"Здесь действительно очень оживлённо.\"}, {\"original\": \"有民俗活动吗？\", \"translated\": \"Есть ли какие-нибудь народные мероприятия?\"}, {\"original\": \"节日快乐！\", \"translated\": \"Счастливых праздников!\"}, {\"original\": \"活动什么时候结束？\", \"translated\": \"Во сколько заканчивается мероприятие?\"}]', 10, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在博物馆或美术馆中常用的表达吗？\", \"太棒了！以下是与博物馆或美术馆相关的10个常用表达，以及对应的中文翻译：\"]', '[\"参观\", \"导览游\", \"购票\"]', 'zh', '[\"目前，您心中是否有特定场景？例如索要导览手册、与参观路线相关的表达、对展品进行评论的表达等，欢迎随时提问。\", \"请描述您心中所想的具体场景。\"]', NULL, '[{\"original\": \"门票多少钱？\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"你们提供语音导览吗？\", \"translated\": \"Есть ли у вас аудиогиды?\"}, {\"original\": \"这件艺术品是谁创作的？\", \"translated\": \"Кто является автором этого произведения искусства?\"}, {\"original\": \"博物馆最珍贵的藏品在哪里？\", \"translated\": \"Где находится самое ценное произведение музея?\"}, {\"original\": \"允许拍照吗？\", \"translated\": \"Разрешена ли фотосъёмка?\"}, {\"original\": \"这里有没有特别展览？\", \"translated\": \"Есть ли здесь какие-нибудь специальные выставки?\"}, {\"original\": \"参观需要多长时间？\", \"translated\": \"Сколько времени занимает посещение?\"}, {\"original\": \"您能为我们做个介绍吗？\", \"translated\": \"Не могли бы вы кратко рассказать об экспозиции?\"}, {\"original\": \"这些作品真是精美绝伦。\", \"translated\": \"Эти произведения действительно изысканны.\"}, {\"original\": \"纪念品商店在哪儿？\", \"translated\": \"Где находится магазин сувениров?\"}]', 11, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在咖啡馆常用的说法吗？\", \"太棒了！以下是10个与咖啡馆相关的常用说法，并附有俄语翻译：\"]', '[\"点咖啡\", \"休息\", \"社交\"]', 'zh', '[\"目前，您心中是否有特定场景，例如点餐单、点冰饮或热饮、购买其他商品等？欢迎随时提问。\", \"请描述您心中所想的场景。\"]', NULL, '[{\"original\": \"请给我一杯拿铁。\", \"translated\": \"Я возьму латте, пожалуйста.\"}, {\"original\": \"你们有无线网络吗？\", \"translated\": \"У вас есть Wi-Fi?\"}, {\"original\": \"请把菜单给我看一下。\", \"translated\": \"Можно мне посмотреть меню, пожалуйста?\"}, {\"original\": \"可以续杯吗？\", \"translated\": \"Можно ли сделать дополнительную порцию?\"}, {\"original\": \"我的咖啡好了吗？\", \"translated\": \"Готов мой кофе?\"}, {\"original\": \"我可以在这里坐多久？\", \"translated\": \"Сколько времени я могу здесь посидеть?\"}, {\"original\": \"能帮我们拍张照片吗？\", \"translated\": \"Не могли бы вы сделать нам фотографию?\"}, {\"original\": \"洗手间在哪里？\", \"translated\": \"Где туалет?\"}, {\"original\": \"请结账，谢谢。\", \"translated\": \"Счёт, пожалуйста. Спасибо.\"}, {\"original\": \"味道 really 好。\", \"translated\": \"Очень вкусно.\"}]', 12, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Restoranda kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte restoranla ilgili 10 yaygın ifade ve bunların Rusça çevirileri:\"]', '[\"Yemek Yeme\", \"Sipariş Verme\", \"Ödeme\"]', 'tr', '[\"Şu an için aklınızda içecek siparişi vermek, bir şikayette bulunmak veya malzemeler hakkında soru sormak gibi belirli bir durum mu var? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Affedersiniz, yemeğimiz kaç dakika daha sürecektir?\", \"translated\": \"Извините, сколько ещё ждать нашу еду?\"}, {\"original\": \"Lütfen iki kişilik bir masa.\", \"translated\": \"Столик на двоих, пожалуйста.\"}, {\"original\": \"Lütfen menüyü görebilir miyiz?\", \"translated\": \"Можно посмотреть меню, пожалуйста?\"}, {\"original\": \"Önerdiğiniz özel yemekleriniz var mı?\", \"translated\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\"}, {\"original\": \"Bunu ve bunu sipariş etmek istiyorum.\", \"translated\": \"Я хочу заказать это и это.\"}, {\"original\": \"Lütfen bir bardak su. Teşekkürler.\", \"translated\": \"Стакан воды, пожалуйста. Спасибо.\"}, {\"original\": \"Hesabı lütfen.\", \"translated\": \"Счёт, пожалуйста.\"}, {\"original\": \"Kredi kartıyla ödeyebilir miyim?\", \"translated\": \"Можно оплатить кредитной картой?\"}, {\"original\": \"Lütfen bunu götürmek için paketleyebilir misiniz?\", \"translated\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\"}, {\"original\": \"Yiyecek çok lezzetliydi, teşekkür ederiz.\", \"translated\": \"Еда была восхитительной, спасибо.\"}]', 1, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Otelde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte otel ile ilgili 10 yaygın ifade ve Rusça çevirileri:\"]', '[\"Kayıt Ol\", \"Çıkış Yap\", \"Oda Hizmeti\"]', 'tr', '[\"Şu anda aklınızda özel bir durum var mı? Örneğin oda konumu, başka bir otel hizmeti veya çıkış işlemi gibi. Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Merhaba, bir rezervasyonum var. İşte pasaportum.\", \"translated\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\"}, {\"original\": \"Boş odanız var mı?\", \"translated\": \"У вас есть свободные номера?\"}, {\"original\": \"Affedersiniz, otelin bir spor salonu veya çamaşırhane bölümü var mı?\", \"translated\": \"Извините, в отеле есть тренажёрный зал или прачечная?\"}, {\"original\": \"Kahvaltı saat kaçta başlıyor?\", \"translated\": \"Во сколько начинается завтрак?\"}, {\"original\": \"Lütfen bir oda anahtarı alabilir miyim?\", \"translated\": \"Можно мне ключ от номера, пожалуйста?\"}, {\"original\": \"Lütfen bana bagajlarımı odaya taşımada yardımcı olur musunuz?\", \"translated\": \"Не могли бы вы помочь мне отнести багаж в номер?\"}, {\"original\": \"Oda servisini nasıl arayabilirim?\", \"translated\": \"Как вызвать службу обслуживания номеров?\"}, {\"original\": \"Çıkış saati kaçta?\", \"translated\": \"До какого времени необходимо освободить номер?\"}, {\"original\": \"Bana bir makbuz/fatura yazabilir misiniz?\", \"translated\": \"Не могли бы вы выписать мне квитанцию/счёт?\"}, {\"original\": \"Bagajlarımı burada bırakabilir miyim?\", \"translated\": \"Можно оставить здесь мой багаж?\"}]', 2, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Havaalanında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte havaalanı ile ilgili 10 yaygın ifade ve Rusça çevirileri:\"]', '[\"Giriş yapma\", \"Uçağa binme\", \"Bagaj kontrolü\"]', 'tr', '[\"Şu anda aklınızda özel bir durum mu var, örneğin check-in, bagaj teslimi veya araç kiralama hizmeti? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş masası nerede?\", \"translated\": \"Где стойка регистрации?\"}, {\"original\": \"Lütfen pencere kenarında bir koltuk istiyorum.\", \"translated\": \"Я бы хотел место у окна, пожалуйста.\"}, {\"original\": \"Bu uçuş gecikmiş mi?\", \"translated\": \"Этот рейс задерживается?\"}, {\"original\": \"Bu bagajı kontrol ettirmem gerekiyor.\", \"translated\": \"Мне нужно зарегистрировать этот багаж.\"}, {\"original\": \"İniş kapısı nerede?\", \"translated\": \"Где выход на посадку?\"}, {\"original\": \"Uçak kalkmak üzere.\", \"translated\": \"Самолёт вот-вот взлетит.\"}, {\"original\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\", \"translated\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\"}, {\"original\": \"Vergisiz mağaza nerede?\", \"translated\": \"Где магазин беспошлинной торговли?\"}, {\"original\": \"Bavulumu bulamıyorum.\", \"translated\": \"Я не могу найти свой чемодан.\"}, {\"original\": \"Tekerlekli sandalye hizmetiniz var mı?\", \"translated\": \"Предоставляется ли услуга инвалидных колясок?\"}]', 3, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Toplu taşıma araçlarında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Toplu Taşıma ile ilgili 10 yaygın ifade ve Rusça çevirileri:\"]', '[\"Otobüs/Metro Kullanma\", \"Bilet Satın Alma\", \"Aktarma\"]', 'tr', '[\"Şimdilik aklınızda özel bir durum var mı, örneğin otobüs durağı sormak, bilet fiyatını öğrenmek ya da inecek yer belirtmek? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bu otobüs terminala gidiyor mu?\", \"translated\": \"Этот автобус идёт до автовокзала?\"}, {\"original\": \"Bir sonraki durak neresi?\", \"translated\": \"Какая следующая остановка?\"}, {\"original\": \"Bilet nereden alabilirim?\", \"translated\": \"Где я могу купить билет?\"}, {\"original\": \"XX\'e bir bilet, lütfen.\", \"translated\": \"Один билет до XX, пожалуйста.\"}, {\"original\": \"Aktarma yapmam gerekiyor mu?\", \"translated\": \"Нужно ли мне пересаживаться?\"}, {\"original\": \"Bir sonraki metro treni ne zaman geliyor?\", \"translated\": \"Через сколько прибудет следующий поезд метро?\"}, {\"original\": \"Affedersiniz, geçebilir miyim?\", \"translated\": \"Извините, пропустите меня, пожалуйста.\"}, {\"original\": \"Bu koltuk dolu mu?\", \"translated\": \"Это место занято?\"}, {\"original\": \"Affedersiniz, XX’e gitmek için 2. Hat’a nerede aktarım yapabilirim?\", \"translated\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\"}, {\"original\": \"XX’e nasıl giderim?\", \"translated\": \"Как мне добраться до XX?\"}]', 4, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Turistik yerlerde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte turistik yerlerle ilgili 10 yaygın ifade ve bunların Rusça çevirileri:\"]', '[\"Manzara Görme\", \"Fotoğraf Çekme\", \"Bilet Satın Alma\"]', 'tr', '[\"Şimdilik aklınızda, bilet fiyatını sormak, bir otopark bulmak ya da tur rehberi hizmeti gibi belirli bir durum mu var? Sorun özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"Öğrenci biletleri mevcut mu?\", \"translated\": \"Есть ли льготные билеты для студентов?\"}, {\"original\": \"Bu yer saat kaçta açılıyor?\", \"translated\": \"Во сколько открывается достопримечательность?\"}, {\"original\": \"Burada yapılacak eğlenceli şeyler neler?\", \"translated\": \"Чем здесь интересно заняться?\"}, {\"original\": \"Bizi birlikte çeker misiniz?\", \"translated\": \"Не могли бы вы сделать для нас фотографию?\"}, {\"original\": \"Sightseeing otobüsü nerede?\", \"translated\": \"Где автобус для осмотра достопримечательностей?\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"Где находится туалет?\"}, {\"original\": \"En iyi manzara noktası nerede?\", \"translated\": \"Где лучшее место для просмотра?\"}, {\"original\": \"Buradaki manzara çok güzel.\", \"translated\": \"Здесь прекрасный вид.\"}, {\"original\": \"Rehberli tur mevcut mu?\", \"translated\": \"Доступна ли экскурсия с гидом?\"}]', 5, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Taksi veya taksi hizmeti ile ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Taksi veya Taksi Hizmeti ile ilgili 10 yaygın ifade ve Rusça çevirileri:\"]', '[\"Taksiye Biniş\", \"Varış Yerini Belirtme\", \"Ödeme\"]', 'tr', '[\"Şu anda en çok ne yapmak istersiniz? Örneğin, varış yerini sormak, ücreti öğrenmek ya da fatura istemek gibi. Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bir taksi nerede bulabilirim?\", \"translated\": \"Где я могу взять такси?\"}, {\"original\": \"Lütfen beni bu adrese götürün.\", \"translated\": \"Пожалуйста, отвезите меня по этому адресу.\"}, {\"original\": \"Yaklaşık olarak ne kadar tutar?\", \"translated\": \"Примерно сколько это будет стоить?\"}, {\"original\": \"Lütfen taksimetreyi kullanır mısınız?\", \"translated\": \"Не могли бы вы, пожалуйста, включить счётчик?\"}, {\"original\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\", \"translated\": \"Пожалуйста, поезжайте немного быстрее, мне спешно.\"}, {\"original\": \"Lütfen burada durun.\", \"translated\": \"Остановитесь, пожалуйста, здесь.\"}, {\"original\": \"Kart veya mobil ödeme kabul ediyor musunuz?\", \"translated\": \"Принимаете ли вы оплату картой или через мобильные приложения?\"}, {\"original\": \"Lütfen bir fiş verebilir misiniz?\", \"translated\": \"Можно мне, пожалуйста, чек?\"}, {\"original\": \"Teşekkür ederim, şoför bey.\", \"translated\": \"Спасибо, водитель.\"}, {\"original\": \"Kaç dakika kaldı?\", \"translated\": \"Сколько ещё осталось ехать?\"}]', 6, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Eczanede kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte eczane ile ilgili 10 yaygın ifade ve bunların Rusça çevirileri:\"]', '[\"İlaç Satın Alma\", \"Danışmanlık\", \"Ödeme\"]', 'tr', '[\"Şimdilik aklınızda, ilacı nasıl alacağınızı sormak, sigorta kullanımıyla ilgili ifadeler kullanmak veya ilacın kullanım süresini öğrenmek gibi belirli bir durum var mı? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Soğuk algınlığı ilacı var mı?\", \"translated\": \"У вас есть лекарство от простуды?\"}, {\"original\": \"Bu ilacı nasıl kullanmalıyım?\", \"translated\": \"Как мне принимать это лекарство?\"}, {\"original\": \"Ağrı kesici ilaçlarınız var mı?\", \"translated\": \"У вас есть обезболивающие?\"}, {\"original\": \"Kullanım kılavuzu var mı?\", \"translated\": \"Есть ли инструкция по применению?\"}, {\"original\": \"Bu ilacın yan etkileri var mı?\", \"translated\": \"Это лекарство имеет какие-либо побочные эффекты?\"}, {\"original\": \"Tıbbi sigorta kartımı kullanabilir miyim?\", \"translated\": \"Можно ли воспользоваться моей медицинской страховкой?\"}, {\"original\": \"Lütfen bir kutu yara bandı verebilir misiniz?\", \"translated\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\"}, {\"original\": \"Ateş düşürücü ilaçlarınız var mı?\", \"translated\": \"У вас есть жаропонижающие?\"}, {\"original\": \"Hafif bir çizik aldım. Antiseptik ve yara bandı var mı?\", \"translated\": \"Я немного поранился. У вас есть антисептик и пластыри?\"}, {\"original\": \"Kaçta kapanıyorsunuz?\", \"translated\": \"Во сколько вы закрываетесь?\"}]', 7, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Acil Servislerle ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Acil Servislerle ilgili 10 yaygın ifade ve bunların Rusça çevirileri:\"]', '[\"Polisi Aramak\", \"İlkyardım\", \"Yardım Çağrısı\"]', 'tr', '[\"Şu an için aklınızda belirli bir acil durum var mı, örneğin yangın, yaralanma ve yardım gereksinimi, acil çağrı? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bana bir ambulans çağırmama yardımcı olun.\", \"translated\": \"Пожалуйста, помогите мне вызвать скорую помощь.\"}, {\"original\": \"Hastane nerede?\", \"translated\": \"Где находится больница?\"}, {\"original\": \"Birisi yaralandı.\", \"translated\": \"Кто-то получил травму.\"}, {\"original\": \"Lütfen bana yardımcı olun.\", \"translated\": \"Пожалуйста, помогите мне.\"}, {\"original\": \"Polis karakolu nerede?\", \"translated\": \"Где находится полицейский участок?\"}, {\"original\": \"Eşyalarımı kaybettim.\", \"translated\": \"Я потерял свои вещи.\"}, {\"original\": \"İtfaiye numarası nedir?\", \"translated\": \"Какой номер пожарной службы?\"}, {\"original\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\", \"translated\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\"}, {\"original\": \"Acil çıkış var mı?\", \"translated\": \"Здесь есть аварийный выход?\"}, {\"original\": \"Birisi bayıldı.\", \"translated\": \"Кто-то потерял сознание.\"}]', 8, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Sahilde veya havuz kenarında kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte sahil veya havuz kenarına ilişkin 10 yaygın ifade ve bunların Rusça çevirileri:\"]', '[\"Yüzme\", \"Güneşlenme\", \"Plaj Sporları\"]', 'tr', '[\"Şimdilik, katılacağınız yerel etkinlik veya festivalin bağlamını, örneğin kültürel festival, gıda festivali veya müzik festivali gibi, lütfen bana belirtir misiniz? Lütfen bağlamı sağlayın.\", \"Katıldığınız etkinlikleri lütfen belirtin.\"]', '[\"Aklınızda özel bir durum mu var? Özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', '[{\"original\": \"Bakın! Oradaki dalgalar gerçekten büyük.\", \"translated\": \"Смотрите! Волны там действительно огромные.\"}, {\"original\": \"Güneş koruyucu sürmeyi unutmayın, buradaki UV ışınları çok güçlü.\", \"translated\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\"}, {\"original\": \"Bu plajdaki kum çok ince, pamuk üzerinde yürüyormuş gibi hissediliyor.\", \"translated\": \"Песок на этом пляже такой мелкий, что кажется, будто вы ступаете по вате.\"}, {\"original\": \"Plajda voleybol oynamak nasıl olur?\", \"translated\": \"Как насчёт игры в волейбол на пляже?\"}, {\"original\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\", \"translated\": \"Парусники вдали выглядят прекрасно.\"}, {\"original\": \"Buradaki su çok berrak, balıkları bile görebiliyorsunuz.\", \"translated\": \"Вода здесь такая прозрачная, что даже видно рыб.\"}, {\"original\": \"Hadi biraz deniz kabuğu bulmaya gidelim.\", \"translated\": \"Давайте найдём ракушки.\"}, {\"original\": \"Günbatımında plajda yürüyüş yapmak kesinlikle çok romantik olmalı.\", \"translated\": \"Прогулка по пляжу на закате, наверное, очень романтична.\"}, {\"original\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\", \"translated\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\"}, {\"original\": \"Deniz yükseliyor, kıyıya doğru yürüyelim.\", \"translated\": \"Начинается прилив, давайте направимся к берегу.\"}]', 9, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Yerel Etkinlikler ve Festivallerde kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte Yerel Etkinlikler ve Festivallerle ilgili 10 yaygın ifade ile birlikte Rusça çevirileri:\"]', '[\"Etkinliklere Katılmak\", \"Festivalleri Kutlamak\", \"Kültür Öğrenmek\"]', 'tr', '[\"Şimdilik, katıldığınız yerel etkinlik veya festivalin bağlamını, örneğin Cadılar Bayramı, konser ya da arkadaş partisi gibi, ya da başka bir şey olarak lütfen bana belirtir misiniz? Lütfen bağlamı sağlayın.\", \"Aklınızda canlandırdığınız etkinlikleri tanımlayınız.\"]', '[\"Aklınızda belirli bir durum mu var? Sorunuzu özgürce sorabilirsiniz.\", \"Aklınızda canlandırdığınız durumu tanımlayınız.\"]', '[{\"original\": \"Bugün herhangi bir etkinlik var mı?\", \"translated\": \"Есть ли сегодня какие-нибудь мероприятия?\"}, {\"original\": \"Bu festivalle ilgili özel bir şey var mı?\", \"translated\": \"В этом празднике есть что-нибудь особенное?\"}, {\"original\": \"Kutlama nerede yapılacak?\", \"translated\": \"Где проходит празднование?\"}, {\"original\": \"Biletleri nasıl alabilirim?\", \"translated\": \"Как я могу купить билеты?\"}, {\"original\": \"Gösteri saat kaçta başlıyor?\", \"translated\": \"Во сколько начинается представление?\"}, {\"original\": \"Hangi geleneksel yiyecekler var?\", \"translated\": \"Какая традиционная еда здесь есть?\"}, {\"original\": \"Burada gerçekten hareketli bir atmosfer var.\", \"translated\": \"Здесь действительно очень оживлённо.\"}, {\"original\": \"Halk oyunları gibi etkinlikler var mı?\", \"translated\": \"Есть ли какие-нибудь народные мероприятия?\"}, {\"original\": \"Mutlu tatiller!\", \"translated\": \"Счастливых праздников!\"}, {\"original\": \"Etkinlik saat kaçta bitiyor?\", \"translated\": \"Во сколько заканчивается мероприятие?\"}]', 10, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Müze veya Sanat Galerisi\'nde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Müze veya Sanat Galerisi ile ilgili 10 yaygın ifade ve bunların Rusça çevirileri:\"]', '[\"Ziyaret Etmek\", \"Rehberli Tur\", \"Bilet Satın Almak\"]', 'tr', '[\"Şimdilik aklınızda özel bir durum var mı, örneğin tanıtım kılavuzu istemek, yol haritası ile ilgili ifadeler kullanmak, sergilenen eserler hakkında yorum yapmak gibi? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"Sesli rehberleriniz var mı?\", \"translated\": \"У вас есть аудиогиды?\"}, {\"original\": \"Bu eseri kim yaratmış?\", \"translated\": \"Кто создал это произведение искусства?\"}, {\"original\": \"Müzenin en değerli eseri nerede?\", \"translated\": \"Где находится самая ценная экспонат музея?\"}, {\"original\": \"Fotoğraf çekmeye izin veriliyor mu?\", \"translated\": \"Разрешена ли фотосъёмка?\"}, {\"original\": \"Burada özel sergiler var mı?\", \"translated\": \"Здесь проходят какие-нибудь специальные выставки?\"}, {\"original\": \"Ziyaret kaç dakika sürüyor?\", \"translated\": \"Сколько времени занимает посещение?\"}, {\"original\": \"Bize bir giriş yapar mısınız?\", \"translated\": \"Не могли бы вы представить нам краткое введение?\"}, {\"original\": \"Bu eserler gerçekten çok zarif.\", \"translated\": \"Эти произведения действительно изысканны.\"}, {\"original\": \"Hediyelik eşya dükkanı nerede?\", \"translated\": \"Где находится магазин сувениров?\"}]', 11, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Kafelerde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte kafelerle ilgili 10 yaygın ifade ve bunların Rusça çevirileri:\"]', '[\"Kahvaltı Siparişi Verme\", \"Dinlenme\", \"Sosyalleşme\"]', 'tr', '[\"Şimdilik aklınızda, bir menü istemek, soğuk ya da sıcak içecekler sipariş etmek, diğer ürünler almak gibi belirli bir durum mu var? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bir latte getirir misiniz?\", \"translated\": \"Я возьму латте, пожалуйста.\"}, {\"original\": \"Wi-Fi var mı?\", \"translated\": \"У вас есть Wi-Fi?\"}, {\"original\": \"Menüyü görebilir miyim, lütfen?\", \"translated\": \"Можно мне посмотреть меню, пожалуйста?\"}, {\"original\": \"İkinci dolum yapılabilir mi?\", \"translated\": \"Можно ли сделать дополнительный налив?\"}, {\"original\": \"Kahvaltım hazır mı?\", \"translated\": \"Мой кофе уже готов?\"}, {\"original\": \"Burada ne kadar süre oturabilirim?\", \"translated\": \"Сколько времени я могу здесь посидеть?\"}, {\"original\": \"Bizi birlikte çektikten sonra fotoğraf çekebilir misiniz?\", \"translated\": \"Не могли бы вы сделать нам фотографию?\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"Где туалет?\"}, {\"original\": \"Hesap, lütfen. Teşekkür ederim.\", \"translated\": \"Счёт, пожалуйста. Спасибо.\"}, {\"original\": \"Gerçekten çok lezzetli.\", \"translated\": \"Он очень вкусный.\"}]', 12, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"レストランで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、レストランに関連する一般的な表現10個とそのロシア語訳を示します：\"]', '[\"食事\", \"注文\", \"レジ\"]', 'ja', '[\"今のところ、注文、クレーム、食材の確認など、特定の状況が頭に浮かんでいますか？遠慮なくお尋ねください。\", \"頭に浮かんでいる状況を教えてください。\"]', NULL, '[{\"original\": \"すみません、料理はあとどのくらいで来ますか？\", \"translated\": \"Извините, сколько ещё ждать нашу еду?\"}, {\"original\": \"二人用のテーブルをお願いします。\", \"translated\": \"Столик на двоих, пожалуйста.\"}, {\"original\": \"メニューを見せていただけますか？\", \"translated\": \"Можно посмотреть меню, пожалуйста?\"}, {\"original\": \"おすすめの自家製料理はありますか？\", \"translated\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\"}, {\"original\": \"これを注文したいのですが、あとこれもお願いします。\", \"translated\": \"Я хочу заказать это и это.\"}, {\"original\": \"水を一杯お願いします。ありがとうございます。\", \"translated\": \"Стакан воды, пожалуйста. Спасибо.\"}, {\"original\": \"お会計をお願いします。\", \"translated\": \"Счёт, пожалуйста.\"}, {\"original\": \"クレジットカードで支払えますか？\", \"translated\": \"Можно оплатить кредитной картой?\"}, {\"original\": \"これを持ち帰り用に包んでいただけますか？\", \"translated\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\"}, {\"original\": \"料理がとても美味しかったです。ありがとうございました。\", \"translated\": \"Еда была восхитительной, спасибо.\"}]', 1, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ホテルで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、ホテル関連の一般的な表現10個とそのロシア語訳を示します：\"]', '[\"チェックイン\", \"チェックアウト\", \"ルームサービス\"]', 'ja', '[\"今のところ、お部屋の位置やその他のホテルサービス、チェックアウトなど、具体的な状況が頭に浮かんでいますか？何でもお気軽にお尋ねください。\", \"頭に浮かんでいる状況をご説明ください。\"]', NULL, '[{\"original\": \"こんにちは、予約をしております。こちらが私のパスポートです。\", \"translated\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\"}, {\"original\": \"空室はありますか？\", \"translated\": \"У вас есть свободные номера?\"}, {\"original\": \"すみませんが、ホテルにはジムやランドリールームはありますか？\", \"translated\": \"Извините, в отеле есть тренажёрный зал или прачечная?\"}, {\"original\": \"朝食の開始時間は何時ですか？\", \"translated\": \"Во сколько начинается завтрак?\"}, {\"original\": \"部屋の鍵をいただけますか？\", \"translated\": \"Можно мне ключ от номера, пожалуйста?\"}, {\"original\": \"荷物を部屋まで運んでいただけますか？\", \"translated\": \"Не могли бы вы помочь мне отнести багаж в номер?\"}, {\"original\": \"ルームサービスの呼び出し方はどうすればいいですか？\", \"translated\": \"Как вызвать службу обслуживания номеров?\"}, {\"original\": \"チェックアウトの時間は何時ですか？\", \"translated\": \"До какого времени необходимо освободить номер?\"}, {\"original\": \"領収書／請求書を書いていただけますか？\", \"translated\": \"Не могли бы вы выписать мне квитанцию/счёт?\"}, {\"original\": \"荷物をここに預けても大丈夫ですか？\", \"translated\": \"Можно оставить здесь мой багаж?\"}]', 2, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"空港で使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、空港に関連する一般的な表現10個とそのロシア語訳を示します：\"]', '[\"チェックイン\", \"搭乗\", \"手荷物預け\"]', 'ja', '[\"今のところ、チェックイン、手荷物受取、またはレンタカー利用など、特定の状況をお考えですか？お気軽にご質問ください。\", \"ご希望の状況をご説明ください。\"]', NULL, '[{\"original\": \"チェックインカウンターはどこですか？\", \"translated\": \"Где стойка регистрации?\"}, {\"original\": \"窓側の席をお願いします。\", \"translated\": \"Я бы хотел место у окна, пожалуйста.\"}, {\"original\": \"この便は遅れていますか？\", \"translated\": \"Этот рейс задерживается?\"}, {\"original\": \"この荷物を預けたいのですが。\", \"translated\": \"Мне нужно зарегистрировать этот багаж.\"}, {\"original\": \"搭乗口はどこですか？\", \"translated\": \"Где выход на посадку?\"}, {\"original\": \"飛行機が今から離陸します。\", \"translated\": \"Самолёт вот-вот взлетит.\"}, {\"original\": \"ノートパソコンとモバイルバッテリーを取り出さなければなりませんか？\", \"translated\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\"}, {\"original\": \"免税店はどこですか？\", \"translated\": \"Где магазин беспошлинной торговли?\"}, {\"original\": \"私のスーツケースが見つかりません。\", \"translated\": \"Я не могу найти свой чемодан.\"}, {\"original\": \"車椅子サービスはありますか？\", \"translated\": \"Предоставляется ли услуга инвалидных колясок?\"}]', 3, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"公共交通機関で使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、公共交通機関に関連する一般的な表現10個と、それらのロシア語訳を示します：\"]', '[\"バスまたは地下鉄の利用\", \"切符の購入\", \"乗り換え\"]', 'ja', '[\"今のところ、バス停の場所を尋ねる、運賃を確認する、降車するなど、特定の状況が頭に浮かんでいますか？何でもお気軽にお尋ねください。\", \"頭に浮かんでいる状況を教えてください。\"]', NULL, '[{\"original\": \"このバスは終点まで行きますか？\", \"translated\": \"Этот автобус идёт до автовокзала?\"}, {\"original\": \"次の停留所はどこですか？\", \"translated\": \"Какая следующая остановка?\"}, {\"original\": \"切符はどこで買えますか？\", \"translated\": \"Где я могу купить билет?\"}, {\"original\": \"XX行きの切符を一枚お願いします。\", \"translated\": \"Один билет до XX, пожалуйста.\"}, {\"original\": \"乗り換えが必要ですか？\", \"translated\": \"Нужно ли мне пересаживаться?\"}, {\"original\": \"次の地下鉄の列車まであと何分ですか？\", \"translated\": \"Через сколько прибудет следующий поезд метро?\"}, {\"original\": \"すみません、通らせてください。\", \"translated\": \"Извините, пропустите меня, пожалуйста.\"}, {\"original\": \"この席は空いていますか？\", \"translated\": \"Это место занято?\"}, {\"original\": \"すみません、XXへ行くには２号線にどこで乗り換えればいいですか？\", \"translated\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\"}, {\"original\": \"XXへはどう行けばいいですか？\", \"translated\": \"Как мне добраться до XX?\"}]', 4, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"観光地で使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、観光地に関連する一般的な表現10個と、そのロシア語訳を示します：\"]', '[\"観光\", \"写真撮影\", \"チケット購入\"]', 'ja', '[\"今のところ、入場料の問い合わせ、駐車場の場所確認、またはガイドサービスの利用など、特定の状況が頭に浮かんでいますか？遠慮なくお尋ねください。\", \"頭に浮かんでいる状況を教えてください。\"]', NULL, '[{\"original\": \"入場料はいくらですか？\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"学生割引のチケットはありますか？\", \"translated\": \"Есть ли льготные билеты для студентов?\"}, {\"original\": \"観光スポットの開園時間は何時ですか？\", \"translated\": \"Во сколько открывается достопримечательность?\"}, {\"original\": \"ここではどんな楽しいことが体験できますか？\", \"translated\": \"Чем здесь можно интересно заняться?\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"Не могли бы вы сделать для нас фотографию?\"}, {\"original\": \"観光バスの乗り場はどこですか？\", \"translated\": \"Где автобус для осмотра достопримечательностей?\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"Где находится туалет?\"}, {\"original\": \"一番良い展望スポットはどこですか？\", \"translated\": \"Где лучшее место для просмотра?\"}, {\"original\": \"ここからの景色はとても美しいです。\", \"translated\": \"Здесь прекрасные виды.\"}, {\"original\": \"ガイド付きツアーはありますか？\", \"translated\": \"Доступна ли экскурсия с гидом?\"}]', 5, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"タクシーまたはタクシーサービスで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、タクシーまたはタクシーサービスに関連する一般的な表現10個と、そのロシア語訳を示します：\"]', '[\"タクシーを利用する\", \"行き先を伝える\", \"支払い\"]', 'ja', '[\"今のところ、目的地の確認、料金の確認、領収書の請求など、今最も知りたいことは何ですか？ご自由にお尋ねください。\", \"頭の中で思い浮かぶ状況を教えてください。\"]', NULL, '[{\"original\": \"タクシーはどこで乗れますか？\", \"translated\": \"Где можно взять такси?\"}, {\"original\": \"この住所までお願いします。\", \"translated\": \"Пожалуйста, отвезите меня по этому адресу.\"}, {\"original\": \"だいたいいくらぐらいになりますか？\", \"translated\": \"Примерно сколько это будет стоить?\"}, {\"original\": \"メーターを使っていただけますか？\", \"translated\": \"Не могли бы вы, пожалуйста, включить счётчик?\"}, {\"original\": \"急いでいるので、もう少し速く運転していただけますか？\", \"translated\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\"}, {\"original\": \"ここで止めてください。\", \"translated\": \"Остановитесь, пожалуйста, здесь.\"}, {\"original\": \"カードやモバイル決済は使えますか？\", \"translated\": \"Принимаете ли вы оплату картой или через мобильные платежи?\"}, {\"original\": \"領収書をいただけますか？\", \"translated\": \"Можно мне, пожалуйста, чек?\"}, {\"original\": \"ありがとうございました、運転手さん。\", \"translated\": \"Спасибо, водитель.\"}, {\"original\": \"あとどのくらいですか？\", \"translated\": \"Сколько ещё ехать?\"}]', 6, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"薬局で使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、薬局でよく使われる10個の表現と、それらのロシア語訳を示します：\"]', '[\"薬の購入\", \"相談\", \"支払い\"]', 'ja', '[\"今のところ、服薬方法の説明を尋ねる場面や、保険の利用に関する表現、服用期間についての表現など、特定の状況が頭に浮かんでいますか？ご自由にお尋ねください。\", \"頭に浮かんでいる状況を教えてください。\"]', NULL, '[{\"original\": \"風邪薬はありますか？\", \"translated\": \"У вас есть лекарство от простуды?\"}, {\"original\": \"この薬の飲み方はどうすればいいですか？\", \"translated\": \"Как мне принимать это лекарство?\"}, {\"original\": \"鎮痛剤はありますか？\", \"translated\": \"У вас есть обезболивающие?\"}, {\"original\": \"説明書は付いていますか？\", \"translated\": \"Есть ли инструкция по применению?\"}, {\"original\": \"この薬には副作用がありますか？\", \"translated\": \"Это лекарство имеет какие-либо побочные эффекты?\"}, {\"original\": \"医療保険証を使っても大丈夫ですか？\", \"translated\": \"Могу ли я воспользоваться своей медицинской страховой картой?\"}, {\"original\": \"バンドエイドを一箱お願いできますか？\", \"translated\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\"}, {\"original\": \"解熱剤はありますか？\", \"translated\": \"У вас есть жаропонижающие?\"}, {\"original\": \"ちょっと擦り傷をしました。消毒液とバンドエイドはありますか？\", \"translated\": \"Я немного поранился. У вас есть антисептик и пластыри?\"}, {\"original\": \"何時まで営業していますか？\", \"translated\": \"Во сколько вы закрываетесь?\"}]', 7, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"緊急サービスで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、緊急サービスに関連する一般的な表現10個と、そのロシア語訳を示します：\"]', '[\"警察を呼ぶ\", \"応急処置\", \"助けを呼ぶ\"]', 'ja', '[\"今のところ、火事、怪我をして助けが必要、緊急通報など、特定の緊急状況について考えていますか？ご質問はいつでもどうぞ。\", \"頭の中で思い浮かべている状況を教えてください。\"]', NULL, '[{\"original\": \"救急車を呼んでください。\", \"translated\": \"Пожалуйста, помогите мне вызвать скорую помощь.\"}, {\"original\": \"病院はどこですか？\", \"translated\": \"Где находится больница?\"}, {\"original\": \"誰かが怪我をしました。\", \"translated\": \"Кто-то получил травму.\"}, {\"original\": \"助けてください。\", \"translated\": \"Пожалуйста, помогите мне.\"}, {\"original\": \"警察署はどこですか？\", \"translated\": \"Где находится полицейский участок?\"}, {\"original\": \"荷物をなくしました。\", \"translated\": \"Я потерял свои вещи.\"}, {\"original\": \"消防署の電話番号は何番ですか？\", \"translated\": \"Какой номер пожарной службы?\"}, {\"original\": \"パスポートを紛失しました。近くの警察署はどこですか？\", \"translated\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\"}, {\"original\": \"非常口はありますか？\", \"translated\": \"Здесь есть аварийный выход?\"}, {\"original\": \"誰かが気を失いました。\", \"translated\": \"Кто-то потерял сознание.\"}]', 8, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ビーチやプールサイドで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、ビーチやプールサイドに関連する一般的な表現10個と、そのロシア語訳を示します：\"]', '[\"水泳\", \"日光浴\", \"ビーチスポーツ\"]', 'ja', '[\"現時点で、ご参加予定の地域のイベントや祭り（例：文化祭、フードフェスティバル、音楽祭など）の背景について教えていただけますか？背景情報をご提供ください。\", \"ご参加予定のアクティビティを教えてください。\"]', '[\"具体的な状況が頭に浮かんでいますか？遠慮なくお尋ねください。\", \"頭に浮かんでいる状況を説明してください。\"]', '[{\"original\": \"見て！あそこに見える波が本当に大きいよ。\", \"translated\": \"Смотрите! Волны там действительно очень большие.\"}, {\"original\": \"日焼け止めを塗ることを忘れないでね。ここでの紫外線はとても強いから。\", \"translated\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\"}, {\"original\": \"このビーチの砂はとても細かくて、綿の上を歩いているような感じがする。\", \"translated\": \"Песок на этом пляже такой мелкий, что идти по нему — всё равно что ступать по хлопку.\"}, {\"original\": \"ビーチでバレーボールをやるのはどう？\", \"translated\": \"Как насчёт игры в волейбол на пляже?\"}, {\"original\": \"遠くに見えるヨットがとても美しいね。\", \"translated\": \"Парусники вдали выглядят очень красиво.\"}, {\"original\": \"ここでの水はとても透明で、魚まで見えちゃうよ。\", \"translated\": \"Вода здесь такая прозрачная, что даже рыбок можно разглядеть.\"}, {\"original\": \"一緒に貝殻を探しに行こう。\", \"translated\": \"Давайте пойдём собирать морские ракушки.\"}, {\"original\": \"夕日が沈む頃にビーチを散歩するのは、きっととてもロマンチックだろうね。\", \"translated\": \"Прогулка по пляжу на закате, наверное, очень романтична.\"}, {\"original\": \"ここでは海産物がとても新鮮だと聞いたから、ぜひ食べてみよう。\", \"translated\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\"}, {\"original\": \"潮が満ちてきたから、岸に向かおう。\", \"translated\": \"Начинается прилив, давайте направимся к берегу.\"}]', 9, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"地域のイベントや祭りで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、地域のイベントや祭りに関連する一般的な表現10個と、そのロシア語訳を示します：\"]', '[\"イベントへの参加\", \"祭りの祝い\", \"文化の学習\"]', 'ja', '[\"まずは、あなたが参加予定の地域のイベントや祭りの状況（例：ハロウィン、コンサート、友人とのパーティーなど）について教えていただけますか？その他でも構いませんので、状況を教えてください。\", \"あなたの頭に浮かぶ活動内容を教えてください。\"]', '[\"特定の状況が思い浮かびましたら、遠慮なくお尋ねください。\", \"あなたの頭に浮かぶ状況を教えてください。\"]', '[{\"original\": \"今日何かイベントはありますか？\", \"translated\": \"Есть ли сегодня какие-нибудь мероприятия?\"}, {\"original\": \"この祭りには何か特別なことがありますか？\", \"translated\": \"В этом празднике есть что-нибудь особенное?\"}, {\"original\": \"お祝いはどこで行われますか？\", \"translated\": \"Где проходит празднование?\"}, {\"original\": \"チケットの購入方法を教えてください。\", \"translated\": \"Как я могу купить билеты?\"}, {\"original\": \"パフォーマンスは何時から始まりますか？\", \"translated\": \"Во сколько начинается представление?\"}, {\"original\": \"どんな伝統的な食べ物がありますか？\", \"translated\": \"Какая традиционная еда здесь есть?\"}, {\"original\": \"ここは本当ににぎやかですね。\", \"translated\": \"Здесь действительно оживлённо.\"}, {\"original\": \"民俗行事はありますか？\", \"translated\": \"Есть ли какие-нибудь народные мероприятия?\"}, {\"original\": \"楽しい休日を！\", \"translated\": \"Счастливых праздников!\"}, {\"original\": \"イベントは何時までですか？\", \"translated\": \"Во сколько заканчивается мероприятие?\"}]', 10, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"美術館または博物館で使える一般的な表現を10個教えていただけますか？\", \"素晴らしいです！以下に、美術館または博物館に関連する一般的な表現10個と、それらのロシア語訳を示します：\"]', '[\"訪問\", \"ガイド付きツアー\", \"チケット購入\"]', 'ja', '[\"今のところ、案内パンフレットの請求、ルートマップに関する表現、展示品に対する感想を述べる表現など、特定の状況が頭に浮かんでいますか？ご自由にお尋ねください。\", \"頭に浮かんでいる状況を教えてください。\"]', NULL, '[{\"original\": \"入館料はいくらですか？\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"オーディオガイドはありますか？\", \"translated\": \"У вас есть аудиогиды?\"}, {\"original\": \"この作品は誰が制作したのですか？\", \"translated\": \"Кто создал это произведение искусства?\"}, {\"original\": \"美術館の最も貴重な作品はどこにありますか？\", \"translated\": \"Где находится самая ценная экспозиция музея?\"}, {\"original\": \"写真撮影は許可されていますか？\", \"translated\": \"Разрешена ли фотосъёмка?\"}, {\"original\": \"ここには特別展はありますか？\", \"translated\": \"Здесь проходят какие-нибудь специальные выставки?\"}, {\"original\": \"見学にはどのくらいの時間がかかりますか？\", \"translated\": \"Сколько времени занимает посещение?\"}, {\"original\": \"ご案内いただけますか？\", \"translated\": \"Не могли бы вы кратко рассказать об экспозиции?\"}, {\"original\": \"これらの作品は本当に素晴らしいです。\", \"translated\": \"Эти произведения действительно изысканны.\"}, {\"original\": \"お土産ショップはどこですか？\", \"translated\": \"Где находится магазин сувениров?\"}]', 11, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"カフェで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、カフェに関連する一般的な表現10個とそのロシア語訳を示します：\"]', '[\"コーヒーを注文する\", \"休む\", \"交流する\"]', 'ja', '[\"今のところ、メニューの注文、アイスまたはホットドリンクの依頼、その他の商品の確認など、特定の状況が頭に浮かんでいますか？何でもお気軽にお尋ねください。\", \"頭に浮かんでいる状況を教えてください。\"]', NULL, '[{\"original\": \"ラテを一杯お願いします。\", \"translated\": \"Я возьму латте, пожалуйста.\"}, {\"original\": \"Wi-Fiはありますか？\", \"translated\": \"У вас есть Wi-Fi?\"}, {\"original\": \"メニューを見せていただけますか？\", \"translated\": \"Можно мне посмотреть меню, пожалуйста?\"}, {\"original\": \"追加注文はできますか？\", \"translated\": \"Разрешено ли добавлять кофе бесплатно?\"}, {\"original\": \"私のコーヒーはできましたか？\", \"translated\": \"Мой кофе уже готов?\"}, {\"original\": \"ここにどのくらい座っていられますか？\", \"translated\": \"Сколько времени я могу здесь посидеть?\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"Не могли бы вы сделать нам фотографию?\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"Где туалет?\"}, {\"original\": \"お会計をお願いします。ありがとうございます。\", \"translated\": \"Счёт, пожалуйста. Спасибо.\"}, {\"original\": \"とてもおいしいです。\", \"translated\": \"Очень вкусно.\"}]', 12, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a restaurant?\", \"Fantastic! Here are 10 common phrases related to restaurants, along with Russian translations:\"]', '[\"Dining\", \"Ordering\", \"Checkout\"]', 'en', '[\"For now, do you have a specific situation in mind, such as ordering drinks, making a complaint, or asking about ingredients? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Excuse me, how much longer will our food be?\", \"translated\": \"Извините, сколько ещё ждать нашу еду?\"}, {\"original\": \"A table for two, please.\", \"translated\": \"Столик на двоих, пожалуйста.\"}, {\"original\": \"Could we see the menu, please?\", \"translated\": \"Можно посмотреть меню, пожалуйста?\"}, {\"original\": \"Do you have any signature dishes to recommend?\", \"translated\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\"}, {\"original\": \"I\'d like to order this, and this.\", \"translated\": \"Я хочу заказать это и это.\"}, {\"original\": \"A glass of water, please. Thanks.\", \"translated\": \"Стакан воды, пожалуйста. Спасибо.\"}, {\"original\": \"The bill, please.\", \"translated\": \"Счёт, пожалуйста.\"}, {\"original\": \"Can I pay by credit card?\", \"translated\": \"Можно оплатить кредитной картой?\"}, {\"original\": \"Could you pack this to go, please?\", \"translated\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\"}, {\"original\": \"The food was delicious, thank you.\", \"translated\": \"Еда была восхитительной, спасибо.\"}]', 1, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a hotel?\", \"Fantastic! Here are 10 common phrases related to hotels, along with English translations:\"]', '[\"Check-in\", \"Check-out\", \"Room Service\"]', 'en', '[\"For now, do you have a specific situation in mind, such as room location, other hotel services, or check-out? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Hello, I have a reservation. Here is my passport.\", \"translated\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\"}, {\"original\": \"Do you have any vacancies?\", \"translated\": \"У вас есть свободные номера?\"}, {\"original\": \"Excuse me, does the hotel have a gym or a laundry room?\", \"translated\": \"Извините, в отеле есть тренажёрный зал или прачечная?\"}, {\"original\": \"What time does breakfast start?\", \"translated\": \"Во сколько начинается завтрак?\"}, {\"original\": \"Could I have a room key, please?\", \"translated\": \"Можно мне ключ от номера, пожалуйста?\"}, {\"original\": \"Could you help me take my luggage to the room?\", \"translated\": \"Не могли бы вы помочь мне отнести багаж в номер?\"}, {\"original\": \"How do I call room service?\", \"translated\": \"Как вызвать службу обслуживания номеров?\"}, {\"original\": \"What time is check-out?\", \"translated\": \"До какого времени необходимо освободить номер?\"}, {\"original\": \"Could you write me a receipt/invoice?\", \"translated\": \"Не могли бы вы выписать мне квитанцию/счёт?\"}, {\"original\": \"Can I leave my luggage here?\", \"translated\": \"Можно оставить здесь мой багаж?\"}]', 2, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use at the airport?\", \"Fantastic! Here are 10 common phrases related to the airport, along with Russian translations:\"]', '[\"Check-in\", \"Boarding\", \"Baggage Check\"]', 'en', '[\"For now, do you have a specific situation in mind, such as check-in, baggage claim, or car rental service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Where is the check-in counter?\", \"translated\": \"Где стойка регистрации?\"}, {\"original\": \"I\'d like a window seat, please.\", \"translated\": \"Я бы хотел место у окна, пожалуйста.\"}, {\"original\": \"Is this flight delayed?\", \"translated\": \"Этот рейс задерживается?\"}, {\"original\": \"I need to check this baggage.\", \"translated\": \"Мне нужно зарегистрировать этот багаж.\"}, {\"original\": \"Where is the boarding gate?\", \"translated\": \"Где выход на посадку?\"}, {\"original\": \"The plane is about to take off.\", \"translated\": \"Самолёт вот-вот взлетит.\"}, {\"original\": \"Do I need to take out my laptop and power bank?\", \"translated\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\"}, {\"original\": \"Where is the duty-free shop?\", \"translated\": \"Где магазин беспошлинной торговли?\"}, {\"original\": \"I can\'t find my suitcase.\", \"translated\": \"Я не могу найти свой чемодан.\"}, {\"original\": \"Do you have a wheelchair service?\", \"translated\": \"Предоставляется ли услуга инвалидных колясок?\"}]', 3, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in Public Transportation?\", \"Fantastic! Here are 10 common phrases related to Public Transportation, along with Russian translations:\"]', '[\"Taking Bus/Subway\", \"Buying Tickets\", \"Transferring\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for a bus stop, ticket price, or getting off? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Does this bus go to the terminal?\", \"translated\": \"Этот автобус идёт до автовокзала?\"}, {\"original\": \"What is the next stop?\", \"translated\": \"Какая следующая остановка?\"}, {\"original\": \"Where can I buy a ticket?\", \"translated\": \"Где я могу купить билет?\"}, {\"original\": \"One ticket to XX, please.\", \"translated\": \"Один билет до XX, пожалуйста.\"}, {\"original\": \"Do I need to transfer?\", \"translated\": \"Нужно ли мне пересаживаться?\"}, {\"original\": \"How long until the next subway train?\", \"translated\": \"Через сколько прибудет следующий поезд метро?\"}, {\"original\": \"Excuse me, please let me pass.\", \"translated\": \"Извините, пропустите меня, пожалуйста.\"}, {\"original\": \"Is this seat taken?\", \"translated\": \"Это место занято?\"}, {\"original\": \"Excuse me, where can I transfer to Line 2 to get to XX?\", \"translated\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\"}, {\"original\": \"How do I get to XX?\", \"translated\": \"Как мне добраться до XX?\"}]', 4, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in tourist attractions?\", \"Fantastic! Here are 10 common phrases related to tourist attractions, along with Russian translations:\"]', '[\"Sightseeing\", \"Taking Photos\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking about ticket prices, finding a parking lot, or requesting tour guide services? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"How much is the entrance fee?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"Are there student tickets available?\", \"translated\": \"Есть ли льготные билеты для студентов?\"}, {\"original\": \"What time does the attraction open?\", \"translated\": \"Во сколько открывается достопримечательность?\"}, {\"original\": \"What are the fun things to do here?\", \"translated\": \"Чем здесь интересно заняться?\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"Не могли бы вы сделать для нас фотографию?\"}, {\"original\": \"Where is the sightseeing bus?\", \"translated\": \"Где автобус для осмотра достопримечательностей?\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"Где находится туалет?\"}, {\"original\": \"Where is the best viewing spot?\", \"translated\": \"Где лучшее место для просмотра?\"}, {\"original\": \"The scenery here is beautiful.\", \"translated\": \"Здесь прекрасные виды.\"}, {\"original\": \"Is there a guided tour available?\", \"translated\": \"Доступна ли экскурсия с гидом?\"}]', 5, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in Taxi or Taxi Service?\", \"Fantastic! Here are 10 common phrases related to Taxi or Taxi Service, along with Russian translations:\"]', '[\"Taking Taxi\", \"Telling Destination\", \"Payment\"]', 'en', '[\"For now, what do you most want to do now—such as asking for the destination, the fare, or requesting an invoice? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Where can I get a taxi?\", \"translated\": \"Где я могу взять такси?\"}, {\"original\": \"Please take me to this address.\", \"translated\": \"Пожалуйста, отвезите меня по этому адресу.\"}, {\"original\": \"Roughly how much will it be?\", \"translated\": \"Примерно сколько это будет стоить?\"}, {\"original\": \"Could you use the meter, please?\", \"translated\": \"Не могли бы вы, пожалуйста, включить счётчик?\"}, {\"original\": \"Please drive a bit faster, I\'m in a hurry.\", \"translated\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\"}, {\"original\": \"Please stop here.\", \"translated\": \"Остановитесь, пожалуйста, здесь.\"}, {\"original\": \"Do you accept cards or mobile payments?\", \"translated\": \"Принимаете ли вы оплату картой или через мобильные платежи?\"}, {\"original\": \"Could I have a receipt, please?\", \"translated\": \"Можно мне, пожалуйста, чек?\"}, {\"original\": \"Thank you, driver.\", \"translated\": \"Спасибо, водитель.\"}, {\"original\": \"How much further is it?\", \"translated\": \"Как далеко ещё?\"}]', 6, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in pharmacy?\", \"Fantastic! Here are 10 common phrases related to pharmacy, along with Russian translations:\"]', '[\"Buying Medicine\", \"Consultation\", \"Payment\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking for instructions on taking medicine, phrases related to using insurance, or duration of medication? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Do you have cold medicine?\", \"translated\": \"У вас есть лекарство от простуды?\"}, {\"original\": \"How should I take this medicine?\", \"translated\": \"Как мне принимать это лекарство?\"}, {\"original\": \"Do you have any painkillers?\", \"translated\": \"У вас есть обезболивающие?\"}, {\"original\": \"Is there an instruction leaflet?\", \"translated\": \"Есть ли инструкция по применению?\"}, {\"original\": \"Does this medicine have any side effects?\", \"translated\": \"Это лекарство имеет какие-либо побочные эффекты?\"}, {\"original\": \"Can I use my medical insurance card?\", \"translated\": \"Можно ли воспользоваться моей медицинской страховкой?\"}, {\"original\": \"Could I have a box of Band-Aids, please?\", \"translated\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\"}, {\"original\": \"Do you have any fever reducers?\", \"translated\": \"У вас есть жаропонижающие?\"}, {\"original\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\", \"translated\": \"Я немного поранился. У вас есть антисептик и пластыри?\"}, {\"original\": \"What time do you close?\", \"translated\": \"Во сколько вы закрываетесь?\"}]', 7, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in Emergency Services?\", \"Fantastic! Here are 10 common phrases related to Emergency Services, along with Russian translations:\"]', '[\"Calling Police\", \"First Aid\", \"Calling for Help\"]', 'en', '[\"For now, do you have a specific emergency situation in mind, such as fire, injury and need for help, or an emergency call? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Please help me call an ambulance.\", \"translated\": \"Пожалуйста, помогите мне вызвать скорую помощь.\"}, {\"original\": \"Where is the hospital?\", \"translated\": \"Где находится больница?\"}, {\"original\": \"Someone is injured.\", \"translated\": \"Кто-то получил травму.\"}, {\"original\": \"Please help me.\", \"translated\": \"Пожалуйста, помогите мне.\"}, {\"original\": \"Where is the police station?\", \"translated\": \"Где находится полицейский участок?\"}, {\"original\": \"I\'ve lost my belongings.\", \"translated\": \"Я потерял свои вещи.\"}, {\"original\": \"What is the number for the fire department?\", \"translated\": \"Какой номер пожарной службы?\"}, {\"original\": \"I\'ve lost my passport. Do you know where the nearest police station is?\", \"translated\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\"}, {\"original\": \"Is there an emergency exit?\", \"translated\": \"Здесь есть аварийный выход?\"}, {\"original\": \"Someone has fainted.\", \"translated\": \"Кто-то потерял сознание.\"}]', 8, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use at the beach or poolside?\", \"Fantastic! Here are 10 common phrases related to the beach or poolside, along with English translations:\"]', '[\"Swimming\", \"Sunbathing\", \"Beach Sports\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you’re attending, such as a cultural festival, food festival, or music festival? Please provide the context.\", \"Please provide the activities that you attend.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[{\"original\": \"Look! The waves over there are really big.\", \"translated\": \"Смотрите! Волны там действительно очень большие.\"}, {\"original\": \"Remember to apply sunscreen; the UV rays here are very strong.\", \"translated\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовое излучение здесь очень сильное.\"}, {\"original\": \"The sand on this beach is so fine, it feels like stepping on cotton.\", \"translated\": \"Песок на этом пляже такой мелкий, что кажется, будто вы ступаете по хлопку.\"}, {\"original\": \"How about playing volleyball on the beach?\", \"translated\": \"Как насчёт игры в волейбол на пляже?\"}, {\"original\": \"The sailboats in the distance look beautiful.\", \"translated\": \"Парусники вдали выглядят очень красиво.\"}, {\"original\": \"The water here is so clear, you can even see the fish.\", \"translated\": \"Вода здесь такая прозрачная, что даже видно рыб.\"}, {\"original\": \"Let\'s go find some seashells.\", \"translated\": \"Давайте пойдём поискать ракушки.\"}, {\"original\": \"Taking a walk on the beach at sunset must be very romantic.\", \"translated\": \"Прогулка по пляжу на закате, наверное, очень романтична.\"}, {\"original\": \"I heard the seafood here is very fresh; let\'s go try some.\", \"translated\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\"}, {\"original\": \"The tide is coming in; let\'s head towards the shore.\", \"translated\": \"Начинается прилив, давайте направимся к берегу.\"}]', 9, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in Local Events and Festivals?\", \"Fantastic! Here are 10 common phrases related to Local Events and Festivals, along with English translations:\"]', '[\"Attending Events\", \"Celebrating Festivals\", \"Learning Culture\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you\'re attending, such as Halloween, a concert, a friend\'s party, or something else? Please provide the context.\", \"Please describe the activities you have in mind.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation you have in mind.\"]', '[{\"original\": \"Are there any events today?\", \"translated\": \"Есть ли сегодня какие-нибудь мероприятия?\"}, {\"original\": \"Is there anything special about this festival?\", \"translated\": \"В этом празднике есть что-нибудь особенное?\"}, {\"original\": \"Where is the celebration being held?\", \"translated\": \"Где проходит празднование?\"}, {\"original\": \"How can I buy tickets?\", \"translated\": \"Как я могу купить билеты?\"}, {\"original\": \"What time does the performance start?\", \"translated\": \"Во сколько начинается представление?\"}, {\"original\": \"What traditional food is there?\", \"translated\": \"Какая традиционная еда здесь есть?\"}, {\"original\": \"It\'s really lively here.\", \"translated\": \"Здесь действительно оживлённо.\"}, {\"original\": \"Are there any folk activities?\", \"translated\": \"Есть ли какие-нибудь народные мероприятия?\"}, {\"original\": \"Happy holidays!\", \"translated\": \"С праздником!\"}, {\"original\": \"What time does the event end?\", \"translated\": \"Во сколько заканчивается мероприятие?\"}]', 10, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a museum or art gallery?\", \"Fantastic! Here are 10 common phrases related to museums or art galleries, along with Russian translations:\"]', '[\"Visiting\", \"Guided Tour\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking for an introduction manual, phrases related to a roadmap, or phrases related to commenting on an exhibit? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"How much is the admission fee?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"Do you have audio guides?\", \"translated\": \"Есть ли у вас аудиогиды?\"}, {\"original\": \"Who created this artwork?\", \"translated\": \"Кто является автором этого произведения искусства?\"}, {\"original\": \"Where is the museum\'s most prized piece?\", \"translated\": \"Где находится самое ценное произведение музея?\"}, {\"original\": \"Is photography allowed?\", \"translated\": \"Разрешена ли фотосъёмка?\"}, {\"original\": \"Are there any special exhibitions here?\", \"translated\": \"Есть ли здесь какие-нибудь специальные выставки?\"}, {\"original\": \"How long does the visit take?\", \"translated\": \"Сколько времени занимает посещение?\"}, {\"original\": \"Could you give us an introduction?\", \"translated\": \"Не могли бы вы кратко рассказать об экспозиции?\"}, {\"original\": \"These works are truly exquisite.\", \"translated\": \"Эти произведения действительно изысканны.\"}, {\"original\": \"Where is the souvenir shop?\", \"translated\": \"Где находится магазин сувениров?\"}]', 11, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in cafes?\", \"Fantastic! Here are 10 common phrases related to cafes, along with English translations:\"]', '[\"Ordering Coffee\", \"Resting\", \"Socializing\"]', 'en', '[\"For now, do you have a specific situation in mind, like asking for a menu, ice or hot drinks, other products? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"I\'ll have a latte, please.\", \"translated\": \"Я возьму латте, пожалуйста.\"}, {\"original\": \"Do you have Wi-Fi?\", \"translated\": \"У вас есть Wi-Fi?\"}, {\"original\": \"Could I see the menu, please?\", \"translated\": \"Можно мне посмотреть меню, пожалуйста?\"}, {\"original\": \"Are refills allowed?\", \"translated\": \"Разрешено ли дополнительное наливание?\"}, {\"original\": \"Is my coffee ready?\", \"translated\": \"Готов мой кофе?\"}, {\"original\": \"How long can I sit here?\", \"translated\": \"Сколько времени я могу здесь посидеть?\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"Не могли бы вы сделать для нас фотографию?\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"Где туалет?\"}, {\"original\": \"Check, please. Thank you.\", \"translated\": \"Счёт, пожалуйста. Спасибо.\"}, {\"original\": \"It tastes really good.\", \"translated\": \"Очень вкусно.\"}]', 12, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في الفندق؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بالفندق، مع الترجمات الروسية المقابلة:\"]', '[\"تسجيل الدخول\", \"تسجيل المغادرة\", \"خدمة الغرف\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف معين في ذهنك، مثل موقع الغرفة أو أي خدمة فندقية أخرى أو إجراءات المغادرة؟ لا تتردد في طرح الأسئلة.\", \"من فضلك وصف الموقف الذي يخطر ببالك.\"]', NULL, '[{\"original\": \"مرحبًا، لدي حجزٌ، وهذه جواز سفري.\", \"translated\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\"}, {\"original\": \"هل لديكم أي غرف شاغرة؟\", \"translated\": \"У вас есть свободные номера?\"}, {\"original\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسيل الملابس؟\", \"translated\": \"Извините, в отеле есть тренажёрный зал или прачечная?\"}, {\"original\": \"في أي وقت تبدأ وجبة الإفطار؟\", \"translated\": \"Во сколько начинается завтрак?\"}, {\"original\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\", \"translated\": \"Можно мне ключ от номера, пожалуйста?\"}, {\"original\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\", \"translated\": \"Не могли бы вы помочь мне отнести багаж в номер?\"}, {\"original\": \"كيف أطلب خدمة الغرف؟\", \"translated\": \"Как вызвать службу обслуживания номеров?\"}, {\"original\": \"في أي وقت يتم المغادرة؟\", \"translated\": \"До какого времени необходимо освободить номер?\"}, {\"original\": \"هل يمكنكم إعطائي إيصالًا/فاتورةً؟\", \"translated\": \"Не могли бы вы выписать мне квитанцию/счёт?\"}, {\"original\": \"هل يمكنني ترك أمتعتي هنا؟\", \"translated\": \"Можно оставить здесь мой багаж?\"}]', 2, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في المطار؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بالمطار، مع الترجمات الروسية الخاصة بها:\"]', '[\"التسجيل\", \"الصعود إلى الطائرة\", \"فحص الأمتعة\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف معين في بالك، مثل تسجيل الوصول أو استلام الأمتعة أو خدمة تأجير السيارات؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي يدور في ذهنك.\"]', NULL, '[{\"original\": \"أين كاونتر تسجيل الدخول؟\", \"translated\": \"Где стойка регистрации?\"}, {\"original\": \"أود أن أجلس في مقعد بجانب النافذة، من فضلك.\", \"translated\": \"Я бы хотел место у окна, пожалуйста.\"}, {\"original\": \"هل هذا الرحلة متأخرة؟\", \"translated\": \"Этот рейс задерживается?\"}, {\"original\": \"أحتاج إلى فحص هذه الأمتعة.\", \"translated\": \"Мне нужно зарегистрировать этот багаж.\"}, {\"original\": \"أين بوابة الصعود إلى الطائرة؟\", \"translated\": \"Где выход на посадку?\"}, {\"original\": \"الطائرة على وشك الإقلاع.\", \"translated\": \"Самолёт вот-вот взлетит.\"}, {\"original\": \"هل يجب أن أخرج جهاز الكمبيوتر المحمول والبنك الكهربائي الخاص بي؟\", \"translated\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\"}, {\"original\": \"أين متجر التفريغ الجمركي؟\", \"translated\": \"Где магазин беспошлинной торговли?\"}, {\"original\": \"لا أستطيع العثور على حقيبتي.\", \"translated\": \"Я не могу найти свой чемодан.\"}, {\"original\": \"هل تقدمون خدمة الكرسي المتحرك؟\", \"translated\": \"Предоставляется ли услуга инвалидных колясок?\"}]', 3, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في وسائل النقل العام؟\", \"رائع! إليكم عشر عبارات شائعة تتعلق بوسائل النقل العام، مع الترجمة الروسية لها:\"]', '[\"ركوب الحافلة أو المترو\", \"شراء التذاكر\", \"التحويل\"]', 'ar', '[\"في الوقت الراهن، هل لديك موقفٌ معيّن في ذهنك، مثل الاستفسار عن موقف الحافلة أو سعر التذكرة أو طلب النزول من الحافلة؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي يدور في ذهنك.\"]', NULL, '[{\"original\": \"هل هذه الحافلة تذهب إلى المحطة؟\", \"translated\": \"Этот автобус идёт до автовокзала?\"}, {\"original\": \"ما هي المحطة التالية؟\", \"translated\": \"Какая следующая остановка?\"}, {\"original\": \"أين يمكنني شراء تذكرة؟\", \"translated\": \"Где я могу купить билет?\"}, {\"original\": \"تذكرة واحدة إلى XX، من فضلك.\", \"translated\": \"Один билет до XX, пожалуйста.\"}, {\"original\": \"هل عليَّ التحويل؟\", \"translated\": \"Нужно ли мне пересаживаться?\"}, {\"original\": \"كم المدة المتبقية حتى قطار المترو القادم؟\", \"translated\": \"Через сколько прибудет следующий поезд метро?\"}, {\"original\": \"عذرًا، من فضلك اسمح لي بالمرور.\", \"translated\": \"Извините, пропустите меня, пожалуйста.\"}, {\"original\": \"هل هذا المقعد محجوز؟\", \"translated\": \"Это место занято?\"}, {\"original\": \"عذرًا، أين يمكنني التحويل إلى الخط الثاني للوصول إلى XX؟\", \"translated\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\"}, {\"original\": \"كيف أصل إلى XX؟\", \"translated\": \"Как мне добраться до XX?\"}]', 4, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في أماكن الجذب السياحي؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بأماكن الجذب السياحي، مع الترجمات الروسية المقابلة:\"]', '[\"السياحة\", \"التقاط الصور\", \"شراء التذاكر\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف محدد في ذهنك، مثل الاستفسار عن سعر التذاكر، أو إيجاد موقف للسيارات، أو طلب خدمة دليل سياحي؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي يدور في ذهنك.\"]', NULL, '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"هل تتوفر تذاكر للطلاب؟\", \"translated\": \"Есть ли льготные билеты для студентов?\"}, {\"original\": \"في أي وقت يفتح المعلم السياحي؟\", \"translated\": \"Во сколько открывается достопримечательность?\"}, {\"original\": \"ما الأشياء الممتعة التي يمكن القيام بها هنا؟\", \"translated\": \"Чем здесь интересно заняться?\"}, {\"original\": \"هل يمكنك التقاط صورة لنا؟\", \"translated\": \"Не могли бы вы сделать для нас фотографию?\"}, {\"original\": \"أين حافلة الجولات السياحية؟\", \"translated\": \"Где автобус для осмотра достопримечательностей?\"}, {\"original\": \"أين الحمام؟\", \"translated\": \"Где находится туалет?\"}, {\"original\": \"ما أفضل مكان لمشاهدة المناظر؟\", \"translated\": \"Где лучшее место для просмотра?\"}, {\"original\": \"المنظر هنا جميلٌ جدًّا.\", \"translated\": \"Здесь прекрасный вид.\"}, {\"original\": \"هل توجد جولة إرشادية متاحة؟\", \"translated\": \"Доступна ли экскурсия с гидом?\"}]', 5, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها عند استئجار تاكسي أو استخدام خدمة التاكسي؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بالتاكسي أو خدمة التاكسي، مع الترجمة الروسية لها:\"]', '[\"أخذ تاكسي\", \"إبلاغ الوجهة\", \"الدفع\"]', 'ar', '[\"في الوقت الحالي، ما الذي تود فعله أكثر الآن؟ مثل سؤال عن الوجهة، أو السعر، أو طلب فاتورة. لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي يجول في ذهنك.\"]', NULL, '[{\"original\": \"أين يمكنني أخذ تاكسي؟\", \"translated\": \"Где я могу взять такси?\"}, {\"original\": \"من فضلك خذني إلى هذا العنوان.\", \"translated\": \"Пожалуйста, отвезите меня по этому адресу.\"}, {\"original\": \"كم يبلغ السعر تقريبًا؟\", \"translated\": \"Примерно сколько это будет стоить?\"}, {\"original\": \"هل يمكنك استخدام العداد من فضلك؟\", \"translated\": \"Не могли бы вы, пожалуйста, включить счётчик?\"}, {\"original\": \"من فضلك ا-driving أسرع قليلًا، فأنا مستعجل.\", \"translated\": \"Пожалуйста, поезжайте немного быстрее, мне спешно.\"}, {\"original\": \"من فضلك توقف هنا.\", \"translated\": \"Остановитесь, пожалуйста, здесь.\"}, {\"original\": \"هل تقبل الدفع بالبطاقات أو عبر الهاتف المحمول؟\", \"translated\": \"Принимаете ли вы оплату картой или через мобильные приложения?\"}, {\"original\": \"هل يمكنني الحصول على إشعار دفع من فضلك؟\", \"translated\": \"Можно мне, пожалуйста, чек?\"}, {\"original\": \"شكرًا لك يا سائق.\", \"translated\": \"Спасибо, водитель.\"}, {\"original\": \"كم تبقى من المسافة؟\", \"translated\": \"Сколько ещё осталось ехать?\"}]', 6, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في الصيدلية؟\", \"رائع! إليكم عشر عبارات شائعة تتعلق بالصيدلية، مع الترجمات الروسية المقابلة:\"]', '[\"شراء أدوية\", \"استشارة\", \"دفع\"]', 'ar', '[\"في الوقت الحالي، هل لديكم موقف محدد في ذهنكم، مثل طلب توجيهات حول كيفية تناول الدواء، أو العبارات المتعلقة باستخدام التأمين الصحي، أو مدة تناول الدواء؟ لا تترددوا في طرح أي سؤال.\", \"يرجى وصف الموقف الذي يخطر ببالكم.\"]', NULL, '[{\"original\": \"هل لديكم دواء للبرد؟\", \"translated\": \"У вас есть лекарство от простуды?\"}, {\"original\": \"كيف يجب أن آخذ هذا الدواء؟\", \"translated\": \"Как мне принимать это лекарство?\"}, {\"original\": \"هل لديكم مسكنات للألم؟\", \"translated\": \"У вас есть обезболивающие?\"}, {\"original\": \"هل توجد نشرة إرشادات مع هذا الدواء؟\", \"translated\": \"Есть ли инструкция по применению?\"}, {\"original\": \"هل لهذا الدواء أي آثار جانبية؟\", \"translated\": \"Это лекарство имеет какие-либо побочные эффекты?\"}, {\"original\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\", \"translated\": \"Можно ли воспользоваться моей медицинской страховкой?\"}, {\"original\": \"هل يمكنني الحصول على علبة من الضمادات اللاصقة، من فضلكم؟\", \"translated\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\"}, {\"original\": \"هل لديكم خافضات للحرارة؟\", \"translated\": \"У вас есть жаропонижающие?\"}, {\"original\": \"لديّ جرح سطحي بسيط. هل لديكم مطهر وضمادات لاصقة؟\", \"translated\": \"Я немного поранился. У вас есть антисептик и пластыри?\"}, {\"original\": \"في أي وقت تغلقون؟\", \"translated\": \"Во сколько вы закрываетесь?\"}]', 7, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في خدمات الطوارئ؟\", \"رائع! إليكم عشر عبارات شائعة تتعلق بخدمات الطوارئ، مع الترجمات الروسية الخاصة بها:\"]', '[\"الاتصال بالشرطة\", \"الإسعافات الأولية\", \"الاستغاثة\"]', 'ar', '[\"في الوقت الحالي، هل توجد لديك حالة طارئة محددة في ذهنك، مثل الحريق أو الإصابة والاحتياج للمساعدة أو الاتصال بالطوارئ؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الحالة التي تدور في ذهنك.\"]', NULL, '[{\"original\": \"من فضلك ساعدني في الاتصال بالإسعاف.\", \"translated\": \"Пожалуйста, помогите мне вызвать скорую помощь.\"}, {\"original\": \"أين المستشفى؟\", \"translated\": \"Где находится больница?\"}, {\"original\": \"شخص ما أُصيب.\", \"translated\": \"Кто-то получил травму.\"}, {\"original\": \"من فضلك ساعدني.\", \"translated\": \"Пожалуйста, помогите мне.\"}, {\"original\": \"أين قسم الشرطة؟\", \"translated\": \"Где находится полицейский участок?\"}, {\"original\": \"لقد فقدت أغراضي.\", \"translated\": \"Я потерял свои вещи.\"}, {\"original\": \"ما هو رقم إدارة الإطفاء؟\", \"translated\": \"Какой номер пожарной службы?\"}, {\"original\": \"لقد فقدت جواز سفري. هل تعرف أين أقرب قسم شرطة؟\", \"translated\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\"}, {\"original\": \"هل يوجد مخرج طوارئ؟\", \"translated\": \"Здесь есть аварийный выход?\"}, {\"original\": \"شخص ما فقد وعيه.\", \"translated\": \"Кто-то потерял сознание.\"}]', 8, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها على الشاطئ أو بالقرب من المسبح؟\", \"رائع! إليكم عشر عبارات شائعة مرتبطة بالشاطئ أو المسبح، مع الترجمات الروسية الخاصة بها:\"]', '[\"السباحة\", \"الاستلقاء تحت أشعة الشمس\", \"الرياضات الشاطئية\"]', 'ar', '[\"في الوقت الحالي، هل يمكنكم تزويدي بسياق الحدث المحلي أو المهرجان الذي ستشاركون فيه، مثل مهرجان ثقافي أو مهرجان غذائي أو مهرجان موسيقي؟ يُرجى تزويدي بهذا السياق.\", \"يرجى تزويدي بالأنشطة التي ستشاركون فيها.\"]', '[\"هل لديكم موقف معين في ذهنكم؟ لا تترددوا في طرح أي سؤال.\", \"يرجى وصف الموقف الذي تفكرون فيه.\"]', '[{\"original\": \"انظر! الأمواج هناك كبيرة جدًّا.\", \"translated\": \"Смотрите! Волны там действительно очень большие.\"}, {\"original\": \"تذكَّر أن تضع واقي الشمس، فأشعة فوق البنفسجية هنا قوية جدًّا.\", \"translated\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\"}, {\"original\": \"الرمل على هذه الشاطئ ناعم جدًّا، لدرجة أن المشي عليه يشبه المشي على القطن.\", \"translated\": \"Песок на этом пляже такой мелкий, что кажется, будто вы ступаете по хлопку.\"}, {\"original\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\", \"translated\": \"Как насчёт игры в волейбол на пляже?\"}, {\"original\": \"القوارب الشراعية في الأفق تبدو جميلة جدًّا.\", \"translated\": \"Парусники вдали выглядят очень красиво.\"}, {\"original\": \"الماء هنا صافٍ جدًّا لدرجة أنك تستطيع رؤية الأسماك.\", \"translated\": \"Вода здесь такая прозрачная, что даже видно рыб.\"}, {\"original\": \"هيا نذهب للبحث عن بعض المحار.\", \"translated\": \"Давайте пойдём поискать ракушки.\"}, {\"original\": \"التنزُّه على الشاطئ عند غروب الشمس لا بد أنه أمرٌ رومانسيٌّ جدًّا.\", \"translated\": \"Прогулка по пляжу на закате, наверное, очень романтична.\"}, {\"original\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًّا، فلنذهب ونجرب بعضها.\", \"translated\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\"}, {\"original\": \"المدّ في ازدياد، فلنتجه نحو الساحل.\", \"translated\": \"Начинается прилив, давайте направимся к берегу.\"}]', 9, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك تزويدي بعشر عبارات شائعة يمكنني استخدامها في الفعاليات والمهرجانات المحلية؟\", \"رائع! إليك عشر عبارات شائعة مرتبطة بالفعاليات والمهرجانات المحلية، مع الترجمات الروسية المقابلة:\"]', '[\"حضور الفعاليات\", \"الاحتفال بالمناسبات\", \"تعلم الثقافة\"]', 'ar', '[\"في الوقت الحالي، هل يمكنك إخباري بالسياق الخاص بالفعالية أو المهرجان المحلي الذي ستشارك فيه، مثل عيد الهالوين أو الحفل الموسيقي أو حفلة أصدقاء أو أي شيء آخر؟ يُرجى تزويدي بهذا السياق.\", \"يرجى وصف الأنشطة التي تراود ذهنك.\"]', '[\"هل لديك موقف محدد في ذهنك؟ لا تتردد في طرح سؤالك.\", \"يرجى وصف الموقف الذي تفكر فيه.\"]', '[{\"original\": \"هل توجد أي فعاليات اليوم؟\", \"translated\": \"Есть ли сегодня какие-нибудь мероприятия?\"}, {\"original\": \"هل هناك شيء خاص في هذه المهرجان؟\", \"translated\": \"В этом празднике есть что-нибудь особенное?\"}, {\"original\": \"أين تُقام الاحتفالية؟\", \"translated\": \"Где проходит празднование?\"}, {\"original\": \"كيف يمكنني شراء التذاكر؟\", \"translated\": \"Как я могу купить билеты?\"}, {\"original\": \"في أي وقت تبدأ العروض؟\", \"translated\": \"Во сколько начинается представление?\"}, {\"original\": \"ما الأطعمة التقليدية المتاحة؟\", \"translated\": \"Какая традиционная еда здесь есть?\"}, {\"original\": \"المكان حيويٌّ جدًّا هنا.\", \"translated\": \"Здесь действительно очень оживлённо.\"}, {\"original\": \"هل توجد أنشطة شعبية؟\", \"translated\": \"Есть ли какие-нибудь народные мероприятия?\"}, {\"original\": \"أعياد سعيدة!\", \"translated\": \"С праздником!\"}, {\"original\": \"في أي وقت تنتهي الفعالية؟\", \"translated\": \"Во сколько заканчивается мероприятие?\"}]', 10, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في متحف أو معرض فني؟\", \"رائع! إليك عشر عبارات شائعة مرتبطة بالمتحف أو المعرض الفني، مع الترجمات الروسية الخاصة بها:\"]', '[\"الزيارة\", \"الجولة المُرشدة\", \"شراء التذاكر\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف معين في ذهنك، مثل طلب دليل تعريفي، أو عبارات مرتبطة بالخريطة التوجيهية، أو عبارات مرتبطة بالتعليق على المعروضات؟ لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي يخطر ببالك.\"]', NULL, '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"هل لديكم أدلة صوتية؟\", \"translated\": \"У вас есть аудиогиды?\"}, {\"original\": \"من هو مبتكر هذه القطعة الفنية؟\", \"translated\": \"Кто создал это произведение искусства?\"}, {\"original\": \"أين توجد أثمن قطعة في المتحف؟\", \"translated\": \"Где находится самая ценная экспонат музея?\"}, {\"original\": \"هل يُسمح بالتصوير الفوتوغرافي؟\", \"translated\": \"Разрешена ли фотосъёмка?\"}, {\"original\": \"هل توجد هنا أي معارض خاصة؟\", \"translated\": \"Здесь проходят какие-нибудь специальные выставки?\"}, {\"original\": \"كم تستغرق الزيارة من الوقت؟\", \"translated\": \"Сколько времени занимает посещение?\"}, {\"original\": \"هل يمكنكم إعطاؤنا مقدمة؟\", \"translated\": \"Не могли бы вы представить нам краткое введение?\"}, {\"original\": \"هذه الأعمال رائعةٌ حقًّا.\", \"translated\": \"Эти произведения действительно изысканны.\"}, {\"original\": \"أين تقع متجر الهدايا التذكارية؟\", \"translated\": \"Где находится магазин сувениров?\"}]', 11, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في المقاهي؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بالمقاهي، مع الترجمات الروسية المقابلة:\"]', '[\"طلب القهوة\", \"الاستراحة\", \"التواصل الاجتماعي\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف محدد في ذهنك، مثل طلب القائمة أو المشروبات الباردة أو الساخنة أو منتجات أخرى؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي تفكر فيه.\"]', NULL, '[{\"original\": \"سأطلب لاتيه، من فضلك.\", \"translated\": \"Я возьму латте, пожалуйста.\"}, {\"original\": \"هل لديكم اتصال واي فاي؟\", \"translated\": \"У вас есть Wi-Fi?\"}, {\"original\": \"هل يمكنني رؤية القائمة، من فضلك؟\", \"translated\": \"Можно мне посмотреть меню, пожалуйста?\"}, {\"original\": \"هل يُسمح بإعادة التعبئة؟\", \"translated\": \"Разрешено ли добавлять кофе бесплатно?\"}, {\"original\": \"هل قهوةُّي جاهزة؟\", \"translated\": \"Готов мой кофе?\"}, {\"original\": \"كم من الوقت يمكنني الجلوس هنا؟\", \"translated\": \"Сколько времени я могу здесь посидеть?\"}, {\"original\": \"هل يمكنكم التقاط صورة لنا؟\", \"translated\": \"Не могли бы вы сделать нам фотографию?\"}, {\"original\": \"أين الحمام؟\", \"translated\": \"Где туалет?\"}, {\"original\": \"الحساب، من فضلك. شكرًا لكم.\", \"translated\": \"Счёт, пожалуйста. Спасибо.\"}, {\"original\": \"الطَّعمُ لذيذٌ جدًّا.\", \"translated\": \"Очень вкусно.\"}]', 12, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser au restaurant ?\", \"Formidable ! Voici 10 expressions courantes liées au restaurant, accompagnées de leurs traductions en russe :\"]', '[\"Restauration\", \"Commande\", \"Paiement\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple commander des boissons, formuler une réclamation ou demander des informations sur les ingrédients ? N’hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\", \"translated\": \"Извините, сколько ещё ждать нашу еду?\"}, {\"original\": \"Une table pour deux, s\'il vous plaît.\", \"translated\": \"Столик на двоих, пожалуйста.\"}, {\"original\": \"Pourrions-nous voir la carte, s\'il vous plaît ?\", \"translated\": \"Можно посмотреть меню, пожалуйста?\"}, {\"original\": \"Avez-vous des plats signature à nous recommander ?\", \"translated\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\"}, {\"original\": \"Je voudrais commander ceci et cela.\", \"translated\": \"Я хочу заказать это и это.\"}, {\"original\": \"Un verre d\'eau, s\'il vous plaît. Merci.\", \"translated\": \"Стакан воды, пожалуйста. Спасибо.\"}, {\"original\": \"L\'addition, s\'il vous plaît.\", \"translated\": \"Счёт, пожалуйста.\"}, {\"original\": \"Puis-je payer par carte bancaire ?\", \"translated\": \"Можно оплатить кредитной картой?\"}, {\"original\": \"Pourriez-vous emballer cela à emporter, s\'il vous plaît ?\", \"translated\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\"}, {\"original\": \"Le plat était délicieux, merci.\", \"translated\": \"Еда была восхитительной, спасибо.\"}]', 1, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser à l’hôtel ?\", \"Formidable ! Voici 10 expressions courantes liées à l’hôtel, accompagnées de leurs traductions en russe :\"]', '[\"Enregistrement\", \"Départ\", \"Service en chambre\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple l’emplacement de la chambre, d’autres services hôteliers ou le départ ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Bonjour, j’ai une réservation. Voici mon passeport.\", \"translated\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\"}, {\"original\": \"Avez-vous des chambres disponibles ?\", \"translated\": \"У вас есть свободные номера?\"}, {\"original\": \"Excusez-moi, l’hôtel dispose-t-il d’une salle de sport ou d’une buanderie ?\", \"translated\": \"Извините, в отеле есть тренажёрный зал или прачечная?\"}, {\"original\": \"À quelle heure commence le petit-déjeuner ?\", \"translated\": \"Во сколько начинается завтрак?\"}, {\"original\": \"Pourrais-je avoir la clé de ma chambre, s’il vous plaît ?\", \"translated\": \"Можно мне ключ от номера, пожалуйста?\"}, {\"original\": \"Pourriez-vous m’aider à porter mes bagages jusqu’à ma chambre ?\", \"translated\": \"Не могли бы вы помочь мне отнести багаж в номер?\"}, {\"original\": \"Comment puis-je appeler le service d’étage ?\", \"translated\": \"Как вызвать службу обслуживания номеров?\"}, {\"original\": \"À quelle heure est la sortie ?\", \"translated\": \"До какого времени необходимо освободить номер?\"}, {\"original\": \"Pourriez-vous me délivrer un reçu / une facture ?\", \"translated\": \"Не могли бы вы выписать мне квитанцию/счёт?\"}, {\"original\": \"Puis-je laisser mes bagages ici ?\", \"translated\": \"Можно оставить здесь мой багаж?\"}]', 2, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser à l’aéroport ?\", \"Formidable ! Voici 10 expressions courantes liées à l’aéroport, accompagnées de leurs traductions en russe :\"]', '[\"Enregistrement\", \"Embarquement\", \"Enregistrement des bagages\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple l’enregistrement, le retrait des bagages ou la location de voiture ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Où se trouve le comptoir d\'enregistrement ?\", \"translated\": \"Где стойка регистрации?\"}, {\"original\": \"Je voudrais un siège côté fenêtre, s\'il vous plaît.\", \"translated\": \"Я бы хотел место у окна, пожалуйста.\"}, {\"original\": \"Ce vol est-il retardé ?\", \"translated\": \"Этот рейс задерживается?\"}, {\"original\": \"Je dois enregistrer ce bagage.\", \"translated\": \"Мне нужно зарегистрировать этот багаж.\"}, {\"original\": \"Où se trouve la porte d\'embarquement ?\", \"translated\": \"Где выход на посадку?\"}, {\"original\": \"L\'avion va bientôt décoller.\", \"translated\": \"Самолёт вот-вот взлетит.\"}, {\"original\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\", \"translated\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\"}, {\"original\": \"Où se trouve la boutique hors taxes ?\", \"translated\": \"Где магазин беспошлинной торговли?\"}, {\"original\": \"Je ne retrouve pas ma valise.\", \"translated\": \"Я не могу найти свой чемодан.\"}, {\"original\": \"Proposez-vous un service de fauteuil roulant ?\", \"translated\": \"Предоставляется ли услуга инвалидных колясок?\"}]', 3, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans les transports en commun ?\", \"Formidable ! Voici 10 expressions courantes liées aux transports en commun, accompagnées de leurs traductions en russe :\"]', '[\"Prendre le bus ou le métro\", \"Acheter des billets\", \"Effectuer une correspondance\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander où se trouve l’arrêt de bus, le prix du billet ou comment descendre du véhicule ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Ce bus va-t-il à la gare routière ?\", \"translated\": \"Этот автобус идёт до автовокзала?\"}, {\"original\": \"Quel est le prochain arrêt ?\", \"translated\": \"Какая следующая остановка?\"}, {\"original\": \"Où puis-je acheter un billet ?\", \"translated\": \"Где я могу купить билет?\"}, {\"original\": \"Un billet pour XX, s’il vous plaît.\", \"translated\": \"Один билет до XX, пожалуйста.\"}, {\"original\": \"Dois-je changer de transport ?\", \"translated\": \"Нужно ли мне пересаживаться?\"}, {\"original\": \"Dans combien de temps arrive le prochain métro ?\", \"translated\": \"Через сколько прибудет следующий поезд метро?\"}, {\"original\": \"Excusez-moi, je dois passer.\", \"translated\": \"Извините, пропустите меня, пожалуйста.\"}, {\"original\": \"Cette place est-elle occupée ?\", \"translated\": \"Это место занято?\"}, {\"original\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d’aller à XX ?\", \"translated\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\"}, {\"original\": \"Comment puis-je me rendre à XX ?\", \"translated\": \"Как мне добраться до XX?\"}]', 4, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans les sites touristiques ?\", \"Formidable ! Voici 10 expressions courantes liées aux sites touristiques, accompagnées de leurs traductions en russe :\"]', '[\"Visite touristique\", \"Prendre des photos\", \"Acheter des billets\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander le prix des billets, trouver un parking ou solliciter un service de guide touristique ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Combien coûte l\'entrée ?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"Y a-t-il des billets étudiants disponibles ?\", \"translated\": \"Есть ли льготные билеты для студентов?\"}, {\"original\": \"À quelle heure ouvre l\'attraction ?\", \"translated\": \"Во сколько открывается достопримечательность?\"}, {\"original\": \"Quelles sont les activités amusantes à faire ici ?\", \"translated\": \"Чем здесь можно интересно заняться?\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"Не могли бы вы сделать для нас фотографию?\"}, {\"original\": \"Où est le bus touristique ?\", \"translated\": \"Где автобус для осмотра достопримечательностей?\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"Где находится туалет?\"}, {\"original\": \"Quel est le meilleur endroit pour admirer la vue ?\", \"translated\": \"Где лучшее место для просмотра?\"}, {\"original\": \"Le paysage est magnifique ici.\", \"translated\": \"Здесь прекрасный вид.\"}, {\"original\": \"Une visite guidée est-elle disponible ?\", \"translated\": \"Доступна ли экскурсия с гидом?\"}]', 5, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser avec un taxi ou un service de taxi ?\", \"Formidable ! Voici 10 expressions courantes liées au taxi ou au service de taxi, accompagnées de leurs traductions en russe :\"]', '[\"Prendre un taxi\", \"Indiquer la destination\", \"Paiement\"]', 'fr', '[\"Pour l’instant, que souhaitez-vous faire principalement maintenant : demander la destination, le montant ou une facture ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Où puis-je prendre un taxi ?\", \"translated\": \"Где я могу взять такси?\"}, {\"original\": \"Veuillez me conduire à cette adresse.\", \"translated\": \"Пожалуйста, отвезите меня по этому адресу.\"}, {\"original\": \"Combien cela coûtera-t-il approximativement ?\", \"translated\": \"Примерно сколько это будет стоить?\"}, {\"original\": \"Pourriez-vous utiliser le compteur, s’il vous plaît ?\", \"translated\": \"Не могли бы вы, пожалуйста, включить счётчик?\"}, {\"original\": \"Pourriez-vous conduire un peu plus vite, je suis pressé(e).\", \"translated\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\"}, {\"original\": \"Veuillez vous arrêter ici.\", \"translated\": \"Остановитесь, пожалуйста, здесь.\"}, {\"original\": \"Acceptez-vous les paiements par carte ou mobile ?\", \"translated\": \"Принимаете ли вы оплату картой или через мобильные платежи?\"}, {\"original\": \"Pourrais-je avoir un reçu, s’il vous plaît ?\", \"translated\": \"Можно мне, пожалуйста, чек?\"}, {\"original\": \"Merci, monsieur/madame le chauffeur.\", \"translated\": \"Спасибо, водитель.\"}, {\"original\": \"Il reste encore combien de temps ?\", \"translated\": \"Как далеко ещё?\"}]', 6, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser en pharmacie ?\", \"Formidable ! Voici 10 expressions courantes liées à la pharmacie, accompagnées de leurs traductions en russe :\"]', '[\"Acheter des médicaments\", \"Consultation\", \"Paiement\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander des instructions sur la prise de médicaments, des expressions liées à l’utilisation de l’assurance maladie ou à la durée du traitement ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Avez-vous des médicaments contre le rhume ?\", \"translated\": \"У вас есть лекарство от простуды?\"}, {\"original\": \"Comment dois-je prendre ce médicament ?\", \"translated\": \"Как мне принимать это лекарство?\"}, {\"original\": \"Avez-vous des analgésiques ?\", \"translated\": \"У вас есть обезболивающие?\"}, {\"original\": \"Y a-t-il une notice d’instructions ?\", \"translated\": \"Есть ли инструкция по применению?\"}, {\"original\": \"Ce médicament a-t-il des effets secondaires ?\", \"translated\": \"Это лекарство имеет какие-либо побочные эффекты?\"}, {\"original\": \"Puis-je utiliser ma carte d’assurance maladie ?\", \"translated\": \"Можно ли воспользоваться моей медицинской страховкой?\"}, {\"original\": \"Pourriez-vous me donner une boîte de pansements, s’il vous plaît ?\", \"translated\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\"}, {\"original\": \"Avez-vous des antipyrétiques ?\", \"translated\": \"У вас есть жаропонижающие?\"}, {\"original\": \"Je me suis un peu écorché. Avez-vous un antiseptique et des pansements ?\", \"translated\": \"Я немного поранился. У вас есть антисептик и пластыри?\"}, {\"original\": \"À quelle heure fermez-vous ?\", \"translated\": \"Во сколько вы закрываетесь?\"}]', 7, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans les services d\'urgence ?\", \"Formidable ! Voici 10 expressions courantes liées aux services d\'urgence, accompagnées de leurs traductions en russe :\"]', '[\"Appeler la police\", \"Premiers secours\", \"Appeler à l\'aide\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation d\'urgence précise en tête, par exemple un incendie, une personne blessée nécessitant de l\'aide, ou un appel d\'urgence ? N\'hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', NULL, '[{\"original\": \"Veuillez m\'aider à appeler une ambulance.\", \"translated\": \"Пожалуйста, помогите мне вызвать скорую помощь.\"}, {\"original\": \"Où se trouve l\'hôpital ?\", \"translated\": \"Где находится больница?\"}, {\"original\": \"Quelqu\'un est blessé.\", \"translated\": \"Кто-то получил травму.\"}, {\"original\": \"Veuillez m\'aider.\", \"translated\": \"Пожалуйста, помогите мне.\"}, {\"original\": \"Où se trouve le commissariat ?\", \"translated\": \"Где находится полицейский участок?\"}, {\"original\": \"J\'ai perdu mes affaires.\", \"translated\": \"Я потерял свои вещи.\"}, {\"original\": \"Quel est le numéro des pompiers ?\", \"translated\": \"Какой номер пожарной службы?\"}, {\"original\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le commissariat le plus proche ?\", \"translated\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\"}, {\"original\": \"Y a-t-il une sortie de secours ?\", \"translated\": \"Здесь есть аварийный выход?\"}, {\"original\": \"Quelqu\'un s\'est évanoui.\", \"translated\": \"Кто-то потерял сознание.\"}]', 8, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser à la plage ou au bord de la piscine ?\", \"Formidable ! Voici 10 expressions courantes liées à la plage ou au bord de la piscine, accompagnées de leurs traductions en russe :\"]', '[\"Natation\", \"Bain de soleil\", \"Sports de plage\"]', 'fr', '[\"Pour l’instant, pourriez-vous me préciser le contexte de l’événement ou de la fête locale auquel vous participez, par exemple un festival culturel, un festival gastronomique ou un festival de musique ? Veuillez fournir ce contexte.\", \"Veuillez indiquer les activités auxquelles vous participez.\"]', '[\"Avez-vous une situation précise en tête ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\", \"translated\": \"Смотрите! Волны там действительно очень большие.\"}, {\"original\": \"N\'oubliez pas d\'appliquer de la crème solaire, les rayons UV sont très forts ici.\", \"translated\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\"}, {\"original\": \"Le sable de cette plage est si fin qu\'on dirait marcher sur du coton.\", \"translated\": \"Песок на этом пляже такой мелкий, что идти по нему — всё равно что ступать по хлопку.\"}, {\"original\": \"Et si on jouait au volley-ball sur la plage ?\", \"translated\": \"Как насчёт игры в волейбол на пляже?\"}, {\"original\": \"Les voiliers au loin sont magnifiques.\", \"translated\": \"Парусники вдалеке выглядят очень красиво.\"}, {\"original\": \"L\'eau est si claire ici qu\'on peut même voir les poissons.\", \"translated\": \"Вода здесь такая прозрачная, что даже рыбок можно разглядеть.\"}, {\"original\": \"Allons chercher des coquillages.\", \"translated\": \"Давайте пойдём собирать морские ракушки.\"}, {\"original\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\", \"translated\": \"Прогулка по пляжу на закате, наверное, очень романтична.\"}, {\"original\": \"J\'ai entendu dire que les fruits de mer sont très frais ici, allons en goûter.\", \"translated\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\"}, {\"original\": \"La marée monte, dirigeons-nous vers la rive.\", \"translated\": \"Начинается прилив, давайте направимся к берегу.\"}]', 9, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser lors d’événements locaux et de festivals ?\", \"Formidable ! Voici 10 expressions courantes liées aux événements locaux et aux festivals, accompagnées de leurs traductions en russe :\"]', '[\"Assister à des événements\", \"Célébrer des festivals\", \"Apprendre la culture\"]', 'fr', '[\"Pour l’instant, pourriez-vous me préciser le contexte de l’événement local ou du festival auquel vous participez, par exemple Halloween, un concert, une fête entre amis ou autre chose ? Veuillez fournir ce contexte.\", \"Veuillez décrire les activités qui vous viennent à l’esprit.\"]', '[\"Avez-vous une situation précise en tête ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Y a-t-il des événements aujourd\'hui ?\", \"translated\": \"Есть ли сегодня какие-нибудь мероприятия?\"}, {\"original\": \"Y a-t-il quelque chose de particulier à propos de ce festival ?\", \"translated\": \"В этом празднике есть что-нибудь особенное?\"}, {\"original\": \"Où se déroule la célébration ?\", \"translated\": \"Где проходит празднование?\"}, {\"original\": \"Comment puis-je acheter des billets ?\", \"translated\": \"Как я могу купить билеты?\"}, {\"original\": \"À quelle heure commence la représentation ?\", \"translated\": \"Во сколько начинается представление?\"}, {\"original\": \"Quels sont les plats traditionnels ?\", \"translated\": \"Какая традиционная еда здесь есть?\"}, {\"original\": \"C\'est vraiment animé ici.\", \"translated\": \"Здесь действительно оживлённо.\"}, {\"original\": \"Y a-t-il des activités populaires ?\", \"translated\": \"Есть ли какие-нибудь народные мероприятия?\"}, {\"original\": \"Joyeuses fêtes !\", \"translated\": \"Счастливых праздников!\"}, {\"original\": \"À quelle heure se termine l\'événement ?\", \"translated\": \"Во сколько заканчивается мероприятие?\"}]', 10, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans un musée ou une galerie d\'art ?\", \"Formidable ! Voici 10 expressions courantes liées au musée ou à la galerie d\'art, accompagnées de leurs traductions en russe :\"]', '[\"Visite\", \"Visite guidée\", \"Achat de billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander une notice explicative, des expressions liées à un parcours guidé, des expressions pour commenter une exposition ? N\'hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', NULL, '[{\"original\": \"Quel est le montant des frais d\'entrée ?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"Disposez-vous de guides audio ?\", \"translated\": \"У вас есть аудиогиды?\"}, {\"original\": \"Qui est l\'auteur de cette œuvre ?\", \"translated\": \"Кто создал это произведение искусства?\"}, {\"original\": \"Où se trouve la pièce la plus précieuse du musée ?\", \"translated\": \"Где находится самая ценная экспонат музея?\"}, {\"original\": \"La photographie est-elle autorisée ?\", \"translated\": \"Разрешена ли фотосъёмка?\"}, {\"original\": \"Y a-t-il des expositions spéciales ici ?\", \"translated\": \"Здесь проходят какие-нибудь специальные выставки?\"}, {\"original\": \"Combien de temps dure la visite ?\", \"translated\": \"Сколько времени занимает посещение?\"}, {\"original\": \"Pourriez-vous nous en faire une présentation ?\", \"translated\": \"Не могли бы вы представить нам краткое введение?\"}, {\"original\": \"Ces œuvres sont véritablement exquises.\", \"translated\": \"Эти произведения действительно изысканны.\"}, {\"original\": \"Où se trouve la boutique de souvenirs ?\", \"translated\": \"Где находится магазин сувениров?\"}]', 11, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans les cafés ?\", \"Formidable ! Voici 10 expressions courantes liées aux cafés, accompagnées de leurs traductions en russe :\"]', '[\"Commander du café\", \"Se reposer\", \"Socialiser\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander la carte, des boissons glacées ou chaudes, d’autres produits ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Je prendrai un latte, s’il vous plaît.\", \"translated\": \"Я возьму латте, пожалуйста.\"}, {\"original\": \"Avez-vous le Wi-Fi ?\", \"translated\": \"У вас есть Wi-Fi?\"}, {\"original\": \"Pourrais-je voir la carte, s’il vous plaît ?\", \"translated\": \"Можно мне посмотреть меню, пожалуйста?\"}, {\"original\": \"Les recharges sont-elles autorisées ?\", \"translated\": \"Разрешено ли добавлять кофе бесплатно?\"}, {\"original\": \"Mon café est-il prêt ?\", \"translated\": \"Мой кофе уже готов?\"}, {\"original\": \"Combien de temps puis-je rester assis ici ?\", \"translated\": \"Сколько времени я могу здесь посидеть?\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"Не могли бы вы сделать нам фотографию?\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"Где туалет?\"}, {\"original\": \"L’addition, s’il vous plaît. Merci.\", \"translated\": \"Счёт, пожалуйста. Спасибо.\"}, {\"original\": \"C’est vraiment délicieux.\", \"translated\": \"Очень вкусно.\"}]', 12, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Restaurant verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Restaurants sowie deren russische Übersetzungen:\"]', '[\"Gastronomie\", \"Bestellen\", \"Kasse\"]', 'de', '[\"Vorerst: Haben Sie eine bestimmte Situation im Kopf, etwa das Bestellen von Getränken, das Erheben einer Beschwerde oder das Nachfragen nach Zutaten? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', NULL, '[{\"original\": \"Entschuldigung, wie lange dauert es noch bis zu unserem Essen?\", \"translated\": \"Извините, сколько ещё ждать нашу еду?\"}, {\"original\": \"Ein Tisch für zwei Personen, bitte.\", \"translated\": \"Столик на двоих, пожалуйста.\"}, {\"original\": \"Könnten wir bitte die Speisekarte sehen?\", \"translated\": \"Можно посмотреть меню, пожалуйста?\"}, {\"original\": \"Haben Sie empfehlenswerte Hausgerichte?\", \"translated\": \"У вас есть фирменные блюда, которые вы могли бы порекомендовать?\"}, {\"original\": \"Ich möchte dies hier und das hier bestellen.\", \"translated\": \"Я хочу заказать это и это.\"}, {\"original\": \"Ein Glas Wasser, bitte. Danke.\", \"translated\": \"Стакан воды, пожалуйста. Спасибо.\"}, {\"original\": \"Die Rechnung, bitte.\", \"translated\": \"Счёт, пожалуйста.\"}, {\"original\": \"Kann ich mit Kreditkarte bezahlen?\", \"translated\": \"Можно оплатить кредитной картой?\"}, {\"original\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\", \"translated\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\"}, {\"original\": \"Das Essen war köstlich, vielen Dank.\", \"translated\": \"Еда была восхитительной, спасибо.\"}]', 1, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Hotel verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Hotels sowie deren russische Übersetzungen:\"]', '[\"Einchecken\", \"Auschecken\", \"Zimmerservice\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf, etwa die Lage des Zimmers, weitere Hoteldienstleistungen oder den Check-out? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', NULL, '[{\"original\": \"Hallo, ich habe eine Reservierung. Hier ist mein Reisepass.\", \"translated\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\"}, {\"original\": \"Haben Sie noch freie Zimmer?\", \"translated\": \"У вас есть свободные номера?\"}, {\"original\": \"Entschuldigung, verfügt das Hotel über ein Fitnessstudio oder einen Waschraum?\", \"translated\": \"Извините, в отеле есть тренажёрный зал или прачечная?\"}, {\"original\": \"Wann beginnt das Frühstück?\", \"translated\": \"Во сколько начинается завтрак?\"}, {\"original\": \"Könnte ich bitte den Zimmerschlüssel haben?\", \"translated\": \"Можно мне ключ от номера, пожалуйста?\"}, {\"original\": \"Könnten Sie mir helfen, mein Gepäck auf das Zimmer zu bringen?\", \"translated\": \"Не могли бы вы помочь мне отнести багаж в номер?\"}, {\"original\": \"Wie rufe ich den Zimmerservice?\", \"translated\": \"Как вызвать службу обслуживания номеров?\"}, {\"original\": \"Wann ist der Check-out?\", \"translated\": \"Во сколько заканчивается регистрация выезда?\"}, {\"original\": \"Könnten Sie mir bitte eine Quittung / Rechnung ausstellen?\", \"translated\": \"Не могли бы вы выписать мне квитанцию/счёт?\"}, {\"original\": \"Darf ich mein Gepäck hier lassen?\", \"translated\": \"Можно оставить здесь мой багаж?\"}]', 2, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich am Flughafen verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Flughafen sowie deren russische Übersetzungen:\"]', '[\"Einchecken\", \"Boarding\", \"Gepäckabgabe\"]', 'de', '[\"Momentan: Haben Sie eine konkrete Situation im Kopf, etwa das Einchecken, die Gepäckausgabe oder einen Mietwagenservice? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', NULL, '[{\"original\": \"Wo ist der Check-in-Schalter?\", \"translated\": \"Где стойка регистрации?\"}, {\"original\": \"Ich hätte gerne einen Fensterplatz.\", \"translated\": \"Я бы хотел место у окна, пожалуйста.\"}, {\"original\": \"Ist dieser Flug verspätet?\", \"translated\": \"Этот рейс задерживается?\"}, {\"original\": \"Ich muss dieses Gepäck aufgeben.\", \"translated\": \"Мне нужно зарегистрировать этот багаж.\"}, {\"original\": \"Wo ist das Boarding-Gate?\", \"translated\": \"Где выход на посадку?\"}, {\"original\": \"Das Flugzeug startet gleich.\", \"translated\": \"Самолёт вот-вот взлетит.\"}, {\"original\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\", \"translated\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\"}, {\"original\": \"Wo ist der Duty-free-Shop?\", \"translated\": \"Где магазин беспошлинной торговли?\"}, {\"original\": \"Ich kann meinen Koffer nicht finden.\", \"translated\": \"Я не могу найти свой чемодан.\"}, {\"original\": \"Bieten Sie einen Rollstuhlservice an?\", \"translated\": \"Предоставляется ли услуга инвалидных колясок?\"}]', 3, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im öffentlichen Nahverkehr verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema öffentlicher Nahverkehr samt russischer Übersetzung:\"]', '[\"Mit Bus/U-Bahn fahren\", \"Fahrkarten kaufen\", \"Umsteigen\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf, etwa nach einer Haltestelle zu fragen, den Fahrpreis zu erfragen oder darzulegen, dass Sie aussteigen möchten? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', NULL, '[{\"original\": \"Fährt dieser Bus zum Terminal?\", \"translated\": \"Этот автобус идёт до конечной остановки?\"}, {\"original\": \"Was ist die nächste Haltestelle?\", \"translated\": \"Какая следующая остановка?\"}, {\"original\": \"Wo kann ich ein Ticket kaufen?\", \"translated\": \"Где я могу купить билет?\"}, {\"original\": \"Ein Ticket nach XX, bitte.\", \"translated\": \"Один билет до XX, пожалуйста.\"}, {\"original\": \"Muss ich umsteigen?\", \"translated\": \"Нужно ли мне пересаживаться?\"}, {\"original\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\", \"translated\": \"Сколько осталось до следующего поезда метро?\"}, {\"original\": \"Entschuldigung, bitte lassen Sie mich durch.\", \"translated\": \"Извините, пропустите меня, пожалуйста.\"}, {\"original\": \"Ist dieser Platz bereits besetzt?\", \"translated\": \"Это место занято?\"}, {\"original\": \"Entschuldigung, wo kann ich umsteigen, um mit der Linie 2 nach XX zu gelangen?\", \"translated\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\"}, {\"original\": \"Wie komme ich nach XX?\", \"translated\": \"Как мне добраться до XX?\"}]', 4, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich an touristischen Sehenswürdigkeiten verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit touristischen Sehenswürdigkeiten samt russischer Übersetzung:\"]', '[\"Sehenswürdigkeiten besichtigen\", \"Fotos machen\", \"Tickets kaufen\"]', 'de', '[\"Momentan: Haben Sie eine konkrete Situation im Kopf, etwa das Nachfragen nach dem Eintrittspreis, das Suchen eines Parkplatzes oder die Inanspruchnahme eines Führerservices? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', NULL, '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"Gibt es ermäßigte Eintrittskarten für Schüler?\", \"translated\": \"Есть ли льготные билеты для студентов?\"}, {\"original\": \"Wann öffnet die Sehenswürdigkeit?\", \"translated\": \"Во сколько открывается достопримечательность?\"}, {\"original\": \"Was gibt es hier Spannendes zu tun?\", \"translated\": \"Чем здесь интересно заняться?\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"Не могли бы вы сделать для нас фотографию?\"}, {\"original\": \"Wo befindet sich der Sightseeing-Bus?\", \"translated\": \"Где автобус для осмотра достопримечательностей?\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"Где находится туалет?\"}, {\"original\": \"Wo ist der beste Aussichtspunkt?\", \"translated\": \"Где лучшее место для просмотра?\"}, {\"original\": \"Die Landschaft hier ist wunderschön.\", \"translated\": \"Здесь прекрасный вид.\"}, {\"original\": \"Gibt es eine geführte Tour?\", \"translated\": \"Доступна ли экскурсия с гидом?\"}]', 5, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Zusammenhang mit einem Taxi oder einem Taxidienst verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Taxi oder Taxidienst zusammen mit russischen Übersetzungen:\"]', '[\"Taxi nehmen\", \"Ziel angeben\", \"Zahlen\"]', 'de', '[\"Im Moment: Was möchten Sie gerade am liebsten tun – beispielsweise das Ziel angeben, nach dem Preis fragen oder eine Rechnung anfordern? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', NULL, '[{\"original\": \"Wo kann ich ein Taxi bekommen?\", \"translated\": \"Где я могу взять такси?\"}, {\"original\": \"Bitte fahren Sie mich zu dieser Adresse.\", \"translated\": \"Пожалуйста, отвезите меня по этому адресу.\"}, {\"original\": \"Wie viel kostet es ungefähr?\", \"translated\": \"Примерно сколько это будет стоить?\"}, {\"original\": \"Könnten Sie bitte den Taxameter benutzen?\", \"translated\": \"Не могли бы вы, пожалуйста, включить счётчик?\"}, {\"original\": \"Bitte fahren Sie etwas schneller, ich habe es eilig.\", \"translated\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\"}, {\"original\": \"Bitte halten Sie hier an.\", \"translated\": \"Остановитесь, пожалуйста, здесь.\"}, {\"original\": \"Akzeptieren Sie Karten oder mobile Zahlungen?\", \"translated\": \"Принимаете ли вы оплату картой или через мобильные платежи?\"}, {\"original\": \"Könnte ich bitte eine Quittung haben?\", \"translated\": \"Можно мне, пожалуйста, чек?\"}, {\"original\": \"Vielen Dank, Fahrer.\", \"translated\": \"Спасибо, водитель.\"}, {\"original\": \"Wie weit ist es noch?\", \"translated\": \"Как далеко ещё?\"}]', 6, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich in der Apotheke verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit der Apotheke sowie deren russische Übersetzungen:\"]', '[\"Medikamente kaufen\", \"Beratung\", \"Zahlung\"]', 'de', '[\"Vorläufig: Haben Sie eine konkrete Situation im Kopf, etwa die Bitte um Anweisungen zur Einnahme von Medikamenten, Formulierungen im Zusammenhang mit der Nutzung einer Krankenversicherung oder zur Dauer der Medikamenteneinnahme? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', NULL, '[{\"original\": \"Haben Sie Medikamente gegen Erkältung?\", \"translated\": \"У вас есть лекарство от простуды?\"}, {\"original\": \"Wie soll ich dieses Medikament einnehmen?\", \"translated\": \"Как мне принимать это лекарство?\"}, {\"original\": \"Haben Sie Schmerzmittel?\", \"translated\": \"У вас есть обезболивающие?\"}, {\"original\": \"Gibt es eine Gebrauchsanweisung?\", \"translated\": \"Есть ли инструкция по применению?\"}, {\"original\": \"Hat dieses Medikament Nebenwirkungen?\", \"translated\": \"Это лекарство имеет какие-либо побочные эффекты?\"}, {\"original\": \"Kann ich meine Krankenversicherungskarte verwenden?\", \"translated\": \"Можно ли воспользоваться моей медицинской страховкой?\"}, {\"original\": \"Könnte ich bitte eine Packung Pflaster haben?\", \"translated\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\"}, {\"original\": \"Haben Sie Fiebersenkungsmittel?\", \"translated\": \"У вас есть жаропонижающие?\"}, {\"original\": \"Ich habe mir leicht die Haut aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\", \"translated\": \"Я немного поранился. У вас есть антисептик и пластыри?\"}, {\"original\": \"Wann schließen Sie?\", \"translated\": \"Во сколько вы закрываетесь?\"}]', 7, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Bereich der Notfalldienste verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke aus dem Bereich der Notfalldienste zusammen mit ihren russischen Übersetzungen:\"]', '[\"Polizei rufen\", \"Erste Hilfe leisten\", \"Hilfe rufen\"]', 'de', '[\"Vorläufig: Haben Sie eine bestimmte Notsituation im Kopf, beispielsweise Feuer, Verletzung und Hilfebedarf oder einen Notruf? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', NULL, '[{\"original\": \"Bitte helfen Sie mir, einen Krankenwagen zu rufen.\", \"translated\": \"Пожалуйста, помогите мне вызвать скорую помощь.\"}, {\"original\": \"Wo ist das Krankenhaus?\", \"translated\": \"Где находится больница?\"}, {\"original\": \"Jemand ist verletzt.\", \"translated\": \"Кто-то пострадал.\"}, {\"original\": \"Bitte helfen Sie mir.\", \"translated\": \"Пожалуйста, помогите мне.\"}, {\"original\": \"Wo ist die Polizeistation?\", \"translated\": \"Где находится полицейский участок?\"}, {\"original\": \"Ich habe meine Sachen verloren.\", \"translated\": \"Я потерял свои вещи.\"}, {\"original\": \"Wie lautet die Notrufnummer für die Feuerwehr?\", \"translated\": \"Какой номер пожарной службы?\"}, {\"original\": \"Ich habe meinen Pass verloren. Wissen Sie, wo die nächste Polizeistation ist?\", \"translated\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\"}, {\"original\": \"Gibt es einen Notausgang?\", \"translated\": \"Есть ли аварийный выход?\"}, {\"original\": \"Jemand ist in Ohnmacht gefallen.\", \"translated\": \"Кто-то потерял сознание.\"}]', 8, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich am Strand oder am Pool verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Strand oder Schwimmbad sowie deren russische Übersetzungen:\"]', '[\"Schwimmen\", \"Sonnenbaden\", \"Strandsport\"]', 'de', '[\"Könnten Sie mir vorläufig den Kontext der lokalen Veranstaltung oder des Festivals, an dem Sie teilnehmen, mitteilen – beispielsweise ein Kulturfestival, ein Kulinarikfestival oder ein Musikfestival? Bitte geben Sie den Kontext an.\", \"Bitte nennen Sie die Aktivitäten, an denen Sie teilnehmen.\"]', '[\"Haben Sie eine konkrete Situation im Kopf? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[{\"original\": \"Schau! Die Wellen dort drüben sind wirklich groß.\", \"translated\": \"Смотрите! Волны там действительно большие.\"}, {\"original\": \"Vergiss nicht, Sonnenschutzmittel aufzutragen – die UV-Strahlen sind hier sehr stark.\", \"translated\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовое излучение здесь очень сильное.\"}, {\"original\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle gehen.\", \"translated\": \"Песок на этом пляже такой мелкий, что кажется, будто вы ступаете по хлопку.\"}, {\"original\": \"Wie wäre es mit einer Partie Volleyball am Strand?\", \"translated\": \"Как насчёт игры в волейбол на пляже?\"}, {\"original\": \"Die Segelboote in der Ferne sehen wunderschön aus.\", \"translated\": \"Парусники вдали выглядят прекрасно.\"}, {\"original\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\", \"translated\": \"Вода здесь такая прозрачная, что даже видно рыб.\"}, {\"original\": \"Lass uns nach Muscheln suchen.\", \"translated\": \"Давайте пойдём поискать ракушки.\"}, {\"original\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\", \"translated\": \"Прогулка по пляжу на закате, наверное, очень романтична.\"}, {\"original\": \"Ich habe gehört, dass die Meeresfrüchte hier sehr frisch sind – lass uns welche probieren.\", \"translated\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\"}, {\"original\": \"Die Flut kommt näher, gehen wir zum Ufer zurück.\", \"translated\": \"Прилив идёт, давайте направимся к берегу.\"}]', 9, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich bei lokalen Veranstaltungen und Festen verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zu lokalen Veranstaltungen und Festen samt deutscher Übersetzung:\"]', '[\"Teilnahme an Veranstaltungen\", \"Feiern von Festen\", \"Kultur kennenlernen\"]', 'de', '[\"Könnten Sie mir vorläufig den Kontext der lokalen Veranstaltung oder des Festes mitteilen, an dem Sie teilnehmen – beispielsweise Halloween, ein Konzert, eine Party bei Freunden oder etwas anderes? Bitte geben Sie den Kontext an.\", \"Bitte beschreiben Sie die Aktivitäten, die Ihnen dabei in den Sinn kommen.\"]', '[\"Haben Sie bereits eine konkrete Situation im Kopf? Fragen Sie ruhig danach.\", \"Bitte beschreiben Sie die Situation, die Ihnen dabei in den Sinn kommt.\"]', '[{\"original\": \"Gibt es heute irgendwelche Veranstaltungen?\", \"translated\": \"Есть ли сегодня какие-нибудь мероприятия?\"}, {\"original\": \"Gibt es bei diesem Fest etwas Besonderes?\", \"translated\": \"В этом празднике есть что-нибудь особенное?\"}, {\"original\": \"Wo findet die Feier statt?\", \"translated\": \"Где проходит празднование?\"}, {\"original\": \"Wie kann ich Tickets kaufen?\", \"translated\": \"Как я могу купить билеты?\"}, {\"original\": \"Wann beginnt die Aufführung?\", \"translated\": \"Во сколько начинается представление?\"}, {\"original\": \"Welche traditionellen Speisen gibt es?\", \"translated\": \"Какая традиционная еда здесь есть?\"}, {\"original\": \"Es ist hier wirklich lebhaft.\", \"translated\": \"Здесь действительно очень оживлённо.\"}, {\"original\": \"Gibt es Volksaktivitäten?\", \"translated\": \"Есть ли какие-нибудь народные мероприятия?\"}, {\"original\": \"Frohe Feiertage!\", \"translated\": \"Счастливых праздников!\"}, {\"original\": \"Wann endet die Veranstaltung?\", \"translated\": \"Во сколько заканчивается мероприятие?\"}]', 10, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Museum oder in der Kunstgalerie verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Museen oder Kunstgalerien sowie deren russische Übersetzungen:\"]', '[\"Besuch\", \"Geführte Tour\", \"Kartenvorverkauf\"]', 'de', '[\"Vorerst: Haben Sie eine bestimmte Situation im Kopf, z. B. die Bitte um ein Einführungshandbuch, Ausdrücke im Zusammenhang mit einem Rundgang, Ausdrücke zur Kommentierung von Exponaten? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', NULL, '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"Bieten Sie Audioführungen an?\", \"translated\": \"У вас есть аудиогиды?\"}, {\"original\": \"Wer hat dieses Kunstwerk geschaffen?\", \"translated\": \"Кто создал это произведение искусства?\"}, {\"original\": \"Wo befindet sich das wertvollste Stück des Museums?\", \"translated\": \"Где находится самая ценная экспонат музея?\"}, {\"original\": \"Ist Fotografieren erlaubt?\", \"translated\": \"Разрешена ли фотосъёмка?\"}, {\"original\": \"Gibt es hier besondere Ausstellungen?\", \"translated\": \"Здесь проходят какие-нибудь специальные выставки?\"}, {\"original\": \"Wie lange dauert der Besuch?\", \"translated\": \"Сколько времени занимает посещение?\"}, {\"original\": \"Könnten Sie uns bitte eine Einführung geben?\", \"translated\": \"Не могли бы вы представить нам краткое введение?\"}, {\"original\": \"Diese Werke sind wirklich exquisit.\", \"translated\": \"Эти произведения действительно изысканны.\"}, {\"original\": \"Wo befindet sich der Souvenirladen?\", \"translated\": \"Где находится магазин сувениров?\"}]', 11, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich in Cafés verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Cafés sowie deren russische Übersetzungen:\"]', '[\"Kaffee bestellen\", \"Ausruhen\", \"Sozialisieren\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf, etwa das Bestellen einer Speisekarte, von Eis oder heißen Getränken, anderer Produkte? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', NULL, '[{\"original\": \"Ich nehme einen Latte, bitte.\", \"translated\": \"Я возьму латте, пожалуйста.\"}, {\"original\": \"Haben Sie WLAN?\", \"translated\": \"У вас есть Wi-Fi?\"}, {\"original\": \"Könnte ich bitte die Speisekarte sehen?\", \"translated\": \"Можно мне посмотреть меню, пожалуйста?\"}, {\"original\": \"Dürfen Nachfüllungen gemacht werden?\", \"translated\": \"Разрешено ли дополнительное наливание?\"}, {\"original\": \"Ist mein Kaffee fertig?\", \"translated\": \"Готов мой кофе?\"}, {\"original\": \"Wie lange darf ich hier sitzen?\", \"translated\": \"Сколько времени я могу здесь посидеть?\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"Не могли бы вы сделать нам фотографию?\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"Где туалет?\"}, {\"original\": \"Die Rechnung, bitte. Vielen Dank.\", \"translated\": \"Счёт, пожалуйста. Спасибо.\"}, {\"original\": \"Es schmeckt wirklich gut.\", \"translated\": \"Очень вкусно.\"}]', 12, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en un restaurante?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el restaurante, junto con sus traducciones al ruso:\"]', '[\"Comer\", \"Pedir\", \"Pagar\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir bebidas, presentar una queja o preguntar sobre los ingredientes? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"Perdón, ¿cuánto tiempo más tardará nuestra comida?\", \"translated\": \"Извините, сколько ещё ждать нашу еду?\"}, {\"original\": \"Una mesa para dos, por favor.\", \"translated\": \"Столик на двоих, пожалуйста.\"}, {\"original\": \"¿Podríamos ver el menú, por favor?\", \"translated\": \"Можно посмотреть меню, пожалуйста?\"}, {\"original\": \"¿Tienen algún plato especial que nos recomienden?\", \"translated\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\"}, {\"original\": \"Quisiera pedir esto y esto.\", \"translated\": \"Я хочу заказать это и это.\"}, {\"original\": \"Un vaso de agua, por favor. Gracias.\", \"translated\": \"Стакан воды, пожалуйста. Спасибо.\"}, {\"original\": \"La cuenta, por favor.\", \"translated\": \"Счёт, пожалуйста.\"}, {\"original\": \"¿Puedo pagar con tarjeta de crédito?\", \"translated\": \"Можно оплатить кредитной картой?\"}, {\"original\": \"¿Podrían empaquetar esto para llevar, por favor?\", \"translated\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\"}, {\"original\": \"La comida estaba deliciosa, gracias.\", \"translated\": \"Еда была восхитительной, спасибо.\"}]', 1, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en un hotel?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el hotel, junto con sus traducciones al ruso:\"]', '[\"Registro de entrada\", \"Registro de salida\", \"Servicio de habitaciones\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como la ubicación de la habitación, otros servicios del hotel o el proceso de salida? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"Hola, tengo una reserva. Aquí tiene mi pasaporte.\", \"translated\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\"}, {\"original\": \"¿Tienen habitaciones disponibles?\", \"translated\": \"У вас есть свободные номера?\"}, {\"original\": \"Disculpe, ¿tiene el hotel gimnasio o lavandería?\", \"translated\": \"Извините, в отеле есть тренажёрный зал или прачечная?\"}, {\"original\": \"¿A qué hora comienza el desayuno?\", \"translated\": \"Во сколько начинается завтрак?\"}, {\"original\": \"¿Podría darme la llave de la habitación, por favor?\", \"translated\": \"Можно мне ключ от номера, пожалуйста?\"}, {\"original\": \"¿Podría ayudarme a llevar mi equipaje a la habitación?\", \"translated\": \"Не могли бы вы помочь мне отнести багаж в номер?\"}, {\"original\": \"¿Cómo llamo al servicio de habitaciones?\", \"translated\": \"Как вызвать службу обслуживания номеров?\"}, {\"original\": \"¿A qué hora es la salida?\", \"translated\": \"До какого времени необходимо освободить номер?\"}, {\"original\": \"¿Podría emitirme un recibo/factura?\", \"translated\": \"Не могли бы вы выписать мне квитанцию/счёт?\"}, {\"original\": \"¿Puedo dejar aquí mi equipaje?\", \"translated\": \"Можно оставить здесь мой багаж?\"}]', 2, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en el aeropuerto?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el aeropuerto, junto con sus traducciones al ruso:\"]', '[\"Registro\", \"Embarque\", \"Facturación de equipaje\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como el registro de embarque, la recogida de equipaje o el servicio de alquiler de coches? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Dónde está el mostrador de facturación?\", \"translated\": \"Где стойка регистрации?\"}, {\"original\": \"Me gustaría un asiento junto a la ventana, por favor.\", \"translated\": \"Я бы хотел место у окна, пожалуйста.\"}, {\"original\": \"¿Este vuelo tiene retraso?\", \"translated\": \"Этот рейс задерживается?\"}, {\"original\": \"Necesito facturar este equipaje.\", \"translated\": \"Мне нужно зарегистрировать этот багаж.\"}, {\"original\": \"¿Dónde está la puerta de embarque?\", \"translated\": \"Где выход на посадку?\"}, {\"original\": \"El avión está a punto de despegar.\", \"translated\": \"Самолёт вот-вот взлетит.\"}, {\"original\": \"¿Tengo que sacar mi ordenador portátil y mi power bank?\", \"translated\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\"}, {\"original\": \"¿Dónde está la tienda libre de impuestos?\", \"translated\": \"Где магазин беспошлинной торговли?\"}, {\"original\": \"No encuentro mi maleta.\", \"translated\": \"Я не могу найти свой чемодан.\"}, {\"original\": \"¿Ofrecen servicio de sillas de ruedas?\", \"translated\": \"Предоставляется ли услуга инвалидных колясок?\"}]', 3, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en el transporte público?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el transporte público, junto con sus traducciones al ruso:\"]', '[\"Tomar autobús/metro\", \"Comprar entradas\", \"Transbordar\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como preguntar dónde está la parada de autobús, el precio del billete o cómo bajarse? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Este autobús va a la terminal?\", \"translated\": \"Этот автобус идёт до автовокзала?\"}, {\"original\": \"¿Cuál es la próxima parada?\", \"translated\": \"Какая следующая остановка?\"}, {\"original\": \"¿Dónde puedo comprar un billete?\", \"translated\": \"Где я могу купить билет?\"}, {\"original\": \"Un billete para XX, por favor.\", \"translated\": \"Один билет до XX, пожалуйста.\"}, {\"original\": \"¿Tengo que hacer transbordo?\", \"translated\": \"Нужно ли мне пересаживаться?\"}, {\"original\": \"¿Cuánto tiempo falta para el próximo tren del metro?\", \"translated\": \"Через сколько прибудет следующий поезд метро?\"}, {\"original\": \"Disculpe, permítame pasar, por favor.\", \"translated\": \"Извините, пропустите меня, пожалуйста.\"}, {\"original\": \"¿Esta plaza está ocupada?\", \"translated\": \"Это место занято?\"}, {\"original\": \"Disculpe, ¿dónde puedo transbordar a la línea 2 para llegar a XX?\", \"translated\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\"}, {\"original\": \"¿Cómo llego a XX?\", \"translated\": \"Как мне добраться до XX?\"}]', 4, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en lugares turísticos?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con lugares turísticos, junto con sus traducciones al ruso:\"]', '[\"Visitar lugares de interés\", \"Tomar fotos\", \"Comprar entradas\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como preguntar sobre el precio de las entradas, encontrar un estacionamiento o solicitar un servicio de guía turística? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"¿Hay entradas para estudiantes disponibles?\", \"translated\": \"Есть ли льготные билеты для студентов?\"}, {\"original\": \"¿A qué hora abre la atracción?\", \"translated\": \"Во сколько открывается достопримечательность?\"}, {\"original\": \"¿Qué cosas divertidas se pueden hacer aquí?\", \"translated\": \"Чем здесь интересно заняться?\"}, {\"original\": \"¿Podría hacernos una foto?\", \"translated\": \"Не могли бы вы сделать для нас фотографию?\"}, {\"original\": \"¿Dónde está el autobús turístico?\", \"translated\": \"Где автобус для осмотра достопримечательностей?\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"Где находится туалет?\"}, {\"original\": \"¿Cuál es el mejor lugar para observar?\", \"translated\": \"Где лучшее место для просмотра?\"}, {\"original\": \"El paisaje aquí es hermoso.\", \"translated\": \"Здесь прекрасный вид.\"}, {\"original\": \"¿Hay visitas guiadas disponibles?\", \"translated\": \"Доступна ли экскурсия с гидом?\"}]', 5, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar al tomar un taxi o utilizar un servicio de taxis?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con los taxis o los servicios de taxis, junto con sus traducciones al ruso:\"]', '[\"Tomar un taxi\", \"Indicar el destino\", \"Pago\"]', 'es', '[\"Por ahora, ¿qué es lo que más desea hacer en este momento? Por ejemplo: preguntar el destino, el precio o solicitar una factura. No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Dónde puedo conseguir un taxi?\", \"translated\": \"Где я могу взять такси?\"}, {\"original\": \"Por favor, lléveme a esta dirección.\", \"translated\": \"Пожалуйста, отвезите меня по этому адресу.\"}, {\"original\": \"¿Cuánto costará aproximadamente?\", \"translated\": \"Примерно сколько это будет стоить?\"}, {\"original\": \"¿Podría usar el taxímetro, por favor?\", \"translated\": \"Не могли бы вы, пожалуйста, включить счётчик?\"}, {\"original\": \"Por favor, conduzca un poco más rápido, tengo prisa.\", \"translated\": \"Пожалуйста, поезжайте немного быстрее, мне спешно.\"}, {\"original\": \"Párese aquí, por favor.\", \"translated\": \"Остановитесь, пожалуйста, здесь.\"}, {\"original\": \"¿Acepta tarjetas o pagos móviles?\", \"translated\": \"Принимаете ли вы оплату картой или через мобильные приложения?\"}, {\"original\": \"¿Podría darme un recibo, por favor?\", \"translated\": \"Можно мне, пожалуйста, чек?\"}, {\"original\": \"Gracias, conductor.\", \"translated\": \"Спасибо, водитель.\"}, {\"original\": \"¿Cuánto falta aún?\", \"translated\": \"Сколько ещё осталось ехать?\"}]', 6, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en una farmacia?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con la farmacia, junto con sus traducciones al ruso:\"]', '[\"Compra de Medicamentos\", \"Consulta\", \"Pago\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir instrucciones sobre cómo tomar un medicamento, frases relacionadas con el uso del seguro médico o la duración del tratamiento? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Tiene medicamento para el resfriado?\", \"translated\": \"У вас есть лекарство от простуды?\"}, {\"original\": \"¿Cómo debo tomar este medicamento?\", \"translated\": \"Как мне принимать это лекарство?\"}, {\"original\": \"¿Tiene algún analgésico?\", \"translated\": \"У вас есть обезболивающие?\"}, {\"original\": \"¿Hay un folleto con instrucciones?\", \"translated\": \"Есть ли инструкция по применению?\"}, {\"original\": \"¿Este medicamento tiene efectos secundarios?\", \"translated\": \"Это лекарство имеет какие-либо побочные эффекты?\"}, {\"original\": \"¿Puedo usar mi tarjeta de seguro médico?\", \"translated\": \"Можно ли воспользоваться моей медицинской страховкой?\"}, {\"original\": \"¿Podría darme una caja de tiritas, por favor?\", \"translated\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\"}, {\"original\": \"¿Tiene algún antipirético?\", \"translated\": \"У вас есть жаропонижающие?\"}, {\"original\": \"Tengo una pequeña herida superficial. ¿Tiene antiséptico y tiritas?\", \"translated\": \"Я немного поранился. У вас есть антисептик и пластыри?\"}, {\"original\": \"¿A qué hora cierran?\", \"translated\": \"Во сколько вы закрываетесь?\"}]', 7, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en los servicios de emergencia?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con los servicios de emergencia, junto con sus traducciones al ruso:\"]', '[\"Llamar a la policía\", \"Primeros auxilios\", \"Pedir ayuda\"]', 'es', '[\"Por ahora, ¿tiene alguna situación de emergencia específica en mente, como incendio, herido y necesidad de ayuda, llamada de emergencia? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"Por favor, ayúdeme a llamar a una ambulancia.\", \"translated\": \"Пожалуйста, помогите мне вызвать скорую помощь.\"}, {\"original\": \"¿Dónde está el hospital?\", \"translated\": \"Где находится больница?\"}, {\"original\": \"Alguien resultó herido.\", \"translated\": \"Кто-то получил травму.\"}, {\"original\": \"Por favor, ayúdeme.\", \"translated\": \"Пожалуйста, помогите мне.\"}, {\"original\": \"¿Dónde está la comisaría?\", \"translated\": \"Где находится полицейский участок?\"}, {\"original\": \"He perdido mis pertenencias.\", \"translated\": \"Я потерял свои вещи.\"}, {\"original\": \"¿Cuál es el número de los bomberos?\", \"translated\": \"Какой номер пожарной службы?\"}, {\"original\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría más cercana?\", \"translated\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\"}, {\"original\": \"¿Hay una salida de emergencia?\", \"translated\": \"Здесь есть аварийный выход?\"}, {\"original\": \"Alguien ha desmayado.\", \"translated\": \"Кто-то потерял сознание.\"}]', 8, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en la playa o junto a la piscina?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con la playa o la piscina, junto con sus traducciones al ruso:\"]', '[\"Nadar\", \"Tomar el sol\", \"Practicar deportes playeros\"]', 'es', '[\"Por ahora, ¿podría indicarme el contexto del evento o festival local al que asistirá, por ejemplo, un festival cultural, un festival gastronómico o un festival musical? Por favor, proporcione ese contexto.\", \"Indíqueme, por favor, las actividades a las que asistirá.\"]', '[\"¿Tiene alguna situación específica en mente? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', '[{\"original\": \"¡Mira! Las olas allí son realmente grandes.\", \"translated\": \"Смотрите! Волны там действительно очень большие.\"}, {\"original\": \"Recuerda aplicar protector solar; los rayos UV aquí son muy intensos.\", \"translated\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\"}, {\"original\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\", \"translated\": \"Песок на этом пляже такой мелкий, что кажется, будто вы ступаете по хлопку.\"}, {\"original\": \"¿Qué tal jugar al voleibol en la playa?\", \"translated\": \"Как насчёт игры в волейбол на пляже?\"}, {\"original\": \"Los veleros a lo lejos lucen hermosos.\", \"translated\": \"Парусники вдали выглядят прекрасно.\"}, {\"original\": \"El agua aquí es tan transparente que incluso puedes ver los peces.\", \"translated\": \"Вода здесь такая прозрачная, что даже видно рыб.\"}, {\"original\": \"Vamos a buscar conchas marinas.\", \"translated\": \"Давайте пойдём собирать ракушки.\"}, {\"original\": \"Pasear por la playa al atardecer debe ser muy romántico.\", \"translated\": \"Прогулка по пляжу на закате, наверное, очень романтична.\"}, {\"original\": \"He oído que los mariscos aquí son muy frescos; vayamos a probarlos.\", \"translated\": \"Я слышал, что морепродукты здесь очень свежие, давайте попробуем.\"}, {\"original\": \"La marea está subiendo; volvamos hacia la orilla.\", \"translated\": \"Прилив идёт, давайте направимся к берегу.\"}]', 9, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en eventos y festivales locales?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con eventos y festivales locales, junto con sus traducciones al ruso:\"]', '[\"Asistir a eventos\", \"Celebrar festivales\", \"Aprender sobre la cultura\"]', 'es', '[\"Por ahora, ¿podría indicarme el contexto del evento o festival local al que asistirá, como Halloween, un concierto, una fiesta entre amigos u otra cosa? Por favor, proporcione ese contexto.\", \"Describa, por favor, las actividades que tiene en mente.\"]', '[\"¿Tiene alguna situación específica en mente? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', '[{\"original\": \"¿Hay algún evento hoy?\", \"translated\": \"Есть ли сегодня какие-нибудь мероприятия?\"}, {\"original\": \"¿Hay algo especial en este festival?\", \"translated\": \"В этом празднике есть что-нибудь особенное?\"}, {\"original\": \"¿Dónde se celebra la festividad?\", \"translated\": \"Где проходит празднование?\"}, {\"original\": \"¿Cómo puedo comprar entradas?\", \"translated\": \"Как я могу купить билеты?\"}, {\"original\": \"¿A qué hora empieza la actuación?\", \"translated\": \"Во сколько начинается представление?\"}, {\"original\": \"¿Qué comida tradicional hay?\", \"translated\": \"Какая традиционная еда здесь есть?\"}, {\"original\": \"Aquí es realmente animado.\", \"translated\": \"Здесь действительно очень оживлённо.\"}, {\"original\": \"¿Hay alguna actividad popular?\", \"translated\": \"Есть ли какие-нибудь народные мероприятия?\"}, {\"original\": \"¡Felices fiestas!\", \"translated\": \"Счастливых праздников!\"}, {\"original\": \"¿A qué hora termina el evento?\", \"translated\": \"Во сколько заканчивается мероприятие?\"}]', 10, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un museo o galería de arte?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con museos o galerías de arte, junto con sus traducciones al ruso:\"]', '[\"Visita\", \"Visita guiada\", \"Compra de entradas\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir un manual de introducción, frases relacionadas con una ruta guiada, frases para comentar una exposición? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"¿Tienen guías de audio?\", \"translated\": \"У вас есть аудиогиды?\"}, {\"original\": \"¿Quién creó esta obra de arte?\", \"translated\": \"Кто создал это произведение искусства?\"}, {\"original\": \"¿Dónde se encuentra la pieza más valiosa del museo?\", \"translated\": \"Где находится самая ценная экспонат музея?\"}, {\"original\": \"¿Está permitida la fotografía?\", \"translated\": \"Разрешена ли фотосъёмка?\"}, {\"original\": \"¿Hay alguna exposición especial aquí?\", \"translated\": \"Здесь проходят какие-нибудь специальные выставки?\"}, {\"original\": \"¿Cuánto tiempo dura la visita?\", \"translated\": \"Сколько времени занимает посещение?\"}, {\"original\": \"¿Podría darnos una introducción?\", \"translated\": \"Не могли бы вы дать нам краткое введение?\"}, {\"original\": \"Estas obras son verdaderamente exquisitas.\", \"translated\": \"Эти произведения действительно изысканны.\"}, {\"original\": \"¿Dónde está la tienda de souvenirs?\", \"translated\": \"Где находится магазин сувениров?\"}]', 11, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en cafeterías?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con cafeterías, junto con sus traducciones al ruso:\"]', '[\"Pedir café\", \"Descansar\", \"Socializar\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir el menú, bebidas frías o calientes, otros productos? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"Tomaré un latte, por favor.\", \"translated\": \"Я возьму латте, пожалуйста.\"}, {\"original\": \"¿Tienen conexión Wi-Fi?\", \"translated\": \"У вас есть Wi-Fi?\"}, {\"original\": \"¿Podría ver el menú, por favor?\", \"translated\": \"Можно мне посмотреть меню, пожалуйста?\"}, {\"original\": \"¿Se permiten recargas?\", \"translated\": \"Разрешено ли добавлять кофе бесплатно?\"}, {\"original\": \"¿Ya está listo mi café?\", \"translated\": \"Мой кофе уже готов?\"}, {\"original\": \"¿Cuánto tiempo puedo quedarme aquí?\", \"translated\": \"Сколько времени я могу здесь посидеть?\"}, {\"original\": \"¿Podría tomarnos una foto?\", \"translated\": \"Не могли бы вы сделать для нас фотографию?\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"Где туалет?\"}, {\"original\": \"La cuenta, por favor. Gracias.\", \"translated\": \"Счёт, пожалуйста. Спасибо.\"}, {\"original\": \"Sabe realmente bien.\", \"translated\": \"Очень вкусно.\"}]', 12, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنك أن تزودني بـ10 عبارات شائعة يمكنني استخدامها في المطعم؟\", \"رائع! إليك 10 عبارات شائعة تتعلق بالمطعم:\"]', '[\"تناول الطعام\", \"طلب الطعام\", \"الدفع\"]', 'ar', '[\"بالنسبة للآن، هل لديك وضع معين في ذهنك، مثل طلب المشروبات أو تقديم شكوى أو الاستفسار عن المكونات، فلا تتردد في السؤال.\", \"رجاءً وصف الوضع الذي في ذهنك.\"]', NULL, '[{\"original\": \"عذرا، كم سيستغرق طعامنا؟\", \"translated\": \"Извините, сколько еще ждать нашу еду?\"}, {\"original\": \"طاولة لشخصين من فضلك.\", \"translated\": \"Столик на двоих, пожалуйста.\"}, {\"original\": \"هل يمكننا رؤية القائمة من فضلك؟\", \"translated\": \"Можно посмотреть меню, пожалуйста?\"}, {\"original\": \"هل لديك أي أطباق خاصة توصي بها؟\", \"translated\": \"Есть ли у вас какие-нибудь фирменные блюда, которые вы можете порекомендовать?\"}, {\"original\": \"أود أن أطلب هذا وهذا.\", \"translated\": \"Я хотел бы заказать это и это.\"}, {\"original\": \"كأس من الماء من فضلك. شكراً.\", \"translated\": \"Стакан воды, пожалуйста. Спасибо.\"}, {\"original\": \"الفاتورة من فضلك.\", \"translated\": \"Счет, пожалуйста.\"}, {\"original\": \"هل يمكنني الدفع ببطاقة الائتمان؟\", \"translated\": \"Можно оплатить картой?\"}, {\"original\": \"هل يمكنك تعبئة هذا ليأخذ معه من فضلك؟\", \"translated\": \"Можно это упаковать с собой, пожалуйста?\"}, {\"original\": \"كان الطعام شهيًا، شكراً لك.\", \"translated\": \"Еда была вкусной, спасибо.\"}]', 1, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare al ristorante?\", \"Fantastico! Ecco 10 frasi comuni relative al ristorante, insieme alle rispettive traduzioni in russo:\"]', '[\"Ristorazione\", \"Ordinazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio ordinare bevande, presentare un reclamo o chiedere informazioni sugli ingredienti? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\", \"translated\": \"Извините, сколько ещё ждать нашу еду?\"}, {\"original\": \"Un tavolo per due, per favore.\", \"translated\": \"Столик на двоих, пожалуйста.\"}, {\"original\": \"Potremmo vedere il menù, per favore?\", \"translated\": \"Можно посмотреть меню, пожалуйста?\"}, {\"original\": \"Avete dei piatti tipici da consigliarci?\", \"translated\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\"}, {\"original\": \"Vorrei ordinare questo e quest’altro.\", \"translated\": \"Я хочу заказать это и это.\"}, {\"original\": \"Un bicchiere d’acqua, per favore. Grazie.\", \"translated\": \"Стакан воды, пожалуйста. Спасибо.\"}, {\"original\": \"Il conto, per favore.\", \"translated\": \"Счёт, пожалуйста.\"}, {\"original\": \"Posso pagare con carta di credito?\", \"translated\": \"Можно оплатить кредитной картой?\"}, {\"original\": \"Potrebbe impacchettare questo da portare via, per favore?\", \"translated\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\"}, {\"original\": \"Il cibo era delizioso, grazie.\", \"translated\": \"Еда была восхитительной, спасибо.\"}]', 1, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare in un hotel?\", \"Fantastico! Ecco 10 frasi comuni relative all\'hotel, insieme alle rispettive traduzioni in russo:\"]', '[\"Check-in\", \"Check-out\", \"Servizio in camera\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio la posizione della camera, altri servizi dell\'hotel o il check-out? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Salve, ho una prenotazione, ecco il mio passaporto.\", \"translated\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\"}, {\"original\": \"Avete camere disponibili?\", \"translated\": \"У вас есть свободные номера?\"}, {\"original\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\", \"translated\": \"Извините, в отеле есть тренажёрный зал или прачечная?\"}, {\"original\": \"A che ora inizia la colazione?\", \"translated\": \"Во сколько начинается завтрак?\"}, {\"original\": \"Potrei avere la chiave della mia stanza, per favore?\", \"translated\": \"Можно мне ключ от номера, пожалуйста?\"}, {\"original\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\", \"translated\": \"Не могли бы вы помочь мне отнести багаж в номер?\"}, {\"original\": \"Come posso chiamare il servizio in camera?\", \"translated\": \"Как вызвать службу обслуживания номеров?\"}, {\"original\": \"A che ora è il check-out?\", \"translated\": \"До какого времени необходимо освободить номер?\"}, {\"original\": \"Potrebbe rilasciarmi una ricevuta/fattura?\", \"translated\": \"Не могли бы вы выписать мне квитанцию/счёт?\"}, {\"original\": \"Posso lasciare qui i miei bagagli?\", \"translated\": \"Можно оставить здесь мой багаж?\"}]', 2, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in aeroporto?\", \"Fantastico! Ecco 10 frasi comuni relative all\'aeroporto, insieme alle traduzioni in russo:\"]', '[\"Check-in\", \"Imbarco\", \"Controllo bagagli\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio il check-in, il ritiro bagagli o il servizio di noleggio auto? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dov\'è il banco del check-in?\", \"translated\": \"Где стойка регистрации?\"}, {\"original\": \"Vorrei un posto vicino al finestrino, per favore.\", \"translated\": \"Я бы хотел место у окна, пожалуйста.\"}, {\"original\": \"Questo volo è in ritardo?\", \"translated\": \"Этот рейс задерживается?\"}, {\"original\": \"Devo registrare questo bagaglio.\", \"translated\": \"Мне нужно зарегистрировать этот багаж.\"}, {\"original\": \"Dov\'è l\'ingresso per l\'imbarco?\", \"translated\": \"Где выход на посадку?\"}, {\"original\": \"L\'aeroplano sta per decollare.\", \"translated\": \"Самолёт вот-вот взлетит.\"}, {\"original\": \"Devo estrarre il mio laptop e la power bank?\", \"translated\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\"}, {\"original\": \"Dov\'è il negozio duty-free?\", \"translated\": \"Где магазин беспошлинной торговли?\"}, {\"original\": \"Non riesco a trovare la mia valigia.\", \"translated\": \"Я не могу найти свой чемодан.\"}, {\"original\": \"Offrite un servizio di sedia a rotelle?\", \"translated\": \"Предоставляется ли услуга инвалидных колясок?\"}]', 3, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei trasporti pubblici?\", \"Fantastico! Ecco 10 frasi comuni relative ai trasporti pubblici, insieme alle rispettive traduzioni in russo:\"]', '[\"Prendere l\'autobus o la metropolitana\", \"Acquistare biglietti\", \"Effettuare un trasferimento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere dove si trova la fermata dell’autobus, il prezzo del biglietto o come scendere? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Questo autobus va al capolinea?\", \"translated\": \"Этот автобус идёт до автовокзала?\"}, {\"original\": \"Qual è la prossima fermata?\", \"translated\": \"Какая следующая остановка?\"}, {\"original\": \"Dove posso comprare un biglietto?\", \"translated\": \"Где я могу купить билет?\"}, {\"original\": \"Un biglietto per XX, per favore.\", \"translated\": \"Один билет до XX, пожалуйста.\"}, {\"original\": \"Devo cambiare mezzo?\", \"translated\": \"Нужно ли мне пересаживаться?\"}, {\"original\": \"Quanto manca al prossimo treno della metropolitana?\", \"translated\": \"Через сколько прибудет следующий поезд метро?\"}, {\"original\": \"Scusi, mi lasci passare, per favore.\", \"translated\": \"Извините, пропустите меня, пожалуйста.\"}, {\"original\": \"Questo posto è occupato?\", \"translated\": \"Это место занято?\"}, {\"original\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\", \"translated\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\"}, {\"original\": \"Come arrivo a XX?\", \"translated\": \"Как мне добраться до XX?\"}]', 4, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nelle attrazioni turistiche?\", \"Fantastico! Ecco 10 frasi comuni relative alle attrazioni turistiche, insieme alle rispettive traduzioni in russo:\"]', '[\"Visita turistica\", \"Scattare foto\", \"Acquistare biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il prezzo dei biglietti, trovare un parcheggio o richiedere un servizio di guida turistica? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"Sono disponibili biglietti per studenti?\", \"translated\": \"Есть ли льготные билеты для студентов?\"}, {\"original\": \"A che ora apre la attrazione?\", \"translated\": \"Во сколько открывается достопримечательность?\"}, {\"original\": \"Quali sono le cose divertenti da fare qui?\", \"translated\": \"Чем здесь интересно заняться?\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"Не могли бы вы сделать для нас фотографию?\"}, {\"original\": \"Dove si trova l\'autobus turistico?\", \"translated\": \"Где автобус для осмотра достопримечательностей?\"}, {\"original\": \"Dove si trova il bagno?\", \"translated\": \"Где находится туалет?\"}, {\"original\": \"Dov\'è il miglior punto panoramico?\", \"translated\": \"Где лучшее место для просмотра?\"}, {\"original\": \"Il paesaggio qui è bellissimo.\", \"translated\": \"Здесь прекрасный вид.\"}, {\"original\": \"È disponibile un tour guidato?\", \"translated\": \"Доступна ли экскурсия с гидом?\"}]', 5, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare con un taxi o un servizio taxi?\", \"Fantastico! Ecco 10 frasi comuni relative al taxi o a un servizio taxi, insieme alle rispettive traduzioni in russo:\"]', '[\"Prendere un taxi\", \"Indicare la destinazione\", \"Pagamento\"]', 'it', '[\"Per ora, cosa vorrebbe fare principalmente in questo momento? Ad esempio chiedere la destinazione, il costo o una ricevuta: senta pure di chiedere.\", \"La prego di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dove posso prendere un taxi?\", \"translated\": \"Где я могу взять такси?\"}, {\"original\": \"Mi porti a questo indirizzo, per favore.\", \"translated\": \"Пожалуйста, отвезите меня по этому адресу.\"}, {\"original\": \"Quanto costerà all\'incirca?\", \"translated\": \"Примерно сколько это будет стоить?\"}, {\"original\": \"Potrebbe usare il tassametro, per favore?\", \"translated\": \"Не могли бы вы, пожалуйста, включить счётчик?\"}, {\"original\": \"Può guidare un po\' più velocemente, sono di fretta.\", \"translated\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\"}, {\"original\": \"Si fermi qui, per favore.\", \"translated\": \"Остановитесь здесь, пожалуйста.\"}, {\"original\": \"Accetta carte o pagamenti mobili?\", \"translated\": \"Принимаете ли вы оплату картой или через мобильные платежи?\"}, {\"original\": \"Potrei avere lo scontrino, per favore?\", \"translated\": \"Можно мне, пожалуйста, чек?\"}, {\"original\": \"Grazie, autista.\", \"translated\": \"Спасибо, водитель.\"}, {\"original\": \"Quanto manca ancora?\", \"translated\": \"Сколько ещё осталось ехать?\"}]', 6, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare in farmacia?\", \"Fantastico! Ecco 10 frasi comuni relative alla farmacia, insieme alle rispettive traduzioni in russo:\"]', '[\"Acquisto di Farmaci\", \"Consultazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere istruzioni sull’assunzione di un farmaco, frasi relative all’utilizzo dell’assicurazione sanitaria o alla durata della terapia? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Ha dei farmaci per il raffreddore?\", \"translated\": \"У вас есть лекарство от простуды?\"}, {\"original\": \"Come devo assumere questo farmaco?\", \"translated\": \"Как мне принимать это лекарство?\"}, {\"original\": \"Ha degli antidolorifici?\", \"translated\": \"У вас есть обезболивающие?\"}, {\"original\": \"È incluso un foglietto illustrativo?\", \"translated\": \"Есть ли инструкция по применению?\"}, {\"original\": \"Questo farmaco ha effetti collaterali?\", \"translated\": \"Это лекарство имеет какие-либо побочные эффекты?\"}, {\"original\": \"Posso utilizzare la mia tessera sanitaria?\", \"translated\": \"Можно ли воспользоваться моей медицинской страховкой?\"}, {\"original\": \"Potrei avere una confezione di cerotti, per favore?\", \"translated\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\"}, {\"original\": \"Ha dei farmaci antipiretici?\", \"translated\": \"У вас есть жаропонижающие?\"}, {\"original\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\", \"translated\": \"Я немного поранился. У вас есть антисептик и пластыри?\"}, {\"original\": \"A che ora chiude?\", \"translated\": \"Во сколько вы закрываетесь?\"}]', 7, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei servizi di emergenza?\", \"Fantastico! Ecco 10 frasi comuni relative ai servizi di emergenza, insieme alle rispettive traduzioni in russo:\"]', '[\"Chiamare la polizia\", \"Pronto soccorso\", \"Chiedere aiuto\"]', 'it', '[\"Per il momento, ha in mente una situazione di emergenza specifica, ad esempio un incendio, una persona ferita che necessita di aiuto o una chiamata d\'emergenza? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\", \"translated\": \"Пожалуйста, помогите мне вызвать скорую помощь.\"}, {\"original\": \"Dov\'è l\'ospedale?\", \"translated\": \"Где находится больница?\"}, {\"original\": \"Qualcuno è ferito.\", \"translated\": \"Кто-то получил травму.\"}, {\"original\": \"Per favore, mi aiuti.\", \"translated\": \"Пожалуйста, помогите мне.\"}, {\"original\": \"Dov\'è la stazione di polizia?\", \"translated\": \"Где находится полицейский участок?\"}, {\"original\": \"Ho perso i miei effetti personali.\", \"translated\": \"Я потерял свои вещи.\"}, {\"original\": \"Qual è il numero dei vigili del fuoco?\", \"translated\": \"Какой номер пожарной службы?\"}, {\"original\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\", \"translated\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\"}, {\"original\": \"C\'è un\'uscita di emergenza?\", \"translated\": \"Здесь есть аварийный выход?\"}, {\"original\": \"Qualcuno è svenuto.\", \"translated\": \"Кто-то потерял сознание.\"}]', 8, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare in spiaggia o in piscina?\", \"Fantastico! Ecco 10 frasi comuni relative alla spiaggia o alla piscina, insieme alle rispettive traduzioni in russo:\"]', '[\"Nuoto\", \"Abbronzatura\", \"Sport sulla spiaggia\"]', 'it', '[\"Per ora, potrebbe gentilmente indicarmi il contesto dell\'evento o della festa locale a cui parteciperà, ad esempio una festa culturale, una festa del cibo o una festa musicale? Fornisca il contesto.\", \"Indichi le attività a cui parteciperà.\"]', '[\"Ha in mente una situazione specifica? Non esiti a chiedere.\", \"Descriva la situazione che ha in mente.\"]', '[{\"original\": \"Guarda! Le onde laggiù sono davvero grandi.\", \"translated\": \"Смотрите! Волны там действительно очень большие.\"}, {\"original\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\", \"translated\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\"}, {\"original\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\", \"translated\": \"Песок на этом пляже такой мелкий, что кажется, будто вы ступаете по хлопку.\"}, {\"original\": \"Che ne dici di giocare a pallavolo in spiaggia?\", \"translated\": \"Как насчёт игры в волейбол на пляже?\"}, {\"original\": \"Le barche a vela in lontananza sembrano bellissime.\", \"translated\": \"Парусники вдали выглядят прекрасно.\"}, {\"original\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\", \"translated\": \"Вода здесь такая прозрачная, что даже видно рыб.\"}, {\"original\": \"Andiamo a cercare delle conchiglie.\", \"translated\": \"Давайте пойдём собирать ракушки.\"}, {\"original\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\", \"translated\": \"Прогулка по пляжу на закате, наверное, очень романтична.\"}, {\"original\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\", \"translated\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\"}, {\"original\": \"La marea sta salendo, dirigiamoci verso la riva.\", \"translated\": \"Начинается прилив, давайте направимся к берегу.\"}]', 9, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare durante eventi e festival locali?\", \"Fantastico! Ecco 10 frasi comuni relative a eventi e festival locali, insieme alle rispettive traduzioni in russo:\"]', '[\"Partecipare a eventi\", \"Celebrare festival\", \"Apprendere la cultura\"]', 'it', '[\"Per ora, potrebbe gentilmente indicarmi il contesto dell’evento o del festival locale a cui parteciperà, ad esempio Halloween, un concerto, una festa tra amici o qualcos’altro? La preghiamo di specificare il contesto.\", \"La preghiamo di descrivere le attività che ha in mente.\"]', '[\"Ha in mente una situazione specifica? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Ci sono eventi oggi?\", \"translated\": \"Есть ли сегодня какие-нибудь мероприятия?\"}, {\"original\": \"C\'è qualcosa di speciale in questo festival?\", \"translated\": \"В этом празднике есть что-нибудь особенное?\"}, {\"original\": \"Dove si tiene la celebrazione?\", \"translated\": \"Где проходит празднование?\"}, {\"original\": \"Come posso acquistare i biglietti?\", \"translated\": \"Как я могу купить билеты?\"}, {\"original\": \"A che ora inizia lo spettacolo?\", \"translated\": \"Во сколько начинается представление?\"}, {\"original\": \"Quali sono i cibi tradizionali?\", \"translated\": \"Какая традиционная еда здесь есть?\"}, {\"original\": \"Qui è davvero animato.\", \"translated\": \"Здесь действительно очень оживлённо.\"}, {\"original\": \"Ci sono attività popolari?\", \"translated\": \"Есть ли какие-нибудь народные мероприятия?\"}, {\"original\": \"Buone feste!\", \"translated\": \"Счастливых праздников!\"}, {\"original\": \"A che ora termina l\'evento?\", \"translated\": \"Во сколько заканчивается мероприятие?\"}]', 10, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un museo o in una galleria d\'arte?\", \"Fantastico! Ecco 10 frasi comuni relative a un museo o a una galleria d\'arte, insieme alle rispettive traduzioni in russo:\"]', '[\"Visita\", \"Tour guidato\", \"Acquisto di biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere un manuale introduttivo, frasi relative alla mappa del percorso, frasi per commentare le opere esposte? Si senta libero di chiedere.\", \"La prego di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"Avete guide audio?\", \"translated\": \"Есть ли у вас аудиогиды?\"}, {\"original\": \"Chi ha creato quest\'opera d\'arte?\", \"translated\": \"Кто является автором этого произведения искусства?\"}, {\"original\": \"Dove si trova il pezzo più prezioso del museo?\", \"translated\": \"Где находится самое ценное произведение музея?\"}, {\"original\": \"È consentito fare fotografie?\", \"translated\": \"Разрешена ли фотосъёмка?\"}, {\"original\": \"Ci sono delle mostre speciali qui?\", \"translated\": \"Есть ли здесь какие-нибудь специальные выставки?\"}, {\"original\": \"Quanto tempo richiede la visita?\", \"translated\": \"Сколько времени занимает посещение?\"}, {\"original\": \"Potreste darci una breve introduzione?\", \"translated\": \"Не могли бы вы кратко рассказать об экспозиции?\"}, {\"original\": \"Queste opere sono davvero squisite.\", \"translated\": \"Эти произведения действительно изысканны.\"}, {\"original\": \"Dove si trova il negozio dei souvenir?\", \"translated\": \"Где находится магазин сувениров?\"}]', 11, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare nei bar?\", \"Fantastico! Ecco 10 frasi comuni relative ai bar, insieme alle rispettive traduzioni in russo:\"]', '[\"Ordinare un caffè\", \"Riposare\", \"Socializzare\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il menù, bevande fredde o calde, altri prodotti? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Prenderò un caffè latte, per favore.\", \"translated\": \"Я возьму латте, пожалуйста.\"}, {\"original\": \"Avete il Wi-Fi?\", \"translated\": \"У вас есть Wi-Fi?\"}, {\"original\": \"Potrei vedere il menu, per favore?\", \"translated\": \"Можно мне посмотреть меню, пожалуйста?\"}, {\"original\": \"Sono ammessi i rabbocchi?\", \"translated\": \"Разрешено ли добавлять кофе бесплатно?\"}, {\"original\": \"Il mio caffè è pronto?\", \"translated\": \"Мой кофе уже готов?\"}, {\"original\": \"Per quanto tempo posso stare seduto qui?\", \"translated\": \"Сколько времени я могу здесь посидеть?\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"Не могли бы вы сделать для нас фотографию?\"}, {\"original\": \"Dov\'è il bagno?\", \"translated\": \"Где туалет?\"}, {\"original\": \"Il conto, per favore. Grazie.\", \"translated\": \"Счёт, пожалуйста. Спасибо.\"}, {\"original\": \"Ha davvero un ottimo sapore.\", \"translated\": \"Очень вкусно.\"}]', 12, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare al ristorante?\", \"Fantastico! Ecco 10 frasi comuni relative al ristorante, insieme alle rispettive traduzioni in cinese:\"]', '[\"Ristorazione\", \"Ordinazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio ordinare bevande, presentare un reclamo o chiedere informazioni sugli ingredienti? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\", \"translated\": \"打扰一下，我们的菜还要等多久？\"}, {\"original\": \"Un tavolo per due, per favore.\", \"translated\": \"请给我们安排一张两人桌。\"}, {\"original\": \"Potremmo vedere il menu, per favore?\", \"translated\": \"麻烦给我们看一下菜单。\"}, {\"original\": \"Avete dei piatti tipici da consigliarci?\", \"translated\": \"你们有什么招牌菜可以推荐吗？\"}, {\"original\": \"Vorrei ordinare questo e quest’altro.\", \"translated\": \"我要点这个和这个。\"}, {\"original\": \"Un bicchiere d’acqua, per favore. Grazie.\", \"translated\": \"请给我一杯水，谢谢。\"}, {\"original\": \"Il conto, per favore.\", \"translated\": \"请结账。\"}, {\"original\": \"Posso pagare con carta di credito?\", \"translated\": \"我可以刷信用卡付款吗？\"}, {\"original\": \"Potrebbe confezionarmelo da asporto, per favore?\", \"translated\": \"麻烦帮我把这份打包带走。\"}, {\"original\": \"Il cibo era delizioso, grazie.\", \"translated\": \"饭菜非常美味，谢谢。\"}]', 1, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un hotel?\", \"Fantastico! Ecco 10 frasi comuni relative all\'hotel, insieme alle rispettive traduzioni in cinese:\"]', '[\"Check-in\", \"Check-out\", \"Servizio in camera\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio la posizione della camera, altri servizi offerti dall\'hotel o il check-out? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Salve, ho una prenotazione, ecco il mio passaporto.\", \"translated\": \"你好，我已预订房间，这是我的护照。\"}, {\"original\": \"Avete camere disponibili?\", \"translated\": \"请问还有空房吗？\"}, {\"original\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\", \"translated\": \"打扰一下，酒店有健身房或洗衣房吗？\"}, {\"original\": \"A che ora inizia la colazione?\", \"translated\": \"早餐几点开始？\"}, {\"original\": \"Potrei avere la chiave della mia stanza, per favore?\", \"translated\": \"请给我一把房卡，谢谢。\"}, {\"original\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\", \"translated\": \"您能帮我把行李送到房间吗？\"}, {\"original\": \"Come posso chiamare il servizio in camera?\", \"translated\": \"我该怎么呼叫客房服务？\"}, {\"original\": \"A che ora è il check-out?\", \"translated\": \"退房时间是几点？\"}, {\"original\": \"Potrebbe rilasciarmi una ricevuta/fattura?\", \"translated\": \"请您给我开一张收据/发票。\"}, {\"original\": \"Posso lasciare qui i miei bagagli?\", \"translated\": \"我可以把行李寄存在这里吗？\"}]', 2, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in aeroporto?\", \"Fantastico! Ecco 10 frasi comuni relative all\'aeroporto, insieme alle rispettive traduzioni in cinese:\"]', '[\"Check-in\", \"Imbarco\", \"Controllo bagagli\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio il check-in, il ritiro dei bagagli o il servizio di noleggio auto? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dov\'è il banco del check-in?\", \"translated\": \"值机柜台在哪里？\"}, {\"original\": \"Vorrei un posto vicino al finestrino, per favore.\", \"translated\": \"请给我一个靠窗的座位。\"}, {\"original\": \"Questo volo è in ritardo?\", \"translated\": \"这个航班延误了吗？\"}, {\"original\": \"Devo registrare questo bagaglio.\", \"translated\": \"我需要托运行李。\"}, {\"original\": \"Dov\'è l\'ingresso per l\'imbarco?\", \"translated\": \"登机口在哪里？\"}, {\"original\": \"L\'aeroplano sta per decollare.\", \"translated\": \"飞机即将起飞。\"}, {\"original\": \"Devo estrarre il mio laptop e la power bank?\", \"translated\": \"我需要把笔记本电脑和充电宝拿出来吗？\"}, {\"original\": \"Dov\'è il negozio duty-free?\", \"translated\": \"免税店在哪里？\"}, {\"original\": \"Non riesco a trovare la mia valigia.\", \"translated\": \"我找不到我的行李箱了。\"}, {\"original\": \"Offrite un servizio di sedia a rotelle?\", \"translated\": \"你们提供轮椅服务吗？\"}]', 3, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei trasporti pubblici?\", \"Fantastico! Ecco 10 frasi comuni relative ai trasporti pubblici, insieme alle rispettive traduzioni in cinese:\"]', '[\"Prendere l\'autobus o la metropolitana\", \"Acquistare biglietti\", \"Effettuare un trasferimento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere dove si trova la fermata dell’autobus, il prezzo del biglietto o come scendere? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Questo autobus va al capolinea?\", \"translated\": \"这趟公交车去终点站吗？\"}, {\"original\": \"Qual è la prossima fermata?\", \"translated\": \"下一站是哪里？\"}, {\"original\": \"Dove posso comprare un biglietto?\", \"translated\": \"我在哪里可以买票？\"}, {\"original\": \"Un biglietto per XX, per favore.\", \"translated\": \"请给我一张去XX的车票。\"}, {\"original\": \"Devo cambiare mezzo?\", \"translated\": \"我需要换乘吗？\"}, {\"original\": \"Quanto manca al prossimo treno della metropolitana?\", \"translated\": \"下一班地铁列车还要等多久？\"}, {\"original\": \"Scusi, mi lasci passare, per favore.\", \"translated\": \"不好意思，请让我过去。\"}, {\"original\": \"Questo posto è occupato?\", \"translated\": \"这个座位有人吗？\"}, {\"original\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\", \"translated\": \"不好意思，请问我在哪里换乘二号线去XX？\"}, {\"original\": \"Come arrivo a XX?\", \"translated\": \"我怎么去XX？\"}]', 4, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nelle attrazioni turistiche?\", \"Fantastico! Ecco 10 frasi comuni relative alle attrazioni turistiche, insieme alle rispettive traduzioni in cinese:\"]', '[\"Visita turistica\", \"Scattare foto\", \"Acquistare biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il prezzo dei biglietti, trovare un parcheggio o richiedere un servizio di guida turistica? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"Sono disponibili biglietti per studenti?\", \"translated\": \"有学生票吗？\"}, {\"original\": \"A che ora apre la attrazione?\", \"translated\": \"景点几点开门？\"}, {\"original\": \"Quali sono le cose divertenti da fare qui?\", \"translated\": \"这里有哪些好玩的项目？\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"您能帮我们拍张照片吗？\"}, {\"original\": \"Dove si trova l\'autobus per i tour turistici?\", \"translated\": \"观光巴士在哪里？\"}, {\"original\": \"Dove si trova il bagno?\", \"translated\": \"洗手间在哪儿？\"}, {\"original\": \"Dove si trova il punto migliore per osservare la vista?\", \"translated\": \"最佳观景点在哪儿？\"}, {\"original\": \"Il paesaggio qui è bellissimo.\", \"translated\": \"这里的风景很美。\"}, {\"original\": \"È disponibile un tour guidato?\", \"translated\": \"有提供导游服务吗？\"}]', 5, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare per un taxi o un servizio taxi?\", \"Fantastico! Ecco 10 frasi comuni relative al taxi o a un servizio taxi, insieme alle rispettive traduzioni in cinese:\"]', '[\"Prendere un taxi\", \"Indicare la destinazione\", \"Pagamento\"]', 'it', '[\"Per ora, cosa desidera fare principalmente in questo momento? Ad esempio chiedere la destinazione, il costo o una ricevuta: si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dove posso prendere un taxi?\", \"translated\": \"我在哪里可以打到出租车？\"}, {\"original\": \"Mi porti a questo indirizzo, per favore.\", \"translated\": \"请送我去这个地址。\"}, {\"original\": \"Quanto costerà all\'incirca?\", \"translated\": \"大概需要多少钱？\"}, {\"original\": \"Potrebbe usare il tassametro, per favore?\", \"translated\": \"请您打表计费，好吗？\"}, {\"original\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\", \"translated\": \"请开快一点，我赶时间。\"}, {\"original\": \"Si fermi qui, per favore.\", \"translated\": \"请在这里停车。\"}, {\"original\": \"Accetta carte di credito o pagamenti mobili?\", \"translated\": \"您接受银行卡或手机支付吗？\"}, {\"original\": \"Potrei avere lo scontrino, per favore?\", \"translated\": \"可以给我一张收据吗？\"}, {\"original\": \"Grazie, autista.\", \"translated\": \"谢谢您，司机师傅。\"}, {\"original\": \"Quanto manca ancora?\", \"translated\": \"还有多远？\"}]', 6, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in farmacia?\", \"Fantastico! Ecco 10 frasi comuni relative alla farmacia, insieme alle rispettive traduzioni in cinese:\"]', '[\"Acquisto di Farmaci\", \"Consultazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere indicazioni sull’assunzione di un farmaco, frasi relative all’utilizzo dell’assicurazione sanitaria o alla durata della terapia? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Ha dei farmaci per il raffreddore?\", \"translated\": \"你们有治感冒的药吗？\"}, {\"original\": \"Come devo assumere questo farmaco?\", \"translated\": \"这种药我该怎么服用？\"}, {\"original\": \"Ha degli antidolorifici?\", \"translated\": \"你们有止痛药吗？\"}, {\"original\": \"È incluso un foglietto illustrativo?\", \"translated\": \"这个药有说明书吗？\"}, {\"original\": \"Questo farmaco ha effetti collaterali?\", \"translated\": \"这种药有什么副作用吗？\"}, {\"original\": \"Posso usare la mia tessera sanitaria?\", \"translated\": \"我能用我的医保卡吗？\"}, {\"original\": \"Potrei avere una confezione di cerotti, per favore?\", \"translated\": \"请给我一盒创可贴，谢谢。\"}, {\"original\": \"Ha dei farmaci per abbassare la febbre?\", \"translated\": \"你们有退烧药吗？\"}, {\"original\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\", \"translated\": \"我有点擦伤，你们有消毒药水和创可贴吗？\"}, {\"original\": \"A che ora chiude?\", \"translated\": \"你们几点关门？\"}]', 7, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei servizi di emergenza?\", \"Fantastico! Ecco 10 frasi comuni relative ai servizi di emergenza, insieme alle rispettive traduzioni in cinese:\"]', '[\"Chiamare la polizia\", \"Pronto soccorso\", \"Chiedere aiuto\"]', 'it', '[\"Per il momento, ha in mente una situazione di emergenza specifica, ad esempio un incendio, una persona ferita che necessita di aiuto o una chiamata d\'emergenza? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\", \"translated\": \"请帮我叫一辆救护车。\"}, {\"original\": \"Dov\'è l\'ospedale?\", \"translated\": \"医院在哪里？\"}, {\"original\": \"Qualcuno è ferito.\", \"translated\": \"有人受伤了。\"}, {\"original\": \"Per favore, mi aiuti.\", \"translated\": \"请帮帮我。\"}, {\"original\": \"Dov\'è la stazione di polizia?\", \"translated\": \"警察局在哪里？\"}, {\"original\": \"Ho perso i miei effetti personali.\", \"translated\": \"我的物品丢失了。\"}, {\"original\": \"Qual è il numero del corpo dei vigili del fuoco?\", \"translated\": \"消防部门的电话号码是多少？\"}, {\"original\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\", \"translated\": \"我的护照丢了。您知道最近的警察局在哪里吗？\"}, {\"original\": \"C\'è un\'uscita di emergenza?\", \"translated\": \"有紧急出口吗？\"}, {\"original\": \"Qualcuno è svenuto.\", \"translated\": \"有人晕倒了。\"}]', 8, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potresti fornirmi 10 frasi comuni che posso usare in spiaggia o in piscina?\", \"Fantastico! Ecco 10 frasi comuni relative alla spiaggia o alla piscina, insieme alle rispettive traduzioni in cinese:\"]', '[\"Nuoto\", \"Bagni di sole\", \"Sport sulla spiaggia\"]', 'it', '[\"Per ora, potresti gentilmente indicarmi il contesto dell’evento o della festa locale a cui parteciperai, ad esempio una festa culturale, una festa del cibo o una festa musicale? Fornisci il contesto.\", \"Indica le attività a cui parteciperai.\"]', '[\"Hai in mente una situazione specifica? Chiedi pure liberamente.\", \"Descrivi la situazione che hai in mente.\"]', '[{\"original\": \"Guarda! Le onde laggiù sono davvero grandi.\", \"translated\": \"看！那边的海浪真大。\"}, {\"original\": \"Ricordati di applicare la crema solare, qui i raggi UV sono molto intensi.\", \"translated\": \"记得涂防晒霜，这里的紫外线很强。\"}, {\"original\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\", \"translated\": \"这片海滩的沙子非常细腻，踩上去像踩在棉花上。\"}, {\"original\": \"Che ne dici di giocare a pallavolo in spiaggia?\", \"translated\": \"在海滩上打排球怎么样？\"}, {\"original\": \"Le barche a vela in lontananza sembrano bellissime.\", \"translated\": \"远处的帆船看起来真美。\"}, {\"original\": \"L\'acqua qui è così trasparente che si vedono persino i pesci.\", \"translated\": \"这里的海水如此清澈，连鱼都能看见。\"}, {\"original\": \"Andiamo a cercare delle conchiglie.\", \"translated\": \"我们去找些贝壳吧。\"}, {\"original\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\", \"translated\": \"日落时分在海滩上散步一定很浪漫。\"}, {\"original\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\", \"translated\": \"听说这里的海鲜非常新鲜，我们去尝尝吧。\"}, {\"original\": \"La marea sta salendo, dirigiamoci verso la riva.\", \"translated\": \"涨潮了，我们往岸边走吧。\"}]', 9, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare durante eventi e festival locali?\", \"Fantastico! Ecco 10 frasi comuni relative a eventi e festival locali, insieme alle rispettive traduzioni in cinese:\"]', '[\"Partecipare a eventi\", \"Celebrare festival\", \"Apprendere la cultura\"]', 'it', '[\"Per ora, potrebbe gentilmente indicarmi il contesto dell’evento o del festival locale a cui parteciperà, ad esempio Halloween, un concerto, una festa tra amici o qualcos’altro? La preghiamo di specificare il contesto.\", \"La preghiamo di descrivere le attività che ha in mente.\"]', '[\"Ha in mente una situazione specifica? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Ci sono eventi oggi?\", \"translated\": \"今天有什么活动吗？\"}, {\"original\": \"C\'è qualcosa di speciale in questo festival?\", \"translated\": \"这个节日有什么特别之处吗？\"}, {\"original\": \"Dove si tiene la celebrazione?\", \"translated\": \"庆祝活动在哪里举行？\"}, {\"original\": \"Come posso acquistare i biglietti?\", \"translated\": \"我该如何购买门票？\"}, {\"original\": \"A che ora inizia lo spettacolo?\", \"translated\": \"演出什么时候开始？\"}, {\"original\": \"Quali sono i cibi tradizionali?\", \"translated\": \"有哪些传统食物？\"}, {\"original\": \"Qui è davvero animato.\", \"translated\": \"这里真热闹。\"}, {\"original\": \"Ci sono attività popolari?\", \"translated\": \"有民俗活动吗？\"}, {\"original\": \"Buone feste!\", \"translated\": \"节日快乐！\"}, {\"original\": \"A che ora termina l\'evento?\", \"translated\": \"活动什么时候结束？\"}]', 10, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un museo o in una galleria d\'arte?\", \"Fantastico! Ecco 10 frasi comuni relative a un museo o a una galleria d\'arte, insieme alle rispettive traduzioni in cinese:\"]', '[\"Visita\", \"Tour guidato\", \"Acquisto di biglietti\"]', 'it', '[\"Per il momento, ha in mente una situazione specifica, ad esempio chiedere un manuale introduttivo, frasi relative a una mappa, frasi per commentare un\'esposizione? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"Avete guide audio?\", \"translated\": \"你们提供语音导览吗？\"}, {\"original\": \"Chi ha creato quest\'opera d\'arte?\", \"translated\": \"这件艺术品是谁创作的？\"}, {\"original\": \"Dove si trova il pezzo più prezioso del museo?\", \"translated\": \"博物馆最珍贵的藏品在哪里？\"}, {\"original\": \"È consentito fare fotografie?\", \"translated\": \"允许拍照吗？\"}, {\"original\": \"Ci sono delle mostre speciali qui?\", \"translated\": \"这里有没有特别展览？\"}, {\"original\": \"Quanto tempo richiede la visita?\", \"translated\": \"参观需要多长时间？\"}, {\"original\": \"Potreste darci una breve introduzione?\", \"translated\": \"您能为我们做个介绍吗？\"}, {\"original\": \"Queste opere sono davvero squisite.\", \"translated\": \"这些作品真是精美绝伦。\"}, {\"original\": \"Dove si trova il negozio dei souvenir?\", \"translated\": \"纪念品商店在哪儿？\"}]', 11, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare nei bar?\", \"Fantastico! Ecco 10 frasi comuni relative ai bar, insieme alle rispettive traduzioni in cinese:\"]', '[\"Ordinare un caffè\", \"Riposare\", \"Socializzare\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il menù, bevande ghiacciate o calde, altri prodotti? Si senta libero di chiedere.\", \"Descriva la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Prenderò un caffè latte, per favore.\", \"translated\": \"请给我一杯拿铁。\"}, {\"original\": \"Avete il Wi-Fi?\", \"translated\": \"你们有无线网络吗？\"}, {\"original\": \"Potrei vedere il menu, per favore?\", \"translated\": \"请给我看一下菜单，谢谢。\"}, {\"original\": \"Sono ammesse le ricariche?\", \"translated\": \"可以续杯吗？\"}, {\"original\": \"Il mio caffè è pronto?\", \"translated\": \"我的咖啡好了吗？\"}, {\"original\": \"Per quanto tempo posso stare seduto qui?\", \"translated\": \"我可以在这里坐多久？\"}, {\"original\": \"Potrebbe fare una foto per noi?\", \"translated\": \"能帮我们拍张照片吗？\"}, {\"original\": \"Dov\'è il bagno?\", \"translated\": \"洗手间在哪里？\"}, {\"original\": \"Il conto, per favore. Grazie.\", \"translated\": \"请结账，谢谢。\"}, {\"original\": \"Ha davvero un ottimo sapore.\", \"translated\": \"味道 really 好。\"}]', 12, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare al ristorante?\", \"Fantastico! Ecco 10 frasi comuni relative al ristorante, insieme alle traduzioni in turco:\"]', '[\"Ristorazione\", \"Ordinazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio ordinare bevande, presentare un reclamo o chiedere informazioni sugli ingredienti? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\", \"translated\": \"Affedersiniz, yemeğimiz kaç dakika daha sürecektir?\"}, {\"original\": \"Un tavolo per due, per favore.\", \"translated\": \"Lütfen iki kişilik bir masa.\"}, {\"original\": \"Potremmo vedere il menù, per favore?\", \"translated\": \"Lütfen menüyü görebilir miyiz?\"}, {\"original\": \"Avete dei piatti tipici da consigliarci?\", \"translated\": \"Önerdiğiniz özel yemekleriniz var mı?\"}, {\"original\": \"Vorrei ordinare questo e quest’altro.\", \"translated\": \"Bunu ve bunu sipariş etmek istiyorum.\"}, {\"original\": \"Un bicchiere d’acqua, per favore. Grazie.\", \"translated\": \"Lütfen bir bardak su. Teşekkürler.\"}, {\"original\": \"Il conto, per favore.\", \"translated\": \"Hesabı lütfen.\"}, {\"original\": \"Posso pagare con carta di credito?\", \"translated\": \"Kredi kartıyla ödeyebilir miyim?\"}, {\"original\": \"Potrebbe impacchettare questo da portare via, per favore?\", \"translated\": \"Lütfen bunu götürmek için paketleyebilir misiniz?\"}, {\"original\": \"Il cibo era delizioso, grazie.\", \"translated\": \"Yiyecekler çok lezzetliydi, teşekkür ederiz.\"}]', 1, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un hotel?\", \"Fantastico! Ecco 10 frasi comuni relative all\'hotel, insieme alle rispettive traduzioni in turco:\"]', '[\"Check-in\", \"Check-out\", \"Servizio in camera\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio la posizione della camera, altri servizi offerti dall\'hotel o il check-out? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Salve, ho una prenotazione, ecco il mio passaporto.\", \"translated\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\"}, {\"original\": \"Avete camere disponibili?\", \"translated\": \"Boş odanız var mı?\"}, {\"original\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\", \"translated\": \"Affedersiniz, otelde bir spor salonu veya çamaşırhane var mı?\"}, {\"original\": \"A che ora inizia la colazione?\", \"translated\": \"Kahvaltı saat kaçta başlıyor?\"}, {\"original\": \"Potrei avere la chiave della mia stanza, per favore?\", \"translated\": \"Lütfen bir oda anahtarı verebilir misiniz?\"}, {\"original\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\", \"translated\": \"Bagajımı odaya taşımama yardımcı olur musunuz?\"}, {\"original\": \"Come posso chiamare il servizio in camera?\", \"translated\": \"Oda servisini nasıl arayabilirim?\"}, {\"original\": \"A che ora è il check-out?\", \"translated\": \"Çıkış saati kaçta?\"}, {\"original\": \"Potrebbe rilasciarmi una ricevuta/fattura?\", \"translated\": \"Bana bir makbuz/fatura yazabilir misiniz?\"}, {\"original\": \"Posso lasciare qui i miei bagagli?\", \"translated\": \"Bagajımı burada bırakabilir miyim?\"}]', 2, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in aeroporto?\", \"Fantastico! Ecco 10 frasi comuni relative all\'aeroporto, insieme alle traduzioni in turco:\"]', '[\"Check-in\", \"Imbarco\", \"Controllo bagagli\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio il check-in, il ritiro bagagli o il servizio di noleggio auto? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dov\'è il banco del check-in?\", \"translated\": \"Giriş masası nerede?\"}, {\"original\": \"Vorrei un posto vicino al finestrino, per favore.\", \"translated\": \"Lütfen bir pencere koltuğu istiyorum.\"}, {\"original\": \"Questo volo è in ritardo?\", \"translated\": \"Bu uçuş gecikmiş mi?\"}, {\"original\": \"Devo registrare questo bagaglio.\", \"translated\": \"Bu bagajı kontrol ettirmem gerekiyor.\"}, {\"original\": \"Dov\'è l\'ingresso per l\'imbarco?\", \"translated\": \"İniş kapısı nerede?\"}, {\"original\": \"L\'aeroplano sta per decollare.\", \"translated\": \"Uçak hemen kalkacak.\"}, {\"original\": \"Devo estrarre il mio laptop e la power bank?\", \"translated\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\"}, {\"original\": \"Dov\'è il negozio duty-free?\", \"translated\": \"Vergisiz alışveriş mağazası nerede?\"}, {\"original\": \"Non riesco a trovare la mia valigia.\", \"translated\": \"Bavulumu bulamıyorum.\"}, {\"original\": \"Offrite un servizio di sedia a rotelle?\", \"translated\": \"Tekerlekli sandalye hizmetiniz var mı?\"}]', 3, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei trasporti pubblici?\", \"Fantastico! Ecco 10 frasi comuni relative ai trasporti pubblici, insieme alle rispettive traduzioni in turco:\"]', '[\"Prendere l\'autobus o la metropolitana\", \"Acquistare biglietti\", \"Effettuare un trasferimento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere dove si trova la fermata dell’autobus, il prezzo del biglietto o come scendere? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Questo autobus va al capolinea?\", \"translated\": \"Bu otobüs terminala gidiyor mu?\"}, {\"original\": \"Qual è la prossima fermata?\", \"translated\": \"Bir sonraki durak neresi?\"}, {\"original\": \"Dove posso comprare un biglietto?\", \"translated\": \"Bilet nereden alabilirim?\"}, {\"original\": \"Un biglietto per XX, per favore.\", \"translated\": \"XX\'e bir bilet, lütfen.\"}, {\"original\": \"Devo cambiare mezzo?\", \"translated\": \"Aktarma yapmam gerekiyor mu?\"}, {\"original\": \"Tra quanto arriva il prossimo treno della metropolitana?\", \"translated\": \"Bir sonraki metro trenine ne kadar kaldı?\"}, {\"original\": \"Scusi, mi lasci passare, per favore.\", \"translated\": \"Üzgünüm, geçebilir miyim?\"}, {\"original\": \"Questo posto è occupato?\", \"translated\": \"Bu koltuk dolu mu?\"}, {\"original\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\", \"translated\": \"Üzgünüm, XX\'e gitmek için 2. Hat\'a nerede aktarım yapabilirim?\"}, {\"original\": \"Come posso arrivare a XX?\", \"translated\": \"XX\'e nasıl giderim?\"}]', 4, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nelle attrazioni turistiche?\", \"Fantastico! Ecco 10 frasi comuni relative alle attrazioni turistiche, insieme alle traduzioni in turco:\"]', '[\"Visita turistica\", \"Scattare foto\", \"Acquistare biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il prezzo dei biglietti, trovare un parcheggio o richiedere un servizio di guida turistica? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"Sono disponibili biglietti per studenti?\", \"translated\": \"Öğrenci biletleri mevcut mu?\"}, {\"original\": \"A che ora apre la attrazione?\", \"translated\": \"Bu yer saat kaçta açılıyor?\"}, {\"original\": \"Quali sono le cose divertenti da fare qui?\", \"translated\": \"Burada yapılacak eğlenceli şeyler neler?\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"Bizi birlikte çeker misiniz?\"}, {\"original\": \"Dove si trova l\'autobus per i tour turistici?\", \"translated\": \"Sightseeing otobüsü nerede?\"}, {\"original\": \"Dove si trova il bagno?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"Dove si trova il punto migliore per osservare?\", \"translated\": \"En iyi manzara noktası nerede?\"}, {\"original\": \"Il panorama qui è bellissimo.\", \"translated\": \"Buradaki manzara çok güzel.\"}, {\"original\": \"È disponibile un tour guidato?\", \"translated\": \"Rehberli tur mevcut mu?\"}]', 5, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare per un taxi o un servizio taxi?\", \"Fantastico! Ecco 10 frasi comuni relative al taxi o a un servizio taxi, insieme alle rispettive traduzioni in turco:\"]', '[\"Prendere un taxi\", \"Indicare la destinazione\", \"Pagamento\"]', 'it', '[\"Per ora, cosa vorrebbe fare principalmente in questo momento? Ad esempio chiedere la destinazione, il costo o una ricevuta: si senta libero di chiedere.\", \"La preghiamo di descrivere mentalmente la situazione.\"]', NULL, '[{\"original\": \"Dove posso prendere un taxi?\", \"translated\": \"Bir taksi nerede bulabilirim?\"}, {\"original\": \"Mi porti a questo indirizzo, per favore.\", \"translated\": \"Lütfen beni bu adrese götürür müsünüz?\"}, {\"original\": \"Quanto costerà all\'incirca?\", \"translated\": \"Yaklaşık olarak ne kadar tutar?\"}, {\"original\": \"Potrebbe usare il tassametro, per favore?\", \"translated\": \"Lütfen taksimetre kullanır mısınız?\"}, {\"original\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\", \"translated\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\"}, {\"original\": \"Si fermi qui, per favore.\", \"translated\": \"Lütfen burada durur musunuz?\"}, {\"original\": \"Accetta carte di credito o pagamenti mobili?\", \"translated\": \"Kart veya mobil ödeme kabul ediyor musunuz?\"}, {\"original\": \"Potrei avere lo scontrino, per favore?\", \"translated\": \"Lütfen bir fiş verebilir misiniz?\"}, {\"original\": \"Grazie, autista.\", \"translated\": \"Teşekkür ederim, şoför bey.\"}, {\"original\": \"Quanto manca ancora?\", \"translated\": \"Kaç dakika daha var?\"}]', 6, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in farmacia?\", \"Fantastico! Ecco 10 frasi comuni relative alla farmacia, insieme alle rispettive traduzioni in turco:\"]', '[\"Acquisto di Farmaci\", \"Consultazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere indicazioni sull’assunzione di un farmaco, frasi relative all’utilizzo dell’assicurazione sanitaria o alla durata della terapia? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Ha dei farmaci per il raffreddore?\", \"translated\": \"Soğuk algınlığı ilacı var mı?\"}, {\"original\": \"Come devo assumere questo farmaco?\", \"translated\": \"Bu ilacı nasıl kullanmalıyım?\"}, {\"original\": \"Ha degli antidolorifici?\", \"translated\": \"Ağrı kesici ilaçlarınız var mı?\"}, {\"original\": \"È incluso un foglietto illustrativo?\", \"translated\": \"Kullanım kılavuzu var mı?\"}, {\"original\": \"Questo farmaco ha effetti collaterali?\", \"translated\": \"Bu ilacın yan etkileri var mı?\"}, {\"original\": \"Posso utilizzare la mia tessera sanitaria?\", \"translated\": \"Tıbbi sigorta kartımı kullanabilir miyim?\"}, {\"original\": \"Potrei avere una confezione di cerotti, per favore?\", \"translated\": \"Lütfen bir kutu yara bandı verebilir misiniz?\"}, {\"original\": \"Ha dei farmaci antipiretici?\", \"translated\": \"Ateş düşürücü ilaçlarınız var mı?\"}, {\"original\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\", \"translated\": \"Hafif bir çizik aldım. Antiseptik ve yara bandı var mı?\"}, {\"original\": \"A che ora chiude?\", \"translated\": \"Kaçta kapanıyorsunuz?\"}]', 7, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei servizi di emergenza?\", \"Fantastico! Ecco 10 frasi comuni relative ai servizi di emergenza, insieme alle rispettive traduzioni in turco:\"]', '[\"Chiamare la polizia\", \"Pronto soccorso\", \"Chiedere aiuto\"]', 'it', '[\"Per il momento, ha in mente una situazione di emergenza specifica, ad esempio incendio, persona ferita che necessita di aiuto, chiamata d\'emergenza? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\", \"translated\": \"Lütfen bana bir ambulans çağırmama yardımcı olun.\"}, {\"original\": \"Dov\'è l\'ospedale?\", \"translated\": \"Hastane nerede?\"}, {\"original\": \"Qualcuno è ferito.\", \"translated\": \"Birisi yaralandı.\"}, {\"original\": \"Per favore, mi aiuti.\", \"translated\": \"Lütfen bana yardımcı olun.\"}, {\"original\": \"Dov\'è la stazione di polizia?\", \"translated\": \"Polis karakolu nerede?\"}, {\"original\": \"Ho perso i miei oggetti.\", \"translated\": \"Eşyalarımı kaybettim.\"}, {\"original\": \"Qual è il numero del corpo dei vigili del fuoco?\", \"translated\": \"İtfaiye numarası nedir?\"}, {\"original\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\", \"translated\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\"}, {\"original\": \"C\'è un\'uscita di emergenza?\", \"translated\": \"Acil çıkış var mı?\"}, {\"original\": \"Qualcuno è svenuto.\", \"translated\": \"Birisi bayıldı.\"}]', 8, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in spiaggia o in piscina?\", \"Fantastico! Ecco 10 frasi comuni relative alla spiaggia o alla piscina, insieme alle rispettive traduzioni in turco:\"]', '[\"Nuoto\", \"Abbronzatura\", \"Sport sulla spiaggia\"]', 'it', '[\"Per il momento, potrebbe gentilmente indicarmi il contesto dell\'evento o della festa locale a cui parteciperà, ad esempio una festa culturale, una festa del cibo o una festa musicale? La prego di specificare il contesto.\", \"La prego di indicare le attività a cui parteciperà.\"]', '[\"Ha in mente una situazione specifica? Non esiti a chiedere.\", \"La prego di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Guarda! Le onde laggiù sono davvero grandi.\", \"translated\": \"Bakın! Oradaki dalgalar gerçekten büyük.\"}, {\"original\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\", \"translated\": \"Güneş koruyucu sürmeyi unutmayın, buradaki UV ışınları çok güçlü.\"}, {\"original\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\", \"translated\": \"Bu plajdaki kum çok ince, pamuk üzerinde yürüyormuş gibi hissediliyor.\"}, {\"original\": \"Che ne dici di giocare a pallavolo in spiaggia?\", \"translated\": \"Plajda voleybol oynamak nasıl olur?\"}, {\"original\": \"Le barche a vela in lontananza sembrano bellissime.\", \"translated\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\"}, {\"original\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\", \"translated\": \"Buradaki su çok berrak, balıkları bile görebiliyorsunuz.\"}, {\"original\": \"Andiamo a cercare delle conchiglie.\", \"translated\": \"Hadi biraz deniz kabuğu arayalım.\"}, {\"original\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\", \"translated\": \"Gün batımında plajda yürüyüş yapmak kesinlikle çok romantik olmalı.\"}, {\"original\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\", \"translated\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\"}, {\"original\": \"La marea sta salendo, dirigiamoci verso la riva.\", \"translated\": \"Deniz yükseliyor, kıyıya doğru gidelim.\"}]', 9, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare durante eventi e festival locali?\", \"Fantastico! Ecco 10 frasi comuni relative a eventi e festival locali, insieme alle rispettive traduzioni in turco:\"]', '[\"Partecipare a eventi\", \"Celebrare festival\", \"Apprendere la cultura\"]', 'it', '[\"Per ora, potrebbe gentilmente indicarmi il contesto dell’evento o del festival locale a cui parteciperà, ad esempio Halloween, un concerto, una festa tra amici o qualcos’altro? La preghiamo di specificare il contesto.\", \"La preghiamo di descrivere le attività che ha in mente.\"]', '[\"Ha in mente una situazione specifica? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Ci sono eventi oggi?\", \"translated\": \"Bugün herhangi bir etkinlik var mı?\"}, {\"original\": \"C\'è qualcosa di speciale in questo festival?\", \"translated\": \"Bu festivalle ilgili özel bir şey var mı?\"}, {\"original\": \"Dove si tiene la celebrazione?\", \"translated\": \"Kutlama nerede yapılacak?\"}, {\"original\": \"Come posso acquistare i biglietti?\", \"translated\": \"Biletleri nasıl alabilirim?\"}, {\"original\": \"A che ora inizia lo spettacolo?\", \"translated\": \"Gösteri saat kaçta başlıyor?\"}, {\"original\": \"Quali sono i cibi tradizionali?\", \"translated\": \"Hangi geleneksel yiyecekler var?\"}, {\"original\": \"Qui è davvero animato.\", \"translated\": \"Burada gerçekten hareketli bir atmosfer var.\"}, {\"original\": \"Ci sono attività popolari?\", \"translated\": \"Halk oyunları gibi etkinlikler var mı?\"}, {\"original\": \"Buone feste!\", \"translated\": \"Mutlu tatiller!\"}, {\"original\": \"A che ora termina l\'evento?\", \"translated\": \"Etkinlik saat kaçta bitiyor?\"}]', 10, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un museo o in una galleria d\'arte?\", \"Fantastico! Ecco 10 frasi comuni relative a un museo o a una galleria d\'arte, insieme alle rispettive traduzioni in turco:\"]', '[\"Visita\", \"Tour guidato\", \"Acquisto di biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere un manuale introduttivo, frasi relative a una mappa, frasi per commentare un\'esposizione? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"Avete guide audio?\", \"translated\": \"Sesli rehberleriniz var mı?\"}, {\"original\": \"Chi ha creato quest\'opera d\'arte?\", \"translated\": \"Bu eseri kim yaratmış?\"}, {\"original\": \"Dove si trova il pezzo più prezioso del museo?\", \"translated\": \"Müzenin en değerli eseri nerede?\"}, {\"original\": \"È consentito fare fotografie?\", \"translated\": \"Fotoğraf çekmeye izin veriliyor mu?\"}, {\"original\": \"Ci sono mostre speciali in corso?\", \"translated\": \"Burada özel sergiler var mı?\"}, {\"original\": \"Quanto tempo richiede la visita?\", \"translated\": \"Ziyaret kaç dakika sürüyor?\"}, {\"original\": \"Potreste darci una breve introduzione?\", \"translated\": \"Bize bir tanıtım yapabilir misiniz?\"}, {\"original\": \"Queste opere sono davvero squisite.\", \"translated\": \"Bu eserler gerçekten çok zarif.\"}, {\"original\": \"Dove si trova il negozio di souvenir?\", \"translated\": \"Hediyelik eşya dükkanı nerede?\"}]', 11, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare nei bar?\", \"Fantastico! Ecco 10 frasi comuni relative ai bar, insieme alle rispettive traduzioni in turco:\"]', '[\"Ordinare un caffè\", \"Riposare\", \"Socializzare\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il menu, bevande ghiacciate o calde, altri prodotti? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Prenderò un caffè latte, per favore.\", \"translated\": \"Lütfen bir latte getirir misiniz?\"}, {\"original\": \"Avete il Wi-Fi?\", \"translated\": \"Wi-Fi var mı?\"}, {\"original\": \"Potrei vedere il menu, per favore?\", \"translated\": \"Menüyü görebilir miyim, lütfen?\"}, {\"original\": \"Sono ammesse le ricariche?\", \"translated\": \"İkinci dolum yapılabilir mi?\"}, {\"original\": \"Il mio caffè è pronto?\", \"translated\": \"Kahvaltım hazır mı?\"}, {\"original\": \"Per quanto tempo posso restare seduto qui?\", \"translated\": \"Burada ne kadar oturabilirim?\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"Bizi birlikte fotoğraflar mısınız?\"}, {\"original\": \"Dov\'è il bagno?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"Il conto, per favore. Grazie.\", \"translated\": \"Hesap lütfen. Teşekkür ederim.\"}, {\"original\": \"Ha davvero un ottimo sapore.\", \"translated\": \"Gerçekten çok lezzetli.\"}]', 12, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare al ristorante?\", \"Fantastico! Ecco 10 frasi comuni relative al ristorante, insieme alle rispettive traduzioni in giapponese:\"]', '[\"Ristorazione\", \"Ordinazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio ordinare bevande, presentare un reclamo o chiedere informazioni sugli ingredienti? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\", \"translated\": \"すみません、料理はあとどのくらいで来ますか？\"}, {\"original\": \"Un tavolo per due, per favore.\", \"translated\": \"二人用のテーブルをお願いします。\"}, {\"original\": \"Potremmo vedere il menù, per favore?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"Avete dei piatti speciali da consigliare?\", \"translated\": \"おすすめの自慢料理はありますか？\"}, {\"original\": \"Vorrei ordinare questo e quest’altro.\", \"translated\": \"これを注文したいのですが、あとこれもお願いします。\"}, {\"original\": \"Un bicchiere d’acqua, per favore. Grazie.\", \"translated\": \"水を一杯お願いします。ありがとうございます。\"}, {\"original\": \"Il conto, per favore.\", \"translated\": \"お会計をお願いします。\"}, {\"original\": \"Posso pagare con carta di credito?\", \"translated\": \"クレジットカードで支払えますか？\"}, {\"original\": \"Potrebbe impacchettare questo da portare via, per favore?\", \"translated\": \"これを持ち帰り用に包んでいただけますか？\"}, {\"original\": \"Il cibo era delizioso, grazie.\", \"translated\": \"料理がとても美味しかったです。ありがとうございました。\"}]', 1, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un hotel?\", \"Fantastico! Ecco 10 frasi comuni relative all\'hotel, insieme alle rispettive traduzioni in giapponese:\"]', '[\"Check-in\", \"Check-out\", \"Servizio in camera\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio la posizione della camera, altri servizi offerti dall\'hotel o il check-out? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Salve, ho una prenotazione. Ecco il mio passaporto.\", \"translated\": \"こんにちは、予約をしております。こちらが私のパスポートです。\"}, {\"original\": \"Avete camere disponibili?\", \"translated\": \"空室はありますか？\"}, {\"original\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\", \"translated\": \"すみませんが、ホテルにはジムやランドリールームはありますか？\"}, {\"original\": \"A che ora inizia la colazione?\", \"translated\": \"朝食の開始時間は何時ですか？\"}, {\"original\": \"Potrei avere la chiave della mia camera, per favore?\", \"translated\": \"部屋の鍵をいただけますか？\"}, {\"original\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\", \"translated\": \"荷物を部屋まで運んでいただけますか？\"}, {\"original\": \"Come posso chiamare il servizio in camera?\", \"translated\": \"ルームサービスの呼び出し方はどうすればいいですか？\"}, {\"original\": \"A che ora è il check-out?\", \"translated\": \"チェックアウトの時間は何時ですか？\"}, {\"original\": \"Potrebbe rilasciarmi una ricevuta/fattura?\", \"translated\": \"領収書／請求書を書いていただけますか？\"}, {\"original\": \"Posso lasciare qui i miei bagagli?\", \"translated\": \"荷物をここに預けても大丈夫ですか？\"}]', 2, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in aeroporto?\", \"Fantastico! Ecco 10 frasi comuni relative all\'aeroporto, insieme alle rispettive traduzioni in giapponese:\"]', '[\"Check-in\", \"Imbarco\", \"Controllo bagagli\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio il check-in, il ritiro bagagli o il servizio di noleggio auto? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dov\'è il banco del check-in?\", \"translated\": \"チェックインカウンターはどこですか？\"}, {\"original\": \"Vorrei un posto vicino al finestrino, per favore.\", \"translated\": \"窓側の席をお願いします。\"}, {\"original\": \"Questo volo è in ritardo?\", \"translated\": \"この便は遅れていますか？\"}, {\"original\": \"Devo registrare questo bagaglio.\", \"translated\": \"この荷物を預けたいのですが。\"}, {\"original\": \"Dov\'è l\'ingresso per l\'imbarco?\", \"translated\": \"搭乗口はどこですか？\"}, {\"original\": \"L\'aeroplano sta per decollare.\", \"translated\": \"飛行機が今から離陸します。\"}, {\"original\": \"Devo estrarre il mio laptop e la power bank?\", \"translated\": \"ノートパソコンとモバイルバッテリーを取り出さなければなりませんか？\"}, {\"original\": \"Dov\'è il negozio duty-free?\", \"translated\": \"免税店はどこですか？\"}, {\"original\": \"Non riesco a trovare la mia valigia.\", \"translated\": \"私のスーツケースが見つかりません。\"}, {\"original\": \"Offrite un servizio di sedia a rotelle?\", \"translated\": \"車椅子サービスはありますか？\"}]', 3, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei trasporti pubblici?\", \"Fantastico! Ecco 10 frasi comuni relative ai trasporti pubblici, insieme alle rispettive traduzioni in giapponese:\"]', '[\"Prendere l\'autobus o la metropolitana\", \"Acquistare biglietti\", \"Effettuare un trasferimento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere dove si trova la fermata dell’autobus, il prezzo del biglietto o come scendere? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Questo autobus va al capolinea?\", \"translated\": \"このバスは終点まで行きますか？\"}, {\"original\": \"Qual è la prossima fermata?\", \"translated\": \"次の停留所はどこですか？\"}, {\"original\": \"Dove posso comprare un biglietto?\", \"translated\": \"切符はどこで買えますか？\"}, {\"original\": \"Un biglietto per XX, per favore.\", \"translated\": \"XX行きの切符を一枚お願いします。\"}, {\"original\": \"Devo cambiare mezzo?\", \"translated\": \"乗り換えが必要ですか？\"}, {\"original\": \"Quanto manca al prossimo treno della metropolitana?\", \"translated\": \"次の地下鉄の列車まであと何分ですか？\"}, {\"original\": \"Scusi, mi lasci passare, per favore.\", \"translated\": \"すみません、通らせてください。\"}, {\"original\": \"Questo posto è occupato?\", \"translated\": \"この席は空いていますか？\"}, {\"original\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\", \"translated\": \"すみません、XXへ行くには２号線にどこで乗り換えればいいですか？\"}, {\"original\": \"Come arrivo a XX?\", \"translated\": \"XXへはどう行けばいいですか？\"}]', 4, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nelle attrazioni turistiche?\", \"Fantastico! Ecco 10 frasi comuni relative alle attrazioni turistiche, insieme alle traduzioni in giapponese:\"]', '[\"Visita turistica\", \"Scattare foto\", \"Acquistare biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il prezzo dei biglietti, trovare un parcheggio o richiedere un servizio di guida turistica? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"Sono disponibili biglietti per studenti?\", \"translated\": \"学生割引のチケットはありますか？\"}, {\"original\": \"A che ora apre la attrazione?\", \"translated\": \"観光スポットの開園時間は何時ですか？\"}, {\"original\": \"Quali sono le cose divertenti da fare qui?\", \"translated\": \"ここではどんな楽しいことが体験できますか？\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"Dove si trova l\'autobus per i tour turistici?\", \"translated\": \"観光バスの乗り場はどこですか？\"}, {\"original\": \"Dove si trova il bagno?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"Dove si trova il punto migliore per osservare la vista?\", \"translated\": \"一番良い展望スポットはどこですか？\"}, {\"original\": \"Il paesaggio qui è bellissimo.\", \"translated\": \"ここからの景色はとても美しいです。\"}, {\"original\": \"È disponibile un tour guidato?\", \"translated\": \"ガイド付きツアーはありますか？\"}]', 5, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare per un taxi o un servizio taxi?\", \"Fantastico! Ecco 10 frasi comuni relative al taxi o a un servizio taxi, insieme alle rispettive traduzioni in giapponese:\"]', '[\"Prendere un taxi\", \"Indicare la destinazione\", \"Pagamento\"]', 'it', '[\"Per ora, cosa vorrebbe fare principalmente in questo momento? Ad esempio chiedere la destinazione, il costo o una ricevuta: non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dove posso prendere un taxi?\", \"translated\": \"タクシーはどこで乗れますか？\"}, {\"original\": \"Mi porti a questo indirizzo, per favore.\", \"translated\": \"この住所までお願いします。\"}, {\"original\": \"Quanto costerà all\'incirca?\", \"translated\": \"だいたいいくらぐらいになりますか？\"}, {\"original\": \"Potrebbe usare il tassametro, per favore?\", \"translated\": \"メーターを使っていただけますか？\"}, {\"original\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\", \"translated\": \"急いでいるので、もう少し速く運転していただけますか？\"}, {\"original\": \"Si fermi qui, per favore.\", \"translated\": \"ここで止めてください。\"}, {\"original\": \"Accetta carte di credito o pagamenti mobili?\", \"translated\": \"カードやモバイル決済は使えますか？\"}, {\"original\": \"Potrei avere lo scontrino, per favore?\", \"translated\": \"領収書をいただけますか？\"}, {\"original\": \"Grazie, autista.\", \"translated\": \"ありがとうございました、運転手さん。\"}, {\"original\": \"Quanto manca ancora?\", \"translated\": \"あとどれくらいですか？\"}]', 6, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in farmacia?\", \"Fantastico! Ecco 10 frasi comuni relative alla farmacia, insieme alle rispettive traduzioni in giapponese:\"]', '[\"Acquisto di Farmaci\", \"Consultazione\", \"Pagamento\"]', 'it', '[\"Per il momento, ha in mente una situazione specifica, ad esempio chiedere istruzioni sull’assunzione di un farmaco, frasi relative all’utilizzo dell’assicurazione sanitaria o alla durata della terapia? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Ha dei farmaci per il raffreddore?\", \"translated\": \"風邪薬はありますか？\"}, {\"original\": \"Come devo assumere questo farmaco?\", \"translated\": \"この薬の飲み方はどうすればいいですか？\"}, {\"original\": \"Ha degli antidolorifici?\", \"translated\": \"鎮痛剤はありますか？\"}, {\"original\": \"È incluso un foglietto illustrativo?\", \"translated\": \"説明書は付いていますか？\"}, {\"original\": \"Questo farmaco ha effetti collaterali?\", \"translated\": \"この薬には副作用がありますか？\"}, {\"original\": \"Posso utilizzare la mia tessera sanitaria?\", \"translated\": \"医療保険証を使っても大丈夫ですか？\"}, {\"original\": \"Potrei avere una confezione di cerotti, per favore?\", \"translated\": \"バンドエイドを一箱お願いできますか？\"}, {\"original\": \"Ha dei farmaci antipiretici?\", \"translated\": \"解熱剤はありますか？\"}, {\"original\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\", \"translated\": \"ちょっと擦り傷をしました。消毒液とバンドエイドはありますか？\"}, {\"original\": \"A che ora chiude?\", \"translated\": \"何時まで営業していますか？\"}]', 7, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei servizi di emergenza?\", \"Fantastico! Ecco 10 frasi comuni relative ai servizi di emergenza, insieme alle rispettive traduzioni in giapponese:\"]', '[\"Chiamare la polizia\", \"Pronto soccorso\", \"Chiedere aiuto\"]', 'it', '[\"Per ora, ha in mente una situazione di emergenza specifica, ad esempio un incendio, una persona ferita che necessita di aiuto o una chiamata d\'emergenza? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\", \"translated\": \"救急車を呼んでください。\"}, {\"original\": \"Dov\'è l\'ospedale?\", \"translated\": \"病院はどこですか？\"}, {\"original\": \"Qualcuno è ferito.\", \"translated\": \"誰かが怪我をしました。\"}, {\"original\": \"Per favore, mi aiuti.\", \"translated\": \"助けてください。\"}, {\"original\": \"Dov\'è la stazione di polizia?\", \"translated\": \"警察署はどこですか？\"}, {\"original\": \"Ho perso i miei effetti personali.\", \"translated\": \"荷物をなくしました。\"}, {\"original\": \"Qual è il numero dei vigili del fuoco?\", \"translated\": \"消防署の電話番号は何番ですか？\"}, {\"original\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\", \"translated\": \"パスポートを紛失しました。近くの警察署はどこですか？\"}, {\"original\": \"C\'è un\'uscita di emergenza?\", \"translated\": \"非常口はありますか？\"}, {\"original\": \"Qualcuno è svenuto.\", \"translated\": \"誰かが気を失いました。\"}]', 8, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in spiaggia o in piscina?\", \"Fantastico! Ecco 10 frasi comuni relative alla spiaggia o alla piscina, insieme alle rispettive traduzioni in giapponese:\"]', '[\"Nuoto\", \"Abbronzatura\", \"Sport sulla spiaggia\"]', 'it', '[\"Per ora, potrebbe indicarmi il contesto dell\'evento o della festa locale a cui parteciperà, ad esempio una festa culturale, una festa del cibo o una festa musicale? La prego di specificare il contesto.\", \"La prego di indicare le attività a cui parteciperà.\"]', '[\"Ha in mente una situazione specifica? Non esiti a chiedere.\", \"La prego di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Guarda! Le onde laggiù sono davvero grandi.\", \"translated\": \"見て！あそこに見える波が本当に大きいよ。\"}, {\"original\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\", \"translated\": \"日焼け止めを塗ることを忘れないでね。ここでの紫外線はとても強いから。\"}, {\"original\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\", \"translated\": \"このビーチの砂はとても細かくて、綿の上を歩いているような感じがする。\"}, {\"original\": \"Che ne dici di giocare a pallavolo in spiaggia?\", \"translated\": \"ビーチでバレーボールをしようか？\"}, {\"original\": \"Le barche a vela in lontananza sembrano bellissime.\", \"translated\": \"遠くに見えるヨットがとても美しいね。\"}, {\"original\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\", \"translated\": \"ここでの水はとても透明度が高く、魚まで見えてしまう。\"}, {\"original\": \"Andiamo a cercare delle conchiglie.\", \"translated\": \"一緒に貝殻を探しに行こう。\"}, {\"original\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\", \"translated\": \"夕日が沈む頃のビーチ散歩はきっととてもロマンチックだろうね。\"}, {\"original\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\", \"translated\": \"ここでは海産物がとても新鮮だと聞いたから、ぜひ食べてみよう。\"}, {\"original\": \"La marea sta salendo, dirigiamoci verso la riva.\", \"translated\": \"潮が満ちてきているから、そろそろ岸へ向かおう。\"}]', 9, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare durante eventi e festival locali?\", \"Fantastico! Ecco 10 frasi comuni relative a eventi e festival locali, insieme alle rispettive traduzioni in giapponese:\"]', '[\"Partecipare a eventi\", \"Celebrare festival\", \"Apprendere la cultura\"]', 'it', '[\"Per ora, potrebbe gentilmente indicarmi il contesto dell\'evento o del festival locale a cui parteciperà, ad esempio Halloween, un concerto, una festa tra amici o qualcos\'altro? La prego di specificare il contesto.\", \"La prego di descrivere le attività che ha in mente.\"]', '[\"Ha in mente una situazione specifica? Si senta libero di chiedere.\", \"La prego di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Ci sono eventi oggi?\", \"translated\": \"今日、何かイベントはありますか？\"}, {\"original\": \"C\'è qualcosa di speciale in questo festival?\", \"translated\": \"この祭りには何か特別なことはありますか？\"}, {\"original\": \"Dove si tiene la celebrazione?\", \"translated\": \"お祝いはどこで行われますか？\"}, {\"original\": \"Come posso acquistare i biglietti?\", \"translated\": \"チケットはどこで購入できますか？\"}, {\"original\": \"A che ora inizia lo spettacolo?\", \"translated\": \"パフォーマンスは何時から始まりますか？\"}, {\"original\": \"Quali sono i cibi tradizionali?\", \"translated\": \"どんな伝統的な食べ物がありますか？\"}, {\"original\": \"Qui è davvero animato.\", \"translated\": \"ここは本当ににぎやかですね。\"}, {\"original\": \"Ci sono attività folkloristiche?\", \"translated\": \"民俗行事はありますか？\"}, {\"original\": \"Buone feste!\", \"translated\": \"楽しい休日を！\"}, {\"original\": \"A che ora finisce l\'evento?\", \"translated\": \"イベントは何時までですか？\"}]', 10, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un museo o in una galleria d\'arte?\", \"Fantastico! Ecco 10 frasi comuni relative a un museo o a una galleria d\'arte, insieme alle rispettive traduzioni in giapponese:\"]', '[\"Visita\", \"Tour guidato\", \"Acquisto di biglietti\"]', 'it', '[\"Per il momento, ha in mente una situazione specifica, ad esempio chiedere un manuale introduttivo, frasi relative a una mappa, frasi per commentare un\'esposizione? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"入館料はいくらですか？\"}, {\"original\": \"Avete guide audio?\", \"translated\": \"オーディオガイドはありますか？\"}, {\"original\": \"Chi ha creato quest\'opera d\'arte?\", \"translated\": \"この作品は誰が制作したものですか？\"}, {\"original\": \"Dove si trova il pezzo più prezioso del museo?\", \"translated\": \"美術館の最も貴重な作品はどこにありますか？\"}, {\"original\": \"È consentito fare fotografie?\", \"translated\": \"写真撮影は許可されていますか？\"}, {\"original\": \"Ci sono delle mostre speciali qui?\", \"translated\": \"ここには特別展はありますか？\"}, {\"original\": \"Quanto tempo richiede la visita?\", \"translated\": \"見学にはどのくらいの時間がかかりますか？\"}, {\"original\": \"Potreste darci una breve introduzione?\", \"translated\": \"簡単にご紹介いただけますか？\"}, {\"original\": \"Queste opere sono davvero squisite.\", \"translated\": \"これらの作品は本当に素晴らしいです。\"}, {\"original\": \"Dove si trova il negozio dei souvenir?\", \"translated\": \"お土産ショップはどこにありますか？\"}]', 11, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare nei caffè?\", \"Fantastico! Ecco 10 frasi comuni relative ai caffè, insieme alle rispettive traduzioni in giapponese:\"]', '[\"Ordinare un caffè\", \"Riposare\", \"Socializzare\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il menu, bevande fredde o calde, altri prodotti? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Prenderò un caffè latte, per favore.\", \"translated\": \"ラテを一杯お願いします。\"}, {\"original\": \"Avete il Wi-Fi?\", \"translated\": \"Wi-Fiはありますか？\"}, {\"original\": \"Potrei vedere il menu, per favore?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"Sono ammessi i rabbocchi?\", \"translated\": \"追加注文はできますか？\"}, {\"original\": \"Il mio caffè è pronto?\", \"translated\": \"私のコーヒーはできましたか？\"}, {\"original\": \"Per quanto tempo posso stare seduto qui?\", \"translated\": \"ここにどのくらい座っていられますか？\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"Dov\'è il bagno?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"Il conto, per favore. Grazie.\", \"translated\": \"お会計をお願いします。ありがとうございました。\"}, {\"original\": \"Ha davvero un ottimo sapore.\", \"translated\": \"とてもおいしいです。\"}]', 12, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare al ristorante?\", \"Fantastico! Ecco 10 frasi comuni relative al ristorante, insieme alle rispettive traduzioni in inglese:\"]', '[\"Ristorazione\", \"Ordinazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio ordinare bevande, presentare un reclamo o chiedere informazioni sugli ingredienti? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\", \"translated\": \"Excuse me, how much longer will our food be?\"}, {\"original\": \"Un tavolo per due, per favore.\", \"translated\": \"A table for two, please.\"}, {\"original\": \"Potremmo vedere il menù, per favore?\", \"translated\": \"Could we see the menu, please?\"}, {\"original\": \"Avete dei piatti tipici da consigliarci?\", \"translated\": \"Do you have any signature dishes to recommend?\"}, {\"original\": \"Vorrei ordinare questo e quest’altro.\", \"translated\": \"I\'d like to order this, and this.\"}, {\"original\": \"Un bicchiere d’acqua, per favore. Grazie.\", \"translated\": \"A glass of water, please. Thanks.\"}, {\"original\": \"Il conto, per favore.\", \"translated\": \"The bill, please.\"}, {\"original\": \"Posso pagare con carta di credito?\", \"translated\": \"Can I pay by credit card?\"}, {\"original\": \"Potrebbe impacchettare questo da portare via, per favore?\", \"translated\": \"Could you pack this to go, please?\"}, {\"original\": \"Il cibo era delizioso, grazie.\", \"translated\": \"The food was delicious, thank you.\"}]', 1, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un hotel?\", \"Fantastico! Ecco 10 frasi comuni relative all\'hotel, insieme alle rispettive traduzioni in inglese:\"]', '[\"Check-in\", \"Check-out\", \"Servizio in camera\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio la posizione della stanza, altri servizi dell\'hotel o il check-out? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Salve, ho una prenotazione, ecco il mio passaporto.\", \"translated\": \"Hello, I have a reservation. Here is my passport.\"}, {\"original\": \"Avete camere disponibili?\", \"translated\": \"Do you have any vacancies?\"}, {\"original\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\", \"translated\": \"Excuse me, does the hotel have a gym or a laundry room?\"}, {\"original\": \"A che ora inizia la colazione?\", \"translated\": \"What time does breakfast start?\"}, {\"original\": \"Potrei avere la chiave della mia stanza, per favore?\", \"translated\": \"Could I have a room key, please?\"}, {\"original\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\", \"translated\": \"Could you help me take my luggage to the room?\"}, {\"original\": \"Come posso chiamare il servizio in camera?\", \"translated\": \"How do I call room service?\"}, {\"original\": \"A che ora è il check-out?\", \"translated\": \"What time is check-out?\"}, {\"original\": \"Potrebbe rilasciarmi una ricevuta/fattura?\", \"translated\": \"Could you write me a receipt/invoice?\"}, {\"original\": \"Posso lasciare qui i miei bagagli?\", \"translated\": \"Can I leave my luggage here?\"}]', 2, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in aeroporto?\", \"Fantastico! Ecco 10 frasi comuni relative all’aeroporto, insieme alle rispettive traduzioni in inglese:\"]', '[\"Check-in\", \"Imbarco\", \"Controllo bagagli\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio il check-in, il ritiro bagagli o il servizio di noleggio auto? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dov\'è il banco del check-in?\", \"translated\": \"Where is the check-in counter?\"}, {\"original\": \"Vorrei un posto vicino al finestrino, per favore.\", \"translated\": \"I\'d like a window seat, please.\"}, {\"original\": \"Questo volo è in ritardo?\", \"translated\": \"Is this flight delayed?\"}, {\"original\": \"Devo registrare questo bagaglio.\", \"translated\": \"I need to check this baggage.\"}, {\"original\": \"Dov\'è l\'ingresso per l\'imbarco?\", \"translated\": \"Where is the boarding gate?\"}, {\"original\": \"L\'aeroplano sta per decollare.\", \"translated\": \"The plane is about to take off.\"}, {\"original\": \"Devo estrarre il mio laptop e la power bank?\", \"translated\": \"Do I need to take out my laptop and power bank?\"}, {\"original\": \"Dov\'è il negozio duty-free?\", \"translated\": \"Where is the duty-free shop?\"}, {\"original\": \"Non riesco a trovare la mia valigia.\", \"translated\": \"I can\'t find my suitcase.\"}, {\"original\": \"Offrite un servizio di sedia a rotelle?\", \"translated\": \"Do you have a wheelchair service?\"}]', 3, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei trasporti pubblici?\", \"Fantastico! Ecco 10 frasi comuni relative ai trasporti pubblici, insieme alle rispettive traduzioni in inglese:\"]', '[\"Prendere l\'autobus o la metropolitana\", \"Acquistare biglietti\", \"Effettuare un trasferimento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere dove si trova la fermata dell’autobus, il prezzo del biglietto o come scendere? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Questo autobus va alla stazione?\", \"translated\": \"Does this bus go to the terminal?\"}, {\"original\": \"Qual è la prossima fermata?\", \"translated\": \"What is the next stop?\"}, {\"original\": \"Dove posso acquistare un biglietto?\", \"translated\": \"Where can I buy a ticket?\"}, {\"original\": \"Un biglietto per XX, per favore.\", \"translated\": \"One ticket to XX, please.\"}, {\"original\": \"Devo cambiare?\", \"translated\": \"Do I need to transfer?\"}, {\"original\": \"Tra quanto arriva il prossimo treno della metropolitana?\", \"translated\": \"How long until the next subway train?\"}, {\"original\": \"Scusi, mi lasci passare, per favore.\", \"translated\": \"Excuse me, please let me pass.\"}, {\"original\": \"Questo posto è occupato?\", \"translated\": \"Is this seat taken?\"}, {\"original\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\", \"translated\": \"Excuse me, where can I transfer to Line 2 to get to XX?\"}, {\"original\": \"Come arrivo a XX?\", \"translated\": \"How do I get to XX?\"}]', 4, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nelle attrazioni turistiche?\", \"Fantastico! Ecco 10 frasi comuni relative alle attrazioni turistiche, insieme alle rispettive traduzioni in inglese:\"]', '[\"Visita turistica\", \"Scattare foto\", \"Acquistare biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il prezzo dei biglietti, trovare un parcheggio o richiedere un servizio di guida turistica? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"How much is the entrance fee?\"}, {\"original\": \"Sono disponibili biglietti per studenti?\", \"translated\": \"Are there student tickets available?\"}, {\"original\": \"A che ora apre la attrazione?\", \"translated\": \"What time does the attraction open?\"}, {\"original\": \"Quali sono le cose divertenti da fare qui?\", \"translated\": \"What are the fun things to do here?\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"Dove si trova l\'autobus per i tour turistici?\", \"translated\": \"Where is the sightseeing bus?\"}, {\"original\": \"Dove si trova il bagno?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"Dove si trova il punto migliore per osservare la vista?\", \"translated\": \"Where is the best viewing spot?\"}, {\"original\": \"Il paesaggio qui è bellissimo.\", \"translated\": \"The scenery here is beautiful.\"}, {\"original\": \"È disponibile un tour guidato?\", \"translated\": \"Is there a guided tour available?\"}]', 5, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare con un taxi o un servizio taxi?\", \"Fantastico! Ecco 10 frasi comuni relative al taxi o a un servizio taxi, insieme alle rispettive traduzioni in inglese:\"]', '[\"Prendere un taxi\", \"Indicare la destinazione\", \"Pagamento\"]', 'it', '[\"Per ora, cosa vorrebbe fare principalmente in questo momento? Ad esempio chiedere la destinazione, il costo o una ricevuta: si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dove posso prendere un taxi?\", \"translated\": \"Where can I get a taxi?\"}, {\"original\": \"Mi porti a questo indirizzo, per favore.\", \"translated\": \"Please take me to this address.\"}, {\"original\": \"Quanto costerà all\'incirca?\", \"translated\": \"Roughly how much will it be?\"}, {\"original\": \"Potrebbe usare il tassametro, per favore?\", \"translated\": \"Could you use the meter, please?\"}, {\"original\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\", \"translated\": \"Please drive a bit faster, I\'m in a hurry.\"}, {\"original\": \"Si fermi qui, per favore.\", \"translated\": \"Please stop here.\"}, {\"original\": \"Accetta carte di credito o pagamenti mobili?\", \"translated\": \"Do you accept cards or mobile payments?\"}, {\"original\": \"Potrei avere lo scontrino, per favore?\", \"translated\": \"Could I have a receipt, please?\"}, {\"original\": \"Grazie, autista.\", \"translated\": \"Thank you, driver.\"}, {\"original\": \"Quanto manca ancora?\", \"translated\": \"How much further is it?\"}]', 6, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in farmacia?\", \"Fantastico! Ecco 10 frasi comuni relative alla farmacia, insieme alle rispettive traduzioni in inglese:\"]', '[\"Acquisto di Farmaci\", \"Consultazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere indicazioni sull’assunzione di un farmaco, frasi relative all’utilizzo dell’assicurazione sanitaria o alla durata della terapia? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Ha dei farmaci per il raffreddore?\", \"translated\": \"Do you have cold medicine?\"}, {\"original\": \"Come devo assumere questo farmaco?\", \"translated\": \"How should I take this medicine?\"}, {\"original\": \"Ha degli antidolorifici?\", \"translated\": \"Do you have any painkillers?\"}, {\"original\": \"È incluso un foglietto illustrativo?\", \"translated\": \"Is there an instruction leaflet?\"}, {\"original\": \"Questo farmaco ha effetti collaterali?\", \"translated\": \"Does this medicine have any side effects?\"}, {\"original\": \"Posso utilizzare la mia tessera sanitaria?\", \"translated\": \"Can I use my medical insurance card?\"}, {\"original\": \"Potrei avere una confezione di cerotti, per favore?\", \"translated\": \"Could I have a box of Band-Aids, please?\"}, {\"original\": \"Ha dei farmaci per abbassare la febbre?\", \"translated\": \"Do you have any fever reducers?\"}, {\"original\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\", \"translated\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\"}, {\"original\": \"A che ora chiude?\", \"translated\": \"What time do you close?\"}]', 7, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei servizi di emergenza?\", \"Fantastico! Ecco 10 frasi comuni relative ai servizi di emergenza, insieme alle rispettive traduzioni in inglese:\"]', '[\"Chiamare la polizia\", \"Pronto soccorso\", \"Chiedere aiuto\"]', 'it', '[\"Per ora, ha in mente una situazione di emergenza specifica, ad esempio un incendio, una persona ferita che necessita di aiuto o una chiamata d\'emergenza? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\", \"translated\": \"Please help me call an ambulance.\"}, {\"original\": \"Dov\'è l\'ospedale?\", \"translated\": \"Where is the hospital?\"}, {\"original\": \"Qualcuno è ferito.\", \"translated\": \"Someone is injured.\"}, {\"original\": \"Per favore, mi aiuti.\", \"translated\": \"Please help me.\"}, {\"original\": \"Dov\'è la stazione di polizia?\", \"translated\": \"Where is the police station?\"}, {\"original\": \"Ho perso i miei oggetti.\", \"translated\": \"I\'ve lost my belongings.\"}, {\"original\": \"Qual è il numero del corpo dei vigili del fuoco?\", \"translated\": \"What is the number for the fire department?\"}, {\"original\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\", \"translated\": \"I\'ve lost my passport. Do you know where the nearest police station is?\"}, {\"original\": \"C\'è un\'uscita di emergenza?\", \"translated\": \"Is there an emergency exit?\"}, {\"original\": \"Qualcuno è svenuto.\", \"translated\": \"Someone has fainted.\"}]', 8, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in spiaggia o in piscina?\", \"Fantastico! Ecco 10 frasi comuni relative alla spiaggia o alla piscina, insieme alle rispettive traduzioni in inglese:\"]', '[\"Nuoto\", \"Abbronzatura\", \"Sport sulla spiaggia\"]', 'it', '[\"Per ora, potrebbe gentilmente indicarmi il contesto dell\'evento o della festa locale a cui parteciperà, ad esempio una festa culturale, una festa del cibo o una festa musicale? Fornisca il contesto.\", \"Indichi le attività a cui parteciperà.\"]', '[\"Ha in mente una situazione specifica? Si senta libero di chiedere.\", \"Descriva la situazione che ha in mente.\"]', '[{\"original\": \"Guarda! Le onde laggiù sono davvero grandi.\", \"translated\": \"Look! The waves over there are really big.\"}, {\"original\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\", \"translated\": \"Remember to apply sunscreen, the UV rays here are very strong.\"}, {\"original\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\", \"translated\": \"The sand on this beach is so fine, it feels like stepping on cotton.\"}, {\"original\": \"Che ne dici di giocare a pallavolo in spiaggia?\", \"translated\": \"How about playing volleyball on the beach?\"}, {\"original\": \"Le barche a vela in lontananza sembrano bellissime.\", \"translated\": \"The sailboats in the distance look beautiful.\"}, {\"original\": \"L\'acqua qui è così trasparente che si riescono persino a vedere i pesci.\", \"translated\": \"The water here is so clear, you can even see the fish.\"}, {\"original\": \"Andiamo a cercare delle conchiglie.\", \"translated\": \"Let\'s go find some seashells.\"}, {\"original\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\", \"translated\": \"Taking a walk on the beach at sunset must be very romantic.\"}, {\"original\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\", \"translated\": \"I heard the seafood here is very fresh, let\'s go try some.\"}, {\"original\": \"La marea sta salendo, dirigiamoci verso la riva.\", \"translated\": \"The tide is coming in, let\'s head towards the shore.\"}]', 9, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare durante eventi e festival locali?\", \"Fantastico! Ecco 10 frasi comuni relative a eventi e festival locali, insieme alle rispettive traduzioni in inglese:\"]', '[\"Partecipare a eventi\", \"Celebrare festival\", \"Apprendere la cultura\"]', 'it', '[\"Per ora, potrebbe indicarmi il contesto dell’evento o del festival locale a cui parteciperà, ad esempio Halloween, un concerto, una festa tra amici o qualcos’altro? La preghiamo di specificare il contesto.\", \"La preghiamo di descrivere le attività che ha in mente.\"]', '[\"Ha in mente una situazione specifica? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Ci sono eventi oggi?\", \"translated\": \"Are there any events today?\"}, {\"original\": \"C\'è qualcosa di speciale in questo festival?\", \"translated\": \"Is there anything special about this festival?\"}, {\"original\": \"Dove si tiene la celebrazione?\", \"translated\": \"Where is the celebration being held?\"}, {\"original\": \"Come posso acquistare i biglietti?\", \"translated\": \"How can I buy tickets?\"}, {\"original\": \"A che ora inizia lo spettacolo?\", \"translated\": \"What time does the performance start?\"}, {\"original\": \"Quali sono i cibi tradizionali?\", \"translated\": \"What traditional food is there?\"}, {\"original\": \"Qui è davvero animato.\", \"translated\": \"It\'s really lively here.\"}, {\"original\": \"Ci sono attività folkloristiche?\", \"translated\": \"Are there any folk activities?\"}, {\"original\": \"Buone feste!\", \"translated\": \"Happy holidays!\"}, {\"original\": \"A che ora termina l\'evento?\", \"translated\": \"What time does the event end?\"}]', 10, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un museo o in una galleria d\'arte?\", \"Fantastico! Ecco 10 frasi comuni relative a un museo o a una galleria d\'arte, insieme alle rispettive traduzioni in inglese:\"]', '[\"Visita\", \"Tour guidato\", \"Acquisto di biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere un manuale introduttivo, frasi relative a una mappa, frasi per commentare un\'esposizione? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"How much is the admission fee?\"}, {\"original\": \"Avete guide audio?\", \"translated\": \"Do you have audio guides?\"}, {\"original\": \"Chi ha creato quest\'opera d\'arte?\", \"translated\": \"Who created this artwork?\"}, {\"original\": \"Dove si trova il pezzo più prezioso del museo?\", \"translated\": \"Where is the museum\'s most prized piece?\"}, {\"original\": \"È consentito fare fotografie?\", \"translated\": \"Is photography allowed?\"}, {\"original\": \"Ci sono mostre speciali in corso?\", \"translated\": \"Are there any special exhibitions here?\"}, {\"original\": \"Quanto tempo richiede la visita?\", \"translated\": \"How long does the visit take?\"}, {\"original\": \"Potreste darci una breve introduzione?\", \"translated\": \"Could you give us an introduction?\"}, {\"original\": \"Queste opere sono davvero squisite.\", \"translated\": \"These works are truly exquisite.\"}, {\"original\": \"Dove si trova il negozio di souvenir?\", \"translated\": \"Where is the souvenir shop?\"}]', 11, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare nei bar?\", \"Fantastico! Ecco 10 frasi comuni relative ai bar, insieme alle rispettive traduzioni in inglese:\"]', '[\"Ordinare un caffè\", \"Riposare\", \"Socializzare\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il menù, bevande fredde o calde, altri prodotti? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Prenderò un caffè latte, per favore.\", \"translated\": \"I\'ll have a latte, please.\"}, {\"original\": \"Avete il Wi-Fi?\", \"translated\": \"Do you have Wi-Fi?\"}, {\"original\": \"Potrei vedere il menu, per favore?\", \"translated\": \"Could I see the menu, please?\"}, {\"original\": \"Sono ammessi i rabbocchi?\", \"translated\": \"Are refills allowed?\"}, {\"original\": \"Il mio caffè è pronto?\", \"translated\": \"Is my coffee ready?\"}, {\"original\": \"Per quanto tempo posso stare seduto qui?\", \"translated\": \"How long can I sit here?\"}, {\"original\": \"Potrebbe fare una foto per noi?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"Dov\'è il bagno?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"Il conto, per favore. Grazie.\", \"translated\": \"Check, please. Thank you.\"}, {\"original\": \"Ha davvero un ottimo sapore.\", \"translated\": \"It tastes really good.\"}]', 12, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare al ristorante?\", \"Fantastico! Ecco 10 frasi comuni relative al ristorante, insieme alle traduzioni in arabo:\"]', '[\"Ristorazione\", \"Ordinazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio ordinare bevande, presentare un reclamo o chiedere informazioni sugli ingredienti? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\", \"translated\": \"عذرًا، كم من الوقت سيستغرق وصول طعامنا؟\"}, {\"original\": \"Un tavolo per due, per favore.\", \"translated\": \"طاولة لشخصين، من فضلكم.\"}, {\"original\": \"Potremmo vedere il menù, per favore?\", \"translated\": \"هل يمكننا رؤية القائمة، من فضلكم؟\"}, {\"original\": \"Avete dei piatti tipici da consigliarci?\", \"translated\": \"هل لديكم أطباق مميزة توصون بها؟\"}, {\"original\": \"Vorrei ordinare questo e quest’altro.\", \"translated\": \"أود طلب هذا وهذا.\"}, {\"original\": \"Un bicchiere d’acqua, per favore. Grazie.\", \"translated\": \"كوب ماء، من فضلكم. شكرًا لكم.\"}, {\"original\": \"Il conto, per favore.\", \"translated\": \"الفاتورة، من فضلكم.\"}, {\"original\": \"Posso pagare con carta di credito?\", \"translated\": \"هل يمكنني الدفع باستخدام بطاقة الائتمان؟\"}, {\"original\": \"Potrebbe impacchettare questo da portare via, per favore?\", \"translated\": \"هل يمكنكم تغليف هذا لل带走، من فضلكم؟\"}, {\"original\": \"Il cibo era delizioso, grazie.\", \"translated\": \"كان الطعام لذيذًا جدًّا، شكرًا لكم.\"}]', 1, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un hotel?\", \"Fantastico! Ecco 10 frasi comuni relative all\'hotel, insieme alle traduzioni in arabo:\"]', '[\"Check-in\", \"Check-out\", \"Servizio in camera\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio la posizione della camera, altri servizi offerti dall\'hotel o il check-out? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Salve, ho una prenotazione, ecco il mio passaporto.\", \"translated\": \"مرحبًا، لدي حجزٌ، وهذه جواز سفري.\"}, {\"original\": \"Avete camere disponibili?\", \"translated\": \"هل لديكم أي غرف شاغرة؟\"}, {\"original\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\", \"translated\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسيل الملابس؟\"}, {\"original\": \"A che ora inizia la colazione?\", \"translated\": \"في أي وقت تبدأ وجبة الإفطار؟\"}, {\"original\": \"Potrei avere la chiave della mia camera, per favore?\", \"translated\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\"}, {\"original\": \"Potrebbe aiutarmi a portare i miei bagagli nella camera?\", \"translated\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\"}, {\"original\": \"Come posso chiamare il servizio in camera?\", \"translated\": \"كيف أتصل بخدمة الغرف؟\"}, {\"original\": \"A che ora è il check-out?\", \"translated\": \"في أي وقت تنتهي إجراءات المغادرة؟\"}, {\"original\": \"Potrebbe rilasciarmi una ricevuta/fattura?\", \"translated\": \"هل يمكنكم إعطائي إيصالًا/فاتورةً؟\"}, {\"original\": \"Posso lasciare qui i miei bagagli?\", \"translated\": \"هل يمكنني ترك أمتعتي هنا؟\"}]', 2, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in aeroporto?\", \"Fantastico! Ecco 10 frasi comuni relative all’aeroporto, insieme alle traduzioni in arabo:\"]', '[\"Check-in\", \"Imbarco\", \"Controllo bagagli\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio il check-in, il ritiro bagagli o il servizio di noleggio auto? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dov\'è il banco del check-in?\", \"translated\": \"أين كاونتر تسجيل الدخول؟\"}, {\"original\": \"Vorrei un posto vicino al finestrino, per favore.\", \"translated\": \"أود أن أجلس في مقعد بجانب النافذة، من فضلك.\"}, {\"original\": \"Questo volo è in ritardo?\", \"translated\": \"هل هذا الرحلة متأخرة؟\"}, {\"original\": \"Devo registrare questo bagaglio.\", \"translated\": \"يجب أن أُسجّل هذه الأمتعة.\"}, {\"original\": \"Dov\'è l\'ingresso per l\'imbarco?\", \"translated\": \"أين بوابة الصعود إلى الطائرة؟\"}, {\"original\": \"L\'aeroplano sta per decollare.\", \"translated\": \"الطائرة على وشك الإقلاع.\"}, {\"original\": \"Devo estrarre il mio laptop e la power bank?\", \"translated\": \"هل يجب أن أخرج جهاز الكمبيوتر المحمول والبنك الكهربائي الخاص بي؟\"}, {\"original\": \"Dov\'è il negozio duty-free?\", \"translated\": \"أين متجر التخفيضات الجمركية؟\"}, {\"original\": \"Non riesco a trovare la mia valigia.\", \"translated\": \"لا أستطيع العثور على حقيبتي.\"}, {\"original\": \"Offrite un servizio di sedia a rotelle?\", \"translated\": \"هل تقدمون خدمة الكرسي المتحرك؟\"}]', 3, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare nei trasporti pubblici?\", \"Fantastico! Ecco 10 frasi comuni relative ai trasporti pubblici, insieme alle traduzioni in arabo:\"]', '[\"Prendere l\'autobus o la metropolitana\", \"Acquistare biglietti\", \"Effettuare un trasferimento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere dove si trova la fermata dell’autobus, il prezzo del biglietto o come scendere? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Questo autobus va al capolinea?\", \"translated\": \"هل هذه الحافلة تذهب إلى المحطة؟\"}, {\"original\": \"Qual è la prossima fermata?\", \"translated\": \"ما هي المحطة التالية؟\"}, {\"original\": \"Dove posso acquistare un biglietto?\", \"translated\": \"أين يمكنني شراء تذكرة؟\"}, {\"original\": \"Un biglietto per XX, per favore.\", \"translated\": \"تذكرة واحدة إلى XX، من فضلك.\"}, {\"original\": \"Devo cambiare mezzo?\", \"translated\": \"هل عليَّ التحويل؟\"}, {\"original\": \"Tra quanto arriva il prossimo treno della metropolitana?\", \"translated\": \"كم المدة المتبقية حتى قطار المترو القادم؟\"}, {\"original\": \"Scusi, mi lasci passare, per favore.\", \"translated\": \"عذرًا، من فضلك اسمح لي بالمرور.\"}, {\"original\": \"Questo posto è occupato?\", \"translated\": \"هل هذا المقعد محجوز؟\"}, {\"original\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\", \"translated\": \"عذرًا، أين يمكنني التحويل إلى الخط الثاني للوصول إلى XX؟\"}, {\"original\": \"Come arrivo a XX?\", \"translated\": \"كيف أصل إلى XX؟\"}]', 4, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nelle attrazioni turistiche?\", \"Fantastico! Ecco 10 frasi comuni relative alle attrazioni turistiche, insieme alle traduzioni in arabo:\"]', '[\"Visita turistica\", \"Scattare foto\", \"Acquistare biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il prezzo dei biglietti, trovare un parcheggio o richiedere un servizio di guida turistica? Chieda pure.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"Sono disponibili biglietti per studenti?\", \"translated\": \"هل تتوفر تذاكر للطلاب؟\"}, {\"original\": \"A che ora apre la attrazione?\", \"translated\": \"في أي وقت يفتح المعلم السياحي؟\"}, {\"original\": \"Quali sono le cose divertenti da fare qui?\", \"translated\": \"ما الأشياء الممتعة التي يمكن القيام بها هنا؟\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"هل يمكنك التقاط صورة لنا؟\"}, {\"original\": \"Dove si trova l\'autobus per i tour turistici?\", \"translated\": \"أين حافلة الجولات السياحية؟\"}, {\"original\": \"Dove si trova il bagno?\", \"translated\": \"أين الحمام؟\"}, {\"original\": \"Dove si trova il punto migliore per osservare?\", \"translated\": \"ما أفضل مكان لمشاهدة المناظر؟\"}, {\"original\": \"Il panorama qui è bellissimo.\", \"translated\": \"المنظر هنا جميلٌ جدًّا.\"}, {\"original\": \"È disponibile un tour guidato?\", \"translated\": \"هل توجد جولة إرشادية متاحة؟\"}]', 5, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare per un taxi o un servizio taxi?\", \"Fantastico! Ecco 10 frasi comuni relative al taxi o a un servizio taxi, insieme alle traduzioni in arabo:\"]', '[\"Prendere un taxi\", \"Indicare la destinazione\", \"Pagamento\"]', 'it', '[\"Per ora, cosa desidera fare principalmente in questo momento, ad esempio chiedere la destinazione, il costo o una ricevuta? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dove posso prendere un taxi?\", \"translated\": \"أين يمكنني أخذ تاكسي؟\"}, {\"original\": \"Mi porti a questo indirizzo, per favore.\", \"translated\": \"من فضلك خذني إلى هذا العنوان.\"}, {\"original\": \"Quanto costerà all\'incirca?\", \"translated\": \"كم يبلغ السعر تقريبًا؟\"}, {\"original\": \"Potrebbe usare il tassametro, per favore?\", \"translated\": \"هل يمكنك استخدام العداد من فضلك؟\"}, {\"original\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\", \"translated\": \"من فضلك ا-driving أسرع قليلًا، فأنا مستعجل.\"}, {\"original\": \"Si fermi qui, per favore.\", \"translated\": \"من فضلك توقف هنا.\"}, {\"original\": \"Accetta carte di credito o pagamenti mobili?\", \"translated\": \"هل تقبل الدفع بالبطاقات أو عبر الهاتف المحمول؟\"}, {\"original\": \"Potrei avere lo scontrino, per favore?\", \"translated\": \"هل يمكنني الحصول على إشعار دفع من فضلك؟\"}, {\"original\": \"Grazie, autista.\", \"translated\": \"شكرًا لك يا سائق.\"}, {\"original\": \"Quanto manca ancora?\", \"translated\": \"كم تبقى بعد من المسافة؟\"}]', 6, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in farmacia?\", \"Fantastico! Ecco 10 frasi comuni relative alla farmacia, insieme alle traduzioni in arabo:\"]', '[\"Acquisto di Farmaci\", \"Consultazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere istruzioni sull’assunzione di un farmaco, frasi relative all’uso dell’assicurazione sanitaria o alla durata della terapia? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Ha dei farmaci per il raffreddore?\", \"translated\": \"هل لديكم دواء للبرد؟\"}, {\"original\": \"Come devo assumere questo farmaco?\", \"translated\": \"كيف يجب أن آخذ هذا الدواء؟\"}, {\"original\": \"Ha degli antidolorifici?\", \"translated\": \"هل لديكم مسكنات للألم؟\"}, {\"original\": \"È incluso un foglietto illustrativo?\", \"translated\": \"هل توجد نشرة إرشادات مع هذا الدواء؟\"}, {\"original\": \"Questo farmaco ha effetti collaterali?\", \"translated\": \"هل لهذا الدواء أي آثار جانبية؟\"}, {\"original\": \"Posso utilizzare la mia tessera sanitaria?\", \"translated\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\"}, {\"original\": \"Potrei avere una confezione di cerotti, per favore?\", \"translated\": \"هل يمكنني الحصول على علبة من الضمادات اللاصقة، من فضلكم؟\"}, {\"original\": \"Ha dei farmaci antipiretici?\", \"translated\": \"هل لديكم خافضات للحرارة؟\"}, {\"original\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\", \"translated\": \"لديّ جرح سطحي بسيط. هل لديكم مطهر وضمادات لاصقة؟\"}, {\"original\": \"A che ora chiude?\", \"translated\": \"في أي وقت تغلقون؟\"}]', 7, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei servizi di emergenza?\", \"Fantastico! Ecco 10 frasi comuni relative ai servizi di emergenza, insieme alle traduzioni in arabo:\"]', '[\"Chiamare la polizia\", \"Pronto soccorso\", \"Chiedere aiuto\"]', 'it', '[\"Per ora, ha in mente una situazione di emergenza specifica, ad esempio incendio, ferito e bisogno di aiuto, chiamata d\'emergenza? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\", \"translated\": \"من فضلك ساعدني في الاتصال بالإسعاف.\"}, {\"original\": \"Dov\'è l\'ospedale?\", \"translated\": \"أين المستشفى؟\"}, {\"original\": \"Qualcuno è ferito.\", \"translated\": \"شخص ما أُصيب.\"}, {\"original\": \"Per favore, mi aiuti.\", \"translated\": \"من فضلك ساعدني.\"}, {\"original\": \"Dov\'è la stazione di polizia?\", \"translated\": \"أين مركز الشرطة؟\"}, {\"original\": \"Ho perso i miei effetti personali.\", \"translated\": \"لقد فقدت أغراضي.\"}, {\"original\": \"Qual è il numero del corpo dei vigili del fuoco?\", \"translated\": \"ما هو رقم دائرة الإطفاء؟\"}, {\"original\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\", \"translated\": \"لقد فقدت جواز سفري. هل تعرف أين أقرب مركز شرطة؟\"}, {\"original\": \"C\'è un\'uscita di emergenza?\", \"translated\": \"هل يوجد مخرج طوارئ؟\"}, {\"original\": \"Qualcuno è svenuto.\", \"translated\": \"شخص ما فقد وعيه.\"}]', 8, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in spiaggia o in piscina?\", \"Fantastico! Ecco 10 frasi comuni relative alla spiaggia o alla piscina, insieme alle rispettive traduzioni in arabo:\"]', '[\"Nuoto\", \"Abbronzatura\", \"Sport sulla spiaggia\"]', 'it', '[\"Per ora, potrebbe gentilmente indicarmi il contesto dell\'evento o della festa locale a cui parteciperà, ad esempio una festa culturale, una festa del cibo o una festa musicale? La preghiamo di specificare il contesto.\", \"La preghiamo di indicare le attività a cui parteciperà.\"]', '[\"Ha in mente una situazione specifica? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Guarda! Le onde laggiù sono davvero grandi.\", \"translated\": \"انظر! الأمواج هناك كبيرة جدًّا.\"}, {\"original\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\", \"translated\": \"تذكَّر أن تضع واقي الشمس، فأشعة فوق البنفسجية هنا قوية جدًّا.\"}, {\"original\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\", \"translated\": \"الرمال على هذه الشاطئ ناعمة جدًّا، لدرجة أن المشي عليها يشبه المشي على القطن.\"}, {\"original\": \"Che ne dici di giocare a pallavolo sulla spiaggia?\", \"translated\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\"}, {\"original\": \"Le barche a vela in lontananza sembrano bellissime.\", \"translated\": \"القوارب الشراعية في الأفق تبدو جميلة جدًّا.\"}, {\"original\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\", \"translated\": \"الماء هنا صافٍ جدًّا لدرجة أنك تستطيع رؤية الأسماك.\"}, {\"original\": \"Andiamo a cercare delle conchiglie.\", \"translated\": \"هيا نذهب للبحث عن بعض المحار.\"}, {\"original\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\", \"translated\": \"التنزه على الشاطئ عند غروب الشمس لا بد أنه أمر رومانسي جدًّا.\"}, {\"original\": \"Ho sentito dire che qui il pesce e i frutti di mare sono freschissimi, andiamo a provarli.\", \"translated\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًّا، فلنذهب ونجرب بعضها.\"}, {\"original\": \"La marea sta salendo, dirigiamoci verso la riva.\", \"translated\": \"المدّ قادم، لذا دعونا نتجه نحو اليابسة.\"}]', 9, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare durante eventi e festival locali?\", \"Fantastico! Ecco 10 frasi comuni relative a eventi e festival locali, insieme alle rispettive traduzioni in arabo:\"]', '[\"Partecipare a eventi\", \"Celebrare festival\", \"Apprendere la cultura\"]', 'it', '[\"Per ora, potrebbe gentilmente indicarmi il contesto dell’evento o del festival locale a cui parteciperà, ad esempio Halloween, un concerto, una festa tra amici o qualcos’altro? La preghiamo di specificare il contesto.\", \"La preghiamo di descrivere le attività che ha in mente.\"]', '[\"Ha in mente una situazione specifica? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Ci sono eventi oggi?\", \"translated\": \"هل توجد أي فعاليات اليوم؟\"}, {\"original\": \"C\'è qualcosa di speciale in questo festival?\", \"translated\": \"هل هناك شيء خاص في هذه المهرجان؟\"}, {\"original\": \"Dove si tiene la celebrazione?\", \"translated\": \"أين تُقام الاحتفالات؟\"}, {\"original\": \"Come posso acquistare i biglietti?\", \"translated\": \"كيف يمكنني شراء التذاكر؟\"}, {\"original\": \"A che ora inizia lo spettacolo?\", \"translated\": \"في أي وقت تبدأ العروض؟\"}, {\"original\": \"Quali sono i cibi tradizionali?\", \"translated\": \"ما الأطعمة التقليدية المتاحة؟\"}, {\"original\": \"Qui è davvero animato.\", \"translated\": \"المكان مفعَمٌ بالحيوية حقًّا.\"}, {\"original\": \"Ci sono attività popolari?\", \"translated\": \"هل توجد أنشطة شعبية؟\"}, {\"original\": \"Buone feste!\", \"translated\": \"أعياد سعيدة!\"}, {\"original\": \"A che ora termina l\'evento?\", \"translated\": \"في أي وقت تنتهي الفعالية؟\"}]', 10, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un museo o in una galleria d\'arte?\", \"Fantastico! Ecco 10 frasi comuni relative a un museo o a una galleria d\'arte, insieme alle traduzioni in arabo:\"]', '[\"Visita\", \"Tour guidato\", \"Acquisto di biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere un manuale introduttivo, frasi relative a una mappa concettuale, frasi per commentare un\'esposizione? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"كم تبلغ رسوم الدخول؟\"}, {\"original\": \"Avete guide audio?\", \"translated\": \"هل لديكم أدلة صوتية؟\"}, {\"original\": \"Chi ha creato quest\'opera d\'arte?\", \"translated\": \"من هو مبتكر هذه القطعة الفنية؟\"}, {\"original\": \"Dove si trova il pezzo più prezioso del museo?\", \"translated\": \"أين توجد أثمن قطعة في المتحف؟\"}, {\"original\": \"È consentito fare fotografie?\", \"translated\": \"هل يُسمح بالتصوير الفوتوغرافي؟\"}, {\"original\": \"Ci sono delle mostre speciali qui?\", \"translated\": \"هل توجد هنا أي معارض خاصة؟\"}, {\"original\": \"Quanto tempo richiede la visita?\", \"translated\": \"كم تستغرق الزيارة من الوقت؟\"}, {\"original\": \"Potreste darci una breve introduzione?\", \"translated\": \"هل يمكنكم أن تقدّموا لنا عرضًا تمهيديًّا؟\"}, {\"original\": \"Queste opere sono davvero squisite.\", \"translated\": \"هذه الأعمال فعلاً رائعةٌ جدًّا.\"}, {\"original\": \"Dove si trova il negozio dei souvenir?\", \"translated\": \"أين تقع متجر الهدايا التذكارية؟\"}]', 11, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare nei caffè?\", \"Fantastico! Ecco 10 frasi comuni relative ai caffè, insieme alle traduzioni in arabo:\"]', '[\"Ordinare un caffè\", \"Riposare\", \"Socializzare\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il menù, bevande fredde o calde, altri prodotti? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Prenderò un caffè latte, per favore.\", \"translated\": \"سأطلب لاتيه، من فضلك.\"}, {\"original\": \"Avete il Wi-Fi?\", \"translated\": \"هل لديكم اتصال واي فاي؟\"}, {\"original\": \"Potrei vedere il menu, per favore?\", \"translated\": \"هل يمكنني رؤية القائمة، من فضلك؟\"}, {\"original\": \"Sono ammesse le ricariche?\", \"translated\": \"هل يُسمح بإعادة التعبئة؟\"}, {\"original\": \"Il mio caffè è pronto?\", \"translated\": \"هل قهوةُّي جاهزة؟\"}, {\"original\": \"Per quanto tempo posso stare seduto qui?\", \"translated\": \"كم من الوقت يمكنني الجلوس هنا؟\"}, {\"original\": \"Potrebbe fare una foto per noi?\", \"translated\": \"هل يمكنكم التقاط صورة لنا؟\"}, {\"original\": \"Dov\'è il bagno?\", \"translated\": \"أين الحمام؟\"}, {\"original\": \"Il conto, per favore. Grazie.\", \"translated\": \"الفاتورة، من فضلك. شكرًا لكم.\"}, {\"original\": \"Ha davvero un ottimo sapore.\", \"translated\": \"الطَّعمُ ممتازٌ حقًّا.\"}]', 12, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare al ristorante?\", \"Fantastico! Ecco 10 frasi comuni relative al ristorante, insieme alle rispettive traduzioni in francese:\"]', '[\"Ristorazione\", \"Ordinazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio ordinare bevande, presentare un reclamo o chiedere informazioni sugli ingredienti? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\", \"translated\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\"}, {\"original\": \"Un tavolo per due, per favore.\", \"translated\": \"Une table pour deux, s\'il vous plaît.\"}, {\"original\": \"Potremmo vedere il menu, per favore?\", \"translated\": \"Pourrions-nous voir la carte, s\'il vous plaît ?\"}, {\"original\": \"Avete dei piatti tipici da consigliarci?\", \"translated\": \"Avez-vous des plats signature à nous recommander ?\"}, {\"original\": \"Vorrei ordinare questo e quest’altro.\", \"translated\": \"Je voudrais commander ceci et cela.\"}, {\"original\": \"Un bicchiere d’acqua, per favore. Grazie.\", \"translated\": \"Un verre d\'eau, s\'il vous plaît. Merci.\"}, {\"original\": \"Il conto, per favore.\", \"translated\": \"L\'addition, s\'il vous plaît.\"}, {\"original\": \"Posso pagare con carta di credito?\", \"translated\": \"Puis-je payer par carte bancaire ?\"}, {\"original\": \"Potrebbe confezionarmelo da asporto, per favore?\", \"translated\": \"Pourriez-vous emballer cela à emporter, s\'il vous plaît ?\"}, {\"original\": \"Il cibo era delizioso, grazie.\", \"translated\": \"Le plat était délicieux, merci.\"}]', 1, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un hotel?\", \"Fantastico! Ecco 10 frasi comuni relative all\'hotel, insieme alle rispettive traduzioni in francese:\"]', '[\"Check-in\", \"Check-out\", \"Servizio in camera\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio la posizione della camera, altri servizi offerti dall\'hotel o il check-out? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Salve, ho una prenotazione, ecco il mio passaporto.\", \"translated\": \"Bonjour, j’ai une réservation. Voici mon passeport.\"}, {\"original\": \"Avete camere disponibili?\", \"translated\": \"Avez-vous des chambres disponibles ?\"}, {\"original\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\", \"translated\": \"Excusez-moi, l’hôtel dispose-t-il d’une salle de sport ou d’une buanderie ?\"}, {\"original\": \"A che ora inizia la colazione?\", \"translated\": \"À quelle heure commence le petit-déjeuner ?\"}, {\"original\": \"Potrei avere la chiave della mia stanza, per favore?\", \"translated\": \"Pourrais-je avoir la clé de ma chambre, s’il vous plaît ?\"}, {\"original\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\", \"translated\": \"Pourriez-vous m’aider à porter mes bagages jusqu’à ma chambre ?\"}, {\"original\": \"Come posso chiamare il servizio in camera?\", \"translated\": \"Comment puis-je appeler le service d’étage ?\"}, {\"original\": \"A che ora è il check-out?\", \"translated\": \"À quelle heure doit-on quitter la chambre ?\"}, {\"original\": \"Potrebbe rilasciarmi una ricevuta/fattura?\", \"translated\": \"Pourriez-vous me faire un reçu / une facture ?\"}, {\"original\": \"Posso lasciare qui i miei bagagli?\", \"translated\": \"Puis-je laisser mes bagages ici ?\"}]', 2, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in aeroporto?\", \"Fantastico! Ecco 10 frasi comuni relative all’aeroporto, insieme alle rispettive traduzioni in francese:\"]', '[\"Check-in\", \"Imbarco\", \"Controllo bagagli\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio il check-in, il ritiro bagagli o il servizio di noleggio auto? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dov\'è il banco del check-in?\", \"translated\": \"Où se trouve le comptoir d\'enregistrement ?\"}, {\"original\": \"Vorrei un posto vicino al finestrino, per favore.\", \"translated\": \"Je voudrais un siège côté fenêtre, s\'il vous plaît.\"}, {\"original\": \"Questo volo è in ritardo?\", \"translated\": \"Ce vol est-il retardé ?\"}, {\"original\": \"Devo registrare questo bagaglio.\", \"translated\": \"Je dois enregistrer ce bagage.\"}, {\"original\": \"Dov\'è l\'ingresso per l\'imbarco?\", \"translated\": \"Où se trouve la porte d\'embarquement ?\"}, {\"original\": \"L\'aeroplano sta per decollare.\", \"translated\": \"L\'avion va bientôt décoller.\"}, {\"original\": \"Devo estrarre il mio laptop e la power bank?\", \"translated\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\"}, {\"original\": \"Dov\'è il negozio duty-free?\", \"translated\": \"Où se trouve la boutique hors taxes ?\"}, {\"original\": \"Non riesco a trovare la mia valigia.\", \"translated\": \"Je ne retrouve pas ma valise.\"}, {\"original\": \"Offrite un servizio di sedia a rotelle?\", \"translated\": \"Proposez-vous un service de fauteuil roulant ?\"}]', 3, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei trasporti pubblici?\", \"Fantastico! Ecco 10 frasi comuni relative ai trasporti pubblici, insieme alle rispettive traduzioni in francese:\"]', '[\"Prendere l\'autobus o la metropolitana\", \"Acquistare biglietti\", \"Effettuare un trasferimento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere dove si trova la fermata dell’autobus, il prezzo del biglietto o come scendere? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Questo autobus va al capolinea?\", \"translated\": \"Ce bus va-t-il jusqu\'à la gare routière ?\"}, {\"original\": \"Qual è la prossima fermata?\", \"translated\": \"Quel est le prochain arrêt ?\"}, {\"original\": \"Dove posso comprare un biglietto?\", \"translated\": \"Où puis-je acheter un billet ?\"}, {\"original\": \"Un biglietto per XX, per favore.\", \"translated\": \"Un billet pour XX, s\'il vous plaît.\"}, {\"original\": \"Devo cambiare mezzo?\", \"translated\": \"Dois-je changer de transport ?\"}, {\"original\": \"Quanto manca al prossimo treno della metropolitana?\", \"translated\": \"Combien de temps avant le prochain métro ?\"}, {\"original\": \"Scusi, mi lasci passare, per favore.\", \"translated\": \"Excusez-moi, laissez-moi passer, s\'il vous plaît.\"}, {\"original\": \"Questo posto è occupato?\", \"translated\": \"Cette place est-elle occupée ?\"}, {\"original\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\", \"translated\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d\'aller à XX ?\"}, {\"original\": \"Come arrivo a XX?\", \"translated\": \"Comment puis-je me rendre à XX ?\"}]', 4, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nelle attrazioni turistiche?\", \"Fantastico! Ecco 10 frasi comuni relative alle attrazioni turistiche, insieme alle traduzioni in francese:\"]', '[\"Visita turistica\", \"Scattare foto\", \"Acquistare biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il prezzo dei biglietti, trovare un parcheggio o richiedere un servizio di guida turistica? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"Combien coûte l\'entrée ?\"}, {\"original\": \"Sono disponibili biglietti per studenti?\", \"translated\": \"Y a-t-il des billets étudiants disponibles ?\"}, {\"original\": \"A che ora apre la attrazione?\", \"translated\": \"À quelle heure ouvre l\'attraction ?\"}, {\"original\": \"Quali sono le cose divertenti da fare qui?\", \"translated\": \"Quelles sont les activités amusantes à faire ici ?\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"Dove si trova l\'autobus per i tour turistici?\", \"translated\": \"Où est le bus touristique ?\"}, {\"original\": \"Dove si trova il bagno?\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"Dove si trova il punto migliore per osservare?\", \"translated\": \"Quel est le meilleur endroit pour admirer la vue ?\"}, {\"original\": \"Il panorama qui è bellissimo.\", \"translated\": \"Le paysage est magnifique ici.\"}, {\"original\": \"È disponibile un tour guidato?\", \"translated\": \"Une visite guidée est-elle disponible ?\"}]', 5, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare per un taxi o un servizio taxi?\", \"Fantastico! Ecco 10 frasi comuni relative al taxi o a un servizio taxi, insieme alle rispettive traduzioni in francese:\"]', '[\"Prendere un taxi\", \"Indicare la destinazione\", \"Pagamento\"]', 'it', '[\"Per ora, cosa vorrebbe fare principalmente in questo momento? Ad esempio chiedere la destinazione, il costo o una ricevuta: si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dove posso prendere un taxi?\", \"translated\": \"Où puis-je prendre un taxi ?\"}, {\"original\": \"Mi porti a questo indirizzo, per favore.\", \"translated\": \"Veuillez me conduire à cette adresse.\"}, {\"original\": \"Quanto costerà all\'incirca?\", \"translated\": \"Combien cela coûtera-t-il approximativement ?\"}, {\"original\": \"Potrebbe usare il tassametro, per favore?\", \"translated\": \"Pourriez-vous utiliser le compteur, s’il vous plaît ?\"}, {\"original\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\", \"translated\": \"Pourriez-vous conduire un peu plus vite, je suis pressé(e).\"}, {\"original\": \"Si fermi qui, per favore.\", \"translated\": \"Veuillez vous arrêter ici.\"}, {\"original\": \"Accetta carte di credito o pagamenti mobili?\", \"translated\": \"Acceptez-vous les paiements par carte ou mobile ?\"}, {\"original\": \"Potrei avere lo scontrino, per favore?\", \"translated\": \"Pourrais-je avoir un reçu, s’il vous plaît ?\"}, {\"original\": \"Grazie, autista.\", \"translated\": \"Merci, monsieur/madame le chauffeur.\"}, {\"original\": \"Quanto manca ancora?\", \"translated\": \"Il reste encore combien de temps ?\"}]', 6, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in farmacia?\", \"Fantastico! Ecco 10 frasi comuni relative alla farmacia, insieme alle rispettive traduzioni in francese:\"]', '[\"Acquisto di Medicinali\", \"Consulenza\", \"Pagamento\"]', 'it', '[\"Per il momento, ha in mente una situazione specifica, ad esempio chiedere istruzioni sull’assunzione di un farmaco, frasi relative all’utilizzo dell’assicurazione sanitaria o alla durata della terapia? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Ha dei farmaci per il raffreddore?\", \"translated\": \"Avez-vous des médicaments contre le rhume ?\"}, {\"original\": \"Come devo assumere questo farmaco?\", \"translated\": \"Comment dois-je prendre ce médicament ?\"}, {\"original\": \"Ha degli antidolorifici?\", \"translated\": \"Avez-vous des analgésiques ?\"}, {\"original\": \"È incluso un foglietto illustrativo?\", \"translated\": \"Y a-t-il une notice d’instructions ?\"}, {\"original\": \"Questo farmaco ha effetti collaterali?\", \"translated\": \"Ce médicament a-t-il des effets secondaires ?\"}, {\"original\": \"Posso usare la mia tessera sanitaria?\", \"translated\": \"Puis-je utiliser ma carte d’assurance maladie ?\"}, {\"original\": \"Potrei avere una confezione di cerotti, per favore?\", \"translated\": \"Pourriez-vous me donner une boîte de pansements, s’il vous plaît ?\"}, {\"original\": \"Ha dei farmaci antipiretici?\", \"translated\": \"Avez-vous des antipyrétiques ?\"}, {\"original\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\", \"translated\": \"Je me suis un peu écorché. Avez-vous un antiseptique et des pansements ?\"}, {\"original\": \"A che ora chiude?\", \"translated\": \"À quelle heure fermez-vous ?\"}]', 7, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei servizi di emergenza?\", \"Fantastico! Ecco 10 frasi comuni relative ai servizi di emergenza, insieme alle traduzioni in francese:\"]', '[\"Chiamare la polizia\", \"Pronto soccorso\", \"Chiedere aiuto\"]', 'it', '[\"Per ora, ha in mente una situazione di emergenza specifica, come un incendio, una persona ferita che necessita di aiuto o una chiamata d\'emergenza? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\", \"translated\": \"Veuillez m\'aider à appeler une ambulance.\"}, {\"original\": \"Dov\'è l\'ospedale?\", \"translated\": \"Où se trouve l\'hôpital ?\"}, {\"original\": \"Qualcuno è ferito.\", \"translated\": \"Quelqu\'un est blessé.\"}, {\"original\": \"Per favore, mi aiuti.\", \"translated\": \"Veuillez m\'aider.\"}, {\"original\": \"Dov\'è la stazione di polizia?\", \"translated\": \"Où se trouve le poste de police ?\"}, {\"original\": \"Ho perso i miei effetti personali.\", \"translated\": \"J\'ai perdu mes affaires.\"}, {\"original\": \"Qual è il numero dei vigili del fuoco?\", \"translated\": \"Quel est le numéro des pompiers ?\"}, {\"original\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\", \"translated\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le poste de police le plus proche ?\"}, {\"original\": \"C\'è un\'uscita di emergenza?\", \"translated\": \"Y a-t-il une sortie de secours ?\"}, {\"original\": \"Qualcuno è svenuto.\", \"translated\": \"Quelqu\'un s\'est évanoui.\"}]', 8, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in spiaggia o in piscina?\", \"Fantastico! Ecco 10 frasi comuni relative alla spiaggia o alla piscina, insieme alle traduzioni in francese:\"]', '[\"Nuoto\", \"Abbronzatura\", \"Sport sulla spiaggia\"]', 'it', '[\"Per il momento, potrebbe gentilmente indicarmi il contesto dell’evento o della festa locale a cui parteciperà, ad esempio una festa culturale, una festa del cibo o una festa musicale? Fornisca il contesto.\", \"Indichi le attività a cui parteciperà.\"]', '[\"Ha in mente una situazione specifica? Si senta libero di chiedere.\", \"Descriva la situazione che ha in mente.\"]', '[{\"original\": \"Guarda! Le onde laggiù sono davvero grandi.\", \"translated\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\"}, {\"original\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\", \"translated\": \"N\'oubliez pas d\'appliquer de la crème solaire, les rayons UV sont très intenses ici.\"}, {\"original\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\", \"translated\": \"Le sable de cette plage est si fin qu\'on a l\'impression de marcher sur du coton.\"}, {\"original\": \"Che ne dici di giocare a pallavolo in spiaggia?\", \"translated\": \"Et si on jouait au volley-ball sur la plage ?\"}, {\"original\": \"Le barche a vela in lontananza sembrano bellissime.\", \"translated\": \"Les voiliers au loin sont magnifiques.\"}, {\"original\": \"L\'acqua qui è così trasparente che si riescono persino a vedere i pesci.\", \"translated\": \"L\'eau est si claire ici qu\'on peut même voir les poissons.\"}, {\"original\": \"Andiamo a cercare delle conchiglie.\", \"translated\": \"Allons chercher des coquillages.\"}, {\"original\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\", \"translated\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\"}, {\"original\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\", \"translated\": \"J\'ai entendu dire que les fruits de mer sont très frais ici, allons en goûter.\"}, {\"original\": \"La marea sta salendo, dirigiamoci verso la riva.\", \"translated\": \"La marée monte, dirigeons-nous vers la rive.\"}]', 9, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare durante eventi e festival locali?\", \"Fantastico! Ecco 10 frasi comuni relative a eventi e festival locali, insieme alle rispettive traduzioni in francese:\"]', '[\"Partecipare a eventi\", \"Celebrare festival\", \"Apprendere la cultura\"]', 'it', '[\"Per ora, potrebbe indicarmi il contesto dell’evento o del festival locale a cui parteciperà, ad esempio Halloween, un concerto, una festa tra amici o qualcos’altro? La preghiamo di specificare il contesto.\", \"La preghiamo di descrivere le attività che ha in mente.\"]', '[\"Ha in mente una situazione specifica? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Ci sono eventi oggi?\", \"translated\": \"Y a-t-il des événements aujourd\'hui ?\"}, {\"original\": \"C\'è qualcosa di speciale in questo festival?\", \"translated\": \"Y a-t-il quelque chose de particulier à propos de ce festival ?\"}, {\"original\": \"Dove si tiene la celebrazione?\", \"translated\": \"Où se déroule la célébration ?\"}, {\"original\": \"Come posso acquistare i biglietti?\", \"translated\": \"Comment puis-je acheter des billets ?\"}, {\"original\": \"A che ora inizia lo spettacolo?\", \"translated\": \"À quelle heure commence la représentation ?\"}, {\"original\": \"Quali sono i cibi tradizionali?\", \"translated\": \"Quels sont les plats traditionnels ?\"}, {\"original\": \"Qui è davvero animato.\", \"translated\": \"C\'est vraiment animé ici.\"}, {\"original\": \"Ci sono attività popolari?\", \"translated\": \"Y a-t-il des activités populaires ?\"}, {\"original\": \"Buone feste!\", \"translated\": \"Joyeuses fêtes !\"}, {\"original\": \"A che ora termina l\'evento?\", \"translated\": \"À quelle heure se termine l\'événement ?\"}]', 10, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un museo o in una galleria d\'arte?\", \"Fantastico! Ecco 10 frasi comuni relative a un museo o a una galleria d\'arte, insieme alle rispettive traduzioni in francese:\"]', '[\"Visita\", \"Tour guidato\", \"Acquisto di biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere un manuale introduttivo, frasi relative a una mappa concettuale, frasi per commentare un\'esposizione? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"Quel est le montant des frais d\'entrée ?\"}, {\"original\": \"Avete guide audio?\", \"translated\": \"Proposez-vous des guides audio ?\"}, {\"original\": \"Chi ha creato quest\'opera d\'arte?\", \"translated\": \"Qui est l\'auteur de cette œuvre ?\"}, {\"original\": \"Dove si trova il pezzo più prezioso del museo?\", \"translated\": \"Où se trouve la pièce la plus précieuse du musée ?\"}, {\"original\": \"È consentito fare fotografie?\", \"translated\": \"La photographie est-elle autorisée ?\"}, {\"original\": \"Ci sono delle mostre speciali qui?\", \"translated\": \"Y a-t-il des expositions spéciales ici ?\"}, {\"original\": \"Quanto tempo richiede la visita?\", \"translated\": \"Combien de temps dure la visite ?\"}, {\"original\": \"Potreste darci una breve introduzione?\", \"translated\": \"Pourriez-vous nous en faire une présentation ?\"}, {\"original\": \"Queste opere sono davvero squisite.\", \"translated\": \"Ces œuvres sont véritablement exquises.\"}, {\"original\": \"Dove si trova il negozio dei souvenir?\", \"translated\": \"Où se trouve la boutique de souvenirs ?\"}]', 11, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare nei caffè?\", \"Fantastico! Ecco 10 frasi comuni relative ai caffè, insieme alle rispettive traduzioni in francese:\"]', '[\"Ordinare un caffè\", \"Riposare\", \"Socializzare\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il menu, bevande fredde o calde, altri prodotti? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Prenderò un caffè latte, per favore.\", \"translated\": \"Je prendrai un latte, s’il vous plaît.\"}, {\"original\": \"Avete il Wi-Fi?\", \"translated\": \"Avez-vous le Wi-Fi ?\"}, {\"original\": \"Potrei vedere il menu, per favore?\", \"translated\": \"Pourrais-je voir la carte, s’il vous plaît ?\"}, {\"original\": \"Sono ammesse le ricariche?\", \"translated\": \"Les recharges sont-elles autorisées ?\"}, {\"original\": \"Il mio caffè è pronto?\", \"translated\": \"Mon café est-il prêt ?\"}, {\"original\": \"Per quanto tempo posso stare seduto qui?\", \"translated\": \"Combien de temps puis-je rester assis ici ?\"}, {\"original\": \"Potrebbe fare una foto per noi?\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"Dov\'è il bagno?\", \"translated\": \"Où sont les toilettes ?\"}, {\"original\": \"Il conto, per favore. Grazie.\", \"translated\": \"L’addition, s’il vous plaît. Merci.\"}, {\"original\": \"Ha davvero un ottimo sapore.\", \"translated\": \"C’est vraiment délicieux.\"}]', 12, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare al ristorante?\", \"Fantastico! Ecco 10 frasi comuni relative al ristorante, insieme alle rispettive traduzioni in tedesco:\"]', '[\"Ristorazione\", \"Ordinazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio ordinare bevande, presentare un reclamo o chiedere informazioni sugli ingredienti? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\", \"translated\": \"Entschuldigung, wie lange dauert es noch bis zu unserem Essen?\"}, {\"original\": \"Un tavolo per due, per favore.\", \"translated\": \"Ein Tisch für zwei Personen, bitte.\"}, {\"original\": \"Potremmo vedere il menu, per favore?\", \"translated\": \"Könnten wir bitte die Speisekarte sehen?\"}, {\"original\": \"Avete dei piatti tipici da consigliarci?\", \"translated\": \"Haben Sie empfehlenswerte Hausgerichte?\"}, {\"original\": \"Vorrei ordinare questo e quest’altro.\", \"translated\": \"Ich möchte dies hier und das hier bestellen.\"}, {\"original\": \"Un bicchiere d’acqua, per favore. Grazie.\", \"translated\": \"Ein Glas Wasser, bitte. Danke.\"}, {\"original\": \"Il conto, per favore.\", \"translated\": \"Die Rechnung, bitte.\"}, {\"original\": \"Posso pagare con carta di credito?\", \"translated\": \"Kann ich mit Kreditkarte bezahlen?\"}, {\"original\": \"Potrebbe confezionarmelo da asporto, per favore?\", \"translated\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\"}, {\"original\": \"Il cibo era delizioso, grazie.\", \"translated\": \"Das Essen war köstlich, vielen Dank.\"}]', 1, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un hotel?\", \"Fantastico! Ecco 10 frasi comuni relative all\'hotel, insieme alle rispettive traduzioni in tedesco:\"]', '[\"Check-in\", \"Check-out\", \"Servizio in camera\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio la posizione della camera, altri servizi dell\'hotel o il check-out? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Salve, ho una prenotazione. Ecco il mio passaporto.\", \"translated\": \"Hallo, ich habe eine Reservierung. Hier ist mein Pass.\"}, {\"original\": \"Avete camere disponibili?\", \"translated\": \"Haben Sie noch freie Zimmer?\"}, {\"original\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\", \"translated\": \"Entschuldigung, verfügt das Hotel über ein Fitnessstudio oder einen Waschraum?\"}, {\"original\": \"A che ora inizia la colazione?\", \"translated\": \"Wann beginnt das Frühstück?\"}, {\"original\": \"Potrei avere la chiave della mia stanza, per favore?\", \"translated\": \"Könnte ich bitte den Zimmerschlüssel haben?\"}, {\"original\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\", \"translated\": \"Könnten Sie mir beim Tragen meines Gepäcks ins Zimmer helfen?\"}, {\"original\": \"Come posso chiamare il servizio in camera?\", \"translated\": \"Wie rufe ich den Zimmerservice an?\"}, {\"original\": \"A che ora è il check-out?\", \"translated\": \"Wann ist der Check-out?\"}, {\"original\": \"Potrebbe rilasciarmi una ricevuta/fattura?\", \"translated\": \"Könnten Sie mir bitte eine Quittung / Rechnung ausstellen?\"}, {\"original\": \"Posso lasciare qui i miei bagagli?\", \"translated\": \"Darf ich mein Gepäck hier lassen?\"}]', 2, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in aeroporto?\", \"Fantastico! Ecco 10 frasi comuni relative all’aeroporto, insieme alle traduzioni in tedesco:\"]', '[\"Check-in\", \"Imbarco\", \"Controllo bagagli\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio il check-in, il ritiro bagagli o il servizio di noleggio auto? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dov\'è il banco del check-in?\", \"translated\": \"Wo ist der Check-in-Schalter?\"}, {\"original\": \"Vorrei un posto vicino al finestrino, per favore.\", \"translated\": \"Ich hätte gerne einen Fensterplatz, bitte.\"}, {\"original\": \"Questo volo è in ritardo?\", \"translated\": \"Ist dieser Flug verspätet?\"}, {\"original\": \"Devo registrare questo bagaglio.\", \"translated\": \"Ich muss dieses Gepäck aufgeben.\"}, {\"original\": \"Dov\'è l\'ingresso per l\'imbarco?\", \"translated\": \"Wo ist das Boarding-Gate?\"}, {\"original\": \"L\'aeroplano sta per decollare.\", \"translated\": \"Das Flugzeug startet gleich.\"}, {\"original\": \"Devo estrarre il mio laptop e il power bank?\", \"translated\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\"}, {\"original\": \"Dov\'è il negozio duty-free?\", \"translated\": \"Wo ist der Duty-free-Shop?\"}, {\"original\": \"Non riesco a trovare la mia valigia.\", \"translated\": \"Ich kann meinen Koffer nicht finden.\"}, {\"original\": \"Offrite un servizio di sedia a rotelle?\", \"translated\": \"Bieten Sie einen Rollstuhlservice an?\"}]', 3, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei trasporti pubblici?\", \"Fantastico! Ecco 10 frasi comuni relative ai trasporti pubblici, insieme alle rispettive traduzioni in tedesco:\"]', '[\"Prendere l\'autobus o la metropolitana\", \"Acquistare biglietti\", \"Effettuare un trasferimento\"]', 'it', '[\"Per il momento, ha in mente una situazione specifica, ad esempio chiedere dove si trova la fermata dell’autobus, il prezzo del biglietto o come scendere? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Questo autobus va al capolinea?\", \"translated\": \"Fährt dieser Bus zum Terminal?\"}, {\"original\": \"Qual è la prossima fermata?\", \"translated\": \"Was ist die nächste Haltestelle?\"}, {\"original\": \"Dove posso comprare un biglietto?\", \"translated\": \"Wo kann ich ein Ticket kaufen?\"}, {\"original\": \"Un biglietto per XX, per favore.\", \"translated\": \"Ein Ticket nach XX, bitte.\"}, {\"original\": \"Devo cambiare mezzo?\", \"translated\": \"Muss ich umsteigen?\"}, {\"original\": \"Quanto manca al prossimo treno della metropolitana?\", \"translated\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\"}, {\"original\": \"Scusi, mi lasci passare, per favore.\", \"translated\": \"Entschuldigung, bitte lassen Sie mich durch.\"}, {\"original\": \"Questo posto è occupato?\", \"translated\": \"Ist dieser Platz bereits besetzt?\"}, {\"original\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\", \"translated\": \"Entschuldigung, wo kann ich umsteigen, um mit der Linie 2 nach XX zu gelangen?\"}, {\"original\": \"Come arrivo a XX?\", \"translated\": \"Wie komme ich nach XX?\"}]', 4, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nelle attrazioni turistiche?\", \"Fantastico! Ecco 10 frasi comuni relative alle attrazioni turistiche, insieme alle rispettive traduzioni in tedesco:\"]', '[\"Visita turistica\", \"Scattare fotografie\", \"Acquistare biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il prezzo dei biglietti, trovare un parcheggio o richiedere un servizio di guida turistica? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"Sono disponibili biglietti per studenti?\", \"translated\": \"Gibt es ermäßigte Eintrittskarten für Schüler?\"}, {\"original\": \"A che ora apre la attrazione?\", \"translated\": \"Wann öffnet die Sehenswürdigkeit?\"}, {\"original\": \"Quali sono le cose divertenti da fare qui?\", \"translated\": \"Was gibt es hier Spannendes zu tun?\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"Dove si trova l\'autobus per i tour turistici?\", \"translated\": \"Wo befindet sich der Sightseeing-Bus?\"}, {\"original\": \"Dove si trova il bagno?\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"Dove si trova il punto migliore per osservare?\", \"translated\": \"Wo ist der beste Aussichtspunkt?\"}, {\"original\": \"Il panorama qui è bellissimo.\", \"translated\": \"Die Landschaft hier ist wunderschön.\"}, {\"original\": \"È disponibile un tour guidato?\", \"translated\": \"Gibt es eine Führung?\"}]', 5, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare per un taxi o un servizio taxi?\", \"Fantastico! Ecco 10 frasi comuni relative al taxi o a un servizio taxi, insieme alle rispettive traduzioni in tedesco:\"]', '[\"Prendere un taxi\", \"Indicare la destinazione\", \"Pagamento\"]', 'it', '[\"Per ora, cosa vorrebbe fare principalmente in questo momento? Ad esempio chiedere la destinazione, il costo o una ricevuta: si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dove posso prendere un taxi?\", \"translated\": \"Wo kann ich ein Taxi bekommen?\"}, {\"original\": \"Mi porti a questo indirizzo, per favore.\", \"translated\": \"Bitte fahren Sie mich zu dieser Adresse.\"}, {\"original\": \"Quanto costerà all\'incirca?\", \"translated\": \"Wie viel kostet es ungefähr?\"}, {\"original\": \"Potrebbe usare il tassametro, per favore?\", \"translated\": \"Könnten Sie bitte den Taxameter benutzen?\"}, {\"original\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\", \"translated\": \"Bitte fahren Sie etwas schneller, ich habe es eilig.\"}, {\"original\": \"Si fermi qui, per favore.\", \"translated\": \"Bitte halten Sie hier an.\"}, {\"original\": \"Accetta carte di credito o pagamenti mobili?\", \"translated\": \"Akzeptieren Sie Karten oder mobile Zahlungen?\"}, {\"original\": \"Potrei avere lo scontrino, per favore?\", \"translated\": \"Könnte ich bitte eine Quittung haben?\"}, {\"original\": \"Grazie, autista.\", \"translated\": \"Vielen Dank, Fahrer.\"}, {\"original\": \"Quanto manca ancora?\", \"translated\": \"Wie weit ist es noch?\"}]', 6, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in farmacia?\", \"Fantastico! Ecco 10 frasi comuni relative alla farmacia, insieme alle rispettive traduzioni in tedesco:\"]', '[\"Acquisto di Farmaci\", \"Consultazione\", \"Pagamento\"]', 'it', '[\"Per il momento, ha in mente una situazione specifica, ad esempio chiedere indicazioni sull’assunzione di un farmaco, frasi relative all’uso dell’assicurazione sanitaria o alla durata della terapia? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Ha dei farmaci per il raffreddore?\", \"translated\": \"Haben Sie Medikamente gegen Erkältung?\"}, {\"original\": \"Come devo assumere questo farmaco?\", \"translated\": \"Wie soll ich dieses Medikament einnehmen?\"}, {\"original\": \"Ha degli antidolorifici?\", \"translated\": \"Haben Sie Schmerzmittel?\"}, {\"original\": \"È incluso un foglietto illustrativo?\", \"translated\": \"Gibt es eine Gebrauchsanweisung?\"}, {\"original\": \"Questo farmaco ha effetti collaterali?\", \"translated\": \"Hat dieses Medikament Nebenwirkungen?\"}, {\"original\": \"Posso usare la mia tessera sanitaria?\", \"translated\": \"Kann ich meine Krankenversicherungskarte verwenden?\"}, {\"original\": \"Potrei avere una confezione di cerotti, per favore?\", \"translated\": \"Könnte ich bitte eine Packung Pflaster haben?\"}, {\"original\": \"Ha dei farmaci antipiretici?\", \"translated\": \"Haben Sie Fiebersenkende Mittel?\"}, {\"original\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\", \"translated\": \"Ich habe mir leicht die Haut aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\"}, {\"original\": \"A che ora chiude?\", \"translated\": \"Wann schließen Sie?\"}]', 7, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei servizi di emergenza?\", \"Fantastico! Ecco 10 frasi comuni relative ai servizi di emergenza, insieme alle rispettive traduzioni in tedesco:\"]', '[\"Chiamare la polizia\", \"Pronto soccorso\", \"Chiedere aiuto\"]', 'it', '[\"Per il momento, ha in mente una situazione di emergenza specifica, ad esempio incendio, ferito e bisogno di aiuto, chiamata d\'emergenza? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\", \"translated\": \"Bitte helfen Sie mir, einen Krankenwagen zu rufen.\"}, {\"original\": \"Dov\'è l\'ospedale?\", \"translated\": \"Wo ist das Krankenhaus?\"}, {\"original\": \"Qualcuno è ferito.\", \"translated\": \"Jemand ist verletzt.\"}, {\"original\": \"Per favore, mi aiuti.\", \"translated\": \"Bitte helfen Sie mir.\"}, {\"original\": \"Dov\'è la stazione di polizia?\", \"translated\": \"Wo ist die Polizeistation?\"}, {\"original\": \"Ho perso i miei oggetti.\", \"translated\": \"Ich habe meine Sachen verloren.\"}, {\"original\": \"Qual è il numero del corpo dei vigili del fuoco?\", \"translated\": \"Wie lautet die Notrufnummer für die Feuerwehr?\"}, {\"original\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\", \"translated\": \"Ich habe meinen Pass verloren. Wissen Sie, wo die nächste Polizeistation ist?\"}, {\"original\": \"C\'è un\'uscita di emergenza?\", \"translated\": \"Gibt es einen Notausgang?\"}, {\"original\": \"Qualcuno è svenuto.\", \"translated\": \"Jemand ist in Ohnmacht gefallen.\"}]', 8, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in spiaggia o in piscina?\", \"Fantastico! Ecco 10 frasi comuni relative alla spiaggia o alla piscina, insieme alle rispettive traduzioni in tedesco:\"]', '[\"Nuoto\", \"Abbronzatura\", \"Sport sulla spiaggia\"]', 'it', '[\"Per il momento, potrebbe indicarmi il contesto dell\'evento o della festa locale a cui parteciperà, ad esempio una festa culturale, una festa del cibo o una festa musicale? La preghiamo di specificare il contesto.\", \"La preghiamo di indicare le attività a cui parteciperà.\"]', '[\"Ha in mente una situazione specifica? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Guarda! Le onde laggiù sono davvero grandi.\", \"translated\": \"Schau! Die Wellen dort drüben sind wirklich groß.\"}, {\"original\": \"Ricordati di applicare la crema solare, qui i raggi UV sono molto intensi.\", \"translated\": \"Vergiss nicht, Sonnencreme aufzutragen – die UV-Strahlen sind hier sehr stark.\"}, {\"original\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\", \"translated\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle gehen.\"}, {\"original\": \"Che ne dici di giocare a pallavolo in spiaggia?\", \"translated\": \"Wie wäre es mit einer Partie Volleyball am Strand?\"}, {\"original\": \"Le barche a vela in lontananza sembrano bellissime.\", \"translated\": \"Die Segelboote in der Ferne sehen wunderschön aus.\"}, {\"original\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\", \"translated\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\"}, {\"original\": \"Andiamo a cercare delle conchiglie.\", \"translated\": \"Lass uns ein paar Muscheln suchen.\"}, {\"original\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\", \"translated\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\"}, {\"original\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\", \"translated\": \"Ich habe gehört, dass die Meeresfrüchte hier sehr frisch sind – lass uns welche probieren.\"}, {\"original\": \"La marea sta salendo, dirigiamoci verso la riva.\", \"translated\": \"Die Flut kommt herein, gehen wir Richtung Ufer.\"}]', 9, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare durante eventi e festival locali?\", \"Fantastico! Ecco 10 frasi comuni relative a eventi e festival locali, insieme alle rispettive traduzioni in tedesco:\"]', '[\"Partecipare a eventi\", \"Celebrare festival\", \"Apprendere la cultura\"]', 'it', '[\"Per il momento, potrebbe indicarmi il contesto dell’evento o del festival locale a cui parteciperà, ad esempio Halloween, un concerto, una festa tra amici o qualcos’altro? La preghiamo di specificare il contesto.\", \"La preghiamo di descrivere le attività che ha in mente.\"]', '[\"Ha in mente una situazione specifica? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Ci sono eventi oggi?\", \"translated\": \"Gibt es heute irgendwelche Veranstaltungen?\"}, {\"original\": \"C\'è qualcosa di speciale in questo festival?\", \"translated\": \"Gibt es bei diesem Fest etwas Besonderes?\"}, {\"original\": \"Dove si tiene la celebrazione?\", \"translated\": \"Wo findet die Feier statt?\"}, {\"original\": \"Come posso acquistare i biglietti?\", \"translated\": \"Wie kann ich Tickets kaufen?\"}, {\"original\": \"A che ora inizia lo spettacolo?\", \"translated\": \"Wann beginnt die Aufführung?\"}, {\"original\": \"Quali sono i cibi tradizionali?\", \"translated\": \"Welche traditionellen Speisen gibt es?\"}, {\"original\": \"Qui è davvero animato.\", \"translated\": \"Es ist hier wirklich lebhaft.\"}, {\"original\": \"Ci sono attività popolari?\", \"translated\": \"Gibt es Volksaktivitäten?\"}, {\"original\": \"Buone feste!\", \"translated\": \"Frohe Feiertage!\"}, {\"original\": \"A che ora termina l\'evento?\", \"translated\": \"Wann endet die Veranstaltung?\"}]', 10, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un museo o in una galleria d\'arte?\", \"Fantastico! Ecco 10 frasi comuni relative a un museo o a una galleria d\'arte, insieme alle rispettive traduzioni in tedesco:\"]', '[\"Visita\", \"Tour guidato\", \"Acquisto di biglietti\"]', 'it', '[\"Per il momento, ha in mente una situazione specifica, ad esempio chiedere un manuale introduttivo, frasi relative a una mappa concettuale, frasi per commentare un\'esposizione? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"Wie hoch ist der Eintrittspreis?\"}, {\"original\": \"Avete guide audio?\", \"translated\": \"Bieten Sie Audioführungen an?\"}, {\"original\": \"Chi ha creato quest\'opera d\'arte?\", \"translated\": \"Wer hat dieses Kunstwerk geschaffen?\"}, {\"original\": \"Dove si trova il pezzo più prezioso del museo?\", \"translated\": \"Wo befindet sich das wertvollste Stück des Museums?\"}, {\"original\": \"È consentito fare fotografie?\", \"translated\": \"Ist das Fotografieren erlaubt?\"}, {\"original\": \"Ci sono delle mostre speciali qui?\", \"translated\": \"Gibt es hier besondere Ausstellungen?\"}, {\"original\": \"Quanto tempo richiede la visita?\", \"translated\": \"Wie lange dauert der Besuch?\"}, {\"original\": \"Potreste darci una breve introduzione?\", \"translated\": \"Könnten Sie uns bitte eine Einführung geben?\"}, {\"original\": \"Queste opere sono davvero squisite.\", \"translated\": \"Diese Werke sind wirklich exquisit.\"}, {\"original\": \"Dove si trova il negozio dei souvenir?\", \"translated\": \"Wo befindet sich der Souvenirladen?\"}]', 11, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare nei caffè?\", \"Fantastico! Ecco 10 frasi comuni relative ai caffè, insieme alle rispettive traduzioni in tedesco:\"]', '[\"Ordinare un caffè\", \"Riposare\", \"Socializzare\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il menù, del ghiaccio o bevande calde, altri prodotti? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Prenderò un caffè latte, per favore.\", \"translated\": \"Ich hätte gerne einen Latte, bitte.\"}, {\"original\": \"Avete il Wi-Fi?\", \"translated\": \"Haben Sie WLAN?\"}, {\"original\": \"Potrei vedere il menu, per favore?\", \"translated\": \"Könnte ich bitte die Speisekarte sehen?\"}, {\"original\": \"Sono ammessi i rabbocchi?\", \"translated\": \"Darf man nachfüllen?\"}, {\"original\": \"Il mio caffè è pronto?\", \"translated\": \"Ist mein Kaffee fertig?\"}, {\"original\": \"Per quanto tempo posso stare seduto qui?\", \"translated\": \"Wie lange darf ich hier sitzen?\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"Könnten Sie bitte ein Foto von uns machen?\"}, {\"original\": \"Dov\'è il bagno?\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"Il conto, per favore. Grazie.\", \"translated\": \"Die Rechnung, bitte. Vielen Dank.\"}, {\"original\": \"Ha davvero un ottimo sapore.\", \"translated\": \"Es schmeckt wirklich gut.\"}]', 12, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare in un ristorante?\", \"Fantastico! Ecco 10 frasi comuni relative al ristorante, insieme alle traduzioni in spagnolo:\"]', '[\"Ristorazione\", \"Ordinazione\", \"Pagamento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio ordinare bevande, presentare un reclamo o chiedere informazioni sugli ingredienti? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\", \"translated\": \"Perdón, ¿cuánto tiempo más tardará nuestra comida?\"}, {\"original\": \"Un tavolo per due, per favore.\", \"translated\": \"Una mesa para dos, por favor.\"}, {\"original\": \"Potremmo vedere il menù, per favore?\", \"translated\": \"¿Podríamos ver el menú, por favor?\"}, {\"original\": \"Avete dei piatti tipici da consigliarci?\", \"translated\": \"¿Tienen algún plato especial que nos recomienden?\"}, {\"original\": \"Vorrei ordinare questo e quest’altro.\", \"translated\": \"Quisiera pedir esto y esto.\"}, {\"original\": \"Un bicchiere d’acqua, per favore. Grazie.\", \"translated\": \"Un vaso de agua, por favor. Gracias.\"}, {\"original\": \"Il conto, per favore.\", \"translated\": \"La cuenta, por favor.\"}, {\"original\": \"Posso pagare con carta di credito?\", \"translated\": \"¿Puedo pagar con tarjeta de crédito?\"}, {\"original\": \"Potrebbe impacchettare questo da portare via, per favore?\", \"translated\": \"¿Podrían empaquetar esto para llevar, por favor?\"}, {\"original\": \"Il cibo era delizioso, grazie.\", \"translated\": \"La comida estaba deliciosa, gracias.\"}]', 1, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un hotel?\", \"Fantastico! Ecco 10 frasi comuni relative all\'hotel, insieme alle traduzioni in spagnolo:\"]', '[\"Check-in\", \"Check-out\", \"Servizio in camera\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio la posizione della camera, altri servizi dell\'hotel o il check-out? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Salve, ho una prenotazione, ecco il mio passaporto.\", \"translated\": \"Hola, tengo una reserva. Aquí tiene mi pasaporte.\"}, {\"original\": \"Avete camere disponibili?\", \"translated\": \"¿Tienen habitaciones disponibles?\"}, {\"original\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\", \"translated\": \"Disculpe, ¿tiene el hotel gimnasio o lavandería?\"}, {\"original\": \"A che ora inizia la colazione?\", \"translated\": \"¿A qué hora comienza el desayuno?\"}, {\"original\": \"Potrei avere la chiave della mia stanza, per favore?\", \"translated\": \"¿Podría darme la llave de la habitación, por favor?\"}, {\"original\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\", \"translated\": \"¿Podría ayudarme a llevar mi equipaje a la habitación?\"}, {\"original\": \"Come posso chiamare il servizio in camera?\", \"translated\": \"¿Cómo llamo al servicio de habitaciones?\"}, {\"original\": \"A che ora è il check-out?\", \"translated\": \"¿A qué hora es la salida?\"}, {\"original\": \"Potrebbe rilasciarmi una ricevuta/fattura?\", \"translated\": \"¿Podría emitirme un recibo/factura?\"}, {\"original\": \"Posso lasciare qui i miei bagagli?\", \"translated\": \"¿Puedo dejar aquí mi equipaje?\"}]', 2, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in aeroporto?\", \"Fantastico! Ecco 10 frasi comuni relative all’aeroporto, insieme alle traduzioni in spagnolo:\"]', '[\"Check-in\", \"Imbarco\", \"Controllo bagagli\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio il check-in, il ritiro bagagli o il servizio di noleggio auto? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dov\'è il banco del check-in?\", \"translated\": \"¿Dónde está el mostrador de facturación?\"}, {\"original\": \"Vorrei un posto vicino al finestrino, per favore.\", \"translated\": \"Me gustaría un asiento junto a la ventana, por favor.\"}, {\"original\": \"Questo volo è in ritardo?\", \"translated\": \"¿Este vuelo tiene retraso?\"}, {\"original\": \"Devo registrare questo bagaglio.\", \"translated\": \"Necesito facturar este equipaje.\"}, {\"original\": \"Dov\'è l\'ingresso per l\'imbarco?\", \"translated\": \"¿Dónde está la puerta de embarque?\"}, {\"original\": \"L\'aeroplano sta per decollare.\", \"translated\": \"El avión está a punto de despegar.\"}, {\"original\": \"Devo estrarre il mio laptop e la power bank?\", \"translated\": \"¿Debo sacar mi ordenador portátil y mi banco de energía?\"}, {\"original\": \"Dov\'è il negozio duty-free?\", \"translated\": \"¿Dónde está la tienda libre de impuestos?\"}, {\"original\": \"Non riesco a trovare la mia valigia.\", \"translated\": \"No encuentro mi maleta.\"}, {\"original\": \"Offrite un servizio di sedia a rotelle?\", \"translated\": \"¿Ofrecen servicio de sillas de ruedas?\"}]', 3, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei trasporti pubblici?\", \"Fantastico! Ecco 10 frasi comuni relative ai trasporti pubblici, insieme alle rispettive traduzioni in spagnolo:\"]', '[\"Prendere l\'autobus o la metropolitana\", \"Acquistare biglietti\", \"Effettuare un trasferimento\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere dove si trova la fermata dell’autobus, il prezzo del biglietto o come scendere? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Questo autobus va al capolinea?\", \"translated\": \"¿Este autobús va a la terminal?\"}, {\"original\": \"Qual è la prossima fermata?\", \"translated\": \"¿Cuál es la próxima parada?\"}, {\"original\": \"Dove posso comprare un biglietto?\", \"translated\": \"¿Dónde puedo comprar un billete?\"}, {\"original\": \"Un biglietto per XX, per favore.\", \"translated\": \"Un billete para XX, por favor.\"}, {\"original\": \"Devo cambiare mezzo?\", \"translated\": \"¿Tengo que hacer transbordo?\"}, {\"original\": \"Quanto manca al prossimo treno della metropolitana?\", \"translated\": \"¿Cuánto tiempo falta para el próximo tren del metro?\"}, {\"original\": \"Scusi, mi lasci passare, per favore.\", \"translated\": \"Disculpe, permítame pasar, por favor.\"}, {\"original\": \"Questo posto è occupato?\", \"translated\": \"¿Esta plaza está ocupada?\"}, {\"original\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\", \"translated\": \"Disculpe, ¿dónde puedo hacer transbordo a la línea 2 para llegar a XX?\"}, {\"original\": \"Come arrivo a XX?\", \"translated\": \"¿Cómo llego a XX?\"}]', 4, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nelle attrazioni turistiche?\", \"Fantastico! Ecco 10 frasi comuni relative alle attrazioni turistiche, insieme alle traduzioni in spagnolo:\"]', '[\"Visita turistica\", \"Scattare foto\", \"Acquistare biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il prezzo dei biglietti, trovare un parcheggio o richiedere un servizio di guida turistica? Chieda pure.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"Sono disponibili biglietti per studenti?\", \"translated\": \"¿Hay entradas para estudiantes disponibles?\"}, {\"original\": \"A che ora apre la attrazione?\", \"translated\": \"¿A qué hora abre la atracción?\"}, {\"original\": \"Quali sono le cose divertenti da fare qui?\", \"translated\": \"¿Qué cosas divertidas se pueden hacer aquí?\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"¿Podría hacernos una foto?\"}, {\"original\": \"Dove si trova l\'autobus turistico?\", \"translated\": \"¿Dónde está el autobús turístico?\"}, {\"original\": \"Dove si trova il bagno?\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"Qual è il miglior punto panoramico?\", \"translated\": \"¿Cuál es el mejor lugar para observar?\"}, {\"original\": \"Il paesaggio qui è bellissimo.\", \"translated\": \"El paisaje aquí es hermoso.\"}, {\"original\": \"È disponibile un tour guidato?\", \"translated\": \"¿Hay visitas guiadas disponibles?\"}]', 5, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare per un taxi o un servizio taxi?\", \"Fantastico! Ecco 10 frasi comuni relative al taxi o a un servizio taxi, insieme alle rispettive traduzioni in spagnolo:\"]', '[\"Prendere un taxi\", \"Indicare la destinazione\", \"Pagamento\"]', 'it', '[\"Per ora, cosa vorrebbe fare principalmente in questo momento? Ad esempio chiedere la destinazione, il costo o una ricevuta: si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Dove posso prendere un taxi?\", \"translated\": \"¿Dónde puedo conseguir un taxi?\"}, {\"original\": \"Mi porti a questo indirizzo, per favore.\", \"translated\": \"Por favor, lléveme a esta dirección.\"}, {\"original\": \"Quanto costerà all\'incirca?\", \"translated\": \"¿Cuánto costará aproximadamente?\"}, {\"original\": \"Potrebbe usare il tassametro, per favore?\", \"translated\": \"¿Podría usar el taxímetro, por favor?\"}, {\"original\": \"Può guidare un po\' più velocemente, sono di fretta.\", \"translated\": \"Por favor, conduzca un poco más rápido, tengo prisa.\"}, {\"original\": \"Si fermi qui, per favore.\", \"translated\": \"Párese aquí, por favor.\"}, {\"original\": \"Accetta carte di credito o pagamenti mobili?\", \"translated\": \"¿Acepta tarjetas o pagos móviles?\"}, {\"original\": \"Potrei avere una ricevuta, per favore?\", \"translated\": \"¿Podría darme un recibo, por favor?\"}, {\"original\": \"Grazie, autista.\", \"translated\": \"Gracias, conductor.\"}, {\"original\": \"Quanto manca ancora?\", \"translated\": \"¿Cuánto falta todavía?\"}]', 6, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in farmacia?\", \"Fantastico! Ecco 10 frasi comuni relative alla farmacia, insieme alle rispettive traduzioni in spagnolo:\"]', '[\"Acquisto di Medicinali\", \"Consulenza\", \"Pagamento\"]', 'it', '[\"Per il momento, ha in mente una situazione specifica, ad esempio chiedere istruzioni sull’assunzione di un farmaco, frasi relative all’utilizzo dell’assicurazione sanitaria o alla durata della terapia? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Ha dei farmaci per il raffreddore?\", \"translated\": \"¿Tiene medicamento para el resfriado?\"}, {\"original\": \"Come devo assumere questo farmaco?\", \"translated\": \"¿Cómo debo tomar este medicamento?\"}, {\"original\": \"Ha degli antidolorifici?\", \"translated\": \"¿Tiene algún analgésico?\"}, {\"original\": \"È incluso un foglietto illustrativo?\", \"translated\": \"¿Hay un folleto con instrucciones?\"}, {\"original\": \"Questo farmaco ha effetti collaterali?\", \"translated\": \"¿Este medicamento tiene efectos secundarios?\"}, {\"original\": \"Posso utilizzare la mia tessera sanitaria?\", \"translated\": \"¿Puedo usar mi tarjeta de seguro médico?\"}, {\"original\": \"Potrei avere una confezione di cerotti, per favore?\", \"translated\": \"¿Podría darme una caja de tiritas, por favor?\"}, {\"original\": \"Ha dei farmaci per abbassare la febbre?\", \"translated\": \"¿Tiene algún antipirético?\"}, {\"original\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\", \"translated\": \"Tengo una pequeña herida superficial. ¿Tiene antiséptico y tiritas?\"}, {\"original\": \"A che ora chiude?\", \"translated\": \"¿A qué hora cierran?\"}]', 7, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare nei servizi di emergenza?\", \"Fantastico! Ecco 10 frasi comuni relative ai servizi di emergenza, insieme alle rispettive traduzioni in spagnolo:\"]', '[\"Chiamare la polizia\", \"Pronto soccorso\", \"Chiedere aiuto\"]', 'it', '[\"Per ora, ha in mente una situazione di emergenza specifica, ad esempio incendio, ferito e bisogno di aiuto, chiamata d\'emergenza? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\", \"translated\": \"Por favor, ayúdeme a llamar a una ambulancia.\"}, {\"original\": \"Dov\'è l\'ospedale?\", \"translated\": \"¿Dónde está el hospital?\"}, {\"original\": \"Qualcuno è ferito.\", \"translated\": \"Alguien resultó herido.\"}, {\"original\": \"Per favore, mi aiuti.\", \"translated\": \"Por favor, ayúdeme.\"}, {\"original\": \"Dov\'è la stazione di polizia?\", \"translated\": \"¿Dónde está la comisaría?\"}, {\"original\": \"Ho perso i miei effetti personali.\", \"translated\": \"He perdido mis pertenencias.\"}, {\"original\": \"Qual è il numero del corpo dei vigili del fuoco?\", \"translated\": \"¿Cuál es el número de los bomberos?\"}, {\"original\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\", \"translated\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría más cercana?\"}, {\"original\": \"C\'è un\'uscita di emergenza?\", \"translated\": \"¿Hay una salida de emergencia?\"}, {\"original\": \"Qualcuno è svenuto.\", \"translated\": \"Alguien ha desmayado.\"}]', 8, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potresti fornirmi 10 frasi comuni che posso usare in spiaggia o a bordo piscina?\", \"Fantastico! Ecco 10 frasi comuni relative alla spiaggia o al bordo piscina, insieme alle traduzioni in spagnolo:\"]', '[\"Nuoto\", \"Abbronzatura\", \"Sport sulla spiaggia\"]', 'it', '[\"Per ora, potresti gentilmente indicarmi il contesto dell\'evento o della festa locale a cui parteciperai, ad esempio una festa culturale, una festa del cibo o una festa musicale? Fornisci il contesto.\", \"Indica le attività a cui parteciperai.\"]', '[\"Hai in mente una situazione specifica? Chiedi pure liberamente.\", \"Descrivi la situazione che hai in mente.\"]', '[{\"original\": \"Guarda! Le onde laggiù sono davvero grandi.\", \"translated\": \"¡Mira! Las olas allí son realmente grandes.\"}, {\"original\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\", \"translated\": \"Recuerda aplicar protector solar; los rayos UV aquí son muy intensos.\"}, {\"original\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\", \"translated\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\"}, {\"original\": \"Che ne dici di giocare a pallavolo in spiaggia?\", \"translated\": \"¿Qué tal jugar voleibol en la playa?\"}, {\"original\": \"Le barche a vela in lontananza sono bellissime.\", \"translated\": \"Los veleros a lo lejos se ven hermosos.\"}, {\"original\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\", \"translated\": \"El agua aquí es tan transparente que incluso puedes ver los peces.\"}, {\"original\": \"Andiamo a cercare delle conchiglie.\", \"translated\": \"Vamos a buscar conchas marinas.\"}, {\"original\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\", \"translated\": \"Pasear por la playa al atardecer debe ser muy romántico.\"}, {\"original\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\", \"translated\": \"He oído decir que los mariscos aquí son muy frescos; vayamos a probarlos.\"}, {\"original\": \"La marea sta salendo, dirigiamoci verso la riva.\", \"translated\": \"La marea está subiendo; volvamos hacia la orilla.\"}]', 9, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare durante eventi e festival locali?\", \"Fantastico! Ecco 10 frasi comuni relative a eventi e festival locali, insieme alle rispettive traduzioni in spagnolo:\"]', '[\"Partecipare a eventi\", \"Celebrare festival\", \"Apprendere la cultura\"]', 'it', '[\"Per ora, potrebbe gentilmente indicarmi il contesto dell\'evento o del festival locale a cui parteciperà, ad esempio Halloween, un concerto, una festa tra amici o qualcos\'altro? La prego di specificare il contesto.\", \"La prego di descrivere le attività che ha in mente.\"]', '[\"Ha in mente una situazione specifica? Si senta libero di chiedere.\", \"La prego di descrivere la situazione che ha in mente.\"]', '[{\"original\": \"Ci sono eventi oggi?\", \"translated\": \"¿Hay algún evento hoy?\"}, {\"original\": \"C\'è qualcosa di speciale in questo festival?\", \"translated\": \"¿Hay algo especial en este festival?\"}, {\"original\": \"Dove si tiene la celebrazione?\", \"translated\": \"¿Dónde se celebra la festividad?\"}, {\"original\": \"Come posso acquistare i biglietti?\", \"translated\": \"¿Cómo puedo comprar entradas?\"}, {\"original\": \"A che ora inizia lo spettacolo?\", \"translated\": \"¿A qué hora empieza la actuación?\"}, {\"original\": \"Quali sono i cibi tradizionali?\", \"translated\": \"¿Qué comida tradicional hay?\"}, {\"original\": \"Qui è davvero animato.\", \"translated\": \"Aquí hay mucha animación.\"}, {\"original\": \"Ci sono attività popolari?\", \"translated\": \"¿Hay alguna actividad popular?\"}, {\"original\": \"Buone feste!\", \"translated\": \"¡Felices fiestas!\"}, {\"original\": \"A che ora termina l\'evento?\", \"translated\": \"¿A qué hora termina el evento?\"}]', 10, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso utilizzare in un museo o in una galleria d\'arte?\", \"Fantastico! Ecco 10 frasi comuni relative a un museo o a una galleria d\'arte, insieme alle rispettive traduzioni in spagnolo:\"]', '[\"Visita\", \"Tour guidato\", \"Acquisto di biglietti\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere un manuale introduttivo, frasi relative a una mappa concettuale, frasi per commentare un\'esposizione? Si senta libero di chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Quanto costa il biglietto d\'ingresso?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"Avete guide audio?\", \"translated\": \"¿Tienen guías de audio?\"}, {\"original\": \"Chi ha creato quest\'opera d\'arte?\", \"translated\": \"¿Quién creó esta obra de arte?\"}, {\"original\": \"Dove si trova il pezzo più prezioso del museo?\", \"translated\": \"¿Dónde se encuentra la pieza más valiosa del museo?\"}, {\"original\": \"È consentito fare fotografie?\", \"translated\": \"¿Está permitida la fotografía?\"}, {\"original\": \"Ci sono delle mostre speciali qui?\", \"translated\": \"¿Hay alguna exposición especial aquí?\"}, {\"original\": \"Quanto tempo richiede la visita?\", \"translated\": \"¿Cuánto tiempo dura la visita?\"}, {\"original\": \"Potreste darci una breve introduzione?\", \"translated\": \"¿Podría darnos una introducción?\"}, {\"original\": \"Queste opere sono davvero squisite.\", \"translated\": \"Estas obras son verdaderamente exquisitas.\"}, {\"original\": \"Dove si trova il negozio dei souvenir?\", \"translated\": \"¿Dónde está la tienda de souvenirs?\"}]', 11, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potrebbe fornirmi 10 frasi comuni che posso usare nei bar?\", \"Fantastico! Ecco 10 frasi comuni relative ai bar, insieme alle traduzioni in spagnolo:\"]', '[\"Ordinare un caffè\", \"Riposare\", \"Socializzare\"]', 'it', '[\"Per ora, ha in mente una situazione specifica, ad esempio chiedere il menù, bevande ghiacciate o calde, altri prodotti? Non esiti a chiedere.\", \"La preghiamo di descrivere la situazione che ha in mente.\"]', NULL, '[{\"original\": \"Prenderò un caffè latte, per favore.\", \"translated\": \"Tomaré un latte, por favor.\"}, {\"original\": \"Avete il Wi-Fi?\", \"translated\": \"¿Tienen conexión Wi-Fi?\"}, {\"original\": \"Potrei vedere il menu, per favore?\", \"translated\": \"¿Podría ver el menú, por favor?\"}, {\"original\": \"Sono ammessi i rabbocchi?\", \"translated\": \"¿Se permiten recargas?\"}, {\"original\": \"Il mio caffè è pronto?\", \"translated\": \"¿Ya está listo mi café?\"}, {\"original\": \"Per quanto tempo posso stare seduto qui?\", \"translated\": \"¿Cuánto tiempo puedo quedarme aquí?\"}, {\"original\": \"Potrebbe scattarci una foto?\", \"translated\": \"¿Podría tomarnos una foto?\"}, {\"original\": \"Dov\'è il bagno?\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"Il conto, per favore. Grazie.\", \"translated\": \"La cuenta, por favor. Gracias.\"}, {\"original\": \"Ha davvero un ottimo sapore.\", \"translated\": \"Sabe realmente bien.\"}]', 12, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в ресторане?\", \"Отлично! Вот 10 распространённых фраз, связанных с рестораном, а также их переводы на итальянский язык:\"]', '[\"Питание\", \"Заказ\", \"Оформление заказа\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация на уме, например заказ напитков, жалоба или вопрос об ингредиентах — смело задавайте.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Извините, сколько ещё ждать нашу еду?\", \"translated\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\"}, {\"original\": \"Столик на двоих, пожалуйста.\", \"translated\": \"Un tavolo per due, per favore.\"}, {\"original\": \"Можно посмотреть меню, пожалуйста?\", \"translated\": \"Potremmo vedere il menù, per favore?\"}, {\"original\": \"У вас есть какие-нибудь фирменные блюда, которые вы могли бы порекомендовать?\", \"translated\": \"Avete dei piatti tipici da consigliarci?\"}, {\"original\": \"Я хочу заказать это и это.\", \"translated\": \"Vorrei ordinare questo e quest’altro.\"}, {\"original\": \"Стакан воды, пожалуйста. Спасибо.\", \"translated\": \"Un bicchiere d’acqua, per favore. Grazie.\"}, {\"original\": \"Счёт, пожалуйста.\", \"translated\": \"Il conto, per favore.\"}, {\"original\": \"Можно оплатить кредитной картой?\", \"translated\": \"Posso pagare con carta di credito?\"}, {\"original\": \"Не могли бы вы упаковать это на вынос, пожалуйста?\", \"translated\": \"Potrebbe impacchettare questo da portare via, per favore?\"}, {\"original\": \"Еда была восхитительной, спасибо.\", \"translated\": \"Il cibo era delizioso, grazie.\"}]', 1, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в отеле?\", \"Отлично! Вот 10 распространённых фраз, связанных с отелем, а также их переводы на итальянский язык:\"]', '[\"Регистрация заезда\", \"Регистрация выезда\", \"Обслуживание в номере\"]', 'ru', '[\"Пока что: у вас есть какая-то конкретная ситуация на уме, например, расположение номера, другие услуги отеля или выезд из отеля? Смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Здравствуйте, у меня есть бронирование. Вот мой паспорт.\", \"translated\": \"Salve, ho una prenotazione, ecco il mio passaporto.\"}, {\"original\": \"У вас есть свободные номера?\", \"translated\": \"Avete camere disponibili?\"}, {\"original\": \"Извините, в отеле есть тренажёрный зал или прачечная?\", \"translated\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\"}, {\"original\": \"Во сколько начинается завтрак?\", \"translated\": \"A che ora inizia la colazione?\"}, {\"original\": \"Можно мне ключ от номера, пожалуйста?\", \"translated\": \"Potrei avere la chiave della mia camera, per favore?\"}, {\"original\": \"Не могли бы вы помочь мне отнести багаж в номер?\", \"translated\": \"Potrebbe aiutarmi a portare i miei bagagli nella camera?\"}, {\"original\": \"Как вызвать службу обслуживания номеров?\", \"translated\": \"Come posso chiamare il servizio in camera?\"}, {\"original\": \"До какого времени необходимо освободить номер?\", \"translated\": \"A che ora è il check-out?\"}, {\"original\": \"Не могли бы вы выписать мне квитанцию/счёт?\", \"translated\": \"Potrebbe rilasciarmi una ricevuta/fattura?\"}, {\"original\": \"Можно оставить здесь мой багаж?\", \"translated\": \"Posso lasciare qui i miei bagagli?\"}]', 2, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в аэропорту?\", \"Отлично! Вот 10 распространённых фраз, связанных с аэропортом, а также их переводы на итальянский язык:\"]', '[\"Регистрация на рейс\", \"Посадка на борт\", \"Сдача багажа\"]', 'ru', '[\"Пока что: у вас на уме какая-то конкретная ситуация, например регистрация на рейс, получение багажа или аренда автомобиля? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Где стойка регистрации?\", \"translated\": \"Dov\'è il banco del check-in?\"}, {\"original\": \"Я бы хотел место у окна, пожалуйста.\", \"translated\": \"Vorrei un posto vicino al finestrino, per favore.\"}, {\"original\": \"Этот рейс задерживается?\", \"translated\": \"Questo volo è in ritardo?\"}, {\"original\": \"Мне нужно зарегистрировать этот багаж.\", \"translated\": \"Devo registrare questo bagaglio.\"}, {\"original\": \"Где выход на посадку?\", \"translated\": \"Dov\'è l\'ingresso per l\'imbarco?\"}, {\"original\": \"Самолёт вот-вот взлетит.\", \"translated\": \"L\'aeroplano sta per decollare.\"}, {\"original\": \"Нужно ли извлекать ноутбук и внешний аккумулятор?\", \"translated\": \"Devo estrarre il mio laptop e la power bank?\"}, {\"original\": \"Где магазин беспошлинной торговли?\", \"translated\": \"Dov\'è il negozio duty-free?\"}, {\"original\": \"Я не могу найти свой чемодан.\", \"translated\": \"Non riesco a trovare la mia valigia.\"}, {\"original\": \"Предоставляется ли услуга инвалидных колясок?\", \"translated\": \"Offrite un servizio di sedia a rotelle?\"}]', 3, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в общественном транспорте?\", \"Отлично! Вот 10 распространённых фраз, связанных с общественным транспортом, а также их переводы на итальянский язык:\"]', '[\"Поездка на автобусе/метро\", \"Покупка билетов\", \"Пересадка\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация в уме, например, запрос о месте остановки автобуса, цене билета или выходе из транспорта — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Этот автобус идёт до автовокзала?\", \"translated\": \"Questo autobus va al capolinea?\"}, {\"original\": \"Какая следующая остановка?\", \"translated\": \"Qual è la prossima fermata?\"}, {\"original\": \"Где я могу купить билет?\", \"translated\": \"Dove posso comprare un biglietto?\"}, {\"original\": \"Один билет до XX, пожалуйста.\", \"translated\": \"Un biglietto per XX, per favore.\"}, {\"original\": \"Нужно ли мне пересаживаться?\", \"translated\": \"Devo cambiare mezzo?\"}, {\"original\": \"Через сколько прибывает следующий поезд метро?\", \"translated\": \"Quanto manca al prossimo treno della metropolitana?\"}, {\"original\": \"Извините, пропустите меня, пожалуйста.\", \"translated\": \"Scusi, mi lasci passare, per favore.\"}, {\"original\": \"Это место занято?\", \"translated\": \"Questo posto è occupato?\"}, {\"original\": \"Извините, где я могу пересесть на линию 2, чтобы добраться до XX?\", \"translated\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\"}, {\"original\": \"Как мне добраться до XX?\", \"translated\": \"Come arrivo a XX?\"}]', 4, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на туристических объектах?\", \"Прекрасно! Вот 10 распространённых фраз, связанных с туристическими объектами, а также их переводы на итальянский язык:\"]', '[\"Осмотр достопримечательностей\", \"Фотографирование\", \"Покупка билетов\"]', 'ru', '[\"Пока что у вас есть какая-то конкретная ситуация в уме, например, вопрос о цене билетов, поиск парковочного места или услуг гида? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"Есть ли льготные билеты для студентов?\", \"translated\": \"Sono disponibili biglietti per studenti?\"}, {\"original\": \"Во сколько открывается достопримечательность?\", \"translated\": \"A che ora apre la attrazione?\"}, {\"original\": \"Чем здесь можно интересно заняться?\", \"translated\": \"Quali sono le cose divertenti da fare qui?\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"Potrebbe scattarci una foto?\"}, {\"original\": \"Где автобус для осмотра достопримечательностей?\", \"translated\": \"Dove si trova l\'autobus turistico?\"}, {\"original\": \"Где находится туалет?\", \"translated\": \"Dove si trova il bagno?\"}, {\"original\": \"Где лучшее место для просмотра?\", \"translated\": \"Dov\'è il punto migliore per osservare la vista?\"}, {\"original\": \"Здесь прекрасные виды.\", \"translated\": \"Il paesaggio qui è bellissimo.\"}, {\"original\": \"Доступна ли экскурсия с гидом?\", \"translated\": \"È disponibile un tour guidato?\"}]', 5, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать при заказе такси или пользовании услугами такси?\", \"Отлично! Вот 10 распространённых фраз, связанных с такси или услугами такси, а также их переводы на итальянский язык:\"]', '[\"Вызов такси\", \"Указание места назначения\", \"Оплата\"]', 'ru', '[\"Пока что: что вы сейчас больше всего хотите сделать — уточнить пункт назначения, спросить цену или запросить счёт? Свободно задавайте любые вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в голове.\"]', NULL, '[{\"original\": \"Где я могу взять такси?\", \"translated\": \"Dove posso prendere un taxi?\"}, {\"original\": \"Пожалуйста, отвезите меня по этому адресу.\", \"translated\": \"Mi porti a questo indirizzo, per favore.\"}, {\"original\": \"Примерно сколько это будет стоить?\", \"translated\": \"Quanto costerà all\'incirca?\"}, {\"original\": \"Не могли бы вы, пожалуйста, включить счётчик?\", \"translated\": \"Potrebbe usare il tassametro, per favore?\"}, {\"original\": \"Пожалуйста, поезжайте немного быстрее, мне нужно спешить.\", \"translated\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\"}, {\"original\": \"Остановитесь, пожалуйста, здесь.\", \"translated\": \"Si fermi qui, per favore.\"}, {\"original\": \"Принимаете ли вы оплату картой или через мобильные платежи?\", \"translated\": \"Accetta carte di credito o pagamenti mobili?\"}, {\"original\": \"Можно мне, пожалуйста, чек?\", \"translated\": \"Potrei avere lo scontrino, per favore?\"}, {\"original\": \"Спасибо, водитель.\", \"translated\": \"Grazie, autista.\"}, {\"original\": \"Как далеко ещё?\", \"translated\": \"Quanto manca ancora?\"}]', 6, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать в аптеке?\", \"Превосходно! Вот 10 распространённых фраз, связанных с аптекой, а также их переводы на итальянский язык:\"]', '[\"Покупка лекарств\", \"Консультация\", \"Оплата\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация в уме, например, запрос инструкций по приёму лекарств, фразы, связанные с использованием страхования, продолжительностью приёма лекарств — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас в голове.\"]', NULL, '[{\"original\": \"У вас есть лекарство от простуды?\", \"translated\": \"Ha dei farmaci per il raffreddore?\"}, {\"original\": \"Как мне принимать это лекарство?\", \"translated\": \"Come devo assumere questo farmaco?\"}, {\"original\": \"У вас есть обезболивающие?\", \"translated\": \"Ha degli antidolorifici?\"}, {\"original\": \"Есть ли инструкция по применению?\", \"translated\": \"È incluso un foglietto illustrativo?\"}, {\"original\": \"Это лекарство имеет какие-либо побочные эффекты?\", \"translated\": \"Questo farmaco ha effetti collaterali?\"}, {\"original\": \"Можно ли воспользоваться моей медицинской страховкой?\", \"translated\": \"Posso usare la mia tessera sanitaria?\"}, {\"original\": \"Не могли бы вы дать мне коробку пластырей, пожалуйста?\", \"translated\": \"Potrei avere una confezione di cerotti, per favore?\"}, {\"original\": \"У вас есть жаропонижающие?\", \"translated\": \"Ha dei farmaci antipiretici?\"}, {\"original\": \"Я немного поранился. У вас есть антисептик и пластыри?\", \"translated\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\"}, {\"original\": \"Во сколько вы закрываетесь?\", \"translated\": \"A che ora chiude?\"}]', 7, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в службах экстренной помощи?\", \"Отлично! Вот 10 распространённых фраз, связанных со службами экстренной помощи, а также их переводы на итальянский язык:\"]', '[\"Вызов полиции\", \"Первая помощь\", \"Призыв о помощи\"]', 'ru', '[\"Пока что: у вас есть конкретная чрезвычайная ситуация в уме, например пожар, травма и необходимость помощи, экстренный вызов — смело задавайте вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Пожалуйста, помогите мне вызвать скорую помощь.\", \"translated\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\"}, {\"original\": \"Где находится больница?\", \"translated\": \"Dov\'è l\'ospedale?\"}, {\"original\": \"Кто-то получил травму.\", \"translated\": \"Qualcuno è ferito.\"}, {\"original\": \"Пожалуйста, помогите мне.\", \"translated\": \"Per favore, mi aiuti.\"}, {\"original\": \"Где находится полицейский участок?\", \"translated\": \"Dov\'è la stazione di polizia?\"}, {\"original\": \"Я потерял свои вещи.\", \"translated\": \"Ho perso i miei effetti personali.\"}, {\"original\": \"Какой номер пожарной службы?\", \"translated\": \"Qual è il numero dei vigili del fuoco?\"}, {\"original\": \"Я потерял паспорт. Не подскажете, где ближайший полицейский участок?\", \"translated\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\"}, {\"original\": \"Здесь есть аварийный выход?\", \"translated\": \"C\'è un\'uscita di emergenza?\"}, {\"original\": \"Кто-то потерял сознание.\", \"translated\": \"Qualcuno è svenuto.\"}]', 8, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на пляже или у бассейна?\", \"Превосходно! Вот 10 распространённых фраз, связанных с пляжем или бассейном, а также их переводы на итальянский язык:\"]', '[\"Плавание\", \"Загар\", \"Пляжные виды спорта\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного мероприятия или фестиваля, в котором вы участвуете: культурный фестиваль, гастрономический фестиваль или музыкальный фестиваль? Пожалуйста, укажите контекст.\", \"Пожалуйста, перечислите мероприятия, в которых вы участвуете.\"]', '[\"У вас есть какая-то конкретная ситуация на уме? Свободно задавайте вопрос.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', '[{\"original\": \"Смотрите! Волны там действительно огромные.\", \"translated\": \"Guarda! Le onde laggiù sono davvero grandi.\"}, {\"original\": \"Не забудьте нанести солнцезащитный крем — ультрафиолетовые лучи здесь очень сильные.\", \"translated\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\"}, {\"original\": \"Песок на этом пляже такой мелкий, что ощущение такое, будто вы ступаете по хлопку.\", \"translated\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\"}, {\"original\": \"Как насчёт игры в волейбол на пляже?\", \"translated\": \"Che ne dici di giocare a pallavolo sulla spiaggia?\"}, {\"original\": \"Парусники вдали выглядят очень красиво.\", \"translated\": \"Le barche a vela in lontananza sembrano bellissime.\"}, {\"original\": \"Вода здесь такая прозрачная, что даже рыбок можно разглядеть.\", \"translated\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\"}, {\"original\": \"Давайте пойдём поискать морские ракушки.\", \"translated\": \"Andiamo a cercare delle conchiglie.\"}, {\"original\": \"Прогулка по пляжу на закате, наверное, очень романтична.\", \"translated\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\"}, {\"original\": \"Я слышал, что морепродукты здесь очень свежие — давайте попробуем.\", \"translated\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\"}, {\"original\": \"Начинается прилив, давайте направимся к берегу.\", \"translated\": \"La marea sta salendo, dirigiamoci verso la riva.\"}]', 9, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые я могу использовать на местных мероприятиях и праздниках?\", \"Превосходно! Вот 10 распространённых фраз, связанных с местными мероприятиями и праздниками, а также их переводы на итальянский язык:\"]', '[\"Посещение мероприятий\", \"Празднование фестивалей\", \"Изучение культуры\"]', 'ru', '[\"Пока что не могли бы вы сообщить мне контекст местного мероприятия или праздника, на который вы собираетесь пойти: Хэллоуин, концерт, вечеринка у друзей или что-то ещё? Пожалуйста, укажите контекст.\", \"Опишите, пожалуйста, те мероприятия, которые приходят вам на ум.\"]', '[\"У вас есть конкретная ситуация в уме? Свободно задавайте вопрос.\", \"Опишите, пожалуйста, ту ситуацию, которая приходит вам на ум.\"]', '[{\"original\": \"Есть ли сегодня какие-нибудь мероприятия?\", \"translated\": \"Ci sono eventi oggi?\"}, {\"original\": \"В этом празднике есть что-нибудь особенное?\", \"translated\": \"C\'è qualcosa di speciale in questo festival?\"}, {\"original\": \"Где проходит празднование?\", \"translated\": \"Dove si tiene la celebrazione?\"}, {\"original\": \"Как я могу купить билеты?\", \"translated\": \"Come posso acquistare i biglietti?\"}, {\"original\": \"Во сколько начинается представление?\", \"translated\": \"A che ora inizia lo spettacolo?\"}, {\"original\": \"Какая традиционная еда здесь есть?\", \"translated\": \"Quali sono i cibi tradizionali?\"}, {\"original\": \"Здесь действительно очень оживлённо.\", \"translated\": \"Qui è davvero animato.\"}, {\"original\": \"Есть ли какие-нибудь народные мероприятия?\", \"translated\": \"Ci sono attività popolari?\"}, {\"original\": \"Счастливых праздников!\", \"translated\": \"Buone feste!\"}, {\"original\": \"Во сколько заканчивается мероприятие?\", \"translated\": \"A che ora termina l\'evento?\"}]', 10, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в музее или художественной галерее?\", \"Превосходно! Вот 10 распространённых фраз, связанных с музеем или художественной галереей, а также их переводы на итальянский язык:\"]', '[\"Посещение\", \"Экскурсия\", \"Покупка билетов\"]', 'ru', '[\"Пока что: у вас есть конкретная ситуация на уме, например, просьба о вводном буклете, фразы, связанные с маршрутом посетителя, фразы, связанные с комментариями к экспонатам — смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"У вас есть аудиогиды?\", \"translated\": \"Avete guide audio?\"}, {\"original\": \"Кто создал это произведение искусства?\", \"translated\": \"Chi ha creato quest\'opera d\'arte?\"}, {\"original\": \"Где находится самая ценная экспонат музея?\", \"translated\": \"Dove si trova il pezzo più prezioso del museo?\"}, {\"original\": \"Разрешена ли фотосъёмка?\", \"translated\": \"È consentito fare fotografie?\"}, {\"original\": \"Здесь проходят какие-нибудь специальные выставки?\", \"translated\": \"Ci sono delle mostre speciali qui?\"}, {\"original\": \"Сколько времени занимает посещение?\", \"translated\": \"Quanto tempo richiede la visita?\"}, {\"original\": \"Не могли бы вы представить нам краткое введение?\", \"translated\": \"Potreste darci una breve introduzione?\"}, {\"original\": \"Эти произведения действительно изысканны.\", \"translated\": \"Queste opere sono davvero squisite.\"}, {\"original\": \"Где находится магазин сувениров?\", \"translated\": \"Dove si trova il negozio dei souvenir?\"}]', 11, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Не могли бы вы предоставить мне 10 распространённых фраз, которые можно использовать в кафе?\", \"Превосходно! Вот 10 распространённых фраз, связанных с кафе, а также их переводы на итальянский язык:\"]', '[\"Заказ кофе\", \"Отдых\", \"Общение\"]', 'ru', '[\"Пока что: у вас на уме какая-то конкретная ситуация, например, запрос меню, прохладительных или горячих напитков, других товаров? Смело задавайте вопросы.\", \"Опишите, пожалуйста, ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Я возьму латте, пожалуйста.\", \"translated\": \"Prenderò un caffè latte, per favore.\"}, {\"original\": \"У вас есть Wi-Fi?\", \"translated\": \"Avete il Wi-Fi?\"}, {\"original\": \"Можно мне посмотреть меню, пожалуйста?\", \"translated\": \"Potrei vedere il menu, per favore?\"}, {\"original\": \"Разрешено ли добавлять кофе бесплатно?\", \"translated\": \"Sono ammesse le ricariche?\"}, {\"original\": \"Мой кофе уже готов?\", \"translated\": \"Il mio caffè è pronto?\"}, {\"original\": \"Сколько времени я могу здесь посидеть?\", \"translated\": \"Per quanto tempo posso stare seduto qui?\"}, {\"original\": \"Не могли бы вы сделать для нас фотографию?\", \"translated\": \"Potrebbe fare una foto per noi?\"}, {\"original\": \"Где туалет?\", \"translated\": \"Dov\'è il bagno?\"}, {\"original\": \"Счёт, пожалуйста. Спасибо.\", \"translated\": \"Il conto, per favore. Grazie.\"}, {\"original\": \"Очень вкусно.\", \"translated\": \"Ha davvero un ottimo sapore.\"}]', 12, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在餐厅常用的表达吗？\", \"太棒了！以下是与餐厅相关的10个常用表达，以及对应的意大利语翻译：\"]', '[\"用餐\", \"下单\", \"结账\"]', 'zh', '[\"目前，您心中是否有特定场景，例如点饮料、提出投诉或询问食材？欢迎随时提问。\", \"请描述您心中所想的场景。\"]', NULL, '[{\"original\": \"打扰一下，我们的菜还要等多久？\", \"translated\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\"}, {\"original\": \"请给我们安排一张两人桌。\", \"translated\": \"Un tavolo per due, per favore.\"}, {\"original\": \"请问可以看一下菜单吗？\", \"translated\": \"Potremmo vedere il menù, per favore?\"}, {\"original\": \"你们有什么招牌菜可以推荐吗？\", \"translated\": \"Avete dei piatti tipici da consigliarci?\"}, {\"original\": \"我要点这个和这个。\", \"translated\": \"Vorrei ordinare questo e quest’altro.\"}, {\"original\": \"请给我一杯水，谢谢。\", \"translated\": \"Un bicchiere d’acqua, per favore. Grazie.\"}, {\"original\": \"请结账。\", \"translated\": \"Il conto, per favore.\"}, {\"original\": \"我可以刷信用卡付款吗？\", \"translated\": \"Posso pagare con carta di credito?\"}, {\"original\": \"请问可以帮我把这份打包带走吗？\", \"translated\": \"Potrebbe impacchettare questo da portare via, per favore?\"}, {\"original\": \"饭菜非常美味，谢谢。\", \"translated\": \"Il cibo era delizioso, grazie.\"}]', 1, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在酒店场景中常用的表达吗？\", \"太棒了！以下是与酒店相关的10个常用表达，以及对应的意大利语翻译：\"]', '[\"入住\", \"退房\", \"客房服务\"]', 'zh', '[\"目前，您心中是否有特定的情境？例如房间位置、其他酒店服务，或退房等，欢迎随时提问。\", \"请描述您心中设想的情境。\"]', NULL, '[{\"original\": \"你好，我已预订房间，这是我的护照。\", \"translated\": \"Salve, ho una prenotazione, ecco il mio passaporto.\"}, {\"original\": \"请问还有空房吗？\", \"translated\": \"Avete camere disponibili?\"}, {\"original\": \"打扰一下，酒店有健身房或洗衣房吗？\", \"translated\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\"}, {\"original\": \"早餐几点开始？\", \"translated\": \"A che ora inizia la colazione?\"}, {\"original\": \"请给我一把房卡，谢谢。\", \"translated\": \"Potrei avere la chiave della mia stanza, per favore?\"}, {\"original\": \"您能帮我把行李送到房间吗？\", \"translated\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\"}, {\"original\": \"我该怎么呼叫客房服务？\", \"translated\": \"Come posso chiamare il servizio in camera?\"}, {\"original\": \"退房时间是几点？\", \"translated\": \"A che ora è il check-out?\"}, {\"original\": \"请您给我开一张收据/发票。\", \"translated\": \"Potrebbe rilasciarmi una ricevuta/fattura?\"}, {\"original\": \"我可以把行李寄存在这里吗？\", \"translated\": \"Posso lasciare qui i miei bagagli?\"}]', 2, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在机场常用的短语吗？\", \"太棒了！以下是与机场相关的10个常用短语，以及对应的意大利语翻译：\"]', '[\"办理登机手续\", \"登机\", \"托运行李\"]', 'zh', '[\"目前，您心里是否有特定场景，例如办理登机手续、行李认领或租车服务？欢迎随时提问。\", \"请描述您心中所想的场景。\"]', NULL, '[{\"original\": \"值机柜台在哪里？\", \"translated\": \"Dov\'è il banco del check-in?\"}, {\"original\": \"我想要一个靠窗的座位，谢谢。\", \"translated\": \"Vorrei un posto vicino al finestrino, per favore.\"}, {\"original\": \"这个航班延误了吗？\", \"translated\": \"Questo volo è in ritardo?\"}, {\"original\": \"我需要托运行李。\", \"translated\": \"Devo registrare questo bagaglio.\"}, {\"original\": \"登机口在哪里？\", \"translated\": \"Dov\'è l\'ingresso per l\'imbarco?\"}, {\"original\": \"飞机即将起飞。\", \"translated\": \"L\'aeroplano sta per decollare.\"}, {\"original\": \"我需要把笔记本电脑和充电宝拿出来吗？\", \"translated\": \"Devo estrarre il mio laptop e la power bank?\"}, {\"original\": \"免税店在哪里？\", \"translated\": \"Dov\'è il negozio duty-free?\"}, {\"original\": \"我找不到我的行李箱了。\", \"translated\": \"Non riesco a trovare la mia valigia.\"}, {\"original\": \"你们提供轮椅服务吗？\", \"translated\": \"Offrite un servizio di sedia a rotelle?\"}]', 3, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在公共交通中常用的表达吗？\", \"太棒了！以下是与公共交通相关的10个常用表达，以及对应的意大利语翻译：\"]', '[\"乘坐公交/地铁\", \"购买车票\", \"换乘\"]', 'zh', '[\"目前，您心中是否有特定的情境，例如询问公交站、票价或下车等？欢迎随时提问。\", \"请描述您心中所想的情境。\"]', NULL, '[{\"original\": \"这趟公交车去终点站吗？\", \"translated\": \"Questo autobus va al capolinea?\"}, {\"original\": \"下一站是哪里？\", \"translated\": \"Qual è la prossima fermata?\"}, {\"original\": \"我在哪里可以买票？\", \"translated\": \"Dove posso comprare un biglietto?\"}, {\"original\": \"请给我一张去XX的车票。\", \"translated\": \"Un biglietto per XX, per favore.\"}, {\"original\": \"我需要换乘吗？\", \"translated\": \"Devo cambiare mezzo?\"}, {\"original\": \"下一班地铁列车还要等多久？\", \"translated\": \"Tra quanto arriva il prossimo treno della metropolitana?\"}, {\"original\": \"不好意思，请让我过去。\", \"translated\": \"Scusi, mi lasci passare, per favore.\"}, {\"original\": \"这个座位有人吗？\", \"translated\": \"Questo posto è occupato?\"}, {\"original\": \"不好意思，请问我在哪里换乘二号线去XX？\", \"translated\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\"}, {\"original\": \"我怎么去XX？\", \"translated\": \"Come arrivo a XX?\"}]', 4, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在旅游景点常用的表达吗？\", \"太棒了！以下是与旅游景点相关的10个常用表达，以及对应的意大利语翻译：\"]', '[\"观光游览\", \"拍照留念\", \"购买门票\"]', 'zh', '[\"目前，您心中是否有特定场景，例如询问门票价格、寻找停车场或导游服务？欢迎随时提问。\", \"请描述您心中所想的具体场景。\"]', NULL, '[{\"original\": \"门票多少钱？\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"有学生票吗？\", \"translated\": \"Sono disponibili biglietti per studenti?\"}, {\"original\": \"景点几点开门？\", \"translated\": \"A che ora apre la attrazione?\"}, {\"original\": \"这里有哪些好玩的项目？\", \"translated\": \"Quali sono le cose divertenti da fare qui?\"}, {\"original\": \"您能帮我们拍张照片吗？\", \"translated\": \"Potrebbe scattarci una foto?\"}, {\"original\": \"观光巴士在哪里？\", \"translated\": \"Dove si trova l\'autobus per i tour turistici?\"}, {\"original\": \"洗手间在哪儿？\", \"translated\": \"Dove si trova il bagno?\"}, {\"original\": \"最佳观景点在哪儿？\", \"translated\": \"Dove si trova il punto migliore per osservare la vista?\"}, {\"original\": \"这里的风景很美。\", \"translated\": \"Il paesaggio qui è bellissimo.\"}, {\"original\": \"有提供导游服务吗？\", \"translated\": \"È disponibile un tour guidato?\"}]', 5, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在乘坐出租车或使用出租车服务时常用的表达吗？\", \"太棒了！以下是与出租车或出租车服务相关的10个常用表达，以及对应的意大利语翻译：\"]', '[\"乘坐出租车\", \"告知目的地\", \"付款\"]', 'zh', '[\"目前，您最想做什么？例如询问目的地、费用，或索要发票，欢迎随时提问。\", \"请描述您脑海中设想的情境。\"]', NULL, '[{\"original\": \"我在哪里可以打到出租车？\", \"translated\": \"Dove posso prendere un taxi?\"}, {\"original\": \"请送我去这个地址。\", \"translated\": \"Mi porti a questo indirizzo, per favore.\"}, {\"original\": \"大概需要多少钱？\", \"translated\": \"Quanto costerà all\'incirca?\"}, {\"original\": \"请您打表计费，好吗？\", \"translated\": \"Potrebbe usare il tassametro, per favore?\"}, {\"original\": \"请开快一点，我赶时间。\", \"translated\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\"}, {\"original\": \"请在这里停车。\", \"translated\": \"Si fermi qui, per favore.\"}, {\"original\": \"您接受银行卡或手机支付吗？\", \"translated\": \"Accetta carte di credito o pagamenti mobili?\"}, {\"original\": \"可以给我一张收据吗？\", \"translated\": \"Potrei avere lo scontrino, per favore?\"}, {\"original\": \"谢谢您，司机师傅。\", \"translated\": \"Grazie, autista.\"}, {\"original\": \"还有多远？\", \"translated\": \"Quanto manca ancora?\"}]', 6, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个药房常用表达吗？\", \"太棒了！以下是与药房相关的10个常用表达，以及对应的意大利语翻译：\"]', '[\"购买药品\", \"咨询\", \"支付\"]', 'zh', '[\"目前，您心中是否有特定场景？例如询问服药说明、与使用保险相关的问题、用药时长等，欢迎随时提问。\", \"请描述您心中所想的具体场景。\"]', NULL, '[{\"original\": \"你们有治感冒的药吗？\", \"translated\": \"Ha dei farmaci per il raffreddore?\"}, {\"original\": \"这种药我该怎么服用？\", \"translated\": \"Come devo assumere questo farmaco?\"}, {\"original\": \"你们有止痛药吗？\", \"translated\": \"Ha degli antidolorifici?\"}, {\"original\": \"这个药有说明书吗？\", \"translated\": \"È incluso un foglietto illustrativo?\"}, {\"original\": \"这种药有什么副作用吗？\", \"translated\": \"Questo farmaco ha effetti collaterali?\"}, {\"original\": \"我能用我的医保卡吗？\", \"translated\": \"Posso usare la mia tessera sanitaria?\"}, {\"original\": \"请给我一盒创可贴，谢谢。\", \"translated\": \"Potrei avere una confezione di cerotti, per favore?\"}, {\"original\": \"你们有退烧药吗？\", \"translated\": \"Ha dei farmaci antipiretici?\"}, {\"original\": \"我有点擦伤，你们有消毒药水和创可贴吗？\", \"translated\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\"}, {\"original\": \"你们几点关门？\", \"translated\": \"A che ora chiude?\"}]', 7, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在紧急服务中常用的短语吗？\", \"太棒了！以下是与紧急服务相关的10个常用短语，以及对应的意大利语翻译：\"]', '[\"报警\", \"急救\", \"求助\"]', 'zh', '[\"目前，您心中是否有特定的紧急情况，例如火灾、受伤需要帮助、紧急呼叫等？欢迎随时提问。\", \"请描述您心中所想的情况。\"]', NULL, '[{\"original\": \"请帮我叫一辆救护车。\", \"translated\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\"}, {\"original\": \"医院在哪儿？\", \"translated\": \"Dov\'è l\'ospedale?\"}, {\"original\": \"有人受伤了。\", \"translated\": \"Qualcuno è ferito.\"}, {\"original\": \"请帮帮我。\", \"translated\": \"Per favore, mi aiuti.\"}, {\"original\": \"警察局在哪儿？\", \"translated\": \"Dov\'è la stazione di polizia?\"}, {\"original\": \"我的物品丢失了。\", \"translated\": \"Ho perso i miei effetti personali.\"}, {\"original\": \"消防部门的电话号码是多少？\", \"translated\": \"Qual è il numero del corpo dei vigili del fuoco?\"}, {\"original\": \"我的护照丢了。您知道最近的警察局在哪儿吗？\", \"translated\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\"}, {\"original\": \"有紧急出口吗？\", \"translated\": \"C\'è un\'uscita di emergenza?\"}, {\"original\": \"有人晕倒了。\", \"translated\": \"Qualcuno è svenuto.\"}]', 8, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在海滩或泳池边常用的短语吗？\", \"太棒了！以下是与海滩或泳池边相关的10个常用短语，以及对应的意大利语翻译：\"]', '[\"游泳\", \"日光浴\", \"海滩运动\"]', 'zh', '[\"目前，请您提供您将要参加的当地活动或节日的相关背景信息，例如文化节、美食节或音乐节。请提供具体背景。\", \"请您说明您将参与的活动内容。\"]', '[\"您心中是否有特定场景？欢迎随时提问。\", \"请描述您心中设想的具体场景。\"]', '[{\"original\": \"看！那边的海浪真大。\", \"translated\": \"Guarda! Le onde laggiù sono davvero grandi.\"}, {\"original\": \"记得涂防晒霜，这里的紫外线很强。\", \"translated\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\"}, {\"original\": \"这片海滩的沙子非常细腻，踩上去像踏在棉花上。\", \"translated\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\"}, {\"original\": \"在海滩上打排球怎么样？\", \"translated\": \"Che ne dici di giocare a pallavolo in spiaggia?\"}, {\"original\": \"远处的帆船看起来真美。\", \"translated\": \"Le barche a vela in lontananza sembrano bellissime.\"}, {\"original\": \"这里的海水如此清澈，连鱼儿都能看见。\", \"translated\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\"}, {\"original\": \"我们去找些贝壳吧。\", \"translated\": \"Andiamo a cercare delle conchiglie.\"}, {\"original\": \"日落时分在海滩上散步一定很浪漫。\", \"translated\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\"}, {\"original\": \"听说这里的海鲜非常新鲜，我们去尝尝吧。\", \"translated\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\"}, {\"original\": \"潮水涨起来了，我们往岸边走吧。\", \"translated\": \"La marea sta salendo, dirigiamoci verso la riva.\"}]', 9, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在本地活动和节日中常用的表达吗？\", \"太棒了！以下是与本地活动和节日相关的10个常用表达，以及对应的意大利语翻译：\"]', '[\"参加活动\", \"庆祝节日\", \"学习文化\"]', 'zh', '[\"目前，您能否告诉我您将参加的本地活动或节日的具体背景，例如万圣节、音乐会、朋友聚会，或其他活动？请提供相关背景。\", \"请描述您脑海中设想的活动内容。\"]', '[\"您心中是否有特定的情境？欢迎随时提问。\", \"请描述您脑海中设想的具体情境。\"]', '[{\"original\": \"今天有什么活动吗？\", \"translated\": \"Ci sono eventi oggi?\"}, {\"original\": \"这个节日有什么特别之处吗？\", \"translated\": \"C\'è qualcosa di speciale in questo festival?\"}, {\"original\": \"庆祝活动在哪里举行？\", \"translated\": \"Dove si tiene la celebrazione?\"}, {\"original\": \"我该如何购买门票？\", \"translated\": \"Come posso acquistare i biglietti?\"}, {\"original\": \"演出什么时候开始？\", \"translated\": \"A che ora inizia lo spettacolo?\"}, {\"original\": \"有哪些传统食物？\", \"translated\": \"Quali sono i cibi tradizionali?\"}, {\"original\": \"这里真热闹。\", \"translated\": \"Qui è davvero animato.\"}, {\"original\": \"有民俗活动吗？\", \"translated\": \"Ci sono attività popolari?\"}, {\"original\": \"节日快乐！\", \"translated\": \"Buone feste!\"}, {\"original\": \"活动什么时候结束？\", \"translated\": \"A che ora termina l\'evento?\"}]', 10, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在博物馆或美术馆中常用的表达吗？\", \"太棒了！以下是与博物馆或美术馆相关的10个常用表达，以及对应的意大利语翻译：\"]', '[\"参观\", \"导览游\", \"购票\"]', 'zh', '[\"目前，您心中是否有特定场景？例如索要导览手册、与参观路线相关的表达、对展品进行评论的相关表达等，欢迎随时提问。\", \"请描述您心中所想的场景。\"]', NULL, '[{\"original\": \"门票多少钱？\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"你们提供语音导览吗？\", \"translated\": \"Avete guide audio?\"}, {\"original\": \"这件艺术品是谁创作的？\", \"translated\": \"Chi ha creato quest\'opera d\'arte?\"}, {\"original\": \"博物馆最珍贵的藏品在哪里？\", \"translated\": \"Dove si trova il pezzo più prezioso del museo?\"}, {\"original\": \"允许拍照吗？\", \"translated\": \"È consentito fare fotografie?\"}, {\"original\": \"这里有没有特别展览？\", \"translated\": \"Ci sono delle mostre speciali qui?\"}, {\"original\": \"参观需要多长时间？\", \"translated\": \"Quanto tempo richiede la visita?\"}, {\"original\": \"您能为我们做个介绍吗？\", \"translated\": \"Potreste darci una breve introduzione?\"}, {\"original\": \"这些作品真是精美绝伦。\", \"translated\": \"Queste opere sono davvero squisite.\"}, {\"original\": \"纪念品商店在哪儿？\", \"translated\": \"Dove si trova il negozio dei souvenir?\"}]', 11, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"您能为我提供10个在咖啡馆常用的表达吗？\", \"太棒了！以下是与咖啡馆相关的10个常用表达，以及对应的意大利语翻译：\"]', '[\"点咖啡\", \"休息\", \"社交\"]', 'zh', '[\"目前，您心中是否有特定场景，例如点餐、要冰饮或热饮、购买其他商品等？欢迎随时提问。\", \"请描述您心中所想的场景。\"]', NULL, '[{\"original\": \"请给我一杯拿铁。\", \"translated\": \"Prenderò un caffè latte, per favore.\"}, {\"original\": \"你们有无线网络吗？\", \"translated\": \"Avete il Wi-Fi?\"}, {\"original\": \"请给我看一下菜单，谢谢。\", \"translated\": \"Potrei vedere il menu, per favore?\"}, {\"original\": \"可以续杯吗？\", \"translated\": \"Sono ammesse le ricariche?\"}, {\"original\": \"我的咖啡好了吗？\", \"translated\": \"Il mio caffè è pronto?\"}, {\"original\": \"我可以在这里坐多久？\", \"translated\": \"Per quanto tempo posso stare seduto qui?\"}, {\"original\": \"能帮我们拍张照片吗？\", \"translated\": \"Potrebbe fare una foto per noi?\"}, {\"original\": \"洗手间在哪里？\", \"translated\": \"Dov\'è il bagno?\"}, {\"original\": \"请结账，谢谢。\", \"translated\": \"Il conto, per favore. Grazie.\"}, {\"original\": \"味道 really 好。\", \"translated\": \"Ha davvero un ottimo sapore.\"}]', 12, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Restoranda kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte restoranla ilgili 10 yaygın ifade ve İtalyanca çevirileri:\"]', '[\"Yemek Yeme\", \"Sipariş Verme\", \"Ödeme\"]', 'tr', '[\"Şu anda aklınızda içecek siparişi vermek, bir şikayette bulunmak ya da malzemeler hakkında soru sormak gibi belirli bir durum mu var? Sorularınızı özgürce yöneltin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Affedersiniz, yemeğimiz kaç dakika daha sürecektir?\", \"translated\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\"}, {\"original\": \"Lütfen iki kişilik bir masa.\", \"translated\": \"Un tavolo per due, per favore.\"}, {\"original\": \"Lütfen menüyü görebilir miyiz?\", \"translated\": \"Potremmo vedere il menù, per favore?\"}, {\"original\": \"Önerdiğiniz özel yemekleriniz var mı?\", \"translated\": \"Avete dei piatti tipici da consigliarci?\"}, {\"original\": \"Bunu ve bunu sipariş etmek istiyorum.\", \"translated\": \"Vorrei ordinare questo e quest’altro.\"}, {\"original\": \"Lütfen bir bardak su. Teşekkürler.\", \"translated\": \"Un bicchiere d’acqua, per favore. Grazie.\"}, {\"original\": \"Hesabı lütfen.\", \"translated\": \"Il conto, per favore.\"}, {\"original\": \"Kredi kartıyla ödeyebilir miyim?\", \"translated\": \"Posso pagare con carta di credito?\"}, {\"original\": \"Lütfen bunu götürmek için paketleyebilir misiniz?\", \"translated\": \"Potrebbe impacchettare questo da portare via, per favore?\"}, {\"original\": \"Yiyecekler çok lezzetliydi, teşekkür ederiz.\", \"translated\": \"Il cibo era delizioso, grazie.\"}]', 1, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Otelde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte otel ile ilgili 10 yaygın ifade ve İtalyanca çevirileri:\"]', '[\"Kayıt Ol\", \"Çıkış Yap\", \"Oda Hizmeti\"]', 'tr', '[\"Şimdilik aklınızda özel bir durum var mı, örneğin oda konumu, başka bir otel hizmeti ya da çıkış işlemi? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Merhaba, bir rezervasyonum var, işte pasaportum.\", \"translated\": \"Salve, ho una prenotazione, ecco il mio passaporto.\"}, {\"original\": \"Boş odanız var mı?\", \"translated\": \"Avete camere disponibili?\"}, {\"original\": \"Affedersiniz, otelde bir spor salonu veya çamaşırhane var mı?\", \"translated\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\"}, {\"original\": \"Kahvaltı saat kaçta başlıyor?\", \"translated\": \"A che ora inizia la colazione?\"}, {\"original\": \"Lütfen bir oda anahtarı verebilir misiniz?\", \"translated\": \"Potrei avere la chiave della mia stanza, per favore?\"}, {\"original\": \"Bagajımı odaya taşımama yardımcı olur musunuz?\", \"translated\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\"}, {\"original\": \"Oda servisini nasıl arayabilirim?\", \"translated\": \"Come posso chiamare il servizio in camera?\"}, {\"original\": \"Çıkış saati kaçta?\", \"translated\": \"A che ora è il check-out?\"}, {\"original\": \"Bana bir makbuz/fatura yazabilir misiniz?\", \"translated\": \"Potrebbe rilasciarmi una ricevuta/fattura?\"}, {\"original\": \"Bagajımı burada bırakabilir miyim?\", \"translated\": \"Posso lasciare qui i miei bagagli?\"}]', 2, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Havaalanında kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte havaalanı ile ilgili 10 yaygın ifade ve İtalyanca çevirileri:\"]', '[\"Giriş yapma\", \"Uçağa binme\", \"Bagaj kontrolü\"]', 'tr', '[\"Şu an için aklınızda özel bir durum var mı, örneğin check-in, bagaj teslimi ya da araç kiralama hizmeti? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş masası nerede?\", \"translated\": \"Dov\'è il banco del check-in?\"}, {\"original\": \"Lütfen pencere kenarında bir koltuk istiyorum.\", \"translated\": \"Vorrei un posto vicino al finestrino, per favore.\"}, {\"original\": \"Bu uçuş gecikmiş mi?\", \"translated\": \"Questo volo è in ritardo?\"}, {\"original\": \"Bu bagajı kontrol ettirmem gerekiyor.\", \"translated\": \"Devo registrare questo bagaglio.\"}, {\"original\": \"İniş kapısı nerede?\", \"translated\": \"Dov\'è l\'ingresso per l\'imbarco?\"}, {\"original\": \"Uçak kalkmak üzere.\", \"translated\": \"L\'aeroplano sta per decollare.\"}, {\"original\": \"Dizüstü bilgisayarımı ve şarj cihazımı çıkarmam gerekiyor mu?\", \"translated\": \"Devo estrarre il mio laptop e la power bank?\"}, {\"original\": \"Vergisiz mağaza nerede?\", \"translated\": \"Dov\'è il negozio duty-free?\"}, {\"original\": \"Bavulumu bulamıyorum.\", \"translated\": \"Non riesco a trovare la mia valigia.\"}, {\"original\": \"Tekerlekli sandalye hizmetiniz var mı?\", \"translated\": \"Offrite un servizio di sedia a rotelle?\"}]', 3, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Toplu taşıma alanında kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte Toplu Taşıma ile ilgili 10 yaygın ifade ve İtalyanca çevirileri:\"]', '[\"Otobüs/Metro Kullanma\", \"Bilet Satın Alma\", \"Aktarma\"]', 'tr', '[\"Şimdilik aklınızda özel bir durum var mı, örneğin otobüs durağı sormak, bilet fiyatını öğrenmek ya da inecek yer belirtmek? Sorunuzu özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bu otobüs terminala gidiyor mu?\", \"translated\": \"Questo autobus va al capolinea?\"}, {\"original\": \"Bir sonraki durak neresi?\", \"translated\": \"Qual è la prossima fermata?\"}, {\"original\": \"Bilet nereden alabilirim?\", \"translated\": \"Dove posso comprare un biglietto?\"}, {\"original\": \"XX\'e bir bilet, lütfen.\", \"translated\": \"Un biglietto per XX, per favore.\"}, {\"original\": \"Aktarma yapmam gerekiyor mu?\", \"translated\": \"Devo cambiare?\"}, {\"original\": \"Bir sonraki metro trenine ne kadar kaldı?\", \"translated\": \"Quanto manca al prossimo treno della metropolitana?\"}, {\"original\": \"Üzgünüm, geçebilir miyim?\", \"translated\": \"Scusi, mi lasci passare, per favore.\"}, {\"original\": \"Bu koltuk dolu mu?\", \"translated\": \"Questo posto è occupato?\"}, {\"original\": \"Üzgünüm, XX\'e gitmek için 2. Hat\'a nerede aktarım yapabilirim?\", \"translated\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\"}, {\"original\": \"XX\'e nasıl giderim?\", \"translated\": \"Come arrivo a XX?\"}]', 4, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Turistik yerlerde kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte turistik yerlerle ilgili 10 yaygın ifade ve İtalyanca çevirileri:\"]', '[\"Manzara İzlemek\", \"Fotoğraf Çekmek\", \"Bilet Almak\"]', 'tr', '[\"Şu anda aklınızda, bilet fiyatını sormak, bir otopark bulmak ya da tur rehberi hizmeti almak gibi belirli bir durum mu var? Sorunuz için özgürsünüz.\", \"Lütfen aklınızda tuttuğunuz durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"Öğrenci biletleri mevcut mu?\", \"translated\": \"Sono disponibili biglietti per studenti?\"}, {\"original\": \"Bu yer saat kaçta açılıyor?\", \"translated\": \"A che ora apre la attrazione?\"}, {\"original\": \"Burada yapılacak eğlenceli şeyler neler?\", \"translated\": \"Quali sono le cose divertenti da fare qui?\"}, {\"original\": \"Bizi birlikte fotoğraflar mısınız?\", \"translated\": \"Potrebbe scattarci una foto?\"}, {\"original\": \"Sightseeing otobüsü nerede?\", \"translated\": \"Dove si trova l\'autobus per i tour turistici?\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"Dove si trova il bagno?\"}, {\"original\": \"En iyi manzara noktası nerede?\", \"translated\": \"Dove si trova il punto migliore per osservare?\"}, {\"original\": \"Buradaki manzara çok güzel.\", \"translated\": \"Il panorama qui è bellissimo.\"}, {\"original\": \"Rehberli tur mevcut mu?\", \"translated\": \"È disponibile un tour guidato?\"}]', 5, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Taksi veya taksi hizmeti ile ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Taksi veya Taksi Hizmeti ile ilgili 10 yaygın ifade ve İtalyanca çevirileri:\"]', '[\"Taksiye Biniş\", \"Varış Yerini Belirtme\", \"Ödeme\"]', 'tr', '[\"Şu anda en çok ne yapmak istersiniz? Örneğin, varış yerini sormak, ücreti öğrenmek ya da fatura talep etmek gibi. Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Bir taksi nerede bulabilirim?\", \"translated\": \"Dove posso prendere un taxi?\"}, {\"original\": \"Lütfen beni bu adrese götürün.\", \"translated\": \"Mi porti a questo indirizzo, per favore.\"}, {\"original\": \"Yaklaşık olarak ne kadar tutar?\", \"translated\": \"Quanto costerà all\'incirca?\"}, {\"original\": \"Lütfen taksimetreyi kullanır mısınız?\", \"translated\": \"Potrebbe usare il tassametro, per favore?\"}, {\"original\": \"Lütfen biraz daha hızlı sürer misiniz? Acelem var.\", \"translated\": \"Può guidare un po\' più velocemente, sono di fretta.\"}, {\"original\": \"Lütfen burada durun.\", \"translated\": \"Si fermi qui, per favore.\"}, {\"original\": \"Kart veya mobil ödeme kabul ediyor musunuz?\", \"translated\": \"Accetta carte o pagamenti mobili?\"}, {\"original\": \"Lütfen bir fiş verebilir misiniz?\", \"translated\": \"Potrei avere lo scontrino, per favore?\"}, {\"original\": \"Teşekkürler, şoför bey.\", \"translated\": \"Grazie, autista.\"}, {\"original\": \"Kaç dakika daha var?\", \"translated\": \"Quanto manca ancora?\"}]', 6, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Eczanede kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte eczane ile ilgili 10 yaygın ifade ve bunların İtalyanca çevirileri:\"]', '[\"İlaç Satın Almak\", \"Danışmanlık\", \"Ödeme\"]', 'tr', '[\"Şimdilik aklınızda, ilaç kullanım talimatları sormak, sigorta kullanımıyla ilgili ifadeler veya tedavi süresi gibi belirli bir durum mu var? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Soğuk algınlığı ilacı var mı?\", \"translated\": \"Ha dei farmaci per il raffreddore?\"}, {\"original\": \"Bu ilacı nasıl kullanmalıyım?\", \"translated\": \"Come devo assumere questo farmaco?\"}, {\"original\": \"Ağrı kesici ilaçlarınız var mı?\", \"translated\": \"Ha degli antidolorifici?\"}, {\"original\": \"Kullanım kılavuzu var mı?\", \"translated\": \"È incluso un foglietto illustrativo?\"}, {\"original\": \"Bu ilacın yan etkileri var mı?\", \"translated\": \"Questo farmaco ha effetti collaterali?\"}, {\"original\": \"Tıbbi sigorta kartımı kullanabilir miyim?\", \"translated\": \"Posso utilizzare la mia tessera sanitaria?\"}, {\"original\": \"Lütfen bir kutu yara bandı verebilir misiniz?\", \"translated\": \"Potrei avere una confezione di cerotti, per favore?\"}, {\"original\": \"Ateş düşürücü ilaçlarınız var mı?\", \"translated\": \"Ha dei farmaci antipiretici?\"}, {\"original\": \"Hafif bir çizik aldım. Antiseptik ve yara bandı var mı?\", \"translated\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\"}, {\"original\": \"Kaçta kapanıyorsunuz?\", \"translated\": \"A che ora chiude?\"}]', 7, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Acil Servislerle ilgili kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Acil Servislerle ilgili 10 yaygın ifade ve İtalyanca çevirileri:\"]', '[\"Polisi Aramak\", \"İlkyardım\", \"Yardım Çağrısı\"]', 'tr', '[\"Şu an için aklınızda belirli bir acil durum var mı, örneğin yangın, yaralanma ve yardım gereksinimi, acil çağrı? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bana bir ambulans çağırmama yardımcı olun.\", \"translated\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\"}, {\"original\": \"Hastane nerede?\", \"translated\": \"Dov\'è l\'ospedale?\"}, {\"original\": \"Birisi yaralandı.\", \"translated\": \"Qualcuno è ferito.\"}, {\"original\": \"Lütfen bana yardımcı olun.\", \"translated\": \"Per favore, mi aiuti.\"}, {\"original\": \"Polis karakolu nerede?\", \"translated\": \"Dov\'è la stazione di polizia?\"}, {\"original\": \"Eşyalarımı kaybettim.\", \"translated\": \"Ho perso i miei oggetti.\"}, {\"original\": \"İtfaiye numarası nedir?\", \"translated\": \"Qual è il numero del corpo dei vigili del fuoco?\"}, {\"original\": \"Pasaportumu kaybettim. En yakın polis karakolunun nerede olduğunu biliyor musunuz?\", \"translated\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\"}, {\"original\": \"Acil çıkış var mı?\", \"translated\": \"C\'è un\'uscita di emergenza?\"}, {\"original\": \"Birisi bayıldı.\", \"translated\": \"Qualcuno è svenuto.\"}]', 8, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Sahilde veya havuz kenarında kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte sahil veya havuz kenarına ilişkin 10 yaygın ifade ve bunların İtalyanca çevirileri:\"]', '[\"Yüzme\", \"Güneşlenme\", \"Plaj Sporları\"]', 'tr', '[\"Şimdilik, katılacağınız yerel etkinlik veya festivalin bağlamını, örneğin kültürel festival, gıda festivali veya müzik festivali gibi, lütfen bana belirtir misiniz? Lütfen bağlamı sağlayın.\", \"Katıldığınız etkinlikleri lütfen belirtin.\"]', '[\"Aklınızda özel bir durum mu var? Özgürce sorabilirsiniz.\", \"Aklınızda canlandırdığınız durumu lütfen açıklayın.\"]', '[{\"original\": \"Bakın! Oradaki dalgalar gerçekten büyük.\", \"translated\": \"Guarda! Le onde laggiù sono davvero grandi.\"}, {\"original\": \"Güneş koruyucu sürmeyi unutmayın, buradaki UV ışınları çok güçlü.\", \"translated\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\"}, {\"original\": \"Bu plajdaki kum çok ince, pamuk üzerinde yürüyormuş gibi hissediliyor.\", \"translated\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\"}, {\"original\": \"Plajda voleybol oynamak nasıl olur?\", \"translated\": \"Che ne dici di giocare a pallavolo in spiaggia?\"}, {\"original\": \"Uzaktaki yelkenli tekneler çok güzel görünüyor.\", \"translated\": \"Le barche a vela in lontananza sembrano bellissime.\"}, {\"original\": \"Buradaki su çok berrak, balıkları bile görebiliyorsunuz.\", \"translated\": \"L\'acqua qui è così trasparente che si riescono persino a vedere i pesci.\"}, {\"original\": \"Hadi biraz deniz kabuğu bulmaya gidelim.\", \"translated\": \"Andiamo a cercare delle conchiglie.\"}, {\"original\": \"Günbatımında plajda yürüyüş yapmak kesinlikle çok romantik olmalı.\", \"translated\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\"}, {\"original\": \"Buradaki deniz ürünleri çok tazeymiş, hadi biraz deneyelim.\", \"translated\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\"}, {\"original\": \"Deniz yükseliyor, kıyıya doğru yürüyelim.\", \"translated\": \"La marea sta salendo, dirigiamoci verso la riva.\"}]', 9, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Yerel Etkinlikler ve Festivallerde kullanabileceğim 10 yaygın ifadeyi bana sağlayabilir misiniz?\", \"Harika! İşte Yerel Etkinlikler ve Festivallerle ilgili 10 yaygın ifade ve İtalyanca çevirileri:\"]', '[\"Etkinliklere Katılmak\", \"Festivalleri Kutlamak\", \"Kültür Öğrenmek\"]', 'tr', '[\"Şimdilik, katılacağınız yerel etkinlik veya festivalin bağlamını, örneğin Cadılar Bayramı, konser veya arkadaş partisi gibi, lütfen bana belirtir misiniz? Başka bir şey olabilir mi? Lütfen bağlamı belirtin.\", \"Aklınızda canlandırdığınız etkinlikleri tanımlar mısınız?\"]', '[\"Aklınızda özel bir durum mu var? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Aklınızda canlandırdığınız durumu tanımlar mısınız?\"]', '[{\"original\": \"Bugün herhangi bir etkinlik var mı?\", \"translated\": \"Ci sono eventi oggi?\"}, {\"original\": \"Bu festivalle ilgili özel bir şey var mı?\", \"translated\": \"C\'è qualcosa di speciale in questo festival?\"}, {\"original\": \"Kutlama nerede yapılacak?\", \"translated\": \"Dove si tiene la celebrazione?\"}, {\"original\": \"Biletleri nasıl alabilirim?\", \"translated\": \"Come posso acquistare i biglietti?\"}, {\"original\": \"Gösteri saat kaçta başlıyor?\", \"translated\": \"A che ora inizia lo spettacolo?\"}, {\"original\": \"Hangi geleneksel yiyecekler var?\", \"translated\": \"Quali sono i cibi tradizionali?\"}, {\"original\": \"Burada gerçekten hareketli bir atmosfer var.\", \"translated\": \"Qui è davvero animato.\"}, {\"original\": \"Halk oyunu gibi etkinlikler var mı?\", \"translated\": \"Ci sono attività popolari?\"}, {\"original\": \"Mutlu tatiller!\", \"translated\": \"Buone feste!\"}, {\"original\": \"Etkinlik saat kaçta bitiyor?\", \"translated\": \"A che ora termina l\'evento?\"}]', 10, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Müze veya Sanat Galerisi\'nde kullanabileceğim 10 yaygın ifadeyi bana verebilir misiniz?\", \"Harika! İşte Müze veya Sanat Galerisi ile ilgili 10 yaygın ifade ve İtalyanca çevirileri:\"]', '[\"Ziyaret Etmek\", \"Rehberli Tur\", \"Bilet Satın Almak\"]', 'tr', '[\"Şimdilik aklınızda, tanıtım kılavuzu istemek, yol haritası ile ilgili ifadeler kullanmak veya sergilenen eserler hakkında yorum yapmak gibi belirli bir durum var mı? Sorularınızı özgürce sorabilirsiniz.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Giriş ücreti ne kadar?\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"Sesli rehberleriniz var mı?\", \"translated\": \"Avete guide audio?\"}, {\"original\": \"Bu eseri kim yaratmış?\", \"translated\": \"Chi ha creato quest\'opera d\'arte?\"}, {\"original\": \"Müzenin en değerli eseri nerede?\", \"translated\": \"Dove si trova il pezzo più prezioso del museo?\"}, {\"original\": \"Fotoğraf çekmeye izin veriliyor mu?\", \"translated\": \"È consentito fare fotografie?\"}, {\"original\": \"Burada özel sergiler var mı?\", \"translated\": \"Ci sono mostre speciali in corso?\"}, {\"original\": \"Ziyaret kaç dakika sürüyor?\", \"translated\": \"Quanto tempo richiede la visita?\"}, {\"original\": \"Bize bir tanıtım yapabilir misiniz?\", \"translated\": \"Potreste darci una breve introduzione?\"}, {\"original\": \"Bu eserler gerçekten çok zarif.\", \"translated\": \"Queste opere sono davvero squisite.\"}, {\"original\": \"Hediyelik eşya dükkanı nerede?\", \"translated\": \"Dove si trova il negozio di souvenir?\"}]', 11, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Bana kafelerde kullanabileceğim 10 yaygın ifade verebilir misiniz?\", \"Harika! İşte kafelerle ilgili 10 yaygın ifade ve bunların İtalyanca çevirileri:\"]', '[\"Kahvaltı Siparişi Verme\", \"Dinlenme\", \"Sosyalleşme\"]', 'tr', '[\"Şimdilik aklınızda menü istemek, buzlu veya sıcak içecekler sipariş etmek, diğer ürünler hakkında bilgi almak gibi belirli bir durum mu var? Sorularınızı özgürce sormaktan çekinmeyin.\", \"Lütfen aklınızda canlandırdığınız durumu açıklayın.\"]', NULL, '[{\"original\": \"Lütfen bir latte getirir misiniz?\", \"translated\": \"Prenderò un caffè latte, per favore.\"}, {\"original\": \"Wi-Fi var mı?\", \"translated\": \"Avete il Wi-Fi?\"}, {\"original\": \"Menüyü görebilir miyim, lütfen?\", \"translated\": \"Potrei vedere il menu, per favore?\"}, {\"original\": \"İkinci dolum yapılabilir mi?\", \"translated\": \"Sono ammesse le ricariche?\"}, {\"original\": \"Kahvaltım hazır mı?\", \"translated\": \"Il mio caffè è pronto?\"}, {\"original\": \"Burada ne kadar süre oturabilirim?\", \"translated\": \"Per quanto tempo posso stare seduto qui?\"}, {\"original\": \"Bizi birlikte çektikten sonra fotoğraf çekebilir misiniz?\", \"translated\": \"Potrebbe fare una foto per noi?\"}, {\"original\": \"Tuvalet nerede?\", \"translated\": \"Dov\'è il bagno?\"}, {\"original\": \"Hesap, lütfen. Teşekkür ederim.\", \"translated\": \"Il conto, per favore. Grazie.\"}, {\"original\": \"Gerçekten çok lezzetli.\", \"translated\": \"Ha davvero un ottimo sapore.\"}]', 12, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"レストランで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、レストランに関連する一般的な表現10個とそのイタリア語訳を示します：\"]', '[\"飲食\", \"注文\", \"レジ\"]', 'ja', '[\"今のところ、注文、苦情の申し立て、食材についての質問など、特定の状況をお考えですか？ご自由にお尋ねください。\", \"お考えの状況をご説明ください。\"]', NULL, '[{\"original\": \"すみません、料理はあとどのくらいで来ますか？\", \"translated\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\"}, {\"original\": \"二人用のテーブルをお願いします。\", \"translated\": \"Un tavolo per due, per favore.\"}, {\"original\": \"メニューを見せていただけますか？\", \"translated\": \"Possiamo vedere il menù, per favore?\"}, {\"original\": \"おすすめの自慢料理はありますか？\", \"translated\": \"Avete dei piatti tipici da consigliarci?\"}, {\"original\": \"これを注文したいのですが、あとこれもお願いします。\", \"translated\": \"Vorrei ordinare questo e quest’altro.\"}, {\"original\": \"水を一杯お願いします。ありがとうございます。\", \"translated\": \"Un bicchiere d’acqua, per favore. Grazie.\"}, {\"original\": \"お会計をお願いします。\", \"translated\": \"Il conto, per favore.\"}, {\"original\": \"クレジットカードで支払えますか？\", \"translated\": \"Posso pagare con carta di credito?\"}, {\"original\": \"これを持ち帰り用に包んでいただけますか？\", \"translated\": \"Potrebbe impacchettare questo da asporto, per favore?\"}, {\"original\": \"料理がとても美味しかったです。ありがとうございました。\", \"translated\": \"Il cibo era delizioso, grazie.\"}]', 1, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ホテルで使える一般的な表現を10個教えていただけますか？\", \"素晴らしいです！以下に、ホテル関連の一般的な表現10個とそのイタリア語訳をご紹介します：\"]', '[\"チェックイン\", \"チェックアウト\", \"ルームサービス\"]', 'ja', '[\"今のところ、部屋の位置やその他のホテルサービス、チェックアウトなど、特定の状況をお考えですか？何でもお気軽にお尋ねください。\", \"ご希望の状況をご説明ください。\"]', NULL, '[{\"original\": \"こんにちは、予約をしております。こちらが私のパスポートです。\", \"translated\": \"Salve, ho una prenotazione, ecco il mio passaporto.\"}, {\"original\": \"空室はございますか？\", \"translated\": \"Avete camere disponibili?\"}, {\"original\": \"すみませんが、ホテルにはジムやランドリールームはございますか？\", \"translated\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\"}, {\"original\": \"朝食の開始時間は何時からですか？\", \"translated\": \"A che ora inizia la colazione?\"}, {\"original\": \"部屋の鍵をいただけますか？\", \"translated\": \"Potrei avere la chiave della mia stanza, per favore?\"}, {\"original\": \"荷物を部屋まで運んでいただけますか？\", \"translated\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\"}, {\"original\": \"ルームサービスの呼び出し方はどうすればよいですか？\", \"translated\": \"Come posso chiamare il servizio in camera?\"}, {\"original\": \"チェックアウトの時間は何時ですか？\", \"translated\": \"A che ora è il check-out?\"}, {\"original\": \"領収書／請求書を書いていただけますか？\", \"translated\": \"Potrebbe rilasciarmi una ricevuta/fattura?\"}, {\"original\": \"ここに荷物を預けてもよろしいですか？\", \"translated\": \"Posso lasciare qui i miei bagagli?\"}]', 2, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"空港で使える一般的な表現を10個教えていただけますか？\", \"素晴らしいです！以下に、空港に関連する一般的な表現10個とそのイタリア語訳をご紹介します。\"]', '[\"チェックイン\", \"搭乗\", \"手荷物預け\"]', 'ja', '[\"今のところ、チェックイン、手荷物受取、またはレンタカーサービスなど、特定の状況をお考えですか？お気軽にご質問ください。\", \"ご希望の状況について詳しくお聞かせください。\"]', NULL, '[{\"original\": \"チェックインカウンターはどこですか？\", \"translated\": \"Dov\'è il banco del check-in?\"}, {\"original\": \"窓側の席をお願いします。\", \"translated\": \"Vorrei un posto vicino al finestrino, per favore.\"}, {\"original\": \"この便は遅れていますか？\", \"translated\": \"Questo volo è in ritardo?\"}, {\"original\": \"この荷物を預けたいのですが。\", \"translated\": \"Devo registrare questo bagaglio.\"}, {\"original\": \"搭乗口はどこですか？\", \"translated\": \"Dov\'è l\'ingresso per l\'imbarco?\"}, {\"original\": \"飛行機が今から離陸します。\", \"translated\": \"L\'aeroplano sta per decollare.\"}, {\"original\": \"ノートパソコンとモバイルバッテリーを取り出さなければなりませんか？\", \"translated\": \"Devo estrarre il mio laptop e la power bank?\"}, {\"original\": \"免税店はどこですか？\", \"translated\": \"Dov\'è il negozio duty-free?\"}, {\"original\": \"私のスーツケースが見つかりません。\", \"translated\": \"Non riesco a trovare la mia valigia.\"}, {\"original\": \"車椅子サービスはありますか？\", \"translated\": \"Offrite un servizio di sedia a rotelle?\"}]', 3, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"公共交通機関で使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、公共交通機関に関する一般的な表現10個とそのイタリア語訳を示します：\"]', '[\"バスまたは地下鉄の利用\", \"切符の購入\", \"乗り換え\"]', 'ja', '[\"今のところ、バス停の場所を尋ねる、運賃を確認する、降車するなど、特定の状況が頭に浮かんでいますか？何でもお気軽にお尋ねください。\", \"頭に浮かんでいる状況を教えてください。\"]', NULL, '[{\"original\": \"このバスは終点まで行きますか？\", \"translated\": \"Questo autobus va al capolinea?\"}, {\"original\": \"次の停留所はどこですか？\", \"translated\": \"Qual è la prossima fermata?\"}, {\"original\": \"切符はどこで買えますか？\", \"translated\": \"Dove posso comprare un biglietto?\"}, {\"original\": \"XX行きの切符を一枚お願いします。\", \"translated\": \"Un biglietto per XX, per favore.\"}, {\"original\": \"乗り換えが必要ですか？\", \"translated\": \"Devo cambiare mezzo?\"}, {\"original\": \"次の地下鉄の列車まであと何分ですか？\", \"translated\": \"Quanto manca al prossimo treno della metropolitana?\"}, {\"original\": \"すみません、通らせてください。\", \"translated\": \"Scusi, mi lasci passare, per favore.\"}, {\"original\": \"この席は空いていますか？\", \"translated\": \"Questo posto è occupato?\"}, {\"original\": \"すみません、XXへ行くには２号線にどこで乗り換えればいいですか？\", \"translated\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\"}, {\"original\": \"XXへはどう行けばいいですか？\", \"translated\": \"Come arrivo a XX?\"}]', 4, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"観光地で使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、観光地に関連する一般的な表現を10個、イタリア語訳とともにご紹介します。\"]', '[\"観光\", \"写真撮影\", \"チケット購入\"]', 'ja', '[\"今のところ、チケットの価格を尋ねる、駐車場を探す、またはガイドサービスを利用するなど、特定の状況が頭に浮かんでいますか？何でもお気軽にお尋ねください。\", \"頭に浮かんでいる状況を教えてください。\"]', NULL, '[{\"original\": \"入場料はいくらですか？\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"学生割引のチケットはありますか？\", \"translated\": \"Sono disponibili biglietti per studenti?\"}, {\"original\": \"観光スポットの開園時間は何時ですか？\", \"translated\": \"A che ora apre la attrazione?\"}, {\"original\": \"ここではどんな楽しいことが体験できますか？\", \"translated\": \"Quali sono le cose divertenti da fare qui?\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"Potrebbe scattarci una foto?\"}, {\"original\": \"観光バスの乗り場はどこですか？\", \"translated\": \"Dove si trova l\'autobus per i tour turistici?\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"Dove si trova il bagno?\"}, {\"original\": \"一番良い展望スポットはどこですか？\", \"translated\": \"Dove si trova il punto migliore per osservare la vista?\"}, {\"original\": \"ここからの景色はとても美しいです。\", \"translated\": \"Il paesaggio qui è bellissimo.\"}, {\"original\": \"ガイド付きツアーはありますか？\", \"translated\": \"È disponibile un tour guidato?\"}]', 5, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"タクシーまたはタクシーサービスで使える一般的な表現を10個教えていただけますか？\", \"素晴らしいです！以下に、タクシーまたはタクシーサービスに関連する一般的な表現10個とそのイタリア語訳を示します：\"]', '[\"タクシーを利用する\", \"行き先を伝える\", \"支払い\"]', 'ja', '[\"今のところ、目的地の確認、料金の確認、領収書の請求など、今最も知りたいことを自由にお尋ねください。\", \"頭の中で思い浮かぶ状況を教えてください。\"]', NULL, '[{\"original\": \"タクシーはどこで乗れますか？\", \"translated\": \"Dove posso prendere un taxi?\"}, {\"original\": \"この住所までお願いします。\", \"translated\": \"Mi porti a questo indirizzo, per favore.\"}, {\"original\": \"だいたいいくらぐらいになりますか？\", \"translated\": \"Quanto costerà all\'incirca?\"}, {\"original\": \"メーターを使っていただけますか？\", \"translated\": \"Potrebbe usare il tassametro, per favore?\"}, {\"original\": \"急いでいるので、もう少し速く運転していただけますか？\", \"translated\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\"}, {\"original\": \"ここで止めてください。\", \"translated\": \"Si fermi qui, per favore.\"}, {\"original\": \"カードやモバイル決済は使えますか？\", \"translated\": \"Accetta carte di credito o pagamenti mobili?\"}, {\"original\": \"領収書をいただけますか？\", \"translated\": \"Potrei avere lo scontrino, per favore?\"}, {\"original\": \"ありがとうございました、運転手さん。\", \"translated\": \"Grazie, autista.\"}, {\"original\": \"あとどのくらいですか？\", \"translated\": \"Quanto manca ancora?\"}]', 6, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"薬局で使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、薬局でよく使われる10個の表現とそのイタリア語訳を示します：\"]', '[\"薬の購入\", \"相談\", \"支払い\"]', 'ja', '[\"今のところ、服薬方法の説明を尋ねる場面や、保険の利用に関する表現、服用期間など、特定の状況が頭に浮かんでいますか？何でもお気軽にお尋ねください。\", \"頭に浮かんでいる状況を教えてください。\"]', NULL, '[{\"original\": \"風邪薬はありますか？\", \"translated\": \"Ha dei farmaci per il raffreddore?\"}, {\"original\": \"この薬の飲み方はどうすればいいですか？\", \"translated\": \"Come devo assumere questo farmaco?\"}, {\"original\": \"鎮痛剤はありますか？\", \"translated\": \"Ha degli antidolorifici?\"}, {\"original\": \"説明書は付いていますか？\", \"translated\": \"È incluso un foglietto illustrativo?\"}, {\"original\": \"この薬には副作用がありますか？\", \"translated\": \"Questo farmaco ha effetti collaterali?\"}, {\"original\": \"医療保険証を使っても大丈夫ですか？\", \"translated\": \"Posso utilizzare la mia tessera sanitaria?\"}, {\"original\": \"バンドエイドを一箱お願いできますか？\", \"translated\": \"Potrei avere una confezione di cerotti, per favore?\"}, {\"original\": \"解熱剤はありますか？\", \"translated\": \"Ha dei farmaci per abbassare la febbre?\"}, {\"original\": \"ちょっと擦り傷をしました。消毒液とバンドエイドはありますか？\", \"translated\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\"}, {\"original\": \"何時まで営業していますか？\", \"translated\": \"A che ora chiude?\"}]', 7, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"緊急サービスで使える一般的な表現を10個教えていただけますか？\", \"素晴らしいです！以下に、緊急サービスに関連する一般的な表現10個とそのイタリア語訳を示します：\"]', '[\"警察を呼ぶ\", \"応急処置\", \"助けを呼ぶ\"]', 'ja', '[\"今のところ、火事、怪我をして助けが必要、緊急通報など、特定の緊急状況について考えていますか？ご質問は自由にしてください。\", \"頭の中にある状況を教えてください。\"]', NULL, '[{\"original\": \"救急車を呼んでください。\", \"translated\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\"}, {\"original\": \"病院はどこですか？\", \"translated\": \"Dov\'è l\'ospedale?\"}, {\"original\": \"誰かが怪我をしました。\", \"translated\": \"Qualcuno è ferito.\"}, {\"original\": \"助けてください。\", \"translated\": \"Per favore, mi aiuti.\"}, {\"original\": \"警察署はどこですか？\", \"translated\": \"Dov\'è la stazione di polizia?\"}, {\"original\": \"荷物をなくしました。\", \"translated\": \"Ho perso i miei effetti personali.\"}, {\"original\": \"消防署の電話番号は何番ですか？\", \"translated\": \"Qual è il numero dei vigili del fuoco?\"}, {\"original\": \"パスポートを紛失しました。近くの警察署はどこですか？\", \"translated\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\"}, {\"original\": \"非常口はありますか？\", \"translated\": \"C\'è un\'uscita di emergenza?\"}, {\"original\": \"誰かが気を失いました。\", \"translated\": \"Qualcuno è svenuto.\"}]', 8, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"ビーチやプールサイドで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、ビーチやプールサイドに関連する一般的な表現10個とそのイタリア語訳を示します：\"]', '[\"水泳\", \"日光浴\", \"ビーチスポーツ\"]', 'ja', '[\"現時点では、ご参加予定の地域のイベントやフェスティバル（例：文化フェスティバル、フードフェスティバル、音楽フェスティバルなど）の背景情報を教えていただけますか？背景情報をお知らせください。\", \"ご参加予定のアクティビティを教えてください。\"]', '[\"具体的な状況が頭に浮かんでいますか？遠慮なくお尋ねください。\", \"頭に浮かんでいる状況を詳しく教えてください。\"]', '[{\"original\": \"見て！あそこに見える波がとても大きいよ。\", \"translated\": \"Guarda! Le onde laggiù sono davvero grandi.\"}, {\"original\": \"日焼け止めを塗ることを忘れないでね。ここでの紫外線はとても強いから。\", \"translated\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\"}, {\"original\": \"このビーチの砂はとても細かくて、綿の上を歩いているような感じがする。\", \"translated\": \"La sabbia di questa spiaggia è così fine che sembra camminare sul cotone.\"}, {\"original\": \"ビーチでバレーボールをやるのはどう？\", \"translated\": \"Che ne dici di giocare a pallavolo in spiaggia?\"}, {\"original\": \"遠くに見えるヨットがとても美しいね。\", \"translated\": \"Le barche a vela in lontananza sembrano bellissime.\"}, {\"original\": \"ここでの水はとても透明で、魚まで見えちゃうよ。\", \"translated\": \"L\'acqua qui è così trasparente che si riescono persino a vedere i pesci.\"}, {\"original\": \"一緒に貝殻を探しに行こう。\", \"translated\": \"Andiamo a cercare delle conchiglie.\"}, {\"original\": \"夕日が沈む頃のビーチ散歩はきっととてもロマンチックだろうね。\", \"translated\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\"}, {\"original\": \"ここでは海産物がとても新鮮だと聞いたから、ぜひ食べてみよう。\", \"translated\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\"}, {\"original\": \"潮が満ちてきてるから、そろそろ岸に向かおう。\", \"translated\": \"La marea sta salendo, dirigiamoci verso la riva.\"}]', 9, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"地域のイベントや祭りで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、地域のイベントや祭りに関連する一般的な表現10個とそのイタリア語訳を示します：\"]', '[\"イベントへの参加\", \"祭りの祝い\", \"文化の学習\"]', 'ja', '[\"現時点で、ハロウィン、コンサート、友人とのパーティーなど、ご参加予定の地域イベントや祭りの状況について教えていただけますか？それ以外の状況でも構いませんので、お知らせください。\", \"頭に浮かぶ活動内容を教えてください。\"]', '[\"特定の状況が思い浮かんでいますか？遠慮なくお尋ねください。\", \"頭に浮かぶ状況を教えてください。\"]', '[{\"original\": \"今日は何かイベントがありますか？\", \"translated\": \"Ci sono eventi oggi?\"}, {\"original\": \"この祭りには何か特別なことがありますか？\", \"translated\": \"C\'è qualcosa di speciale in questo festival?\"}, {\"original\": \"お祝いはどこで行われますか？\", \"translated\": \"Dove si tiene la celebrazione?\"}, {\"original\": \"チケットはどのように購入できますか？\", \"translated\": \"Come posso acquistare i biglietti?\"}, {\"original\": \"パフォーマンスは何時から始まりますか？\", \"translated\": \"A che ora inizia lo spettacolo?\"}, {\"original\": \"どんな伝統的な食べ物がありますか？\", \"translated\": \"Quali sono i cibi tradizionali?\"}, {\"original\": \"ここは本当ににぎやかですね。\", \"translated\": \"Qui è davvero animato.\"}, {\"original\": \"民俗活動はありますか？\", \"translated\": \"Ci sono attività popolari?\"}, {\"original\": \"楽しい休日を！\", \"translated\": \"Buone feste!\"}, {\"original\": \"イベントは何時までですか？\", \"translated\": \"A che ora termina l\'evento?\"}]', 10, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"美術館や博物館で使える一般的な表現を10個教えていただけますか？\", \"素晴らしいです！以下に、美術館や博物館に関連する一般的な表現10個と、そのイタリア語訳を示します：\"]', '[\"訪問\", \"ガイド付きツアー\", \"チケット購入\"]', 'ja', '[\"今のところ、ガイドブックの請求、見学ルートに関する表現、展示品への感想を述べる表現など、具体的な状況が頭に浮かんでいますか？ご自由にお尋ねください。\", \"頭に浮かんでいる状況を教えてください。\"]', NULL, '[{\"original\": \"入館料はいくらですか？\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"オーディオガイドはありますか？\", \"translated\": \"Avete guide audio?\"}, {\"original\": \"この作品は誰が制作したのですか？\", \"translated\": \"Chi ha creato quest\'opera d\'arte?\"}, {\"original\": \"美術館の最も貴重な作品はどこにありますか？\", \"translated\": \"Dove si trova il pezzo più prezioso del museo?\"}, {\"original\": \"写真撮影は許可されていますか？\", \"translated\": \"È consentito fare fotografie?\"}, {\"original\": \"ここには特別展はありますか？\", \"translated\": \"Ci sono delle mostre speciali qui?\"}, {\"original\": \"見学にはどのくらいの時間がかかりますか？\", \"translated\": \"Quanto tempo richiede la visita?\"}, {\"original\": \"ご案内いただけますか？\", \"translated\": \"Potreste darci una breve introduzione?\"}, {\"original\": \"これらの作品は本当に素晴らしいです。\", \"translated\": \"Queste opere sono davvero squisite.\"}, {\"original\": \"お土産ショップはどこですか？\", \"translated\": \"Dove si trova il negozio dei souvenir?\"}]', 11, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"カフェで使える一般的な表現を10個教えていただけますか？\", \"素晴らしい！以下に、カフェに関連する一般的な表現10個とそのイタリア語訳をご紹介します：\"]', '[\"コーヒーを注文する\", \"休む\", \"交流する\"]', 'ja', '[\"今のところ、メニューの注文、アイスまたはホットドリンクの依頼、その他の商品の確認など、特定の状況をお考えですか？遠慮なくご質問ください。\", \"お考えの状況をご説明ください。\"]', NULL, '[{\"original\": \"ラテを一杯お願いします。\", \"translated\": \"Prenderò un caffè latte, per favore.\"}, {\"original\": \"Wi-Fiはありますか？\", \"translated\": \"Avete il Wi-Fi?\"}, {\"original\": \"メニューを見せていただけますか？\", \"translated\": \"Potrei vedere il menu, per favore?\"}, {\"original\": \"追加注文はできますか？\", \"translated\": \"Sono ammesse le ricariche?\"}, {\"original\": \"私のコーヒーはできましたか？\", \"translated\": \"Il mio caffè è pronto?\"}, {\"original\": \"ここにどのくらい座っていられますか？\", \"translated\": \"Per quanto tempo posso stare seduto qui?\"}, {\"original\": \"私たちの写真を撮っていただけますか？\", \"translated\": \"Potrebbe fare una foto per noi?\"}, {\"original\": \"トイレはどこですか？\", \"translated\": \"Dov\'è il bagno?\"}, {\"original\": \"お会計をお願いします。ありがとうございます。\", \"translated\": \"Il conto, per favore. Grazie.\"}, {\"original\": \"とてもおいしいです。\", \"translated\": \"Ha davvero un ottimo sapore.\"}]', 12, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a restaurant?\", \"Fantastic! Here are 10 common phrases related to restaurants, along with Italian translations:\"]', '[\"Dining\", \"Ordering\", \"Checkout\"]', 'en', '[\"For now, do you have a specific situation in mind, such as ordering drinks, making a complaint, or asking about ingredients? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Excuse me, how much longer will our food be?\", \"translated\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\"}, {\"original\": \"A table for two, please.\", \"translated\": \"Un tavolo per due, per favore.\"}, {\"original\": \"Could we see the menu, please?\", \"translated\": \"Potremmo vedere il menu, per favore?\"}, {\"original\": \"Do you have any signature dishes to recommend?\", \"translated\": \"Avete dei piatti tipici da consigliarci?\"}, {\"original\": \"I\'d like to order this, and this.\", \"translated\": \"Vorrei ordinare questo e quest’altro.\"}, {\"original\": \"A glass of water, please. Thanks.\", \"translated\": \"Un bicchiere d’acqua, per favore. Grazie.\"}, {\"original\": \"The bill, please.\", \"translated\": \"Il conto, per favore.\"}, {\"original\": \"Can I pay by credit card?\", \"translated\": \"Posso pagare con carta di credito?\"}, {\"original\": \"Could you pack this to go, please?\", \"translated\": \"Potrebbe confezionarmelo da asporto, per favore?\"}, {\"original\": \"The food was delicious, thank you.\", \"translated\": \"Il cibo era delizioso, grazie.\"}]', 1, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a hotel?\", \"Fantastic! Here are 10 common phrases related to hotels, along with Italian translations:\"]', '[\"Check-in\", \"Check-out\", \"Room Service\"]', 'en', '[\"For now, do you have a specific situation in mind, such as room location, other hotel services, or check-out? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Hello, I have a reservation. Here is my passport.\", \"translated\": \"Salve, ho una prenotazione. Ecco il mio passaporto.\"}, {\"original\": \"Do you have any vacancies?\", \"translated\": \"Avete camere disponibili?\"}, {\"original\": \"Excuse me, does the hotel have a gym or a laundry room?\", \"translated\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\"}, {\"original\": \"What time does breakfast start?\", \"translated\": \"A che ora inizia la colazione?\"}, {\"original\": \"Could I have a room key, please?\", \"translated\": \"Potrei avere la chiave della mia camera, per favore?\"}, {\"original\": \"Could you help me take my luggage to the room?\", \"translated\": \"Potrebbe aiutarmi a portare i miei bagagli nella camera?\"}, {\"original\": \"How do I call room service?\", \"translated\": \"Come posso chiamare il servizio in camera?\"}, {\"original\": \"What time is check-out?\", \"translated\": \"A che ora è il check-out?\"}, {\"original\": \"Could you write me a receipt/invoice?\", \"translated\": \"Potrebbe rilasciarmi una ricevuta/fattura?\"}, {\"original\": \"Can I leave my luggage here?\", \"translated\": \"Posso lasciare qui i miei bagagli?\"}]', 2, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use at the airport?\", \"Fantastic! Here are 10 common phrases related to the airport, along with Italian translations:\"]', '[\"Check-in\", \"Boarding\", \"Baggage Check\"]', 'en', '[\"For now, do you have a specific situation in mind, such as check-in, baggage claim, or car rental service? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Where is the check-in counter?\", \"translated\": \"Dov\'è il banco del check-in?\"}, {\"original\": \"I\'d like a window seat, please.\", \"translated\": \"Vorrei un posto vicino al finestrino, per favore.\"}, {\"original\": \"Is this flight delayed?\", \"translated\": \"Questo volo è in ritardo?\"}, {\"original\": \"I need to check this baggage.\", \"translated\": \"Devo registrare questo bagaglio.\"}, {\"original\": \"Where is the boarding gate?\", \"translated\": \"Dov\'è l\'ingresso per l\'imbarco?\"}, {\"original\": \"The plane is about to take off.\", \"translated\": \"L\'aeroplano sta per decollare.\"}, {\"original\": \"Do I need to take out my laptop and power bank?\", \"translated\": \"Devo estrarre il mio laptop e la power bank?\"}, {\"original\": \"Where is the duty-free shop?\", \"translated\": \"Dov\'è il negozio duty-free?\"}, {\"original\": \"I can\'t find my suitcase.\", \"translated\": \"Non riesco a trovare la mia valigia.\"}, {\"original\": \"Do you have a wheelchair service?\", \"translated\": \"Offrite un servizio di sedia a rotelle?\"}]', 3, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in public transportation?\", \"Fantastic! Here are 10 common phrases related to public transportation, along with Italian translations:\"]', '[\"Taking Bus/Subway\", \"Buying Tickets\", \"Transferring\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking for a bus stop, ticket price, or when to get off? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Does this bus go to the terminal?\", \"translated\": \"Questo autobus va al capolinea?\"}, {\"original\": \"What is the next stop?\", \"translated\": \"Qual è la prossima fermata?\"}, {\"original\": \"Where can I buy a ticket?\", \"translated\": \"Dove posso acquistare un biglietto?\"}, {\"original\": \"One ticket to XX, please.\", \"translated\": \"Un biglietto per XX, per favore.\"}, {\"original\": \"Do I need to transfer?\", \"translated\": \"Devo cambiare mezzo?\"}, {\"original\": \"How long until the next subway train?\", \"translated\": \"Tra quanto arriva il prossimo treno della metropolitana?\"}, {\"original\": \"Excuse me, please let me pass.\", \"translated\": \"Scusi, mi lasci passare, per favore.\"}, {\"original\": \"Is this seat taken?\", \"translated\": \"Questo posto è occupato?\"}, {\"original\": \"Excuse me, where can I transfer to Line 2 to get to XX?\", \"translated\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\"}, {\"original\": \"How do I get to XX?\", \"translated\": \"Come arrivo a XX?\"}]', 4, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in tourist attractions?\", \"Fantastic! Here are 10 common phrases related to tourist attractions, along with Italian translations:\"]', '[\"Sightseeing\", \"Taking Photos\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking about ticket prices, finding a parking lot, or requesting tour guide services? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"How much is the entrance fee?\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"Are there student tickets available?\", \"translated\": \"Sono disponibili biglietti per studenti?\"}, {\"original\": \"What time does the attraction open?\", \"translated\": \"A che ora apre la attrazione?\"}, {\"original\": \"What are the fun things to do here?\", \"translated\": \"Quali sono le cose divertenti da fare qui?\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"Potrebbe scattarci una foto?\"}, {\"original\": \"Where is the sightseeing bus?\", \"translated\": \"Dove si trova l\'autobus turistico?\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"Dove si trova il bagno?\"}, {\"original\": \"Where is the best viewing spot?\", \"translated\": \"Dove si trova il punto migliore per osservare?\"}, {\"original\": \"The scenery here is beautiful.\", \"translated\": \"Il panorama qui è bellissimo.\"}, {\"original\": \"Is there a guided tour available?\", \"translated\": \"È disponibile un tour guidato?\"}]', 5, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in Taxi or Taxi Service?\", \"Fantastic! Here are 10 common phrases related to Taxi or Taxi Service, along with Italian translations:\"]', '[\"Taking Taxi\", \"Telling Destination\", \"Payment\"]', 'en', '[\"For now, what do you most want to do now—such as asking for the destination, the fare, or requesting an invoice? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Where can I get a taxi?\", \"translated\": \"Dove posso prendere un taxi?\"}, {\"original\": \"Please take me to this address.\", \"translated\": \"Mi porti a questo indirizzo, per favore.\"}, {\"original\": \"Roughly how much will it be?\", \"translated\": \"Quanto costerà all\'incirca?\"}, {\"original\": \"Could you use the meter, please?\", \"translated\": \"Potrebbe usare il tassametro, per favore?\"}, {\"original\": \"Please drive a bit faster, I\'m in a hurry.\", \"translated\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\"}, {\"original\": \"Please stop here.\", \"translated\": \"Si fermi qui, per favore.\"}, {\"original\": \"Do you accept cards or mobile payments?\", \"translated\": \"Accetta carte di credito o pagamenti mobili?\"}, {\"original\": \"Could I have a receipt, please?\", \"translated\": \"Potrei avere lo scontrino, per favore?\"}, {\"original\": \"Thank you, driver.\", \"translated\": \"Grazie, autista.\"}, {\"original\": \"How much further is it?\", \"translated\": \"Quanto manca ancora?\"}]', 6, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in pharmacy?\", \"Fantastic! Here are 10 common phrases related to pharmacy, along with Italian translations:\"]', '[\"Buying Medicine\", \"Consultation\", \"Payment\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking for instructions on taking medicine, phrases related to using insurance, or duration of medication? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Do you have cold medicine?\", \"translated\": \"Ha dei farmaci per il raffreddore?\"}, {\"original\": \"How should I take this medicine?\", \"translated\": \"Come devo assumere questo farmaco?\"}, {\"original\": \"Do you have any painkillers?\", \"translated\": \"Ha degli antidolorifici?\"}, {\"original\": \"Is there an instruction leaflet?\", \"translated\": \"È incluso un foglietto illustrativo?\"}, {\"original\": \"Does this medicine have any side effects?\", \"translated\": \"Questo farmaco ha effetti collaterali?\"}, {\"original\": \"Can I use my medical insurance card?\", \"translated\": \"Posso utilizzare la mia tessera sanitaria?\"}, {\"original\": \"Could I have a box of Band-Aids, please?\", \"translated\": \"Potrei avere una confezione di cerotti, per favore?\"}, {\"original\": \"Do you have any fever reducers?\", \"translated\": \"Ha dei farmaci antipiretici?\"}, {\"original\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\", \"translated\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\"}, {\"original\": \"What time do you close?\", \"translated\": \"A che ora chiude?\"}]', 7, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in Emergency Services?\", \"Fantastic! Here are 10 common phrases related to Emergency Services, along with Italian translations:\"]', '[\"Calling Police\", \"First Aid\", \"Calling for Help\"]', 'en', '[\"For now, do you have a specific emergency situation in mind, such as fire, injury and need for help, or an emergency call? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"Please help me call an ambulance.\", \"translated\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\"}, {\"original\": \"Where is the hospital?\", \"translated\": \"Dov\'è l\'ospedale?\"}, {\"original\": \"Someone is injured.\", \"translated\": \"Qualcuno è ferito.\"}, {\"original\": \"Please help me.\", \"translated\": \"Per favore, mi aiuti.\"}, {\"original\": \"Where is the police station?\", \"translated\": \"Dov\'è la stazione di polizia?\"}, {\"original\": \"I\'ve lost my belongings.\", \"translated\": \"Ho perso i miei oggetti.\"}, {\"original\": \"What is the number for the fire department?\", \"translated\": \"Qual è il numero del corpo dei vigili del fuoco?\"}, {\"original\": \"I\'ve lost my passport. Do you know where the nearest police station is?\", \"translated\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\"}, {\"original\": \"Is there an emergency exit?\", \"translated\": \"C\'è un\'uscita di emergenza?\"}, {\"original\": \"Someone has fainted.\", \"translated\": \"Qualcuno è svenuto.\"}]', 8, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use at the beach or poolside?\", \"Fantastic! Here are 10 common phrases related to the beach or poolside, along with Italian translations:\"]', '[\"Swimming\", \"Sunbathing\", \"Beach Sports\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you\'re attending, such as a cultural festival, food festival, or music festival? Please provide the context.\", \"Please provide the activities that you attend.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation in your mind.\"]', '[{\"original\": \"Look! The waves over there are really big.\", \"translated\": \"Guarda! Le onde laggiù sono davvero grandi.\"}, {\"original\": \"Remember to apply sunscreen; the UV rays here are very strong.\", \"translated\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\"}, {\"original\": \"The sand on this beach is so fine, it feels like stepping on cotton.\", \"translated\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\"}, {\"original\": \"How about playing volleyball on the beach?\", \"translated\": \"Che ne dici di giocare a pallavolo sulla spiaggia?\"}, {\"original\": \"The sailboats in the distance look beautiful.\", \"translated\": \"Le barche a vela in lontananza sembrano bellissime.\"}, {\"original\": \"The water here is so clear, you can even see the fish.\", \"translated\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\"}, {\"original\": \"Let\'s go find some seashells.\", \"translated\": \"Andiamo a cercare delle conchiglie.\"}, {\"original\": \"Taking a walk on the beach at sunset must be very romantic.\", \"translated\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\"}, {\"original\": \"I heard the seafood here is very fresh; let\'s go try some.\", \"translated\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\"}, {\"original\": \"The tide is coming in; let\'s head towards the shore.\", \"translated\": \"La marea sta salendo, dirigiamoci verso la riva.\"}]', 9, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in Local Events and Festivals?\", \"Fantastic! Here are 10 common phrases related to Local Events and Festivals, along with Italian translations:\"]', '[\"Attending Events\", \"Celebrating Festivals\", \"Learning Culture\"]', 'en', '[\"For now, could you please provide me with the context of the local event or festival you\'re attending, such as Halloween, a concert, a friend\'s party, or something else? Please provide the context.\", \"Please describe the activities you have in mind.\"]', '[\"Do you have a specific situation in mind? Feel free to ask.\", \"Please describe the situation you have in mind.\"]', '[{\"original\": \"Are there any events today?\", \"translated\": \"Ci sono eventi oggi?\"}, {\"original\": \"Is there anything special about this festival?\", \"translated\": \"C\'è qualcosa di speciale in questo festival?\"}, {\"original\": \"Where is the celebration being held?\", \"translated\": \"Dove si tiene la celebrazione?\"}, {\"original\": \"How can I buy tickets?\", \"translated\": \"Come posso acquistare i biglietti?\"}, {\"original\": \"What time does the performance start?\", \"translated\": \"A che ora inizia lo spettacolo?\"}, {\"original\": \"What traditional food is there?\", \"translated\": \"Quali sono i cibi tradizionali?\"}, {\"original\": \"It\'s really lively here.\", \"translated\": \"Qui è davvero animato.\"}, {\"original\": \"Are there any folk activities?\", \"translated\": \"Ci sono attività popolari?\"}, {\"original\": \"Happy holidays!\", \"translated\": \"Buone feste!\"}, {\"original\": \"What time does the event end?\", \"translated\": \"A che ora termina l\'evento?\"}]', 10, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in a museum or art gallery?\", \"Fantastic! Here are 10 common phrases related to museums or art galleries, along with Italian translations:\"]', '[\"Visiting\", \"Guided Tour\", \"Buying Tickets\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking for an introduction manual, phrases related to a roadmap, or phrases related to commenting on an exhibit? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"How much is the admission fee?\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"Do you have audio guides?\", \"translated\": \"Avete guide audio?\"}, {\"original\": \"Who created this artwork?\", \"translated\": \"Chi ha creato quest\'opera d\'arte?\"}, {\"original\": \"Where is the museum\'s most prized piece?\", \"translated\": \"Dove si trova il pezzo più prezioso del museo?\"}, {\"original\": \"Is photography allowed?\", \"translated\": \"È consentito fare fotografie?\"}, {\"original\": \"Are there any special exhibitions here?\", \"translated\": \"Ci sono delle mostre speciali qui?\"}, {\"original\": \"How long does the visit take?\", \"translated\": \"Quanto tempo richiede la visita?\"}, {\"original\": \"Could you give us an introduction?\", \"translated\": \"Potreste darci una breve introduzione?\"}, {\"original\": \"These works are truly exquisite.\", \"translated\": \"Queste opere sono davvero squisite.\"}, {\"original\": \"Where is the souvenir shop?\", \"translated\": \"Dove si trova il negozio dei souvenir?\"}]', 11, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Could you provide me with 10 common phrases I can use in cafes?\", \"Fantastic! Here are 10 common phrases related to cafes, along with Italian translations:\"]', '[\"Ordering Coffee\", \"Resting\", \"Socializing\"]', 'en', '[\"For now, do you have a specific situation in mind, such as asking for a menu, ordering ice or hot drinks, requesting other products? Feel free to ask.\", \"Please describe the situation in your mind.\"]', NULL, '[{\"original\": \"I\'ll have a latte, please.\", \"translated\": \"Prenderò un caffè latte, per favore.\"}, {\"original\": \"Do you have Wi-Fi?\", \"translated\": \"Avete il Wi-Fi?\"}, {\"original\": \"Could I see the menu, please?\", \"translated\": \"Potrei vedere il menu, per favore?\"}, {\"original\": \"Are refills allowed?\", \"translated\": \"Sono ammesse le ricariche?\"}, {\"original\": \"Is my coffee ready?\", \"translated\": \"Il mio caffè è pronto?\"}, {\"original\": \"How long can I sit here?\", \"translated\": \"Per quanto tempo posso stare seduto qui?\"}, {\"original\": \"Could you take a picture for us?\", \"translated\": \"Potrebbe fare una foto per noi?\"}, {\"original\": \"Where is the restroom?\", \"translated\": \"Dov\'è il bagno?\"}, {\"original\": \"Check, please. Thank you.\", \"translated\": \"Il conto, per favore. Grazie.\"}, {\"original\": \"It tastes really good.\", \"translated\": \"Ha davvero un ottimo sapore.\"}]', 12, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في المطعم؟\", \"رائع! إليك عشر عبارات شائعة مرتبطة بالمطاعم، مع الترجمات الإيطالية لها:\"]', '[\"الوجبات\", \"الطلب\", \"إنهاء الشراء\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف محدد في ذهنك، مثل طلب المشروبات أو تقديم شكوى أو الاستفسار عن المكونات؟ لا تتردد في السؤال.\", \"يرجى وصف الموقف الذي يخطر ببالك.\"]', NULL, '[{\"original\": \"عذرًا، كم من الوقت سيستغرق وصول طعامنا؟\", \"translated\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\"}, {\"original\": \"طاولة لشخصين، من فضلكم.\", \"translated\": \"Un tavolo per due, per favore.\"}, {\"original\": \"هل يمكننا رؤية القائمة، من فضلكم؟\", \"translated\": \"Potremmo vedere il menu, per favore?\"}, {\"original\": \"هل لديكم أطباق مميزة توصون بها؟\", \"translated\": \"Avete dei piatti tipici da consigliarci?\"}, {\"original\": \"أود طلب هذا وهذا.\", \"translated\": \"Vorrei ordinare questo e quest’altro.\"}, {\"original\": \"كوب من الماء، من فضلكم. شكرًا لكم.\", \"translated\": \"Un bicchiere d’acqua, per favore. Grazie.\"}, {\"original\": \"الفاتورة، من فضلكم.\", \"translated\": \"Il conto, per favore.\"}, {\"original\": \"هل يمكنني الدفع باستخدام بطاقة الائتمان؟\", \"translated\": \"Posso pagare con carta di credito?\"}, {\"original\": \"هل يمكنكم تغليف هذا لل带走، من فضلكم؟\", \"translated\": \"Potrebbe confezionarmelo da asporto, per favore?\"}, {\"original\": \"كان الطعام لذيذًا جدًّا، شكرًا لكم.\", \"translated\": \"Il cibo era delizioso, grazie.\"}]', 1, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في الفندق؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بالفندق، مع الترجمات الإيطالية لها:\"]', '[\"تسجيل الدخول\", \"تسجيل المغادرة\", \"خدمة الغرف\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقف معين في ذهنك، مثل موقع الغرفة أو أي خدمة أخرى يقدمها الفندق أو عملية المغادرة؟ لا تتردد في طرح الأسئلة.\", \"من فضلك وصف الموقف الذي يدور في ذهنك.\"]', NULL, '[{\"original\": \"مرحبًا، لدي حجزٌ، وهذه جواز سفري.\", \"translated\": \"Salve, ho una prenotazione, ecco il mio passaporto.\"}, {\"original\": \"هل لديكم أي غرف شاغرة؟\", \"translated\": \"Avete camere disponibili?\"}, {\"original\": \"عذرًا، هل يحتوي الفندق على صالة ألعاب رياضية أو غرفة لغسيل الملابس؟\", \"translated\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\"}, {\"original\": \"في أي وقت تبدأ وجبة الإفطار؟\", \"translated\": \"A che ora inizia la colazione?\"}, {\"original\": \"هل يمكنني الحصول على مفتاح الغرفة، من فضلكم؟\", \"translated\": \"Potrei avere la chiave della mia camera, per favore?\"}, {\"original\": \"هل يمكنكم مساعدتي في حمل أمتعتي إلى الغرفة؟\", \"translated\": \"Potrebbe aiutarmi a portare i miei bagagli nella camera?\"}, {\"original\": \"كيف أطلب خدمة الغرف؟\", \"translated\": \"Come posso chiamare il servizio in camera?\"}, {\"original\": \"في أي وقت يتم المغادرة؟\", \"translated\": \"A che ora è il check-out?\"}, {\"original\": \"هل يمكنكم إعطائي إيصالًا/فاتورةً؟\", \"translated\": \"Potrebbe rilasciarmi una ricevuta/fattura?\"}, {\"original\": \"هل يمكنني ترك أمتعتي هنا؟\", \"translated\": \"Posso lasciare qui i miei bagagli?\"}]', 2, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في المطار؟\", \"رائع! إليكم عشر عبارات شائعة تتعلق بالمطار، مع الترجمات الإيطالية لها:\"]', '[\"التسجيل\", \"الصعود إلى الطائرة\", \"فحص الأمتعة\"]', 'ar', '[\"في الوقت الحالي، هل تدور في ذهنك حالة محددة، مثل تسجيل الوصول أو استلام الأمتعة أو خدمة تأجير السيارات؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الحالة التي تدور في ذهنك.\"]', NULL, '[{\"original\": \"أين كاونتر تسجيل الوصول؟\", \"translated\": \"Dov\'è il banco del check-in?\"}, {\"original\": \"أود مقعدًا بجانب النافذة، من فضلك.\", \"translated\": \"Vorrei un posto vicino al finestrino, per favore.\"}, {\"original\": \"هل هذا الرحلة متأخرة؟\", \"translated\": \"Questo volo è in ritardo?\"}, {\"original\": \"أحتاج إلى فحص هذه الأمتعة.\", \"translated\": \"Devo registrare questo bagaglio.\"}, {\"original\": \"أين بوابة الصعود إلى الطائرة؟\", \"translated\": \"Dov\'è l\'ingresso per l\'imbarco?\"}, {\"original\": \"الطائرة على وشك الإقلاع.\", \"translated\": \"L\'aeroplano sta per decollare.\"}, {\"original\": \"هل يجب أن أخرج جهاز الكمبيوتر المحمول والبنك الكهربائي الخاص بي؟\", \"translated\": \"Devo estrarre il mio laptop e la power bank?\"}, {\"original\": \"أين متجر التخفيضات الجمركية؟\", \"translated\": \"Dov\'è il negozio duty-free?\"}, {\"original\": \"لا أستطيع العثور على حقيبتي.\", \"translated\": \"Non riesco a trovare la mia valigia.\"}, {\"original\": \"هل تقدمون خدمة الكرسي المتحرك؟\", \"translated\": \"Offrite un servizio di sedia a rotelle?\"}]', 3, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في وسائل النقل العام؟\", \"رائع! إليكم عشر عبارات شائعة تتعلق بوسائل النقل العام، مع الترجمات الإيطالية لها:\"]', '[\"ركوب الحافلة أو المترو\", \"شراء التذاكر\", \"التحويل\"]', 'ar', '[\"لحد الآن، هل لديك موقفٌ معيّن في ذهنك، مثل الاستفسار عن موقف الحافلة أو سعر التذكرة أو طلب النزول من الحافلة؟ لا تتردد في طرح أي سؤال.\", \"من فضلك صف الموقف الذي يدور في ذهنك.\"]', NULL, '[{\"original\": \"هل هذه الحافلة تذهب إلى المحطة؟\", \"translated\": \"Questo autobus va alla stazione?\"}, {\"original\": \"ما هي المحطة التالية؟\", \"translated\": \"Qual è la prossima fermata?\"}, {\"original\": \"أين يمكنني شراء تذكرة؟\", \"translated\": \"Dove posso comprare un biglietto?\"}, {\"original\": \"تذكرة واحدة إلى XX، من فضلك.\", \"translated\": \"Un biglietto per XX, per favore.\"}, {\"original\": \"هل عليَّ التحويل؟\", \"translated\": \"Devo cambiare?\"}, {\"original\": \"كم المدة المتبقية حتى قطار المترو القادم؟\", \"translated\": \"Quanto tempo manca al prossimo treno della metropolitana?\"}, {\"original\": \"عذرًا، من فضلك اسمح لي بالمرور.\", \"translated\": \"Scusi, mi lasci passare, per favore.\"}, {\"original\": \"هل هذا المقعد محجوز؟\", \"translated\": \"Questo posto è occupato?\"}, {\"original\": \"عذرًا، أين يمكنني التحويل إلى الخط الثاني للوصول إلى XX؟\", \"translated\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\"}, {\"original\": \"كيف أصل إلى XX؟\", \"translated\": \"Come arrivo a XX?\"}]', 4, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في أماكن الجذب السياحي؟\", \"رائع! إليك عشر عبارات شائعة تتعلق بأماكن الجذب السياحي، مع الترجمات الإيطالية الخاصة بها:\"]', '[\"السياحة\", \"التقاط الصور\", \"شراء التذاكر\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقفٌ معيّن في ذهنك، مثل الاستفسار عن سعر التذاكر، أو إيجاد موقف للسيارات، أو طلب خدمة دليل سياحي؟ لا تتردد في طرح أسئلتك.\", \"من فضلك وصف الموقف الذي يدور في ذهنك.\"]', NULL, '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"هل تتوفر تذاكر للطلاب؟\", \"translated\": \"Sono disponibili biglietti per studenti?\"}, {\"original\": \"في أي وقت يفتح المعلم السياحي؟\", \"translated\": \"A che ora apre la attrazione?\"}, {\"original\": \"ما الأشياء الممتعة التي يمكن القيام بها هنا؟\", \"translated\": \"Quali sono le cose divertenti da fare qui?\"}, {\"original\": \"هل يمكنك التقاط صورة لنا؟\", \"translated\": \"Potrebbe scattarci una foto?\"}, {\"original\": \"أين حافلة الجولات السياحية؟\", \"translated\": \"Dove si trova l\'autobus per i tour turistici?\"}, {\"original\": \"أين الحمام؟\", \"translated\": \"Dove si trova il bagno?\"}, {\"original\": \"ما أفضل مكان لمشاهدة المناظر؟\", \"translated\": \"Dove si trova il punto migliore per osservare la vista?\"}, {\"original\": \"المنظر هنا جميلٌ جدًّا.\", \"translated\": \"Il paesaggio qui è bellissimo.\"}, {\"original\": \"هل توجد جولة إرشادية متاحة؟\", \"translated\": \"È disponibile un tour guidato?\"}]', 5, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها عند استئجار تاكسي أو استخدام خدمة التاكسي؟\", \"رائع! إليكم عشر عبارات شائعة تتعلق بالتاكسي أو خدمة التاكسي، مع الترجمة الإيطالية لها:\"]', '[\"أخذ تاكسي\", \"إبلاغ الوجهة\", \"الدفع\"]', 'ar', '[\"في الوقت الحالي، ما الشيء الذي ترغب في فعله أكثر من غيره الآن، مثل الاستفسار عن الوجهة أو السعر أو طلب فاتورة؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الموقف الذي تخيله في ذهنك.\"]', NULL, '[{\"original\": \"أين يمكنني أخذ تاكسي؟\", \"translated\": \"Dove posso prendere un taxi?\"}, {\"original\": \"من فضلك خذني إلى هذا العنوان.\", \"translated\": \"Mi porti a questo indirizzo, per favore.\"}, {\"original\": \"كم يبلغ المبلغ تقريبًا؟\", \"translated\": \"Quanto costerà all\'incirca?\"}, {\"original\": \"هل يمكنك استخدام العداد من فضلك؟\", \"translated\": \"Potrebbe usare il tassametro, per favore?\"}, {\"original\": \"من فضلك ا-driving أسرع قليلًا، فأنا مستعجل.\", \"translated\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\"}, {\"original\": \"من فضلك توقف هنا.\", \"translated\": \"Si fermi qui, per favore.\"}, {\"original\": \"هل تقبل الدفع بالبطاقات أو عبر الهاتف المحمول؟\", \"translated\": \"Accetta carte di credito o pagamenti mobili?\"}, {\"original\": \"هل يمكنني الحصول على إشعار دفع من فضلك؟\", \"translated\": \"Potrei avere lo scontrino, per favore?\"}, {\"original\": \"شكرًا لك يا سائق.\", \"translated\": \"Grazie, autista.\"}, {\"original\": \"كم تبقى بعد من الطريق؟\", \"translated\": \"Quanto manca ancora?\"}]', 6, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في الصيدلية؟\", \"رائع! إليكم عشر عبارات شائعة مرتبطة بالصيدلية، مع الترجمات الإيطالية لها:\"]', '[\"شراء أدوية\", \"استشارة\", \"دفع\"]', 'ar', '[\"في الوقت الحالي، هل لديكم موقفٌ معيّن في بالكم، مثل طلب تعليمات حول كيفية تناول الدواء، أو العبارات المرتبطة باستخدام التأمين الصحي، أو مدة العلاج؟ لا تترددوا في طرح الأسئلة.\", \"من فضلكم وصفوا الموقف الذي يخطر في بالكم.\"]', NULL, '[{\"original\": \"هل لديكم دواء للبرد؟\", \"translated\": \"Ha dei farmaci per il raffreddore?\"}, {\"original\": \"كيف يجب أن آخذ هذا الدواء؟\", \"translated\": \"Come devo assumere questo farmaco?\"}, {\"original\": \"هل لديكم مسكنات للألم؟\", \"translated\": \"Ha degli antidolorifici?\"}, {\"original\": \"هل توجد نشرة إرشادات مع هذا الدواء؟\", \"translated\": \"È incluso un foglietto illustrativo?\"}, {\"original\": \"هل لهذا الدواء أي آثار جانبية؟\", \"translated\": \"Questo farmaco ha effetti collaterali?\"}, {\"original\": \"هل يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\", \"translated\": \"Posso utilizzare la mia tessera sanitaria?\"}, {\"original\": \"هل يمكنني الحصول على علبة من الضمادات اللاصقة، من فضلكم؟\", \"translated\": \"Potrei avere una confezione di cerotti, per favore?\"}, {\"original\": \"هل لديكم خافضات للحرارة؟\", \"translated\": \"Ha dei farmaci antipiretici?\"}, {\"original\": \"لدي جرح سطحي بسيط. هل لديكم مطهر وضمادات لاصقة؟\", \"translated\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\"}, {\"original\": \"في أي وقت تغلقون؟\", \"translated\": \"A che ora chiude?\"}]', 7, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في خدمات الطوارئ؟\", \"رائع! إليكم عشر عبارات شائعة تتعلق بخدمات الطوارئ، مع الترجمات الإيطالية الخاصة بها:\"]', '[\"الاتصال بالشرطة\", \"الإسعافات الأولية\", \"الاستغاثة\"]', 'ar', '[\"في الوقت الحالي، هل تدور في ذهنك حالة طارئة محددة، مثل الحريق أو الإصابة والاحتياج للمساعدة أو الاتصال بالطوارئ؟ لا تتردد في طرح أي سؤال.\", \"من فضلك وصف الحالة التي تدور في ذهنك.\"]', NULL, '[{\"original\": \"من فضلك ساعدني في الاتصال بالإسعاف.\", \"translated\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\"}, {\"original\": \"أين المستشفى؟\", \"translated\": \"Dov\'è l\'ospedale?\"}, {\"original\": \"شخص ما أُصيب.\", \"translated\": \"Qualcuno è ferito.\"}, {\"original\": \"من فضلك ساعدني.\", \"translated\": \"Per favore, mi aiuti.\"}, {\"original\": \"أين قسم الشرطة؟\", \"translated\": \"Dov\'è la stazione di polizia?\"}, {\"original\": \"لقد فقدت أغراضي.\", \"translated\": \"Ho perso i miei oggetti.\"}, {\"original\": \"ما هو رقم دائرة الإطفاء؟\", \"translated\": \"Qual è il numero del corpo dei vigili del fuoco?\"}, {\"original\": \"لقد فقدت جواز سفري. هل تعرف أين أقرب قسم شرطة؟\", \"translated\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\"}, {\"original\": \"هل يوجد مخرج طوارئ؟\", \"translated\": \"C\'è un\'uscita di emergenza?\"}, {\"original\": \"شخص ما فقد وعيه.\", \"translated\": \"Qualcuno è svenuto.\"}]', 8, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها على الشاطئ أو بالقرب من المسبح؟\", \"رائع! إليكم عشر عبارات شائعة مرتبطة بالشاطئ أو المسبح، مع الترجمات الإيطالية لها:\"]', '[\"السباحة\", \"الاستلقاء تحت أشعة الشمس\", \"الرياضات الشاطئية\"]', 'ar', '[\"في الوقت الحالي، هل يمكنكم تزويدي بسياق الحدث المحلي أو المهرجان الذي ستشاركون فيه، مثل مهرجان ثقافي أو مهرجان غذائي أو مهرجان موسيقي؟ يُرجى تزويدي بهذا السياق.\", \"يرجى تزويدي بالأنشطة التي ستشاركون فيها.\"]', '[\"هل لديكم موقفٌ معيّن في أذهانكم؟ لا تترددوا في طرح أي سؤال.\", \"وصفوا لنا الموقف الذي تفكرون فيه.\"]', '[{\"original\": \"انظر! الأمواج هناك كبيرة جدًّا.\", \"translated\": \"Guarda! Le onde laggiù sono davvero grandi.\"}, {\"original\": \"تذكَّر أن تضع واقيًا شمسيًّا، فأشعة فوق البنفسجية هنا قوية جدًّا.\", \"translated\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\"}, {\"original\": \"الرمل على هذه الشاطئ ناعم جدًّا، لدرجة أن المشي عليه يشبه المشي على القطن.\", \"translated\": \"La sabbia di questa spiaggia è così fine che sembra camminare sul cotone.\"}, {\"original\": \"ما رأيك في لعب الكرة الطائرة على الشاطئ؟\", \"translated\": \"Che ne dici di giocare a pallavolo in spiaggia?\"}, {\"original\": \"القوارب الشراعية في الأفق تبدو جميلة جدًّا.\", \"translated\": \"Le barche a vela in lontananza sembrano bellissime.\"}, {\"original\": \"الماء هنا صافٍ جدًّا، بل يمكنك رؤية الأسماك حتى.\", \"translated\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\"}, {\"original\": \"هيا نذهب للبحث عن بعض المحار.\", \"translated\": \"Andiamo a cercare delle conchiglie.\"}, {\"original\": \"التنزُّه على الشاطئ عند غروب الشمس يجب أن يكون أمرًا رومانسيًّا جدًّا.\", \"translated\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\"}, {\"original\": \"سمعتُ أن المأكولات البحرية هنا طازجة جدًّا، فلنذهب ونجرب بعضها.\", \"translated\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\"}, {\"original\": \"المدّ في ازدياد، لذا دعنا نتجه نحو الساحل.\", \"translated\": \"La marea sta salendo, dirigiamoci verso la riva.\"}]', 9, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في الفعاليات والمهرجانات المحلية؟\", \"رائع! إليكم عشر عبارات شائعة تتعلق بالفعاليات والمهرجانات المحلية، مع ترجمتها إلى الإيطالية:\"]', '[\"حضور الفعاليات\", \"الاحتفال بالمناسبات\", \"تعلم الثقافة\"]', 'ar', '[\"في الوقت الحالي، هل يمكنكم تزويدي بسياق الفعالية أو المهرجان المحلي الذي ستشاركون فيه، مثل عيد الهالوين أو الحفلة الموسيقية أو حفلة صديق أو أي شيء آخر؟ يُرجى تزويدي بهذا السياق.\", \"يرجى وصف الأنشطة التي تتبادر إلى ذهنك.\"]', '[\"هل لديكم موقف معيّن في بالكم؟ لا تترددوا في طرح سؤال.\", \"يرجى وصف الموقف الذي تتخيلونه.\"]', '[{\"original\": \"هل توجد أي فعاليات اليوم؟\", \"translated\": \"Ci sono eventi oggi?\"}, {\"original\": \"هل هناك شيء خاص في هذه المهرجان؟\", \"translated\": \"C\'è qualcosa di speciale in questo festival?\"}, {\"original\": \"أين تُقام الاحتفالية؟\", \"translated\": \"Dove si tiene la celebrazione?\"}, {\"original\": \"كيف يمكنني شراء التذاكر؟\", \"translated\": \"Come posso acquistare i biglietti?\"}, {\"original\": \"في أي وقت تبدأ العروض؟\", \"translated\": \"A che ora inizia lo spettacolo?\"}, {\"original\": \"ما الأطعمة التقليدية المتاحة؟\", \"translated\": \"Quali sono i cibi tradizionali?\"}, {\"original\": \"المكان حيويٌّ جدًّا هنا.\", \"translated\": \"Qui è davvero animato.\"}, {\"original\": \"هل توجد أنشطة شعبية؟\", \"translated\": \"Ci sono attività popolari?\"}, {\"original\": \"أعياد سعيدة!\", \"translated\": \"Buone feste!\"}, {\"original\": \"في أي وقت تنتهي الفعالية؟\", \"translated\": \"A che ora termina l\'evento?\"}]', 10, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في المتحف أو المعرض الفني؟\", \"رائع! إليك عشر عبارات شائعة مرتبطة بالمتحف أو المعرض الفني، مع الترجمات الإيطالية لها:\"]', '[\"الزيارة\", \"الجولة المُرشدة\", \"شراء التذاكر\"]', 'ar', '[\"في الوقت الحالي، هل لديك موقفٌ معيّن في ذهنك، مثل طلب كتيب التعريف، أو العبارات المتعلقة بالخريطة التوجيهية، أو العبارات المتعلقة بالتعليق على المعروضات؟ لا تتردد في طرح أي سؤال.\", \"يرجى وصف الموقف الذي يدور في ذهنك.\"]', NULL, '[{\"original\": \"كم تبلغ رسوم الدخول؟\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"هل لديكم أدلة صوتية؟\", \"translated\": \"Avete guide audio?\"}, {\"original\": \"من هو مبتكر هذه القطعة الفنية؟\", \"translated\": \"Chi ha creato quest\'opera d\'arte?\"}, {\"original\": \"أين توجد أثمن قطعة في المتحف؟\", \"translated\": \"Dove si trova il pezzo più prezioso del museo?\"}, {\"original\": \"هل يُسمح بالتصوير الفوتوغرافي؟\", \"translated\": \"È consentito fare fotografie?\"}, {\"original\": \"هل توجد هنا أي معارض خاصة؟\", \"translated\": \"Ci sono delle mostre speciali qui?\"}, {\"original\": \"كم تستغرق الزيارة من الوقت؟\", \"translated\": \"Quanto tempo richiede la visita?\"}, {\"original\": \"هل يمكنكم إعطاؤنا مقدمة؟\", \"translated\": \"Potreste darci una breve introduzione?\"}, {\"original\": \"هذه الأعمال رائعةٌ حقًّا.\", \"translated\": \"Queste opere sono davvero squisite.\"}, {\"original\": \"أين تقع متجر الهدايا التذكارية؟\", \"translated\": \"Dove si trova il negozio dei souvenir?\"}]', 11, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"هل يمكنكم تزويدي بعشر عبارات شائعة يمكنني استخدامها في المقاهي؟\", \"رائع! إليكم عشر عبارات شائعة مرتبطة بالمقاهي، مع الترجمات الإيطالية لها:\"]', '[\"طلب القهوة\", \"الراحة\", \"التواصل الاجتماعي\"]', 'ar', '[\"للوقت الحالي، هل لديكم موقف معين في بالكم، مثل طلب القائمة أو الطلبات المثلجة أو الساخنة أو غيرها من المنتجات؟ لا تترددوا في طرح أي سؤال.\", \"من فضلكم وصفوا الموقف الذي يدور في خاطركم.\"]', NULL, '[{\"original\": \"سأطلب لاتيه، من فضلك.\", \"translated\": \"Prenderò un caffè latte, per favore.\"}, {\"original\": \"هل لديكم اتصال واي فاي؟\", \"translated\": \"Avete il Wi-Fi?\"}, {\"original\": \"هل يمكنني رؤية القائمة، من فضلك؟\", \"translated\": \"Potrei vedere il menu, per favore?\"}, {\"original\": \"هل يُسمح بإعادة التعبئة؟\", \"translated\": \"Sono ammessi i rabbocchi?\"}, {\"original\": \"هل قهوةُّي جاهزة؟\", \"translated\": \"Il mio caffè è pronto?\"}, {\"original\": \"كم من الوقت يمكنني الجلوس هنا؟\", \"translated\": \"Per quanto tempo posso stare seduto qui?\"}, {\"original\": \"هل يمكنك التقاط صورة لنا؟\", \"translated\": \"Potrebbe scattarci una foto?\"}, {\"original\": \"أين الحمام؟\", \"translated\": \"Dov\'è il bagno?\"}, {\"original\": \"الفاتورة، من فضلك. شكرًا لك.\", \"translated\": \"Il conto, per favore. Grazie.\"}, {\"original\": \"المذاق ممتازٌ حقًّا.\", \"translated\": \"Ha davvero un ottimo sapore.\"}]', 12, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser au restaurant ?\", \"Formidable ! Voici 10 expressions courantes liées au restaurant, accompagnées de leurs traductions en italien :\"]', '[\"Restauration\", \"Commande\", \"Paiement\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple commander des boissons, formuler une réclamation ou demander des informations sur les ingrédients ? N’hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Excusez-moi, combien de temps encore avant que notre repas soit prêt ?\", \"translated\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\"}, {\"original\": \"Une table pour deux, s\'il vous plaît.\", \"translated\": \"Un tavolo per due, per favore.\"}, {\"original\": \"Pourrions-nous voir la carte, s\'il vous plaît ?\", \"translated\": \"Potremmo vedere il menu, per favore?\"}, {\"original\": \"Avez-vous des plats signature à nous recommander ?\", \"translated\": \"Avete dei piatti speciali da consigliarci?\"}, {\"original\": \"Je voudrais commander ceci et cela.\", \"translated\": \"Vorrei ordinare questo e quest’altro.\"}, {\"original\": \"Un verre d\'eau, s\'il vous plaît. Merci.\", \"translated\": \"Un bicchiere d’acqua, per favore. Grazie.\"}, {\"original\": \"L\'addition, s\'il vous plaît.\", \"translated\": \"Il conto, per favore.\"}, {\"original\": \"Puis-je payer par carte bancaire ?\", \"translated\": \"Posso pagare con carta di credito?\"}, {\"original\": \"Pourriez-vous emballer cela à emporter, s\'il vous plaît ?\", \"translated\": \"Potrebbe impacchettare questo da portare via, per favore?\"}, {\"original\": \"Le plat était délicieux, merci.\", \"translated\": \"Il cibo era delizioso, grazie.\"}]', 1, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser à l’hôtel ?\", \"Formidable ! Voici 10 expressions courantes liées à l’hôtel, accompagnées de leurs traductions en italien :\"]', '[\"Enregistrement\", \"Départ\", \"Service en chambre\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple l’emplacement de la chambre, d’autres services hôteliers ou le départ ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Bonjour, j’ai une réservation. Voici mon passeport.\", \"translated\": \"Salve, ho una prenotazione. Ecco il mio passaporto.\"}, {\"original\": \"Avez-vous des chambres disponibles ?\", \"translated\": \"Avete camere disponibili?\"}, {\"original\": \"Excusez-moi, l’hôtel dispose-t-il d’une salle de sport ou d’une buanderie ?\", \"translated\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\"}, {\"original\": \"À quelle heure commence le petit-déjeuner ?\", \"translated\": \"A che ora inizia la colazione?\"}, {\"original\": \"Pourrais-je avoir la clé de ma chambre, s’il vous plaît ?\", \"translated\": \"Potrei avere la chiave della mia stanza, per favore?\"}, {\"original\": \"Pourriez-vous m’aider à porter mes bagages jusqu’à ma chambre ?\", \"translated\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\"}, {\"original\": \"Comment puis-je joindre le service d’étage ?\", \"translated\": \"Come posso chiamare il servizio in camera?\"}, {\"original\": \"À quelle heure doit-on quitter la chambre ?\", \"translated\": \"A che ora è il check-out?\"}, {\"original\": \"Pourriez-vous me délivrer un reçu / une facture ?\", \"translated\": \"Potrebbe rilasciarmi una ricevuta/fattura?\"}, {\"original\": \"Puis-je laisser mes bagages ici ?\", \"translated\": \"Posso lasciare qui i miei bagagli?\"}]', 2, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser à l’aéroport ?\", \"Formidable ! Voici 10 expressions courantes liées à l’aéroport, accompagnées de leurs traductions en italien :\"]', '[\"Enregistrement\", \"Embarquement\", \"Enregistrement des bagages\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple l’enregistrement, le retrait des bagages ou la location de voiture ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Où se trouve le comptoir d\'enregistrement ?\", \"translated\": \"Dov\'è il banco del check-in?\"}, {\"original\": \"Je voudrais un siège côté fenêtre, s\'il vous plaît.\", \"translated\": \"Vorrei un posto vicino al finestrino, per favore.\"}, {\"original\": \"Ce vol est-il retardé ?\", \"translated\": \"Questo volo è in ritardo?\"}, {\"original\": \"Je dois enregistrer ce bagage.\", \"translated\": \"Devo registrare questo bagaglio.\"}, {\"original\": \"Où se trouve la porte d\'embarquement ?\", \"translated\": \"Dov\'è l\'ingresso per l\'imbarco?\"}, {\"original\": \"L\'avion va bientôt décoller.\", \"translated\": \"L\'aeroplano sta per decollare.\"}, {\"original\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\", \"translated\": \"Devo estrarre il mio laptop e la power bank?\"}, {\"original\": \"Où se trouve la boutique hors taxes ?\", \"translated\": \"Dov\'è il negozio duty-free?\"}, {\"original\": \"Je ne retrouve pas ma valise.\", \"translated\": \"Non riesco a trovare la mia valigia.\"}, {\"original\": \"Proposez-vous un service de fauteuil roulant ?\", \"translated\": \"Offrite un servizio di sedia a rotelle?\"}]', 3, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans les transports en commun ?\", \"Formidable ! Voici 10 expressions courantes liées aux transports en commun, accompagnées de leurs traductions en italien :\"]', '[\"Prendre le bus ou le métro\", \"Acheter des billets\", \"Effectuer une correspondance\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander où se trouve l’arrêt de bus, le prix du billet ou comment descendre du véhicule ? N’hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Ce bus va-t-il jusqu\'à la gare routière ?\", \"translated\": \"Questo autobus va al capolinea?\"}, {\"original\": \"Quel est le prochain arrêt ?\", \"translated\": \"Qual è la prossima fermata?\"}, {\"original\": \"Où puis-je acheter un billet ?\", \"translated\": \"Dove posso comprare un biglietto?\"}, {\"original\": \"Un billet pour XX, s\'il vous plaît.\", \"translated\": \"Un biglietto per XX, per favore.\"}, {\"original\": \"Dois-je changer de transport ?\", \"translated\": \"Devo cambiare mezzo?\"}, {\"original\": \"Combien de temps avant le prochain métro ?\", \"translated\": \"Quanto manca al prossimo treno della metropolitana?\"}, {\"original\": \"Excusez-moi, laissez-moi passer, s\'il vous plaît.\", \"translated\": \"Scusi, mi lasci passare, per favore.\"}, {\"original\": \"Cette place est-elle occupée ?\", \"translated\": \"Questo posto è occupato?\"}, {\"original\": \"Excusez-moi, où puis-je changer pour la ligne 2 afin d\'aller à XX ?\", \"translated\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\"}, {\"original\": \"Comment puis-je me rendre à XX ?\", \"translated\": \"Come arrivo a XX?\"}]', 4, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans les sites touristiques ?\", \"Formidable ! Voici 10 expressions courantes liées aux sites touristiques, accompagnées de leurs traductions en italien :\"]', '[\"Visite touristique\", \"Prendre des photos\", \"Acheter des billets\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander le prix des billets, trouver un parking ou solliciter un service de guide touristique ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Combien coûte le droit d\'entrée ?\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"Y a-t-il des billets étudiants disponibles ?\", \"translated\": \"Sono disponibili biglietti per studenti?\"}, {\"original\": \"À quelle heure l\'attraction ouvre-t-elle ?\", \"translated\": \"A che ora apre la attrazione?\"}, {\"original\": \"Quelles sont les activités amusantes à faire ici ?\", \"translated\": \"Quali sono le cose divertenti da fare qui?\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"Potrebbe scattarci una foto?\"}, {\"original\": \"Où se trouve le bus touristique ?\", \"translated\": \"Dove si trova l\'autobus per i tour turistici?\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"Dove si trova il bagno?\"}, {\"original\": \"Quel est le meilleur point de vue ?\", \"translated\": \"Qual è il punto migliore per osservare la vista?\"}, {\"original\": \"Le paysage est magnifique ici.\", \"translated\": \"Il panorama qui è bellissimo.\"}, {\"original\": \"Une visite guidée est-elle disponible ?\", \"translated\": \"È disponibile un tour guidato?\"}]', 5, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser avec un taxi ou un service de taxi ?\", \"Formidable ! Voici 10 expressions courantes liées au taxi ou au service de taxi, accompagnées de leurs traductions en italien :\"]', '[\"Prendre un taxi\", \"Indiquer la destination\", \"Paiement\"]', 'fr', '[\"Pour l’instant, que souhaitez-vous faire principalement maintenant : demander la destination, le montant ou une facture ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Où puis-je prendre un taxi ?\", \"translated\": \"Dove posso prendere un taxi?\"}, {\"original\": \"Veuillez me conduire à cette adresse.\", \"translated\": \"Mi porti a questo indirizzo, per favore.\"}, {\"original\": \"Combien cela coûtera-t-il approximativement ?\", \"translated\": \"Quanto costerà all\'incirca?\"}, {\"original\": \"Pourriez-vous utiliser le compteur, s’il vous plaît ?\", \"translated\": \"Potrebbe usare il tassametro, per favore?\"}, {\"original\": \"Pourriez-vous conduire un peu plus vite, je suis pressé(e).\", \"translated\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\"}, {\"original\": \"Veuillez vous arrêter ici.\", \"translated\": \"Si fermi qui, per favore.\"}, {\"original\": \"Acceptez-vous les cartes bancaires ou les paiements mobiles ?\", \"translated\": \"Accetta carte di credito o pagamenti mobili?\"}, {\"original\": \"Pourrais-je avoir un reçu, s’il vous plaît ?\", \"translated\": \"Potrei avere lo scontrino, per favore?\"}, {\"original\": \"Merci, monsieur/madame le chauffeur.\", \"translated\": \"Grazie, autista.\"}, {\"original\": \"Il reste encore combien de temps ?\", \"translated\": \"Quanto manca ancora?\"}]', 6, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser en pharmacie ?\", \"Formidable ! Voici 10 expressions courantes liées à la pharmacie, accompagnées de leurs traductions en italien :\"]', '[\"Acheter des médicaments\", \"Consultation\", \"Paiement\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander des instructions sur la prise d’un médicament, des expressions liées à l’utilisation d’une assurance, à la durée du traitement ? N’hésitez pas à poser vos questions.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Avez-vous des médicaments contre le rhume ?\", \"translated\": \"Ha dei farmaci per il raffreddore?\"}, {\"original\": \"Comment dois-je prendre ce médicament ?\", \"translated\": \"Come devo assumere questo farmaco?\"}, {\"original\": \"Avez-vous des analgésiques ?\", \"translated\": \"Ha degli antidolorifici?\"}, {\"original\": \"Y a-t-il une notice d\'utilisation ?\", \"translated\": \"È incluso un foglietto illustrativo?\"}, {\"original\": \"Ce médicament présente-t-il des effets secondaires ?\", \"translated\": \"Questo farmaco ha effetti collaterali?\"}, {\"original\": \"Puis-je utiliser ma carte d\'assurance maladie ?\", \"translated\": \"Posso utilizzare la mia tessera sanitaria?\"}, {\"original\": \"Pourriez-vous me donner une boîte de pansements, s\'il vous plaît ?\", \"translated\": \"Potrei avere una confezione di cerotti, per favore?\"}, {\"original\": \"Avez-vous des antipyrétiques ?\", \"translated\": \"Ha dei farmaci antipiretici?\"}, {\"original\": \"Je me suis un peu écorché. Avez-vous un antiseptique et des pansements ?\", \"translated\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\"}, {\"original\": \"À quelle heure fermez-vous ?\", \"translated\": \"A che ora chiude?\"}]', 7, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans les services d\'urgence ?\", \"Formidable ! Voici 10 expressions courantes liées aux services d\'urgence, accompagnées de leurs traductions en italien :\"]', '[\"Appeler la police\", \"Premiers secours\", \"Appeler à l\'aide\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation d\'urgence précise en tête, par exemple un incendie, une personne blessée nécessitant de l\'aide ou un appel d\'urgence ? N\'hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', NULL, '[{\"original\": \"Veuillez m\'aider à appeler une ambulance.\", \"translated\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\"}, {\"original\": \"Où se trouve l\'hôpital ?\", \"translated\": \"Dov\'è l\'ospedale?\"}, {\"original\": \"Quelqu\'un est blessé.\", \"translated\": \"Qualcuno è ferito.\"}, {\"original\": \"Veuillez m\'aider.\", \"translated\": \"Per favore, mi aiuti.\"}, {\"original\": \"Où se trouve le commissariat ?\", \"translated\": \"Dov\'è la stazione di polizia?\"}, {\"original\": \"J\'ai perdu mes affaires.\", \"translated\": \"Ho perso i miei oggetti.\"}, {\"original\": \"Quel est le numéro des pompiers ?\", \"translated\": \"Qual è il numero del corpo dei vigili del fuoco?\"}, {\"original\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le commissariat le plus proche ?\", \"translated\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\"}, {\"original\": \"Y a-t-il une sortie de secours ?\", \"translated\": \"C\'è un\'uscita di emergenza?\"}, {\"original\": \"Quelqu\'un s\'est évanoui.\", \"translated\": \"Qualcuno è svenuto.\"}]', 8, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser à la plage ou au bord de la piscine ?\", \"Formidable ! Voici 10 expressions courantes liées à la plage ou au bord de la piscine, accompagnées de leurs traductions en italien :\"]', '[\"Natation\", \"Bain de soleil\", \"Sports de plage\"]', 'fr', '[\"Pour l’instant, pourriez-vous m’indiquer le contexte de l’événement ou de la fête locale auquel vous participez, par exemple un festival culturel, un festival gastronomique ou un festival musical ? Veuillez préciser ce contexte.\", \"Veuillez indiquer les activités auxquelles vous participez.\"]', '[\"Avez-vous une situation précise en tête ? N’hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Regardez ! Les vagues là-bas sont vraiment hautes.\", \"translated\": \"Guarda! Le onde laggiù sono davvero grandi.\"}, {\"original\": \"N\'oubliez pas d\'appliquer de la crème solaire, les rayons UV sont très intenses ici.\", \"translated\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\"}, {\"original\": \"Le sable de cette plage est si fin qu\'on a l\'impression de marcher sur du coton.\", \"translated\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\"}, {\"original\": \"Et si on jouait au volley-ball sur la plage ?\", \"translated\": \"Che ne dici di giocare a pallavolo in spiaggia?\"}, {\"original\": \"Les voiliers au loin sont magnifiques.\", \"translated\": \"Le barche a vela in lontananza sembrano bellissime.\"}, {\"original\": \"L\'eau est si claire ici qu\'on peut même voir les poissons.\", \"translated\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\"}, {\"original\": \"Allons chercher des coquillages.\", \"translated\": \"Andiamo a cercare delle conchiglie.\"}, {\"original\": \"Se promener sur la plage au coucher du soleil doit être très romantique.\", \"translated\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\"}, {\"original\": \"J\'ai entendu dire que les fruits de mer sont très frais ici, allons-en goûter.\", \"translated\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\"}, {\"original\": \"La marée monte, dirigeons-nous vers la rive.\", \"translated\": \"La marea sta salendo, dirigiamoci verso la riva.\"}]', 9, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser lors d’événements locaux et de festivals ?\", \"Formidable ! Voici 10 expressions courantes liées aux événements locaux et aux festivals, accompagnées de leurs traductions en italien :\"]', '[\"Assister à des événements\", \"Célébrer des festivals\", \"Apprendre la culture\"]', 'fr', '[\"Pour l’instant, pourriez-vous m’indiquer le contexte de l’événement local ou du festival auquel vous participez, par exemple Halloween, un concert, une fête entre amis ou autre chose ? Veuillez préciser ce contexte.\", \"Veuillez décrire les activités qui vous viennent à l’esprit.\"]', '[\"Avez-vous une situation précise en tête ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', '[{\"original\": \"Y a-t-il des événements aujourd\'hui ?\", \"translated\": \"Ci sono eventi oggi?\"}, {\"original\": \"Y a-t-il quelque chose de particulier à propos de ce festival ?\", \"translated\": \"C\'è qualcosa di speciale in questo festival?\"}, {\"original\": \"Où se déroule la célébration ?\", \"translated\": \"Dove si tiene la celebrazione?\"}, {\"original\": \"Comment puis-je acheter des billets ?\", \"translated\": \"Come posso acquistare i biglietti?\"}, {\"original\": \"À quelle heure commence la représentation ?\", \"translated\": \"A che ora inizia lo spettacolo?\"}, {\"original\": \"Quels sont les plats traditionnels ?\", \"translated\": \"Quali sono i cibi tradizionali?\"}, {\"original\": \"C\'est vraiment animé ici.\", \"translated\": \"Qui è davvero animato.\"}, {\"original\": \"Y a-t-il des activités populaires ?\", \"translated\": \"Ci sono attività popolari?\"}, {\"original\": \"Joyeuses fêtes !\", \"translated\": \"Buone feste!\"}, {\"original\": \"À quelle heure se termine l\'événement ?\", \"translated\": \"A che ora termina l\'evento?\"}]', 10, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me fournir 10 expressions courantes que je peux utiliser dans un musée ou une galerie d\'art ?\", \"Formidable ! Voici 10 expressions courantes liées au musée ou à la galerie d\'art, accompagnées de leurs traductions en italien :\"]', '[\"Visite\", \"Visite guidée\", \"Achat de billets\"]', 'fr', '[\"Pour l\'instant, avez-vous une situation précise en tête, par exemple demander un manuel d\'introduction, des expressions liées à un parcours guidé, des expressions pour commenter une exposition ? N\'hésitez pas à poser votre question.\", \"Veuillez décrire la situation qui vous vient à l\'esprit.\"]', NULL, '[{\"original\": \"Quel est le montant des frais d\'entrée ?\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"Proposez-vous des guides audio ?\", \"translated\": \"Avete guide audio?\"}, {\"original\": \"Qui est l\'auteur de cette œuvre ?\", \"translated\": \"Chi ha creato quest\'opera d\'arte?\"}, {\"original\": \"Où se trouve la pièce la plus précieuse du musée ?\", \"translated\": \"Dove si trova il pezzo più prezioso del museo?\"}, {\"original\": \"La photographie est-elle autorisée ?\", \"translated\": \"È consentito fare fotografie?\"}, {\"original\": \"Y a-t-il des expositions spéciales ici ?\", \"translated\": \"Ci sono delle mostre speciali qui?\"}, {\"original\": \"Combien de temps dure la visite ?\", \"translated\": \"Quanto tempo richiede la visita?\"}, {\"original\": \"Pourriez-vous nous en faire une présentation ?\", \"translated\": \"Potreste darci una breve introduzione?\"}, {\"original\": \"Ces œuvres sont véritablement exquises.\", \"translated\": \"Queste opere sono davvero squisite.\"}, {\"original\": \"Où se trouve la boutique de souvenirs ?\", \"translated\": \"Dove si trova il negozio dei souvenir?\"}]', 11, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Pourriez-vous me donner 10 expressions courantes que je peux utiliser dans les cafés ?\", \"Formidable ! Voici 10 expressions courantes liées aux cafés, accompagnées de leurs traductions en italien :\"]', '[\"Commander du café\", \"Se reposer\", \"Socialiser\"]', 'fr', '[\"Pour l’instant, avez-vous une situation précise en tête, par exemple demander la carte, des boissons glacées ou chaudes, d’autres produits ? N’hésitez pas à demander.\", \"Veuillez décrire la situation qui vous vient à l’esprit.\"]', NULL, '[{\"original\": \"Je prendrai un latte, s’il vous plaît.\", \"translated\": \"Prenderò un latte, per favore.\"}, {\"original\": \"Avez-vous le Wi-Fi ?\", \"translated\": \"Avete il Wi-Fi?\"}, {\"original\": \"Pourrais-je voir la carte, s’il vous plaît ?\", \"translated\": \"Potrei vedere il menu, per favore?\"}, {\"original\": \"Les recharges sont-elles autorisées ?\", \"translated\": \"Sono ammessi i rabbocchi?\"}, {\"original\": \"Mon café est-il prêt ?\", \"translated\": \"Il mio caffè è pronto?\"}, {\"original\": \"Combien de temps puis-je rester assis ici ?\", \"translated\": \"Quanto tempo posso restare seduto qui?\"}, {\"original\": \"Pourriez-vous prendre une photo pour nous ?\", \"translated\": \"Potrebbe fare una foto per noi?\"}, {\"original\": \"Où sont les toilettes ?\", \"translated\": \"Dov\'è il bagno?\"}, {\"original\": \"L’addition, s’il vous plaît. Merci.\", \"translated\": \"Il conto, per favore. Grazie.\"}, {\"original\": \"C’est vraiment délicieux.\", \"translated\": \"Ha davvero un ottimo sapore.\"}]', 12, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Restaurant verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Restaurants sowie deren italienische Übersetzungen:\"]', '[\"Gastronomie\", \"Bestellen\", \"Kasse\"]', 'de', '[\"Vorläufig: Haben Sie eine bestimmte Situation im Kopf, etwa das Bestellen von Getränken, das Erheben einer Beschwerde oder das Nachfragen nach Zutaten? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', NULL, '[{\"original\": \"Entschuldigung, wie lange dauert es noch bis zu unserem Essen?\", \"translated\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\"}, {\"original\": \"Ein Tisch für zwei Personen, bitte.\", \"translated\": \"Un tavolo per due, per favore.\"}, {\"original\": \"Könnten wir bitte die Speisekarte sehen?\", \"translated\": \"Potremmo vedere il menù, per favore?\"}, {\"original\": \"Haben Sie empfehlenswerte Hausgerichte?\", \"translated\": \"Avete dei piatti tipici da consigliarci?\"}, {\"original\": \"Ich möchte dies hier und das hier bestellen.\", \"translated\": \"Vorrei ordinare questo e quest’altro.\"}, {\"original\": \"Ein Glas Wasser, bitte. Danke.\", \"translated\": \"Un bicchiere d’acqua, per favore. Grazie.\"}, {\"original\": \"Die Rechnung, bitte.\", \"translated\": \"Il conto, per favore.\"}, {\"original\": \"Kann ich mit Kreditkarte bezahlen?\", \"translated\": \"Posso pagare con carta di credito?\"}, {\"original\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\", \"translated\": \"Potrebbe impacchettare questo da portare via, per favore?\"}, {\"original\": \"Das Essen war köstlich, vielen Dank.\", \"translated\": \"Il cibo era delizioso, grazie.\"}]', 1, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Hotel verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Hotels sowie deren italienische Übersetzungen:\"]', '[\"Einchecken\", \"Auschecken\", \"Zimmerservice\"]', 'de', '[\"Vorläufig: Haben Sie eine bestimmte Situation im Kopf, etwa die Lage des Zimmers, weitere Hoteldienstleistungen oder den Check-out? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', NULL, '[{\"original\": \"Hallo, ich habe eine Reservierung. Hier ist mein Reisepass.\", \"translated\": \"Salve, ho una prenotazione, ecco il mio passaporto.\"}, {\"original\": \"Haben Sie noch freie Zimmer?\", \"translated\": \"Avete camere disponibili?\"}, {\"original\": \"Entschuldigung, verfügt das Hotel über ein Fitnessstudio oder einen Waschraum?\", \"translated\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\"}, {\"original\": \"Wann beginnt das Frühstück?\", \"translated\": \"A che ora inizia la colazione?\"}, {\"original\": \"Könnte ich bitte den Zimmerschlüssel haben?\", \"translated\": \"Potrei avere la chiave della mia stanza, per favore?\"}, {\"original\": \"Könnten Sie mir helfen, mein Gepäck auf das Zimmer zu bringen?\", \"translated\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\"}, {\"original\": \"Wie rufe ich den Zimmerservice?\", \"translated\": \"Come posso chiamare il servizio in camera?\"}, {\"original\": \"Wann ist der Check-out?\", \"translated\": \"A che ora è il check-out?\"}, {\"original\": \"Könnten Sie mir bitte eine Quittung / Rechnung ausstellen?\", \"translated\": \"Potrebbe rilasciarmi una ricevuta/fattura?\"}, {\"original\": \"Darf ich mein Gepäck hier lassen?\", \"translated\": \"Posso lasciare qui i miei bagagli?\"}]', 2, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich am Flughafen verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Flughafen sowie deren italienische Übersetzungen:\"]', '[\"Einchecken\", \"Boarding\", \"Gepäckabgabe\"]', 'de', '[\"Vorläufig: Haben Sie eine bestimmte Situation im Kopf, etwa das Einchecken, die Gepäckausgabe oder die Autovermietung? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', NULL, '[{\"original\": \"Wo ist der Check-in-Schalter?\", \"translated\": \"Dov\'è il banco del check-in?\"}, {\"original\": \"Ich hätte gerne einen Fensterplatz.\", \"translated\": \"Vorrei un posto vicino al finestrino, per favore.\"}, {\"original\": \"Ist dieser Flug verspätet?\", \"translated\": \"Questo volo è in ritardo?\"}, {\"original\": \"Ich muss dieses Gepäck aufgeben.\", \"translated\": \"Devo registrare questo bagaglio.\"}, {\"original\": \"Wo ist das Boarding-Gate?\", \"translated\": \"Dov\'è l\'ingresso per l\'imbarco?\"}, {\"original\": \"Das Flugzeug startet gleich.\", \"translated\": \"L\'aeroplano sta per decollare.\"}, {\"original\": \"Muss ich meinen Laptop und meine Powerbank herausnehmen?\", \"translated\": \"Devo estrarre il mio laptop e la power bank?\"}, {\"original\": \"Wo ist der Duty-free-Shop?\", \"translated\": \"Dov\'è il negozio duty-free?\"}, {\"original\": \"Ich kann meinen Koffer nicht finden.\", \"translated\": \"Non riesco a trovare la mia valigia.\"}, {\"original\": \"Bieten Sie einen Rollstuhlservice an?\", \"translated\": \"Offrite un servizio di sedia a rotelle?\"}]', 3, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im öffentlichen Nahverkehr verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema öffentlicher Nahverkehr samt italienischer Übersetzungen.\"]', '[\"Mit Bus/U-Bahn fahren\", \"Fahrkarten kaufen\", \"Umsteigen\"]', 'de', '[\"Vorläufig: Haben Sie eine konkrete Situation im Kopf, etwa nach einer Bushaltestelle zu fragen, den Fahrpreis zu erfragen oder darzulegen, dass Sie aussteigen möchten? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', NULL, '[{\"original\": \"Fährt dieser Bus zum Terminal?\", \"translated\": \"Questo autobus va al capolinea?\"}, {\"original\": \"Was ist die nächste Haltestelle?\", \"translated\": \"Qual è la prossima fermata?\"}, {\"original\": \"Wo kann ich ein Ticket kaufen?\", \"translated\": \"Dove posso comprare un biglietto?\"}, {\"original\": \"Ein Ticket nach XX, bitte.\", \"translated\": \"Un biglietto per XX, per favore.\"}, {\"original\": \"Muss ich umsteigen?\", \"translated\": \"Devo cambiare mezzo?\"}, {\"original\": \"Wie lange dauert es noch bis zum nächsten U-Bahn-Zug?\", \"translated\": \"Quanto manca al prossimo treno della metropolitana?\"}, {\"original\": \"Entschuldigung, bitte lassen Sie mich durch.\", \"translated\": \"Scusi, mi lasci passare, per favore.\"}, {\"original\": \"Ist dieser Platz bereits besetzt?\", \"translated\": \"Questo posto è occupato?\"}, {\"original\": \"Entschuldigung, wo kann ich umsteigen, um mit der Linie 2 nach XX zu gelangen?\", \"translated\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\"}, {\"original\": \"Wie komme ich nach XX?\", \"translated\": \"Come arrivo a XX?\"}]', 4, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich an touristischen Sehenswürdigkeiten verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit touristischen Sehenswürdigkeiten sowie deren italienische Übersetzungen:\"]', '[\"Sehenswürdigkeiten besichtigen\", \"Fotos machen\", \"Tickets kaufen\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf, etwa das Erfragen des Eintrittspreises, das Suchen eines Parkplatzes oder die Inanspruchnahme eines Fremdenführers? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', NULL, '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"Gibt es ermäßigte Eintrittskarten für Schüler?\", \"translated\": \"Sono disponibili biglietti per studenti?\"}, {\"original\": \"Wann öffnet die Sehenswürdigkeit?\", \"translated\": \"A che ora apre la attrazione?\"}, {\"original\": \"Was gibt es hier Spannendes zu tun?\", \"translated\": \"Quali sono le cose divertenti da fare qui?\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"Potrebbe scattarci una foto?\"}, {\"original\": \"Wo befindet sich der Sightseeing-Bus?\", \"translated\": \"Dove si trova l\'autobus per i tour turistici?\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"Dove si trova il bagno?\"}, {\"original\": \"Wo ist der beste Aussichtspunkt?\", \"translated\": \"Dove si trova il punto migliore per osservare?\"}, {\"original\": \"Die Landschaft hier ist wunderschön.\", \"translated\": \"Il panorama qui è bellissimo.\"}, {\"original\": \"Gibt es eine geführte Tour?\", \"translated\": \"È disponibile un tour guidato?\"}]', 5, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Zusammenhang mit einem Taxi oder einem Taxidienst verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Taxi oder Taxidienst sowie deren italienische Übersetzungen:\"]', '[\"Taxi nehmen\", \"Ziel angeben\", \"Zahlen\"]', 'de', '[\"Vorerst: Was möchten Sie gerade am liebsten tun – beispielsweise das Ziel angeben, den Preis erfragen oder eine Rechnung anfordern? Fragen Sie ruhig!\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', NULL, '[{\"original\": \"Wo kann ich ein Taxi bekommen?\", \"translated\": \"Dove posso prendere un taxi?\"}, {\"original\": \"Bitte fahren Sie mich zu dieser Adresse.\", \"translated\": \"Mi porti a questo indirizzo, per favore.\"}, {\"original\": \"Wie viel kostet es ungefähr?\", \"translated\": \"Quanto costerà all\'incirca?\"}, {\"original\": \"Könnten Sie bitte den Taxameter benutzen?\", \"translated\": \"Potrebbe usare il tassametro, per favore?\"}, {\"original\": \"Bitte fahren Sie etwas schneller, ich habe es eilig.\", \"translated\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\"}, {\"original\": \"Bitte halten Sie hier an.\", \"translated\": \"Si fermi qui, per favore.\"}, {\"original\": \"Akzeptieren Sie Karten oder mobile Zahlungen?\", \"translated\": \"Accetta carte di credito o pagamenti mobili?\"}, {\"original\": \"Könnte ich bitte eine Quittung haben?\", \"translated\": \"Potrei avere lo scontrino, per favore?\"}, {\"original\": \"Vielen Dank, Fahrer.\", \"translated\": \"Grazie, autista.\"}, {\"original\": \"Wie weit ist es noch?\", \"translated\": \"Quanto manca ancora?\"}]', 6, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich in der Apotheke verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke aus dem Apothekenbereich samt italienischer Übersetzung:\"]', '[\"Medikamente kaufen\", \"Beratung\", \"Zahlung\"]', 'de', '[\"Vorläufig: Haben Sie eine konkrete Situation im Kopf, etwa das Nachfragen nach Einnahmeanweisungen für Medikamente, Formulierungen im Zusammenhang mit der Krankenversicherung oder der Dauer der Medikamenteneinnahme? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', NULL, '[{\"original\": \"Haben Sie Medikamente gegen Erkältung?\", \"translated\": \"Ha dei farmaci per il raffreddore?\"}, {\"original\": \"Wie soll ich dieses Medikament einnehmen?\", \"translated\": \"Come devo assumere questo farmaco?\"}, {\"original\": \"Haben Sie Schmerzmittel?\", \"translated\": \"Ha degli antidolorifici?\"}, {\"original\": \"Gibt es eine Gebrauchsanweisung?\", \"translated\": \"È incluso un foglietto illustrativo?\"}, {\"original\": \"Hat dieses Medikament Nebenwirkungen?\", \"translated\": \"Questo farmaco ha effetti collaterali?\"}, {\"original\": \"Kann ich meine Krankenversicherungskarte verwenden?\", \"translated\": \"Posso usare la mia tessera sanitaria?\"}, {\"original\": \"Könnte ich bitte eine Packung Pflaster haben?\", \"translated\": \"Potrei avere una confezione di cerotti, per favore?\"}, {\"original\": \"Haben Sie Fiebersenkende Mittel?\", \"translated\": \"Ha dei farmaci antipiretici?\"}, {\"original\": \"Ich habe mir leicht die Haut aufgeschürft. Haben Sie Desinfektionsmittel und Pflaster?\", \"translated\": \"Ho una piccola escoriazione. Ha dell’antisettico e dei cerotti?\"}, {\"original\": \"Wann schließen Sie?\", \"translated\": \"A che ora chiude?\"}]', 7, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich im Notdienst verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Notdiensten sowie deren italienische Übersetzungen:\"]', '[\"Polizei rufen\", \"Erste Hilfe leisten\", \"Hilfe rufen\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Notsituation im Kopf, beispielsweise Feuer, Verletzung und Hilfebedarf oder einen Notruf? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf vorschwebt.\"]', NULL, '[{\"original\": \"Bitte helfen Sie mir, einen Krankenwagen zu rufen.\", \"translated\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\"}, {\"original\": \"Wo ist das Krankenhaus?\", \"translated\": \"Dov\'è l\'ospedale?\"}, {\"original\": \"Jemand ist verletzt.\", \"translated\": \"Qualcuno è ferito.\"}, {\"original\": \"Bitte helfen Sie mir.\", \"translated\": \"Per favore, mi aiuti.\"}, {\"original\": \"Wo ist die Polizeistation?\", \"translated\": \"Dov\'è la stazione di polizia?\"}, {\"original\": \"Ich habe meine Sachen verloren.\", \"translated\": \"Ho perso i miei effetti personali.\"}, {\"original\": \"Wie lautet die Notrufnummer für die Feuerwehr?\", \"translated\": \"Qual è il numero del corpo dei vigili del fuoco?\"}, {\"original\": \"Ich habe meinen Reisepass verloren. Wissen Sie, wo die nächste Polizeistation ist?\", \"translated\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\"}, {\"original\": \"Gibt es einen Notausgang?\", \"translated\": \"C\'è un\'uscita di emergenza?\"}, {\"original\": \"Jemand ist in Ohnmacht gefallen.\", \"translated\": \"Qualcuno è svenuto.\"}]', 8, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich am Strand oder am Pool verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zum Thema Strand oder Schwimmbad sowie deren italienische Übersetzungen:\"]', '[\"Schwimmen\", \"Sonnenbaden\", \"Strandsport\"]', 'de', '[\"Könnten Sie mir vorläufig den Kontext der lokalen Veranstaltung oder des Festivals, an dem Sie teilnehmen, mitteilen – beispielsweise ein Kulturfestival, ein Kulinarikfestival oder ein Musikfestival? Bitte geben Sie den Kontext an.\", \"Bitte nennen Sie die Aktivitäten, an denen Sie teilnehmen.\"]', '[\"Haben Sie eine konkrete Situation im Kopf? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen vorschwebt.\"]', '[{\"original\": \"Schau! Die Wellen dort drüben sind wirklich groß.\", \"translated\": \"Guarda! Le onde laggiù sono davvero grandi.\"}, {\"original\": \"Vergiss nicht, Sonnenschutzmittel aufzutragen – die UV-Strahlen sind hier sehr stark.\", \"translated\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\"}, {\"original\": \"Der Sand an diesem Strand ist so fein, dass es sich anfühlt, als würde man auf Baumwolle gehen.\", \"translated\": \"La sabbia di questa spiaggia è così fine che sembra camminare su cotone.\"}, {\"original\": \"Wie wäre es mit einer Partie Volleyball am Strand?\", \"translated\": \"Che ne dici di giocare a pallavolo sulla spiaggia?\"}, {\"original\": \"Die Segelboote in der Ferne sehen wunderschön aus.\", \"translated\": \"Le barche a vela in lontananza sembrano bellissime.\"}, {\"original\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\", \"translated\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\"}, {\"original\": \"Lass uns ein paar Muscheln suchen.\", \"translated\": \"Andiamo a cercare delle conchiglie.\"}, {\"original\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\", \"translated\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\"}, {\"original\": \"Ich habe gehört, dass die Meeresfrüchte hier sehr frisch sind – lass uns welche probieren.\", \"translated\": \"Ho sentito dire che qui il pesce e i frutti di mare sono molto freschi, andiamo a provarli.\"}, {\"original\": \"Die Flut kommt herein, gehen wir Richtung Ufer.\", \"translated\": \"La marea sta salendo, dirigiamoci verso la riva.\"}]', 9, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich bei lokalen Veranstaltungen und Festen verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke zu lokalen Veranstaltungen und Festen samt italienischer Übersetzung:\"]', '[\"Teilnahme an Veranstaltungen\", \"Feiern von Festen\", \"Kultur kennenlernen\"]', 'de', '[\"Könnten Sie mir vorerst den Kontext der lokalen Veranstaltung oder des Festes mitteilen, an dem Sie teilnehmen – beispielsweise Halloween, ein Konzert, eine Party bei Freunden oder etwas anderes? Bitte geben Sie den Kontext an.\", \"Bitte beschreiben Sie die Aktivitäten, die Ihnen dabei in den Sinn kommen.\"]', '[\"Haben Sie eine konkrete Situation im Kopf? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen dabei in den Sinn kommt.\"]', '[{\"original\": \"Gibt es heute irgendwelche Veranstaltungen?\", \"translated\": \"Ci sono eventi oggi?\"}, {\"original\": \"Gibt es bei diesem Fest etwas Besonderes?\", \"translated\": \"C\'è qualcosa di speciale in questo festival?\"}, {\"original\": \"Wo findet die Feier statt?\", \"translated\": \"Dove si tiene la celebrazione?\"}, {\"original\": \"Wie kann ich Tickets kaufen?\", \"translated\": \"Come posso acquistare i biglietti?\"}, {\"original\": \"Wann beginnt die Aufführung?\", \"translated\": \"A che ora inizia lo spettacolo?\"}, {\"original\": \"Welche traditionellen Speisen gibt es?\", \"translated\": \"Quali sono i cibi tradizionali?\"}, {\"original\": \"Es ist hier wirklich lebhaft.\", \"translated\": \"Qui è davvero animato.\"}, {\"original\": \"Gibt es Volksaktivitäten?\", \"translated\": \"Ci sono attività popolari?\"}, {\"original\": \"Frohe Feiertage!\", \"translated\": \"Buone feste!\"}, {\"original\": \"Wann endet die Veranstaltung?\", \"translated\": \"A che ora termina l\'evento?\"}]', 10, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich in einem Museum oder einer Kunstgalerie verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Museen oder Kunstgalerien sowie deren italienische Übersetzungen:\"]', '[\"Besuch\", \"Geführte Tour\", \"Kartenvorverkauf\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf, etwa das Nachfragen nach einer Einführungsbroschüre, Ausdrücke im Zusammenhang mit einem Rundgang oder Formulierungen zur Kommentierung von Exponaten? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', NULL, '[{\"original\": \"Wie hoch ist der Eintrittspreis?\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"Bieten Sie Audioführungen an?\", \"translated\": \"Avete guide audio?\"}, {\"original\": \"Wer hat dieses Kunstwerk geschaffen?\", \"translated\": \"Chi ha creato quest\'opera d\'arte?\"}, {\"original\": \"Wo befindet sich das wertvollste Stück des Museums?\", \"translated\": \"Dove si trova il pezzo più prezioso del museo?\"}, {\"original\": \"Ist Fotografieren erlaubt?\", \"translated\": \"È consentito fare fotografie?\"}, {\"original\": \"Gibt es hier besondere Ausstellungen?\", \"translated\": \"Ci sono delle mostre speciali qui?\"}, {\"original\": \"Wie lange dauert der Besuch?\", \"translated\": \"Quanto tempo richiede la visita?\"}, {\"original\": \"Könnten Sie uns bitte eine Einführung geben?\", \"translated\": \"Potreste darci una breve introduzione?\"}, {\"original\": \"Diese Werke sind wirklich exquisit.\", \"translated\": \"Queste opere sono davvero squisite.\"}, {\"original\": \"Wo befindet sich der Souvenirladen?\", \"translated\": \"Dove si trova il negozio dei souvenir?\"}]', 11, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Könnten Sie mir 10 gängige Ausdrücke nennen, die ich in Cafés verwenden kann?\", \"Fantastisch! Hier sind 10 gängige Ausdrücke im Zusammenhang mit Cafés sowie deren italienische Übersetzungen:\"]', '[\"Kaffee bestellen\", \"Ausruhen\", \"Sozialisieren\"]', 'de', '[\"Vorerst: Haben Sie eine konkrete Situation im Kopf, etwa das Bestellen einer Speisekarte, von Eis oder heißen Getränken, anderer Produkte? Fragen Sie ruhig.\", \"Bitte beschreiben Sie die Situation, die Ihnen im Kopf herumgeht.\"]', NULL, '[{\"original\": \"Ich hätte gerne einen Latte, bitte.\", \"translated\": \"Prenderò un caffè latte, per favore.\"}, {\"original\": \"Haben Sie WLAN?\", \"translated\": \"Avete il Wi-Fi?\"}, {\"original\": \"Könnte ich bitte die Speisekarte sehen?\", \"translated\": \"Potrei vedere il menu, per favore?\"}, {\"original\": \"Darf man nachfüllen?\", \"translated\": \"Sono ammesse le ricariche?\"}, {\"original\": \"Ist mein Kaffee fertig?\", \"translated\": \"Il mio caffè è pronto?\"}, {\"original\": \"Wie lange darf ich hier sitzen?\", \"translated\": \"Per quanto tempo posso stare seduto qui?\"}, {\"original\": \"Könnten Sie bitte ein Foto von uns machen?\", \"translated\": \"Potrebbe fare una foto per noi?\"}, {\"original\": \"Wo ist die Toilette?\", \"translated\": \"Dov\'è il bagno?\"}, {\"original\": \"Die Rechnung, bitte. Vielen Dank.\", \"translated\": \"Il conto, per favore. Grazie.\"}, {\"original\": \"Es schmeckt wirklich gut.\", \"translated\": \"Ha davvero un ottimo sapore.\"}]', 12, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en un restaurante?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el restaurante, junto con sus traducciones al italiano:\"]', '[\"Comer\", \"Pedir\", \"Pagar\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir bebidas, presentar una queja o preguntar sobre los ingredientes? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"Perdón, ¿cuánto tiempo más tardará nuestra comida?\", \"translated\": \"Scusi, quanto ancora dobbiamo aspettare per il nostro cibo?\"}, {\"original\": \"Una mesa para dos, por favor.\", \"translated\": \"Un tavolo per due, per favore.\"}, {\"original\": \"¿Podríamos ver el menú, por favor?\", \"translated\": \"Potremmo vedere il menu, per favore?\"}, {\"original\": \"¿Tienen algún plato especial que nos recomienden?\", \"translated\": \"Avete dei piatti tipici da consigliarci?\"}, {\"original\": \"Quisiera pedir esto y esto.\", \"translated\": \"Vorrei ordinare questo e quest’altro.\"}, {\"original\": \"Un vaso de agua, por favor. Gracias.\", \"translated\": \"Un bicchiere d’acqua, per favore. Grazie.\"}, {\"original\": \"La cuenta, por favor.\", \"translated\": \"Il conto, per favore.\"}, {\"original\": \"¿Puedo pagar con tarjeta de crédito?\", \"translated\": \"Posso pagare con carta di credito?\"}, {\"original\": \"¿Podrían empaquetar esto para llevar, por favor?\", \"translated\": \"Potrebbe confezionarmelo da asporto, per favore?\"}, {\"original\": \"La comida estaba deliciosa, gracias.\", \"translated\": \"Il cibo era delizioso, grazie.\"}]', 1, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en un hotel?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el hotel, junto con sus traducciones al italiano:\"]', '[\"Registro de entrada\", \"Registro de salida\", \"Servicio de habitaciones\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como la ubicación de la habitación, otros servicios del hotel o el proceso de salida? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"Hola, tengo una reserva. Aquí tiene mi pasaporte.\", \"translated\": \"Salve, ho una prenotazione. Ecco il mio passaporto.\"}, {\"original\": \"¿Tienen habitaciones disponibles?\", \"translated\": \"Avete camere disponibili?\"}, {\"original\": \"Disculpe, ¿tiene el hotel gimnasio o lavandería?\", \"translated\": \"Scusi, l\'hotel dispone di una palestra o di una lavanderia?\"}, {\"original\": \"¿A qué hora comienza el desayuno?\", \"translated\": \"A che ora inizia la colazione?\"}, {\"original\": \"¿Podría darme la llave de la habitación, por favor?\", \"translated\": \"Potrei avere la chiave della mia camera, per favore?\"}, {\"original\": \"¿Podría ayudarme a llevar mi equipaje a la habitación?\", \"translated\": \"Potrebbe aiutarmi a portare i miei bagagli nella stanza?\"}, {\"original\": \"¿Cómo llamo al servicio de habitaciones?\", \"translated\": \"Come posso chiamare il servizio in camera?\"}, {\"original\": \"¿A qué hora es la salida?\", \"translated\": \"A che ora è il check-out?\"}, {\"original\": \"¿Podría emitirme un recibo/factura?\", \"translated\": \"Potrebbe rilasciarmi una ricevuta/fattura?\"}, {\"original\": \"¿Puedo dejar aquí mi equipaje?\", \"translated\": \"Posso lasciare qui i miei bagagli?\"}]', 2, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en el aeropuerto?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el aeropuerto, junto con sus traducciones al italiano:\"]', '[\"Registro\", \"Embarque\", \"Facturación de equipaje\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como el registro de embarque, la recogida de equipaje o el servicio de alquiler de coches? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Dónde está el mostrador de facturación?\", \"translated\": \"Dov\'è il banco del check-in?\"}, {\"original\": \"Me gustaría un asiento junto a la ventana, por favor.\", \"translated\": \"Vorrei un posto vicino al finestrino, per favore.\"}, {\"original\": \"¿Este vuelo tiene retraso?\", \"translated\": \"Questo volo è in ritardo?\"}, {\"original\": \"Necesito facturar este equipaje.\", \"translated\": \"Devo registrare questo bagaglio.\"}, {\"original\": \"¿Dónde está la puerta de embarque?\", \"translated\": \"Dov\'è l\'ingresso per l\'imbarco?\"}, {\"original\": \"El avión está a punto de despegar.\", \"translated\": \"L\'aeroplano sta per decollare.\"}, {\"original\": \"¿Tengo que sacar mi ordenador portátil y mi power bank?\", \"translated\": \"Devo estrarre il mio laptop e la power bank?\"}, {\"original\": \"¿Dónde está la tienda libre de impuestos?\", \"translated\": \"Dov\'è il negozio duty-free?\"}, {\"original\": \"No encuentro mi maleta.\", \"translated\": \"Non riesco a trovare la mia valigia.\"}, {\"original\": \"¿Ofrecen servicio de sillas de ruedas?\", \"translated\": \"Offrite un servizio di sedia a rotelle?\"}]', 3, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en el transporte público?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con el transporte público, junto con sus traducciones al italiano:\"]', '[\"Tomar autobús o metro\", \"Comprar billetes\", \"Transbordar\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como preguntar por la parada de autobús, el precio del billete o cómo bajarse? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Este autobús va a la terminal?\", \"translated\": \"Questo autobus va al capolinea?\"}, {\"original\": \"¿Cuál es la próxima parada?\", \"translated\": \"Qual è la prossima fermata?\"}, {\"original\": \"¿Dónde puedo comprar un billete?\", \"translated\": \"Dove posso acquistare un biglietto?\"}, {\"original\": \"Un billete para XX, por favor.\", \"translated\": \"Un biglietto per XX, per favore.\"}, {\"original\": \"¿Tengo que hacer transbordo?\", \"translated\": \"Devo cambiare?\"}, {\"original\": \"¿Cuánto tiempo falta para el próximo tren del metro?\", \"translated\": \"Tra quanto arriva il prossimo treno della metropolitana?\"}, {\"original\": \"Disculpe, permítame pasar, por favor.\", \"translated\": \"Scusi, mi lasci passare, per favore.\"}, {\"original\": \"¿Esta plaza está ocupada?\", \"translated\": \"Questo posto è occupato?\"}, {\"original\": \"Disculpe, ¿dónde puedo hacer transbordo a la línea 2 para llegar a XX?\", \"translated\": \"Scusi, dove posso cambiare per la linea 2 per arrivare a XX?\"}, {\"original\": \"¿Cómo llego a XX?\", \"translated\": \"Come arrivo a XX?\"}]', 4, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en atracciones turísticas?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con atracciones turísticas, junto con sus traducciones al italiano:\"]', '[\"Visitar lugares de interés\", \"Tomar fotos\", \"Comprar entradas\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como preguntar sobre el precio de las entradas, encontrar un estacionamiento o solicitar un servicio de guía turística? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Cuánto cuesta la entrada?\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"¿Hay entradas para estudiantes disponibles?\", \"translated\": \"Sono disponibili biglietti per studenti?\"}, {\"original\": \"¿A qué hora abre la atracción?\", \"translated\": \"A che ora apre la attrazione?\"}, {\"original\": \"¿Qué cosas divertidas se pueden hacer aquí?\", \"translated\": \"Quali sono le cose divertenti da fare qui?\"}, {\"original\": \"¿Podría hacernos una foto?\", \"translated\": \"Potrebbe scattarci una foto?\"}, {\"original\": \"¿Dónde está el autobús turístico?\", \"translated\": \"Dove si trova l\'autobus per i tour turistici?\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"Dove si trova il bagno?\"}, {\"original\": \"¿Cuál es el mejor lugar para observar?\", \"translated\": \"Dove si trova il punto migliore per osservare la vista?\"}, {\"original\": \"El paisaje aquí es hermoso.\", \"translated\": \"Il paesaggio qui è bellissimo.\"}, {\"original\": \"¿Hay visitas guiadas disponibles?\", \"translated\": \"È disponibile un tour guidato?\"}]', 5, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar al tomar un taxi o utilizar un servicio de taxis?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con los taxis o los servicios de taxis, junto con sus traducciones al italiano:\"]', '[\"Tomar un taxi\", \"Indicar el destino\", \"Pago\"]', 'es', '[\"Por ahora, ¿qué es lo que más desea hacer ahora? Por ejemplo, preguntar el destino, el precio o solicitar una factura. No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Dónde puedo conseguir un taxi?\", \"translated\": \"Dove posso prendere un taxi?\"}, {\"original\": \"Por favor, lléveme a esta dirección.\", \"translated\": \"Mi porti a questo indirizzo, per favore.\"}, {\"original\": \"¿Cuánto costará aproximadamente?\", \"translated\": \"Quanto costerà all\'incirca?\"}, {\"original\": \"¿Podría usar el taxímetro, por favor?\", \"translated\": \"Potrebbe usare il tassametro, per favore?\"}, {\"original\": \"Por favor, conduzca un poco más rápido, tengo prisa.\", \"translated\": \"Può guidare un po\' più velocemente, per favore? Ho fretta.\"}, {\"original\": \"Párese aquí, por favor.\", \"translated\": \"Si fermi qui, per favore.\"}, {\"original\": \"¿Acepta tarjetas o pagos móviles?\", \"translated\": \"Accetta carte di credito o pagamenti mobili?\"}, {\"original\": \"¿Podría darme un recibo, por favor?\", \"translated\": \"Potrei avere lo scontrino, per favore?\"}, {\"original\": \"Gracias, conductor.\", \"translated\": \"Grazie, autista.\"}, {\"original\": \"¿Cuánto falta todavía?\", \"translated\": \"Quanto manca ancora?\"}]', 6, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en una farmacia?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con la farmacia, junto con sus traducciones al italiano:\"]', '[\"Compra de Medicamentos\", \"Consulta\", \"Pago\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir instrucciones sobre cómo tomar un medicamento, frases relacionadas con el uso del seguro médico o la duración del tratamiento? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Tiene medicamento para el resfriado?\", \"translated\": \"Ha dei farmaci per il raffreddore?\"}, {\"original\": \"¿Cómo debo tomar este medicamento?\", \"translated\": \"Come devo assumere questo farmaco?\"}, {\"original\": \"¿Tiene algún analgésico?\", \"translated\": \"Ha degli antidolorifici?\"}, {\"original\": \"¿Hay un folleto con instrucciones?\", \"translated\": \"C\'è un foglietto illustrativo?\"}, {\"original\": \"¿Este medicamento tiene efectos secundarios?\", \"translated\": \"Questo farmaco ha effetti collaterali?\"}, {\"original\": \"¿Puedo usar mi tarjeta de seguro médico?\", \"translated\": \"Posso usare la mia tessera sanitaria?\"}, {\"original\": \"¿Podría darme una caja de tiritas, por favor?\", \"translated\": \"Potrei avere una confezione di cerotti, per favore?\"}, {\"original\": \"¿Tiene algún antipirético?\", \"translated\": \"Ha degli antipiretici?\"}, {\"original\": \"Tengo una pequeña herida superficial. ¿Tiene antiséptico y tiritas?\", \"translated\": \"Ho una piccola escoriazione. Ha dell\'antisettico e dei cerotti?\"}, {\"original\": \"¿A qué hora cierran?\", \"translated\": \"A che ora chiude?\"}]', 7, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en los servicios de emergencia?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con los servicios de emergencia, junto con sus traducciones al italiano:\"]', '[\"Llamar a la policía\", \"Primeros auxilios\", \"Pedir ayuda\"]', 'es', '[\"Por ahora, ¿tiene alguna situación de emergencia específica en mente, como incendio, herido y necesidad de ayuda, llamada de emergencia? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"Por favor, ayúdeme a llamar a una ambulancia.\", \"translated\": \"Per favore, mi aiuti a chiamare un\'ambulanza.\"}, {\"original\": \"¿Dónde está el hospital?\", \"translated\": \"Dove si trova l\'ospedale?\"}, {\"original\": \"Alguien resultó herido.\", \"translated\": \"Qualcuno è ferito.\"}, {\"original\": \"Por favor, ayúdeme.\", \"translated\": \"Per favore, mi aiuti.\"}, {\"original\": \"¿Dónde está la comisaría?\", \"translated\": \"Dove si trova la stazione di polizia?\"}, {\"original\": \"He perdido mis pertenencias.\", \"translated\": \"Ho perso i miei effetti personali.\"}, {\"original\": \"¿Cuál es el número de los bomberos?\", \"translated\": \"Qual è il numero dei vigili del fuoco?\"}, {\"original\": \"He perdido mi pasaporte. ¿Sabe dónde está la comisaría más cercana?\", \"translated\": \"Ho perso il mio passaporto. Sa dov\'è la stazione di polizia più vicina?\"}, {\"original\": \"¿Hay una salida de emergencia?\", \"translated\": \"C\'è un\'uscita di emergenza?\"}, {\"original\": \"Alguien ha desmayado.\", \"translated\": \"Qualcuno è svenuto.\"}]', 8, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en la playa o junto a la piscina?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con la playa o la piscina, junto con sus traducciones al italiano:\"]', '[\"Nadar\", \"Tomar el sol\", \"Practicar deportes playeros\"]', 'es', '[\"Por ahora, ¿podría indicarme el contexto del evento o festival local al que asistirá, como un festival cultural, un festival gastronómico o un festival musical? Por favor, proporcione ese contexto.\", \"Indique las actividades a las que asistirá.\"]', '[\"¿Tiene alguna situación específica en mente? No dude en preguntar.\", \"Describa la situación que tiene en mente.\"]', '[{\"original\": \"¡Mira! Las olas allí son realmente grandes.\", \"translated\": \"Guarda! Le onde laggiù sono davvero grandi.\"}, {\"original\": \"Recuerda aplicar protector solar, los rayos UV aquí son muy intensos.\", \"translated\": \"Ricordati di applicare la crema solare, i raggi UV qui sono molto intensi.\"}, {\"original\": \"La arena de esta playa es tan fina que parece pisar algodón.\", \"translated\": \"La sabbia di questa spiaggia è così fine che sembra camminare sul cotone.\"}, {\"original\": \"¿Qué tal jugar voleibol en la playa?\", \"translated\": \"Che ne dici di giocare a pallavolo in spiaggia?\"}, {\"original\": \"Los veleros a lo lejos se ven hermosos.\", \"translated\": \"Le barche a vela in lontananza sono bellissime.\"}, {\"original\": \"El agua aquí es tan transparente que incluso puedes ver los peces.\", \"translated\": \"L\'acqua qui è così trasparente che si vedono perfino i pesci.\"}, {\"original\": \"Vamos a buscar conchas marinas.\", \"translated\": \"Andiamo a cercare delle conchiglie.\"}, {\"original\": \"Pasear por la playa al atardecer debe ser muy romántico.\", \"translated\": \"Passeggiare sulla spiaggia al tramonto deve essere molto romantico.\"}, {\"original\": \"He oído que los mariscos aquí son muy frescos; vayamos a probarlos.\", \"translated\": \"Ho sentito dire che qui il pesce e i frutti di mare sono freschissimi, andiamo a provarli.\"}, {\"original\": \"La marea está subiendo, vamos hacia la orilla.\", \"translated\": \"La marea sta salendo, dirigiamoci verso la riva.\"}]', 9, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en eventos y festivales locales?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con eventos y festivales locales, junto con sus traducciones al italiano:\"]', '[\"Asistir a eventos\", \"Celebrar festivales\", \"Aprender sobre la cultura\"]', 'es', '[\"Por ahora, ¿podría indicarme el contexto del evento o festival local al que asistirá, por ejemplo, Halloween, un concierto, una fiesta entre amigos u otra cosa? Por favor, proporcione ese contexto.\", \"Describa, por favor, las actividades que tiene en mente.\"]', '[\"¿Tiene alguna situación específica en mente? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', '[{\"original\": \"¿Hay algún evento hoy?\", \"translated\": \"Ci sono eventi oggi?\"}, {\"original\": \"¿Hay algo especial en este festival?\", \"translated\": \"C\'è qualcosa di speciale in questo festival?\"}, {\"original\": \"¿Dónde se celebra la festividad?\", \"translated\": \"Dove si tiene la celebrazione?\"}, {\"original\": \"¿Cómo puedo comprar entradas?\", \"translated\": \"Come posso acquistare i biglietti?\"}, {\"original\": \"¿A qué hora empieza la actuación?\", \"translated\": \"A che ora inizia lo spettacolo?\"}, {\"original\": \"¿Qué comida tradicional hay?\", \"translated\": \"Quali sono i cibi tradizionali?\"}, {\"original\": \"Aquí es realmente animado.\", \"translated\": \"Qui è davvero animato.\"}, {\"original\": \"¿Hay alguna actividad popular?\", \"translated\": \"Ci sono attività popolari?\"}, {\"original\": \"¡Felices fiestas!\", \"translated\": \"Buone feste!\"}, {\"original\": \"¿A qué hora termina el evento?\", \"translated\": \"A che ora termina l\'evento?\"}]', 10, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que pueda usar en un museo o galería de arte?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con museos o galerías de arte, junto con sus traducciones al italiano:\"]', '[\"Visita\", \"Visita guiada\", \"Compra de entradas\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir un manual de introducción, frases relacionadas con una ruta guiada o frases para comentar una exposición? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"¿Cuál es la tarifa de entrada?\", \"translated\": \"Quanto costa il biglietto d\'ingresso?\"}, {\"original\": \"¿Tienen guías de audio?\", \"translated\": \"Avete guide audio?\"}, {\"original\": \"¿Quién creó esta obra de arte?\", \"translated\": \"Chi ha creato quest\'opera d\'arte?\"}, {\"original\": \"¿Dónde se encuentra la pieza más valiosa del museo?\", \"translated\": \"Dove si trova il pezzo più prezioso del museo?\"}, {\"original\": \"¿Está permitida la fotografía?\", \"translated\": \"È consentito fare fotografie?\"}, {\"original\": \"¿Hay alguna exposición especial aquí?\", \"translated\": \"Ci sono delle mostre speciali qui?\"}, {\"original\": \"¿Cuánto tiempo dura la visita?\", \"translated\": \"Quanto tempo richiede la visita?\"}, {\"original\": \"¿Podría darnos una introducción?\", \"translated\": \"Potreste darci una breve introduzione?\"}, {\"original\": \"Estas obras son verdaderamente exquisitas.\", \"translated\": \"Queste opere sono davvero squisite.\"}, {\"original\": \"¿Dónde está la tienda de souvenirs?\", \"translated\": \"Dove si trova il negozio dei souvenir?\"}]', 11, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"¿Podría proporcionarme 10 frases comunes que puedo usar en cafeterías?\", \"¡Fantástico! Aquí tiene 10 frases comunes relacionadas con cafeterías, junto con sus traducciones al italiano:\"]', '[\"Pedir café\", \"Descansar\", \"Socializar\"]', 'es', '[\"Por ahora, ¿tiene alguna situación específica en mente, como pedir el menú, bebidas con hielo o calientes, otros productos? No dude en preguntar.\", \"Describa, por favor, la situación que tiene en mente.\"]', NULL, '[{\"original\": \"Tomaré un latte, por favor.\", \"translated\": \"Prenderò un caffè latte, per favore.\"}, {\"original\": \"¿Tienen conexión Wi-Fi?\", \"translated\": \"Avete il Wi-Fi?\"}, {\"original\": \"¿Podría ver el menú, por favor?\", \"translated\": \"Potrei vedere il menu, per favore?\"}, {\"original\": \"¿Se permiten recargas?\", \"translated\": \"Sono ammessi i rabbocchi?\"}, {\"original\": \"¿Ya está listo mi café?\", \"translated\": \"Il mio caffè è pronto?\"}, {\"original\": \"¿Cuánto tiempo puedo quedarme aquí?\", \"translated\": \"Per quanto tempo posso stare seduto qui?\"}, {\"original\": \"¿Podría tomarnos una foto?\", \"translated\": \"Potrebbe scattarci una foto?\"}, {\"original\": \"¿Dónde está el baño?\", \"translated\": \"Dov\'è il bagno?\"}, {\"original\": \"La cuenta, por favor. Gracias.\", \"translated\": \"Il conto, per favore. Grazie.\"}, {\"original\": \"Sabe realmente bien.\", \"translated\": \"Ha davvero un ottimo sapore.\"}]', 12, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"저에게 식당에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋아요! 식당과 관련된 10가지 일반적인 문장과 이탈리아어 번역을 드립니다:\"]', '[\"식사\", \"주문\", \"결제\"]', 'ko', '[\"지금은, 음료 주문, 불만 제기, 성분 문의 등 특정 상황이 떠오르시나요? 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"실례합니다, 음식은 얼마나 더 오래 걸릴까요?\", \"translated\": \"Mi scusi, quanto ancora ci vorrà per il nostro cibo?\"}, {\"original\": \"두 분을 위한 테이블을 부탁드립니다.\", \"translated\": \"Un tavolo per due, per favore.\"}, {\"original\": \"메뉴를 보여주실 수 있겠어요?\", \"translated\": \"Possiamo vedere il menu, per favore?\"}, {\"original\": \"추천해 주실 만한 특별한 요리가 있나요?\", \"translated\": \"Avete dei piatti speciali da consigliare?\"}, {\"original\": \"이것과 이것을 주문하고 싶어요.\", \"translated\": \"Vorrei ordinare questo e questo.\"}, {\"original\": \"물 한 잔 부탁드립니다. 감사합니다.\", \"translated\": \"Un bicchiere d\'acqua, per favore. Grazie.\"}, {\"original\": \"계산서를 부탁드려요.\", \"translated\": \"Il conto, per favore.\"}, {\"original\": \"신용카드로 결제할 수 있나요?\", \"translated\": \"Posso pagare con la carta di credito?\"}, {\"original\": \"이걸 포장해 주실 수 있나요?\", \"translated\": \"Potreste imballarlo da asporto, per favore?\"}, {\"original\": \"음식이 정말 맛있었어요. 감사합니다.\", \"translated\": \"Il cibo era delizioso, grazie.\"}]', 1, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"호텔에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 호텔과 관련된 10가지 일반적인 문장과 이탈리아어 번역을 제공합니다:\"]', '[\"체크인\", \"체크아웃\", \"객실 서비스\"]', 'ko', '[\"지금은, 방 위치, 다른 호텔 서비스 또는 체크아웃과 같은 구체적인 상황이 있으신가요? 자유롭게 물어보세요.\", \"심중에 생각하고 계신 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"안녕하세요, 예약이 있습니다, 여기 여권입니다.\", \"translated\": \"Ciao, ho una prenotazione, ecco il mio passaporto.\"}, {\"original\": \"예약 가능한 객실이 있습니까?\", \"translated\": \"Avete disponibilità?\"}, {\"original\": \"실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\", \"translated\": \"Scusi, l\'hotel ha una palestra o una lavanderia?\"}, {\"original\": \"아침 식사가 몇 시부터 시작됩니까?\", \"translated\": \"A che ora inizia la colazione?\"}, {\"original\": \"방 키를 좀 주시겠어요?\", \"translated\": \"Potrei avere una chiave della stanza, per favore?\"}, {\"original\": \"짐을 방까지 가져다 도와주실 수 있나요?\", \"translated\": \"Potreste aiutarmi a portare i miei bagagli nella stanza?\"}, {\"original\": \"객실 서비스를 부르는 방법은 무엇인가요?\", \"translated\": \"Come faccio a chiamare il servizio in camera?\"}, {\"original\": \"체크아웃 시간은 몇 시입니까?\", \"translated\": \"A che ora è il check-out?\"}, {\"original\": \"영수증/송장 작성해 주시겠어요?\", \"translated\": \"Potreste scrivere un ricevuta/fattura per me?\"}, {\"original\": \"저의 짐을 여기 두어도 괜찮나요?\", \"translated\": \"Posso lasciare i miei bagagli qui?\"}]', 2, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공항에서 사용할 수 있는 10가지 일반적인 문구를 제공해 주시겠습니까?\", \"좋습니다! 공항과 관련된 10가지 일반적인 문구와 이탈리아어 번역을 제공합니다:\"]', '[\"체크인\", \"탑승\", \"수하물 검사\"]', 'ko', '[\"현재, 체크인, 수하물 인수, 자동차 대여 서비스 등 특정 상황을 생각하고 계신가요? 자유롭게 물어보세요.\", \"제가 생각하는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"체크인 카운터는 어디입니까?\", \"translated\": \"Dov\'è il banco di check-in?\"}, {\"original\": \"창가 자리가 있으면 좋겠습니다.\", \"translated\": \"Vorrei un posto vicino al finestrino, per favore.\"}, {\"original\": \"이 항공편이 지연되었나요?\", \"translated\": \"Questo volo è in ritardo?\"}, {\"original\": \"이 수하물을 확인해야 합니다.\", \"translated\": \"Devo effettuare il controllo di questo bagaglio.\"}, {\"original\": \"승객 탑승 게이트는 어디입니까?\", \"translated\": \"Dov\'è la porta di imbarco?\"}, {\"original\": \"비행기가 출발할 예정입니다.\", \"translated\": \"L\'aereo sta per decollare.\"}, {\"original\": \"노트북과 전원 어댑터를 꺼내야 하나요?\", \"translated\": \"Devo rimuovere il mio laptop e la mia batteria portatile?\"}, {\"original\": \"관세 면세점은 어디입니까?\", \"translated\": \"Dov\'è il negozio duty-free?\"}, {\"original\": \"내 수하물이 보이지 않습니다.\", \"translated\": \"Non riesco a trovare la mia valigia.\"}, {\"original\": \" wheelchair 서비스가 있습니까?\", \"translated\": \"Avete un servizio di sedia a rotelle?\"}]', 3, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"대중교통에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 대중교통과 관련된 10가지 일반적인 문장과 이탈리아어 번역을 제공합니다:\"]', '[\"버스/지하철 탑승\", \"티켓 구매\", \"환승\"]', 'ko', '[\"지금은, 버스 정류장에 대한 질문, 티켓 가격, 하차 등과 같은 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"심상 중인 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"이 버스는 종점으로 가나요?\", \"translated\": \"Questo autobus va alla stazione?\"}, {\"original\": \"다음 정류장은 어디예요?\", \"translated\": \"Qual è la prossima fermata?\"}, {\"original\": \"티켓을 어디에서 살 수 있나요?\", \"translated\": \"Dove posso comprare un biglietto?\"}, {\"original\": \"XX로 가는 티켓 하나 주세요.\", \"translated\": \"Un biglietto per XX, per favore.\"}, {\"original\": \"환승해야 하나요?\", \"translated\": \"Devo cambiare linea?\"}, {\"original\": \"다음 지하철이 몇 분 후에 오나요?\", \"translated\": \"Quanto manca all\'arrivo del prossimo treno della metropolitana?\"}, {\"original\": \"실례합니다, 지나가도 될까요?\", \"translated\": \"Mi scusi, mi faccia passare.\"}, {\"original\": \"이 자리에 누가 앉았나요?\", \"translated\": \"Questo posto è occupato?\"}, {\"original\": \"실례합니다, XX로 가려면 2호선으로 어디에서 환승하면 되나요?\", \"translated\": \"Mi scusi, dove posso cambiare per la Linea 2 per andare a XX?\"}, {\"original\": \"XX에 어떻게 가면 되나요?\", \"translated\": \"Come faccio ad arrivare a XX?\"}]', 4, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"관광 명소에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 관광 명소와 관련된 10가지 일반적인 문장과 이탈리아어 번역을 제공합니다:\"]', '[\"관광하기\", \"사진 찍기\", \"티켓 구매하기\"]', 'ko', '[\"현재, 티켓 가격을 묻거나 주차장 찾기 또는 투어 가이드 서비스와 같은 특정 상황을 생각하고 계신가요? 자유롭게 물어보세요.\", \"심중에 생각하고 계신 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"Quanto costa l\'ingresso?\"}, {\"original\": \"학생 할인 티켓이 있나요?\", \"translated\": \"Sono disponibili biglietti per gli studenti?\"}, {\"original\": \"이 관광지가 몇 시에 문을 여나요?\", \"translated\": \"A che ora apre l\'attrazione?\"}, {\"original\": \"여기서 즐길 수 있는 재미있는 활동은 무엇인가요?\", \"translated\": \"Cosa si può fare di divertente qui?\"}, {\"original\": \"우리 사진을 찍어 줄 수 있나요?\", \"translated\": \"Puoi scattarci una foto?\"}, {\"original\": \"관광 버스는 어디에 있나요?\", \"translated\": \"Dove si trova l\'autobus turistico?\"}, {\"original\": \"화장실은 어디에 있나요?\", \"translated\": \"Dove si trova il bagno?\"}, {\"original\": \"가장 좋은 전망 장소는 어디인가요?\", \"translated\": \"Dove è il miglior punto di vista?\"}, {\"original\": \"여기 경치가 아름답네요.\", \"translated\": \"Il paesaggio qui è bello.\"}, {\"original\": \"가이드 투어가 있나요?\", \"translated\": \"È disponibile un tour guidato?\"}]', 5, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"택시나 택시 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있습니까?\", \"좋아요! 택시나 택시 서비스와 관련된 10가지 일반적인 문장과 이탈리아어 번역을 드립니다:\"]', '[\"택시 타기\", \"도착지 말하기\", \"결제\"]', 'ko', '[\"지금, 목적지 요청, 요금, 영수증 요청 등과 같은 것을 가장 원하시는 것은 무엇입니까? 자유롭게 물어보세요.\", \"심중에 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"택시를 어디서 탈 수 있나요?\", \"translated\": \"Dove posso prendere un taxi?\"}, {\"original\": \"이 주소로 저를 데려가 주세요.\", \"translated\": \"Portami a questo indirizzo.\"}, {\"original\": \"얼마 정도 될까요?\", \"translated\": \"Circa quanto costerà?\"}, {\"original\": \"계기판을 사용해 주시겠어요?\", \"translated\": \"Può usare il tassametro, per favore?\"}, {\"original\": \"좀 더 빨리 운전해 주세요, 저는 급합니다.\", \"translated\": \"Guidi un po\' più velocemente, ho fretta.\"}, {\"original\": \"여기에서 멈춰 주세요.\", \"translated\": \"Si fermi qui.\"}, {\"original\": \"카드나 모바일 결제를 받으세요?\", \"translated\": \"Accettate carte o pagamenti mobili?\"}, {\"original\": \"영수증을 좀 주실 수 있나요?\", \"translated\": \"Posso avere lo scontrino, per favore?\"}, {\"original\": \"감사합니다, 운전자님.\", \"translated\": \"Grazie, autista.\"}, {\"original\": \"얼마 더 가야 하나요?\", \"translated\": \"Quanto manca?\"}]', 6, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"약국에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 약국과 관련된 10가지 일반적인 표현과 이탈리아어 번역을 드립니다:\"]', '[\"약 구입\", \"상담\", \"결제\"]', 'ko', '[\"현재, 약을 복용하는 방법에 대해 묻는 것처럼 구체적인 상황이 있으신가요? 보험 관련 표현, 약물의 기간, 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"감기약이 있습니까?\", \"translated\": \"Hai medicine per il raffreddore?\"}, {\"original\": \"이 약은 어떻게 복용해야 하나요?\", \"translated\": \"Come devo prendere questa medicina?\"}, {\"original\": \"진통제가 있습니까?\", \"translated\": \"Hai dei farmaci per il dolore?\"}, {\"original\": \"사용 안내서가 있습니까?\", \"translated\": \"C\'è un foglietto illustrativo?\"}, {\"original\": \"이 약에는 부작용이 있습니까?\", \"translated\": \"Questo farmaco ha effetti collaterali?\"}, {\"original\": \"의료보험 카드를 사용할 수 있나요?\", \"translated\": \"Posso usare la mia carta assicurativa sanitaria?\"}, {\"original\": \"붕대 상자 하나 주실 수 있나요?\", \"translated\": \"Potrei avere una confezione di cerotti, per favore?\"}, {\"original\": \"발열 억제제가 있습니까?\", \"translated\": \"Hai dei medicinali per la febbre?\"}, {\"original\": \"조금 까져서 부상이 생겼어요. 항균제와 붕대가 있습니까?\", \"translated\": \"Ho un piccolo graffio. Hai dell\'antisettico e cerotti?\"}, {\"original\": \"몇 시에 문을 닫으십니까?\", \"translated\": \"A che ora chiudete?\"}]', 7, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"응급 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 응급 서비스와 관련된 10가지 일반적인 문장과 이탈리아어 번역을 제공합니다:\"]', '[\"경찰 호출\", \"응급처치\", \"도움 요청\"]', 'ko', '[\"현재, 불이나 부상으로 도움이 필요한 상황, 응급 전화 등 특정 응급 상황이 있으신가요? 자유롭게 물어보세요.\", \"심상에 있는 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"응급차를 불러줘.\", \"translated\": \"Per favore, aiutami a chiamare un\'ambulanza.\"}, {\"original\": \"병원은 어디에요?\", \"translated\": \"Dov\'è l\'ospedale?\"}, {\"original\": \"누군가 다쳤어요.\", \"translated\": \"Qualcuno è ferito.\"}, {\"original\": \"도와주세요.\", \"translated\": \"Per favore, aiutami.\"}, {\"original\": \"경찰서는 어디에요?\", \"translated\": \"Dov\'è la stazione dei pompieri?\"}, {\"original\": \"내 소지품을 잃어버렸어요.\", \"translated\": \"Ho perso i miei oggetti.\"}, {\"original\": \"소방서 전화번호는 무엇인가요?\", \"translated\": \"Qual è il numero per il dipartimento dei vigili del fuoco?\"}, {\"original\": \"여권을 잃어버렸어요. 가장 가까운 경찰서는 어디인가요?\", \"translated\": \"Ho perso il mio passaporto. Sai dove si trova la stazione della polizia più vicina?\"}, {\"original\": \"비상출구는 어디에요?\", \"translated\": \"C\'è un\'uscita di emergenza?\"}, {\"original\": \"누군가 쓰러졌어요.\", \"translated\": \"Qualcuno ha perso conoscenza.\"}]', 8, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"해변 또는 수영장가에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 해변 또는 수영장가와 관련된 10개의 일반적인 문장과 이탈리아어 번역을 제공합니다:\"]', '[\"수영\", \"태양을 쬐기\", \"해변 스포츠\"]', 'ko', '[\"지금은, 참석하는 현지 이벤트나 축제의 맥락을 제공해 주세요. 예를 들어 문화 축제, 음식 축제 또는 음악 축제 등입니다. 맥락을 제공해 주세요.\", \"참석하는 활동을 제공해 주세요.\"]', '[\"특정 상황이 마음에 있는지 여부를 확인해 주세요. 자유롭게 질문하세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', '[{\"original\": \"보라! 저쪽의 파도가 정말 크다.\", \"translated\": \"Guarda! Le onde laggiù sono davvero grandi.\"}, {\"original\": \"자외선 차단제를 바르세요, 여기 자외선이 매우 강합니다.\", \"translated\": \"Ricorda di applicare la crema solare, i raggi UV qui sono molto forti.\"}, {\"original\": \"이 해변의 모래는 매우 미세해서 마치 울타리에 발을 디디는 것처럼 느껴집니다.\", \"translated\": \"La sabbia su questa spiaggia è così fine, sembra di camminare su cotone.\"}, {\"original\": \"해변에서 배구를 하기 어때?\", \"translated\": \"Perché non proviamo a giocare a pallavolo in spiaggia?\"}, {\"original\": \"멀리 있는 요트들이 아름다워 보인다.\", \"translated\": \"Le barche a vela lontane hanno un aspetto bellissimo.\"}, {\"original\": \"여기 물은 매우 맑아서 물고기를 보는 것이 가능하다.\", \"translated\": \"Acqua qui è così limpida, si possono anche vedere i pesci.\"}, {\"original\": \"해안가에서 조개를 찾으러 가자.\", \"translated\": \"Andiamo a cercare conchiglie.\"}, {\"original\": \"일몰 때 해변을 산책하는 것은 매우 로맨틱할 것이다.\", \"translated\": \"Far passeggiare sulla spiaggia al tramonto deve essere molto romantico.\"}, {\"original\": \"여기 해산물이 매우 신선하다는 것을 들었어요, 같이 먹어보자.\", \"translated\": \"Ho sentito che il pesce qui è molto fresco, andiamo a provare.\"}, {\"original\": \"조수 간조가 오고 있으니, 해안으로 가자.\", \"translated\": \"L\'alta marea sta arrivando, andiamo verso la riva.\"}]', 9, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"로컬 이벤트 및 축제에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋습니다! 로컬 이벤트 및 축제와 관련된 10가지 일반적인 표현과 함께 이탈리아어 번역을 제공합니다:\"]', '[\"이벤트 참석\", \"절기 축하하기\", \"문화 배우기\"]', 'ko', '[\"현재까지, 당신이 참석하는 로컬 이벤트 또는 축제의 맥락을 제공해 주시겠습니까? 예를 들어 할로윈, 콘서트 또는 친구 파티, 또는 기타 사항을 말해 주세요. 맥락을 제공해 주세요.\", \"당신의 마음에 떠오르는 활동을 설명해 주세요.\"]', '[\"특정 상황이 마음에 드시나요? 자유롭게 물어보세요.\", \"당신의 마음에 떠오르는 상황을 설명해 주세요.\"]', '[{\"original\": \"오늘 행사가 있나요?\", \"translated\": \"Ci sono eventi oggi?\"}, {\"original\": \"이 축제에 특별한 점이 있나요?\", \"translated\": \"C\'è qualcosa di speciale per questa festa?\"}, {\"original\": \"축제는 어디에서 열리나요?\", \"translated\": \"Dove si svolge la celebrazione?\"}, {\"original\": \"티켓을 어떻게 구입할 수 있나요?\", \"translated\": \"Come posso acquistare i biglietti?\"}, {\"original\": \"공연은 몇 시에 시작하나요?\", \"translated\": \"A che ora inizia lo spettacolo?\"}, {\"original\": \"이곳에 어떤 전통 음식이 있나요?\", \"translated\": \"Quali cibi tradizionali ci sono?\"}, {\"original\": \"여기 정말 활기가 넘치네요.\", \"translated\": \"È veramente vivace qui.\"}, {\"original\": \"민속 활동이 있나요?\", \"translated\": \"Ci sono attività folkloristiche?\"}, {\"original\": \"즐거운 명절 되세요!\", \"translated\": \"Buone vacanze!\"}, {\"original\": \"행사는 몇 시에 끝나나요?\", \"translated\": \"A che ora finisce l\'evento?\"}]', 10, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"박물관 또는 미술관에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 박물관 또는 미술관과 관련된 10가지 일반적인 문장과 이탈리아어 번역을 드립니다.\"]', '[\"방문\", \"가이드 투어\", \"티켓 구매\"]', 'ko', '[\"지금은 특정 상황이 생각나십니까, 예를 들어 안내서 요청, 로드맵과 관련된 문장, 전시품에 대한 의견을 표현하는 문장 등 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마예요?\", \"translated\": \"Quanto costa l\'ingresso?\"}, {\"original\": \"음성 안내 서비스가 있나요?\", \"translated\": \"Avete guide audio?\"}, {\"original\": \"이 작품을 만든 사람은 누구예요?\", \"translated\": \"Chi ha creato quest\'opera d\'arte?\"}, {\"original\": \"박물관에서 가장 소중한 작품은 어디에 있나요?\", \"translated\": \"Dove si trova la pezzo più pregiato del museo?\"}, {\"original\": \"사진 촬영이 가능한가요?\", \"translated\": \"È consentita la fotografia?\"}, {\"original\": \"여기 특별 전시회가 있나요?\", \"translated\": \"Ci sono mostre speciali qui?\"}, {\"original\": \"방문에 얼마나 시간이 걸리나요?\", \"translated\": \"Quanto dura la visita?\"}, {\"original\": \"우리에게 간단한 소개를 해주실 수 있나요?\", \"translated\": \"Potete darci un\'introduzione?\"}, {\"original\": \"이 작품들은 정말 아름답네요.\", \"translated\": \"Queste opere sono veramente eleganti.\"}, {\"original\": \"기념품 가게는 어디에 있나요?\", \"translated\": \"Dove si trova il negozio di souvenir?\"}]', 11, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"카페에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 카페와 관련된 10가지 일반적인 문장과 이탈리아어 번역을 제공합니다:\"]', '[\"커피 주문\", \"휴식\", \"사회적 활동\"]', 'ko', '[\"지금은, 메뉴를 요청하거나, 아이스 또는 핫 음료, 기타 제품에 대한 상황을 구체적으로 생각하고 계신가요? 자유롭게 물어보세요.\", \"현재 마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"저는 라테 하나 주세요.\", \"translated\": \"Vorrei un latte, per favore.\"}, {\"original\": \"와이파이 있으세요?\", \"translated\": \"Avete il Wi-Fi?\"}, {\"original\": \"메뉴 좀 보여주세요.\", \"translated\": \"Potrei vedere il menu, per favore?\"}, {\"original\": \"리필 가능하세요?\", \"translated\": \"È permesso rifornire?\"}, {\"original\": \"제 커피 준비되었나요?\", \"translated\": \"Il mio caffè è pronto?\"}, {\"original\": \"이곳에서 얼마나 오래 있을 수 있나요?\", \"translated\": \"Per quanto tempo posso stare qui?\"}, {\"original\": \"우리 사진 좀 찍어줄 수 있나요?\", \"translated\": \"Potreste fare una foto per noi?\"}, {\"original\": \"화장실은 어디에요?\", \"translated\": \"Dove si trova il bagno?\"}, {\"original\": \"계산해 주세요. 감사합니다.\", \"translated\": \"Conto, per favore. Grazie.\"}, {\"original\": \"맛이 정말 좋습니다.\", \"translated\": \"Ha un sapore veramente buono.\"}]', 12, 'it');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"레스토랑에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 레스토랑과 관련된 10가지 일반적인 문장과 함께 러시아어 번역을 드립니다:\"]', '[\"식사\", \"주문\", \"결제\"]', 'ko', '[\"지금은, 음료 주문, 불만 제기, 성분에 대한 질문 등 특정 상황이 머릿속에 있는지 궁금합니다. 자유롭게 물어보세요.\", \"머릿속에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"실례합니다, 음식은 얼마나 더 오래 걸리나요?\", \"translated\": \"Извините, как скоро наше питание будет готово?\"}, {\"original\": \"이렇게 두 분을 위한 테이블을 부탁드립니다.\", \"translated\": \"Стол на двоих, пожалуйста.\"}, {\"original\": \"메뉴를 보여주실 수 있겠어요?\", \"translated\": \"Можно посмотреть меню, пожалуйста?\"}, {\"original\": \"추천할 만한 특별한 요리가 있나요?\", \"translated\": \"У вас есть какие-нибудь рекомендуемые блюда?\"}, {\"original\": \"이것과 이것을 주문하고 싶어요.\", \"translated\": \"Я хочу заказать это и это.\"}, {\"original\": \"물 한 잔 부탁드려요. 감사합니다.\", \"translated\": \"Стакан воды, пожалуйста. Спасибо.\"}, {\"original\": \"계산서 좀 주세요.\", \"translated\": \"Счет, пожалуйста.\"}, {\"original\": \"신용카드로 지불할 수 있나요?\", \"translated\": \"Могу я заплатить кредитной картой?\"}, {\"original\": \"이걸 포장해 주실 수 있겠어요?\", \"translated\": \"Можно упаковать это для выноса, пожалуйста?\"}, {\"original\": \"음식이 정말 맛있었어요, 감사합니다.\", \"translated\": \"Еда была вкусной, спасибо.\"}]', 1, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"호텔에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있습니까?\", \"좋아요! 호텔과 관련된 10가지 일반적인 표현과 러시아어 번역을 제공합니다:\"]', '[\"체크인\", \"체크아웃\", \"객실 서비스\"]', 'ko', '[\"현재, 방 위치, 기타 호텔 서비스 또는 체크아웃과 같은 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"심중에 생각하고 있는 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"안녕하세요, 예약이 있습니다, 여권을 드립니다.\", \"translated\": \"Здравствуйте, у меня бронь, вот мой паспорт.\"}, {\"original\": \"예약 가능한 객실이 있습니까?\", \"translated\": \"У вас есть свободные номера?\"}, {\"original\": \"실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\", \"translated\": \"Извините, есть ли в отеле тренажерный зал или прачечная?\"}, {\"original\": \"아침 식사가 몇 시부터 시작합니까?\", \"translated\": \"Во сколько начинается завтрак?\"}, {\"original\": \"방 키를 주시겠습니까?\", \"translated\": \"Могу я получить ключ от номера, пожалуйста?\"}, {\"original\": \"제 짐을 방으로 옮겨주실 수 있겠습니까?\", \"translated\": \"Можете ли вы помочь мне доставить мою поклажу в номер?\"}, {\"original\": \"객실 서비스를 부르는 방법은 무엇입니까?\", \"translated\": \"Как я могу вызвать обслуживание в номер?\"}, {\"original\": \"체크아웃 시간은 몇 시입니까?\", \"translated\": \"Во сколько время выезда?\"}, {\"original\": \"영수증/송장 작성해 주시겠습니까?\", \"translated\": \"Можете ли вы выдать мне чек/счет?\"}, {\"original\": \"제 짐을 여기 두어도 될까요?\", \"translated\": \"Могу ли я оставить здесь свою поклажу?\"}]', 2, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공항에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 공항과 관련된 10가지 일반적인 문장과 러시아어 번역을 제공합니다:\"]', '[\"체크인\", \"승객 탑승\", \"수화물 수령\"]', 'ko', '[\"현재, 체크인, 수하물 수령, 자동차 대여 서비스와 같은 구체적인 상황이 있으신가요? 자유롭게 물어보세요.\", \"심중에 생각하고 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"체크인 카운터는 어디입니까?\", \"translated\": \"Где находится стойка регистрации?\"}, {\"original\": \"창가 자리를 원합니다.\", \"translated\": \"Я хотел бы место у окна, пожалуйста.\"}, {\"original\": \"이 항공편은 지연되었나요?\", \"translated\": \"Этот рейс задерживается?\"}, {\"original\": \"이 수하물을 확인해야 합니다.\", \"translated\": \"Мне нужно зарегистрировать этот багаж.\"}, {\"original\": \"승무 게이트는 어디입니까?\", \"translated\": \"Где находится выход для посадки?\"}, {\"original\": \"비행기가 곧 이륙할 예정입니다.\", \"translated\": \"Самолет скоро взлетит.\"}, {\"original\": \"노트북과 파워뱅크를 꺼내야 하나요?\", \"translated\": \"Мне нужно вынуть ноутбук и зарядное устройство?\"}, {\"original\": \"면세점은 어디입니까?\", \"translated\": \"Где находится магазин беспошлинной торговли?\"}, {\"original\": \"내 수화물을 찾을 수 없습니다.\", \"translated\": \"Я не могу найти свою чемодан.\"}, {\"original\": \"휠체어 서비스를 제공합니까?\", \"translated\": \"У вас есть услуга коляски?\"}]', 3, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공공교통에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋아요! 공공교통과 관련된 10가지 일반적인 문장과 러시아어 번역을 드립니다:\"]', '[\"버스/지하철 탑승\", \"티켓 구매\", \"환승\"]', 'ko', '[\"지금은, 버스 정류장에 대한 문의, 티켓 가격, 하차와 같은 구체적인 상황이 있으신가요? 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"이 버스는 터미널로 가나요?\", \"translated\": \"Этот автобус идет в терминал?\"}, {\"original\": \"다음 정류장은 어디예요?\", \"translated\": \"Какая следующая остановка?\"}, {\"original\": \"표를 어디서 살 수 있나요?\", \"translated\": \"Где я могу купить билет?\"}, {\"original\": \"XX까지 한 장의 표를 주세요.\", \"translated\": \"Один билет до XX, пожалуйста.\"}, {\"original\": \"환승해야 하나요?\", \"translated\": \"Мне нужно пересесть?\"}, {\"original\": \"다음 지하철이 몇 분 후에 오나요?\", \"translated\": \"Сколько времени до следующего поезда метро?\"}, {\"original\": \"실례합니다, 지나가도 되겠습니까?\", \"translated\": \"Извините, разрешите пройти.\"}, {\"original\": \"이 자리에 사람이 앉았나요?\", \"translated\": \"Это место занято?\"}, {\"original\": \"실례합니다, XX로 가기 위해 2호선으로 어디에서 환승하면 되나요?\", \"translated\": \"Извините, где я могу перейти на Линию 2, чтобы добраться до XX?\"}, {\"original\": \"XX에 어떻게 가면 되나요?\", \"translated\": \"Как мне добраться до XX?\"}]', 4, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"관광지에서 사용할 수 있는 10가지 일반 문구를 제공해 주실 수 있나요?\", \"좋습니다! 관광지와 관련된 10가지 일반 문구와 함께 러시아어 번역을 제공합니다:\"]', '[\"관광하기\", \"사진 찍기\", \"티켓 구매\"]', 'ko', '[\"지금은, 특정 상황이 생각나시는지요? 예를 들어 티켓 가격에 대해 묻거나, 주차장 찾기 또는 투어 가이드 서비스에 대해 물어보는 것처럼 자유롭게 질문해 주세요.\", \"혹시 마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마예요?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"학생 할인 티켓이 있나요?\", \"translated\": \"Доступны ли студенческие билеты?\"}, {\"original\": \"이 관광지가 몇 시에 열어요?\", \"translated\": \"Во сколько открыта достопримечательность?\"}, {\"original\": \"여기서 할 수 있는 재미있는 일은 뭐예요?\", \"translated\": \"Что интересного можно здесь сделать?\"}, {\"original\": \"우리 사진을 찍어줄 수 있나요?\", \"translated\": \"Можете ли вы сделать для нас фото?\"}, {\"original\": \"관광 버스는 어디에 있어요?\", \"translated\": \"Где находится автобус для экскурсий?\"}, {\"original\": \"화장실은 어디에 있어요?\", \"translated\": \"Где находится туалет?\"}, {\"original\": \"가장 좋은 전망지는 어디예요?\", \"translated\": \"Где лучшая точка для просмотра?\"}, {\"original\": \"여기 경치가 아름다워요.\", \"translated\": \"Пейзажи здесь красивые.\"}, {\"original\": \"가이드 투어 서비스가 있나요?\", \"translated\": \"Доступна ли гидированная экскурсия?\"}]', 5, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"택시나 택시 서비스에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있습니까?\", \"좋아요! 택시나 택시 서비스와 관련된 10개의 일반적인 문장과 러시아어 번역이 있습니다:\"]', '[\"택시 타기\", \"도착지 말하기\", \"결제\"]', 'ko', '[\"지금, 목적지 요청, 요금 문의, 영수증 요청 등 하고 싶은 것을 자유롭게 물어보세요.\", \"마음속에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"택시를 어디에서 탈 수 있나요?\", \"translated\": \"Где я могу взять такси?\"}, {\"original\": \"이 주소로 저를 데려가 주세요.\", \"translated\": \"Пожалуйста, отвезите меня по этот адрес.\"}, {\"original\": \"얼마나 비쌀까요?\", \"translated\": \"Примерно сколько это будет стоить?\"}, {\"original\": \"계기표를 사용해 주세요.\", \"translated\": \"Можете, пожалуйста, использовать счётчик?\"}, {\"original\": \"조금 더 빨리 운전해 주세요, 저는 급합니다.\", \"translated\": \"Пожалуйста, езжайте чуть быстрее, у меня спешка.\"}, {\"original\": \"여기서 멈춰 주세요.\", \"translated\": \"Пожалуйста, остановитесь здесь.\"}, {\"original\": \"카드나 모바일 결제를 받으세요?\", \"translated\": \"Вы принимаете карты или мобильные платежи?\"}, {\"original\": \"영수증을 좀 주실 수 있나요?\", \"translated\": \"Могу я получить квитанцию, пожалуйста?\"}, {\"original\": \"감사합니다, 운전자님.\", \"translated\": \"Спасибо, водитель.\"}, {\"original\": \"이곳에서 얼마나 더 가야 하나요?\", \"translated\": \"Как далеко ещё?\"}]', 6, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"약국에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 약국과 관련된 10가지 일반적인 문장과 러시아어 번역을 제공합니다:\"]', '[\"약 구매\", \"상담\", \"결제\"]', 'ko', '[\"지금은, 약을 복용하는 방법에 대해 묻는 것처럼 구체적인 상황이 있으신가요? 보험 관련 문장, 약물의 지속 기간 등 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"차가운 약이 있습니까?\", \"translated\": \"У вас есть лекарство от простуды?\"}, {\"original\": \"이 약은 어떻게 복용해야 하나요?\", \"translated\": \"Как мне принимать это лекарство?\"}, {\"original\": \"진통제가 있습니까?\", \"translated\": \"У вас есть обезболивающие?\"}, {\"original\": \"사용 설명서가 있습니까?\", \"translated\": \"Есть ли инструкция?\"}, {\"original\": \"이 약에 부작용이 있습니까?\", \"translated\": \"У этого лекарства есть побочные эффекты?\"}, {\"original\": \"내 의료 보험 카드를 사용할 수 있습니까?\", \"translated\": \"Могу ли я использовать свою медицинскую страховую карту?\"}, {\"original\": \"붕대 상자 하나 주실 수 있습니까?\", \"translated\": \"Можно получить коробку пластырей, пожалуйста?\"}, {\"original\": \"발열 완화제가 있습니까?\", \"translated\": \"У вас есть средства от температуры?\"}, {\"original\": \"조금 까져서 부상이 생겼어요. 소독약과 붕대가 있습니까?\", \"translated\": \"У меня небольшая царапина. У вас есть антибиотик и пластыри?\"}, {\"original\": \"언제 문을 닫으십니까?\", \"translated\": \"Во сколько вы закрываетесь?\"}]', 7, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"응급 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 응급 서비스와 관련된 10가지 일반적인 문장과 러시아어 번역을 드립니다:\"]', '[\"경찰 호출\", \"응급처치\", \"도움 요청\"]', 'ko', '[\"현재, 특정한 응급 상황이 있으신가요? 예를 들어 화재, 부상 및 도움이 필요한 경우, 응급 전화 등 자유롭게 질문해 주세요.\", \"심상에 있는 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"응급차를 불러줘.\", \"translated\": \"Пожалуйста, помогите мне вызвать скорую помощь.\"}, {\"original\": \"병원은 어디야?\", \"translated\": \"Где больница?\"}, {\"original\": \"누군가 부상당했어.\", \"translated\": \"Кто-то ранен.\"}, {\"original\": \"도와줘.\", \"translated\": \"Пожалуйста, помогите мне.\"}, {\"original\": \"경찰서는 어디야?\", \"translated\": \"Где полицейский участок?\"}, {\"original\": \"내 소지품을 잃어버렸어.\", \"translated\": \"Я потерял свои вещи.\"}, {\"original\": \"소방서 번호는 뭐야?\", \"translated\": \"Какой номер пожарной службы?\"}, {\"original\": \"여권을 잃어버렸어. 가까운 경찰서는 어디야?\", \"translated\": \"Я потерял свой паспорт. Знаете ли вы, где ближайший полицейский участок?\"}, {\"original\": \"비상 출구는 어디야?\", \"translated\": \"Есть ли аварийный выход?\"}, {\"original\": \"누군가 쓰러졌어.\", \"translated\": \"Кто-то потерял сознание.\"}]', 8, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"해변 또는 수영장가에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 해변 또는 수영장가와 관련된 10개의 일반적인 문장과 러시아어 번역을 드립니다:\"]', '[\"수영\", \"태양광 쬐기\", \"해변 스포츠\"]', 'ko', '[\"지금은, 참석하는 지역 이벤트 또는 축제의 맥락을 제공해 주시겠어요? 예를 들어 문화 축제, 음식 축제 또는 음악 축제 등입니다. 맥락을 제공해 주세요.\", \"참석하는 활동을 제공해 주세요.\"]', '[\"특정 상황이 마음에 있으신가요? 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', '[{\"original\": \"보라, 저쪽의 파도가 정말 크다.\", \"translated\": \"Смотри! Волны там действительно большие.\"}, {\"original\": \"자외선 차단제를 바르세요, 여기 자외선은 매우 강합니다.\", \"translated\": \"Не забудь нанести солнцезащитный крем, ультрафиолетовые лучи здесь очень сильные.\"}, {\"original\": \"이 해변의 모래는 매우 미세해서 마치 울퉁불퉁한 천을 밟는 것 같아요.\", \"translated\": \"Песок на этом пляже такой тонкий, что кажется, будто ты ступаешь на вату.\"}, {\"original\": \"해변에서 배구를 하기 어때요?\", \"translated\": \"Как насчет игры в волейбол на пляже?\"}, {\"original\": \"멀리 있는 요트들이 아름다워 보여요.\", \"translated\": \"Яхты на расстоянии выглядят красиво.\"}, {\"original\": \"이 곳의 물이 매우 맑아서 물고기를 볼 수 있어요.\", \"translated\": \"Вода здесь такая чистая, что можно даже увидеть рыбок.\"}, {\"original\": \"시조를 찾아보자.\", \"translated\": \"Давай поищем ракушки.\"}, {\"original\": \"일몰 시간에 해변을 산책하는 건 매우 로맨틱할 거예요.\", \"translated\": \"Прогулка по пляжу на закате должна быть очень романтичной.\"}, {\"original\": \"여기 해산물이 매우 신선하다고 들었어요, 가서 먹어보자.\", \"translated\": \"Я слышал, морепродукты здесь очень свежие, давай попробуем.\"}, {\"translated\": \"Прилив подходит, давай двигаться к берегу.\"}]', 9, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"로컬 이벤트 및 축제에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋습니다! 로컬 이벤트 및 축제와 관련된 10가지 일반적인 표현과 함께 러시아어 번역을 제공합니다:\"]', '[\"이벤트 참석\", \"절기 축하하기\", \"문화 배우기\"]', 'ko', '[\"현재, 당신이 참석하는 로컬 이벤트 또는 축제의 맥락을 제공해 주세요. 예를 들어 할로윈, 콘서트, 친구 파티 또는 기타 사항이 있을 수 있습니다. 맥락을 제공해 주세요.\", \"당신이 생각하는 활동을 설명해 주세요.\"]', '[\"특정 상황이 마음에 있으신가요? 자유롭게 물어보세요.\", \"당신이 생각하는 상황을 설명해 주세요.\"]', '[{\"original\": \"오늘 이벤트가 있나요?\", \"translated\": \"Есть ли сегодня какие-нибудь события?\"}, {\"original\": \"이 축제에 특별한 점이 있나요?\", \"translated\": \"Что особенного в этом празднике?\"}, {\"original\": \"축제는 어디에서 열리나요?\", \"translated\": \"Где проходит праздник?\"}, {\"original\": \"티켓을 어떻게 구입할 수 있나요?\", \"translated\": \"Как я могу купить билеты?\"}, {\"original\": \"공연은 몇 시에 시작하나요?\", \"translated\": \"Во сколько начинается представление?\"}, {\"original\": \"전통 음식은 무엇인가요?\", \"translated\": \"Какие традиционные блюда есть?\"}, {\"original\": \"여기 정말 활기가 넘치네요.\", \"translated\": \"Здесь действительно оживленно.\"}, {\"original\": \"민속 활동이 있나요?\", \"translated\": \"Есть ли какие-нибудь народные мероприятия?\"}, {\"original\": \"행복한 명절 되세요!\", \"translated\": \"Счастливых праздников!\"}, {\"original\": \"이벤트는 몇 시에 끝나나요?\", \"translated\": \"Во сколько заканчивается мероприятие?\"}]', 10, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"박물관 또는 미술관에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 박물관 또는 미술관과 관련된 10가지 일반적인 문장과 러시아어 번역을 제공합니다:\"]', '[\"방문\", \"가이드 투어\", \"티켓 구매\"]', 'ko', '[\"지금은 특정 상황이 생각나시나요, 예를 들어 안내 매뉴얼 요청, 로드맵 관련 문장, 전시품에 대한 의견 관련 문장 등 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"Сколько стоит входной билет?\"}, {\"original\": \"오디오 가이드가 있나요?\", \"translated\": \"У вас есть аудиогиды?\"}, {\"original\": \"이 작품을 만든 사람은 누구인가요?\", \"translated\": \"Кто создал это произведение искусства?\"}, {\"original\": \"이 박물관에서 가장 소중한 작품은 어디에 있나요?\", \"translated\": \"Где находится самая ценная вещь в музее?\"}, {\"original\": \"사진 촬영이 가능한가요?\", \"translated\": \"Разрешено ли фотографирование?\"}, {\"original\": \"여기 특별 전시회가 있나요?\", \"translated\": \"Здесь есть какие-либо специальные выставки?\"}, {\"original\": \"방문에 얼마나 시간이 걸리나요?\", \"translated\": \"Сколько времени занимает посещение?\"}, {\"original\": \"우리에게 소개를 해주실 수 있나요?\", \"translated\": \"Можете ли вы дать нам введение?\"}, {\"original\": \"이 작품들은 정말 아름답습니다.\", \"translated\": \"Эти произведения действительно изысканные.\"}, {\"original\": \"기념품 가게는 어디에 있나요?\", \"translated\": \"Где находится магазин сувениров?\"}]', 11, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"카페에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주시겠어요?\", \"아주 좋습니다! 카페와 관련된 10가지 일반적인 표현과 함께 러시아어 번역이 있습니다：\"]', '[\"커피 주문\", \"휴식\", \"사회적 활동\"]', 'ko', '[\"지금은, 특정 상황을 생각하고 계신가요, 예를 들어 메뉴 요청, 아이스 또는 핫 음료, 기타 제품, 자유롭게 물어보세요.\", \"심중에 생각하고 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"제가 라테 하나 주세요.\", \"translated\": \"Я возьму латте, пожалуйста.\"}, {\"original\": \"와이파이 있으세요?\", \"translated\": \"У вас есть Wi-Fi?\"}, {\"original\": \"메뉴 좀 보여주세요.\", \"translated\": \"Могу я посмотреть меню, пожалуйста?\"}, {\"original\": \"리필 가능하세요?\", \"translated\": \"Разрешены ли подливы?\"}, {\"original\": \"제 커피 준비되었어요?\", \"translated\": \"Мой кофе готов?\"}, {\"original\": \"이곳에서 얼마나 오래 있을 수 있어요?\", \"translated\": \"Сколько времени я могу здесь сидеть?\"}, {\"original\": \"우리 사진 좀 찍어주실 수 있나요?\", \"translated\": \"Можете ли вы сделать для нас фото?\"}, {\"original\": \"화장실은 어디에요?\", \"translated\": \"Где туалет?\"}, {\"original\": \"계산해 주세요. 감사합니다.\", \"translated\": \"Счет, пожалуйста. Спасибо.\"}, {\"original\": \"정말 맛있어요.\", \"translated\": \"Оно действительно вкусное.\"}]', 12, 'ru');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"레스토랑에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 다음은 레스토랑과 관련된 10가지 일반적인 문장과 중국어 번역이 있습니다:\"]', '[\"식사\", \"주문\", \"결제\"]', 'ko', '[\"지금은 특정 상황을 생각하고 계신가요? 예를 들어 음료 주문, 불만 제기 또는 재료에 대한 문의 등 자유롭게 물어보세요.\", \"심중에 생각하고 계신 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"실례합니다, 음식은 얼마나 더 오래 걸릴까요?\", \"translated\": \"打扰一下，我们的食物还要等多久？\"}, {\"original\": \"이렇게 두 명을 위한 테이블을 부탁드립니다.\", \"translated\": \"请给我一张两人桌。\"}, {\"original\": \"메뉴를 보여주실 수 있나요?\", \"translated\": \"我们可以看一下菜单吗？\"}, {\"original\": \"추천할 만한 특산 dish가 있나요?\", \"translated\": \"你们有什么特色菜推荐吗？\"}, {\"original\": \"이것과 이것을 주문하고 싶어요.\", \"translated\": \"我想点这个和这个。\"}, {\"original\": \"물 한 잔 부탁드립니다. 감사합니다.\", \"translated\": \"请来一杯水。谢谢。\"}, {\"original\": \"계산서를 주세요.\", \"translated\": \"请结账。\"}, {\"original\": \"신용카드로 결제할 수 있나요?\", \"translated\": \"我可以用信用卡支付吗？\"}, {\"original\": \"이걸 포장해 주실 수 있나요?\", \"translated\": \"请把这份打包带走，可以吗？\"}, {\"original\": \"음식이 정말 맛있었어요. 감사합니다.\", \"translated\": \"食物很好吃，谢谢。\"}]', 1, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"호텔에서 사용할 수 있는 10가지 일반적인 문구를 제공해 주시겠습니까?\", \"좋습니다! 다음은 호텔과 관련된 10가지 일반적인 문구와 중국어 번역입니다:\"]', '[\"체크인\", \"체크아웃\", \"객실 서비스\"]', 'ko', '[\"현재, 방 위치, 다른 호텔 서비스 또는 체크아웃과 같은 구체적인 상황이 있으신가요? 자유롭게 물어보세요.\", \"마음에 드는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"안녕하세요, 예약이 있습니다, 여기 여권이 있습니다.\", \"translated\": \"你好，我有预订，这是我的护照。\"}, {\"original\": \"예약 가능한 객실이 있습니까?\", \"translated\": \"你们还有空房吗？\"}, {\"original\": \"실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\", \"translated\": \"打扰了，酒店有健身房或洗衣房吗？\"}, {\"original\": \"아침 식사가 몇 시부터 시작됩니까?\", \"translated\": \"早餐几点开始？\"}, {\"original\": \"방 키를 주시겠어요?\", \"translated\": \"可以给我一个房卡吗？\"}, {\"original\": \"짐을 방까지 가져다 도와주실 수 있나요?\", \"translated\": \"你能帮我把行李拿到房间吗？\"}, {\"original\": \"객실 서비스를 부르는 방법은 무엇입니까?\", \"translated\": \"我怎么叫客房服务？\"}, {\"original\": \"체크아웃 시간은 몇 시입니까?\", \"translated\": \"退房时间是几点？\"}, {\"original\": \"영수증/송장 작성해 주시겠어요?\", \"translated\": \"能给我开一张收据/发票吗？\"}, {\"original\": \"저기 짐을 잠시 두어도 될까요?\", \"translated\": \"我可以把行李放在这里吗？\"}]', 2, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공항에서 사용할 수 있는 10가지 일반적인 문구를 제공해 주실 수 있나요?\", \"좋아요! 공항과 관련된 10가지 일반적인 문구와 중국어 번역을 아래에 나열해 드립니다:\"]', '[\"체크인\", \"승실\", \"수하물 검사\"]', 'ko', '[\"지금은 특정 상황을 생각하고 계신가요? 예를 들어 체크인, 수하물 인수 또는 자동차 대여 서비스 등 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"체크인 카운터는 어디입니까?\", \"translated\": \"值机柜台在哪里？\"}, {\"original\": \"창가 자리가 있고 싶습니다.\", \"translated\": \"我想坐靠窗的座位。\"}, {\"original\": \"이 항공편은 지연되고 있습니까?\", \"translated\": \"这班航班延误了吗？\"}, {\"original\": \"이 수하물을 확인해야 합니다.\", \"translated\": \"我需要托运这个行李。\"}, {\"original\": \"승객 탑승 게이트는 어디입니까?\", \"translated\": \"登机口在哪里？\"}, {\"original\": \"비행기는 곧 이륙할 예정입니다.\", \"translated\": \"飞机即将起飞。\"}, {\"original\": \"노트북과 충전기(파워뱅크)를 꺼내야 하나요?\", \"translated\": \"我需要取出我的笔记本电脑和充电宝吗？\"}, {\"original\": \"관세 면세점은 어디입니까?\", \"translated\": \"免税店在哪里？\"}, {\"original\": \"내 수화물이 보이지 않습니다.\", \"translated\": \"我找不到我的行李箱。\"}, {\"original\": \"휠체어 서비스가 있습니까?\", \"translated\": \"你们有轮椅服务吗？\"}]', 3, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"대중교통에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 대중교통과 관련된 10가지 일반적인 문장과 중국어 번역을 제공합니다:\"]', '[\"버스/지하철 탑승\", \"티켓 구매\", \"환승\"]', 'ko', '[\"현재, 버스 정류장에 대한 문의, 티켓 가격, 하차 등 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"제가 생각하는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"이 버스는 종점으로 가나요?\", \"translated\": \"这辆公交车到终点站吗？\"}, {\"original\": \"다음 정류장은 어디예요?\", \"translated\": \"下一站是什么？\"}, {\"original\": \"티켓을 어디에서 살 수 있나요?\", \"translated\": \"在哪里可以买票？\"}, {\"original\": \"XX로 가는 티켓 하나 주세요.\", \"translated\": \"一张去XX的票，谢谢。\"}, {\"original\": \"전환해야 하나요?\", \"translated\": \"我需要换乘吗？\"}, {\"original\": \"다음 지하철이 몇 분 후에 오나요?\", \"translated\": \"下一班地铁多久能来？\"}, {\"original\": \"실례합니다, 지나가도 될까요?\", \"translated\": \"不好意思，请让我过去。\"}, {\"original\": \"이 자리는 이미 예약된 건가요?\", \"translated\": \"这个座位有人吗？\"}, {\"original\": \"실례합니다, XX로 가기 위해 2호선으로 어떻게 갈아타나요?\", \"translated\": \"不好意思，我怎么换乘到2号线去XX？\"}, {\"original\": \"XX에 어떻게 가면 되나요?\", \"translated\": \"我怎么去XX？\"}]', 4, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"여가 시설에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 관광 명소와 관련된 10가지 일반적인 문장과 중국어 번역을 제공합니다:\"]', '[\"관광하기\", \"사진 찍기\", \"티켓 구매하기\"]', 'ko', '[\"현재, 구체적인 상황이 있으신가요? 예를 들어 티켓 가격에 대해 묻거나 주차장 찾기, 투어 가이드 서비스 등 자유롭게 물어보세요.\", \"제 마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"门票多少钱？\"}, {\"original\": \"학생 할인 티켓이 있나요?\", \"translated\": \"有学生票吗？\"}, {\"original\": \"이 관광지가 언제 개장하나요?\", \"translated\": \"景点几点开门？\"}, {\"original\": \"여기서 할 수 있는 재미있는 활동은 무엇인가요?\", \"translated\": \"这里有什么好玩的？\"}, {\"original\": \"우리 사진을 찍어 줄 수 있나요?\", \"translated\": \"能给我们拍张照片吗？\"}, {\"original\": \"관광버스는 어디에 있나요?\", \"translated\": \"观光巴士在哪里？\"}, {\"original\": \"화장실은 어디에 있나요?\", \"translated\": \"洗手间在哪里？\"}, {\"original\": \"가장 좋은 전망지는 어디인가요?\", \"translated\": \"最佳观景点在哪里？\"}, {\"original\": \"여기 경치가 아름답네요.\", \"translated\": \"这里的风景很美。\"}, {\"original\": \"가이드 투어가 있나요?\", \"translated\": \"有导游讲解吗？\"}]', 5, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"택시나 택시 서비스에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있습니까?\", \"좋아요! 택시나 택시 서비스와 관련된 10개의 일반적인 문장과 중국어 번역을 아래에 나열합니다:\"]', '[\"택시 타기\", \"목적지 말하기\", \"결제\"]', 'ko', '[\"지금, 목적지 요청, 요금 묻기, 영수증 요청 등 하고 싶은 것을 자유롭게 물어보세요.\", \"상황을 마음속에서 설명해 주세요.\"]', NULL, '[{\"original\": \"택시를 어디서 탈 수 있나요?\", \"translated\": \"我哪里能打车？\"}, {\"original\": \"이 주소로 저를 데려가 주세요.\", \"translated\": \"请带我到这个地址。\"}, {\"original\": \"얼마 정도 될까요?\", \"translated\": \"大概多少钱？\"}, {\"original\": \"계기표를 사용해 주시겠어요?\", \"translated\": \"请问可以使用计价器吗？\"}, {\"original\": \"조금 더 빨리 운전해 주실 수 있나요? 저는 급한 일이 있어요.\", \"translated\": \"请开快一点，我赶时间。\"}, {\"original\": \"여기에서 멈춰 주세요.\", \"translated\": \"请在这里停一下。\"}, {\"original\": \"카드나 모바일 결제를 받으세요?\", \"translated\": \"你们接受刷卡还是手机支付吗？\"}, {\"original\": \"영수증을 한 장 주실 수 있나요?\", \"translated\": \"请问可以给我一张发票吗？\"}, {\"original\": \"감사합니다, 운전자님.\", \"translated\": \"谢谢，司机。\"}, {\"original\": \"이곳에서 얼마나 더 가야 하나요?\", \"translated\": \"还有多远？\"}]', 6, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"약국에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 약국과 관련된 10가지 일반적인 표현과 중국어 번역을 드립니다:\"]', '[\"약 구매\", \"상담\", \"결제\"]', 'ko', '[\"현재까지, 약을 복용하는 방법에 대해 묻는 것, 보험 관련 표현, 약물의 기간, 자유롭게 질문하세요.\", \"심리적으로 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"감기 약이 있습니까?\", \"translated\": \"你有感冒药吗？\"}, {\"original\": \"이 약은 어떻게 복용해야 하나요?\", \"translated\": \"我应该怎么服用这种药？\"}, {\"original\": \"진통제가 있습니까?\", \"translated\": \"你有止痛药吗？\"}, {\"original\": \"사용 설명서가 있습니까?\", \"translated\": \"有没有使用说明书？\"}, {\"original\": \"이 약에는 부작용이 있습니까?\", \"translated\": \"这种药有什么副作用吗？\"}, {\"original\": \"내 의료 보험 카드를 사용할 수 있습니까?\", \"translated\": \"我可以使用我的医保卡吗？\"}, {\"original\": \"붕대 상자 하나 주실 수 있나요?\", \"translated\": \"请给我一盒创可贴好吗？\"}, {\"original\": \"발열 완화제가 있습니까?\", \"translated\": \"你们有退烧药吗？\"}, {\"original\": \"조금 베인 것 같아요. 소독약과 붕대가 있습니까?\", \"translated\": \"我有点擦伤，你们有消毒药水和创可贴吗？\"}, {\"original\": \"언제 문을 닫으십니까?\", \"translated\": \"你们几点关门？\"}]', 7, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"응급 서비스에서 사용할 수 있는 10가지 일반적인 문구를 제공해 주시겠습니까?\", \"좋습니다! 응급 서비스와 관련된 10가지 일반적인 문구와 중국어 번역을 드립니다:\"]', '[\"경찰 호출\", \"응급 처치\", \"도움 요청\"]', 'ko', '[\"현재, 특정한 응급 상황이 있으신가요? 예를 들어 화재, 부상 및 도움이 필요한 경우, 응급 전화 등 자유롭게 물어보세요.\", \"심중의 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"응급차를 불러줘.\", \"translated\": \"请帮我叫救护车。\"}, {\"original\": \"병원은 어디에요?\", \"translated\": \"医院在哪里？\"}, {\"original\": \"누군가 부상당했어요.\", \"translated\": \"有人受伤了。\"}, {\"original\": \"도와주세요.\", \"translated\": \"请帮助我。\"}, {\"original\": \"경찰서는 어디에요?\", \"translated\": \"警察局在哪里？\"}, {\"original\": \"내 소지품을 잃어버렸어요.\", \"translated\": \"我的物品丢了。\"}, {\"original\": \"소방서 전화번호는 무엇인가요?\", \"translated\": \"消防部门的电话号码是多少？\"}, {\"original\": \"여권을 잃어버렸어요. 가장 가까운 경찰서는 어디인가요?\", \"translated\": \"我的护照丢了。你知道最近的警察局在哪里吗？\"}, {\"original\": \"비상구는 어디에요?\", \"translated\": \"有紧急出口吗？\"}, {\"original\": \"누군가 쓰러졌어요.\", \"translated\": \"有人晕倒了。\"}]', 8, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"비치 또는 수영장가에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주시겠어요?\", \"좋습니다! 비치 또는 수영장가와 관련된 10개의 일반적인 문장과 중국어 번역을 제공합니다:\"]', '[\"수영\", \"태양광 쬐기\", \"해변 스포츠\"]', 'ko', '[\"현재까지, 참석하는 지역 이벤트나 축제의 맥락을 제공해 주시겠어요? 예를 들어 문화 축제, 음식 축제 또는 음악 축제 등입니다. 맥락을 제공해 주세요.\", \"참석하는 활동을 알려주세요.\"]', '[\"특정 상황이 머릿속에 있는지 여부를 확인해 주세요. 자유롭게 물어보세요.\", \"머릿속에 있는 상황을 설명해 주세요.\"]', '[{\"original\": \"보라! 저쪽 파도가 정말 크다.\", \"translated\": \"看！那边的海浪真的很大。\"}, {\"original\": \"자외선 차단제를 바르세요, 여기 자외선은 매우 강합니다.\", \"translated\": \"记得涂防晒霜，这里的紫外线很强。\"}, {\"original\": \"이 해변의 모래는 매우 미세해서 마치 면처럼 밟히는 느낌이다.\", \"translated\": \"这个海滩的沙子非常细，感觉像是踩在棉花上。\"}, {\"original\": \"해변에서 배구를 해볼까?\", \"translated\": \"在沙滩上打排球怎么样？\"}, {\"original\": \"멀리 있는 요트들이 아름답게 보인다.\", \"translated\": \"远处的帆船看起来很美丽。\"}, {\"original\": \"여기 물이 매우 맑아서 물고기를 볼 수 있다.\", \"translated\": \"这里的水非常清澈，甚至可以看到鱼。\"}, {\"original\": \"시조를 찾아보자.\", \"translated\": \"我们去捡一些贝壳吧。\"}, {\"original\": \"일몰 때 해변을 산책하는 것은 매우 로맨틱할 것이다.\", \"translated\": \"在日落时分沿着海滩散步一定很浪漫。\"}, {\"original\": \"여기 해산물이 매우 신선하다고 들었으니, 가서 먹어보자.\", \"translated\": \"我听说这里的海鲜非常新鲜，我们去尝一些吧。\"}, {\"original\": \"조수는 들어오고 있으니, 해안으로 향하자.\", \"translated\": \"潮水正在涨起来，我们往岸边走吧。\"}]', 9, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"로컬 이벤트 및 축제에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋아요! 로컬 이벤트 및 축제와 관련된 10가지 일반적인 표현과 중국어 번역을 드립니다:\"]', '[\"이벤트 참석\", \"절기 축하\", \"문화 배우기\"]', 'ko', '[\"현재, 당신이 참석하는 로컬 이벤트 또는 축제의 맥락을 제공해 주세요. 예를 들어 할로윈, 콘서트, 친구 파티 또는 기타 사항입니다. 맥락을 제공해 주세요.\", \"당신이 생각하는 활동을 설명해 주세요.\"]', '[\"자유롭게 묻고 싶은 특정 상황이 있으신가요?\", \"당신이 생각하는 상황을 설명해 주세요.\"]', '[{\"original\": \"오늘 이벤트가 있나요?\", \"translated\": \"今天有什么活动吗？\"}, {\"original\": \"이 축제에 특별한 점이 있나요?\", \"translated\": \"这个节日有什么特别之处吗？\"}, {\"original\": \"축제는 어디에서 열리나요?\", \"translated\": \"庆祝活动在哪里举行？\"}, {\"original\": \"티켓을 어떻게 구할 수 있나요?\", \"translated\": \"我怎么买票？\"}, {\"original\": \"공연은 몇 시에 시작하나요?\", \"translated\": \"演出什么时候开始？\"}, {\"original\": \"이곳에 어떤 전통 음식이 있나요?\", \"translated\": \"有什么传统食物？\"}, {\"original\": \"여기 정말 분위기가 좋네요.\", \"translated\": \"这里真的很热闹。\"}, {\"original\": \"민속 활동이 있나요?\", \"translated\": \"有什么民间活动吗？\"}, {\"original\": \"명절 축하합니다!\", \"translated\": \"节日快乐！\"}, {\"original\": \"이벤트는 몇 시에 끝나나요?\", \"translated\": \"活动什么时候结束？\"}]', 10, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"박물관 또는 미술관에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠어요?\", \"좋았어요! 박물관 또는 미술관과 관련된 10가지 일반적인 문장과 중국어 번역을 아래에 나열해 드립니다:\"]', '[\"방문\", \"가이드 투어\", \"티켓 구매\"]', 'ko', '[\"지금은 특정 상황이 생각나시는지, 예를 들어 안내서 요청, 로드맵 관련 문장, 전시품에 대한 의견 표현과 관련된 문장 등 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"入场费是多少？\"}, {\"original\": \"음성 안내 서비스가 있나요?\", \"translated\": \"你们有语音导览吗？\"}, {\"original\": \"이 작품을 만든 사람은 누구인가요?\", \"translated\": \"这幅艺术品是谁创作的？\"}, {\"original\": \"이 박물관에서 가장 소중한 작품은 어디에 있나요?\", \"translated\": \"博物馆最珍贵的作品在哪里？\"}, {\"original\": \"사진 촬영이 가능한가요?\", \"translated\": \"允许拍照吗？\"}, {\"original\": \"여기 특별 전시회가 있나요?\", \"translated\": \"这里有什么特别展览吗？\"}, {\"original\": \"방문에 얼마나 시간이 걸리나요?\", \"translated\": \"参观需要多长时间？\"}, {\"original\": \"우리에게 간단한 소개를 해주실 수 있나요?\", \"translated\": \"你能给我们做个介绍吗？\"}, {\"original\": \"이 작품들은 정말 아름답습니다.\", \"translated\": \"这些作品真是精美。\"}, {\"original\": \"기념품 가게는 어디에 있나요?\", \"translated\": \"纪念品商店在哪里？\"}]', 11, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"카페에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 카페와 관련된 10가지 일반적인 문장과 중국어 번역을 제공합니다:\"]', '[\"커피 주문\", \"휴식\", \"사회적 활동\"]', 'ko', '[\"현재, 메뉴를 요청하거나, 얼음 또는 뜨거운 음료, 기타 제품에 대한 질문 등 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"심리적으로 생각하고 계신 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"제가 라테 한 잔 주세요.\", \"translated\": \"请给我一杯拿铁。\"}, {\"original\": \"와이파이 있으세요?\", \"translated\": \"你们有Wi-Fi吗？\"}, {\"original\": \"메뉴 좀 보여주세요.\", \"translated\": \"可以看一下菜单吗？\"}, {\"original\": \"리필 가능합니까?\", \"translated\": \"可以续杯吗？\"}, {\"original\": \"제 커피 준비되었나요?\", \"translated\": \"我的咖啡好了吗？\"}, {\"original\": \"이곳에서 얼마나 오래 있을 수 있나요?\", \"translated\": \"我可以坐在这里多久？\"}, {\"original\": \"우리 사진 좀 찍어 주시겠어요?\", \"translated\": \"能给我们拍张照片吗？\"}, {\"original\": \"화장실은 어디에 있나요?\", \"translated\": \"洗手间在哪里？\"}, {\"original\": \"계산해 주세요. 감사합니다.\", \"translated\": \"请结账。谢谢。\"}, {\"original\": \"정말 맛있어요.\", \"translated\": \"味道真的很好。\"}]', 12, 'zh');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"저에게 식당에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 식당과 관련된 10가지 일반적인 문장과 터키어 번역을 드립니다:\"]', '[\"식사\", \"주문\", \"결제\"]', 'ko', '[\"지금은, 음료 주문, 불만 제기 또는 성분에 대한 문의와 같은 특정 상황을 고려하고 계신가요? 자유롭게 물어보세요.\", \"심중한 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"실례합니다, 음식은 얼마나 더 오래 걸릴까요?\", \"translated\": \"Özür dilerim, yemeklerimiz ne kadar daha uzun süre sürecektir?\"}, {\"original\": \"두 분을 위한 테이블을 부탁드립니다.\", \"translated\": \"Lütfen iki kişilik bir masa.\"}, {\"original\": \"메뉴를 보여주실 수 있겠어요?\", \"translated\": \"Lütfen menüyü görebilir miyiz?\"}, {\"original\": \"추천할 만한 특별 요리가 있나요?\", \"translated\": \"Önermek için özel yemekleriniz var mı?\"}, {\"original\": \"이것과 이것을 주문하고 싶어요.\", \"translated\": \"Bunu ve bunu sipariş etmek istiyorum.\"}, {\"original\": \"물 한 잔 부탁드려요. 감사합니다.\", \"translated\": \"Lütfen bir bardak su. Teşekkür ederim.\"}, {\"original\": \"계산서 좀 주세요.\", \"translated\": \"Hesap, lütfen.\"}, {\"original\": \"신용카드로 결제할 수 있나요?\", \"translated\": \"Kredi kartıyla ödemek isteyebilir miyim?\"}, {\"original\": \"이걸 포장해 주실 수 있나요?\", \"translated\": \"Lütfen alıp götürmek için paketleyin.\"}, {\"original\": \"음식이 정말 맛있었어요. 감사합니다.\", \"translated\": \"Yemekler harika, teşekkür ederim.\"}]', 1, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"호텔에서 사용할 수 있는 10가지 일반적인 문구를 제공해 주시겠습니까?\", \"좋습니다! 호텔과 관련된 10가지 일반적인 문구와 터키어 번역을 제공합니다:\"]', '[\"체크인\", \"체크아웃\", \"객실 서비스\"]', 'ko', '[\"현재, 방 위치, 다른 호텔 서비스 또는 체크아웃과 같은 구체적인 상황이 있으신가요? 자유롭게 물어보세요.\", \"심상에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"안녕하세요, 예약이 있습니다, 여권을 드립니다.\", \"translated\": \"Merhaba, rezervasyonum var, pasaportum burada.\"}, {\"original\": \"예약 가능한 객실이 있습니까?\", \"translated\": \"Boş bir oda var mı?\"}, {\"original\": \"실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\", \"translated\": \"İsmar, otelde bir kahve makinesi veya çamaşırhane var mı?\"}, {\"original\": \"아침 식사가 몇 시부터 시작합니까?\", \"translated\": \"Kahvaltı ne zaman başlıyor?\"}, {\"original\": \"방 키를 주시겠습니까?\", \"translated\": \"Lütfen bir oda anahtarı verin.\"}, {\"original\": \"짐을 방까지 가져다 도와주실 수 있습니까?\", \"translated\": \"Odama bagajımı taşımamı yardımcı olabilir misiniz?\"}, {\"original\": \"객실 서비스를 부르는 방법은 무엇입니까?\", \"translated\": \"Oda hizmetini nasıl çağırabilirim?\"}, {\"original\": \"체크아웃 시간은 언제입니까?\", \"translated\": \"Check-out saat kaç?\"}, {\"original\": \"영수증/송금 영수증을 만들어 주시겠습니까?\", \"translated\": \"Bana bir fatura/kesim yazabilir misiniz?\"}, {\"original\": \"짐을 여기에 두어도 괜찮습니까?\", \"translated\": \"Bagajımı burada bırakabilirim mi?\"}]', 2, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공항에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋습니다! 공항과 관련된 10가지 일반적인 표현과 터키어 번역이 있습니다:\"]', '[\"체크인\", \"승객 탑승\", \"수화물 수령\"]', 'ko', '[\"현재, 체크인, 수하물 수령, 차량 대여 서비스와 같은 특정 상황이 있으신가요? 자유롭게 문의해 주세요.\", \"제가 생각하는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"체크인 카운터는 어디입니까?\", \"translated\": \"Check-in korsesi nerede?\"}, {\"original\": \"창가 자리가 있고 싶습니다.\", \"translated\": \"Lütfen bir pencere koltuğu istiyorum.\"}, {\"original\": \"이 항공편은 지연되고 있습니까?\", \"translated\": \"Bu seyahat ertelendi mi?\"}, {\"original\": \"이 수하물을 확인해야 합니다.\", \"translated\": \"Bu bagajı kontrol etmem gerekiyor.\"}, {\"original\": \"승객 탑승 게이트는 어디입니까?\", \"translated\": \"Yolculuk kapısı nerede?\"}, {\"original\": \"비행기가 바로 이륙할 예정입니다.\", \"translated\": \"Uçak kalkış yapmaya hazır.\"}, {\"original\": \"노트북과 전자파워뱅크를 꺼내야 합니까?\", \"translated\": \"Laptop ve güç bankamı çıkarmam gerekmiyor mu?\"}, {\"original\": \"관세 면세점은 어디입니까?\", \"translated\": \"Dutisiz mağaza nerede?\"}, {\"original\": \"내 수하가 보이지 않습니다.\", \"translated\": \"Suitcumu bulamıyorum.\"}, {\"original\": \"휠체어 서비스를 제공합니까?\", \"translated\": \"Kasayla servisiniz var mı?\"}]', 3, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"대중교통에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 대중교통과 관련된 10가지 일반적인 문장과 터키어 번역을 제공합니다:\"]', '[\"버스/지하철 탑승\", \"티켓 구매\", \"환승\"]', 'ko', '[\"지금은 특정 상황이 생각나시는지요, 예를 들어 버스 정류장 묻기, 티켓 가격, 내리기 등 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"이 버스는 종점으로 가나요?\", \"translated\": \"Bu otobüs terminal\'e gider mi?\"}, {\"original\": \"다음 정류장은 어디인가요?\", \"translated\": \"Bir sonraki durak neredir?\"}, {\"original\": \"티켓을 어디에서 살 수 있나요?\", \"translated\": \"Bilet nereden alınır?\"}, {\"original\": \"XX로 가는 티켓 하나 주세요.\", \"translated\": \"Lütfen bir bilet istiyorum XX için.\"}, {\"original\": \"환승해야 하나요?\", \"translated\": \"Aktarmaya ihtiyacım var mı?\"}, {\"original\": \"다음 지하철은 얼마나 걸리나요?\", \"translated\": \"Bir sonraki metro treni ne kadar sürede gelir?\"}, {\"original\": \"실례합니다, 지나가도 될까요?\", \"translated\": \"İzin verin, geçebilir miyim?\"}, {\"original\": \"이 자리에 누가 앉았나요?\", \"translated\": \"Bu koltuk boş mu?\"}, {\"original\": \"실례합니다, XX로 가려면 2호선으로 어디에서 환승하면 되나요?\", \"translated\": \"İzin verin, XX\'e gitmek için 2. Hat\'a nasıl aktarabilirim?\"}, {\"original\": \"XX에 어떻게 가나요?\", \"translated\": \"XX\'e nasıl gidebilirim?\"}]', 4, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"관광지에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋습니다! 관광지와 관련된 10가지 일반적인 표현과 터키어 번역을 아래에 나열합니다:\"]', '[\"관광하기\", \"사진 찍기\", \"티켓 구매\"]', 'ko', '[\"현재, 특정 상황이 있으신가요? 예를 들어, 티켓 가격 문의, 주차장 찾기, 또는 투어 가이드 서비스 등 자유롭게 물어보세요.\", \"제가 생각하는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"Giriş ücreti ne kadar?\"}, {\"original\": \"학생 할인 티켓이 있나요?\", \"translated\": \"Öğrenci biletleri mevcut mu?\"}, {\"original\": \"이 관광지가 몇 시에 열어요?\", \"translated\": \"Etkinlik saat kaçta açılıyor?\"}, {\"original\": \"여기서 할 수 있는 재미있는 활동은 무엇인가요?\", \"translated\": \"Burada eğlenceli şeyler neler?\"}, {\"original\": \"우리 사진을 찍어 줄 수 있나요?\", \"translated\": \"Bize bir fotoğraf çekebilir misiniz?\"}, {\"original\": \"관광버스는 어디에 있나요?\", \"translated\": \"Sightseeing otobüsü nerede?\"}, {\"original\": \"화장실은 어디에 있나요?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"가장 좋은 전망지는 어디인가요?\", \"translated\": \"En iyi gözleme noktası nerede?\"}, {\"original\": \"여기 경치가 아름다워요.\", \"translated\": \"Buradaki manzara güzel.\"}, {\"original\": \"가이드 투어가 있나요?\", \"translated\": \"Yönlendirilmiş tur mevcut mu?\"}]', 5, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"택시 또는 택시 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있습니까?\", \"좋아요! 택시 또는 택시 서비스와 관련된 10가지 일반적인 문장과 터키어 번역을 드립니다:\"]', '[\"택시 타기\", \"목적지 말하기\", \"결제\"]', 'ko', '[\"지금, 현재 하고 싶은 일, 목적지 요청, 요금 묻기, 영수증 요청 등 자유롭게 물어보세요.\", \"마음속에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"택시를 어디서 탈 수 있나요?\", \"translated\": \"Bir taksimetre nerede alabilirim?\"}, {\"original\": \"이 주소로 저를 데려가 주세요.\", \"translated\": \"Bu adrese bana götürür müsünüz?\"}, {\"original\": \"大概 얼마나 비쌀까요?\", \"translated\": \"Yaklaşık olarak ne kadar olur?\"}, {\"original\": \"제발 계기장 사용해 주세요.\", \"translated\": \"Lütfen sayaç kullanabilir misiniz?\"}, {\"original\": \"제가 서둘러야 해서 조금 더 빠르게 운전해 주세요.\", \"translated\": \"Hızlı sürer misiniz, acelem var.\"}, {\"original\": \"여기에서 멈춰 주세요.\", \"translated\": \"Burada durun lütfen.\"}, {\"original\": \"카드나 모바일 결제를 받으세요?\", \"translated\": \"Kart mı yoksa mobil ödeme mi kabul edersiniz?\"}, {\"original\": \"영수증 좀 주세요.\", \"translated\": \"Lütfen fatura istiyorum.\"}, {\"original\": \"감사합니다, 기사님.\", \"translated\": \"Teşekkür ederim şöfor.\"}, {\"original\": \"얼마나 더 가야 하나요?\", \"translated\": \"Kaç km daha var?\"}]', 6, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"약국에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 약국과 관련된 10가지 일반적인 문장과 터키어 번역을 드립니다:\"]', '[\"약 구입\", \"상담\", \"결제\"]', 'ko', '[\"지금은, 약물 복용 방법에 대한 지시를 묻는 것처럼 구체적인 상황이 있습니까? 보험 관련 문장, 약물 복용 기간, 자유롭게 물어보세요.\", \"심리적으로 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"감기약이 있습니까?\", \"translated\": \"Soğuk ilaçınız var mı?\"}, {\"original\": \"이 약은 어떻게 복용해야 하나요?\", \"translated\": \"Bu ilacı nasıl kullanmam gerekir?\"}, {\"original\": \"진통제가 있습니까?\", \"translated\": \"Ateş düşürücünüz var mı?\"}, {\"original\": \"사용 설명서가 있습니까?\", \"translated\": \"Kılavuz kitapçığınız var mı?\"}, {\"original\": \"이 약에 부작용이 있습니까?\", \"translated\": \"Bu ilacın yan etkileri var mı?\"}, {\"original\": \"내 의료 보험 카드를 사용할 수 있나요?\", \"translated\": \"Tıbbi sigorta kartımı kullanabilirim mi?\"}, {\"original\": \"붕대 상자 하나 주실 수 있나요?\", \"translated\": \"Lütfen bir kutu bandaj istiyorum.\"}, {\"original\": \"발열 완화제가 있습니까?\", \"translated\": \"Ateş düşürücü var mı?\"}, {\"original\": \"조금 다쳤어요. 소독제와 붕대가 있습니까?\", \"translated\": \"Biraz yara var. Antiseptik ve bandajınız var mı?\"}, {\"original\": \"언제 문을 닫으십니까?\", \"translated\": \"Saat kaçta kapanıyorsunuz?\"}]', 7, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"응급 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠어요?\", \"좋아요! 응급 서비스와 관련된 10가지 일반적인 문장과 터키어 번역을 드립니다:\"]', '[\"경찰 호출\", \"응급처치\", \"도움 요청\"]', 'ko', '[\"지금은, 당신이 마음에 떠올리는 구체적인 응급 상황이 있습니까? 예를 들어 화재, 부상 및 도움이 필요한 경우, 응급 전화, 자유롭게 물어보세요.\", \"마음에 떠올리는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"응급차를 불러줘.\", \"translated\": \"Lütfen bir ambulans çağırmamı yardım edin.\"}, {\"original\": \"병원은 어디예요?\", \"translated\": \"Hastane nerede?\"}, {\"original\": \"누군가 부상당했어요.\", \"translated\": \"Biri yaralandı.\"}, {\"original\": \"도와주세요.\", \"translated\": \"Lütfen bana yardım edin.\"}, {\"original\": \"경찰서는 어디예요?\", \"translated\": \"Polis istasyonu nerede?\"}, {\"original\": \"내 소지품을 잃어버렸어요.\", \"translated\": \"Eşyamı kaybettim.\"}, {\"original\": \"소방서 전화번호는 무엇인가요?\", \"translated\": \"Yangın ekiplerinin numarası nedir?\"}, {\"original\": \"여권을 잃어버렸어요. 가까운 경찰서는 어디인가요?\", \"translated\": \"Passamı kaybettim. Yakın polis istasyonu nerede biliyor musun?\"}, {\"original\": \"비상출구는 어디예요?\", \"translated\": \"Acil çıkış var mı?\"}, {\"original\": \"누군가 쓰러졌어요.\", \"translated\": \"Biri bayıldı.\"}]', 8, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"비치나 수영장가에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있나요?\", \"아주 좋습니다! 비치나 수영장가와 관련된 10개의 일반적인 문장과 터키어 번역을 제공합니다:\"]', '[\"수영\", \"태양광선 쬐기\", \"해변 스포츠\"]', 'ko', '[\"지금은, 참석하는 지역 이벤트나 축제의 맥락을 제공해 주세요. 예를 들어 문화 축제, 음식 축제 또는 음악 축제 등입니다. 맥락을 제공해 주세요.\", \"참석하는 활동을 알려주세요.\"]', '[\"특정한 상황이 마음에 드시나요? 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', '[{\"original\": \"보라, 저기 파도가 정말 크다.\", \"translated\": \"Bak! Orada ki dalgalar gerçekten büyük.\"}, {\"original\": \"자외선 차단제를 바르세요, 여기 자외선이 매우 강합니다.\", \"translated\": \"Güneş kremi sürmeyi unutma, buradaki UV ışınları çok güçlü.\"}, {\"original\": \"이 해변의 모래는 매우 미끄럽고, 마치 쿠션에 발을 디딘 것처럼 느껴집니다.\", \"translated\": \"Bu sahildeki kum çok ince, yün gibi hisseder gibi oluyor.\"}, {\"original\": \"해변에서 배구를 하면 어때요?\", \"translated\": \"Plajda voleybol oynamaya ne dersin?\"}, {\"original\": \"멀리 있는 요트들이 아름답게 보입니다.\", \"translated\": \"Uzaktaki yelkenliler çok güzel görünüyor.\"}, {\"original\": \"이 곳의 물이 매우 맑아서 물고기를 볼 수 있습니다.\", \"translated\": \"Buradaki su çok berrak, balıkları bile görebilirsin.\"}, {\"original\": \"시조를 찾아볼까요?\", \"translated\": \"Deniz kabuklarını bulmaya gidelim.\"}, {\"original\": \"일몰 때 해변을 산책하는 것은 매우 로맨틱할 것입니다.\", \"translated\": \"Akşam saatlerinde plajda yürüyüş yapmak çok romantik olurdu.\"}, {\"original\": \"여기 해산물이 매우 신선하다고 들었어요, 가서 먹어보죠.\", \"translated\": \"Buradaki deniz ürünleri çok taze, denemek için gidelim.\"}, {\"original\": \"조수 갈라지는 중이에요, 해안으로 가야겠어요.\", \"translated\": \"Dalgalar gelmeye başlıyor, kıyıya doğru gidelim.\"}]', 9, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"로컬 이벤트 및 축제에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋아요! 로컬 이벤트 및 축제와 관련된 10가지 일반적인 표현과 터키어 번역을 제공합니다:\"]', '[\"이벤트 참석\", \"절기 축하\", \"문화 배우기\"]', 'ko', '[\"현재, 당신이 참석하는 로컬 이벤트 또는 축제의 맥락을 제공해 주시겠어요? 예를 들어 할로윈, 콘서트, 친구 파티, 또는 기타 사항이 있나요? 맥락을 제공해 주세요.\", \"당신이 생각하는 활동을 설명해 주세요.\"]', '[\"특정 상황이 마음에 있으신가요? 자유롭게 물어보세요.\", \"당신이 생각하는 상황을 설명해 주세요.\"]', '[{\"original\": \"오늘 이벤트가 있나요?\", \"translated\": \"Bugün etkinlik var mı?\"}, {\"original\": \"이 축제에 특별한 점이 있나요?\", \"translated\": \"Bu festivalin özel bir yanı var mı?\"}, {\"original\": \"축제는 어디에서 열리나요?\", \"translated\": \"Kutlamalar nerede yapılacak?\"}, {\"original\": \"티켓을 어떻게 구입할 수 있나요?\", \"translated\": \"Bilet almak için ne yapabilirim?\"}, {\"original\": \"공연은 몇 시에 시작하나요?\", \"translated\": \"Performans saat kaçta başlayacak?\"}, {\"original\": \"이곳에 어떤 전통 음식이 있나요?\", \"translated\": \"Burada hangi geleneksel yiyecekler var?\"}, {\"original\": \"여기 정말 활기가 넘치네요.\", \"translated\": \"Burada gerçekten canlı bir atmosfer var.\"}, {\"original\": \"민속 활동이 있나요?\", \"translated\": \"Burada halk aktiviteleri var mı?\"}, {\"original\": \"명절 축하합니다!\", \"translated\": \"İyi tatiller!\"}, {\"original\": \"이벤트는 몇 시에 끝나나요?\", \"translated\": \"Etkinlik saat kaçta biter?\"}]', 10, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"박물관 또는 미술관에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 박물관 또는 미술관과 관련된 10가지 일반적인 문장과 터키어 번역을 드립니다:\"]', '[\"방문\", \"가이드 투어\", \"티켓 구매\"]', 'ko', '[\"현재, 소개 매뉴얼을 요청하거나 로드맵과 관련된 문장, 전시물에 대한 의견을 표현하는 문장과 같은 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"여러분이 생각하고 계신 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"Giriş ücreti ne kadardır?\"}, {\"original\": \"음성 안내 서비스가 있나요?\", \"translated\": \"Sesli rehberiniz var mı?\"}, {\"original\": \"이 작품을 만든 사람은 누구인가요?\", \"translated\": \"Bu eseri kim yaratmıştır?\"}, {\"original\": \"이 박물관에서 가장 소중한 작품은 어디에 있나요?\", \"translated\": \"Müzenin en değerli parçası nerededir?\"}, {\"original\": \"사진 촬영이 가능한가요?\", \"translated\": \"Fotoğraf çekmek izin veriliyor mu?\"}, {\"original\": \"여기 특별 전시회가 있나요?\", \"translated\": \"Burada özel sergiler mi var?\"}, {\"original\": \"방문하는 데 얼마나 걸리나요?\", \"translated\": \"Ziyaret ne kadar sürer?\"}, {\"original\": \"우리에게 소개를 해주실 수 있나요?\", \"translated\": \"Bize bir girişimde bulunabilir misiniz?\"}, {\"original\": \"이 작품들은 정말 아름답습니다.\", \"translated\": \"Bu eserler gerçekten harika.\"}, {\"original\": \"기념품 가게는 어디에 있나요?\", \"translated\": \"Hediyelik eşya mağazası nerede?\"}]', 11, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"카페에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 카페와 관련된 10가지 일반적인 문장과 터키어 번역을 아래에 소개합니다:\"]', '[\"커피 주문\", \"휴식\", \"사회적 상호작용\"]', 'ko', '[\"현재까지, 특정 상황이 있으신가요? 예를 들어 메뉴 요청, 아이스 또는 핫 음료, 기타 제품, 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"제가 라테 하나 주세요.\", \"translated\": \"Lütfen bir latte istiyorum.\"}, {\"original\": \"와이파이 있으세요?\", \"translated\": \"Wi-Fi var mı?\"}, {\"original\": \"메뉴 좀 보여주세요.\", \"translated\": \"Lütfen menüyü gösterebilir misiniz?\"}, {\"original\": \"리필 가능하세요?\", \"translated\": \"Yeniden doldurma izin veriliyor mu?\"}, {\"original\": \"제 커피 준비되었어요?\", \"translated\": \"Kahvem hazır mı?\"}, {\"original\": \"이곳에서 얼마나 오래 있을 수 있나요?\", \"translated\": \"Burada ne kadar kalmamıza izin var?\"}, {\"original\": \"우리 사진 좀 찍어주실 수 있나요?\", \"translated\": \"Bize bir fotoğraf çekebilir misiniz?\"}, {\"original\": \"화장실은 어디에요?\", \"translated\": \"Tuvalet nerede?\"}, {\"original\": \"계산해 주세요. 감사합니다.\", \"translated\": \"Hesap, lütfen. Teşekkür ederim.\"}, {\"original\": \"진짜 맛있어요.\", \"translated\": \"Çok iyi geliyor.\"}]', 12, 'tr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"레스토랑에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 레스토랑과 관련된 10가지 일반적인 문장과 일본어 번역을 드립니다:\"]', '[\"식사\", \"주문\", \"결제\"]', 'ko', '[\"지금은, 음료 주문, 불만 제기 또는 성분에 대한 문의와 같은 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"실례합니다, 음식은 얼마나 더 오래 걸리나요?\", \"translated\": \"すみません、お食事はあとどれくらいかかりますか？\"}, {\"original\": \"이용객 두 명을 위한 테이블을 부탁드립니다.\", \"translated\": \"2人用のテーブルをお願いします。\"}, {\"original\": \"메뉴를 보여주실 수 있겠어요?\", \"translated\": \"メニューよろしくお願いします。\"}, {\"original\": \"추천할 만한 특별한 요리가 있습니까?\", \"translated\": \"おすすめの特徴的な料理はありますか？\"}, {\"original\": \"이것과 이것을 주문하고 싶어요.\", \"translated\": \"これを注文したいです、それとこれも。\"}, {\"original\": \"물 한 잔 부탁드립니다. 감사합니다.\", \"translated\": \"水1杯お願いします。ありがとうございます。\"}, {\"original\": \"계산서를 주세요.\", \"translated\": \"お会計をお願いします。\"}, {\"original\": \"신용카드로 결제할 수 있나요?\", \"translated\": \"クレジットカードで支払えますか？\"}, {\"original\": \"이걸 포장해 주실 수 있나요?\", \"translated\": \"これは持ち帰りにできますか？\"}, {\"original\": \"음식이 정말 맛있었어요. 감사합니다.\", \"translated\": \"ご飯が美味しかったです、ありがとう。\"}]', 1, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"호텔에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주시겠습니까?\", \"좋습니다! 호텔과 관련된 10가지 일반적인 표현과 일본어 번역을 드립니다:\"]', '[\"체크인\", \"체크아웃\", \"객실 서비스\"]', 'ko', '[\"현재, 방 위치, 다른 호텔 서비스 또는 체크아웃과 같은 구체적인 상황이 있으신가요? 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"안녕하세요, 예약이 있습니다, 여권을 드릴게요.\", \"translated\": \"こんにちは、予約があります。パスポートをお見せします。\"}, {\"original\": \"예약 가능한 객실이 있습니까?\", \"translated\": \"空室はありますか？\"}, {\"original\": \"실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\", \"translated\": \"すみません、ホテルにジムや洗濯ルームはありますか？\"}, {\"original\": \"아침 식사가 몇 시부터 시작됩니까?\", \"translated\": \"朝食はいつからですか？\"}, {\"original\": \"방 키를 주시겠어요?\", \"translated\": \"部屋の鍵をいただけますか？\"}, {\"original\": \"짐을 방으로 옮겨 주실 수 있겠어요?\", \"translated\": \"荷物を部屋まで運んでいただけますか？\"}, {\"original\": \"객실 서비스를 부르는 방법은 무엇입니까?\", \"translated\": \"ルームサービスを呼びたいのですが。\"}, {\"original\": \"체크아웃 시간은 몇 시입니까?\", \"translated\": \"チェックアウトは何時ですか？\"}, {\"original\": \"영수증/송금 영수증을 작성해 주시겠어요?\", \"translated\": \"領収書や請求書を書いていただけますか？\"}, {\"original\": \"짐을 여기 두고 가도 되나요?\", \"translated\": \"荷物をここに置いていってもいいですか？\"}]', 2, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공항에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 공항과 관련된 10가지 일반적인 문장과 일본어 번역을 아래에 나열합니다:\"]', '[\"체크인\", \"탑승\", \"수하물 검사\"]', 'ko', '[\"현재, 체크인, 수하물 수령, 자동차 대여 서비스와 같은 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"제가 생각하는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"체크인 카운터는 어디입니까?\", \"translated\": \"チェックインカウンターはどこですか？\"}, {\"original\": \"창가 자리가 있고 싶어요.\", \"translated\": \"窓側の座席を希望します。\"}, {\"original\": \"이 항공편이 지연되었나요?\", \"translated\": \"このフライトは遅延していますか？\"}, {\"original\": \"이 수하물을 확인해야 합니다.\", \"translated\": \"この荷物をチェックしたいです。\"}, {\"original\": \"승객 탑승 게이트는 어디입니까?\", \"translated\": \"出発ゲートはどこですか？\"}, {\"original\": \"비행기가 바로 이륙할 예정입니다.\", \"translated\": \"飛行機は間もなく離陸します。\"}, {\"original\": \"노트북과 충전기(파워뱅크)를 꺼내야 하나요?\", \"translated\": \"ラップトップと充電器を取り出さなければなりませんか？\"}, {\"original\": \"면세점은 어디입니까?\", \"translated\": \"免税店はどこですか？\"}, {\"original\": \"내 수화물이 보이지 않아요.\", \"translated\": \"私のスーツケースが見つかりません。\"}, {\"original\": \"휠체어 서비스를 제공합니까?\", \"translated\": \"車いすサービスはありますか？\"}]', 3, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"대중교통에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 대중교통과 관련된 10가지 일반적인 문장과 일본어 번역을 아래에 나열합니다:\"]', '[\"버스/지하철 이용\", \"티켓 구매\", \"환승\"]', 'ko', '[\"지금은 특정 상황이 생각나시는지요, 예를 들어 버스 정류장 물어보기, 티켓 가격, 내리는 것 등 자유롭게 질문해 주세요.\", \"마음에 떠오르는 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"이 버스는 터미널로 가나요?\", \"translated\": \"このバスはターミナルに行きますか？\"}, {\"original\": \"다음 정류장은 어디인가요?\", \"translated\": \"次の停車駅はどこですか？\"}, {\"original\": \"哪里可以买票？\", \"translated\": \"切符はどこで買えますか？\"}, {\"original\": \"제발 하나의 티켓을 주세요.\", \"translated\": \"XX行きの切符を一つください。\"}, {\"original\": \"전환해야 하나요?\", \"translated\": \"乗り換えが必要ですか？\"}, {\"original\": \"다음 지하철이 몇 분 후에 오나요?\", \"translated\": \"次の地下鉄の到着までどれくらいかかりますか？\"}, {\"original\": \"실례합니다, 지나가도 괜찮을까요?\", \"translated\": \"すみません、通りたいのですが。\"}, {\"original\": \"이 자리에 누가 앉아 있나요?\", \"translated\": \"この座席は使っていますか？\"}, {\"original\": \"실례합니다, 이곳에서 2호선으로 전환하려면 어디로 가야 하나요?\", \"translated\": \"すみません、XXに行くには2号線にどこで乗り換えればいいですか？\"}, {\"original\": \"어떻게 하면 XX에 도착할 수 있나요?\", \"translated\": \"XXへはどう行けばいいですか？\"}]', 4, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"관광지에서 사용할 수 있는 10가지 일반 문장을 제공해 주실 수 있나요?\", \"좋습니다! 관광지와 관련된 10가지 일반 문장과 일본어 번역을 제공합니다:\"]', '[\"관광하기\", \"사진 찍기\", \"티켓 구매하기\"]', 'ko', '[\"지금은, 예를 들어 티켓 가격 문의, 주차장 찾기 또는 투어 가이드 서비스와 같은 구체적인 상황을 생각하고 계신가요, 자유롭게 물어보세요.\", \"심상 중인 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"학생 할인 티켓이 있나요?\", \"translated\": \"学生用の切符はありますか？\"}, {\"original\": \"이 관광지가 몇 시에 열어요?\", \"translated\": \"この観光地はいつ開館しますか？\"}, {\"original\": \"여기서 할 수 있는 재미있는 활동은 뭐예요?\", \"translated\": \"ここではどんな面白いことをすることができますか？\"}, {\"original\": \"우리 사진을 찍어 줄 수 있나요?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"관광버스는 어디에 있어요?\", \"translated\": \"観光バスはどこにありますか？\"}, {\"original\": \"화장실은 어디에 있어요?\", \"translated\": \"トイレはどこにありますか？\"}, {\"original\": \"가장 좋은 전망지는 어디인가요?\", \"translated\": \"最も良い観賞スポットはどこですか？\"}, {\"original\": \"이곳의 경치가 아름다워요.\", \"translated\": \"ここにある風景は美しいです。\"}, {\"original\": \"가이드 투어가 있나요?\", \"translated\": \"ガイド付きツアーはありますか？\"}]', 5, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"택시나 택시 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있습니까?\", \"좋습니다! 택시나 택시 서비스와 관련된 10가지 일반적인 문장과 일본어 번역을 제공합니다:\"]', '[\"택시 타기\", \"도착지 말하기\", \"결제\"]', 'ko', '[\"현재, 목적지 요청, 요금 확인 또는 세금계산서 요청과 같은 것을 가장 원하시는 것은 무엇입니까, 자유롭게 물어보세요.\", \"마음속에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"택시를 어디에서 탈 수 있나요?\", \"translated\": \"タクシーはどこで乗れますか？\"}, {\"original\": \"이 주소로 저를 데려가 주세요.\", \"translated\": \"この住所に連れて行ってください。\"}, {\"original\": \"大概多少钱？\", \"translated\": \"だいたいどのくらいになりますか？\"}, {\"original\": \"계산기 사용해 주시겠어요?\", \"translated\": \"メーターを使っていただけますか？\"}, {\"original\": \"제가 급한데 좀 더 빨리 운전해 주세요.\", \"translated\": \"少し速く運転していただけますか？私は急いでいます。\"}, {\"original\": \"여기서 멈춰 주세요.\", \"translated\": \"ここで止めてください。\"}, {\"original\": \"카드나 모바일 결제를 받으세요?\", \"translated\": \"カードやモバイル決済は受けられますか？\"}, {\"original\": \"영수증을 주실 수 있나요?\", \"translated\": \"領収書をいただけますか？\"}, {\"original\": \"감사합니다, 기사님.\", \"translated\": \"ありがとう、ドライバーさん。\"}, {\"original\": \"얼마나 더 가야 하나요?\", \"translated\": \"あとどれくらいですか？\"}]', 6, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"약국에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 약국과 관련된 10가지 일반적인 문장과 일본어 번역을 드립니다:\"]', '[\"약 구입\", \"상담\", \"결제\"]', 'ko', '[\"지금은, 약을 복용하는 방법에 대해 묻는 상황, 보험과 관련된 문장, 약물의 지속 기간 등 특정 상황을 생각하고 계신가요? 자유롭게 물어보세요.\", \"여러분이 생각하고 계신 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"감기약이 있습니까?\", \"translated\": \"風邪薬はありますか？\"}, {\"original\": \"이 약은 어떻게 복용해야 하나요?\", \"translated\": \"この薬はどのように服用すればよいですか？\"}, {\"original\": \"진통제가 있습니까?\", \"translated\": \"鎮痛剤はありますか？\"}, {\"original\": \"사용 설명서가 있습니까?\", \"translated\": \"使用説明書はありますか？\"}, {\"original\": \"이 약에 부작용이 있습니까?\", \"translated\": \"この薬には副作用がありますか？\"}, {\"original\": \"내 의료 보험 카드를 사용할 수 있나요?\", \"translated\": \"私の医療保険証を使用できますか？\"}, {\"original\": \"붕대 한 상자 주실 수 있겠어요?\", \"translated\": \"バンドエイドの箱をください。\"}, {\"original\": \"열 내리는 약이 있습니까?\", \"translated\": \"解熱剤はありますか？\"}, {\"original\": \"조금 까져요. 소독약과 붕대가 있습니까?\", \"translated\": \"ちょっと擦り傷があるんです。消毒液とバンドエイドはありますか？\"}, {\"original\": \"언제 문을 닫으십니까?\", \"translated\": \"閉店時間はいつですか？\"}]', 7, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"응급 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋아요! 응급 서비스와 관련된 10가지 일반적인 문장과 일본어 번역을 아래에 나열합니다:\"]', '[\"경찰 호출\", \"응급처치\", \"도움 요청\"]', 'ko', '[\"현재, 특정한 응급 상황이 있으신가요? 예를 들어 화재, 부상 및 도움이 필요한 경우, 응급 전화 등 자유롭게 질문해 주세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"응급차를 불러줘.\", \"translated\": \"救急車を呼んでください。\"}, {\"original\": \"병원은 어디예요?\", \"translated\": \"病院はどこですか？\"}, {\"original\": \"누군가 다쳤어요.\", \"translated\": \"誰かが怪我をしました。\"}, {\"original\": \"도와주세요.\", \"translated\": \"助けてください。\"}, {\"original\": \"경찰서는 어디예요?\", \"translated\": \"警察署はどこですか？\"}, {\"original\": \"내 소지품을 잃어버렸어요.\", \"translated\": \"私の荷物をなくしました。\"}, {\"original\": \"소방서 번호는 무엇인가요?\", \"translated\": \"消防局の番号は何ですか？\"}, {\"original\": \"여권을 잃어버렸어요. 가장 가까운 경찰서는 어디예요?\", \"translated\": \"パスポートをなくしました。最寄りの警察署はどこですか？\"}, {\"original\": \"비상출구는 어디예요?\", \"translated\": \"非常出口はありますか？\"}, {\"original\": \"누군가 기절했어요.\", \"translated\": \"誰かが気を失いました。\"}]', 8, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"비치나 수영장가에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주시겠어요?\", \"좋아요! 비치나 수영장과 관련된 10개의 일반적인 문장과 일본어 번역을 드립니다:\"]', '[\"수영\", \"태양광 쬐기\", \"해변 스포츠\"]', 'ko', '[\"지금은, 참석하는 지역 이벤트나 축제의 맥락을 알려주세요. 예를 들어 문화 축제, 음식 축제 또는 음악 축제 등입니다. 맥락을 제공해 주세요.\", \"참석하는 활동을 알려주세요.\"]', '[\"특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"심리적으로 생각하고 있는 상황을 설명해 주세요.\"]', '[{\"original\": \"보라, 저쪽 파도가 정말 크다.\", \"translated\": \"見てごらん、あそこで波がとても大きいよ。\"}, {\"original\": \"자외선 차단제를 바르세요, 여기 자외선이 매우 강합니다.\", \"translated\": \"日焼け止めを塗ることを忘れないでね、ここは紫外線が強いの。\"}, {\"original\": \"이 해변의 모래는 매우 미끄러워서 마치 솜처럼 느껴집니다.\", \"translated\": \"このビーチの砂はとても細かくて、綿に足をつけるみたいだよ。\"}, {\"original\": \"해변에서 배구를 해볼까?\", \"translated\": \"ビーチでバドミントンをしようか？\"}, {\"original\": \"멀리 있는 요트들이 아름답게 보인다.\", \"translated\": \"遠くのヨットたちが美しいね。\"}, {\"original\": \"여기 물은 매우 맑아서 물고기를 볼 수 있습니다.\", \"translated\": \"ここでの水はとても透き通っていて、魚が見えるよ。\"}, {\"original\": \"시조개를 찾으러 가자.\", \"translated\": \"貝殻を探しに行こう。\"}, {\"original\": \"일몰 때 해변을 산책하는 것은 매우 로맨틱할 것 같아.\", \"translated\": \"日の入り時にビーチを散歩するのはとてもロマンチックだろうね。\"}, {\"original\": \"여기 해산물이 매우 신선하다는 걸 들었어, 가서 먹어보자.\", \"translated\": \"ここでの海産物はとても新鮮だと聞いたから、食べてみよう。\"}, {\"original\": \"조수 간만이 올라오고 있어, 해안으로 가자.\", \"translated\": \"潮が引き始めている、岸に向かおう。\"}]', 9, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"로컬 이벤트와 페스티벌에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋습니다! 로컬 이벤트와 페스티벌과 관련된 10가지 일반적인 표현과 일본어 번역을 제공합니다:\"]', '[\"이벤트 참석\", \"절기 축제 축하\", \"문화 배우기\"]', 'ko', '[\"현재, 당신이 참석하는 로컬 이벤트나 페스티벌의 맥락을 제공해 주시겠습니까? 예를 들어 할로윈, 콘서트, 친구 파티 또는 기타 사항이 있습니까? 맥락을 제공해 주세요.\", \"당신이 생각하는 활동을 설명해 주세요.\"]', '[\"자유롭게 물어보실 수 있습니다.\", \"당신이 생각하는 상황을 설명해 주세요.\"]', '[{\"original\": \"오늘 행사가 있나요?\", \"translated\": \"今日はイベントがありますか？\"}, {\"original\": \"이 축제에는 특별한 점이 있나요?\", \"translated\": \"この祭りには特別なことありますか？\"}, {\"original\": \"축제는 어디에서 열리나요?\", \"translated\": \"祝賀はどこで開催されますか？\"}, {\"original\": \"티켓을 어떻게 구입할 수 있나요?\", \"translated\": \"チケットをどうやって買えばいいですか？\"}, {\"original\": \"공연은 몇 시에 시작하나요?\", \"translated\": \"公演の開始時間はいつですか？\"}, {\"original\": \"이곳에 어떤 전통 음식이 있나요?\", \"translated\": \"この地で食べられる伝統的な料理は何ですか？\"}, {\"original\": \"여기 정말 활기가 넘치네요.\", \"translated\": \"ここは本当ににぎやかですね。\"}, {\"original\": \"민속 활동은 있는가요?\", \"translated\": \"民話の活動はありますか？\"}, {\"original\": \"즐거운 명절 되세요!\", \"translated\": \"ハッピーホリデイ！\"}, {\"original\": \"행사는 몇 시에 끝나나요?\", \"translated\": \"イベントの終了時間はいつですか？\"}]', 10, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"박물관 또는 미술관에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 박물관 또는 미술관과 관련된 10가지 일반적인 문장과 일본어 번역을 아래에 소개합니다:\"]', '[\"방문\", \"가이드 투어\", \"티켓 구매\"]', 'ko', '[\"현재, 도서 안내서를 요청하거나, 로드맵과 관련된 문장, 전시품에 대한 의견을 표현하는 문장과 같은 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"심리적으로 생각하고 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"入場料はいくらですか？\"}, {\"original\": \"오디오 가이드가 있나요?\", \"translated\": \"オーディオガイドはありますか？\"}, {\"original\": \"이 작품을 만든 사람은 누구인가요?\", \"translated\": \"この芸術作品を誰が作ったのですか？\"}, {\"original\": \"이 박물관의 가장 소중한 작품은 어디에 있나요?\", \"translated\": \"美術館で最も貴重な作品はどこにありますか？\"}, {\"original\": \"사진 촬영이 가능한가요?\", \"translated\": \"写真撮影は許可されていますか？\"}, {\"original\": \"여기 특별 전시회가 있나요?\", \"translated\": \"ここには特別展覧会がありますか？\"}, {\"original\": \"방문에는 얼마나 시간이 걸리나요?\", \"translated\": \"見学にはどのくらい時間がかかりますか？\"}, {\"original\": \"우리에게 소개를 해주실 수 있나요?\", \"translated\": \"私たちに紹介してくださいませんか？\"}, {\"original\": \"이 작품들은 정말 아름답습니다.\", \"translated\": \"これらの作品は本当に美しくて素晴らしいです。\"}, {\"original\": \"기념품 가게는 어디에 있나요?\", \"translated\": \"サマーアイテムショップはどこにありますか？\"}]', 11, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"카페에서 사용할 수 있는 10가지 일반적인 문구를 제공해 주실 수 있나요?\", \"좋아요! 카페와 관련된 10가지 일반적인 문구와 일본어 번역을 드립니다:\"]', '[\"커피 주문\", \"휴식\", \"사회적 상호작용\"]', 'ko', '[\"현재, 메뉴를 요청하거나, 얼음 또는 뜨거운 음료, 기타 제품에 대한 상황을 구체적으로 생각하고 계신가요? 자유롭게 물어보세요.\", \"마음속에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"제가 라테 한 잔 주세요.\", \"translated\": \"ラテをください。\"}, {\"original\": \"와이파이 있으세요?\", \"translated\": \"Wi-Fiはありますか？\"}, {\"original\": \"메뉴 좀 보여주실 수 있나요?\", \"translated\": \"メニューを見せていただけますか？\"}, {\"original\": \"리필 가능합니까?\", \"translated\": \"リフィルはできますか？\"}, {\"original\": \"제 커피 준비되었나요?\", \"translated\": \"私のコーヒーは出来ましたか？\"}, {\"original\": \"이곳에서 얼마나 오래 있을 수 있나요?\", \"translated\": \"ここに何時間座っていられますか？\"}, {\"original\": \"우리 사진 좀 찍어줄 수 있나요?\", \"translated\": \"私たちの写真を撮っていただけますか？\"}, {\"original\": \"화장실은 어디에 있나요?\", \"translated\": \"トイレはどこですか？\"}, {\"original\": \"계산해 주세요. 감사합니다.\", \"translated\": \"お会計をお願いします。ありがとう。\"}, {\"original\": \"정말 맛있어요.\", \"translated\": \"とても美味しいです。\"}]', 12, 'ja');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"식당에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 식당과 관련된 10가지 일반적인 문장과 영어 번역을 제공합니다:\"]', '[\"식사\", \"주문\", \"결제\"]', 'ko', '[\"현재, 음료 주문, 불만 제기 또는 성분에 대한 질문과 같은 구체적인 상황이 있으신가요? 자유롭게 물어보세요.\", \"심리적으로 생각하고 있는 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"실례합니다, 음식은 얼마나 더 오래 걸릴까요?\", \"translated\": \"Excuse me, how much longer will our food be?\"}, {\"original\": \"두 명을 위한 테이블을 부탁드립니다.\", \"translated\": \"A table for two, please.\"}, {\"original\": \"메뉴를 보여주실 수 있겠어요?\", \"translated\": \"Could we see the menu, please?\"}, {\"original\": \"추천할 만한 특별한 요리가 있나요?\", \"translated\": \"Do you have any signature dishes to recommend?\"}, {\"original\": \"이것과 이것을 주문하고 싶어요.\", \"translated\": \"I\'d like to order this, and this.\"}, {\"original\": \"물 한 잔 부탁드립니다. 감사합니다.\", \"translated\": \"A glass of water, please. Thanks.\"}, {\"original\": \"계산서를 부탁드립니다.\", \"translated\": \"The bill, please.\"}, {\"original\": \"신용카드로 지불할 수 있나요?\", \"translated\": \"Can I pay by credit card?\"}, {\"original\": \"이걸 포장해 주실 수 있나요?\", \"translated\": \"Could you pack this to go, please?\"}, {\"original\": \"음식이 정말 맛있었어요. 감사합니다.\", \"translated\": \"The food was delicious, thank you.\"}]', 1, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"호텔에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 호텔과 관련된 10가지 일반적인 문장과 영어 번역을 드립니다:\"]', '[\"체크인\", \"체크아웃\", \"객실 서비스\"]', 'ko', '[\"현재, 방 위치, 다른 호텔 서비스, 체크아웃 등 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"심중에 생각하고 계신 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"안녕하세요, 예약이 있습니다, 여기 여권이 있습니다.\", \"translated\": \"Hello, I have a reservation, Here is my passport.\"}, {\"original\": \"예약 가능한 객실이 있습니까?\", \"translated\": \"Do you have any vacancies?\"}, {\"original\": \"잠시 실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\", \"translated\": \"Excuse me, does the hotel have a gym or a laundry room?\"}, {\"original\": \"아침 식사가 몇 시부터 시작합니까?\", \"translated\": \"What time does breakfast start?\"}, {\"original\": \"방 키를 주실 수 있겠습니까?\", \"translated\": \"Could I have a room key, please?\"}, {\"original\": \"제 짐을 방까지 가져다 도와주실 수 있겠습니까?\", \"translated\": \"Could you help me take my luggage to the room?\"}, {\"original\": \"객실 서비스를 부르는 방법은 무엇입니까?\", \"translated\": \"How do I call room service?\"}, {\"original\": \"체크아웃 시간은 몇 시입니까?\", \"translated\": \"What time is check-out?\"}, {\"original\": \"영수증/송금 영수증을 작성해 주실 수 있겠습니까?\", \"translated\": \"Could you write me a receipt/invoice?\"}, {\"original\": \"제 짐을 여기 두어도 괜찮습니까?\", \"translated\": \"Can I leave my luggage here?\"}]', 2, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공항에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 공항과 관련된 10가지 일반적인 문장과 영어 번역을 아래에 나열합니다:\"]', '[\"체크인\", \"승객 탑승\", \"수하물 수령\"]', 'ko', '[\"현재, 체크인, 수하물 인수 또는 차량 대여 서비스와 같은 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"심상 중인 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"체크인 카운터는 어디입니까?\", \"translated\": \"Where is the check-in counter?\"}, {\"original\": \"창가 자리를 원합니다.\", \"translated\": \"I\'d like a window seat, please.\"}, {\"original\": \"이 비행기 지연되었나요?\", \"translated\": \"Is this flight delayed?\"}, {\"original\": \"이 수하물을 확인해야 합니다.\", \"translated\": \"I need to check this baggage.\"}, {\"original\": \"승무 게이트는 어디입니까?\", \"translated\": \"Where is the boarding gate?\"}, {\"original\": \"비행기가 곧 이륙할 예정입니다.\", \"translated\": \"The plane is about to take off.\"}, {\"original\": \"노트북과 충전기를 꺼내야 하나요?\", \"translated\": \"Do I need to take out my laptop and power bank?\"}, {\"original\": \"면세점은 어디입니까?\", \"translated\": \"Where is the duty-free shop?\"}, {\"original\": \"내 수화물이 보이지 않습니다.\", \"translated\": \"I can\'t find my suitcase.\"}, {\"original\": \" wheelchair 서비스를 제공합니까?\", \"translated\": \"Do you have a wheelchair service?\"}]', 3, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공공교통에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 공공교통과 관련된 10가지 일반적인 문장과 영어 번역을 아래에 나열합니다:\"]', '[\"버스/지하철 탑승\", \"티켓 구매\", \"환승\"]', 'ko', '[\"지금은 특정 상황이 생각나시는지 궁금합니다. 예를 들어 버스 정류장 물어보기, 티켓 가격, 하차 등 자유롭게 질문해 주세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"이 버스는 종점으로 가나요?\", \"translated\": \"Does this bus go to the terminal?\"}, {\"original\": \"다음 정류장은 어디예요?\", \"translated\": \"What is the next stop?\"}, {\"original\": \"티켓을 어디에서 살 수 있나요?\", \"translated\": \"Where can I buy a ticket?\"}, {\"original\": \"XX까지 티켓 하나 주세요.\", \"translated\": \"One ticket to XX, please.\"}, {\"original\": \"환승해야 하나요?\", \"translated\": \"Do I need to transfer?\"}, {\"original\": \"다음 지하철이 몇 분 후에 오나요?\", \"translated\": \"How long until the next subway train?\"}, {\"original\": \"실례합니다, 지나가도 될까요?\", \"translated\": \"Excuse me, please let me pass.\"}, {\"original\": \"이 자리에 누가 앉아 있나요?\", \"translated\": \"Is this seat taken?\"}, {\"original\": \"실례합니다, XX로 가려면 2호선으로 어디에서 환승해야 하나요?\", \"translated\": \"Excuse me, where can I transfer to Line 2 to get to XX?\"}, {\"original\": \"XX로 가는 방법을 알려주세요.\", \"translated\": \"How do I get to XX?\"}]', 4, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"여행지에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 여행지와 관련된 10가지 일반적인 문장과 영어 번역을 드립니다:\"]', '[\"관광하기\", \"사진 찍기\", \"티켓 구매\"]', 'ko', '[\"현재, 티켓 가격에 대해 묻거나 주차장 찾기 또는 투어 가이드 서비스와 같은 구체적인 상황을 생각하고 계신가요? 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"How much is the entrance fee?\"}, {\"original\": \"학생 할인 티켓이 있나요?\", \"translated\": \"Are there student tickets available?\"}, {\"original\": \"이 관광지가 몇 시에 열리나요?\", \"translated\": \"What time does the attraction open?\"}, {\"original\": \"여기서 할 수 있는 재미있는 일은 무엇인가요?\", \"translated\": \"What are the fun things to do here?\"}, {\"original\": \"우리를 위한 사진을 찍어줄 수 있나요?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"관광버스는 어디에 있나요?\", \"translated\": \"Where is the sightseeing bus?\"}, {\"original\": \"화장실은 어디에 있나요?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"가장 좋은 전망지는 어디인가요?\", \"translated\": \"Where is the best viewing spot?\"}, {\"original\": \"여기 경치가 아름답네요.\", \"translated\": \"The scenery here is beautiful.\"}, {\"original\": \"가이드 투어가 있나요?\", \"translated\": \"Is there a guided tour available?\"}]', 5, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"택시나 택시 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있습니까?\", \"좋아요! 택시나 택시 서비스와 관련된 10가지 일반적인 문장과 영어 번역을 제공합니다:\"]', '[\"택시 타기\", \"목적지 말하기\", \"결제\"]', 'ko', '[\"지금, 목적지 요청, 요금 문의, 세금계산서 요청 등 하고 싶은 것을 자유롭게 물어보세요.\", \"상황을 마음속에 설명해 주세요.\"]', NULL, '[{\"original\": \"택시를 어디에서 탈 수 있나요?\", \"translated\": \"Where can I get a taxi?\"}, {\"original\": \"이 주소로 저를 데려가 주세요.\", \"translated\": \"Please take me to this address.\"}, {\"original\": \"얼마나 들까요?\", \"translated\": \"Roughly how much will it be?\"}, {\"original\": \"계산기 사용해 주시겠어요?\", \"translated\": \"Could you use the meter, please?\"}, {\"original\": \"좀 더 빨리 운전해 주시겠어요? 저는 급한 일이 있어요.\", \"translated\": \"Please drive a bit faster, I\'m in a hurry.\"}, {\"original\": \"여기서 멈춰 주세요.\", \"translated\": \"Please stop here.\"}, {\"original\": \"카드나 모바일 결제를 받으세요?\", \"translated\": \"Do you accept cards or mobile payments?\"}, {\"original\": \"영수증을 좀 주세요.\", \"translated\": \"Could I have a receipt, please?\"}, {\"original\": \"감사합니다, 기사님.\", \"translated\": \"Thank you, driver.\"}, {\"original\": \"이곳까지 얼마나 더 가야 하나요?\", \"translated\": \"How much further is it?\"}]', 6, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"약국에서 사용할 수 있는 10가지 일반 문장을 제공해 주실 수 있나요?\", \"좋아요! 약국과 관련된 10가지 일반 문장과 영어 번역을 아래에 나열합니다:\"]', '[\"약 구매\", \"상담\", \"결제\"]', 'ko', '[\"지금은, 약을 복용하는 방법을 묻는 상황, 보험 관련 문장, 약의 지속 기간 등 특정 상황을 생각하고 계신가요? 자유롭게 물어보세요.\", \"현재 마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"감기약이 있습니까?\", \"translated\": \"Do you have cold medicine?\"}, {\"original\": \"이 약은 어떻게 복용해야 하나요?\", \"translated\": \"How should I take this medicine?\"}, {\"original\": \"진통제가 있습니까?\", \"translated\": \"Do you have any painkillers?\"}, {\"original\": \"사용 설명서가 있습니까?\", \"translated\": \"Is there an instruction leaflet?\"}, {\"original\": \"이 약에 부작용이 있습니까?\", \"translated\": \"Does this medicine have any side effects?\"}, {\"original\": \"내 보험 카드로 사용할 수 있습니까?\", \"translated\": \"Can I use my medical insurance card?\"}, {\"original\": \"붕대 한 상자 주시겠어요?\", \"translated\": \"Could I have a box of Band-Aids, please?\"}, {\"original\": \"발열 억제제가 있습니까?\", \"translated\": \"Do you have any fever reducers?\"}, {\"original\": \"조금 까져요. 소독제와 붕대가 있습니까?\", \"translated\": \"I\'ve got a bit of a scrape. Do you have any antiseptic and Band-Aids?\"}, {\"original\": \"언제 문을 닫습니까?\", \"translated\": \"What time do you close?\"}]', 7, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"응급 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋아요! 응급 서비스와 관련된 10가지 일반적인 문장과 영어 번역을 드립니다:\"]', '[\"경찰 호출\", \"응급 처치\", \"도움 요청\"]', 'ko', '[\"현재, 마음에 드는 특정 응급 상황이 있습니까? 예를 들어, 화재, 부상 및 도움이 필요한 경우, 응급 전화 등 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"응급차를 불러줘.\", \"translated\": \"Please help me call an ambulance.\"}, {\"original\": \"병원은 어디예요?\", \"translated\": \"Where is the hospital?\"}, {\"original\": \"누군가 다쳤어요.\", \"translated\": \"Someone is injured.\"}, {\"original\": \"도와주세요.\", \"translated\": \"Please help me.\"}, {\"original\": \"경찰서는 어디예요?\", \"translated\": \"Where is the police station?\"}, {\"original\": \"내 소지품을 잃어버렸어요.\", \"translated\": \"I\'ve lost my belongings.\"}, {\"original\": \"소방서 번호는 무엇인가요?\", \"translated\": \"What is the number for the fire department?\"}, {\"original\": \"여권을 잃어버렸어요. 가까운 경찰서는 어디예요?\", \"translated\": \"I\'ve lost my passport. Do you know where the nearest police station is?\"}, {\"original\": \"비상출구는 어디예요?\", \"translated\": \"Is there an emergency exit?\"}, {\"original\": \"누군가 쓰러졌어요.\", \"translated\": \"Someone has fainted.\"}]', 8, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"비치 또는 수영장가에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 비치 또는 수영장가와 관련된 10개의 일반적인 문장과 영어 번역을 제공합니다:\"]', '[\"수영\", \"태양광 쬐기\", \"해변 스포츠\"]', 'ko', '[\"현재까지, 참석하는 지역 이벤트 또는 축제(문화 축제, 음식 축제, 음악 축제 등)의 맥락을 제공해 주시겠습니까? 맥락을 제공해 주세요.\", \"참석하는 활동을 알려주세요.\"]', '[\"특정 상황이 마음에 드신다면 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', '[{\"original\": \"보라, 저쪽의 파도가 정말 크다.\", \"translated\": \"Look! The waves over there are really big.\"}, {\"original\": \"자외선 차단제를 바르세요, 여기 자외선이 매우 강합니다.\", \"translated\": \"Remember to apply sunscreen, the UV rays here are very strong.\"}, {\"original\": \"이 해변의 모래는 매우 미끄럽고, 마치 솜처럼 느껴집니다.\", \"translated\": \"The sand on this beach is so fine, it feels like stepping on cotton.\"}, {\"original\": \"해변에서 배구를 하기 어때요?\", \"translated\": \"How about playing volleyball on the beach?\"}, {\"original\": \"멀리 있는 요트들이 아름답게 보입니다.\", \"translated\": \"The sailboats in the distance look beautiful.\"}, {\"original\": \"여기 물은 매우 맑아서 물고기를 볼 수 있습니다.\", \"translated\": \"The water here is so clear, you can even see the fish.\"}, {\"original\": \"시조를 찾으러 가자.\", \"translated\": \"Let\'s go find some seashells.\"}, {\"original\": \"일몰 때 해변을 산책하는 것은 매우 로맨틱할 것입니다.\", \"translated\": \"Taking a walk on the beach at sunset must be very romantic.\"}, {\"original\": \"여기 해산물이 매우 신선하다고 들었어요, 같이 먹어보죠.\", \"translated\": \"I heard the seafood here is very fresh, let\'s go try some.\"}, {\"original\": \"조수 간조가 시작되고 있으니, 해안으로 가야겠습니다.\", \"translated\": \"The tide is coming in, let\'s head towards the shore.\"}]', 9, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"로컬 이벤트 및 축제에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 로컬 이벤트 및 축제와 관련된 10가지 일반적인 문장과 영어 번역을 아래에 나열해 드리겠습니다.\"]', '[\"이벤트에 참석하기\", \"축제를 축하하기\", \"문화를 배우기\"]', 'ko', '[\"현재, 로컬 이벤트 또는 축제에 참석하는 상황을 알려주실 수 있나요? 예를 들어 할로윈, 콘서트, 친구 파티 또는 기타 사항이 있을 수 있습니다. 상황을 제공해 주세요.\", \"여러분의 마음속에 있는 활동을 설명해 주세요.\"]', '[\"특정 상황이 마음에 있으신가요? 자유롭게 물어보세요.\", \"여러분의 마음속에 있는 상황을 설명해 주세요.\"]', '[{\"original\": \"오늘 이벤트가 있나요?\", \"translated\": \"Are there any events today?\"}, {\"original\": \"이 축제에 특별한 점이 있나요?\", \"translated\": \"Is there anything special about this festival?\"}, {\"original\": \"축제는 어디에서 열리나요?\", \"translated\": \"Where is the celebration being held?\"}, {\"original\": \"티켓을 어떻게 구입할 수 있나요?\", \"translated\": \"How can I buy tickets?\"}, {\"original\": \"공연은 몇 시에 시작하나요?\", \"translated\": \"What time does the performance start?\"}, {\"original\": \"이곳에 전통 음식은 무엇인가요?\", \"translated\": \"What traditional food is there?\"}, {\"original\": \"여기 정말 활기차네요.\", \"translated\": \"It\'s really lively here.\"}, {\"original\": \"민속 활동이 있나요?\", \"translated\": \"Are there any folk activities?\"}, {\"original\": \"명절 즐겁게 보내세요!\", \"translated\": \"Happy holidays!\"}, {\"original\": \"이벤트는 몇 시에 끝나나요?\", \"translated\": \"What time does the event end?\"}]', 10, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"박물관 또는 미술관에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 박물관 또는 미술관과 관련된 10가지 일반적인 문장과 영어 번역을 제공합니다:\"]', '[\"방문\", \"가이드 투어\", \"티켓 구매\"]', 'ko', '[\"지금은, 설명서를 요청하거나, 로드맵과 관련된 문장, 전시품에 대한 의견을 표현하는 문장과 같은 특정 상황을 생각하고 계신가요? 자유롭게 물어보세요.\", \"심상 중인 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"How much is the admission fee?\"}, {\"original\": \"음성 안내 서비스가 있나요?\", \"translated\": \"Do you have audio guides?\"}, {\"original\": \"이 작품을 만든 사람은 누구인가요?\", \"translated\": \"Who created this artwork?\"}, {\"original\": \"박물관에서 가장 소중한 작품은 어디에 있나요?\", \"translated\": \"Where is the museum\'s most prized piece?\"}, {\"original\": \"사진 촬영이 가능한가요?\", \"translated\": \"Is photography allowed?\"}, {\"original\": \"이곳에 특별 전시회가 있나요?\", \"translated\": \"Are there any special exhibitions here?\"}, {\"original\": \"방문에 얼마나 시간이 걸리나요?\", \"translated\": \"How long does the visit take?\"}, {\"original\": \"우리에게 소개를 해주실 수 있나요?\", \"translated\": \"Could you give us an introduction?\"}, {\"original\": \"이 작품들은 정말 아름답습니다.\", \"translated\": \"These works are truly exquisite.\"}, {\"original\": \"기념품 가게는 어디에 있나요?\", \"translated\": \"Where is the souvenir shop?\"}]', 11, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"카페에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋아요! 카페와 관련된 10가지 일반적인 표현과 영어 번역을 아래에 나열해 드립니다:\"]', '[\"커피 주문하기\", \"휴식하기\", \"소셜링하기\"]', 'ko', '[\"현재, 특정 상황을 생각하고 계신가요? 예를 들어 메뉴를 묻는 것, 얼음 또는 뜨거운 음료, 기타 제품, 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"제가 라테 하나 주세요.\", \"translated\": \"I\'ll have a latte, please.\"}, {\"original\": \"와이파이 있으세요?\", \"translated\": \"Do you have Wi-Fi?\"}, {\"original\": \"메뉴 좀 보여주세요.\", \"translated\": \"Could I see the menu, please?\"}, {\"original\": \"리필 가능하세요?\", \"translated\": \"Are refills allowed?\"}, {\"original\": \"제 커피 준비됐나요?\", \"translated\": \"Is my coffee ready?\"}, {\"original\": \"이곳에서 얼마나 오래 있을 수 있나요?\", \"translated\": \"How long can I sit here?\"}, {\"original\": \"우리 사진 좀 찍어줄 수 있나요?\", \"translated\": \"Could you take a picture for us?\"}, {\"original\": \"화장실은 어디에요?\", \"translated\": \"Where is the restroom?\"}, {\"original\": \"계산해 주세요. 감사합니다.\", \"translated\": \"Check, please. Thank you.\"}, {\"original\": \"진짜 맛있어요.\", \"translated\": \"It tastes really good.\"}]', 12, 'en');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"레스토랑에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋습니다! 레스토랑과 관련된 10가지 일반적인 표현과 아랍어 번역을 제공합니다:\"]', '[\"식사\", \"주문\", \"결제\"]', 'ko', '[\"지금은 특정 상황이 생각나시나요? 예를 들어 음료 주문, 불만 제기, 성분 문의 등 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"실례합니다, 음식은 얼마나 더 오래 걸리나요?\", \"translated\": \"إعتذر، كم من الوقت سيستغرق طلبنا؟\"}, {\"original\": \"이용객 두 명을 위한 테이블을 부탁드립니다.\", \"translated\": \"طاولة لشخصين من فضلك.\"}, {\"original\": \"메뉴를 보여주실 수 있겠어요?\", \"translated\": \"هل يمكننا رؤية القائمة من فضلك؟\"}, {\"original\": \"추천할 만한 특별한 요리가 있나요?\", \"translated\": \"هل لديك أطباق مميزة توصي بها؟\"}, {\"original\": \"이것과 이것을 주문하고 싶어요.\", \"translated\": \"أريد أن أطلب هذا وهذا.\"}, {\"original\": \"물 한 잔 부탁드려요. 감사합니다.\", \"translated\": \"كوب ماء من فضلك. شكرًا.\"}, {\"original\": \"계산서 좀 주세요.\", \"translated\": \"الفاتورة من فضلك.\"}, {\"original\": \"신용카드로 지불할 수 있나요?\", \"translated\": \"هل يمكنني الدفع ببطاقة ائتمان؟\"}, {\"original\": \"이걸 포장해 주실 수 있겠어요?\", \"translated\": \"هل يمكنك تغليف هذا للذهاب من فضلك؟\"}, {\"original\": \"음식이 정말 맛있었어요, 감사합니다.\", \"translated\": \"الطعام لذيذ جدًا، شكرًا.\"}]', 1, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"호텔에서 사용할 수 있는 10가지 일반적인 문구를 제공해 주실 수 있나요?\", \"좋아요! 호텔과 관련된 10가지 일반적인 문구와 아랍어 번역을 제공합니다:\"]', '[\"체크인\", \"체크아웃\", \"객실 서비스\"]', 'ko', '[\"현재, 방 위치, 기타 호텔 서비스 또는 체크아웃과 같은 구체적인 상황이 있으신가요? 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"안녕하세요, 예약이 있습니다, 여기 여권입니다.\", \"translated\": \"مرحباً، لدي حجز، هذا جوازي.\"}, {\"original\": \"예약 가능한 객실이 있습니까?\", \"translated\": \"هل لديك أماكن شاغرة؟\"}, {\"original\": \"잠시 실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\", \"translated\": \"عفواً، هل يملك الفندق صالة رياضة أو غرفة غسيل؟\"}, {\"original\": \"아침 식사가 몇 시부터 시작됩니까?\", \"translated\": \"متى تبدأ وجبة الإفطار؟\"}, {\"original\": \"방 키를 좀 주실 수 있겠어요?\", \"translated\": \"هل يمكنني الحصول على مفتاح الغرفة من فضلك؟\"}, {\"original\": \"제 짐을 방으로 옮겨 주실 수 있겠어요?\", \"translated\": \"هل يمكنك مساعدتي في نقل أمتعتي إلى الغرفة؟\"}, {\"original\": \"룸서비스를 부르는 방법은 무엇입니까?\", \"translated\": \"كيف أتصل بخدمة الغرف؟\"}, {\"original\": \"체크아웃 시간은 몇 시입니까?\", \"translated\": \"متى يكون توقيت المغادرة؟\"}, {\"original\": \"영수증/송장 좀 만들어 주시겠어요?\", \"translated\": \"هل يمكنك إعطائي إيصال/فاتورة؟\"}, {\"original\": \"제 짐을 이곳에 둘 수 있겠어요?\", \"translated\": \"يمكنني ترك أمتعتي هنا؟\"}]', 2, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공항에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 공항과 관련된 10가지 일반적인 문장과 아랍어 번역을 드립니다:\"]', '[\"체크인\", \"승객 탑승\", \"수화물 수령\"]', 'ko', '[\"지금은, 체크인, 수하물 인수, 자동차 대여 서비스와 같은 특정 상황이 생각나시나요? 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"체크인 카운터는 어디입니까?\", \"translated\": \"أين محطة تسجيل الوصول؟\"}, {\"original\": \"창가 자리로 예약하고 싶어요.\", \"translated\": \"أرغب في مقعد بجانب النافذة، من فضلك.\"}, {\"original\": \"이 항공편이 지연되었나요?\", \"translated\": \"هل رحلة الطيران متأخرة؟\"}, {\"original\": \"이 수하물을 확인해야 합니다.\", \"translated\": \"أحتاج إلى فحص هذه الأمتعة.\"}, {\"original\": \"승객 탑승 게이트는 어디입니까?\", \"translated\": \"أين بوابة الصعود؟\"}, {\"original\": \"비행기가 출발할 준비가 되었습니다.\", \"translated\": \"الطائرة على وشك الإقلاع.\"}, {\"original\": \"노트북과 전원 어댑터를 꺼내야 하나요?\", \"translated\": \"هل أحتاج إلى إخراج حاسوبي المحمول ووحدة الطاقة؟\"}, {\"original\": \"관세 면세점은 어디입니까?\", \"translated\": \"أين متجر البقالة الخالية من الضرائب؟\"}, {\"original\": \"내 수화물이 보이지 않아요.\", \"translated\": \"لا أستطيع العثور على حقيبتي.\"}, {\"original\": \"휠체어 서비스를 제공합니까?\", \"translated\": \"هل تقدم خدمة كرسي متحرك؟\"}]', 3, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공공교통에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠어요?\", \"좋습니다! 공공교통과 관련된 10가지 일반적인 문장과 아랍어 번역을 제공합니다:\"]', '[\"버스/지하철 탑승\", \"티켓 구매\", \"환승\"]', 'ko', '[\"지금은 특정 상황이 생각나시나요, 예를 들어 버스 정류장에 대한 질문, 티켓 가격, 하차 등 자유롭게 물어보세요.\", \"심중에 생각하고 계신 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"이 버스는 종점에 가나요?\", \"translated\": \"هل يذهب هذا الحافلة إلى المحطة؟\"}, {\"original\": \"다음 정류장은 어디예요?\", \"translated\": \"ما هي المحطة التالية؟\"}, {\"original\": \"티켓을 어디에서 살 수 있나요?\", \"translated\": \"أين يمكنني شراء تذكرة؟\"}, {\"original\": \"XX까지 티켓 하나 부탁드려요.\", \"translated\": \"تذكرة واحدة إلى XX، من فضلك.\"}, {\"original\": \"전환해야 하나요?\", \"translated\": \"هل أحتاج إلى الانتقال؟\"}, {\"original\": \"다음 지하철은 얼마나 걸리나요?\", \"translated\": \"كم من الوقت حتى وصول القطار التالي؟\"}, {\"original\": \"실례합니다, 지나가도 될까요?\", \"translated\": \"عفواً، اسمحوا لي بالمرور.\"}, {\"original\": \"이 자리에 누가 앉았나요?\", \"translated\": \"هل هذه المقعد مخصص؟\"}, {\"original\": \"실례합니다, XX로 가기 위해 2호선으로 어떻게 갈아타나요?\", \"translated\": \"عفواً، أين يمكنني الانتقال إلى الخط 2 للوصول إلى XX؟\"}, {\"original\": \"XX에 어떻게 가나요?\", \"translated\": \"كيف أصل إلى XX؟\"}]', 4, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"관광지에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 관광지와 관련된 10가지 일반적인 문장과 아랍어 번역을 제공합니다:\"]', '[\"관광\", \"사진 촬영\", \"티켓 구매\"]', 'ko', '[\"현재, 티켓 가격에 대해 묻는 것, 주차장 찾기, 또는 투어 가이드 서비스처럼 구체적인 상황을 생각하고 계신가요? 자유롭게 물어보세요.\", \"제가 생각하는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"كم تكلفة الدخول؟\"}, {\"original\": \"학생 할인 티켓이 있나요?\", \"translated\": \"هل هناك تذاكر للطلاب متاحة؟\"}, {\"original\": \"이 관광지가 몇 시에 열어요?\", \"translated\": \"متى يفتح هذا المكان؟\"}, {\"original\": \"여기서 할 수 있는 재미있는 활동은 뭔가요?\", \"translated\": \"ما هي الأنشطة الممتعة التي يمكن القيام بها هنا؟\"}, {\"original\": \"우리 사진을 찍어줄 수 있나요?\", \"translated\": \"هل يمكنك التقاط صورة لنا؟\"}, {\"original\": \"관광버스는 어디에 있나요?\", \"translated\": \"أين يوجد حافلة الرحلات السياحية؟\"}, {\"original\": \"화장실은 어디에 있나요?\", \"translated\": \"أين находится دور الحمام؟\"}, {\"original\": \"가장 좋은 전망지는 어디인가요?\", \"translated\": \"أين أفضل مكان للنظر؟\"}, {\"original\": \"여기 경치가 아름다워요.\", \"translated\": \"المناظر الطبيعية هنا جميلة.\"}, {\"original\": \"가이드 투어가 있나요?\", \"translated\": \"هل هناك جولة موجهة متاحة؟\"}]', 5, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"택시나 택시 서비스에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 택시나 택시 서비스와 관련된 10개의 일반적인 문장과 아랍어 번역이 있습니다:\"]', '[\"택시 타기\", \"목적지 말하기\", \"결제\"]', 'ko', '[\"지금은, 목적지 요청, 요금 확인 또는 송장 요청과 같은 것을 가장 원하시는 것이 무엇입니까, 자유롭게 물어보세요.\", \"마음속에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"택시를 어디서 탈 수 있나요?\", \"translated\": \"أين يمكنني الحصول على سيارة أجرة؟\"}, {\"original\": \"이 주소로 저를 데려가 주세요.\", \"translated\": \"الرجاء أخذني إلى العنوان هذا.\"}, {\"original\": \"얼마나 될까요?\", \"translated\": \"كم تكلفة الرحلة تقريبًا؟\"}, {\"original\": \"계산기를 사용해 주시겠어요?\", \"translated\": \"هل يمكنك استخدام العداد، من فضلك؟\"}, {\"original\": \"조금 더 빨리 운전해 주세요, 저는 서둘러야 해요.\", \"translated\": \"الرجاء القيادة بسرعة قليلاً، أنا في عجلة.\"}, {\"original\": \"여기서 멈춰 주세요.\", \"translated\": \"الرجاء التوقف هنا.\"}, {\"original\": \"카드나 모바일 결제를 받으세요?\", \"translated\": \"هل تقبل البطاقات أو الدفع عبر الهاتف المحمول؟\"}, {\"original\": \"영수증을 주실 수 있나요?\", \"translated\": \"هل يمكنني الحصول على إيصال، من فضلك؟\"}, {\"original\": \"감사합니다, 운전자님.\", \"translated\": \"شكرًا لك، سائق.\"}, {\"original\": \"여기까지 얼마나 더 가야 하나요?\", \"translated\": \"كم يبقى حتى الوصول؟\"}]', 6, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"약국에서 사용할 수 있는 10가지 일반 문장을 제공해 주실 수 있나요?\", \"좋습니다! 약국과 관련된 10가지 일반 문장과 아랍어 번역을 드립니다:\"]', '[\"약 구매\", \"상담\", \"결제\"]', 'ko', '[\"현재까지, 특정 상황이 있으신가요? 예를 들어, 약물 복용 방법을 묻는 경우, 보험 관련 문장, 약물 복용 기간 등 자유롭게 물어보세요.\", \"제 마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"감기약이 있습니까?\", \"translated\": \"هل لديك أدوية لعلاج نزلات البرد؟\"}, {\"original\": \"이 약은 어떻게 복용해야 하나요?\", \"translated\": \"كيف يجب أن أتناول هذا الدواء؟\"}, {\"original\": \"진통제가 있습니까?\", \"translated\": \"هل لديك مسكنات للألم؟\"}, {\"original\": \"사용 설명서가 있습니까?\", \"translated\": \"هل هناك ورقة تعليمات؟\"}, {\"original\": \"이 약에 부작용이 있습니까?\", \"translated\": \"هل لهذا الدواء آثار جانبية؟\"}, {\"original\": \"내 의료 보험 카드를 사용할 수 있나요?\", \"translated\": \"يمكنني استخدام بطاقة التأمين الصحي الخاصة بي؟\"}, {\"original\": \"붕대 한 상자 주세요.\", \"translated\": \"هل يمكنني الحصول على علبة من الضمادات الطبية، من فضلك؟\"}, {\"original\": \"열 내리는 약이 있습니까?\", \"translated\": \"هل لديك أدوية لتقليل الحمى؟\"}, {\"original\": \"조금 까져요. 소독약과 붕대가 있습니까?\", \"translated\": \"لديّ بعض الجروح. هل لديك مضاد للبكتيريا وضمادات طبية؟\"}, {\"original\": \"언제 문을 닫으십니까?\", \"translated\": \"ما الوقت الذي تغلقون فيه؟\"}]', 7, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"응급 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있습니까?\", \"좋습니다! 응급 서비스와 관련된 10가지 일반적인 문장과 아랍어 번역을 아래에 소개합니다:\"]', '[\"경찰 호출\", \"응급 처치\", \"도움 요청\"]', 'ko', '[\"현재, 당신이 생각하는 특정한 응급 상황이 있는지, 예를 들어 화재, 부상 및 도움이 필요한 경우, 응급 전화 등, 자유롭게 물어보세요.\", \"심각한 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"응급차를 불러줘.\", \"translated\": \"الرجاء مساعدتي في طلب سيارة إسعاف.\"}, {\"original\": \"병원은 어디예요?\", \"translated\": \"أين المستشفى؟\"}, {\"original\": \"누군가 다쳤어요.\", \"translated\": \"شخص ما أصيب.\"}, {\"original\": \"도와주세요.\", \"translated\": \"الرجاء مساعدتي.\"}, {\"original\": \"경찰서는 어디예요?\", \"translated\": \"أين مركز الشرطة؟\"}, {\"original\": \"내 소지품을 잃어버렸어요.\", \"translated\": \"قدت فقدت أشيائي.\"}, {\"original\": \"소방서 전화번호는 무엇인가요?\", \"translated\": \"ما هو الرقم الخاص بقسم الحريق؟\"}, {\"original\": \"여권을 잃어버렸어요. 가장 가까운 경찰서는 어디인가요?\", \"translated\": \"فقدت جوازي السفر. هل تعرف أين يقع أقرب مركز شرطة؟\"}, {\"original\": \"비상출구는 어디예요?\", \"translated\": \"هل هناك مخرج طوارئ؟\"}, {\"original\": \"누군가 기절했어요.\", \"translated\": \"شخص ما فقد وعيه.\"}]', 8, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"비치 또는 수영장가에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 비치 또는 수영장가와 관련된 10개의 일반적인 문장과 아랍어 번역을 제공합니다:\"]', '[\"수영\", \"태양광 쬐기\", \"해변 스포츠\"]', 'ko', '[\"지금은, 참석하는 지역 이벤트 또는 축제의 맥락을 제공해 주시겠어요? 예를 들어 문화 축제, 음식 축제 또는 음악 축제 등입니다. 맥락을 제공해 주세요.\", \"참석하는 활동을 알려주세요.\"]', '[\"특정 상황이 마음에 있는지 여부를 묻습니다. 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', '[{\"original\": \"보라! 저쪽 파도가 정말 크다.\", \"translated\": \"انظر! الأمواج هناك كبيرة جداً.\"}, {\"original\": \"자외선 차단제를 바르세요, 여기 자외선이 매우 강합니다.\", \"translated\": \"تذكر أن تضع كريم الحماية من أشعة الشمس، الأشعة فوق البنفسجية هنا قوية جداً.\"}, {\"original\": \"이 해변의 모래는 매우 미세해서 마치 쿠션 위에 서 있는 것처럼 느껴집니다.\", \"translated\": \"رمال هذه الشاطئة ناعمة جداً، إنها تشبه المشي على قطن.\"}, {\"original\": \"해변에서 배구를 하기 어때요?\", \"translated\": \"كيف يكون من رمي الكرة على الشاطئ؟\"}, {\"original\": \"멀리 있는 요트들이 아름답게 보입니다.\", \"translated\": \"السفن الشراعية في الأفق تبدو جميلة.\"}, {\"original\": \"여기 물이 매우 맑아서 물고기를 볼 수 있습니다.\", \"translated\": \"الماء هنا واضح جداً، يمكنك رؤية الأسماك حتى.\"}, {\"original\": \"시해조를 찾아보자.\", \"translated\": \"لنذهب بحثاً عن قواقع البحر.\"}, {\"original\": \"일몰 시간대에 해변을 산책하는 것은 매우 로맨틱할 것입니다.\", \"translated\": \"التنزه على الشاطئ عند غروب الشمس يجب أن يكون ممتعاً جداً.\"}, {\"original\": \"여기 해산물이 매우 신선하다는 걸 들었어요, 가서 먹어보죠.\", \"translated\": \"سمعت أن المأكولات البحرية هنا طازجة جداً، دعنا نجرب بعضها.\"}, {\"original\": \"조수 간조가 오고 있으니, 해안으로 향합시다.\", \"translated\": \"المد يقترب، دعنا نتجه نحو الشاطئ.\"}]', 9, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"로컬 이벤트 및 축제에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋습니다! 로컬 이벤트 및 축제와 관련된 10가지 일반적인 표현과 아랍어 번역을 드립니다:\"]', '[\"이벤트 참석\", \"절기 축하\", \"문화 배우기\"]', 'ko', '[\"현재, 귀하가 참석하는 로컬 이벤트 또는 축제의 맥락을 제공해 주시겠습니까? 예를 들어 할로윈, 콘서트 또는 친구 파티, 또는 기타 어떤 것이라도 말입니다. 맥락을 제공해 주세요.\", \"당신이 생각하는 활동을 설명해 주세요.\"]', '[\"특정 상황이 마음에 있는지 여부를 묻습니다. 자유롭게 물어보세요.\", \"당신이 생각하는 상황을 설명해 주세요.\"]', '[{\"original\": \"오늘 행사가 있나요?\", \"translated\": \"هل هناك أحداث اليوم؟\"}, {\"original\": \"이 축제에는 특별한 점이 있나요?\", \"translated\": \"هل هناك شيء خاص عن هذا العيد؟\"}, {\"original\": \"축제는 어디에서 열리나요?\", \"translated\": \"أين تُقام الاحتفالات؟\"}, {\"original\": \"티켓을 어떻게 구할 수 있나요?\", \"translated\": \"كيف يمكنني شراء التذاكر؟\"}, {\"original\": \"공연은 몇 시에 시작하나요?\", \"translated\": \"متى تبدأ العرض؟\"}, {\"original\": \"이곳에 어떤 전통 음식이 있나요?\", \"translated\": \"ما هي الأطعمة التقليدية الموجودة؟\"}, {\"original\": \"여기 정말 활기가 넘치네요.\", \"translated\": \"هنا مزدحم حقًا.\"}, {\"original\": \"전통적인 활동이 있나요?\", \"translated\": \"هل هناك أي أنشطة شعبية؟\"}, {\"original\": \"즐거운 명절 되세요!\", \"translated\": \"أهنئك بأعياد سعيدة!\"}, {\"original\": \"행사는 몇 시에 끝나나요?\", \"translated\": \"متى تنتهي الحدث؟\"}]', 10, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"박물관 또는 미술관에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 박물관 또는 미술관과 관련된 10개의 일반적인 문장과 아랍어 번역을 드립니다:\"]', '[\"방문\", \"가이드 투어\", \"티켓 구매\"]', 'ko', '[\"지금은 특정 상황이 떠오르시나요, 예를 들어 안내서 요청, 로드맵 관련 문장, 전시품에 대한 의견 관련 문장 등 자유롭게 물어보세요.\", \"심중에 생각하고 계신 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"كم تبلغ تكلفة الدخول؟\"}, {\"original\": \"오디오 가이드가 있나요?\", \"translated\": \"هل لديكم أدوات صوتية للاستكشاف؟\"}, {\"original\": \"이 작품을 만든 사람은 누구인가요?\", \"translated\": \"من قام بإنشاء هذا العمل الفني؟\"}, {\"original\": \"이 박물관에서 가장 소중한 작품은 어디에 있나요?\", \"translated\": \"أين يقع أفضل قطعة في المتحف؟\"}, {\"original\": \"사진 촬영이 가능한가요?\", \"translated\": \"هل مسموح بالتصوير الفوتوغرافي؟\"}, {\"original\": \"여기 특별 전시회가 있나요?\", \"translated\": \"هل هناك معارض خاصة هنا؟\"}, {\"original\": \"방문에 얼마나 시간이 걸리나요?\", \"translated\": \"كم تستغرق الزيارة؟\"}, {\"original\": \"우리에게 소개를 해주실 수 있나요?\", \"translated\": \"هل يمكنك إعطائنا مقدمة؟\"}, {\"original\": \"이 작품들은 정말 아름답습니다.\", \"translated\": \"هذه الأعمال فعلاً رائعة.\"}, {\"original\": \"기념품 가게는 어디에 있나요?\", \"translated\": \"أين متجر التذكارات؟\"}]', 11, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"카페에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 카페와 관련된 10가지 일반적인 문장과 아랍어 번역을 제공합니다:\"]', '[\"커피 주문\", \"휴식\", \"사회적 활동\"]', 'ko', '[\"현재까지, 특정 상황이 있으신가요? 예를 들어 메뉴 요청, 얼음 음료 또는 뜨거운 음료, 기타 제품, 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"제가 라테 한 잔 주세요.\", \"translated\": \"سأطلب كوب كابتشينو، من فضلك.\"}, {\"original\": \"와이파이 있으세요?\", \"translated\": \"هل لديكم واي فاي؟\"}, {\"original\": \"메뉴 좀 보여주실 수 있나요?\", \"translated\": \"هل يمكنني رؤية القائمة، من فضلك؟\"}, {\"original\": \"리필 가능하세요?\", \"translated\": \"هل يسمح بإعادة الملء؟\"}, {\"original\": \"제 커피 준비됐나요?\", \"translated\": \"هل قهوتي جاهزة؟\"}, {\"original\": \"이곳에서 얼마나 오래 앉을 수 있나요?\", \"translated\": \"كم من الوقت يمكنني الجلوس هنا؟\"}, {\"original\": \"우리 사진 좀 찍어줄 수 있나요?\", \"translated\": \"هل يمكنك التقاط صورة لنا؟\"}, {\"original\": \"화장실은 어디에요?\", \"translated\": \"أين دورة المياه؟\"}, {\"original\": \"계산해 주세요. 감사합니다.\", \"translated\": \"الحساب، من فضلك. شكرًا.\"}, {\"original\": \"진짜 맛있어요.\", \"translated\": \"تذوقها بشكل رائع.\"}]', 12, 'ar');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"저에게 식당에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 식당과 관련된 10가지 일반적인 문장과 함께 프랑스어 번역을 제공합니다:\"]', '[\"식사\", \"주문\", \"결제\"]', 'ko', '[\"지금은, 특정 상황이 마음에 드시는지 궁금합니다. 예를 들어 음료 주문, 불만 제기 또는 재료에 대한 질문 등 자유롭게 묻고 싶으신 상황을 설명해 주세요.\", \"마음에 떠오르는 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"실례합니다, 음식은 얼마나 더 오래 걸릴까요?\", \"translated\": \"Excusez-moi, combien de temps encore notre nourriture va-t-elle prendre ?\"}, {\"original\": \"두 분을 위한 테이블을 부탁드립니다.\", \"translated\": \"Une table pour deux, s\'il vous plaît.\"}, {\"original\": \"메뉴를 보여주실 수 있겠어요?\", \"translated\": \"Pouvez-vous nous montrer le menu, s\'il vous plaît ?\"}, {\"original\": \"추천할 만한 특별한 요리가 있나요?\", \"translated\": \"Avez-vous des plats signature à recommander ?\"}, {\"original\": \"이것과 이것을 주문하고 싶어요.\", \"translated\": \"Je voudrais commander celui-ci, et celui-là.\"}, {\"original\": \"물 한 잔 부탁드려요. 감사합니다.\", \"translated\": \"Un verre d\'eau, s\'il vous plaît. Merci.\"}, {\"original\": \"계산서를 주세요.\", \"translated\": \"L\'addition, s\'il vous plaît.\"}, {\"original\": \"신용카드로 결제할 수 있나요?\", \"translated\": \"Puis-je payer par carte de crédit ?\"}, {\"original\": \"이걸 포장해 주실 수 있나요?\", \"translated\": \"Pourriez-vous emballer cela à emporter, s\'il vous plaît ?\"}, {\"original\": \"음식이 정말 맛있었어요, 감사합니다.\", \"translated\": \"La nourriture était délicieuse, merci.\"}]', 1, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"호텔에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 호텔과 관련된 10가지 일반적인 문장과 프랑스어 번역을 제공합니다:\"]', '[\"체크인\", \"체크아웃\", \"객실 서비스\"]', 'ko', '[\"지금은, 방 위치, 다른 호텔 서비스 또는 체크아웃과 같은 구체적인 상황이 있으신가요? 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"안녕하세요, 예약이 있습니다, 여권을 드릴게요.\", \"translated\": \"Bonjour, j\'ai une réservation, voici mon passeport.\"}, {\"original\": \"예약 가능한 객실이 있습니까?\", \"translated\": \"Avez-vous des chambres disponibles ?\"}, {\"original\": \"실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\", \"translated\": \"Pardon, l\'hôtel a-t-il une salle de gym ou une buanderie ?\"}, {\"original\": \"아침 식사가 몇 시부터 시작됩니까?\", \"translated\": \"À quelle heure le petit-déjeuner commence-t-il ?\"}, {\"original\": \"방 키를 좀 주시겠어요?\", \"translated\": \"Pourriez-vous me donner une clé de chambre, s\'il vous plaît ?\"}, {\"original\": \"내 짐을 방까지 도와줄 수 있겠어요?\", \"translated\": \"Pourriez-vous m\'aider à porter mes bagages dans la chambre ?\"}, {\"original\": \"객실 서비스를 부르는 방법은 무엇입니까?\", \"translated\": \"Comment appelle-t-on le service de chambre ?\"}, {\"original\": \"체크아웃 시간은 언제입니까?\", \"translated\": \"À quelle heure est le check-out ?\"}, {\"original\": \"영수증/세금계산서를 만들어 주실 수 있겠어요?\", \"translated\": \"Pourriez-vous me rédiger un reçu/facture ?\"}, {\"original\": \"저의 짐을 여기 두어도 괜찮을까요?\", \"translated\": \"Puis-je laisser mes bagages ici ?\"}]', 2, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공항에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 공항과 관련된 10가지 일반적인 문장과 프랑스어 번역을 제공합니다:\"]', '[\"체크인\", \"승실\", \"수화물 체크\"]', 'ko', '[\"현재, 체크인, 수하물 수령, 자동차 대여 서비스와 같은 구체적인 상황이 있으신가요? 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"체크인 카운터는 어디입니까?\", \"translated\": \"Où est le comptoir d\'enregistrement ?\"}, {\"original\": \"창가 좌석을 원합니다.\", \"translated\": \"Je voudrais un siège près du hublot, s\'il vous plaît.\"}, {\"original\": \"이 항공편은 지연되었나요?\", \"translated\": \"Ce vol est-il retardé ?\"}, {\"original\": \"이 수화물을 확인해야 합니다.\", \"translated\": \"Je dois enregistrer cette bagage.\"}, {\"original\": \"승객 탑승 게이트는 어디입니까?\", \"translated\": \"Où est la porte d\'embarquement ?\"}, {\"original\": \"비행기가 바로 이륙할 예정입니다.\", \"translated\": \"L\'avion va bientôt décoller.\"}, {\"original\": \"노트북과 충전식 배터리를 꺼내야 하나요?\", \"translated\": \"Dois-je sortir mon ordinateur portable et ma batterie externe ?\"}, {\"original\": \"무세금 쇼핑점은 어디입니까?\", \"translated\": \"Où se trouve le magasin de douane ?\"}, {\"original\": \"내 수화물을 찾을 수 없습니다.\", \"translated\": \"Je ne trouve pas mon bagage.\"}, {\"original\": \"휠체어 서비스를 제공하나요?\", \"translated\": \"Avez-vous un service de fauteuil roulant ?\"}]', 3, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"대중교통에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 대중교통과 관련된 10가지 일반적인 문장과 프랑스어 번역을 드립니다:\"]', '[\"버스/지하철 탑승\", \"티켓 구매\", \"환승\"]', 'ko', '[\"지금은, 특정 상황이 있으신가요? 예를 들어 버스 정류장에 대한 문의, 티켓 가격, 하차 등 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"이 버스는 터미널로 가나요?\", \"translated\": \"Ce bus va-t-il au terminal ?\"}, {\"original\": \"다음 정류장은 어디예요?\", \"translated\": \"Quelle est la prochaine arrêt ?\"}, {\"original\": \"어디에서 티켓을 살 수 있나요?\", \"translated\": \"Où puis-je acheter un billet ?\"}, {\"original\": \"XX까지 한 장의 티켓을 주세요.\", \"translated\": \"Un billet pour XX, s\'il vous plaît.\"}, {\"original\": \"환승해야 하나요?\", \"translated\": \"Est-ce que je dois changer de ligne ?\"}, {\"original\": \"다음 지하철 열차는 얼마나 걸리나요?\", \"translated\": \"Combien de temps avant le prochain train de métro ?\"}, {\"original\": \"실례합니다, 지나가도 될까요?\", \"translated\": \"Pardon, laissez-moi passer.\"}, {\"original\": \"이 자리에 누가 앉았나요?\", \"translated\": \"Cette place est-elle occupée ?\"}, {\"original\": \"실례합니다, XX에 가기 위해 2호선으로 어디에서 환승해야 하나요?\", \"translated\": \"Pardon, où puis-je changer pour la ligne 2 afin d\'aller à XX ?\"}, {\"original\": \"XX에 어떻게 가면 되나요?\", \"translated\": \"Comment puis-je aller à XX ?\"}]', 4, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"관광지에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 관광지와 관련된 10가지 일반적인 문장과 프랑스어 번역을 드립니다:\"]', '[\"관광하기\", \"사진 찍기\", \"티켓 구매\"]', 'ko', '[\"지금은, 특정 상황이 생각나시는지 궁금합니다. 예를 들어, 티켓 가격 문의, 주차장 찾기, 또는 투어 가이드 서비스 등 자유롭게 물어보세요.\", \"심중에 생각하시는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"Combien coûte l\'entrée ?\"}, {\"original\": \"학생 할인 티켓이 있나요?\", \"translated\": \"Y a-t-il des billets étudiants disponibles ?\"}, {\"original\": \"이 관광지가 언제 개장하나요?\", \"translated\": \"À quelle heure l\'attraction ouvre-t-elle ?\"}, {\"original\": \"여기서 할 수 있는 재미있는 일은 무엇인가요?\", \"translated\": \"Quelles sont les choses amusantes à faire ici ?\"}, {\"original\": \"우리 사진을 찍어 줄 수 있나요?\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"관광버스는 어디에 있나요?\", \"translated\": \"Où se trouve le bus de tourisme ?\"}, {\"original\": \"화장실은 어디에 있나요?\", \"translated\": \"Où se trouvent les toilettes ?\"}, {\"original\": \"가장 좋은 전망지는 어디인가요?\", \"translated\": \"Où est le meilleur endroit pour admirer le paysage ?\"}, {\"original\": \"이곳의 경치가 아름답네요.\", \"translated\": \"Le paysage ici est magnifique.\"}, {\"original\": \"가이드 투어가 있나요?\", \"translated\": \"Y a-t-il une visite guidée disponible ?\"}]', 5, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"택시나 택시 서비스에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있습니까?\", \"좋습니다! 택시나 택시 서비스와 관련된 10개의 일반적인 문장과 프랑스어 번역을 제공합니다:\"]', '[\"택시 타기\", \"목적지 말하기\", \"결제\"]', 'ko', '[\"지금, 목적지 요청, 요금 확인 또는 세금계산서 요청과 같은 것을 가장 원하시는 것이 무엇입니까, 자유롭게 물어보세요.\", \"마음속에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"택시를 어디서 탈 수 있나요?\", \"translated\": \"Où puis-je prendre un taxi ?\"}, {\"original\": \"이 주소로 저를 데려가 주세요.\", \"translated\": \"S\'il vous plaît, amenez-moi à cette adresse.\"}, {\"original\": \"얼마나 더 걸리나요?\", \"translated\": \"Environ combien cela coûtera-t-il ?\"}, {\"original\": \"계기장 사용해 주시겠어요?\", \"translated\": \"Pourriez-vous utiliser le compteur, s\'il vous plaît ?\"}, {\"original\": \"좀 더 빨리 운전해 주세요, 저는 급한 일이 있어요.\", \"translated\": \"S\'il vous plaît, roulez un peu plus vite, je suis pressé.\"}, {\"original\": \"여기서 멈춰 주세요.\", \"translated\": \"S\'il vous plaît, arrêtez ici.\"}, {\"original\": \"카드나 모바일 결제를 받으세요?\", \"translated\": \"Acceptez-vous les cartes ou les paiements mobiles ?\"}, {\"original\": \"영수증을 주실 수 있나요?\", \"translated\": \"Pouvez-vous me donner un reçu, s\'il vous plaît ?\"}, {\"original\": \"감사합니다, 운전사님.\", \"translated\": \"Merci, monsieur le conducteur.\"}, {\"original\": \"얼마나 더 가야 하나요?\", \"translated\": \"Cela fait combien de temps encore ?\"}]', 6, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"약국에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 약국과 관련된 10가지 일반적인 문장과 프랑스어 번역을 제공합니다:\"]', '[\"약 구입\", \"상담\", \"결제\"]', 'ko', '[\"지금은, 약을 복용하는 방법에 대해 묻는 것, 보험과 관련된 문장, 약물의 지속 기간 등 특정 상황이 있으신가요? 자유롭게 질문하십시오.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"감기 약이 있습니까?\", \"translated\": \"Avez-vous des médicaments contre le rhume ?\"}, {\"original\": \"이 약은 어떻게 복용해야 하나요?\", \"translated\": \"Comment dois-je prendre ce médicament ?\"}, {\"original\": \"진통제가 있습니까?\", \"translated\": \"Avez-vous des analgésiques ?\"}, {\"original\": \"사용 설명서가 있습니까?\", \"translated\": \"Y a-t-il une notice d\'instructions ?\"}, {\"original\": \"이 약에 부작용이 있습니까?\", \"translated\": \"Ce médicament a-t-il des effets secondaires ?\"}, {\"original\": \"내 의료 보험 카드를 사용할 수 있습니까?\", \"translated\": \"Puis-je utiliser ma carte d\'assurance maladie ?\"}, {\"original\": \"붕대 상자 하나 주실 수 있겠어요?\", \"translated\": \"Pourriez-vous me donner une boîte de pansements, s\'il vous plaît ?\"}, {\"original\": \"발열 완화제가 있습니까?\", \"translated\": \"Avez-vous des médicaments pour la fièvre ?\"}, {\"original\": \"조금 벗어난 곳이 있어요. 항균제와 붕대가 있습니까?\", \"translated\": \"J\'ai un petit éraflure. Avez-vous un antiseptique et des pansements ?\"}, {\"original\": \"언제 문을 닫습니까?\", \"translated\": \"À quelle heure fermez-vous ?\"}]', 7, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"응급 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 응급 서비스와 관련된 10가지 일반적인 문장과 프랑스어 번역을 드립니다:\"]', '[\"경찰 호출\", \"응급처치\", \"도움 요청\"]', 'ko', '[\"지금은 특정한 응급 상황을 생각하고 계신가요? 예를 들어 화재, 부상 및 도움이 필요한 경우, 응급 전화 등 자유롭게 질문해 주세요.\", \"심상에 있는 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"응급차를 불러줘.\", \"translated\": \"Aidez-moi à appeler une ambulance.\"}, {\"original\": \"병원은 어디야?\", \"translated\": \"Où se trouve l\'hôpital ?\"}, {\"original\": \"누군가 부상당했어.\", \"translated\": \"Une personne est blessée.\"}, {\"original\": \"도와줘.\", \"translated\": \"Aidez-moi s\'il vous plaît.\"}, {\"original\": \"경찰서는 어디야?\", \"translated\": \"Où se trouve le commissariat de police ?\"}, {\"original\": \"내 소지품을 잃어버렸어.\", \"translated\": \"J\'ai perdu mes affaires.\"}, {\"original\": \"소방서 번호는 뭐야?\", \"translated\": \"Quel est le numéro du service des pompiers ?\"}, {\"original\": \"여권을 잃어버렸어. 가까운 경찰서는 어디야?\", \"translated\": \"J\'ai perdu mon passeport. Savez-vous où se trouve le commissariat de police le plus proche ?\"}, {\"original\": \"비상 출구는 어디야?\", \"translated\": \"Y a-t-il une sortie de secours ?\"}, {\"original\": \"누군가 쓰러졌어.\", \"translated\": \"Une personne s\'est évanouie.\"}]', 8, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"비치 또는 수영장가에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 비치 또는 수영장가와 관련된 10개의 일반적인 문장과 프랑스어 번역을 제공합니다:\"]', '[\"수영\", \"태양광 쬐기\", \"해변 스포츠\"]', 'ko', '[\"지금은, 참석하는 지역 이벤트나 축제의 맥락을 제공해 주시겠습니까? 예를 들어 문화 축제, 음식 축제 또는 음악 축제 등입니다. 맥락을 제공해 주세요.\", \"참석하는 활동을 알려주세요.\"]', '[\"특정 상황이 마음에 드십니까? 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', '[{\"original\": \"보라! 저쪽의 파도가 정말 크다.\", \"translated\": \"Regardez ! Les vagues là-bas sont vraiment grandes.\"}, {\"original\": \"자외선 차단제를 바르세요, 여기 자외선이 매우 강합니다.\", \"translated\": \"N’oubliez pas d’appliquer de la crème solaire, les rayons UV ici sont très forts.\"}, {\"original\": \"이 해변의 모래는 매우 미끄러워서 마치 솜처럼 발에 닿는 느낌이다.\", \"translated\": \"Le sable de cette plage est si fin qu’il ressemble à du coton.\"}, {\"original\": \"해변에서 배구를 하기 어때?\", \"translated\": \"Que diriez-vous de jouer au volley-ball sur la plage ?\"}, {\"original\": \"멀리 있는 요트들이 아름답게 보인다.\", \"translated\": \"Les voiliers à l’horizon ont l’air beaux.\"}, {\"original\": \"여기 물은 매우 맑아서 물고기를 볼 수 있다.\", \"translated\": \"L’eau ici est si claire que vous pouvez même voir les poissons.\"}, {\"original\": \"해조류를 찾아보자.\", \"translated\": \"Allons chercher des coquillages.\"}, {\"original\": \"일몰 때 해변을 산책하는 것은 매우 로맨틱할 것이다.\", \"translated\": \"Faire une promenade sur la plage au coucher du soleil doit être très romantique.\"}, {\"original\": \"여기 해산물이 매우 신선하다는 걸 들었으니, 가서 먹어보자.\", \"translated\": \"J’ai entendu dire que le poisson ici est très frais, allons en essayer.\"}, {\"original\": \"조수 간만이 들어오고 있으니, 해안으로 가자.\", \"translated\": \"La marée monte, allons vers la plage.\"}]', 9, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"로컬 이벤트와 페스티벌에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋습니다! 로컬 이벤트와 페스티벌과 관련된 10가지 일반적인 표현과 함께 프랑스어 번역을 제공합니다:\"]', '[\"이벤트 참석\", \"절기 축하하기\", \"문화 배우기\"]', 'ko', '[\"현재, 로컬 이벤트 또는 페스티벌에 참석하는 상황을 알려주실 수 있겠습니까? 예를 들어 할로윈, 콘서트, 친구 파티 또는 기타 사항이 있습니까? 상황을 제공해 주세요.\", \"당신의 마음에 떠오르는 활동을 설명해 주세요.\"]', '[\"특정 상황이 마음에 드시나요? 자유롭게 물어보세요.\", \"당신의 마음에 떠오르는 상황을 설명해 주세요.\"]', '[{\"original\": \"오늘 이벤트가 있나요?\", \"translated\": \"Y a-t-il des événements aujourd\'hui ?\"}, {\"original\": \"이 축제에 특별한 점이 있나요?\", \"translated\": \"Y a-t-il quelque chose de spécial à propos de ce festival ?\"}, {\"original\": \"축제는 어디에서 열리나요?\", \"translated\": \"Où a lieu la célébration ?\"}, {\"original\": \"티켓을 어떻게 구할 수 있나요?\", \"translated\": \"Comment puis-je acheter des billets ?\"}, {\"original\": \"공연은 몇 시에 시작하나요?\", \"translated\": \"À quelle heure commence la performance ?\"}, {\"original\": \"이곳에 어떤 전통 음식이 있나요?\", \"translated\": \"Quel est le plat traditionnel disponible ?\"}, {\"original\": \"여기 정말 분위기가 좋네요.\", \"translated\": \"C\'est vraiment animé ici.\"}, {\"original\": \"전통적인 활동이 있나요?\", \"translated\": \"Y a-t-il des activités folkloriques ?\"}, {\"original\": \"명절 인사 드립니다!\", \"translated\": \"Belles vacances !\"}, {\"original\": \"이벤트는 몇 시에 끝나나요?\", \"translated\": \"À quelle heure l\'événement se termine-t-il ?\"}]', 10, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"박물관 또는 미술관에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 박물관 또는 미술관과 관련된 10가지 일반적인 문장과 함께 프랑스어 번역을 제공합니다:\"]', '[\"방문\", \"가이드 투어\", \"티켓 구매\"]', 'ko', '[\"지금은, 특정 상황이 생각나시는지요? 예를 들어 안내 매뉴얼 요청, 로드맵과 관련된 문장, 전시품에 대한 의견을 표현하는 문장 등 자유롭게 물어보세요.\", \"마음속에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"Combien coûte l\'entrée ?\"}, {\"original\": \"오디오 가이드가 있나요?\", \"translated\": \"Avez-vous des guides audio ?\"}, {\"original\": \"이 작품을 만든 사람은 누구인가요?\", \"translated\": \"Qui a créé cette œuvre d\'art ?\"}, {\"original\": \"이 박물관의 가장 값진 작품은 어디에 있나요?\", \"translated\": \"Où se trouve la pièce la plus précieuse du musée ?\"}, {\"original\": \"사진 촬영이 가능한가요?\", \"translated\": \"La photographie est-elle autorisée ?\"}, {\"original\": \"여기 특별 전시회가 있나요?\", \"translated\": \"Y a-t-il des expositions spéciales ici ?\"}, {\"original\": \"방문에 얼마나 시간이 걸리나요?\", \"translated\": \"Combien de temps dure la visite ?\"}, {\"original\": \"우리에게 소개를 해주실 수 있나요?\", \"translated\": \"Pourriez-vous nous faire une introduction ?\"}, {\"original\": \"이 작품들은 정말 아름답습니다.\", \"translated\": \"Ces œuvres sont vraiment exquises.\"}, {\"original\": \"기념품 가게는 어디에 있나요?\", \"translated\": \"Où se trouve le magasin de souvenirs ?\"}]', 11, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"카페에서 사용할 수 있는 10가지 일반적인 문구를 제공해 주실 수 있나요?\", \"좋아요! 카페와 관련된 10가지 일반적인 문구와 프랑스어 번역을 아래에 나열해 드립니다:\"]', '[\"커피 주문\", \"휴식\", \"사회적 활동\"]', 'ko', '[\"현재, 메뉴를 요청하거나 아이스 또는 핫 음료, 기타 제품에 대해 묻는 등 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"심중에 생각하고 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"제가 라테 한 잔 주세요.\", \"translated\": \"Je voudrais un latte, s\'il vous plaît.\"}, {\"original\": \"와이파이 있으세요?\", \"translated\": \"Avez-vous du Wi-Fi ?\"}, {\"original\": \"메뉴 좀 보여주실 수 있나요?\", \"translated\": \"Pourriez-vous me montrer le menu, s\'il vous plaît ?\"}, {\"original\": \"리필 가능합니까?\", \"translated\": \"Les rafraîchissements sont-ils autorisés ?\"}, {\"original\": \"제 커피 준비되었나요?\", \"translated\": \"Mon café est-il prêt ?\"}, {\"original\": \"이곳에서 얼마나 오래 있을 수 있나요?\", \"translated\": \"Combien de temps puis-je rester ici ?\"}, {\"original\": \"우리 사진 좀 찍어줄 수 있나요?\", \"translated\": \"Pourriez-vous prendre une photo pour nous ?\"}, {\"original\": \"화장실은 어디에요?\", \"translated\": \"Où se trouve la salle de bain ?\"}, {\"original\": \"계산해 주세요. 감사합니다.\", \"translated\": \"L\'addition, s\'il vous plaît. Merci.\"}, {\"original\": \"맛있어요.\", \"translated\": \"Ça a vraiment bon goût.\"}]', 12, 'fr');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"식당에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주시겠습니까?\", \"좋습니다! 식당과 관련된 10가지 일반적인 표현과 독일어 번역을 아래에 나열합니다:\"]', '[\"식사\", \"주문\", \"결제\"]', 'ko', '[\"현재, 음료 주문, 불만 제기, 성분 문의 등 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"심중에 생각하고 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"실례합니다, 음식은 얼마나 더 오래 걸릴까요?\", \"translated\": \"Entschuldigung, wie viel länger wird unser Essen noch dauern?\"}, {\"original\": \"두 분을 위한 테이블을 부탁드립니다.\", \"translated\": \"Ein Tisch für zwei, bitte.\"}, {\"original\": \"메뉴를 보여주실 수 있겠어요?\", \"translated\": \"Können wir die Speisekarte sehen, bitte?\"}, {\"original\": \"추천할 만한 특별한 요리가 있나요?\", \"translated\": \"Haben Sie irgendwelche Signature Gerichte zu empfehlen?\"}, {\"original\": \"이것과 이것을 주문하고 싶어요.\", \"translated\": \"Ich möchte dies bestellen und das.\"}, {\"original\": \"물 한 잔 부탁드립니다. 감사합니다.\", \"translated\": \"Ein Glas Wasser, bitte. Danke.\"}, {\"original\": \"계산서 좀 주세요.\", \"translated\": \"Die Rechnung, bitte.\"}, {\"original\": \"신용카드로 결제할 수 있나요?\", \"translated\": \"Kann ich mit Kreditkarte zahlen?\"}, {\"original\": \"이걸 포장해 주실 수 있나요?\", \"translated\": \"Könnten Sie das bitte zum Mitnehmen verpacken?\"}, {\"original\": \"음식이 정말 맛있었어요. 감사합니다.\", \"translated\": \"Das Essen war lecker, danke.\"}]', 1, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"호텔에서 사용할 수 있는 10가지 일반적인 문구를 제공해 주시겠습니까?\", \"좋습니다! 호텔과 관련된 10가지 일반적인 문구와 독일어 번역을 아래에 나열합니다:\"]', '[\"체크인\", \"체크아웃\", \"객실 서비스\"]', 'ko', '[\"현재, 객실 위치, 다른 호텔 서비스 또는 체크아웃과 같은 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"머릿속에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"안녕하세요, 예약이 있습니다, 여기 여권입니다.\", \"translated\": \"Hallo, ich habe eine Reservierung, hier ist mein Pass.\"}, {\"original\": \"예약 가능한 객실이 있습니까?\", \"translated\": \"Haben Sie freie Zimmer?\"}, {\"original\": \"실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\", \"translated\": \"Entschuldigung, hat das Hotel ein Fitnessstudio oder eine Waschsalon?\"}, {\"original\": \"아침 식사가 몇 시부터 시작합니까?\", \"translated\": \"Um welche Uhrzeit beginnt das Frühstück?\"}, {\"original\": \"방 키를 좀 주실 수 있겠어요?\", \"translated\": \"Könnten Sie mir bitte einen Zimmerschlüssel geben?\"}, {\"original\": \"제 짐을 방으로 옮겨 주실 수 있겠어요?\", \"translated\": \"Können Sie mir helfen, mein Gepäck in das Zimmer zu bringen?\"}, {\"original\": \"룸서비스를 부르는 방법은 무엇입니까?\", \"translated\": \"Wie rufe ich den Zimmerservice an?\"}, {\"original\": \"체크아웃 시간은 언제입니까?\", \"translated\": \"Um welche Uhrzeit ist die Abreise?\"}, {\"original\": \"영수증/세금계산서를 작성해 주실 수 있겠어요?\", \"translated\": \"Können Sie mir eine Rechnung/Faktura schreiben?\"}, {\"original\": \"제 짐을 여기 두어도 괜찮나요?\", \"translated\": \"Kann ich mein Gepäck hier lassen?\"}]', 2, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공항에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주시겠습니까?\", \"좋습니다! 공항과 관련된 10가지 일반적인 표현과 독일어 번역을 드립니다:\"]', '[\"체크인\", \"승객 탑승\", \"수하물 수령\"]', 'ko', '[\"현재, 체크인, 수하물 인수 또는 차량 대여 서비스와 같은 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"심중에 생각하고 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"체크인 카운터는 어디입니까?\", \"translated\": \"Wo ist der Check-in-Schalter?\"}, {\"original\": \"창가 좌석을 원합니다.\", \"translated\": \"Ich möchte einen Fensterplatz, bitte.\"}, {\"original\": \"이 항공편이 지연되었나요?\", \"translated\": \"Ist dieses Flugzeug verzögert?\"}, {\"original\": \"이 수하물을 확인해야 합니다.\", \"translated\": \"Ich muss diesen Koffer abgeben.\"}, {\"original\": \"승객 탑승 게이트는 어디입니까?\", \"translated\": \"Wo ist die Boarding-Gate?\"}, {\"original\": \"비행기가 바로 이륙할 예정입니다.\", \"translated\": \"Das Flugzeug startet gleich.\"}, {\"original\": \"노트북과 충전기(파워뱅크)를 꺼내야 하나요?\", \"translated\": \"Muss ich meinen Laptop und den Akkupack herausnehmen?\"}, {\"original\": \"면세점은 어디입니까?\", \"translated\": \"Wo ist der Duty-Free-Shop?\"}, {\"original\": \"내 수하물이 보이지 않습니다.\", \"translated\": \"Ich kann meinen Koffer nicht finden.\"}, {\"original\": \"휠체어 서비스가 있습니까?\", \"translated\": \"Haben Sie einen Rollstuhl-Service?\"}]', 3, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공공교통에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 공공교통과 관련된 10가지 일반적인 문장과 독일어 번역을 제공합니다:\"]', '[\"버스/지하철 탑승\", \"티켓 구매\", \"환승\"]', 'ko', '[\"현재까지, 버스 정류장에 대한 질문, 티켓 가격, 하차 등과 같은 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"이 버스는 터미널로 가나요?\", \"translated\": \"Fährt dieser Bus zum Terminal?\"}, {\"original\": \"다음 정류장은 어디예요?\", \"translated\": \"Welche ist die nächste Haltestelle?\"}, {\"original\": \"티켓을 어디에서 살 수 있나요?\", \"translated\": \"Wo kann ich ein Ticket kaufen?\"}, {\"original\": \"제가 XX까지 티켓 하나 주세요.\", \"translated\": \"Ein Ticket nach XX, bitte.\"}, {\"original\": \"환승해야 하나요?\", \"translated\": \"Muss ich umsteigen?\"}, {\"original\": \"다음 지하철이 몇 분 후에 오나요?\", \"translated\": \"Wie lange noch bis zum nächsten U-Bahn-Train?\"}, {\"original\": \"실례합니다, 제가 지나갈 수 있게 해주세요.\", \"translated\": \"Entschuldigung, lassen Sie mich durch.\"}, {\"original\": \"이 자리에 사람이 앉았나요?\", \"translated\": \"Ist dieser Sitz belegt?\"}, {\"original\": \"실례합니다, 저는 XX에 가기 위해 2호선으로 환승할 수 있나요?\", \"translated\": \"Entschuldigung, wo kann ich umsteigen auf Linie 2, um nach XX zu kommen?\"}, {\"original\": \"어떻게 하면 XX에 갈 수 있나요?\", \"translated\": \"Wie komme ich nach XX?\"}]', 4, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"관광지에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 관광지와 관련된 10가지 일반적인 문장과 독일어 번역을 제공합니다:\"]', '[\"관광하기\", \"사진 찍기\", \"티켓 구매하기\"]', 'ko', '[\"현재, 티켓 가격에 대해 묻거나 주차장 찾기 또는 투어 가이드 서비스와 같은 구체적인 상황을 생각하고 계신가요, 자유롭게 물어보세요.\", \"상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"Wie viel kostet der Eintrittspreis?\"}, {\"original\": \"학생 할인 티켓이 있나요?\", \"translated\": \"Gibt es Studententickets?\"}, {\"original\": \"이 관광지가 몇 시에 열어요?\", \"translated\": \"Um wie viel Uhr öffnet die Sehenswürdigkeit?\"}, {\"original\": \"여기서 할 수 있는 재미있는 활동은 뭐예요?\", \"translated\": \"Was sind die lustigen Dinge, die man hier machen kann?\"}, {\"original\": \"우리 사진을 찍어줄 수 있나요?\", \"translated\": \"Können Sie ein Foto für uns machen?\"}, {\"original\": \"관광버스는 어디에 있어요?\", \"translated\": \"Wo ist der Sightseeing-Bus?\"}, {\"original\": \"화장실은 어디에 있어요?\", \"translated\": \"Wo ist die Toilette?\"}, {\"original\": \"가장 좋은 전망지는 어디예요?\", \"translated\": \"Wo ist der beste Aussichtspunkt?\"}, {\"original\": \"여기는 경치가 아름다워요.\", \"translated\": \"Die Landschaft hier ist wunderschön.\"}, {\"original\": \"가이드 투어가 있나요?\", \"translated\": \"Ist eine geführte Tour verfügbar?\"}]', 5, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"택시나 택시 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있습니까?\", \"좋아요! 택시나 택시 서비스와 관련된 10가지 일반적인 문장과 독일어 번역을 드립니다:\"]', '[\"택시 타기\", \"도착지 말하기\", \"결제\"]', 'ko', '[\"지금, 목적지 요청, 요금 묻기, 영수증 요청 등과 같은 것을 가장 원하시는 것은 무엇입니까, 자유롭게 물어보세요.\", \"마음속에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"택시를 어디서 탈 수 있나요?\", \"translated\": \"Wo kann ich ein Taxi bekommen?\"}, {\"original\": \"이 주소로 저를 데려가 주세요.\", \"translated\": \"Bitte fahren Sie mich zu dieser Adresse.\"}, {\"original\": \"大概多少钱？\", \"translated\": \"Etwa wie viel wird es kosten?\"}, {\"original\": \"계산기 사용해 주시겠어요?\", \"translated\": \"Können Sie bitte den Zähler verwenden?\"}, {\"original\": \"조금 더 빨리 운전해 주시겠어요? 저는 급한 일이 있어요.\", \"translated\": \"Bitte fahren Sie etwas schneller, ich bin in Eile.\"}, {\"original\": \"여기서 멈춰 주세요.\", \"translated\": \"Bitte halten Sie hier.\"}, {\"original\": \"카드나 모바일 결제를 받으세요?\", \"translated\": \"Akzeptieren Sie Karten oder Mobile Zahlungen?\"}, {\"original\": \"영수증 좀 주시겠어요?\", \"translated\": \"Kann ich eine Quittung haben, bitte?\"}, {\"original\": \"감사합니다, 기사님.\", \"translated\": \"Vielen Dank, Fahrer.\"}, {\"original\": \"얼마나 더 가야 하나요?\", \"translated\": \"Wie viel weiter ist es noch?\"}]', 6, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"약국에서 사용할 수 있는 10가지 일반적인 문구를 제공해 주시겠습니까?\", \"좋아요! 약국과 관련된 10가지 일반적인 문구와 독일어 번역을 드립니다:\"]', '[\"약 구매\", \"상담\", \"결제\"]', 'ko', '[\"지금은, 의약품 복용 방법에 대한 안내를 요청하거나 보험 관련 문구, 약물 복용 기간 등 특정 상황을 생각하고 계신가요? 자유롭게 물어보세요.\", \"심리적으로 생각하고 계신 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"냉감 약이 있습니까?\", \"translated\": \"Haben Sie kalte Medikamente?\"}, {\"original\": \"이 약은 어떻게 복용해야 하나요?\", \"translated\": \"Wie soll ich dieses Medikament einnehmen?\"}, {\"original\": \"진통제가 있습니까?\", \"translated\": \"Haben Sie Schmerztabletten?\"}, {\"original\": \"사용 설명서가 있습니까?\", \"translated\": \"Gibt es eine Gebrauchsanweisung?\"}, {\"original\": \"이 약에 부작용이 있습니까?\", \"translated\": \"Hat dieses Medikament Nebenwirkungen?\"}, {\"original\": \"내 의료 보험 카드를 사용할 수 있습니까?\", \"translated\": \"Kann ich meine Krankenkartenkarte verwenden?\"}, {\"original\": \"붕대 상자 하나 주실 수 있겠어요?\", \"translated\": \"Könnten Sie bitte eine Box Pflaster haben?\"}, {\"original\": \"발열 완화제가 있습니까?\", \"translated\": \"Haben Sie Fieber senkende Mittel?\"}, {\"original\": \"조금 긁힌 곳이 있어요. 소독약과 붕대가 있습니까?\", \"translated\": \"Ich habe einen kleinen Kratzer. Haben Sie Desinfektionsmittel und Pflaster?\"}, {\"original\": \"언제 문을 닫습니까?\", \"translated\": \"Wann schließen Sie?\"}]', 7, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"응급 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 응급 서비스와 관련된 10가지 일반적인 문장과 독일어 번역을 드립니다:\"]', '[\"경찰 호출\", \"응급처치\", \"도움 요청\"]', 'ko', '[\"지금은, 특정한 응급 상황이 생각나십니까? 예를 들어 화재, 부상 및 도움이 필요, 응급 전화 등 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"응급차를 불러줘.\", \"translated\": \"Helfen Sie mir, einen Notarzt zu rufen.\"}, {\"original\": \"병원은 어디예요?\", \"translated\": \"Wo ist das Krankenhaus?\"}, {\"original\": \"누군가 다쳤어요.\", \"translated\": \"Jemand ist verletzt.\"}, {\"original\": \"도와주세요.\", \"translated\": \"Helfen Sie mir bitte.\"}, {\"original\": \"경찰서는 어디예요?\", \"translated\": \"Wo ist die Polizeistation?\"}, {\"original\": \"내 소지품을 잃어버렸어요.\", \"translated\": \"Ich habe meine Gegenstände verloren.\"}, {\"original\": \"소방서 번호는 뭐예요?\", \"translated\": \"Was ist die Nummer für die Feuerwehr?\"}, {\"original\": \"여권을 잃어버렸어요. 가장 가까운 경찰서는 어디예요?\", \"translated\": \"Ich habe meinen Pass verloren. Kennen Sie die nächste Polizeistation?\"}, {\"original\": \"비상출구는 어디예요?\", \"translated\": \"Gibt es einen Notausgang?\"}, {\"original\": \"누군가 쓰러졌어요.\", \"translated\": \"Jemand ist ohnmächtig geworden.\"}]', 8, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"비치나 수영장가에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있습니까?\", \"좋습니다! 비치나 수영장과 관련된 10개의 일반적인 문장과 독일어 번역을 제공합니다:\"]', '[\"수영\", \"태양광 쬐기\", \"해변 스포츠\"]', 'ko', '[\"현재, 참석하는 지역 이벤트나 축제의 맥락을 제공해 주시겠습니까? 예를 들어 문화 축제, 음식 축제 또는 음악 축제와 같은 것들입니다. 맥락을 제공해 주세요.\", \"참석하는 활동을 제공해 주세요.\"]', '[\"특정 상황이 마음에 드신다면 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', '[{\"original\": \"보라, 저쪽 파도가 정말 크다.\", \"translated\": \"Sieh mal! Die Wellen dort draußen sind wirklich groß.\"}, {\"original\": \"자외선 차단제를 바르세요, 여기 자외선이 매우 강합니다.\", \"translated\": \"Denk daran, Sonnencreme aufzutragen, die UV-Strahlen hier sind sehr stark.\"}, {\"original\": \"이 해변의 모래는 매우 미세해서 마치 면처럼 밟는 느낌이에요.\", \"translated\": \"Der Sand auf diesem Strand ist so fein, es fühlt sich an, als würde man auf Wattierung treten.\"}, {\"original\": \"해변에서 배구를 할까요?\", \"translated\": \"Wie wäre es, Volleyball am Strand zu spielen?\"}, {\"original\": \"멀리 있는 요트들이 아름다워 보여요.\", \"translated\": \"Die Segelboote in der Ferne sehen schön aus.\"}, {\"original\": \"이곳의 물은 매우 맑아서 물고기를 볼 수 있어요.\", \"translated\": \"Das Wasser hier ist so klar, dass man sogar die Fische sehen kann.\"}, {\"original\": \"시조를 찾아볼까요.\", \"translated\": \"Lass uns nach Muscheln suchen.\"}, {\"original\": \"일몰 때 해변을 산책하는 건 매우 로맨틱할 것 같아요.\", \"translated\": \"Ein Spaziergang am Strand bei Sonnenuntergang muss sehr romantisch sein.\"}, {\"original\": \"이곳의 해산물이 매우 신선하다는 걸 들었어요, 가서 먹어봐요.\", \"translated\": \"Ich habe gehört, dass das Meeresfrüchte hier sehr frisch sind, lassen Sie uns einige probieren.\"}, {\"original\": \"조수 간만이 다가오고 있어요, 해안으로 가자.\", \"translated\": \"Die Gezeiten kommen herein, wir sollten zum Ufer gehen.\"}]', 9, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"로컬 이벤트 및 축제에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋습니다! 로컬 이벤트 및 축제와 관련된 10가지 일반적인 표현과 함께 독일어 번역을 제공합니다:\"]', '[\"이벤트에 참석하기\", \"절기 축제를 축하하기\", \"문화를 배우기\"]', 'ko', '[\"현재까지, 당신이 참석하는 로컬 이벤트 또는 축제의 맥락을 제공해 주시겠습니까? 예를 들어 할로윈, 콘서트 또는 친구 파티, 또는 기타 사항을 말해주세요. 맥락을 제공해 주세요.\", \"당신의 마음에 떠오르는 활동을 설명해 주세요.\"]', '[\"특정 상황이 마음에 드신다면 자유롭게 물어보세요.\", \"당신의 마음에 떠오르는 상황을 설명해 주세요.\"]', '[{\"original\": \"오늘 이벤트가 있나요?\", \"translated\": \"Gibt es heute Veranstaltungen?\"}, {\"original\": \"이 축제에 특별한 점이 있나요?\", \"translated\": \"Hat dieses Festival etwas Besonderes?\"}, {\"original\": \"축제는 어디에서 열리나요?\", \"translated\": \"Wo findet die Feier statt?\"}, {\"original\": \"티켓을 어떻게 구입할 수 있나요?\", \"translated\": \"Wie kann ich Tickets kaufen?\"}, {\"original\": \"공연은 몇 시에 시작하나요?\", \"translated\": \"Um welche Zeit beginnt die Vorstellung?\"}, {\"original\": \"이곳에 어떤 전통 음식이 있나요?\", \"translated\": \"Welche traditionellen Speisen gibt es?\"}, {\"original\": \"여기 정말 활기차네요.\", \"translated\": \"Es ist hier wirklich lebhaft.\"}, {\"original\": \"전통적인 활동이 있나요?\", \"translated\": \"Gibt es folkloristische Aktivitäten?\"}, {\"original\": \"명절 인사 드립니다!\", \"translated\": \"Frohe Ferien!\"}, {\"original\": \"이벤트는 몇 시에 끝나나요?\", \"translated\": \"Um welche Zeit endet die Veranstaltung?\"}]', 10, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"박물관 또는 미술관에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 박물관 또는 미술관과 관련된 10개의 일반적인 문장과 독일어 번역을 드립니다:\"]', '[\"방문\", \"가이드 투어\", \"티켓 구매\"]', 'ko', '[\"지금은, 예를 들어 안내서 요청, 로드맵과 관련된 문장, 전시품에 대한 의견을 표현하는 문장과 같은 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"심중에 생각하고 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"Wie viel kostet der Eintrittspreis?\"}, {\"original\": \"오디오 가이드가 있나요?\", \"translated\": \"Haben Sie Audioführer?\"}, {\"original\": \"이 작품을 만든 사람은 누구인가요?\", \"translated\": \"Wer hat dieses Kunstwerk geschaffen?\"}, {\"original\": \"박물관의 가장 값진 작품은 어디에 있나요?\", \"translated\": \"Wo befindet sich das wertvollste Stück des Museums?\"}, {\"original\": \"사진 촬영이 가능한가요?\", \"translated\": \"Ist Fotografie erlaubt?\"}, {\"original\": \"여기 특별 전시회가 있나요?\", \"translated\": \"Gibt es hier besondere Ausstellungen?\"}, {\"original\": \"방문하는 데 얼마나 오래 걸리나요?\", \"translated\": \"Wie lange dauert der Besuch?\"}, {\"original\": \"우리에게 소개를 해주실 수 있나요?\", \"translated\": \"Können Sie uns eine Einführung geben?\"}, {\"original\": \"이 작품들은 정말 아름답습니다.\", \"translated\": \"Diese Werke sind wirklich exquisit.\"}, {\"original\": \"기념품 가게는 어디에 있나요?\", \"translated\": \"Wo ist der Souvenirladen?\"}]', 11, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"카페에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 카페와 관련된 10가지 일반적인 문장과 독일어 번역을 제공합니다:\"]', '[\"커피 주문\", \"휴식\", \"사회적 활동\"]', 'ko', '[\"지금은, 메뉴를 요청하거나, 아이스 또는 핫 음료, 기타 제품에 대한 상황을 구체적으로 생각하고 계신가요? 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"제가 라테를 주세요.\", \"translated\": \"Ich nehme einen Latte, bitte.\"}, {\"original\": \"와이파이가 있나요?\", \"translated\": \"Haben Sie WLAN?\"}, {\"original\": \"메뉴를 보여주실 수 있나요?\", \"translated\": \"Könnten Sie uns die Speisekarte zeigen?\"}, {\"original\": \"리필이 가능한가요?\", \"translated\": \"Dürfen wir nachfüllen?\"}, {\"original\": \"제 커피 준비되었나요?\", \"translated\": \"Ist mein Kaffee fertig?\"}, {\"original\": \"여기서 얼마나 오래 있을 수 있나요?\", \"translated\": \"Wie lange darf ich hier sitzen?\"}, {\"original\": \"우리 사진을 찍어줄 수 있나요?\", \"translated\": \"Können Sie ein Foto für uns machen?\"}, {\"original\": \"화장실은 어디에 있나요?\", \"translated\": \"Wo ist das Badezimmer?\"}, {\"original\": \"계산해 주세요. 감사합니다.\", \"translated\": \"Die Rechnung, bitte. Vielen Dank.\"}, {\"original\": \"맛이 정말 좋습니다.\", \"translated\": \"Es schmeckt wirklich gut.\"}]', 12, 'de');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"식당에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋습니다! 식당과 관련된 10가지 일반적인 문장과 스페인어 번역을 제공합니다:\"]', '[\"식사\", \"주문\", \"결제\"]', 'ko', '[\"지금은, 음료 주문, 불만 제기, 성분 문의 등 특정 상황이 떠오르시나요? 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"실례합니다, 음식은 얼마나 더 오래 걸릴까요?\", \"translated\": \"¿Perdón, cuánto más tardará nuestra comida?\"}, {\"original\": \"이용객 두 명을 위한 테이블을 부탁드립니다.\", \"translated\": \"Una mesa para dos, por favor.\"}, {\"original\": \"메뉴를 보여주실 수 있겠어요?\", \"translated\": \"¿Podríamos ver el menú, por favor?\"}, {\"original\": \"추천할 만한 특별한 요리가 있나요?\", \"translated\": \"¿Tienen algún plato especial que recomendar?\"}, {\"original\": \"이것과 이것을 주문하고 싶어요.\", \"translated\": \"Me gustaría pedir este y este.\"}, {\"original\": \"물 한 잔 부탁드려요. 감사합니다.\", \"translated\": \"Un vaso de agua, por favor. Gracias.\"}, {\"original\": \"계산서 부탁드립니다.\", \"translated\": \"La cuenta, por favor.\"}, {\"original\": \"신용카드로 결제할 수 있나요?\", \"translated\": \"¿Puedo pagar con tarjeta de crédito?\"}, {\"original\": \"이걸 포장해 주실 수 있겠어요?\", \"translated\": \"¿Podrían empaquetarlo para llevar, por favor?\"}, {\"original\": \"음식이 정말 맛있었어요. 감사합니다.\", \"translated\": \"La comida fue deliciosa, gracias.\"}]', 1, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"호텔에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 호텔과 관련된 10가지 일반적인 문장과 스페인어 번역을 제공합니다:\"]', '[\"체크인\", \"체크아웃\", \"객실 서비스\"]', 'ko', '[\"현재, 방 위치, 기타 호텔 서비스 또는 체크아웃과 같은 구체적인 상황이 있으신가요? 자유롭게 물어보세요.\", \"심상에 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"안녕하세요, 예약이 있습니다, 여기 여권입니다.\", \"translated\": \"Hola, tengo una reservación, aquí está mi pasaporte.\"}, {\"original\": \"예약 가능한 객실이 있습니까?\", \"translated\": \"¿Tienen alguna habitación disponible?\"}, {\"original\": \"실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\", \"translated\": \"Disculpe, ¿el hotel tiene gimnasio o lavandería?\"}, {\"original\": \"아침 식사가 몇 시부터 시작됩니까?\", \"translated\": \"¿A qué hora comienza el desayuno?\"}, {\"original\": \"방 키를 주실 수 있겠습니까?\", \"translated\": \"¿Me puede dar una llave de habitación, por favor?\"}, {\"original\": \"짐을 방까지 가져다 줄 수 있겠습니까?\", \"translated\": \"¿Puede ayudarme a llevar mi equipaje a la habitación?\"}, {\"original\": \"객실 서비스를 부르는 방법은 무엇입니까?\", \"translated\": \"¿Cómo llamo al servicio de habitaciones?\"}, {\"original\": \"체크아웃 시간은 언제입니까?\", \"translated\": \"¿A qué hora es el check-out?\"}, {\"original\": \"영수증/송장 작성해 주실 수 있겠습니까?\", \"translated\": \"¿Puede escribirme un recibo/factura?\"}, {\"original\": \"짐을 여기에 둘 수 있나요?\", \"translated\": \"¿Puedo dejar mi equipaje aquí?\"}]', 2, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"공항에서 사용할 수 있는 10가지 일반 문장을 제공해 주실 수 있나요?\", \"좋아요! 공항과 관련된 10가지 일반 문장과 스페인어 번역을 아래에 소개합니다:\"]', '[\"체크인\", \"승객 탑승\", \"수하물 수령\"]', 'ko', '[\"현재, 체크인, 수하물 인수, 자동차 대여 서비스와 같은 구체적인 상황이 있으신가요? 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"체크인 카운터는 어디입니까?\", \"translated\": \"¿Dónde está el mostrador de facturación?\"}, {\"original\": \"창가 자리가 있으면 좋겠습니다.\", \"translated\": \"Me gustaría un asiento junto a la ventanilla, por favor.\"}, {\"original\": \"이 항공편이 지연되고 있습니까?\", \"translated\": \"¿Está retrasado este vuelo?\"}, {\"original\": \"이 수하물을 확인해야 합니다.\", \"translated\": \"Necesito facturar esta maleta.\"}, {\"original\": \"승객 탑승 게이트는 어디입니까?\", \"translated\": \"¿Dónde está la puerta de embarque?\"}, {\"original\": \"비행기가 곧 이륙할 예정입니다.\", \"translated\": \"El avión está a punto de despegar.\"}, {\"original\": \"노트북과 전원 어댑터를 꺼내야 하나요?\", \"translated\": \"¿Debo sacar mi portátil y mi banco de energía?\"}, {\"original\": \"관세 면세점은 어디입니까?\", \"translated\": \"¿Dónde está la tienda de artículos libres de impuestos?\"}, {\"original\": \"내 수화물이 보이지 않습니다.\", \"translated\": \"No puedo encontrar mi maleta.\"}, {\"original\": \"휠체어 서비스가 있습니까?\", \"translated\": \"¿Tienen servicio de silla de ruedas?\"}]', 3, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"대중교통에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 대중교통과 관련된 10가지 일반적인 문장과 스페인어 번역을 제공합니다:\"]', '[\"버스/지하철 타기\", \"티켓 구입\", \"환승\"]', 'ko', '[\"지금은, 버스 정류장에 대한 질문, 티켓 가격, 하차와 같은 특정 상황이 있으신가요? 자유롭게 물어보세요.\", \"심중에 생각하고 있는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"이 버스는 터미널로 가나요?\", \"translated\": \"¿Este autobús va al terminal?\"}, {\"original\": \"다음 정류장은 어디인가요?\", \"translated\": \"¿Cuál es la siguiente parada?\"}, {\"original\": \"티켓을 어디서 살 수 있나요?\", \"translated\": \"¿Dónde puedo comprar un boleto?\"}, {\"original\": \"XX까지 한 장의 티켓을 주세요.\", \"translated\": \"Un boleto a XX, por favor.\"}, {\"original\": \"전환해야 하나요?\", \"translated\": \"¿Necesito cambiar de transporte?\"}, {\"original\": \"다음 지하철은 얼마나 걸리나요?\", \"translated\": \"¿Cuánto tiempo falta para el siguiente tren del metro?\"}, {\"original\": \"실례합니다, 지나가도 되겠어요?\", \"translated\": \"Disculpe, por favor déjeme pasar.\"}, {\"original\": \"이 자리에 누가 앉았나요?\", \"translated\": \"¿Esta silla está ocupada?\"}, {\"original\": \"실례합니다, XX에 가려면 2호선으로 어디에서 환승해야 하나요?\", \"translated\": \"Disculpe, ¿dónde puedo cambiar a la Línea 2 para llegar a XX?\"}, {\"original\": \"XX에 어떻게 가나요?\", \"translated\": \"¿Cómo llego a XX?\"}]', 4, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"관광 명소에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 관광 명소와 관련된 10가지 일반적인 문장과 스페인어 번역을 제공합니다:\"]', '[\"관광\", \"사진 촬영\", \"티켓 구매\"]', 'ko', '[\"현재, 티켓 가격에 대해 묻는 것, 주차장 찾기, 또는 투어 가이드 서비스처럼 구체적인 상황을 생각하고 계신가요? 자유롭게 물어보세요.\", \"심리적으로 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"학생 할인 티켓이 있나요?\", \"translated\": \"¿Hay entradas para estudiantes disponibles?\"}, {\"original\": \"이 관광지가 몇 시에 열어요?\", \"translated\": \"¿A qué hora abre la atracción?\"}, {\"original\": \"여기서 할 수 있는 재미있는 활동은 무엇인가요?\", \"translated\": \"¿Qué cosas divertidas se pueden hacer aquí?\"}, {\"original\": \"우리 사진을 찍어 줄 수 있나요?\", \"translated\": \"¿Podrías tomar una foto para nosotros?\"}, {\"original\": \"관광버스는 어디에 있나요?\", \"translated\": \"¿Dónde está el autobús turístico?\"}, {\"original\": \"화장실은 어디에 있나요?\", \"translated\": \"¿Dónde están los baños?\"}, {\"original\": \"가장 좋은 전망대는 어디인가요?\", \"translated\": \"¿Dónde es el mejor lugar para ver?\"}, {\"original\": \"여기 경치가 아름다워요.\", \"translated\": \"El paisaje aquí es hermoso.\"}, {\"original\": \"가이드 투어가 있나요?\", \"translated\": \"¿Hay un tour guiado disponible?\"}]', 5, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"택시나 택시 서비스에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있습니까?\", \"좋아요! 택시나 택시 서비스와 관련된 10가지 일반적인 문장과 스페인어 번역을 제공합니다:\"]', '[\"택시 타기\", \"목적지 말하기\", \"결제\"]', 'ko', '[\"지금은 무엇을 가장 원하시나요, 목적지에 대해 묻거나, 요금을 묻거나, 세금계산서를 요청하는 것처럼 자유롭게 물어보세요.\", \"마음속의 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"택시를 어디서 탈 수 있나요?\", \"translated\": \"¿Dónde puedo tomar un taxi?\"}, {\"original\": \"이 주소로 제가 가게 해주세요.\", \"translated\": \"Por favor, lleveme a esta dirección.\"}, {\"original\": \"大概 얼마 정도 될까요?\", \"translated\": \"¿Aproximadamente cuánto costará?\"}, {\"original\": \"계기표 사용해 주세요.\", \"translated\": \"¿Podría usar el taxímetro, por favor?\"}, {\"original\": \"조금 더 빨리 운전해 주실 수 있나요? 저는 급한 일이 있어요.\", \"translated\": \"Por favor, conduzca un poco más rápido, estoy apurado.\"}, {\"original\": \"여기서 멈춰 주세요.\", \"translated\": \"Por favor, pare aquí.\"}, {\"original\": \"카드나 모바일 결제를 받으세요?\", \"translated\": \"¿Acepta tarjetas o pagos móviles?\"}, {\"original\": \"영수증 좀 주실 수 있나요?\", \"translated\": \"¿Me podría dar un comprobante, por favor?\"}, {\"original\": \"감사합니다, 기사님.\", \"translated\": \"Gracias, conductor.\"}, {\"original\": \"이제 얼마나 더 가야 하나요?\", \"translated\": \"¿Cuánto más queda?\"}]', 6, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"약국에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 약국과 관련된 10가지 일반적인 문장과 스페인어 번역을 제공합니다:\"]', '[\"약 구매\", \"상담\", \"결제\"]', 'ko', '[\"지금은, 약물 복용 지침을 묻는 경우, 보험 관련 문장, 약물 복용 기간 등 특정 상황을 생각하고 계신가요? 자유롭게 물어보세요.\", \"현재 마음에 떠오르는 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"감기약이 있습니까?\", \"translated\": \"¿Tienes medicamento para el resfriado?\"}, {\"original\": \"이 약은 어떻게 복용해야 하나요?\", \"translated\": \"¿Cómo debo tomar este medicamento?\"}, {\"original\": \"진통제가 있습니까?\", \"translated\": \"¿Tienes algún analgésico?\"}, {\"original\": \"사용 설명서가 있습니까?\", \"translated\": \"¿Hay un folleto con instrucciones?\"}, {\"original\": \"이 약에는 부작용이 있습니까?\", \"translated\": \"¿Este medicamento tiene efectos secundarios?\"}, {\"original\": \"내 의료 보험 카드를 사용할 수 있습니까?\", \"translated\": \"¿Puedo usar mi tarjeta de seguro médico?\"}, {\"original\": \"붕대 상자 하나 주시겠어요?\", \"translated\": \"¿Me puede dar un paquete de vendas, por favor?\"}, {\"original\": \"해열제가 있습니까?\", \"translated\": \"¿Tienes algún medicamento para reducir la fiebre?\"}, {\"original\": \"조금 까졌어요. 항균제와 붕대가 있습니까?\", \"translated\": \"Me he hecho un pequeño arañazo. ¿Tienes algún antiséptico y vendas?\"}, {\"original\": \"언제 문을 닫으십니까?\", \"translated\": \"¿A qué hora cierran?\"}]', 7, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"응급 서비스에서 사용할 수 있는 10가지 일반적인 문구를 제공해 주실 수 있나요?\", \"좋아요! 응급 서비스와 관련된 10가지 일반적인 문구와 스페인어 번역을 아래에 나열합니다:\"]', '[\"경찰 호출\", \"응급처치\", \"도움 요청\"]', 'ko', '[\"지금은, 특정한 응급 상황이 떠오르시나요? 예를 들어 화재, 부상 및 도움이 필요한 경우, 응급 전화 등 자유롭게 물어보세요.\", \"마음에 떠오르는 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"응급차를 불러줘.\", \"translated\": \"Por favor, ayúdeme a llamar una ambulancia.\"}, {\"original\": \"병원은 어디예요?\", \"translated\": \"¿Dónde está el hospital?\"}, {\"original\": \"누군가 다쳤어요.\", \"translated\": \"Alguien está herido.\"}, {\"original\": \"도와주세요.\", \"translated\": \"Por favor, ayúdeme.\"}, {\"original\": \"경찰서는 어디예요?\", \"translated\": \"¿Dónde está la estación de policía?\"}, {\"original\": \"내 소지품을 잃어버렸어요.\", \"translated\": \"He perdido mis pertenencias.\"}, {\"original\": \"소방서 번호는 무엇인가요?\", \"translated\": \"¿Cuál es el número del departamento de bomberos?\"}, {\"original\": \"여권을 잃어버렸어요. 가장 가까운 경찰서는 어디예요?\", \"translated\": \"He perdido mi pasaporte. ¿Sabe dónde está la estación de policía más cercana?\"}, {\"original\": \"비상출구는 어디예요?\", \"translated\": \"¿Hay una salida de emergencia?\"}, {\"original\": \"누군가 쓰러졌어요.\", \"translated\": \"Alguien se ha desmayado.\"}]', 8, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"비치나 수영장가에서 사용할 수 있는 10개의 일반적인 문장을 제공해 주실 수 있습니까?\", \"좋습니다! 비치나 수영장과 관련된 10개의 일반적인 문장과 스페인어 번역을 제공합니다:\"]', '[\"수영\", \"태양광 쬐기\", \"해변 스포츠\"]', 'ko', '[\"지금은, 참석하는 지역 이벤트나 축제의 맥락을 제공해 주시겠습니까? 예를 들어 문화 축제, 음식 축제 또는 음악 축제와 같은 것들입니다. 맥락을 제공해 주세요.\", \"참석하는 활동을 알려주세요.\"]', '[\"특정 상황이 마음에 있는 경우, 자유롭게 물어보세요.\", \"마음에 있는 상황을 설명해 주세요.\"]', '[{\"original\": \"보라! 저쪽의 파도는 정말 크다.\", \"translated\": \"¡Mira! Las olas de allá son muy grandes.\"}, {\"original\": \"자외선 차단제를 바르세요, 여기 자외선은 매우 강합니다.\", \"translated\": \"Recuerda aplicar protector solar, los rayos UV aquí son muy fuertes.\"}, {\"original\": \"이 해변의 모래는 매우 미끄럽고, 마치 솜처럼 느껴집니다.\", \"translated\": \"La arena de esta playa es tan fina que parece caminar sobre algodón.\"}, {\"original\": \"해변에서 배구를 하기 어때요?\", \"translated\": \"¿Qué tal jugar voleibol en la playa?\"}, {\"original\": \"멀리 있는 요트들이 아름답게 보입니다.\", \"translated\": \"Los veleros a lo lejos lucen hermosos.\"}, {\"original\": \"이 곳의 물은 매우 맑아서 물고기를 보는 것이 가능합니다.\", \"translated\": \"El agua aquí es tan clara que incluso se pueden ver los peces.\"}, {\"original\": \"우린 조개를 찾아보자.\", \"translated\": \"Vamos a buscar algunas conchas.\"}, {\"original\": \"일몰 때 해변을 산책하는 것은 매우 로맨틱할 것입니다.\", \"translated\": \"Dar un paseo por la playa al atardecer debe ser muy romántico.\"}, {\"original\": \"여기 해산물은 매우 신선하다고 들었으니, 가서 먹어보자.\", \"translated\": \"He oído que el marisco aquí es muy fresco, vamos a probarlo.\"}, {\"original\": \"조수는 들어오고 있으니, 해안으로 향합시다.\", \"translated\": \"La marea está entrando, vamos hacia la orilla.\"}]', 9, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"로컬 이벤트와 페스티벌에서 사용할 수 있는 10가지 일반적인 표현을 제공해 주실 수 있나요?\", \"좋아요! 로컬 이벤트와 페스티벌과 관련된 10가지 일반적인 표현과 스페인어 번역을 제공합니다:\"]', '[\"이벤트 참석\", \"절기 축하하기\", \"문화 배우기\"]', 'ko', '[\"현재까지, 로컬 이벤트 또는 페스티벌에 참석하는 상황을 알려주세요. 예를 들어 할로윈, 콘서트 또는 친구 파티, 또는 기타 다른 것일 수 있습니다. 상황을 제공해 주세요.\", \"여러분이 생각하는 활동을 설명해 주세요.\"]', '[\"자유롭게 묻고 싶은 특정 상황이 있으신가요?\", \"여러분이 생각하는 상황을 설명해 주세요.\"]', '[{\"original\": \"오늘 이벤트가 있나요?\", \"translated\": \"¿Hay algún evento hoy?\"}, {\"original\": \"이 축제에 특별한 점이 있나요?\", \"translated\": \"¿Hay algo especial sobre este festival?\"}, {\"original\": \"축제는 어디에서 열리나요?\", \"translated\": \"¿Dónde se celebra la celebración?\"}, {\"original\": \"티켓을 어떻게 구입할 수 있나요?\", \"translated\": \"¿Cómo puedo comprar entradas?\"}, {\"original\": \"공연은 몇 시에 시작하나요?\", \"translated\": \"¿A qué hora comienza la actuación?\"}, {\"original\": \"이곳에 전통 음식은 무엇인가요?\", \"translated\": \"¿Qué comida tradicional hay?\"}, {\"original\": \"여기 정말 활기가 넘치네요.\", \"translated\": \"Aquí es muy animado.\"}, {\"original\": \"민속 활동이 있나요?\", \"translated\": \"¿Hay alguna actividad folclórica?\"}, {\"original\": \"명절 인사 드립니다!\", \"translated\": \"¡Felices vacaciones!\"}, {\"original\": \"이벤트는 몇 시에 끝나나요?\", \"translated\": \"¿A qué hora termina el evento?\"}]', 10, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"박물관 또는 미술관에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주실 수 있나요?\", \"좋아요! 박물관 또는 미술관과 관련된 10가지 일반적인 문장과 스페인어 번역을 제공합니다:\"]', '[\"방문\", \"가이드 투어\", \"티켓 구매\"]', 'ko', '[\"지금은 특정 상황이 생각나시나요, 예를 들어 안내 매뉴얼을 요청하는 경우, 로드맵과 관련된 문장, 전시품에 대한 의견을 표현하는 문장 등 자유롭게 물어보세요.\", \"심상 중인 상황을 설명해 주세요.\"]', NULL, '[{\"original\": \"입장료는 얼마인가요?\", \"translated\": \"¿Cuánto cuesta la entrada?\"}, {\"original\": \"오디오 가이드가 있나요?\", \"translated\": \"¿Tienen guías auditivas?\"}, {\"original\": \"이 작품을 만든 사람은 누구인가요?\", \"translated\": \"¿Quién creó esta obra de arte?\"}, {\"original\": \"이 박물관의 가장 소중한 작품은 어디에 있나요?\", \"translated\": \"¿Dónde está la pieza más valiosa del museo?\"}, {\"original\": \"사진 촬영이 가능한가요?\", \"translated\": \"¿Se permite la fotografía?\"}, {\"original\": \"여기 특별 전시회가 있나요?\", \"translated\": \"¿Hay alguna exposición especial aquí?\"}, {\"original\": \"방문에는 얼마나 시간이 걸리나요?\", \"translated\": \"¿Cuánto tiempo dura la visita?\"}, {\"original\": \"우리에게 소개를 해주실 수 있나요?\", \"translated\": \"¿Podrían darnos una introducción?\"}, {\"original\": \"이 작품들은 정말 아름답습니다.\", \"translated\": \"Estas obras son verdaderamente exquisitas.\"}, {\"original\": \"기념품 가게는 어디에 있나요?\", \"translated\": \"¿Dónde está la tienda de recuerdos?\"}]', 11, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"카페에서 사용할 수 있는 10가지 일반적인 문장을 제공해 주시겠습니까?\", \"좋습니다! 카페와 관련된 10가지 일반적인 문장과 스페인어 번역을 제공합니다:\"]', '[\"커피 주문\", \"휴식\", \"사회적 활동\"]', 'ko', '[\"지금은, 메뉴를 요청하거나, 아이스 또는 핫 음료, 기타 제품에 대한 상황 등을 구체적인 상황을 생각하고 계신가요, 자유롭게 물어보세요.\", \"심중에 생각하고 계신 상황을 설명해 주십시오.\"]', NULL, '[{\"original\": \"제가 라테 하나 주세요.\", \"translated\": \"Me traiga un latte, por favor.\"}, {\"original\": \"와이파이 있으세요?\", \"translated\": \"¿Tiene Wi-Fi?\"}, {\"original\": \"메뉴 좀 보여주세요.\", \"translated\": \"¿Podría ver el menú, por favor?\"}, {\"original\": \"리필 가능하세요?\", \"translated\": \"¿Se permiten refills?\"}, {\"original\": \"제 커피 준비되었어요?\", \"translated\": \"¿Mi café ya está listo?\"}, {\"original\": \"이곳에서 얼마나 있을 수 있나요?\", \"translated\": \"¿Cuánto tiempo puedo quedarme aquí?\"}, {\"original\": \"우리 사진 좀 찍어줄 수 있나요?\", \"translated\": \"¿Podría tomar una foto para nosotros?\"}, {\"original\": \"화장실은 어디예요?\", \"translated\": \"¿Dónde está el baño?\"}, {\"original\": \"계산해 주세요. 감사합니다.\", \"translated\": \"Cuenta, por favor. Gracias.\"}, {\"original\": \"진짜 맛있어요.\", \"translated\": \"Sabe muy bien.\"}]', 12, 'es');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potresti farmi conoscere 10 frasi comuni che posso usare nei ristoranti?\", \"Fantastico! Ecco 10 frasi comuni relative ai ristoranti, con le traduzioni in coreano:\"]', '[\"Dining\", \"Ordering\", \"Checkout\"]', 'it', '[\"Per ora, hai in mente una situazione specifica, come ordinare bevande, fare una lamentela o chiedere informazioni sugli ingredienti? Non esitare a chiedere.\", \"Descrivi la situazione che hai in mente.\"]', NULL, '[{\"original\": \"Mi scusi, quanto manca ancora per il nostro cibo?\", \"translated\": \"실례합니다, 음식은 얼마나 더 오래 걸릴까요?\"}, {\"original\": \"Un tavolo per due, prego.\", \"translated\": \"두 분을 위한 테이블을 부탁드립니다.\"}, {\"original\": \"Possiamo vedere il menu, per favore?\", \"translated\": \"메뉴를 보여주실 수 있겠어요?\"}, {\"original\": \"Avete dei piatti speciali che consigliate?\", \"translated\": \"추천해 주실 만한 특별한 요리가 있나요?\"}, {\"original\": \"Vorrei ordinare questo e questo.\", \"translated\": \"이것과 이것을 주문하고 싶어요.\"}, {\"original\": \"Un bicchiere d\'acqua, prego. Grazie.\", \"translated\": \"물 한 잔 부탁드립니다. 감사합니다.\"}, {\"original\": \"Il conto, per favore.\", \"translated\": \"계산서를 주세요.\"}, {\"original\": \"Posso pagare con la carta di credito?\", \"translated\": \"신용카드로 결제할 수 있나요?\"}, {\"original\": \"Potreste imballarlo da asporto, per favore?\", \"translated\": \"이걸 포장해 주실 수 있나요?\"}, {\"original\": \"Il cibo era delizioso, grazie.\", \"translated\": \"음식이 정말 맛있었어요. 감사합니다.\"}]', 1, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Puoi fornirmi 10 frasi comuni che posso usare in hotel?\", \"Fantastico! Ecco 10 frasi comuni relative agli hotel, con le traduzioni in coreano:\"]', '[\"Check-in\", \"Check-out\", \"Servizio camera\"]', 'it', '[\"Per ora, hai in mente una situazione specifica, come la posizione della stanza, altri servizi dell\'hotel o il check-out, non esitare a chiedere.\", \"Descrivi la situazione che hai in mente.\"]', NULL, '[{\"original\": \"Ciao, ho una prenotazione, ecco il mio passaporto.\", \"translated\": \"안녕하세요, 예약이 있습니다, 여기 여권이 있습니다.\"}, {\"original\": \"Avete disponibilità?\", \"translated\": \"예약 가능한 객실이 있습니까?\"}, {\"original\": \"Scusi, l\'hotel ha una palestra o un\'area per il lavaggio?\", \"translated\": \"실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\"}, {\"original\": \"A che ora inizia la colazione?\", \"translated\": \"아침 식사가 몇 시부터 시작됩니까?\"}, {\"original\": \"Potrei avere una chiave della stanza, per favore?\", \"translated\": \"방 키를 주시겠어요?\"}, {\"original\": \"Potreste aiutarmi a portare i miei bagagli nella stanza?\", \"translated\": \"짐을 방까지 가져다 도와주실 수 있나요?\"}, {\"original\": \"Come faccio a chiamare il servizio in camera?\", \"translated\": \"객실 서비스를 부르는 방법은 무엇입니까?\"}, {\"original\": \"A che ora è il check-out?\", \"translated\": \"체크아웃 시간은 몇 시입니까?\"}, {\"original\": \"Potreste scrivere un ricevuta/fattura per me?\", \"translated\": \"영수증/송장 작성해 주시겠어요?\"}, {\"original\": \"Posso lasciare i miei bagagli qui?\", \"translated\": \"저는 짐을 여기 두어도 되나요?\"}]', 2, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potresti fornirmi 10 frasi comuni che posso usare in aeroporto?\", \"Fantastico! Ecco 10 frasi comuni relative all\'aeroporto, con le traduzioni in coreano:\"]', '[\"Check-in\", \"Imbarco\", \"Controllo bagagli\"]', 'it', '[\"Per ora, hai in mente una situazione specifica, ad esempio il check-in, il ritiro bagagli o il servizio di noleggio auto? Non esitare a chiedere.\", \"Descrivi la situazione che hai in mente.\"]', NULL, '[{\"original\": \"Dove si trova il banco di check-in?\", \"translated\": \"체크인 카운터는 어디입니까?\"}, {\"original\": \"Vorrei un posto accanto al finestrino, per favore.\", \"translated\": \"창가 자리를 원합니다.\"}, {\"original\": \"Questo volo è in ritardo?\", \"translated\": \"이 항공편이 지연되고 있습니까?\"}, {\"original\": \"Devo controllare questa bagaglia.\", \"translated\": \"이 수하물을 확인해야 합니다.\"}, {\"original\": \"Dove si trova la porta d\'imbarco?\", \"translated\": \"탑승 게이트는 어디입니까?\"}, {\"original\": \"L\'aereo sta per decollare.\", \"translated\": \"비행기가 곧 이륙할 예정입니다.\"}, {\"original\": \"Devo rimuovere il mio computer portatile e il power bank?\", \"translated\": \"노트북과 전원 어댑터를 꺼내야 하나요?\"}, {\"original\": \"Dove si trova il negozio di articoli doganali?\", \"translated\": \"무세금 쇼핑점은 어디입니까?\"}, {\"original\": \"Non riesco a trovare il mio bagaglio.\", \"translated\": \"내 수화물이 보이지 않습니다.\"}, {\"original\": \"Avete un servizio di sedia a rotelle?\", \"translated\": \"휠체어 서비스를 제공합니까?\"}]', 3, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potresti fornirmi 10 frasi comuni che posso usare nei trasporti pubblici?\", \"Fantastico! Ecco 10 frasi comuni relative ai trasporti pubblici, con le traduzioni in coreano:\"]', '[\"Prendere l\'autobus/metropolitana\", \"Acquistare biglietti\", \"Effettuare un cambio\"]', 'it', '[\"Per ora, hai in mente una situazione specifica, ad esempio chiedere la fermata dell\'autobus, il prezzo del biglietto o scendere, non esitare a chiedere.\", \"Descrivi la situazione che hai in mente.\"]', NULL, '[{\"original\": \"Questo autobus va alla stazione?\", \"translated\": \"이 버스는 터미널로 가나요?\"}, {\"original\": \"Qual è la prossima fermata?\", \"translated\": \"다음 정류장은 어디예요?\"}, {\"original\": \"Dove posso comprare un biglietto?\", \"translated\": \"어디에서 티켓을 살 수 있나요?\"}, {\"original\": \"Un biglietto per XX, per favore.\", \"translated\": \"XX까지 한 장의 티켓을 주세요.\"}, {\"original\": \"Devo cambiare?\", \"translated\": \"환승해야 하나요?\"}, {\"original\": \"Quanto manca all\'arrivo del prossimo treno della metropolitana?\", \"translated\": \"다음 지하철이 몇 분 후에 오나요?\"}, {\"original\": \"Mi scusi, mi faccia passare.\", \"translated\": \"실례합니다, 지나가도 될까요?\"}, {\"original\": \"Questo posto è occupato?\", \"translated\": \"이 자리는 예약된 건가요?\"}, {\"original\": \"Mi scusi, dove posso cambiare per la Linea 2 per arrivare a XX?\", \"translated\": \"실례합니다, XX에 가기 위해 2호선으로 어디에서 환승해야 하나요?\"}, {\"original\": \"Come faccio a raggiungere XX?\", \"translated\": \"XX에 어떻게 가야 하나요?\"}]', 4, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potresti fornirmi 10 frasi comuni che posso usare nei luoghi di interesse turistico?\", \"Fantastico! Ecco 10 frasi comuni relative ai luoghi di interesse turistico, insieme alle traduzioni in coreano:\"]', '[\"Visita turistica\", \"Scattare foto\", \"Acquistare biglietti\"]', 'it', '[\"Per ora, hai in mente una situazione specifica, ad esempio chiedere il prezzo dei biglietti, trovare un parcheggio o servizi di guida turistica, puoi chiedere liberamente.\", \"Descrivi la situazione che hai in mente.\"]', NULL, '[{\"original\": \"Quanto costa l\'ingresso?\", \"translated\": \"입장료는 얼마인가요?\"}, {\"original\": \"Sono disponibili biglietti per gli studenti?\", \"translated\": \"학생 할인 티켓이 있나요?\"}, {\"original\": \"A che ora apre l\'attrazione?\", \"translated\": \"이 관광지가 몇 시에 열리나요?\"}, {\"original\": \"Cosa si può fare di divertente qui?\", \"translated\": \"여기서 할 수 있는 재미있는 일은 무엇인가요?\"}, {\"original\": \"Puoi scattarci una foto?\", \"translated\": \"우리를 위한 사진을 찍어줄 수 있나요?\"}, {\"original\": \"Dove si trova l\'autobus turistico?\", \"translated\": \"관광버스는 어디에 있나요?\"}, {\"original\": \"Dove si trovano i bagni?\", \"translated\": \"화장실은 어디에 있나요?\"}, {\"original\": \"Dove è il miglior punto di osservazione?\", \"translated\": \"가장 좋은 전망지는 어디인가요?\"}, {\"original\": \"Il paesaggio qui è bello.\", \"translated\": \"여기 경치가 아름답네요.\"}, {\"original\": \"È disponibile un tour guidato?\", \"translated\": \"가이드 투어가 있나요?\"}]', 5, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Puoi fornirmi 10 frasi comuni che posso usare in Taxi o nel servizio di Taxi?\", \"Fantastico! Ecco 10 frasi comuni relative a Taxi o al servizio di Taxi, con traduzioni in coreano:\"]', '[\"Prendere un taxi\", \"Dire la destinazione\", \"Pagamento\"]', 'it', '[\"Per ora, cosa vorresti fare adesso, come chiedere la destinazione, il costo o richiedere una fattura, non esitare a chiedere.\", \"Descrivi la situazione nella tua mente.\"]', NULL, '[{\"original\": \"Dove posso prendere un taxi?\", \"translated\": \"택시를 어디서 탈 수 있나요?\"}, {\"original\": \"Per favore portami a questo indirizzo.\", \"translated\": \"이 주소로 저를 데려가 주세요.\"}, {\"original\": \"Quanto dovrebbe costare circa?\", \"translated\": \"얼마 정도 나올까요?\"}, {\"original\": \"Puoi usare il tassametro, per favore?\", \"translated\": \"계기장 사용해 주시겠어요?\"}, {\"original\": \"Per favore guida un po\' più veloce, ho fretta.\", \"translated\": \"좀 더 빨리 운전해 주실 수 있나요? 저는 급한 일이 있어요.\"}, {\"original\": \"Per favore fermati qui.\", \"translated\": \"여기서 멈춰 주세요.\"}, {\"original\": \"Accetti carte o pagamenti mobili?\", \"translated\": \"카드나 모바일 결제를 받으세요?\"}, {\"original\": \"Mi puoi dare uno scontrino, per favore?\", \"translated\": \"영수증 좀 주시겠어요?\"}, {\"original\": \"Grazie, autista.\", \"translated\": \"감사합니다, 운전사님.\"}, {\"original\": \"Quanto manca ancora?\", \"translated\": \"이곳에서 얼마나 더 가야 하나요?\"}]', 6, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potresti fornirmi 10 frasi comuni che posso usare in farmacia?\", \"Fantastico! Ecco 10 frasi comuni relative alla farmacia, insieme alle traduzioni in coreano:\"]', '[\"Acquisto di farmaci\", \"Consulta\", \"Pagamento\"]', 'it', '[\"Per ora, hai in mente una situazione specifica, ad esempio chiedere le istruzioni per prendere un farmaco, frasi relative all\'uso dell\'assicurazione, durata del farmaco, non esitare a chiedere.\", \"Descrivi la situazione che hai in mente.\"]', NULL, '[{\"original\": \"Hai dei medicinali per il raffreddore?\", \"translated\": \"감기 약이 있습니까?\"}, {\"original\": \"Come devo prendere questo farmaco?\", \"translated\": \"이 약은 어떻게 복용해야 하나요?\"}, {\"original\": \"Hai degli analgesici?\", \"translated\": \"진통제가 있습니까?\"}, {\"original\": \"C\'è un foglietto illustrativo?\", \"translated\": \"사용 설명서가 있습니까?\"}, {\"original\": \"Questo farmaco ha effetti collaterali?\", \"translated\": \"이 약에는 부작용이 있습니까?\"}, {\"original\": \"Posso usare la mia carta della assicurazione sanitaria?\", \"translated\": \"내 보험 카드를 사용할 수 있나요?\"}, {\"original\": \"Potrei avere una confezione di bende, per favore?\", \"translated\": \"붕대 상자 하나 주실 수 있나요?\"}, {\"original\": \"Hai degli riduttori di febbre?\", \"translated\": \"발열 억제제가 있습니까?\"}, {\"original\": \"Ho un piccolo graffio. Hai dell\'antisettico e delle bende?\", \"translated\": \"조금 까져요. 소독약과 붕대가 있습니까?\"}, {\"original\": \"A che ora chiudete?\", \"translated\": \"언제 문을 닫으십니까?\"}]', 7, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potresti fornirmi 10 frasi comuni che posso utilizzare nei Servizi di Emergenza?\", \"Fantastico! Ecco 10 frasi comuni relative ai Servizi di Emergenza, insieme alle traduzioni in coreano:\"]', '[\"Chiamare la polizia\", \"Primo soccorso\", \"Chiedere aiuto\"]', 'it', '[\"Per ora, hai in mente una situazione di emergenza specifica, come un incendio, una persona ferita che ha bisogno di aiuto, chiamata di emergenza, non esitare a chiedere.\", \"Descrivi la situazione che hai in mente.\"]', NULL, '[{\"original\": \"Per favore, aiutami a chiamare un\'ambulanza.\", \"translated\": \"응급차를 불러주세요.\"}, {\"original\": \"Dove si trova l\'ospedale?\", \"translated\": \"병원은 어디입니까?\"}, {\"original\": \"Qualcuno è ferito.\", \"translated\": \"누군가 부상을 입었습니다.\"}, {\"original\": \"Per favore, aiutami.\", \"translated\": \"도와주세요.\"}, {\"original\": \"Dove si trova la stazione dei pompieri?\", \"translated\": \"경찰서는 어디입니까?\"}, {\"original\": \"Ho perso i miei oggetti.\", \"translated\": \"내 소지품을 잃어버렸습니다.\"}, {\"original\": \"Qual è il numero del dipartimento dei vigili del fuoco?\", \"translated\": \"소방서 전화번호는 무엇입니까?\"}, {\"original\": \"Ho perso il mio passaporto. Sai dove si trova la stazione della polizia più vicina?\", \"translated\": \"여권을 잃어버렸어요. 가장 가까운 경찰서는 어디입니까?\"}, {\"original\": \"C\'è un\'uscita di emergenza?\", \"translated\": \"비상출구가 있습니까?\"}, {\"original\": \"Qualcuno ha svenuto.\", \"translated\": \"누군가 쓰러졌습니다.\"}]', 8, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potresti fornirmi 10 frasi comuni che posso usare in spiaggia o vicino alla piscina?\", \"Fantastico! Ecco 10 frasi comuni relative alla spiaggia o alla piscina, con traduzioni in coreano:\"]', '[\"Nuotare\", \"Abbronzarsi\", \"Sport sulla spiaggia\"]', 'it', '[\"Per ora, puoi per favore fornirmi il contesto dell\'evento o del festival locale a cui partecipi, ad esempio un festival culturale, un festival della comida o un festival musicale. Per favore fornisci il contesto.\", \"Fornisci le attività a cui partecipi.\"]', '[\"Hai una situazione specifica in mente, non esitare a chiedere.\", \"Descrivi la situazione che hai in mente.\"]', '[{\"original\": \"Guarda! Le onde laggiù sono veramente grandi.\", \"translated\": \"보라, 저쪽 파도가 정말 크다.\"}, {\"original\": \"Ricorda di applicare la crema solare, i raggi UV qui sono molto forti.\", \"translated\": \"자외선 차단제를 바르세요, 여기 자외선이 매우 강합니다.\"}, {\"original\": \"La sabbia su questa spiaggia è così fine, sembra di camminare su cotone.\", \"translated\": \"이 해변의 모래는 매우 미끄러워서 마치 솜처럼 발아래에 있는 것 같아요.\"}, {\"original\": \"Perché non giocare a pallavolo sulla spiaggia?\", \"translated\": \"해변에서 배구를 하기 어때요?\"}, {\"original\": \"I velieri lontani sembrano bellissimi.\", \"translated\": \"멀리 있는 요트들이 아름답게 보여요.\"}, {\"original\": \"L\'acqua qui è così limpida, si possono persino vedere i pesci.\", \"translated\": \"이곳의 물이 매우 맑아서 물고기를 보는 것이 가능해요.\"}, {\"original\": \"Andiamo a cercare conchiglie.\", \"translated\": \"시해 껍질을 찾으러 가자.\"}, {\"original\": \"Farci una passeggiata sulla spiaggia al tramonto deve essere molto romantico.\", \"translated\": \"일몰 때 해변을 산책하는 것은 매우 로맨틱할 거예요.\"}, {\"original\": \"Ho sentito che il pesce qui è molto fresco, andiamo a provare.\", \"translated\": \"여기 해산물이 매우 신선하다고 들었어요, 같이 먹어보자.\"}, {\"original\": \"La marea sta arrivando, andiamo verso la riva.\", \"translated\": \"조수간만이 다가오고 있어요, 해안으로 향합시다.\"}]', 9, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potresti farmi conoscere 10 frasi comuni che posso usare in eventi e festival locali?\", \"Fantastico! Ecco 10 frasi comuni relative agli eventi e festival locali, insieme alle traduzioni in coreano:\"]', '[\"Partecipare a Eventi\", \"Celebrare Feste\", \"Imparare la Cultura\"]', 'it', '[\"Per ora, potresti per favore farmi conoscere il contesto dell\'evento o del festival locale a cui parteciperai, come Halloween, un concerto o una festa di amici, o qualcos\'altro? Per favore fornisci il contesto.\", \"Descrivi le attività che hai in mente.\"]', '[\"Hai una situazione specifica in mente, non esitare a chiedere.\", \"Descrivi la situazione che hai in mente.\"]', '[{\"original\": \"Ci sono eventi oggi?\", \"translated\": \"오늘 이벤트가 있나요?\"}, {\"original\": \"C\'è qualcosa di speciale per questa festa?\", \"translated\": \"이 축제에 특별한 점이 있나요?\"}, {\"original\": \"Dove si svolge la celebrazione?\", \"translated\": \"축제는 어디에서 열리나요?\"}, {\"original\": \"Come posso acquistare i biglietti?\", \"translated\": \"티켓을 어떻게 구입할 수 있나요?\"}, {\"original\": \"A che ora inizia lo spettacolo?\", \"translated\": \"공연은 몇 시에 시작하나요?\"}, {\"original\": \"Quali cibi tradizionali ci sono?\", \"translated\": \"이곳에 전통 음식은 무엇인가요?\"}, {\"original\": \"È davvero vivace qui.\", \"translated\": \"여기 정말 활기찬 곳이에요.\"}, {\"original\": \"Ci sono attività folkloristiche?\", \"translated\": \"민속 활동이 있나요?\"}, {\"original\": \"Buone vacanze!\", \"translated\": \"즐거운 명절 되세요!\"}, {\"original\": \"A che ora finisce l\'evento?\", \"translated\": \"이벤트는 몇 시에 끝나나요?\"}]', 10, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potresti fornirmi 10 frasi comuni che posso usare in un museo o in una galleria d\'arte?\", \"Fantastico! Ecco 10 frasi comuni relative a un museo o a una galleria d\'arte, insieme alle traduzioni in coreano:\"]', '[\"Visita\", \"Tour guidato\", \"Acquisto biglietti\"]', 'it', '[\"Per ora, hai in mente una situazione specifica, ad esempio chiedere un manuale di introduzione, frasi relative a un percorso, frasi relative a commenti sugli oggetti esposti, non esitare a chiedere.\", \"Descrivi la situazione che hai in mente.\"]', NULL, '[{\"original\": \"Quanto costa l\'ingresso?\", \"translated\": \"입장료는 얼마인가요?\"}, {\"original\": \"Avete guide audio?\", \"translated\": \"음성 가이드가 있나요?\"}, {\"original\": \"Chi ha creato quest\'opera d\'arte?\", \"translated\": \"이 작품을 만든 사람은 누구인가요?\"}, {\"original\": \"Dove si trova la pezzo più pregiato del museo?\", \"translated\": \"박물관에서 가장 소중한 작품은 어디에 있나요?\"}, {\"original\": \"È consentita la fotografia?\", \"translated\": \"사진 촬영이 가능한가요?\"}, {\"original\": \"Ci sono mostre speciali qui?\", \"translated\": \"여기 특별 전시회가 있나요?\"}, {\"original\": \"Quanto tempo dura la visita?\", \"translated\": \"방문하는 데 얼마나 걸리나요?\"}, {\"original\": \"Potete darci un\'introduzione?\", \"translated\": \"우리에게 소개를 해주실 수 있나요?\"}, {\"original\": \"Queste opere sono veramente squisite.\", \"translated\": \"이 작품들은 정말 아름답습니다.\"}, {\"original\": \"Dove si trova il negozio dei souvenir?\", \"translated\": \"기념품 가게는 어디에 있나요?\"}]', 11, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Potresti fornirmi 10 frasi comuni che posso usare nei caffè?\", \"Fantastico! Ecco 10 frasi comuni relative ai caffè, con le traduzioni in coreano:\"]', '[\"Ordinare un caffè\", \"Riposare\", \"Socializzare\"]', 'it', '[\"Per ora, hai in mente una situazione specifica, ad esempio chiedere il menu, bevande ghiacciate o calde, altri prodotti, non esitare a chiedere.\", \"Descrivi la situazione che hai in mente.\"]', NULL, '[{\"original\": \"Vorrei un latte, per favore.\", \"translated\": \"제가 라테 하나 주세요.\"}, {\"original\": \"Avete il Wi-Fi?\", \"translated\": \"와이파이 있으세요?\"}, {\"original\": \"Mi potete mostrare il menu, per favore?\", \"translated\": \"메뉴 좀 보여주세요.\"}, {\"original\": \"Sono ammesse le rinfrescanti?\", \"translated\": \"리필 가능하세요?\"}, {\"original\": \"Il mio caffè è pronto?\", \"translated\": \"제 커피 준비되었어요?\"}, {\"original\": \"Per quanto tempo posso stare qui?\", \"translated\": \"이곳에서 얼마나 있을 수 있나요?\"}, {\"original\": \"Potreste scattarci una foto?\", \"translated\": \"우리 사진 좀 찍어 주시겠어요?\"}, {\"original\": \"Dov\'è il bagno?\", \"translated\": \"화장실은 어디예요?\"}, {\"original\": \"Il conto, per favore. Grazie.\", \"translated\": \"계산해 주세요. 감사합니다.\"}, {\"original\": \"Ha un sapore veramente buono.\", \"translated\": \"정말 맛있어요.\"}]', 12, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Можете ли вы предоставить мне 10 общих фраз, которые я могу использовать в ресторане?\", \"Отлично! Вот 10 общих фраз, связанных с рестораном, вместе с переводами на корейский язык:\"]', '[\"Обед\", \"Заказ\", \"Оплата\"]', 'ru', '[\"На данный момент, у вас есть конкретная ситуация на уме, например, заказ напитков, подача жалобы или запрос о составе продуктов, не стесняйтесь задавать вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Извините, как скоро наше питание будет готово?\", \"translated\": \"실례합니다, 음식은 얼마나 더 오래 걸릴까요?\"}, {\"original\": \"Стол на двоих, пожалуйста.\", \"translated\": \"이렇게 두 명을 위한 테이블을 주세요.\"}, {\"original\": \"Можем ли мы увидеть меню, пожалуйста?\", \"translated\": \"메뉴를 보여주실 수 있나요?\"}, {\"original\": \"У вас есть какие-нибудь фирменные блюда для рекомендации?\", \"translated\": \"추천할 만한 특산 dish가 있나요?\"}, {\"original\": \"Я хочу заказать это, и это.\", \"translated\": \"이것과 이것을 주문하고 싶어요.\"}, {\"original\": \"Стакан воды, пожалуйста. Спасибо.\", \"translated\": \"물 한 잔 주세요. 감사합니다.\"}, {\"original\": \"Счет, пожалуйста.\", \"translated\": \"계산서 주세요.\"}, {\"original\": \"Могу я заплатить кредитной картой?\", \"translated\": \"신용카드로 지불할 수 있나요?\"}, {\"original\": \"Можете ли вы упаковать это для выноса, пожалуйста?\", \"translated\": \"이걸 포장해 주실 수 있나요?\"}, {\"original\": \"Еда была вкусной, спасибо.\", \"translated\": \"음식이 정말 맛있었어요. 감사합니다.\"}]', 1, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Можете ли вы предоставить мне 10 общих фраз, которые я могу использовать в отеле?\", \"Отлично! Вот 10 общих фраз, связанных с отелем, вместе с корейскими переводами:\"]', '[\"Регистрация заезда\", \"Регистрация выезда\", \"Сервис номера\"]', 'ru', '[\"На данный момент, у вас есть конкретная ситуация на уме, например, расположение номера, любые другие отельные услуги или выезд, не стесняйтесь задавать вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Здравствуйте, у меня есть бронирование, вот мой паспорт.\", \"translated\": \"안녕하세요, 예약이 있습니다, 여권을 드립니다.\"}, {\"original\": \"У вас есть свободные номера?\", \"translated\": \"예약 가능한 객실이 있습니까?\"}, {\"original\": \"Извините, есть ли в отеле спортзал или прачечная?\", \"translated\": \"실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\"}, {\"original\": \"В котором часу начинается завтрак?\", \"translated\": \"아침 식사가 몇 시에 시작합니까?\"}, {\"original\": \"Могу я получить ключ от номера, пожалуйста?\", \"translated\": \"방 키를 주시겠어요?\"}, {\"original\": \"Можете ли вы помочь мне доставить мою сумку в номер?\", \"translated\": \"짐을 방까지 가져다 도와주실 수 있나요?\"}, {\"original\": \"Как вызвать обслуживание номеров?\", \"translated\": \"객실 서비스를 부르는 방법은 무엇입니까?\"}, {\"original\": \"В котором часу окончание регистрации?\", \"translated\": \"체크아웃 시간은 몇 시입니까?\"}, {\"original\": \"Можете ли вы выдать мне квитанцию/счет?\", \"translated\": \"영수증/송금서를 작성해 주시겠어요?\"}, {\"original\": \"Могу ли я оставить здесь свою сумку?\", \"translated\": \"짐을 여기 두어도 괜찮나요?\"}]', 2, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Можете ли вы предоставить мне 10 общих фраз, которые я могу использовать в аэропорту?\", \"Отлично! Вот 10 общих фраз, связанных с аэропортом, вместе с переводами на корейский:\"]', '[\"Регистрация\", \"Посадка\", \"Сдача багажа\"]', 'ru', '[\"На данный момент, у вас есть конкретная ситуация на уме, например, регистрация, получение багажа или услуга проката автомобилей, задавайте любой вопрос.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Где находится стойка регистрации?\", \"translated\": \"체크인 카운터는 어디입니까?\"}, {\"original\": \"Я бы хотел оконное место, пожалуйста.\", \"translated\": \"창가 좌석을 원합니다.\"}, {\"original\": \"Этот рейс задерживается?\", \"translated\": \"이 항공편은 지연되고 있습니까?\"}, {\"original\": \"Мне нужно зарегистрировать этот багаж.\", \"translated\": \"이 수화물을 검사해야 합니다.\"}, {\"original\": \"Где находится посадочная площадка?\", \"translated\": \"승객 탑승 게이트는 어디입니까?\"}, {\"original\": \"Самолет собирается взлететь.\", \"translated\": \"비행기가 곧 이륙할 예정입니다.\"}, {\"original\": \"Мне нужно извлечь ноутбук и зарядное устройство?\", \"translated\": \"노트북과 충전식 배터리를 꺼내야 합니까?\"}, {\"original\": \"Где находится магазин беспошлинной торговли?\", \"translated\": \"관세 면세점은 어디입니까?\"}, {\"original\": \"Я не могу найти свою сумку.\", \"translated\": \"내 수화물을 찾을 수 없습니다.\"}, {\"original\": \"У вас есть услуга инвалидных колясок?\", \"translated\": \"휠체어 서비스를 제공합니까?\"}]', 3, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Можете ли вы предоставить мне 10 общих фраз, которые я могу использовать в общественном транспорте?\", \"Отлично! Вот 10 общих фраз, связанных с общественным транспортом, вместе с переводами на корейский:\"]', '[\"Взять автобус/метро\", \"Приобрести билеты\", \"Пересадка\"]', 'ru', '[\"Пока что, у вас есть конкретная ситуация на уме, например, спросить о остановке автобуса, цене билета или выходе, не стесняйтесь задавать вопросы.\", \"Пожалуйста, опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Этот автобус идет в терминал?\", \"translated\": \"이 버스는 터미널로 가나요?\"}, {\"original\": \"Какая следующая остановка?\", \"translated\": \"다음 정류장은 어디예요?\"}, {\"original\": \"Где я могу купить билет?\", \"translated\": \"어디에서 티켓을 살 수 있나요?\"}, {\"original\": \"Один билет до XX, пожалуйста.\", \"translated\": \"XX까지 한 장의 티켓을 주세요.\"}, {\"original\": \"Мне нужно пересесть?\", \"translated\": \"이야기 바꿔야 하나요?\"}, {\"original\": \"Сколько времени до следующего поезда метро?\", \"translated\": \"다음 지하철은 몇 분 후에 오나요?\"}, {\"original\": \"Извините, пропустите меня.\", \"translated\": \"실례합니다, 지나가도 될까요?\"}, {\"original\": \"Это место занято?\", \"translated\": \"이 자리에 누가 앉았나요?\"}, {\"original\": \"Извините, где я могу пересесть на Линию 2, чтобы добраться до XX?\", \"translated\": \"실례합니다, XX에 가려면 2호선으로 어디에서 갈아타나요?\"}, {\"original\": \"Как мне добраться до XX?\", \"translated\": \"XX에 가는 방법을 알려주세요.\"}]', 4, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Можете ли вы предоставить мне 10 общих фраз, которые я могу использовать в туристических достопримечательностях?\", \"Отлично! Вот 10 общих фраз, связанных с туристическими достопримечательностями, а также перевод на корейский язык:\"]', '[\"Осмотр достопримечательностей\", \"Фотосъемка\", \"Покупка билетов\"]', 'ru', '[\"На данный момент, у вас есть конкретная ситуация на уме, например, спросить о цене билета, найти парковку или услугу гида, свободно задавать вопросы.\", \"Опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"입장료는 얼마인가요?\"}, {\"original\": \"Есть ли студенческие билеты?\", \"translated\": \"학생 할인 티켓이 있나요?\"}, {\"original\": \"Во сколько открыта достопримечательность?\", \"translated\": \"이 관광지가 언제 개장하나요?\"}, {\"original\": \"Что интересного можно здесь сделать?\", \"translated\": \"여기서 할 수 있는 재미있는 일은 무엇인가요?\"}, {\"original\": \"Можете сделать нам фото?\", \"translated\": \"우리를 위한 사진을 찍어 주실 수 있나요?\"}, {\"original\": \"Где находится автобус для экскурсий?\", \"translated\": \"관광버스는 어디에 있나요?\"}, {\"original\": \"Где находится туалет?\", \"translated\": \"화장실은 어디에 있나요?\"}, {\"original\": \"Где лучшая точка для просмотра?\", \"translated\": \"가장 좋은 전망지는 어디인가요?\"}, {\"original\": \"Пейзажи здесь красивые.\", \"translated\": \"여기 경치가 아름답네요.\"}, {\"original\": \"Доступна ли гидированная экскурсия?\", \"translated\": \"가이드 투어가 있나요?\"}]', 5, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Можете ли вы предоставить мне 10 общих фраз, которые я могу использовать в такси или при заказе такси?\", \"Отлично! Вот 10 общих фраз, связанных с такси или услугой такси, вместе с переводами на корейский язык:\"]', '[\"Взять такси\", \"Сказать пункт назначения\", \"Оплата\"]', 'ru', '[\"На данный момент, что вы больше всего хотите сделать сейчас, например, спросить о направлении, сколько стоит, или попросить счет, не стесняйтесь задавать вопросы.\", \"Пожалуйста, опишите ситуацию в своем воображении.\"]', NULL, '[{\"original\": \"Где я могу взять такси?\", \"translated\": \"택시를 어디서 탈 수 있나요?\"}, {\"original\": \"Пожалуйста, отвезите меня по этот адрес.\", \"translated\": \"이 주소로 저를 데려가 주세요.\"}, {\"original\": \"Примерно сколько это будет стоить?\", \"translated\": \"얼마 정도 될까요?\"}, {\"original\": \"Можете, пожалуйста, использовать счётчик?\", \"translated\": \"계기표를 사용해 주시겠어요?\"}, {\"original\": \"Пожалуйста, езжайте чуть быстрее, у меня спешка.\", \"translated\": \"좀 더 빨리 운전해 주실 수 있나요? 저는 서둘러야 해요.\"}, {\"original\": \"Пожалуйста, остановитесь здесь.\", \"translated\": \"여기에서 멈춰 주세요.\"}, {\"original\": \"Вы принимаете карты или мобильные платежи?\", \"translated\": \"카드나 모바일 결제를 받으세요?\"}, {\"original\": \"Могу ли я получить чек, пожалуйста?\", \"translated\": \"영수증을 좀 주실 수 있나요?\"}, {\"original\": \"Спасибо, водитель.\", \"translated\": \"감사합니다, 기사님.\"}, {\"original\": \"Как далеко ещё?\", \"translated\": \"이곳에서 얼마나 더 가야 하나요?\"}]', 6, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Можете ли вы предоставить мне 10 общих фраз, которые я могу использовать в аптеке?\", \"Отлично! Вот 10 общих фраз, связанных с аптекой, вместе с переводами на корейский язык:\"]', '[\"Покупка лекарств\", \"Консультация\", \"Оплата\"]', 'ru', '[\"На данный момент, у вас есть конкретная ситуация на уме, например, спрашиваете о инструкциях по применению лекарства, фразы, связанные с использованием страхования, продолжительность приема лекарства, свободно задавать вопросы.\", \"Опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Есть ли у вас лекарство от простуды?\", \"translated\": \"감기 약이 있습니까?\"}, {\"original\": \"Как мне принимать это лекарство?\", \"translated\": \"이 약은 어떻게 복용해야 하나요?\"}, {\"original\": \"Есть ли у вас обезболивающие?\", \"translated\": \"진통제가 있습니까?\"}, {\"original\": \"Есть ли инструкция?\", \"translated\": \"사용 설명서가 있습니까?\"}, {\"original\": \"У этого лекарства есть побочные эффекты?\", \"translated\": \"이 약에는 부작용이 있습니까?\"}, {\"original\": \"Могу ли я использовать свою медицинскую карту?\", \"translated\": \"내 의료 보험 카드를 사용할 수 있나요?\"}, {\"original\": \"Можно ли получить коробку пластырей, пожалуйста?\", \"translated\": \"붕대 상자 하나 주실 수 있나요?\"}, {\"original\": \"Есть ли у вас жаропонижающие?\", \"translated\": \"발열 억제제가 있습니까?\"}, {\"original\": \"У меня немного царапина. Есть ли у вас антисептик и пластыри?\", \"translated\": \"조금 깍지가 생겼어요. 소독약과 붕대가 있습니까?\"}, {\"original\": \"Во сколько вы закрываетесь?\", \"translated\": \"언제 문을 닫으십니까?\"}]', 7, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Можете ли вы предоставить мне 10 общих фраз, которые я могу использовать в службах экстренной помощи?\", \"Отлично! Вот 10 общих фраз, связанных с службами экстренной помощи, вместе с переводами на корейский язык:\"]', '[\"Позвонить в полицию\", \"Первая помощь\", \"Попросить о помощи\"]', 'ru', '[\"Пока что, у вас есть конкретная ситуация чрезвычайной ситуации в уме, например, пожар, травма и помощь, вызов экстренной службы, свободно задавайте вопросы.\", \"Опишите ситуацию, которая у вас в уме.\"]', NULL, '[{\"original\": \"Помогите мне вызвать скорую помощь.\", \"translated\": \"응급차를 불러줘.\"}, {\"original\": \"Где больница?\", \"translated\": \"병원은 어디예요?\"}, {\"original\": \"Кто-то ранен.\", \"translated\": \"누군가 부상당했어요.\"}, {\"original\": \"Помогите мне.\", \"translated\": \"도와주세요.\"}, {\"original\": \"Где полицейский участок?\", \"translated\": \"경찰서는 어디예요?\"}, {\"original\": \"Я потерял свои вещи.\", \"translated\": \"내 소지품을 잃어버렸어요.\"}, {\"original\": \"Какой номер пожарной службы?\", \"translated\": \"소방서 전화번호는 무엇인가요?\"}, {\"original\": \"Я потерял паспорт. Знаете ли вы, где ближайший полицейский участок?\", \"translated\": \"여권을 잃어버렸어요. 가까운 경찰서는 어디예요?\"}, {\"original\": \"Есть ли аварийный выход?\", \"translated\": \"비상출구는 어디예요?\"}, {\"original\": \"Кто-то потерял сознание.\", \"translated\": \"누군가 쓰러졌어요.\"}]', 8, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Можете ли вы предоставить мне 10 общих фраз, которые я могу использовать на пляже или у бассейна?\", \"Отлично! Вот 10 общих фраз, связанных с пляжем или бассейном, а также перевод на корейский язык:\"]', '[\"Плавание\", \"Солнечные ванны\", \"Пляжные игры\"]', 'ru', '[\"На данный момент, можете ли вы, пожалуйста, предоставить контекст локального мероприятия или фестиваля, в котором вы участвуете, например, культурный фестиваль, фестиваль еды или музыкальный фестиваль. Пожалуйста, предоставьте контекст.\", \"Пожалуйста, перечислите мероприятия, в которых вы участвуете.\"]', '[\"У вас есть конкретная ситуация в виду, задавайте вопросы свободно.\", \"Пожалуйста, опишите ситуацию, которая у вас в уме.\"]', '[{\"original\": \"Смотри! Волны там действительно большие.\", \"translated\": \"보라, 저쪽 파도가 정말 크다.\"}, {\"original\": \"Не забудь нанести солнцезащитный крем, ультрафиолетовые лучи здесь очень сильные.\", \"translated\": \"자외선 차단제를 발라야 해, 여기 자외선이 매우 강하다.\"}, {\"original\": \"Песок на этом пляже такой тонкий, что кажется, будто идешь по вате.\", \"translated\": \"이 해변의 모래는 매우 미세해서 마치 쿠션 위에 서 있는 것처럼 느껴진다.\"}, {\"original\": \"Как насчет игры в волейбол на пляже?\", \"translated\": \"해변에서 배구를 하면 어때?\"}, {\"original\": \"Яхты на расстоянии выглядят красиво.\", \"translated\": \"멀리 있는 요트들이 아름답게 보인다.\"}, {\"original\": \"Вода здесь такая чистая, что даже можно увидеть рыб.\", \"translated\": \"여기 물은 매우 맑아서 물고기를 보는 것이 가능하다.\"}, {\"original\": \"Давай найдем какие-нибудь ракушки.\", \"translated\": \"시조를 찾으러 가자.\"}, {\"original\": \"Прогулка по пляжу на закате должна быть очень романтичной.\", \"translated\": \"일몰 때 해변을 산책하는 것은 매우 로맨틱할 것이다.\"}, {\"original\": \"Я слышал, что морепродукты здесь очень свежие, давай попробуем.\", \"translated\": \"여기 해산물이 매우 신선하다고 들었어, 같이 먹어보자.\"}, {\"original\": \"Прилив подходит, давай двигаться к берегу.\", \"translated\": \"조수 갈라짐이 시작되고 있으니, 해안으로 가자.\"}]', 9, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Можете ли вы предоставить мне 10 общих фраз, которые я могу использовать на местных мероприятиях и праздниках?\", \"Отлично! Вот 10 общих фраз, связанных с местными мероприятиями и праздниками, а также перевод на корейский язык:\"]', '[\"Посещение мероприятий\", \"Празднование фестивалей\", \"Изучение культуры\"]', 'ru', '[\"Пока что, можете ли вы, пожалуйста, предоставить контекст местного мероприятия или праздника, в котором вы участвуете, например, Хэллоуин, концерт или вечеринка друга, или что-то еще? Пожалуйста, предоставьте контекст\", \"Опишите активности, которые вы имеете в виду.\"]', '[\"Есть ли у вас конкретная ситуация, которую вы имеете в виду, задавайте свободно.\", \"Опишите ситуацию, которая у вас в голове.\"]', '[{\"original\": \"Есть ли сегодня какие-либо события?\", \"translated\": \"오늘 행사가 있나요?\"}, {\"original\": \"Что особенного в этом празднике?\", \"translated\": \"이 축제에 특별한 점이 있나요?\"}, {\"original\": \"Где проходит праздник?\", \"translated\": \"축제는 어디에서 열리나요?\"}, {\"original\": \"Как я могу купить билеты?\", \"translated\": \"티켓을 어떻게 구입할 수 있나요?\"}, {\"original\": \"Во сколько начинается представление?\", \"translated\": \"공연은 몇 시에 시작하나요?\"}, {\"original\": \"Какие традиционные блюда есть?\", \"translated\": \"이곳에 전통 음식은 무엇인가요?\"}, {\"original\": \"Здесь действительно оживленно.\", \"translated\": \"여기 정말 활기가 넘치네요.\"}, {\"original\": \"Есть ли народные мероприятия?\", \"translated\": \"민속 활동이 있나요?\"}, {\"original\": \"Счастливых праздников!\", \"translated\": \"즐거운 명절 되세요!\"}, {\"original\": \"Во сколько заканчивается событие?\", \"translated\": \"행사는 몇 시에 끝나나요?\"}]', 10, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Можете ли вы предоставить мне 10 общих фраз, которые я могу использовать в музее или художественной галерее?\", \"Отлично! Вот 10 общих фраз, связанных с музеем или художественной галереей, вместе с переводами на корейский язык:\"]', '[\"Посещение\", \"Гидоводство\", \"Покупка билетов\"]', 'ru', '[\"Пока что, у вас есть конкретная ситуация на уме, например, запрос на инструкцию по ознакомлению, фразы, связанные с маршрутом, фразы, связанные с комментарием к экспонату, свободно задавайте вопросы.\", \"Опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Сколько стоит входной билет?\", \"translated\": \"입장료는 얼마인가요?\"}, {\"original\": \"У вас есть аудиогиды?\", \"translated\": \"오디오 가이드가 있나요?\"}, {\"original\": \"Кто создал это произведение искусства?\", \"translated\": \"이 작품을 만든 사람은 누구인가요?\"}, {\"original\": \"Где находится самая ценная вещь музея?\", \"translated\": \"이 박물관의 가장 소중한 작품은 어디에 있나요?\"}, {\"original\": \"Разрешено ли фотографировать?\", \"translated\": \"사진 촬영이 가능한가요?\"}, {\"original\": \"Здесь есть какие-нибудь специальные выставки?\", \"translated\": \"여기 특별 전시회가 있나요?\"}, {\"original\": \"Сколько времени занимает посещение?\", \"translated\": \"방문에는 얼마나 시간이 걸리나요?\"}, {\"original\": \"Можете ли вы дать нам введение?\", \"translated\": \"우리에게 소개를 해주실 수 있나요?\"}, {\"original\": \"Эти произведения действительно изысканные.\", \"translated\": \"이 작품들은 정말 아름답습니다.\"}, {\"original\": \"Где находится магазин сувениров?\", \"translated\": \"기념품 가게는 어디에 있나요?\"}]', 11, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"Можете ли вы предоставить мне 10 общих фраз, которые я могу использовать в кафе?\", \"Отлично! Вот 10 общих фраз, связанных с кафе, вместе с переводами на корейский язык:\"]', '[\"Покупка кофе\", \"Отдых\", \"Общение\"]', 'ru', '[\"На данный момент, у вас есть конкретная ситуация на уме, например, запрос меню, холодные или горячие напитки, другие товары, задавайте вопросы свободно.\", \"Опишите ситуацию, которая у вас на уме.\"]', NULL, '[{\"original\": \"Я возьму латте, пожалуйста.\", \"translated\": \"제가 라테 하나 주세요.\"}, {\"original\": \"У вас есть Wi-Fi?\", \"translated\": \"와이파이 있으세요?\"}, {\"original\": \"Могу я посмотреть меню, пожалуйста?\", \"translated\": \"메뉴 좀 보여주세요.\"}, {\"original\": \"Разрешены ли подливы?\", \"translated\": \"리필 가능하세요?\"}, {\"original\": \"Моя кофе готова?\", \"translated\": \"제 커피 준비되었어요?\"}, {\"original\": \"Сколько времени я могу здесь сидеть?\", \"translated\": \"이곳에서 얼마나 오래 있을 수 있나요?\"}, {\"original\": \"Вы можете сделать для нас фото?\", \"translated\": \"우리 사진 좀 찍어주실 수 있나요?\"}, {\"original\": \"Где туалет?\", \"translated\": \"화장실은 어디에요?\"}, {\"original\": \"Счет, пожалуйста. Спасибо.\", \"translated\": \"계산해 주세요. 감사합니다.\"}, {\"original\": \"Оно действительно вкусное.\", \"translated\": \"진짜 맛있어요.\"}]', 12, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"你能给我10个可以在餐厅使用的常用短语吗？\", \"太好了！以下是与餐厅相关的10个常用短语，以及韩语翻译：\"]', '[\"用餐\", \"下单\", \"结账\"]', 'zh', '[\"目前，你有没有想到的具体情境，比如点饮料、提出投诉或询问食材，随时可以问。\", \"请描述一下你心中的情境。\"]', NULL, '[{\"original\": \"打扰一下，我们的食物还要等多久？\", \"translated\": \"실례합니다, 음식은 얼마나 더 오래 걸릴까요?\"}, {\"original\": \"两位的桌子，请。\", \"translated\": \"이렇게 두 명을 위한 테이블을 주세요.\"}, {\"original\": \"我们可以看一下菜单吗？\", \"translated\": \"메뉴를 보여주실 수 있나요?\"}, {\"original\": \"你们有什么特色菜推荐吗？\", \"translated\": \"추천할 만한 특산 dish가 있나요?\"}, {\"original\": \"我想点这个和这个。\", \"translated\": \"이것과 이것을 주문하고 싶어요.\"}, {\"original\": \"请来一杯水。谢谢。\", \"translated\": \"물 한 잔 주세요. 감사합니다.\"}, {\"original\": \"账单，请。\", \"translated\": \"계산서 주세요.\"}, {\"original\": \"我可以用信用卡支付吗？\", \"translated\": \"신용카드로 지불할 수 있나요?\"}, {\"original\": \"可以打包带走吗？\", \"translated\": \"이걸 포장해 주실 수 있나요?\"}, {\"original\": \"食物很好吃，谢谢。\", \"translated\": \"음식이 정말 맛있었어요. 감사합니다.\"}]', 1, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"你能给我10个可以在酒店使用的常用短语吗？\", \"太好了！以下是与酒店相关的10个常用短语，以及韩语翻译：\"]', '[\"入住\", \"退房\", \"客房服务\"]', 'zh', '[\"目前，你有没有脑海中具体的情景，比如房间位置、其他酒店服务或退房，请随时提问。\", \"请描述一下你脑海中的情景。\"]', NULL, '[{\"original\": \"你好，我有预订，这是我的护照。\", \"translated\": \"안녕하세요, 예약이 있습니다, 여권을 드릴게요.\"}, {\"original\": \"你们还有空房吗？\", \"translated\": \"예약 가능한 객실이 있습니까?\"}, {\"original\": \"打扰了，酒店有健身房或洗衣房吗？\", \"translated\": \"실례합니다, 호텔에 체육관이나 세탁실이 있습니까?\"}, {\"original\": \"早餐几点开始？\", \"translated\": \"아침 식사가 몇 시부터 시작됩니까?\"}, {\"original\": \"请问可以给我一个房间钥匙吗？\", \"translated\": \"방 키를 주시겠어요?\"}, {\"original\": \"你能帮我把行李搬到房间吗？\", \"translated\": \"짐을 방으로 옮겨 주실 수 있겠어요?\"}, {\"original\": \"我怎么叫客房服务？\", \"translated\": \"룸서비스를 부르는 방법은 무엇입니까?\"}, {\"original\": \"退房时间是几点？\", \"translated\": \"체크아웃 시간은 몇 시입니까?\"}, {\"original\": \"你能给我开一张收据/发票吗？\", \"translated\": \"영수증/인보이스를 작성해 주시겠어요?\"}, {\"original\": \"我可以把行李放在这里吗？\", \"translated\": \"짐을 여기 두어도 되나요?\"}]', 2, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"你能给我10个在机场常用的短语吗？\", \"太好了！以下是与机场相关的10个常用短语，以及韩语翻译：\"]', '[\"入住\", \"登机\", \"行李托运\"]', 'zh', '[\"目前，你有没有特定的情景在脑海中，比如值机、行李提取或租车服务，可以随时提问。\", \"请描述一下你脑海中的情景。\"]', NULL, '[{\"original\": \"值机柜台在哪里？\", \"translated\": \"체크인 카운터는 어디입니까?\"}, {\"original\": \"我想坐靠窗的座位。\", \"translated\": \"창가 자리 좀 주세요.\"}, {\"original\": \"这趟航班延误了吗？\", \"translated\": \"이 항공편은 지연되었나요?\"}, {\"original\": \"我需要托运这个行李。\", \"translated\": \"이 수하물을 확인해야 합니다.\"}, {\"original\": \"登机口在哪里？\", \"translated\": \"탑승 게이트는 어디입니까?\"}, {\"original\": \"飞机即将起飞。\", \"translated\": \"비행기가 곧 이륙할 예정입니다.\"}, {\"original\": \"我需要取出我的笔记本电脑和充电宝吗？\", \"translated\": \"노트북과 파워뱅크를 꺼내야 하나요?\"}, {\"original\": \"免税店在哪里？\", \"translated\": \"관세 면세점은 어디입니까?\"}, {\"original\": \"我找不到我的行李箱。\", \"translated\": \"내 수화물이 보이지 않아요.\"}, {\"original\": \"你们有轮椅服务吗？\", \"translated\": \"휠체어 서비스를 제공합니까?\"}]', 3, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"你能给我10个在公共交通中常用的短语吗？\", \"太好了！以下是与公共交通相关的10个常用短语，以及韩语翻译：\"]', '[\"乘坐公交车/地铁\", \"购买车票\", \"换乘\"]', 'zh', '[\"目前，你有没有想到的具体情况，比如询问公交站、票价或下车，可以随时提问。\", \"请描述一下你脑海中设想的情况。\"]', NULL, '[{\"original\": \"这辆公交车到终点站吗？\", \"translated\": \"이 버스는 터미널로 가나요?\"}, {\"original\": \"下一站是什么？\", \"translated\": \"다음 정류장은 어디예요?\"}, {\"original\": \"在哪里可以买票？\", \"translated\": \"표를 어디서 살 수 있나요?\"}, {\"original\": \"一张去XX的票，谢谢。\", \"translated\": \"XX로 가는 표 하나 주세요.\"}, {\"original\": \"我需要换乘吗？\", \"translated\": \"환승해야 하나요?\"}, {\"original\": \"下一班地铁多久能来？\", \"translated\": \"다음 지하철이 몇 분 후에 오나요?\"}, {\"original\": \"不好意思，请让我过去。\", \"translated\": \"실례합니다, 지나가도 될까요?\"}, {\"original\": \"这个座位有人吗？\", \"translated\": \"이 자리에 누가 앉아 있나요?\"}, {\"original\": \"不好意思，我怎么换乘2号线去XX？\", \"translated\": \"실례합니다, XX에 가려면 2호선으로 어디에서 환승해야 하나요?\"}, {\"original\": \"我怎么去XX？\", \"translated\": \"어떻게 하면 XX에 도착할 수 있나요?\"}]', 4, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"你能给我10个在旅游景点常用的短语吗？\", \"太好了！以下是与旅游景点相关的10个常用短语，以及韩语翻译：\"]', '[\"观光\", \"拍照\", \"购买门票\"]', 'zh', '[\"目前，你有没有特定的情境在脑海中，比如询问门票价格、找停车场或导游服务，可以随时提问。\", \"请描述一下你脑海中的情境。\"]', NULL, '[{\"original\": \"门票多少钱？\", \"translated\": \"입장료는 얼마인가요?\"}, {\"original\": \"有学生票吗？\", \"translated\": \"학생 할인 티켓이 있나요?\"}, {\"original\": \"景点几点开门？\", \"translated\": \"이 관광지가 몇 시에 문을 여나요?\"}, {\"original\": \"这里有什么好玩的？\", \"translated\": \"여기서 할 수 있는 재미있는 활동은 무엇인가요?\"}, {\"original\": \"能给我们拍张照片吗？\", \"translated\": \"우리 사진을 찍어 줄 수 있나요?\"}, {\"original\": \"观光巴士在哪里？\", \"translated\": \"관광버스는 어디에 있나요?\"}, {\"original\": \"洗手间在哪里？\", \"translated\": \"화장실은 어디에 있나요?\"}, {\"original\": \"最佳观景位置在哪里？\", \"translated\": \"가장 좋은 전망지는 어디인가요?\"}, {\"original\": \"这里的风景很美。\", \"translated\": \"이곳의 풍경이 아름다워요.\"}, {\"original\": \"有导游讲解吗？\", \"translated\": \"가이드 투어가 있나요?\"}]', 5, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"你能给我10个在出租车或出租车服务中可以使用的常用短语吗？\", \"太好了！以下是与出租车或出租车服务相关的10个常用短语，以及韩语翻译：\"]', '[\"打车\", \"告知目的地\", \"支付\"]', 'zh', '[\"目前，你现在最想做什么，比如询问目的地、费用，或者要求发票，随意提问。\", \"请描述你脑海中的情况。\"]', NULL, '[{\"original\": \"我可以在哪里打车？\", \"translated\": \"택시를 어디에서 탈 수 있나요?\"}, {\"original\": \"请带我到这个地址。\", \"translated\": \"이 주소로 저를 데려가 주세요.\"}, {\"original\": \"大概多少钱？\", \"translated\": \"大概 얼마나 될까요?\"}, {\"original\": \"请问可以使用计价器吗？\", \"translated\": \"계기판을 사용해 주시겠어요?\"}, {\"original\": \"请开快一点，我赶时间。\", \"translated\": \"조금 더 빠르게 운전해 주세요, 저는 급한 일이 있어요.\"}, {\"original\": \"请在这里停一下。\", \"translated\": \"여기서 멈춰 주세요.\"}, {\"original\": \"你们接受刷卡还是手机支付吗？\", \"translated\": \"카드나 모바일 결제를 받으세요?\"}, {\"original\": \"我可以要一张发票吗？\", \"translated\": \"영수증을 좀 주실 수 있나요?\"}, {\"original\": \"谢谢，司机。\", \"translated\": \"감사합니다, 운전사님.\"}, {\"original\": \"还有多远？\", \"translated\": \"얼마나 더 가야 하나요?\"}]', 6, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"你能给我10个常用的药房用语吗？\", \"太好了！以下是与药房相关的10个常用短语，以及韩语翻译：\"]', '[\"购买药品\", \"咨询\", \"支付\"]', 'zh', '[\"目前，你心里有没有具体的情境，比如询问服药说明、与保险相关的短语、药物持续时间，可以随时提问。\", \"请描述一下你心中的情境。\"]', NULL, '[{\"original\": \"你有感冒药吗？\", \"translated\": \"감기 약이 있습니까?\"}, {\"original\": \"我应该怎么吃这种药？\", \"translated\": \"이 약은 어떻게 복용해야 하나요?\"}, {\"original\": \"你有止痛药吗？\", \"translated\": \"진통제가 있습니까?\"}, {\"original\": \"有没有使用说明书？\", \"translated\": \"사용 설명서가 있습니까?\"}, {\"original\": \"这种药有什么副作用吗？\", \"translated\": \"이 약에 부작용이 있습니까?\"}, {\"original\": \"我可以使用我的医保卡吗？\", \"translated\": \"내 의료 보험 카드를 사용할 수 있나요?\"}, {\"original\": \"请给我一盒创可贴，可以吗？\", \"translated\": \"붕대 상자 하나 주실 수 있나요?\"}, {\"original\": \"你们有退烧药吗？\", \"translated\": \"발열 억제제가 있습니까?\"}, {\"original\": \"我有点擦伤，你们有消毒液和创可贴吗？\", \"translated\": \"조금 깍지가 생겼어요. 소독약과 붕대가 있습니까?\"}, {\"original\": \"你们几点关门？\", \"translated\": \"언제 문을 닫으십니까?\"}]', 7, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"你能给我10个可以在紧急服务中使用的常用短语吗？\", \"太好了！以下是与紧急服务相关的10个常用短语，以及韩语翻译：\"]', '[\"报警\", \"急救\", \"寻求帮助\"]', 'zh', '[\"目前，你有没有特定的紧急情况在脑海中，比如火灾、受伤需要帮助、紧急电话，可以自由提问。\", \"请描述一下你脑海中的情况。\"]', NULL, '[{\"original\": \"请帮我叫救护车。\", \"translated\": \"응급차를 불러줘.\"}, {\"original\": \"医院在哪里？\", \"translated\": \"병원은 어디예요?\"}, {\"original\": \"有人受伤了。\", \"translated\": \"누군가 다쳤어요.\"}, {\"original\": \"请帮助我。\", \"translated\": \"도와주세요.\"}, {\"original\": \"警察局在哪里？\", \"translated\": \"경찰서는 어디예요?\"}, {\"original\": \"我丢失了物品。\", \"translated\": \"내 소지품을 잃어버렸어요.\"}, {\"original\": \"消防部门的号码是多少？\", \"translated\": \"소방서 전화번호는 뭐예요?\"}, {\"original\": \"我丢了自己的护照。你知道最近的警察局在哪里吗？\", \"translated\": \"내 여권을 잃어버렸어요. 가장 가까운 경찰서는 어디예요?\"}, {\"original\": \"有紧急出口吗？\", \"translated\": \"비상출구가 있나요?\"}, {\"original\": \"有人晕倒了。\", \"translated\": \"누군가 쓰러졌어요.\"}]', 8, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"你能给我10个在海滩或泳池边常用的短语吗？\", \"太好了！以下是与海滩或泳池边相关的10个常用短语，以及韩语翻译：\"]', '[\"游泳\", \"日光浴\", \"沙滩运动\"]', 'zh', '[\"目前，请你提供你参加的当地活动或节日的背景信息，比如文化节日、美食节或音乐节。请提供背景信息。\", \"请提供你参加的活动。\"]', '[\"你有没有脑海中想到的具体情况，可以随时提问。\", \"请描述你脑海中的情况。\"]', '[{\"original\": \"看！那边的浪真的很大。\", \"translated\": \"보라, 저쪽의 파도가 정말 크다.\"}, {\"original\": \"记得涂防晒霜，这里的紫外线很强。\", \"translated\": \"자외선 차단제를 바르는 걸 잊지 말아야 해, 이곳의 자외선은 매우 강하다.\"}, {\"original\": \"这个海滩的沙子非常细，感觉像踩在棉花上。\", \"translated\": \"이 해변의 모래는 매우 부드럽고, 마치 천처럼 밟히는 느낌이다.\"}, {\"original\": \"在沙滩上打排球怎么样？\", \"translated\": \"해변에서 배구를 하기 어때?\"}, {\"original\": \"远处的帆船看起来很美丽。\", \"translated\": \"멀리 있는 요트들이 아름답게 보인다.\"}, {\"original\": \"这里的水非常清澈，甚至可以看到鱼。\", \"translated\": \"이 곳의 물은 매우 맑아서 물고기를 볼 수 있다.\"}, {\"original\": \"我们去捡一些贝壳吧。\", \"translated\": \"시조를 찾아보자.\"}, {\"original\": \"在日落时分沿着海滩散步一定很浪漫。\", \"translated\": \"일몰 시간에 해변을 산책하는 건 매우 로맨틱할 것이다.\"}, {\"original\": \"我听说这里的海鲜非常新鲜，我们去尝尝吧。\", \"translated\": \"이곳의 해산물이 매우 신선하다는 걸 들었어, 가서 먹어보자.\"}, {\"original\": \"潮水要涨起来了，我们往岸边走吧。\", \"translated\": \"조수의 물이 들어오고 있어, 해안으로 가자.\"}]', 9, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"你能给我提供10个在本地活动和节日中可以使用的常见短语吗？\", \"太好了！以下是与本地活动和节日相关的10个常见短语，以及韩语翻译：\"]', '[\"参加活动\", \"庆祝节日\", \"学习文化\"]', 'zh', '[\"目前，请您提供您参加的本地活动或节日的背景信息，比如万圣节、音乐会或朋友聚会，或者其他内容？请提供背景信息。\", \"请描述您脑海中的活动。\"]', '[\"您有没有特定的情况在脑海中，可以自由提问。\", \"请描述您脑海中的情况。\"]', '[{\"original\": \"今天有什么活动吗？\", \"translated\": \"오늘 행사가 있나요?\"}, {\"original\": \"这个节日有什么特别之处吗？\", \"translated\": \"이 축제에 특별한 점이 있나요?\"}, {\"original\": \"庆祝活动在哪里举行？\", \"translated\": \"축제는 어디에서 열리나요?\"}, {\"original\": \"我怎么买票？\", \"translated\": \"티켓을 어떻게 구할 수 있나요?\"}, {\"original\": \"演出什么时候开始？\", \"translated\": \"공연은 몇 시에 시작하나요?\"}, {\"original\": \"有什么传统食物？\", \"translated\": \"전통 음식은 무엇인가요?\"}, {\"original\": \"这里真的很热闹。\", \"translated\": \"여기 정말 활기가 넘치네요.\"}, {\"original\": \"有什么民间活动吗？\", \"translated\": \"민속 활동이 있나요?\"}, {\"original\": \"节日快乐！\", \"translated\": \"즐거운 명절 되세요!\"}, {\"original\": \"活动什么时候结束？\", \"translated\": \"행사는 몇 시에 끝나나요?\"}]', 10, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"你能给我10个在博物馆或艺术馆中可以使用的常用短语吗？\", \"太好了！以下是一些与博物馆或艺术馆相关的10个常用短语，以及韩语翻译：\"]', '[\"参观\", \"导游游览\", \"购买门票\"]', 'zh', '[\"目前，你有没有脑海中具体的情景，比如询问介绍手册、与路线相关的短语、与评论展品相关的短语，可以随时提问。\", \"请描述一下你脑海中的情景。\"]', NULL, '[{\"original\": \"入场费是多少？\", \"translated\": \"입장료는 얼마인가요?\"}, {\"original\": \"你们有语音导览吗？\", \"translated\": \"오디오 가이드가 있나요?\"}, {\"original\": \"这幅艺术品是谁创作的？\", \"translated\": \"이 작품을 만든 사람은 누구인가요?\"}, {\"original\": \"博物馆最珍贵的展品在哪里？\", \"translated\": \"박물관의 가장 값진 작품은 어디에 있나요?\"}, {\"original\": \"允许拍照吗？\", \"translated\": \"사진 촬영이 가능한가요?\"}, {\"original\": \"这里有什么特别展览吗？\", \"translated\": \"이곳에 특별 전시회가 있나요?\"}, {\"original\": \"参观需要多长时间？\", \"translated\": \"방문에 얼마나 걸리나요?\"}, {\"original\": \"能给我们做个介绍吗？\", \"translated\": \"우리에게 소개를 해줄 수 있나요?\"}, {\"original\": \"这些作品真是精美绝伦。\", \"translated\": \"이 작품들은 정말 아름답습니다.\"}, {\"original\": \"纪念品商店在哪里？\", \"translated\": \"기념품 가게는 어디에 있나요?\"}]', 11, 'ko');
INSERT INTO `scene_default_phrases` VALUES (null, '[\"你能给我10个在咖啡馆常用的短语吗？\", \"太好了！以下是与咖啡馆相关的10个常用短语，以及韩语翻译：\"]', '[\"点咖啡\", \"休息\", \"社交\"]', 'zh', '[\"目前，你心里是否有具体的情景，比如询问菜单、冰饮或热饮、其他产品，可以随意提问。\", \"请描述你心中的情景。\"]', NULL, '[{\"original\": \"请给我一杯拿铁。\", \"translated\": \"제가 라테 한 잔 주세요.\"}, {\"original\": \"你们有Wi-Fi吗？\", \"translated\": \"와이파이 있으세요?\"}, {\"original\": \"可以看一下菜单吗？\", \"translated\": \"메뉴 좀 보여주세요.\"}, {\"original\": \"可以续杯吗？\", \"translated\": \"리필 가능하세요?\"}, {\"original\": \"我的咖啡好了吗？\", \"translated\": \"제 커피 준비되었나요?\"}, {\"original\": \"我可以坐在这里多久？\", \"translated\": \"이곳에서 얼마나 오래 있을 수 있나요?\"}, {\"original\": \"可以给我们拍张照片吗？\", \"translated\": \"우리 사진 좀 찍어줄 수 있나요?\"}, {\"original\": \"洗手间在哪里？\", \"translated\": \"화장실은 어디에요?\"}, {\"original\": \"请结账。谢谢。\", \"translated\": \"계산해 주세요. 감사합니다.\"}, {\"original\": \"味道真的很好。\", \"translated\": \"맛이 정말 좋아요.\"}]', 12, 'ko');
